window.SCHELLING_WORK_DATA = {"metadata": {"work_id": "sw-I-05", "series": "SW", "band": "5", "volume_number": "5", "title": "Schriften 1802–1803", "short_title": "Schriften 1802–1803", "source_title": "Schriften 1802–1803", "siglum": "SW I.5", "edition": "Total Verlag 1997 (Sämmtliche Werke 1856–1861)", "collection_title": "Digitale Schelling-Edition"}, "toc_printed": [{"title": "1. Abhandlungen, Recensionen etc. aus dem Kritischen Journal der Philosophie", "page": 4, "level": 0, "kind": "work"}, {"title": "a. Ueber das Wesen der philosophischen Kritik überhaupt und ihr Verhältniß zum gegenwärtigen Zustand der Philosophie insbesondere", "page": null, "level": 1, "kind": "section"}, {"title": "b. Ueber das absolute Identitätssystem und sein Verhältniß zu dem neuesten (Reinholdischen) Dualismus", "page": null, "level": 1, "kind": "section"}, {"title": "c. Rückert und Weiß, oder die Philosophie, zu der es keines Denkens und Wissens bedarf", "page": null, "level": 1, "kind": "section"}, {"title": "d. Ueber das Verhältniß der Naturphilosophie zur Philosophie überhaupt", "page": null, "level": 1, "kind": "section"}, {"title": "e. Ueber die Construktion in der Philosophie", "page": null, "level": 1, "kind": "section"}, {"title": "f. Ueber Dante in philosophischer Beziehung", "page": null, "level": 1, "kind": "section"}, {"title": "g. Notizenblatt", "page": null, "level": 1, "kind": "section"}, {"title": "2. Vorlesungen über die Methode des akademischen Studiums", "page": 206, "level": 0, "kind": "work"}, {"title": "Erste Vorlesung. Ueber den absoluten Begriff der Wissenschaft", "page": 211, "level": 1, "kind": "vorlesung"}, {"title": "Zweite Vorlesung. Ueber die wissenschaftliche und sittliche Bestimmung der Akademien", "page": 224, "level": 1, "kind": "vorlesung"}, {"title": "Dritte Vorlesung. Ueber die ersten Voraussetzungen des akademischen Studiums", "page": 240, "level": 1, "kind": "vorlesung"}, {"title": "Vierte Vorlesung. Ueber das Studium der reinen Vernunftwissenschaften: der Mathematik und Philosophie im Allgemeinen", "page": 249, "level": 1, "kind": "vorlesung"}, {"title": "Fünfte Vorlesung. Ueber die gewöhnlichen Einwendungen gegen das Studium der Philosophie", "page": 258, "level": 1, "kind": "vorlesung"}, {"title": "Sechste Vorlesung. Ueber das Studium der Philosophie insbesondere", "page": 265, "level": 1, "kind": "vorlesung"}, {"title": "Siebente Vorlesung. Ueber einige äußere Gegensätze der Philosophie, namentlich der positiven Wissenschaften", "page": 276, "level": 1, "kind": "vorlesung"}, {"title": "Achte Vorlesung. Ueber die historische Construktion des Christenthums", "page": 287, "level": 1, "kind": "vorlesung"}, {"title": "Neunte Vorlesung. Ueber das Studium der Theologie", "page": 295, "level": 1, "kind": "vorlesung"}, {"title": "Zehnte Vorlesung. Ueber das Studium der Historie und der Jurisprudenz", "page": 306, "level": 1, "kind": "vorlesung"}, {"title": "Eilfte Vorlesung. Ueber die Naturwissenschaft im Allgemeinen", "page": 317, "level": 1, "kind": "vorlesung"}, {"title": "Zwölfte Vorlesung. Ueber das Studium der Physik und Chemie", "page": 328, "level": 1, "kind": "vorlesung"}, {"title": "Dreizehnte Vorlesung. Ueber das Studium der Medicin und der organischen Naturlehre überhaupt", "page": 335, "level": 1, "kind": "vorlesung"}, {"title": "Vierzehnte Vorlesung. Ueber die Wissenschaft der Kunst, in Bezug auf das akademische Studium", "page": 344, "level": 1, "kind": "vorlesung"}, {"title": "3. Philosophie der Kunst (aus dem handschriftlichen Nachlaß)", "page": 351, "level": 0, "kind": "work"}, {"title": "Einleitung", "page": null, "level": 1, "kind": "einleitung"}, {"title": "Beweggründe zur Bearbeitung der Wissenschaft der Kunst", "page": 359, "level": 2, "kind": "section"}, {"title": "Möglichkeit einer Philosophie der Kunst", "page": 364, "level": 2, "kind": "section"}, {"title": "Allgemeinste Deduktion der Philosophie der Kunst", "page": 369, "level": 2, "kind": "section"}, {"title": "I. Allgemeiner Theil der Philosophie der Kunst", "page": null, "level": 1, "kind": "abschnitt"}, {"title": "A. Construktion der Kunst überhaupt und im Allgemeinen", "page": 373, "level": 2, "kind": "section"}, {"title": "B. Construktion des Stoffs der Kunst", "page": null, "level": 2, "kind": "section"}, {"title": "1. Ableitung der Mythologie als Stoffs der Kunst", "page": 389, "level": 3, "kind": "section"}, {"title": "2. Gegensatz der antiken und modernen Poesie in Bezug auf Mythologie", "page": 418, "level": 3, "kind": "section"}, {"title": "C. Construktion des Besonderen oder der Form der Kunst (des besonderen Kunstwerks)", "page": null, "level": 2, "kind": "section"}, {"title": "1. Theorie des Kunstwerks überhaupt (Erhabenheit und Schönheit, Naiv und Sentimental, Styl und Manier)", "page": 458, "level": 3, "kind": "section"}, {"title": "2. Spielarten der ästhetischen Idee in das concrete Kunstwerk", "page": null, "level": 3, "kind": "section"}, {"title": "a. Deduktion der Kunstwerk selbst", "page": 481, "level": 4, "kind": "section"}, {"title": "b. Deduktion der redenden Kunst", "page": 482, "level": 4, "kind": "section"}, {"title": "II. Besonderer Theil der Philosophie der Kunst", "page": null, "level": 1, "kind": "abschnitt"}, {"title": "D. Construktion der Kunstformen in der Entgegensetzung der realen und idealen Reihe", "page": null, "level": 2, "kind": "section"}, {"title": "1. Reale Seite der Kunstwelt oder die bildende Kunst", "page": null, "level": 3, "kind": "section"}, {"title": "a. Construktion der Musik (Klang, Schall, Gehör)", "page": 489, "level": 4, "kind": "section"}, {"title": "b. Construktion der Malerei (Licht, Farben, Gesichtssinn)", "page": 507, "level": 4, "kind": "section"}, {"title": "c. Construktion der Plastik und ihrer Formen", "page": 570, "level": 4, "kind": "section"}, {"title": "Architektur", "page": 573, "level": 5, "kind": "section"}, {"title": "Basrelief", "page": 599, "level": 5, "kind": "section"}, {"title": "Skulptur", "page": 603, "level": 5, "kind": "section"}, {"title": "Symbolische Bedeutung der menschlichen Gestalt", "page": 604, "level": 5, "kind": "section"}, {"title": "Allgemeine Anmerkungen über die bildende Kunst überhaupt", "page": 628, "level": 4, "kind": "section"}, {"title": "2. Ideale Seite der Kunstwelt oder die redende Kunst (Poesie im engeren Sinn)", "page": null, "level": 3, "kind": "section"}, {"title": "a. Verhältniß der Poesie zur Kunst überhaupt", "page": 630, "level": 4, "kind": "section"}, {"title": "b. Wesen und Form der Poesie", "page": 634, "level": 4, "kind": "section"}, {"title": "c. Construktion der einzelnen Dichtarten", "page": null, "level": 4, "kind": "section"}, {"title": "Die epische Poesie", "page": 639, "level": 5, "kind": "section"}, {"title": "aa. Construktion des Epos nach seinen Hauptbestimmungen", "page": 646, "level": 6, "kind": "section"}, {"title": "bb. Der epische Stoff (Vergleichung des Virgil mit Homer)", "page": 654, "level": 6, "kind": "section"}, {"title": "cc. Die Charakteristik des Epos in besonderen Gattungen: Elegie und Idylle", "page": 659, "level": 6, "kind": "section"}, {"title": "Lehrgedicht und Satyre (Lucretius)", "page": 663, "level": 6, "kind": "section"}, {"title": "Das romantische (moderne) Epos: Rittergedicht (Ariosto)", "page": 670, "level": 6, "kind": "section"}, {"title": "Roman (Cervantes, Goethe)", "page": 673, "level": 6, "kind": "section"}, {"title": "Epische Versuche mit neueren Stoffen (Voß, Goethe)", "page": 684, "level": 6, "kind": "section"}, {"title": "ee. Die göttliche Komödie des Dante (eine epische Gattung für sich)", "page": 686, "level": 6, "kind": "section"}, {"title": "Die dramatische Poesie: Begriff des dramatischen Gedichts überhaupt", "page": 688, "level": 5, "kind": "section"}, {"title": "aaa. Das Wesen und der wahre Gegenstand der Tragödie", "page": 694, "level": 6, "kind": "section"}, {"title": "bbb. Die innere Construktion der Tragödie", "page": 700, "level": 6, "kind": "section"}, {"title": "ccc. Die äußere Form der Tragödie (Aeschylus, Sophokles, Euripides)", "page": 705, "level": 6, "kind": "section"}, {"title": "Von dem Wesen der Komödie (Aristophanes)", "page": 712, "level": 6, "kind": "section"}, {"title": "cc. Die moderne dramatische Poesie (Shakespeare)", "page": 719, "level": 5, "kind": "section"}, {"title": "Calderon", "page": 726, "level": 6, "kind": "section"}, {"title": "Goethes Faust", "page": 731, "level": 6, "kind": "section"}, {"title": "Die moderne Komödie", "page": 734, "level": 6, "kind": "section"}, {"title": "Zurückstreben der redenden zur bildenden Kunst in Musik, Gesang, Tanz", "page": 736, "level": 4, "kind": "section"}], "pages": [{"page_pdf": 1401, "page_book": 565, "page_kind": "title_page", "sigel": "SW I.5", "units": [{"type": "footnote", "text": "(Jenaer Allgemeine Literatur-Zeitung, 1802, Nr. 101.)"}, {"type": "footnote", "text": "Kl. Schr. Arzneigelahrtheit. 1) Bamberg: Sätze, welche zur Erlangung des medicinischen Doctorats unter dem Vorsitze des Hrn. Prof. I. Döllinger, am 14. September 1801 vertheidigt F. Stransky, Ritter von Greiffenfels, der Böhme, XV Sätze. 2) Ebendas.: Sätze, welche etc. vertheidigt F. Borggreve, der Westphale, XII Sätze. 3) Ebendas. Sätze, welche etc. d. 15. Sept. vertheidigt N. Sauer, der Westphale, XV Sätze. 4) Ebendas. Sätze, welche etc. vertheidigt F. E. Niethhammer aus Beilstein, im Herz. Würtemberg, XV Sätze. Zu Bamberg scheint man Doctoren der Medicin zu machen, ohne die Herausgabe von Inauguraldissertationen und das Vertheidigen derselben in lateinischer Sprache zu verlangen. Es ist, so viel wir wissen, dem Publicum nicht bekannt gemacht worden, was man an die Stelle dieser Prüfungen gesetzt hat, eine Rechenschaft, welche die dortige Facultät oder Regierung der Welt schuldig gewesen wäre, weil sie doch von dieser, und nicht allein vom Bamberger District ihre Doctoren wird anerkannt wissen wollen. Man erstaunt, wenn man aus diesen gedruckten Blättern sieht, welcher wissenschaftliche und sittliche Unfug auf dem Catheder der Bamberger medicinischen Facultät öffentlich unter Vorsitz des Hrn. Prof. Ignatz Döllinger getrieben, und mit Ertheilung des Doctortitels und der medicinischen Doctorrechte belohnt wird. Das Sublimste aus dem Athenäum,"}, {"type": "footnote", "text": "aus der Lucinde, aus Schellings und Röschlaubs Schriften, ist hier benutzt. Wir heben nur das Auffallendste aus. \"Der Menschen-Organismus ist die höchste Metamorphose der weniger cohärenten Metallreitze. Die Theorie der weniger cohärenten Metallreitze ist die Propädeutik der Physiologie. Negative Reize setzen im lebenden Organismus unmittelbar das Hervortreten der Reitzbarkeit, werden selbst in solchem zur Reitzbarkeit. Die Menschen-Organismen bilden im Allgemeinen einen Magnet, und der Unterschied der Constitutionen der Gattungen sowohl als Arten beruht bloß auf der Verschiedenheit der Stelle, die die Gattung sowohl als Art in diesem Magnet einnimmt. In asthenischen Krankheiten ist der Erkältungsproceß durch Hitze dargestellt. In dem Weibe ist mit der Empfängniß, diesem großen elektrischen Schlage, unmittelbar das Beginnen eines höheren Cohäsionsprocesses (Thierbildung) gesetzt. Browns Elements of Medicine sind die würdigste Vorrede zu einer Theorie der Heilung. (So weit zurückgedrängt hat also Brownen die Bamberger Schule!) Die antagonistische Heilmethode hat nur in den selbstgenügsamen Träumereien geheimden Raths Hufelands Realität. Sogenanntes medicinisches System geh. Raths Hufelands giebt mit jenem des Hofraths Reich Pole, der Indifferenzpunkt ist Präsidenten von Kotzebue's hohe Poesie.\" So weit der Verfasser von Nr. 1, der Ritter aus Böhmen. Die Verfasser von Nr. 2 und 4 zeigen sich als Anhänger der Erregungstheorie und Schellingischen Naturphilosophie; aber doch als verständige, gesittete Menschen, und wir bedauern sie, daß sie in Bamberg in solcher Gesellschaft den Doktorhut erhielten. Der Verfasser aber von Nr. 3, R. Sauer, der Westphale, läßt in sich einen würdigen Zögling Röschlaubs erkennen. Man höre ihn: \"Die Continuität der drei organischen Grundfunctionen und ihre wechselseitigen Verhältnisse zu einander aufzuzeigen, ist Aufgabe der Physiologie. Der Ausdruck dieser drei organischen Functionen ist der bestimmte Organismus; ihre Verschiedenheit in den Produkten für die empirische Anschauung darzulegen, ist das Geschäfte der Anatomie. Der Organismus steht unter dem Schema der krummen Linie. Die Sensibilität ist der Schluß der thierischen Organisation. Im Gehirne des Menschen ist das Innerste der Erde entfaltet. Alle Thätigkeit der Organisation, die über das Produkt und das Geschlecht hinausgeht, ist durch die Sinne vermittelt. Durch den Fructificationsakt der Thiere wird unmittelbar die Sensibilität hervorgerufen. Der menschliche Fötus durchläuft im Uterus seine ganze Metamorphose. Der Mann ist durch das Weib an die Erde gebunden. Das Blut ist ein fluctuirender Magnet, der jeden Augenblick die erlöschende Duplicität wieder weckt. Organische Chemie ist eine französische Plattheit, in die sich Hr. Reil fest gerannt hat.\" Wahrlich es ist doch ein magnum dei beneficium sensu communi valere!"}, {"type": "heading", "text": "Fünfter Band: Friedrich Wilhelm Joseph von Schellings sämmtliche Werke. 1802. 1803.", "level": null}]}, {"page_pdf": 1402, "page_book": 5, "page_kind": "frontmatter", "sigel": "SW I.5", "units": [{"type": "heading", "text": "Vorwort des Herausgebers.", "level": null}, {"type": "paragraph", "text": "Der gegenwärtige Band ist unter den bisher erschienenen der erste, welcher eine größere noch unbekannte Arbeit Schellings aus der älteren Zeit veröffentlicht, die Philosophie der Kunst. Ich begleite sie mit einigen Bemerkungen. Zuerst mit der, daß die Philosophie der Kunst zu den andern in diesen Band aufgenommenen Schriften Schellings theilweise im Verhältniß der früheren Abfassung zu stehen und für diese als Concept und Material gedient zu haben scheint. So z.B. der achten und neunten Vorlesung in der (erst nach dem ersten Vortrag der Philosophie der Kunst gedruckten) Methode des akademischen Studiums, welche von der historischen Construktion des Christenthums und dem Studium der Theologie handeln, lag offenbar die Philosophie der Kunst als Concept zu Grunde, denn jene können als ein Auszug aus dieser angesehen werden. Die vierzehnte Vorlesung über die Wissenschaft der Kunst ist sogar ein fast wörtlicher Abdruck aus der Einleitung in die Philosophie der Kunst, vielleicht wurde sie erst bei der Herausgabe der Methode den übrigen Vorlesungen hinzugefügt (vgl. S. 357, Anm.). Ganz das Gleiche ist der Fall mit dem Aufsatz über Dante im Kritischen Journal Bd. 2, Stück 3; auch dieser ist ein beinahe wörtlicher Abdruck aus der Philosophie der Kunst; die kleinen Abweichungen sind von der Art, wie sie die unbedeutende Ueberarbeitung eines schon Fertigen mit sich bringt: kleine Ueberflüssigkeiten wurden weggestrichen, verschiedene Sätze anders gestellt, einige weitere Belegstellen aus Dante ausgelassen. Aber auch der Inhalt jener beiden Abhandlungen im Kritischen"}, {"type": "paragraph", "text": "Journal: Ueber das Wesen der philosophischen Kritik überhaupt und ihr Verhältniß zum gegenwärtigen Zustand der Philosophie insbesondere und Ueber das Verhältniß der Naturphilosophie zur Philosophie überhaupt, weist sehr bestimmt auf die Philosophie der Kunst zurück. Bekanntlich waren beide Abhandlungen bereits in Hegels Werke aufgenommen, als Schelling erklärte, die zweite habe ihn ausschließlich zum Verfasser, die erste aber, welche zugleich als Einleitung in das mit Hegel gemeinschaftlich herausgegebene Kritische Journal der Philosophie diente, sey zum Theil von diesem geschrieben.1 Diese Erklärung Schellings hielt einige nicht ab, dennoch darauf zu bestehen, auch die Abhandlung über das Verhältniß der Naturphilosophie zur Philosophie überhaupt sey Hegelschen Ursprungs. Die völlige Nichtigkeit der meisten hierfür vorgebrachten Gründe ist schon von andern nachgewiesen worden, früher von Erdmann2 zuletzt von Haym.3 Durch die Philosophie der Kunst aber wird Schellings Autorschaft vollends so augenscheinlich, daß sie auch ohne dessen persönliches Zeugniß nicht mehr bezweifelt werden könnte. So vergleiche man z.B. mit dem Eingang jener Abhandlung (S. 106) die Philosophie der Kunst S. 365 ff., woselbst namentlich auch der jener Abhandlung eigenthümliche Ausdruck *ideelle Bestimmungen *(zu unterscheiden von dem andern von Hegel, wie von Schelling, gebrauchten Ausdruck * ideelle Bestimmtheit)* vorkommt und ausführlich erklärt wird. Im Weitern bildet die Philosophie der Kunst in dem hieher gehörigen Abschnitt des allgemeinen Theils eine fortlaufende Parallele und eine Art Commentar zu besagter Abhandlung, weßhalb ich auch die durch diesen ganzen Band hindurchlaufenden Citate von einzelnen Parallel-Stellen und -Ausdrücken für dieselbe in die Philosophie der Kunst hinein nicht mehr fortgesetzt habe. Um nur Einiges anzuführen, so"}]}, {"page_pdf": 1403, "page_book": 7, "page_kind": "toc", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "heißt es z.B. in der Abhandlung S. 119, Z. 7 v.o.: \"Faßt man die"}, {"type": "footnote", "text": "1 S. Literarischer Anzeiger 1838, Nr. XXXXV. 2 Die Entwicklung der deutschen Speculation seit Kant, 2. Theil, S. 693. 3 Hegel und seine Zeit, S. 156 und S. 495, Anm. 8."}, {"type": "paragraph", "text": "griechische Mythologie bloß von der endlichen Seite auf, so erscheint diese durchaus bloß als ein Schematismus des Endlichen oder der Natur; nur in der Einheit etc. ist sie symbolisch.\" Eine Parallele hiezu, beziehungsweise eine Erklärung findet sich Philosophie der Kunst S. 408, Z. 15 ff. v.u., verglichen mit der kurz vorher gegebenen Auseinandersetzung des Unterschieds von Schematismus und Symbolik. Ein anderer einzelner und zugleich dunkler Gedanke in der Abhandlung S. 108, Z. 15 v.o. ist : \"die Poesie, solange sie noch nicht Sache der Gattung oder wenigstens eines ganzen Geschlechts etc.\"1 Dieser findet sich ausführlich entwickelt in §. 42 der Philosophie der Kunst (S. 414) vgl. mit S. 438, Z. 6 ff. v.o. und S. 442, Z. 10 v.u. Ein allgemeinerer Gedanke, der, daß alle Entgegengesetzten es aufhören zu seyn, sowie jedes für sich in sich absolut ist, S. 119, Z. 5 v.u. findet seinen wiederholten Ausdruck und seine Anwendung durch die ganze Philosophie der Kunst hindurch und erscheint als ein dem Schellingschen Philosophiren eingeborener Gedanke; man vergleiche z.B. S. 449, Z. 5 ff. v.o., ferner S. 470, Z. 12 ff. v.u., sowie die ganze Seite 475. Eben jener Satz aber (S. 119, Z. 5 ff. v.u.) hat seinem übrigen Inhalt nach eine vollständige Parallele in S. 448, Z. 13 ff. v.o. Aber auch über die Abfassung der *Einleitung *ins Kritische Journal (Ueber das Wesen der philosophischen Kritik etc.) gewährt der handschriftliche Nachlaß einen sehr bestimmten Aufschluß. Schelling hatte sich über seinen Antheil an derselben bloß im Allgemeinen geäußert: \"Viele Stellen, die ich jedoch im Augenblick nicht näher zu bezeichnen wüßte, sowie die Hauptgedanken sind von mir; es mag wohl keine Stelle seyn, die ich nicht wenigstens revidirt.\" Diese Stellen lassen sich nun wirklich mit Hülfe des handschriftlichen Nachlasses annähernd bezeichnen und die Hauptgedanken sich auf Schelling zurückführen. Z.B. der S. 7 ausgesprochene Gedanke der Identität der absoluten Form mit der Formlosigkeit findet"}, {"type": "footnote", "text": "1 Man vergl. übrigens schon System des transsc. Idealismus, S. 477 (Bd. 3, S. 629)."}, {"type": "paragraph", "text": "sich ausführlicher Philosophie der Kunst S. 465 und wiederholt angewendet S. 470, Z. 8 ff. v.o. Ein Passus S. 8 handelt von der Besonderheit, die sich für Originalität halte, die Philosophie der Kunst S. 456 aber (cf. S. 447, Z. 14 v.o.) gibt an, worin der Unterschied der Originalität von der Besonderheit bestehe. Ziemlich im Anfang der Abhandlung (S.4) heißt es: \"daß die Philosophie nur Eine ist, und nur Eine seyn kann, beruht darauf, daß die Vernunft nur Eine, und sowenig es verschiedene Vernunften geben kann, ebensowenig kann sich zwischen die Vernunft und ihr Selbsterkennen eine Wand stellen u.s.w.\" Nun liegt das Fragment einer Vorlesung aus dem Jahr 1803 vor mir, welche von der Idee der universellen Philosophie handelt. Hier sagt Schelling in einer auch sonst der Aufbewahrung nicht unwerthen Stelle:"}]}, {"page_pdf": 1404, "page_book": 9, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "footnote", "text": "Daß diese Idee der universellen Philosophie sich in den späteren Zeiten wissenschaftlich mehr oder weniger verlor, dieß erhellt freilich deutlich aus den letzten Regungen im Gebiete dieser Wissenschaft. Kant hat in die einzelnen Sphären der Philosophie - in die theoretische, wie in die praktische - den ersten Keim einer künftigen die ganze Wissenschaft betreffenden Revolution geworfen, aber er selbst ist nicht bis zu dem Centralpunkt vorgedrungen. Er statuirt so viele verschiedene Vernunften, als er verschiedene Kritiken geschrieben hat, und wie in einem bekannten Epigramm einige Kunstrichter, die von verschiedenen Geschmäcken redeten, gefragt wurden: wo dieser Geschmäcke Geschmack sey, so könnte man wohl Kant fragen: Wo ist dieser Vernunften Vernunft? - Fichte hat es ausdrücklich als seine Absicht erklärt, der theoretischen und praktischen Vernunft ein gemeinschaftliches wissenschaftliches Princip zu geben, allein der eigentliche Indifferenzpunkt beider liegt bei ihm zuletzt nicht im Wissen, sondern im Glauben, und der Gegensatz beider Seiten der Philosophie wird dadurch aufgehoben, daß die eine der anderen untergeordnet und aufgeopfert ist."}, {"type": "paragraph", "text": "Sollten nun nicht diese beiden Stellen aus Einer Feder geflossen seyn? und sollte nicht schon die jenen Worten der Abhandlung vorangehende Zusammenstellung der philosophischen Kritik mit der * Kunstkritik* eher auf Schelling als auf Hegel hinweisen? - Ein Gedanke, der in der Methode des akademischen Studiums (S. 273), in der Abhandlung über das Verhältniß der Naturphilosophie zur Philosophie überhaupt (S. 116) und in der über das Wesen der Kritik S. 15"}, {"type": "paragraph", "text": "gleichmäßig sich findet, ist: daß in Cartesius der *Dualismus *in der neueren Cultur zuerst in wissenschaftlicher Form sich ausgesprochen habe. Dieser also, sowie vielleicht auch der Tadel über Leibniz' Theodicee (S. 14) als \"ein Verfallen in die Unphilosophie\", wie es Schelling in einer im nächsten Band zu veröffentlichenden Darstellung der Leibnizischen Philosophie aus jener Zeit geradezu nennt, wird wohl Letzterem zuzuschreiben seyn. Citationen der Einleitung ins Kritische Journal in gelehrten Zeitschriften, wie z.B. Leipziger Literaturzeitung 1812, Nro. 90 (Recension von Schellings Schrift gegen Jacobi), zeigen, daß man früher nicht daran zweifelte, dieselbe enthalte nur Schellingsche Gedanken. Doch läge hierin noch kein Beweis, so wenig als in Bachmanns Zeugniß für den Hegelschen Ursprung der Abhandlung über die Construktion in der Philosophie. Obwohl (um gleich auch die anderen aus dem Kritischen Journal der Philosophie aufgenommenen Stücke durchzugehen) obwohl der Aufsatz: *Rückert und Weiß *oder die Philosophie, zu der es keines Denkens bedarf, in Hegels Werke nicht aufgenommen worden war, so wurden doch nachträglich Stimmen laut, welche ihn für diese in Anspruch nahmen. \"Dieselbe leichte Ironie, mit welcher Hegel Krug abfertigte, dieselbe logische Bestimmtheit, derselbe Gang der Analyse walten auch hier.\" Man könnte billigerweise fragen, ob denn Schelling von diesen Eigenschaften so verlassen gewesen; man dürfte ferner nur z.B. auf die ebenfalls im Kritischen Journal erschienene, aber wohl deßhalb, weil sie im Notizenblatt steht, wenig oder gar nicht beachtete Villerssche Recension hinweisen, die an leichter Behandlung und logischer Schärfe der Rückertschen nichts nachgibt. Allein es bedarf dessen nicht, denn es ist ein äußerer, von allen subjektiven Ansichten unabhängiger Grund vorhanden, nach welchem der Verfasser jenes Aufsatzes kein anderer als Schelling ist. Es unterliegt nämlich keinem Zweifel, daß dieser das Notizenblatt im Kritischen Journal (S. 164 ff.) geschrieben hat, aus der Nro. 5 desselben aber (S. 181), in der Schellings Feder ganz besonders"}, {"type": "paragraph", "text": "zu erkennen ist, folgt, daß der Verfasser der Rückertschen Recension und der Schreiber dieses"}]}, {"page_pdf": 1405, "page_book": 11, "page_kind": "toc", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Notizenblatts, da es einen Nachtrag zur ersteren enthält, einer und derselbe ist. Dieser Grund ist ganz entscheidend. Uebrigens finden sich auch noch andere einzelne Anzeichen ihres Schellingschen Ursprungs. Z.B. ein stehender Ausdruck im Kritischen Journal ist der: \"Durchbruch\", \"zum Durchbruch verhelfen\" oder \"zum Durchbruch kommen\"; vgl. S. 7, Z. 11 v.o. in der schon als Schellingisch erkannten Stelle, S. 126, Z. 14 v.u., S. 187, Z. 12 v.u. Dieser Ausdruck findet sich hier zweimal S. 78 und S. 93. Der prägnante philosophische Gebrauch des Worts *empfängt* S. 92, Z. 1 v.u. ist gleichfalls ein zu jener Zeit Schelling eigenthümlicher und findet sich z.B. S. 212, Z. 18. v.o. (vgl. S. 140, Z. 3 v.o.) in diesem und S. 517, Z. 8 v.o., sowie S. 519, Z. 2 v.u. (Abh. über die Metalle) im vorhergehenden Band. Schellingisch wie nur irgend etwas ist der Satz S. 94: \"jener Nothwendigkeit aber, welche nicht mit der Freiheit im Kampfe liegt, jener göttlichen, übersinnlichen, unbewegten, heiligen, die Schicksal heißt, sich zu unterwerfen, ist die Lehre jeder ächten Philosophie und die einzige Weisheit.\" Ganz ähnlich heißt es in einem Würzburger Manuscript:"}, {"type": "footnote", "text": "Dieß beruhigt uns, dieß erhebt uns auf immer über alle leere Sehnsucht, Furcht und Hoffnung, zu wissen, daß nicht wir handeln, sondern daß eine göttliche Nothwendigkeit in uns handelt, von der wir zum Ziel getragen werden, und mit der nichts im Widerstreit stehen kann, was aus absoluter Freiheit folgt."}, {"type": "paragraph", "text": "Wenn endlich S. 87 Rückert vorgeworfen wird, er nehme den Idealismus auf den ganz gemeinen Standpunkt herunter, \"wo jeder Taglöhner und Markthelfer auch steht\", so erinnert dieß an die Worte eines Briefs an Fichte1: \"Kann ich dafür, wenn man mir keinen andern Begriff der Natur zuschreibt, als den jeder Chemiker und Apotheker auch hat.\" Man sehe auch das Citat S. 88."}, {"type": "footnote", "text": "1 Briefwechsel, S. 103."}, {"type": "paragraph", "text": "Den entschieden nicht-Hegelschen Ursprung der auch nicht in die Werke Hegels aufgenommenen Abhandlung über die *Construktion in der Philosophie *hat neuerdings Haym1 geltend gemacht, indem er vorzüglich den Satz heraus hebt, in welchem von der noch zu erwartenden Erfindung der \"universellen Symbolik\" die Rede ist (S. 130, Z. 8 ff. v.o.). Zu diesem Ausspruch findet sich der Commentar in einem Abschnitt der Philosophie der Kunst (S. 446 ff.), wo Schelling die Frage beantwortet, ob es wohl möglich sey, aus der *speculativen *Physik den Stoff einer neuen Mythologie zu nehmen. Außerdem hat Haym unter anderem auf das Citat des Systems des transscendentalen Idealismus im Text und ohne Nennung des Verfassers (S. 138) hingewiesen, (mit welchem das ähnliche Citat in der Methode des akademischen Studiums, S. 290 zu vergleichen wäre). Allein viel entscheidender als dieses Citat, ist die Aeußerung über seine *sämmtlichen * Schriften, welche S. 148, Z. 8 ff. v.u. steht, und wodurch sich Schelling geradezu als den Verfasser dieser Abhandlung bekennt. Im Uebrigen verweise ich auf die von mir durchgängig citirten vielen und auffallenden Parallelstellen aus allen gleichzeitigen Schriften Schellings, namentlich die von S. 252 bis 256 angeführten. Der §. IV der ferneren Darstellungen, der von der philosophischen Construktion handelt (im vorhergehenden Band S. 391 ff.), würde aber, besonders von S. 405 an (Neue Zeitschrift 1 Bd., Stück 2, S. 24 ff.) für sich allein vollkommen hinreichend seyn Schelling als Verfasser der Höyerschen Recension durch ihren Inhalt zu beglaubigen. Die Schrift Höyers zu recensiren, mußte Schelling um so angenehmer seyn, je mehr er in dem Entwicklungsgang dieses schwedischen Philosophen ein gut Theil seines eignen Wegs in einem lebenden Gegenbild reconstruirt sah. Man vergleiche in dieser"}]}, {"page_pdf": 1406, "page_book": 12, "page_kind": "toc", "sigel": "SW I.5", "units": [{"type": "footnote", "text": "1 a.a.O. S. 213. und S. 503, Anm. 1. Auch von dem Aufsatz über Rückert und Weiß sagt Haym S. 502, Anm. 3, die Hegelsche Autorschaft desselben sey mindestens zweifelhaft, aber es ist ein Widerspruch, wenn er denselben dennoch zur Charakteristik Hegels anwendet, wie dieß z.B. S. 185 geschieht."}, {"type": "paragraph", "text": "Hinsicht S. 140, Z. 6 ff. v.u. vgl. mit der vorhin citirten Stelle S. 148, Z. 8. ff. v.u. An die letztgenannte Recension schließt sich nach Inhalt und Wichtigkeit die *Villerssche *(S. 184 ff.) an, für deren Schellingschen Ursprung vorhandene Briefe noch besonders Zeugniß geben, worin sich Villers über die Recension beschwert und Schelling ihm antwortet.1 (Auch von Höyer ist der Brief da, mit welchem er die Uebersendung seines Buchs an Schelling begleitet und diesen um sein Urtheil bittet, aber kein weiterer.) Daß die Anzeige der andern französischen Schrift (S. 202) ebenfalls von Schelling ist, ist nicht zu bezweifeln. Noch bemerke ich, daß die Methode des akademischen Studiums verschiedene Zusätze aus dem Handexemplar des Verfassers erhalten hat, z.B. S. 226, 229, 230, 255, Anm. u.a. Dagegen wurden einige kleine Stücke zu ephemeren und unbedeutenden Inhalts im Kritischen Journal übergangen, nämlich aus dem Notizenblatt Bd. 1, Stück 3, S. 94-98, ferner was S. 163 dieses Bandes und S. 206 in den betreffenden Noten erwähnt ist. Ich komme nun wieder auf die Philosophie der Kunst. Es wurde schon nachgewiesen, daß die Philosophie der Kunst zur Abhandlung über das Verhältniß der Naturphilosophie zur Philosophie überhaupt vielfach einen Commentar bilde. Ebenso wurde bereits bemerkt, daß die religionsphilosophische Vorlesung in der Methode des akademischen Studiums als ein Auszug aus der Philosophie der Kunst gelten könne: diese enthält den gleichen Gedankengang mit jener, beide haben wörtliche Uebereinstimmungen, wie denn zwei in beiden fast ganz gleichlautende Stellen, um sie nicht zweimal zu drucken, in der Philosophie der Kunst weggelassen wurden, da es unbeschadet des Sinns und Zusammenhangs geschehen konnte; nämlich, was S. 288 steht, ist S. 430, Z. 3-4 v.u., und was S. 289, Z. 3 v.o. bis S. 290, Z. 4 v.o."}, {"type": "footnote", "text": "1 Man vergleiche über Villers Steffens' Was ich erlebte, Band V, S. 374."}, {"type": "paragraph", "text": "steht, ist S. 434, Z. 9-10 v.u. ausgefallen. Endlich harmoniren beide (die Methode und die Philosophie der Kunst) in den Formeln für den Gegensatz des Heidenthums und Christenthums. In beiden nämlich wird das Heidenthum als Darstellung oder Anschauung des Unendlichen im Endlichen, das Christenthum als Darstellung oder Anschauung des Endlichen im Unendlichen charakterisirt, während in der schon besprochenen Abhandlung über das Verhältniß der Naturphilosophie zur Philosophie überhaupt umgekehrt das Heidenthum als Aufnahme oder Einbildung des Endlichen ins Unendliche, das Christenthum als Einbildung des Unendlichen ins Endliche bestimmt wird. Und hierüber ist zunächst noch einiges zu sagen; denn der Wechsel jener Formeln in der Methode des akademischen Studiums und in der genannten Abhandlung war der einzige Einwurf gegen die Nichtidentität des Verfassers beider, der einigen Schein hatte, wiewohl man freilich gar nicht bedacht zu haben scheint, daß ja schon der *Gebrauch der Formel *\"Einbildung des Endlichen ins Unendliche oder des Unendlichen ins Endliche\" * an sich* - ohne ihre Anwendung auf das Wesen des Heidenthums und des Christenthums - eine Schelling"}]}, {"page_pdf": 1407, "page_book": 14, "page_kind": "toc", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "ganz eigenthümliche ist, und die sich bei ihm in verschiedenen gleichgeltenden Ausdrücken überall wiederholt, wie als Einbildung des Idealen ins Reale, des Allgemeinen ins Besondere, der Einheit in die Vielheit, und umgekehrt. Die Anwendung der Formel erscheint gegen sie selbst nur als etwas Accidentelles. Wollte man daher Hegel jene Abhandlung zuschreiben, so müßte man vor allem sich und andern begreiflich machen, wie Hegel auf einmal einer Formel sich bedienen konnte, die so ganz nur Schellingisch war. Zu behaupten, Hegel habe eben hier den Schellingschen Ton nachgeahmt, ist doch zu naiv, zumal das weitere Curiosum herauskäme, daß dann Schelling in der Methode (nur mit Umstellung der Formeln) seinen Nachahmer wieder nachgeahmt hätte. Es ist unendlich viel leichter zu denken, daß Schelling in der Anwendung jener Formel auf das Heidenthum und Christenthum variirte, als anzunehmen, daß Hegel"}, {"type": "paragraph", "text": "sich völlig und plötzlich nur für den Zweck jener Abhandlung in das Gewand einer ihm fremden Diktion gehüllt habe. In der That lassen sich auch jene Formeln in ihrer Anwendung aufs Heidenthum und Christenthum leicht verwechseln, ohne daß dadurch die anderweitige Hauptbestimmung des Charakters der beiden Religionen selbst verändert oder aufgehoben würde, die sich vielmehr auch bei veränderten Formeln gleich bleibt, wie ich mir zu zeigen erlaube. Für das Wesen des Heidenthums nämlich ist die sich gleichbleibende Hauptbestimmung, daß es sey Unterordnung des Unendlichen unter die Endlichkeit (Methode, S. 288) - Vergötterung des Endlichen (Abh., S. 120, Z. 6 v.o.) -, für das Christenthum Unterordnung des Endlichen unter das Unendliche. Setzen wir nun diese Bestimmung in jene Formeln um, so finden wir, daß die gleiche Formel nur von verschiedenen Standpunkten aus das einemal auf das Heidenthum, das anderemal auf das Christenthum paßt. Wir nehmen z.B. die Formel \"Einbildung des Endlichen ins Unendliche\". Wird nun in dieser der Nachdruck auf den Ausgangspunkt gelegt, nämlich das Endliche, so paßt sie aufs Heidenthum, und so ist sie in der Abhandlung genommen, vergl. S. 119. Wird aber mit derselben Formel (Einbildung oder Aufnahme des Endlichen ins Unendliche) bezeichnet, was das herrschende Princip in einer Religion ist, so paßt sie aufs Christenthum, und so - nämlich als Anschauung des Endlichen im Unendlichen - ist die Formel in der Methode angewendet. Ebenso, nur umgekehrt, verhält es sich mit der andern Formel \"Einbildung des Unendlichen ins Endliche\". Sieht man hier darauf, daß das Herrschende das Endliche ist, so ist sie die Formel fürs Heidenthum (nach der Methode S. 288, vgl. S. 292, Z. 16 v.o.); sieht man aber auf den Ausgangspunkt, welcher das Unendliche ist, so ist sie die Formel fürs Christenthum, wie in der Abhandlung S. 119. - Will man darüber streiten, welche von beiden die bessere Formulirung sey, so ist es ohne Zweifel besser, zu sagen, das Wesen des Christenthums sey Aufnahme des Endlichen ins Unendliche oder Anschauung"}, {"type": "paragraph", "text": "des Endlichen im Unendlichen, das des Heidenthums umgekehrt Einbildung des Unendlichen ins Endliche, wie es auch Schelling in der *Methode *vorzog, sofern das, was ein anderes aufnimmt, das Herrschende ist, das Aufgenommene dagegen das Beherrschte (nach Philosophie der Kunst S. 378, Z.5 v.o.), im Heidenthum aber war das Herrschende das Endliche, im Christenthum ist es das Unendliche; der Weg aber oder das Mittel hierzu (zum Uebergewicht des Unendlichen über das Endliche, des Idealen über das Reale im Christenthum) ist \"nicht eine Erhebung der Endlichkeit zur Unendlichkeit, sondern eine Endlichwerdung des Unendlichen\", wie die Abhandlung sagt (S. 117), oder, wie die Methode (S. 292) sich ausdrückt, vgl. mit Philosophie der Kunst S. 431 ff.: das * wahre* Unendliche mußte erst ins Endliche kommen, um dieses an sich selbst zu opfern, es dadurch zu versöhnen und - als Geist - zum"}]}, {"page_pdf": 1408, "page_book": 16, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Unendlichen zurückzuführen: - wir sehen, die Methode (und die Philosophie der Kunst) stimmt auch in dieser letzteren Bestimmung mit der Abhandlung völlig überein ungeachtet ihrer Abweichung von derselben bei der Anwendung jener Formel. Wenn Schelling in der Abhandlung vielmehr das Christenthum als Einbildung des Unendlichen ins Endliche oder als Anschauung des Unendlichen im Endlichen bezeichnete, so ist meines Erachtens der Grund darin zu suchen, daß er es dort nicht nach seiner *allgemeinen *Richtung, sondern gleich nur nach dem charakterisirt, was er als sein Besonderstes und Innerstes, als seine \"Vollendung\" erklärt, zu welcher das Christenthum als Gegensatz nur der Weg sey (S. 120, Z. 1 v.o.). Das Streben nach dieser Vollendung nennt er Mysticismus. Nach dieser tief in ihm liegenden Tendenz betrachtet, ist das Christenthum Schauen des Unendlichen im Endlichen, während seine \"allgemeine und unmittelbare Richtung\" auf das Unendliche geht. Sein herrschendes Princip ist das Unendliche, aber innerhalb dieser principiellen Richtung selbst bricht wieder \"das symbolische Bestreben\" (= das Unendliche im Endlichen zu schauen) durch. Die Philosophie der Kunst"}, {"type": "paragraph", "text": "gibt auch hierüber Aufklärung; man vergleiche insbesondere S. 447. Ebendaselbst (S. 448) findet sich dann auch das Nähere über das Verhältniß der Speculation zu jenem Mysticismus. Im Weiteren bemerke ich nun von der Philosophie der Kunst, daß deren Anfangssätze (§§. 1-15), so wie sie hier gedruckt sind, wohl erst den späteren, Würzburger Vorträgen angehören; bei dem ersten Vortrag in Jena scheint sie der Verfasser anders gegeben zu haben, wie ich auch aus der äußeren Beschaffenheit des Manuscripts abnehme, ohne Zweifel mehr conform der ursprünglichen Ausdrucksweise des Identitätssystems. - Es scheint, daß Schelling niemals im Sinn hatte, die Aesthetik als Ganzes zu ediren; er konnte es auch nach der Herausgabe der Methode des akademischen Studiums und dem in das Kritische Journal Aufgenommenen ohne Wiederholung von schon Bekanntem nicht mehr thun. Ueberdieß hatte er in derselben vielfach nur die von Schiller, Goethe, den Schlegels vertretene Literatur benutzt, und konnte gerade z.B. diesen Männern gegenüber auf das ihm Eigenthümliche keinen so großen Werth legen. Ihm konnte die Philosophie der Kunst nur als ein Versuch gelten, den er zunächst für sich selbst machte, die Ideen und die Methode seiner Philosophie auf die Wissenschaft der Kunst anzuwenden, und etwa durch diese Anwendung bei seinen Zuhörern ein lebendiges Verständniß und erhöhtes Interesse für ein System zu wecken, durch das allerdings zum erstenmal das vielgestaltige, für den Laien schwer zu begreifende Wesen der Kunst in bestimmte, einfache und unter sich harmonirende Construktionen gefaßt war. Hätte nun auch dieser letztere Vorzug besonders bei noch weiterer Ausbildung sie ihm als druckwürdig erscheinen lassen können, so mochte er dagegen bald von dieser oder jener seiner eigensten, zur Zeit der ersten Abfassung der Aesthetik besonders gehegten und in dieser noch mehr als in den anderen gleichzeitigen Schriften prononcirten Ideen abgekommen seyn, so daß es ihm doch nicht möglich war die Philosophie der Kunst ohne eine theilweise gänzliche Umarbeitung zu"}, {"type": "paragraph", "text": "veröffentlichen. Und auch über einzelnes Historische, wie z.B. über den Ursprung der gothischen Baukunst, war er vielleicht nach wenigen Jahren anderer Ansicht geworden. Je weniger aber er selbst an die Publikation seiner Aesthetik dachte, desto mehr scheint sie sich durch nachgeschriebene Hefte überall hin verbreitet zu haben, worüber eine Anmerkung in den Jahrbüchern der Medicin als Wissenschaft Bd. 2, Heft 2, S. 303 sich ausspricht. Ohne das Interesse, welches die Philosophie der Kunst auch in ihrem allgemeinen Theil als"}]}, {"page_pdf": 1409, "page_book": 18, "page_kind": "toc", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Commentar und Pendant zu anderen Schriften Schellings und als Mittel der Aufhellung einiger Ungewißheiten in der philosophischen Literatur darbot, würde wohl auch jetzt das Ganze nicht veröffentlicht worden seyn, und ich bin schuldig ausdrücklich zu sagen, daß der Verfasser selbst für wirklich druckwürdig nur die Abhandlung über die Tragödie erklärt hat, vom Uebrigen aber höchstens Einzelnes des Drucks werth erachtete. Allein, was nun z.B. die besonderen Kunstformen betrifft, aus deren Darstellung man etwa einzelnes auszuwählen gehabt hätte, so wollte sich hier kein Maßstab für die Ausscheidung finden, vielmehr schien die Harmonie des Ganzen, das Ineinandergreifende, durch Parallelen sich gegenseitig Erklärende der einzelnen Stücke durchaus nicht zu erlauben dieses oder jenes auszusondern. Auch war nicht etwa ein Theil vor dem andern durch reichere Ausführung bevorzugt. Doch selbst für die Mittheilung des Grund legenden allgemeinen Theils sprach nicht bloß ein kritisches Interesse und nicht bloß der Vortheil des völligeren Verständnisses auch des besonderen. Hatte doch Schelling selbst durch eine Aeußerung in seinen nachgelassenen Schriften (Einleitung in die Philosophie der Mythologie, S. 241) begierig gemacht das Kapitel über die *Mythologie *in der Philosophie der Kunst kennen zu lernen. Es interessirt uns nun zu sehen, wie er schon damals die Mythologie nicht vom bloßen Zufall subjektiver Erfindung herleitete, - die Phantasie zwar war die Erfinderin, aber sie folgte in ihren Dichtungen unwillkürlich dem Typus der Ideen, insofern einer Nothwendigkeit,"}, {"type": "paragraph", "text": "sie bildete in der Mythologie eine zweite *Welt *mit absoluter Objektivität, und nicht das Werk einzelner Individuen als Individuen war die Mythologie, sondern das eines ganzen Geschlechts, sofern es selbst Individuum (S. 414). Diese Nothwendigkeit muß freilich später in der Philosophie der Mythologie einer ganz anderen Platz machen. Das Geschlecht, \"das einem einzelnen Menschen gleich,\" wird zum menschlichen Bewußtseyn selbst - in welchem auch allein die Totalität dem Individuum gleich ist - und in diesem erzeugen sich die Göttervorstellungen ursprünglich ohne alles Zuthun der Phantasie mit einer Nothwendigkeit, die sich durchaus nicht von Ideen oder von einer idealen Regel herschreibt, sondern von einer Katastrophe des menschlichen Bewußtseyns und einem daraus folgenden unwillkürlichen Proceß, dem das Bewußtseyn hingegeben ist, unter dem es leidet. Es dürfte somit die vollständige Veröffentlichung der Philosophie der Kunst aus verschiedenen Gründen gerechtfertigt und etliches aus diesem vor mehr als 50 Jahren gehaltenen Vortrag vielleicht selbst denen nicht unwillkommen seyn, welche heutzutage an dieser Wissenschaft arbeiten. Zum Schlusse noch die Erinnerung, daß der Zeitfolge nach zum Inhalt dieses Bandes auch die im Jahr 1802 geschriebenen * Zusätze * zur zweiten Auflage der Ideen zu einer Philosophie der Natur (Band 2 dieser Ausgabe) gehören, von welchen überdieß der erste, der die Ueberschrift hat \"Darstellung der allgemeinen Idee der Philosophie überhaupt und der Naturphilosophie insbesondere als nothwendigen und integranten Theils der ersteren\" mit der viel besprochenen Abhandlung über das Verhältniß der Naturphilosophie zur Philosophie überhaupt in einiger Verwandtschaft steht."}, {"type": "footnote", "text": "Eßlingen, im Oktober 1859."}, {"type": "paragraph", "text": "K. F. A. Schelling."}, {"type": "paragraph", "text": "*Inhalt.*"}]}, {"page_pdf": 1410, "page_book": 1, "page_kind": "toc", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Seite 1. Abhandlungen, Recensionen etc. aus dem Kritischen Journal der Philosophie.............................................................................................................. 1"}, {"type": "paragraph", "text": "a) Ueber das Wesen der philosophischen Kritik überhaupt und ihr"}, {"type": "paragraph", "text": "Verhältniß zum gegenwärtigen Zustand der Philosophie insbesondere. b) Ueber das absolute Identitätssystem und sein Verhältniß zu dem neuesten"}, {"type": "paragraph", "text": "(Reinholdischen Dualismus). c) Rückert und Weiß oder die Philosophie, zu dem es keines Denkens und"}, {"type": "paragraph", "text": "Wissens bedarf. d) Ueber das Verhältniß der Naturphilosophie zur Philosophie überhaupt. e) Ueber die Construktion in der Philosophie. f) Ueber Dante in philosophischer Beziehung. g) Notizenblatt. 2. Vorlesungen über die Methode des akademischen Studiums ........................ 207 3. Philosophie der Kunst (*aus dem handschriftlichen Nachlaß)* ........................ 353"}, {"type": "paragraph", "text": "Abhandlungen, Recensionen etc."}, {"type": "paragraph", "text": "aus dem Kritischen Journal der Philosophie."}, {"type": "paragraph", "text": "1802. 1803."}, {"type": "paragraph", "text": "Ueber das Wesen der philosophischen Kritik überhaupt, und ihr Verhältniß zum gegenwärtigen Zustand der Philosophie insbesondere1."}, {"type": "footnote", "text": "1 Diese Abhandlung bildet die \"Einleitung\" in das von Schelling und Hegel herausgegebene Kritische Journal der Philosophie, und es haben beide an derselben Theil. Man vergl. das Vorwort dieses Bandes. D. H."}, {"type": "paragraph", "text": "Die Kritik, in welchem Theil der Kunst oder Wissenschaft sie ausgeübt werde, fordert einen Maßstab, der von dem Beurtheilenden ebenso unabhängig als von dem Beurtheilten, nicht von der einzelnen Erscheinung, noch der Besonderheit des Subjekts, sondern von dem ewigen und unwandelbaren Urbild der Sache selbst hergenommen sey. Wie die Idee schöner Kunst durch die Kunstkritik nicht erst geschaffen oder erfunden, sondern schlechthin vorausgesetzt wird, ebenso ist in der philosophischen Kritik die Idee der Philosophie selbst die Bedingung und Voraussetzung, ohne welche jene in alle Ewigkeiten nur Subjektivitäten gegen Subjektivitäten, niemals das Absolute gegen das Bedingte zu"}]}, {"page_pdf": 1411, "page_book": 4, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "setzen hätte. Da die philosophische Kritik sich von der Kunstkritik nicht durch Beurtheilung des Vermögens zur Objektivität, das in einem Werke sich ausdrückt, sondern nur durch den Gegenstand oder die Idee selbst unterscheidet, welche diesem zu Grunde liegt, und welche keine andere als die der Philosophie selbst seyn kann, so müßte (da, was das erste betrifft, die philosophische Kritik mit der Kunstkritik gleiche Ansprüche auf allgemeine Gültigkeit hat), wer derselben gleichwohl Objektivität des"}, {"type": "paragraph", "text": "Urtheils absprechen wollte, nicht die Möglichkeit bloß verschiedener Formen der einen und selben Idee, sondern die Möglichkeit wesentlich verschiedener und doch gleich wahrer Philosophien behaupten, - eine Vorstellung, auf welche, so großen Trost sie enthalten mag, eigentlich keine Rücksicht zu nehmen ist. Daß die Philosophie nur Eine ist, und nur Eine seyn kann, beruht darauf, daß die Vernunft nur Eine ist; und so wenig es verschiedene Vernunften geben kann, ebensowenig kann sich zwischen die Vernunft und ihr Selbsterkennen eine Wand stellen, durch welche dieses eine wesentliche Verschiedenheit der Erscheinung werden könnte, denn die Vernunft absolut betrachtet, und insofern sie Objekt ihrer selbst im Selbsterkennen, also Philosophie wird, ist wieder nur eins und dasselbe, und daher durchaus das gleiche. Da der Grund einer Verschiedenheit in der Philosophie selbst nicht im Wesen derselben liegen kann, welches schlechthin Eines ist, auch nicht in der Ungleichheit des Vermögens, die Idee derselben objektiv zu gestalten, weil nämlich philosophisch betrachtet die Idee selbst alles ist, das Vermögen aber sie darzustellen, das zu ihrem Besitz hinzukommt, der Philosophie nur noch eine andere, ihr nicht eigenthümliche Seite gibt, so könnte also eine Möglichkeit unendlich vieler und verschiedener Reflexe, deren jeder, seinem Wesen nach verschieden vom andern gesetzt, gleiches Recht hätte sich gegen die andern zu behaupten, nur dadurch herausgebracht werden, daß, indem die Philosophie als ein Erkennen des Absoluten bestimmt wird, dieses, es sey als Gott oder in irgend einer andern Rücksicht als Natur, in unbeweglicher und absoluter Entgegensetzung gegen das Erkennen als subjektives gedacht würde. Allein auch bei dieser Ansicht würde die Verschiedenheit sich selbst aufheben und verbessern müssen. Denn indem das Erkennen als etwas Formelles vorgestellt wird, wird es in seinem Verhältnisse zum Gegenstand als durchaus passiv gedacht, und an das Subjekt, das dieses Empfangens der Gottheit oder des reinen objektiven Anschauens der Natur fähig seyn soll, gefordert werden, daß es überhaupt sich gegen jedes andere Verhältniß zu irgend einer Beschränkung verschließe, und aller eignen Thätigkeit sich enthalte, indem dadurch die Reinheit des"}, {"type": "paragraph", "text": "Empfangens getrübt würde. Durch diese Passivität des Aufnehmens und die Gleichheit des Objekts würde dasjenige, was als Resultat vorgestellt wird, das Erkennen des Absoluten, und eine daraus hervorgehende Philosophie durchaus wieder nur Eine und allenthalben dieselbe seyn müssen. Dadurch, daß die Wahrheit der Vernunft so wie die Schönheit nur Eine ist, ist Kritik als objektive Beurtheilung überhaupt möglich, und es folgt von selbst, daß sie nur für diejenigen einen Sinn habe, in welchen die Idee der Einen und selben Philosophie vorhanden ist; ebenso nur solche Werke betreffen kann, in welchen diese Idee als mehr oder weniger deutlich ausgesprochen zu erkennen ist. Das Geschäft der Kritik ist für diejenigen und an denjenigen Werken durchaus verloren, welche jener Idee entbehren sollten. Mit diesem Mangel der Idee kommt die Kritik am meisten in Verlegenheit, denn wenn alle Kritik Subsumtion unter die Idee ist, so hört da, wo diese fehlt, nothwendig alle Kritik auf, und diese kann sich kein anderes unmittelbares Verhältniß geben als das der Verwerfung. In der Verwerfung aber bricht sie"}]}, {"page_pdf": 1412, "page_book": 6, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "alle Beziehung desjenigen, worin die Idee der Philosophie mangelt, mit demjenigen, in dessen Dienst sie ist, gänzlich ab. Weil das gegenseitige Anerkennen hiermit aufgehoben wird, erscheinen nur zwei Subjektivitäten gegeneinander; was nichts miteinander gemein hat, tritt eben damit in gleichem Recht auf, und die Kritik hat sich, indem sie das zu Beurtheilende für alles andere nur nicht für Philosophie, und weil es doch nichts seyn will als Philosophie, dadurch für gar nichts erklärt, in die Stellung eines Subjektiven versetzt, und ihr Ausspruch erscheint als ein einseitiger Machtspruch; eine Stellung, welche, da ihr Thun objektiv seyn soll, unmittelbar ihrem Wesen widerspricht; ihr Urtheil ist eine Appellation an die Idee der Philosophie, die aber, weil sie nicht von dem Gegenpart anerkannt wird, für diesen ein fremder Gerichtshof ist. Gegen dieß Verhältniß der Kritik, welche die Unphilosophie von der Philosophie abscheidet, - auf einer Seite zu stehen, und die Unphilosophie auf der entgegengesetzten zu haben, ist unmittelbar keine Rettung. Weil die Unphilosophie sich negativ gegen die Philosophie"}, {"type": "paragraph", "text": "verhält, und also von Philosophie nicht die Rede seyn kann, so bleibt nichts übrig als zu erzählen, wie sich diese negative Seite ausspricht und ihr Nichtsseyn, welches, insofern es eine Erscheinung hat, Plattheit heißt, bekennt, und da es nicht fehlen kann, daß, was im Anfang nichts ist, im Fortgang nur immer mehr und mehr als nichts erscheine, so daß es so ziemlich allgemein als solches erkannt werden kann, so versöhnt die Kritik durch diese von der ersten Nullität aus fortgesetzte Construktion wieder auch die Unfähigkeit, welche in dem ersten Ausspruch nichts als Eigenmächtigkeit und Willkür sehen konnte. Wo aber die Idee der Philosophie wirklich vorhanden ist, da ist es Geschäft der Kritik, die Art und den Grad, in welchem sie frei und klar hervortritt, so wie den Umfang, in welchem sie sich zu einem wissenschaftlichen System der Philosophie herausgearbeitet hat, deutlich zu machen. Was das Letztere betrifft, so muß man es mit Freude und Genuß annehmen, wenn die reine Idee der Philosophie ohne wissenschaftlichen Umfang mit Geist als eine Naivetät sich ausdrückt, welche nicht zur Objektivität eines systematischen Bewußtseyns gelangt; es ist der Abdruck einer schönen Seele, welche die Trägheit hatte, sich vor dem Sündenfall des Denkens zu bewahren, aber auch des Muths entbehrte, sich in ihn zu stürzen und seine Schuld bis zu ihrer Auflösung durchzuführen, darum aber auch zur Selbstanschauung in einem objektiven Ganzen der Wissenschaft nicht gelangte. Die leere Form solcher Geister aber, die ohne Geist in kurzen Worten, Wesen und Hauptsache der Philosophie geben wollen, hat weder wissenschaftliche noch sonst eine interessante Bedeutung. Wenn aber die Idee der Philosophie wissenschaftlicher wird, so ist von der Individualität, welche unbeschadet der Gleichheit der Idee der Philosophie und der rein objektiven Darstellung derselben ihren Charakter ausdrücken wird, die Subjektivität oder Beschränktheit, welche sich in die Darstellung der Idee der Philosophie einmischt, wohl zu unterscheiden; an den hierdurch getrübten Schein der Philosophie hat sich die Kritik vorzüglich zu wenden und ihn herunter zu reißen."}, {"type": "paragraph", "text": "Wenn es sich hier zeigt, daß die Idee der Philosophie wirklich vorschwebt, so kann die Kritik an die Forderung und an das Bedürfniß, das sich ausdrückt, das Objektive, worin das Bedürfniß seine Befriedigung sucht, halten, und die Eingeschränktheit der Gestalt aus ihrer eignen ächten Tendenz nach vollendeter Objektivität widerlegen. Es ist aber hierbei ein gedoppelter Fall möglich. Entweder hat sich das Bewußtseyn über die Subjektivität nicht eigentlich entwickelt; die Idee der Philosophie hat sich nicht zur Klarheit freier Anschauung erhoben und bleibt in einem dunkleren Hintergrunde stehen, etwa auch weil Formen, in"}]}, {"page_pdf": 1413, "page_book": 8, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "denen sich viel ausgedrückt findet, und die eine große Autorität haben, noch den Durchbruch zur reinen Formlosigkeit, oder, was dasselbe ist, zur höchsten Form hindern. Wenn die Kritik das Werk und die That nicht als Gestalt der Idee kann gelten lassen, so wird sie doch das Streben nicht verkennen; das eigentlich wissenschaftliche Interesse dabei ist, die Schale aufzureiben, die das innere Aufstreben noch hindert den Tag zu sehen; es ist wichtig, die Mannichfaltigkeit der Reflexe des Geistes, deren jeder seine Sphäre in der Philosophie haben muß, so wie das Untergeordnete und Mangelhafte derselben zu kennen. Oder es erhellt, daß die Idee der Philosophie deutlicher erkannt worden ist, daß aber die Subjektivität sich der Philosophie insoweit, als um sich selbst zu retten nöthig wird, zu erwehren bestrebt ist. Hier gilt es nicht darum, die Idee der Philosophie emporzuheben, sondern die Winkelzüge aufzudecken, welche die Subjektivität, um der Philosophie zu entgehen, anwendet, so wie die Schwäche, für welche eine Beschränktheit ein sicherer Halt ist, theils für sich, theils in Rücksicht auf die Idee der Philosophie, die mit einer Subjektivität vergesellschaftet wird, anschaulich zu machen; denn wahre Energie jener Idee und Subjektivität sind unverträglich. Es gibt aber noch eine Manier, an die sich die Kritik vorzüglich zu heften hat, nämlich diejenige, welche im Besitz der Philosophie zu seyn vorgibt, die Formen und Worte, in welchen große philosophische Systeme sich ausdrücken, gebraucht, viel mitspricht, aber im Grunde"}, {"type": "paragraph", "text": "ein leerer Wortdunst ohne inneren Gehalt ist. Ein solches Geschwätze ohne die Idee der Philosophie erwirbt sich durch seine Weitläufigkeit und eigne Anmaßung eine Art von Autorität, theils weil es fast unglaublich scheint, daß so viel Schale ohne Kern seyn soll, theils weil die Leerheit eine Art von allgemeiner Verständlichkeit hat. Da es nichts Ekelhafteres gibt als diese Verwandlung des Ernsts der Philosophie in Plattheit, so hat die Kritik alles aufzubieten, um dieses Unglück abzuwehren. Diese verschiedenen Formen finden sich im Allgemeinen mehr oder weniger herrschend in dem jetzigen deutschen Philosophiren, worauf dieses kritische Journal gerichtet ist. Dabei haben sie aber die Eigenthümlichkeit, daß, seitdem durch Kant und noch mehr durch Fichte die Idee einer Wissenschaft und besonders der Philosophie als Wissenschaft aufgestellt worden, und die Möglichkeit, durch mancherlei philosophische Gedanken über diesen oder jenen Gegenstand, etwa in Abhandlungen für Akademien, sich als Philosophen geltend zu machen, vorbei ist, und das einzelne Philosophiren allen Credit verloren hat, - jedes philosophische Beginnen sich zu einer Wissenschaft und einem System erweitert, oder wenigstens als absolutes Princip der ganzen Philosophie aufsteht, und daß dadurch eine solche Menge von Systemen und Principien entsteht, die dem philosophirenden Theil des Publikums eine äußere Aehnlichkeit mit jenem Zustande der Philosophie in Griechenland gibt, als jeder vorzüglichere philosophische Kopf die Idee der Philosophie nach seiner Individualität ausarbeitete. Zugleich scheint die philosophische Freiheit, die Erhebung über Autorität und die Selbständigkeit des Denkens unter uns so weit gediehen zu seyn, daß es für Schande gehalten würde, sich als Philosophen nach einer schon vorhandenen Philosophie zu nennen; und das Selbstdenken meint sich allein durch Originalität, die ein ganz eignes und neues System erfindet, ankündigen zu müssen. So nothwendig das innere Leben der Philosophie, wenn es sich zur äußern Gestalt gebiert, ihr von der Form seiner eigenthümlichen Organisation mitgibt, so sehr ist das Originelle des Genies verschieden von der *Besonderheit*, die sich *für Originalität * hält und ausgibt; denn diese Besonderheit, wenn sie näher ins Auge gefaßt wird, hält sich in"}]}, {"page_pdf": 1414, "page_book": 10, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Wahrheit innerhalb der allgemeinen Heerstraße der Cultur, und kann sich nicht einmal rühmen aus dieser heraus zur reinen Idee der Philosophie gekommen zu seyn; denn wenn sie diese ergriffen hätte, würde sie dieselbe in andern philosophischen Systemen erkennen, und eben damit, wenn sie ihre eigne lebendige Form zwar behalten muß, doch sich nicht den Namen einer *eignen Philosophie *beilegen können. Was sie innerhalb jener Heerstraße sich Eigenes erschaffen hat, ist eine besondere Reflexionsform, aufgegriffen von irgend einem einzelnen und darum untergeordneten Standpunkt, die in einem Zeitalter, das den Verstand so vielseitig ausgebildet, besonders auch ihn so mannichfaltig an der Philosophie verarbeitet hat, wohlfeil zu haben ist. Eine Versammlung solcher origineller Tendenzen und des mannichfaltigen Bestrebens nach eignen Formen und Systemen bietet mehr das Schauspiel der Qual der Verdammten, die entweder ihrer Beschränktheit ewig verbunden sind, oder von einer zu der andern greifen und alle durchbewundern und eine nach der andern wegwerfen müssen, als das Schauspiel des freien Aufwachsens der mannichfaltigsten lebendigen Gestalten in den philosophischen Gärten Griechenlands dar. Was die Arbeit betrifft, eine *solche Besonderheit zum System *zu erweitern und sie als das Ganze darzustellen, so hält diese Arbeit freilich härter, und die Besonderheit müßte an ihr scheitern, denn wie wäre das Beschränkte fähig, sich zu einem Ganzen auszudehnen, ohne eben damit sich selbst zu zersprengen? Schon die Sucht nach einem besonderen Princip geht darauf, etwas Eigenthümliches und nur sich selbst Genügendes zu besitzen, das sich dem Anspruch an Objektivität des Wissens und an Totalität desselben entzieht. Und doch ist das Ganze mehr oder weniger, in objektiver Form, wenigstens als Materialien, als eine Menge des Wissens vorhanden; es ist schwer, ihm Gewalt anzuthun und consequent seinen eigenthümlichen Begriff durch dasselbe durchzuführen; zugleich ist es nimmer erlaubt, es beifällig, weil es einmal da ist, ohne Zusammenhang aufzuführen; am genialischsten sieht es aus, sich darum nicht zu bekümmern, und sein eigenthümlichstes Princip einmal als das alleinige hinzustellen, ohne den"}, {"type": "paragraph", "text": "Zusammenhang1, mit welchem sich das übrige Wissen selbst bekümmern möge; es scheint eher eine niedrige Arbeit zu seyn, dem Grundprincip seinen wissenschaftlichen objektiven Umfang zu geben. Soll aber dieser Umfang theils nicht fehlen, theils doch die Mühe erspart seyn, das Mannichfaltige des Wissens in den Zusammenhang unter sich und mit der Beschränktheit des Princips zu bringen, so vereinigt diejenige Manier alle diese Forderungen, welche provisorisch philosophirt, d.h. das Vorhandene nicht aus dem Bedürfnisse eines Systems des Wissens, sondern aus dem Grunde aufführt, weil es scheint, daß es doch auch seinen Gebrauch, den Kopf zu üben, habe; denn wofür wäre es sonst vorhanden? In dieser Rücksicht hat die kritische Philosophie einen vorzüglich guten Dienst geleistet. Indem nämlich durch sie erwiesen worden ist, um es in ihren Worten zu sagen, daß die Verstandesbegriffe nur ihre Anwendung in der Erfahrung haben, die Vernunft als erkennend sich durch ihre theoretischen Ideen nur in Widersprüche verwickelt, und dem Wissen überhaupt seine Objekte durch die Sinnlichkeit gegeben werden müssen, so wird dieß dahin benutzt, auf die Vernunft in der Wissenschaft Verzicht zu thun, und sich dem krassesten Empirismus zu ergeben. Wenn die rohesten in die Erfahrung hineingetragenen Begriffe, eine durch die grellsten Geburten einer geistlosen Reflexion verunreinigte Anschauung für innere und äußere Erfahrung und für Thatsachen des Bewußtseyns ausgegeben und unter diesem Titel alles zusammengerafft wird, auf irgend woher erhaltene Versicherung, daß es im Bewußtseyn sich vorfinde, so geschieht dieß mit Berufung auf die kritische Philosophie, welche die Erfahrung und Wahrnehmung zur Erkenntniß für nothwendig erweise, und der Vernunft kein constitutives, sondern nur ein regulatives Verhältniß zum Wissen erlaube. Außerdem daß die Unphilosophie und Unwissenschaftlichkeit, wie sie sonst die Philosophie frei verachtete, eine philosophische Form zu ihrer Rechtfertigung angenommen hat, hat sie hierdurch zugleich noch höhere"}]}, {"page_pdf": 1415, "page_book": 11, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Vortheile erreicht, nämlich den gesunden Menschenverstand und jedes beschränkte Bewußtseyn"}, {"type": "footnote", "text": "1 \"um den Zusammenhang\", wie es im Original heißt, muß als Druckfehler angesehen werden. D. H."}, {"type": "paragraph", "text": "und die höchsten Blüthen desselben, nämlich die jeweiligen höchsten moralischen Interessen der Menschheit mit der Philosophie ausgesöhnt. Wenn aber die Subjektivität ohne Rücksicht der Schwierigkeit, welche sie findet, sich als ein System darzustellen, auch darum, weil bereits die kritische Philosophie wenigstens einen großen Umfang endlicher Formen verdächtig oder unbrauchbar gemacht hat, mit einer Einsicht in ihre Beschränktheit und einer Art von bösem Gewissen behaftet ist, und sich scheut, sich als absolut hinzustellen, wie mag sie ohnerachtet des eignen bessern Wissens und der vorschwebenden Idee der Philosophie erhalten und geltend gemacht werden? - Mit einer als endlich anerkannten Form soll nur vors erste angefangen werden, sie soll nichts vorstellen als den dem Scheine nach willkürlichen Anfangspunkt, der sich zwar nicht für sich selbst trägt, aber den man vor der Hand, weil sich seine Nützlichkeit schon zeigen werde, gelten, nur provisorisch, problematisch und hypothetisch auf Bitte einstweilen ohne weitere Prätension sich gefallen lassen soll; hintennach werde er sich schon legitimiren; - wenn wir nun von ihm aus zu dem Wahren gelangen, so werde die Dankbarkeit für das Wegweisen jenen willkürlichen Anfangspunkt für ein Nothwendiges erkennen und ihn bewährt finden. Allein weil das Wahre keines Gängelbandes bedarf, um an demselben herbeigeführt zu werden, sondern gleich für sich selbst aufzutreten die Kraft in sich tragen muß, und weil das Beschränkte, für was es darin, daß es nicht in sich den Gehalt des Bestehens zu haben, sondern nur etwas Hypothetisches und Problematisches zu seyn eingestanden wird, - selbst anerkannt ist, denn doch noch am Ende als ein wahres Wahres bewährt werden soll, so erhellt, daß es hauptsächlich um die Rettung der Endlichkeit zu thun war; was hinterher nicht mehr hypothetisch seyn soll, kann es auch nicht von Anfang seyn, oder was anfangs hypothetisch ist, kann hinterher nicht mehr kategorisch werden; sonst trete es gleich als absolut auf, aber da es dazu, wie billig, zu schüchtern ist, bedarf es eines Umwegs, um es einzuschwärzen. Daß ein solcher endlicher Anfangspunkt für etwas einstweilen Hypothetisches ausgegeben wird, bringt, da er mit dem Scheine, ohne"}, {"type": "paragraph", "text": "alle Prätension zu seyn, auftritt, nur eine Täuschung weiter herein; er trete bescheiden als ein hypothetischer oder sogleich als ein gewisser auf, so führt beides zu demselben Resultat, daß das Endliche als das, was es ist, in seiner Trennung erhalten, und das Absolute eine Idee, ein Jenseits, d.h. mit einer Endlichkeit behaftet bleibt. Der gewisse Anfangspunkt, der, um gewiß zu seyn, im unmittelbaren Bewußtseyn aufgegriffen wird, scheint, was ihm dadurch, daß er ein endlicher ist, abgeht, durch seine unmittelbare Gewißheit zu ersetzen; und das reine Selbstbewußtseyn, da es, insofern es Anfangspunkt ist, als ein reines in unmittelbarer Entgegensetzung gegen das Empirische gesetzt wird, ist ein solcher; um solche endliche Gewißheit kann es an und für sich der Philosophie nicht zu thun seyn; eine Philosophie, die, um an eine Gewißheit sich anzuknüpfen, von dem allgemeingültigsten, jedem Menschenverstande nahen Satze oder Thätigkeit ausgeht, thut entweder mit dieser Nützlichkeit etwas Ueberflüssiges, denn sie muß, um Philosophie zu seyn, doch sogleich über diese Beschränktheit hinausgehen und sie aufheben; der gemeine"}]}, {"page_pdf": 1416, "page_book": 13, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Menschenverstand, der damit verführt werden sollte, wird es sehr gut merken, wenn man seine Sphäre verläßt, und ihn über sich hinausführen will; oder wenn dieses endliche Gewisse als solches nicht aufgehoben, sondern als ein Fixes bleiben und bestehen soll, so muß es wohl seine Endlichkeit anerkennen und Unendlichkeit *fordern*, aber das Unendliche tritt damit eben nur als eine Forderung, als ein Gedachtes auf, * nur als eine Idee*, welche als nothwendige und umfassende, alles beschließende Vernunftidee, doch darum noch ein Einseitiges ist, weil dasjenige, das sie denkt (oder sonst irgend das Bestimmte, mit dem angefangen wurde) und sie selbst als getrennt gesetzt werden. Diese Arten von Rettungen des Beschränkten, - durch welche das Absolute zur höchsten Idee, nur nicht zugleich zum einzigen Seyn erhoben wird, und da von hier an erst die Wissenschaft der Philosophie anfängt, in dem ganzen System derselben der Gegensatz herrschend und absolut bleibt, - sind gewissermaßen das, was unsere neuere philosophische Cultur charakterisirt, so daß in diesen Begriff ziemlich alles fällt, was in unsern Tagen für Philosophie gegolten hat."}, {"type": "paragraph", "text": "Wenn auch die höchste philosophische Erscheinung der letzten Zeit die fixe Polarität des Innerhalb und Außerhalb, Diesseits und Jenseits nicht so weit überwunden hat, daß nicht eine andere Philosophie, mit der man sich im Wissen dem Absoluten nur nähert, und eine andere, die im Absoluten selbst ist (gesetzt die letztere werde auch nur unter dem Titel des Glaubens statuirt), als entgegengesetzte zurückblieben, und wenn auf diese Art dem Gegensatze des Dualismus seine höchste Abstraktion gegeben, und die Philosophie damit nicht aus der Sphäre unserer Reflexionscultur herausgeführt worden ist, so ist schon die Form der höchsten Abstraktion des Gegensatzes von der größten Wichtigkeit, und von diesem schärfsten Extrem der Uebergang zur ächten Philosophie um so leichter, weil die Idee des Absoluten, die aufgestellt wird, eigentlich selbst schon den Gegensatz, den die Form einer Idee, eines Sollens, einer unendlichen Forderung mit sich führt, verwirft. Es ist nicht zu übersehen, wie sehr durch die mannichfaltige Bearbeitung, welche der Gegensatz überhaupt, den jede Philosophie überwinden will, dadurch erfahren hat, daß gegen eine Form desselben, in der er in einer Philosophie herrschend war, sich eine folgende Philosophie richtete, und sie überwand, wenn sie schon bewußtlos wieder in eine andere Form desselben zurückfiel, das Studium der Philosophie überhaupt gewonnen hat, zugleich aber, in welcher Mannichfaltigkeit der Formen sie sich herumzuwerfen fähig ist. Dagegen hat eine andere herrschende Manier durchaus nur nachtheilige Seiten, nämlich diejenige, welche sogleich die philosophischen Ideen, wie sie hervortreten, *populär *oder eigentlich gemein zu machen bestrebt ist. Die Philosophie ist ihrer Natur nach etwas Esoterisches, für sich weder für den Pöbel gemacht noch einer Zubereitung für den Pöbel fähig; sie ist nur dadurch Philosophie, daß sie dem Verstande, und damit noch mehr dem gesunden Menschenverstande, worunter man die locale und temporäre Beschränktheit eines Geschlechts der Menschen versteht, gerade entgegengesetzt ist; im Verhältniß zu diesem ist an und für sich die Welt der Philosophie eine verkehrte Welt. Wenn Alexander an seinen Lehrer, als er hörte, dieser mache Schriften über seine"}, {"type": "paragraph", "text": "Philosophie öffentlich bekannt, aus dem Herzen von Asien schrieb, daß er das, was sie zusammen philosophirt hätten, nicht hätte sollen gemein machen, und Aristoteles sich damit vertheidigte, daß seine Philosophie herausgegeben und auch nicht herausgegeben sey, so muß die Philosophie zwar die Möglichkeit erkennen, daß das Volk sich zu ihr erhebt, aber sie muß sich nicht zum Volk erniedrigen. In diesen Zeiten der Freiheit und Gleichheit aber, in welchen sich ein so großes Publikum gebildet hat, das"}]}, {"page_pdf": 1417, "page_book": 15, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "nichts von sich ausgeschlossen wissen will, sondern sich zu allem gut oder alles für sich gut genug hält, hat das Schönste und das Beste dem Schicksal nicht entgehen können, daß die Gemeinheit, die sich nicht zu dem, was sie über sich schweben sieht, zu erheben vermag, es dafür so lange behandelt, bis es gemein genug ist, um zur Aneignung fähig zu seyn; und das Plattmachen hat sich zu einer Art von anerkannt verdienstlicher Arbeit emporgeschwungen. Es ist keine Seite des besseren Bestrebens des menschlichen Geistes, welche dieses Schicksal nicht erfahren hätte; es braucht eine Idee der Kunst oder der Philosophie sich nur blicken zu lassen, so geht es gleich an ein Zubereiten, bis die Sache für Kanzel, Compendien und für den Hausbedarf des Reichsanzeigerischen Publikums zurecht gerührt ist; Leibniz hatte durch seine Theodicee diese Mühe für seine Philosophie zum Theil selbst übernommen, und seiner Philosophie dadurch nicht, aber seinem Namen großen Eingang verschafft; und jetzt finden sich sogleich genug dienstfertige Leute zu diesem Zweck. Mit einzelnen Begriffen macht sich die Sache von selbst; es ist nichts nöthig, als ihren Namen auf das, was man in seinem bürgerlichen Leben längst hat, zu ziehen; die Aufklärung drückt schon in ihrem Ursprung und an und für sich die Gemeinheit des Verstandes und seine eitle Erhebung über die Vernunft aus, und daher hat es keiner Veränderung ihrer Bedeutung bedurft, um sie beliebt und faßlich zu machen; aber man kann annehmen, daß das Wort Ideal nunmehr die allgemeine Bedeutung dessen trägt, was keine Wahrheit in sich hat, oder das Wort Humanität desjenigen, was überhaupt platt ist. - Der scheinbar umgekehrte Fall, welcher aber im Grunde mit jenem ganz gleich ist, tritt da ein, wo schon der Stoff populär ist,"}, {"type": "paragraph", "text": "und Popularitäten, die mit keinem Schritt die Sphäre des gemeinen Begreifens überschreiten, durch philosophische und methodische Zubereitung zum äußern Ansehen der Philosophie gebracht werden sollen. So wie im ersten Fall die Voraussetzung gemacht wird, daß, was philosophisch ist, doch zugleich populär seyn, so im zweiten, daß, was seiner Beschaffenheit nach populär ist, auf irgend eine Weise philosophisch werden könne; also in beiden Compatibilität der Flachheit mit der Philosophie. Man kann diese mancherlei Bestrebungen überhaupt auf den in allen Dingen sich regenden Geist der Unruhe und des unsteten Wesens beziehen, welcher unsere Zeit auszeichnet, und der den deutschen Geist nach langen Jahrhunderten der härtesten Zähheit, der es die fürchterlichsten Krämpfe kostet eine alte Form abzustreifen, endlich so weit gebracht hat, auch philosophische Systeme in den Begriff des immer Wechselnden und der Neuigkeiten zu ziehen; doch müßte man diese Sucht des Wechselnden und Neuen nicht mit der Indifferenz des Spiels, welches in seinem größten Leichtsinn zugleich der erhabenste und der einzig wahre Ernst ist, selbst verwechseln; denn jenes unruhige Treiben geht mit der größten Ernsthaftigkeit der Beschränktheit zu Werke; aber doch hat das Schicksal ihr nothwendig das dunkle Gefühl eines Mißtrauens und eine geheime Verzweiflung gegeben, die zunächst dadurch sichtbar wird, daß, weil die ernsthafte Beschränktheit ohne lebendigen Ernst ist, sie im Ganzen nicht viel an ihre Sachen setzen kann, und darum auch keine großen oder höchst ephemerische Wirkungen thun kann. Sonst, wenn man will, kann man jene Unruhe auch als eine Gährung betrachten, durch welche der Geist aus der Verwesung der verstorbenen Bildung zu einem neuen Leben sich emporringt und unter der Asche hervor einer verjüngten Gestalt entgegenquillt. Gegen die Cartesische Philosophie nämlich, welche den allgemein um sich greifenden Dualismus in der Cultur der neueren Geschichte unserer nordwestlichen Welt, - einen *Dualismus*, von welchem, als dem Untergange alles alten Lebens, die stillere Umänderung des öffentlichen Lebens der Menschen, so wie die lauteren politischen und religiösen Revolutionen überhaupt nur verschiedenfarbige Außenseiten sind, - in philosophischer"}]}, {"page_pdf": 1418, "page_book": 17, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Form ausgesprochen hat, mußte, wie gegen die allgemeine Cultur, die sie ausdrückt, jede Seite der lebendigen Natur, so auch die Philosophie, Rettungsmittel suchen; was von der Philosophie in dieser Rücksicht gethan worden ist, ist, wo es rein und offen war, mit Wuth behandelt worden, wo es verdeckter und verwirrter geschah, hat sich der Verstand desselben um so leichter bemächtigt und es in das vorige dualistische Wesen umgeschaffen; auf diesen Tod haben sich alle Wissenschaften gegründet, und was noch wissenschaftlich, also wenigstens subjektiv lebendig an ihnen war, hat die Zeit vollends getödtet; so daß, wenn es nicht unmittelbar der Geist der Philosophie selbst wäre, der in dieses weite Meer untergetaucht und zusammengeengt die Kraft seiner wachsenden Schwingen um so stärker fühlt, auch die Langeweile der Wissenschaften - dieser Gebäude eines von der Vernunft verlassenen Verstandes, der, was das Aergste ist, mit dem geborgten Namen entweder einer aufklärenden oder der moralischen Vernunft am Ende auch die Theologie ruinirt hat, - die ganze flache Expansion unerträglich machen und wenigstens eine Sehnsucht des Reichthums nach einem Tropfen Feuers, nach einer Concentration lebendigen Anschauens und, nachdem das Todte lange genug erkannt worden ist, nach einer Erkenntniß des Lebendigen, die allein durch Vernunft möglich ist, erregen müßte. Es muß nothwendig an die Möglichkeit einer solchen wirklichen Erkenntniß, nicht bloß an jenes negative Durchwandern oder perennirende Aufschießen neuer Formen geglaubt werden, wenn eine wahre Wirkung von einer Kritik derselben, nämlich nicht ein bloß negatives Zerschlagen dieser Beschränktheiten, sondern von ihr eine Wegbereitung für den Einzug wahrer Philosophie erwartet werden soll; sonst, inwiefern sie nur die erste Wirkung sollte haben können, ist es wenigstens immer billig, daß Beschränktheiten auch die Prätension und der Genuß ihres ephemerischen Daseyns verbittert und abgekürzt wird; und wer mag, kann in der Kritik auch nichts weiter als das ewig sich wälzende Rad, das jeden Augenblick eine Gestalt, welche die Welle oben hinauf trug, hinunterzieht, erblicken; es sey, daß er auf der breiten Base des gesunden Menschenverstandes ruhend, seiner selbst sicher nur an diesem"}, {"type": "paragraph", "text": "objektiven Schauspiel des Erscheinens und Verschwindens sich weidet, und aus ihm selbst sich noch mehr Trost und Befestigung für seine Entfernung von der Philosophie holt, indem er a priori durch Induktion die Philosophie, an welcher das Beschränkte scheitert, auch für eine Beschränktheit ansieht; - oder daß er mit inniger und neugieriger Theilnahme das Kommen und Gehen der aufschießenden Formen bewundernd und mit vieler Bemühung aufgreift, dann mit klugen Augen ihrem Verschwinden zusieht, und schwindelnd sich forttreiben läßt. Wenn die Kritik selbst einen einseitigen Gesichtspunkt gegen andere ebenso einseitige geltend machen will, so ist sie Polemik und Parteisache; aber auch die wahre Philosophie kann sich gegenüber von der Unphilosophie des äußeren polemischen Ansehens um so weniger erwehren, da ihr, weil sie nichts Positives mit dieser gemein hat und darüber in einer Kritik sich mit ihr nicht einlassen kann, nur jenes negative Kritisiren und das Construiren der nothwendig einzelnen Erscheinung der Unphilosophie, und weil diese Regel hat und in jedem Individuum auch wieder anders sich gestaltet, auch des Individuums, in dem sie sich aufgethan hat, übrig bleibt. - Weil aber, wenn eine Menge eine andere Menge gegen sich über stehen hat, jede von beiden eine Partei heißt, aber wie die eine aufhört etwas zu scheinen, auch die andere aufhört Partei zu seyn, so muß eines Theils jede Seite es unerträglich finden, nur als eine Partei zu erscheinen und den augenblicklichen, von selbst verschwindenden Schein, den sie sich im Streit gibt, nicht vermeiden, sondern sich in Kampf, der zugleich die werdende Manifestation des Nichts der andern Menge ist, einlassen. Anderntheils wenn eine Menge sich gegen die Gefahr des Kampfs und der Manifestation ihres inneren Nichts damit retten wollte, daß sie die andere *nur *für eine Partei erklärte, so hätte sie diese eben damit für etwas anerkannt und sich selbst diejenige Allgemeingültigkeit abgesprochen, für welche das, was wirklich Partei ist, nicht Partei, sondern vielmehr"}]}, {"page_pdf": 1419, "page_book": 18, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "gar nichts seyn muß, und damit zugleich sich selbst als Partei, d.h. als Nichts für die wahre Philosophie, bekannt."}, {"type": "paragraph", "text": "Ueber das absolute Identitäts-System und sein Verhältniß zu dem neuesten"}, {"type": "paragraph", "text": "(Reinholdischen) Dualismus."}, {"type": "paragraph", "text": "*Ein Gespräch zwischen dem Verfasser und einem Freund.*"}, {"type": "paragraph", "text": "* Der Verfasser. *Was haben Sie denn hier, und was macht Sie auf eine so ungewöhnliche Art zu lachen? *Der Freund.* Was Sie hier sehen, sind Reinholds Beiträge zur leichteren Uebersicht der Philosophie; was mich aber zu lachen macht, ist eine Entdeckung über Sie, welche in dem dritten Stück vorkommt. *Der Verfasser.* Nichts weiter? Doch lassen Sie hören. Macht Reinhold Entdeckungen? *Der Freund.* Allerdings, und zwar keine geringeren, als daß Sie sich der Lehrsätze seines Lehrers als heuristischer Principien bedient, und, wiewohl allem Ansehen nach, ohne es selbst zu wissen und zu wollen, zugleich mit ihm (Reinhold nämlich) bei dem, was Sie die Absurdität selbst genannt haben, in die Schule gegangen seyen. Sehen Sie; hier S. 171 ist die Stelle. *Der Verfasser.* Freilich hier steht es, und wüßte man nicht gleich, wo man es hinzuthun hat und worauf es die Antwort seyn soll, so könnte man es denn doch als eine ganz originelle Erfindung bewundern. So aber ist es, außerdem daß es an sich keinen Sinn hat, noch überdieß eine ganz gemeine Retorsion. *Der Freund.* Es ist wahr; ich erinnere mich der Aeußerungen in der Vorrede zu der neuen Darstellung, Ihres Systems -"}, {"type": "paragraph", "text": "*Der Verfasser.* Ganz richtig, ich sage daselbst: es solle Reinhold hiemit förmlich erlaubt seyn, mich in Recensionen, Journalen etc. behaupten zu lassen, was ihm gut dünke, übrigens aber sich meiner Ideen und Methode als *heuristischen Princips *zu bedienen, welches (so setzt' ich hinzu) von gutem Nutzen seyn soll, und sogar gegen den Idealismus mit * aus ihm selbst genommenen*, nur auf dem Uebergang in seinen Kopf gehörig absurd gewordenen Ideen zu kämpfen. *Der Freund.* Sie sehen, er hat sich Ihre Erlaubniß schnell zu Nutze gemacht, und gleich unmittelbar bei ihr selbst angefangen, sie als heuristisches Princip zu brauchen. *Der Verfasser.* Uebersehen Sie nicht, daß er selber, schon früher nämlich, am Ende seiner Recension meines Idealismus, nöthig gefunden hat zu erklären, man werde sich meines Systems als heuristischen Princips vortheilhaft bedienen: was er damals sagte, und was er hier sagt, ist Ein Ding; nur der Ausdruck muß sich ihm umgekehrt haben. Damals beschied er sich noch, seitdem, sehe ich, hat er in seiner Schule auch gelernt unbescheiden zu seyn. Die Naivetät jener Aeußerung und das gute Zutrauen, daß ich mir es ganz ruhig würde gefallen lassen, glaubte ich nicht besser als durch die angeführte Erlaubniß erwiedern"}]}, {"page_pdf": 1420, "page_book": 20, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "zu können. *Der Freund.* Bemerken Sie aber wohl, daß er jener Aeußerungen von Ihnen mit keiner Sylbe Erwähnung thut. *Der Verfasser.* Desto besser! Da muß ich ja fast, so zu sagen, eine Spur von Verstand erblicken. *Der Freund.* Sie sehen aber wenigstens, mein Freund, daß Sie mit den kurzen und bloß beiläufigen Bemerkungen, wie die in jener Vorrede, nicht abkommen, sondern endlich sich doch werden entschließen müssen, den Zudringlichkeiten dieser Leute ein gründliches Ende zu machen und sie bei der Wurzel anzugreifen. Oder bekennen Sie wenigstens eine zu große Gleichgültigkeit gegen Ihre Gegner und für Ihre eigne Sache zu haben. *Der Verfasser.* Lieber Freund, Feinde und Gegner zu haben,"}, {"type": "paragraph", "text": "ist in dieser Zeit für eine Sache zu halten, welche zur Ehre gereicht und zum Gutseyn mit gehört. Dieser Reinhold aber ist mir von jeher ein langweiliger Geselle gewesen, so daß, mit ihm mich einzulassen, oder ihn zu meinen Gegnern zu rechnen, mich immer viel Ueberwindung gekostet hat. Seit er nun zwar in die geistige Ehe getreten ist, worin er sich, wie er sagt, auf das reine Empfangen einschränkt, ist er, ich gestehe es, ein unterhaltenderer Gegenstand für die Darstellung geworden, so daß ich es nicht verschwören will, einmal gute Laune und Muße an ihn zu wenden. Ihn zu widerlegen oder mich gegen ihn zu vertheidigen, habe ich noch nie nöthig gefunden. *Der Freund. *Einer Kritik des Reinholdischen sogenannten Systems sollen Sie auch ferner überhoben seyn; es ist dazu genug, daß man Ihre Grundsätze kennen lerne, da es für jeden, der diese faßt und jenes kennt, das Zeichen des Thiers schon an der Stirne trägt, und als ein Dualismus von der rohesten Art eine weitere Beurtheilung seiner inneren Beschaffenheit und Wesen nach eben nicht erfordert. So arm ist auch die deutsche Welt noch nicht an Kritikern, daß ihm das nöthige Recht nicht widerfahren sollte. Dazu sind die Würzburger, ja sogar die Tübinger Gelehrten Anzeigen vollkommen hinreichend. Was Reinhold selbst betrifft, so befindet er sich zu tief unter der Idee, von welcher man nur anfangen könnte ihm mit einer Beurtheilung verständlich zu werden, und diese Geistesknechtschaft muß, wie jede andere, durch die er gegangen ist, ihre gesetzte Zeit dauern, ehe man hoffen kann ihm irgend etwas beizubringen. Er muß immer erst das Ende und den Gipfel des Unsinns vor sich sehen, ehe er aufhört. Was sein Betragen betrifft, so hat er den Vortheil, sich ohne Scheu alles erlauben zu dürfen, weil er nichts mehr zu verlieren hat. Eine Sache aber, die nicht beurtheilt werden kann, ist doch wenigstens fähig charakterisirt zu werden. *Der Verfasser.* Auch ist dieß meine Meinung, nur muß man ihr erst Zeit lassen sich selbst zu charakterisiren. Die geheime Furcht, das Gefühl der Nullität, das diese Art der Eingeschränktheit ängstiget, bringt sie endlich unfehlbar zur Verwirrung, und zwingt so die Trübseligkeit"}, {"type": "paragraph", "text": "selbst, durch ihre Krümmungen und Wendungen kurzweilig zu werden. Meine Maxime ist, daß man in jedem solchen Fall den Moment des höchsten Ausbruchs erwarten muß, um die Sache aufs kürzeste abthun zu können. *Der Freund.* Diesen Moment haben Sie, was Reinhold betrifft, wirklich erwartet, und es scheint mir, daß Sie sich eben über diesen Punkt am ehesten auf mein Urtheil verlassen dürfen, da ich entfernt von allem eignen Antheil an diesem Schauspiel, und keine Stelle einnehmend, wo ich jemanden oder jemand mir zu nahe treten könnte, gleichwohl meinem Interesse für den Gegenstand so viel historische Kenntniß der Sache und der Personen verdanke, um zu bemerken, wie Ihr Schweigen und Ihre wohlbekannte"}]}, {"page_pdf": 1421, "page_book": 22, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Geringschätzung auch dieser Schwachherzigkeit Muth macht, die sich, wie Sie sehen, auf die bisher gebrauchten, eben auch nicht löblichen Mittel nicht mehr einschränkt, sondern in ein neues Fach übergeht. Diese letzte Erfindung, so schlecht sie ist ihrem Ursprung nach, so widersprechend nothwendig und ihm selbst verderblich im Fortgang, kann Ihnen denn doch zeigen, daß Sie dem Reinhold künftig genauer auf die Finger sehen müssen. *Der Verfasser.* Ruhig, lieber Freund, was nöthig ist, wird geschehen. Ich verspreche mir von dieser neuen Wendung auch noch anderes. Er wird nicht umhin können uns selbst einige hervorragende Zipfel seines Systems in die Hand zu geben, die wir nur aufheben dürfen, um die saubern Dinge, die darunter verborgen sind, und die er, so oft sie hervorgezogen werden, immer wieder hübsch zuzudecken sucht, oder sich anstellt von ihnen nichts zu wissen, an den Tag zu fördern. Er wird uns die Mühe abnehmen; wir dürfen ihn nur machen lassen, sicher, daß er sich selbst um den Hals rede. Ich vermuthe auch in den Beweisen einen überschwänglichen Fond von Belustigung. Doch damit ich der Sache gewiß werde, so bitte ich Sie, ehe wir weiter gehen, mich genauer zu unterrichten, welche Bewandtniß es mit seiner Entdeckung hat. *Der Freund.* Den ersten Stoß also hat ihm die neue Darstellung des Systems der Philosophie beigebracht. Wenn Sie aber"}, {"type": "paragraph", "text": "glauben, daß diese allein hingereicht, so irren Sie sich, lieber Freund. Denn freilich, daß Ihr System überhaupt, und so, wie es in dem letzten Heft Ihrer Zeitschrift dargestellt ist, insbesondere, sich mit dem, was er jetzt Philosophie nennt, schlecht vertrage, und ihr ihn alle Wege entgegengesetzt seyn müsse, konnte er, wenn auch nur aus den kleinen unbeliebigen Aeußerungen über ihn in der Vorrede, noch wohl ohne fremde Hülfe begriffen und einigermaßen ermessen haben. Es hätte aber lange Zeit währen können, ehe er den eigentlichen Punkt der Entgegensetzung herausgefunden und es darüber zu etwas mehr als einem dunkeln Gefühl gebracht hätte, wäre nicht glücklicher oder vielmehr unglücklicher Weise ein Recensent in der Erlanger Lit. Zeitung erschienen, der ihm darüber die Augen öffnete, indem er den herausgehobenen Hauptpunkt jener Darstellung den unglaublichen Mißverständnissen, Verdrehungen und Entstellungen der neuen Philosophie, welche jener sich zu Schulden kommen läßt, nicht minder als seinen eignen Lehrsätzen auf eine Weise entgegenstellte, bei der freilich der diametrale Gegensatz beider und die traurige Nackt- und Bloßheit der letztern in ein sehr helles Licht kam. *Der Verfasser.* Kennen Sie den Recensenten? Seine Arbeit schien mir ein Verdienst um die Wissenschaft. *Der Freund.* Ich kenne ihn nicht, aber Reinhold versichert, daß Sie ihn kennen, daß er zu Ihren Freunden, Ihren Schülern, zu Ihrer bis daher, wie er sich ausdrückt, esoterischen Schule gehöre. *Der Verfasser.* Ich versichere, daß mir seine Person völlig unbekannt ist, und daß von alle dem, meines Wissens, kein Wort wahr ist. - Auch schien er mir eben nicht überall meinen Sinn getroffen zu haben. *Der Freund.* Solche Insinuationen erlauben sich die, welche alle Mittel und Wege, wär' es auch nur das frische Herzeleid, das ihre Gegner den Redaktoren eines gelehrten Blattes angethan haben, benutzen, um lobpreisende Recensionen ihrer Sachen in gelehrte Zeitungen zu bringen. *Der Verfasser.* Das lohnt sich der Mühe nicht. Lassen Sie weiter hören."}, {"type": "paragraph", "text": "*Der Freund.* Nachdem nun der Riß, welchen zunächst die unerwartete Recension, entfernter Weise"}]}, {"page_pdf": 1422, "page_book": 24, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "die unerwartete Darstellung Ihres Systems in das Lehrgebäude gemacht hatten, durch eine *neue Darstellung*, zu welcher man dorther, in aller Geschwindigkeit die Mittel borgte, neu übertüncht, und die schönen Lehrstücke, welche durch jene an den Tag gebracht worden, dem Licht entzogen und vorläufig wieder zugewühlt waren; nachdem man ferner bemerkt hatte, daß alle diese Verrenkungen und sämmtliche Nachhülfen (die Sie noch müssen kennen lernen) nicht gehörig verfangen wollen und doch nur kurze Frist verleihen: so gab dann die Verwirrung, in die man dadurch gerathen war, und die Furcht, daß die kleinen Handgriffe nicht unbemerkt bleiben möchten, erst den Gedanken, lieber das Zuvorkommen zu spielen, und dann die weitern Maßregeln ein, von denen Sie jetzt mehr hören sollen. Sie hatten in der letzten Darstellung Ihr System, das Reinhold in dem letzterschienenen Heft seiner Beiträge auf alle Weise aus seiner Stelle zu rücken und zu verunstalten gesucht hatte, eigends wieder zurechte gerückt; da er sich nun dadurch rechts und links beengt fühlte, so mußte er es sich vorläufig wieder in die Lage bringen, worin er es zu sehen gewohnt war, um auf diese Weise seiner Meister zu werden. *Der Verfasser.* Ich wette, daß ihm dieses um so leichter geworden ist, da er nur nöthig hatte, sich selbst zu übertreffen. *Der Freund.* Sie können überzeugt seyn, er hat es in allen seinen Fugen, Theilen und Zügen so verdreht, entstellt und verzerrt, daß Sie es selbst nicht wieder kennen sollten. Doch hören Sie selbst (er liest von Seite 165-168 des angeführten Stücks der Beiträge1). - Wie nennen Sie diese Manier? *Der Verfasser. *Wir werden sie am kürzesten und billigsten von ihrem Urbild und höchsten Muster die Fr. Nicolaische Manier nennen. Denn es ist offenbar, daß Reinhold, nachdem er sich darauf zu legen angefangen, in dieser Kunst bereits keinen andern Meister mehr über sich erkennt als den unvergleichlichen und unübertrefflichen Fr. Nicolai."}, {"type": "footnote", "text": "1 Wir wollten mit dem Abdruck dieser Stelle das Papier nicht verderben, und überlassen sie daher dem Leser selbst nachzusehen."}, {"type": "paragraph", "text": "*Der Freund. *Vergessen Sie nicht den andern Theil dieser Manier, welcher darin besteht, den Gegner mit einem Schwall von Geschwätz zu übergießen, alle Schleusen des Unsinns aufzuziehen, und alles in eine solche Wasserfluth zu setzen, daß nichts mehr kenntlich oder von dem andern unterscheidbar ist. In dieser Kunst des grund-, boden- und endlosen Geschwätzes hat er das Urbild bereits nicht nur erreicht, sondern sogar übertroffen. *Der Verfasser.* Freilich von dem kräftigeren Geist, der sich nach Fichtes Antwortschreiben in seinem Buchstaben rühren sollte, habe ich eben auch noch nichts verspüren können. *Der Freund.* Wenn die Kraft nicht etwa in dem tüchtigen Unterstreichen liegt. *Der Verfasser.* Auch das hat er schon zu sehr abgenutzt. Ich wollte ihm schon lange den Rath geben, sich beim Druck mitunter statt der schwarzen der rothen Dinte zu bedienen, welche besonders bei den *Als *und *Inwiefern* und *Insoweit *vortreffliche Dienste leisten müßte. Sehen Sie aber doch zu, ob wir aus dieser Ueberschwemmung einige Brocken herausfischen und zur Betrachtung bringen können! *Der Freund.* Das Erste, was man sich ohngefähr daraus nehmen kann, ist, daß er Ihr System für ein Produkt aus Spinozismus und Idealismus hält. Daß dieß in seinem Kopf sich so gefunden, der sein ganzes Leben in nichts als Zusammenkneten und Zusammenleimen sich geübt hat, verwundert mich nicht; denn sonst wird diese Vorstellung nicht leicht bei einem vernünftigen Menschen angetroffen werden, da Sie sich, man sollte glauben, deutlich genug über diesen Punkt erklärt haben. Mir schien Ihre Meinung über Spinozismus und Idealismus immer diese zu seyn, daß nämlich jedes dieser Systeme für sich schon den Punkt enthalte, der aus der Einzelnheit eines jeden herausgehoben zugleich als der absolute"}]}, {"page_pdf": 1423, "page_book": 25, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Indifferenzpunkt aller speculativen Wahrheit und beider Systeme erscheinen müßte, so daß nicht eines durch das andere ergänzt, sondern jedes für sich selbst das Ganze, beide also nicht relativ oder synthetisch, sondern absolut eines seyen, so wie es mir hinwiederum schien, daß, widersprächen sich beide wirklich, alsdann"}, {"type": "paragraph", "text": "nach Ihrer Meinung der Grund dieses Widerspruchs nicht zwischen beiden, sondern in jedem für sich betrachtet liegen müßte. *Der Verfasser.* Im Allgemeinen ist dieß allerdings mit meiner Ansicht davon übereinstimmend. Das Besondere dieses Verhältnisses aber konnte nur in der Folge meiner Darstellung vorkommen, und ganz vorzüglich sollte Reinhold, der nachgerade wohl wissen könnte, wie kurzbeschnittene Flügel er hat, dem Buchstaben nach-, geschweige vorzufliegen, sich beschieden haben, darüber etwas zum voraus zu wissen. Das Wesentliche davon aber ist Folgendes. Wie man auch die höchste Idee der Philosophie in Worte fasse, ob sie als absolute Identität des Denkens und der Ausdehnung, des Ideellen und Reellen, oder wie sonst ausgesprochen werde, denn alle diese verschieden scheinenden Ausdrücke sind ziemlich gleichbedeutend, so enthält sie doch von allen diesen Gegensätzen an sich betrachtet weder das eine noch das andere, sondern dasselbe dem Wesen nach, was ideal ist, ist zugleich auch real, dasselbe, was denkt, auch das, was ausgedehnt ist, so daß, wofern die Einheit nur wirklich als absolut gedacht wird, in der Natur desjenigen, was durch jene Idee bezeichnet wird, auch alle Dinge ohne einigen Unterschied des Seyns und Nichtseyns, der Möglichkeit und der Wirklichkeit, mit Einem Wort auf eine nichtzeitliche, ewige Weise enthalten und ausgedrückt seyn müssen, und also auch nur durch und gleichsam an jener Trennung des Denkens und Seyns, welche mit dem Bewußtseyn und für das Bewußtseyn gesetzt wird, heraustreten aus der Ewigkeit, sich absondern von dem All und in ein zeitliches Daseyn übergehen. Jene im Bewußtseyn und zum Behuf des Bewußtseyns nothwendige Trennung dessen, was wir in jener Idee als vereinigt gesetzt haben, geschieht aber, weil eins nur an dem andern, der Leib nur an der Seele, die Seele nur an dem Leib sich absondern kann von der Ewigkeit, nothwendig so, daß zugleich auf der einen Seite das Denken als gesetzt durch das Seyn, auf der andern das Seyn als gesetzt durch das Denken, und der eine absolute Indifferenzpunkt in zwei entgegengesetzte relative Brennpunkte getrennt erscheint. Denn wie von selbst erhellet, so ist auch die Trennung, die"}, {"type": "paragraph", "text": "im Bewußtseyn gesetzt ist, bloß relativ, indem Denken und Seyn doch nicht auseinanderkommen, sondern eins bleiben, nur daß wechselsweise, indem das eine durch das andere, auch hinwiederum dieses durch jenes bestimmt und gesetzt wird. Der wahre Idealismus beruht einzig auf dem Beweise, daß außerhalb des Bewußtseyns und abgesehen von ihm jene Trennung gar nicht existire; da nun eben durch dieselbe und allein durch sie das All sich öffnet, die gesammte Erscheinungswelt sich herauswirft aus dem, worin alles eins und nichts unterscheidbar ist, so ist der Idealismus in Ansehung der Erscheinungswelt oder gegenüber vom Endlichen positiv, negativ in Bezug auf jenes Außerhalb des Bewußtseyns, in Ansehung dessen der Realismus oder Spinozismus kategorisch und positiv ist. Diese Aussage des Idealismus: \"das Seyn ist nicht an sich abgesondert vom Denken, ebensowenig das Denken von dem Seyn\" hat Fichte nicht nur überhaupt mit der höchsten Klarheit aufgestellt, sondern dasselbe auch aufs bestimmteste durch sein Princip und das, was er als Charakter desselben angibt, ausgesprochen. Das Ich, welches nichts anderes als der höchste Ausdruck jenes Absonderungsakts ist, ist nach ihm reiner"}]}, {"page_pdf": 1424, "page_book": 27, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Akt, nichts als sein eignes Thun, nichts unabhängig von seinem Handeln, überhaupt bloß durch und für sich selbst, nichts also an sich oder in Ansehung des Absoluten, ebenso auch alles, was mit dem Ich und eben deßwegen auch nur für das Ich abgesondert ist von der Allheit. Mehr als diese negative Seite der Philosophie kann im Idealismus als Idealismus nicht dargestellt werden. Die erste Bemerkung dieser nothwendigen Schranken des Idealismus und Hinweisung auf das, was außer ihnen liegt, findet sich schon in den Briefen über Dogmatismus und Kriticismus, deren Sinn manchem vielleicht jetzt eher aufgehen möchte, als es bei ihrer ersten Erscheinung der Fall seyn konnte. Was aber der Reinhold von dieser Sache vorbringt, beweiset nur, was wir längst gewußt, daß er noch immer nicht einmal die Anfangsgründe des Idealismus gefaßt hat. *Der Freund. *Ich glaube nun deutlich zu sehen, daß der Gegensatz von Naturphilosophie und Transscendentalphilosophie bei Ihnen keinen andern Sinn haben kann, als es hat, wenn Spinoza das erste"}, {"type": "paragraph", "text": "Buch seiner Ethik de natura, von der Allheit, und das zweite de mente, oder von dem Ich, überschrieben hat. *Der Verfasser.* Keinen andern. * Der Freund.* Haben Sie bemerkt, wie Reinhold den Ausdruck speculative Physik mißbraucht, den Sie der Naturphilosophie geben, sofern sie vom System der Philosophie abgesondert und als eine eigne Wissenschaft von den in jenem bestimmten Principien aus weiter fortgeführt werden kann? Er gebraucht diese Bezeichnung für sie, insofern sie integranter Theil des Systems selbst ist, und bringt auf diese Weise heraus: Ihre Philosophie sey transscendentalphilosophisch und speculativphysisch zugleich. *Der Verfasser.* Dieß verdiente in der N. Allg. deutschen Bibliothek gedruckt zu stehen. Doch lassen Sie uns weiter gehen. War da nicht von einer Stelle die Rede, worin ich sagte, daß Natur- und Transscendentalphilosophie die beiden ewig entgegengesetzten seyn müssen, und ließ er nicht so etwas verlauten, als hätte die eine und gleiche Wahrheit der beiden mir erst jetzt aufzugehen angefangen? Ueberzeugen Sie mich mit meinen Augen, daß Reinhold das Letzte wirklich gesagt hat, denn was das Erste betrifft, so ist es noch jetzt meine Meinung. *Der Freund.* Ueberzeugen Sie sich ; hier S. 167. *Der Verfasser.* Lieber Freund, da wir doch Willens scheinen, den Spaß weiter fortzusetzen, und diesem würdigen Mann ganz den Proceß zu machen, haben Sie doch die Güte, die nöthigen Aktenstücke herbeizuschaffen. *Der Freund.* Sie finden diese hier alle schon beisammen; auch die Blätter der A. Lit. Zeitung, worin die Recension des Idealismus abgedruckt ist. *Der Verfasser.* Vortrefflich. Die erst angeführte Stelle steht hier S. IX der Vorrede zum System des Idealismus (Bd. III, S. 331). Was ich in jener Stelle leugne, ist eben das, was er jetzt einfältig genug mir zuschreibt, versucht zu haben, die Möglichkeit einer Vereinigung beider Wissenschaften durch Synthese. Es wäre ihm sehr gut gewesen, wenn er die Stelle richtig verstanden und gehörig benutzt hätte."}, {"type": "paragraph", "text": "*Der Freund.* So viel ich durch Sie selbst von der Construktion Ihres Systems erfahren habe, so sind jene beiden entgegengesetzten in demselben wirklich getrennt, ja es ist als System ohne jene Trennung nicht einmal zu denken. Sprechen Sie nicht schon in dem Anfang Ihrer Darstellung von einer reellen und ideellen Reihe, und welchen Sinn hätte ohne jene Trennung der Indifferenzpunkt? - Besonders klar schien mir, was Sie mit Anwendung des Satzes, den Sie an einem Orte über das Wesen des Organischen"}]}, {"page_pdf": 1425, "page_book": 29, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "aufgestellt haben, von der Gestalt des Universum und der ihr ähnlichen der Philosophie geäußert haben, nämlich daß sie nach außen indifferent sey, nach innen aber nothwendig aus zwei entgegengesetzten Quellpunkten das allgemeine Leben und Bewegung verbreite. *Der Verfasser.* Ganz richtig, und dasselbe läßt sich auch schon aus dem eben von uns Verhandelten einsehen, daß, wenn das Seyn nur an dem Denken, das Denken an dem Seyn sich absondert vom Ewigen, alsdann auch jene absolute Identität beider, worin alles begriffen ist, sich im Bewußtseyn und für das Bewußtseyn nur durch zwei entgegengesetzte Identitätspunkte darstellen und ausdrücken kann. Jeder dieser Punkte ist nur durch den andern, aber eben deßwegen keiner an sich; an sich ist nur das, worin sie absolut eins sind, und der nur mit den Augen der Vernunft zu erblickende Centralpunkt beider. So wie jene bloß relativen Indifferenzpunkte getrennt sind, sind es auch Naturphilosophie und Transscendentalphilosophie, die eben durch ihre Trennung gesetzt sind. *Der Freund.* Das Merkwürdigste ist, daß Reinhold in der angeführten Recension Ihres Idealismus davon selbst etwas eingesehen zu haben schien, denn er sagt ausdrücklich (S. 365): Jedes von beiden (Natur und Ich in Ihrem Sinne) schließt nur durch seine Relativität das andere aus, begreift aber durch seine Absolutheit das andere in sich. *Der Verfasser.* Wir werden, wenn ich nicht irre, in dieser Recension noch andere Merkwürdigkeiten der Art finden. * Der Freund.* Der Mißgriff eines Idealismus, der einen Realismus mit sich im Gegensatze hätte, müßte nach dieser Vorstellung"}, {"type": "paragraph", "text": "darin bestehen, daß, da er eine absolute Identität des Denkens und des Seyns als Princip setzen muß, er doch das Seyn nur durch das Denken bestimmt seyn läßt, also von jenen beiden relativen Indifferenzpunkten nur den einen auffaßt, den absoluten aber im Fortgang des Systems ganz verliert; denn von diesem angesehen, kann das Seyn an sich ebensowenig durch das Denken als das Denken durch das Seyn bestimmt seyn, da beide vielmehr absolut eins sind vermöge der höchsten Idee. *Der Verfasser.* Hierüber wäre noch vieles zu reden, mein Freund, wozu wir jetzt die Muße nicht finden möchten. Nothwendig aber zum Setzen des Absoluten ist, daß es nicht zugleich, sondern vielmehr auf völlig gleiche Weise als unendliche Realität und unendliche Idealität gesetzt werde. Denn es kann als Absolutes nur unter der Form der Antinomie gesetzt werden, und, indem die Forderung an die Vernunft geschieht, es als beides auf völlig gleiche Weise zu denken, so wird es, weil eins das andere ausschließt, nothwendig als dasjenige gedacht, was an sich weder das eine noch das andere, aber eben deßwegen absolut ist. So bald es fixirt wird unter dem einen dieser beiden Reflexionsgegensätze, so daß es entweder bloß als unendliches Seyn oder als unendliches Denken ohne alle Antinomie gedacht wird, sind wir auch aus der Sphäre der wahren Absolutheit heraus in der einer bloß relativen; so wie wir dagegen, wenn es als beides zugleich gedacht werden soll, in der Sphäre der Endlichkeit, der Limitation und der Theilbarkeit uns befinden. Alle diese Bestimmungen und die Unterschiede dieser Bestimmungen sind wesentlich, um den Eingang in jedes speculative System, besonders den Spinozismus und dasjenige, welches meinen Darstellungen zum Grunde liegt, zu finden. Gleichwie nun die höchste Existenz, die des Absoluten, auf jener völligen Untrennbarkeit und der totalen Gleichgültigkeit beruhet, jetzt als Erkennen und dann nicht als Seyn, jetzt als Seyn und dann nicht als Erkennen gedacht zu werden, so muß auch alles wahrhaft Existirende, insofern es als solches gesetzt wird, nicht zugleich, sondern vielmehr auf völlig gleiche Weise als modus der Idealität und der Realität, als Seele und als"}]}, {"page_pdf": 1426, "page_book": 31, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Leib gedacht werden, so daß wahrhaft und an sich betrachtet eigentlich weder das eine noch das andere existirt, sondern das Untheilbare und absolut Identische beider, das wir weiter nicht bestimmen können, ohne es unter dem einen dieser Attribute zu setzen. Bei dieser Beschaffenheit der Sache muß, wie auf der einen Seite durch die Endlichkeit des Seyns das unendliche Denken der allgemeinen Identität entrissen und als Denken gesetzt wird, hinwiederum auf der entgegenstehenden durch die Endlichkeit des Denkens das unendliche Seyn der Allheit entzogen und als Seyn gesetzt werden, so daß nach zwei entgegengesetzten Richtungen gleichwohl nie bloß das eine oder das andere, sondern das unveränderlich Identische beider gesetzt werde, und alle Bestimmung durch Idealität und Realität eine bloß relative sey. Denn was Sie im Gegensatz gegen ein anderes als ein Seyn setzen, z.B. den Leib im Gegensatz gegen die Seele, ist, an sich selbst betrachtet, nicht minder ein modus des Erkennens als jenes, so wie in der Leibnizischen Lehre der Leib ebenso wie die Seele, an sich betrachtet, selbst wieder eine Monas ist. *Der Freund.* Wenn also auch Idealismus und Realismus als völlig entgegengesetzte Systeme angesehen werden könnten, so daß es möglich wäre zu sagen, jener betrachte die Dinge bloß unter dem Attribut des unendlichen Erkennens, dieser unter dem des unendlichen Seyns, obgleich dieß freilich in Ansehung des wahren Idealismus so wenig der Fall ist als in Ansehung des wahren Realismus, so wären doch beide, vorausgesetzt, daß nur jedes in seiner Art vollkommen sey, ebenso nothwendig eine und dieselbe Wissenschaft von ganz gleichem Inhalt, als es nothwendig ist, daß jedes Ding, obwohl auf völlig gleiche Weise, modus des Erkennens und des Seyns, dennoch nur ein und dasselbe sich selbst absolut gleiche Ding von Einem Gehalt und Wesen ist. *Der Verfasser.* So ist es, und es durfte auch bloß in derselben Vorrede weiter gelesen werden, was gleich nachher von der* ganz gleichen* Realität, d.h. doch wohl der Indifferenz beider Wissenschaften in theoretischer, rein speculativer Rücksicht gesagt ist, um zu"}, {"type": "paragraph", "text": "begreifen, was es mit der Entgegensetzung beider für eine Bewandtniß habe. *Der Freund.* Auch hat Reinhold nicht unterlassen, das völlig zu verdrehen, was Sie dort von der rein theoretischen Betrachtung sagen. *Der Verfasser.* Ich verstehe darunter nichts anderes, als was ich an einer andern Stelle rein objektives Philosophiren, Philosophiren ohne alle Einmischung von praktischem Interesse genannt habe, kurz das entgegengesetzte des Reinholdischen, das die schalen Subjektivitäten seines dürftigen Geistes unter dem Namen der Liebe und des Glaubens an Wahrheit verbirgt. Daß dort nicht von praktischer Philosophie in dem Sinn die Rede sey, in welchem sie selbst ein nothwendiger Theil der rein-theoretischen oder eigentlichen speculativen Philosophie ist, hätte er eben daraus sehen können, daß ihr in demselben Zusammenhange aller Einfluß auf das reine Theoretisiren abgesprochen wird. *Der Freund.* Lieber Freund, dann hätte er Ihnen auch nicht beweisen können, daß Sie die eine und selbe Wahrheit unter den beiden verschiedenen Formen erst jetzt zu sehen angefangen, und daß Sie die Augengläser dazu sich von dem Lehrer haben machen lassen. *Der Verfasser.* Die optische Täuschung über den letzten Punkt ist leicht zu erklären. Denn daß freilich er und der Lehrer uns andere mit Augengläsern versehen wollten, ist uns zur Genüge bekannt, nur behauptete ich, daß sie dabei nach Art des heiligen Crispinus verfahren, unsere eignen entwendet, und statt dieser, welche scharf waren, dieselben mattgeschliffen zurückgeben wollten. *Der Freund.* Sonst sagt man: der Lügner muß ein gutes Gedächtniß haben. Hier trifft es auch den Verdreher und Verfälscher. Wenn er auch albern genug ist sich einzubilden, Ihre Philosophie vor dem Publikum entstellen zu können, so sollte er doch so viel Verstand behalten, es nicht auf solche Weise zu machen, daß man ihn selbst gegen ihn selbst als Zeugen stellen kann. Hier, in dem dritten Heft berichtet er: sich von dem Ich und der Natur zu der absoluten Identität beider zu erheben, sey ein Gedanke, der"}]}, {"page_pdf": 1427, "page_book": 32, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Ihnen erst gekommen,"}, {"type": "paragraph", "text": "Ihre Philosophie, die sich darauf gründet, eine ganz neue Wissenschaft. Nun lesen Sie folgende Stelle aus seiner Recension Ihres Idealismus. *Der Verfasser.* \"Unbedingte Identität des Objektiven und Subjektiven ist das Thema und Princip dieser Philosophie; und es läßt sich schon vor aller weitern Untersuchung mit völliger Gewißheit wissen, daß sie kein anderes Resultat herausbringen könne, als was sie schon in ihre Aufgabe hineingelegt hat: *\"daß sich nämlich über die Natur und das Ich hinaus nichts weiter denken lasse als die absolute Identität von beiden, daß beide nur insofern reelle Wahrheit und Gewißheit haben, als sie schlechthin eines und dasselbe sind, daß die Natur in ihrem Unterschiede vom Ich bloße Erscheinung des Ichs, das Ich in seinem Unterschiede von der Natur bloße Erscheinung der Natur, beides aber an sich und für sich selbst betrachtet und der reellen Wahrheit nach das All-Eins sey.\" * (Jen. Allg. Lit. Zeit. August 1800. S. 363). *Der Freund.* Seite 365 finden Sie folgende Aeußerung: \"durch die Wiederherstellung der *nur zum Behuf der Erklärung aufgehobenen *Identität werde diese als unbedingtes im Objektiven und Subjektiven nichts als sich selbst bedingendes All-Eins *auch im Wissen des Philosophen *bewährt, undso* die reine Wahrheit *gefunden.\" Ferner, denn er hat es auch hierin wie in nichts an reichlichem Auseinandersetzen ermangeln lassen, S. 369: \"Um das einzige schlechthin ursprüngliche Wahre und Gewisse als solches kennen zu lernen, muß sich der Transscendentalphilosoph über jede bloße *Erscheinung *desselben emporschwingen, folglich sowohl von seinem empirischen Ich als den sich demselben ankündigenden (empirischen) Objekten schlechthin abstrahiren, die *unbedingte Dieselbigkeit *in ihrer ursprünglichen Entzweiung denken und beschauen.\" *Der Verfasser.* Eine Stelle, die gar keinen Zweifel läßt, steht S. 371, wo gesagt wird: \"Realismus und Idealismus, wovon jener der Naturphilosophie, dieser der Transscendentalphilosophie gleich gesetzt wird, seyen nur verschiedene, jedoch nothwendig aufeinander"}, {"type": "paragraph", "text": "zurückweisende Ansichten *von einem und demselben sich selbst bedingenden Unbedingten.\" Der Freund.* Nun sollen Sie die eine und gleiche Wahrheit in beiden zuvor nicht gesehen haben. *Der Verfasser.* Sie brauchten nicht einmal so weit zurückzugehen, denn noch bestimmter wo möglich steht dasselbe noch in dem ersten Heft der Beiträge S. 86, wo es heißt: \"das Urwahre oder reelle Absolute in die Alleinigkeit oder Dieselbigkeit des Ichs und der Natur, in die absolute Identität von beiden zu setzen, war Schellingen aufbehalten. Die Transscendentalphilosophie oder die reine Wissenslehre und die Naturphilosophie oder die reine Naturlehre sind nur zwei verschiedene Ansichten von* einer und derselben Sache*, von der absoluten Dieselbigkeit, dem Alleins.\" *Der Freund.* Wie hat sich denn nun zwischen dem ersten und dritten Heft das Blatt so gewendet, daß er jenem Ihnen zum Vorwurf macht, über dem Ich, und der Natur die absolute Dieselbigkeit beider als das Urwahre zu setzen, und jetzt, da er sieht, daß dieß allerdings der Fall ist, sich gar nicht mehr erinnern kann, daß er dieß selbst für Ihr Princip ausgegeben? *Der Verfasser.* Wenn dieß Dummheit ist (wie ich denn nicht zweifle), so ist sie von der exemplarischen Art; denn es will mir nicht gefallen, daß Sie ihn einen Verfälscher nennen, da Sie sehen, daß es ihm hierzu am gemeinsten Theil gebricht. *Der Freund.* Wie wollen Sie aber eine solche exorbitante Erscheinung selbst begreiflich machen? *Der Verfasser. *Nichts scheint mir einfacher zu seyn. Es braucht dazu nichts weiter angenommen zu"}]}, {"page_pdf": 1428, "page_book": 34, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "werden, als daß er niemals eigentlich gewußt habe, was er dort niedergeschrieben, und daß er gleich anfänglich nicht verstanden, was er jetzt nicht versteht, so, daß er eigentlich es zu verstehen niemals aufgehört, weil er nie angefangen hat, und jetzt nur sich auflehnt, weil er gezwungen wird, etwas bei dem zu denken, was er bisher ganz gedankenlos gelesen und ebenso gedankenlos wieder niedergeschrieben hatte, wofür überdieß noch viele"}, {"type": "paragraph", "text": "andere Spuren als Beweise angeführt werden könnten. Denn in derselben Recension finden Sie ja Mißverständnisse und Einwürfe genug, welche deutlich zeigen, daß er alle jene Aeußerungen zu Papier gebracht, ohne das Geringste dabei zu denken. Genügt aber Ihnen dieses nicht, so überlegen Sie, da dieß allerdings an die Verrücktheit zu grenzen scheint, wie ansteckend diese ist, und wie receptibel in dieser Rücksicht sich Reinhold auch sonst gezeigt hat. So führt er in der eben vorgelesenen Stelle an: der Transscendentalphilosoph erhebe sich über jede bloße Erscheinung und abstrahire demnach vor allem andern *ganz von dem empirischen Ich; *dessen unerachtet läßt er sich jetzt durch den Lehrer beschwatzen, und sich aufbinden: die Ichheit in unserm System sey die palpabelste Individualität (Beitr. I, S. 159), was sich dieser wohl nach seiner Verstocktheit in den Kopf gesetzt haben mag und sich gewiß auch in seinem Leben nicht daraus vertreiben läßt. Und aus diesem Begriff führt Reinhold jetzt seine siegreichen Beweise gegen Fichte und mich. * Der Freund.* Das Letztere erklärt nicht ganz, denn wie aus seinem gedruckten Bericht erhellet, so hat er den eignen Verstand schon seit dem Februar 1800 gänzlich untergekriegt (Beitr. I, S. 163). Es hätten sich also schon in jener Recension, die vom August, und der angeführten Abhandlung, die von einem noch spätern Datum ist, die Spuren der Verstandesverwirrung zeigen müssen. *Der Verfasser.* Auch zeigen sie sich, nur ist der höchste Grad noch nicht erreicht; in dem letzten Heft der Beiträge gesellen sich zu den ersten Gemüthsbewegungen noch mehrere andere, die der gekränkten Eitelkeit, welche nicht nur den Verstand verwirrt, sondern selbst die Sinne benebelt, so daß, hätte man ihm auch jene Stellen vorgelegt, er doch mit sehenden Augen nicht gesehen hätte; hierauf die Angst, da es nun nicht mehr zu verbergen ist, daß, was er und der Lehrer gegen uns vorbringen - wollten, von uns selbst aufgehörte Ideen sind, die sie nur nicht zu brauchen wußten, und über die Ihnen das rechte Verständniß erst geöffnet werden mußte; dann die Verzweiflung, da er weiß, daß er für seine Sache keine andern Waffen hat als sein"}, {"type": "paragraph", "text": "Geschwätz, das ihm jetzt auf einmal gelegt schien. Er erfährt aus meiner Darstellung, daß der Idealismus keineswegs von der palpabelsten Individualität ausgehe; das ist ein zu starker Schlag vor den Kopf, denn dieß wenigstens glaubte er unumstößlich gewiß. Nun paßt das alte auswendig gelernte Pensum über den Idealismus nicht mehr. Es hat also vorläufig mit dem Geschwätz ein Ende. *Der Freund.* Auch hört man dieses Angstgeschrei der Unsicherheit, die nur Zeit will, um es mit Suchen und Tappen endlich noch zu etwas zu bringen, besonders stark in den Blättern gegen Fichte. Er läßt mich, ruft er zu wiederholten Malen aus, gar nicht ausreden, ja er will mich nicht einmal zum Sprechen kommen lassen, und ich habe doch noch so viel zu schwatzen, so viel zu erläutern, so viel Modificationen beizubringen. *Der Verfasser.* Muß er nun nicht aus allen Leibeskräften sich bestreben, mein System seinem eignen Zeugniß widersprechend mit aller Gewalt zu einem neuen zu machen, nicht aus bösem Willen, sondern aus Noth; denn da er an das widersinnige System, welches er für das unsere hielt, sein gesammtes"}]}, {"page_pdf": 1429, "page_book": 36, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Geistesvermögen - doch nicht einmal mit sonderlichem Erfolg - gesetzt hat, wo sollen zur Widerlegung dieses - ihm neuen die Kräfte herkommen? *Der Freund. *Für ihn ist es allerdings ganz neu, und wird es wohl immer bleiben. Denn übrigens haben Sie auch das, was in Bezug auf die getrennten Darstellungen des Idealismus und der Naturphilosophie in der jetzigen wirklich neu ist, schon längst als Ihre Ansicht angekündigt. In dem schon im Mai 1800, also unmittelbar nach Erscheinung Ihres transscendentalen Idealismus, geschriebenen Aufsatz: Deduktion der Kategorien der Physik, findet sich gegen das Ende, nachdem Sie sich über das Verhältniß der Naturphilosophie und des Idealismus erklärt haben (eine Erklärung, aus der man die ganze Idee Ihres Systems nehmen konnte), die bestimmteste Aeußerung: was Sie hier zuerst ganz ausgesprochen, zu begründen, seyen die Vorbereitungen lange gemacht worden; aber ohne eine vollständige Geschichte des Selbstbewußtseyns vom idealistischen Gesichtspunkte aus vorauszusetzen, sey"}, {"type": "paragraph", "text": "die Ausführung nicht möglich gewesen. * Dazu Ihr System des Idealismus.* Ferner: sobald Sie hoffen können, daß der Inhalt jenes Werkes in die allgemeine Gedankenmasse gedrungen und aufgenommen sey, werden Sie mit dem, was Sie darauf zu gründen denken, den Anfang machen. (Zeitschr. für spec. Ph. I. Band, 2. Heft, S. 87. [dieser Ausgabe 1 Abth. Bd. IV, S. 78)]. *Der Verfasser.* Auf jene Aeußerung bezieht sich, was ich in der Vorrede zu der neuen Darstellung sage, ich mache diese früher bekannt, als ich selbst beabsichtigt habe; denn freilich konnte ich mich, von Reinhold und Consorten jetzt nichts zu sagen, nicht rühmen, daß die wahre, nicht an der Oberfläche liegende, Tendenz jenes Werks allgemein verstanden worden sey. Uebrigens bedurfte es bei Lesern, die sich nur nicht auf das bloße Empfangen einschränken, sondern selbstthätig etwas in ihrem Kopf zusammenbringen können, gar nicht einmal der förmlichen Aufstellung des Systems, um meine eigentliche Meinung über die Natur der wahren Philosophie im Allgemeinen zu fassen. Denn sogar Reinhold in den angeführten Stellen kann sich ja nicht entbrechen (obwohl, wie man sieht, ohne alles Bewußtseyn) zu sagen: das, worin die Natur und das Ich absolut eines seyen, sey Princip meiner *ganzen* Philosophie, so daß man nun fast schließen müßte, er wäre selbst ein Mitglied meiner bis daher, wie er sich ausdrückt, esoterischen Schule gewesen. Die bestimmteste Ankündigung und sogar den allgemeinen Plan dieser Wissenschaft enthält die Abhandlung, worin Eschenmayers, aus der ihm eignen Ansicht des Idealismus hergenommene, Einwürfe widerlegt werden sollten1. *Der Freund. *Reinhold mußte diese Stellen gelesen haben, als er sich im zweiten Stück an die Darstellung Ihrer Philosophie machte. Denn jenes Heft Ihrer Zeitschrift ist noch früher als das erste Stück seiner Beiträge erschienen. * Der Verfasser.* Ob er sie gelesen oder nicht, ist völlig gleichgültig."}, {"type": "footnote", "text": "1 Vorzüglich gehören hieher die Stellen S. 124 und 125. S. 143 und 144 der angeführten Abhandlung [im vorhergehenden Bande S. 89. 90. 102]."}, {"type": "paragraph", "text": "Auch wenn er sie gelesen, würde er doch nicht anders gewußt haben, als daß es nun einmal so sey, wie er sich eingebildet, und daß, wie er auch in der Vorrede zum ersten Stück (S. VIII) selbst versichert, das Zeitalter in der Philosophie einen sehr wesentlichen Schritt rückwärts zu thun habe."}]}, {"page_pdf": 1430, "page_book": 38, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "*Der Freund. * Ja wohl einen sehr wesentlichen. Die Zeit kann nun einmal die Siebenmeilenstiefel auch rückwärts anlegen. *Der Verfasser.* Ich leugne nicht, daß, wenn ich auf eine totale Verwirrung in seinem Kopf durch meine neue Darstellung nicht gerechnet habe, sie mir doch eben auch nicht unerwartet kommt, da es ihm freilich nahe genug gelegt war, einzusehen oder wenigstens eine Ahndung davon zu bekommen, wie absurd er und der Lehrer uns verstanden, erstens in dem, was sie als unsere Meinung ausgaben und, wie gesagt, mit großer Anstrengung - doch nicht einmal widerlegt hatten, so wenig auch dazu gehörte, zweitens in dem, was sie von dem Unsrigen entwendet und, wieder ganz schief verstanden, gegen uns brauchen wollten. Aus dieser nicht einfachen, sondern doppelten und dreifachen Verwirrung sich herauszufinden, ging über seine Kräfte. Gegen den Punkt anzurennen, den er mit allen seinen groben und stumpfen Waffen bisher noch nie erreicht hatte, und der hier eben an die Spitze gestellt war, so, daß er seiner Wirkung nicht entgehen konnte, war ihm unmöglich. Denn wir bemerken auch sonst und in andern Wirkungen, wie selbst mit der tiefsten Eingeschränktheit sich wenigstens ein instinktartiges Vorgefühl der Vernichtung verträgt, das bei dem Anblick dessen, worin die Vernichtungskraft liegt, in Angst und kraftlose Zuckungen ausbricht. Die nächste Zuflucht der Schwachheit in einem solchen Zustande ist: den Widerstreit gar nicht als Widerstreit und die tödtliche Entgegensetzung vielmehr als höchste Einigkeit zu erblicken. *Der Freund. *Offenbar war die erste Regung Reinholds, wie immer so auch bei dieser Gelegenheit, ein Wunsch, die Amalgamation bewerkstelligen zu können, und seine ganze Abhandlung ist nichts anderes als das Resultat eines solchen mißlungenen Experiments. Sie brauchen in Ihrer Darstellung Ihr Eigenthum, Worte, welche der Lehrer aus"}, {"type": "paragraph", "text": "Fichtes und Ihren Schriften diebischer Weise entwendet und zu einem ganz verkehrten Gebrauch umgemünzt hat, die Methode, welche dieser der Naturphilosophie nachäffen - wollte, die Stufenfolge der Dinge durch Potenzen auszudrücken u.s.w. Wie soll die unendliche Schülerhaftigkeit, die sich auf das reine Lernen, lautere Empfangen und Nachdenken im eigentlichsten Verstande gelegt hat, sich hier zurecht finden? Auch sieht man, daß die ganze Abhandlung eigentlich von der fröhlichen Voraussetzung einer völligen Einheit zwischen Ihnen und dem Lehrer ausgegangen ist; in der Folge aber, wie er die Beweise führen soll, geht ihm einer nach dem andern zu Schanden, und er muß die grenzenlose Ungereimtheit begehen, immer zwei Dinge zu beweisen: 1) daß hier offenbare Uebereinstimmung, 2) daß eine totale Entgegensetzung sey. Zuletzt spricht er nur noch von *Analogien* beider Systeme, deren *eigentliche Ursache*, wie er sagt, ihm hier ganz gleichgültig seyn könnte. *Der Verfasser. *Ich will gerne glauben, daß er hiervon eben nicht viel wissen will. Desto mehr aber wollen wir uns angelegen seyn lassen der Sache auf den Grund zu kommen. Lassen Sie doch von jenen Aehnlichkeiten hören. *Der Freund. *Die erste ist: Beide Systeme (wie er es nennt) gehen von der absoluten Identität aus. *Der Verfasser.* Wenn das nicht die gröbste Unwissenheit wäre, so wäre es die höchste Unverschämtheit. So aber ist es das Erste. Sagen Sie an, was nennt dieses Volk absolute Identität, und wie kann es sich rühmen auch nur davon auszugehen? *Der Freund. *Was es etwa künftig so nennen werde, nämlich wenn es so mit der Zeit allerhand in Erfahrung gebracht hat, ist nicht deutlich zu sehen. *Vorläufig *aber setzt es nichts weiter voraus, als daß das Denken als Denken unstreitiger Charakter der Vernunft, und der unstreitige Charakter des Denkens absolute Identität sey. *Der Verfasser. *Solche Trivialitäten also, daß der Charakter der Vernunft im Denken, der Charakter des Denkens aber in absoluter Identität bestehe, sind die Entdeckungen, mit denen es groß thut,"}]}, {"page_pdf": 1431, "page_book": 39, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "und die irgend ein Mensch von ihnen zu entlehnen versucht werden könnte? Und diese abgedroschene Identität, die des Denkens, ist ihr Princip? *Der Freund. *Freilich. Auch setzt Reinhold gleich dazu: jedes der beiden Systeme versteht dabei etwas ganz anderes. *Der Verfasser. *Das mag er sich gut seyn lassen. Nun sagen Sie aber, was soll denn das Ganze, und was heißt es? *Der Freund. *Was weiß ich? - Nichts. *Der Verfasser. * Ich bitte Sie, lassen Sie uns alle Möglichkeiten aufsuchen damit einen menschlichen Sinn zu verbinden. Mir selbst steht der Verstand stille vor solcher völligen Sinnlosigkeit. *Der Freund. *Daß Sie das Wort von ihnen gelernt haben, werden jene gewiß nicht sagen, da sie wohl wissen werden, es von uns gestohlen und auf ihr communes Zeug angewandt zu haben. Reinhold selbst führt es in allen seinen Darstellungen als die Hauptidee Ihrer Philosophie an. In demselben Sinne, in welchem Sie es brauchen, braucht es Fichte mehrmals, und namentlich in einer sehr merkwürdigen und für die Bestimmung des speculativen Charakters seines Idealismus sehr wichtigen Stelle, deren ich mich in der Einleitung zu seiner Moral erinnere (S. II. VII). Es kann also auch nicht so gemeint seyn: dieser Begriff sey von Ihnen erst jetzt in dieser Bedeutung gebraucht worden. *Der Verfasser. *Auch würde ich dieß nicht verstehen. Kann etwa der Begriff zweideutig seyn, oder anders als bei solchen, die ihn überhaupt nicht verstehen, zweideutig werden? *Der Freund.* Z.B. Sie haben das Absolute der Form nach bestimmt als Subjekt *und *Objekt, dem Wesen nach aber bestimmen Sie es als das, was *weder *Subjekt * noch *Objekt ist. *Der Verfasser.* Daß es dem *An-sich * oder Wesen nach weder das eine noch das andere und nur darum *absolute *Identität beider sey, ist ein allgemein bekannter Satz des Idealismus. Z.B. lesen Sie folgende Stelle meines Systems des Idealismus, S. 433 [I. Abth. Bd. 3, S. 600]."}, {"type": "paragraph", "text": "*Der Freund. * \"Wenn jenes Höhere (was über dem Freien und dem Nothwendigen ist) nichts anderes ist als der (allgemeine) Grund der Identität zwischen dem absolut Subjektiven und absolut Objektiven, dem Bewußtseyn und Bewußtlosen, welche eben zum Behuf der Erscheinung im freien Handeln sich trennen, so kann jenes Höhere selbst *weder Subjekt noch Objekt*, auch nicht *beides zugleich*, sondern nur die *absolute Identität *seyn, in welcher gar keine Duplicität ist, und welche eben deßwegen, weil die Bedingung alles Bewußtseyns Duplicität ist, nie zum Bewußtseyn gelangen kann. Dieses ewig Unbewußte, was, gleichsam die ewige Sonne im Reich der Geister, durch sein eignes ungetrübtes Licht sich verbirgt, und obgleich es nie Objekt wird, doch allen freien Handlungen seine Identität aufdrückt, ist zugleich dasselbe für alle Intelligenzen, die unsichtbare Wurzel, wovon alle Intelligenzen nur die Potenzen sind, und das ewig Vermittelnde des sich selbst bestimmenden Subjektiven in uns und des Objektiven oder Anschauenden, zugleich der Grund der Gesetzmäßigkeit in der Freiheit und der Freiheit in der Gesetzmäßigkeit des Objektiven.\" *Der Verfasser. * Seite 471 [624] desselben Werks finden Sie bestimmt folgende Aeußerung: \"Die *ganze *Philosophie geht aus und muß ausgehen von einem Princip, das als das absolut Identische schlechthin nichtobjektiv ist.\" - Dieses absolut Identische wird unmittelbar darauf bestimmt als das *an sich weder Sub- noch Objektive*, das nur für die intellektuelle Anschauung zugänglich ist. Von dieser wird behauptet, sie erlange nur durch die Kunst eine allgemeingültige Objektivität. Das Kunstwerk allein reflektire, was sonst durch nichts reflektirt wird, \"jenes absolut Identische, was schon im Ich sich getrennt"}]}, {"page_pdf": 1432, "page_book": 41, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "hat (hier wird es also ausdrücklich dem Ich entgegengesetzt), und was demnach der Philosoph schon im ersten Akt des Bewußtseyns getrennt setzen müsse.\" *Der Freund.* Warum hat man an diesen Stellen nicht schon längst den wahren Geist Ihrer Philosophie erkannt? *Der Verfasser. *Mir ist dieß sehr begreiflich. Die wenigsten haben eine Idee davon, daß man sich zum Behuf einer Darstellung"}, {"type": "paragraph", "text": "oder bei Hervorbringung eines Werks willkürlich begrenzen könne. Sie treiben die Philosophie als ein Handwerk, und wollen sie auch von andern so getrieben wissen. Da es zu jeder Zeit wenig ist, was sie wissen, so schütten sie auch jedesmal alles aus, was sie im Vorrath haben, es mag nun passen oder nicht. So konnten sie sich nicht denken, daß, indem ich eine Darstellung des transscendentalen Idealismus gab, ich auch wirklich nichts weiter als eben den Idealismus darstellen wollte, so wie ich ja auch eine Darstellung der Monadologie oder des Materialismus geben könnte. Die Grenze, in welche sich der Idealismus einschließt, und die in meiner Darstellung gleich anfangs bestimmt angegeben wird, ist: daß er nicht über das Selbstbewußtseyn hinausgeht. \"Durch die Beschränktheit meiner Aufgabe, heißt es S. 31 [357], die mich ins Unendliche zurück in den Umkreis des Wissens einschließt, wird mir das Selbstbewußtseyn (als das erste Wissen) ein Selbständiges, und zum absoluten Princip nicht alles Seyns, sondern alles Wissens. - - Gegen die Aufgabe selbst, oder vielmehr gegen die Bestimmung der Aufgabe kann der Dogmatiker schon deßwegen nichts einwenden, weil ich meine Aufgabe ganz willkürlich *einschränken*, nur nicht willkürlich erweitern darf.\" Bei dieser Bewandtniß der Sache kann jene absolute Einheit alles dessen, was im Bewußtseyn und zugleich mit dem Bewußtseyn sich trennt, diese - eben deßwegen *außerhalb *des Bewußtseyns liegende Identität nicht Princip des Idealismus als Idealismus seyn, sie ist aber das Höchste, worauf er geht, und worin er sich selbst endet. - Daß aber die *ganze *Philosophie, d.h. diejenige, welche nicht Idealismus im Gegensatz des Realismus, noch Realismus im Gegensatz des Idealismus ist, von ihr *ausgehe*, ist in der oben angeführten Stelle behauptet. *Der Freund.* So kann es also auch nicht einmal so gemeint seyn, daß Sie doch dieses letzte Wort über die ganze Philosophie bisher noch nicht gesprochen haben. * Der Verfasser. *Ich muß es wohl ausgesprochen haben, da ja Reinhold sogar, der eben sonst nicht leicht zu verständigen ist, es mir nachgesprochen hat."}, {"type": "paragraph", "text": "*Der Freund.* Ich weiß, daß er in der Recension, nach seiner Weise, nicht aufhören kann, und es zehnmal wiederholt: die absolute Identität des Subjektiven und Objektiven sey für Ihre Philosophie die Eine Grundwahrheit, auf die sich alles reducirt (A.L.Z. a.a.O. S. 371). Das, was er in der vorhin schon (oben S. 32) angeführten Stelle die unbedingte Identität des Subjektiven und Objektiven genannt hat, und was nach ihm Thema und Princip dieser Philosophie ist, nennt er S. 364 eine *schlechthin ursprüngliche* Identität alles Objektiven und Subjektiven. In demselben Zusammenhange scheint er sogar so viel von der Sache zu begreifen, daß er sagt: diese Identität müsse eben darum absolut, und als absolut keiner Erklärung bedürftig seyn, weil man sie schon aufgehoben haben müsse, um sie zu erklären. Daß er mit dieser unbedingten Identität dasselbe bezeichnen wollte, was Sie in den angeführten Stellen dasjenige nennen, was an sich weder sub- noch objektiv, ebensowenig *beides zugleich *ist, erhellet daraus, daß er S. 369 erzählt, sie offenbare sich, als solche, ursprünglich nur der Kunstanschauung."}]}, {"page_pdf": 1433, "page_book": 43, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "*Der Verfasser.* Genug und übergenug, es ist derselbe Wahnsinn, den wir schon früher kennen lernten. Bemerken Sie noch, um das Maß voll zu machen, daß ihm die Rückkehr zu dem, was an sich weder *subjektiv * noch *objektiv * ist, unter der Hand zu einer Rückkehr in die *absolute Subjektivität* wird (S. 372). *Der Freund.* Diese Gedankenlosigkeit ist nicht größer, als daß er im ersten Heft S. 23 von Spinoza sagt: \"er habe das Absolute als *absolute Objektivität*, und eben darum als ein Unendliches der Ausdehnung - u.s.w. bestimmt.\" Es ist wie mit dem Idealismus, der, obwohl er von der absoluten Subjekt-Objektivität ausgeht, dennoch von der *absoluten Subjektivität *auch u.s.w. ausgehen sollte. *Der Verfasser.* Doch will ich mit ihm sehr zufrieden seyn, wenn er mir den Unterschied zwischen der wahren absoluten Identität und dem, was er so nennt, recht ins Licht gestellt hat. * Der Freund. *Sorgen Sie nicht, so gut er es vermochte, hat er es freilich thun müssen."}, {"type": "paragraph", "text": "* Der Verfasser.* Seine sogenannte Identität ist, soviel ich aus seinen wortreichen Erklärungen in dem ersten Heft habe nehmen können, nichts weiter als die ganz gemeine bloß logische des Gattungsbegriffes, eine abstrakte Verstandes-Identität, wie sich Hegel sehr gut ausgedrückt hat. Dieß erhellet am besten aus der anfänglichen Beschreibung; und lassen Sie uns besonders zusehen, daß uns die *unendliche Wiederholbarkeit *nicht abhanden kommt. Sie ist eine gute Beschreibung des Verstandesbegriffs. Von der Idee ist keine Spur darin, denn die Idee ist das, worin das Allgemeine und Besondere schlechthin eins ist, und was eben deßwegen nicht wiederholbar seyn kann, denn die Wiederholbarkeit setzt den Gegensatz des Allgemeinen und des Besonderen voraus. Auch haben wir bei Reinhold auf der einen Seite die abstrakte Einheit des Begriffs, das unendlich Wiederholbare, auf der andern als schlechthin entgegenstehend die Nichtidentität, die bloße Mannichfaltigkeit als Charakter des zur Anwendung des Denkens nöthigen Stoffs, also eine ebenso absolute Besonderheit als dort absolute Einheit, welche beide erst in der Anwendung des Denkens als Denkens *synthesirt*, also durchaus auf keine absolute Weise vereinigt werden. So subaltern als jene Identität selbst ist (sie ist nämlich Identität nur, weil sie bloß der eine Faktor eines absoluten Dualismus ist), ist es nothwendig auch die Unendlichkeit, die ihr beigelegt wird. Denn freilich ist der Begriff als Begriff und an sich unendlich. Er bedarf der Quantität und der unendlichen Wiederholung nicht, um es zu seyn. Aber eben deßwegen ist diese Unendlichkeit, wie jene Einheit, eine bloß abstrakte, und die falsche Abstraktion rächt sich auch hier, indem nachher eine Unendlichkeit fertiger und fixirter Endlichkeiten in der Mannichfaltigkeit des Stoffs nachgeschneit kommt. Höher als zu diesem Gegensatz geht es nicht. Was die wahre Speculation oben zusammenknüpft, bringen sie unten zusammen, und sind der einfältigen Meinung, daß außer ihnen irgend jemand mit den schülermäßigen Ausdrücken: Anwendung des Denkens u.s.w. sich werde abfinden lassen. Sie haben in alten und neuen Büchern einige andere, gute Worte gefunden, mit denen sie aber nichts anzufangen wissen. Man muß nicht fragen, was"}, {"type": "paragraph", "text": "ihre Meinung sey, denn ein vollkommener Galimathias bleibt gleich unverständlich für Kluge wie für Thoren. Besonders scheinen dem Lehrer einige Ausdrücke, die man bei Plato auf allen Seiten auflesen kann, von der stehenden Einheit in der Vielheit, von dem, was sich selbst gleich, und dem, was sich ungleich ist, mit Reinholdischen und Fichteschen Begriffen und Ausdrücken zusammengeflossen zu seyn. Eine ähnliche Art der Unphilosophie muß übrigens schon zu Platos Zeiten nicht ganz unbekannt gewesen seyn; denn in derselben Stelle, wo er sagt: \"Die Alten, besser und näher den Göttern als wir, haben uns"}]}, {"page_pdf": 1434, "page_book": 45, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "die Sage hinterlassen, daß, da aus Einem und Vielem die Natur alles desjenigen sey, von dem man sagt, daß es *ewig *sey, und dieses die Unendlichkeit und die Grenze in sich zusammengewachsen enthalte, wir bei dieser Beschaffenheit der Sache jederzeit von allem Eine Idee voraussetzen und suchen müssen.\" - in demselben Zusammenhange fährt er fort: \"Die sich aber jetzt Philosophen nennen, setzen das Eine und das Viele, wie es kommt, früher oder später, als es recht ist, nach der Einheit aber unmittelbar unendlich vieles (unendliche Mannichfaltigkeit), das Mittlere aber entflieht ihnen.\" (Phileb. pag. 219. 220, ed. Bip.) Von demjenigen also, was für die Speculation das einzig Höchste ist, dem, wo mit dem Unendlichen auch das Endliche, mit der Einheit auch die Entgegensetzung wieder eins ist, mit Einem Wort, von der wahren absoluten Identität und der wahren Unendlichkeit derjenigen, welche Ewigkeit ist, ist in dieser vermeinten Philosophie nichts anzutreffen. * Der Freund.* Das nennt Reinhold eine Amalgamation des Endlichen mit dem Unendlichen. *Der Verfasser. *Diese Schmähung der höchsten Idee muß seiner Unwissenheit zu gute gehalten werden. *Der Freund.* Das Höchste, wozu man etwa zugeben könnte daß jene angebliche Philosophie sich erhebe, wäre das, was in Ihrem System die quantitative Indifferenz (A2) genannt wird, stünde dieser nicht bei jenen die Differenz (oder das A = B) schlechthin entgegen. Da auf der Synthesis der Differenz oder des Besonderen und"}, {"type": "paragraph", "text": "der Indifferenz, des Allgemeinen, sogar das Bewußtseyn beruht, so kann es dieses zweispaltige Denken nicht einmal bis zum Bewußtseyn bringen, geschweige bis zu dem, worin die Differenz und die Indifferenz, das Besondere und das Allgemeine absolut eins sind (A3). *Der Verfasser.* Wie es nun komme und möglich sey, daß diese unwissende Arroganz, die so tief unter ihrer Zeit steht, und die Philosophie freilich nicht nur um Einen Schritt, sondern um alle Schritte, die sie vorwärts gethan hat, bis in den äußersten Zustand der Unmündigkeit zurück versetzen würde, der auch die ersten Begriffe aller Speculation fremd sind, sich als Philosophie brüsten könne, will ich nicht beantworten. Ist aber die Frage davon, wie sich diese Ausgeburt zu meinem Systeme verhalte, so will ich nur so viel sagen: wie sich der gröbste Dualismus zu einem wahren absoluten Identitätssystem, oder wie sich zwei völlig incommensurable Dinge, z.B. die von einem trivialen und in seiner Trivialität wieder verbrannten Gehirn zusammengesetzte, von einem Sudler aber ausgeführte Fratze, zu einem mit Kunstbestreben entworfenen und gemäß seinem Begriff ausgeführten Werk verhält. Da ferner nicht einzusehen ist, wie eine Identität, welche einen Stoff mit unendlicher Mannichfaltigkeit und Nichtidentität außer und neben sich - voraussetzt, und in der Anwendung sich mit ihm zu fügen hat, eine *absolute * Identität heißen könne, so bleibt nichts übrig, als Reinholden und seinem Spießgesellen von Rechtswegen anzudeuten, daß sie sich dieses angemaßten und ihnen gar nicht zuständigen Worts künftig enthalten sollen. *Der Freund.* Wenn ich noch recht Bescheid weiß, so hat es der Spießgeselle nicht einmal gebraucht, sondern Reinhold hat es sich zugeeignet. *Der Verfasser.* Ganz passend hierher heißt es bei Shakspeare: Er hat das Wort von irgend einem gescheidten Manne gehört und auf einen Narren angewendet. - Denn ich erinnere mich ebensowenig, bei dem Lehrer etwas davon bemerkt zu haben. * Der Freund.* Sie haben also doch endlich den Grundriß der Logik gelesen?"}]}, {"page_pdf": 1435, "page_book": 47, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "*Der Verfasser.* Weniger als gelesen und etwas mehr als bloß durchblättert; gerade so viel, als nöthig ist zu sagen, weß Geistes Kind er sey; seit dem verflossenen Sommer 1801. *Der Freund.* Gestehen Sie wenigstens, daß Sie hierin eine größere Nachlässigkeit haben, als man dafür hält, daß einem Gelehrten gezieme! Denn wie das Buch auch sonst beschaffen seyn mag, so mußten Sie es doch wenigstens darum lesen, weil das Aufheben davon gemacht wurde. *Der Verfasser.* Bester Freund, was den einzigen, der es machte, betrifft, so hatte ich über diesen meine Idee fixirt, und wußte, was ich von ihm zu halten hätte. Doch wäre dieß allerdings kein zureichender Grund gewesen; Sie müssen also wissen, daß, was den Verfasser betrifft, ich dieses Menschen schon länger kenne; wußte, daß er schon früher in der Philosophie gestümpert, und erst, nachdem mit den vorhergegangenen kleinen schriftstellerischen Versuchen schlechterdings keine Aufmerksamkeit zu erregen war, sich durch den Grundriß der Logik aus der Obscurität empor zu arbeiten getrachtet hatte. - Vielleicht sind Ihnen selbst einige Blätter unter dem Titel: Ursprung des Begriffs der Willensfreiheit und gewisse Briefe über den Ursprung einer Metaphysik überhaupt vorgekommen. *Der Freund.* Ich habe nie davon gehört. *Der Verfasser.* Wahrscheinlich wären sie mir ebenso unbekannt geblieben, hätte sie mir der Verfasser nicht selbst zugeschickt. Diese beiden Schriften allein sind schon hinreichend, sich einen ziemlich bestimmten Begriff von dem Geistesvermögen ihres Autors zu machen. Er war nämlich dergestalt über und über mit der empirischen Psychologie behaftet, daß ich nie einen Menschen gesehen zu haben mich erinnere, der so völlig blind und ohne alle Ahndung, daß es etwas Speculatives gebe, wo ihm eine Idee vorkam, sie frischweg aus der empirischen Psychologie zu erklären anfing, gleich als ob es nie jemand eingefallen wäre an der Realität dieses Empirischen zu zweifeln. So z.B. wird ihm in der angeführten Schrift die Idee der Willensfreiheit ganz vollkommen durch eine psychologische Täuschung erklärt."}, {"type": "paragraph", "text": "*Der Freund.* Kein Wunder, daß er auch den Idealismus sich empirisch psychologisch zurecht machte. *Der Verfasser.* Ganz richtig. Auch widerlegte er ihn aus seinen empirisch psychologischen Kapiteln heraus. Mit Einem Wort, ich habe ihn nie anders gekannt als in der dicksten und tiefsten Empirie so versunken und ertrunken, und über alles Speculative mit solcher Finsterniß geschlagen, daß er über seine empirische Psychologie auch auf keine Weise zu bedeuten war. Zu diesem Uebel gesellten sich zwei andere, die oberflächliche Schönschreiberei, worin er sich besonders einige Helden zum Muster gesetzt hatte, und die Sucht, die Philosophie durch ihre Geschichte zu studiren, dieser aber mit empirischer Psychologie aufzuhelfen, so daß der Kreis, der mit der Empirie angefangen hatte, auch in Empirie sich wieder schloß, und also gar kein Ausweg übrig blieb. Das Höchste, wozu sich eine so seichte Natur noch etwa erheben konnte, war allerdings die Reinholdische Theorie vom Stoff und der Form, weßwegen ich es ganz begreiflich fand, als ich von dem Grundriß der Logik als einem Spätling der Reinholdischen Elementarphilosophie hörte, um so mehr, da ich den Verfasser auch sonst als einen Menschen kannte"}, {"type": "paragraph", "text": "- - von dürft'gem Geiste, der sich nährt Von Gegenständen, Künsten, Nachahmungen, Die alt schon und von andern abgenutzt Erst seine Mode werden. - -"}, {"type": "paragraph", "text": "Dieß alles konnte mich nicht abhalten, den Grundriß wenigstens so bald zu lesen, als ich von dessen Existenz hörte und seiner habhaft werden konnte (welches beides geraume Zeit nach seiner Erscheinung"}]}, {"page_pdf": 1436, "page_book": 48, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "geschah); auch nicht, daß ich vernahm, was sich mir nachher bestätigte, und was ich mir zum voraus vorstellen konnte, er habe bei seinem Werk mehr die Befriedigung gewisser schlechter Regungen als das Interesse der Wissenschaft vor Augen gehabt; habe sich in seiner Schrift der kleinlichsten Art des Hasses, insbesondere gegen mich, entledigt; habe, zum Dank für eine ganz bestimmt von mir entlehnte Idee über Mechanismus und Organismus, in demselben Zusammenhange,"}, {"type": "paragraph", "text": "in welchem er sich ihrer bedient und der Schrift, aus der er sie genommen, erwähnt, sich Ausbrüche der gemeinsten Persönlichkeit erlaubt, und von seiner Crapulosität weit genug sich hinreißen lassen, um an einer Stelle seine Empfindlichkeit sogar darüber zu äußern, daß irgend ein alberner Mensch im Intelligenzblatt der Erl. Lit. Zeitung, solange sie noch unter der Leitung des ersten Redakteurs eine gute Anlage zur Klatschbude zeigte, mich ein Universalgenie oder etwas der Art genannt hatte. Dieß alles mußte, weit entfernt mich von der Lektüre zurückzuhalten, sie mir vielmehr interessant machen. Denn erstens ist bekannt, daß sehr oft der Haß den Mangel des Genies ersetzt, zweitens, daß Gott nicht selten auch ein unehrbares Gefäß sich ausersieht, um etwas Gutes für die Welt darein zu legen. Auch in dem Fluß, der sonst nichts als Schlamm und Unrath führt, kann man zerstreute Goldkörner vermuthen, besonders wenn man weiß, daß er edle Berge auch nur im Vorbeigehen bespült hat. Was mich aber von aller Lektüre des Werks freizusprechen schien (denn ich will in meiner Erzählung fortfahren), ist Folgendes. Im Sommer 1800 hatte ich mit dem Verfasser selbst eine persönliche Unterredung, welche mich, obgleich es zu meiner Ueberzeugung eben nicht nöthig war, doch vollends ganz in den Abgrund von Absurdität hinabsehen ließ, der in diesem Individuum sich aufgethan hatte. Ich verbürge, daß ich keinen Zug davon angebe, der nicht genau richtig ist, und daß, obgleich viele unbedeutende Zwischenreden wegfallen mögen, doch, die ich erwähne, die Hauptsache und dem Inhalt nach ganz so beschaffen waren, wie ich sie angebe. Urtheilen Sie selbst, und erlauben Sie, daß ich diese kleine Scene in unser Gespräch einschalte. *Ich *(nachdem er mich versichert hatte, daß die Subjekt-Objektivität der Idealisten die palpabelste Individualität sey, daß er von einer reinen Identität (sollte heißen: einer solchen, die nicht Identität des Subjekts und Objekts sey) ausgehe, und diese als das schlechthin Determinirende und Ursache aller Determination auf den Stoff einwirken lasse, machte ihm die Frage): Wie denken Sie diesen Stoff; ohne Zweifel doch wohl im Raum? Er. Freilich; denn *ich* kann mir keinen Stoff unabhängig vom Raum denken."}, {"type": "paragraph", "text": "*Ich.* Nehmen Sie auch an, daß er den Raum erfülle? *Er. * (zaudernd). *Ich.* Wofern Sie dieß nicht annehmen, so werden Sie ihn von dem Raum selbst nicht unterscheiden können. *Er.* Auch muß er den Raum erfüllen. *Ich. *Ohne Zweifel nach allen drei Dimensionen? *Er. *Wie anders? Ich wußte noch nicht, was er in dem Grundriß der Logik S. 116 sagt: \"daß diese Ausdehnung ihr Wesen nun eben in drei Raumdimensionen an den Körpern ausstelle, erfahren wir freilich - erst durch den Anblick dieser Körper selbst\".) *Ich.* Wie glücklich sind Sie, daß Sie dieß alles umsonst haben und voraussetzen können; da wir andern uns die Mühe nicht dauern lassen, die Materie mit ihren drei Dimensionen zu deduciren. - Sie können sich aber keine Raumerfüllung überhaupt, sondern müssen jede nothwendig als eine bestimmte"}]}, {"page_pdf": 1437, "page_book": 50, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "denken. So können Sie auch nicht denken, daß Ihr Stoff den Raum nur überhaupt erfülle, sondern nothwendig, daß er ihn in einem bestimmten Grade erfülle. *Er* (abermals bedenklich, und wirklich nicht wissend; oder nicht zu wissen sich anstellend, was Raumerfüllung in bestimmtem Grade bedeute, womit er die extensive Größe der Raumanfüllung verwechselte. Es mußte diesem großen Philosophen der Unterschied durch das Beispiel auseinandergesetzt werden, daß eine extensiv gleich große Portion Luft und Blei den Raum doch intensiv verschieden erfüllen). Es läßt sich hierüber nichts sagen, als daß der Stoff den Raum mit unendlicher Mannichfaltigkeit erfülle. * Ich.* Wo Sie unendliche Mannichfaltigkeit setzen, setzen Sie unendliche Unterscheidbarkeit, und diese wiederum setzt unendliche Bestimmtheit voraus. Sie haben also nicht nur die allgemeine Bestimmtheit des Grads der Raumerfüllung, sondern auch eine Unendlichkeit von Bestimmtheiten. Wie kommen nun alle diese Bestimmtheiten schon in den Stoff als Stoff, da doch nach Ihnen alle Determination in dem Stoff erst durch die Einwirkung der Identität auf ihn gesetzt wird? *Er.* (nachdem er durch verschiedene Wendungen von diesem Punkt hinweg zu kommen gesucht, aber immer wieder darauf zurückgeführt, und nachdem zu wiederholtenmalen handgreiflich gemacht worden war, daß er eine Menge von Bestimmtheiten in dem Stoff als Stoff unabhängig von dem Bestimmenden, also ein Denken außer dem Denken und vor dem Denken, mithin eine baare Absurdität annehme, endet von seiner Seite das ganze Gespräch, nachdem er weiter nichts vorzubringen weiß, - mit einem Lachen)."}, {"type": "paragraph", "text": "* Ich.* Gestehen Sie, daß, wenn man es in der Philosophie recht bequem haben will, man sich zu Ihnen halten muß. Denn ich sehe nun deutlich, daß Sie unabhängig von und vor allem Denken nicht nur einen Stoff, sondern auch den Raum, die drei Dimensionen der Raumerfüllung, ja sogar eine unendliche Menge verschiedener Grade der Raumerfüllung haben. Mit Einem Wort, Sie fangen mit dem an, womit wir andern aufhören, und können es auf diese Weise ganz natürlich weit bringen u.s.w. u.s.w. Er (fährt wie oben fort zu lachen und beschließt damit die Unterhaltung). *Der Freund.* Unmöglich ist es, nicht in diese Regung mit einzustimmen. * Der Verfasser.* Sollte ich nun nicht diesen betrogenen Menschen bemitleiden, der seine Narrheit für Weisheit, seine Schülerbegriffe für Ideen, sein zusammengestohlenes Exercitium für eine ganz neue Philosophie, sein Flickwerk für Meisterwerk nicht sowohl selbst hielt, als vielmehr durch einen andern Schwachkopf sich verführen ließ zu halten. Es gehörte auch nicht weniger dazu als die Erfahrung, daß Reinhold wirklich die Sache im Ernst fortzutreiben gesonnen sey, und die Bemerkung mehrerer Freunde, daß die Waffen, deren er anfing sich zu bedienen, und welche jenen mehr giftiger als triftiger Art schienen, äußerer Rücksichten wegen eine Vertheidigung von unserer Seite und eine Darstellung seiner Sache nothwendig machen könnten, um mich endlich zur Hervorsuchung und einer etwas mehr als bloß oberflächlichen Durchblätterung des Buchs zu bringen. *Der Freund.* Sehr sollte es mich ergötzen, bei dieser Gelegenheit einige Ihrer Bemerkungen darüber zu hören. *Der Verfasser.* So viel mir jetzt eben davon beigeht, steht Ihnen gerne zu Diensten. Das ganze Buch habe ich mir construirt als eine Hülfe der Natur, nöthig gemacht dadurch, daß unglücklicher (und zu einer solchen Zeit fast unvermeidlicher) Weise in einen zur tiefsten Empirie bestimmten Kopf einige speculative Ideen von außen gerathen waren, die, als ein fremdartiger Stoff, nicht eher vertragen werden konnten, bis sie empirisch psychologisch assimilirt und auf diese"}, {"type": "paragraph", "text": "Weise der eigenthümlichen Organisation des Kopfs wieder unterworfen waren; als einen unförmlichen"}]}, {"page_pdf": 1438, "page_book": 52, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Absceß des Gehirns also, gebildet durch die Einwirkung des Idealismus auf ein mit empirischer Psychologie getränktes, durch einige confuse Ideen aus der Reinholdischen Elementar-, der Kantischkritischen Philosophie und einigen noch vom Schulunterricht her bekannten Systemen verrücktes und in seiner Ordnung gestörtes Seelenorgan, das sich durch diesen Auswuchs zur Gesundheit zu reconstruiren suchte, so wie wir oft sehen, daß die hülfreiche Natur ein inneres Uebel in äußern Monstrositäten ausstößt. Der chemische Proceß, der die Masse, worin so heterogene Bestandtheile zusammentrafen, ergriff, ging, wie man deutlich sieht, in allen seinen Zersetzungen, Niederschlägen und Anschießungen ganz ohne alles Zuthun oder einigen Antheil des Subjekts von statten, und ist insofern in der That ein reinobjektives Naturphänomen. *Der Freund.* Merkwürdig scheint mir in dieser Rücksicht, daß, nach dem jetzigen schalen und nüchternen Sprechen des Subjekts zu urtheilen, der Proceß wirklich die gehoffte Wirkung gehabt hat, und daß die nüchterne und asthenische Seele Reinholds jetzt eben anfängt von dem hitzigen Fieber ergriffen zu werden, während es bei jenem in ein kaltes übergeht, so daß, indem jener zur Besinnung kommt, dieser betrunken zurückbleibt, nicht unähnlich in diesem Schicksal dem einfältigen, jedoch klügeren und berühmteren Sancho Pansa, der, in dem Augenblick, wo sein Herr aufhört zu rasen, eben recht anfängt an alle seine Narrheiten zu glauben. *Der Verfasser.* Gleichwie nun das Auge sich an wunderbaren Versteinerungen, die eine seltsame Zusammenkunft chemischer Agentien und Reagentien hervorbringt, oder an bisarren Seegeschöpfen ergötzt, in welchen die äußere Feuchtigkeit des Elements den innern Bildungstrieb in widersinnische Formen zwingt, so kann es sich hier und in diesem Individuum nicht bloß Einer solchen Seltsamkeit, sondern einer vollständigen Collektion und gleichsam eines Naturaliencabinets aller möglichen absurden Formen und Concrescenzen von der Zirbeldrüse des Cartesius an bis herunter zu dem eignen Pferde-Ich des Verfassers erfreuen."}, {"type": "paragraph", "text": "Obgleich es schwer ist in einer so trüben Masse irgend ein reines Element zu erkennen, so sieht man doch, daß das Hauptferment, wodurch sie in Bewegung gesetzt ist, aus dem Idealismus angeflogen, und was noch von Philosophie, in kaum sichtbaren Adern, durch das Ganze sich hinzieht (denn ich habe, wenn ich nicht irre, bereits bemerkt, daß der Verfasser ein Narr von der gemischten Art sey), von den Idealisten aufgehörte und angeeignete Ideen sind. So z.B. hat er von diesen vernommen, daß das Philosophiren unmittelbar mit dem Unbedingten und sonach dem, was bloß unter dem Gesetz der Identität steht, anfange, und daß von diesem Unbedingten alles negirt werden müsse, was bloß synthetischer Natur ist, daß das Princip der Identität nicht bloß negatives Kriterium der Wahrheit, wie bei Kant, sondern positives Princip sey - ein Satz, mit dem Fichte, zuerst in der Recension des Aenesidemus, und nachher in den ersten Blättern der Wissenschaftslehre, die Philosophie über die Kantische Beschränktheit hinaus aufs Absolute führte. So hat er auch ferner aus §. 1. der Wissenschaftslehre erfahren, daß das eigentlich Gedachte in dem A = A nicht A selbst, oder A als Subjekt und Prädicat, sondern der nothwendige Zusammenhang (die Copula), mit Einem Wort die Identität selbst sey. So wie man nun oft die Erfahrung machen kann, daß Menschen, die bis daher in einer rohen Unwissenheit gelebt haben, wenn ihnen etwa zufälliger Weise einmal ein kleines Licht aufgeht, sich über sich selbst nicht genug verwundern und die seltenen Naturgaben in sich preisen können, so konnte auch unser Verfasser, dem in dieser Region alles fremd und völlig neu war, da er das erstemal von etwas über dem Empirismus vernahm, sich vor sich selbst nicht tief genug in den Staub beugen (S. 296), und da die Bewegungen dieses Erstaunens Reinholden ganz in demselben Zustand des dicksten Empirismus antrafen, den er bis daher noch nie hatte überwinden können, so war es eine Art von Nothwendigkeit, daß er mechanisch dieselben Bewegungen nachmachte, und sie nun noch immer nachzumachen fortfährt."}]}, {"page_pdf": 1439, "page_book": 53, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Allein dieweil in allen Künsten und Wissenschaften, besonders aber"}, {"type": "paragraph", "text": "in der Philosophie, die Flügel, die man von andern entlehnt, nicht weit tragen, so sank jener auch, nachdem er vergeblich zu dem wahren Unbedingten und dem Aether der höchsten Identität sich zu erheben gesucht hatte, alsbald in den Reinholdischen Stoff, den stehenden Sumpf der faulen Philosophie, zurück. Die von Seiten Reinholds ergangene Versicherung, über alle Objektivität und Subjektivität (nur nicht zur absoluten Identität beider) hinaus dringen zu wollen, hat sich darein aufgelöst, daß sie in die tiefste Subjektivität, welche als solche freilich eine *reine *Identität ist, in das Denken als Denken, welches den Stoff nicht nur sich gegenüberstehend hat, sondern voraussetzt, verfallen sind. Daß sie, indem der Stoff schlechtweg als unendliche Mannichfaltigkeit bestimmt wird, ein Seyn, und zwar, wie aus dem erzählten Gespräch erhellet, ein ganz fertiges empirisches Seyn mit allen möglichen Bestimmungen des Denkens vor und außer dem Denken, sonach ein sich selbst widersprechendes Denken setzen, daß ferner das Denken als Denken seiner angeblichen Absolutheit unbeschadet doch zugleich als beschränkt durch, und nothwendig sich fügend mit dem was ihm entgegen, und von ihm schlechthin unabhängig vorausgesetzt wird, selbst nicht mehr ein Denken, sondern ein baares Nichtdenken ist - sind Betrachtungen, welche sich dieses unschuldige Philosophiren nicht beigehen läßt. Die flache Phantasie, wie die Formularphilosophie, hat ihr Wesen im Halbdenken, zu deutsch Faseln, für welches die Entia imaginationis gehören, dergleichen die unendliche Mannichfaltigkeit ist, die, als unendliche Bestimmtheit vor dem Denken, weder wirklich gedacht noch irgend einer Anschauung auch nur halbweg vergegenwärtigt werden kann. In den ersten Zeiten, nachdem Fichte aufgetreten war, würde ein solches Geschwätz im Augenblick verhallt seyn, kein Mensch, auch nicht einmal Reinhold, würde darauf gehört haben; daß die Sätze vom Stoff und seiner unendlichen Mannichfaltigkeit, der Einheit, welche durch die Form hinzukommt u.s.w. jetzt wieder als neue zu Markt gebracht werden und sich zeigen dürfen, beweiset nur, mit welcher unglaublichen Schnelligkeit sie vergessen worden sind. Ebenso steif entgegengesetzt als im Anfange bleibt das Denken und der Stoff in der ganzen Folge; beide"}, {"type": "paragraph", "text": "gehen in zwei gleich unmöglichen Welten, durch nichts vereinigt, nebeneinander her; nichtsdestoweniger wirkt auf der einen Seite das Denken oder die Identität ein auf den Stoff, auf der andern (S. 319) ist es der Stoff, der das Denken afficirt, hier ist die Reconstruktion des Kopfs zum Empirismus vollendet, wir haben den Influxus physicus vereint mit Reinholdischer Elementarphilosophie, durch beides zusammen den Dualismus gröber, als er je in der Philosophie existirt hat. - Mit der Art des Fügens beider hat es folgende Bewandtniß: Obgleich der Stoff höchste Nichtidentität, unendliche Mannichfaltigkeit ist, so hat er doch eine verwünschte Anlage gedacht zu werden. Nichtsdestoweniger muß er, um gedacht zu werden, als Stoff vernichtet werden, was hier mit der tiefsinnigen, dem Lehrer ganz genau ähnlich sehenden Bemerkung aus der empirischen Psychologie: \"*Gesprochene wie geschriebene * Worte z.B. müssen als Materie im *Hören *und * Lesen zernichtet *werden, wenn Gedanken daraus entstehen sollen\", illustrirt wird. - Doch ganz aufgerieben soll der Stoff nicht werden; was nämlich hier übrig bleibt, wird an die Stelle der Kantischen reinen Anschauungen eingeflickt; es ist die unvertilgbare, wieder in ein Neben- und Nacheinander zerfallende Form des Außereinander, die übrig bleibt und sich mit dem Denken *fügt*, - warum? - o der glückseligen Philosophie, der hier eben an der rechten Stelle ein fertiges Naturgesetz nicht entsteht - weil *nach dem Gesetz der Natur *die Form nicht durch die Form zerstörbar ist. Damit aber der Gipfel des Unsinns nicht unerstiegen gelassen werde, so wird der Stoff in seiner Unabhängigkeit"}]}, {"page_pdf": 1440, "page_book": 55, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "und Vorausgesetztheit vom Denken als Denken, welches sich in das Wesen aller Wesen und die Gottheit selber verwandelt hat, bestätigt; in einem und demselben Athem aber auch wieder möglich gefunden, daß ihn Gott sich erschaffen habe (S. 256), und damit auch gegen diese Gleichgültigkeit noch ein Widerspruch existire, wird dieser nach und nach erschriebene Gott, obgleich es möglich ist, daß er den Stoff vor sich finde (angef. S.), nichtsdestoweniger als Grund aller Möglichkeit und Wirklichkeit aufgestellt. Sollte ich endlich von der Zustandebringung des ganzen Werks"}, {"type": "paragraph", "text": "ein Bild geben, so hat meines Erachtens außer dem Verfasser, wenn man sein - Schreiben anders mit einem Malen vergleichen darf, kein vollkommeneres Ebenbild dieser Manier existirt als jener Maler zu Ubeda, von dem Cervantes im dritten Theile seines Don Quixote erzählt, der, wenn man ihn fragte, was er male, zur Antwort gab: *was es wird*, oder:* was herauskommt*, und wenn er etwa einen Hahn malte, so schrieb er darunter: dieses ist ein Hahn, damit es keiner für einen Fuchs oder für ein Schwein ansehe. Was insbesondere die Beredtsamkeit des Werks betrifft, so erhebt sie sich, vorzüglich in den Stellen, wo der Verfasser auf das Daseyn Gottes zu sprechen kommt, und wo er ganz den alten Staub der dogmatischen Compendienmetaphysik wieder ausklopft, zu dem Pathos und der Kraft, die man sonst an den Kapuziner-Predigten zu rühmen pflegte. So wie mir dagegen Reinhold nicht unähnlich einigen Individuen unter den ehemaligen Esprits forts in Frankreich scheint, die, nachdem sie im Leben sich von der allgemeinen Freigeisterei hatten hinreißen lassen einen Ekel vor der bestehenden Religion zu affichiren, auf dem Todtenbette endlich der geistlichen Fürsorge eines schmutzigen Kapuziners froh wurden. Doch jener ruhe nun im Frieden, da wir schwerlich je versucht werden könnten zu ihm zurückzukehren, nachdem er einen Abschreiber gefunden, der es auf sich genommen, ihn aus dem verworrenen Concept seiner Narrheit ins Reine zu bringen, obgleich dieß alle noch so gute Abschreiber der Welt nicht im Stande seyn möchten zu thun. Ich bitte Sie also, zu unserm Gegenstand zurückzukehren, von dem wir ganz abgekommen sind, und umsomehr in ihrem Bericht fortzufahren, da uns dieser noch mehrere Gelegenheit zu lustigen Zügen und unterhaltenden Vergleichungen darbieten wird. *Der Freund.* Sehr gerne, denn es scheint mir, daß, je weiter wir in diesen Gegenstand hineingehen, er immer anziehender wird. Unter die Entdeckungen des Lehrers also rechnet Reinhold besonders die Negation aller Quantitäts-, Qualitäts- und Modalitäts-Verschiedenheit in Ansehung des Denkens als Denkens. *Der Verfasser.* Dieß ist allerdings richtig, insoferne er nämlich"}, {"type": "paragraph", "text": "die Erfindung gemacht hat, *das *Denken als Denken zu nennen, was wir absolutes Ich, absolute Identität von Subjekt und Objekt genannt haben; denn um jetzt nichts von Kant zu sagen, dessen ganze Philosophie eben in jenem negativen Resultate besteht, daß durch die nach Quantität, Qualität u.s.w. unterschiedenen Begriffe nur Erscheinungen, nicht das, was *an sich* ist, bestimmt sey, so ist diese negative Art, das wahre oder vermeinte Absolute zu charakterisiren, gerade diejenige, zu welcher jeder Anfänger in der Philosophie zuerst greift, wie z.B. ich selbst in der Schrift *vom Ich *gethan habe. \"Für das* absolute * Ich (= absolute Identität des Subjektiven und Objektiven) heißt es an einer Stelle, gibt es keine Möglichkeit, Wirklichkeit und Nothwendigkeit.\" Auf dieselbe Weise werden von ihm alle Reflexionsgegensätze und Synthesen geleugnet. - \"Für das absolute Ich, heißt es an einer andern Stelle"}]}, {"page_pdf": 1441, "page_book": 57, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "jener Schrift, würde, wenn es überhaupt Möglichkeit und Wirklichkeit für dasselbe gäbe, alle Möglichkeit Wirklichkeit, alle Wirklichkeit Möglichkeit seyn. Für das endliche Ich aber gibt es Möglichkeit und Wirklichkeit, mithin muß sein Streben (und wie aus dem Zusammenhange erhellet, auch sein Denken) in Bezug auf beide so bestimmt seyn, wie das Seyn des absoluten Ichs bestimmt wäre, wenn in Ansehung desselben Möglichkeit und Wirklichkeit stattfände. - Was für das absolute Ich *absolute* Zusammenstimmung ist, ist für das endliche hervorgebrachte\" (a.a.O. S. 178, 207 [Bd. 1, S. 232]). Hier erhellet deutlich die Behauptung, daß die Natur des Absoluten durch die Einheit desjenigen bestimmt werden müsse, was in der Reflexion sich entgegengesetzt ist, nur daß von dem Begriff dieser Einheit abgezogen werde, was die Reflexionssynthese dareinbringt, die Bedingtheit durch den Gegensatz; daß also die Einheit nicht als gemachte, zusammengesetzte, sondern als absolute, z.B. nicht als Nothwendigkeit, sofern diese durch Möglichkeit und Wirklichkeit bedingt, sondern sofern sie über beiden und sie vielmehr bedingend ist, mit Einem Wort als *heilige *Nothwendigkeit, *heilige *Identität gedacht werde. Davon hat nun jener aus den Schriften der Idealisten einigermaßen etwas aufgegriffen und gelernt, das Absolute Denken als Denken"}, {"type": "paragraph", "text": "genannt, und von dem Seinigen noch den Reinholdischen Stoff, den Dualismus, die empirische Psychologie hinzugethan und so seinen Gedankenbrei zusammengerührt. *Der Freund.* Sie werden sich vielleicht noch mehr an den einzelnen Proben ergötzen. Hier sind sie. Ihr Satz: \"die absolute Identität kann als Identität nie aufgehoben werden\" - wie man aus dem Zusammenhange sieht, so viel als: auf *keine Weise aus sich herausgegangen gedacht werden -* wird mit dem Satz zusammengestellt: das Denken als Denken leide keinen Qualitätsunterschied; im Denken als Denken gebe es keine Negation. - Mir schien gerade jener Satz einer von denen zu seyn, die am direktesten diesem Dualismus entgegengesetzt sind, der an dem Herausgehen der absoluten Identität aus sich selbst - auf den Stoff, welcher nicht sie selbst, sondern das gerade Entgegengesetzte von ihr, Mannichfaltigkeit ist, - gar kein Arg hat. *Der Verfasser.* Wie wenig in diesem Dualismus daran gedacht sey, ein Herausgehen der absoluten Identität aus sich selbst zu negiren - vielmehr wie viel er sich damit weiß, über ein solches Herausgehen sogar einen recht handgreiflichen Aufschluß geben zu können, darüber existirt unglücklicherweise eine sehr bestimmte Stelle in dem Grundtext selbst. Es ist diese, S. 114. \"Zur Möglichkeit der Anwendung jenes Eins (des Denkens als Denkens) muß ein plus, mithin ein Etwas *hinzukommen* (hier wären wir also zwar schon glücklich heraus. Allein es kommt noch besser). Dieß Etwas kann nicht *jenes *Eins selbst wieder seyn, denn sonst hätte es ja kein plus, sondern *bloß sich selbst wieder.* (Freilich!) Dieß Etwas muß aber auch von solcher Beschaffenheit seyn, daß * jenes *Eins dasselbe *annehmen* kann; wie brächte man sonst jenes Eins und * dieses * Etwas zusammen? Wäre dieses Etwas ein Eins, und wäre doch *nicht jenes Eins, so dürften sie sich fügen.* Wäre dieses Etwas kein Eins, und *jenes *Eins könnte es zu einem Eins machen - so dürften sie sich fügen. Wäre dieses Etwas z.B. Stoff, und der Stoff hätte eine *Form*, und diese Form wäre *als Form *unvertilgbar, und jenes Eins"}, {"type": "paragraph", "text": "könnte alles am Stoffe bis auf seine Form zernichten: so könnte *jenes *Eins dieses Etwas zu einem Eins machen, und jenes Eins und dieses zum Eins gemachte Etwas dürften sich fügen, *müßten *sich (beide also wechselseitig) fügen, weil keine Form die andere mehr zernichten kann. Wir hätten mithin 1 + 1, d.i."}]}, {"page_pdf": 1442, "page_book": 59, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "*wir wären heraus zu unserm Zwei* u.s.f.\" - Lese weiter, wer Lust hat; wir wollen jenes Eins und dieses Etwas sich aneinander nach Herzenslust reiben und fügen lassen. *Der Freund. *Hören Sie anderes. Der Satz: in Bezug auf die absolute Identität sey keine quantitative Differenz denkbar, und die absolute Identität sey nur unter der Form der quantitativen Indifferenz des Subjektiven und Objektiven, wird dem Satz gleichgestellt, das Denken als Denken leide keinen Quantitätsunterschied; was mir wieder wie die Faust aufs Auge zu passen scheint. *Der Verfasser.* Wie die Trivialitäten eines Rechenmeisters zu einem Satz des Euklid. - Von quantitativer Differenz, um dieß zuerst zu sagen, kann bei jenen gar nicht die Rede seyn, da sie eine qualitative, sonach absolute Differenz in ihrer unendlichen Mannichfaltigkeit haben. Von quantitativer Indifferenz aber noch weniger, da sie von einer andern als ihrer abstrakten, an der einen Seite gelähmten Identität nichts wissen. Ich machte durch jenen Satz zunächst den Gegensatz gegen alle Vorstellung einer *qualitativen* Indifferenz, nach der nämlich das Absolute nicht sowohl auf gleiche Weise, als vielmehr zugleich Erkennen und Seyn, ideell und reell ist. Ganz bestimmt hatte ich dabei die Sätze *Jacobis *in seiner Darstellung des Spinoza vor Augen: \"Beide (Gedanke und Ausdehnung) machen zusammen nur ein unzertrennliches Wesen aus, so, daß es gleichgültig (indifferent) ist, unter welcher von diesen Eigenschaften man Gott denkt\"; ferner: \"Das Denken an sich betrachtet gehört nach Spinoza ebensowenig zur Ausdehnung, als die Ausdehnung an sich betrachtet zum Denken gehört, sondern sie sind vereinigt, *einzig und allein, weil sie die beiden (gleich unendlichen) Eigenschaften eines und desselben untheilbaren Wesens sind.*\" (Briefe über die Lehre des Spinoza S. 183."}, {"type": "paragraph", "text": "191). Weil zwei gleich unendliche Eigenschaften voneinander nicht reell unterscheidbar sind, so tritt hier das ein, was Jacobi an einer andern Stelle sagt, die ich gleichfalls im Sinne hatte, die *Einheit *dieses Gottes (des Spinozischen) beruht auf der Identität des Nichtzuunterscheidenden, und schließt folglich eine Art der Mehrheit nicht aus1. Diese Einheit des Nichtzuunterscheidenden ist es, was ich quantitative Indifferenz nenne. Ich befinde mich folglich hier in einer Region, wohin mir nicht folgen zu können Reinhold sich bescheiden wird. *Der Freund.* Fast hätte ich vergessen, daß er Ihre Forderung: um die Vernunft als totale Identität des Subjektiven und Objektiven zu denken, von sich als dem Denkenden zu abstrahiren - mit der Forderung: um das Denken als Denken zu denken, von dem Ich, d.h. eben von der Identität des Subjektiven und Objektiven, zu abstrahiren, zusammenfließen läßt."}, {"type": "footnote", "text": "1 Obgleich allerdings solche verlegene Pretiositäten, wie die in dem Aufsatz: über das Unternehmen des Kriticismus u.s.w. sich für ein Journal qualificiren, welches bestimmt ist, die Philosophie um einen wesentlichen Schritt rückwärts zu versetzen, so hat der Verfasser seine wahre Meinung über das Unwesen seines Freundes Reinhold doch nicht unbezeugt gelassen in folgenden Stellen, von denen es zu verwundern, wie sie jener ohne Zwischenrede hingehen lassen, da er sonst zudringlich genug ist, den Vortrag Jacobis mit seinen saubern Anmerkungen zu verbrämen. - S. 45. \"Ich habe nun 18 Jahre lang zu begreifen gesucht, und es ist mir mit jedem Jahre nur unbegreiflicher geworden, wie ihr ein Mannigfaltiges, zu welchem die Einheit, und eine Einheit, zu welcher das Mannigfaltige - nur hinzukommt, euch vorzustellen, oder diese reine Begebenheit auf irgend eine Weise zu denken vermögt. Vermögt ihr aber dieses nicht, sondern setzen beide, Mannigfaltigkeit und Einheit, sich gegenseitig dergestalt voraus, bedingen sie sich gegenseitig dergestalt, daß sie nur in einander und zugleich gedacht werden können, als forma substantialis alles Denkens und Seyns: was wird dann aus eurer ganzen apriorischen (aus dem Denken als Denken geführten) Weberei\". - S. 95. \"Die Philosophie muß mit Plato anfangen vom Maß; - im Princip des Individuirens ist gegeben das Geheimniß des Mannigfaltigen und Einen in unzertrennlicher Verbindung; das Seyn, die Realität, die Substanz. Unsere Begriffe darüber sind lauter Wechselbegriffe. Einheit setzt Allheit, Allheit Vielheit, Vielheit Einheit zum voraus. Einheit ist daher Anfang und Ende dieses ewigen Zirkels und heißt - Individualität, Organismus, Object - Subjectivität.\" (Was hier für eine Verbesserung der idealischen Subjekt-Objektivität beabsichtigt werde, ist nicht leicht zu sagen)."}]}, {"page_pdf": 1443, "page_book": 60, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "*Der Verfasser.* Hier fällt die Ungereimtheit gleich in die Augen. - Was in jener Stelle gesagt ist, hat eine ganz andere Beziehung. Es ist von derjenigen Abstraktion die Rede, welche, wie in der vorhin angeführten Abhandlung meiner * Zeitschrift * (Bd. 2, Heft 1, S. 118 [Bd. 4, S. 79]) gezeigt wird, nothwendig ist zu einer * reintheoretischen* Philosophie1, dieselbe, in Bezug auf welche es an einer andern Stelle derselben Zeitschrift (Bd. 1, Heft 2, S. 85 [Bd. 4, S. 77]) heißt: wenn man erst lernen wird, reintheoretisch bloß objektiv (in dem Sinne, wie man von einem objektiven Dichten spricht), ohne alle Einmischung vom Subjektiven zu denken, so wird dieß verständlich werden. *Der Freund.* Eine schöne Frage ist's, die Reinhold aufwirft, was denn nach der Abstraktion von dem Subjektiven in der intellektuellen Anschauung, wodurch das Objektive in derselben unmittelbar aufhört objektiv zu seyn, weil es dasjenige ist, worein alle Subjektivität und Objektivität selbst fällt,* übrig bleibe.* Er stellt sich nämlich vor, daß Sie von dem Subjekt-Objektiven *in* der intellektuellen Anschauung selbst abstrahiren. - Die vorzüglichste Merkwürdigkeit, die"}, {"type": "footnote", "text": "1 Zur Erläuterung stehe hier folgende Stelle aus dem angeführten Ort S. 122 [88]: \"Selbst in dem System des Idealismus mußte ich, um einen theoretischen Theil zu Stande zu bringen, das Ich (das subjektive Subjekt-Objekt) aus seiner eignen Anschauung herausnehmen, von dem Subjektiven in der intellektuellen Anschauung abstrahiren, mit Einem Wort, es als Bewußtloses setzen. Aber das Ich, insofern es bewußtlos ist, ist nicht = Ich, denn Ich ist nur das Subjekt-Objekt, insofern es sich selbst als solches erkennt.\" - Die hier geschilderte Abstraktion vom Subjektiven ist also der Weg zum reinen Subjekt-Objekt, = absolutem Ich, absoluter Identität des Subjektiven und Objektiven. Es mag hinreichend seyn, nur in der Anmerkung noch zu erwähnen, daß jene Menschen sich beigehen lassen, ihrerseits von einem objektiven Idealismus zu sprechen (Beitrag 1, S. 132). Fast sollte man hier eine Spur der oben angeführten Abhandlung erkennen. - Wenn es irgend einen objektiven Idealismus gibt, so ist es der, welcher in dem theoretischen Theil meines Systems aufgestellt wird. Denn daß das, was jene jetzt rationalen Realismus nennen, es nicht ist, bedarf so wenig eines weitern Beweises, als ihr dummes Versichern, ihre Philosophie sey der wiederaufgeweckte Platonismus und Leibnizianismus, für Kenner einer Widerlegung."}, {"type": "paragraph", "text": "er nachher auftreibt, ist: der Standpunkt der Philosophie in beiden Systemen sey der der *Vernunft - Der Verfasser.* Wollte Gott, daß er dieß von dem seinigen rühmen könnte! *Der Freund.* - die philosophische Erkenntniß eine Erkenntniß der Dinge *wie sie an sich sind*. *Der Verfasser.* Das steht freilich bei allen wahren Philosophen von Plato an, nur gerade in dem Grundriß der Logik erinnere ich mich nicht das Geringste davon gelesen, noch viel weniger wirklich gefunden zu haben. *Der Freund. *Damit er doch erführe, was Ihnen Vernunft und was Ihnen Dinge an sich sind, würde ich ihm den Rath geben, sich vom Herrn Professor Paulus zur schuldigen Danksagung für die Dedication dessen neue Ausgabe des Spinoza schenken zu lassen, welches dieser nur den Nutzen der Wissenschaft im Auge habende Gelehrte gewiß gerne thun würde, um ihm aus seiner groben Unwissenheit zu helfen. *Der Verfasser.* Vielleicht würde er dann auch sich bescheiden, über Spinoza urtheilen zu können. *Der Freund.* Hören Sie noch das Letzte. Nämlich er hat die Dreistigkeit, Erwähnung davon zu thun, daß Sie, wie der Lehrer, sich in Ihrem System der Bezeichnung durch Potenzen bedienen. *Der Verfasser. * Fast könnte ich versucht werden, dieß vielmehr für eine Redlichkeit von seiner Seite zu halten. Denn diesen Punkt, welcher ein bloßes Faktum betrifft, und auch rein faktisch ausgemacht werden kann, hätte er nicht berühren sollen, wenn er seinen Vortheil verstanden und im Auge gehabt"}]}, {"page_pdf": 1444, "page_book": 62, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "hätte. Es muß nämlich, wie sich einem jeden, der nur lesen kann, nachweisen läßt, nun auf den Lehrer unausbleiblich der Verdacht fallen, die Idee *von Potenzen in der Philosophie überhaupt*, auf jeden Fall, es sey nun von mir oder einem andern, den ich gleich anführen werde, sich angeeignet, diesen *bestimmten *Begriff aber von Potenzen in der Philosophie und die *Bestimmung der einzelnen Potenzen* sogar und ganz"}, {"type": "paragraph", "text": "insbesondere von mir entlehnt zu haben. Obgleich es mir freilich nicht gleichgültig seyn kann, wer meine Methode anwendet, ob jemand, der ihr gewachsen ist oder sie bloß ungeschickt nachahmet, so hätte jener doch meinetwegen diesen Unfug ruhig treiben können. Jetzt aber werde ich ihn mir freilich verbitten müssen. Den ausgedehntesten Gebrauch der allgemeinen mathematischen Zeichen, des + und - z.B., ferner der Bezeichnung von Begriffen durch mathematische Formeln (dieselbigen welche ich anwende) und durch Potenzen dieser Formeln insbesondere hat *Eschenmayer *in seinen 1797 erschienenen *Sätzen aus der Naturmetaphysik *und seinem ein Jahr nachher erschienenen *Versuch, die magnetischen Erscheinungen *a priori * abzuleiten*, gemacht. - In meiner *Einleitung *zur Naturphilosophie, die im Junius 1799 erschien, sind die hervorspringendsten Punkte meiner Deduktion des dynamischen und organischen Produkts folgende: \"Die anorgische Natur ist Produkt der *ersten*, die organische *der zweiten Potenz *- so wurde oben festgesetzt, es wird sich aber bald zeigen, daß sie Produkt einer noch *höheren Potenz *ist\": am angef. Ort S. 76 (Band 3, S. 322]. \"Der Lebensproceß muß wieder die *höhere Potenz *des chemischen seyn. - Der Widerspruch der Natur in Ansehung des organischen Produkts ist der, daß das Produkt produktiv, d.h. *Produkt der dritten Potenz *seyn soll, und doch als Produkt der dritten Potenz in Indifferenz übergehen soll\"; S. 77. 79 [323. 324]. \"Das Individuum hört schneller oder langsamer auf produktiv zu seyn, aber eben damit auch auf *Produkt der dritten Potenz *zu seyn, und den Indifferenzpunkt erreicht die Natur mit ihm erst, nachdem es zu einem *Produkt der zweiten Potenz *(bloß chemischen) herabgekommen ist\"; S. 79 [324]. \"Die Aufgabe setzt voraus, organisches und anorgisches Produkt seyen sich entgegengesetzt, da doch jenes nur die *höhere Potenz *von diesem ist\"; S. 81 [325] u.s.w. u.s.w. Ganz ähnlich sind nun auch in dem bekannten Grundriß die Potenzen gestellt, nur daß noch herbeigeholt ist, was im *Entwurf *der"}, {"type": "paragraph", "text": "Naturphilosophie (S. 200) [Bd. 3, S. 182] von der todten Materie als einem Schlaf-, dem Thierleben als einem Traumzustand der Monaden, dem Vernunftleben als dem Zustand der Erwachung (nach Leibniz) gesagt ist. Denn obgleich dort nur dem Menschen die dritte Potenz zugestanden wird, so erhellet doch, unter andern aus der sublimen Beobachtung einer Pferde-Vorstellung, daß ihm der Mensch in dieser Potenz nur gleichsam den Gipfel bezeichne; wenn man nicht annehmen wollte, daß sich der Lehrer gleich an die erste der oben angeführten Stellen, wo die organische Natur noch ein Produkt der zweiten Potenz heißt, gehalten habe - und über diese Potenzen ruft er dann pathetisch aus: \"diese Formeln werden bleiben, so lange eine Erkenntniß des Identitätsgesetzes, folglich eine Erkenntniß des Denkens, folglich eine Philosophie in der Welt bleibt.\" *Der Freund.* Man müßte das Pathos solcher Menschen schlecht kennen, wenn man es nicht zu deuten wüßte, und es verwundert mich, daß Sie problematisch von etwas sprechen, was ganz offenbar am Tage"}]}, {"page_pdf": 1445, "page_book": 64, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "liegt. Ihre* Einleitung* ist zeitig genug erschienen, um von ihm gegen das Ende seines saubern Produkts, wo das Unwesen mit den Potenzen erst angehet1, benutzt zu werden, und eben um die Gegend fängt auch das Schimpfen auf die Naturphilosophie an, der er es in dem, was er vom Wesen der Pflanze, des Thiers u.s.w. sagt, offenbar nachthun - wollte. Ich muß Sie nochmals an die schon erwähnte Stelle erinnern, wo er den in der Vorrede zu Ihrer Schrift"}, {"type": "footnote", "text": "1 Die Rohheit der Anwendung dieser Begriffe in jenem Werk braucht nicht weiter auseinandergesetzt zu werden, so wenig, als die schon von andern bemerkten groben Verstöße gegen die ersten Begriffe der Mathematik, die sich in seinen Formeln vorfinden. - In meinem System hat es mit den Potenzen diese Bewandtniß, daß sie im Einzelnen wie im Ganzen sind, z.B. daß ich der drei Potenzen zur Construktion jedes Körperindividuums ebenso bedarf als zur Construktion des Ganzen. Der Fall ist nämlich der, daß in der ersten Potenz alle Potenzen der (in Bezug auf das Ganze) ersten, in der zweiten der zweiten, in der dritten der dritten untergeordnet sind. Das einzig Reelle in allem, in dem Einzelnen wie im Ganzen, ist mir das A3, das, worin das Allgemeine und das Besondere, das Unendliche und das Endliche absolut eins sind, mit Einem Wort das Ewige."}, {"type": "paragraph", "text": "von der Weltseele (S. VIII) [Bd. 2, S. 350] aufgestellten Satz: \"Mechanismus ist ohne vorausgesetzten Organismus nicht zu denken\" sich zueignet, unmittelbar darauf anfängt seine Pöbeleien gegen Sie auszustoßen und, damit man ja nicht zweifelhaft sey, warum er dieß eben jetzt sich beigehen lasse, von dem \"vielversprechend, statt der Herberge zum Ich ausgehängten *Weltseelenschild*\" zu sprechen (S. 175). *Der Verfasser. *Er thut noch mehr; er versichert: an diesem Satz, daß der Mechanismus erst durch den Organismus möglich gemacht wird, hing ich, dieß sind seine Worte, schon lange so fest, daß ich *endlich* das viele von mir darüber Niedergeschriebene einem der größten deutschen Naturforscher zur Einsicht überschickte. *Der Freund.* So? und warum findet er denn nöthig, dieß hier zu erzählen? *Der Verfasser.* Einen nicht geringen Spaß könnte man sich machen, ihn anzuhalten, daß er diesen Naturforscher nun namhaft mache. *Der Freund.* Ich hoffe, er wird ebenso besonnen seyn, wie in einem ähnlichen Fall der bekannte Damberger, mit dem er noch andere Vergleichungspunkte darbietet, - ihn unter die Todten zu versetzen. Die Leerheit und Armuth an eignen Ideen geht so weit, daß in der Darstellung, welche im zweiten Heft der Beiträge abgedruckt ist, auch der Satz: der Organismus sey der aufgehaltene Strom von Ursachen und Wirkungen, die in der Kreislinie in sich selbst zurückkehrende Succession, in den rationalen Realismus aufgenommen und als gute Prise betrachtet worden ist. Hierin kann Reinhold in der Folge eine neue Aehnlichkeit auffinden. *Der Verfasser.* Sie wissen es ja aus der Recension; es läßt sich freilich nicht leugnen, daß ich viel materialiter Wahres gefunden, es fehlt nur an dem rechten Grund - man muß erst das Denken als Denken darunter stellen. *Der Freund.* Wenn nun jemand sehen will, wie die innere Angst sich in Worten ausspricht, so kann man ihm den Reinholdischen Aufsatz empfehlen. Was vergißt man nicht in der Verzweiflung? Es"}, {"type": "paragraph", "text": "fällt ihm sogar nicht ein, daß die ganze Construktion ihres Idealismus durch eine Stufenfolge von Potenzen fortgehet, und daß die Methode, die Sie in der neuen Darstellung anwenden, ganz die, nur in einer engern Sphäre, schon dem System des Idealismus zum Grund liegende ist."}]}, {"page_pdf": 1446, "page_book": 66, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Er hat in der Vorrede zum ersten Heft erklärt, daß, * wenn er sich auch dießmal wieder täusche * (und er sieht nun wohl, wie wenig dieß der Fall sey), dann auch sein Name - *verhallen *möge. *Der Verfasser.* Das wird er schon von selbst thun, ohne daß er ihm die Erlaubniß dazu gibt. *Der Freund.* Er ist mit Einem Wort todt und fühlt sich todt. *Der Verfasser. *Erwähnten Sie nicht gleich anfangs noch eines letzten Versuchs, den er mit einer neuen Darstellung seines Lehrgebäudes gemacht hat? *Der Freund.* Diese müssen Sie selbst lesen. *Der Verfasser. *Sie wissen, wie es mir geht, und daß ich mir von seinen philosophischen Aufsätzen in der Regel ebenso viel verspreche, als von dem Hexen-Einmal-Eins. Haben Sie einmal sich überwunden es zu lesen, so nehmen Sie auch noch die Mühe auf sich, etwas davon mir mitzutheilen. *Der Freund. *So viel ich selber davon weiß, gerne. Wie gesagt also, und wie aus seinem eignen Bericht in der Vorrede zu ersehen ist, so hat ihn besonders die Erlanger Recension aus dem Concept gebracht. - Gleichwie nun der Ameisen arbeitsames Volk, wenn etwa ein vorübergehender Muthwilliger ihren Bau gestört hat, mit geschäftiger Emsigkeit eilt, ihn so gut wie möglich wiederherzustellen, so suchte auch jener, nachdem die erste Bewegung vorüber war, die zerstreuten Lehrstücke seines Systems wieder zusammen, fing von vorne an zu commentiren und modificiren, und arbeitete die * bereits zur Hälfte ausgeführte *Darstellung der Elemente des rationalen Realismus in die gegenwärtige neue Darstellung um, welche, denn er ist hierüber ganz unbefangen, jetzt in derselben Form der methodischen Einkleidung erscheint, welche Spinoza seinem Lehrer Des Cartes,"}, {"type": "paragraph", "text": "Schelling aber für sein absolutes Identitätssystem dem Spinoza, Reinhold jetzt wieder Schellingen abgeborgt hat. Denn daß er nach empfundener Wirkung die Sache in der Form sucht, ist natürlich. Gott weiß, daß sie ihm sauren Schweiß mag gekostet haben, und daß er sich redlich gequält hat etwas der Art hervorzubringen; was aber die innere Evidenz betrifft, so findet man zwar sehr viele Erklärungen, Erläuterungen, ja sogar Erklärungen der Erklärungen und Erläuterungen der Erläuterungen, von 20 Worten im Durchschnitt 10½ gesperrt (wo, was dem Beweis an Schärfe abgeht, durch das Unterstreichen ersetzt wird), und Perioden wie folgende: das Wesen, welches sich selber *als *Wesen, im Wesen, und durchs Wesen an der Wirklichkeit als solcher wiederholt, folglich als Wesen, welches als Wesen an der Wirklichkeit den Charakter des Denkens als Denkens annimmt, ist das vernünftige Wesen: - desto weniger aber Lehrsätze, und noch weniger Beweise, versteht sich philosophische, nicht Erläuterungen, wie die angeführte vom Lesen und Hören hergenommene, der Nothwendigkeit der Zernichtung des Stoffs, um es damit zum Denken zu bringen. *Der Verfasser.* Andere bestreben sich, was seiner Natur nach unpopulär ist, populär zu machen, dieser aber scheint mir die Philosophie immer gebraucht zu haben, um die Popularitäten, über die er sich nie erheben konnte, zu depopularisiren und mit philosophischen Formeln zur Philosophie hinaufzuschrauben. *Der Freund. *Nur mit dem Unterschied, daß jene wissen, was sie thun, er aber gleicht jemand, der in einem tiefen Traum liegend sich an schweren Zweifelsknoten abarbeitet, und wenn er erwacht, findet, daß es ganz gemeine Dinge waren, nur daß *er* nicht erwacht und von einem Traum unmittelbar in den andern fällt. Von seinen letzten Sätzen zwar braucht man größtentheils nur die unförmliche Form hinwegzunehmen, um nichts als Plattitüden dahinter zu finden; wie die angeführte, daß das vernünftige Wesen ein denkendes Wesen sey und dergl. Ich habe nun freilich zunächst und vorzüglich nach den neuen Krümmungen und Auswegen gesehen, die er sich zu machen sucht."}]}, {"page_pdf": 1447, "page_book": 68, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "*Der Verfasser.* Diese müssen wir ihm verrennen. *Der Freund. *Obgleich er die Leser in der Vorrede glauben machen will, es hätte mit der neuen Darstellung nichts weiter auf sich als die Anwendung dieser Form, so hat er doch nicht unterlassen, von Ihrer Darstellung in der Sache so gut zu lernen, als er es verstand, nur freilich, daß er es sehr schlecht verstand. Von seiner absoluten Identität zuerst zu sagen, so ist die unendliche Wiederholbarkeit für dießmal wirklich nicht wiederholt worden. *Der Verfasser. *Wir sind schon übereingekommen, daß wir dieß nicht zugeben werden. *Der Freund. *Freilich, man merkt wohl die Stelle, unter welcher Sie das Feuer angemacht haben, und von welcher er gerne ganz sachte hinwegrücken möchte. *Der Verfasser.* Was ist sie ihm denn aber jetzt? *Der Freund. * Sie ist nichts mehr und nichts weniger als der Charakter des Denkens als Denkens, und dieser Charakter ist nichts mehr und nichts weniger als die absolute Identität. *Der Verfasser. *Ganz genau wie der Narr in *Was ihr wollt: *das was ist, ist, denn was ist * das *als *das*, und *ist *als *ist. Der Freund. *Dieß gilt aber, wohl zu merken, bloß *vorläufig *- (denn sein ganzes Philosophiren ist nur vorläufig) - es ist bloß problematisch, hypothetisch aufgestellt, nur eine Préambule, eine einleitende Exposition, nichts weiter (S. 193). *Der Verfasser.* Ich finde das vortrefflich. *Der Freund. *Was aber ihm und dem Lehrer die absolute Identität apodiktisch und kategorisch genommen sey, das kann sich erst am Ende des Tappens finden, und dann auch allein sich ergeben, ob und inwiefern in der Anwendung des Denkens * Subjektivität, Objektivität oder beides zugleich *enthalten sey. *Der Verfasser. *Ueber alle Maßen verständig! Man soll ihm seine absolute Identität nur nicht gleich so heftig und kategorisch hinsetzen, damit sie ihrer gichtbrüchigen Natur wegen nicht vollends entzwei geht. Nach und nach findet es sich schon. Man muß ihr nur Zeit lassen."}, {"type": "paragraph", "text": "*Der Freund. *Durch dieses Hinterthürchen soll er uns nicht entkommen. - Sie müssen über diesen Punkt noch einiges hören. §. 12 wird versichert: im Objekt sey Möglichkeit und Wirklichkeit in Conjunktion, folglich Wirklichkeit und Möglichkeit nicht nur keines ohne das andere, sondern auch jedes im anderen, ohne daß darum gleichwohl eines das andere sey oder je werden könne. *Der Verfasser. *Da sehe doch einer, das klingt ja fast wie eine Beschreibung desselben, was wir Indifferenz genannt haben. Wie können denn Möglichkeit und Wirklichkeit im Objekt so conjungirt seyn, daß, ohne daß eines das andere ist, gleichwohl eins in dem anderen enthalten seyn kann, ohne durch etwas Höheres vereinigt zu seyn, genannt absolute Identität, die, da Möglichkeit und Wirklichkeit im reflektirten Erkennen, jenes dem unendlichen Denken, dieses dem unendlichen Seyn entspricht, nothwendig absolute Indifferenz des Denkens und des Seyns, der Idealität und der Realität seyn müßte. *Der Freund. *Sie können dieß noch bestimmter §. 15, Zus. 1 finden, wo es heißt: \"das Wesen, die Nothwendigkeit, das *absolute Seyn *als absolutes Seyn ist weder allein das Seyn der Möglichkeit noch allein das Seyn der Wirklichkeit noch allein beides zusammen (in wieferne nur keines ohne das andere ist), sondern es ist das Seyn der Möglichkeit als solches enthalten in dem der Wirklichkeit als solchem, und zugleich auch dieses als solches enthalten in jenem als solchem, ohne daß darum das Seyn der Möglichkeit zum Seyn der Wirklichkeit und dieses zu jenem geworden wäre und werden könnte.\" - Es ist offenbar, daß dieses auf eine absolute Identität des Subjektiven und Objektiven hinaus - will; da also dieser Satz seinem System im ersten Princip widerspricht, so gehört er zu den nöthig gefundenen Einlenkungen und ist auf keine Weise als auf seinem ersten Grund und Boden gewachsen anzusehen. Die"}]}, {"page_pdf": 1448, "page_book": 69, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "allerschönste Nothhülfe dieser Art aber hat er noch anderswo in dem Zus. 3 zu §. 26 versteckt. Dort heißt es (hören Sie und verwundern Sie sich): \"Auch die absolute Identität kann nur in ihrer *Anwendung *- als das *Absolute *gedacht werden.\""}, {"type": "paragraph", "text": "*Der Verfasser. * Sagt' ich's nicht, es werde so kommen? Denn kann die absolute Identität nur in der Anwendung als *absolut *gedacht werden, und ist in der Anwendung das Denken mit dem Stoff vereinigt, so kann sie also auch nur, insofern sie die Einheit des Denkens und des Stoffs ist, als Absolutes gedacht werden. Hier haben wir also die Einheit, worin die Einheit und der Gegensatz selbst wieder eines sind. *Der Freund.* Er verwickelt sich aber dadurch in die crassesten Widersprüche. Denn §. 4 heißt es: \"als *absolute *unbedingte Identität setzt das Denken als Denken schlechterdings nichts außer sich voraus.\" *Der Verfasser. *Gemach! Hier ist ja schon dasselbe, denn so setzt es ja auch den Stoff nicht außer sich voraus, und hat ihn also in sich. *Der Freund. *Keinesweges. Denn nach §. 5 setzt es nicht bloß in, sondern auch zu der Anwendung als Anwendung den Stoff allerdings voraus. Es setzt ihn also nur nicht voraus, weil und solange es nicht angewendet wird, sobald es aber dazu kommt, ist ihm nicht zu helfen. *Der Verfasser. *Es ist also, als ob man sagte: der reine Magen, als reiner Magen, setzt schlechterdings nichts außer sich selber voraus. Zu seiner Anwendung aber, als Anwendung, setzt er nothwendig einen Stoff voraus. *Der Freund.* Allerdings. Nun war aber in der andern Stelle behauptet, die absolute Identität sey nur in der Anwendung absolut; was also §. 4, insofern es *absolut* ist, nichts, außer sich selber, voraussetzt, wird §. 26 absolut, insofern es etwas außer sich voraussetzt. *Der Verfasser. * Das sind die härtesten Widersprüche, die mir noch vorgekommen sind. *Der Freund. *Wenn auch nicht das Vermögen da war, so war doch der gute Wille da, in aller Schnelligkeit etwas ganz anderes unterzuschieben. Um diese neuen Brocken anzubringen, mußte eben \"die schon bis zur Hälfte bearbeitete Darstellung\" in die *gegenwärtige neue Darstellung *umgearbeitet werden."}, {"type": "paragraph", "text": "*Der Verfasser. *Das wäre ja schlimmer als falsches Spielen. *Der Freund.* Ganz richtig. Er corrigirt seine Philosophie, wie man sagt, corriger la fortune. *Der Verfasser. *Thun Sie ihm nicht unrecht. Sagen Sie lieber umgekehrt: Er ist so schwach von Verstand, so unsicher seiner Sache, und benimmt sich so ungeschickt, daß er bei dem besten Willen von der Welt, den er hat, für einen Filou angesehen werden kann. Er hat sich schon bei andern Gelegenheiten ebenso bloßgestellt. Z.B. das merkwürdige Theorem, daß der Stoff zu den Vorstellungen von den Dingen an sich komme, mußte sich, als er es gegen einen Leipziger Recensenten nicht anders zu vertheidigen wußte, geschwind zu einer bloßen *philosophischen Excursion *bequemen (Siehe seine Beiträge zur Berichtigung bisheriger Mißverständnisse Bd. 1, S. 436). Damals hatte er es mit dem excursorischen, jetzt hilft er sich mit dem präcursorischen Philosophiren. Wer hätte dazumal glauben können, daß dieß eine bloß unbewußte heillose Ausflucht wäre; wer konnte ihn aber auch bei Bewußtseyn so einfältig glauben, einen Satz, den er mitten in einer Reihe von Theoremen mit Beweis aus dem Vorhergehenden und nothwendiger Folge für das Nachkommende aufstellte, und der noch überdieß zu seinem System ganz unentbehrlich war, bei sich selbst für eine bloße Excursion halten zu können? Dieser Fall ist also schon mehrmals da gewesen."}]}, {"page_pdf": 1449, "page_book": 71, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "*Der Freund. *Auch hat er auf diesen Fall sein Testament gemacht. Denn in dem Aufsatz gegen Fichte erklärt er: *seine Eigenliebe *würde in einem Fall, wo nur das eine oder das andere angenommen werden könnte, sich lieber eines hämischen und boshaften als eines über alle Maßen albernen, platten und gemeinen Verfahrens beschuldigt wissen (S. 204). Dem sey wie ihm wolle, hier ist noch eine Probe †. 4, Zusatz : \"die absolute Identität bleibt auch in ihrer Anwendung sich selbst gleich, folglich auch in der Anwendung des Denkens als Denkens - reines Denken.\" Sieht nun dieser Satz dem: die absolute Identität kann nie aufgehoben werden, nicht wie aus dem Gesicht geschnitten, und wie"}, {"type": "paragraph", "text": "fügt er sich mit dem obigen *Fügen *der beiden Eins des Denkens und des Stoffs, wodurch es zu einem Zwei kommt (oben S. 57. 58)? *Der Verfasser. *Wenn er freilich so mit der Zeit immer zulernt, und ferner so fleißig ist im Schaben und Ausputzen seines Systems, so kann er mit der Zeit, wenn er es nur nicht ganz durchsichtig schabt, wohl noch etwas herausschaben, es sey nun was es wolle, auf jeden Fall etwas, woran sein Autor weder jemals gedacht hat noch jetzt denkt. *Der Freund. *Allerdings, denn, was den Lehrer betrifft, so wird dieser freilich nicht mehr weit springen, nachdem ihn die Furie verlassen hat; er hat schon jetzt die beste Gelegenheit, aufs bestimmteste an seiner eignen Person zu erfahren: \"warum die Philosophie in der letzten Zeit so weit heruntergekommen?\" und überhaupt alle mögliche Veranlassung, die Philosophie mehr an seinem Ich als sein Ich in der Philosophie zu zeigen. *Der Verfasser. *Vergessen Sie den Stoff nicht, den vielgewandten, der vielfach umgeirrt. *Der Freund. *Nachdem er in der Elementar-Philosophie als ein Lehrsatz mit Beweis aufgetreten, hernach zur Zeit der Noth als bloße Excursion auswandern mußte, darauf nach seiner Zurückberufung noch im ersten (S. 111) und im zweiten Heft postulirt worden war, muß er sich nun hier unter dem Namen einer * Erklärung* einschleichen. *Der Verfasser. *Freilich, denn mit dem Beweis hat es schon seit jenen Zeiten nicht mehr fort wollen. *Der Freund. *Er ist davon aber auch bereits so dünn geworden, daß man mit ihm demnächst wird transparent decoriren können. Er heißt nämlich jetzt das an sich* Unbestimmte *und durch sich selbst Unbestimmbare. *Der Verfasser. *Die unendliche Mannichfaltigkeit ist ihm also bereits abgeschossen. - Auch diese müssen wir nicht fahren lassen. *Der Freund.* Ich bewundere nur die Albernheit, zu glauben, daß das Publikum solchen groben Betrug nicht merken und sich den abgetragenen Stoff noch immer für den ersten bunten verkaufen lassen werde."}, {"type": "paragraph", "text": "*Der Verfasser.* Und wo ist denn die unvertilgbare Form hin, die noch eben da war (oben S. 57)? Ich dachte, was eine unvertilgbare Form hätte, könnte nie so weit herunterkommen, ein an sich ganz und gar nacktes und bloßes Unbestimmtes zu werden. *Der Freund. *Auch ist die Zagherzigkeit darüber so wie über das ganze Lehrgebäude nicht gering. Wie in der Vorrede die doch gar zu auffallende Leerheit des Systems - mit der besonderen Vortrefflichkeit desselben entschuldigt wird, so bekommt auch die Abgeblichenheit des Stoffs ihre eigne Erläuterung, denn in der Erläuterung jener Erklärungen heißt es: inwiefern die aufgestellten Erklärungen dem Ergründen selbst und folglich auch der ergründeten und nur insofern kategorischen und apodiktischen"}]}, {"page_pdf": 1450, "page_book": 73, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Erkenntniß vorhergehen, machen sie auf keine andere als hypothetische und problematische Gültigkeit Anspruch. - Nun thue ihm einer etwas, um mit Fichte zu reden. *Der Verfasser. *O herrliche Fabel der Danaiden, wie oft und in wie vielen Exempeln bewährst du dich als höchste Wahrheit! Nicht der Strafe wegen, sondern aus lauter angeborener Angst vor einem *Grund* (welches ihre Strafe ist) gießen diese, nicht wie jene gezwungen, sondern freiwillig in ein löcherichtes Faß, *damit *es unten wieder auslaufe. *Der Freund. * Wenn doch nur einmal Beispielshalber auch die Geometrie von problematischen und hypothetischen Erklärungen ausginge - um zur apodiktischen und kategorischen Wahrheit zu gelangen. *Der Verfasser. *Mit Einem Wort, mein Freund, so viel auch für das Gegentheil zu sprechen schien, und obgleich er selbst erklärt hat, im Collisionsfall lieber für hämisch und boshaft als für über allen Begriff albern und einfältig gehalten zu werden, so können wir doch, nachdem wir alles wohl überlegt haben, und so sehr wir sogar seine Eigenliebe in Anschlag bringen mögen, für dießmal von seiner Erklärung keinen Gebrauch machen, und müssen nothgezwungen ihn als Muster und Exempel der Dummheit aufstellen, so, daß ich nun auch des festen Willens bin, für dießmal zum Werk zu schreiten und ihn in seiner natürlichen Beschaffenheit darzustellen."}, {"type": "paragraph", "text": "*Der Freund. * Es bedürfte dazu nichts als der ganz einfachen Entwickelung von Thatsachen, eben wie die in unserem Gespräch, ohne ein Wort davon noch dazu zu thun, und was verhindert Sie, nun gerade dieses Gespräch erscheinen zu lassen? *Der Verfasser.* Freund, bedenken Sie, was Sie thun, und wozu Sie mich versuchen. Wollen wir es darauf wagen, daß wir dem Reinhold anhelfen, wieder eins nachzumachen, gleichviel ob er es vermag oder nicht, wie die demonstrative Methode, und ihm dadurch aufs neue Gelegenheit geben, die Fadheit seines Geistes wie dort die seiner Philosophie zu zeigen, unsere eignen Einfälle gegen ihn an seinem Hacken herauszuziehen, um sie, wie es Nicolai thut, wieder wörtlich abdrucken zu lassen und sein Journal damit zu füllen. Denn er glaubt uns genug geschlagen, wenn er sie anführt, so wie er jetzt alles gethan zu haben meint, wenn er gezeigt hat, daß etwas auf die Identität des Subjekts und Objekts oder die Compenetration des Idealismus und Materialismus zurückkommt, als ob dieß etwas an sich Entsetzliches wäre, wobei er sich noch auf schon angeführte Gründe beruft, da er sich darüber doch nie anders als in einem sich unendlich wiederholenden kläglichen Geschwätz hat vernehmen lassen. Vorläufig und problematisch, bis er zu der apodiktischen und kategorischen Erkenntniß seiner selbst durch sich selbst kommt, hüllt er sich in den Mantel seiner Liebe und seines Glaubens an Wahrheit - und wird sanft; oder sollen wir es darauf wagen, seine Lammsnatur so weit zu überwinden, daß er zu formellen Lügen und Calumnien fortschreitet, welches mir leid wäre, weil wir alsdann, obgleich nicht selbst sündigend, doch Ursache von Sünde wären? Dabei ginge er allen schwierigen Punkten hübsch aus dem Wege, als da sind: der Dualismus, das Nebeneinander des animalischen Impulses, der das Denken afficirt, der Stoff, die Ein- und Unterschiebsel der neuen Darstellung, unsere Beweise, daß er so weit gekommen, nach einem Jahr nicht mehr zu wissen, was er vor 12 Monaten geschrieben, ja die eigne abgelegte Philosophie für eine neue Entdeckung und einen mit seiner Philosophie überzogenen und lackirten"}, {"type": "paragraph", "text": "Gassenjungen für einen großen Philosophen anzusehen. Mit Einem Wort - *Der Freund. *Ganz wie in seiner Erklärung auf Fichtes Antwortschreiben."}]}, {"page_pdf": 1451, "page_book": 75, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "*Der Verfasser. *Sie haben mir davon noch nichts gesagt; wie nimmt er sich denn da? *Der Freund.* Er gibt sich alle Mühe, den bittern Spott, mit dem ihn Fichte übergossen, für Schonung, Milde und Ueberrest ehemaligen Wohlwollens auszugeben, und überhaupt sein Publikum glauben zu machen, daß Fichte noch immer einige Achtung für ihn habe, während *Sie *freilich ganz aus allen Schranken gegen ihn gegangen; besonders rühmt er, daß ihn Fichte mein würdiger Freund nennt, ohngefähr in dem Tone, wie man seinen Famulus anredet. Hernach producirt er testimonia diligentiae et bonae applicationis, die ihm Fichte ehemals ausgestellt hat. *Der Verfasser. *Das weiß Gott, Fichte mag mit dem trocknen Schleicher seine theure Noth gehabt, und nicht Einmal, sondern unzähligemal bei sich selbst ausgerufen haben:"}, {"type": "footnote", "text": "Wie nur dem Kopf nicht alle Hoffnung schwindet, Der immer fort an schalem Zeuge klebt, Mit gier'ger Hand nach Schätzen gräbt, Und froh ist, wenn er Regenwürmer findet!"}, {"type": "paragraph", "text": "Er mißbraucht nun, was ihm Fichte vielleicht gesagt hat, um seine gedrückte Schülerhaftigkeit, die dem freien herrlichen Geist im höchsten Grad zuwider seyn mußte, in etwas zu erheben. - Was sollen denn jene Zeugnisse? *Der Freund. *Beweisen, daß es jetzt nur eine angenommene Miene sey, wenn man ihm sagt, daß er von der Wissenschaftslehre nichts verstanden habe. *Der Verfasser.* Ich dächte, das läge jetzt klar genug am Tage, und darüber könnte ein Zeugniß weiter nichts beweisen, als daß sich Fichte geirrt habe, so wie er auch in seinem Antwortschreiben sagt: er habe immer nur geglaubt, aber nie gewußt, daß ihn Reinhold"}, {"type": "paragraph", "text": "verstanden. Ich habe weder seine Recension der Fichteschen Werke, noch was er sonst von sich darüber ausgehen lassen, gelesen, außer der ersten Erklärung über die Wissenschaftslehre, an der ich ein- für allemal satt hatte, und kann also nicht sagen, inwiefern Fichte auch nur glauben konnte, von ihm verstanden zu seyn. Meine Meinung über jene erste Erklärung, welche darin bestand, daß er die Wissenschaftslehre keinesweges begriffen, steht im philosophischen Journal (Jahrgang 1797, 10tes Heft. [Bd. I, S. 409 ff.]). *Der Freund. *Damit läßt er sich nicht zurechtweisen. - So ist es auch bekannt, welche schnöde Begriffe von der Willensfreiheit und welche heillose Theorie, nach der sie in der bloßen Willkür bestünde, er aufgestellt und, wie man nun sieht, bis zu seiner letzten Sinnesänderung nicht abgelegt hat. Sie haben ihm in derselben Abhandlung und schon früher gezeigt, auf welchen schlechten Wegen er sich damit befinde. Nun legt er über dieselben gotteslästerlichen Vorstellungen - nicht etwa, wie sich allerdings gebührte, in seinem, sondern in Fichtes und Ihrem Namen seine öffentliche Beichte im deutschen Merkur und seinem Journal ab. Hierauf hat er zuerst die wahrlich doch nicht gleichgültige Anklage des Atheismus gegründet, bis er endlich so weit gelangte, am Ende des Aufsatzes gegen Sie zu fragen: darf hier Atheismus nur noch gewittert werden? - Werden Sie darauf keine Rücksicht nehmen? *Der Verfasser.* Haben so viele Erfahrungen, die er über die Trüglichkeit seiner Divinations- und Witterungsgabe zu machen Gelegenheit gehabt hat, nicht hingereicht ihn zu witzigen, so haben sie doch allen andern gezeigt, was sie davon zu halten haben, die Schmach aber dieser Verläumdung wird auf ihn selbst zurückfallen. Wo man hin hören kann, ist sein Name so in Verfall, daß kein Mensch ist, der auf seine Anklage achten wird. Soll ich die edle Zeit verscherzen, soll ich den Blick abwenden von dem, was allein mich fesselt, einzig beschäftigt? Mich können sie verläumden, schmähen, mitunter auch stören; die"}]}, {"page_pdf": 1452, "page_book": 76, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Sache aber, die sie lästern, wird den Neid schlechter Zeitgenossen überleben, und ist von dem an Zahl kleineren, an Gewicht"}, {"type": "paragraph", "text": "aber und an Einsicht bei weitem größeren Theil schon jetzt für das erkannt, was sie ist. *Der Freund. *So rathe ich Ihnen also nochmals, dieses Gespräch ohne weiteres niederzuschreiben, es erspart Ihnen die Zeit. *Der Verfasser. *Ich bin mit meinen Fragen noch nicht zu Ende. Wir haben unter uns gesprochen, wie wir unter uns zu sprechen pflegen, d.h. wir haben einen Hund einen Hund, eine Katze eine Katze genannt. Wollen wir es uns wieder nachsagen lassen, daß wir den Reinhold eine Schwachkopf genannt, ein Exempel der Dummheit, und von ihm geurtheilt, er sey ganz herunter, und lasse sich von einem Narren beschlafen, von dem Lehrer aber, er sey ein Narr, und in seiner Narrheit trivial, platt, pöbelhaft u.s.w. *Der Freund.* Lassen Sie doch , denn es ist schon viel zu abgenutzt, auf die falsche Humanität loszuziehen, diejenigen ruhig ihre Glossen machen, welche jene mild sich anstellende Rechtschaffenheit mit der beständigen Versuchung zu falschen Streichen und der alle Augenblicke eintretenden Gefahr, zur Niederträchtigkeit umzuschlagen, weit eher reimen können als die keine Rücksicht kennende Gradheit des Urtheils. Sie haben sich ja nie an sie gekehrt. *Der Verfasser.* Wollen wir uns das philosophische Talent und den einmal berühmten Namen unseres Gegenstandes vorrücken lassen? *Der Freund. *Das hat ja in der That und in der Wahrheit nicht nur jetzt nicht, sondern niemals für uns existirt. *Der Verfasser.* Wollen wir es auf uns nehmen, daß man es grausam von uns findet, ein Privatgespräch vor das Publikum zu bringen, das ich mit jemand gehalten, an dessen öffentlichen Aeußerungen es schon genug hat? Denn die Scene mit dem Lehrer gehört auch zu unserer gegenwärtigen Mittheilung. *Der Freund. *Bedenken Sie, daß jemand, der einen solchen Degout vor dem Schreiben bekommen, wie jener in dem Aufsatz über das sinkende Ansehen der Philosophie manifestirt, dem Sokrates, dem er sich in jener Rücksicht bescheidentlich gleichstellt, auch darin gleich"}, {"type": "paragraph", "text": "sey, daß man seinen Belehrungen Publicität geben darf, ohne ihn dadurch zu beleidigen. *Der Verfasser.* Wenn er nun aber, da es ihm schwerlich angenehm seyn wird, das gesprochen zu haben, und doch nicht Schwarz auf Weiß gegen ihn zeugt, förmlich ableugnete, was ich jedoch nicht hoffen will? *Der Freund. *So zeugt gegen ihn Ihr Wort und Ihre Ehre, die Sie dadurch, daß Sie es drucken lassen, zum Pfand setzen, daß er für einen Lügner zu halten sey. *Der Verfasser.* Sie schneiden mir alle Bedenklichkeiten ab; können Sie mir auch die letzte nehmen, daß Freunde mich tadeln werden, welche vielleicht ein kunstgerechtes Gespräch suchen und statt dessen ein ganz natürliches finden? * Der Freund.* Auch; denn der Freund nimmt es auf sich, Sie in kein Besseres hineingezogen zu haben. Wollen Sie nun? * Der Verfasser.* Ich denke; in Hoffnung künftiger, die erfreulicher seyn sollen. Leben Sie wohl."}]}, {"page_pdf": 1453, "page_book": 79, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Rückert und Weiß, oder die Philosophie zu der es keines Denkens und"}, {"type": "paragraph", "text": "Wissens bedarf."}, {"type": "paragraph", "text": "I. Der Realismus, oder Grundzüge zu einer durchaus praktischen Philosophie. Von *Joseph Rückert.* Leipzig bei G. J. Göschen, 1801. II. Winke über eine durchaus praktische Philosophie als Vorläufer derselben herausgegeben von *Christian Weiß. *Sanabilibus aegrotamus malis. Leipzig bei demselben. III. Lehrbuch der Logik. Von demselben. Daselbst, 1801."}, {"type": "paragraph", "text": "Der jedesmalige gemeine Menschenverstand, der sich im Kampf gegen Philosophie zum herrschenden Zeitgeist ausbildet, drückt auf die, welche unter ihm sind, zuletzt mit solcher Gewalt, daß einige oder mehrere aus der Menge endlich als die begeisterten Propheten und Sprecher desselben aufstehen. Welche eben ergriffen werden, ist völlig gleichgültig, wenn sie nur ergriffen sind; dann aber müssen sie als wichtige und kostbare Zeugen betrachtet und gewissermaßen heilig gehalten werden. Geraume Zeit oft gibt sich jener Geist nur in einzelnen, unentschiedeneren oder verhüllteren Wirkungen zu erkennen; viele, die nicht minder von ihm leiden, sträuben sich noch es zu offenbaren; endlich kommt es bei einem oder wenigen zum Durchbruch; von dem Moment an ist ihnen alle Furcht genommen, sie verkünden in Göttersprüchen die Weisheit der Zeit; hat erst einer gesprochen, so entzündet er auch"}, {"type": "paragraph", "text": "den andern, und macht den lange verhaltenen gemeinen Menschenverstand bei ihm frei, der nun endlich in vollen Strömen auszubrechen die Freiheit hat. In diesen Augenblicken der ersten überströmenden Fülle der Gemeinheit muß man sie hören, weil diese hier noch nicht gelernt hat sich wieder zu verhüllen, noch die Wonne verbirgt, einmal wieder frei ihr Innerstes bekennen zu dürfen. Wir sehen die Aussprüche und Verkündigungen der Herren *Rückert *und *Weiß *wirklich für einen solchen Gipfel und höchsten Ausbruch an, zu welchem der jetzige Zeitgeist in der Philosophie gekommen ist; wir werden vielleicht nachher Gelegenheit haben, eine Anzahl Philosophen namhaft zu machen, die minder offen, weniger begeistert, deßwegen doch nicht weniger beurkunden, daß sie unter denselben Einflüssen stehen und den gleichen Eindruck mit jenen erfahren haben. Das allgemeine Leiden der Zeit ist hier wirklich ausgesprochen, welches sich in dem kurzen Ausdrucke zusammenfassen läßt: ohne alle Philosophie gleichwohl eine Philosophie haben zu wollen; nicht als ob es ein fühlbares Leiden wäre, von jener ausgeschlossen zu seyn, sondern weil die Menge verdammt ist, sie zu wollen, ohne sie wollen zu können. Aus der Einen Quelle dieses Uebels entstehen die ungescheuten Klagen, daß es mit der Philosophie neuerdings in allewege darauf abgesehen sey, über den gemeinen Menschenverstand und die Thatsachen des Bewußtseyns hinauszugehen, ja überhaupt ein wirkliches *Wissen*, mit Ausschließung alles Glaubens, Voraussetzens, Postulirens u.s.w., in dieser Region zu erzielen, der Philosophie Einen Gegenstand zu geben, und von diesem Einen Gegenstand eine so bestimmte Idee zu Grunde zu legen, daß, wer diese nicht hätte, unmittelbar dadurch auf die Philosophie selbst Verzicht zu thun genöthigt wäre; hernach, wo diese Klagen sich, aus welchem Grund es sey, nicht laut zu werden getrauen, - Unwissenheitslehren mit dem peinlichsten, dicke Bücher hindurch"}]}, {"page_pdf": 1454, "page_book": 80, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "ausgehaltenen Bestreben, sich ja vor nichts so sehr als dem Gebrauch der Vernunft oder dem Ertapptwerden darauf zu hüten; endlich Skepticismen, welche nicht die Speculation gegen die gemeine Ansicht,"}, {"type": "paragraph", "text": "sondern umgekehrt diese in ihren plattesten Aeußerungen gegen jene in ihren höchsten kehren, zum wenigsten problematisches und hypothetisches Philosophiren, bis die zähe Masse in Fluß kommt, willkürliche Anfangspunkte; endlich wo das verborgene Uebel ganz an den Tag bricht, das laute Bekenntniß: *der Erbfehler mehr oder weniger aller Wissenschaften, der Philosophie aber insbesondere, habe darin gelegen, daß sie auf ein Wissen ausgegangen; alles Theoretisiren sey Thorheit, Einschränkung aufs Praktische dagegen, auf Kultur des gemeinen Menschensinns, Weisheit; alle wahre Philosophie bestehe einzig darin, diese Weisheit zu lehren u.s.w. *- Dieß ist dann das Bekenntniß der Herren Rückert und Weiß in den oben angezeigten Schriften, mit denen wir es nun ferner auf folgende Weise halten wollen. Wir legen billig das Original, die Schrift des Herrn Rückert, zu Grunde. Im Allgemeinen möchte zwar, was ein geistreicher Schriftsteller von den gewöhnlichen Uebersetzern sagt, und was auch auf andere paßt, nämlich, daß sie die gewirkten Tapeten auf der unrechten Seite zeigen, wo die Fäden gröber aussehen, hier weniger seine Anwendung finden, da es in Ansehung des gemeinen Menschenverstandes keine Originalität gibt; insofern jedoch möchte es auf Herrn Weiß (welcher nach S. VI der Vorrede zu Nr. 2 durch seine *Winke *ein öffentliches Zeugniß davon für sich und andere ablegen wollte, daß der Grund der neuen Philosophie *plötzlich *und *mächtig *wirke) seine Anwendung haben, da es begreiflich ist, daß die freigemachte Quelle des gemeinen Menschenverstandes hier schon viel offener, ungehinderter und gleichsam lustiger fließe, als bei jenem, der sie erst wieder auszugraben hatte; aus diesem Grunde werden wir Hrn. Weiß zu Hülfe rufen, wo sich jener uns nicht ganz ausgesprochen zu haben scheint. Im Allgemeinen haben wir das Verhältniß beider folgender Art gefunden. Es ist nicht zu leugnen, daß Hr. *Rückert *eine Neigung zum Soliden, eine gewisse natürliche Anlage zur dritten Dimension und zum Handfesten hat, die sich nur selten als Plumpheit äußert,"}, {"type": "paragraph", "text": "wie z.B., wenn er die Philosophen, die sich das Wissen zur Aufgabe setzen, *Speculanten, Wissenschaftler u.s.w. *(S. 6), das Speculiren einen *gelehrten Müßiggang * nennt, oder wenn er S. 5 sagt: Wer nach dem Grunde seines Wissens als Wissens frage, dem sey es nicht *Ernst *- ihn treibe speculative Neugierde, die eine *ernste *Philosophie *vor die Thür weise; *dagegen geht es bei Hrn. *Weiß *bereits ziemlich in die Fläche, was dort noch eine Art von Dicke hat, ist hier ganz erträglich dünne; bei Hrn. Rückert kann man noch etwas auf eine gewisse dumpfe und unbeholfene Verworrenheit des Kopfes rechnen, dieser dagegen ist ganz leicht und klar über die Sache des gemeinen Menschenverstandes; wahrscheinlich liegt darin auch der Grund davon, daß, was bei Hrn. Rückert noch als eine derbe Tendenz erscheint, hier ganz windig aussieht und eine völlig durchsichtige Armseligkeit angenommen hat. Der Hauptsatz dieser Philosophie ist zwar schon oben ausgesprochen worden; um ihn aber wo möglich in seiner ganzen Klarheit zu gewinnen, wollen wir noch einige von den verschiedenen Formen anführen, unter welchen er wiederkommt. \"Die Wahrheit ist eine *Aufgabe*, die durch Wissen nicht gelöst werden kann. - Alle realen Wissenschaften sind nicht durch Wissen, sondern auf praktischem Wege entstanden. - Dasselbe gilt auch von der Philosophie, sofern sie nur in der That Realität hat. - Die Gründlichkeit des Philosophen zeigt sich darin, daß er - - auf keinem Punkte sich *einbildet *(freilich!) etwas *aus*"}]}, {"page_pdf": 1455, "page_book": 82, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "*theoretischen Principien *oder *Gründen des Wissens zu erkennen. *(Warum wird hier vermieden zu sagen, aus theoretischen Principien oder Gründen des Wissens etwas zu wissen?) - Im gesunden Seelenzustande verlangt der Mensch das Wahre selbst gar nicht u.s.w. Rückert S. 12. 17. 19. 27. Die Leser müssen sich mit uns gedulden, bis wir im Stande sind vollends ganz klar herauszubringen, wie weit es mit diesem Verschmähen des Wissens und Theoretisirens gehe oder gemeint sey, und wie sich in dem Kopf der Hrn. Rückert und Weiß der Widerspruch von Wissenschaften, die nicht auf dem Wege des Wissens oder aus Gründen des"}, {"type": "paragraph", "text": "Wissens entstanden sind, und einer durchaus praktischen Philosophie aufgelöst habe. Zur vorläufigen Betrachtung wollen wir die Erklärung, die Hr. Weiß von *theoretisch *gegeben hat: \"theoretisch heißt alles, was durch ein Denken hinlänglich bestimmt werden kann\" (S. 20), und einige andere Erklärungen desselben, woraus sich in Kürze etwas über den Sinn jener Meinung abnehmen läßt, mittheilen. Nach S. 78 kann die wahre Philosophie *anheben *nur mit einer praktischen Richtung, welche der Philosoph genommen haben muß, *ehe *er philosophirt, und welche, nach der gegebenen Beschreibung, darin besteht, daß er auf das Wahre und Gute ausgeht,* nicht um es in seinem Grunde theoretisch zu erkennen *- dazu soll es also nie und nimmermehr kommen, auch nachdem man sich die praktische Richtung gegeben hat; man wird begierig seyn zu wissen, worin nun die Philosophie bestehe, welche nach jener praktischen Richtung erst *anheben *kann - *sondern*, fährt der Verfasser fort,* um sich nach und zu demselben unablässig zu bilden.* Sollte dieß noch nicht hinreichend befunden werden, so wird die Art, wie diese *Philosophie *gleich zu Anfang von Hrn. Weiß eingeleitet wird, allen möglichen Aufschluß darüber geben, was eigentlich ihn und seinen Autor drücke: es ist die sonderbare Eigenthümlichkeit aller bisherigen Philosophien, daß man ihre Grundsätze mit dem *Verstande *aufgefaßt haben oder *wissen *mußte, ehe man zu ihrem vollen Besitze gelangen konnte\" (Vorrede zur Nr. 2 erste Seite); an einen Gegensatz mit der Vernunft ist hier wohl nicht zu denken, da in dem ganzen Buche nicht das Geringste davon verlautet, beide vielmehr in ganz gleicher Verdammniß begriffen sind. So richtig jener Weg auch *scheinen möge*, so habe er doch dieses gegen sich, daß alle diejenigen übel berathen bleiben (ja wohl!), welche *bei dem besten Willen* nicht im Stande sind, *sich mit ihrem Verstande zu jener Einsicht in die Wahrheit der Principien zu erheben.* Man sieht also, für welche Art Menschen in dieser Philosophie gesorgt werden soll. Sie ist ein wahres Evangelium für den Pöbel, der zu ihr - dieß wird als sich von selbst verstehend vorausgesetzt"}, {"type": "paragraph", "text": "- eben auch ein Recht haben und gelangen soll, eine allgemeine Seligsprechung derer, die da arm sind an Geist. - \"Soll denn die Philosophie *Weisheitslehre *seyn (dieß ist nämlich Herrn Weiß eine ausgemachte Sache, und welche Weisheit gemeint sey, wird in der Folge klar werden), und zwar zu der Weisheit der einzig richtige Weg, *so scheint allen denen die Weisheit versagt zu seyn, welche nicht theoretisch genug gebildet sind, um durch Wissen der Principien der Philosophie zu ihr zu gelangen.*\" - Freilich, die Pforte ist eng, und der Weg ist schmal, der zum Wissen führet, und wenige sind, die ihn wandeln. Eine breite Heerstraße der Weisheit für alles Volk soll nun angelegt werden - nicht nur die des insgemein sogenannten, schon übrigens hinlänglich gemeinen, gemeinen Menschenverstandes, des theoretischen, sondern eine noch viel breitere des noch gemeineren praktischen. - \"Jetzt ist die Aussicht eröffnet zu einer andern *nicht auf Theorie gebauten Philosophie*\", welche also auch alle die Fehler vermeidet, die an den andern gerügt worden sind, nämlich, daß sie diejenigen ausschließt, die nicht Gaben genug haben, um"}]}, {"page_pdf": 1456, "page_book": 84, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "sich zur Einsicht in Principien zu erheben. \"Diese Philosophie unterscheidet sich von allen bisherigen Systemen vorläufig auch dadurch, *daß sie nicht zuerst auf den Verstand wirkt.*\" Sie nimmt dagegen die praktische Richtung in Anspruch, und wenn einer bisher sein *Heil *im Wissen suchte, oder wenn er *glaubte*, einen absoluten Grund alles Wissens in sich vor seinem Thun und unabhängig von demselben zu enthalten, so wird ihm nun vorerst das Irrige dieser *Meinung *deutlich gemacht u.s.w.\" Bei dieser Beschaffenheit der Sache hat Hr. Weiß hinlänglichen Grund, \"den meisten Beifall für diese *Philosophie *von denen zu erwarten, welche keinem System, *am wenigsten *dem neuen Idealismus streng zugethan sind\" S. VII, und da die Receptivität für diese Philosophie ohne Zweifel in gleichem Verhältniß der Entfernung von aller Theorie und theoretischen Uebung des Geistes zunimmt, so kann man ohngefähr sehen, wo Hr. Weiß die meisten Anhänger zu suchen haben wird. - Daselbst wird die praktische Richtung nach dem"}, {"type": "paragraph", "text": "Wahren auch noch als bestehend in einer aufrichtigen Lossagung *von allem ursprünglichen Ich und aller Willkür des Denkens und Handelns *beschrieben. Billig sollte der wenigstens, welcher *zuerst *diese Philosophie für das Volk, * die nicht auf den Verstand wirkt*, lehren wollte, zuvor die andere gelernt haben. Nachher freilich überhebt die *praktische Richtung *aller dieser Beschwerlichkeiten. Wir könnten hier unsere Anzeige beschließen, da es ohne allen Zweifel unsern Lesern mit uns klar genug ist, daß hier durchaus nichts von Philosophie zu suchen sey; allein theils scheint es uns nicht uninteressant, an diesem Fall eine Probe des vorläufig beschriebenen negativen Construirens zu geben, theils hoffen wir, indem wir die subjektiven Quellen dieser *Philosophie* aufzeigen (da an objektive nicht zu denken ist), wenigstens einige Fäden zu entdecken, durch welche dieses platte Gewebe von Unwissenschaftlichkeit mit einigen herrschenden Vorstellungen zusammenhängt, und zugleich bemerklich zu machen, wie ein bloßer Keim von Unphilosophie, den irgend eine wirkliche Philosophie, wie die Kantische, übrig läßt, mit der Zeit sicher wuchere und für sich unabhängiges Unkraut erzeuge. Die subjektiven Quellen also dieses Realismus betreffend, so ist die erste ohne Zweifel in dem gänzlichen Mangel an Kritik zu suchen, mit welcher die Verfasser von dem ganz aus der Erfahrung aufgegriffenen Gegensatz der Freiheit und Nothwendigkeit als einer absolut gewissen Sache ausgehen, an der es keinem Menschen einfallen könnte zu zweifeln; daß jene Entgegensetzung eine bloß abgeleitete, selbst nur im Bewußtseyn gemachte sey, und an sich so wenig ein Nothwendiges im Gegensatz gegen ein Freies als ein Freies gegenüber von einem Nothwendigen sey, ist ein Gedanke, der, eine einzige nicht verfolgte Spur bei Hrn. Rückert ausgenommen, den Verfassern offenbar nie beigegangen, und der ihnen ohne Zweifel auch unverständlich ist. Besonders zeigt sich bei Hrn. Weiß die Freiheit des Menschen als eine ganz unantastbare Sache, die überall vorausgesetzt wird als sich von selbst verstehend; keine Speculation kann sich dahin versteigen, sie zu leugnen,"}, {"type": "paragraph", "text": "als etwa die ganz absurde des Spinozismus, dem S. 29 entgegengesetzt wird: *der Mensch verliere in ihm seine eigne Existenz und sein selbständiges Wesen*, woraus ersichtlich ist, was es mit dem angeblichen Realismus, der Verdammung der Willkür und der Unterordnung unter das Reale für eine Bewandtniß hat, nämlich das eigne Daseyn und die Freiheit soll dabei doch bleiben (sie ist nach S. 31 ein unveräußerliches Gut des Menschen). - Im Spinozismus, heißt es ferner, ist dem Menschen nichts gelassen als ein *kraftloses *Gutseyn, eine Liebe, welche nicht Kraft mit Kraft, Streben mit Streben verbindet (im Spinozismus ist also Gott auch wohl ein Streben, eine Kraft; man sieht, daß dem Verfasser überall keine"}]}, {"page_pdf": 1457, "page_book": 86, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "andern als empirischen Begriffe vorschweben); späterhin (S. 31) heißt es sogar, der Mensch werde im Spinozismus um seine Freiheit *betrogen;* wir wünschten zu erfahren, in welchem einzigen Systeme, auch den Idealismus nicht ausgenommen, die Freiheit eine andere Realität als für die Erscheinung hätte, wenn schon S. 32 berichtet wird, es haben zu jeder Zeit Männer (welche andere aber, als die mit den Hrn. Rückert und Weiß sich am Boden der tiefsten Empirie hielten?) aufstehen müssen, welche es versuchten, die Freiheit in der Philosophie zur Ehre des Systems und das System zum Vortheil der Freiheit zu retten - *und das bedeutendste dieser Art sey der neueste Idealismus. *In demselben (S. 33) sey nichts ohne die Intelligenz, und die *Intelligenz *(sage Intelligenz) sey frei. Alles beweist, daß die Reflexion der Verfasser die tiefste Stufe der Absonderung vom Absoluten, die nämlich, wo sie als absolute Entgegensetzung erscheint, aufgefaßt habe; auch Hrn. Rückerts Beweis seines Lehrsatzes: die alte Aufgabe der Philosophie löse sich zuletzt in die Frage auf: wie es möglich sey, daß ein Freies mit einem Nothwendigen außer ihm harmonire, wird aus ganz empirischen Begriffen, faktisch, mit der beständigen Voraussetzung \"des eignen freien Wesens der Forscher\" geführt. Es ist nichts Seltenes bei einer solchen verworrenen Eingeschränktheit, daß ihr im Hintergrunde des Gedächtnisses etwas liegen bleibt,"}, {"type": "paragraph", "text": "worüber sie nun weiter nicht reflektirt, dieß braucht sie bei jeder Gelegenheit, und es ist gewöhnlich das, was sie verworren macht. So folgt allerdings, nachdem die Freiheit auf diese Weise vorausgesetzt ist, daß dem freien Wesen alles Nothwendige *gegeben * seyn müsse, so wie ferner mit diesem Mangel aller Kritik und Reflexion nothwendig die tiefste Subjektivität der Ansicht der Philosophie verbunden seyn muß. Wie denn Hrn. Weiß (nach S. 12) alle Evidenz eine bloß *subjektive Nöthigung *ist, nach Hrn. Rückert aber (S. 7) unsere Forderung (eines Grundes jener Harmonie des Freien mit einem Nothwendigen) nicht auf Wißbegierde und Speculationsinteresse sich gründet, - darin läge eine objektive Tendenz) - \"unser Interesse an einer solchen Harmonie hat vielmehr einen tieferen *ernsteren *Grund, und indem wir dieser (ernsten) Stimmung unseres Geistes uns bewußt werden, sehen wir keinen andern Weg zur Lösung unserer Aufgabe, als vor allem *unser Interesse *an einer solchen Harmonie, d.h. den *subjektiven Grund* hierüber *in uns selbst *zu erforschen.\" Die sogenannte praktische Richtung ist also nichts anderes als die Richtung auf die absolute Subjektivität. Nach S. 28 ist das Wahre nicht in der *Gewalt *des Menschen, aber er ist in der Gewalt des Wahren; in seiner Gewalt ist lediglich Harmonie mit jenem Wahren. Außerdem, daß dieß vorläufig auch das Fixe der Entgegensetzung zwischen dem Freien und Nothwendigen darthut, zeigt es auch die beständige Voraussetzung, daß die Philosophie sich an das zu halten habe, was *in der Gewalt *des Menschen ist, also natürlich ganz an das Praktische. Klar ist, wie von dieser aufs höchste gespannten Subjektivität, indem das Freie in der absoluten Entgegensetzung gegen das Nothwendige gedacht ist, der unmittelbare Sprung zu dem gemeinsten Realismus geschehen muß. Hiermit hängt genau das totale Mißverstehen erst des Kantischen und dann besonders des Fichteschen Idealismus zusammen, welches sich mit großer Arroganz, und von Seiten des Herrn Weiß mit ganz besonderer Naivetät äußert, und eine andere subjektive Quelle dieser Philosophie ist. Dem Herrn Rückert nämlich"}, {"type": "paragraph", "text": "ist es eine bekannte Sache, daß nach dem letzteren besonders *das Freie - * in* seinem *Sinne nämlich, in der empirischen Entgegensetzung gegen das Nothwendige - * das Nothwendige erschaffe; *dieß widerlegt er nun S. 21 ff. wie natürlich aus dem allergemeinsten Menschenverstand, indem er zeigt: Freiheit (im"}]}, {"page_pdf": 1458, "page_book": 88, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "angegebenen Sinn) solle durch etwas anderes als nothwendig bestimmt angesehen werden, dieß sey die Aufgabe - nicht daß sich das Freie selbst schlechthin bestimme, *denn auch der Böse bestimme sich schlechthin, sonst wäre er kein Böser.* Der Idealist verfahre bloß im Gefühle seiner Freiheit, und breche alle Schranken der Nothwendigkeit, mit ihnen aber auch den festen Grund und Boden, auf dem der Mensch stehe, und ohne den er gar keinen sichern Fuß habe, mit Füßen ein. Der Idealist sage uns: in dem Freien liege das Nothwendige selbst ursprünglich und nothwendig. - Dem widerspreche aber der gesunde Menschenverstand. Das Freie löse seine Aufgabe nicht so, daß es das Reale hervorzubringen strebe, sondern es solle und könne nur streben ein Bild des Realen zu werden. Auf diese Weise geht es denn nun weiter. - Wer zweifelt an allen diesen gemeinen Menschenverstandswahrheiten? Die Sache ist nur die, daß von dem *Freien*, wie es Hr. Rückert bestimmt, nicht nur insofern nicht, als es das Reale hervorbringen soll, sondern überhaupt nicht und in keinem Zusammenhang in der Philosophie die Rede ist. Es gehört ganz und gar zu der Empirie, und die Philosophie hat nichts mit ihm zu schaffen, mit allen jenen gesunden und derben Wahrheiten schlägt also Hr. Rückert seinen eignen gemeinen Menschenverstand, der den Idealismus für etwas nahm, was er so ohngefähr auch begreifen könnte. Durch die ganze Schrift bemerkt man keine Ahndung, daß es wohl etwa nicht das Rechte seyn möchte, die Philosophie überhaupt und den Idealismus insbesondere auf diesen ganz gemeinen Standpunkt herunterzunehmen, wo jeder Taglöhner und Markthelfer auch steht und ihn, wenn er nur so viel davon wüßte als Hr. Rückert (welches leicht möglich wäre), auch auf gleich geschickte Weise widerlegen würde. In dieser bleiernen Dumpfheit spricht er nun weiter in demselben Tone fort: dem Realismus,"}, {"type": "paragraph", "text": "versteht sich dem Rückertschen, gegenüber, sey der consequente Idealismus praktischer Egoismus und der Anfang aller Verkehrtheit und Thorheit des Menschen (S. 42), ein bodenloses System der absoluten Willkür (S. 54; S. 63 werden Willkür und Idealismus als ganz gleichbedeutende Worte eins an die Stelle des andern substituirt), der Idealist könne schlechthin an keinen Gott *glauben *(als ob es Philosophie wäre, an Gott zu *glauben*, welches Hr. Rückert S. 51 so erklärt: Ich glaube an einen Gott heißt: *ich thue, als wäre ein Gott *- welches denn philosophisch betrachtet die allerschlechteste und niederträchtigste Sorte von Atheismus ist); S.84 fällt dieser Plumpheit doch ein, daß der Fichtesche Idealismus das Ich im *Praktischen *gleichwohl von etwas Aeußerem abhängig mache, gerade wie Hr. Rückert; von diesem Satz, den freilich in seinem Menschenverstandssinn noch keine Philosophie geleugnet hat, glaubt er nun, er sey im Idealismus als eine philosophische Wahrheit enthalten, und findet darin die *einzig inconsequente Seite dieses Systems. * S. 97 dankt er der Wissenschaftslehre, daß sie auf dem Felde dieser Philosophie (des Idealismus) den wohlthätigen und täuschenden Nebel vollends zerstreut, und uns da *lauter Selbstheit und Willkür *gezeigt habe, wo wir zuvor noch eine Herberge des Nothwendigen ahndeten. Daß diese Ansichten bei Herrn Weiß noch mehr ins Klägliche übergehen, werden die Leser schon erwarten; wir wollen aber, um die zeitliche Abkunft dieser Philosophie noch bestimmter zu bezeichnen, besonders anführen, daß sie aus einem Gedränge der Verfasser zwischen Kant und Fichte entsprungen ist, über welches sich Herr Weiß folgendermaßen ausdrückt: \"Entweder kühn durchgeführt die Ideenreihe, *bis wo alle Realität Willkür wird *(nämlich wie im transscendentalen Idealismus), oder lieber * ein Ende gemacht aller Philosophie * und zurückgekehrt zur Heimath der Mutter Natur\", zu welcher wir denn Herrn Weiß alles Glück wünschen, und ihm vorläufig schon das Eichelessen des goldnen Zeitalters empfehlen wollen1."}, {"type": "footnote", "text": "1 Man vergleiche zu dieser Wendung die ganz ähnliche, die sich in Abth. 2, Bd. IV, S. 22 findet. D. H."}]}, {"page_pdf": 1459, "page_book": 89, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Gleichwohl ist es offenbar genug, daß die beiden Herren Rückert und Weiß auch nur die Möglichkeit, über ihre Plattheiten sich zu äußern, und ihnen wenigstens diese Form zu geben, ja selbst den ersten Gegensatz, mit dem ihr vermeintes Philosophiren beginnt, Kant und Fichte zu danken haben, und wenn Herr Rückert außer andern Anmaßungen gegenüber von Kant auch noch die hat, zu sagen: *Friede *sey zwischen dir und mir! oder wenn er Fichten, nachdem er die oben angeführten Aeußerungen über die bodenlose Willkür seines Systems gethan, anredet: \"Edler Fichte, verzeih! Nein, du selbst bist ein anderes Ich als das, welches uns deine Lehre zeigt - ich sage es laut: *dein wahrer reiner Geist ist der Inhalt dieses Schriftchens*\" -, so hat er zu dem Ersteren allerdings insofern einigen Grund, als Kant die wahrhaft speculative Seite des Wissens in die praktische Philosophie gewiesen hat, zu dem Letzteren aber insofern, als er, selbst zum Volk sich rechnend, den wahren, reinen Geist Fichtes in einigen seiner populärsten Aeußerungen und Schriften sucht, wo denn allerdings etwa ein Rückertscher Menschenverstand einige Bestätigung für seine Herabsetzung des Wissens und die *praktische *Richtung der Speculation finden möchte, nach welcher das *An-sich *oder das Ur-Reale uns nur in der Pflicht vorgehalten wird , welchen Satz denn Herr Rückert auch Seite 67 zur Erklärung Kants anwendet. Sonst ist offenbar, daß eben jenes leere Denken, gegen welches Kant und Fichte streiten, für Herrn Rückert ebenso wie für die übrige Menge das *Wissen selbst *ist, und daß er sich insofern mit dieser in dem ganz gleichen Wahn befindet, nur daß er, weil er doch so viel gemerkt hat, daß jenes kein wahres Wissen sey, nun das Wissen überhaupt wegwirft. So wenig ist ihm das wahre Licht über Kant oder Fichte aufgegangen. Aus dieser gänzlichen Unwissenheit über ein absolutes Wissen, so wie der ersten fixen Entgegensetzung der Freiheit und Nothwendigkeit, die im relativen Wissen nie aufgehoben werden kann, folgt nun von selbst die Unfähigkeit, in welcher sich beide Verfasser befinden, sich außer den beiden Möglichkeiten eine andere zu denken, daß entweder das"}, {"type": "paragraph", "text": "Nothwendige aus dem Freien, oder das Freie aus dem Nothwendigen erklärt werden müsse, welche Unfähigkeit dann eine dritte subjektive Quelle ihrer *Philosophie *ist. Jene Voraussetzung liegt zwar schon Herrn Rückerts erstem Beweis zu Grunde; er wiederholt es aber ganz bestimmt mehrmals, unter andern S. 97, wo es heißt: Idealität und Realität harmoniren nicht durch Wechselbestimmung (wer behauptet denn dieses?); sie harmoniren bloß dann, *wenn das Reale als Grund des Idealen gedacht wird*, und nicht wieder umgekehrt. \"Sonst, spricht er nun wie im Traume fort, nimmt man an (wo denn?), alles Nothwendige habe ursprünglich seinen Grund in dem Freien.\" Da nun das Wissen gleichfalls in das Freie gesetzt wird, so muß jenes zu dem Nothwendigen, welches nach dem oben Angeführten zugleich Grund des Freien ist, dasselbe Verhältniß der Entgegensetzung haben wie dieses; hierauf beruht nun die einzige Art von Beweis, die für den Satz geführt wird: die Harmonie des Freien und Nothwendigen könne selbst kein Wissen seyn, und nicht nur schlechterdings auf dem *Felde *des Wissens nicht aufgefunden, sondern auch, aufgefunden, nie ein Wissen werden; denn, heißt es S. 7 f., sie soll das Denken und Wissen (das Freie) schlechthin bestimmen, mithin über alles Denken und Wissen als höchster Bestimmungsgrund desselben erhaben seyn und allem Denken und Wissen schlechthin vorhergehen. - Da wir unter Voraussetzung jener Harmonie erst überhaupt etwas wissen, so kann sie selbst kein Wissen mehr seyn. - Aus dem *bloßen Denken *(s. o.), Vorstellen und Wissen entwickelt sich nur leere Form. Die Realität des Wissens liegt in dem Bestimmtseyn durch etwas, das schlechthin *außer aller Sphäre des Denkens und Wissens liegt. -* Welches denn in Ansehung des Rückertschen Wissens wirklich ein unzweifelhafter Satz ist."}]}, {"page_pdf": 1460, "page_book": 91, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Bei Herrn Weiß ist jenes Verhältniß des Freien und Nothwendigen so entschieden, daß nach seiner Meinung außerdem nichts übrig bleibt, als \"daß beide gleich ursprünglich und unabhängig nebeneinander seyen\", welches aber, sonderbar genug, eben der Fall seiner Philosophie ist, denn die einzige Art, das Freie aus dem Nothwendigen abzuleiten,"}, {"type": "paragraph", "text": "die ihm dort (S. 65) selber beigeht, ist, daß das Freie ein von dem Nothwendigen *freigelassenes *sey, wobei er sich selbst bewußt seyn wird, nichts gedacht zu haben. \"Das Freie, fährt er hierauf S. 66 fort, ist nach allen Theorien etwas (freilich daran hat man noch nie gezweifelt), und für alles, was ist, wird ein genügender Grund gesucht; vom Freien also auch außer ihm im Nothwendigen. - Wollte man aber (S. 67) das Nothwendige durch das Freie bestimmt seyn lassen, \"so geschah dieß (das Bestimmen nämlich) selbst nothwendig, d.h. durch die Natur des Freien schlechthin, und dann ist diese selbst nothwendig und nicht mehr frei.\" Auch nur diese, obgleich noch immer oberflächliche Reflexion, konnte, weiter verfolgt, zu etwas Besserem führen. Der höchste Grund, den Herr Weiß endlich gegen den Idealismus vorbringt (denn wir müssen ihm die Gerechtigkeit widerfahren lassen, daß ihm S. 67 allerdings noch etwas von dem Fall beigeht, daß Nothwendiges und Freies etwa absolut eins seyn möchten), ist der: Wie kann das ursprünglich Identische widersprechend werden bloß dadurch, daß es von einer andern Seite (sollte heißen: von verschiedenen Seiten) angesehen wird; welche gemeine Menschenverstandsfrage denn schon hinreichend beweist, wie gut Herr Weiß jenen Fall verstanden habe. Die Meinung bei Herrn Weiß aber ist die, daß wir eigentlich weder den dritten noch den zweiten noch auch den ersten Fall annehmen, sondern uns ganz an den praktischen Weg halten, und auf diesem ein Bild jenes Realen, Nothwendigen - durch Freiheit!! hervorbringen sollen. Der unbedingten Achtung beider Verfasser für das, was sie Menschensinn, Menschenverstand u.s.w. nennen, brauchen wir nicht weiter besonders als einer ferneren subjektiven Quelle Erwähnung zu thun; nach S. 26 Rückerts muß der Philosoph dem gesunden Menschenverstand *Vertrauen einflößen *und sich deßhalb auf dem praktischen (empirischen) Standpunkte halten. - Der Stern des Philosophen ist ein Irrwisch, der gemeine Menschenverstand der Polarstern der Weisheit. Der Philosoph muß sich orientiren; an ihm ist die Reihe umzukehren und sich zu nähern, der Ausspruch des gesunden Menschenverstandes"}, {"type": "paragraph", "text": "ist *für sich *gewiß, der Ausspruch des Philosophen nur unter Bedingung u.s.w. (S. 28). Daß die ganze Folge von philosophisch seynsollenden Lehrsätzen nun aus solchen gemeinen Menschenverstandsbrocken bestehe, z.B. daß das Nothwendige die Willkür einschränke, daß der Mensch nur in Rücksicht seines Thuns frei sey, nicht aber in Rücksicht der Folge desselben, womit dann klärlich bewiesen wird, wie wenig das Freie gedacht werden könne als das Nothwendige schaffend - kann man aus dem Bisherigen von selbst ermessen. Hiermit verbindet sich eine besonders dem Herrn Weiß sehr beliebte Vorstellung von einer gewissen rohen Gesundheit der Seele, wobei man sich unwillkürlich an den *Chinesen in Rom *erinnert. Wenn wir nun noch die schon einzeln bemerklich gemachte Schwerfälligkeit der Reflexion in Anschlag bringen, die durch das Ganze geht und aus dem allgemeinen, nun einmal daliegenden Vorrath von Begriffen und dem Schatz der Sprache, ohne alle weitere Kritik, ohne alle Ahndung, daß es einer Rechtfertigung ihres Gebrauchs bedürfen möchte, Begriffe und Worte, wie es die Ergießungen des gesunden Menschenverstandes eben erfordern, aufgreift (z.B. S. 64 Rückert \"das Nothwendige außer dem Menschen ist *Thun auf ihn*\" u.s. ferner) - wenn wir auch diese Dumpfheit in Anschlag bringen, so"}]}, {"page_pdf": 1461, "page_book": 93, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "werden wir ein so ziemlich vollständiges Bild der Unwissenschaftlichkeit des Ganzen zum voraus entwerfen können. Wir haben nun noch das nächste Resultat aus der subjektiven Quelle dieser Philosophie und das letzte objektive Endresultat für Philosophie und Wissenschaft überhaupt zu betrachten. Wie sich das Freie und Nothwendige im Anfang, bleibt es auch in der ganzen Folge sich entgegengesetzt; dessen unerachtet aber wird das Nothwendige wieder zum Grund der Harmonie zwischen ihm selbst und dem Freien gemacht, das Freie im Nothwendigen gegründet. Es erhellt hieraus, nicht nur daß jener Gegensatz überhaupt ein schlechthin willkürlicher Anfangspunkt ist, und daß, um diesen Realismus zu erhalten, genau die Stelle des Bewußtseyns aufgefaßt werden müsse, wo das Freie *empfängt * und im relativen Gegensatz mit dem"}, {"type": "paragraph", "text": "Nothwendigen erscheint, - ein Müssen, für welches der einzige Grund selbst in der Willkür und der von dem allergemeinsten gemeinen Menschenverstand geleiteten Reflexion liegt, - sondern auch, daß es zu einer wahren und absoluten Harmonie des Freien und Nothwendigen auch im Fortgang nirgends kommen könne. Ist das Freie im Nothwendigen gegründet, so ist kein Grund, von dem *Gegensatz *anzufangen, sondern es muß mit dem Nothwendigen angefangen werden. Nachdem Herr Rückert sich mit dem Gegensatz lange genug gequält hat, kommt es S. 45 damit zum Durchbruch, daß der Mensch *als *frei schlechthin nichts sey. Wenn nun die Freiheit als Freiheit nichts ist, so konnte sie also der Nothwendigkeit auf keine Weise an die Seite gestellt werden. Man sieht wohl, warum diese Unwissenschaftlichkeit vermeiden mußte, die Freiheit gleich im ersten Princip zu negiren; ist das Nothwendige das Absolute, so mußte das Freie, als Erscheinung, aus ihm abgeleitet werden, welches dann speculativ, theoretisch gewesen wäre, und diesem gemeinen Menschenverstand schwer gefallen seyn würde; oder sollte die Antwort diese seyn: jene Ableitung sey unmöglich, so muß sich dann diese Lehre nicht für Realismus, sondern für irgend etwas anderes, eine Bouterwekische Unwissenheitslehre oder einen Schulzeschen Skepticismus ausgeben. Besonders merkwürdig in dieser Rücksicht ist der vierzehnte Lehrsatz S. 61, \"die Aufgabe einer Harmonie ist nur die Aufgabe eines *Menschen*, nicht eines Freien überhaupt; nur *für den Menschen ist Nothwendiges da; *und Mensch heißt selbst nichts anderes als ein Freies, das mit einer Aufgabe, d.h. abhängig, einhergeht.\" - Man muß den auch geschwächt hervorbrechenden Lichtstrahl anerkennen, wo er ist. Es bedurfte von dieser Reflexion aus, welche im Grunde nichts anderes sagt, als daß der Gegensatz von Freiem und Nothwendigem überhaupt keine Realität an sich habe, daß er nur in Ansehung des menschlichen, d.h. doch wohl des endlichen Bewußtseyns überhaupt gemacht werde, daß also an sich so wenig ein Nothwendiges als ein Freies sey - es bedurfte von hier aus keines Schrittes, sondern nur der genaueren Beachtung dieser Reflexion selbst, um diesen ganzen Realismus als ein in seinem Fundament null und"}, {"type": "paragraph", "text": "nichtiges Ding zu erkennen, und einzusehen, daß wahrhaft und an sich das Freie so wenig im Nothwendigen als dieses in jenem gegründet seyn könne, daß beides nur die relativen Gegensätze an einem und demselben seyen, das an sich weder frei noch nothwendig, aber eben deßwegen die absolute Einheit beider ist. Es ist nicht zu zweifeln, daß in machen Stellen, welche sich durch Stärke und durch Schönheit der Diktion, durch Innigkeit und ein wirklich ernstes Gefühl auszeichnen (z.B. beim XXVII. Lehrsatz, \"der Mensch und all sein Thun haben nur dann Realität, wenn er sich im freinothwendigen Thun seines Nichts"}]}, {"page_pdf": 1462, "page_book": 95, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "für sich, aber zugleich des ewigen festen Grundes, in dem er ruht, lebendig bewußt wird, d.h. wenn er nichts für sich seyn will, weil er in der That nichts für sich ist; und dieß handelnde Bewußtseyn ist selbst zugleich die höchste Regel der Wahrheit und alles seines Thuns\"), und mehreren andern ähnlichen Stellen, z.B. S. 90, dem Verfasser jene höhere Einheit vorgeschwebt habe. Denn mit jener Nothwendigkeit, die der Freiheit entgegengesetzt und ebenso unheilig ist wie diese, hat der Mensch ganz gleiches Recht zu seyn, und weit entfernt sich ihr zu unterwerfen, ist er vielmehr eben zum beständigen Streit mit derselben bestimmt, obgleich er auch von diesem frei zu seyn wünscht; jener Nothwendigkeit aber, welche nicht mit der Freiheit im Kampf liegt, jener göttlichen, übersinnlichen, unbewegten, heiligen, die Schicksal heißt, sich zu unterwerfen, ist die Lehre jeder ächten Philosophie und die einzige Weisheit. Mit einer solchen Nothwendigkeit aber ließe sich dann nicht jenes leichte und frivole Spiel des gemeinen Menschenverstands spielen; sie ist Gegenstand nur der Speculation, und wenn sie im Leben auch in ihren Wirkungen erfahren werden kann, so kann sie doch an sich selbst nur durch Vernunft und Philosophie erkannt werden. Hieraus ist nun ohne Mühe zu begreifen, wozu in diesem Realismus jene Nothwendigkeit werden müsse, nämlich allerdings zu der greifbarsten, gemeinsten und durchaus empirischen des gemeinen Menschenverstandes. Die Harmonie mit dem Nothwendigen ist nicht eine Harmonie mit dem Ewigen, sondern (wie im XXsten Lehrsatz ausdrücklich"}, {"type": "paragraph", "text": "festgesetzt wird) mit dem *Gegebenen; *auch S. 92 wird das Nothwendige mit dem *Anschaulichen *(bei Kant) parallelisirt, und Herr Weiß, welcher überhaupt keine Ahndung des Höheren verräth (S. 45, wo er von Kant spricht), setzt ohne Bedenken das *Reale *in die Erfahrung, welches denn in diesem Zusammenhang, wir scheuen uns nicht es zu sagen, die wahre Gotteslästerung ist. Das letzte objektive Endresultat des Ganzen construirt sich nun vollends von selbst. Das ursprüngliche Verhältniß des Nothwendigen zum Freien ist *Erfahrung * (S. 64). Alles Wissen ist bloß Form des Thuns, das Thun selbst aber, da es mit dem *Gegebenen *zu harmoniren hat, - *grober Empirismus*, welches denn auch die wahre und richtige Uebersetzung des angeblichen Realismus ist. - Der Euphemismus ist verzeihlich, da es sonst nicht an Erklärungen fehlt, die bestimmt genug sind. Es gibt schlechthin gar kein Wissen *vor * dem Handeln, wird dem gleichgesetzt: es gibt gar kein Wissen a priori (S. 74); dieses (Wissen a priori) ist auch, wie man deutlich sieht, das Höchste, was die beiden Verfasser in der Philosophie überhaupt kennen. \"Welchen Grund (a priori) mag auch wohl ein sich selbst genügendes (reines Ich) haben, aus sich herauszugehen, um dadurch eine Einschränkung seiner Thätigkeit von außen möglich zu machen?\" (S. 76 Rückert) - Wozu soll doch nur das Bewußtseyn erklärt werden? Ist diese Aufgabe der Philosophie in einem andern Interesse als in dem leeren der Speculation gegründet? - Das Bewußtseyn ist ja nie einem Zweifel unterworfen. - Nach Herrn Weiß (S. 24) hat die natura naturans des Spinoza und Fichtes reines Ich das Hauptgebrechen, daß sie ganz unabhängig vom *empirischen Ich * handeln. Auf derselben Seite erhalten wir auch den vollkommenen Aufschluß, wie es mit der *durchaus praktischen *Philosophie gemeint sey. Nämlich, daß etwa das *Objekt* praktisch sey, macht die Sache noch nicht aus; *für das Denken und dessen Geschäft ist es nicht praktisch. *Es ist also wirklich auf eine völlige Negation alles Denkens angesehen; und erst mit dieser ist die radikale Umkehrung des Spinozismus, deren sich der Idealismus"}]}, {"page_pdf": 1463, "page_book": 97, "page_kind": "toc", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "nur fälschlich gerühmt hat (d.h. aller Philosophie) wirklich geschehen. Man könnte die Frage aufwerfen, fährt Herr Rückert fort, ob dann nicht wenigstens die Logik vor dem *Richterstuhle *des Realismus als Wissenschaft a priori anerkannt werden müsse? - Keineswegs . . . Sie ist im Grunde nur das, was man jetzt unter dem Titel der *Moral *aufführt (S. 77). Der Weise nur kann eine Wissenschaft a priori besitzen, nämlich insofern er andern Gesetze und Vorschriften gibt, *sich selbst und ihren Zustand zu verbessern;* dieß ist aber nicht so gemeint, als ob er dieß vor aller Erfahrung wüßte, sondern nur vor der der andern, nicht vor seiner eignen. *Jede theoretisch behandelte Wissenschaft beruht als solche auf Willkür, ist Scheinwissenschaft und von aller wahren Realität entblößt *(XXVster Lehrsatz). Aus diesem Grunde beruht auch Mathematik auf Täuschung - nur weil der Grund dieser Täuschung außer ihr selbst liegt, kann sie in sich formell zusammenhängend und gewiß seyn (S. 104). Mathematik und Physik, wie sie dermalen angesehen und behandelt werden, sind Scheinwissenschaften und gehen den Weg des Idealismus. Wir behandeln sie als *etwas für sich*, da sie doch offenbar ursprünglich nichts anderes als Form unseres Thuns sind (S. 63). Nicht daß wir nach mathematischen und physischen Principien ein Haus bauen können, beweiset die Realität jener Principien. Das Häuserbauen ist selbst ein freies Thun, und ein Haus ein *freies *Werk, welches an und für sich bloße Form ohne alle Realität ist (S. 109). Da nun jene Principien (S. 108) erst durch ihre *Richtung auf Weisheit *den Charakter der Realität erhalten, so ersieht man leichtlich, daß sie auch in ihrer Anwendung auf das Häuserbauen nur durch die Richtung des Häuserbauens auf Weisheit Realität erhalten. - Nach Herrn Weiß ist, die Philosophie mag anheben wo sie will, ein Faktum allezeit das, wovon sie ausgehen muß (Logik S. 189); \"in das System des neuesten, sich kritisch nennenden, im Grunde aber transscendenten Idealismus (s. Hrn. Prof. Jakobs Annalen der Philosophie) können wir nicht eingehen, denn das *Faktum *der Erfahrung ist ein anderes: da ist (welche Tiefe der Reflexion!) in dem Bewußtseyn"}, {"type": "paragraph", "text": "nicht das *Ding*, sondern nur der *Begriff *vom Ding zufolge einer *Empfindung*, dieser Gedanke aber, dieses Wissen, wird bezogen auf ein anderes, welches theoretisch nicht erkannt, sondern ursprünglich nur nach praktischen Principien seyn kann\" (S. 198). - \"Die neue Philosophie ist Organon der Wissenschaften, indem sie ihnen *allen* den Weg zeigt, den sie an der Hand der *Erfahrung *zu gehen haben\" (No. 2. S. 86). Dazu bedarf es also eines Organons. Unter diesen Wissenschaften werden Anthropologie (wozu auch die Psychologie gehört) und Naturwissenschaft die vorzüglichsten seyn. Wir dächten, dieß alles hätten wir vorher schon ganz ebenso gehabt; die *psychologischen * Vorkenntnisse der Logik würden nun auch nicht mehr die schlechte Entschuldigung mit dem Zustand der Schulen bedürfen. Da es auf so viel Seiten doch nicht vermeidlich ist, daß den Verfassern nicht bisweilen eine Art von theoretischen Gedanken in die Quere liefe, oder irgendwo die Unvermeidlichkeit eines Wissens hervorspränge, z.B. bei Weiß S. 79: \"der Mensch fängt an mit dem reinen Entschlusse, *auszugehen *auf das Wahre - und es an sich abzubilden\" (wo man doch denken sollte, er müßte es in jenem Ausgehen erst gefunden, also gewußt haben, ehe er es an sich abbilden könnte), so muß man sich ihr Verwahren vor allem Wissen nicht nur privativ, als ein bloßes nur nicht Wissen, sondern als ein wirkliches positives Wehren gegen das Wissen vorstellen; und wenn Ulyß, um dem Gesang der Syrenen ungefährdet vorüberzuschiffen, seinen Gefährten die Ohren zuklebte, so muß man sich denken, daß sie erstens sich selbst nicht nur die Ohren, sondern alle Sinne und selbst den Verstand verkleistern, den aber, bei dem dieß nicht angeht, wenigstens mit dem Ankertau ihres Realismus an den Mastbaum zu binden suchen müssen. Herr Weiß ist in der That zu bescheiden, wenn er überall Herrn Rückert als seinen Vormann erkennt und ihm den ersten Stoß zu der neuen Weisheit zu verdanken haben will. Denn in der Logik zeigt er sich überall schon ganz in den rechten Principien, und als Probe seiner Begriffe von wissenschaftlicher Form führen wir hier nur einige Stellen dieses Buchs an, S. 199: \"die Philosophie kann nicht Wissenschaft"}]}, {"page_pdf": 1464, "page_book": 98, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "werden, sonst müßte das Wesen des Menschen ein Wissen und er *ganz allein auf den Satz des Widerspruchs gegründet seyn*\"; - ferner den §. 337., wo er sagt: Constitutive Principien in der Philosophie müssen zwar seyn - nur aber hier können wir keinen Gebrauch davon machen, denn 1) dient die analytische Methode ganz besonders gut zum Anfang; 2) aber würde man alsdann fordern, daß *Ein* Princip aufgestellt würde - denn mehrere entgegengesetzte wären der Einheit der Vernunft und dem Interesse der Wissenschaft zuwider - *allein dieß *(Eine Princip) *wäre nur in dem Fall möglich, daß die Erfahrung *ursprünglich nichts als *ein Produkt der Spontaneität sey - und dieß wird geleugnet. -* So ist es ja also mit constitutiven Principien in der Philosophie überhaupt nichts; sechs Zeilen vorher aber wird behauptet, sie müßten allerdings seyn. - Wer so sehr Stümper ist, hat wohl allen möglichen Grund, auf das Wissen und Theoretisiren Verzicht zu thun und den Grund einer Philosophie, *die nicht zuerst auf den Verstand wirkt*, plötzlich und mächtig auf sich wirken zu lassen. Unsere Leser werden in Ansehung des Herrn Rückert von selbst die Bemerkung gemacht haben, wie sich in ihm als würdigem Repräsentanten für die Philosophie der allgemeine praktische Brauchbarkeits- und Nützlichkeitsgeist der Zeit ausdrücke, und begreifen, wie die Absonderung des Handelns von aller Speculation, der Moral von den Ideen, als ob auch nur ein Handeln, das würdig ist so genannt zu werden, möglich wäre, ohne speculative Ideen in ihm auszudrücken, endlich auch diese Wendung nehmen mußte, und wie nun zuerst der auf das Wissen überhaupt geworfene Verdacht, dann die Wirkung, welche der Idealismus fast allgemein gehabt hat, die meisten in Ansehung ihres Denksystems bis zum absoluten Nihilismus zu reduciren, die äußere Form dazu geliehen hat, und wie hierauf von dieser totalen Zerknirschung und subjektiven Nichtsheit der Weg zu diesem Realismus nur Ein Schritt ist. Wie sich die von Kant dargethane Idealität der Außenwelt durch den Fichteschen Idealismus bei Herrn Rückert wirklich in eine absolute Willkür und Nichtigkeit, die nun ganz nothwendig ihr Entgegengesetztes"}, {"type": "paragraph", "text": "hervorbringt, verwandelt hat, kann man unter andern an der Art sehen, wie er die Täuschung, welche der Mathematik zu Grunde liegt, erklärt. Das Nothwendige, sagt er, ist für das Freie *ewig Eins*, wenn dieses sich nämlich frei auf dasselbe als seinen letzten Grund hinrichtet. Richtet es sich dagegen als Willkür auf sich selbst, so hört das Nothwendige außer ihm in dieser Eigenschaft für es auf; es ist nicht *ewig Eins*, es erscheint ihm als ein * Vieles*, Mannichfaltiges, Verschiedenes, als immer ein Anderes. - Auf diesem Standpunkte wird ihm die Sphäre, worin das (idealisch) Viele ihm *außereinander *erscheint, der *Raum*, die *Folge*, jenes Vielen - *Zeit *werden. Der Grund von Zeit und Raum ist also Willkür,* das in Willkür verwandelte Nothwendige. * Für einen auf seinen Grund gerichteten und der Einheit des letzteren sich bewußten Geist gibt es daher schlechterdings weder Raum noch Zeit, daher auch keine Mathematik u.s.w. (S. 104 ff.). Man wird in dieser Erklärung, außerdem daß sie nur nicht tief genug geht, um die wahre zu erreichen, auf jeden Fall eine gewisse herzhafte und entschlossene Art zu denken finden; und so wenig Ansprüche auf Philosophie und eine höhere Begeisterung, als die des gemeinen Menschenverstandes, das *Ganze* machen kann, so ist doch schon oben bemerkt worden, daß einzelne lichte Stellen und Blicke einer nicht durchgedrungenen, auch wohl nicht zum Durchdringen bestimmten Speculation darin angetroffen werden, so wie es unleugbar ist, daß der Wendung, welche das Denken des Verfassers genommen hat, wirklich eine kräftige und originale praktische Tendenz zu Grunde liege, die, wenn sie sich, anstatt gegen"}]}, {"page_pdf": 1465, "page_book": 100, "page_kind": "toc", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "die Philosophie, dahin kehrt, wohin sie ihrer Natur nach gerichtet seyn muß, nämlich gegen das Leben und die mehr äußern Sphären menschlicher Thätigkeit, sich mit viel Energie und Wirkung wird äußern können. Was aber den Herrn *Weiß *betrifft, * so *müssen wir gestehen, daß wir bei ihm weder Herzhaftigkeit noch Entschlossenheit des Denkens, nicht einen entfernten Zug von Speculation oder irgend eine andere ursprüngliche Richtung, als die der Geistesdürftigkeit und des Unvermögens gefunden haben, welches denn auch das Einzige ist, was sich"}, {"type": "paragraph", "text": "von ihm in diese neue Philosophie geworfen hat, die ihm nicht so sehr an ihm selbst willkommen ist, als weil sie ihn ein für allemal der Beschwerlichkeiten des philosophischen Verstandesgebrauchs überhebt und noch dazu bei aller Unwissenheit sehr weise und kluge Mienen anzunehmen erlaubt. Anders als höchst gemein kann man gewiß eine solche Art zu denken nicht finden, die gegen keine speculative Idee oder gegen die Speculation selbst eine andere Waffe hat als die Berufung auf die *Menschheit*, worunter nicht der vernünftige Theil derselben (denn sonst könnte unmittelbar auf diesen provocirt werden, auch ist es eben nicht um diesen zu thun, wie S. 75. 76 klar gesagt ist: der *Mensch *will nichts ursprünglich für sich seyn, kein *Ich, keine reine Vernunft *-), sondern offenbar der rein *thierische *oder wenigstens der thierische als nothwendige Zugabe zum vernünftigen verstanden wird. Sorge doch für die Menschheit in diesem Sinn wer da will, durch Rumfordische Suppen, Runkelrübenbau1 u.s.w., nur in der Philosophie wolle man nicht für sie sorgen. Herr Weiß aber meint, wenn er sagen könne: die *Menschheit *möchte diese Art zu philosophiren nicht gutheißen, eine Philosophie von Grund aus geschlagen und vernichtet zu haben. Von Kant heißt es, S. 45: \"dadurch, daß er auf dem *empirischen *Boden zu festen Fuß gefaßt habe, um zu jenen Speculationen, welche eine Abstraktion von allem *Gegebenen *fordern, gelangen oder sie gut heißen zu können, wenn ein anderer sie aufstellte - habe er sich zu seinem Ruhme *in seiner Menschheit bewährt*\"; nach S. 47 findet der *Mensch *Kants Resultat (daß zu der Sinnlichkeit und dem Verstand a priori noch *Empfindung *hinzukommen müßte) *richtig*, \"denn er hatte schon lange den Luftgebäuden der Metaphysik bedenklich zugesehen, und *freut *sich nun - der Antinomien in ihrer Leere\". - \"Der *Mensch *muß auch in der Philosophie eingedenk bleiben seiner *Natur* (welcher andern nach dem Vorhergehenden als der thierischen?), *damit dem Speculationsgeist Einhalt geschehe*\". - S. 55: \"Auch in Kants praktischer Philosophie, und noch lieblicher als dort (in"}, {"type": "footnote", "text": "1 Vergl. 1. Abth., Bd. 3, S. 622, Anm. 2. D. H."}, {"type": "paragraph", "text": "der theoretischen), * weht der gute Geist des reinen Menschen; *daselbst. - Daß sich der Mensch das Gesetz selbst gebe, welchem er sich doch stets unterworfen fühle, er, der stets unter dem Einfluß der Objekte steht, und geboren wird und stirbt, ohne gefragt zu werden (hier ist also die Thierheit ganz klar; an einer andern Stelle, S. 83, wird zu gleichem Zweck eine weitläufige Beschreibung der schwachen Anfänge des Menschen vom Gehen und Sprechenlernen an gemacht), - dieß begreift der *Mensch *nicht. - \"Die *Menschheit triumphirt *über die Wissenschaft\" (S. 53), dagegen (S. 62) im Spinozismus *seufzt *und *stöhnt* sie. Nach S. VIII der Vorrede verdient es wohl *von Neuem *untersucht zu werden, und fragt sich überhaupt noch: ob der *Mensch *ursprünglich ein Ich sey (dieß ist also die Untersuchung des Idealismus)."}]}, {"page_pdf": 1466, "page_book": 102, "page_kind": "toc", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Der Hauptfehler ist: das reine Ich ist nichts für die *Menschheit*, wahrscheinlich ebensowenig als der reine Raum der Geometrie. Der Hauptsyllogismus gegen alle theoretische Philosophie, der S. 79 noch einmal wiederholt wird, kommt darauf zurück: in der Philosophie als Theorie sey alles nur gewiß, sofern es nothwendig gedacht werde. Nun aber wirke im Denken nicht der *ganze Mensch*, also etc. Um die niedrige Art zu denken, die durch das Ganze geht, noch weiter einzusehen, muß man vorzüglich die Stellen lesen, wie S. 22, wo an der wissenschaftlichen Philosophie getadelt wird, daß man durch dieses Wissen noch nicht *gut *werde, und allerdings große Erkenntniß haben könne, ohne deßwegen *vernünftig zu leben*, wozu doch alle Philosophie benutzt werden müsse. - Wie mag doch, heißt es S. 61, dem *Menschen *jene Idee eines tadellosen Handelns (das reine Ich) genügen. - \"Für das reine Ich sey es ein ewiger Vorwurf, daß es vor aller Zeit *aus sich herausging * und die Welt der Objekte schuf,* um sich nachher in dieser Welt und durch diese Welt ewig zu quälen. *Freilich, wie es dem reinen Ich je einfallen könnte, sich bis zu der Individualität des Herrn Weiß zu beschränken, um sich mit Philosophie und der Behauptung seiner Thierheit gegen die Philosophie zu quälen, möchte ein schwer zu lösendes Problem seyn. - Wenn man diesen faden, unklugen Schwätzer nun wieder von dem * Ernst * und der *Würde *der"}, {"type": "paragraph", "text": "Philosophie, von dem *Heiligsten *und* Besten*, was auf diesem Wege, dem idealistischen, verdreht werde (S. 61), reden hört, oder wenn man Tiraden wie folgende liest: \"das Freie schaudert zurück, und Auflösung in alle Elemente ist Wohlthat gegen die *Zumuthung*, ein *Gott zu werden\" - es fürchtet dennoch immer, einmal ein Gott zu werden*! - so kann man sich dann erst einen vollkommenen Begriff von der Gemeinheit und Unwürdigkeit machen, die sich hier als * unverderbte Menschheit*, reine Menschennatur u.s.w. aufdringt. Wie wenig ernstliches Bemühen um Philosophie Herr Weiß sich gegeben habe, erhellt aus der leichtfertigen Unwissenheit, mit der er über die Lehren früherer Philosophen spricht, und man kann wohl sagen, der gänzlichen auch historischen Unkenntniß der Philosophie. Wissen kann Herr Weiß nicht, noch kann ihm in seinem ganzen Leben begreiflich werden, wie ganz und gar nichts er von Philosophie überhaupt verstehe; jener Punkt ist faktisch, und macht ihn vielleicht aufmerksam, da er doch dem Titel nach Professor der Philosophie heißt, insofern wenigstens sein Freies auf das Nothwendige zu richten, daß er aus der kleinen Periode von Pythagoras, der den Namen σοφός in den des Philosophen verwandelte, bis auf Herrn Rückert, der dieß nun wieder umgekehrt hat, - von der Philosophie soviel historische Kenntniß, als ohne eignen Geist möglich ist, sich zu verschaffen sucht. - \"Alle metaphysischen Systeme, heißt es S. 113, *enden * bei einem absoluten; *besteht* es in einem Seyn, so nennen sie es den *Gott*\"*. *Nach S. 14 konnte *Leibniz *nicht sich denken, wie zwei *ganz heterogene* Substanzen, Geist und Leib, aufeinander wirken. Nicht doch; Leibniz gab gar keine zwei ganz heterogene Substanzen, als Leib und Seele, zu; nach S. 70 aber bestehen bei Leibniz neben und außer den Monaden auch die Körper, und S. 14 wird dieß so erläutert: die Monaden empfinden,* und das Zeugniß der Sinne hierüber *(über das Empfinden?) *kann keine Täuschung seyn: es gibt also Körper -* dieß alles, wohl zu merken, nach *Leibniz*! Bei Descartes *wirken *nach S. 12 Materie und Geist aufeinander, allein ihre Wirkungen stehen unter der *Leitung *einer höchsten Macht. Welche richtige Vorstellungen"}, {"type": "paragraph", "text": "vom Spinozismus und Idealismus der Verfasser habe, ist schon hinlänglich früher bemerklich gemacht worden, welche Begriffe aber von der Würde der Philosophie, mag unter andern Folgendes zeigen: \"Zu allem andern, sagt er, nehme man nun noch, daß jede Philosophie als Wissenschaft, je vollkommener sie"}]}, {"page_pdf": 1467, "page_book": 104, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "war, um so mehr dem * gemeinen Menschensinne*, der natürlichen *Ansicht der Dinge *entgegen sprach. *Spinoza will mich bereden* (bewahre Gott, wer wird den klugen Herrn Weiß etwas bereden wollen? - Und der *thörichte Spinoza *dem *weisen Herrn Weiß *etwas weiß machen? Der weiß sich schon davor in Acht zu nehmen), *ich* sey* nur *eine Modification der Gottheit. (Daß Spinoza von Herrn Weiß bewiesen, er sey eine Modification der Gottheit, wird wohl sonst niemanden bekannt seyn; wär' es nun die billige Bescheidenheit, sich selbst für unwürdig zu halten, eine Modification der Gottheit zu seyn und auch nur einen Strahl der natura naturans in sich zu haben, so verdiente dieß Lob; Herr Weiß aber dünkt sich etwas viel Besseres und gar anderes zu seyn als *nur *eine Modification der Gottheit, und es wird nun ganz klar, wie hoch bei aller Unterordnung unter das Reale das vermeinte Ich und die *eigne *Menschheit des Herrn Weiß steht). - * Fichte*, heißt es weiter (S. 71), *bürdet mir auf*, durch eine höhere Thätigkeit als die *alltägliche* im Denken und Handeln (producire ich die Objekte). Es ist also nur die Nichtalltäglichkeit dieser Thätigkeit, was sie verdächtig macht. \"Wer *glaubt*, heißt es weiter, (*glaubt*) allen diesen Lehren? Ich frage, wer *glaubt *als *unbestochener Mensch*. Und woher hat denn die Philosophie das Recht, den *schlichten Menschenverstand *eines Irrthums zu zeihen? Sprach er doch laut und herrlich und lange vor aller Philosophie!\" - Jemand, der so ohne allen Verstand spricht, und indem er beständig den gesunden Menschenverstand als die gute * Gabe Gottes* im Mund führt, auf jeder Seite beurkundet, wie gänzlich es ihm selbst sogar daran gebricht, überhebt die Philosophie aller Kritik, und kann an seinen eignen Richter verwiesen werden. Wir werden uns nicht wundern, wenn die meisten Leser finden sollten, daß wir uns bei Produkten"}, {"type": "paragraph", "text": "der Art wie die Rückertschen und Weißschen über alle Gebühr verweilt haben. Wir führen aber dagegen an, erstens, daß solche Produkte nicht außer dem Zusammenhang des Ganzen betrachtet werden müssen und darum wenigstens Rücksicht verdienen, weil dieselbe Tendenz, die sich in ihnen nur auf eine auffallendere Weise kundgibt, sehr vielen, ja den meisten philosophischen Bestrebungen der Zeit, welche manchen Lesern alsdann vielleicht doch nicht so unmerkwürdig vorkommen möchten, nur verborgener, zu Grunde liegt; alsdann auch, daß jeder wissen müsse, zu dem bestimmten Zweck auch die bestimmten Mittel zu ergreifen. Wir werden uns auch ferner nicht verdrießen lassen, die Unwissenschaftlichkeit, Oberflächlichkeit, diesen Grad der Verwilderung, den man sich kaum so vorstellen könnte, und jene niedrige Denkart in der Philosophie, wo wir sie finden, mit gleicher Genauigkeit darzustellen; die allgemeine Versicherung der Plattheit hat auf die zunehmende Unverschämtheit derer, gegen welche sie gerichtet ist, keine Wirkung, als die, daß sie ihnen Muth macht, in Intelligenzblättern u.s.w. sich in gleicher Allgemeinheit und mit der ihnen eignen Arroganz dagegen zu wehren und vor dem Publikum weiß zu brennen. Darlegung von Gründen im Detail muß ihnen diesen Muth nehmen. Wir werden die Hoffnung nicht aufgeben, auf diesem Wege die Beendigung jenes immer mehr umgreifenden Unwesens erreicht zu sehen, daß, indem in jeder andern Wissenschaft und Kunst, auch der gemeinsten, zum Lehren, wenn nicht besonderes Talent, doch wenigstens Kenntniß des Geschehenen und Erfundenen erfordert wird, dagegen in der Philosophie alle Augenblicke andere ohne vorhergegangene Studien, ohne vorläufige Uebung des Kopfs auch nur an dem Vorhandenen, voll krasser Unwissenheit, die nur von ihrem Dünkel und ihrer pöbelhaften Art, über philosophische Dinge zu denken, übertroffen wird, sich zu Lehrern aufrichten. Die noch immer nicht erloschene Achtung für Gründlichkeit läßt auf die Erreichung dieses Zwecks um so sicherer rechnen, da jene, wenn sie durch Gründe, wie wir wohl wissen, absolut unverbesserlich sind, doch bis jetzt noch einige Scheu vor der öffentlichen Meinung haben (die sie jetzt nur zu hintergehen hoffen), und durch diese zuletzt wohl auch noch soviel"}]}, {"page_pdf": 1468, "page_book": 105, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Respekt vor der Philosophie bekommen möchten, um mit ihren unreinen Händen sie unberührt zu lassen. Wir wünschen, daß Herr Weiß seine Talente, die für die Philosophie von keinem Werth sind, andern Fächern nicht entziehe, worin sie glücklicher angewendet seyn würden, und in denen er sich durch Schriften, wie: über die Annehmlichkeiten des Landlebens oder den Einfluß schöner Naturscenen auf die Bildung des Herzens, oder allgemeinere: über den Nutzen der menschlichen Glückseligkeit, u. dgl. bei einem Theil des Publikums vortheilhaft empfehlen wird."}, {"type": "paragraph", "text": "Ueber das Verhältniß der Naturphilosophie zur Philosophie überhaupt."}, {"type": "paragraph", "text": "Der Zweck dieses Aufsatzes ist, mehrere, theils aus einer einseitigen und falschen Ansicht der Philosophie, theils aus Seichtigkeit und gänzlicher Unwissenschaftlichkeit entspringende Vorurtheile und Aeußerungen gegen und über die Naturphilosophie in ihr Licht zu stellen. Wenn hier ein Verhältniß der Naturphilosophie zur Philosophie überhaupt angenommen wird, so ist selbiges keineswegs als ein untergeordnetes Verhältniß zu begreifen: was Philosophie ist, ist es ganz und ungetheilt; was es nicht in diesem Sinne ist oder seine Principien von der Philosophie nur entlehnt, übrigens aber sich ganz von dem Gegenstand derselben entfernt und ganz andere als philosophische Zwecke verfolgt, kann nicht Philosophie, auch nicht im strengern Sinn philosophische Wissenschaft heißen. Alle Unterschiede, welche in dieser Rücksicht gemacht werden, sind leer und bloß ideell, es ist nur Eine Philosophie und Eine Wissenschaft der Philosophie; was ihr verschiedene philosophische Wissenschaften nennt, sind nur Darstellungen des Einen und ungetheilten Ganzen der Philosophie unter verschiedenen ideellen Bestimmungen, oder, daß ich gleich den bekannten Ausdruck brauche, in unterschiedenen Potenzen. Die vollkommene Erscheinung der Philosophie tritt nur in der Totalität aller Potenzen hervor; das Princip der Philosophie selbst hat deßhalb, als die Identität aller, nothwendig keine Potenz; aber dieser Indifferenzpunkt der absoluten Einheit liegt wieder in jeder besonderen"}, {"type": "paragraph", "text": "Einheit für sich, so wie in jeder sich alle wiederholen; das Construiren der Philosophie geht nicht auf ein Construiren der Potenzen, als solcher, und demnach als verschiedener, sondern in jeder nur auf Darstellung des Absoluten, so daß jede für sich wieder das Ganze ist. Das Verhältniß der einzelnen Theile in dem geschlossenen und organischen Ganzen der Philosophie ist wie das der verschiedenen Gestalten in einem vollkommen construirten poetischen Werk, wo jede, indem sie ein Glied des Ganzen ist, doch, als vollkommener Reflex desselben, wieder in sich absolut und unabhängig ist. Ihr könnt die einzelne Potenz herausheben aus dem Ganzen und für sich behandeln; aber nur insofern ihr wirklich das Absolute in ihr darstellt, ist diese Darstellung selbst *Philosophie*; in jedem andern Fall, wo ihr sie *als besondere* behandelt und für sie, als besondere, Gesetze oder Regeln aufstellt, kann sie nur"}]}, {"page_pdf": 1469, "page_book": 108, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Theorie eines bestimmten Gegenstandes, wie Theorie der Natur, Theorie der Kunst heißen. Ihr könnt, um dieß allgemein zu fassen, überhaupt bemerken, daß alle Gegensätze und Differenzen nur verschiedene Formen sind, die in ihrer Verschiedenheit wesenlos, nur in ihrer Einheit, und da die Einheit aller nicht wieder ein Besonderes seyn kann, nur insofern reell sind, als jede in sich das absolute Ganze, das Universum repräsentirt. Wenn ihr nun die Gesetze auf das Besondere als Besondere gründet, so entfernet ihr eben dadurch euren Gegenstand von dem Absoluten, eure Wissenschaft von der Philosophie. Die Naturphilosophie ist also, als solche, die Philosophie ganz und ungetheilt, und inwiefern Natur das objektive *Wissen*, und der Ausdruck des Indifferenzpunktes, sofern er in ihr liegt, *Wahrheit*, so wie desselben, sofern er in der ideellen Welt liegt, Schönheit ist, kann die ganze Philosophie von der theoretischen Seite angesehen, Naturphilosophie heißen1. Daß in anderer Rücksicht auch die Theorie der Natur, als speculative Physik, ihre Grundsätze aus der Naturphilosophie nimmt, geht uns hier nichts an, und wir schließen diese Beziehung für gegenwärtig"}, {"type": "footnote", "text": "1 Vergl. Zeitschrift für speculative Physik, Bd. 2, Heft 2, S. 127, im vorhergehenden Band S. 212, Note. D. H."}, {"type": "paragraph", "text": "völlig aus. Es ist von Naturphilosophie als solcher und *an sich* die Rede, nicht von dem, was von ihr nur abgeleitet ist, obgleich dieses fast allgemein mit ihr verwechselt wird. Nach diesen Erklärungen kann von einem Verhältniß der Naturphilosophie zur Philosophie nur die Rede seyn, entweder inwiefern ihre Idee auf etwas, das man für Philosophie hält, bezogen, oder inwiefern sie, in ihrer Absolutheit, als integranter und nothwendiger Theil der ganzen Philosophie betrachtet wird. Diese selbst aber kann wieder unter einem doppelten Gesichtspunkt betrachtet werden, entweder von der *reinwissenschaftlichen* Seite, oder in ihrer *Weltbeziehung*, welche vornämlich zwei Seiten hat, die Beziehung auf die Religion, sofern diese die zur unwandelbaren objektiven Anschauung gewordene Speculation selbst ist, und die auf die Moralität, sofern diese ein objektiver Ausdruck speculativer Ideen im Handeln ist1. Die Poesie, solange sie noch nicht Sache der Gattung oder wenigstens eines ganzen Geschlechts und das Ein und Alles einer Nation geworden ist, wird selbst nur in Beziehungen betrachtet; unbedingte und allgemeingültige Beziehungspunkte sind selbst nur die beiden angegebenen, auf die wir uns aus diesem Grunde auch in der gegenwärtigen Betrachtung einschränken wollen."}, {"type": "footnote", "text": "1 Vergl. in der vorhergehenden Abhandlung, S. 98. D. H."}, {"type": "heading", "text": "I.", "level": null}, {"type": "paragraph", "text": "Die schiefen Urtheile, welchen die Naturphilosophie von Seiten dessen, was man Philosophie zu nennen beliebt, ausgesetzt ist, sind so tief verflochten in den Grundirrthum, der fast allen neueren Bestrebungen und selbst den versuchten Umkehrungen unverrückt zu Grunde gelegen hat, daß man, um jene zu würdigen, nothwendig bis auf diesen zurückgehen muß. Da derselbe gewissermaßen zugleich der Centralpunkt der ganzen modernen Kultur ist, so ist für die Philosophie, die aus dem von ihr gezogenen Kreis von allgemeinen Ideen herausschreitet, nirgends ein Anknüpfungspunkt; der historische Faden, der sonst manche von einer Form der Philosophie zur andern zu leiten vermag, reißt hier ab, sie müßten in eine viel frühere Zeit zurückgehen, als ihnen bekannt ist,"}]}, {"page_pdf": 1470, "page_book": 109, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "um jenen Punkt zu finden; da also die, welche von einer Seite wirklich Philosophen sind, in der Regel kein anderes Beurtheilungsprincip als das ihrer eignen Beschränktheit, die es nicht sind, obgleich sie sich rühmen es zu seyn, kein anderes als das der historischen Vergleichung und Entgegenstellung haben, so ist ohne Aufdeckung des Punkts, über den sie vor allen Dingen hinaus müssen, ehe sie über den Grund und die Tendenz der Naturphilosophie zu urtheilen im Stande sind, ihre Meinung darüber auf keine Weise zu berichtigen. Dieser Punkt, über den sie bisher nicht hinaus können, ist, um es aufs kürzeste zu sagen, die unbedingte Forderung *das Absolute außer sich zu haben*; wie selbst aus der Wirkung des Christenthums, das die ganze Kultur der späteren Welt allgebietend bestimmte, und der Aufnahme des Absoluten in die innerste Subjektivität unmittelbar das Entgegengesetzte - gänzliches Hinausrücken des Göttlichen über die durch Zurückziehung ihres Lebensprincips erstarrte Welt - nothwendig entstand, ist hier nicht der Ort weiter auszuführen, so wenig als nöthig ist, die Tiefe und unüberwindliche Einwurzelung jener Forderung daraus weiter begreiflich zu machen, daß sie sich der höchsten Irreligiosität am meisten empfahl, welche, indem sie durch die Entfernung Gottes - als einer außer- und überweltlichen Substanz - aus der Welt ihm den höchsten Tribut der Frömmigkeit bezahlt zu haben glaubte, dagegen in dieser Welt desto freiere Hände behielt und sie nach dem gemeinsten Verstande sowohl betrachten als gebrauchen konnte. Daß aller Dogmatismus überhaupt, daß namentlich in den neuesten Zeiten Jacobis Predigen und Reinholds Versichern keine andere Ursache habe als jenes unaustilgbare Begehren, ist vielleicht allgemein genug anerkannt. Weniger anerkannt ist bis jetzt, daß die reine Umkehrung der Forderung, nämlich *das Ich außer dem Absoluten zu halten*, für die Philosophie ganz dasselbe Resultat gewähre, und der Grund, warum dieß nicht so allgemein bemerkt wird, ist folgender: da man, dem ersten Princip unbeschadet, das Absolute wieder als Glaube, mithin so, daß es theoretisch angesehen doch immer nur *im* Ich und *für* das Ich, und nur *praktisch* betrachtet *unabhängig*"}, {"type": "paragraph", "text": "*vom Ich, außer ihm * ist, in die Philosophie hintennach einführen kann, so hat man den Vortheil, sich *gegenüber vom Dogmatismus*, der das außer-sich-Haben des Absoluten behauptet, das leugnende und annihilirende Verhältniß zu geben, ohne daß man deßwegen das Absolute wahrhaft *im * Ich hätte, welches nicht seyn könnte, ohne dieses als besondere Form zu vernichten1. Es ist an sich offenbar, daß, wie das außer-sich-Setzen des Absoluten im Dogmatismus zum inneren und verborgenen Grund die Forderung hat, daß das Ich außer dem Absoluten bleibe, so das zugestandene und zum Princip gemachte Setzen des Ich außer dem Absoluten durch eine sehr einfache Nothwendigkeit hinwiederum das Setzen des Absoluten außer dem Ich zur Folge hat; daß aber die *Folge* wieder das innere Motiv des *Grundes* sey, wird vielleicht aus Folgendem klar werden. Bei dieser Wendung, welche allerdings eine *Umkehrung* des Dogmatismus ist, wird in der theoretischen Philosophie das *An-sich* geleugnet, nicht als ob das Ich es wahrhaft in sich, oder sich wahrhaft in es setzte, sondern: es wird schlechthin aufgehoben, seine Realität gänzlich hinweg geleugnet, *aus dem Grund, weil es doch immer wieder, als Gedankending, in das Ich setzbar, und insofern ein Produkt des Ich sey.* Hier ist also die Forderung offenbar ausgesprochen: *das An-sich müsse, um reell zu seyn, unabhängig von dem Ich, außer ihm seyn*, d.h. es ist die ganze Voraussetzung des Dogmatismus sonnenklar ausgedrückt. Die ganz eigne Verwirrung, eine Philosophie darum gerade für *Idealismus* und sogar vollendeten zu"}]}, {"page_pdf": 1471, "page_book": 111, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "halten und auszugeben, weil sie 1) das An-sich überhaupt (das absolut Ideale), 2) weil sie es *aus dem Grunde leugnet*, daß es nur als *Ding* an sich, als ein *Außer* dem Ich, demnach dogmatisch-realistisch, denkbar erscheint, hat außer der Tradition von Kant - der übrigens, wie sich beweisen ließe, ein ganz anderes Recht hatte, seine Philosophie Idealismus zu"}, {"type": "footnote", "text": "1 Vergl. im vorhergehenden Band, S. 356 (Neue Zeitschrift für speculative Physik, I, 1, S. 26). D. H."}, {"type": "paragraph", "text": "nennen, - seinen Grund wohl vorzüglich nur in dem Imponirenden, das es gegenüber von dem gemeinen Verstand hat, wenn ihm versichert wird, daß die einzelnen sinnlichen Dinge nicht außer ihm existiren, so wie in der verborgenen Wichtigkeit, die der Realität dieser Dinge gegeben wird, daß man *sie leugnen*, für das Charakteristische einer besonderen Philosophie halten, und diese sich durch solches Leugnen allein den Namen Idealismus verdienen kann. Weil aber nach der ganzen Absicht dieses *Idealismus* das Ich in seiner empirischen Integrität bleiben soll - denn eben darum wird das An-sich weggeschafft, weil um des Ich willen, das *für sich* bestehen soll, es auch außer demselben gedacht werden muß, - da er überhaupt sich zum Gesetz macht, das reine Bewußtseyn nur, sofern es im *empirischen* gegeben ist, anzuerkennen, dieses aber, das empirische, nicht ist ohne die Berührung der Objekte, so ist nothwendig, daß durch einen theoretisch *unbegreiflichen Anstoß* oder auch vermöge *unbegreiflicher* das Ich einschließender *Schranken* so viel Affektionen in es gesetzt sey'n, als den Objekten entsprechen; diese Seite des Ich ist die empfindende und zugleich praktische; durch die Anschauung, also in seiner Qualität als Intelligenz, deren innere Thätigkeit ein sich Hin- und Herbewegen ist, werden die Qualitäten der Glattheit, Rauhheit, Süßigkeit oder Bitterkeit in den Raum - die allgemeine Form des sich Hin- und Herbewegens äußerlich angeschaut - gesetzt, über Flächen verbreitet, und mit Einem Wort zu concreten Dingen ausgebildet. Daß dergleichen Popularitäten, so wie eine solche Vorstellung der Natur, nach welcher sie in Affektionen wie grün und gelb u.s.w., und dazu producirten runden oder eckigten Objekten besteht, eine Naturphilosophie füglich entbehren machen, ist offenbar genug. Besonders bemerkenswerth aber ist die Einbildung, die Natur annihilirt zu haben dadurch, daß man die Accidenzen in ihrer ganzen empirischen Realität erhalten und nur das Wesen oder die Substanz, dem sie inhäriren, in das Ich verpflanzt hat, als ob sie da nun nicht eben erst recht festsäßen und ganz unvertilglich wären."}, {"type": "paragraph", "text": "Es kann nicht zweifelhaft seyn, warum in dieser Form der Philosophie weder überhaupt eine Natur noch eine Naturphilosophie statuirt wird, das Letztere nämlich nicht etwa, wie jene sich den Schein geben möchte, weil Naturphilosophie einen empirischen Realismus begründet, sondern vielmehr, weil sie den in den oben beschriebenen Affektionen des Ich begründeten empirischen Realismus für nichts hält und auf das *An-sich* und Intelligible der Natur geht, - nicht weil sie einen Gegensatz der Natur und des Ich - ein Seyn der Natur *außer dem Ich* -, sondern weil sie eine absolute Identität behauptet, in der *beide* gemeinschaftlich versenkt werden, weil sie also weder in dem unbegreiflichen Anstoß noch in den unbegreiflichen Schranken eine wahre Schranke erkennt, und mit Einem Wort *absoluter Idealismus *ist. Wir müssen uns von der praktischen Seite jener Art der Philosophie noch genauer unterrichten, um ganz im Klaren zu sehen, welche Bewandtniß es mit ihrem Idealismus in Bezug auf Dogmatismus hat. Die Behauptung ist: vom theoretischen Standpunkt aus sey die Philosophie Idealismus; auf dem"}]}, {"page_pdf": 1472, "page_book": 113, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "praktischen stelle sich der *Realismus* her und trete in seine Rechte wieder ein. Es ist damit keineswegs auf ein wahres Erheben des Idealismus zur Absolutheit, in welcher er den Realismus von selbst begreift1, demnach auf keine wahre Aufhebung des Gegensatzes dieser beiden angesehen. Da ferner jener praktische Standpunkt doch auch wieder seine theoretische Ansicht hat - und nur das, was in Ansehung seiner speculativ behauptet wird, kann ja wirkliche Philosophie seyn - so löst sich auch von dieser Seite nothwendig das Ganze wieder in den Idealismus auf, der das Ich *außer* dem Absoluten und demnach auch dieses außer jenem hält. Um die Frage aufs rundeste zu stellen: Was ist es eigentlich, das diesen Idealismus antreibt den Realismus in der praktischen Philosophie zu suchen? - Es ist sein Begriff von *Realismus*, nach welchem das Ich das Absolute *außer sich* haben muß, *unabhängig von sich*, wenn es *reell* seyn soll."}, {"type": "footnote", "text": "1 Vergleiche im vorhergehenden Band S. 370 (Neue Zeitschrift für speculative Physik, I, 1, S. 46). D. H."}, {"type": "paragraph", "text": "Es gibt für ihn keine Realität des Absoluten als in dem Verhältniß der Sklaverei und Unterwerfung des Ich unter jenes; das Absolute muß in der Gestalt des absoluten Gebietens, das Ich in der Gestalt des unbedingten An- und Aufnehmens dieses Gebietens erscheinen, wenn seine Vorstellung von Realität realisirt werden soll. - Nur das Kategorische der Pflicht läßt mit sich nicht jenes in der theoretischen Philosophie getriebene Spiel treiben, daß es immer wieder als *Gedankending* in das Ich gesetzt und dadurch sein Produkt wird - *darum*, weil es in diesem Verhältniß die Qualität eines absoluten Außer-dem-Ich behält - ist es reell! - Dazu gehört aber, daß es wirklich nie zur absoluten Aufnahme jenes Kategorischen und Unendlichen in das Ich komme; denn käme es dazu, so wäre der unumgänglich nothwendige und erwünschte Gegensatz des Ich und des Absoluten aufgehoben; das Absolute wäre ja nun wieder im *Ich* gesetzt, also nicht mehr reell, es ist also nothwendig, daß dieses Verhältniß in einem unendlichen Progressus prolongirt werde, *wenn das System bleiben soll, unmöglich* also auch, daß in der Zeit eine Ewigkeit sey, und das Endliche sich die Unendlichkeit voraus nehme1. Weil aber die Empfindungen und Affektionen des Ich auch dazu gehören, daß es als empirisches, und demnach auch in der Entgegensetzung und bloß relativen Einheit mit dem reinen Ich, welches das reine Wollen selbst ist, erhalten werde, so müssen nun ferner diese Affektionen zum voraus so bestimmt seyn, daß sie den praktischen Zwecken der Vernunftwesen entsprechen. Das Licht ist kein Durchbrechen des göttlichen Princips in der Natur, kein Symbol des ewigen der Natur eingebildeten Urwissens: es ist, damit die leiblich aus zäher und modificabler Materie zusammengesetzten Vernunftwesen, indem sie miteinander sprechen, zugleich einander sehen können, so wie die Luft, damit, indem sie einander sehen, sie zugleich miteinander sprechen können. Diese Vernunftwesen, welche doch selbst wieder eingeschränkte Erscheinungen der absoluten Vernunft und ebenso empirisch sind als irgend ein anderes, an deren"}, {"type": "footnote", "text": "1 Man vergl. hier Briefwechsel Fichtes und Schellings S. 97 und zu dem gleich Folgenden ebendas. S. 105. D. H."}, {"type": "paragraph", "text": "Thun und Treiben man auch keinen Grund erkennen kann, warum sie eben diese Priorität behaupten,"}]}, {"page_pdf": 1473, "page_book": 115, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "sind demnach der allgemeine Stock im Universum, dem die gesammte Endlichkeit inoculirt ist. Welches aber die absolute Identität sey, worin jedem Vernunftwesen seine allgemeine und besondere Beschränktheit prädeterminirt, und in der auch die Natur zuletzt allein begriffen ist, wird sich aus dem Folgenden ergeben. Wie die nordisch-barbarischen Sprachen für das Absolute keinen andern Ausdruck haben, als der von gut hergenommen ist, so ist die moralische Weltordnung, nur paraphrastisch, Ausdruck einer gleichen - nicht Sprach-, sondern philosophischen Armuth. Indem das Absolute statt der speculativen eine rein moralische Bedeutung bekommt, geht dieselbe nothwendig auf alles über: daß auch das Universum auf eine moralisch bedingte Welt reducirt und alle übrige Schönheit und Herrlichkeit der Natur in dergleichen Beziehungen aufgelöst wird, hat keine Bedeutung, da diese doch großentheils nur aus Glattheit und Rauhheit, Grünheit und Gelbheit, wozu wir das Glatte und Rauhe, Grüne und Gelbe erst produciren, besteht. Es gibt keine andere Idee Gottes als die angegebene, weil er nur in dieser Beziehung, der der Pflicht, ewig außer dem Ich bleibt. Nur in einer sittlichen Ordnung auch kann die Natur entworfen seyn und Realität haben, denn nur in ihr kann jedem Individuum die allgemeine und besondere Beschränktheit bestimmt seyn, kraft welcher es sich selbst seine Welt entwirft, da diese überhaupt die Sphäre seiner Pflicht, und ohne den kategorischen Imperativ überall keine Welt ist. Die wahrhaft speculative Frage bleibt dabei noch immer unbeantwortet, nämlich wie das schlechthin Eine, der schlechthin einfach ewige Wille, aus dem alles ausfließt, sich in eine Vielheit und aus der Vielheit wiedergeborene Einheit - eine moralische *Welt* - ausbreite: zur Auflösung dieser Frage thut es nichts, daß das schlechthin Eine als ein *Wille* dargestellt wird; solche ideelle Bestimmungen sind für die Philosophie gänzlich zufällig und bringen die Speculation nicht von der Stelle. Jene Frage wäre eine unumgängliche, unvermeidliche Aufgabe, wenn diese Philosophie das, was für sie das Absolute ist, wirklich auch"}, {"type": "paragraph", "text": "zum Princip machte, wovor sie sich aber wohl hütet. Sie hat die Bequemlichkeit, sich die ganze Endlichkeit mit dem Ich gleich geben zu lassen, und mit dem Dogmatismus auch dieses gemein, daß das Absolute für sie ein Resultat, ein zu Begründendes ist, und wenn jener auf Gott nur aus der Welt schließt, die er ohne ihn nicht begriffe, so nimmt dagegen diese Idealismus genannte Form der Philosophie Gott nur an, um die moralischen Zwecke reimen zu können, also keineswegs um *seiner selbst willen*. Gott möchte immerhin nicht seyn, wenn man nur ohne ihn in der moralischen Welt fertig würde, so wie dort, wenn man ohne ihn die Welt überhaupt erklären könnte; er ist nicht um seiner eignen Absolutheit willen, als die Idee aller Ideen, die durch sich selbst die absolute Realität unmittelbar in sich begreift, sondern in einer noch dazu einseitigen Beziehung auf die Vernunftwesen. Nur daß sie der uralten Entzweiung eine *neue Form* gegeben hat, ist das Charakteristische dieser Philosophie; solcher Formen kann es unzählige geben, keine besteht, jede trägt die Vergänglichkeit in sich selbst. Sie kann nichts Bleibendes gründen: ein Enthusiasmus, der sich groß dünkt, wenn er sein Ich dem wilden Sturme der Elemente, den tausendmal tausend Sonnen und den Trümmern des Weltalls - in Gedanken - entgegenstellt, macht sie populär und zu einer, übrigens tauben und hohlen, Frucht der Zeit, deren Geist diese leere Form eine Zeit lang emporgetragen hat, bis sie, wie seine eigne Ebbe eintritt, mit ihm zugleich zurücksinkt. Was *bleibt*, ist nur, was alle Entzweiung aufhebt, denn nur dieses ist wahrhaft Eins und unwandelbar dasselbe. Einzig aus diesem kann sich ein wahres Universum des Wissens, eine alles befassende Gestaltung entwickeln. Nur was aus der absoluten Einheit des Unendlichen und Endlichen hervorgeht, ist unmittelbar durch sich selbst der symbolischen Darstellung fähig, fähig also auch dessen, wohin jede wahre Philosophie strebt, in der Religion objektiv, ein ewiger Quell neuer Anschauung und ein"}]}, {"page_pdf": 1474, "page_book": 116, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "allgemeiner Typus alles desjenigen zu werden, worin das menschliche Handeln die Harmonie des Universums auszudrücken und abzubilden bestrebt ist."}, {"type": "heading", "text": "II.", "level": null}, {"type": "paragraph", "text": "Das Vorhergehende zeigt deutlich das Verhältniß der Naturphilosophie zu einem solchen Idealismus, der zwar die sinnliche Realität leugnet, übrigens aber mit allen Gegensätzen des Dogmatismus behaftet bleibt. Da es sich beweisen läßt, daß, wenige große Erscheinungen ausgenommen, die hier nicht in Anschlag kommen können, da sie allgemein mißkannt und verfolgt worden sind, alle neueren Veränderungen der Philosophie und der Ansicht des Universums seit dem Dualismus des Cartesius, in welchem sich die längst vorhandene Entzweiung nur mit Bewußtseyn und wissenschaftlich ausgesprochen hat, nur verschiedene Formen der Einen unüberwundenen und der bisherigen Kultur unüberwindlichen Entgegensetzung waren; da im Gegentheil Naturphilosophie durchaus nur aus einem System der absoluten Identität hervorgehen und in einem solchen begriffen und erkannt werden kann, so ist um so weniger zu verwundern, daß sie auch in dem, was man die allgemeinen Interessen der Menschheit zu nennen pflegt, und was von der Philosophie gleichsam das Allgemeingut ist, überall Widerspruch antreffen wird. Nur ein gänzliches Mißkennen der Richtung unserer Philosophie kann daraus, daß wir die religiöse und sittliche Beziehung, welche der Philosophie in den bisherigen Systemen gegeben wird, absolut verwerfen müssen, den Schluß ziehen, daß wir diese Beziehung überhaupt verwerfen. Es findet das gerade Gegentheil statt: weil wir eine Philosophie, die nicht *in ihrem Princip* schon Religion ist, auch nicht für Philosophie anerkennen, verwerfen wir eine Erkenntniß des Absoluten, die aus der Philosophie nur als *Resultat* hervorgeht, die Gott nicht an sich, sondern in einer empirischen Beziehung denkt; aus dem Grunde eben, weil uns der Geist der Sittlichkeit und der Philosophie einer und derselbe ist, verwerfen wir eine Lehre, welcher zufolge das Intellektuelle wie die Natur nur Mittel der Sittlichkeit und eben darum an sich selbst von dem inneren Wesen der Sittlichkeit entblößt seyn müßte."}, {"type": "paragraph", "text": "Wir bemerken, zum Verständniß des Folgenden, daß es uns unmöglich ist, Religion, als solche, ohne historische Beziehung zu denken, und es wird darin nichts Befremdendes seyn, wenn man sich überhaupt gewöhnt hat, das Historische aus dem Gesichtspunkt höherer Begriffe anzusehen und sich von den Verhältnissen der empirischen Nothwendigkeit, welche das gemeine Wissen darin erkennt, zu der unbedingten und ewigen Nothwendigkeit zu erheben, durch die alles, was überhaupt in der Geschichte, ebenso wie alles, was in dem Lauf der Natur wirklich wird, vorher bestimmt ist. Es ist kein Zufall, ebensowenig eine bedingte Nothwendigkeit, daß der allgemeine Geist der Religion der späteren Welt dieser bestimmte ist, und wenn er in einer Geistesrichtung, die einer vor uns untergegangenen Welt angehörte, seinen Gegensatz hat, so ist dieß in dem allgemeinen Plan der Schicksale der Welt und den ewigen Gesetzen, welche die Laufbahn der menschlichen Geschichte bestimmen, vorgezeichnet und gegründet. Der Keim des Christenthums war das Gefühl einer Entzweiung der Welt mit Gott, seine Richtung war"}]}, {"page_pdf": 1475, "page_book": 118, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "die Versöhnung mit Gott, nicht durch eine Erhebung der Endlichkeit zur Unendlichkeit, sondern durch eine Endlichwerdung des Unendlichen, durch ein Menschwerden Gottes. Das Christenthum stellte diese Vereinung für den ersten Moment seiner Erscheinung als einen Gegenstand des Glaubens auf: Glauben ist die innere Gewißheit, die sich die Unendlichkeit vorausnimmt, und das Christenthum selbst deutete durch diese Zurückführung sich selbst als einen Keim an, der seine Entwicklung erst in der unendlichen Zeit mit den Bestimmungen der Welt haben sollte; einzelne Abweichungen von der Richtung dieses Glaubens und überhaupt Zwischenzustände können in Bezug auf das Ganze nicht in Betracht kommen; wir haben unsern Blick nur auf die allgemeinen und großen Erscheinungen zu heften. Alle Symbole des Christenthums zeigen die Bestimmung, die Identität Gottes mit der Welt in Bildern vorzustellen, die dem Christenthum eigenthümliche Richtung ist die der Anschauung Gottes im Endlichen, sie entspringt aus dem Innersten seines Wesens und ist"}, {"type": "paragraph", "text": "nur in ihm möglich, denn daß diese Richtung einzeln auch vor und außer dem Christenthum war, beweist nur seine Allgemeinheit und Nothwendigkeit, und daß auch die historischen Gegensätze wie alle anderen nur auf einem Vorherrschen beruhen. Wir können diesen auf das Anschauen des Unendlichen im Endlichen gerichteten Sinn allgemein Mysticismus nennen. Nichts beweist auffallender, daß der Mysticismus die nothwendige durch den innersten Geist des Christenthums vorgeschriebene Anschauungsweise ist, als daß er selbst in dem Entgegengesetztesten, wie der Protestantismus, wieder in neuen und zum Theil nur dunkleren Formen durchbrach. Wenn die Mystiker des Christenthums in der herrschenden Meinung Widerspruch fanden und selbst als Irrgläubige betrachtet und ausgestoßen wurden, so war es, weil sie den Glauben in ein Schauen verwandelten und die noch nicht reife Frucht der Zeit zum voraus brechen wollten; und wenn das allgemeine Streben der modernen Zeit dahin gegangen ist, den Gegensatz, der im Glauben, welcher kein Wissen ist, besteht, objektiv, im Unglauben subjektiv, demnach vollkommen, zu erhalten, so kann das nichts gegen die erste Richtung beweisen, welche im Glauben selbst auf das Schauen als ein Gewisses, Zukünftiges deutete. Den höchsten Punkt des Gegensatzes mit dem Heidenthum macht die Mystik im Christenthum; in demselben ist die esoterische Religion selbst die öffentliche, und umgekehrt, dagegen ein großer Theil der Vorstellungen in den Mysterien der Heiden selbst mythischer Natur war. Sehen wir von den dunklern Gegenständen der letzten ab, so war die ganze Religion, wie die Poesie der Griechen, frei von allem Mysticismus, und vielleicht war es im Christenthum eben zur vollkommneren Ausbildung seiner ersten Richtung nothwendig, daß die sich mehr und mehr und mehr der Poesie nähernde, krystallhelle Mystik des Katholicismus durch die Prosa des Protestantismus verdrängt werden mußte, innerhalb dessen erst der Mysticismus in der ausgebildetsten Form ausgeboren wurde. Die bestimmte Entgegensetzung des Christenthums und Heidenthums verstattet uns, dieselben als zwei einander entgegenstehende Einheiten"}, {"type": "paragraph", "text": "zu betrachten, die sich nur durch die Richtung voneinander unterscheiden. Die Einheit des letzteren war die unmittelbare Göttlichkeit des Natürlichen, die absolute Aufnahme oder Einbildung des Endlichen ins Unendliche. Wenn man da, wo die zwei Gegensätze unmittelbar in eins fallen, von einer Richtung reden kann, so ging die religiöse und poetische Anschauung im Heidenthum vom Endlichen aus und endete im Unendlichen. Faßt man die griechische Mythologie von der endlichen Seite auf, so erscheint sie durchaus"}]}, {"page_pdf": 1476, "page_book": 120, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "bloß als ein Schematismus des Endlichen oder der Natur; nur in der Einheit, die sie in der Unterordnung unter die Endlichkeit gleichwohl erreicht hat, ist sie symbolisch. Der Charakter des Christenthums, von der Seite des Unendlichen aufgefaßt, ist der Charakter der Reflexion, seine Einheit ist Einbildung des Unendlichen ins Endliche, Anschauung des Göttlichen im Natürlichen. Daß die Aufgabe des Christenthums in einer größern Ferne liegt und ihre Auflösung eine unbestimmbare Zeit zu fordern scheint, liegt schon in ihrer Natur. Die Einheit, welche der griechischen Mythologie zu Grunde liegt, kann als eine noch unaufgehobene Identität angesehen werden, sie ist die, von welcher die erste Anschauung ausgeht, ihre Herrschaft kann, wie das Alter der Unschuld, nur kurze Zeit dauern, sie muß unwiederbringlich verloren erscheinen. Die Aufgabe des Christenthums setzt die absolute Trennung schon voraus, das Endliche in der Unendlichkeit ist das Angeborene, das Unendliche im Gegensatz mit der Endlichkeit ist durch Freiheit, und trennt sich, wenn es sich trennt, absolut. Der Moment der Vereinigung kann mit dem der Entzweiung nicht zusammenfallen: es sind zwischen der Trennung und Zurückrufung des unendlichen Begriffs aus der unendlichen Flucht nothwendige Zwischenzustände, welche die Bedeutung und die Richtung des Ganzen nicht bestimmen können. Wie überhaupt alle Entgegengesetzte es aufhören zu seyn, sowie jedes für sich in sich absolut ist, so ist nicht zu zweifeln, daß auch in der Richtung, die dem Christenthum vorgeschrieben ist, die andere Einheit, welche die der Aufnahme des Unendlichen ins Endliche ist, sich in die Heiterkeit und Schönheit der griechischen Religion verklären könne."}, {"type": "paragraph", "text": "Das Christenthum als Gegensatz ist nur der Weg zur Vollendung; in der Vollendung selbst hebt es sich als Entgegengesetztes auf; dann ist der Himmel wahrhaft wieder gewonnen und das Absolute Evangelium verkündet. Es ist keine Religion ohne die eine oder die andere der beiden Anschauungen, ohne die unmittelbare Vergötterung des Endlichen oder das Schauen Gottes im Endlichen. Dieser Gegensatz ist der einzig mögliche in der Religion, darum gibt es nur Heidenthum und Christenthum, außer diesen beiden ist nichts als die beiden gemeinschaftliche Absolutheit. Jenes sieht unmittelbar in dem Göttlichen und den geistigen Urbildern das Natürliche, und dieses sieht durch die Natur, als den unendlichen Leib Gottes, bis in das Innerste und den Geist Gottes. Für beide ist die Natur Grund und Quell der Anschauung des Unendlichen. Ob dieser Moment der Zeit, welcher für alle Bildungen der Zeit und die Wissenschaften und Werke der Menschen ein so merkwürdiger Wendepunkt geworden ist, es nicht auch für die Religion seyn werde und die Zeit des wahren Evangeliums der Versöhnung der Welt mit Gott sich in dem Verhältniß nähere, in welchem die zeitlichen und bloß äußeren Formen des Christenthums zerfallen und verschwinden, ist eine Frage, die der eignen Beantwortung eines jeden, der die Zeichen des Künftigen versteht, überlassen werden muß. Die neue Religion, die schon sich in einzelnen Offenbarungen verkündet, welche Zurückführung auf das erste Mysterium des Christenthums und Vollendung desselben ist, wird in der Wiedergeburt der Natur zum Symbol der ewigen Einheit erkannt; die erste Versöhnung und Auflösung des uralten Zwistes muß in der Philosophie gefeiert werden, deren Sinn und Bedeutung nur der faßt, welcher das Leben der neuerstandenen Gottheit in ihr erkennt."}, {"type": "heading", "text": "III.", "level": null}, {"type": "paragraph", "text": "Die Betrachtung der Philosophie von dem allgemeinen historischen Standpunkt aus würde für manche"}]}, {"page_pdf": 1477, "page_book": 121, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "wenigstens den Nutzen haben, sie über die engen Formen ihres Philosophirens, in welchem sie die Grenzen"}, {"type": "paragraph", "text": "des allgemeinen Geistes gesteckt zu haben glauben, ins Klare zu setzen. Anderen würde sie bei dem Unvermögen, sich aus freier Selbstthätigkeit zu Ideen zu erheben, wenigstens einen allgemeineren Maßstab der Beurtheilung angeben, als die auf den engen Kreis der gegenwärtigen Zeit eingeschränkte Kenntniß der Formen und Richtungen der Philosophie. Durch dieselbe Wendung, welche zum Princip der Philosophie die absolute Entzweiung gemacht hat, wurde auch die Betrachtungsweise der Natur bestimmt, welche in der neueren Zeit die herrschende ist. Auch in dem Verhältniß, welches die Wissenschaft der Alten zur Natur hat, drückt sich die noch unaufgehobene Identität aus; jene beschränkte sich auf Beobachtung, weil diese allein die Gegenstände in ihrer Integrität und Ungetrenntheit aufnimmt. Die Kunst zu isoliren und die Natur unter künstlich veranstalteten Verbindungen und Trennungen zu beobachten, ist eine Erfindung der späteren Kultur. Wenn aber auch die gemeine Geschäftigkeit der Empirie eine völlig blinde ist, so war der erste Strahl, der sie allgemeiner geweckt hat, und der den edleren Trieb zur Erforschung der Natur unterhielt, jener dem Gefühl der späteren Welt tief eingeprägte Instinkt, das entflohene Leben in die Natur zurückzurufen. Der Enthusiasmus, mit welchem alle lebendigen Erscheinungen der allgemeinen Natur, welche von den Alten fast nicht gekannt und wenig geachtet waren, von den Neuern als soviel Zeugen des in der Natur verschlossenen Lebens aufgenommen wurden, zeigt von der einen Seite zwar die ursprüngliche Rohheit der letzten im Gegensatz gegen die Bildung der ersten, aber zugleich auch die unwiderstehliche Nothwendigkeit, mit der dem menschlichen Geist diese Richtung aufgedrungen wurde. Es ist keine Aussicht, aus dem ungebildeten Ernst und der trüben Empfindsamkeit der modernen Betrachtung der Natur wieder zu der Heiterkeit und Reinheit der griechischen Naturanschauung zurückzukehren, als auf dem Einen Wege der Wiederherstellung der verlorenen Identität durch die Speculation und Wiederaufhebung der Entzweiung in einer höheren Potenz, da zu der ersten, nachdem sie einmal überschritten, zurückzukehren versagt ist."}, {"type": "paragraph", "text": "Enge Geister, die den großen Zusammenhang der allgemeinen Bildung und der Formen, in denen sie sich ausdrückt, nicht begreifen, mögen über die Naturphilosophie vorerst das Urtheil der Irreligion sprechen oder hervorrufen; sie wird nichtsdestoweniger ein neuer Quell der Anschauung und Erkenntniß Gottes werden. Noch wohlfeiler ist der Vorwurf der Nicht- oder Unsittlichkeit, mit dem ein mark- und kraftloses Reden von Moralität, aus dem alle Idee Gottes entfernt ist, erst die Religion verdrängt hat und nun auch die Philosophie zu verdrängen versucht. Die wissenschaftliche Rohheit, die mit diesem Moralisiren verbunden ist, begreift die Einheit des Ichs und der Natur, demnach die Naturphilosophie empirisch, als Naturalismus, wie dagegen den Idealismus als Egoismus. Aus wahrer sittlicher Energie muß eine Philosophie entspringen, die ganz aus reiner Vernunft und nur in den Ideen ist; jenes Vorschieben der Sittlichkeit ist aber gegen die Vernunft und Speculation gerichtet. Sittlichkeit im Princip ist Befreiung der Seele von dem Fremd- und Stoffartigen, Erhebung zum Bestimmtseyn durch reine Vernunft ohne andere Beimischung. Dieselbe Reinigung der Seele ist die Bedingung zur Philosophie. Die sittliche und die intellektuelle Beziehung aller Dinge ist insofern wieder eine und dieselbe, es ist die Beziehung auf die reine, schlechthin allgemeine Vernunft, ohne Stoff, ohne Dazwischentretendes oder fremde Vermittlung."}]}, {"page_pdf": 1478, "page_book": 123, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Die wahrhaft sittliche Betrachtung der Natur ist demnach auch die wahrhaft intellektuelle, und umgekehrt. Die sittliche Beziehung, welche die intellektuelle ausschließt, ist auch keine sittliche mehr. Beide sind eins im Princip, keine geht der andern wahrhaft vor oder nach; nur empirisch erscheint es so; das Sittliche ist unserm Werden in der Zeit nach das Erste, wodurch wir in die Intellektualwelt eingreifen und uns in ihr erkennen. Das angeborene Wissen ist nur eine Einbildung des Unendlichen oder Allgemeinen in das Besondere unserer Natur; die sittliche Anforderung geht unmittelbar durch sich selbst auf die Hineinbildung unsers Besonderen in das rein Allgemeine, das Wesen, das Unendliche: aber dieser Gegensatz des Wissens mit dem Sittlichen besteht auch nur für das Wissen und Handeln in der Zeit. Das *wahre*"}, {"type": "paragraph", "text": "Wissen wendet sich von dem bloßen Widerschein des Unendlichen im Endlichen ab und zu dem *An-sich* oder Urwissen, und in dieser Richtung ist es nicht ohne die vollendete Einbildung oder Auflösung des Besonderen im Allgemeinen, d.h. ohne die sittliche Reinheit der Seele. Hinwiederum ist die wahre, nicht bloß negative Sittlichkeit nicht, ohne daß die Seele in der Ideenwelt einheimisch und in ihr wie in ihrem Eigenthum sey. Die Sittlichkeit, welche vom Intellektualen sich trennt, ist nothwendig leer, denn nur aus diesem nimmt sie den Stoff ihres Handelns. Derjenige also, der nicht seine Seele bis zur Theilnahme an dem Urwissen geläutert hat, ist auch nicht zur letzten sittlichen Vollendung gelangt. Das Reine, schlechthin Allgemeine ist für ihn ein Außer-ihm; er selbst demnach steckt noch in dem Unreinen, und ist im Besonderen und Empirischen befangen. \"Die Reinigung, sagt Plato (Phaed. p. 152), besteht darin, die Seele so viel möglich von dem Leib abzusondern und zu gewöhnen, sich in sich selbst von allen Seiten aus dem Leib zu sammeln und zurückzuziehen und nach Vermögen in sich selbst zu wohnen. *Tod* heißt eine solche Lösung der Seele von dem Leib. Am meisten streben nach dieser Lösung *die wahrhaft Philosophirenden*.\" In diesem Streben nach Reinigung begegnen sich also die Sittlichkeit und die Philosophie. Der Weg zu jener Befreiung ist nicht der bloß negative Begriff der Endlichkeit, daß sie nämlich eine Schranke der Seele ist, denn hierdurch wird sie nicht überwunden. Es bedarf eines positiven Begriffs und einer gleichen Anschauung des An-sich; denn derjenige, der weiß, daß nur für den Schein das Natürliche von dem Göttlichen getrennt, der Leib nur in der unvollkommenen Erkenntniß Leib und von der Seele verschieden, in dem An-sich aber dasselbe mit ihr ist, wird sich auch am meisten üben, jenen vom Sokrates gepriesenen Tod zu sterben, der der Eingang zu der ewigen Freiheit und dem wahren Leben ist. Die aber zwischen das rein Allgemeine oder Unendliche und die Seele, auf welche Weise es sey, entweder daß sie sich überhaupt mit ihrem Bewußtseyn nicht darüber erheben, oder mit Bewußtseyn etwas Fremdartiges, einen Stoff oder dergleichen einschieben, werden nie"}, {"type": "paragraph", "text": "wahrhaft von jener Schranke befreit werden und das Endliche und den Leib als ein Positives und wahrhaft Wirkliches immerfort mit sich schleppen. Der wahre Triumph und die letzte Befreiung der Seele liegt allein im absoluten Idealismus, im absoluten Tod des Reellen als solchen. Die Lästerer, welche das sittliche Princip der Philosophie verläumden, kennen weder das Ziel noch die Stufen der Seele, durch welche sie zur Läuterung gelangt. Das Erste, was sie erfährt, ist die Sehnsucht; denn die Natur, um in sich den Abdruck des unsterblichen Wesens zu empfangen, ist nothwendig zugleich das Grab der Vollkommenheit. Die Seele, welche den Verlust des höchsten Gutes gewahr wird, eilt, der Ceres gleich, die Fackel an dem flammenden Berg zu entzünden, die Erde zu durchforschen, alle"}]}, {"page_pdf": 1479, "page_book": 125, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Tiefen und Höhen zu durchspähen, umsonst, bis sie ermüdet endlich in *Eleusis* anlangt. Dieses ist die zweite Stufe; allein nur die allsehende Sonne offenbart den Hades als den Ort, der das ewige Gut vorenthält. Die Seele, welcher diese Offenbarung widerfährt, geht zur letzten Erkenntniß über, sich zum ewigen Vater zu wenden: die unauflösliche Verkettung zu lösen, vermag auch der König der Götter nicht, aber er verstattet der Seele, sich des verlorenen Guts in den Bildungen zu freuen, welche der Strahl des ewigen Lichts durch ihre Vermittlung dem finstern Schooß der Tiefe entreißt."}, {"type": "paragraph", "text": "Ueber die Construktion in der Philosophie."}, {"type": "paragraph", "text": "Abhandlung über die philosophische Construktion, als Einleitung zu Vorlesungen in der Philosophie, von *Benj. Karl H. Höyer*. Aus dem Schwedischen. Stockholm bei Sieverstolpen, in Commission bei Fr. Perthes in Hamburg. 1801."}, {"type": "paragraph", "text": "Daß die Philosophie weder die engen Grenzen des Kantischen Kriticismus überschreiten, noch auf dem von Fichte eingeleiteten Weg zu einer positiven und apodiktischen Philosophie weiter fortschreiten könne, ohne daß die Methode der Construktion in ihrer größten Strenge in sie eingeführt werde, davon könnte sich jeder im Allgemeinen durch die vorliegende Schrift überzeugen, welche den Hauptpunkt, auf den die wissenschaftliche Vollendung der Philosophie ankommt, mit großer Klarheit bezeichnet und darstellt. Die Lehre von der philosophischen Construktion wird künftig eines der wichtigsten Kapitel in der wissenschaftlichen Philosophie ausmachen: es ist unleugbar, daß, so wie viele an den Fortschritten derselben Theil zu nehmen durch den Mangel des Begriffs der Construktion verhindert werden, so hinwiederum gegen eine gewisse falsche Liberalität, die sich mit dem Geistreichen in der Philosophie begnügt und unter der äußern Form des Philosophirens das bloße Räsonniren begünstigt, oder gegen die Mischung aller Standpunkte, welche Wahres und Falsches verwirrt und ununterscheidbar macht, das Dringen auf strenge von den ersten Prämissen ausgeführte Construktion, das kräftigste Mittel sey."}, {"type": "paragraph", "text": "Manche philosophische Bestrebungen erhalten sich in einem gewissen äußeren Ansehen des Zusammenhangs, einzig weil sie sich auf jenen Weg nicht einlassen und gegen die Probe der wissenschaftlichen Construktion sich sträuben; und doch muß gerade in der Philosophie Materie und Form am unzertrennlichsten seyn, so daß ein von Seiten der Form vernachlässigtes System es in gleichem Grade von Seiten des Inhalts seyn muß. Es kommt in der Philosophie überhaupt nicht darauf an, was gewußt werde, sondern aus welchen Gründen es gewußt werde. Ehe man zu dem schlechthin Absoluten durchgedrungen ist, findet sicher und nothwendig immer der Wahlspruch der Skeptiker seine Stelle, daß jedem Grund ein gleicher Grund entgegengesetzt werden kann. Man kann nicht leugnen, daß in den von Seiten der Form ungereimtesten und widersinnigsten Systemen einzelne Sätze wahrer Philosophie vorkommen; allein sie sind in ihnen ohne allen wissenschaftlichen Werth, ohne Sinn und Gehalt. Das Gefühl von der Wahrheit im Einzelnen bei totaler Verworrenheit im Ganzen erzeugt die beschränkteste"}]}, {"page_pdf": 1480, "page_book": 127, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Rechthaberei und obstinirteste Unbelehrbarkeit, so daß für manche Köpfe, sie von der gänzlichen Nullität ihrer Philosophie zu überzeugen, kein anderes Mittel wäre, als der Form, wenn dieß möglich wäre, bei ihnen zum Durchbruch zu verhelfen. Die Form also, welche einerseits den Philosophen selbst vor Irrthümern und Abschweifungen bewahrt, ist andererseits in seiner Hand eine sehr wichtige, ja die einzige Waffe gegen die Halbphilosophie und die Unphilosophie, welche beide keine Ansprüche auf die Form machen können, ohne eben damit ihre ganze Blöße zu offenbaren. Es wird aus dem gleichen Grunde vorläufig keine Philosophie für wahre und absolute Philosophie gelten können, welche nicht beweisen kann, daß sie die absolute Form gewonnen hat, oder, da eine solche überhaupt noch nicht existiren möchte, so wird auch keine Richtung und keine Bestrebung in der Philosophie für die wahre geachtet werden können, welche nicht die Einsicht in die *Unzertrennlichkeit des Wesens und der Form* zum Leitstern und Princip hat. Das große Beispiel, das Spinoza von dem Gebrauch der geometrischen"}, {"type": "paragraph", "text": "Methode in der Philosophie gegeben hat, anstatt zur Vervollkommnung desselben aufzufordern, hat vielmehr das Gegentheil bewirkt; die Welt, welche diesen Geist nicht verstand, suchte eine Hauptquelle seiner Irrthümer in dieser Form, der man von dieser Zeit an eine gewisse Verwandtschaft mit dem Fatalismus und Atheismus zuschrieb. Wenn Spinoza geirrt hat, so ist es darin, daß er nicht weit genug zurück construirt, und wenn nicht die Form, doch die rein ideelle Seite der Philosophie zu sehr vernachlässigt hat. Es ist mit dem Dogmatismus wie mit der geometrischen Methode selbst: es gibt einen äußeren und inneren, formellen und wesentlichen Dogmatismus. Der wesentliche Dogmatismus hat nur Ein Merkmal, es ist der Gebrauch der Reflexionsformen vom Absoluten. Daß ein solcher dem innersten Geist des Spinozismus entgegen ist, der selbst vielmehr das antipodische System des dogmatischen ist, läßt sich, aller Beweise, die man von seinem Buchstaben hernehmen möchte, unerachtet, streng darthun. Spinoza hat den formellen Dogmatismus nicht vermieden, seiner Philosophie fehlt das nothwendige Element des Skepticismus: da die Philosophie ganz in der Region des *Unendlichen* ist, so daß sie nicht wie die Mathematik einen höheren Reflex über sich hat, sondern alle Reflexe in sich selbst vereinigt, so muß auch der ihres eignen Wesens sie immer begleiten; sie ist nicht nur ein Wissen, sondern immer und nothwendig zugleich wieder ein Wissen dieses Wissens, nur nicht in einem endlosen Fortgang, sondern in immer gegenwärtiger Unendlichkeit1. Von der *Wolfischen *Philosophie wollen wir nicht reden, welche in jedem Betracht Dogmatismus ist, und deren armselige und geistlose Anwendung der äußeren Form der geometrischen Methode überdieß keine Idee der Construktion erwecken konnte. Wir wenden uns zu *Kant*, der die demonstrative Methode in der Philosophie nur im Geist des Dogmatismus und als logische Analysis begreift und der Kritik des Gebrauchs derselben in der Philosophie einen eignen Abschnitt seiner Methodenlehre gewidmet hat. Was den allgemeinsten Begriff der Construktion betrifft, so ist Kant"}, {"type": "footnote", "text": "1 Vergl. Bruno, im vorherg. Band S. 290 (Ausg. von 1842, S. 143). D. H."}]}, {"page_pdf": 1481, "page_book": 129, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "vielleicht der erste, der ihn so tief und ächt philosophisch aufgefaßt hat. Er beschreibt Construktion durchgängig als Gleichsetzung *des Begriffs* und *der Anschauung*, und fordert dazu eine nicht-empirische Anschauung, die einerseits, als Anschauung, einzeln oder concret ist, andererseits als Construktion eines Begriffs Allgemeingültigkeit für alle möglichen Anschauungen, die unter denselben Begriff gehören, ausdrücken muß. Ob der dem Allgemeinbegriff Dreieck entsprechende Gegenstand in der reinen Anschauung oder der empirischen entworfen wird, ist für seine Fähigkeit, den Begriff unbeschadet seiner Allgemeinheit auszudrücken, ganz gleichgültig, weil bei der empirischen Anschauung selbst doch nur auf die Handlung der Construktion des Begriffes an und für sich selbst gesehen wird u.s.w. Bis hierher drückt Kant die Idee der Construktion und den Grund aller Evidenz vollkommen aus. Wenn er aber nachher die Möglichkeit der Construktion in der Philosophie leugnet, weil diese nur mit reinen Begriffen ohne Anschauung zu thun habe, und er gleichwohl der Mathematik eine nicht-empirische Anschauung zur Construktion zugesteht, so wird offenbar, daß er an dieser doch eigentlich nur die *empirische* Seite, die Beziehung auf das Sinnliche, geschätzt, dagegen bei jener vermißt hat. Denn daß die Philosophie auf bloße reine Begriffe ohne alle Anschauung beschränkt sey, würde nur dann folgen, wenn bewiesen wäre, daß es keine ihren Begriffen angemessene *nicht-empirische* Anschauung geben könne; diese nicht-empirische Anschauung für die Philosophie leugnet nun Kant, weil eine solche intellektuell seyn müßte, nach seiner Meinung aber alle Anschauung nothwendig sinnlich ist. Nun ist aber offenbar, daß, was an der mathematischen Anschauung das schlechthin *Allgemeine*, die reine Einheit des Allgemeinen und Besonderen selbst ist, nicht sinnlich, sondern vielmehr das rein Intellektuelle selbst ist. Er setzt also die Einzigkeit der mathematischen Anschauung ganz in ihre sinnliche Beziehung oder darein, daß sie die *sinnlich* reflektirte intellektuelle Anschauung ist, und es mußte demnach zu der Forderung einer nicht-empirischen, d.h. intellektuellen Anschauung für die mathematische Construktion noch die besondere der sinnlichen Beziehung *als solcher* hinzugefügt werden."}, {"type": "paragraph", "text": "Da Kant für die Geometrie die nicht-empirische Anschauung zugibt, so kann er den absoluten Unterschied zwischen Mathematik und Philosophie nicht darein setzen, daß es für diese eine nicht-empirische Anschauung geben müßte, dergleichen es doch nicht gebe. Der Unterschied beider wird vielmehr darein fallen, daß dem Mathematiker die in der Sinnlichkeit reflektirte, dem Philosophen dagegen nur die reine in sich selbst reflektirte intellektuelle Anschauung zu Gebot steht. Der Raum, wie er der Geometrie, und die Zeit, wie sie der Arithmetik nach Kant zu Grunde liegt, ist die ganze intellektuelle Anschauung; aber dort im Endlichen, hier im Unendlichen ausgedrückt. Welche Gründe in Kants ganzer Philosophie liegen, die ihm die schlechthin und an sich betrachtete intellektuelle Anschauung unzugänglich machen, ist theils bekannt genug, theils wird es aus dem Folgenden noch klarer werden. Um nicht von den Widersprüchen zu reden, in welche sich Kant durch Verwerfung der Construktion und rein intellektuellen Anschauung verflicht, da seine *transscendentale Einbildungskraft*, seine *reine Synthesis der Apperception*, die Wirklichkeit einer solchen Anschauung involviren, da er, wie auch in der angezeigten Schrift richtig bemerkt ist, so oft erklärt, daß Begriffe, die nur mittelbare Vorstellungen von Objekten sind, außer der Einheit mit diesen schlechthin leer seyen, während er selbst nachher die Philosophie auf rein discursive Begriffe beschränkt, - um diese Widersprüche nicht zu berühren, fragt sich doch, was denn eigentlich die Mathematik, dadurch daß die intellektuelle Anschauung in ihr des sinnlichen Ausdrucks fähig ist, vor der Philosophie voraus habe. Offenbar nichts als die Möglichkeit, sich ohne alles intellektuelle Bewußtseyn gleichwohl dem Scheine nach in den Besitz ihrer Construktionen zu setzen, und die zufällige Stütze der äußeren sinnlichen Anschauung für den, der einer solchen bedarf -"}]}, {"page_pdf": 1482, "page_book": 130, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Vorzüge, die ein wahrer Philosoph dem Mathematiker wahrlich nicht beneiden könnte, und wegen deren Plato gewiß nicht gesagt hat: die Geometrie sey dem Philosophen zu kennen nothwendig, *um das Wesentliche zu schauen und sich aus dem Veränderlichen zu erheben.* Wollte man auch mit dem Verfasser dem Geometer den Vortheil"}, {"type": "paragraph", "text": "zugestehen, daß er außer dem Bild, daß seine Aufmerksamkeit leitet, zugleich ein *Zeichen* habe, das seine an sich fließende (?) Handlung fixirt, wodurch er die Fehler seiner Schlußfolge sogleich entdecken kann, so wird erstens, wie er selbst bemerkt, dieser Vortheil in dem andern Zweige der Mathematik beträchtlich vermindert, indem es da kein Bild des Objekts, sondern nur ein Zeichen gibt, und Verhältnisse von Größen, und in der Algebra sogar nur Verhältnisse von Verhältnissen, betrachtet werden; andererseits ist zu erwarten, ob nicht außer der speciellen symbolischen und charakteristischen Darstellung der Mathematik die universelle Symbolik oder Charakteristik erfunden, und so die Idee, welche Leibniz schon hegte, realisirt werde; daß einige Schritte schon geschehen sind, welche die Möglichkeit einer solchen Erfindung beweisen, ließe sich leicht zeigen. Die hauptsächlichsten Gründe, wie sie sich auch bei Kant aussprechen, die der Construktion *in der Philosophie* und dadurch der Philosophie selbst als Wissenschaft in den herrschenden Vorstellungen entgegenstehen, kommen auf folgende zurück. Der erste ist die absolute Entgegensetzung des Allgemeinen und Besonderen, die Kant zwar in der mathematischen Construktion als aufgehoben anerkennen muß, in der Philosophie aber durchaus stehen läßt. \"Die mathematische Erkenntniß, sagt er, betrachtet das Allgemeine im Besonderen, die philosophische dagegen *das Besondere nur im Allgemeinen*\" (Krit. d. r. V. S. 742). Es sind hierüber verschiedene Bemerkungen zu machen. Erstens, da jede wahre Identität des Allgemeinen und Besonderen an sich *Anschauung* ist, so kann darin, daß in dem einen Fall das Besondere im Allgemeinen, im andern das Allgemeine im Besonderen dargestellt wird, kein Grund liegen, von dem ersten die Anschauung zu negiren, es würden daraus nur zwei verschiedene *Arten* der Anschauungen folgen. Versteht man unter dem Allgemeinen das reine Verstandes- oder discursiv Allgemeine, so ist leicht zu zeigen, daß eben *diese beiden Arten* der *Anschauung* in den beiden Zweigen der Mathematik wirklich gegeben sind, daß die Arithmetik ein Besonderes (Verhältniß von einzelnen Größen) im Allgemeinen,"}, {"type": "paragraph", "text": "die Geometrie ein Allgemeines (den Begriff einer Figur) im Besonderen ausdrückt. Es erhellt eben hieraus auch, daß alle Gegensätze, welche durch die Antithese des Allgemeinen und Besonderen möglich sind, in die Mathematik selbst fallen, daß Philosophie in keiner Entgegensetzung mit der Mathematik sey, und daß, wenn in dieser sich die Construktion nach zwei Seiten theilt, sie in jener im absoluten Indifferenzpunkt sey, oder bestimmter: daß wenn jene nothwendig *entweder* Darstellung des Allgemeinen im Besonderen, *oder* Darstellung des Besonderen im Allgemeinen ist, diese *weder* das eine noch das andere, sondern *Darstellung der Einheiten in absoluter Indifferenz *ist, welche in der Mathematik getrennt erscheinen. Es gibt eine andere Idee des Allgemeinen, welche Kant nicht kennt und annimmt, unerachtet er eine Erklärung der Philosophie, die ohne Zweifel nach derselben entworfen worden ist, aus der Tradition annimmt, eine Idee, nach welcher allerdings Philosophie als *Darstellung des Besonderen im Allgemeinen* bezeichnet werden kann. Das Allgemeine ist hier das wesentlich und absolut Allgemeine, nicht der Begriff, sondern die Idee,"}]}, {"page_pdf": 1483, "page_book": 132, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "welche, wenn wir Allgemeines und Besonderes als Reflexionsgegensätze im Kantischen Sinn denken, diese selbst wieder ebenso begreift, wie seinerseits das Besondere, in dem Sinn wie es in der Geometrie vorkommt, außer dem Besonderen als formellen Faktor auch wieder das Allgemeine in sich faßt. In diesem Sinn ist aber das Allgemeine als Einheit des Allgemeinen und Besonderen für sich schon Gegenstand von Anschauung, versteht sich rein intellektueller, als Idee; in diesem Sinn aber nimmt es Kant nicht, er kann also auch Philosophie nicht als Darstellung des Besonderen im Allgemeinen erklären. Selbst der oben gemachte Unterschied zwischen Geometrie und Arithmetik, daß nämlich jene das Allgemeine im Besonderen, diese das Besondere im Allgemeinen darstelle, findet, genauer zu reden, nicht in Ansehung der Construktion selbst, als solcher, sondern in andern Beziehungen statt, denn die Construktion, als solche, ist in der Mathematik und Philosophie immer absolute und *reale* Gleichsetzung des"}, {"type": "paragraph", "text": "Allgemeinen und Besonderen1. Das Besondere in der Geometrie ist doch nicht der empirische Triangel, der auf dem Papier etwa oder sonst entworfen wird, sondern, nach Kant selbst, *der Triangel der reinen Anschauung*; nur diesen hat eigentlich die Construktion im Auge, der empirische verhält sich als ein Accidens, als eine Zufälligkeit, auf die gar nicht reflektirt wird; *dieses* Besondere aber ist eben schon *das im Allgemeinen dargestellte* Besondere, insofern also die Idee oder das reale Allgemeine selbst und mit dieser nicht in bloß formaler, sondern *wesentlicher* Einheit2. Sonderbar genug ist es, daß Kant dem Philosophen gerade auch einen geometrischen *Begriff* vorhält, um mit dem Geometer in der Construktion desselben zu wetteifern. \"Man gebe, sagt er, einem Philosophen den Begriff eines Triangels, und lasse ihn nach seiner Art ausfindig machen, wie sich wohl die Summe seiner Winkel zum rechen verhalten möge. Er hat nun nichts als den Begriff von einer Figur, die in drei geraden Linien eingeschlossen ist, und an ihr den Begriff von ebenso viel Winkeln. Nun mag er diesem Begriff so lange nachdenken, als er will, er wird nichts Neues herausbringen. Er kann den Begriff der geraden Linie oder eines Winkels oder der Zahl drei zergliedern und deutlich machen, aber nicht auf andere Eigenschaften kommen, die in diesen Begriffen gar nicht liegen. Allein der Geometer nehme diese Frage vor\" etc. Dieß ist gerade ebenso klug, als wenn er dagegen von dem Geometer die Construktion einer Idee, z.B. der Schönheit, des Rechts, der Gleichheit, oder des Raums selbst verlangen wollte, der sich ohne Zweifel nicht geschickter dabei benehmen würde als der Philosoph bei der Construktion des Triangels. Es ist, als ob man einem Musiker Farben und Pinsel vorlegen wollte, um damit eine Musik aufzuführen, oder einem Bildhauer Musiknoten und Instrumente, um damit eine Statue zu verfertigen, und wenn man dann aus der Unmöglichkeit die Nichtexistenz ihrer Kunst bewiese."}, {"type": "footnote", "text": "1 Vergl. Methode des akad. Studiums, Originalausg. S. 97; cf. S. 92. D. H. 2 Vergl. Neue Zeitschrift für speculative Physik, 1. Bd., 2. Stück, S. 24. (Band IV, S. 405). D. H."}, {"type": "paragraph", "text": "Zugleich würde aus dieser Stelle folgen, daß der Philosoph nach Kant mit den Begriffen, auf die er beschränkt ist, nicht anders als analytisch zu Werk gehen könne. Ist denn das Kants Meinung, oder hat dieses spätere Kapitel die frühern vergessen? Jedoch angemessener dem Geist seines eignen Systems sind die andern Aeußerungen, welche indeß alle nichts als Wiederholungen desselben Gegensatzes der discursiven Begriffe mit den Anschauungen,"}]}, {"page_pdf": 1484, "page_book": 134, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der Einheit mit der Mannichfaltigkeit sind. Alles *a priori* Mannichfaltige ist schon zur Mathematik gezogen, für die Philosophie bleibt also nichts als der *reine Verstand* einerseits und das *empirisch Mannichfaltige* andererseits, welches aber als empirisches von ihr ausgeschlossen ist. Sie geht also mit völlig leerer Hand, nämlich mit leerem Verstand, aus. - Mit einem unbestimmten Mannichfaltigen, wie der Stoff einiger andern, würde sie doch wieder *ohne Objekt* construiren. Sie construirt also überhaupt nicht. Anders gewendet: die Philosophie hat *keine andern* Begriffe a priori, als die eine Synthesis möglicher Anschauungen (demnach selbst bloß eine *Möglichkeit* von Anschauungen) enthalten, womit man also wohl synthetisch a priori urtheilen kann, aber nicht construiren. - Ganz richtig, daß* mit* diesen Begriffen nicht zu construiren ist, aber man kann *sie* construiren, und auch dieses nicht, sofern sie *synthetische * und noch dazu discursive Begriffe sind, denen die Wirklichkeit in den Anschauungen gegenübersteht; es wird überhaupt nicht, und es werden auch diese Begriffe nicht construirt als in den Ideen, der Begriff der Ursache und Wirkung z.B. in der Idee der absoluten Einheit der Möglichkeit und Wirklichkeit, der der Möglichkeit und Wirklichkeit selbst in der Idee der absoluten Einheit des Subjektiven und Objektiven u.s.f.1 Alle diese Aeußerungen sind nothwendig in einer Ansicht, nach der es in dem menschlichen Geiste nichts gibt als leere Begriffe, empirische Anschauungen und zwischen beiden einen absoluten Hiatus. Kant kann in diesem Theil seiner Methodenlehre und dem Inhalt desselben nicht"}, {"type": "footnote", "text": "1 Vergl. Bruno, im vorhergehenden Band S. 246 ff. 249 ff. (Ausgabe von 1842, S. 58 ff. und 63 ff.). D. H."}, {"type": "paragraph", "text": "einmal vollkommene Rechenschaft geben über sein eignes Verfahren, wie er nämlich selbst zu jenen synthetischen Begriffen gekommen. Es ist auch ganz richtig, daß er sie nicht construirt hat, da er sie vielmehr aus der Erfahrung nach Analogie aufgegriffen hat. Undenkbar ist, daß er die Voraussetzung mit Bewußtseyn gemacht: es sey kein höherer Quell der Erkenntniß jener Begriffe, aus dem sie mit Nothwendigkeit und wahrhaft a priori begriffen werden können. - Der Rückgang im Construiren - oder, weil dieß nicht zugegeben ist - im Denken überhaupt, kann nicht eher als bei dem Punkt aufhören, wo das Construirende und Construirte - Denkende und Gedachte - schlechthin in eins zusammenfällt. Nur dieser Punkt kann *Princip* der Construktion heißen. Dieß ist bei jenen Begriffen nicht der Fall; denn ohne Zweifel ist das, was diese Begriffe in der philosophischen Reflexion denkt, ein anderes, als was *nach ihnen* denkt, und was in der Kantischen Analytik eigentlich *das Construirte* ist. Für das Letzte mögen sie Princip seyn, für das Erste sind sie es nicht. Jenes fällt also noch ganz aus dem Umkreis der Construktion - oder überhaupt der Philosophie - hinaus, der überhaupt nicht geschlossen werden kann als durch das eben beschriebene Zusammentreffen. Begriffe also, welche selbst das Construirte sind, oder wenigstens nicht den Charakter eines Princips der Construktion tragen, zu den *Mitteln* der Construktion machen, beweist, daß man mit keinem Schritt von dem bloß Reflektirten und Abgeleiteten hinweg gekommen ist, obgleich es denn wieder ganz richtig ist, daß *mit* diesen Begriffen nicht zu construiren sey. Auch der Geometer construirt nicht *mit* dem Begriff des Triangels, des Quadrats u.s.w., da würde es so vielerlei und so verschiedene Evidenzen geben, als es Construktionen gibt, diese alle sind selbst das Construirte, im *An-sich* des Geometers Dargestellte, sollte er *mit* diesen Begriffen construiren, so würde er damit nicht anders verfahren, als wie nach der obigen Schilderung der Philosoph damit verfahren sollte. Es ist nur *Ein* Princip der Construktion, *Eines, womit* construirt wird, in der Mathematik wie in der Philosophie. Dem"}]}, {"page_pdf": 1485, "page_book": 135, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Geometer ist es die in allen Construktionen gleiche und absolute Einheit des Raums, dem Philosophen die des Absoluten. Es ist, wie schon gesagt, nur Eines, was construirt wird, nämlich *Ideen*, und alles Abgeleitete wird nicht als Abgeleitetes, sondern in seiner Idee construirt. Vielleicht spricht es sich nirgends so unmittelbar und unbefangen als in diesem Räsonniren Kants über philosophische Construktion aus, daß er in seiner Kritik der reinen Vernunft durchaus nur mit dem *Verstande* zu thun hat, daß er demnach zu den wahren Gegenständen der Philosophie, zum Ideenreich, wovon er nur höchst confuse Berichte von andern hat, nicht durchgedrungen sey. Selbst in den Begriffen des Verfassers der obigen Schrift zeigt sich noch eine gewisse Abhängigkeit von der Kantischen Beschränktheit und Richtung seiner Philosophie auf die Verstandesendlichkeit, wenn er S. 47 sagt: \"*Sogar* diejenigen Begriffe, die er (Kant) Ideen nennt, entstehen durch Construktion. Eine Idee ist eigentlich ein Begriff, der an sich ohne Realität und also gar kein Begriff ist; er ist nicht construirt und kann es nicht werden; im weiteren Sinn ist sie auch ein Begriff, der bloß *jetzt noch* keine Realität hat. Eine eigentliche Idee wäre also nichts oder nicht einmal etwas Denkbares; insofern sie aber doch in anderer Rücksicht ein Begriff ist, so ist gerade meine vergebliche Bemühung, ihn zu construiren, darin construirt.\" Der Verfasser kennt aber doch, wie man schon hieraus sieht, die Elemente aller Construktion, die Kant völlig unbekannt sind, das Absolute, das an sich uneingeschränkt und schlechthin Eines ist, und das Besondere, welches ein Eingeschränktes und nicht Eines, sondern Vieles ist, ein Streit, der aber nur *in der Construktion* der Idee und durch produktive Einbildung gelöst werden kann. Schon begriffen in den zuvor angeführten Gründen gegen Construktion in der Philosophie ist der, daß durch die Construktion doch bloß *mögliche* Objekte gegeben werden; auch der Verfasser dringt vielleicht mehr, als es der Philosophie gebührt, auf die äußere Nothwendigkeit, die er von der idealen oder inneren unterscheidet, und die nach ihm eigentlich diejenige ist, welche der Metaphysik von jeher vorzüglich"}, {"type": "paragraph", "text": "zu schaffen gemacht hat. - Daß Kant, dem seine reinen Verstandesbegriffe in Ewigkeit nur Möglichkeiten geben, nach einer Wirklichkeit außer ihnen fragt, ist nothwendig. Denn in der Construktion, deren Idee der Verfasser geltend macht, ist nicht jene bloß relative oder rein ideale, sondern absolute Möglichkeit gegeben, welche die Wirklichkeit in sich begreift. Der Verfasser hat sich mit der Idee der Construktion dem absoluten Idealismus geweiht. Ist die Frage nach der absoluten Realität, so ist diese unmittelbar mit der absoluten Idealität gegeben. Ist, wie es scheint, von der äußeren Nothwendigkeit als Bestimmung der empirischen Wirklichkeit die Rede, so kann diese als solche niemals in der Idee nachgewiesen werden, denn sie wird eben *empirische Wirklichkeit* durch ihre Absonderung von der Idee, und selbst die allgemeinen Gesetze, nach welchen sie in dieser Absonderung sich zu diesem so und nicht anders Bestimmten verwandelt, können wiederum nur in der Idee construirt werden. Den letzten Anker einer phantasiereichen Hoffnung, wie er es nennt, in der intellektuellen Welt sichere Wissenschaft zu gründen, meint Kant dadurch auszureißen, daß er zeigt, daß keines der drei Stücke, welche zur Gründlichkeit der Mathematik erfordert werden, nämlich Definitionen, Axiome und Demonstrationen, von der Philosophie könne geleistet oder nachgeahmt werden. Eine sehr nothwendige Untersuchung wäre gewesen, inwiefern denn Definitionen und Axiome zur Gründlichkeit der Mathematik beitragen. Die alten Skeptiker richteten eben gegen diesen Eingang in die Mathematik ihre hauptsächlichsten Zweifelsgründe. Ist es Beweis von Gründlichkeit, könnte man sagen, die gerade Linie und die Kreislinie zu definiren, da man nicht im Stande ist ihre Genesis anzugeben? Wie komme ich nur"}]}, {"page_pdf": 1486, "page_book": 137, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "überhaupt zu zwei und mehreren Dingen, um es als Axiom aufzustellen, daß zwei Dinge, die einem dritten gleich sind, sich selbst gleich sind, oder zu den Begriffen des Ganzen und des Theils, um zu sagen, daß das Ganze größer ist als sein Theil? Diese Fragen ließen sich, wie man wohl sieht, ins Unendliche fortsetzen, die Möglichkeit derselben beweist, daß Axiome und Definitionen keineswegs, wie sie hier von Kant vorgestellt werden, wahre"}, {"type": "paragraph", "text": "*Principien*, daß sie vielmehr *Grenzpunkte* der Principien und der Wissenschaft - Grenzpunkte des Zurückgehens auf ein absolut Erstes sind. Dergleichen Grenzpunkte bedarf jede untergeordnete Wissenschaft, z.B. die Physik; durch dieselbe isolirt sie sich gleichsam und bildet sich für sich. - Wie kann nun das, was die bloße Beschränkung einer Wissenschaft ausmacht, zum Maßstab der Gründlichkeit der Wissenschaft überhaupt und der Wissenschaft aller Wissenschaften insbesondere gemacht werden. Eben deßwegen, weil die Philosophie ganz *im absoluten Wissen* ist und auch die Construktion selbst wieder construirt, auch die Definition wieder definiren müßte, gibt es für sie diese Begrenzungen nicht. Aber selbst in dem Fall, daß diese besondere wissenschaftliche Form allgemeine Gültigkeit hätte, würden doch die Gründe, aus welchen Kant die Unmöglichkeit wahrer Definitionen und Axiome in der Philosophie beweist, nicht mehr Stich halten, als die, aus welchen er die Unmöglichkeit der Construktion in der Philosophie überhaupt folgert. Er begreift auch in den Definitionen das Geschäft des Philosophen als bloß analytisch; von dieser Voraussetzung sind alle seine Gründe hergenommen. Der Verfasser bemerkt daher sehr richtig: sobald man auch in der Mathematik die Handlung der Construktion aus dem Gesicht verliere oder die Aufmerksamkeit vorzüglich darauf zu heften unterlasse, und die Definitionen nach den gewöhnlichen Regeln der Logik mit Angebung des Geschlechts und desjenigen, wodurch der Begriff zur Art unter diesem Geschlechte wird, einzurichten suchte, wäre man in der Mathematik den nämlichen Schwierigkeiten und Irrungen ausgesetzt, die Kant bloß in der Philosophie finde; keine Analyse könne in der Mathematik, so wenig als in der Philosophie, die Ueberzeugung von ihrer Richtigkeit und Vollständigkeit hervorbringen u.s.w. (S. 60). Kant selbst bemerkt, es seyen keine Begriffe, die zum Definiren taugen, als solche, die eine willkürliche Synthesis enthalten, die a priori construirt werden kann. Aber eben solche zugleich freie und nothwendige Synthesen sind alle Construktionen der Philosophie, und überhaupt die Ideen. Wenn die Philosophie keine Definitionen im Sinn der"}, {"type": "paragraph", "text": "Mathematik hat, so ist es, weil sie ihr Construiren nirgends begrenzt. Die Definitionen der Mathematik sind auch Construktionen, nur *für sie* unmittelbare. Wenn Kant die Axiome als *synthetische Sätze a priori von unmittelbarer Gewißheit* beschreibt, so stoßen wir hier auf eine höhere Untersuchung über die Richtigkeit der allgemeinen Behauptung Kants von der synthetischen Beschaffenheit aller Grundsätze und Lehrsätze der Mathematik. Es ist hier nicht der Ort, allgemein zu beweisen, daß die Evidenz überhaupt und die mathematische insbesondere nicht auf einem bloß synthetischen Verhältniß beruhen könne. Es wird aus dem, was wir zunächst von der Demonstration beweisen werden, erhellen, daß alle Demonstration nichts anderes als Herbeiführung des Punkts, wo das Identische und Synthetische eins ist, oder allgemeine Zurückführung der Synthesis auf die reine Identität des Denkens überhaupt ist (S. d. System d. transsc. Idealismus S. 40 [Bd. 3, S. 363]). Wenn dieß der Fall ist, so können Axiome, als synthetische, gleichwohl unmittelbar gewisse Sätze, von Lehrsätzen nicht wesentlich, sondern nur formell verschieden seyn. Sie stellen nur die abgebrochene"}]}, {"page_pdf": 1487, "page_book": 139, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Demonstration vor, die weiter zurückverfolgt über das besondere Gebiet der Mathematik in das allgemeine hineinführen würde, wie z.B. das mathematische Axiom, daß, was einem und demselben gleich ist, untereinander gleich ist, in der Philosophie aus der Natur des Syllogismus construirt wird. Wenn übrigens Kant Axiome als solche für etwas der Mathematik ganz Eigenthümliches hält, so scheint er übersehen zu haben, daß es auch in dieser Wissenschaft analytische Köpfe gibt, die diese Axiome, z.B. das eben angeführte, noch für beweisbar halten und wirklich zu beweisen unternehmen, so wie, wenn es mit den Definitionen dieser Wissenschaft die von ihm vorgegebene Bewandtniß hätte, keine Fälle in ihr existiren könnten, wie der bekannte mit der Definition der Parallellinien bei Euklides, welche ein großer Theil der neueren Geometer als Lehrsatz betrachtet wissen will, obgleich noch keiner einen Beweis dafür mit allgemeiner Zustimmung hat aufstellen können."}, {"type": "paragraph", "text": "Was zuletzt die *Demonstration* anlangt, so ist sie überhaupt die vollendete Gleichung des Allgemeinen und Besonderen; in dieser aber können wir zwei Momente unterscheiden, wovon nur eines wesentlich ist, das andere zur besonderen Beziehung der Mathematik gehört. Das erste ist die absolute Gleichsetzung der schlechthin allgemeinen und der besonderen Einheit. So liegt, um uns an das Beispiel der Geometrie zu halten, der Geometrie in allen ihren Construktionen eine und dieselbe Einheit des Idealen und Realen, der reine Raum, als absolute Form zu Grunde; in der Construktion aber wird eine besondere Einheit, z.B. die des Quadrats oder Parallelogramms, gesetzt. Hier besteht die Gleichsetzung darin, daß jene absolute Einheit in jeder einzelnen Construktion als das Allgemeine *ganz* und ungetheilt im Besonderen ausgedrückt sey. Auf diesem Streit zwischen dem schlechthin Allgemeinen, das insofern nichts Besonderes enthält, und dem Besonderen, das insofern dem Allgemeinen nicht adäquat ist, beruht alle Construktion. - Um die Eigenschaften der angegebenen Figuren zu beweisen, bedarf der Geometer nichts weiter als die allgemeine und absolute Form des reinen Raums als solchen, *er geht nicht aus seinem Absoluten heraus*, um zum Besonderen zu gelangen, und eben darauf, daß er zur Demonstration der besonderen Einheit nichts anderes als die absolute bedarf, beruht die Evidenz. Das andere Moment, welches bei der Mathematik in Betrachtung kommt, ist, daß auch im Besonderen seiner Construktion Allgemeines und Besonderes als absolut gleich betrachtet werden, daß er in dem einzelnen Dreieck z.B. die Unendlichkeit aller Dreiecke begreift, daß ihm jenes, obgleich es empirisch ist, statt aller dient. Von dem Letztern liegt der Grund einzig darin, daß die der Form nach intellektuelle Anschauung der Geometrie der Materie nach eine sinnliche ist. Daß das erste und wesentliche Moment der Demonstration der Philosophie fehle, hat Kant nicht bewiesen, und es steht zu beweisen, daß auch Darstellung des Besonderen im Allgemeinen (wie Kant die Philosophie erklärt) ebenso undenkbar ist, als das Umgekehrte (wenn man nämlich mit andern Philosophie als Herleitung des Besonderen aus"}, {"type": "paragraph", "text": "dem Allgemeinen, der Mannichfaltigkeit aus der Einheit erklären wollte), wofern nicht das Besondere in intellektueller Anschauung, als Construktion oder Idee die ungetheilte Einheit des Allgemeinen empfängt. Es ist also offenbar wieder das andere Moment, d.h. die sinnliche Beziehung der Mathematik allein, welche Kant bei der Philosophie vermißt, und wegen der er ihr die Möglichkeit der Demonstration abspricht."}]}, {"page_pdf": 1488, "page_book": 141, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Man kann übrigens noch bemerken, daß derselbe Gegensatz, welcher in der Demonstration zwischen der allgemeinen Anschauung des Triangels z.B. und dem empirischen oder bildlichen ist, in der Philosophie nur innerlich im Subjekt, gleichwohl stattfinde. Das Construirte ist doch immer nur Anschauung des Individuum, und insofern durch empirische Bedingungen bestimmt. Die Vernunft sieht aber in dem empirischen Gegenbild doch nur die Idee oder die reine Synthesis des Allgemeinen und Besonderen selbst; wo dieß nicht ist, handelt im Philosophen nicht die Vernunft, sondern das Individuum."}, {"type": "paragraph", "text": "Wir wenden uns zu dem Verfasser der angezeigten Schrift. Er behauptet: *Kant* construire, ohne es zu wissen (man scheint bestimmter sagen zu können, daß Kant, wenn er ein vollendetes Bewußtseyn seiner Philosophie hätte und der Reflexion darüber fähig wäre, construiren müßte); *Fichte* construire, aber ohne Regel. Man könnte sagen, daß Fichte die sokratische Methode des Unterrichts zur objektiven der Wissenschaft selbst gemacht habe, nur daß dort durchgängige Absichtlichkeit erkennbar ist, dagegen hier gerade alles viel subjektiver und willkürlicher zusammenhängt. Merkwürdig ist, wie der Verfasser, der seinen Weg von Fichte aus genommen hat, eben durch die an die Philosophie gemachte Forderung der Form, auch dem Geist und der Sache nach über den Fichteschen Idealismus hinausgeführt worden ist. Er legitimirt sich schon durch die Art, wie er dieß erklärt, als ächter Kenner der Philosophie und als Schriftsteller, der einen Rang unter den wahren Denkern"}, {"type": "paragraph", "text": "verdient. \"Eine Wissenschaft, sagt er S. 79, ist nichts anderes als *eine nach einer Regel fortgeführte Construktion*, und nur dadurch unterscheidet sie sich überhaupt von aller *Empirie* und von der Schlußweise und der Handlungsart des gemeinen Menschenverstandes. Dieser Schritt ist daher für die Philosophie noch übrig. Gewiß ist es unvermeidlich, daß der Idealismus, jemehr er ausgearbeitet und durch neue hervorwachsende Schwierigkeiten der Vollkommenheit näher gezwungen wird, sich desto mehr dieser Construktion nach einer Regel nähern und endlich dieselbe erreichen werde.\" Wenn man dazu nimmt, daß den Nachrichten der Vorrede zu Folge diese Schrift im Original schon vor jetzt drei Jahren verfaßt war, so wird man um so mehr bewundern, wie richtig der Verfasser gesehen hat. Er bemerkt ferner über die Absicht seiner Schrift, daß, wenn auch der Idealismus durch eigne Kraft zu der von ihm geforderten Methode durchdringe, er doch nicht eher die Festigkeit der Mathematik erreichen werde, als er über diese Methode selbst eine sichere Wissenschaft besitzt. Die Philosophie enthalte von allem wissenschaftlichen Denken die meiste Freiheit, *und sey daher ebensowohl Kunst als Wissenschaft.* Als den Hauptwendepunkt zwischen Fichte und ihm gibt er an, daß in der Wissenschaftslehre an den wichtigsten Stellen das reine Ich mit der reinen, aller Modificationen entkleideten, schlechthin ursprünglichen Handlung verwechselt werde, daß Fichte auf diese Weise zwei reine Ich und sogleich ein Nicht-Ich erhalte, wobei der Gesichtspunkt oft verrückt werde, und er nöthig habe zu *versichern, daß seine Philosophie völlig idealistisch sey*. Wie aus der in der Folge zu gebenden näheren Beschreibung seiner *ursprünglichen Handlung* erhellen wird, ist diese jedoch von dem Ich der Form nach nicht verschieden, da er ihr eine rein centrifugale und centripetirende Tendenz zuschreibt, sondern nur ein unvollständiger Ausdruck des von der Beziehung auf das empirische Bewußtseyn befreiten und an sich angeschauten Subjekt-Objekts. Wir haben nun zunächst die Beschaffenheit seiner eignen Idee von"}]}, {"page_pdf": 1489, "page_book": 142, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der Philosophie genauer kennen zu lernen. Wir übergehen seine Einleitung, die man nach dem Zweck, den man sich vorgesetzt hat, wissenschaftlicher nehmen kann: er knüpft die Idee der Philosophie an den Gegensatz der Freiheit und der Nothwendigkeit (S. 92). Die Art, wie er *die reine Handlung* als Princip der philosophischen Construktion zu erweisen sucht, ist kürzlich folgende: *Einschränkung des Gleichartigen* ist der strenge und eigentliche Begriff der Construktion. Einen gleichartigen oder reinen Stoff für die Construktion gibt es nun außer der reinen Anschauung überhaupt nicht, diese sey intellektuell oder sinnlich (S. 51). In Ansehung der Philosophie insbesondere kann ebensowenig das Objekt in der Gestalt des reinen Dings als das Subjekt in der Gestalt der bloßen Vorstellung zur Auflösung der Hauptaufgabe dieser Wissenschaft zureichen. Da hierdurch nicht nur alle Substanz, sowohl als Objekt wie auch als Subjekt, sondern auch jedes Accidens, sowohl sofern es Zustand, als sofern es als bestimmte, reelle Handlung, ausgeschlossen ist, so bleibt nichts als die in sich, unabhängig von allen Modificationen betrachtete *reine Handlung* übrig, als das, woraus alle Philosophie herzuleiten, oder vielmehr worin alle Construktion vorzunehmen ist. Es scheint eine formelle Unrichtigkeit zu seyn, daß der Verfasser die ursprüngliche Handlung, wahrscheinlich nur als *Handlung*, als *Postulat*, charakterisirt und gleichwohl nachher construirt. - Die Linie des Geometers ist eben deßwegen Postulat, weil und *inwiefern * er sie nicht construirt. Postuliren ist Verzichtthun auf Construiren. Allein dieses Verhältniß, das er seinem Princip gibt, hat noch bedeutendere Folgen für den Gehalt seiner Philosophie. Außer der subjektiven Abhängigkeit, die es dadurch erhält, kann auch die Urhandlung als bloßes Postulat nicht zugleich als das wahre und einzige *An-sich, das Absolute selbst* begriffen werden; der Verfasser würde sich dadurch wieder auf einem gleichen Standpunkt mit Fichte befinden, dem das Ich zwar Princip, aber nicht zugleich das einzige Absolute, und demnach mit einem *Außer-ihm* behaftet ist. Das Absolute wird auch ihm nur als absolutes *Ding* erscheinen können, wie aus seinen"}, {"type": "paragraph", "text": "Einwürfen gegen den Dogmatismus (S. 103) erhellt, worunter er auch den Realismus begreift, wie er sich im Spinoza dargestellt hat. Um nur einen Beweis anzuführen, so ist die Eine Frage, die er (S. 104) dem Realismus (in diesem Sinn) entgegenstellt: \"Was ist eine Realität, die es nicht *für eine Intelligenz*, für mich oder irgend ein Ich ist?\" hinreichend zu beweisen, daß auch er zu dem ansich- und absolut-Seyn das Außer-dem-Ich fordert, denn da ein *Außer-dem-Ich* immer und nothwendig auch nur *für* das Ich ist, so hat er nur, sofern er das *An-sich* auf die erste Weise begreift, Grund zu seiner Frage. Schon dieß wäre hinreichend zu beweisen, daß der Verfasser in seiner Construktion den Punkt des absoluten Zusammentreffens der Erkenntniß und des Absoluten - des einzigen, worin sie sich absolut schließt, nicht erreicht hat, obgleich vielleicht niemand diesem Punkt näher gewesen ist als er selbst. Es ist wie bei Kant und Fichte, von denen jener nach des Verfassers eigner Bemerkung uns immer wieder zum Realismus, dieser zu einem absoluten Nicht-Ich zurückführt; er fällt unvermeidlich immer wieder in die relative Dualität des Ichs und der Dinge zurück, *die beide bleiben sollen, weil das eine nur im Gegensatz gegen das andere Realität hat*; die *Freiheit* behält bei ihm, obgleich sie nur das eine Glied der Antithese ist, wovon die Nothwendigkeit das andere, ebenso wie bei Fichte, eine Art von Priorität; diese soll vorzüglich bleiben, und wo möglich nicht bloß, wie die Dinge auch, allein für die Erscheinung, sondern in irgend einem vorzüglicheren Sinne. Ein besonderes Anliegen ist ihm die *specielle* Realität der Dinge, daß sie nämlich gerade *diese und keine anderen Eigenschaften* haben, die ihm doch offenbar in einem speculativeren Sinn erschienen ist als *Fichte* (der versichert, die Frage nach derselben zuerst geweckt und beantwortet zu haben), da er diese Frage mit der uralten von der *Entstehung des Uebels * in"}]}, {"page_pdf": 1490, "page_book": 144, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der Welt für identisch erklärt. Wenn wir an den einzelnen Aeußerungen des Verfassers etwas zu tadeln finden, so ist es nur, weil sie hinter seinen eignen, vortrefflichen"}, {"type": "paragraph", "text": "Ideen zurückbleiben. Die Stufe, welche seine Speculation wirklich erreicht hat, stimmt sich nach der Höhe, in welcher er den absoluten Identitätspunkt seines Systems gefaßt hat. Wir heben diesen als das Bezeichnendste des Ganzen heraus, wornach allein eigentlich gesucht werden und die Frage seyn kann. Der Vereinigungspunkt zwischen der reellen Welt oder Natur und einem intelligibeln System der Wesen und Handlungen - welche beide (reell) einander vollkommen entsprechen müssen, ohne daß doch je das eine sich mit dem andern vermischen oder aufhören könnte ideell (der Vorstellungsart nach) von ihm verschieden zu seyn - liegt nach dem Verfasser *in der Nothwendigkeit eines allgemeinen Systems in den Einschränkungen der ursprünglichen Handlung*, ohne welches ihre Einheit und Denkbarkeit verschwinden würde. Der Anfang dieses Systems in der *Intelligenz*, welcher der der Intelligenz selbst ist, ist wiederum sowohl als frei wie auch als nothwendig zu denken, nämlich aus verschiedenen Gesichtspunkten. Freiheit und Nothwendigkeit in der Intelligenz sind nur zwei verschiedene Ansichten, deren Indifferenzpunkt in der *ursprünglichen Handlung ohne alle Modification liegt.* Diese ist an sich weder frei noch nothwendig *in* Entgegensetzung, und doch für die Reflexion beides auf gleiche Weise. *Bestimmt* und *nothwendig* als *Grund*, da ein unbestimmter Grund auch ein unbestimmender und insofern keiner ist; aber als *absoluter* Grund ist sie zugleich unbestimmt und frei, da sie durch keinen höheren bestimmt ist. Die *Causalität* der ursprünglichen Handlung ist zugleich die *Handlung selbst* ganz und gar; der *Uebergang zur Bestimmung* und *sie selbst* eins. Die ursprüngliche, in der Intelligenz als Freiheit eintretende Handlung ist daher unbegreiflich, und muß es seyn. Ja das Erste in jeder bestimmten Kette von Begriffen oder Dingen oder Begebenheiten ist daher als ein Akt *absoluter* Freiheit zu begreifen. - Aus der ursprünglichen Handlung und dieser Kraft derselben ist alles Leben, alle Kraft in der Natur; könnte sie aufhören, so würde auch alles Daseyn verschwinden. Aus ihrer Unendlichkeit entsteht in den Dingen das unendlich Bestimmte."}, {"type": "paragraph", "text": "Bestimmung in ihrer Vollständigkeit ist System; denn sie ist die Einheit im Mannichfaltigen. Durch die wesentliche Einheit der ursprünglichen Handlung gibt es auch im strengen Sinne nur Ein System, denn ein zweites müßte durch etwas anderes als sie entstanden seyn, welches unmöglich ist. Als einer absoluten Handlung entsprechend, ist es außerdem in sich selbst zurückkehrend, vollkommen durch sich bestimmt, mehrere Naturen sind unmöglich, denn *Natur* ist das System *für den endlichen Anschauer*, der *Inbegriff der Bedingungen* für die *Vorstellung des Unendlichen im Endlichen, des Absoluten im Eingeschränkten*. Sobald sie entweder *bloß als Objekt* oder *bloß als Vorstellung*, rein subjektiv, oder auch als eine rein *bestimmte* Handlung, rein leidend, betrachtet wird, geschieht dieß nur durch Abstraktion von gewissen Bedingungen derselben. Daß wir uns der ursprünglichen Einheit des Systems unerachtet als frei fühlen *in einer jeden Handlung*, davon liegt der Grund nicht *in dem ersten Akt*, wodurch Wirklichkeit und Natur zuerst entstanden, sondern in einem neuen, insofern dem ersten entgegengesetzten Akt der Reflexion. *Durch denselben entsteht ein neues System, nicht dem Inhalte nach*, nicht eine neue Natur im eigentlichen Sinne, *sondern bloß eine neue Vorstellungsart*. Dieß System, welches an sich *ein und dasselbe* mit dem ersten ist, ist die *intelligible Welt*, die, bloß *durch diese Vorstellungsart* entstanden, der vorigen, und"}]}, {"page_pdf": 1491, "page_book": 146, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "zwar durch Freiheit entgegengesetzt ist. - Solange ich *innerhalb* dieses intelligiblen Systems bleibe, bin ich auch nicht frei; jede Handlung ist da, ob es gleich ein System, ein organisches Ganzes zur Aufrechthaltung der Freiheit ist, oder vielmehr gerade aus diesem Grunde, in allen Theilen bestimmt. Ich bin also nur in der zweiten Reflexion frei, die mich über dieses System erhebt - nicht in Rücksicht der Handlungsart, sondern in Rücksicht der Fortsetzung derselben, indem ich unmittelbar in die Natur zurücksinken kann oder nicht, die jene (die Handlungsart) in concreto schon, als dieselbe, enthält. Was mich bei der ersten Reflexion festhält, die"}, {"type": "paragraph", "text": "Causalität der ursprünglichen Handlung selbst, thut es bei der zweiten nicht. Diese kann aufhören, ohne daß jene gestört werde. Diese Zufälligkeit der zweiten Reflexion in Bezug auf die erste, da es nämlich in dem System derselben nichts verändert, daß ich einen Theil ihres ganzen Produkts in mich aufnehme oder nicht, ist das, was Zurechnung und überhaupt Freiheit als Wahl zwischen Entgegengesetzten oder Willkür bestimmt. Ueber der ersten und zweiten Reflexion gibt es noch eine höhere Reflexion, welche die beiden ersten vereinigt: es ist die *philosophische Reflexion*. Auch sie hat ihr System; denn die Wahrheit ist nur Eine. Sie ist nichts anderes als die *alles umfassende* Reflexion, vollständiges System nach allen Seiten, oder wiederum Natur. *Sie ist die Natur zum höchsten Bewußtseyn gebracht, Natur in ihrer Klarheit und Vortrefflichkeit*. Dieß ist, wenn nicht durchaus wörtlich, doch dem Sinn und der Sache nach, der Abriß der Identität, zu welcher sich die Philosophie in dem Geist des Verfassers ausgebildet hat, und die in der vorliegenden Schrift ausgedrückt ist. Wir haben zu oft und wiederholt in dieser Zeitschrift die Grundsätze ausgesprochen, die uns bei der Beurtheilung einzig leiten, um noch die Versicherung nöthig zu haben, daß der Verfasser nach unsrer Meinung sich des wahrhaft speculativen Standpunktes bemächtigt habe; wo dieser ist, macht er sich selbst geltend, und es hieße nur in die besonderen Formen eines originell denkenden Geistes einbrechen, wenn wir die einzelnen Züge kritisch mustern oder beurtheilen wollten. Es ist noch eine Seite, außer der des Gehalts, deren Wichtigkeit hervorzuheben dieses Werk sich selbst bestrebt. Wie weit sich die Idee des Verfassers von der Philosophie der *Form* nach ausgebildet habe, wird sich vorzüglich aus der von ihm aufgestellten Construktion der ursprünglichen Handlung ergeben, um so mehr, da durch dieselbe zugleich die ganze *wissenschaftliche Form* der Philosophie bestimmt werden muß und bei dem Verfasser wirklich bestimmt ist. Die Einleitung seiner Construktion macht er auf folgende Weise:"}, {"type": "paragraph", "text": "die reine Handlung ist zugleich die ursprüngliche und absolute. Sie ist eine reine Anschauung. Denn nur insofern ist es möglich eine Construktion in ihr vorzunehmen. Jede Construktion fordert ein Schema, die ursprüngliche Construktion das ursprünglichste - also in der allgemeinen höchsten Aufgabe: Einigkeit mit uns selbst, liegende: das * Ich.* (Dieser letzte Uebergang ist allerdings weder der gewählteste noch der strengste). Unter Ich wird aber bloß ein *reines* Ich oder *Intelligenz* gesucht, nicht ein Ich mit wirklichem Bewußtseyn, oder irgend einer Modification, sondern das bloße Wesen und Form der Intelligenz (das reine Subjekt-Objekt). Der merkwürdigste Punkt, wie in aller Philosophie, so auch in dieser Construktion ist der des sogenannten Uebergangs vom Unendlichen zum Endlichen, das Entstehen der Einschränkung in dem an sich Uneingeschränkten, durchaus Gleichartigen und Absoluten. - Wir können nicht sagen, daß der"}]}, {"page_pdf": 1492, "page_book": 148, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Verfasser den ganzen Umfang dieses Problems ermessen habe, indeß ist sein erster Schritt in der Construktion die Synthesis der Schranke und des Uneingeschränkten. \"Im *Wesen* der Handlung als *einer solchen*, nicht *außer ihr*, in irgend einer Bedeutung, liegt nothwendig Einschränkung; die Einschränkung und die Handlung sind gleich absolut.\" Wäre diese Einschränkung oder Grenze fließend und unaufhörlich verändert, so wäre sie ohne Wirkung und schränkte nicht ein, die Handlung hätte kein Produkt, da dieß fixirt seyn muß. Die Handlung muß also mit der absoluten Einschränkung ein Gleichgewicht, eine *Ruhe* gewinnen, und diese Ruhe ist Grenze derselben und zugleich Produkt - nicht der Einschränkung, denn diese producirt nichts, sondern der mit der Einschränkung synthesirten Handlung - Produkt also, wozu die entgegengesetzten Absoluta gemeinschaftlich beitragen. Dieses erste Produkt ist nun für den Verfasser gleichsam der Urstoff, an dem durch ein beständiges Reflektirtwerden und Zurückhandeln der ursprünglichen Handlung alle Form in fortgehender Steigerung hervortritt. Jedes folgende Produkt ist dadurch ausgezeichnet, daß die Handlung des vorhergehenden in es kommt, so daß in jedem späteren"}, {"type": "paragraph", "text": "Produkt mehr Handlung ist als in dem früheren. Das Subjektive wird zum Objektiven, die Thätigkeit zum Produkt geschlagen. Im ersten Produkt ist ein stillstehendes Objekt; im zweiten ein Objekt, das zugleich Handlung ist (oder umgekehrt), - das Ganze Vorstellung -; im dritten ein Produkt, in welchem das Objekt selbst Vorstellung ist - das Ganze Subjekt -; in dem folgenden wird das Subjekt selbst, dem die Vorstellung Objekt war, Objekt, - das Ganze *Bewußtseyn*, welches daher alle vorhergehenden begreift. Durch die letzte Handlung wird auch dasjenige, dessen Objekt das Bewußtseyn ist, selbst Produkt, d.h. *Ich*. Die Reihe ist demnach nach zwei Seiten geschlossen, von der einen durch das erste Produkt, welches gleichsam das höchste Objekt, bloß Ruhe ist, von der andern durch das *absolute* Subjekt, über welches kein höheres Produkt aufgezeigt werden kann. Daraus, daß das Ich in jeder Beziehung das letzte Produkt ist, folgt, daß jedes Produkt über dasselbe in eines von denen Produkten zurückfällt, welche vor diesem Ich in der Handlung entstehen. Unter jeder möglichen Relation sind *nur drei Glieder* möglich, denen drei Produkte entsprechen. Die Glieder, die über diese Anzahl hinzukommen, müssen durch eine frühere Reflexion schon in einem oder mehreren Gliedern einer vorhergegangenen Relation liegen. Also in jeder folgenden Relation, oder, um unsern Ausdruck dafür zu gebrauchen, in jeder folgenden Potenz muß ich immer wieder beim Subjekt stehen bleiben, und erhalte wieder nichts als ein Ich, wiewohl ein genauer eingeschränktes, die Glieder der vorhergehenden Relation, z.B. der zweiten, fallen zum Objekt herab, sind es aber nur in der dritten Dignität u.s.f. Wir wollen nicht behaupten, daß diese Stufenfolge bei dem Verfasser zur höchsten Klarheit, oder, was dasselbe ist, auch zur formellen Anschaulichkeit herausgearbeitet sey; wünschen aber möchte man, daß diejenigen, welche diese Form in der Gestalt, die sie in der Naturphilosophie, dem Systeme des Idealismus u.s.w. erhalten hat, als bloßes Spiel einiger bei ihnen nicht gut angeschriebenen Geistesvermögen begriffen haben, die innere Nothwendigkeit derselben, die sie an sich einzusehen nicht vermögen, wenigstens aus der Unabhängigkeit ahnden"}, {"type": "paragraph", "text": "möchten, mit der sie auch in andern entstanden ist und sich ausgebildet hat. Am klarsten und allgemeinsten ausgedrückt findet sich dieses wissenschaftliche Verfahren in der"}]}, {"page_pdf": 1493, "page_book": 150, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "folgenden Stelle (S. 156). \"Durch den Mechanismus des Verstandes, heißt es, wird die zuletzt gemachte Synthesis unaufhörlich aufs neue Thesis mit ihrer Antithesis in der Handlung, bis in der letzten Synthesis die Aufgabe gelöst ist, die darin besteht, die Intelligenz zur Einigkeit mit sich selbst in der Vorstellung der Natur, oder in einer höheren Reflexion, zum Bewußtseyn dieser Einigkeit zu bringen. Sobald dieses bewerkstelligt ist - was doch (empirisch) insofern nie möglich und denkbar ist, als diese äußerste Synthesis nicht als ein in seinen kleinsten Theilen vollendetes System im Bewußtseyn sich einfinden kann, weil die Intelligenz ihre Endlichkeit nicht überwinden kann -, so hört die Intelligenz auf, und wird wieder die reine zu nichts erlöschende Handlung; die Intelligenz hat dann nichts mehr zu verstehen, denn alles ist eins, und ohne zu verstehen existirt sie nicht.\" Die Schranken des Fichteschen Idealismus liegen, rein theoretisch betrachtet, vorzüglich darin, daß er den Grund der Begrenzung nicht absolut im Ich, sondern in einem Entgegengesetzten hat; daß er die Construktion oder vielmehr Reflexion auf die enge Stelle des Zusammentreffens der reinen und der empirischen Ichheit (des subjektiven Subjekt-Objekts) beschränkt1, und daß die Form der Thesis, Antithesis und Synthesis in ihm bloß logisch genommen ist. Das Ich, welches hier *Princip* ist, ist dem Verfasser ein Construirtes, er ist dadurch wahrhaft *transscendental*, daß er eine Stufenfolge von Handlungen aufstellt, die jenseits des Ich liegt, die Form der Thesis, Antithesis und Synthesis wiederholt sich ihm im Einzelnen wie im Ganzen, und ist der Typus einer realen und allgemeinen Organisation. Der objektive Umfang und die universelle Beziehung, welche die Idee des Verfassers wenigstens in der Anlage zeigt, wird sich aus folgenden Aeußerungen beurtheilen lassen. In der Construktion der Materie, wie sie in Kants metaphysischen Anfangsgründen der Naturwissenschaft"}, {"type": "footnote", "text": "1 Vergl. Fichtes und Schellings Briefwechsel, S. 59 unten. D. H."}, {"type": "paragraph", "text": "gegeben ist, erkennt man die einzige Probe von Construktion mit Bewußtseyn bei ihm. \"Was ist wohl diese von ihm construirte Urmaterie?\" fragt der Verfasser. - \"Nichts als eine Modification derjenigen Urrealität, die das Produkt der ersten denkbaren Handlung ausdrückte und in demselben enthalten war. Dieß Produkt war auch das *erste Objekt*; weiter hinab erhalte ich ein davon hergeleitetes oder genauer eingeschränktes Objekt im Raume. Folglich besteht auch das Wesen der Materie in diesem Negativen und Positiven, wodurch sie den Raum erfüllt. - Was aber von der Materie überhaupt gilt, das muß auch von jeder Materie gelten, sie sey übrigens noch so bestimmt und individualisirt. Die bestimmte ist außerdem auch ein Produkt, und hat also die Eigenschaften eines Produkts, da die Natur für mich durch Construktion entsteht, und alle Construktion ein Produciren ist. - Da also dieser Dualism sich als wesentlich in aller Construktion einfindet, so muß auch er die einzige befriedigende Erklärung aller Erscheinungen geben. - Was keine *Atomistik*, keine *mechanische Chemie*, keine *materielle Psychologie*, kein *Hylozoismus* und keine *verborgenen Eigenschaften* erklären können, muß durch dieß Princip begreiflich seyn. Die Cohäsion sogar so wie auch bestimmte Körper und ihre Eigenschaften müssen einmal dadurch entwickelt werden und damit zusammenhangen können. Man hat in der Naturlehre schon Elasticität, und vielleicht ist dieser Begriff noch zu wenig angewandt. Wenigstens ist Ursache zu vermuthen, daß die Polarität, die man in gewissen Körpern findet, von dieser Elasticität hergeleitet oder mit ihr in Zusammenhang befunden werden könne, um so mehr, da beide augenscheinlich bloß eine Modification des allgemeinen Dualismus sind. - Ohne Naturphilosophie keine Naturwissenschaft. Der einzig wahre Endzweck des (empirischen) Naturstudiums kann außer der Anwendung nur seyn, auch die specielle Naturkenntniß zum nothwendigen und vollständigen Zusammenhange mit dieser Naturmetaphysik zu bringen.\" Es ist höchst erfreulich, unter der Fluth in Deutschland erscheinender philosophischer Bücher, welche"}]}, {"page_pdf": 1494, "page_book": 151, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "meist nur die unglaubliche Rohheit, den Mangel an Bildung und selbst der historischen Kenntniß der"}, {"type": "paragraph", "text": "Philosophie bei ihren Verfassern beurkunden, ein fremdes so durchgebildetes, gedachtes, in den Zustand der Wissenschaft wirksam eingreifendes und mit durchgängiger Kenntniß und Beurtheilung des Vorhandenen abgefaßtes Werk zu bemerken. Nach einer Nachricht in der Vorrede des Uebersetzers ertheilte dem Verfasser nach Erscheinung dieses Werks, als Probeschrift, die allgemeine Meinung und das öffentliche Urtheil die erste Stelle unter denen, die der Regierung zur Besetzung des damals ledigen theoretisch-philosophischen Lehrstuhls zu Upsala vorgeschlagen wurden. \"Allein, setzt er hinzu, der Scharfsinn, die vollkommene Sachkenntniß, das lebendige Interesse für Wissenschaft und deren Verbreitung, die Gabe des klaren und anschaulichen Vortrags, und dergleichen, sonst vielleicht unschädliche Eigenschaften, sind doch freilich nur untergeordnete Züge im Bild eines rechtlichen Professors. Nur ein Mann, dem das Lob der Moderirtheit gebührte, verdiente das Glück - und die Ueberraschung, zum Lehrer der Philosophie ernannt zu werden.\""}, {"type": "paragraph", "text": "Ueber Dante in philosophischer Beziehung."}, {"type": "paragraph", "text": "Die die Vergangenheit mehr als die Gegenwart lieben, wird es nicht befremden, sich von den, eben nicht immer belohnenden Anblicken der letzteren zu einem so entfernten Denkmal der mit Poesie verbundenen Philosophie zurückgeführt zu sehen, als die Werke des Dante sind, die längst die Heiligkeit des Alterthums bedeckt. Ich verlange als Rechtfertigung dieses Platzes, den diese Gedanken hier einnehmen, vorerst nichts zugegeben, als: daß das Gedicht, auf welches sie sich beziehen, eines der merkwürdigsten Probleme der philosophischen und historischen Construktion der Kunst ist. Der Verfolg wird zeigen, daß diese Untersuchung eine weit allgemeinere, die Verhältnisse der Philosophie selbst betreffende, in sich schließt, und für diese von nicht geringerem Interesse als für die Poesie ist, deren wechselseitige Verschmelzung, zu welcher die ganze neuere Zeit sich neigt, von beiden Seiten gleich bestimmte Bedingungen fordert."}, {"type": "paragraph", "text": "Im Allerheiligsten,"}, {"type": "paragraph", "text": "Wo Religion und Poesie verbündet, steht Dante als Hohepriester und weiht die ganze moderne Kunst für ihre Bestimmung ein. Nicht ein einzelnes Gedicht, sondern die ganze Gattung der neueren Poesie repräsentirend und selbst eine Gattung für sich, steht die göttliche Komödie so ganz abgeschlossen, daß die von einzelneren Formen abstrahirte Theorie für sie ganz unzureichend ist, und"}]}, {"page_pdf": 1495, "page_book": 153, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "sie als eine eigne Welt auch ihre eigne Theorie fordert. Das Prädicat der Göttlichkeit gab ihr der Urheber, weil sie von der Theologie und von göttlichen Dingen handelt; Komödie nannte er sie nach den einfachsten Begriffen von dieser und der entgegengesetzten Gattung, wegen des furchtbaren Beginns und des glücklichen Ausgangs, und weil die gemischte Natur seines Gedichts, dessen Stoff bald erhabener, bald niedriger ist, auch eine gemischte Art des Vortrags nothwendig machte. Man sieht aber leicht, daß es nach den gewöhnlichen Begriffen nicht dramatisch heißen kann, da es keine beschränkte Handlung darstellt. Inwiefern Dante selbst als die Hauptperson betrachtet wird, die nur als Band für die unermeßliche Reihe von Gesichten und Gemälden dient und mehr leidend als thätig sich verhält, könnte dieses Gedicht dem Roman sich zu nähern scheinen; aber auch dieser Begriff erschöpft es so wenig, als es nach einer gewöhnlicheren Vorstellung episch heißen kann, da in den Gegenständen der Darstellung selbst keine Aufeinanderfolge stattfindet. Als Lehrgedicht es zu betrachten, ist gleichfalls nicht möglich, da es in einer viel unbedingteren Form und Absicht als der des Lehrens geschrieben ist. Es ist also nichts von alle dem insbesondere, auch nicht etwa nur eine Zusammensetzung, sondern eine ganz eigenthümliche, gleichsam organische, durch keine willkürliche Kunst wieder hervorzubringende Mischung aller Elemente dieser Gattungen, ein absolutes Individuum, nichts anderem und nur sich selbst vergleichbar. Der Stoff des Gedichts ist im Allgemeinen die ausgesprochene Identität der ganzen Zeit des Dichters, die Durchdringung der Begebenheiten derselben mit den Ideen der Religion, der Wissenschaft und der Poesie in dem überlegensten Geist jenes Jahrhunderts. Unsere Absicht ist nicht, es in seiner unmittelbaren Zeitbeziehung, sondern vielmehr in seiner Allgemeingültigkeit und Urbildlichkeit für die ganze moderne Poesie zu fassen. Das nothwendige Gesetz derselben bis zu dem in noch unbestimmbarer Ferne liegenden Punkt, wo das große Epos der neuen Zeit, das bis jetzt nur rhapsodisch und in einzelnen Erscheinungen sich verkündet,"}, {"type": "paragraph", "text": "als beschlossene Totalität hervortritt, ist: daß das Individuum den ihm offenbaren Theil der Welt zu einem Ganzen bilde, und aus dem Stoff seiner Zeit, ihrer Geschichte und ihrer Wissenschaft sich seine Mythologie erschaffe. Denn wie die alte Welt allgemein die Welt der Gattungen, so ist die moderne die der Individuen: dort ist das Allgemeine wahrhaft das Besondere, das Geschlecht wirkt als Individuum; hier ist umgekehrt die Besonderheit der Ausgangspunkt, die zur Allgemeinheit werden soll. In jener ist eben deßwegen alles dauernd, unvergänglich: die Zahl hat gleichsam keine Gewalt, da der Allgemeinbegriff mit dem des Individuums in eins fällt: in dieser ist Wechsel und Wandel bleibendes Gesetz, kein beschlossener, sondern nur ein durch Individualität ins Unendliche zu erweiternder Kreis faßt ihre Bestimmungen, und weil Universalität zum Wesen der Poesie gehört, so ist die nothwendige Forderung diese, daß das Individuum durch die höchste Eigenthümlichkeit wieder allgemeingültig, durch die vollendete Besonderheit wieder absolut werde. Eben durch das schlechthin Individuelle, nichts anderem Vergleichbare seines Gedichts ist Dante der Schöpfer der modernen Kunst, die ohne diese willkürliche Nothwendigkeit und nothwendige Willkür nicht gedacht werden kann. Von dem ersten Beginn der griechischen Poesie an sehen wir sie von der Wissenschaft und Philosophie rein geschieden, im Homer, und diesen Sonderungsproceß bis zur vollkommenen Entgegensetzung der Dichter und Philosophen fortgesetzt, welche durch allegorische Erklärungen der Homerischen Dichtungen vergeblich eine Harmonie zu erkünsteln suchten. In der neueren Zeit ist die Wissenschaft der Poesie und Mythologie vorangegangen, welche nicht Mythologie seyn kann, ohne universell zu seyn und alle Elemente der vorhandenen Bildung, die Wissenschaft, die Religion, die Kunst"}]}, {"page_pdf": 1496, "page_book": 155, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "selbst, in ihren Kreis zu ziehen, und nicht allein den Stoff der gegenwärtigen, sondern auch den der vergangenen Zeit zu einer vollkommenen Einheit zu verknüpfen. In diesem Widerstreit, da die Kunst das Geschlossene, Begrenzte fordert, der Geist der Welt aber gegen das Unbegrenzte hintreibt und mit unwandelbarer Festigkeit jede Schranke niederreißt, muß das"}, {"type": "paragraph", "text": "Individuum eintreten, mit absoluter Freiheit sondern, der Mischung der Zeit dauernde Gestalten abzugewinnen suchen, und innerhalb der durch Willkür gezogenen Formen dem Gebilde seiner Dichtung durch die absolute Eigenthümlichkeit wieder die Nothwendigkeit in sich und die Allgemeingültigkeit nach außen geben. Dieß hat Dante gethan. Er hatte vor sich den Stoff der Geschichte der Gegenwart wie der Vergangenheit. Er konnte ihn nicht zum reinen Epos verarbeiten, theils seiner Natur wegen, theils weil er dadurch wieder andere Seiten der Bildung seiner Zeit ausgeschlossen hätte. Zu der Ganzheit derselben gehörte auch die Astronomie, die Theologie und Philosophie der Zeit. Er konnte diese nicht in einem Lehrgedicht vortragen, denn auch dadurch beschränkte er sich wieder, und sein Gedicht mußte, um universell zu seyn, zugleich historisch seyn. Es bedurfte einer ganz willkürlichen, vom Individuum ausgehenden, Erfindung, um diesen Stoff zu verknüpfen und organisch zu einem Ganzen zu bilden. Die Ideen der Philosophie und Theologie in Symbolen darzustellen, war unmöglich, denn es war keine symbolische Mythologie vorhanden. Er konnte aber ebensowenig sein Gedicht ganz allegorisch machen, denn alsdann konnte es wieder nicht historisch seyn. Es mußte also eine durchaus eigenthümliche Mischung des Allegorischen und Historischen seyn. In der exemplarischen Poesie der Alten war kein Ausweg dieser Art möglich: nur das Individuum konnte ihn ergreifen, nur schlechthin freie Erfindung ihn verfolgen. Das Gedicht des Dante ist nicht allegorisch in dem Sinn, daß die Gestalten desselben etwas anderes nur bedeuteten, ohne unabhängig von der Bedeutung und an sich selbst zu seyn. Von der andern Seite ist keine derselben auf solche Weise von der Bedeutung unabhängig, daß sie zugleich die Idee selbst und mehr als Allegorie von ihr wäre. Es ist also in seinem Gedicht ein ganz eigenthümliches Mittel zwischen Allegorie und zwischen symbolisch-objektiver Gestaltung. Es ist kein Zweifel, und der Dichter hat es selbst anderwärts erklärt, daß Beatrice z.B. eine Allegorie, der Theologie nämlich, ist. So ihre Gefährtinnen, so viele andere Gestalten. Aber sie zählen zugleich für sich"}, {"type": "paragraph", "text": "selbst, und treten als historische Personen ein, ohne deßwegen Symbole zu seyn. Dante ist in dieser Rücksicht urbildlich, da er ausgesprochen hat, was der moderne Dichter zu thun hat, um das Ganze der Geschichte und Bildung seiner Zeit, den einzigen mythologischen Stoff, der ihm vorliegt, in einem poetischen Ganzen niederzulegen. Er muß aus absoluter Willkür Allegorisches und Historisches verknüpfen, er muß allegorisch seyn, und ist es auch wider seinen Willen, weil er nicht symbolisch seyn kann, und historisch, weil er poetisch seyn soll. Die Erfindung, die er in dieser Rücksicht macht, ist jedesmal einzig, eine Welt für sich, ganz der Person angehörig. Das einzige deutsche Gedicht von universeller Anlage knüpft die äußersten Enden in dem Streben der Zeit durch die ganz eigenthümliche Erfindung einer partiellen Mythologie, die Gestalt des Faust, auf ähnliche Weise zusammen, obgleich es in bei weitem mehr Aristophanischer Bedeutung Komödie und in anderm mehr poetischem Sinne göttlich heißen kann als das Gedicht des Dante. Die Energie, mit welcher das Individuum die besondere Mischung des vorliegenden Stoffs der Zeit"}]}, {"page_pdf": 1497, "page_book": 157, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "und seines Lebens gestaltet, bestimmt das Maß, in welchem er mythologische Kraft erhält. Die Personen des Dante erhalten schon durch die Stelle, an welche er sie versetzt und welche ewig ist, eine Art der Ewigkeit; aber nicht nur das Wirkliche, was er aus seiner Zeit aufnimmt, wie die Geschichte des Ugolino u.a., sondern auch, was er gänzlich erdichtet, wie das Ende des Ulysses und seiner Gefährten, hat im Zusammenhang seines Gedichtes eine wahrhaft mythologische Gewißheit. Es könnte nur ein sehr untergeordnetes Interesse haben, die Philosophie, Physik und Astronomie des Dante an und für sich darzustellen, da seine wahre Eigenthümlichkeit nur in der Art ihrer Verschmelzung mit der Poesie liegt. Das Ptolomäische Weltsystem, welches gewissermaßen der Grund seines poetischen Gebäudes ist, hat an sich selbst schon eine mythologische Farbe; wenn aber seine Philosophie insgemein als aristotelische charakterisirt wird, so muß darunter nicht die rein"}, {"type": "paragraph", "text": "peripatetische, sondern die der damaligen Zeit eigne Verbindung derselben mit den Ideen der platonischen verstanden werden, wie sich durch viele Proben seines Gedichtes beweisen ließe. Wir wollen nicht bei der Kraft und Gediegenheit einzelner Stellen, der Einfachheit und unendlichen Naivetät einzelner Bilder verweilen, in denen er seine philosophischen Ideen ausspricht, wie das bekannte von der Seele, die aus den Händen Gottes kommt als ein kleines Mägdlein, das mit Weinen und Lachen kindisch thut, ein einfältig Seelchen, das nichts weiß, außer daß es, bewegt von dem heitern Urheber, sich gern zu dem wendet, wodurch es ergötzt wird: wir reden nur von der allgemein symbolischen Form des Ganzen, in deren Absolutheit mehr als in irgend etwas anderm die Allgemeingültigkeit und die Ewigkeit dieses Gedichts erkannt wird. Wenn die Verbindung der Philosophie und Poesie auch nur in ihrer untergeordnetsten Synthese als Lehrgedicht aufgefaßt wird, so ist, weil das Gedicht ohne äußeren Zweck seyn soll, nothwendig, daß die Absicht (zu lehren) in ihm selbst wieder aufgehoben und in eine Absolutheit verwandelt ist, so daß es um seiner selbst willen zu seyn scheinen könne. Dieß ist aber nur denkbar, wenn das Wissen als Bild des Universums und in der vollkommenen Eintracht mit demselben, als der ursprünglichsten und schönsten Poesie, an und für sich selbst schon poetisch ist. Dantes Gedicht ist eine viel höhere Durchdringung der Wissenschaft und der Poesie, und um so viel mehr muß seine Form, auch in der freieren Selbständigkeit, dem allgemeinen Typus der Weltanschauung angemessen seyn. Die Eintheilung des Universum und Anordnung des Stoffs nach den drei Reichen, des Infernum, Purgatorium und Paradieses ist auch unabhängig von der besondern Bedeutung dieser Begriffe im Christenthum eine allgemein symbolische Form, so daß man nicht sieht, warum in derselben Form nicht jedes ausgezeichnete Zeitalter seine göttliche Komödie haben könnte. Wie für das neuere Drama die Form der fünf Aufzüge als die gewöhnliche angenommen ist, weil jede Begebenheit in ihrem Beginn, Fortgang, ihrer Culmination, Hinneigung zum Ende"}, {"type": "paragraph", "text": "und wirklichen Ende betrachtet werden kann, so ist jene Trichotomie des Dante für die höhere prophetische Poesie, welche eine ganze Zeit ausspräche, als allgemeine Form denkbar, deren Ausfüllung nur unendlich verschieden wäre, wie sie durch die Macht origineller Erfindung immer aufs neue belebt werden könnte. Aber nicht nur als äußere Form, sondern als sinnbildlicher Ausdruck des inneren Typus aller Wissenschaft und Poesie ist jene Form ewig und fähig, die drei großen Gegenstände der Wissenschaft und Bildung, Natur, Geschichte und Kunst in sich zu fassen. Die Natur ist, als die Geburt aller Dinge, die ewige Nacht, und als diejenige Einheit, wodurch diese in sich selbst sind, das Aphelium"}]}, {"page_pdf": 1498, "page_book": 159, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "des Universums, der Ort der Entfernung von Gott als dem wahren Centro. Das Leben und die Geschichte, deren Natur stufenweises Fortschreiten ist, ist nur Läuterung, Uebergang zu einem absoluten Zustand. Dieser ist nur in der Kunst gegenwärtig, welche die Ewigkeit anticipirt, das Paradies des Lebens und wahrhaft im Centro ist. Dantes Gedicht ist also, von allen Seiten betrachtet, kein einzelnes Werk eines besonderen Zeitalters, einer besonderen Stufe der Bildung, sondern urbildlich durch die Allgemeingültigkeit, die es mit der absolutesten Individualität vereinigt, durch die Universalität, vermöge der es keine Seite des Lebens und der Bildung ausschließt, durch die Form endlich, welche nicht besonderer Typus, sondern Typus der Betrachtung des Universums überhaupt ist. Die besondere Anordnung des Gedichts nach innen kann allerdings nicht diese Allgemeingültigkeit haben, da sie nach Begriffen der Zeit und besondern Absichten des Dichters gebildet ist, dagegen ist der allgemeine innere Typus, wie von einem solchen kunstvollen und durchaus absichtlichen Werk nicht anders erwartet werden kann, auch äußerlich wieder durch Gestalt, Farbe, Ton der drei großen Theile des Gedichts symbolisirt. Bei der Ungemeinheit seines Stoffs bedurfte Dante für die Form seiner Erfindungen im Einzelnen einer Art von Beglaubigung, welche ihm nur die Wissenschaft der Zeit geben konnte, die für ihn gleichsam"}, {"type": "paragraph", "text": "die Mythologie und der allgemeine Grund ist, der den kühnen Bau seiner Erfindungen trägt. Aber auch im Einzelnen bleibt er ganz der Absicht getreu, allegorisch zu seyn, ohne daß er aufhörte historisch und poetisch zu seyn. Das Infernum, Purgatorium und Paradies sind gleichsam nur das in concreto und architektonisch aufgeführte System der Theologie. Die Maße, Zahlen und Verhältnisse, die er im Innern derselben beobachtet, waren durch diese Wissenschaft vorgeschrieben, und er begab sich hierin absichtlich der Freiheit der Erfindung, um seinem dem Stoff nach unbegrenzten Gedicht durch die Form Nothwendigkeit und Begrenzung zu geben. Die allgemeine Heiligkeit und die Bedeutung der Zahlen ist eine andere äußere Form, auf die seine Poesie sich gründet. So ist überhaupt die ganze logische und syllogistische Gelehrsamkeit jener Zeit für ihn nur Form, die ihm zugegeben werden muß, um zu derjenigen Region zu gelangen, in welcher sich seine Poesie befindet. Dennoch sucht Dante in diesem Anschließen an religiöse und wissenschaftliche Vorstellungen, als das allgemeingültigste, was seine Zeit darbot, niemals eine Art gemeiner poetischer Wahrscheinlichkeit, sondern hebt vielmehr eben damit alle Absicht auf, den groben Sinnen zu schmeicheln. Sein erster Eingang in die Hölle geschieht, wie er geschehen mußte, ohne einen unpoetischen Versuch, ihn zu motiviren oder begreiflich zu machen, in einem Zustand, ähnlich dem eines Gesichts, ohne daß doch die Absicht wäre, ihn dafür gelten zu machen. Seine Erhebung durch die Augen der Beatrice, durch welche die göttliche Kraft sich an ihn gleichsam fortleitet, drückt er in einer einzigen Zeile aus: das Wunderbare seiner eignen Begegnisse verwandelt er unmittelbar selbst wieder in ein Gleichniß von Geheimnissen der Religion, und beglaubigt jene durch das noch höhere Mysterium, wie wenn er seine Aufnahme in den Mond, die der des Lichtes in ungetrenntes Wasser gleicht, zu einem Bilde der Menschwerdung Gottes macht. Die Fülle der Kunst, die Tiefe der bis ins Einzelne gehenden Absichtlichkeit in der innern Construktion der drei Welttheile darzustellen, wäre eine eigne Wissenschaft, wie kurze Zeit nach des Dichters Tode"}]}, {"page_pdf": 1499, "page_book": 161, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "von seiner Nation anerkannt wurde, indem sie einen eignen Lehrstuhl des Dante errichtete, den zuerst Boccaccio begleitete. Aber nicht nur die einzelnen Erfindungen jedes der drei Theile des Gedichts lassen das Allgemein-bedeutende der ersten Form durchscheinen, sondern noch bestimmter drückt sich das Gesetz derselben in dem innerlichen und geistigen Rhythmus aus, wodurch sie einander entgegengesetzt sind. Das Infernum, wie es das furchtbarste in den Gegenständen ist, ist auch das stärkste im Ausdruck, das strengste in der Diktion, auch den Worten nach dunkel und graunvoll. Auf einem Theil des Purgatorium ruht eine tiefe Stille, da die Wehklagen der untern Welt verstummen, auf den Anhöhen desselben, den Vorhöfen des Himmels, wird alles Farbe; das Paradies ist eine wahre Musik der Sphären. Die Mannichfaltigkeit und Verschiedenheit der Strafen im Infernum ist mit einer fast beispiellosen Invention ausgedacht. Zwischen den Verbrechen und den Qualen ist nie ein anderer als poetischer Zusammenhang. Dantes Geist entsetzt sich vor dem Schrecklichen nicht, ja er geht bis an die äußerste Grenze desselben. Aber es ließe sich für jeden einzelnen Fall zeigen, daß er niemals aufhört erhaben und demnach wahrhaft schön zu seyn; denn was Menschen, die das Ganze nicht zu fassen im Stande sind, zum Theil als niedrig ausgezeichnet haben, ist es nicht in ihrem Sinne, sondern nothwendiges Element der Gemischtheit des Gedichts, wegen welcher es Dante selbst Komödie nannte. Der Haß des Argen, der Zorn eines göttlichen Gemüths, der sich in Dantes schrecklicher Composition ausdrückt, sind nicht das Erbtheil gemeiner Seelen. Es ist zwar noch sehr zweifelhaft, was insgemein angenommen wird, daß die Verbannung aus Florenz, nachdem er bis dahin seine Poesie vornehmlich nur der Liebe geweiht hatte, zuerst seinen zum Ernsthaften und Außerordentlichen aufgelegten Geist zu der höchsten Erfindung gespornt habe, worin er das Ganze seines Lebens, der Schicksale seines Herzens und seines Vaterlandes, zugleich mit dem Unmuth darüber aushauchte. Aber die Rache, die er im Infernum übt, übt er wie im Namen des Weltgerichts, als berufener Strafrichter"}, {"type": "paragraph", "text": "mit prophetischer Kraft, nicht nach persönlichem Haß, sondern mit frommer durch die Gräuel der Zeit empörter Seele und einer längst nicht mehr gekannten Liebe des Vaterlandes, wie er selbst in einer Stelle des Paradieses sich darstellt, wo er sagt: \"Wenn es je geschieht, daß das heilige Gedicht, an welches Hand gelegt haben so der Himmel als die Erde, und das mich bleich gemacht hat viele Jahre hindurch, überwindet die Grausamkeit der Zeit, die mich ausschließt aus der schönen Hürde, wo ich, ein Lämmlein, schlief, feind den Wölfen, die sie verheeren: mit anderer Stimme dann und neuem Vließ werde ich zurückkehren und an dem Ort meiner Taufe den Lorbeer empfangen.\" Die Schrecklichkeit der Qualen der Verdammten mäßigt er durch seine eigne Empfindung darüber, die noch fast am Ziele so vielen Jammers die Augen ihm so berauscht, daß er zu weinen begierig ist, und Virgilius ihm sagt: Warum betrübst du dich doch? Es ist schon bemerkt worden, daß die meisten Strafen des Infernum symbolisch für die Verbrechen sind, die durch sie gestraft werden, aber mehrere sind es noch in weit allgemeinerer Beziehung. Von dieser Art ist insbesondere die Darstellung einer Metamorphose, wo zwei Naturen zugleich sich ineinander und durcheinander verwandeln und den Stoff gleichsam tauschen. Keine der Verwandlungen des Alterthums kann sich an Erfindung mit dieser messen, und wenn ein Naturforscher oder didaktischer Dichter Sinnbilder der ewigen Metamorphose der Natur von solcher Kraft zu entwerfen vermöchte, könnte er sich glücklich preisen. Das Infernum ist nicht nur, wie schon bemerkt, der äußern Form der Darstellung nach, sondern dadurch von den andern Theilen unterschieden, daß es vorzugsweise das Reich der Gestalten, und demnach der plastische Theil des Gedichts ist. Das Purgatorium muß man als den pittoresken erkennen. Nicht allein sind die Büßungen, die den Sündern hier auferlegt werden, zum Theil ganz malerisch, bis zur"}]}, {"page_pdf": 1500, "page_book": 162, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Heiterkeit behandelt; sondern insbesondere bietet die Wanderung über die heiligen Hügel der Büßungsstätte einen raschen Wechsel vorübergehender Aussichten, Scenen und mannichfacher Wirkungen des Lichtes"}, {"type": "paragraph", "text": "dar, bis auf den letzten Grenzen desselben, nachdem der Dichter am Lethe angekommen ist, die höchste Pracht der Malerei und der Farbe sich aufthut in den Schilderungen der göttlichen uralten Haine dieser Gegend, der himmlischen Klarheit der Wasser, die von ihren ewigen Schatten bedeckt sind, der Jungfrau, der er an ihren Ufern begegnet und der Ankunft der Beatrice in einer Wolke von Blumen, unter einem weißen Schleier, bekränzt mit Oliven, gehüllt in einen grünen Mantel und in Purpur lebendiger Flamme gekleidet. Der Dichter ist durch das Herz der Erde selbst zum Lichte gedrungen: im Dunkel der Unterwelt konnte nur die Gestalt unterschieden werden, im Purgatorium entzündet sich das Licht noch gleichsam mit dem irdischen Stoff und wird Farbe. Im Paradies bleibt nur die reine Musik des Lichtes, der Reflex hört auf, und der Dichter erhebt sich stufenweise zur Anschauung der farblosen reinen Substanz der Gottheit selbst. Die zur Zeit des Dichters mit mythologischer Würde bekleidete Ansicht des Weltsystems, der Qualität der Gestirne und des Maßes ihrer Bewegung ist der Grund, auf welchen sich seine Erfindungen in diesem Theil des Gedichtes stützen; und wenn er in dieser Sphäre der Absolutheit dennoch Grade und Unterschiede stattfinden läßt, hebt er sie durch das herrliche Wort wieder auf, das er eine der Schwesterseelen, die er im Monde begegnet, aussprechen läßt: daß jedes *Wo* im Himmel Paradies ist. Die Anlage des Gedichts bringt es mit sich, daß eben auf der Erhebung durch das Paradies die höchsten Sätze der Theologie erörtert werden. Die hohe Verehrung gegen diese Wissenschaft wird durch die Liebe zu Beatrice vorgebildet. Es ist nothwendig, daß in dem Verhältniß, als die Anschauung in das rein Allgemeine sich auflöst, die Poesie Musik wird, die Gestaltung verschwindet, und daß in dieser Beziehung das Infernum als der poetischere Theil erscheinen kann. Allein es ist hier durchaus nichts einzeln zu nehmen, und die besondere Vortrefflichkeit eines jeden Theils nur durch die Zusammenstimmung zum Ganzen bewährt und wahrhaft erkennbar. Wird das Verhältniß der"}, {"type": "paragraph", "text": "drei Theile im Ganzen gefaßt, so wird es als nothwendig erkannt, daß das Paradies der rein musikalische und lyrische ist, selbst in der Absicht des Dichters, der diese auch in den äußeren Formen durch den häufigeren Gebrauch der lateinischen Worte kirchlicher Hymnen ausdrückt. Die bewundernswürdige Größe des Gedichts, welche in der Durchdringung aller Elemente der Poesie und Kunst hervorleuchtet, gelangt auf diese Weise ganz zur äußeren Erscheinung. Dieses göttliche Werk ist nicht plastisch, nicht pittoresk, nicht musikalisch, sondern dieß alles zugleich und in zusammenstimmender Harmonie: es ist nicht dramatisch, nicht episch, nicht lyrisch, sondern auch von diesem eine ganz eigne, einzige, beispiellose Mischung. Ich glaube zugleich gezeigt zu haben, daß es prophetisch, vorbildlich ist für die ganze moderne Poesie. Es faßt alle ihre Bestimmungen in sich und entsteigt dem noch vielfach gemischten Stoff derselben als das erste sich über die Erde und zum Himmel ausbreitende Gewächs, die erste Frucht der Verklärung. Die die Poesie der späteren Zeit nicht nach oberflächlichen Begriffen, sondern in ihrem Quell kennen lernen wollen, mögen an diesem großen und strengen Geist sich üben, um zu wissen, durch welche Mittel die Ganzheit der neueren Zeit umfaßt werde, und daß kein so leicht geknüpftes Band sie vereinige. Die hiezu"}]}, {"page_pdf": 1501, "page_book": 164, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "nicht berufen sind, mögen gleich die Worte am Anfang des ersten Theils auf sich selbst beziehen: Laßt alle Hoffnung fahren, die ihr eingeht1!"}, {"type": "footnote", "text": "1 Als \"Anhang\" zu diesem Aufsatz oder eigentlich als Gegenstück zu seiner eignen Auffassung Dantes hatte der Verfasser am Schluß des Kritischen Journals die Ansicht Bouterweks über Dante vorgeführt; es wurde dieß, nebst einer anderen Auslassung ähnlichen Inhalts, die dort zu lesen ist, übergangen. D. H."}, {"type": "paragraph", "text": "*Notizenblatt.*"}, {"type": "paragraph", "text": "1. Besonderer Zweck des Blattes."}, {"type": "paragraph", "text": "Von dem inneren Zustand der Philosophie ist in der dem Ganzen als Einleitung vorgesetzten Abhandlung ein allgemeines Bild entworfen worden; der äußere Zustand, welcher nicht vor die Kritik gehört, ist darum doch nicht so uninteressant, daß nicht allerdings Notiz von ihm genommen werden dürfte. Denn, um nichts von den merkwürdigen klimatischen Unterschieden zu sagen, welche die Betrachtung desselben im Großen wie im Kleinen und sogar schon auf der geringen Oberfläche Deutschlands zeigt, so sind äußere Erscheinungen, welche auf Philosophie Bezug haben, schon ihrer Natur nach mehr oder weniger Wirkungen innerer Verhältnisse, und weisen auf diese zurück. Umstände und Schickung der Zeit haben der Philosophie in unsern Tagen ein sehr ausgedehntes und für ihre innere Kultur nicht ganz unwichtiges Verhältniß zu einer Menge von Gegenständen und Menschen gegeben, die, wenn sie sich besinnen könnten, selbst verwundert seyn müßten, wie sie dazu gekommen. Die allgemeine Aufmerksamkeit, welche die Philosophie auf sich gezogen, hat den Schwarm von Menschen immer mehr vergrößert, der, wenn er nicht in sie eindringen kann, sie wenigstens äußerlich umschwirrt und sich durch sein Gesumme unnütz macht. Eine Menge friedlicher Bürger des Gelehrtenstaats, die innerhalb der vier Pfähle ihrer Brodwissenschaft vergnügte Leute gewesen sind, hat"}, {"type": "paragraph", "text": "die allen andern Wissenschaften von der philosophischen Republik aus angedrohte Erschütterung oder gar Revolution aus ihrer Ruhe aufgestört. Gewiß ist es ein merkwürdiges Zeichen der Zeit, wenn auch die curta supellex einen Kurt Sprengel nicht abhält, von den Transscendentalphilosophen Notiz zu nehmen; oder wenn ein solider, hausbackener Verstand sich von Tübingen her vernehmen lassen muß: *die* Zeit sey noch nicht gekommen, wo man es als ausgemacht ansehen könnte, daß die Erscheinungen der Natur durch die Gesetze des Denkens bestimmt seyen; oder ein ungezogener junger Mensch aus Niedersachsen, den Röschlaub von wegen seiner Lügenhaftigkeit gezüchtigt hatte, im Intelligenzblatt der Jenaer Allgemeinen Literaturzeitung auf die Philosophie und das, was dieser Pöbel Sophisterei nennt, schimpfen muß. Das häufig wiederholte Verschmähen des Auktoritätsglaubens, des Mangels an Selbstdenken, hat"}]}, {"page_pdf": 1502, "page_book": 166, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "endlich die Folge gehabt, daß jeder, der irgend eine Trivialität aufzujagen im Stande ist, sich zu einem Philosophen von eigner Hand constituirt, und wenn man ihm etwa zu verstehen gibt, daß er gegenüber von Fichte z.B. allerdings zu schweigen und in allewege die Hand auf den Mund zu legen habe, im Intelligenzblatt der Allgemeinen Literaturzeitung ganz ungebärdig sich anstellt, auf seine Selbständigkeit pocht, und sich nicht etwa darüber verwundert, daß dieser überhaupt seiner nur Meldung gethan, sondern darüber, daß er die wahre Meinung über ihn gesagt hat. Dieß alles und noch mehr bildet ein für die Philosophie selbst ganz äußeres Verhältniß zu einzelnen Menschen; ein weit ausgedehnteres und mehr oder weniger allgemeines zum gesammten Publikum bildet die Betriebsamkeit ganzer Institute, die, außerdem daß sie den Gang der Literatur im Ganzen und das Wohl aller Wissenschaften leiten, insbesondere auch das der Philosophie bei dem Publikum besorgen und befördern wollen. Obgleich das mit Recht berühmteste und durch einige in früheren Zeiten an den Tag geförderte Meisterwerke im Fach der philosophischen Kritik ausgezeichnetste derselben, die Jenaische Allgemeine Literaturzeitung, dem allgemeinen Loos menschlicher Dinge so wenig entgehen konnte, daß in der letzten Zeit, in Ansehung der"}, {"type": "paragraph", "text": "Philosophie, fast sogar das Sprüchwort an ihm wahr geworden wäre: der Krug geht so lange zu Wasser, bis er bricht, so ermangelt es doch, nachdem von ihm die weise und in der That lobenswerthe Maxime angenommen worden ist, von der Recension bedeutenderer philosophischer Werke gänzlich abzulassen, nicht, unbedeutende von Zeit zu Zeit mit einer passenden Sauce zu versehen. Zum Theil in Recensionen, zum Theil und besonders in eignen Aufsätzen gibt die Oberdeutsche, sonst auch Salzburger genannte, Literaturzeitung den Salat dazu, der, weil er ohne Salz und Pfeffer ist, von den Würzburger Gelehrten Anzeigen mit Petersilie gewürzt, von den Tübingischen aber mit einer Gabe linden Oels unschädlicher Plattheit übergossen wird, so daß das Publikum im Ganzen wenigstens immer noch auf eine Art von philosophischem Gericht rechnen kann. Zu diesen, obgleich sie abgängig geworden sind, doch noch Abgang findenden Blättern gesellt sich ein beigängiges Institut unter dem Namen eines Jahrbuchs der Literatur, das im Bewußtseyn seiner Beigängigkeit, wie billig, bescheiden ist, und sich im Ganzen bloß für ein merkantilisches Anzeigecomtoir anerkennt und ausgibt, aber durch eine gewisse Gründlichkeit auch in philosophischen Beurtheilungen mit den abgängigen noch immer die Vergleichung aushalten kann. Die Erlangische Literaturzeitung hat im philosophischen Fach sich durch mehrere Recensionen über die allgemeine edle Simplicität und Mittelmäßigkeit erhoben, ist aber dadurch stark in den Ruf gekommen, den transscendentalen Idealismus unerlaubtermaßen zu begünstigen, und überhaupt sich an die verderblichen Neuerer anzuschließen, weßhalb auch noch ganz kurz in dem Intelligenzblatt der Jenaischen Allgemeinen Literaturzeitung gegen sie, wenn nicht die Glocke angezogen, doch wenigstens eine Schelle geläutet worden ist. So groß und umfassend die Geschäftigkeit dieser Institute ist, so gibt es doch sogar einzelne Menschen, die sie durch Industrie hierin noch zu übertreffen suchen, und unter andern einen durch Natur und Fleiß ausgezeichneten Böttcher, der allein fähig ist, das ganze große Heidelberger Faß der Literatur, das sich zu jeder Messe mit so verschiedenartigen Ingredienzien füllt, mit Einem, aus Einem Stück"}, {"type": "paragraph", "text": "gearbeiteten Reif zu binden. Unendlich angenehm muß es einem großen Theil des Publikums seyn, der, ohne eben genaue und richtige Begriffe zu verlangen, gleichwohl ein allgemeines Apperçu des jedesmaligen Ertrags begehrt, und obenein noch durch die lehrreichen Gleichnisse, welche dabei von"}]}, {"page_pdf": 1503, "page_book": 168, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Thierpflanzen, Schnabelthieren und aus allen drei Reichen der Natur und Kunst hergenommen werden, eine so ziemlich vollständige Kenntniß aller naturhistorischen und anderer Merkwürdigkeiten der letzten Zeit erlangt, und da des Geträtsches im bürgerlichen Leben ohnehin nicht genug werden kann, hier noch überdieß mit Stadtgeschwätzen aus der gelehrten Welt regalirt wird. Da in Deutschland alles nachgemacht wird, so ist zu fürchten, daß, wie nach der obigen Bemerkung die Philosophie und jedes einzelne Fach der Literatur, besonders aber der Industrie, seinen Insektenschwarm herbeizieht, so sich nicht eine eigne Art großer dicker Schmeißfliegen bilde, die nicht nur auf einzelne Produkte, sondern auf das Gesammte der Literatur sich niederlassen. Eine solche Fliege hat sich noch unlängst, den Herausgebern wahrscheinlich unbemerkt, in der Meßrelation der Stuttgarter Allgemeinen Zeitung auch auf Hegels Schrift: Differenz des Fichteschen und Schellingischen Systems der Philosophie, gesetzt, und wir machen um so mehr auf sie aufmerksam, da dieß eben ein Beispiel ist, welche glaubwürdige Klatschereien und in der Sache gegründete Nachrichten das Publikum sich auf diesem Wege zu versprechen hat1. Dieß alles, was wir hier angeführt haben, obgleich es nur einige Züge davon sind, rechnen wir zu dem äußeren Zustand der Wissenschaften. Was sich von diesem auf Philosophie bezieht, werden wir in diesem Notizenblatt berühren, in der Hoffnung, besonders durch Aufmerksamkeit auf das deutsche Recensirwesen es unsern Lesern zu empfehlen. Denn wem wird es nicht angenehm seyn, die vortrefflichen Aeußerungen und philosophischen Sentiments, die unter der Menge anderer Recensionen und in den voluminösen Bänden der gelehrten"}, {"type": "footnote", "text": "1 Zu dieser Stelle war im Kritischen Journal (1. Bd., 1. Stück, S. 120) eine eigene Erklärung Hegels gegen den Verfasser der Meßrelation in einer Note beigefügt, welche hier weggelassen ist. D. H."}, {"type": "paragraph", "text": "Blätter als einzelne Perlen versteckt liegen, hier besonders aufbewahrt zu finden; wen es nicht interessiren, wenn wir, von diesen Aeußerungen aus schließend, dem neugierigen Publikum Kunde und Notiz von den eignen Grundsätzen mancher Beurtheiler und ihren philosophischen Systemen geben können, welche ohne unsere Bemühung wahrscheinlich ewig verborgen blieben, da bekanntlich die philosophischen Recensenten an kritischen Instituten, ausgenommen die Erlanger Literaturzeitung, woran ordentlich auch sonst bekannte philosophische Schriftsteller, als da sind Fichte, Steffens, Eschenmayer, Schelling u.a.m. durch Beiträge Theil genommen haben sollen, sich mit dem Schreiben und Verfassen eigner Schriften oder gar Aufstellung von Grundsätzen und Systemen in der Regel eben nicht abzugeben pflegen."}, {"type": "paragraph", "text": "2. Ein Brief von Zettel an Squenz."}, {"type": "paragraph", "text": "Ich weiß nicht, Freund, wie es kommt, aber es geht mir fast wie Ihnen1, daß ich keine zwei Gedanken im Kopf zusammenbringen kann, und ganz unberufene Vorstellungen, die mir noch überdieß höchst ungelegen sind, sich zwischen meinen Entschluß, zu denken, und die Ausführung eindrängen und die letztere im höchsten Grade beschwerlich machen2. Könnte ich Ihnen die ganz eignen Empfindungen beschreiben! Bisweilen ist es mir, als wäre ich schon gestorben; das viele Vorschwatzen von meinen Seelenwanderungen macht mich in unseligen Augenblicken oft wirklich glauben, daß ich dieselbe"}]}, {"page_pdf": 1504, "page_book": 169, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Transformation wieder erfahren, die ich schon einmal im *Sommernachtstraum*3 erlitten habe. Was in mir jetzt eben aufs neue diese Vorstellungen erregt hat, ist eine Recension der beiden ersten Hefte der *Beiträge* in dem Leipziger *Jahrbuch der neuesten Literatur* Stück 125."}, {"type": "footnote", "text": "1 Beiträge III. Stück, S. 111. 2 Beiträge daselbst, S. 112. 3 Shakespeare's dramat. Werke, übers. von A. W. Schlegel. Erster Bd. S. 221."}, {"type": "paragraph", "text": "So hat also meine treue Sorgfalt, solchen Recensionen, die unsere Sache verschreien und das Publikum dagegen stimmen könnten, durch eine eigne in der Jenaer Allgemeinen Literaturzeitung zuvorzukommen1, nicht verhindern können, daß nicht eine solche sogar in Leipzig an den Tag käme. Der Verfasser ist wiederum ein offenbares Mitglied der bewußten esoterischen Schule. Es ist mir zwar überhaupt oft verwundersam, daß, obgleich von dem neunzehnten Jahrhundert nun schon beinahe ein Jahr verflossen ist, doch eben der jüngste Tag des Idealismus und das wahre und eigentliche Ende der philosophischen Revolution, zu dem ich dem Jahrhunderte Glück gewünscht habe, noch immer nicht sich einfinden oder auch nur von ferne durch Zeichen zu erkennen geben will, so daß mir meine sämmtlichen Ermahnungen über das Subjektiviren in der Philosophie und das Herumdrehen um den Mittelpunkt der Ichheit nicht selten wie in den Brunnen gefallen vorkommen. Die Fichtisch-Schellingischen Transscendentalphilosophen, wenn sie noch recht linde sind, sehen meinen jetzigen Zustand als einen für meine Individualität nothwendigen Uebergang und etwaigen Durchbruch zum wahren Idealismus und mein provisorisches Philosophiren überhaupt nur für eine Art von Fegefeuer an, in dem ich mich jetzt herumwälzen müßte, um, wenn ich mich genug gereinigt, der intellektuellen Anschauungen ihrer Philosophie vielleicht noch theilhaftig zu werden. Ueberhaupt fange ich an zu merken, daß sie unsere Sache für gar nichts Originelles, nicht einmal für einen eignen Aufzug, sondern nur für ein schlechtes, unbedeutendes, auf meine Kosten, zur Hochzeitfeier des Theseus und der Hippolyta, aufgeführtes, sich von selbst in nichts auflösendes Zwischenspiel achten. Ich wußte nun zwar sehr wohl, daß es mit unserer Philosophie noch nicht ganz im Reinen wäre, und machte zu diesem Behuf die Erfindung des vorläufigen Philosophirens, denn, dacht' ich, kommt Zeit, kommt Rath; auch gab ich in der letzten Darstellung den Gegnern auf eine feine Weise zu verstehen, daß ich ihrer absoluten Identität des Subjektiven und Objektiven nicht so sehr abgeneigt wäre, nur daß man damit nicht gleich ins Haus fallen müßte,"}, {"type": "footnote", "text": "1 Beiträge I. Stück, S. 164."}, {"type": "paragraph", "text": "auch habe ich mir ihre hauptsächlichsten Schlagwörter so ziemlich angeeignet, und überhaupt unter der Hand verschiedene kleine Modificationen eingeschaltet, mit denen ich mich in der Folge werde ausreden können, so daß von dieser Seite nichts zu fürchten schien. Allein was das problematische Philosophiren betrifft, so ist es mir von dem D. Hegel in der bekannten Schrift sehr übel versalzt worden, so wie dieß überhaupt ein gar kategorischer Mensch ist, der die vielen Umstände mit der Philosophie nicht leiden kann, und nur so geradezu auch ohne das Appetit hat. Dabei ist es nicht leicht ihn zu lesen und zu verstehen, und er hat noch die Unart, mich mit witzigen Einfällen anzulassen, wobei ich mich gar nicht zu"}]}, {"page_pdf": 1505, "page_book": 171, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "benehmen weiß, da ich selbst außer vielen andern Lastern auch von dem des Witzes mich völlig frei weiß, höchstens, daß ich, wenn sie es mir zu arg machen, bisweilen ein wenig scurril zu seyn mich bestrebe. Ueberhaupt ist es mir eingefallen, daß die Gegner sich gar nicht auf Widerlegungen einlassen zu wollen scheinen, sondern noch immer uns bloß lächerlich machen wollen, welches ich gar nicht vertragen kann, denn ich bin ein so zärtlicher Esel, daß ich gleich kratzen muß, wenn es mich kitzelt1. Der Respekt ist völlig dahin, denn, ob ich gleich nicht gesagt habe: ich habe weder am Anfang noch in der Mitte noch selbst kurz vor dem Ende der philosophischen Revolution gewußt, *wovon eigentlich die Rede sey*, so habe ich doch gesagt, sie sey anders ausgefallen, als ich am Anfang, anders als ich in der Mitte, und wieder anders als ich gegen das Ende angekündigt und behauptet2: da ich nun mit jeder dieser Perioden das wahre Ende prophezeit und durch jede dieser Wendungen die höchste Idee der Philosophie realisirt glaubte, so muß ich entweder nicht gewußt haben, was Philosophie, oder nicht, wovon in jenen Versuchen sie zu realisiren die Rede sey, so daß es ebenso viel ist, als ob ich jenes gesagt hätte. Was aber die anderen Feinheiten betrifft, so hat der oben angeführte Recensent sogar schon im voraus darauf hingedeutet, wenn er sagt: Sonderbar genug sey mir bei meinem idealistischen Cursus eben die"}, {"type": "footnote", "text": "1 Sommernachtstraum, 4. Aufzug, 1. Scene. 2 Beiträge I. Vorrede S. III f."}, {"type": "paragraph", "text": "Forderung entgangen, daß beim Absoluten von aller Subjektivität und Objektivität zu abstrahiren sey, hieraus habe sich nun mein polemisches Princip gebildet, nach welchem ich die Bestimmungen des Absoluten, wie sie in einem reflektirenden System, dergleichen das Fichtesche, eben für die Reflexion, nothwendig sind, für dem Absoluten selbst und objektiv inhärirende Qualitäten halte. Im Allgemeinen behauptet er, daß ich das Absolute nur durch Ueberlieferung erhalten habe, und erklärt daher meine Mißverständnisse, sowie er mir auch nicht undeutlich Ignoranz Schuld gibt, indem ich das Mährchen von Spinozas Objektivismus noch immer so wie das von Fichtes Subjektivismus nachbete. Was mögen nun das für neue Händel seyn? Denn von beidem bin ich ja noch vor kurzem ganz gewiß gewesen. Es ist freilich wahr, daß, da ich die Philosophie überhaupt erst durch die Kantische kennen lernte, mir der Sinn für andere Philosophie als diese ursprünglich schon verrückt wurde, und da ich bald darauf anfing die Briefe über selbige und ein eignes System zu schreiben, so hielt ich mich auch fähig, a priori, nämlich aus meinen eignen jedesmaligen Grundsätzen heraus zu bestimmen, was andere Philosophen gedacht haben müssen, und ich gestehe, daß mir dieser Fehler noch jetzt bisweilen nachgeht. In der Fichteschen Schule, wohin ich ganz roh kam, ließen sie mich freilich merken, ich müßte eine geraume Zeit mich als bloßen Schüler betrachten, der ganz von vorne anzufangen habe, ehe ich mir beigehen ließe, selbst wieder etwas zu wissen; dieß gefiel mir nicht, und darum entlief ich bei der ersten Gelegenheit zu Ihnen, lieber Squenz. Nun suchen jene mich freilich zu bedeuten, daß ich, der es nur mit dem angestrengtesten Lernen zu etwas hätte bringen können, der Mann nicht sey, der ihre Systeme beurtheilen, noch viel weniger sie belehren könnte, was ihre Systeme seyen, oder ihnen meine eignen groben und unreinen Begriffe davon (so drücken sie sich aus) aufdringen dürfte. So bemerkt auch der Recensent (woher die Leute nur alles erfahren mögen?), daß ich Schellings Naturphilosophie, welche als zweite Grundwissenschaft der Philosophie mir das nöthige Licht über den von mir mißverstandenen transscendentalen Idealismus hätte geben können, bloß bei"}]}, {"page_pdf": 1506, "page_book": 173, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Gelegenheit der in Geschwindigkeit gemachten Anzeige seines transscendentalen Idealismus kennen gelernt, und also den Werth, welchen die momentane Sonderung beider Grundwissenschaften als solcher für die Reflexion und ihre Wiedervereinigung auf Darstellung des ächt speculativen Systems habe, nicht habe bemerken können. Fast fürchte ich, lieber Squenz, daß wir einen dummen Streich gemacht haben, unser System rationalen Realismus zu nennen. Warum haben Sie auch so geradezu gesagt, ich bin und bleibe Realist1? Das benutzen nun die Feinde, und sagen: der Rationalismus sey weder reell noch ideell, also könne auch ein Realismus nicht rational seyn, und das wäre ja das Aergste, was unserem System begegnen könnte, wenn es nicht rational wäre. Der Rationalismus, meint der Recensent, lasse sich nur denken, entweder als reflektirender, wo er vermöge der doppelten Ansicht der Reflexion transscendentaler Idealismus oder Naturphilosophie ist: oder als construirender Rationalismus, welches wohl die eigentliche Benennung für die reine und Eine, an sich weder idealistische noch realistische, Philosophie sey. Sie merken wohl, wo das hinaus will? Ganz besonders ist mir aufgefallen, daß der Recensent uns Schuld gibt, in unserer Philosophie seyen noch viel ärgere Concrescenzen und Coalitionen der Phantasie, als wir denen unserer Gegner Schuld geben. Ich weiß nicht, wie das kommt, da ich doch, Gott weiß, keine Spur von Phantasie an mir bemerken kann, vielmehr einen ganz trocknen, ja dürren Kopf habe. Das muß also auf Sie gehen, Squenz, und (lassen Sie es mich gestehen) öfters kam es mir vor, als ob Sie zwar, Gott sey Dank! keine Einbildungskraft, aber eine pferdemäßige Phantasie haben. Diese schreckliche Phantasie wird uns noch ruiniren, besonders wenn sie Ihnen noch oft solche Querstreiche macht, wie in Ihrem letzten Schreiben. Denn überhaupt habe ich bemerkt, daß die Gegner gegen Sie eine absonderliche Verachtung affektiren und von Ihnen fast nur wie von einem mauvais sujet reden. Mir wollen die Gegner nur eine Phantasie für das Schlechte zuschreiben, und der Recensent sagt unter andern: ich scheine den Aufsatz über Heautogonie"}, {"type": "footnote", "text": "1 Beiträge I, 159."}, {"type": "paragraph", "text": "zu einem Absonderungsorgan für meine polemischen Cruditäten bestimmt zu haben, und in dem über Autonomie habe sich meine Verfolgungswuth, die er mit der eines Renegaten vergleicht, sogar bis zum Pasquill gesteigert. Melden Sie mir doch mit umgehender Post, was wir unter Realität verstehen wollen, aber in unumwundenen und klaren Ausdrücken, denn der Recensent sagt, solange ich über das, was ich so nenne, mich nicht bestimmt erkläre, so lange sey alles, was ich schreibe, so gut als nicht geschrieben, welches doch wieder entsetzlich wäre. Wenn mich die Gegner nur nicht noch einmal fragen: was ich unter Anwendung des Denkens als Denkens verstehe, und wie ich mir die Einwirkung der Identität auf den Stoff denke, oder ob dieser von Gott erschaffen sey, oder nicht? Ganz unerträglich ist es doch, daß ich die Theorie des Vorstellungsvermögens immer wieder auf dem Brod essen soll; auch der Recensent bringt sie wieder in Anregung, indem er sagt: der fixe Punkt aller meiner Metamorphosen sey die eigne Elementarphilosophie, jene bestehen ohne alle Beziehung auf Vollkommenheit in einem Schwanken nach entgegengesetzten Richtungen, in deren Mitte der eigentliche wahre Zustand des sich metamorphosirenden Subjekts (da meint er wohl mich) liege, und da ich jetzt gewissermaßen die Totalität der Schwankungen von diesem Punkt aus erreicht habe, so müsse für mich, der ich mich eben auf dem Wendepunkte befinde, natürlich der Schein entstehen, als sey nunmehr die"}]}, {"page_pdf": 1507, "page_book": 174, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "philosophische Revolution vollendet, indeß für den Beobachter nur die Vermuthung übrig bliebe, daß die ganze Summe der Declinationen nur gleichsam Einen philosophischen Tag in meiner philosophischen Periode ausmache, und daß die philosophische Nadel (was mag er wohl damit meinen?) über kurz oder lang von Neuem ihre Abweichung beginnen werde. Ich kann nicht sagen, lieber Squenz, wie ganz eigen mir zu Muth wird, wenn ich mich so ganz als ein naturhistorisches Objekt betrachten und construiren sehe, und das unglückliche Wort: *Metamorphose* bringt mir wieder die alten Grillen in den Kopf. O göttliche Titania!"}, {"type": "paragraph", "text": "Was wird nun erst vollends aus Jena kommen? Mit Einem Wort, Freund, ich bin in einem fatalen Zustand, und damit ich Ihnen, liebster Squenz, alles beichte1, wenn Sie fortfahren, so saumselig zu seyn, und die bestialische Phantasie nicht bald unterkriegen, die sie durch die lebhaften Ideenassociationen verhindert, an der Begründung der philosophischen Analysis aus einem gemeinfaßlichen Standpunkte zu arbeiten2, so ist das Stück zum Henker."}, {"type": "paragraph", "text": "Ich umarme Sie."}, {"type": "paragraph", "text": "Ihr Am Ende des ersten Jahrs des neunzehnten Jahrhunderts."}, {"type": "paragraph", "text": "*Zettel, der Weber.*"}, {"type": "footnote", "text": "1 Beiträge I, S. 162. 2 Beiträge III, S. 111."}, {"type": "paragraph", "text": "3. Neue Entdeckung über die Fichtesche Philosophie."}, {"type": "footnote", "text": "(Jenaer Allg. Literatur-Zeitung, 1801, Nr. 362.)"}, {"type": "paragraph", "text": "\"Fichte dürfte wohl seine Lehre auf etwas gründen und mit etwas verbinden, was er in seiner Abhandlung (über die Religion) und in deren Vertheidigung, und in der That in allem, was er bisher unter seinem Namen über sein System bekannt gemacht hat, verbirgt. Dieses System muß *man sorgfältig studiren*, muß dem, was aus der Ableitung alles Bewußtseyns aus den Bedingungen des Selbstbewußtseyns folgt, *selbst* nachgehen, ohne auf Fichtes Leitung zu warten; dann erst erblickt man das in dem *Dunkel* des Allerheiligsten verborgene gí êár ðOí, das Fichte selbst in seinem sonnenklaren Berichte noch nicht an das Licht gezogen hat; dann erst erscheint seine Gotteslehre in ihrer Klarheit und in ihrem innigen Zusammenhang mit seinem System; und *dann erst* kann man *mit Erfolg *die* Waffen des gesunden Menschenverstandes* gegen ihn gebrauchen.\" Wir haben uns nicht enthalten können, diese Stelle als in mancherlei Rücksichten charakteristisch unserem Notizenblatt einzuverleiben; was"}]}, {"page_pdf": 1508, "page_book": 175, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "1) die neue Entdeckung über das Allerheiligste der Fichteschen Philosophie und das Licht betrifft, das in dasselbe gebracht wird, so spiegelt sich unverkennbar das *neugierige* Studium der Philosophie darin ab, das sorgfältig selbst nachgeht, nicht auf Leitung wartet, noch sich hingibt, sondern immer seiner vollkommen bewußt auf die Entdeckung losgeht, welcher von den bisher bekannten Namen denn der neuen Philosophie zu geben sey; hat ein solches Studium einen Namen herausgebracht, so glaubt es das Esoterische entdeckt zu haben, und weil der Philosoph nicht selbst einen alten Namen braucht, schließt es, er habe ein Geheimniß aus dem Wesen seiner Philosophie machen wollen, die man für sich und andere ans Licht ziehen muß; solcher Befriedigung genießt denn auch dieser Lichtzieher, den wir oben sprechen ließen, und der für das Wesen der Fichteschen Philosophie den Namen gí êár ðOí entdeckt hat. 2) Dieser Lichtzieher erweist der Fichteschen Philosophie eine unendlich größere Ehre, als er ohne Zweifel dachte und wollte; es läßt sich von einer Philosophie gar nichts Höheres sagen, als daß nichts Philosophisches, sondern nur der gemeine Menschenverstand gegen sie aufzubringen ist. 3) Ebenso ist es auch für das größte äußere Glück einer Philosophie zu erachten, wenn dasjenige, was gegen sie sich hören läßt, sich selbst für dünkellosen gemeinen Menschenverstand erkennt; denn die leidigste Seite des Kampfs einer Philosophie ist immer die, daß sie es mit gemeinem Menschenverstand zu thun hat, der sich für Philosophie hält, und es ist nichts schwieriger, als ihm jenen philosophischen Dünkel zu benehmen. 4) Der Erfolg, den die Waffen des gemeinen Menschenverstands haben, ist allerdings bei ihm unfehlbar, solang er sich nicht verführen läßt, aus seiner Gemeinheit herauszugehen; wenn er es mit der Philosophie zu thun zu haben glaubt, so hat dagegen die Philosophie nichts mit ihm zu thun."}, {"type": "paragraph", "text": "4. Ausbruch der Volksfreude über den endlichen Untergang der Philosophie."}, {"type": "footnote", "text": "(Oberd. Allg. Literatur-Zeitung, CXXXIII. 1801. Recension der Kritik der theoretischen Philosophie von Schulze. Erster"}, {"type": "footnote", "text": "Band.)"}, {"type": "paragraph", "text": "\"Es ist endlich einmal Zeit, daß den Philosophen die Decke weggenommen wird, die ihre Augen seit mehr als 2000 Jahren mit Finsterniß bedeckt hat. *Die Geduld geht nicht ins Unendliche und hat ihre bestimmten Grenzen*. Wenn die Erwartung zu lange getäuscht wird, so bricht zuletzt *unser* Unwille um so lebhafter aus (le cri de la nation!), je länger uns leere Worte und *Versprechungen* hingehalten haben. Die Philosophen haben schon lange die *Erwartung des Publikums* getäuscht, sie haben schon lange *einen ewigen Frieden* unter sich durch eine *allgemeingültige* Philosophie, durch eine Philosophie ohne Namen versprochen; und mit jedem Jahrhundert wird der Streit in der Philosophie größer; fast mit jedem Jahrzehend gehen neue Systeme der Philosophie hervor, die alle miteinander im Widerspruche stehen, und doch alle auf Allgemeingültigkeit Anspruch machen.\" Es wird hier ein Verhältniß zwischen Philosophen und einem Publikum aufgestellt, wie zwischen einer Administration und dem Volke; die Philosophen hätten das Amt der Seelsorge für die Vernunft des Volks und die Pflicht auf sich, ihm eine constitutionelle Philosophie zu machen und die Vernunft des Volks zu verwalten, welches sich darüber auf seine Philosophen sollte verlassen und seine sonstigen Geschäfte"}]}, {"page_pdf": 1509, "page_book": 177, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "darnach betreiben können; nach der Ansicht dieses Recensenten hat das Publikum eine allgemeingültige Philosophie erwartet, die ihm gegeben werden sollte; das Volk hat zweitausend Jahre vergeblich gewartet (von welcher eselhaften Geduld ist doch dieß Volk), und wenn es noch sechstausend Jahre wartet, so würde es keine Philosophie bekommen; denn das Warten verhilft eben so wenig dazu, als das Warten, bis der Acker von selbst Korn trüge und sein Brod gebacken präsentirte zur Sättigung. - Aber das so lange getäuschte Volk läßt endlich, wie wir"}, {"type": "paragraph", "text": "sehen, gegen die Administration der Vernunft seinen Unwillen losbrechen; es findet einen Mann, der als sein Messias sich an seine Spitze stellt, denn \"Herr Hofrath Schulze hat sich das *unsterbliche Verdienst* erworben, den ewigen Streit in der speculativen Philosophie zu endigen (nicht daß er die Vernunftadministration verbesserte, sondern wie ein Marat, daß er alle Systeme, die sich um die Regierung rissen, guillotinirt). Er hat gezeigt, daß die Philosophie einen Erbfehler hat, u.s.w. Er stellt daher einen Skepticismus auf, den der gewöhnliche Vorwurf nicht trifft, denn der Verfasser *erkennt die logischen Wahrheitenan*; u.s.w. Der Skepticismus des Verfassers ist einleuchtend und klar, daß wir *fest* überzeugt sind, daß *dadurch über alle Systeme der theoretischen Philosophie der Stab gebrochen ist*; daß in *unserm* neuen Jahrhundert die speculative Philosophie als eine Wissenschaft betrachtet werden wird, die als ein künstliches Gewebe von leeren Begriffen nur müßige Köpfe beschäftigen kann.\" Der Umstand ist nicht zu übersehen, daß der, der dieses Freudengeschrei erhebt, nur den ersten Theil des Schulzeschen Werks vor sich hatte, worin die philosophischen Systeme nur erzählend dargestellt werden, und den zweiten nicht, worin ihre Grundlosigkeit erst erwiesen wird, also schon über das bloße Versprechen ihrer Widerlegung seinen Jubel erhebt. Der Jubel über den Untergang der speculativen Philosophie trifft genau mit der psychologischen und moralischen Begründung und Aufführung der Philosophie zusammen, der wir hier im Vorbeigehen erwähnen müssen, wovon ein gewisser Pfarrer und Professor Salat in Schriften: über die Aufklärung, und: Winken des Verhältnisses der intellektuellen zur sittlichen Kultur, und beständigen Erklärungen und Erzählungen darüber, in der oberdeutschen allgemeinen Zeitung ein eitles und leeres Gewäsche zu machen gar nicht aufhören kann. Es scheint, dieser Herr Professor Salat hält sich eigentlich für den philosophischen Apostel Bayerns, und es hat seinem Apostelamte keine andere Bestätigung mehr gefehlt als die wohlfeile Märtyrerkrone, welche ihm seine geistlichen Obern bereitet haben; für das ursprüngliche Diplom zu seinem hohen Berufe, der Ritter gegen die Finsterniß zu werden,"}, {"type": "paragraph", "text": "aber scheint er den Umstand zu halten, daß ins philosophische Journal einmal ein seichter und unphilosophischer Aufsatz, der ihn zum Urheber hatte, aufgenommen wurde; es erscheint keine seiner vielen geschwätzigen Erzählungen von sich und seiner moralischen Philosophie, worin er nicht dieser Ehre, einen Aufsatz im philosophischen Journal gehabt zu haben, erwähnte, und keine Woche der oberdeutschen Zeitung, worin er nicht ein solches eitles Auskramen der Humanität und Moralität und praktischen Philosophie und alles Guten und Wahren und des Vorwärts zum Bessern und Vervollkommnung darbrächte. Das Kantische Moralprincip ist gerade die lahme Mähre, die sich in diese Schwemme schaler moralischer Brühen hineinreiten läßt; der Fichteschen Philosophie traut er nicht recht, denn man kann nicht wissen, ob diese nicht Mücken \"aus dem dunkeln Lande des Mysticismus\" im Kopf habe, so viel wenigstens ist sicher, daß sie gar speculative Philosophie ist; vor deren einem wie vor dem andern Salat und seine moralische und humane Philosophie gleicherweise bange hat; und das eine oder"}]}, {"page_pdf": 1510, "page_book": 179, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "das andere wäre doch Gewürz, das ihrer Geschmacklosigkeit allein nachhelfen könnte. Wie müssen der bayerischen Gediegenheit solche moralische Saalbadereien und asthenische Saläte anekeln, durch welche diesem Bayern die berlinische Aufklärerei in ihrer plattesten Gestalt als eine moralische und humane Aufklärung zugewinkt und eingepfropft werden soll; Salat nennt das, auf eine empirische, das heiße praktische, Weise das Wahre und vorzüglich Wichtige der neuern Philosophie in den Kreis eines feineren und selbstdenkenderen Publikums einführen; wenn das selbstdenkende bayerische Publikum aus dem Salatschen Einführen einen Begriff von der neuern Philosophie erhalten müßte, so müßte es sich wundern, wie unter dem selbstdenkenden Publikum des übrigen Deutschlands räsonnirende Eitelkeit und humane Mattheit für Philosophie gehalten werden könnte, und ihr billig seine unphilosophische Derbheit vorziehen, welche Salat und Consorten breit und platt zu schlagen sich bemühen. Es fällt uns, nachdem das Vorherige schon abgesetzt ist, ein neuer Salat in der oberd. allg. Liter. Z. XVIII. ff. 1802 in die Hand, worin jene praktische und moralische Tendenz des Philosophirens, welches"}, {"type": "paragraph", "text": "der oben angeführte Prophet der Plattheit und Seichtigkeit in Bayern übt, und das Verhältniß, das sie sich zur Philosophie gibt, aufs naivste ausgedrückt ist, und wovon wir uns nicht enthalten können einiges beizubringen, um die Züge dieses moralischen Philosophirens zu vervollständigen. Es ergibt sich nämlich daraus, daß dieses Philosophiren seine Forderung der Moralität, als des einzigen tiefen Grundes der Philosophie, darum macht, um alles Philosophirens überhoben zu seyn, statt desselben moralische Eitelkeit und Dünkel geltend zu machen, und zur Kritik philosophischer Systeme das einfache und schlechte Hausmittel gebraucht, ihre Urheber und Anhänger aus eigner moralischer Urtheilskraft zu unmoralischen Menschen zu creiren. Der Geist, nur nicht der Buchstabe, ist Salats Geschrei, der Geist, der Geist, nicht die Formeln, nicht ein bestimmter Begriff, auf das innere, tiefe Wahre und Urwahre, auf den moralischen Geist kommt es an; sein ermunternder Ausruf und moralischer Rippenstoß: *Immer vorwärts* zum Besseren, Vollkommneren! In Ansehung des Theoretischen geht ihm nichts über die *schöne philosophische Nüchternheit* in Ansehung der Begriffe, des Wissens, der Theorien, Systeme u.s.w., auch die intellektuelle Bildung und der reinere Begriff ist von großem Belange u.s.w. - In solches Treiben und Aufrufen und Winken setzt er das Philosophiren; er verkennt den Werth der Theorien, Systeme, sofern sie aus der Kraft des Intellektuellen kommen und vornämlich in der Schule oder nach ihrem Maßstabe gebaut werden, keineswegs, er erkennt vielmehr die Nothwendigkeit und den entschiedenen * Nutzen* derselben, unmittelbar *für den studirenden Jüngling* und mittelbar fürs Ganze. - Ein solches eitles Saalbadern ins Allgemeine hinein muß man für das halten, was Salat den Geist nennt, das Geistigste aber ist ihm das *Winken*, denn im Winken ist am wenigsten Buchstabe. Die intellektuelle Kultur ist ihm von großem Belang, aber weil der Geist alles ist, so erklärt er, daß es auf mehr oder weniger unreine scientifische Begriffe nicht ankomme, der bloße Systematiker aber sehe zuvörderst auf den Buchstaben, nicht auf den edleren Geist; die Systeme gehen aus dem intellektuellen Vermögen hervor, aber es komme darauf an, welch ein Geist"}, {"type": "paragraph", "text": "sie bewohne; intellektuelles Vermögen und Geist sind Salat zweierlei Dinge. Welche Kraft er diesem intellektuellen Vermögen zutraut, bestimmt sich dadurch, daß ihm der denkende Geist 1) nicht nur von außen abhängig ist, sondern auch 2) als Menschengeist in sich selbst beschränkt; 3) alsdann ist auch die Philosophie nicht allein durch den moralischen Zustand jedes Einzelnen bedingt (denn frei ist des Menschen Wille!), sondern auch 4) bald mehr bald weniger von den äußern Umgebungen und folglich"}]}, {"page_pdf": 1511, "page_book": 181, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "selbst von der Kraft des Mechanismus abhängig. - Kurz man muß auch in dem Salatschen Gewäsche Geist und Buchstaben absondern; zum Buchstaben desselben gehört, daß ihm das intellektuelle Vermögen vom Belange ist, der Geist aber, der über diesem moralischen Wasser schwebt, ist die platteste Verachtung desselben; eine Verachtung, die ihre Verächtlichkeit mit dem moralischen Mantel des Besseren und Vollkommneren zudeckt und unter dieser Haut hervor ungescheut ihre ungezähmte Eitelkeit zur Tugend decretirt und die Unwissenheit (die Salat in dieser *Kritik* einer Geschichte der philosophischen Systeme, aus welcher wir diese Brocken nehmen, verräth) nicht nur nicht zu verbergen sucht, sondern eher groß damit thut, so wie dieß moralische Fell sich zur gemeinsten Unverschämtheit berechtigt glaubt; es ist nöthig, heißt es, auf das Wesen der Philosophie, sofern es sich in dem schönen Verbande zwischen Beispiel und Lehre offenbart, besonders hinzuweisen, zumal da *kürzlich* in der neuesten Schule des *Idealismus* glänzende Sophisten aufstanden, die *praktisch* zwischen *Wissenschaft* und *Leben eine weite Kluft* statuiren; - was heißt dieß praktische Statuiren anders, als daß die Sophisten des neuesten Idealismus unmoralische Menschen seyen; das läßt sich Salat von seinem Geiste sagen, der nur den Geist wittert und über den Buchstaben, was bei Salat so viel als sie Wissenschaft selbst heißt, weggeht. Wenn die moralische Plattheit ohne Eitelkeit ist, so könnte sie sich selbst genügen; aber wenn sie davon angesteckt ihr großes Wort und Urtheil über Philosophie mitsprechen zu müssen meint, so bleibt ihrer Unfähigkeit, zu den Regionen einer intellektuellen Welt aufzusteigen, nur die überall sich aufdringende moralische"}, {"type": "paragraph", "text": "Suffisance dagegen. Was sich Salat von der neuen ästhetisch-philosophischen Schule oder der neuen Sophistik, wie er es nennt, aufgemerkt und in seinem Kopfe überallher zusammengerührt hat, ist, daß das *Moralische* und *Physische* hier nicht mehr wesentlich unterschieden seyen, aber die *Schönheit* sey das Höchste (also nicht bloß Abbild oder Widerschein der *Sittlichkeit* in der Sinnenwelt), und die Religion sey die Poesie der Philosophie!! Daß, setzt Salat hinzu, eine solche Sophistik zur *Befriedigung* sowohl als zur *Beschönigung * der *Leidenden* in dieser *empirischen* Welt trefflich tauge, das versteht sich - und das wissenschaftliche Urtheil lautet dahin: das System dieser philosophirenden Schöngeister (darunter scheint nämlich dieser Schwätzer, der sich besonders einbildet gut schreiben zu können, *was*, wie er sagt, *bei einem Katholiken noch immer etwas Seltenes ist*, sammt und sonders alle zu begreifen, denen seine Fatuität nichts abgewinnen kann, das sie sich anzueignen vermöchte) ist *übrigens* bloßer Naturalismus, mit theoretischen (logischen und metaphysischen) Formeln künstlich eingefaßt und geschminkt mit den Farben der Aesthetik. - So urtheilt über die wissenschaftliche Seite der neueren Philosophie dieser feine moralische Mann mit einem \"übrigens\" so im Vorbeigehen ab; den Hauptaccent legt der unwissende Dünkel aber auf die Befriedigung und Beschönigung der Leidenschaften in dieser empirischen Welt. - Mit Einem Worte, seit die Geistlosigkeit und Gemeinheit sich gesunden Menschenverstand und Moralität zu nennen angemaßt hat, so setzt sie ihrer eignen Nichtswürdigkeit und Unverschämtheit keine Grenzen mehr, und man kann nicht umhin, diese Moralitätshaut für das Schlechteste zu halten, worein sich noch die eitle Unwissenheit gehüllt hat."}, {"type": "paragraph", "text": "5. *[Philosophische Rezensionen in den Göttingischen Gelehrten Anzeigen.]*"}, {"type": "paragraph", "text": "a. Aufnahme, welche die durchaus praktische Philosophie in Göttingen gefunden hat."}]}, {"page_pdf": 1512, "page_book": 182, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Wir machten uns oben, in der Anzeige der Rückert- und Weißischen Schriften, anheischig, eine Anzahl Philosophen namhaft zu machen, mit"}, {"type": "paragraph", "text": "deren Philosophie es gerade ebenso beschaffen wäre wie mit der der beiden angeführten Verfasser. Nachdem obige Anzeige schon abgedruckt war, lesen wir eine Beurtheilung dieser Philosophie, welche nicht zunächst auf den Verstand wirkt, in den Göttingischen gelehrten Anzeigen, woraus wir folgende Stellen auszuheben uns nun veranlaßt sehen. \"Die Verfasser der Schriften, die wir hier anzeigen, scheinen noch ganz kürzlich dem *idealistischen Dogmatismus des* Herrn Fichte und seiner Mitstreiter angehangen, und als ihnen *auf die Länge* bei dieser Philosophie *nicht wohl wurde*, sich nach einer andern umgesehen zu haben.\" Nach welcher andern, als der, welche schon früher in Göttingen aufgegangen, auch meinte, daß nach ihr den Philosophen nun nichts mehr übrig bliebe, als *zur Heimath der Mutter Natur* zurückzukehren. \"Herr Rückert zwar neigt sich noch mit einer Art von *Heimweh* zu den idealistischen Speculationen. Herr Weiß dagegen lehrt entschiedenen Anti-Fichtianismus\"; er ist daher auch der wahre Liebling dieses Recensenten; in seiner Abhandlung sind recht viele vortreffliche Gedanken, *die auch Recensent gern unterschreibt*, Recensent kann dagegen um so weniger disputiren, da er ungefähr *dieselben* Resultate, *besonders so, wie sie Herr Weiß ausdrückt*, auf ganz andern Wegen *am Ende* (ja wohl am Ende; wenn etwas, das keinen Anfang hat, ein Ende haben könnte) *seines* Speculirens gewonnen hat, \"die Einsicht als etwas Theoretisches ist in dem Menschen (Recensent bringt hier die Verbesserung bei: in der Vernunft) gar nicht das Höchste u.s.w., die Richtung unseres Geistes ist praktisch, selbst die Wissenschaft, wenn sie in Ehren bleiben soll u.s.w. - durch die Ich-Wissenschaftslehre wird das Heiligste und Beste verdreht, die wahre Thätigkeit ist ein Bestreben aus sich heraus.\" Was es mit dem *Bestreben aus sich heraus* dieses Recensenten für eine Bewandtniß habe, werden wir vielleicht bei anderer Gelegenheit kennen lernen. Es verdient aber doch, da dieser Recensent insbesondere von Fichte in dem ungescheutesten Tone einer aufs höchste erbitterten Arroganz spricht (z.B. \"Recensent hat die (obigen) Stellen"}, {"type": "paragraph", "text": "um so lieber abgeschrieben, da er in ihnen besonders den guten Geist der Verfasser erkennt, der denn aber, wenn nach Herrn Rückert der gute Geist *dem Herrn Fichte* eigenthümlich einwohnt, nothwendig ein *böser Geist* heißen muß\" u.s.f.), es verdient, sage ich, in dieser Rücksicht bemerkt zu werden, daß dieser Recensent, der eine solche Sprache führt, gleichwohl ohne die Wissenschaftslehre noch vielleicht bis diesen Augenblick bei Kants Kritik stehen, sie commentiren und das kritische Stroh mit seinen verwelkten ästhetischen und schöngeisterischen Blümchen aufzuschmücken suchen würde, - und daß eben dieser Idealismus, der das Beste verdreht, und dieser Dogmatismus es ist, der dem vermeinten Skepticismus dieses Recensenten - man kann nicht sagen: auf die Beine geholfen hat, da er in jeder Rücksicht lahm ist - aber doch wenigstens so viel Herz gegeben hat, auch die Kantische Krücke wegzuwerfen und sich ganz paralytisch zu bekennen, welches denn doch, wie wir denken, kein geringer Dienst ist, da es immer besser ist, die absolute Negativität zu gestehen, als sie auf eine schlechte Weise zu verbergen."}]}, {"page_pdf": 1513, "page_book": 184, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "b. Ansicht des Idealismus daselbst."}, {"type": "paragraph", "text": "In denselbigen Göttingischen Anzeigen hat wahrscheinlich derselbe Recensent auch von einigen im vorigen Jahr zu Bamberg vertheidigten philosophischen Inaugural-Thesen Notiz genommen, welche, wie wir hören, auch in den Reichsanzeiger eingerückt worden sind. Daß der Reichsanzeiger sein Publikum damit zu belustigen meint, ist billig; daß aber gelehrte Anzeigen, die unter der Aufsicht der königlichen Societät der Wissenschaften herausgegeben werden, sich dazu herabgelassen, beweist an dieser königlichen Societät eine ganz besondere gute Laune. Aller Ernst des Unterrichts kann in einem Zeitalter, wo der Dilettantismus so besondern Beifall findet und in allen Fächern so viele Beispiele vor sich hat, nicht verhindern, daß er nicht auch in der Philosophie sich versuchte. Wo aber die Lehrer schon Dilettanten sind, oder nicht einmal dieß, sondern zu ihrer Qual Philosophie treiben und lehren, ist man freilich sicher, daß sich der Dilettantismus auch nicht einmal nach unten verbreite."}, {"type": "paragraph", "text": "- Was übrigens dieser Recensent sich untersteht zu sagen: daß die Sätze, welche er dort ausgezogen hat, *im System des transscendentalen Idealismus* heilige Wahrheiten seyn sollen, leide keinen Zweifel, ist eine zu abgeschmackte und platte Lüge, als daß wir etwas anderes dagegen nöthig fänden, als ermeldte königliche Societät auf diesen Mitarbeiter aufmerksam zu machen, dessen böse Laune gegen die Philosophie auch die gute der Societät verdächtig machen könnte."}, {"type": "paragraph", "text": "6. Notiz von Herrn *Villers* Versuchen, die Kantische Philosophie in Frankreich"}, {"type": "paragraph", "text": "einzuführen."}, {"type": "paragraph", "text": "*1. Philosophie de Kant.* Ou Principes fondamentaux de la philosophie transcendentale. Par *Charles Villers*, de la société Royale de Gottingue. Παντων χρηματων μετρον ανθρωπος. *Protag. ap. Plat.* A Metz chèz Colignon. 1801. (An IX.) *2. Philosophie de Kant.* Aperçu rapide des bases et de la direction de cette Philosophie par le même. *3. Kant jugé par l'Institut* et observations sur ce jugement. Par un disciple de Kant. A Paris chèz Henrichs. An X."}, {"type": "paragraph", "text": "Wenn wir mit diesen Versuchen, die Kantische Philosophie nach Frankreich zu verpflanzen, uns auf die bloße Notiz beschränken, so ist es, weil sie, als solche schon, dem Plan dieses Journals gemäß, unter die auswärtigen Angelegenheiten gehören; ob und inwiefern sie auch in anderer Rücksicht der Philosophie fremd sey'n, wird sich aus dem Folgenden ergeben. Dem Verfasser der Philosophie de Kant scheint vorläufig gar kein Zweifel darüber aufgestiegen zu seyn, ob diese Philosophie, die er für seine Nation darstellen wollte, überhaupt zur Universalität geeignet und nicht bloß auf eine temporäre und lokale Kultur berechnet sey, in deren Zusammenhang sie allein"}]}, {"page_pdf": 1514, "page_book": 185, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "verständlich seyn kann. Wo hätten"}, {"type": "paragraph", "text": "auch die Entscheidungsgründe dieser Frage herkommen sollen? Da nun wir dagegen stark zweifeln, ob nicht die Kantische Philosophie überhaupt ein Provincialismus oder wenigstens Germanismus sey, so befinden wir uns gegenüber von diesem Unternehmen in dem besondern Verhältniß, daß wir geradezu den ganzen Versuch nicht gut heißen können, der, da er die Kritik in der Philosophie darstellen soll, billig selbst mit Kritik hätte angestellt werden sollen. Es wäre eine Kritik über die Kritik erforderlich gewesen, um die Frage zu beantworten: welche Elemente der Kantischen Philosophie eignen sich dazu aus der besondern und nationalen Kultur der Deutschen in die allgemeine aufgenommen zu werden, und die französische Nation, deren Kultur die der andern mehr oder weniger gebieterisch bestimmt und bis jetzt am meisten den Charakter der Allgemeinheit sich zu geben gewußt hat, konnte hier zum bestimmtesten Maßstab dienen. Zu diesem Ende mußte der Darsteller selbst der darzustellenden Sache weniger subordinirt seyn und vorläufig sie selbst in einem größeren und universelleren Sinn aufgefaßt haben. Die äußeren Umgebungen, Einleitungen und Zubereitungen, wodurch die Kantische Philosophie an die französische Kultur angeschlossen werden soll, dienen dazu nicht, wenn es in dem Kern der Sache an der Originalität und der Freiheit der Auffassung fehlt, die den gegebenen Stoff zu einem unabhängigen selbständigen Ganzen gestaltet. Denjenigen, welche zuvörderst unserer Behauptung widersprechen wollten, daß die Kantische Philosophie, wie sie ist, keiner Universalität fähig sey, wollen wir nur mit einigen Gründen für dieselbe dienen. Schon die Sprache, in der diese Philosophie von ihrem Urheber vorgetragen worden ist, ist kein unwichtiges Moment in dieser Beurtheilung, da es sich offenbar genug gezeigt hat, daß die Sprache hier von der Sache unzertrennlich ist, daß, um nach Kant zu philosophiren, man auch wie Kant sprechen muß, und jeder Versuch, den Buchstaben zu verlassen, gleich auch unmittelbar über die schmalen Grenzen desjenigen, was man seine Philosophie nennen kann, hinausführt, wie denn Kant alle Nachfolgenden auf den klaren Buchstaben seiner Schriften"}, {"type": "paragraph", "text": "angewiesen hat, die eigentlichen Kantianer sich jederzeit gehütet haben, auch nur in den Worten und der äußern Form sich von dem Meister zu entfernen, und auch der Hr. Villers bei seinem Bestreben, den Franzosen die rein Kantische Philosophie zu inoculiren, sich in Ansehung alles Wesentlichen an den reinen Buchstaben zu halten gut gefunden hat. Schon diese Identität des Geistes und des Buchstabens, diese Unmöglichkeit, die individuelle Form des Urhebers, die er sich aus dem Nachlaß der Scholastik und einiger spätern Schulen gebildet, zu verlassen und das Wesen zu behalten - läßt über die Universalität des Geistes und innern Sinns der Lehre selbst, so wie sie ist, kein günstiges Vorurtheil fassen. Man kann es nicht gerade Kant beimessen, daß er selbst in Deutschland bei seiner ersten Erscheinung den Philosophen von Profession mehr oder weniger unverständlich war; man mußte in die Geschichte einiger früheren, schon wieder ausgestorbenen Philosophien und sogar Particularschulen zurückgehen, um auch nur in seiner Sprache alle Beziehungen zu verstehen, die er recht künstlich darein verwoben hatte; aber wenn dieß am grünen Holz geschehen ist, was soll am dürren werden? Wenn schon in Deutschland die Kantische Kritik unter den damals geltenden Philosophen die totalste Verwirrung"}]}, {"page_pdf": 1515, "page_book": 187, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "anrichtete, weil diese die Gründe und den Ursprung ihrer eignen Philosophie großentheils vergessen hatten, auf die sich jene (die Kritik) bezog, wie soll man es in Frankreich anfangen, einen längst vergangenen Zustand der Philosophie, der dort nicht einmal je Wurzel gefaßt hat, nur erst wieder ins Gedächtniß zurückzurufen, um einen Ausgang- und Anfangspunkt auch nur des historischen Verstehens der Kantischen Particularitäten zu erhalten? Es läßt sich historisch beweisen, daß Kant die Philosophie in ihren großen und allgemeinen Formen selbst nie studirt hatte, daß ihm Plato, Spinoza, Leibniz selbst nie anders als durch das Medium einer gewissen vor ungefähr 50 Jahren auf deutschen Universitäten gangbaren - sich durch mehrere Mittelglieder von *Wolf* herschreibenden Schulmetaphysik bekannt geworden waren. Auf dieselbe - nicht Leibnizische, nicht"}, {"type": "paragraph", "text": "einmal rein Wolfische - Metaphysik, die er für die einzige nahm, die je existirt hätte oder überhaupt existiren könnte, ist fast seine ganze Kritik, sind seine hauptsächlichsten kritischen Pfeile eigentlich gemünzt. Das Werk eines Geistes, der, anstatt aus freier Produktion die Idee der Philosophie in sich selbst zu erzeugen, aus der nächsten Hand nimmt, was ihm als solche angeboten wird, und *dieses* nun, ohne je zum Urbild selbst durchzudringen, zum Gegenstand seines Zweifelns und eines - je durch das Privativste, was es eben gibt, wie den Humeschen sogenannten Skepticismus, erregten und unterhaltenen - Kritisirens macht, und auf diesem Weg - theilweise und atomistisch, ohne daß die Idee des Ganzen den Theilen vorangegangen wäre - zu einer Kritik des gesammten Erkenntnißvermögens gelangt - das Werk eines solchen Geistes nach allen seinen Elementen und Beziehungen auf eine allgemein ansprechende Weise darzulegen, halten wir für nahezu unmöglich und für eine, wenigstens einem Talent wie dem des Hrn. Villers, nicht lösbare Aufgabe. Man kann nicht anführen, daß Kant durch den besseren Antrieb seines Geistes dennoch nicht selten bis in die Regionen der absoluten und allgemeinsten Speculation fortgeführt wird: die Beschränktheit des ersten Anstoßes verwindet er deßhalb in keiner seiner Ideen, alles bleibt doch der ersten Beziehung untergeordnet, und Aeußerungen der wahren Speculation, wo sie auch zum absoluten Durchbruch kommen, können sich bei ihm bloß als Naivetäten aussprechen, für welche buchstäbliche Commentatoren gerade keinen Sinn haben. Daß innerhalb des Kreises, worein er durch die Art, wie er zur Philosophie gekommen, versetzt ist, sein Geist doch unaufhaltsam zur wissenschaftlichen Totalität fortgeht, kann wohl das Urtheil über seine Individualität und die hohe Achtung, welche diese verdient, aber nicht über seine Philosophie verändern. Diese bleibt, wie sie ist, immer ein abhängiges Produkt, kein frei aus sich selbst entsprungenes Gewächs; seine Philosophie ist ein Gebäude, das, wenn man viel sagt, auf der empirischen Erde und zum Theil auf dem Schutt vergessener Systeme ruht, kein Weltsystem, das sich selbst trägt und hält."}, {"type": "paragraph", "text": "Es sind nur zwei Fälle: entweder will man die Kantische Philosophie als Kantische darstellen, so muß man, da sie in der Erscheinung, die sie sich selbst gegeben, nicht universell ist, auch auf eine solche Darstellung derselben Verzicht thun; oder man beabsichtigt eine solche, so muß man in der Kantischen Philosophie nicht das *Kantische*, sondern nur die *Philosophie* darstellen; das Letzte mußte offenbar Zweck des Verfassers seyn, er muß also auch darnach beurtheilt werden. Wer in Kant die Philosophie darstellen will, muß zuvor die Zufälligkeiten der Form und der"}]}, {"page_pdf": 1516, "page_book": 189, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Persönlichkeit von dem Bleibenden und Wesentlichen gesondert haben (was die alles scheidende Zeit doch, nur später, thut) und zu dem Darzustellenden durchaus in dem Verhältniß sich befinden, welches Kant selbst als ein mögliches anerkennt, *ihn nämlich wirklich besser zu verstehen, als er sich selbst verstand* (Kritik der reinen Vernunft S. 370). Es ist mit diesem Verfahren nicht gesetzt, wie sich manche vorstellen möchten, daß das Original historisch entstellt werde: denn wenn der Fall im Allgemeinen möglich, im Einzelnen wirklich ist, daß der Darstellende den Darzustellenden besser als dieser sich selbst versteht, so würde er ihn ja vielmehr historisch unrichtig darstellen, wenn er nicht seinem besseren Verstehen in Ansehung seiner folgte, und ihn darstellte, wie er wahrhaft ist, nicht wie er sich selbst erschien und sich aussprach. Die Wahrheit würde hier darin bestehen, ihn gleich von den ihm noch anklebenden Beschränktheiten, die dem Darstellenden leichter zu überwinden waren, zu befreien, und an die Stelle der untergeordneten und einseitigen Tendenz gleich die absolute und centrale, die in seinem Geist unentwickelt und bewußtlos gelegen hatte, zu setzen. Das wirklich Historische in einer jeden besondern Form der Philosophie ist doch nur das, was von ihr reell in die Geschichte eingreift und auch wieder historisch wirkt; (es versteht sich, daß temporäre und kurze Wirkungen, wie sie unmittelbar auf die Erscheinung folgen, nicht in Anschlag kommen können). Welches ist diejenige Form, in der die Kantische Philosophie fortwirken, in welcher sie einen der merkwürdigsten Uebergangs- oder Wendepunkte"}, {"type": "paragraph", "text": "in der Geschichte der Philosophie bezeichnen wird? - Ohne Zweifel ist es diese Frage, auf deren Beantwortung es vorzüglich ankommt. Kants Kritik der Vernunft (und diese muß hier hauptsächlich in Betracht gezogen werden) begreift nur Eine Sphäre der Philosophie, die der Reflexion; er hat statt einer Kritik der Vernunft nur eine Kritik des Verstandes und in dieser auch der Verstandes-Vernunft geliefert. Dieß sind Behauptungen, von denen der Beweis theils anderwärts gegeben worden, theils jedem, der ihn verlangt, gegeben werden kann1. Es folgt nach einem ganz einfachen Schluß, daß eine Philosophie, die bloß die Formen der Reflexion, also des Nichtursprünglichen, Abgebildeten, zum Gegenstand hat, je mehr in ihr der Geist wahrer Speculation durchscheint, desto weniger zum *An-sich* und also auch zur Philosophie, die auf dieses gerichtet ist, ein anderes als negatives Verhältniß haben könne. Allein absolute Negation ist eben darum, weil sie dieß ist und an sich wieder absolute Position, z.B. absolutes Verneinen des Reflektirten ist absolutes Setzen des Nicht-reflektirten und darum vollendeter Skepticismus, der seinen wahren Gegensatz nur im Dogmatismus hat (derjenigen Art zu philosophiren, welche durch die Formen der bloßen Reflexion, wie das Gesetz der Ursache und der Wirkung das An-sich zu bestimmen versucht) - die vollendete Philosophie selbst, nur in ihrem negativen Ausdruck, sowie diese in ihrem positiven Ausdruck nichts anderes als ein Setzen des der Reflexion Widersprechenden, nämlich des Absoluten, ist. Es gibt keine andere Philosophie als rein kategorische, es gibt keinen philosophischen Skepticismus, der zweifelhaft ist, ob er zweifele, auch die Philosophie in ihrem negativen Ausdruck ist in diesem kategorisch. Unphilosophie wird sie nur in den beiden Fällen, entweder, wenn sie *innerhalb* ihrer Negativität *diese selbst* wieder positiv macht, wie z.B. wenn aus dem Satz: daß die Formen der Subjektivität, wie die Kategorien bei Kant sind, das *An-sich* nicht bestimmen, der positive Satz wird, daß sie als subjektive Formen das *Bewirkende*"}, {"type": "footnote", "text": "1 Vergl. die Abhandlung über Höyer, oben S. 135, und Methode des akademischen Studiums, S. 129 (Orig.). D. H."}]}, {"page_pdf": 1517, "page_book": 190, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der erscheinenden Dinge seyen, also das Causalgesetz, das selbst nur für das *Reflektirte* gelten soll, wieder zur Erklärung von diesem gebraucht wird: oder, wenn die Negation der Reflexionsformen sich selbst nur unvollkommen und halb ausspricht. Das Letzte ist nun nothwendig der Fall, wo sich die negative Philosophie nur für *Kritik* gibt; denn es ist schon eine Halbheit, gegen den Dogmatismus nur kritisch, nicht absolut verwerfend zu verfahren, und wir gestehen gern, wenn dieß ein Lob ist, daß wir diese Halbheit nirgends vollkommener als in dem Werk des Herrn Villers dargestellt gesehen haben. Die universelle Seite der Kantischen Kritik, diejenige, wodurch sie in der Geschichte bleiben wird, ist: daß sie die Nichtigkeit der subjektiven Formen in der Beziehung auf das An-sich *allgemein und systematisch* dargethan hat; auf die Kritik der reinen Vernunft wird der Denker auch in den künftigen Zeiten als ein unschätzbares Document gegen den Dogmatismus hinweisen und ihr verdanken, daß er ungestört von den widersinnigen Anmaßungen desselben in seiner Wissenschaft ebenso ruhig als der Geometer in der seinigen wohnen wird. Um *diese* Seite der Kritik und demnach sie selbst in allgemeiner Form - frei von der Beschränkung, die sie in dem Urheber einerseits zur bloßen *Kritik*, andererseits in allem, was sie Positives innerhalb ihrer Negativität auf die Bahn zu bringen sucht, selbst zu einer Art des Dogmatismus macht - darzustellen, müßte sie als *absoluter und kategorischer Skepticismus*, also als Philosophie in der *rein negativen* Form dargestellt werden, und diese Form war auch die einzige, welche kräftig auf eine Nation wirken konnte, die für das Negative in der Wissenschaft durchaus empfänglicher als für das Positive, diesem Geistescharakter so viel Richtigkeit des Sinns verdankt, um etwas, das, wie die vom Hrn. Villers dargestellte Kantische Philosophie, ihr weder von der einen Seite mit der Präcision der Mathematik, noch von der andern, da es ihr - bei dieser Beschaffenheit - doch wieder nur als Empirismus erscheinen kann, mit der Klarheit einer Erfahrungsansicht sich darstellt, lieber gänzlich von sich abzuhalten - auf eine Nation, die bei dieser langen"}, {"type": "paragraph", "text": "und gänzlichen Entfernung von der Philosophie, auch in Ansehung der Wissenschaft nur durch Zerstörung und Zertrümmerung der bisher gewohnten Formen des Wissens - die ein universellerer, von deutschem Mark gründlicher genährter Geist leicht selbst bis in die einzelnen Zweige ihres vermeinten Wissens fortzusetzen vermocht hätte - zur Regeneration übergehen zu können scheint. Um die Punkte, an welche sich dieser absolute Skepticismus vorzüglich hätte heften müssen, brauchte man nicht verlegen zu seyn: als solche bieten sich für Frankreich auf der einen Seite der Dogmatismus, in den sich die religiösen Vorstellungen allgemein verwandelt haben, und der dadurch, wie durch die Streiche, welche die sogenannte französische Philosophie gegen ihn, als Religion, geführt hat, Popularität genug erlangt hat, auf der andern Seite der Empirismus an, der in Frankreich in aller Menschen Mund und durch die Bemühungen der französischen Philosophen für die Welt zum allgemeinen Denksystem der Nation geworden ist. Hr. Villers hat sich des Gegensatzes von Dogmatismus und Empirismus bedient, seine Darstellung einzuleiten, und um nachher den kritischen oder transscendentalen Gesichtspunkt gleichsam als ein Mittleres zwischen beiden vorzustellen, wodurch also, wie sich ferner noch deutlicher ergeben wird, am Ende jeder von beiden eine Art von Recht behält. Da es der ersten Grundlage gänzlich an der Idee der Philosophie fehlt, so kann auch der Begriff des Dogmatismus nur schwankend bestimmt seyn, und es ist ganz begreiflich, wenn dem Verfasser auch die Idee der wahren Philosophie unter diese Rubrik fällt und (wie in dem Abschnitt, der die principales *opinions* en metaphysique aufzählt, zu finden ist) der"}]}, {"page_pdf": 1518, "page_book": 192, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Rationalismus in der Bedeutung von Dogmatismus für ihn Folgendes alles unter sich begreift: Naturalisme, Egoisme, Dualisme, Idéalisme und Réalisme, Theosophisme, Harmonie préétablie, idées innées de Platon, de Descartes, de Leibniz. Daß bei dieser Verwirrung aller Begriffe der Verfasser kein sonderliches Herz gegen den Dogmatismus haben konnte und viel säuberlicher mit ihm verfuhr als mit dem Empirismus, macht seinem eignen Bewußtseyn Ehre; eine besonders rühmliche Bescheidenheit"}, {"type": "paragraph", "text": "aber zeigt sich darin, daß - nachdem er S. 20 es als den Gipfel des Dogmatismus angegeben hat: de nier l'existence et la necessité d'une *agent* entre le *moi* et la * nature*, de faire cesser cette antithèse et de dire: *Le moi et la nature ne sont qu'un, ils ne forment qu'un seul et même être* u.s.w. - er doch S.85 es ist mit dem neueren Idealismus wieder gut und dahingestellt seyn lassen will, indem er sich mit der Anmerkung aus der Sache zieht: *Ce n'est pas encore le lieu de parler *du plus hardi et du plus conséquent des idéalistes, du celèbre *Fichte*, und nur S. 237 in einer Note das Urtheil versteckt, daß der neueste Idealismus eine metaphysique transcendante sey. Die Art übrigens, wie das Ich in der Natur und die Natur im Ich seyn solle, wird auf die ganz rohe Art genommen, daß in dem ersten Fall die Natur in ihrer ganzen empirischen Realität bleibe (cette doctrine a l'avantage, de laisser la réalité la plus absolue à *tous les objets qui nous affectent!* etc.), in dem andern das Ich wiederum als eine *empirische* Realität die Welt in sich begreift, und diese Lehre als Egoismus vorgestellt wird. Auf gleiche Weise verräth sich S. 83. 90 das gemeinste Verstehen des Spinoza, Plato u.s.w. Also: von Seiten des Dogmatismus mangelhafte und verworrene Begriffe, in denen an sich ganz verschiedene Lehren unordentlich, ohne philosophisches Verständniß davon, entstellt durcheinander geworfen werden; große Behutsamkeit, sich mit dem neuesten Idealismus zu verfangen, weder durchgreifende Darstellung noch durchgreifende Argumentation gegen den Dogmatismus. Von Seiten des Empirismus ordentliche und in Bezug auf den besondern Zweck nicht untüchtige Polemik, die, als der am besten gearbeitete Theil des Werkes, ihre Wirkung nur darum verfehlen kann, weil der Verfasser in dem, was er für Transscendentalphilosophie ausgibt, selbst darein zurückfällt und in Ansehung des Hauptpunkts sich mit keinem Gedanken über den Empirismus erhebt. Wenn es nicht der Zweck des Verfassers war, was in den oben angeführten Rücksichten allerdings das Räthlichste seyn mochte, sich"}, {"type": "paragraph", "text": "gegenüber von der französischen Philosophie ganz auf das Negative zu beschränken, so mußte er, um das Positive geben zu können, nothwendig vorerst selbst den wahrhaft transscendentalen Gesichtspunkt errungen haben und besitzen. Welchen allgemeinen Begriff er sich von demselben macht, wird man am bestimmtesten da erkennen, wo er ihn dem transscendenten entgegensetzt; auf diesem nämlich wird nach dem fond réel de nos connoissances gefragt; diese Frage ist nach S. 238 du ressort d'une metaphysique ou onthologie (sic) transcendente; jener dagegen wird so eingeleitet: l'être cognitif étant *posé,* la possibilité de ses connoissances étant *posée aussi* (natürlich als empirische Thatsache, über die es keinen Zweifel gibt), il s'agit de rechercher le *mode, * suivant lequel cette possibilité est mise en action etc. Auf diesem Gesichtspunkt heißt *Grund unserer Erkenntnisse * so viel als \"base *formelle*, principe *coordonnant* de nos connoissances\", das andere mitwirkende Princip liegt in den afficirenden Dingen, in dem empirischen Stoff. Anfänglich war die Hauptfrage der Speculation so gestellt: was das Band sey zwischen dem Ich und dem, was nicht Ich ist (S. 70); nachher wird der transscendentale Gesichtspunkt darein gesetzt: gewisse"}]}, {"page_pdf": 1519, "page_book": 194, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "allgemeine Gesetze zu betrachten comme résidant en nous et - réglant les *objets perçus et connus par nous*; hier sind also die Objekte mit dem Ich schon zusammengebracht, und es ist nach einem Band zwischen beiden nicht mehr die Frage. Die Art, wie Hr. Villers den Franzosen den transscendentalen Gesichtspunkt beschreibt (denn an einen Beweis ist nicht zu denken), ist zu merkwürdig, um nicht erwähnt zu werden; sie kann als ein Spiegel dienen, worin sämmtliche deutsche Kantianer das wahre Ebenbild ihrer Philosophie im Reflex erblicken können. Man denke sich, sagt er, eine der optischen Maschinen, die man finstre Kammern nennt, die an der Oeffnung, wodurch sie das Licht empfängt, ein *rothes Glas* habe. Alle Objekte im Grund der Camera obscura werden roth, und diese rothe Farbe wird von der Natur des Glases producirt seyn; dieses Glas ist von solcher"}, {"type": "paragraph", "text": "Beschaffenheit, daß die *rothe Farbe* ein *Gesetz, eine allgemeine Form* für alle von ihm aufgenommenen (perçus) Objekte ist. Könnte unsre dunkle Kammer empfinden und sich ausdrücken, so würde sie nicht ermangeln zu urtheilen und zu behaupten, daß die Häuser, die Bäume, die Menschen, mit Einem Wort daß die ganze Natur roth sey, sie würde sich wohl hüten, gleich den klugen Gedanken zu haben, daß diese in allen Objekten ihrer Erkenntniß allgemeine Farbe von ihr selbst, von der Beschaffenheit des Organs herkommt, durch welche sie die Eindrücke empfängt. Man sieht: dem Hrn. Villers erscheint das *Allgemeine* in der Gestalt einer empirisch-allgemeinen Qualität, wie die rothe Farbe ist: man begreift nicht, warum die Camera obscura, wenn sie empfinden und sprechen könnte, nicht noch andere Allgemeinheiten an den Objekten entdeckte, z.B. daß sie sämmtlich ausgedehnt, von gewisser Form u.s.w. erscheinen. Man kann nicht wissen, wie weit der Witz noch gehen könnte, um auch von diesen Allgemeinheiten den Grund zuletzt in der Verfassung des Glases zu finden, wodurch sie sieht, und zu behaupten, daß die Häuser, die Bäume, die Menschen u.s.w. an sich nicht ausgedehnt seyen, keine Gestalt haben, sondern daß diese Form ihm allein absolut inhärire. - Wenn Hr. Villers übrigens bei der Seele nur erst die *Oeffnung, das rothe Glas* und die Art, wie sie und die Objekte zusammenkommen, aufgezeigt hat, so wird es mit dem Uebrigen keine Schwierigkeit mehr haben. Laßt uns, fährt er fort, auf alle verschiedene Arten Siegelwachs einen geschnittenen Stein drücken, der eine Minerva vorstellen soll. Dieser Stein mit Empfindung begabt, wird glauben, daß alle Siegelwachse unter der Figur einer Minerva existiren, denn er wird selbige nur unter dieser Form wahrnehmen, welche offenbar *das allgemeine Gesetz, die nothwendige Bedingung* aller Perceptionen dieses Steins ist. Wenn es freilich mit der Application seine Richtigkeit hätte, so folgte das andere von selbst, aber eben jenes \"Appliquons\", und wie der Stein zu dem Wachs, das Wachs zu dem Steine komme, ist der garstige und breite Graben, über welchen sich zu erheben der transscendentale Gesichtspunkt erfunden ist."}, {"type": "paragraph", "text": "Wir wollen nicht des dritten Gleichnisses erwähnen, das Hr. Villers von drei Spiegeln, einem planen, cylindrischen und conischen hernimmt: wie er diese Spiegel, nachdem er ihnen Empfindung und Sprache gegeben, nach und nach empirische Philosophen, dann transscendente Philosophen oder Rationalisten werden, und endlich den Uebergang zum transscendentalen Gesichtspunkt machen läßt, wird man nicht ohne Bewunderung des Geistreichen seiner Darstellungsgabe bei ihm selbst nachlesen. Sonst wird in dem Hauptwerk und noch ausführlicher in der Skizze, Nro. 2., die öffentlichen Angaben zufolge zur Notiz von Bonaparte geschrieben wurde, das Verhältniß des Objekts zu dem Ich auch wie das"}]}, {"page_pdf": 1520, "page_book": 196, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der Speisen zu dem Magen und Darmkanal vorgestellt. Das Ich verhält sich nach ihm nicht wie ein bloßer irdener Topf, der an den Nahrungsmitteln nichts verändert, sondern wie ein menschliches Verdauungsorgan, das seine inneren Kräfte und Constitution hat, wodurch es sie in Nahrungssaft, Blut u.s.w. verwandelt. Wir rathen dem Verfasser, da er doch dieses Bild mit besonderer Liebe ausgemalt hat, noch einen Zug aus dem neuen Reinholdischen Realismus (der sich nach Vorrede S.XXX dem Plato wieder nähern soll) darein aufzunehmen; was von dem Stoff ausgeschlossen werden muß, um es mit ihm zu einem Denken zu bringen, wird füglich als das Excernirte, was aber nicht aufgerieben wird und sich im Denken wieder anschließt, als das Secernirte vorgestellt werden können. - Wie übrigens Nahrungsmittel in den Magen kommen, ist bekannt genug: man beißt sie mit den Zähnen, kaut sie, schickt sie hinunter; wie aber die Dinge in das Ich hinein kommen, ist eine Frage, die noch keiner dieser angeblichen Transscendentalphilosophen beantwortet hat; seinen Magen fühlt freilich jeder, das Objekt aber ist ihnen noch immer im Hals stecken geblieben. Der ganze Unterschied dieser Vorstellung von dem Empirismus, gegen den sie so vornehm thut, besteht bloß darin, daß jene außer dem Stoff, den sie ganz vom Boden des Empirismus nimmt, auch noch den geistigen Magensaft angeben zu können meint, wodurch das von außen Eingeführte zum Gedanken, zur Idee, zum Urtheil u.s.w. wird. Da aber nach den Behauptungen"}, {"type": "paragraph", "text": "jener Philosophen *alle* Vorstellungen durch diese Operation hindurchgehen, so haben sie vor den Empiristen nur den Nachtheil voraus, dem Ich einen wahren Polyphemusmagen zuschreiben zu müssen, um den einströmenden Stoff aller Häuser, Bäume, Menschen und der ganzen Natur zu verdauen. Dieser grobe Realismus, der den Eindruck des Objekts auf das Ich stehen läßt, ist nicht nur dem Geiste Kants innigst zuwider, sondern es liegt selbst in seinem aufs roheste genommenen Buchstaben kein Grund, ihm einen solchen zuzuschreiben. Da Kant in der Darstellung seiner Philosophie von keinem absoluten Standpunkt ausgeht, sondern den Leser und sich selbst erst durch die fortgehende Untersuchung darauf erhebt, so müssen Stellen vorkommen, wo er, sein Raisonnement an die gemeine Ansicht anknüpfend, von der Bewirkung von Vorstellungen durch Sinnenrührungen, von Erweckung des Erkenntnißvermögens durch den gegebenen Stoff u.s.w. redet. Aber solchen Stellen stehen eine Menge andere, in denen er wirklich ganz in der transscendentalen Anschauung ist, entgegen, und man kann sich für die, welche über diesen Streitpunkt noch immer den Buchstaben fragen, vorzüglich auf einige der lichtvollsten Stellen *der ersten Ausgabe* seiner Kritik der reinen Vernunft, z.B. in der Lehre von den Paralogismen der reinen Vernunft, aber auch in der von den Kategorien berufen, Stellen, die in den folgenden Ausgaben fehlen, dagegen andere, wie die am Ende seiner Lehre von den Kategorien eingeschaltete Widerlegung des Idealismus, hinzugekommen sind, wovon man sich keinen andern Grund denken kann, als daß Kant, dem die transscendentale Ansicht selbst nie zum bleibenden und unwandelbaren Organ geworden war, der, einzelne Momente ausgenommen, vielleicht nie zu einer Anschauung seines Systems im Ganzen gekommen war, der auch übrigens diese Fremdheit, welche der transscendentale Gesichtspunkt für ihn behielt, durch die beständige Neigung verräth, wieder auf den empirischen Weg einzulenken, daß Kant, sage ich, durch die ihm überall her entgegenkommende Benennung: Idealist, schüchtern und zweifelhaft gemacht, diese Stellen, die ihm vielleicht indeß selbst zu kühn geworden waren,"}, {"type": "paragraph", "text": "unterdrückte. Für den, der den Anfang seines Studiums der Kantischen Werke mit der ersten Ausgabe der"}]}, {"page_pdf": 1521, "page_book": 198, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Kritik gemacht hat, ist es eine eigne Empfindung, in der zweiten die besten Stellen zu vermissen, dagegen so manches Hereingekommene zu finden, was sich zu dem Vorherigen nicht besser schicken will als ein fremder Lappen auf einem guten Kleid; da man diese Bemerkung allgemein übersehen hat, und von sinnlosen Nachbetern Kants Namen noch immer durch Berufung auf die Zufälligkeiten seines Buchstabens Unrecht geschieht, so hielten wir diese Erwähnung nicht für uninteressant. Das, worauf Kant auch da, wo er gewissermaßen gezwungen ist seinen Sinn unumwunden auszusprechen, besteht, z.B. in der bekannten Streitschrift gegen Eberhard, ist: daß die Dinge an sich den *Stoff* unserer Vorstellungen geben. Kant meint hiermit, daß das *Wesen* unserer Vorstellungen in dem An-sich, die Form aber oder die Bestimmungen, mittelst welcher sie Darstellungen von Erscheinungen, d.h. wandelbar und stets veränderlich sind, in der Art unserer Erkenntniß von ihnen begründet sey. Die Kantianer verstanden das umgekehrt, nämlich daß die subjektiven Formen, wodurch die Dinge Erscheinungen sind, das absolut Allgemeine, der Stoff aber, der nach Kant aus dem schlechthin Allgemeinen, dem An-sich oder Ewigen kommt, das Sinnliche, Besondere und Zufällige sey. - Nie konnte Kant sagen wollen, daß die Dinge an sich durch ein Causalverhältniß zum Ich den Stoff der Vorstellungen geben; dieß würde sein ganzes System aufheben, nach welchem dieser Begriff weder von einer Welt in die andere - aus der Intellektualwelt in die erscheinende - reicht, noch, wenn man das Ich, welches die Dinge an sich afficiren sollen, - wiederum ganz gegen seine Erklärung, da er das Ich ebenso wieder zur Erscheinung macht wie die Dinge, die ihm erscheinen - zu einem *An-sich* machen wollte, eine Relation zwischen Dingen an sich begründen könnte. Wenn Kant von Sinnen*affektionen* spricht, so fallen ihm diese mit seiner Kategorienlehre selbst wieder in die Erscheinungswelt; daß man diese Affektionen, welche bei Kant eine Relation von Erscheinendem zu Erscheinendem ausdrücken, und von denen er nicht anders redet, als wie"}, {"type": "paragraph", "text": "der Astronom auch von einem Aufgang und Untergang der Sonne spricht, für ein Verhältniß von Dingen an sich zum Erscheinenden nehmen und diesen groben Mißverstand in Deutschland in unzähligen Büchern wiederholen und endlich sogar ins Französische übersetzen konnte, beweist eine beispiellose Dumpfheit des philosophischen Sinns, die wahrhaftig kein Recht gibt, sich über die Un- oder vielmehr Nicht-Philosophie der Franzosen auf solche Weise zu erheben, als es in der Vorrede des Hrn. Villers und einzelnen Stellen seines Werks geschieht. Der Franzose, wenn er auch selten in einem Theil des Wissens sich zu Ideen erhebt, hat doch den Begriff einer gewissen formellen Vollkommenheit; er will keine Incohärenz, und verlangt noch überdieß lebhaft und kategorisch angeregt zu seyn. Wie soll er sich in einem Werk, das ihm als Bruchstück einer ihm ganz fremden Kultur ohnehin Schwierigkeiten genug darbietet, sich durch Widersprüche hindurchfinden, wie z.B., daß ihm die Vorstellung unserer Erkenntniß als einer Art von Spiegel der Dinge erst als die metaphysique du sauvage et de l'ignorant civilisé verschrieen wird, und man nachher, um den transscendentalen Gesichtspunkt, den er mit jener vertauschen soll, zu demonstriren, selbst wieder zu dieser Analogie recurriren muß? (Man vergl. S. 71 mit S. 111). Oder wenn einem seiner berühmtesten Philosophen (S. 99) die Lektion darüber gelesen wird, daß er die Metaphysique raisonnable eine science de faits, eine Physique expérimentale de l'ame genannt hat, nachdem man vorher (S. 52) selbst die vollkommene subjektive, d.h. kritische Philosophie eine bonne *Anthropologie* rationelle erklärt hatte, wo das rationelle ohne Zweifel ebenso viel als dort das raisonnable bedeutet und höchstens anzeigen soll, daß über die Facta raisonnirt werde, da dieser ganze französisch zubereitete Kantianismus doch keine andere Basis als *Facta* hat). Wie wird derselbe die Declamationen gegen den Sensualismus seiner Nation mit dem reimen können, was er in dem Aperçu rapide als Kantische Lehre erfährt, daß die Idee nichts anderes als sensation transformée sey, daß der intellektuelle Mensch ganz unter dem Mechanismus der Sensation stehe, daß Kant"}]}, {"page_pdf": 1522, "page_book": 199, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "*sur le même chemin* mit Descartes sey, wenn dieser in seiner Dioptrik behauptete, Farben und Töne sey'n nur verschiedene Modificationen unseres Auges und Gehörs, u.s.w.? - Welche Neigung, sich in das ungewisse Studium einer solchen Lehre einzulassen, werden die unsicheren Schritte, das vorsichtige Entfernthalten gewisser nothwendig jedem auffallender Punkte und die Spuren, daß der Verfasser selbst über die Sache, die er vortragen will, nur unvollständig unterrichtet sey, hervorbringen können? Oder welches Zutrauen erwecken, zu lesen, daß Männer, die wie Fichte in Anmerkungen mit großen Lobeserhebungen - beseitigt werden, nachdem sie anfänglich Kants Schüler gewesen, seine Schule wieder verlassen haben (S. XXX), oder daß die speculative Physik, obgleich in einem andern Sinn wie dem von Kant gedacht, indem sie diesen weit überschreite, nichtsdestoweniger Epoche in der Naturphilosophie machen werde (S. 203) u. dgl.? Die beruhigenden Gegenversicherungen wird man in Frankreich nicht im Stande seyn zu beurtheilen, z.B. daß die Transscendentalphilosophie *en général* un bien plus grand nombre de bonnes têtes für sich als gegen sich habe) wo niemand vermuthen wird, daß in dem *en général* auch wieder der Fichtianismus begriffen sey), oder: daß sehr große Mathematiker, Naturforscher, Chemisten, berühmte Aerzte unter der Anzahl von Kants Nachfolgern seyen, und unter andern - *Goethe* auf die Theorie der Künste und der Poesie eine so glückliche Anwendung von der Philosophie transcendentale mache (S. XXXV)! Der Franzose hat eine natürliche Neigung zu parodiren, Beweise auf eine scharfsinnige Art umzukehren und zurückzugeben; unglücklicher Weise läßt sich dieß sehr leicht mit dem größten Theil von dem thun, was der Verfasser von dem Seinigen hinzugefügt hat, wie, um nur Ein Beispiel zu geben, mit der Art von Beweis, die er von dem Satz gibt: daß, was in der Vorstellung der Dinge immer dasselbe ist, dem Subjekt angehören müsse. Wenn ich, sagt der Verfasser, der die transscendentale Subjektivitätslehre sonst auch durch das Beispiel des Hypochondristen erläutert, wenn ich überall, wohin ich nur sehe, einen schwarzen, grünen oder andern Fleck von beständig gleicher Form"}, {"type": "paragraph", "text": "erblicke, werde ich, anstatt daraus zu schließen, daß alle Objekte nothwendig einen schwarzen oder grünen Fleck tragen, nicht viel vernünftiger urtheilen, daß dieser Fleck meinem Auge gehört? Worauf ein anderer, mit geringer Mühe, antworten könnte: weil alles, was von der Subjektivität ausgeht, sich als ein Besonderes, z.B. dem Gelbsüchtigen als *gelbe Farbe*, darstellt, so werde ich vernünftiger Weise schließen, daß, was ich nicht als Besonderes, z.B. als einen schwarzen oder grünen Fleck, sondern als schlechthin Allgemeines, wie Substanz, Ausdehnung u.s.w. erkenne, nicht in meiner Subjektivität, sondern in den Objekten gegründet sey. Andere werden andere Blößen bemerken, die der Verfasser seinem Original gibt, z.B. S. XIV, wo Kants empirische Kenntnisse herausgestrichen werden sollen und als Beweis angeführt wird, er habe daraus, daß die Planetenbahnen im Verhältniß der Sonnenentfernung immer excentrischer werden, geschlossen, daß zwischen den bekannten äußersten Planeten und den Kometen wegen des unverhältnißmäßigen Sprungs noch andere Planeten seyn müssen, ein Schluß, der durch die Entdeckung des Uranus bestätigt worden sey. Weder war Kants Schluß so einfach, als er hier gemacht wird, noch war er selbst so unwissend, die unter den bisher bekannten am meisten excentrische Bahn des Mercurs für diejenige auszugeben, die es am wenigsten wäre. In dem Urtheil des Nationalinstituts oder vielmehr der Notiz, die der zweiten Klasse desselben über eine die Kantische Philosophie betreffende Arbeit eines ihrer Mitglieder gegeben wurde, wogegen No. 3"}]}, {"page_pdf": 1523, "page_book": 201, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "gerichtet ist, erkennt man in einem nichtssagenden leeren Radotiren gleichwohl immer noch eine ganz leidliche Billigkeit, und, wenn man die Begriffe dazu nimmt, die sich die Franzosen von Kant, nach dem, was ihnen bisher von ihm zugebracht worden, machen müssen - eine wahre Gutmüthigkeit, dagegen läßt sich der Verfasser von No. 3 ganz in dem Tone eines deutschen Kantianers vernehmen. Wenn das allgemeine Urtheil über diese Unternehmung in Frankreich ebenso ausfallen sollte wie das einer französischen Zeitschrift: on avoit annoncé aux Français une grande chose, et ils n'ont"}, {"type": "paragraph", "text": "trouvé *qu'une petite*, wenn sie, noch im besten Fall, sich nicht genug verwundern könnten, daß man in Deutschland an dieser Philosophie so viel gefunden habe, so könnte man es ihnen, wie die Sachen jetzt stehen, nicht verargen, so wenig man deßhalb auf der andern Seite die Industrie und die Art von Talent verkennen wird, die erforderlich waren, um sich durch so große Schwierigkeiten, welche einem Fremden die Eigenthümlichkeiten der deutschen Sprache, Kultur, und selbst der für den Ununterrichteten noch zweifelhafte Stand der Wissenschaft in Deutschland bei so wenig innerem Beruf zur Sache entgegenstellen, auch nur bis zu dem Punkte durchzuarbeiten, welchen Herr Villers errungen hat, der seinen Fleiß, selbst bis auf Wendungen und Ausdrücke zu lernen, sogar bis auf das gemeinen Lesern nicht zugängliche Athenäum erstreckt hat, von dem er die deux tendances majeures de notre âge (S. X) entlehnt, als welche er die neue Chemie in Frankreich und die neue Philosophie in Deutschland bezeichnet, wozu er billig, um die drei voll zu machen, auch noch die Kuhpocken hätte setzen sollen. Da indeß Umstände sind, welche die vollkommene Authenticität der Villers'schen Darstellung in Frankreich glaublich1 und diese dadurch zum Maß der gegenwärtigen wissenschaftlichen Kultur in Deutschland machen könnten, und auf der andern Seite Hr. Villers diese Darstellung seiner Nation als die Frucht dessen darbringt, was die Deutschen beschäftigt, während jene in einer erstaunenswürdigen Revolution die höchsten moralischen und physischen Kräfte aufgeboten hat, so ist zu wünschen, daß diejenigen, welche dazu im Stande sind, der Meinung"}, {"type": "footnote", "text": "1 Der Disciple de Kant, No. 3, versichert unter anderem S. 17: \"Cet aperçu des bases du Système de Kant (inseré au spectateur du Nord, par Villers) a été traduit en allemand à Königsberg sous les yeux de ce philosophe\" (p. 17) und: \"Cette introduction (die gegenwärtige von Hr. Villers) sera traduite en allemand par l'ami de Kant et l'editeur de ses derniers ouvrages, Mr. le docteur Rink.\" - Welch ein ami de Kant und wirklicher Editeur de ses derniers ouvrages dieser Hr. Dr. Rink sey, wird sich aus der von ihm kürzlich herausgegebenen physischen Geographie Kants am besten beurtheilen lassen."}, {"type": "paragraph", "text": "auch in Frankreich zuvorkommen, daß außer einigen anerkannt incompetenten Subjekten in Deutschland selbst irgend jemand des Dafürhaltens sey, daß diese oder jede andere bis jetzt in Frankreich bekannt gewordene Darstellung auch nur historisch richtig die Höhe bezeichne, auf welcher Kants Philosophie stand, noch weniger die, zu welcher die Philosophie durch den unausgesetzten Eifer der Deutschen seitdem gehoben worden ist."}, {"type": "paragraph", "text": "7. Anzeige einer die Naturphilosophie betreffenden Schrift."}]}, {"page_pdf": 1524, "page_book": 203, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "* Principes naturels* ou notions générales et particulières de l'Immensité, de l'Espace, de l'Univers, des Corps célestes, des forces vivantes primordiales ou du Principe de mouvement, et des forces secondaires qui en résultent dans les Corps terrestres. Applicables à toutes les branches de Physique et de Morale specialement à la Médecine. Par *Claude-François Le Joyand. IV * Vol. in 8."}, {"type": "paragraph", "text": "Der Titel klingt versprechend genug, und der nähere Anblick des Werks läßt eine in Bezug auf den Zustand der Wissenschaft in Frankreich merkwürdige Erscheinung darin erkennen. Mehr aber muß man nicht in ihm suchen. Es ist der alte Geist des Cartesianismus, der sich wieder regt, aber entkleidet der strengeren Form und der mathematischen Rüstung, mit welcher gegen die Allherrschaft des Newtonianismus in Frankreich aufzutreten er sich nicht mehr getraut. Er sucht seine Stärke in den Argumenten einer allgemeinen wissenschaftlichen und philosophischen Ansicht; allein die Erfahrung der letzten Zeiten hat gezeigt, daß kein französischer Schriftsteller den Calcul und das Experiment, die einzigen Geistesoperationen im theoretischen Gebiet, die ihnen zu Gebot stehen, verlassen kann, ohne sich entweder in leere Empfindsamkeit oder bodenlose Popularität und Seichtigkeit zu verlieren (wie in den Naturwissenschaften der bekannte Bernardin de St. Pierre), oder in einen trüben und prosaischen Mysticismus, wie der aller neueren französischen Mystiker."}, {"type": "paragraph", "text": "Man könnte sagen, der Verfasser vereinige in sich diese beiden Qualitäten, die letzte insbesondere insofern, als der Mysticismus, den er wirklich hat, in der Berührung des Cartesianismus aufhört es zu seyn, und seine wirklich höheren Ideen vom Licht als dem Typus aller Harmonie durch die Prosa des letzteren immer verdorben werden. Ein partielles Wiederaufleben der Cartesianischen Vorstellungsart in Frankreich kann um so weniger unerwartet seyn, da der Newtonianismus, indem er sich aus Geometrie und rein intellektueller Construktion zur Physik gestaltet hat, selbst gewissermaßen wieder dazu zurückgekehrt ist, und Newton durch die zugegebene Möglichkeit, die Gravitation durch Stoß oder Druck zu begreifen, selbst die Schranken für einen andern höher ausgedachten Cartesianismus offen gelassen hat. Der Verfasser erklärt es als seine Absicht, den Newtonischen Koloß, der großen Mittel der Analysis unerachtet, welche unübersteigliche und ins Unendliche vervielfachte Befestigungen um ihn zu bilden scheinen, zu stürzen, und den Scepter der Physik dem Cartesius wieder zu geben, *indem er gleichwohl dessen System von Grund aus zerstöre.* Der Weg hiezu ist, die Wissenschaft zu dem *einfachen Licht der Natur* und der Regel zurückzuführen, welche Hermes Trismegistus seinem Schüler gab: Inprimis intuere lucem. - \"Ich habe, sagt der Verfasser, einzig auf dieses Licht gehofft, und unerachtet meiner zahlreichen Irrthümer, meiner materiellen Widersprüche, sehe ich meine Hoffnung erfüllt. Diesem Licht danke ich die Lösung der größten Probleme der Physik, woran seit dreitausend Jahren alle Sektenhäupter und so viele andere unvergleichbar geistreichere und unterrichtetere Menschen als ich gescheitert haben.\" Der Schlüssel aller Wissenschaft ist dasselbe Princip des ewigen Lichtes, die erste lebendige Grundlage der Philosophie und der alten Religionen der Perser, der Hindus u.s.w. Alle Allegorien, Embleme, hieroglyphische, mystische und symbolische Formen, selbst die Ceremonien, Gebräuche und Handlungen der religiösen und anderer Gesellschaften zeugen von ihm. Es ist der Zeiger und das Urbild der ewigen Einheit, das einzige Princip, welches offenbar die Gesetze bezeichnet, die der Mensch in der Errichtung der"}]}, {"page_pdf": 1525, "page_book": 204, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Hierarchien, der Staaten und aller äußern oder moralischen Verfassungen zu befolgen hat. Brennpunkte dieses Lichtes, welches der Schooß der ewigen Intelligenz ist, sind im Universum, im Menschen, in allen intelligenten Wesen, in allen Wesen ohne Ausnahme - größere oder kleinere, mehr oder weniger starke und empfindbare, sich untereinander entgegengesetzt und entsprechend, rückwirkend aufeinander, um das Gleichgewicht und die Harmonie der Kräfte zu erhalten. Alle stammen aus Einer unversiegbaren und unendlichen Quelle. Die Verbindungen und Modificationen dieses Princips mit den irdischen Substanzen bringen die secundären Agentien und Aktionen hervor. Sichtbar aus seiner Unsichtbarkeit wird dieses Princip allenthalben, wo es durch Dazwischenkunft eines Brennpunkts oder einer localen Vibration (gleichsam eines Schwingungsknotens im Universum) contrahirt und verdichtet wird. Die Manifestationen der obersten Intelligenz gehen bis hieher; vom Princip des Lichtes bis zu Gott bedarf es keines Zwischenglieds, keines Mittlers zwischen dem Gedanken Gottes und seinem vollkommensten Ausdruck. Das Lichtwesen ist der erste aus seinem Willen ausgeflossene Ordner der Dinge. Auf dieser Höhe der Betrachtung ist keine Superstition, sind keine verborgenen Qualitäten, keine Abstraktionen mehr, sondern nur Unterabtheilungen der *Natur* oder des großen Alls. Alles hängt zusammen, der Atheismus selbst und der blinde Materialismus sind nur eine Abstraktion, und verschwinden mit der Anerkennung der allgemeinen Einheit. Die Wiedergeburt der Wissenschaft liegt in dem Wiederverständniß der allgemeinen, offenbaren und einfachen Sprache des Lichts. Alle Theile in dem großen Baum der Wissenschaft und Erkenntniß sind eins und haben dieselben Wurzeln, denselben Stamm. Alle leihen sich wechselseitig Ein Licht, Ein Leben. Der Verderb eines jeden Zweigs derselben, die Schwierigkeit sie zu fassen, ihre Unfruchtbarkeit für uns, der Irrthum und die giftigen Früchte, welche sie tragen, sind nur aus der *Vereinzelung, Absonderung* und *Abstraktion* entstanden."}, {"type": "paragraph", "text": "Dieses sind die allgemeinsten Ideen dieses Werks, denen es nur an dem Hinterhalt einer gründlichen Speculation fehlt, um eine höhere Bedeutung und tiefere, wissenschaftlichere Wirkung zu haben, als sie bei dem Verfasser erlangt haben, der jenes ewige Licht wieder als ein *Fluidum* begreift, das durch seine Reflexion, in Entgegenstellung der Brennpunkte, und (mechanische) Aktion auf die Weltkörper, das Aphelium und Perihelium, das ganze Phänomen der Excentricitäten und seiner Varietäten an Planeten und Kometen, die Axendrehungen, Wankungen und übrige Arten der allgemeinen Bewegung bewirkt. Wozu die Conception eines solchen universellen Princips zunächst führen muß, ist: die Naturerscheinungen in ihrer durchgängigen Identität zu sehen; das orientirende Phänomen ist dem Verfasser der Magnetismus, und zwar der animalische, der seinen Ideen die erste Richtung nach dieser Seite gegeben zu haben scheint. Der thierische Magnetismus ist nach ihm mit allen Phänomenen der Astronomie, der Meteorologie, der Naturgeschichte der drei Reiche verflochten, er befaßt die Verbindung zwischen den Himmelskörpern, Sonnen und Planeten, wie die Einflüsse dieser größeren Ganzen auf die kleinsten Körper, welche durch denselben Theil haben an der gemeinschaftlichen Existenz und dem allgemeinen Einfluß. Je zarter und entwickelter ihre Organisation, desto empfindlicher müssen sie sich für diese Influenz zeigen, so daß derselbe Magnetismus, welcher, noch mineralisch, die bloß einfachen Phänomene der Anziehung und Zurückstoßung erzeugt, im Reich der Vegetation die Bewegungen der Sensitiva, die Verbindung zart ausgebildeter Geschlechtsorgane, die Propagation der Gattung bewirkt, und endlich im Reich des Animalismus die höchsten Erscheinungen der Einigkeit und der Zwietracht, der Sympathie und Antipathie, der Liebe und des Hasses, der sanftesten und der heftigsten Bewegungen"}]}, {"page_pdf": 1526, "page_book": 206, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "durch die leichteste Berührung, selbst die feine Vermittlung der Stimme und des Blicks, hervorbringt. Der Mensch selbst ist nur die Welt im Kleinen, nicht der Form der körperlichen Substanz nach, sondern weil er alle Kräfte und Wirkungen der großen Welt, alle himmlischen Bewegungen, die Natur der Erde, die Eigenschaften des Wassers und"}, {"type": "paragraph", "text": "die Qualität der Luft, die Wirkung aller Constellationen in sich begreift, und die inneren Bewegungen seiner Seele nur die größeren Bewegungen der allgemeinen Natur nachahmen. - Selbst der Schwung der Gedanken, die reinsten Bewegungen des Geistes theilen, je unsinnlicher und abstrakter sie sind, desto mehr die Schwingungen des allgemeinen Lebensprincips, welches die Seele des Universums, der leichte Bote der Götter ist, der mit Einem Flug die Tiefe des Abgrunds und die Höhe der Himmel verbindet. Die gänzliche Abwesenheit einer sicheren und strengen Methode und des ächt wissenschaftlichen Ernstes in diesem Analogien-Spiel verhindert, von dieser Seite einen vollständigeren und bestimmteren Begriff von dem System des Verfassers zu geben, so wie es sich, bei dem Mangel aller Speculation im Princip, nicht der Mühe verlohnen kann, darzustellen, zu welcher Art von System der Cartesianismus sich in dem Geist desselben ausgebildet habe. Als merkwürdige Erscheinung schien jedoch dieses Werk ausgezeichnet werden zu müssen. Die darin enthaltene Darstellung der Physik des Cartesius ist, sofern sie rein historisch ist, von bedeutendem Interesse. Man bemerkt mit Vergnügen einen von dem so ganz leeren neuern Experimentalwesen in Frankreich, das nicht einmal die Wissenschaftlichkeit der Atomistik erreicht, völlig unberührten Geist. - Das Licht vertritt wenigstens als Symbol die Stelle der Idee und der wahren Anschauung1, und wenn diese aus der Asche eines untergegangenen Systems gezogenen Funken die speculative Physik nicht wieder hervorrufen können, so ist es wenigstens ein Schritt dazu, die Welt an das Licht zu knüpfen, diese goldene Kette, die am Throne Jupiters befestigt, alle Wesen trägt und hält2."}, {"type": "footnote", "text": "1 Vergl. oben S. 113, Z. 8 von unten. D. H. 2 Die in Bd. 2, Stück 3 des Kritischen Journals stehende Anzeige einer zweiten die Naturphilosophie betreffenden Schrift (D. J. C. Oersteds Ideen zu einer neuen Architektonik der Naturmetaphysik etc. Herausgegeben von D. M. H. Mendel. Berlin 1802) wurde, da sie ein bloßes Referat enthält, hier weggelassen. D. H."}, {"type": "paragraph", "text": "*Vorlesungen*"}, {"type": "paragraph", "text": "über die Methode des akademischen Studiums."}, {"type": "paragraph", "text": "1803."}, {"type": "paragraph", "text": "Weitere unveränderte Auflagen 1813 und 1830."}]}, {"page_pdf": 1527, "page_book": 209, "page_kind": "toc", "sigel": "SW I.5", "units": [{"type": "heading", "text": "*Vorwort.*", "level": null}, {"type": "paragraph", "text": "Diese Vorlesungen sind im Sommer 1802 auf der Universität zu Jena gehalten. Ihre Wirkung auf eine beträchtliche Anzahl von Zuhörern, die Hoffnung, daß manche Ideen derselben, außer andern Folgen, auch für die nächsten oder doch zukünftigen Bestimmungen der Akademien von einigem Gewicht seyn könnten, der Gedanke, daß, wenn sie ihrem Zwecke nach keine neuen Enthüllungen über die Principien erwarten lassen, doch die dem allgemeinfaßlichen Vortrag genähertere Darstellung der letzteren, so wie die aus ihnen hervorgehende Ansicht des Ganzen der Wissenschaften, nicht ohne allgemeineres Interesse seyn würde, schienen dem Verfasser hinreichende Bestimmungsgründe zur öffentlichen Bekanntmachung derselben."}, {"type": "paragraph", "text": "*Inhalt.*"}, {"type": "paragraph", "text": "Seite *Erste Vorlesung.* Ueber den absoluten Begriff der Wissenschaft .................. 211 *Zweite Vorlesung.* Ueber die wissenschaftliche und sittliche Bestimmung"}, {"type": "paragraph", "text": "der Akademien.............................................................................................. 223 *Dritte Vorlesung.* Ueber die ersten Voraussetzungen des akademischen"}, {"type": "paragraph", "text": "Studiums ...................................................................................................... 239 *Vierte Vorlesung.* Ueber das Studium der reinen"}, {"type": "paragraph", "text": "Vernunftwissenschaften: der Mathematik und der Philosophie im Allgemeinen.................................................................................................. 248 *Fünfte Vorlesung.* Ueber die gewöhnlichen Einwendungen gegen das"}, {"type": "paragraph", "text": "Studium der Philosophie .............................................................................. 257 *Sechste Vorlesung.* Ueber das Studium der Philosophie insbesondere.......... 266 *Siebente Vorlesung.* Ueber einige äußere Gegensätze der Philosophie,"}, {"type": "paragraph", "text": "vornämlich den der positiven Wissenschaften.............................................. 276 *Achte Vorlesung.* Ueber die historische Construktion des Christenthums .... 286 *Neunte Vorlesung.* Ueber das Studium der Theologie .................................. 296 *Zehnte Vorlesung.* Ueber das Studium der Historie und der Jurisprudenz .... 306 *Eilfte Vorlesung.* Ueber die Naturwissenschaft im Allgemeinen .................. 317 *Zwölfte Vorlesung. *Ueber das Studium der Physik und Chemie .................. 327 *Dreizehnte Vorlesung.* Ueber das Studium der Medicin und der"}, {"type": "paragraph", "text": "organischen Naturlehre überhaupt ................................................................ 335 *Vierzehnte Vorlesung.* Ueber Wissenschaft der Kunst, in Bezug auf"}]}, {"page_pdf": 1528, "page_book": 211, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "das akademische Studium ............................................................................ 344"}, {"type": "heading", "text": "Erste Vorlesung. *Ueber den absoluten Begriff der Wissenschaft.*", "level": null}, {"type": "paragraph", "text": "Die besondern Gründe kurz anzugeben, die mich bestimmen diese Vorlesungen zu halten, möchte nicht überflüssig seyn; überflüssiger wäre es ohne Zweifel, sich bei dem allgemeinen Beweis lange zu verweilen, daß Vorlesungen über die Methode des akademischen Studiums für den studirenden Jüngling nicht allein nützlich, sondern nothwendig, für die Belebung und die bessere Richtung der Wissenschaft selbst ersprießlich sind. Der Jüngling, wenn er mit dem Beginn der akademischen Laufbahn zuerst in die Welt der Wissenschaften eintritt, kann, je mehr er selbst Sinn und Trieb für das Ganze hat, desto weniger einen andern Eindruck davon erhalten, als den eines Chaos, in dem er noch nichts unterscheidet, oder eines weiten Oceans, auf den er sich ohne Compaß und Leitstern versetzt sieht. Die Ausnahmen der wenigen, welchen frühzeitig ein sicheres Licht den Weg bezeichnet, der sie zu ihrem Ziele führt, können hier nicht in Betracht kommen. Die gewöhnliche Folge jenes Zustandes ist: bei besser organisirten Köpfen, daß sie sich regel- und ordnungslos allen möglichen Studien hingeben, nach allen Richtungen schweifen, ohne in irgend einer bis zu dem Kern vorzudringen, welcher der Ansatz einer allseitigen und unendlichen Bildung ist, oder ihren fruchtlosen Versuchen im besten Fall etwas anderes als am Ende der akademischen Laufbahn die Einsicht zu verdanken, wie vieles sie"}, {"type": "paragraph", "text": "umsonst gethan und wie vieles Wesentliche vernachlässigt; bei andern, die von minder gutem Stoffe gebildet sind, daß sie gleich anfangs die Resignation üben, alsbald sich der Gemeinheit ergeben und höchstens durch mechanischen Fleiß und mechanisches Auffassen mit dem Gedächtnisse so viel von ihrem besondern Fach sich anzueignen suchen, als sie glauben, daß zu ihrer künftigen äußeren Existenz nothwendig sey. Die Verlegenheit, in der sich der Bessere in Ansehung der Wahl sowohl der Gegenstände als der Art seines Studirens befindet, macht, daß er sein Vertrauen nicht selten Unwürdigen zuwendet, die ihn mit der Niedrigkeit ihrer eignen Vorstellungen von den Wissenschaften oder ihrem Haß dagegen erfüllen. Es ist also nothwendig, daß auf Universitäten öffentlicher allgemeiner Unterricht über den Zweck, die Art, das Ganze und die besondern Gegenstände des akademischen Studiums ertheilt werde. Eine andere Rücksicht kommt noch in Betracht. Auch in der Wissenschaft und Kunst hat das Besondere nur Werth, sofern es das Allgemeine und Absolute in sich empfängt. Es geschieht aber, wie die meisten Beispiele zeigen, nur zu häufig, daß über der bestimmten Beschäftigung die allgemeine der universellen Ausbildung, über dem Bestreben, ein vorzüglicher Rechtsgelehrter oder Arzt zu werden, die weit höhere Bestimmung des Gelehrten überhaupt, des durch Wissenschaft veredelten Geistes vergessen wird. Man könnte erinnern, daß gegen diese Einseitigkeit der Bildung das Studium der allgemeineren Wissenschaften ein zureichendes Gegenmittel sey. Ich bin nicht gesonnen, dieß im Allgemeinen zu leugnen, und behaupte es vielmehr selbst. Die Geometrie und Mathematik läutert den Geist zur rein"}]}, {"page_pdf": 1529, "page_book": 213, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "vernunftmäßigen Erkenntniß, die des Stoffes nicht bedarf. Die Philosophie, welche den ganzen Menschen ergreift und alle Seiten seiner Natur berührt, ist noch mehr geeignet, den Geist von den Beschränktheiten einer einseitigen Bildung zu befreien und in das Reich des Allgemeinen und Absoluten zu erheben. Allein entweder existirt zwischen der allgemeineren Wissenschaft und dem besondern Zweig der Erkenntniß, dem der Einzelne sich"}, {"type": "paragraph", "text": "widmet, überhaupt keine Beziehung, oder die Wissenschaft in ihrer Allgemeinheit kann sich wenigstens nicht so weit herunterlassen, diese Beziehungen aufzuzeigen, so daß der, welcher sie nicht selbst zu erkennen im Stande ist, sich in Ansehung der besondern Wissenschaften doch von der Leitung der absoluten verlassen sieht, und lieber absichtlich sich von dem lebendigen Ganzen isoliren, als durch ein vergebliches Streben nach der Einheit mit demselben seine Kräfte nutzlos verschwenden will. Der besondern Bildung zu einem einzelnen Fach muß also die Erkenntniß des organischen Ganzen der Wissenschaften vorangehen. Derjenige, welcher sich einer bestimmten ergibt, muß die Stelle, die sie in diesem Ganzen einnimmt, und den besondern Geist, der sie beseelt, so wie die Art der Ausbildung kennen lernen, wodurch sie dem harmonischen Bau des Ganzen sich anschließt, die Art also auch, wie er selbst diese Wissenschaft zu nehmen hat, um sie nicht als ein Sklave, sondern als ein Freier und im Geiste des Ganzen zu denken. *Sie* erkennen aus dem eben Gesagten schon, daß eine Methodenlehre des akademischen Studiums nur aus der wirklichen und wahren Erkenntniß des lebendigen Zusammenhangs aller Wissenschaften hervorgehen könne, daß ohne diese jede Anweisung todt, geistlos, einseitig, selbst beschränkt seyn müsse. Vielleicht aber war diese Forderung nie dringender als zu der gegenwärtigen Zeit, wo sich alles in Wissenschaft und Kunst gewaltiger zur Einheit hinzudrängen scheint, auch das scheinbar Entlegenste in ihrem Gebiet sich berührt, jede Erschütterung, die im Centrum oder der Nähe desselben geschieht, schneller und gleichsam unmittelbarer auch in die Theile sich fortleitet, und ein neues Organ der Anschauung allgemeiner und fast für alle Gegenstände sich bildet. Nie kann eine solche Zeit vorbeigehen ohne die Geburt einer neuen Welt, welche diejenigen, die nicht thätigen Theil an ihr haben, unfehlbar in die Nichtigkeit begräbt. Vorzüglich nur den frischen und unverdorbenen Kräften der jugendlichen Welt kann die Bewahrung und Ausbildung einer edlen Sache vertraut werden. Keiner ist von der Mitwirkung ausgeschlossen, da in jeden Theil, den er sich nimmt, ein Moment des allgemeinen Wiedergebärungs-Processes fällt. Um mit"}, {"type": "paragraph", "text": "Erfolg einzugreifen, muß er, selbst vom Geist des Ganzen ergriffen, seine Wissenschaft als organisches Glied begreifen und ihre Bestimmung in der sich bildenden Welt zum voraus erkennen. Hiezu muß er entweder durch sich selbst oder durch andere zu einer Zeit gelangen, wo er nicht selbst schon in obsoleten Formen verhärtet, noch nicht durch lange Einwirkung fremder oder Ausübung eigner Geistlosigkeit der höhere Funken in ihm erstickt ist, in der früheren Jugend also und nach unsern Einrichtungen im Anfang des akademischen Studiums. Von wem soll er diese Erkenntniß erlangen, und wem soll er sich in dieser Rücksicht vertrauen? Am meisten sich selbst und dem bessern Genius, der sicher leitet1; dann denjenigen, von denen sich am bestimmtesten einsehen läßt, daß sie durch ihre besondere Wissenschaft schon verbunden waren, sich die höchsten und allgemeinsten Ansichten von dem Ganzen der Wissenschaften zu erwerben. Derjenige, welcher selbst nicht die allgemeine Idee der Wissenschaft hat, ist ohne Zweifel am wenigsten fähig, sie in"}]}, {"page_pdf": 1530, "page_book": 215, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "andern zu erwecken; der einer untergeordneten und beschränkten Wissenschaft seinen übrigens rühmlichen Fleiß widmet, nicht geeignet, sich zur Anschauung eines organischen Ganzen der Wissenschaft zu erheben. Diese Anschauung ist überhaupt und im Allgemeinen nur von der Wissenschaft aller Wissenschaften, der Philosophie, im Besondern also nur von dem Philosophen zu erwarten, dessen besondere Wissenschaft zugleich die absolut allgemeine, dessen Streben also an sich schon auf die Totalität der Erkenntniß gerichtet seyn muß. Diese Betrachtungen sind es, meine Herren, die mich bestimmt haben, diese Vorlesungen zu eröffnen, deren Absicht *Sie* aus dem Vorhergehenden ohne Mühe erkennen. In wie weit ich im Stande seyn werde, meiner eignen Idee eines solchen Vortrags und demnach meinen Absichten ein Genüge zu thun, diese Frage vorläufig zu beantworten, überlasse ich"}, {"type": "footnote", "text": "1 Jeder Mensch hat einen inneren Freund, seine Eingebungen sind am reinsten in der Jugend; nur Frivolität verscheucht ihn, sowie Hinneigung zu gemeinen Zwecken ihn endlich ganz verstummen macht. (Von hier an wieder Zusätze, theils in Text mit [ ], theils in Noten, aus einem Handexemplar des Verfassers, wie früher. D. H.)"}, {"type": "paragraph", "text": "ruhig dem Zutrauen, welches *Sie* mir jederzeit geschenkt haben, und dessen mich werth zu zeigen, ich auch bei dieser Gelegenheit streben werde. Lassen *Sie* mich alles, was doch bloß Einleitung, Vorbereitung seyn könnte, abkürzen und gleich unmittelbar zu dem Einen gelangen, wovon unsere ganze folgende Untersuchung abhängig seyn wird, und ohne das wir keinen Schritt zur Auflösung unserer Aufgabe thun können. Es ist die Idee des an sich selbst unbedingten Wissens, welches schlechthin nur Eines und in dem auch alles Wissen nur Eines ist, desjenigen Urwissens, welches, nur auf verschiedenen Stufen der erscheinenden idealen Welt sich in Zweige zerspaltend, in den ganzen unermeßlichen Baum der Erkenntniß sich ausbreitet. Als das Wissen alles Wissens muß es dasjenige seyn, was die Forderung oder Voraussetzung, die in jeder Art desselben gemacht wird, aufs vollkommenste und nicht nur *für* den besondern Fall, sondern schlechthin allgemein erfüllt und enthält. Man mag nun diese Voraussetzung als Uebereinstimmung mit dem Gegenstande, als reine Auflösung des Besondern ins Allgemeine oder wie immer ausdrücken, so ist diese weder überhaupt noch in irgend einem Falle ohne die höhere Voraussetzung denkbar, daß das wahre *Ideale* allein und ohne weitere Vermittlung auch das wahre *Reale* und außer jenem kein anderes sey. Wir können diese wesentliche Einheit selbst in der Philosophie nicht eigentlich beweisen, da sie vielmehr der Eingang zu aller Wissenschaftlichkeit ist; es läßt sich nur eben dieß beweisen, daß ohne sie überhaupt keine Wissenschaft sey, und es läßt sich nachweisen, daß in allem, was nur Anspruch macht Wissenschaft zu seyn, eigentlich diese Identität oder dieses gänzliche Aufgehen des Realen im Idealen [und umgekehrt die Möglichkeit der gänzlichen Umsetzung des Idealen ins Reale] beabsichtigt werde. Bewußtlos liegt diese Voraussetzung allem dem, was die verschiedenen Wissenschaften von allgemeinen Gesetzen der Dinge oder der Natur überhaupt rühmen, so wie ihrem Bestreben nach Erkenntniß derselben zu Grunde. Sie wollen, daß das Concrete und das in besondern Erscheinungen Undurchdringliche sich für sie in die reine Evidenz"}, {"type": "paragraph", "text": "und die Durchsichtigkeit einer allgemeinen Vernunfterkenntniß auflöse. Man läßt diese Voraussetzung in den beschränkteren Sphären des Wissens und für den einzelnen Fall gelten, wenn man sie auch allgemein und absolut, wie sie von der Philosophie ausgesprochen wird, weder verstehen noch eben deßwegen"}]}, {"page_pdf": 1531, "page_book": 217, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "zugeben sollte. Mehr oder weniger mit Bewußtseyn gründet der Geometer seine Wissenschaft auf die absolute Realität des schlechthin Idealen, der, wenn er beweist, daß in jedem möglichen Dreieck alle drei Winkel zusammen zweien rechten gleich sind, dieses sein Wissen nicht durch Vergleichung mit concreten oder wirklichen Triangeln, auch nicht unmittelbar von ihnen, sondern von dem Urbild beweist: er weiß dieß unmittelbar aus dem Wissen selbst, welches schlechthin-ideal, und aus diesem Grunde auch schlechthin real ist. Aber wenn man auch die Frage nach der Möglichkeit des Wissens auf die des bloß endlichen Wissens einschränken wollte, so wäre selbst die Art empirischer Wahrheit, welche dieses hat, nimmer durch irgend ein Verhältniß zu etwas, das man Gegenstand nennt - denn wie könnte man zu diesem anders als immer nur durch das Wissen hindurchkommen? - es wäre also überhaupt nicht begreiflich, wenn nicht jenes an sich Ideale, das in dem zeitlichen Wissen nur der Endlichkeit eingebildet erscheint, die Realität und die Substanz der Dinge selbst wäre. Aber eben diese erste Voraussetzung aller Wissenschaften, jene wesentliche Einheit des unbedingt Idealen und des unbedingt Realen ist nur dadurch möglich, daß *dasselbe*, welches das eine ist, auch das andere ist. Dieses aber ist die Idee des Absoluten, welche die ist: daß die *Idee* in Ansehung seiner auch das *Seyn* ist. So daß das *Absolute* auch jene oberste Voraussetzung des Wissens und das erste Wissen selbst ist. Durch dieses erste Wissen ist alles andere Wissen im Absoluten und selbst absolut. Denn obwohl das Urwissen in seiner vollkommenen Absolutheit ursprünglich nur in jenem, als dem absolut-Idealen, wohnt, ist es doch uns selbst als das Wesen aller Dinge und der ewige Begriff von uns selbst eingebildet, und unser Wissen in seiner Totalität"}, {"type": "paragraph", "text": "ist bestimmt, ein Abbild jenes ewigen Wissens zu seyn. Es versteht sich, daß ich nicht von den einzelnen Wissenschaften rede, welche und inwiefern sie sich von dieser Totalität abgesondert und von ihrem wahren Urbild entfernt haben. Allerdings kann nur das Wissen in seiner Allheit der vollkommene Reflex jenes vorbildlichen Wissens seyn, aber alles einzelne Wissen und jede besondere Wissenschaft ist in diesem Ganzen als organischer Theil begriffen; und alles Wissen daher, das nicht mittelbar oder unmittelbar, und sey es durch noch so viele Mittelglieder hindurch, sich auf das Urwissen bezieht, ist ohne Realität und Bedeutung. Von der Fähigkeit, alles, auch das einzelne Wissen, in den Zusammenhang mit dem Ursprünglichen und Einen zu erblicken, hängt es ab, ob man in der einzelnen Wissenschaft mit Geist und mit derjenigen höhern Eingebung arbeite, die man wissenschaftliches Genie nennt. Jeder Gedanke, der nicht in diesem Geiste der Ein- und Allheit gedacht ist, ist in sich selbst leer und verwerflich; was nicht harmonisch einzugreifen fähig ist in dieses treibende und lebende Ganze, ist ein todter Absatz, der nach organischen Gesetzen früher oder später ausgestoßen wird, und freilich gibt es auch im Reiche der Wissenschaft geschlechtslose Bienen genug, die, weil ihnen zu produciren versagt ist, durch anorgische Absätze nach außen ihre eigne Geistlosigkeit in Abdrücken vervielfältigen. Indem ich jene Idee von der Bestimmung alles Wissens ausgesprochen habe, habe ich von der Würde der Wissenschaft an sich selbst nichts mehr hinzuzufügen: keine Norm der Ausbildung oder der Aufnahme der Wissenschaft in sich selbst, die ich in dem Folgenden aufstellen kann, wird aus einem andern Grunde als dieser Einen Idee fließen. Von Pythagoras erzählen die Geschichtschreiber der Philosophie, daß er den bis auf seine Zeit gangbaren Namen der Wissenschaft, σοφία, zuerst in den der φιλοσοφία, der Liebe zur Weisheit, verwandelt habe, aus dem Grunde, weil außer Gott niemand weise sey. Wie es sich mit der historischen Wahrheit dieses Berichts verhalte, so ist doch"}]}, {"page_pdf": 1532, "page_book": 218, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "in jener Umänderung selbst wie in dem angegebenen Grund anerkannt, daß alles Wissen ein Streben nach Gemeinschaft mit dem göttlichen Wesen, eine Theilnahme an demjenigen Urwissen sey, dessen Bild das sichtbare Universum und dessen Geburtsstätte das Haupt der ewigen Macht ist. Nach derselbigen Ansicht, da alles Wissen nur Eines ist, und jede Art desselben nur als Glied eintritt in den Organismus des Ganzen, sind alle Wissenschaften und Arten des Wissens Theile der Einen Philosophie, nämlich des Strebens, an dem Urwissen Theil zu nehmen. Alles nun, was unmittelbar aus dem Absoluten als seiner Wurzel stammt, ist selbst absolut, demnach ohne Zweck außer sich, selbst Zweck. Das Wissen, in seiner Allheit, ist aber die eine, gleich absolute Erscheinung des Einen Universum, von dem das Seyn oder die Natur die andere ist. Im Gebiet des Realen herrscht die Endlichkeit, im Gebiet des Idealen die Unendlichkeit; jenes ist durch Nothwendigkeit das, was es ist, dieses soll es durch Freiheit seyn. Der Mensch, das Vernunftwesen überhaupt, ist hingestellt, eine Ergänzung der Welterscheinung zu seyn: aus ihm, aus seiner Thätigkeit soll sich entwickeln, was zur Totalität der Offenbarung Gottes fehlt, da die Natur zwar das ganze göttliche Wesen, aber nur im Realen, empfängt; das Vernunftwesen soll das Bild derselben göttlichen Natur, wie sie an sich selbst ist, demnach im Idealen ausdrücken. Wir haben gegen die Unbedingtheit der Wissenschaft einen sehr gangbaren Einwurf zu erwarten, dem wir einen höhern Ausdruck leihen wollen, als er gewöhnlich annimmt, nämlich: daß von jener in der Unendlichkeit zu entwerfenden Darstellung des Absoluten das Wissen selbst nur ein Theil, in ihr wieder nur als Mittel begriffen sey, zu dem sich das Handeln als Zweck verhalte. Handeln, Handeln! ist der Ruf, der zwar von vielen Seiten ertönt, am lautesten aber von denjenigen angestimmt wird, bei denen es mit dem Wissen nicht fort will. Es hat viel Empfehlendes für sich, zum Handeln aufzufordern. Handeln, denkt man, kann jeder, denn dieß hängt nur vom freien"}, {"type": "paragraph", "text": "Willen ab. Wissen aber, besonders philosophisches, ist nicht jedermanns Ding, und, ohne andere Bedingungen, auch mit dem besten Willen nichts darin auszurichten. Wir stellen die Frage über den vorliegenden Einwurf gleich so: Was mag das für ein Handeln seyn, zu dem sich das Wissen als Mittel, und das für ein Wissen, welches sich zum Handeln als dem Zweck verhält? Welcher Grund überhaupt nur der Möglichkeit einer solchen Entgegensetzung läßt sich aufzeigen? Wenn die Sätze, die ich hier in Anregung bringen muß, nur in der Philosophie ihr vollkommenes Licht von allen Seiten erhalten können, so verhindert dieß nicht, daß sie wenigstens für die gegenwärtige Anwendung verständlich sey'n. Wer nur überhaupt die Idee des Absoluten gefaßt hat, sieht auch ein, daß in ihm nur Ein Grund möglicher Entgegensetzung gedacht werden kann, und daß also, wenn überhaupt aus ihm Gegensätze begriffen werden können, alle aus jenem Einen fließen müssen. Die Natur des Absoluten ist: als das absolut Ideale auch das Reale zu seyn. In dieser Bestimmung liegen die zwei Möglichkeiten, daß es als Ideales seine Wesenheit in die Form, als das Reale, bildet, und daß es, weil diese in ihm nur eine absolute seyn kann, auf ewig gleiche Weise auch die Form wieder in das Wesen auflöst, so daß es Wesen und Form in vollkommener Durchdringung ist. In diesen zwei Möglichkeiten besteht die Eine Handlung des Urwissens; da es aber schlechthin untheilbar, also ganz und durchaus Realität und Idealität ist, so muß von dieser untrennbaren Duplicität auch in jedem Akt des absoluten Wissens ein Ausdruck und in dem, was im Ganzen als das Reale, wie in dem, was als das Ideale"}]}, {"page_pdf": 1533, "page_book": 220, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "erscheint, beides in Eins gebildet seyn. Wie also in der Natur als Bild der göttlichen Verwandlung der Idealität in die Realität auch wieder die Umwandlung der letzten in die erste durch das Licht und vollendet durch die Vernunft erscheint, so muß dagegen in dem, was im Ganzen als das Ideale begriffen wird, gleichfalls wieder eine reale und ideale Seite angetroffen werden, wovon jene die Idealität in der"}, {"type": "paragraph", "text": "Realität, aber als ideal, diese die entgegengesetzte Art der Einheit erkennen läßt. Die erste Erscheinungsart ist das Wissen, inwiefern in diesem die Subjektivität in der Objektivität erscheint, die andere ist das Handeln, inwiefern in diesem vielmehr eine Aufnahme der Besonderheit in die Allgemeinheit gedacht wird1. Es ist hinreichend, diese Verhältnisse auch nur in der höchsten Abstraktion zu fassen, um einzusehen, daß die Entgegensetzung, in welcher die beiden Einheiten innerhalb der gleichen Identität des Urwissens, als Wissen und Handeln erscheinen, nur für die bloß endliche Auffassung stattfindet; denn es ist von sich selbst klar, daß, wenn in dem Wissen das Unendliche sich dem Endlichen auf ideale Art, im Handeln auf gleiche Weise die Endlichkeit sich der Unendlichkeit einbildet, jede von beiden in der Idee oder dem An-sich die gleiche absolute Einheit des Urwissens ausdrücke. Das zeitliche Wissen ebenso wie das zeitliche Handeln setzt nur auf bedingte Weise und successiv, was in der Idee auf unbedingte Weise und zumal ist, deßhalb erscheinen in jenem Wissen und Handeln ebenso nothwendig getrennt, als sie in dieser, wegen der gleichen Absolutheit, Eines sind, wie in Gott als der Idee aller Ideen die absolute Weisheit unmittelbar dadurch, daß sie absolut ist, auch unbedingte Macht, ohne Vorausgehen der Idee als Absicht, wodurch das Handeln bestimmt wäre, demnach zugleich absolute Nothwendigkeit ist. Es verhält sich mit diesen, wie mit allen andern Gegensätzen, daß sie nur sind, solange jedes Glied nicht für sich absolut, demnach bloß mit dem endlichen Verstand aufgefaßt wird. Der Grund der gemachten Entgegensetzung liegt demnach allein in einem gleich unvollkommenen Begriff vom Wissen und vom Handeln, welches dadurch erhoben werden soll, daß man das Wissen als Mittel zu ihm begreift. Zu dem wahrhaft absoluten Handeln kann das Wissen kein solches Verhältniß haben; denn dieses kann, eben weil es absolut ist, nicht durch ein Wissen bestimmt seyn. Dieselbe Einheit, die im Wissen, bildet sich"}, {"type": "footnote", "text": "1 Vergl. die Abhandlung über das Verhältniß der Naturphilosophie zur Philosophie überhaupt, S. 122 unten. D. H."}, {"type": "paragraph", "text": "auch im Handeln zu einer absoluten in sich gegründeten Welt aus. Vom erscheinenden Handeln ist hier so wenig die Rede als vom erscheinenden Wissen: eines steht und fällt mit dem andern, denn jedes hat allerdings nur im Gegensatz gegen das andere Realität1. Diejenigen, welche das Wissen zum Mittel, das Handeln zum Zweck machen, haben von jenem keinen Begriff, als den sie aus dem täglichen Thun und Treiben genommen haben, so wie dann auch das Wissen darnach seyn muß, um das Mittel zu diesem zu werden. Die Philosophie soll sie lehren, im Leben ihre Pflicht zu thun; dazu bedürfen sie also der Philosophie: sie thun solche nicht aus freier Nothwendigkeit, sondern als Unterworfene eines Begriffs, den ihnen die Wissenschaft an die Hand gibt. Allgemein soll die Wissenschaft dienen, ihnen das Feld zu bestellen, die Gewerbe zu vervollkommnen oder ihre verdorbenen Säfte zu verbessern. Die Geometrie, meinen sie, ist eine schöne Wissenschaft, nicht zwar,"}]}, {"page_pdf": 1534, "page_book": 222, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "weil sie die reinste Evidenz, der objektivste Ausdruck der Vernunft selbst ist, sondern weil sie das Feld messen und Häuser bauen lehrt, oder die Handelsschifffahrt möglich macht; denn daß sie auch zum Kriegführen dient, mindert ihren Werth, weil der Krieg doch ganz gegen die allgemeine Menschenliebe ist. Die Philosophie ist nicht einmal zu jenem und höchstens zu dem letzten gut, nämlich gegen die seichten Köpfe und die Nützlichkeitsapostel in der Wissenschaft Krieg zu führen, und darum auch im Grunde höchst verwerflich. Die den Sinn jener absoluten Einheit des Wissens und Handelns nicht fassen, bringen dagegen solche Popularitäten vor, daß, wenn das Wissen mit dem Handeln eins wäre, dieses immer aus jenem folgen müßte, da man doch sehr gut das Rechte wissen könne, ohne es deßwegen zu thun, und was dergleichen mehr ist. Sie haben ganz Recht, daß das Handeln aus dem Wissen nicht folge, und sie sprechen eben in jener Reflexion aus, daß das Wissen nicht Mittel des Handelns sey. Sie haben nur darin Unrecht, eine solche Folge zu erwarten. Sie begreifen keine Verhältnisse zwischen Absoluten; nicht, wie jedes"}, {"type": "footnote", "text": "1 Vergl. die eben angeführte Stelle. D. H."}, {"type": "paragraph", "text": "Besondere für sich unbedingt seyn kann, und machen das eine im Verhältniß des Zwecks so gut wie das andere im Verhältniß des Mittels zu einem Abhängigen. Wissen und Handeln können nie anders in wahrer Harmonie seyn als durch die gleiche Absolutheit. Wie es kein wahres Wissen gibt, welches nicht mittelbar oder unmittelbar Ausdruck des Urwissens ist, so kein wahres Handeln, welches nicht, und wär' es durch noch so viele Mittelglieder, das Urhandeln und in ihm das göttliche Wesen ausdrückt. Diejenige Freiheit, die man in dem empirischen Handeln sucht oder zu erblicken glaubt, ist ebensowenig wahre Freiheit und ebenso Täuschung, wie die Wahrheit, die im empirischen Wissen. Es gibt keine wahre Freiheit, als durch absolute Nothwendigkeit1, und zwischen jener und dieser ist selbst wieder das Verhältniß, wie zwischen absolutem Wissen und absolutem Handeln2."}, {"type": "footnote", "text": "1 Sie hat sich mit der Nothwendigkeit zu integriren. 2 In der Freiheit, d.h. im Handeln selbst, stellt sich daher die Nothwendigkeit her, sowie nur dagegen ein wahrhaft absolutes Wissen zugleich ein Wissen mit absoluter Nothwendigkeit und mit absoluter Freiheit ist."}, {"type": "heading", "text": "Zweite Vorlesung. *Ueber die wissenschaftliche und sittliche Bestimmung der Akademien.*", "level": null}, {"type": "paragraph", "text": "Der Begriff des akademischen Studiums wies uns einerseits zu dem höhern Begriff eines vorhandenen Ganzen von Wissenschaften zurück, welches wir in seiner obersten Idee, dem Urwissen, zu fassen suchten; andererseits führt er uns auf die besondern Bedingungen, unter welchen die Wissenschaften auf unsern Akademien gelehrt und mitgetheilt werden."}]}, {"page_pdf": 1535, "page_book": 224, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Wohl könnte es des Philosophen würdiger scheinen, von dem Ganzen der Wissenschaften ein unabhängiges Bild zu entwerfen und die Art der ersten Erkenntniß desselben an sich selbst, ohne Beziehung auf die Formen bloß gegenwärtiger Einrichtungen, vorzuschreiben. Allein ich glaube in dem Folgenden beweisen zu können, daß eben auch diese Formen in dem Geist der neueren Welt nothwendig waren, und wenigstens äußere Bedingungen der Wechseldurchdringung der verschiedenartigen Elemente ihrer Bildung so lange seyn werden, bis durch jene die trübe Mischung der letztern sich zu schöneren Organisationen geläutert haben wird. Der Grund, warum das Wissen überhaupt seiner Erscheinung nach in die Zeit fällt, ist schon in dem zuvor Abgehandelten enthalten. Wie die sich in der Endlichkeit reflektirende Einheit des Idealen und Realen"}, {"type": "paragraph", "text": "als beschlossene Totalität, als Natur, im Raum sich ausdrückt, so erscheint dieselbe im Unendlichen angeschaut unter der allgemeinen Form der endlosen Zeit. Aber die Zeit schließt die Ewigkeit nicht aus, und die Wissenschaft, wenn sie ihrer Erscheinung nach eine Geburt der Zeit ist, geht doch auf Gründung einer Ewigkeit mitten in der Zeit. Was wahr ist, ist wie das, was an sich selbst recht und schön ist, seiner Natur nach ewig, und hat mitten in der Zeit kein Verhältniß zu der Zeit. Sache der Zeit ist die Wissenschaft nur, inwiefern sie durch das Individuum sich ausspricht. Das Wissen an sich ist aber so wenig Sache der Individualität als das Handeln an sich. Wie die wahre Handlung diejenige ist, die gleichsam im Namen der ganzen Gattung geschehen könnte, so [ist] das wahre Wissen [nur] dasjenige, worin nicht das Individuum, sondern die Vernunft weiß1. Diese Unabhängigkeit des Wesens der Wissenschaft von der Zeit drückt sich in dem aus, daß sie Sache der Gattung ist, welche selbst ewig ist. Es ist also nothwendig, daß, wie das Leben und Daseyn, so die Wissenschaft sich von Individuum an Individuum, von Geschlecht zu Geschlecht mittheile. Ueberlieferung ist der Ausdruck ihres ewigen Lebens. Es wäre hier nicht der Ort, mit allen Gründen, deren diese Behauptung fähig ist, zu beweisen, daß alle Wissenschaft und Kunst des gegenwärtigen Menschengeschlechts eine überlieferte ist. Es ist undenkbar, daß der Mensch, wie er jetzt erscheint, durch sich selbst sich vom Instinkt zum Bewußtseyn, von der Thierheit zur Vernünftigkeit erhoben habe. Es mußte also dem gegenwärtigen Menschengeschlecht ein anderes vorgegangen seyn, welches die alte Sage unter dem Bilde der Götter und ersten Wohlthäter des menschlichen Geschlechts verewigt hat. Die Hypothese eines Urvolks erklärt blos etwa die Spuren einer hohen Kultur in der Vorwelt, von der wir die schon entstellten Reste nach der ersten Trennung der Völker finden, und etwa die Uebereinstimmung in den Sagen der ältesten Völker, wenn man nichts auf die Einheit des allem eingebornen Erdgeistes rechnen will, aber sie erklärt keinen *ersten*"}, {"type": "footnote", "text": "1 Vergl. die Abhandlung über die Construktion in der Philosophie, S. 140. D. H."}, {"type": "paragraph", "text": "Anfang und schiebt, wie jede empirische Hypothese, die Erklärung nur weiter zurück. Wie dem auch sey, so ist bekannt, daß das erste Ueberlieferungsmittel der höheren Ideen Handlungen, Lebensweise, Gebräuche, Symbole gewesen sind, wie selbst die Dogmen der frühesten Religionen nur in Anweisungen zu religiösen Gebräuchen enthalten waren. Die Staatenbildungen, die Gesetze, die einzelnen Anstalten, die errichtet waren, das Uebergewicht des göttlichen Princips in der Menschheit zu"}]}, {"page_pdf": 1536, "page_book": 226, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "erhalten [seinen Kampf gegen das ungöttliche zu unterstützen], waren ihrer Natur nach ebenso viele Ausdrücke speculativer Ideen. Die Erfindung der Schrift gab der Ueberlieferung zunächst nur eine größere Sicherheit [verminderte die Gefahr, den Sinn der Symbole zu vergessen]; der Gedanke, in dem geistigen Stoff der Rede auch einen Ausdruck der Form und Kunst niederzulegen, der einen dauernden Werth hätte, konnte erst später erwachen. Wie in der schönsten Blüthe der Menschheit selbst die Sittlichkeit nicht gleichsam dem Individuum eignete, sondern Geist des Ganzen war, aus dem sie aus- und in das sie zurückfloß, so lebte auch die Wissenschaft in dem Licht und Aether des öffentlichen Lebens und einer allgemeinen Organisation. Wie überhaupt die spätere Zeit das Reale zurückdrängte und das Leben innerlicher machte, so auch das der Wissenschaft. Die neuere Welt ist in allem, und besonders in der Wissenschaft eine getheilte Welt, die in der Vergangenheit und Gegenwart zugleich lebt. In dem Charakter aller Wissenschaften drückt es sich aus, daß die spätere Zeit von dem historischen Wissen ausgehen mußte, daß sie eine untergegangene Welt der herrlichsten und größten Erscheinungen der Kunst und Wissenschaft hinter sich hatte, mit der sie, durch eine unübersteigliche Kluft [eine Masse von Barbarei] von ihr getrennt, nicht durch das innere Band einer organisch-fortgehenden Bildung, sondern einzig durch das äußere Band der historischen Ueberlieferung zusammenhing. Der auflebende Trieb konnte sich im ersten Wiederbeginn der Wissenschaften in unserm Welttheil nicht ruhig oder ausschließlich auf das eigne Produciren, sondern nur unmittelbar zugleich auf das Verstehen, Bewundern und"}, {"type": "paragraph", "text": "Erklären der vergangenen Herrlichkeiten richten. Zu den ursprünglichen Gegenständen des Wissens trat das vergangene Wissen darüber als ein neuer Gegenstand hinzu; daher und weil zur tiefen Ergründung des Vorhandenen selbst gegenwärtiger Geist erfordert wird, wurden Gelehrter, Künstler und Philosoph gleichbedeutende Begriffe, und das erste Prädicat auch demjenigen zuerkannt, der das Vorhandene mit keinem eignen Gedanken vermehrt hatte; und wenn die Griechen, wie ein ägyptischer Priester zu Solon sagte, ewig jung waren, so war die moderne Welt dagegen in ihrer Jugend schon alt und erfahren. Das Studium der Wissenschaften wie der Künste in ihrer historischen Entwicklung ist zu einer Art der Religion geworden: in ihrer Geschichte erkennt der Philosoph noch unenthüllter gleichsam die Absichten des Weltgeistes; die tiefste Wissenschaft, das gründlichste Genie hat sich in diese Kenntniß ergossen. [Den Bewegungen der äußeren Welt entsprechen nach einem nothwendigen Gesetz die stilleren, aber deßwegen nicht minder tiefgreifenden Metamorphosen, die in dem Geiste des Menschen selbst vorgehen. Zu glauben, daß die geistigen Veränderungen, die Revolutionen der Wissenschaften, die Ideen, die sie erzeugt, die Werke selbst, in denen sich ein bestimmter wissenschaftlicher oder Kunst-Geist ausgesprochen hat, ohne Nothwendigkeit seyen, und nicht nach einem Gesetz sondern durch Zufall entstehen, ist die höchste Barbarei. Ewig heilig ist und sey uns das Alterthum; es ist Pietät, zu den Resten des Alterthums und der gesammten Vorwelt zu wallfahrten, wie es Religion ist, wenn die fromme Einfalt die geglaubten Reliquien eines Heiligen sucht. Emsig, sagt Goethe,"}, {"type": "footnote", "text": "Emsig wallet der Pilger, und wird er den Heiligen finden,"}, {"type": "footnote", "text": "Hören und sehen den Mann, welcher die Wunder gethan? Nein, es führte die Zeit ihn hinweg; du findest nur Reste,"}, {"type": "footnote", "text": "Seinen Schädel, ein paar seiner Gebeine verwahrt, Wir sind alle Pilger, die wir das Alterthum suchen,"}, {"type": "footnote", "text": "Nur ein zerstreutes Gebein ehren wir gläubig und froh."}, {"type": "paragraph", "text": "Aber] ein anderes ist, das Vergangene selbst zum Gegenstand der Wissenschaft zu machen, ein"}]}, {"page_pdf": 1537, "page_book": 227, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "anderes, die Kenntniß davon an die Stelle"}, {"type": "paragraph", "text": "des Wissens selbst zu setzen. Durch das historische Wissen in diesem Sinn wird der Zugang zu dem Urbild verschlossen; es fragt sich dann nicht mehr, ob irgend etwas mit dem An-sich des Wissens, sondern ob es mit irgend etwas Abgeleitetem, welches von jenem ein bloß unvollkommenes Abbild ist, übereinstimme. Aristoteles hatte in seinen Schriften die Naturlehre und Naturgeschichte betreffend die Natur selbst gefragt; in den spätern Zeiten hatte sich das Andenken davon so völlig verloren, daß er selbst an die Stelle des Urbilds trat und gegen die deutlichen Aussprüche der Natur durch Cartesius, Kepler u.a. seine Auctorität zum Zeugen aufgerufen wurde. Nach derselben Art historischer Bildung hat für einen großen Theil der sogenannten Gelehrten bis auf diesen Tag keine Idee Bedeutung und Realität, ehe sie durch andere Köpfe gegangen, historisch und eine Vergangenheit geworden ist. Mehr oder weniger in diesem Geist des historischen Wissens sind, nicht so sehr vielleicht im ersten Beginn der wiedererwachenden Literatur, als in viel späteren Zeiten, unsere Akademien errichtet worden. Ihre ganze wissenschaftliche Organisation möchte sich nur vollständig aus diesem Abtrennen des Wissens von seinem Urbild durch historische Gelehrsamkeit ableiten lassen. Vorerst ist die große Masse dessen, was gelernt werden muß, nur um im Besitz des Vorhandenen zu seyn, die Ursache gewesen, daß man das Wissen so weit wie möglich in verschiedene Zweige zerspaltet und den lebendigen organischen Bau des Ganzen bis ins Kleinste zerfasert hat. Da alle isolirten Theile des Wissens, alle besonderen Wissenschaften also, sofern der universelle Geist aus ihnen gewichen ist, überhaupt nur Mittel zum absoluten Wissen seyn können, so war die nothwendige Folge jenes Zerstückelns, daß über den Mitteln und Anstalten zum Wissen das *Wissen selbst* so gut wie verloren gegangen ist, und während eine geschäftige Menge die Mittel für den Zweck selbst hielt und als Zweck geltend zu machen suchte, jenes, welches nur Eines und in seiner Einheit absolut ist, sich ganz in die obersten Theile zurückzog und auch in diesen zu jeder Zeit nur seltene Erscheinungen eines unbeschränkten Lebens gegeben hat."}, {"type": "paragraph", "text": "Wir haben in dieser Rücksicht vorzüglich die Frage zu beantworten: welche Forderungen selbst innerhalb der angenommenen Beschränkung und in den gegenwärtigen Formen unserer Akademien an diese gemacht werden können, damit aus dieser durchgängigen Trennung im Einzelnen gleichwohl wieder eine Einheit im Ganzen entspringe. Ich werde diese Frage nicht beantworten können, ohne zugleich von den nothwendigen Forderungen an diejenigen, welche eine Akademie permanent constituiren, an die Lehrer also, zu reden. Ich werde mich nicht scheuen, hierüber vor *Ihnen* mit aller Freimüthigkeit zu sprechen. Der Eintritt in das akademische Leben ist in Ansehung des studirenden Jünglings zugleich [der erste Eintritt in die Mündigkeit], die erste Befreiung vom blinden Glauben, er soll hier zuerst lernen und sich üben selbst zu urtheilen. Kein Lehrer, der seines Berufs würdig ist, wird eine andere Achtung verlangen, als die er sich durch Geistesübergewicht, durch wissenschaftliche Bildung und seinen Eifer, diese allgemeiner zu verbreiten, erwerben kann. Nur der Unwissende, der Unfähige wird diese Achtung auf andere Stützen zu gründen suchen. Was mich noch mehr bestimmen muß, in dieser Sache ohne Rückhalt zu reden, ist folgende Betrachtung. Von den Ansprüchen, welche die Studirenden selbst an eine Akademie und die Lehrer derselben machen, hängt zum Theil die Erfüllung derselben ab, und der einmal unter ihnen geweckte wissenschaftliche Geist wirkt vortheilhaft auf das Ganze zurück, indem er den Untüchtigen durch die höheren Forderungen, die an ihn gemacht werden, zurückschreckt, den, welcher sie zu erfüllen fähig ist, zur Ergreifung dieses Wirkungskreises bestimmt."}]}, {"page_pdf": 1538, "page_book": 229, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Gegen die aus der Idee der Sache selbst fließende Forderung der Behandlung aller Wissenschaften im Geist des Allgemeinen und eines absoluten Wissens kann es kein Einwurf seyn, zu fragen: woher die Lehrer sämmtlich zu nehmen wären, die dieses zu leisten vermöchten. Die Akademien sind es ja eben, auf welchen jene ihre erste Bildung erhalten: man gebe diesen nur die geistige Freiheit, und beschränke sie nicht durch Rücksichten, die auf das wissenschaftliche Verhältniß keine Anwendung haben, so werden sich die Lehrer von selbst bilden, die"}, {"type": "paragraph", "text": "jenen Forderungen Genüge thun können und wiederum im Stande sind andere zu bilden. Man könnte fragen, ob es überhaupt zieme, gleichsam im Namen der Wissenschaft Forderungen an Akademien zu machen, da es hinlänglich bekannt und angenommen sey, daß sie Instrumente des Staats sind, die das seyn müssen, wozu dieser sie bestimmt. Wenn es nun seine Absicht wäre, daß in Ansehung der Wissenschaft durchgehends eine gewisse Mäßigkeit, Zurückhaltung, Einschränkung auf das Gewöhnliche oder Nützliche beobachtet würde, wie sollte dann von den Lehrern progressive Tendenz und Lust zur Ausbildung ihrer Wissenschaft nach Ideen erwartet werden können? Es versteht sich wohl von selbst, daß wir gemeinschaftlich voraussetzen und voraussetzen müssen: der Staat wolle in den Akademien wirklich wissenschaftliche Anstalten sehen, und daß alles, was wir in Ansehung ihrer behaupten, nur unter dieser Bedingung gilt. Der Staat wäre unstreitig befugt, die Akademien ganz aufzuheben oder in Industrie- und andere Schulen von ähnlichen Zwecken umzuwandeln; aber er kann nicht das Erste beabsichtigen, ohne zugleich auch das Leben der Ideen und die freieste wissenschaftliche Bewegung zu wollen, durch deren Versagung aus kleinlichen, meistens nur die Ruhe der Unfähigen in Schutz nehmenden Rücksichten das Genie zurückgestoßen, das Talent gelähmt wird. - [Die gewöhnliche Ansicht von Universitäten ist: \"sie sollen dem Staat seine Diener bilden zu vollkommenen Werkzeugen seiner Absichten.\" Diese Werkzeuge sollen doch aber ohne Zweifel durch *Wissenschaft* gebildet werden. Will man also jenen Zweck der Bildung, so muß man auch die Wissenschaft wollen. Die Wissenschaft aber hört als Wissenschaft auf, sobald sie zum *bloßen* Mittel herabgesetzt und nicht zugleich um ihrer selbst willen gefördert wird. Um ihrer selbst willen wird sie aber sicher nicht gefördert, wenn Ideen z.B. aus dem Grund zurückgewiesen werden, weil sie keinen Nutzen für das gemeine Leben haben, von keiner praktischen Anwendung, keines Gebrauchs in der Erfahrung fähig sind. Denn dieß kann wohl der Fall seyn, in Beziehung nämlich auf die Erfahrung, wie sie eben vorhanden"}, {"type": "paragraph", "text": "ist, oder die Erfahrung, die man so nennt, welche eben durch Vernachlässigung aller Ideen das geworden ist, das sie ist, und eben deßhalb nicht mit ihnen übereinstimmen kann. Was rechte, was wirkliche Erfahrung sey, muß erst durch die Ideen bestimmt werden. Die Erfahrung ist wohl gut, wenn sie *ächte* Erfahrung ist, aber eben ob sie das ist, und inwiefern, und was denn in der Erfahrung das eigentlich Erfahrene ist, ist die große Frage. So ist z.B. die Newtonsche Optik angeblich ganz auf Erfahrungen gegründet und nichtsdestoweniger in ihrer Grundansicht, so wie in allen ihren weiteren Folgerungen, als falsch erkennbar, sobald man zuvörderst die *Idee* des Lichtes hat. - So mag allerdings die vorgebliche Erfahrung der Aerzte in manchen Punkten der richtigen aus Ideen geflossenen Theorie widerstreiten; allein wenn z.B. der Arzt selbst erst die Symptome der Krankheit schafft, und diese dann für freiwillige Naturwirkungen ausgibt, so ist hier ohne Zweifel keine reine Erfahrung: vielmehr hätte der Arzt die Krankheit gleich nach der richtigen, aus Ideen fließenden Ansicht behandelt, so wären ihm jene"}]}, {"page_pdf": 1539, "page_book": 231, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Erscheinungen gar nicht entstanden, und er würde sie nicht zu seiner *Erfahrung* zählen, oder wenigstens in ihnen keinen Widerspruch gegen die wahre Theorie sehen. Es gilt von theoretischen Ideen dasselbe, was Kant von praktischen sagt: nämlich daß nichts Schädlicheres und Unwürdigeres gefunden werde, als die Berufung auf Erfahrung, die doch gar nicht existiren würde, wäre sie gleich mit besseren Ansichten und nicht nach rohen Begriffen angestellt worden. - Ich kehre von dieser Abschweifung zurück.] Die äußere Vollständigkeit bringt noch keineswegs das wahre organische [Gesammt-]Leben aller Theile des Wissens hervor, welches durch die Universitäten, die hiervon ihren Namen tragen, erreicht werden soll. Hiezu bedarf es des [Lebensprincips des] gemeinschaftlichen Geistes, der aus der absoluten Wissenschaft kommt, von der die einzelnen Wissenschaften die Werkzeuge oder die objektive reale Seite seyn sollen. Ich kann diese Ansicht hier noch nicht ausführen; indeß ist klar, daß von keiner Anwendung der Philosophie die Rede ist, dergleichen auf beinahe alle Fächer nach und nach versucht worden, ja"}, {"type": "paragraph", "text": "sogar auf die in Bezug auf sie niedrigsten Gegenstände, so daß man fast auch die Landwirthschaft, die Entbindungskunst oder Bandagenlehre philosophisch zu machen sich bestrebt hat. Es kann nicht leicht etwas Thörichteres [und für den Philosophen selbst Lächerlicheres] geben, als das Bestreben von Rechtsgelehrten oder Aerzten, ihre Scienz mit einem [äußeren] philosophischen Ansehen zu bekleiden, während sie über die ersten Grundsätze der Philosophie in Unwissenheit sind, gleichwie wenn jemand eine Kugel, einen Cylinder oder ein anderes Solidum ausmessen wollte, dem nicht einmal der erste Satz des Euklides bekannt wäre. Nur von der Formlosigkeit in den meisten objektiven Wissenschaften rede ich, worin sich auch nicht eine Ahndung von Kunst oder nur die logischen Gesetze des Denkens ausdrücken, von derjenigen Stumpfheit, die mit keinem Gedanken sich über das Besondere erhebt, noch sich vorzustellen vermag, daß sie auch in dem sinnlichen Stoff das Unsinnliche, das Allgemeine darzustellen habe. Nur das schlechthin Allgemeine ist die Quelle der Ideen, und Ideen sind das Lebendige der Wissenschaft. Wer sein besonderes Lehrfach nur als besonderes kennt und nicht fähig ist, weder das Allgemeine in ihm zu erkennen noch den Ausdruck einer universell-wissenschaftlichen Bildung in ihm niederzulegen, ist unwürdig, Lehrer und Bewahrer der Wissenschaften zu seyn. Er wird sich auf vielfache Weise nützlich machen können, als Physiker mit Errichtung von Blitzableitern, als Astronom mit Kalendermachen, als Arzt mit der Anwendung des Galvanismus in Krankheiten oder auf welche andere Weise er will; aber der Beruf des Lehrers fordert höhere als Handwerkertalente. \"Das Abpflöcken der Felder der Wissenschaften, sagt Lichtenberg, mag seinen großen Nutzen haben bei der Vertheilung unter die *Pächter*; aber den Philosophen, der immer den Zusammenhang des Ganzen vor Augen hat, warnt seine nach Einheit strebende Vernunft bei jedem Schritte, auf keine Pflöcke zu achten, die oft Bequemlichkeit und oft Eingeschränktheit eingeschlagen haben.\" Ohne Zweifel war es nicht die besondere Geschicklichkeit in seiner Wissenschaft, sondern das Vermögen, sie mit den Ideen eines bis zur Allgemeinheit ausgebildeten"}, {"type": "paragraph", "text": "Geistes zu durchdringen, wodurch Lichtenberg der geistreichste Physiker seiner Zeit und der vortrefflichste Lehrer seines Fachs gewesen ist. Ich muß hier eine Vorstellung berühren, die sich diejenigen, an welche die Forderung ihr besonderes Fach im Geist des Ganzen zu behandeln, gemacht wird, gewöhnlich davon machen, nämlich, als werde verlangt, sie sollen es als *bloßes* Mittel betrachten; es ist aber vielmehr das gerade Gegentheil der Fall:"}]}, {"page_pdf": 1540, "page_book": 233, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "daß jeder seine Wissenschaft in dem Verhältniß im Geist des Ganzen betreibt, in welchem er sie als Zweck an sich selbst und als absolut [als selbständig] betrachtet. Schon an sich selbst kann nichts als Glied in einer wahren Totalität begriffen seyn, was in ihm bloß als Mittel wirkt. Jeder Staat ist in dem Verhältniß vollkommen, in welchem jedes einzelne Glied, indem es Mittel zum Ganzen, zugleich in sich selbst Zweck ist. Eben dadurch, daß das Besondere in sich absolut ist, ist es auch wieder im Absoluten und integranter Theil desselben, und umgekehrt. Je mehr ein Gelehrter seinen besondern Kreis als Zweck an sich selbst begreift, ja ihn für sich wieder zum Mittelpunkt alles Wissens macht, den er zur allbefassenden Totalität erweitern möchte [in dem er das ganze Universum reflektirt möchte], desto mehr bestrebt er sich, Allgemeines und Ideen in ihm auszudrücken. Dagegen je weniger er vermag, ihn mit universellem Sinn zu fassen, desto mehr wird er ihn, er mag sich nun dessen bewußt oder nicht bewußt seyn, weil das, was nicht Zweck an sich selbst ist, nur Mittel seyn kann, nur als Mittel begreifen. Dies müßte nun billig jedem, der sich selbst ehrt, unerträglich seyn; daher mit dieser Beschränktheit gewöhnlich auch die gemeine Gesinnung und der Mangel des *wahren* Interesse an der Wissenschaft, außer dem, welches sie als Mittel für sehr reale, äußere Zwecke hat, vergesellschaftet ist. Ich weiß recht gut, daß sehr viele und vornehmlich alle die, welche die Wissenschaft überhaupt nur als Nützlichkeit begreifen, die Universitäten als bloße Anstalten zur Ueberlieferung des Wissens, als einen Verein betrachten, der bloß die Absicht hätte, daß jeder in der Jugend lernen könnte, was bis zu seiner Zeit in den Wissenschaften"}, {"type": "paragraph", "text": "geleistet worden ist, so daß es auch als eine Zufälligkeit betrachtet werden müßte, wenn die Lehrer außer dem, daß sie das Vorhandene mittheilen, auch noch die Wissenschaft durch eigne Erfindungen bereichern; - allein selbst angenommen, daß mit den Akademien zunächst nicht mehr als dieses beabsichtigt würde und werden sollte, so fordert man doch ohne Zweifel zugleich, daß die Ueberlieferung mit Geist geschehe, widrigenfalls begreift man nicht, wofür nur überhaupt der lebendige Vortrag auf Akademien nothwendig wäre; man könnte alsdann den Lehrling unmittelbar nur an die ausdrücklich für ihn geschriebenen, gemeinfaßlichen Handbücher oder an die dicken Compilationen in allen Fächern verweisen. Zu einer geistreichen Ueberlieferung gehört aber ohne Zweifel, daß man im Stande sey, die Erfindungen anderer aus der vergangenen und gegenwärtigen Zeit richtig, scharf und in allen Beziehungen aufzufassen. Viele derselben sind von der Art, daß ihr innerster Geist nur durch homogenes Genie, durch wirkliches Nacherfinden gefaßt werden kann. Jemand, der bloß überliefert, wird also in vielen Fällen in manchen Wissenschaften durchaus falsch überliefern. Wo ist denn diejenige historische Darstellung der Philosophie der alten Zeit oder nur eines einzelnen Philosophen der alten oder selbst der neueren Welt, die man als eine gelungene, wahre, ihren Gegenstand erreichende Darstellung mit Sicherheit bezeichnen könnte? - Aber überhaupt, wer in seiner Wissenschaft nur wie in einem fremden Eigenthume lebt, wer sie nicht persönlich besitzt, sich ein sicheres und lebendiges Organ für sie erworben hat, sie nicht in jedem Augenblick neu aus sich zu erzeugen anfangen könnte, ist ein Unwürdiger, der schon in dem Versuch, die Gedanken der Vorwelt oder Gegenwart bloß historisch zu überliefern, über seine Grenze geht und etwas übernimmt, das er nicht leisten kann. Ohne Zweifel rechnet man zu einer geistreichen Ueberlieferung, daß sie mit Urtheil verbunden sey; aber wenn schon das allseitige und richtige Auffassen fremder Erfindungen ohne eignes Vermögen zu Ideen unmöglich ist, wie viel unmöglicher noch das Urtheilen? Daß in Deutschland so viel von solchen geurtheilt wird, aus denen, wenn man sie auf den Kopf stellte, kein eigner"}]}, {"page_pdf": 1541, "page_book": 235, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Gedanke herausfiele, beweist nichts; mit solchen Urtheilen, als diese zu geben im Stande sind, wäre der Wissenschaft gewiß nicht gedient. Die nothwendige Folge des Unvermögens, das Ganze seiner Wissenschaft sich aus sich selbst zu construiren und aus innerer, lebendiger Anschauung darzustellen, ist der bloß historische Vortrag derselben, z.B. der bekannte in der Philosophie: \"Wenn wir unsere Aufmerksamkeit auf uns selbst richten, so werden wir verschiedene Aeußerungen dessen gewahr, was man die Seele nennt. - Man hat diese verschiedenen Wirkungen auf verschiedene Vermögen zurückgebracht. - Man nennt diese Vermögen nach der Verschiedenheit der Aeußerungen Sinnlichkeit, Verstand, Einbildungskraft u.s.w.\" Nun ist aber an sich nichts geistloser nicht nur, sondern auch geisttödtender als eine solche Darstellung; aber es kommt noch überdieß die besondere Bestimmung des akademischen Vortrags in Betracht, genetisch zu seyn. Dieß ist der wahre Vorzug der lebendigen Lehrart, daß der Lehrer nicht Resultate hinstellt, wie es der Schriftsteller pflegt, sondern daß er, in allen höheren Scienzen wenigstens, die Art zu ihnen zu gelangen selbst darstellt und in jedem Fall das Ganze der Wissenschaft gleichsam erst vor den Augen des Lehrlings entstehen läßt. Wie soll nun derjenige, der seine Wissenschaft selbst nicht aus eigner Construktion besitzt, fähig seyn, sie nicht als ein Gegebenes, sondern als ein zu Erfindendes darzustellen? So wenig aber als die bloße Ueberlieferung ohne selbstthätigen Geist hinreichend ist, um als Lehrer mit dem gehörigen Erfolg zu wirken, ebenso sehr wird [freilich] erfordert, daß derjenige, welcher in irgend einer Wissenschaft lehren will, diese zuvor soweit gelernt habe, als möglich ist. In jeder, auch der gemeinsten Kunst wird erfordert, daß man erst Proben des vollendeten Lernens abgelegt habe, ehe man die Kunst als Meister ausüben kann. Wenn man die Leichtigkeit bedenkt, mit der auf manchen Universitäten der Lehrstuhl bestiegen wird, sollte man aber fast keinen Beruf für leichter halten als den des Lehrers; und man würde sich in der Regel sogar sehr irren, einen Trieb der eignen Produktivität für den Grund des schnellen"}, {"type": "paragraph", "text": "Lehrerberufs zu halten, da gerade den, der am ehesten zu produciren im Stande ist, das Lernen am wenigsten Verleugnung kosten kann. Wir haben bisher untersucht, wie die Universitäten auch nur der ersten Absicht nach, in der sie errichtet wurden, seyn könnten. Es scheint aber, daß sie wegen der Einseitigkeit der Idee, die ihnen ursprünglich zu Grunde liegt, weiter zu streben haben. Wir betrachteten sie dieser Idee gemäß bisher als Anstalten, die bloß für das *Wissen* errichtet sind. Da wir keine Gegensätze als wahr zugeben, z.B. den des Wissens und Handelns, so ist allgemein nothwendig, daß in dem Verhältniß, in welchem sich irgend etwas, das seinen Gegensatz in einem andern hat, seiner Absolutheit annähert, auch der Gegensatz, in dem es mit dem andern ist, sich aufhebt. So ist es demnach eine bloße Folge der Rohheit des Wissens, wenn die Akademien noch nicht angefangen haben, als Pflanzschulen der Wissenschaft zugleich allgemeine Bildungsanstalten zu seyn. Es ist nothwendig, hier zugleich die Verfassung der Akademien zu berühren, inwiefern diese auf ihre sittliche Bestimmung einen wesentlichen Einfluß hat. Wenn die bürgerliche Gesellschaft uns großentheils eine entschiedene Disharmonie der Idee und der Wirklichkeit zeigt, so ist es, weil sie vorläufig ganz andere Zwecke zu verfolgen hat, als aus jener hervorgehen, und die Mittel so übermächtig geworden sind, daß sie den Zweck selbst, zu dem sie erfunden sind, untergraben. Die Universitäten, da sie nur Verbindungen für die Wissenschaften sind, brauchen außer dem, was der Staat freiwillig und seines eignen Vortheils wegen für ihre äußere Existenz thun muß, keine andern Veranstaltungen für das Reale, als welche aus der Idee selbst fließen: die"}]}, {"page_pdf": 1542, "page_book": 236, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Weisheit vereinigt sich hier unmittelbar mit der Klugheit; man hat nur das zu thun, was die Idee des Vereins für die Wissenschaft ohnehin vorschreibt, um auch die Verfassung der Akademien vollkommen zu machen. Die bürgerliche Gesellschaft, solange sie noch empirische Zwecke zum Nachtheil der Absoluten verfolgen muß, kann nur eine scheinbare"}, {"type": "paragraph", "text": "und gezwungene, keine wahrhaft innere Identität herstellen. Akademien können nur einen absoluten Zweck haben: außer diesem haben sie gar keinen. - Der Staat hat zur Erreichung seiner Absichten Trennungen nöthig, nicht die in der Ungleichheit der Stände bestehende, sondern die weit mehr innerliche durch das Isoliren und Entgegensetzen des einzelnen Talents, die Unterdrückung so vieler Individualitäten, die Richtung der Kräfte nach so ganz verschiedenen Seiten, um sie zu desto tauglicheren Instrumenten für ihn selbst zu machen. In einem wissenschaftlichen Verein haben alle Mitglieder der Natur der Sache nach Einen Zweck; es *soll* auf Akademien nichts gelten als die Wissenschaft und kein anderer Unterschied seyn, als welchen das Talent und die Bildung macht. Menschen, die bloß da sind, um sich auf andere Weise geltend zu machen, durch Verschwendung, durch nutzlose Hinbringung der Zeit in geistlosen Vergnügungen, mit Einem Wort privilegirte Müssiggänger, wie es in der bürgerlichen Gesellschaft gibt - und gewöhnlich sind es diese, die auf Universitäten am meisten Rohheit verbreiten - sollen hier nicht geduldet, und wer seinen Fleiß und seine auf die Wissenschaft gerichtete Absicht nicht beweisen kann, soll entfernt werden. Wenn die Wissenschaft allein regiert, alle Geister nur für diese in Besitz genommen sind, so werden von selbst keine andern Mißleitungen der so edlen und herrlichen, am Ende doch vorzüglich auf Beschäftigung mit Ideen gerichteten Triebe der Jugend stattfinden können. Wenn auf Universitäten Rohheit herrschend gewesen ist oder je wieder werden könnte, so wäre es großentheils die Schuld der Lehrer oder derjenigen, welchen die Aufsicht über den Geist, der von diesen aus sich verbreitet, zukommt. Wenn die Lehrer selbst keinen andern als den ächten Geist um sich verbreiten, und keine andere Rücksichten als die des Wissens und seiner Vervollkommnung gelten, wenn die Ausbrüche der Pöbelhaftigkeit unwürdiger, den Beruf der Lehrer schändender Menschen nicht durch die Niedrigkeit des jeweiligen gemeinen Wesens selbst geduldet werden, so werden von selbst aus der Reihe der studirenden Jünglinge diejenigen"}, {"type": "paragraph", "text": "verschwinden, die sich nicht anders als durch Rohheit auszuzeichnen vermögen. Das Reich der Wissenschaften ist keine Demokratie, noch weniger Ochlokratie, sondern Aristokratie im edelsten Sinne. Die Besten sollen herrschen. Auch die bloß Unfähigen, welche irgend eine Convenienz empfiehlt, die bloßen sich vordrängenden Schwätzer, die den wissenschaftlichen Stand durch kleine Arten von Industrie entehren, sollen in der gänzlichen Passivität erhalten werden. Von selbst kann schon niemand der Verachtung entgehen, die ihm in diesen Verhältnissen Unwissenheit und geistige Ohnmacht zuziehen, ja, da diese dann meistens mit Lächerlichkeit oder wahrer Niederträchtigkeit gepaart sind, dienen sie der Jugend zum Spiel und stumpfen allzufrüh den natürlichen Ekel eines noch nicht erfahrenen Gemüthes ab. Das Talent bedarf keines Schutzes, wenn nur das Gegentheil nicht begünstigt ist; das Vermögen zu Ideen verschafft sich von selbst die oberste und entschiedenste Wirkung."}]}, {"page_pdf": 1543, "page_book": 238, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Dies ist die einzige Politik, die in Ansehung aller Anstalten für Wissenschaft statthat, um sie blühend zu machen, um ihnen so viel möglich Würde nach innen und Ansehen nach außen zu geben. Um die Akademien insbesondere zu Mustern von Verfassungen zu machen, erforderte es nichts, als was man, ohne einen Widerspruch zu begehen, gar nicht umhin kann zu wollen; und da ich, wie gesagt, die Kluft zwischen Wissen und Handeln überhaupt nicht zugebe, so kann ich sie unter jener Bedingung auch in Ansehung der Akademien nicht zulassen. Die Bildung zum vernunftmäßigen Denken, worunter ich freilich keine bloß oberflächliche Angewöhnung, sondern eine in das Wesen des Menschen selbst übergehende Bildung, die allein auch die ächt wissenschaftliche ist, verstehe, ist auch die einzige zum vernunftmäßigen Handeln; Zwecke, die außer dieser absoluten Sphäre scientifischer Ausbildung liegen, sind durch die erste Bestimmung der Akademien schon von ihnen ausgeschlossen. Derjenige, welcher von seiner besondern Wissenschaft aus die vollkommene Durchbildung bis zum absoluten Wissen erhalten hat, ist von"}, {"type": "paragraph", "text": "selbst in das Reich der Klarheit, der Besonnenheit gehoben, das Gefährlichste für den Menschen ist die Herrschaft dunkler Begriffe, es ist für ihn schon vieles gewonnen, wenn diese nur überhaupt beschränkt ist, es ist alles gewonnen, wenn er zum absoluten Bewußtseyn durchgedrungen ist, wenn er ganz im Licht wandelt. Die Wissenschaft richtet gleich unmittelbar den Sinn auf diejenige Anschauung, die, eine dauernde Selbstgestaltung, unmittelbar zu der Identität mit sich und dadurch zu einem wahrhaft seligen Leben führt. Langsam erzieht die Erfahrung und das Leben, nicht ohne vielen Verlust der Zeit und der Kraft. Dem, der sich der Wissenschaft weiht, ist es vergönnt, die Erfahrung sich vorauszunehmen und das, was doch am Ende einziges Resultat des durchgebildetsten und erfahrungsreichsten Lebens seyn kann, gleich unmittelbar und an sich selbst zu erkennen."}, {"type": "heading", "text": "Dritte Vorlesung. *Ueber die ersten Voraussetzungen des akademischen Studium.*", "level": null}, {"type": "paragraph", "text": "Den hohen Zweck desjenigen, der sich überhaupt der Wissenschaft weiht, glaube ich im Vorhergehenden durch die Idee der letzteren schon hinlänglich ausgesprochen zu haben. Desto kürzer werde ich mich über die allgemeinen Forderungen, die an den gemacht werden müssen, der diesen Beruf erwählt, fassen können. Der Begriff des Studirens schließt an sich schon und besonders nach den Verhältnissen der neueren Cultur eine doppelte Seite in sich. Die erste ist die historische. In Ansehung derselben findet das bloße *Lernen* statt. Die unumgängliche Nothwendigkeit der Gefangennehmung und Ergebung seines Willens unter den Gehorsam des Lernens in allen Wissenschaften folgt schon aus dem früher Bewiesenen. Was auch bessere Köpfe in Erfüllung dieser Bedingung mißleitet, ist eine sehr gewöhnliche Täuschung. Sie fühlen sich nämlich bei dem Lernen mehr angestrengt als eigentlich thätig, und weil die Thätigkeit der natürlichere Zustand ist, halten sie jede Art derselben für eine höhere Aeußerung des angeborenen"}]}, {"page_pdf": 1544, "page_book": 240, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Vermögens, wenn auch die Leichtigkeit, welche das eigne Denken und Entwerfen für sie hat, seinen Grund mehr in der Unkenntniß der wahren Gegenstände und eigentlichen Aufgaben des Wissens, als in einer ächten Fülle des produktiven Triebs haben sollte. Im Lernen,"}, {"type": "paragraph", "text": "selbst wo es durch lebendigen Vortrag geleitet wird, findet wenigstens keine Wahl statt: man muß durch alles, durch das Schwere wie das Leichte, durch das Anziehende wie das minder Anziehende hindurch; die Aufgaben werden hier nicht willkürlich, nach Ideenassociation oder Neigung genommen, sondern mit Nothwendigkeit. In dem Gedankenspiel, bei mittelmäßig reger Einbildungskraft, die mit geringer Kenntniß der wissenschaftlichen Forderungen verbunden ist, nimmt man heraus, was gefällt, und läßt liegen, was nicht gefällt, oder was auch im Erfinden und eignen Denken nicht ohne Anstrengung ergründet werden kann. Selbst derjenige, der von Natur berufen ist, zuvor nicht bearbeitete Gegenstände in neuen Gebieten sich zu seiner Aufgabe zu nehmen, muß doch den Geist auf jene Weise geübt haben, um in diesen einst durchzudringen. Ohne dies wird ihm auch im Selbstconstruiren immer nur ein desultorisches Verfahren und fragmentarisches Denken eigenthümlich bleiben. Die Wissenschaft zu durchdringen, vermag nur, wer sie bis zur Totalität gestalten und bis zu der Gewißheit in sich ausbilden kann, kein wesentliches Mittelglied übersprungen, das Nothwendige erschöpft zu haben. Ein gewisser Ton der Popularität in den obersten Wissenschaften, kraft dessen sie geradezu jedermanns Ding und jeder Fassungskraft angemessen seyn sollten, hat die Scheu vor Anstrengung so allgemein verbreitet, daß die Schlaffheit, die es mit den Begriffen nicht zu genau nimmt, die angenehme Oberflächlichkeit und wohlgefällige Seichtigkeit sogar zur sogenannten feineren Ausbildung gehörte, und man endlich auch den Zweck der akademischen Bildung darauf beschränkte, von dem Wein der höheren Wissenschaften eben nur so viel zu kosten, als man mit Anstand auch einer Dame anbieten könnte. Man muß den Universitäten zum Theil die Ehre widerfahren lassen, daß sie vorzüglich den einbrechenden Strom der Ungründlichkeit, den die neuere Pädagogik noch vermehrte, aufgehalten haben, obgleich es andererseits auch der Ueberdruß an ihrer langweiligen, breiten und von keinem Geist belebten Gründlichkeit war, was jenem den meisten Eingang verschaffte."}, {"type": "paragraph", "text": "Jede Wissenschaft hat außer ihrer eigenthümlichen Seite eine andere noch, die ihr mit der Kunst gemein ist. Es ist die Seite der Form, welche in einigen derselben sogar vom Stoff ganz unzertrennlich ist. Alle Vortrefflichkeit in der Kunst, alle Bildung eines edlen Stoffs in angemessener Form geht aus der Beschränkung hervor, die der Geist sich selbst setzt. Die Form wird nur durch Uebung vollständig erlangt, und aller wahre Unterricht soll seiner Bestimmung nach mehr auf diese als auf den Stoff gehen, [mehr das Organ üben als den Gegenstand überliefern. - Aber das Organ auch der Wissenschaft ist Kunst, und diese will durch Uebung gebildet und gelernt seyn]. Es gibt vergängliche und hinfällige Formen, und als besondere sind alle diejenigen, in die sich der Geist der Wissenschaft hüllt, auch nur verschiedene Erscheinungsweisen des sich in ewig neuen Gestalten verjüngenden und wiedergebärenden Genius. Aber in den besondern Formen ist eine allgemeine und absolute Form, von der jene selbst nur wieder die Symbole sind; und ihr Kunstwerth steigt in dem Maße, in welchem ihnen gelingt jene zu offenbaren. Alle Kunst aber hat eine Seite, von der sie durch Lernen erworben wird. Die Scheu vor Formen und angeblichen Schranken derselben ist die Scheu vor der Kunst in der Wissenschaft."}]}, {"page_pdf": 1545, "page_book": 242, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Aber nicht in der gegebenen und besondern Form, die nur gelernt seyn kann, sondern in eigenthümlicher, selbstgebildeter, den gegebenen Stoff reproduciren, vollendet auch erst das Aufnehmen selbst. Lernen ist nur negative Bedingung, wahre Intussusception nicht ohne innere Verwandlung in sich selbst möglich. Alle Regeln, die man dem Studiren vorschreiben könnte, fassen sich in der einen zusammen: Lerne nur, um selbst zu schaffen. Nur durch dieses göttliche Vermögen der Produktion ist man wahrer Mensch, ohne dasselbe nur eine leidlich klug eingerichtete Maschine. Wer nicht mit demselben höheren Antrieb, womit der Künstler aus einer rohen Masse das Bild seiner Seele und der eignen Erfindung hervorruft, es zur vollkommenen Herausarbeitung des Bildes seiner Wissenschaft in allen Zügen und Theilen bis zur vollkommenen Einheit mit dem Urbild gebracht hat, hat sie überhaupt nicht durchdrungen."}, {"type": "paragraph", "text": "Alles Produciren ruht auf einer Begegnung oder Wechseldurchdringung des Allgemeinen und Besonderen. Den Gegensatz jeder Besonderheit gegen die Absolutheit scharf zu fassen, und zugleich in demselben untheilbaren Akt jene in dieser und diese in jener zu begreifen, ist das Geheimniß der Produktion. Hierdurch bilden sich jene höheren Einheitspunkte, wodurch das Getrennte zur Idee zusammenfließt, jene höheren Formeln, in die sich das Concrete auflöst, die Gesetze, \"aus dem himmlischen Aether geboren, die nicht die sterbliche Natur des Menschen gezeugt hat.\" Die gewöhnliche Eintheilung der Erkenntniß in die rationale und historische wird so bestimmt, daß jene mit der Erkenntniß der Gründe verbunden, diese eine bloße Wissenschaft des Faktum sey. Man könnte einwenden, daß ja auch die Gründe wieder bloß historisch gewußt werden können; allein dann würden sie eben nicht als Gründe aufgefaßt. Man hat den Ekelnamen der Brodwissenschaften allgemein denjenigen gegeben, welche unmittelbarer als andere zum Gebrauch des Lebens dienen. Aber keine Wissenschaft verdient an sich diese Benennung. Wer die Philosophie oder Mathematik als Mittel behandelt, für den ist sie so gut bloßes Brodstudium, als die Rechtsgelehrsamkeit oder Medicin für denjenigen, der kein höheres Interesse für sie hat als das der Nützlichkeit für ihn selbst. Der Zweck alles Brodstudium ist, daß man die bloßen Resultate kennen lernt, entweder mit gänzlicher Vernachlässigung der Gründe, oder daß man auch diese nur um eines äußeren Zwecks willen, z.B. um bei angeordneten Prüfungen nothdürftige Rechenschaft geben zu können, historisch kennen lernt. Man kann sich dazu entschließen, einzig, weil man die Wissenschaft zu einem bloß empirischen Gebrauch erlernen will, d.h. sich selbst bloß als Mittel betrachtet. Nun kann gewiß niemand, der nur einen Funken von Achtung für sich selbst hat, sich gegenüber von der Wissenschaft selbst so niedrig fühlen, daß sie für ihn nur als Abrichtung für empirische Zwecke Werth hätte. Die nothwendigen Folgen einer solchen Art zu studiren, sind diese: Erstens ist es unmöglich, sich auch nur das Empfangene richtig anzueignen, nothwendig also, daß man es falsch anwende, da der"}, {"type": "paragraph", "text": "Besitz desselben nicht auf einem lebendigen Organ der Anschauung, sondern nur auf dem Gedächtniß beruht. Wie oft senden Universitäten aus ihren Schulen solche Brodgelehrte zurück, die sich alles, was sich in ihrem Fach von Gelehrsamkeit da vorfindet, vortrefflich eingeprägt haben, denen es aber für die Aufnahme des Besonderen unter das Allgemeine gänzlich an Urtheil fehlt! Lebendige Wissenschaftlichkeit bildet zur Anschauung; in dieser aber ist das Allgemeine und Besondere immer eins. Der Brodgelehrte dagegen ist anschauungslos, er kann sich im vorkommenden Falle nichts construiren,"}]}, {"page_pdf": 1546, "page_book": 244, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "selbstthätig zusammensetzen, und da er im Lernen doch nicht auf alle möglichen Fälle vorbereitet werden konnte, so ist er in den meisten von seinem Wissen verlassen. Eine andere nothwendige Folge ist, daß ein solcher gänzlich unfähig ist fortzuschreiten; auch damit legt er den Hauptcharakter des Menschen und des wahren Gelehrten insbesondere ab. Er kann nicht fortschreiten, denn wahre Fortschritte sind nicht nach dem Maßstab früherer Lehren, sondern nur aus sich selbst und aus absoluten Principien zu beurtheilen. Höchstens faßt er auf, was selbst keinen Geist hat, neu angepriesene Mittel, diese oder jene fade Theorie, die eben entsteht und die Neugier reizt, oder einige neue Formeln, gelehrte Novitäten u.s.w. Alles muß ihm als eine Besonderheit erscheinen, um von ihm aufgenommen zu werden. Denn nur das Besondere kann gelernt werden, und in der Qualität des Gelerntseyns ist alles nur ein Besonderes. Deßwegen ist er der geschworene Feind jeder ächten Entdeckung, die im Allgemeinen gemacht wird, jeder Idee, weil er sie nicht faßt, jeder wirklichen Wahrheit, die ihn in seiner Ruhe stört. Vergißt er sich noch überdieß so weit, sich dagegen aufzulehnen, so benimmt er sich entweder auf die bekannte ungeschickte Art, das Neue nach Principien und Ansichten zu beurtheilen, die jenes eben in Ansprüche nimmt, mit Gründen oder gar Auctoritäten zu streiten, die in dem vorhergehenden Zustand der Wissenschaft etwa gelten konnten; oder es bleiben ihm im Gefühl seiner Nichtigkeit nur Schmähungen oder die Waffen der Verleumdung übrig, zu denen er sich innerlich berechtigt fühlt, weil jede neue Entdeckung wirklich ein persönlicher Angriff auf ihn ist."}, {"type": "paragraph", "text": "Der Erfolg ihres Studirens oder wenigstens die erste Richtung desselben hängt für alle mehr oder weniger von der Art und dem Grad von Bildung und Kenntniß ab, den sie auf die Akademie mitbringen. Von der ersten äußeren und sittlichen Bildung, die für diese Erziehungsstufe schon erfordert wird, sage ich nichts, da alles, was hierüber zu sagen wäre, sich von selbst versteht. Die sogenannten Vorkenntnisse betreffend, so kann man die Art von Wissen, die vor dem akademischen erworben wird, nicht wohl anders denn als Kenntnisse bezeichnen. Für die Ausdehnung derselben gibt es ohne Zweifel auch einen Punkt, jenseits und diesseits dessen das Rechte nicht besteht. Die höheren Wissenschaften lassen sich nicht in der Qualität von Kenntnissen besitzen oder erlangen. Es würde nicht rathsam seyn, zu einer Zeit, wo doch in keiner Richtung die Absolutheit wahrhaft erreicht werden kann, dasjenige Wissen zu anticipiren, das seiner Natur nach darauf beruht und diesen Charakter zugleich allem anderen Wissen mittheilt. Ja auch von Wissenschaften, deren Stoff zum Theil in Kenntnissen besteht, die nur im Zusammenhang des Ganzen ihren wahren Werth erlangen können, jene mitzutheilen, ehe der Geist durch die höheren Wissenschaften in diesen eingeweiht ist, könnte nur die spätere Vernachlässigung, aber keinen Vortheil zur Folge haben. Der Erziehungseifer der letzten Zeit hat auch die niederern Schulen nur nicht ganz zu Akademien umzuschaffen zum Theil versucht, aber nur der Halbheit in der Wissenschaft neuen Vorschub gethan. Es ist überhaupt nöthig auf jeder Stufe zu verweilen, bis man das sichere Gefühl hat, sich auf ihr festgesetzt zu haben. Nur wenigen *scheint* es verstattet, Stufen zu überspringen, obgleich dieß eigentlich nie der Fall ist. *Newton* las in zartem Alter die Elemente des Euklides wie ein selbstgeschriebenes Werk, oder wie andere unterhaltende Schriften lesen. Er konnte daher von der Elementargeometrie unmittelbar zu den höheren Untersuchungen übergehen. In der Regel ist das andere Extrem des obigen der Fall, nämlich die tiefste Vernachlässigung der Vorbereitungsschulen. Was vor dem Eintritt in das akademische Studium schlechthin schon erworben"}]}, {"page_pdf": 1547, "page_book": 246, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "seyn sollte, ist alles, was zum Mechanischen in den Wissenschaften gehört. Theils hat überhaupt jede Scienz einen bestimmten Mechanismus, theils macht die allgemeine Verfassung der Wissenschaften mechanische Hülfsmittel, zu denselben zu gelangen, unentbehrlich. Ein Beispiel des ersten Falls sind die allgemeinsten und ersten Operationen der Analysis des Endlichen; der akademische Lehrer kann wohl ihre wissenschaftlichen Gründe entwickeln, aber nicht den Rechenmeister machen. Ein Beispiel des andern Falls ist die Kenntniß der Sprachen, alter und neuer, da diese allein den Zugang zu den vornehmsten Quellen der Bildung und der Wissenschaft öffnen. Es gehört hieher überhaupt alles, was mehr oder weniger durch Gedächtniß aufgefaßt seyn will, da dieß im früheren Alter theils am schärfsten ist, theils am meisten geübt seyn will. Ich werde hier nur vorzüglich von dem früheren Studium der Sprachen reden, welches nicht bloß als nothwendige Stufe zu jeder ferneren in der wissenschaftlichen Bildung unumgänglich ist, sondern einen unabhängigen Werth in sich selbst hat. Die elenden Gründe, aus welchen vorzüglich das Erlernen der alten Sprachen im früheren Alter von der modernen Erziehungskunst bestritten wird, bedürfen keiner Widerlegung mehr. Sie gelten nur für ebenso viele besondere Beweise der Gemeinheit der Begriffe, die dieser zu Grunde lagen, und sind vorzüglich von einem mißverstandenen Eifer gegen überwiegende Ausbildung des Gedächtnisses nach den Vorstellungen einer empirischen Psychologie eingegeben. Die angeblichen Erfahrungen darüber waren von gewissen Gedächtnißgelehrten hergenommen, die sich zwar mit Kenntnissen aller Art angefüllt, aber dadurch freilich nicht hatten erwerben können, was ihnen die Natur versagt hatte. Daß übrigens weder ein großer Feldherr noch ein großer Mathematiker oder Philosoph oder Dichter ohne Umfang und Energie des Gedächtnisses möglich war, konnte für sie nicht in Betracht kommen, da es auch gar nicht darauf angesehen war, große Feldherrn, Mathematiker, Dichter oder Philosophen, sondern nützliche, bürgerliche, gewerbsame Menschen zu bilden."}, {"type": "paragraph", "text": "Ich kenne keine Beschäftigungsart, welche mehr geeignet wäre, im früheren Alter dem erwachenden Witz, Scharfsinn, Erfindungskraft die erste Uebung zu geben, als die vornehmlich mit den alten Sprachen. Ich rede hier nämlich nicht von der Wissenschaft der Sprache im abstrakten Sinn, inwiefern diese als unmittelbarer Abdruck des inneren Typus der Vernunft Gegenstand einer wissenschaftlichen Construktion ist. Ebensowenig von der Philologie, zu der sich Sprachkenntniß nur wie das Mittel zu seinem viel höheren Zwecke verhält. Der bloße Sprachgelehrte heißt nur durch Mißbrauch Philolog; dieser steht mit dem Künstler und Philosophen auf den höchsten Stufen, oder vielmehr durchdringen sich beide in ihm. Seine Sache ist die historische Construktion der Werke der Kunst und Wissenschaft, deren Geschichte er in lebendiger Anschauung zu begreifen und darzustellen hat. Auf Universitäten soll eigentlich nur Philologie, in diesem Sinne behandelt, gelehrt werden; der akademische Lehrer soll nicht Sprachmeister seyn. - Ich kehre zu meiner ersten Behauptung zurück. Die Sprache an und für sich selbst schon und bloß grammatisch angesehen, ist eine fortgehende angewandte Logik. Alle wissenschaftliche Bildung [alle Erfindungsfähigkeit] besteht in der Fertigkeit, die Möglichkeiten zu erkennen, da im Gegentheil das gemeine Wissen nur Wirklichkeiten begreift. Der Physiker, wenn er erkannt hat, daß unter gewissen Bedingungen eine Erscheinung wahrhaft möglich sey, hat auch erkannt, daß sie wirklich ist. Das Studium der Sprache als Auslegung, vorzüglich aber als Verbesserung der Lesart durch Conjektur, übt dieses Erkennen der Möglichkeiten auf eine dem Knabenalter angemessene Art, wie es noch im männlichen Alter auch einen knabenhaft bleibenden Sinn angenehm beschäftigen kann. Es ist unmittelbare Bildung des Sinns, aus einer für uns erstorbenen Rede den lebendigen Geist zu erkennen, und es findet darin kein anderes Verhältniß statt, als welches auch der Naturforscher zu der Natur hat. Die Natur ist für uns ein uralter Autor, der in Hieroglyphen geschrieben hat, dessen Blätter"}]}, {"page_pdf": 1548, "page_book": 247, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "kolossal sind, wie *der Künstler* bei Goethe sagt. Eben derjenige, der die Natur bloß auf dem"}, {"type": "paragraph", "text": "empirischen Wege erforschen will, bedarf gleichsam am meisten *Sprach*-Kenntniß von ihr, um die für ihn ausgestorbene Rede zu verstehen. Im höheren Sinn der Philologie ist dasselbe wahr. Die Erde ist ein Buch, das aus Bruchstücken und Rhapsodien sehr verschiedener Zeiten zusammengesetzt ist. Jedes Mineral ist ein wahres philologisches Problem. In der Geologie wird der Wolf noch erwartet, der die Erde ebenso wie den Homer zerlegt und ihre Zusammensetzung zeigt. In die besonderen Theile des akademischen Studium jetzt einzugehen und gleichsam das ganze Gebäude desselben auf den ersten Grundlagen aufzuführen, ist nicht möglich, ohne zugleich die Verzweigungen der Wissenschaft selbst zu verfolgen und das organische Ganze derselben zu construiren. Ich werde demnach zunächst den Zusammenhang aller Wissenschaften unter sich, und die Objektivität, welche diese innere, organische Einheit durch die äußere Organisation der Universitäten erhalten hat, darstellen müssen. Gewissermaßen würde dieser Grundriß die Stelle einer allgemeinen Encyklopädie der Wissenschaften vertreten können; da ich aber diese nie rein an sich, sondern immer zugleich in der besondern Beziehung meines Vortrags betrachten werde, so kann natürlich kein aus den höchsten Principien auf die strengste Art abgeleitetes System der Erkenntnisse hier erwartet werden. Ich kann, so wie überhaupt in diesen Vorlesungen, nicht darauf ausgehen, meinen Gegenstand zu erschöpfen. Dieß kann man nur in der wirklichen Construktion und Demonstration erreichen: ich werde vieles nicht sagen, was vielleicht gesagt zu werden verdiente, desto mehr aber mich hüten, etwas zu sagen, was nicht gesagt werden sollte, entweder an sich, oder weil es die gegenwärtige Zeit und der Zustand der Wissenschaften nothwendig machten."}, {"type": "heading", "text": "Vierte Vorlesung. *Ueber das Studium der reinen Vernunftwissenschaften, der Mathematik und*", "level": null}, {"type": "paragraph", "text": "*der Philosophie im Allgemeinen.*"}, {"type": "paragraph", "text": "Das schlechthin Eine, von dem alle Wissenschaften ausfließen und in das sie zurückkehren, ist das Urwissen, durch dessen Einbildung ins Concrete sich von Einem Centralpunkt aus das Ganze des Erkennens bis in die äußersten Glieder gestaltet. Diejenigen Wissenschaften, in welchen es sich als in seinen unmittelbarsten Organen reflektirt, und das Wissen als Reflektirendes mit dem Urwissen als Reflektirtem in Eins zusammenfällt, sind wie die allgemeinen Sensoria in dem organischen Leib des Wissens. Wir haben von diesen Centralorganen auszugehen, um das Leben von ihnen aus durch verschiedene Quellen bis in die äußersten Theile zu leiten. Für denjenigen, der noch nicht selbst im Besitz desjenigen Wissens ist, welches mit dem Urwissen eins und es selbst ist, gibt es keinen andern Weg, zur Anerkennung desselben geleitet zu werden, als durch den Gegensatz mit dem andern Wissen. Ich kann hier unmöglich begreiflich machen, wie wir dazu kommen, überhaupt etwas Besonderes zu"}]}, {"page_pdf": 1549, "page_book": 249, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "erkennen; nur so viel läßt sich bestimmt auch hier zeigen, daß ein solches Erkennen kein absolutes und eben darum auch nicht unbedingt wahres seyn kann. Man verstehe dieß nicht im Sinne eines gewissen empirischen"}, {"type": "paragraph", "text": "Skepticismus, der die Wahrheit der sinnlichen, d.i. ganz aufs Besondere gerichteten Vorstellungen aus dem Grunde der Sinnentäuschungen bezweifelt, so daß, wenn es keine optischen und anderen Betrüge gäbe, wir alsdann unserer sinnlichen Erkenntniß so ziemlich gewiß seyn könnten; ebensowenig in dem eines rohen Empirismus überhaupt, der die Wahrheit der sinnlichen Vorstellungen allgemein darum bezweifelt, weil doch die Affektionen, aus denen sie entspringen, erst durch die Seele zur Seele gelangen und auf diesem Wege viel von ihrer Ursprünglichkeit verlieren müssen. Aller Causalbezug zwischen Wissen und Seyn gehört selbst mit zu der sinnlichen Täuschung, und wenn jenes ein endliches ist, so ist es dieß vermöge einer Determination, die in ihm selbst und nicht außer ihm liegt. Aber eben dieß, daß es überhaupt ein bestimmtes Wissen ist, macht es zu einem abhängigen, bedingten, stets veränderlichen; das Bestimmte an ihm ist, wodurch es ein Mannichfaltiges und Verschiedenes ist, die *Form.* Das *Wesen* des Wissens ist eines, in allem das gleiche, und kann eben deßwegen auch nicht determinirt seyn. Wodurch sich also Wissen von Wissen unterscheidet, ist die Form, die im Besonderen aus der Indifferenz mit dem Wesen tritt, welches wir insofern auch das Allgemeine nennen können. Form getrennt von Wesen aber ist nicht reell, ist bloß Schein; das besondere Wissen rein als solches demnach kein wahres Wissen. Dem besondern steht das reine allgemeine gegenüber, welches als ein von jenem abgesondertes das abstrakte heißt. Es kann hier ebensowenig die Entstehung dieses Wissens begreiflich gemacht, es kann nur gezeigt werden, daß, wenn in dem besondern die Form dem Wesen unangemessen ist, daß rein allgemeine dagegen dem Verstand als Wesen ohne Form erscheinen müsse. Wo die Form nicht im Wesen und durch dasselbe erkannt wird, wird eine Wirklichkeit erkannt, die nicht aus der Möglichkeit begriffen wird, wie die besondern und sinnlichen Bestimmungen der Substanz in Ewigkeit nicht aus dem Allgemeinbegriff derselben eingesehen werden können; weßhalb diejenigen, die bei diesem Gegensatz stehen bleiben, sich außer dem Allgemeinen noch das Besondere"}, {"type": "paragraph", "text": "unter dem Namen des Stoffs als eines allgemeinen Inbegriffs der sinnlichen Verschiedenheiten zugeben lassen. Im entgegengesetzten Fall wird die reine, abstrakte Möglichkeit begriffen, aus der man nicht zu der Wirklichkeit herauskommen kann, und dieß und jenes ist, mit Lessing zu reden, der breite Graben, vor dem der große Haufen der Philosophen von jeher stehen geblieben ist. Es ist klar genug, daß der letzte Grund und die Möglichkeit aller wahrhaft absoluten Erkenntniß darin ruhen muß, daß eben das Allgemeine zugleich auch das Besondere und dasselbe, was dem Verstand als bloße Möglichkeit ohne Wirklichkeit, Wesen ohne Form erscheint, eben dieses auch die Wirklichkeit und die Form sey: dieß ist die Idee aller Ideen und aus diesem Grunde die des Absoluten selbst. Es ist nicht minder offenbar, daß das Absolute an sich betrachtet, da es eben *nur* diese Identität ist, an sich weder das eine noch das andere der Entgegengesetzten sey, daß es aber als das gleiche *Wesen* beider, und demnach als Identität, in der Erscheinung nur *entweder* im Realen *oder* im Idealen sich darstellen könne. Die beiden Seiten der Erkenntniß, die, in welcher die Wirklichkeit der Möglichkeit, und die, in welcher die letzte der erstern vorangeht, lassen sich nämlich unter sich wieder als reale und ideale"}]}, {"page_pdf": 1550, "page_book": 251, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "entgegensetzen. Wäre es nun denkbar, daß im Realen oder Idealen selbst wieder nicht das eine oder das andere der beiden Entgegengesetzten, sondern die *reine* Identität beider, als solche, durchbräche, so wäre damit ohne Zweifel die Möglichkeit einer absoluten Erkenntniß selbst innerhalb der Erscheinung gegeben. Wenn demnach, um von diesem Punkt aus weiter zu schließen, von der Identität der Möglichkeit und Wirklichkeit rein als solcher im Realen ein Reflex wäre, so könnte sie ebensowenig als ein abstrakter Begriff wie als concretes Ding erscheinen: das erste nicht, weil sie alsdann eine Möglichkeit wäre, der die Wirklichkeit, das andere nicht, weil sie eine Wirklichkeit wäre, der die Möglichkeit gegenüber stünde. Da sie ferner als Identität rein im Realen erscheinen sollte, müßte sie sich als reines *Seyn*, und inwiefern dem Seyn die Thätigkeit"}, {"type": "paragraph", "text": "entgegengesetzt ist, als Negation aller Thätigkeit erscheinen. Dasselbe ist nach dem früher aufgestellten Grundsatz einzusehen: daß jedes, was seinen Gegensatz in einem andern hat, nur, wiefern es in sich absolut ist, zugleich wieder die Identität von sich selbst und seinem Entgegengesetzten ist; denn das Reale wird diesem zufolge als Identität von Möglichkeit und Wirklichkeit nur erscheinen können, inwiefern es in sich selbst absolutes Seyn, alles Entgegengesetzte daher von ihm negirt ist. Ein solches reines *Seyn* mit Verneinung aller Thätigkeit ist nun ohne Zweifel der *Raum*; aber eben derselbe ist auch weder ein Abstraktum, denn sonst müßten mehrere Räume seyn, da der Raum in allen Räumen nur Einer ist, noch ein Concretum, denn sonst müßte ein abstrakter Begriff von ihm seyn, dem er als Besonderes nur unvollkommen angemessen wäre; er ist aber ganz, was er ist, das Seyn erschöpft in ihm den Begriff, und er ist eben deßwegen und nur, weil er absolut real ist, auch wieder absolut ideal. Zu Bestimmung der gleichen Identität, sofern sie im Idealen erscheint, können wir uns unmittelbar des Gegensatzes mit dem Raum bedienen [denn dem Raum, welcher eben dadurch, daß er weder allgemeines noch concretes Wesen ist, sich als Reflex von der absoluten Einheit des Allgemeinen und Besonderen ankündigt, steht nun nothwendig ein anderer Reflex entgegen]; denn da dieser [der Raum] als reines Seyn mit Negationen aller Thätigkeit erscheint, so wird jene [die dem Raum entgegenstehende Form] dagegen sich als reine Thätigkeit mit Verneinung alles Seyns darstellen müssen; aber aus dem Grunde, daß sie *reine* Thätigkeit ist, wird sie nach dem angegebenen Princip auch wieder die Identität von sich und dem Entgegengesetzten, von Möglichkeit also und Wirklichkeit seyn. Eine solche Identität ist die reine *Zeit*. Kein Seyn als solches ist in der Zeit, sondern nur die Veränderungen des Seyns, welche als Thätigkeitsäußerungen und als Negationen des Seyns erscheinen. In der empirischen Zeit geht die Möglichkeit, als Ursache, der Wirklichkeit voran, in der reinen Zeit ist die erste auch die andere. Als Identität des Allgemeinen und Besonderen ist die Zeit so wenig ein abstrakter Begriff als ein concretes"}, {"type": "paragraph", "text": "Ding, und es gilt von ihr in dieser Beziehung alles, was von dem Raume gilt. Diese Beweise sind hinreichend, einzusehen, sowohl daß in der reinen Anschauung des Raums und der Zeit eine wahrhaft objektive Anschauung der Identität von Möglichkeit und Wirklichkeit als solcher gegeben ist, als auch daß beide bloß relative Absolute sind, da weder Raum noch Zeit die Idee aller Ideen an sich, sondern nur in getrenntem Reflex darstellen; daß aus demselben Grunde weder jener noch diese Bestimmungen des An-sich sind, und daß, wenn die in beiden ausgedrückte Einheit Grund einer Erkenntniß oder Wissenschaft ist, diese selbst bloß zur reflektirten Welt gehören, aber nichtsdestoweniger der Form nach absolut seyn müsse."}]}, {"page_pdf": 1551, "page_book": 253, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Wenn nun, was ich hier nicht beweisen, sondern nur als bewiesen in der Philosophie voraussetzen kann, Mathematik, als Analysis und Geometrie, ganz in jenen beiden Anschauungsarten gegründet ist, so folgt, daß in jeder dieser Wissenschaften eine Erkenntnißart herrschend seyn müsse, die der Form nach absolut ist. Die Realität überhaupt und die der Erkenntniß insbesondere beruht weder allein auf dem Allgemeinbegriff noch allein auf der Besonderheit; die mathematische Erkenntniß ist aber weder die eines bloßen Abstraktums noch die eines Concretums, sondern der in der Anschauung dargestellten Idee. Die Darstellung des Allgemeinen und Besondern in der Einheit, heißt überhaupt Construktion, die von der Demonstration wahrhaft nicht unterschieden ist1. Die Einheit selbst drückt sich auf doppelte Weise aus. Erstens darin, daß - um uns an das Beispiel der Geometrie zu halten - allen Construktionen derselben, die sich unter sich wieder unterscheiden, als Triangel, Quadrat, Cirkel u.s.w., dieselbe absolute Form [der reine Raum] zu Grunde liegt, und zum wissenschaftlichen Begreifen derselben in ihrer Besonderheit nichts außer der Einen allgemeinen und absoluten Einheit"}, {"type": "footnote", "text": "1 Vergl. Fernere Darstellungen aus dem System der Philosophie, im vorigen Band S. 407 ff. und Ueber die Construktion in der Philosophie, oben S. 130 ff. und S. 139. D. H."}, {"type": "paragraph", "text": "erfordert wird. Zweitens darin, daß das Allgemeine jeder besondern Einheit, z.B. das allgemeine Dreieck mit dem besondern wieder eins ist, und hinwiederum das besondere Dreieck statt aller gilt und Einheit und Allheit zugleich ist1. Dieselbe Einheit drückt sich als die der Form und Wesen aus, da die Construktion, welche als Erkenntniß bloß Form scheinen würde, zugleich das Wesen des Construirten selbst ist2. Es ist leicht, die Anwendung von dem allen auf die Analysis zu machen. Die Stelle der Mathematik im allgemeinen System des Wissens ist zur Genüge bestimmt, ihre Beziehung auf das akademische Studium ergibt sich daraus von selbst. Eine Erkenntnißart, welche das Wissen über das Gesetz der Causalverbindung, das im gemeinen Wissen wie in einem großen Theil der sogenannten Wissenschaften herrschend ist, in das Gebiet einer reinen Vernunftidentität erhebt, bedarf keines äußern Zwecks. So sehr man auch übrigens die großen Wirkungen der Mathematik in ihrer Anwendung auf die allgemeinen Bewegungsgesetze, in der Astronomie und Physik überhaupt, anerkennte, so wäre derjenige doch nicht zur Erkenntniß der Absolutheit dieser Wissenschaft gelangt, der sie nur um dieser Folgen willen hochschätzte, und dieß überhaupt sowohl, als insbesondere, weil diese zum Theil nur einem Mißbrauch der reinen Vernunftevidenz ihren Ursprung verdanken. Die neuere Astronomie geht als Theorie auf nichts anderes als Umwandlung absoluter, aus der Idee fließender Gesetze in empirische Nothwendigkeiten aus, und hat diesen Zweck zu ihrer vollkommenen Befriedigung erreicht; übrigens kann es durchaus nicht Sache der Mathematik in diesem Sinn, und wie sie jetzt begriffen wird, seyn, über das Wesen oder An-sich der Natur und ihrer Gegenstände das Geringste zu verstehen. Dazu wäre nöthig, daß sie selbst vorerst in ihren Ursprung zurückginge und den in ihr ausgedrückten Typus der Vernunft allgemeiner begriffe. Inwiefern die Mathematik ebenso im Abstrakten, wie die Natur im Concreten, der vollkommenste objektivste Ausdruck"}, {"type": "footnote", "text": "1 Vergl. Ueber die Construktion in der Philosophie, oben S. 132. D. H. 2 Vergl. ebendaselbst, S. 134. D. H."}]}, {"page_pdf": 1552, "page_book": 254, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der Vernunft selbst ist, insofern müssen alle Naturgesetze, wie sie in reine Vernunftgesetze sich auflösen, ihre entsprechenden Formen auch in der Mathematik finden; aber nicht so, wie man dieß bisher angenommen hat, daß diese für jene nur bestimmend und die Natur übrigens in dieser Identität sich nur mechanisch verhalte, sondern so, daß Mathematik und Naturwissenschaft nur eine und dieselbe von verschiedenen Seiten angesehene Wissenschaft sey'n. Die Formen der Mathematik, wie sie jetzt verstanden werden, sind Symbole, für welche denen, die sie besitzen, der Schlüssel verloren gegangen ist, den, nach sichern Spuren und Nachrichten der Alten, noch Euklides besaß. Der Weg zur Wiedererfindung kann nur der seyn, sie durchaus als Formen reiner Vernunft und Ausdrücke von Ideen zu begreifen, die sich in der objektiven Gestalt in ein anderes verwandelt zeigen. Je weniger der gegenwärtige Unterricht der Mathematik geeignet seyn möchte, zu dem ursprünglichen Sinn dieser Formen zurückzuführen, desto mehr wird die Philosophie auf dem nun betretenen Wege auch die Mittel der Enträthselung und der Wiederherstellung jener uralten Wissenschaft an die Hand geben1. Der Lehrling achte fürnehmlich ja einzig auf diese Möglichkeit, so wie auf den bedeutenden Gegensatz der Geometrie und Analysis, der dem des Realismus und Idealismus in der Philosophie auffallend entspricht. Wir haben an der Mathematik den bloß formellen Charakter der absoluten Erkenntnißart, den sie so lange behalten wird, als sie nicht vollkommen symbolisch begriffen ist, aufgezeigt. Die Mathematik gehört insofern noch zur bloß abgebildeten Welt, als sie das Urwissen, die absolute Identität nur im Reflex und, welches davon eine nothwendige Folge ist, in getrennter Erscheinung zeigt, [obgleich das, was sie darstellt, die Ideen, wahre Urwesen und Urformen der Dinge selbst sind]. Die schlechthin und in jeder Beziehung absolute Erkenntnißart würde demnach diejenige sein, welche das Urwissen unmittelbar und an sich selbst zum Grund und Gegenstand hätte [es ausspräche]. Die Wissenschaft"}, {"type": "footnote", "text": "1 Vergl. a.a.O., S. 130. D. H."}, {"type": "paragraph", "text": "aber, die außer jenem kein anderes Urbild hat, ist nothwendig die Wissenschaft alles Wissens, demnach die *Philosophie*. Es kann nicht, weder überhaupt noch insbesondere, hier ein Beweis geführt werden, wodurch jedermänniglich gezwungen würde, zu gestehen, Philosophie sey eben Wissenschaft des Urwissens; es kann nur bewiesen werden, eine solche Wissenschaft sey überhaupt nothwendig, und man kann sicher seyn, beweisen zu können, daß jeder andere Begriff, den man etwa von Philosophie aufstellen möchte, kein Begriff, nicht etwa nur dieser, sondern überhaupt einer möglichen Wissenschaft sey. Philosophie und Mathematik sind sich darin gleich, daß beide in der absoluten Identität des Allgemeinen und Besondern gegründet1, beide also auch, inwiefern jede Einheit dieser Art Anschauung ist, überhaupt in der Anschauung sind; aber die Anschauung der ersten kann nicht wieder wie die der letzten eine reflektirte seyn, sie ist eine unmittelbare Vernunft- oder intellektuelle Anschauung, die mit ihrem Gegenstande, dem Urwissen selbst, schlechthin identisch ist2. Darstellung in intellektueller Anschauung ist philosophische Construktion; aber wie die allgemeine Einheit, die allen zu Grunde liegt, so können auch die besondern, in deren jeder die gleiche Absolutheit des Urwissens aufgenommen wird, nur in der Vernunftanschauung enthalten seyn, und sind insofern Ideen. Die Philosophie ist also die Wissenschaft der Ideen oder der ewigen Urbilder der Dinge."}]}, {"page_pdf": 1553, "page_book": 256, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Ohne intellektuelle Anschauung keine Philosophie! Auch die reine Anschauung des Raums und der Zeit ist nicht im gemeinen Bewußtseyn, als solchem; denn auch sie ist die, nur im Sinnlichen reflektirte,"}, {"type": "footnote", "text": "1 Sieht der Geometer etwa das Concrete in dem (wirklichen) Kreis an? Keineswegs. Aber allerdings auch nicht den bloßen allgemeinen Begriff, sondern das Allgemeine dennoch im Besonderen. Er schaut also zwar nur das Absolute, das schlechthin Relationslose, den Kreis an sich selbst, und nicht das Concrete. Aber er nimmt dieses auch nicht hinweg - er negirt es nicht, sondern ist gleichgültig gegen dasselbe. Es ist ihm für seine Erkenntniß ganz indifferent. (Vergl. die öfter citirte Abhandlung über die Construktion in der Philosophie ganz unten S. 131 u. 132. D. H.) 2 Vergl. a.a.O., S. 129. D. H."}, {"type": "paragraph", "text": "intellektuelle. Aber der Mathematiker hat das Mittel der äußern Darstellung voraus: in der Philosophie fällt auch die Anschauung ganz in die Vernunft zurück1. Wer sie nicht hat, versteht auch nicht, was von ihr gesagt wird; sie kann also überhaupt nicht gegeben werden. Eine negative Bedingung ihres Besitzes ist die klare und innige Einsicht der Nichtigkeit aller bloß endlichen Erkenntniß. Man kann sie in sich bilden; in dem Philosophen muß sie gleichsam zum Charakter werden, zum unwandelbaren Organ, zur Fertigkeit alles nur zu sehen, wie es in der Idee sich darstellt2. Ich habe hier nicht von der Philosophie überhaupt, ich habe nur so weit von ihr zu reden, als sie sich auf die erste wissenschaftliche Bildung bezieht. Von dem Nutzen der Philosophie zu reden, achte ich unter der Würde dieser Wissenschaft. Wer nur überhaupt darnach fragen kann, ist sicher noch nicht einmal fähig ihre Idee zu haben. Sie ist durch sich selbst von der Nützlichkeitbeziehung frei gesprochen. Sie ist nur um ihrer selbst willen; um eines andern willen zu seyn, würde unmittelbar ihr Wesen selbst aufheben. Von den Vorwürfen, die ihr gemacht werden, halte ich nicht ganz unnöthig zu sprechen: sie soll sich nicht durch Nützlichkeit empfehlen, aber auch nicht durch Vorspiegelungen schädlicher Wirkungen, die man ihr zuschreibt, wenigstens in äußern Beziehungen eingeschränkt werden."}, {"type": "footnote", "text": "1 Vergl. ebenfalls oben S. 129. D. H. 2 Vergl. Fernere Darstellungen aus dem System der Philosophie, im vorhergehenden Band S. 361. 362. D. H."}, {"type": "heading", "text": "Fünfte Vorlesung. *Ueber die gewöhnlichen Einwendungen gegen das Studium der Philosophie.*", "level": null}, {"type": "paragraph", "text": "Wenn ich den sehr gemein gewordenen Vorwurf, daß die Philosophie der Religion und dem Staate gefährlich sey, nicht mit Stillschweigen übergehe, so ist es, weil ich glaube, daß die meisten, die sich hierauf entgegnend haben vernehmen lassen, nicht im Stande gewesen sind das Gehörige zu sagen. Die nächste Antwort wäre wohl die: was mag das für ein Staat und was mag das für eine Religion seyn, denen die Philosophie gefährlich seyn kann? Wäre dieß wirklich der Fall, so müßte die Schuld an"}]}, {"page_pdf": 1554, "page_book": 258, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der vorgeblichen Religion und dem angeblichen Staat liegen. Die Philosophie folgt nur ihren innern Gründen und kann sich wenig bekümmern, ob alles, was von Menschen gemacht ist, damit übereinstimme. Von der Religion rede ich hier nicht; ich behalte mir vor, in der Folge die innigste Einheit beider, und wie die eine die andere erzeugt, darzuthun. Was den Staat betrifft, so will ich die Frage allgemein stellen: Wovon kann man in der wissenschaftlichen Beziehung mit Recht sagen oder fürchten, daß es dem Staat gefährlich sey? Es wird sich alsdann ohne Zweifel von selbst ergeben, ob die Philosophie etwas der Art sey, oder ob etwas der Art aus ihr hervorgehen könne."}, {"type": "paragraph", "text": "Eine Richtung in der Wissenschaft halte ich in Beziehung auf den Staat für verderblich und die andere für untergrabend. Die erste ist, wenn das gemeine Wissen sich zum absoluten oder zur Beurtheilung desselben [zur Beurtheilung von Ideen] aufrichten will. Der Staat begünstige nur erst, daß der gemeine Verstand Schiedsrichter über Ideen sey, so wird dieser sich bald auch über den Staat erheben, dessen auf Vernunft und in Ideen gegründete Verfassung er so wenig wie diese begreift. Mit denselben populären Gründen mit welchen er gegen die Philosophie zu streiten meint, kann er und noch viel einleuchtender die ersten Formen des Staates angreifen. Ich muß erklären, was ich unter gemeinem Verstand begreife. Keineswegs allein oder vorzüglich den rohen, schlechthin ungebildeten Verstand, sondern gleicherweise den durch falsche und oberflächliche Kultur zum hohlen und leeren Räsonniren gebildeten Verstand, der sich für absolut gebildet hält, und der in der neueren Zeit sich durch Herabwürdigung alles dessen, was auf Ideen beruht, vorzüglich geäußert hat. Dieser Ideenleerheit, die sich Aufklärung zu nennen untersteht, ist die Philosophie am meisten entgegengesetzt. Man wird zugeben müssen, daß es keine Nation in dieser Erhebung eines räsonnirenden Verstandes über die Vernunft weiter gebracht hat als die französische [und in dieser Beziehung sind unsere Deutschen doch nur armselige und langweilige Prediger im Vergleich mit den französischen Schriftstellern]. Es ist demnach die größte auch historische Ungereimtheit, zu sagen: Philosophie sey für Erhaltung der Rechtsgrundsätze gefährlich (denn ich will mich so ausdrücken, da es allerdings Verfassungen oder Zustände derselben geben könnte, denen die Philosophie zwar nicht gefährlich, aber eben auch nicht günstig seyn kann). Gerade diejenige Nation, die, einige wenige Individuen früherer Zeiten ausgenommen (denen man aber gewiß keinen Einfluß auf die politischen Begebenheiten der späteren zuschreiben wird), in keiner Epoche, am wenigsten in derjenigen, welche der Revolution voranging, Philosophen hatte, war es, die das Beispiel einer durch rohe Greuel bezeichneten Umwälzung mit derselben Frevelhaftigkeit gab, mit welcher sie nachher zu neuen Formen der Sklaverei"}, {"type": "paragraph", "text": "zurückgekehrt ist. Ich leugne nicht, daß Räsonneurs in allen Wissenschaften und nach allen Richtungen in Frankreich den Namen der Philosophen usurpirt haben; es möchte aber wohl keiner von denjenigen seyn, denen unter uns dieser Charakter unbestreitbar zukommt, der einem einzigen von jenen ihn zugestünde. Es ist nicht zu verwundern und wäre an sich, wenn man nicht auf andere Weise über den Werth und die Bedeutung davon aufgeklärt würde, sogar preiswürdig, daß eine kraftvolle Regierung unter diesem Volk jene leeren Abstraktionen proscribirt, in welchen allerdings großentheils oder allein bestand, was die Franzosen von wissenschaftlichen Begriffen hatten. Mit hohlen Verstandesbegriffen läßt sich freilich so wenig ein Staat als eine Philosophie bauen, und eine Nation, die den Zugang zu den Ideen nicht hat, thut"}]}, {"page_pdf": 1555, "page_book": 260, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Recht, wenigstens Reste von solchen aus Trümmern vorhanden gewesener Formen hervorzusuchen. Die Erhebung des gemeinen Verstandes zum Schiedsrichter in Sachen der Vernunft führt ganz nothwendig die Ochlokratie im Reiche der Wissenschaften und mit dieser früher oder später die allgemeine Erhebung des Pöbels herbei. Fade oder heuchlerische Schwätzer, die da meinen, ein gewisses süßlichtes Gemenge sogenannter sittlicher Grundsätze an die Stelle der Ideenherrschaft zu setzen, verrathen nur, wie wenig sie selbst von Sittlichkeit wissen. Es gibt keine ohne Ideen, und alles sittliche Handeln ist es nur als Ausdruck von Ideen1. Die andere Richtung, in welche sich die erste verliert, und welche die Auflösung alles dessen, was auf Ideen gegründet ist, herbeiführen muß, ist die auf das bloß Nützliche. Wenn einmal dieses der höchste Maßstab für alles ist, so gilt er auch für die Staatsverfassung. Nun gibt es aber wohl überhaupt keine wandelbarere Sicherheit als jene; denn von dem, was heute nützlich ist, ist es morgen das Gegentheil. Aber noch überdieß muß dieser, es sey durch welche Wirkung, sich verbreitende Trieb alles Große und jede Energie unter einer Nation ersticken. Nach dem Maßstabe desselben wäre die Erfindung des Spinnrads wichtiger als die eines Weltsystems, und die Einführung der"}, {"type": "footnote", "text": "1 Vergl. die Abhandlung über das Verhältniß der Naturphilosophie zur Philosophie überhaupt, oben S. 105, und S. 123."}, {"type": "paragraph", "text": "Spanischen Schafzucht in einem Lande für ein größeres Werk zu achten als die Umgestaltung einer Welt durch die fast göttlichen Kräfte eines Eroberers. [Wenn die höchsten Preise aller Art auf die Nützlichkeit gesetzt werden, so muß aus diesem schmählichen Eigennutz des Staats endlich ein gleicher Eigennutz der Einzelnen entstehen und Eigennutz noch das einzige Band werden, das den Staat selbst zusammenhält und den Einzelnen an ihn bindet. Nun gibt es aber in der Welt kein zufälligeres Band als eben dieses. Jedes wahre Band, das Dinge oder Menschen vereinigt, muß ein göttliches seyn, d.h. ein solches, worin jedes Glied frei ist, weil jedes nur das Unbedingte will]. Wenn Philosophie eine Nation groß machen könnte, so wäre es eine solche, die ganz in Ideen ist, die nicht über den Genuß grübelte oder die Liebe zum Leben als erste Triebfeder obenansetzte, sondern die Verachtung des Todes lehrte und nicht die Tugenden großer Charaktere psychologisch zergliederte. In Deutschland könnte, da kein äußeres Band es vermag, nur ein inneres, eine herrschende Religion oder Philosophie, den alten Nationalcharakter hervorrufen, der in der Einzelnheit zerfallen ist und immer mehr zerfällt. Es ist gewiß, daß ein kleines, friedliches, zu keinen großen Bestimmungen berufenes Völklein auch keiner großen Motive bedarf; für dieses scheint es hinreichend, daß es leidlich zu essen und zu trinken habe und der Industrie sich ergebe. Selbst in größeren Staaten zwingt die Unverhältnißmäßigkeit der Mittel, die ein armer Boden darreicht, zu den Zwecken, die Regierungen selbst, sich mit diesem Nützlichkeitsgeist zu befreunden und alle Künste und Wissenschaften einzig auf das Streben darnach anzuweisen. Es leidet keinen Zweifel, daß solchen Staaten die Philosophie nichts nützen kann, und wenn die Fürsten anfangen, immer mehr populär zu werden, die Könige selbst sich schämen Könige zu seyn und nur die ersten Bürger seyn wollen, auch die Philosophie nur anfangen kann, sich in eine bürgerliche Moral umzuwandeln und von ihren hohen Regionen in das gemeine Leben herabzusteigen. Die Staatsverfassung ist ein Bild der Verfassung des Ideenreichs. In diesem ist das Absolute als die Macht, vor der alles ausfließt,"}]}, {"page_pdf": 1556, "page_book": 262, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der Monarch, die Ideen sind - nicht der Adel oder das Volk, weil das Begriffe sind, die nur im Gegensatz gegeneinander Realität haben, sondern - die Freien: die einzelnen wirklichen Dinge sind die Sklaven und Leibeigenen. Eine gleiche Stufenfolge ist unter den Wissenschaften. Die Philosophie lebt nur in Ideen, die Beschäftigung mit den einzelnen wirklichen Dingen überläßt sie den Physicis, Astronomis u.s.w. - Allein dieß sind ja selbst nur überspannte Ideen, und wer glaubt in dieser Humanität und Aufgeklärtheit der Zeiten noch an die hohen Beziehungen des Staats? Wenn dem einbrechenden Strom, der immer sichtbarer Hohes und Niederes vermischt, seit auch der Pöbel zu schreiben anhebt und jeder Plebejer in den Rang der Urtheiler sich erhebt, irgend etwas Einhalt zu thun vermag, so ist es die Philosophie, deren natürlicher Wahlspruch das Wort ist:"}, {"type": "paragraph", "text": "Odi profanum volgus et arceo. Nachdem man angefangen hatte, die Philosophie, nicht ohne Wirkung, als gefährlich für Staat und Kirche zu verschreien, haben endlich auch die Inhaber verschiedentlicher Wissenschaften ihre Stimme gegen sie erhoben, als ob sie, auch in dieser Beziehung, verderblich wäre, dadurch, daß sie [die Jugend insbesondere] von den gründlichen Wissenschaften abziehe, sie als entbehrlich darstelle u.s.w. Es wäre freilich vortrefflich, wenn auch die Gelehrten gewisser Fächer in den Rang der privilegirten Klassen treten könnten, und von Staats wegen festgesetzt würde, es soll in keinem Zweig des Wissens ein Fortschritt oder gar eine Umwandlung stattfinden. So weit ist es bis jetzt, wenigstens allgemein, noch nicht gekommen, wird auch wohl nie dahin kommen. Es ist keine Wissenschaft, die an sich in Entgegensetzung mit der Philosophie wäre, vielmehr sind alle eben durch sie und in ihr eins. Es ist also immer nur die Wissenschaft, wie sie in irgend eines Menschen Kopf existirt; und ist diese mit der Wissenschaft aller Wissenschaften im Widerstreit, desto schlimmer für sie! Warum ist denn die Geometrie seit langen Zeiten im ungestörten Besitz ihrer Lehrsätze und im ruhigen Fortschreiten?"}, {"type": "paragraph", "text": "Ich weiß, daß nichts so sehr wie das gründliche Studium der Philosophie geschickt ist, Achtung für die Wissenschaft einzuflößen, obgleich diese Achtung für die Wissenschaft nicht immer eben eine Achtung für die Wissenschaften seyn mag, wie sie jetzt sind; und wenn denn nun auch diejenigen, welche in der Philosophie eine Idee der Wahrheit erlangt haben, von dem grund- und bodenlosen und unzusammenhängenden Wesen, das ihnen in andern Fächern unter jenem Namen angeboten wird, sich hinweg wenden und das Tiefere, das Begründetere, Zusammenhängendere suchen, so ist ja dieß reiner Gewinn für die Wissenschaft selbst. Daß diejenigen, die noch frisch, ohne vorgefaßte Meinungen, mit dem ersten noch unverfälschten Sinn für Wahrheit zu den Wissenschaften kommen, vor jeder Luft eines Zweifels an dem, was bisher gegolten, oder selbst der Gewißheit der Ungültigkeit sorgfältig bewahrt und wie geistige Mumien einbalsamirt werden sollen, dafür habe ich wenigstens keinen Sinn. Um nur in die andern Wissenschaften eindringen zu können, müssen sie die Idee der Wahrheit aus der Philosophie empfangen haben, und gewiß wird jeder mit desto größerem Interesse zu einer Wissenschaft kommen, je mehr Ideen er zu ihr bringt; wie ich selbst während der Zeit, daß ich hier gelehrt habe, einen allgemeineren Eifer für alle Theile der Naturwissenschaft durch die Wirkung der Philosophie habe aufleben sehen. [Die Philosophie ist ihrer Natur nach zum Umfassenden, zum Allgemeinen hinstrebend. Wenn nun im einzelnen Menschen oder im Ganzen eines Geschlechts sich mit dem universellen Geist höherer Wissenschaftlichkeit und der Erleuchtung durch Ideen die lebendigste und mannichfaltigste Erkenntniß des Einzelnen verbindet, so entsteht jenes erfreuliche Gleichmaß der Bildung, woraus nur das Gesunde, Gerade, Tüchtige in aller Art von Wissenschaft und Handlung erwachsen kann. Wenn aber freilich in einem gegebenen wissenschaftlichen Zustand dem Trieb zu Umfassendem und Allgemeinen, der etwa durch Philosophie aufgeregt wird, weder die Fülle klassischer Bildung noch die einer"}]}, {"page_pdf": 1557, "page_book": 263, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "wahren, auf Naturanschauung gegründeten Erfahrung das Gleichgewicht hält, so ist unvermeidlich, daß das Ganze nach der Einen Seite sich neigend, früher oder später überstürze, an welch' traurigem Fall dann aber nicht die Philosophie Schuld ist, sondern die Schwäche oder der Mangel desjenigen, das ihr gegenüberstehen soll, und mit welchem zusammen sie allein den vollendeten Organismus der Bildung darzustellen vermag]. Die von dem Schaden, welchen Philosophie bei der Jugend stiftet, so viel zu sagen wissen, befinden sich in einem von beiden folgenden Fällen. Entweder haben sie sich wirklich die Wissenschaft dieser Philosophie verschafft oder nicht. In der Regel ist das Letzte der Fall: wie können sie also urtheilen? Oder das Erste: so verdanken sie selbst dem Studium der Philosophie den Nutzen, einzusehen, daß sie keinen Nutzen habe; wie man von Sokrates zu sagen pflegt, er habe seinem Wissen wenigstens so viel verdankt, zu wissen, daß er nichts wisse; diesen Nutzen sollten sie doch auch andern zu Theil werden lassen und nicht verlangen, daß man ihnen aufs Wort glaube, da die eigne Erfahrung doch ohnehin einen stärkeren Eindruck machen wird als ihre Versicherung; davon nichts zu sagen, daß ohne jene Kenntniß für die Jugend auch ihre scharfsinnige Polemik gegen diese Philosophie unverständlich und ihre Anspielungen dagegen, so grob sie übrigens seyn mögen, verloren waren. Der gewöhnliche Trost, den sie bei der Fruchtlosigkeit ihrer Warnungen und Vermahnungen sich selbst und untereinander geben, ist dann der: daß es mit der Philosophie doch keinen langen Bestand haben werde, daß sie nur die Sache einer Mode sey, die aber, wie noch immer geschehen, zu ihrer Zeit auch vorbeigehen werde, daß ja ohnehin alle Augenblicke neue Philosophien entstehen, und was dergleichen mehr ist. Was das Erste betrifft, so befinden sie sich ganz in dem Fall des Bauern, der an einen tiefen Strom kommend, ihn nur vom Regen geschwellt meint und wartet, bis er ablaufen wird."}, {"type": "paragraph", "text": "Rusticus expectat, dum defluat amnis; at ille Labitur et labetur in omne volubilis aevum."}, {"type": "paragraph", "text": "Was das Letzte betrifft, den schnellen Wechsel der Philosophien, so sind sie wirklich nicht im Stande zu beurtheilen, ob das, was sie so nennen, wirklich verschiedene *Philosophien* sind. Die scheinbaren Veränderungen der Philosophie existiren nur für die Unwissenden. Sie gehen entweder jene überhaupt nicht an, indem es allerdings und eben auch jetzt Bestrebungen genug gibt, die sich für philosophische ausgeben, in denen aber keine Spur davon anzutreffen ist; allein eben um das, was sich Philosophie nennt, ohne es zu seyn, von der Philosophie abzuscheiden, muß ja untersucht, und weil die, die jetzt jung sind, künftig doch auch untersuchen sollen, Philosophie studirt werden. Oder sie sind Verwandlungen, die einen wirklichen Bezug auf Philosophie haben, so sind es Metamorphosen ihrer Form. Ihr Wesen ist unwandelbar dasselbe, seit dem ersten, der es ausgesprochen hat; aber sie ist eine lebendige Wissenschaft, und es gibt einen philosophischen Kunsttrieb, wie es einen poetischen gibt. Wenn noch Umgestaltungen in der Philosophie stattfinden, so ist dieß Beweis, daß sie ihre letzte Form und absolute Gestalt noch nicht gewonnen hat. Es gibt untergeordnetere und höhere, es gibt einseitigere und umfassendere Formen: jede sogenannte neue Philosophie muß aber einen neuen Schritt in der Form gethan haben. Daß die Erscheinungen sich drängen, ist begreiflich, weil die vorhergehende unmittelbarer den Sinn schärft, den Trieb entzündet. Selbst aber auch, wenn die Philosophie in der absoluten Form wird dargestellt seyn - und war sie es denn noch nicht, soweit dieß überhaupt möglich ist? - wird es niemand"}]}, {"page_pdf": 1558, "page_book": 265, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "verwehrt seyn, sie wieder in besondere Formen zu fassen. Die Philosophen haben das ganz eigenthümlich voraus, daß sie in ihrer Wissenschaft ebenso einig als die Mathematiker sind (alle waren es, die überhaupt dafür gelten konnten), und daß doch jeder gleich original seyn kann, was jene nicht können. Die andern Wissenschaften könnten sich Glück wünschen, wenn erst bei ihnen jener Wechsel der Formen ernstlicher einträte. Um die absolute Form zu gewinnen, muß sich der Geist in allen versuchen, dieß ist das allgemeine Gesetz jeder freien Bildung."}, {"type": "paragraph", "text": "Mit der Nachrede, daß die Philosophie eine bloße Sache der Mode sey, kann es auch nicht so ernstlich gemeint seyn. Die sie vorbringen, würden gerade darum sich nur um so leichter damit vertragen. Wenn sie nicht ganz nach der Mode seyn wollen, so wollen sie doch auch nicht ganz altmodisch seyn, und wenn sie nur hie und da etwas, und wär' es bloß ein Wort, von der neueren oder neuesten Philosophie erhaschen können, verschmähen sie es ja doch nicht, sich damit auszuschmücken. Wär' es wirklich nur eine Sache der Mode, wie sie vorgeben, und demnach ebenso leicht, als es ist, einen Kleiderschnitt oder Hut mit dem andern zu verwechseln, auch ein System der Medicin, der Theologie u.s.w. nach den neuesten Grundsätzen aufzustellen, so würden sie gewiß nicht säumen es zu thun. Es muß also doch mit der Philosophie seine ganz eigenthümlichen Schwierigkeiten haben."}, {"type": "heading", "text": "Sechste Vorlesung. *Ueber das Studium der Philosophie insbesondere.*", "level": null}, {"type": "paragraph", "text": "Wenn das Wissen überhaupt an sich selbst Zweck ist, so muß dieß noch vielmehr und im vorzüglichsten Sinne von demjenigen Wissen gelten, in welchem alles andere eins, und welches die Seele und das Leben von ihm ist. Kann Philosophie erlernt, kann sie überhaupt durch Uebung, durch Fleiß erworben werden; oder ist sie ein angeborenes Vermögen, ein freies Geschenk und durch Schickung verliehen? Daß sie als solche nicht gelernt werden könne, ist in dem Vorhergehenden schon enthalten. Nur die Kenntniß von ihren besondern Formen läßt sich auf diesem Wege erlangen. Jene soll aber, bei dem Studium der Philosophie, außer der Ausbildung des nicht zu erwerbenden Vermögens, das Absolute zu fassen, mit beabsichtigt werden. Wenn gesagt wird, daß Philosophie nicht gelernt werden könne, so ist die Meinung nicht, daß deßwegen nun jeder sie ohne Uebung besitze, und daß man etwa ebenso von Natur philosophiren könne, als man sich von Natur besinnen oder Gedanken verbinden kann. Die meisten derjenigen, welche gegenwärtig in der Philosophie urtheilen oder gar sich einfallen lassen eigne Systeme auf die Bahn zu bringen, könnten sich von diesem Dünkel schon durch die Kenntniß des zuvor Gewesenen sattsam heilen. Es würde dann seltener geschehen, was so sehr gewöhnlich ist: daß man zu Irrthümern, die man schon abgelegt hat, durch seichtere Gründe, als welche man selbst"}]}, {"page_pdf": 1559, "page_book": 268, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "dafür zu haben glaubte, bekehrt werden soll; seltener, daß jemand sich überredete, mit ein paar Wortformeln den Geist der Philosophie zu beschwören, und die großen Gegenstände derselben zu fassen. Das, was von der Philosophie, nicht zwar eigentlich gelernt, aber doch durch Unterricht geübt werden kann, ist die Kunstseite dieser Wissenschaft, oder was man allgemein Dialektik nennen kann. Ohne dialektische Kunst ist keine wissenschaftliche Philosophie! Schon ihre Absicht, alles als eins darzustellen und in Formen, die ursprünglich dem Reflex angehören, dennoch das Urwissen auszudrücken, ist Beweis davon. Es ist dieses Verhältniß der Speculation zur Reflexion, worauf alle Dialektik beruht. Aber eben dieses Princip der Antinomie des Absoluten und der bloß endlichen Formen, so wie daß in der Philosophie Kunst und Produktion so wenig als Form und Stoff in der Poesie getrennt seyn können, beweist, daß auch die Dialektik eine Seite hat, von welcher sie nicht *gelernt *werden kann, und daß sie nicht minder, wie das, was man, der ursprünglichen Bedeutung des Worts gemäß, die Poesie in der Philosophie nennen könnte, auf dem produktiven Vermögen beruht1. Von dem innern Wesen des Absoluten, welches die ewige In-Eins-Bildung des Allgemeinen und Besondern selbst ist, ist in der erscheinenden Welt ein Ausfluß in der Vernunft und der Einbildungskraft, welche beide ein und dasselbige sind, nur jene im Idealen, diese im Realen. Mögen diejenigen, denen nichts als ein dürrer und unfruchtbarer Verstand zu Theil geworden ist, sich durch ihre Verwunderung schadlos halten, daß man zur Philosophie Einbildungskraft fordere. Statt desjenigen, was allein so genannt werden kann, ist ihnen nur die lebhafte Ideenassociation, die das Denken erschwert, oder die falsche Imagination als eine regellose Reproduktion sinnlicher Bilder bekannt. Jedes wahre durch Einbildungskraft geschaffene Kunstwerk ist die Auflösung des gleichen Widerspruchs mit dem, der in den Ideen vereinigt dargestellt ist. Der bloß reflektirende Verstand begreift nur einfache Reihen und die Idee, als Synthesis von Entgegengesetzten, als Widerspruch."}, {"type": "footnote", "text": "1 Produktivität des Geistes also erste Bedingung und zwar aller ächten Wissenschaft überhaupt, aber fürnehmlich der Wissenschaft alles Wissens."}, {"type": "paragraph", "text": "Das produktive Vermögen läßt sich, wo es ist, bilden, erhöhen und ins Unendliche durch sich selbst potenziiren: es läßt sich im Gegentheil auch im Keim ersticken oder wenigstens in der Entwicklung hemmen. Wenn es daher eine Anweisung über das Studium der Philosophie geben kann, so muß diese mehr negativer Art seyn. Man kann den Sinn für Ideen nicht schaffen; wo er nicht ist; man kann aber verhindern, daß er nicht erdrückt oder falsch geleitet werde. Der Trieb und die Begierde, das Wesen der Dinge zu erforschen, ist den Menschen allgemein so tief eingepflanzt, daß sie auch das Halbe, das Falsche mit Eifer ergreifen, wenn es nur den Schein und einige Hoffnung gibt, daß es sie zu dieser Erkenntniß führe. Anders begreift man nicht, wie bei einem im Ganzen recht ernstlichen Ernst die oberflächlichsten Versuche in der Philosophie Theilnahme erregen konnten, wenn sie nur in irgend einer Richtung Gewißheit versprachen. Der Verstand, den die Unphilosophie den gesunden nennt, da er nur der gemeine ist, verlangt gleichsam die baare und klingende Münze der Wahrheit und sucht sie sich ohne Rücksicht auf das Unzureichende seiner Mittel zu verschaffen. In die Philosophie übergreifend, erzeugt er die Ungeheuer einer rohen dogmatischen Philosophie, die mit dem Bedingten das Unbedingte zu ermessen, das Endliche zum Unendlichen auszudehnen sucht. Die Art zu schließen, welche in dem Gebiet des Abhängigen von dem einen zum andern reicht, soll ihm hier über die Kluft vom Abgeleiteten zum Absoluten helfen. - In der Regel versteigt er sich nicht einmal so weit, sondern bleibt unmittelbar bei dem, was er seine Thatsachen nennt, stehen. Die bescheidenste Philosophie in dieser Richtung ist die, welche allgemein zwar die Erfahrung als die einzige oder Hauptquelle realer Erkenntniß ausgibt, übrigens aber von den"}]}, {"page_pdf": 1560, "page_book": 269, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Ideen zuläßt, daß sie vielleicht Realität haben, die ihnen nur für unser Wissen gänzlich fehle. Man kann wohl sagen, daß eine solche Philosophie studiren schlimmer ist, als überhaupt keine kennen. Eben über die Thatsachen des Bewußtseyns zu etwas, was an sich selbst absolut wäre, hinaus zu kommen, ist die ursprüngliche Absicht aller Philosophie: diese Thatsachen-Erzählung dafür auszugeben, würde denen, die es pflegen,"}, {"type": "paragraph", "text": "nicht einmal eingekommen seyn, wäre nicht wahre Philosophie vorausgegangen1. Der bloße Zweifel an der gemeinen und endlichen Ansicht der Dinge ist ebenso wenig Philosophie; es muß zum kategorischen Wissen der Nichtigkeit desselben kommen, und dieses negative Wissen muß der positiven Anschauung der Absolutheit gleich werden, wenn es sich auch nur zum ächten Skepticismus erheben soll. Ganz zu den empirischen Versuchen in der Philosophie gehört auch, was man insgemein Logik nennt. Wenn diese eine Wissenschaft der Form, gleichsam die reine Kunstlehre der Philosophie seyn sollte, so müßte sie das seyn, was wir oben unter dem Namen der Dialektik charakterisirt haben. Eine solche existirt noch nicht. Sollte sie eine reine Darstellung der Formen der Endlichkeit in ihrer Beziehung aufs Absolute seyn, so müßte sie wissenschaftlicher Skepticismus seyn: dafür kann auch Kants transscendentale Logik nicht gehalten werden. Versteht man aber unter Logik eine rein formale, sich den Inhalt oder die Materie des Wissens entgegensetzende Wissenschaft, so wäre diese an sich eine der Philosophie direkt entgegengesetzte Scienz, da diese eben auf die absolute Einheit der Form und des Wesens geht oder - inwiefern sie den Stoff in empirischer Bedeutung als das Concrete von sich absondert - eben die absolute Realität, die zugleich absolute Idealität ist, darstellt. Sie ist demnach eine ganz empirische Doktrin, welche die Gesetze des gemeinen Verstandes als absolute aufstellt, z.B. daß von zwei contradiktorisch entgegengesetzten Begriffen jedem Wesen nur einer zukomme, was in der Sphäre der Endlichkeit seine vollkommene Richtigkeit hat, nicht aber in der Speculation, die nur in der Gleichsetzung Entgegengesetzter ihren Anfang hat. Auf gleiche Weise stellt sie Gesetze des Verstandesgebrauchs in seinen verschiedenen Funktionen als Urtheilen, Eintheilen, Schließen auf. Aber wie? Ganz empirisch, ohne ihre Nothwendigkeit zu beweisen, wegen der sie an die Erfahrung verweist, z.B. daß mit vier Begriffen zu schließen, oder in einer Eintheilung"}, {"type": "footnote", "text": "1 Vergl. Einleitung in die Philosophie der Mythologie, II. Abth., B. 1, S. 300. D. H."}, {"type": "paragraph", "text": "Glieder sich entgegenzusetzen, die in anderer Beziehung nicht wieder etwas Gemeinschaftliches haben, eine Ungereimtheit erzeuge. Gesetzt aber, die Logik ließe sich darauf ein, diese Gesetze aus speculativen Gründen als nothwendige für dieß reflektirte Erkennen zu beweisen, so wäre sie alsdann keine absolute Wissenschaft mehr, sondern eine besondere Potenz in dem allgemeinen System der Vernunftwissenschaft. Auf die vorausgesetzte Absolutheit der Logik gründet sich ganz die sogenannte Kritik der reinen Vernunft, welche diese nur in der Unterordnung unter den Verstand kennt1. In dieser [Unterordnung] wird die Vernunft als das Vermögen zu schließen erklärt, da sie vielmehr eine absolute Erkenntnißart ist, wie die durch Schluß eine durchaus bedingte. Wäre keine andere Erkenntniß des Absoluten als die durch Vernunftschlüsse, und keine andere Vernunft als die in der Form des Verstandes, so müßten wir allerdings auf alle unmittelbare"}]}, {"page_pdf": 1561, "page_book": 271, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "und kategorische Erkenntniß des Unbedingten und Uebersinnlichen, wie Kant lehrt, Verzicht thun. Solch ein großer Mißgriff, als es Kant vorgestellt hat, ist es nach diesem nicht, daß man der natürlichen Trockenheit der Logik durch anthropologische und psychologische Vorkenntnisse abzuhelfen gewußt hat, welches vielmehr ein recht gesundes Gefühl von dem Werth der ersten voraussetzt, wie auch alle, welche die Philosophie in Logik setzen, gleichsam eine angeborne Hinneigung zur Psychologie haben. Was übrigens von dieser sogenannten Wissenschaft an sich selbst zu halten sey, begreift sich aus dem Vorhergehenden von selbst. Sie beruht auf der angenommenen Entgegensetzung der Seele und des Leibes, und man kann leicht urtheilen, was bei Nachforschungen über etwas, das gar nicht existirt, nämlich eine dem Leib entgegengesetzte Seele, herauskommen kann. Alle wahre Wissenschaft des Menschen kann nur in der wesentlichen und absoluten Einheit der Seele und des Leibes, d.h. in der *Idee* des Menschen, also überhaupt nicht in dem wirklichen und empirischen Menschen, der von dieser [von der Idee] nur eine relative Erscheinung ist, gesucht werden."}, {"type": "footnote", "text": "1 Vergl. Ueber die Construktion in der Philosophie, oben S. 135. D. H."}, {"type": "paragraph", "text": "Eigentlich müßte von der Psychologie bei der Physik die Rede seyn, die nun ihrerseits mit dem gleichen Grunde das bloß Leibliche betrachtet und die Materie und die Natur für todt annimmt. Die wahre Naturwissenschaft kann ebensowenig aus dieser Trennung, sondern ihrerseits ebenso nur aus der Identität der Seele und des Leibes aller Dinge [d.h. aus der Idee] hervorgehen [denn was in allen Dingen der Natur lebt, ist ebenso nur die Idee, wie das, was in der Seele lebt]: so daß zwischen Physik und Psychologie kein realer Gegensatz denkbar ist. Selbst aber wenn man diesen zugeben wollte, würde man doch von der Psychologie so wenig als etwa von der Physik in derselben Entgegensetzung begreifen, wie sie an die Stelle der Philosophie gesetzt werden könnte. Da die Psychologie die Seele nicht in der Idee, sondern der Erscheinungsweise nach und allein im Gegensatz gegen dasjenige kennt, womit sie in jener eins ist, so hat sie die nothwendige Tendenz, alles im Menschen einem Causalzusammenhang unterzuordnen, nichts zuzugeben, was unmittelbar aus dem Absoluten oder Wesen selbst käme, und hiemit alles Hohe und Ungemeine herabzuwürdigen, [um besonders jene Vorstellung ganz zur Reife zu bringen, nach welcher in dem Menschen nichts auf göttliche Art entsteht. Alles, was gegen die Philosophie als Erkenntniß und Wissenschaft des Absoluten so insgemein vorgebracht wird, stammt aus dieser Seelenlehre her, und dieselbe Anwendung läßt sich von ihr auf die Religion, auf die Kunst, auf die Tugend machen]. Die großen Thaten [und Charaktere] der vergangenen Zeit [in dem herrlichen Leben der alten Welt] erscheinen, unter das psychologische Messer genommen, als das natürliche Resultat einiger ganz begreiflichen Motive. Die Ideen der Philosophie erklären sich aus mehreren sehr groben psychologischen Täuschungen. Die Werke der alten großen Meister der Kunst erscheinen als das natürliche Spiel einiger besondern Gemüthskräfte, und wenn z.B. Shakespeare ein großer Dichter ist, so ist es wegen seiner vortrefflichen Kenntniß des menschlichen Herzens und seiner äußerst feinen Psychologie. Ein Hauptresultat dieser Lehre ist das allgemeine Applanirungssystem der Kräfte, [der Sanscülottismus]. Wozu soll es doch etwas wie Einbildungskraft, Genie u.s.w. geben? Im"}]}, {"page_pdf": 1562, "page_book": 273, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Grunde sind doch alle einander gleich, und was man mit jenen Worten bezeichnet, ist doch nur das Uebergewicht der einen Seelenkraft über die andere, und insofern eine Krankheit, eine Abnormität, [eigentlich nur eine Art des Wahnsinns, in der noch Methode ist], statt daß bei den vernünftigen, ordentlichen, nüchternen Menschen alles in behaglichem Gleichgewicht und darum in vollkommener Gesundheit ist. Eine bloß empirische, auf Thatsachen beruhende, ebenso wie eine bloß analytische und formale Philosophie, kann überhaupt nicht zum Wissen bilden; eine einseitige Philosophie wenigstens nicht zum absoluten Wissen, da sie vielmehr für alle Gegenstände desselben nur einen eingeschränkten Gesichtspunkt bestimmt. Die Möglichkeit einer zwar speculativen, aber übrigens beschränkten Philosophie ist dadurch gegeben, daß, weil alles in allem wiederkehrt und auf allen möglichen Stufen dieselbe Identität nur unter verschiedenen Gestalten sich wiederholt, diese an einem untergeordneten Punkt der Reflexion aufgefaßt und in der besondern Form, in der sie auf diesem erscheint, zum Princip der absoluten Wissenschaft gemacht werden kann. Die Philosophie, die aus einem solchen Princip hervorgeht, ist speculativ, weil es nur der Abstraktion von der Beschränktheit der Auffassung und des Denkens der besondern Identität in der Absolutheit bedarf, um sich zu dem rein und schlechthin Allgemeinen zu erheben; sie ist einseitig, inwiefern sie dieß nicht thut und von dem Ganzen ein nach diesem Gesichtspunkt verzogenes und verschobenes Bild entwirft. Die neuere Welt ist allgemein die Welt der Gegensätze, und wenn in der alten, aller einzelnen Regungen ungeachtet, doch im Ganzen das Unendliche mit dem Endlichen unter einer gemeinschaftlichen Hülle vereinigt liegt, so hat der Geist der späteren Zeit zuerst diese Hülle gesprengt und jenes in absoluter Entgegensetzung mit diesem erscheinen lassen. Von der unbestimmbar größeren Bahn, welche dieser durch das Schicksal vorgezeichnet ist, übersehen wir nur einen so kleinen Theil, daß uns der Gegensatz leicht als das Wesentliche und die Einheit, in die er sich aufzulösen bestimmt ist, jederzeit nur als einzelne Erscheinung auffallen kann. Dennoch ist gewiß, daß diese höhere Einheit, welche"}, {"type": "paragraph", "text": "der gleichsam aus der unendlichen Flucht zurückgerufene Begriff mit dem Endlichen darstellen wird, gegen die gewissermaßen bewußtlos und noch vor der Trennung vorhandene Identität der alten Welt sich im Ganzen wiederum ebenso wie das Kunstwerk zu dem organischen Werk der Natur verhalten wird. Hiermit sey es übrigens wie es wolle, so ist offenbar, daß in der neueren Welt Mittel-Erscheinungen nothwendig sind, in denen der reine Gegensatz hervortritt: es ist nothwendig sogar, daß dieser in der Wissenschaft wie in der Kunst unter den verschiedensten Formen immer wiederkehre, bevor er sich zur wahrhaft absoluten Identität verklärt hat. Der Dualismus, als eine nicht nur überhaupt, sondern auch in seiner Wiederkehr nothwendige Erscheinung der neueren Welt, muß also das Uebergewicht durchaus auf seiner Seite haben, wie denn die in einzelnen Individuen durchgebrochene Identität fast für nichts gerechnet werden kann, da diese ja von ihrer Zeit ausgestoßen und verbannt, von der Nachwelt nur als merkwürdige Beispiele des Irrthums begriffen worden sind. Da in dem Verhältniß, in welchem die großen Objektivitäten der Staatsverfassungen und selbst des allgemeinen religiösen Vereins verschwanden, sich das göttliche Princip von der Welt zurückzog, so konnte in dem Aeußeren der Natur nichts als der reine entseelte Leib des Endlichen zurückbleiben, das Licht hatte sich ganz nach innen gewandt und die Entgegensetzung des Subjektiven und Objektiven mußte ihren höchsten Gipfel erreichen. Wenn man von Spinoza absieht, so ist seit Cartesius, in welchem die Entzweiung sich wissenschaftlich bestimmt ausgesprochen hatte1, bis auf diese Zeit keine ihr entgegengesetzte Erscheinung, da auch Leibnitz seine Lehre in einer Form aussprach, die der Dualismus"}]}, {"page_pdf": 1563, "page_book": 274, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "sich wieder aneignen konnte. Durch diese Zerreißung der Idee hatte auch das Unendliche seine Bedeutung verloren [die für die Vernunft] und diejenige, die es hatte, war ebenso wie jene Entgegensetzung selbst eine bloß subjektive. Diese Subjektivität vollkommen bis zur gänzlichen Verneinung der Realität des Absoluten geltend zu machen, war der erste Schritt, der zur Wiederherstellung der Philosophie"}, {"type": "footnote", "text": "1 Vgl. Ueber das Verhältniß der Naturphilosophie zur Philosophie etc., oben S. 116 und Ueber das Wesen der philos. Kritik, S. 15. D. H."}, {"type": "paragraph", "text": "geschehen konnte und durch die sogenannte kritische Philosophie wirklich geschehen ist. Der Idealismus der Wissenschaftslehre hat nachher diese Richtung der Philosophie vollendet. Der Dualismus nämlich ist auch in dem letztern unaufgehoben zurückgeblieben. Aber das Unendliche oder Absolute im Sinn des Dogmatismus ist bestimmter und mit der letzten Wurzel von Realität, die es in jenem hatte, aufgehoben worden. Als das An-sich mußte es ein absolut-Objektives schlechthin außer dem Ich seyn. Dieß ist undenkbar, indem ja eben dieses außer-dem-Ich-Setzen wieder ein Setzen für das Ich und demnach auch im Ich ist1. Dieses ist der ewige und unauflösliche Cirkel der Reflexion, der durch die Wissenschaftslehre aufs vollkommenste dargestellt ist. Die Idee des Absoluten ist in die Subjektivität, die sie der Richtung der spätern Philosophie zufolge nothwendig hatte, und aus welcher sie nur durch einen sich selbst mißverstehenden Dogmatismus scheinbar gesetzt worden war, dadurch restituirt, daß sie als eine bloß im Handeln und für das Handeln stattfindende Realität anerkannt ist, und man muß demnach den Idealismus in dieser Form als die vollkommen ausgesprochene, zum Bewußtseyn ihrer selbst gekommene Philosophie der neuern Welt betrachten. Im Cartesius, welcher ihr die erste Richtung auf die Subjektivität durch das cogito ergo sum gab, und dessen Einleitung der Philosophie (in seinen Meditationen) mit den späteren Begründungen derselben im Idealismus in der That ganz gleichlautend ist, konnten sich die Richtungen noch nicht rein gesondert darstellen, die Subjektivität von der Objektivität nicht vollkommen geschieden erscheinen. Aber seine eigentliche Absicht, seine wahre Vorstellung von Gott, Welt, Seele hat er deutlicher als durch seine Philosophie, über welche man ihn wegen des Ruhens auf dem ontologischen Beweis der Realität Gottes, dieses Restes ächter Philosophie, noch mißverstehen konnte, in seiner Physik ausgesprochen. Merkwürdig muß es allgemein erscheinen, daß durch denselbigen Geist, in welchem der Dualismus der Philosophie sich entschieden ausbildete, die mechanische Physik in der neueren Welt zuerst die Gestalt des Systems annahm. Mit dem umfassenden Geist des"}, {"type": "footnote", "text": "1 Vgl. Ueber das Verhältniß der Naturphilosophie etc. oben S. 110. D. H."}, {"type": "paragraph", "text": "Cartesius ließe sich die Annihilation der Natur, welcher sich der Idealismus in der oben angegebenen Gestalt rühmt, ebenso wahr und faktisch machen, als sie es in seiner Physik wirklich war. Es kann nämlich für die Speculation nicht den geringsten Unterschied machen, ob die Natur in ihrer empirischen Gestalt, im realen Sinn oder im idealen wirklich ist. Es ist völlig gleichgültig, ob die einzelnen wirklichen Dinge auf die Weise wirklich sind, wie sie ein grober Empirismus sich denkt, oder ob sie nur als"}]}, {"page_pdf": 1564, "page_book": 276, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Affektionen und Bestimmungen *eines jeden * Ich, als der absoluten Substanz, diesem aber wirklich und real inhäriren. Die wahre *Vernichtung *der Natur ist allerdings die, sie zu einem Ganzen absoluter Qualitäten, Beschränktheiten und Affektionen zu machen, welche gleichsam für ideale Atomen gelten können. Im Uebrigen bedarf es keines Beweises, daß eine Philosophie, die irgend einen Gegensatz zurückläßt und nicht wahrhaft die absolute Harmonie hergestellt hat, auch nicht zum *absoluten* Wissen durchgedrungen sey und noch weniger dazu bilden könne. Die Aufgabe, die sich jeder setzen muß, unmittelbar, wie er zur Philosophie gelangt, ist: die Eine wahrhaft absolute Erkenntniß, die ihrer Natur nach auch eine Erkenntniß des Absoluten ist, bis zur Totalität und bis zum vollkommnen Begreifen des Allen in Einem zu verfolgen. Die Philosophie öffnet in dem Absoluten und der Entfernung aller Gegensätze, wodurch dieses selbst wieder, es sey auf subjektive oder objektive Weise, in eine Beschränktheit verwandelt worden ist, nicht nur überhaupt das Reich der Ideen, sondern auch den wahren Urquell aller Erkenntniß der Natur, welche von jenen selbst nur das Werkzeug ist. Ich habe die letzte Bestimmung der neuern Welt schon im Vorhergehenden ausgesprochen, eine höhere, wahrhaft alles begreifende, Einheit darzustellen; sie gilt ebenso sehr für die Wissenschaft als für die Kunst, und eben damit jene sey, müssen alle Gegensätze sich entzweien. Bisher war von innern Gegensätzen in der Philosophie selbst die Rede, ich werde noch einiger äußeren erwähnen müssen, welche ihr Einseitigkeit, falsche Richtung der Zeit und unvollkommene Begriffe gegeben haben."}, {"type": "heading", "text": "Siebente Vorlesung. *Ueber einige äußere Gegensätze der Philosophie, vornämlich den der*", "level": null}, {"type": "paragraph", "text": "*positiven Wissenschaften*."}, {"type": "paragraph", "text": "Als ein äußerer Gegensatz der Philosophie ist der schon früher angeführte von Wissen und Handeln, in seiner Anwendung auf jene, zu betrachten. Dieser ist keineswegs ein solcher, der in dem Geist der modernen Kultur überhaupt gegründet wäre, er ist ein Produkt der neuesten Zeit, ein unmittelbarer Sprößling der wohlbekannten Aufklärerei. Dieser Richtung zufolge gibt es eigentlich nur eine praktische und keine theoretische Philosophie. Wie Kant, nachdem er in der theoretischen Philosophie die Idee Gottes, der Ewigkeit der Seele u.s.w. zu bloßen Ideen gemacht hatte, diesen dagegen in der sittlichen Gesinnung eine Art von Beglaubigung zu geben suchte, so spricht sich in jenen Bestrebungen nur die endlich glückliche Erreichung der vollkommenen Befreiung von Ideen aus, für welche eine angebliche Sittlichkeit das Aequivalent seyn soll. Sittlichkeit ist Gottähnliche Gesinnung, Erhebung über die Bestimmung durch das Concrete ins Reich des schlechthin Allgemeinen. Philosophie ist gleiche Erhebung, und darum mit der Sittlichkeit innig eins, nicht durch Unterordnung, sondern durch wesentliche und innere Gleichheit1. Es ist nur Eine Welt, welche so, wie sie im Absoluten"}, {"type": "footnote", "text": "1 Man vergl. Ueber das Verhältniß der Naturphilosophie zur Philosophie überhaupt, oben S. 122. D. H."}]}, {"page_pdf": 1565, "page_book": 277, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "ist, jedes in seiner Art und Weise abzubilden strebt, das Wissen als Wissen, das Handeln als Handeln. Die Welt des letzten ist daher in sich ebenso absolut als die des ersten, und die Moral eine nicht minder speculative Wissenschaft als die theoretische Philosophie. Jede besondere Pflicht entspricht einer besondern Idee und ist eine Welt für sich, wie jede Gattung in der Natur ihr Urbild hat, dem sie so viel möglich ähnlich zu seyn trachtet. Die Moral kann daher so wenig als Philosophie ohne Construktion gedacht werden. Ich weiß, daß eine Sittenlehre in diesem Sinne noch nicht existirt, aber die Principien und Elemente einer solchen liegen in der hergestellten Absolutheit der Philosophie. Die Sittlichkeit wird in der allgemeinen Freiheit objektivirt, und diese ist selbst nur gleichsam die öffentliche Sittlichkeit. Die Construktion dieser sittlichen Organisation ist eine ganz gleiche Aufgabe mit der Construktion der Natur und ruht auf speculativen Ideen. Der Zerfall der äußern und innern sittlichen Einheit müßte sich durch den Zerfall der Philosophie und die Auflösung der Ideen ausdrücken. Solange es aber nur die sichtbare Ohnmacht ist, welche die Sache des gemeinen Verstandes, da er in seiner natürlichen Gestalt nicht mehr erscheinen kann, unter dem erborgten Namen der Sittlichkeit führt, ist dieser kraftlose Chor nur die nothwendige, der Schwachheit zugegebene Begleitung des energischen Rhythmus der Zeit. Die Sittlichkeit, nachdem der Begriff derselben lange genug bloß negativ gewesen, in ihren positiven Formen zu offenbaren, wird ein Werk der Philosophie seyn. Die Scheu vor der Speculation, das angebliche Forteilen vom bloß Theoretischen zum Praktischen, bewirkt im Handeln nothwendig die gleiche Flachheit wie im Wissen. Das Studium einer streng theoretischen Philosophie macht uns am unmittelbarsten mit Ideen vertraut, und nur Ideen geben dem Handeln Nachdruck und sittliche Bedeutung. Ich erwähne noch eines andern äußeren Gegensatzes, den die Philosophie gefunden hat, des der Religion. Nicht in dem Sinn, in welchem zu anderer Zeit Vernunft und Glauben im Widerstreit vorgestellt"}, {"type": "paragraph", "text": "wurden, sondern in einem, neueren Ursprungs, nach welchem Religion als reine Anschauung des Unendlichen, und Philosophie, welche als Wissenschaft nothwendig aus der Identität derselben herausgeht, entgegengesetzt werden. Wir suchen vorerst, uns diesen Gegensatz verständlich zu machen, um nachher zu finden, worauf es mit ihm abgesehen sey. Daß die Philosophie ihrem Wesen nach ganz in der Absolutheit ist und auf keine Weise aus ihr herausgeht, ist eine vielfach ausgesprochene Behauptung. Sie kennt vom Unendlichen zum Endlichen keinen Uebergang, und beruht ganz auf der Möglichkeit, die Besonderheit in der Absolutheit und diese in jener zu begreifen, welches der Grund der Lehre von den Ideen ist. \"Aber eben daß der Philosoph die Besonderheit in der Absolutheit darstellt und nicht unmittelbar wie von Natur jene in dieser und diese in jener anschaut, setzt schon eine vorhergegangene Differenziirung und ein Herausgehen aus der Identität voraus.\" Nach dieser näheren Bestimmung würde der höchste Zustand des Geistes in Bezug auf das Absolute ein so viel möglich bewußtloses Brüten oder ein Stand der gänzlichen Unschuld seyn müssen, in welchem jenes Anschauen sich sogar selbst nicht als Religion begriffe, weil damit schon Reflexion und ein Heraustreten aus der Identität gesetzt wäre. Nachdem also die Philosophie die Idee des Absoluten hergestellt, von der Beschränkung der Subjektivität befreit und in objektiven Formen, soweit ihr dieß verstattet ist, darzustellen versucht hat, ist jenes als ein neues und gleichsam das letzte Mittel der Subjektivirung ergriffen worden, die Wissenschaft zu verachten, weil diese allgemeingültig, der Formlosigkeit entgegengesetzt, und mit Einem Wort, weil sie Wissenschaft ist. Es ist nicht zu verwundern, daß in einem Zeitalter, wo ein bestimmter Dilettantismus"}]}, {"page_pdf": 1566, "page_book": 279, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "sich fast über alle Gegenstände verbreitet hat, auch das Heiligste ihm nicht entgehen konnte, und diese Art des Nichtkönnens oder Nichtwollens sich in die Religion zurückzieht, um den höheren Anforderungen zu entgehen. Preis denen, die das Wesen der Religion neu verkündet, mit Leben und Energie dargestellt und ihrer Unabhängigkeit von Moral und Philosophie behauptet haben! Wenn sie wollen, daß Religion nicht durch"}, {"type": "paragraph", "text": "Philosophie erlangt werde, so müssen sie mit dem gleichen Grunde wollen, daß Religion nicht die Philosophie geben oder an ihre Stelle treten könne. Was unabhängig von allem objektiven Vermögen erreicht werden kann, ist jene Harmonie mit sich selbst, die zur innern Schönheit wird; aber diese auch objektiv, es sey in Wissenschaft oder Kunst, darzustellen, ist eine von jener bloß subjektiven Genialität sehr verschiedene Aufgabe. Die daher ihr an sich löbliches Bestreben nach jener Harmonie oder wohl gar nur das lebhaft gefühlte Bedürfniß derselben für das Vermögen halten, sie auch äußerlich zu offenbaren, werden ohne die höhere Bedingung mehr nur die Sehnsucht nach Poesie und Philosophie, als sie selbst, ausdrücken, in beiden auf das Formlose wirken, in der Philosophie das System verrufen, das sie, gleicherweise, zu machen und als Symbolik zu verstehen unfähig sind. Auch Poesie also und Philosophie, welche eine andere Art des Dilettantismus entgegensetzt, sind sich darin gleich, daß zu beiden ein aus sich selbst erzeugtes, ursprünglich ausgebornes Bild der Welt erfordert wird. Der größere Theil hält sich mit einem bloß socialen Bild der Welt zur Kunst hinlänglich ausgerüstet und fähig die ewigen Ideen derselben auszudrücken: immer noch der bessere im Vergleich mit jenen, die ohne die geringste Erfahrung der Welt, mit der Einfalt der Kinder, trübselig dichten. Der Empirismus ist in der Poesie ebensowohl und allgemeiner als in der Philosophie herrschend. Diejenigen, die auch etwa zufälligerweise in Erfahrung gebracht, daß alle Kunst von der Anschauung der Natur und des Universum aus und in sie zurückkehre, halten dieser Vorstellung zufolge die einzelnen Erscheinungen oder überhaupt Besonderheiten für die Natur, und meinen, die ihr eingeborne Poesie aufs vollkommenste zu fassen, indem sie jene zu Allegorien von Empfindungen und Gemüthszuständen machen, womit denn, wie leicht zu sehen, dem Empirismus und der Subjektivität, beiden ihr höchstes Recht widerfährt. In der obersten Wissenschaft ist alles eins und ursprünglich verknüpft, Natur und Gott, Wissenschaft und Kunst, Religion und Poesie, und wenn sie in sich alle Gegensätze aufhebt, steht sie auch mit nichts"}, {"type": "paragraph", "text": "anderem nach außen in wahrhafter oder anderer Entgegensetzung, als welche die Unwissenschaftlichkeit, der Empirismus, oder eine oberflächliche Liebhaberei, ohne Gestalt und Ernst, machen mögen. Die Philosophie ist unmittelbare Darstellung und Wissenschaft des Urwissens selbst, aber sie ist es nur *ideal*, nicht real. Könnte die Intelligenz, in Einem Akt des Wissens, das absolute Ganze, als ein in allen Theilen vollendetes System *real *begreifen, so hörte sie eben damit auf endlich zu seyn, sie begriffe Alles wirklich als Eines, aber sie begriffe eben deßwegen Nichts als Bestimmtes. Die *reale *Darstellung des Urwissens ist * alles andere *Wissen, von jenem durch das Element des Concreten geschieden aber in diesem herrscht auch die Absonderung und Trennung, und es kann nie in dem Individuum real eins werden, sondern allein in der Gattung, und auch in dieser nur für eine intellektuelle Anschauung, die den unendlichen Fortschritt als Gegenwart erblickt. Nun ist aber allgemein einzusehen, daß das reel-Werden einer Idee in beständigem Fortschritt, so daß zwar nie das Einzelne, aber doch das Ganze ihr angemessen ist, sich als *Geschichte *ausdrücke."}]}, {"page_pdf": 1567, "page_book": 281, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Geschichte ist weder das rein Verstandes-Gesetzmäßige, dem Begriff Unterworfene, noch das rein Gesetzlose, sondern was, mit dem Schein der Freiheit im Einzelnen, Nothwendigkeit im Ganzen verbindet. Das * wirkliche* Wissen, da es successive Offenbarung des Urwissens ist, hat demnach nothwendig eine historische Seite, und inwiefern alle Geschichte auf die Realisirung eines äußern Organismus als Ausdrucks von Ideen geht, hat die Wissenschaft auch das nothwendige Streben, sich eine objektive Erscheinung und äußere Existenz [einen äußern Organismus] zu geben. Diese äußere Erscheinung kann nur der Abdruck des innern Organismus des Urwissens selbst, und also der Philosophie seyn, nur daß sie getrennt darstellt, was in jenem, und ebenso in dieser, eines ist. Wir haben demnach vorerst den innern Typus der Philosophie von dem gemeinschaftlichen Quell der Form und des Stoffes abzuleiten, um jenem gemäß die Form eines äußern Organismus, in welchem das Wissen wahrhaft objektiv wird, zu bestimmen."}, {"type": "paragraph", "text": "Die reine Absolutheit für sich ist nothwendig auch reine Identität, aber die absolute Form dieser Identität ist: sich selbst auf ewige Weise Subjekt und Objekt zu seyn; dieses können wir als bereits bewiesen voraussetzen. Nicht das Subjektive oder Objektive in diesem ewigen Erkenntnißakt, als solches, ist die Absolutheit, sondern das, was von beiden das gleiche Wesen ist, und was eben deßwegen durch keine Differenz getrübt wird. Dieselbe identische Wesenheit ist in dem, was wir die objektive Seite jenes absoluten Producirens nennen können, als Idealität in die Realität, und in dem, was die subjektive, als Realität in die Idealität gebildet, so daß in jeder von beiden die gleiche Subjekt-Objektivität, und in der absoluten Form auch das ganze Wesen des Absoluten gesetzt ist1. Bezeichnen wir diese zwei Seiten als zwei Einheiten, so ist das Absolute an sich weder die eine noch die andere dieser Einheiten, denn es selbst ist ja eben nur die Identität, das gleiche Wesen einer jeden auch selbst nicht bloß die Indifferenz und dadurch beides, und demnach sind beide im Absoluten, obwohl auf eine nicht unterschiedene Weise, da in beiden der Form und dem Wesen nach dasselbige ist. Wird nun das Absolute als dasjenige aufgefaßt, was an sich reine Identität, aber als diese zugleich das nothwendige Wesen der beiden Einheiten ist, so haben wir damit den absoluten Indifferenzpunkt der Form und des Wesens aufgefaßt, denjenigen, von dem alle Wissenschaft und Erkenntniß ausfließt2. Jede der beiden Einheiten ist in der Absolutheit, was die andere ist. Aber so nothwendig die wesentliche Einheit beider der Charakter der Absolutheit selbst ist, so nothwendig ist es, daß beide in der Nicht-Absolutheit als Nicht-eines und verschieden erscheinen. Denn gesetzt in der Erscheinung würde nur die eine unterschieden, so wäre diese auch *als* die eine im Absoluten; demnach als ausschließend die entgegengesetzte, und sonach selbst als nicht absolut; welches gegen die Voraussetzung ist. Beide differenziiren sich also für die Erscheinung nothwendig, wie sich das absolute Leben der Weltkörper durch zwei relativ-verschiedene"}, {"type": "footnote", "text": "1 Vergl. Ueber die Construktion in der Philosophie, oben S. 136. D. H. 2 a.a.O., S. 131. D. H."}, {"type": "paragraph", "text": "Brennpunkte ausdrückt. Die Form, die in der Absolutheit mit dem Wesen eines und es selbst war, wird als Form unterschieden. In der ersten als Einbildung der ewigen Einheit in die Vielheit, der Unendlichkeit in die Endlichkeit. Dieses ist die Form der Natur, welche, wie sie erscheint, jederzeit nur ein Moment"}]}, {"page_pdf": 1568, "page_book": 283, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "oder Durchgangspunkt in dem ewigen Akt der Einbildung der Identität in die Differenz ist. Rein für sich betrachtet ist sie die Einheit, wodurch sich die Dinge oder Ideen von der Identität als ihrem Centro entfernen und in sich selbst sind. Die Naturseite ist also an sich selbst nur die eine Seite aller Dinge. Die Form der andern Einheit wird als Einbildung der Vielheit in die Einheit, der Endlichkeit in die Unendlichkeit unterschieden und ist die der idealen oder geistigen Welt. Diese rein für sich betrachtet ist die Einheit, wodurch die Dinge in die Identität als ihr Centrum zurückgehen und im Unendlichen sind, wie sie durch die erste in sich selbst sind. Die Philosophie betrachtet die beiden Einheiten nur in der Absolutheit, und demnach auch nur in ideeller, nicht reeller Entgegensetzung. Ihr nothwendiger Typus ist: den absoluten Centralpunkt gleicherweise in den beiden relativen und hinwiederum diese in jenem darzustellen, und diese Grundform, welche im Ganzen ihrer Wissenschaft herrschend ist, wiederholt sich nothwendig auch im Einzelnen. Dieser innere Organismus des Urwissens und der Philosophie ist es nun auch, welcher in dem äußeren Ganzen der Wissenschaften sich ausdrücken und durch Trennung und Verbindung derselben zu einem Körper construiren muß. Alles Objektivwerden des Wissens geschieht nur durch Handeln, welches selbst wieder sich äußerlich durch ideale Produkte ausdrückt. Das allgemeinste derselben ist der Staat, der, wie schon früher bemerkt wurde, nach dem Urbild der Ideenwelt geformt ist. Aber eben weil der Staat selbst nur ein objektiv gewordenes Wissen ist, begreift er nothwendig in sich wieder einen äußern Organismus für das Wissen als solches, gleichsam einen ideellen und geistigen Staat: die Wissenschaften aber, insofern sie durch oder in Bezug auf den Staat Objektivität erlangen, heißen positive Wissenschaften. Der Uebergang in"}, {"type": "paragraph", "text": "die Objektivität setzt nothwendig die allgemeine Trennung der Wissenschaften als besonderer, da sie nur im Urwissen eins sind. Aber der äußere Schematismus ihrer Trennung und ihrer Vereinigung muß doch wieder nach dem Bild des innern Typus der Philosophie entworfen seyn. Nun beruht dieser vorzüglich auf drei Punkten, dem absoluten Indifferenzpunkt, in welchem reale und ideale Welt als eins erblickt werden, und den zwei nur relativ oder ideell entgegengesetzten, wovon der eine der im Realen ausgedrückte absolute und das Centrum der realen Welt, der andere der im Idealen ausgedrückte absolute und das Centrum der idealen Welt ist. Es wird also auch der äußere Organismus des Wissens vorzüglich auf drei voneinander geschiedenen und doch äußerlich verbundenen Wissenschaften beruhen. Die erste, welche den absoluten Indifferenzpunkt objektiv darstellt, wird die unmittelbare Wissenschaft des absoluten und göttlichen Wesens, demnach die Theologie, seyn. Von den beiden andern wird diejenige, welche die reelle Seite der Philosophie für sich nimmt und diese äußerlich repräsentirt, die Wissenschaft der Natur, und insofern diese nicht nur überhaupt sich in der des Organismus concentrirt, sondern auch, wie nachher näher gezeigt werden soll, nur in der Beziehung auf denselben positiv seyn kann, die Wissenschaft des Organismus, also die Medicin, seyn. Die, welche die ideelle Seite der Philosophie in sich getrennt objektivirt, wird allgemein die Wissenschaft der Geschichte, und inwiefern das vorzüglichste Werk der letzten die Bildung der Rechtsverfassung ist, die Wissenschaft des Rechts, oder die Jurisprudenz, seyn. Insofern die Wissenschaften durch den Staat und in ihm eine wirklich objektive Existenz erlangen, eine Macht werden, heißen die Verbindungen für jede derselben insbesondere *Facultäten. *Um von den Verhältnissen derselben untereinander das Nöthige zu bemerken, besonders da Kant in der Schrift: Streit der Facultäten, diese Frage nach sehr einseitigen Gesichtspunkten betrachtet zu haben scheint, so ist offenbar, daß die Theologie, als diejenige, in welcher das Innerste der Philosophie objektivirt ist, die erste und oberste seyn müsse: insofern"}]}, {"page_pdf": 1569, "page_book": 284, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "das Ideale die höhere Potenz des Realen ist, folgt, die juridische Fakultät der medicinischen vorangehe. Was aber die philosophische betrifft, so ist meine Behauptung, daß es überhaupt keine solche gebe noch geben könne, und der ganz einfache Beweis dafür ist: daß das, was alles ist, eben deßwegen nichts insbesondere seyn kann [sowie daß Philosophie nur freier Verein]. Es ist die Philosophie selbst, welche in den drei positiven Wissenschaften objektiv wird, aber sie wird durch keine einzelne derselben in ihrer Totalität objektiv. Die wahre Objektivität der Philosophie in ihrer Totalität ist nur die Kunst; es könnte also auf jeden Fall keine philosophische, sondern nur eine Facultät der Künste geben. Allein die Künste können nie eine äußere Macht und ebensowenig durch den Staat privilegirt als beschränkt seyn. [Dieß ist nur mit den drei ersten Wissenschaften der Fall. Nur der Philosophie ist der Staat unbedingte Freiheit schuldig, er wollte sie denn ganz vernichten, welches das größte Unglück der übrigen Wissenschaften seyn würde]. Es gibt also nur freie Verbindungen für die Kunst: und dieß war auch auf den älteren Universitäten der Sinn der jetzt sogenannten philosophischen Facultät, welche Collegium Artium hieß, wie die Mitglieder desselben Artisten. Diese Verschiedenheit der philosophischen Facultät von den übrigen hat sich bis jetzt noch darin erhalten, daß jene nicht wie diese privilegirte, dagegen auch in Staatspflicht genommene Lehrer (Doctores), sondern Meister (Magistros) der freien Künste creirt. Man könnte sich über die aufgestellte Behauptung auch darauf berufen, daß, wo philosophische Fakultäten sich nicht, ihrer ersten Bestimmung gemäß, als freie Vereinigungen für die Kunst betrachtet haben, und der besondere Geist der Innung in ihnen herrschend war, sie im Ganzen und Einzelnen Carricatur und Gegenstand des allgemeinen Spottes wurden, da sie ihrem Beruf nach billig die höchste und allgemeinste Achtung genießen sollten. Daß Theologie und Jurisprudenz eine positive Seite haben, wird allgemein angenommen; verwickelter ist es, dieselbe für die Naturwissenschaft aufzuzeigen. Die Natur ist eine geschlossene in sich ruhende"}, {"type": "paragraph", "text": "Objektivwerdung des Urwissens; ihr Gesetz ist die Endlichkeit wie das der Geschichte die Unendlichkeit. Hier kann also das Historische des Wissens nicht in den Gegenstand an und für sich, sondern nur in das Subjekt fallen: die Natur handelt immer in ihrer Integrität und mit offenbarer Nothwendigkeit, und inwiefern ein einzelnes Handeln oder eine Begebenheit als solche in ihr gesetzt werden soll, muß es durch die Bestimmung des Subjekts geschehen. Ein solches Bestimmen der Natur zum Handeln, unter gewissen Bedingungen mit Ausschluß anderer, ist, was Experiment heißt. Dieses also gibt der Naturlehre eine historische Seite, da es eine veranstaltete Begebenheit ist, von welcher, wer sie veranstaltet, den Zeugen macht. Aber auch in diesem Sinne hat die Naturwissenschaft doch nicht jene äußere Existenz wie z.B. die Rechtsgelehrsamkeit; sie wird daher zu den positiven nur insofern gezählt, als das Wissen in ihr zur äußern und öffentlichen Pflicht wird. Dieses ist allein in der Medicin der Fall. Damit haben wir den ganzen Körper der positiven Wissenschaften in seinem Gegensatz gegen Philosophie und den Widerstreit des absoluten und historischen Wissens in seiner ganzen Ausdehnung. Was im Allgemeinen über die Behandlung aller besondern Fächer im Geist der Ein- und Allheit gesagt wurde, wird erst jetzt die Probe der Ausführbarkeit bestehen und seiner Möglichkeit nach gerechtfertigt werden müssen."}]}, {"page_pdf": 1570, "page_book": 287, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "heading", "text": "Achte Vorlesung. *Ueber die historische Construktion des Christenthums.*", "level": null}, {"type": "paragraph", "text": "Die realen Wissenschaften überhaupt können von der absoluten als der idealen allein durch das historische Element geschieden oder besondere seyn. Aber die Theologie hat außer dieser allgemeinen Beziehung auf die Geschichte noch eine, die ihr ganz eigenthümlich ist und zu ihrem Wesen insbesondere gehört. Da sie als das wahre Centrum des Objektivwerdens der Philosophie vorzugsweise in speculativen Ideen ist, so ist sie überhaupt die höchste Synthese des philosophischen und historischen Wissens; und als solche sie darzustellen, ist der Hauptzweck folgender Betrachtungen. Ich gründe die historische Beziehung der Theologie nicht allein darauf: daß der erste Ursprung der Religion überhaupt so wie jeder andern Erkenntniß und Cultur allein aus dem Unterricht höherer Naturen begreiflich ist, alle Religion also in ihrem ersten Daseyn schon Ueberlieferung war; denn was die sonst gangbaren empirischen Erklärungsarten betrifft, deren einige die erste Idee von Gott oder Göttern aus Furcht, aus Dankbarkeit oder andern Gemüthsbewegungen, andere durch eine schlaue Erfindung der ersten Gesetzgeber entstehen lassen, so begreifen jene die Idee Gottes überhaupt nur als die psychologische Erscheinung, so wie diese weder erklären, wie nur überhaupt jemand zuerst den Gedanken gefaßt, sich zum Gesetzgeber eines Volkes zu machen, noch wie er Religion insbesondere als Schreckmittel zu brauchen sich einfallen"}, {"type": "paragraph", "text": "lassen konnte, ohne zuvor die Idee derselben aus einer andern Quelle zu haben. Unter der Menge falscher und ideenloser Versuche der letzten Zeit stehen die sogenannten Geschichten der Menschheit oben an, welche ihre Vorstellungen von dem ersten Zustand unsers Geschlechts von den aus Reisebeschreibungen compilirten Zügen der Rohheit wilder Völker hernehmen, welche daher auch in ihnen die vornehmste Rolle spielen. Es gibt keinen Zustand der Barbarei, der nicht aus einer untergegangenen Cultur herstammte. Den künftigen Bemühungen der Erdgeschichte ist es vorbehalten zu zeigen, wie auch jene in einem Zustand der Wildheit lebenden Völker nur von dem Zusammenhang mit der übrigen Welt durch Revolutionen losgerissene und zum Theil zersprengte Völkerschaften sind, die der Verbindung und der schon erworbenen Mittel der Cultur beraubt in den gegenwärtigen Zustand zurücksanken. Ich halte den Zustand der Cultur durchaus für den ersten des Menschengeschlechts, und die erste Gründung der Staaten, der Wissenschaften, der Religion und der Künste für gleichzeitig oder vielmehr für eins, so daß dieß alles nicht wahrhaft gesondert, sondern in der vollkommensten Durchdringung war, wie es einst in der letzten Vollendung wieder seyn wird. Auch darauf gründet sich die historische Beziehung der Theologie nicht allein, daß die besondern Formen des Christenthums, in welchen die Religion unter uns existirt, nur geschichtlich erkannt werden können. Die absolute Beziehung ist, daß in dem Christenthum das Universum überhaupt als *Geschichte*, als moralisches Reich, angeschaut wird, und daß diese allgemeine Anschauung den Grundcharakter desselben ausmacht. Vollkommen können wir dieß nur im Gegensatz gegen die Religion hauptsächlich des griechischen Alterthums einsehen. Wenn ich der noch älteren, vorzüglich der Indischen nicht erwähne, so ist es, weil sie in dieser Beziehung keinen Gegensatz bildet, ohne deßwegen, nach meiner"}]}, {"page_pdf": 1571, "page_book": 288, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Meinung, die Einheit zu seyn. Die Ansicht von dieser hier vollständig mitzutheilen, erlauben die nothwendigen Schranken dieser Untersuchung nicht, wir werden sie daher nur beiläufig aussprechen oder berühren können. Die Mythologie der Griechen war eine geschlossene"}, {"type": "paragraph", "text": "Welt von Symbolen der Ideen, welche real nur als Götter angeschaut werden können. Reine Begrenzung von der einen und ungetheilte Absolutheit von der andern Seite ist das bestimmende Gesetz jeder einzelnen Göttergestalt, eben so wie der Götterwelt im Ganzen. Das Unendliche wurde nur im Endlichen angeschaut und auf diese Weise selbst der Endlichkeit untergeordnet. Die Götter waren Wesen einer höhern Natur, bleibende unwandelbare Gestalten. Ganz anders ist das Verhältniß einer Religion, die auf das Unendliche unmittelbar an sich selbst geht, in welcher das Endliche nicht als Symbol des Unendlichen, zugleich um seiner selbst willen, sondern nur als Allegorie des ersten und in der gänzlichen Unterordnung unter dasselbe gedacht wird. Das Ganze, worin die Ideen einer solchen Religion objektiv werden, ist nothwendig selbst ein Unendliches, keine nach allen Seiten vollendete und begrenzte Welt: die Gestalten nicht bleibend, sondern erscheinend, nicht ewige Naturwesen, sondern historische Gestalten, in denen sich das Göttliche nur vorübergehend offenbaret, und deren flüchtige Erscheinung allein durch den Glauben festgehalten werden kann, niemals aber in eine absolute Gegenwart verwandelt wird. Da, wo das Unendliche selbst endlich werden kann, kann es auch Vielheit werden; es ist Polytheismus möglich: da, wo es durch das Endliche nur bedeutet wird, bleibt es nothwendig eins, und es ist kein Polytheismus als ein Zugleichseyn göttlicher Gestalten möglich. Er entspringt durch Synthese der Absolutheit mit der Begrenzung, so daß in derselben weder die Absolutheit der Form nach noch die Begrenzung aufgehoben wird. In einer Religion wie das Christenthum kann diese nicht von der Natur hergenommen werden, da sie das Endliche überhaupt nicht als Symbol des Unendlichen und in unabhängiger Bedeutung begreift. Sie kann also nur von dem, was in die Zeit fällt, demnach der *Geschichte *hergenommen seyn, und darum ist das Christenthum seinem innersten Geist nach und im höchsten Sinne historisch. Jeder besondere Moment der Zeit ist Offenbarung einer besonderen Seite Gottes, in deren jeder er absolut ist; was die griechische Religion als ein Zumal hatte, hat das Christenthum als ein Nacheinander, wenn"}, {"type": "paragraph", "text": "gleich die Zeit der Sonderung der Erscheinungen und mit ihr der Gestaltung noch nicht gekommen ist. Es ist schon früher angedeutet worden, daß sich Natur und Geschichte überhaupt als die reale und ideale Einheit verhalten; aber ebenso verhält sich die Religion der griechischen Welt zu der christlichen, in welcher das Göttliche aufgehört hat sich in der Natur zu offenbaren und nur in der Geschichte erkennbar ist. Die Natur ist allgemein die Sphäre des in-sich selbst-Seyns der Dinge, in der diese, kraft der Einbildung des Unendlichen in ihr Endliches, als Symbole der Ideen zugleich ein von ihrer Bedeutung unabhängiges Leben haben. Gott wird daher in der Natur gleichsam exoterisch, das Ideale erscheint durch ein anderes als es selbst, durch ein Seyn; aber nur inwiefern dieses Seyn für das Wesen, das Symbol unabhängig von der Idee genommen wird, ist das Göttliche wahrhaft exoterisch, der Idee nach aber esoterisch. In der idealen Welt, also vornehmlich der Geschichte, legt das Göttliche die Hülle ab, sie ist das laut gewordene Mysterium des göttliche Reiches. Wie in den Sinnbildern der Natur lag in den griechischen Dichtungen die Intellektualwelt wie in einer Knospe verschlossen, verhüllt im Gegenstand und unausgesprochen im Subjekt. Das Christenthum"}]}, {"page_pdf": 1572, "page_book": 290, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "dagegen ist das geoffenbarte Mysterium und, wie das Heidenthum seiner Natur nach exoterisch, ebenso seiner Natur nach esoterisch. Mit dem Christenthum mußte sich eben deßwegen auch das ganze Verhältniß der Natur und der idealen Welt umkehren, und wie jene im Heidenthum das Offenbare war, dagegen diese als Mysterium zurücktrat, so mußte im Christenthum vielmehr, in dem Verhältniß als die ideelle Welt offenbar wurde, die Natur als Geheimniß zurücktreten. Den Griechen war die Natur unmittelbar und an sich selbst göttlich, weil auch ihre Götter nicht außer- und übernatürlich waren. Der neueren Welt war sie verschlossen, weil diese sie nicht an sich selbst, sondern als Gleichniß der unsichtbaren und geistigen Welt begriff. Die lebendigsten Erscheinungen der Natur, wie die der Elektricität und der Körper, wenn sie sich chemisch verändern, waren den Alten kaum bekannt, oder erweckten wenigstens unter ihnen nicht den allgemeinen"}, {"type": "paragraph", "text": "Enthusiasmus, mit dem sie in der neueren Welt aufgenommen wurden1. Die höchste Religiosität, die sich in dem christlichen Mysticismus ausdrückte, hielt das Geheimniß der Natur und das der Menschwerdung Gottes für eins und dasselbe. Ich habe schon anderwärts (im System des transscendentalen Idealismus) gezeigt, daß wir überhaupt drei Perioden der Geschichte, die der Natur, des Schicksals und der Vorsehung, annehmen müssen. Diese drei Ideen drücken dieselbe Identität, aber auf verschiedene Weise aus. Auch das Schicksal ist Vorsehung, aber im Realen erkannt, wie die Vorsehung auch Schicksal ist, aber im Idealen angeschaut. Die ewige Nothwendigkeit offenbart sich, in der Zeit der Identität mit ihr, als Natur, wo der Widerstreit des Unendlichen und Endlichen noch im gemeinschaftlichen Keim des Endlichen verschlossen ruht. So in der Zeit der schönsten Blüthe der griechischen Religion und Poesie. Mit dem Abfall von ihr offenbart sie sich als Schicksal, indem sie in den wirklichen Widerstreit mit der Freiheit tritt. Dieß war das Ende der alten Welt, deren Geschichte eben deßwegen im Ganzen genommen als die tragische Periode betrachtet werden kann. Die neue Welt beginnt mit einem allgemeinen Sündenfall, einem Abbrechen des Menschen von der Natur. Nicht die Hingabe an diese selbst ist die Sünde, sondern, solange sie ohne Bewußtseyn des Gegentheils ist, vielmehr das goldne Zeitalter. Das Bewußtseyn darüber hebt die Unschuld auf und fordert daher auch unmittelbar die Versöhnung und die freiwillige Unterwerfung, in der die Freiheit als besiegt und siegend zugleich aus dem Kampf hervorgeht. Diese bewußte Versöhnung, die an die Stelle der bewußtlosen Identität mit der Natur und an die der Entzweiung mit dem Schicksal tritt und auf einer höhern Stufe die Einheit wiederherstellt, ist in der Idee der Vorsehung ausgedrückt. Das Christenthum also leitet in der Geschichte jene Periode der Vorsehung ein, wie die in ihm herrschende Anschauung des Universum die Anschauung desselben als Geschichte und als einer Welt der Vorsehung ist."}, {"type": "footnote", "text": "1 Vergl. Ueber das Verhältniß der Naturphilosophie überhaupt, oben S. 121. D. H."}, {"type": "paragraph", "text": "Dieß ist die große historische Richtung des Christenthums: dieß der Grund, warum die Wissenschaft der Religion in ihm von der Geschichte unzertrennlich, ja mit ihr völlig eins seyn muß. Jene Synthese mit der Geschichte, ohne welche Theologie selbst nicht gedacht werden kann, fordert aber hinwiederum zu ihrer Bedingung die höhere christliche Ansicht der Geschichte. Der Gegensatz, der insgemein zwischen Historie und Philosophie gemacht wird, besteht nur, solange"}]}, {"page_pdf": 1573, "page_book": 292, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "die Geschichte als eine Reihe zufälliger Begebenheiten oder als bloß empirische Nothwendigkeit begriffen wird: das Erste ist die ganz gemeine Ansicht, über die sich die andere zu erheben meint, da sie ihr an Beschränkung gleich ist. Auch die Geschichte kommt aus einer ewigen Einheit und hat ihre Wurzel ebenso im Absoluten wie die Natur oder irgend ein anderer Gegenstand des Wissens. Die Zufälligkeit der Begebenheiten und Handlungen findet der gemeine Verstand vorzüglich durch die Zufälligkeit der Individuen begründet. Ich frage dagegen: was ist denn dieses oder jenes Individuum anders als eben das, welches diese oder jene bestimmte Handlung ausgeführt hat; einen andern Begriff gibt es von ihm nicht: war also die Handlung nothwendig, so war es auch das Individuum. Was selbst von einem noch untergeordneten Standpunkt allein als frei und demnach objektiv zufällig in allem Handeln erscheinen kann, ist bloß, daß das Individuum von dem, was vorherbestimmt und nothwendig ist, dieses Bestimmte gerade zu *seiner *That macht: übrigens aber, und was den Erfolg betrifft, ist es, im Guten wie im Bösen, Werkzeug der absoluten Nothwendigkeit. Die empirische Nothwendigkeit ist nichts anderes als eine Art, die Zufälligkeit durch ein Zurückschieben der Nothwendigkeit ins Unendliche zu verlängern. Wenn wir diese Art der Nothwendigkeit in der Natur nur für die Erscheinung gelten lassen, wie vielmehr in der Geschichte? Wer, von höherem Sinn, wird sich bereden, daß Begebenheiten, wie die Ausbildung des Christenthums, die Völkerwanderung, die Kreuzzüge und so viele andere große Ereignisse, ihren wahren Grund in den empirischen Ursachen gehabt haben, die man gewöhnlich dafür"}, {"type": "paragraph", "text": "ausgibt? Und wenn diese wirklich obwalteten, so sind sie in dieser Beziehung wiederum nur die Werkzeuge einer ewigen Ordnung der Dinge. Was von Geschichte überhaupt gilt, muß insbesondere von der der Religion gelten, nämlich daß sie in einer ewigen Nothwendigkeit gegründet und also eine Construktion derselben möglich sey, wodurch sie mit der Wissenschaft der Religion innigst eins und verbunden wird. Die historische Construktion des Christenthums kann von keinem andern Punkt als der allgemeinen Ansicht ausgehen, daß das Universum überhaupt, und so auch in wiefern es Geschichte ist, nothwendig nach zwei Seiten differenziirt erscheine, und dieser Gegensatz, welchen die neuere Welt gegen die alte macht, ist für sich zureichend, das Wesen und alle besonderen Bestimmungen des Christenthums einzusehen. Die alte Welt ist insofern wieder die Naturseite der Geschichte, als die in ihr herrschende Einheit oder Idee Seyn des Unendlichen im Endlichen ist. Der Schluß der alten Zeit und die Grenze einer neuen, deren herrschendes Princip das Unendliche war, konnte nur dadurch gemacht werden, daß das wahre Unendliche in das Endliche kam, nicht um dieses zu vergöttern, sondern um es in seiner eignen Person Gott zu opfern und dadurch zu versöhnen. Die erste Idee des Christenthums ist daher nothwendig der Menschgewordene Gott, Christus als Gipfel und Ende der alten Götterwelt. Auch er verendlicht in sich das Göttliche, aber er zieht nicht die Menschheit in ihrer Hoheit, sondern in ihrer Niedrigkeit an, und steht als eine von Ewigkeit zwar beschlossene, aber in der Zeit vergängliche Erscheinung da, als Grenze der beiden Welten; er selbst geht zurück ins Unsichtbare, und verheißt statt seiner nicht das ins Endliche kommende, im Endlichen bleibende Princip, sondern den Geist, das ideale Princip, welches vielmehr das Endliche zum Unendlichen zurückführt und als solches das Licht der neuen Welt ist. An diese erste Idee knüpfen sich alle Bestimmungen des Christenthums. Die Einheit des Unendlichen und Endlichen objektiv durch eine Symbolik, wie die griechische Religion, darzustellen, ist seiner ideellen Richtung nach unmöglich. Alle Symbolik fällt ins Subjekt zurück,"}]}, {"page_pdf": 1574, "page_book": 294, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "und die nicht äußerlich, sondern bloß innerlich zu schauende Auflösung des Gegensatzes bleibt daher Mysterium, Geheimniß. Die durch alles hindurchgehende Antinomie des Göttlichen und Natürlichen hebt sich allein durch die subjektive Bestimmung auf, beide auf eine unbegreifliche Weise als eins zu denken. Eine solche subjektive Einheit drückt der Begriff des Wunders aus. Der Ursprung jeder Idee ist nach dieser Vorstellung ein Wunder, da sie in der Zeit entsteht, ohne ein Verhältniß zu ihr zu haben. Keine derselben kann auf zeitliche Weise entstehen, es ist das absolute, d.h. es ist Gott selbst, der sie offenbart, und darum der Begriff der Offenbarung ein schlechthin nothwendiger im Christenthum. Eine Religion, die als Poesie in der Gattung lebt1, bedarf so wenig einer historischen Grundlage, als die immer offene Natur ihrer bedarf. Wo das Göttliche nicht in bleibenden Gestalten lebt, sondern in flüchtigen Erscheinungen vorübergeht, bedarf es der Mittel, diese fest zu halten und durch Ueberlieferung zu verewigen. Außer den eigentlichen Mysterien der Religion gibt es nothwendig eine Mythologie, welche die exoterische Seite derselben ist, und die sich auf die Religion gründet, wie sich die Religion der ersten Art vielmehr umgekehrt auf die Mythologie gründete. Die Ideen einer auf Anschauung des Unendlichen im Endlichen gerichteten Religion müssen vorzugsweise im Seyn ausgedrückt seyn, die Ideen der entgegengesetzten, in der alle Symbolik nur dem Subjekt angehört, können allein durch Handeln objektiv werden. Das ursprüngliche Symbol aller Anschauung Gottes in ihr ist die Geschichte, aber diese ist endlos, unermeßlich, sie muß also durch eine zugleich unendliche und doch begrenzte Erscheinung repräsentirt werden, die selbst nicht wieder real ist, wie der Staat, sondern ideal, und die Einheit aller im Geist bei der Getrenntheit im Einzelnen als unmittelbare Gegenwart darstellt. Diese symbolische Anschauung ist die Kirche als lebendiges Kunstwerk. Wie nun die Handlung, welche die Einheit des Unendlichen und"}, {"type": "footnote", "text": "1 Vergl. oben S. 108. D. H."}, {"type": "paragraph", "text": "Endlichen äußerlich ausdrückt, symbolisch heißen kann, so ist dieselbe, als innerlich, mystisch, und Mysticismus überhaupt eine subjektive Symbolik. Wenn die Aeußerungen dieser Anschauungsart fast zu jeder Zeit in der Kirche Widerspruch und zum Theil Verfolgung gefunden haben, so ist es, weil sie das Esoterische des Christenthums exoterisch zu machen suchten: nicht aber, als ob der innerste Geist dieser Religion ein anderer als der jener Anschauung wäre1. Wenn man die Handlungen und Gebräuche der Kirche für objetiv symbolisch halten will, da ihre Bedeutung doch bloß mystisch gefaßt werden kann, so haben wenigstens diejenigen Ideen des Christenthums, die in den Dogmen symbolisirt wurden, in diesen nicht aufgehört von ganz speculativer Bedeutung zu seyn, da ihre Symbole kein von der Bedeutung unabhängiges Leben in sich selbst erlangt haben, wie die der griechischen Mythologie. Versöhnung des von Gott abgefallenen Endlichen durch seine eigne Geburt in die Endlichkeit ist der erste Gedanke des Christenthums und die Vollendung seiner ganzen Ansicht des Universum und der Geschichte desselben in der Idee der Dreieinigkeit, welche eben deßwegen in ihm schlechthin nothwendig ist. Bekanntlich hat schon Lessing in der Schrift: Erziehung des Menschengeschlechts, die philosophische Bedeutung dieser Lehre zu enthüllen gesucht, und was er darüber gesagt hat, ist vielleicht das Speculativste, was er überhaupt geschrieben. Es fehlt aber seiner Ansicht noch an der Beziehung dieser Idee auf die Geschichte der Welt, welche darin liegt, daß der ewige, aus dem Wesen des Vaters aller Dinge geborene Sohn Gottes das Endliche selbst ist, wie es in der ewigen Anschauung Gottes ist,"}]}, {"page_pdf": 1575, "page_book": 295, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "und welches als ein leidender und den Verhängnissen der Zeit untergeordneter Gott erscheint, der in dem Gipfel seiner Erscheinung, in Christo, die Welt der Endlichkeit schließt und die der Unendlichkeit oder der Herrschaft des Geistes eröffnet. Wäre es für den gegenwärtigen Zweck verstattet, weiter in diese historische Construktion einzugehen, so würden wir auf die gleiche Weise"}, {"type": "footnote", "text": "1 Vergl. Ueber das Verhältniß der Naturphilosophie zur Philosophie überhaupt, oben S. 118. D. H."}, {"type": "paragraph", "text": "alle Gegensätze des Christenthums und Heidenthums, so wie die in jenem herrschenden Ideen und subjektiven Symbole der Ideen als nothwendige erkennen. Es genügt mir, im Allgemeinen die Möglichkeit davon gezeigt zu haben. Wenn das Christenthum nicht nur überhaupt, sondern auch in seinen vornehmsten Formen historisch nothwendig ist, und wir hiermit die höhere Ansicht der Geschichte selbst als eines Ausflusses der ewigen Nothwendigkeit verbinden: so ist darin auch die Möglichkeit gegeben, es historisch als eine göttliche und absolute Erscheinung zu begreifen, also die einer wahrhaft historischen Wissenschaft der Religion, oder der Theologie."}, {"type": "heading", "text": "Neunte Vorlesung. *Ueber das Studium der Theologie.*", "level": null}, {"type": "paragraph", "text": "Wenn ich es schwer finde von dem Studium der Theologie zu reden, so ist es, weil ich die Erkenntnißart und den ganzen Standpunkt, aus welchem ihre Wahrheiten gefaßt seyn wollen, als verloren und vergessen achten muß. Die sämmtlichen Lehren dieser Wissenschaft sind empirisch verstanden und als solche sowohl behauptet als bestritten worden. Auf diesem Boden aber sind sie überall nicht einheimisch und verlieren durchaus allen Sinn und Bedeutung. Die Theologen behaupten, das Christenthum sey eine göttliche Offenbarung, die sie als eine Handlung Gottes in der Zeit vorstellen. Sie begeben sich also eben damit selbst auf den Standpunkt, von welchem aus betrachtet, es keine Frage seyn kann, ob das Christenthum seinem Ursprung nach natürlich erklärbar ist. Derjenige müßte die Geschichte und Bildung der Zeit seines Entstehens sehr wenig kennen, der sich diese Aufgabe nicht befriedigend lösen könnte. Man lese nur die Schriften der Gelehrten, in welchen der Keim des Christenthums nicht nur im Judenthum, sondern selbst in einem einzelnen religiösen Verein, der vor jenem existirte, nachgewiesen ist; ja man bedarf dessen nicht einmal, obgleich, um diesen Zusammenhang darzulegen, der Bericht des Josephus und die Spuren der christlichen Geschichtbücher selbst noch nicht einmal gehörig benutzt sind. Genug, Christus, als der Einzelne,"}, {"type": "paragraph", "text": "ist eine völlig begreifliche Person, und es war eine absolute Nothwendigkeit, ihn als symbolische Person"}]}, {"page_pdf": 1576, "page_book": 298, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "und in höherer Bedeutung zu fassen. Will man die Ausbreitung des Christenthums als ein besonderes Werk der göttlichen Vorsehung betrachten? Man lerne die Zeit kennen, in der es seine ersten Eroberungen machte, um es als eine bloß einzelne Erscheinung des allgemeinen Geistes derselben zu erkennen. Nicht das Christenthum hat diesen erschaffen, sondern es selbst war nur eine vorahndende Anticipation desselben, das Erste, wodurch er ausgesprochen wurde. Das römische Reich war Jahrhunderte zuvor reif zum Christenthum, ehe Constantin das Kreuz zum Panier der neuen Weltherrschaft wählte; die vollste Befriedigung durch alles Aeußere führte die Sehnsucht nach dem Innern und Unsichtbaren herbei, ein zerfallendes Reich, dessen Macht bloß zeitlich war, der verlorne Muth zum Objektiven, das Unglück der Zeit mußten die allgemeine Empfänglichkeit für eine Religion schaffen, welche den Menschen an das Ideale zurückwies, Verleugnung lehrte und zum Glück machte. Die christlichen Religionslehrer können keine ihrer historischen Behauptungen rechtfertigen, ohne zuvor die höhere Ansicht der Geschichte selbst, welche durch die Philosophie wie durch das Christenthum vorgeschrieben ist, zu der ihrigen gemacht zu haben. Sie haben lange genug mit dem Unglauben auf seinem eignen Boden gekämpft, anstatt diesen, als den Standpunkt, auf welchem er steht, selbst anzugreifen. Ihr habt, könnten sie den Naturalisten sagen, für die Betrachtungsweise, die ihr annehmt; vollkommen Recht, und unsere Ansicht schließt es ein, daß ihr auf euerm Standpunkt richtig urtheilet. Wir leugnen nur diesen selbst, oder lassen ihn als einen bloß untergeordneten gelten. Es ist derselbe Fall wie mit dem Empiriker, der dem Philosophen unwidersprechlich beweist, daß alles Wissen nur durch die äußere Nothwendigkeit der Eindrücke gesetzt ist. Dasselbe Verhältniß findet ebenso in Ansehung aller Dogmen der Theologie statt. Von der Idee der Dreieinigkeit ist es klar, daß sie, nicht speculativ aufgefaßt, überhaupt ohne Sinn ist. Die Menschwerdung Gottes in Christo deuten die Theologen ebenso empirisch,"}, {"type": "paragraph", "text": "nämlich daß Gott in einem bestimmten Moment der Zeit menschliche Natur angenommen habe, wobei schlechterdings nichts zu denken seyn kann, da Gott ewig außer aller Zeit ist. Die Menschwerdung Gottes ist also eine Menschwerdung von Ewigkeit. Der Mensch Christus ist in der Erscheinung nur der Gipfel und insofern auch wieder der Anfang derselben, denn von ihm aus sollte sie dadurch sich fortsetzen, daß alle seine Nachfolger Glieder eines und desselben Leibes wären, von dem er das Haupt ist. Dieß in Christo zuerst Gott wahrhaft objektiv geworden, zeugt die Geschichte; denn wer vor ihm hat das Unendliche auf solche Weise geoffenbaret? Es möchte sich beweisen lassen, daß, soweit die historische Kenntniß nur immer zurückgeht, schon zwei bestimmt verschiedene Ströme von Religion und Poesie unterscheidbar sind: der eine, welcher, schon in der Indischen Religion der herrschende, das Intellektualsystem und den ältesten Idealismus überliefert hat, der andere, welcher die realistische Ansicht der Welt in sich faßte. Jener hat, nachdem er durch den ganzen Orient geflossen, im Christenthum sein bleibendes Beet gefunden, und mit dem für sich unfruchtbaren Boden des Occidents vermischt, die Geburten der späteren Welt erzeugt; der andere hat in der griechischen Mythologie durch Ergänzung mit der entgegengesetzten Einheit, dem Idealischen der Kunst, die höchste Schönheit geboren. Und will man die Regungen des entgegengesetzten Pols in der griechischen Bildung für nichts rechnen, die mystischen Elemente einer abgesonderten Art der Poesie, die Verwerfung der Mythologie und Verbannung der Dichter durch die Philosophen, vornämlich Plato, der in einer ganz fremden und entfernten Welt eine Prophezeihung des Christenthums ist? Aber eben, daß das Christenthum schon vor und außer demselben existirt hat, beweist die Nothwendigkeit seiner Idee, und daß auch in dieser Beziehung keine absoluten Gegensätze existiren. Die christlichen Missionarien, die nach Indien kamen, glaubten den Bewohnern etwas Unerhörtes zu verkündigen, wenn sie lehrten, daß der Gott der Christen Mensch geworden sey. Jene waren darüber nicht"}]}, {"page_pdf": 1577, "page_book": 299, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "verwundert, sie bestritten die Fleischwerdung Gottes in Christo keineswegs, und fanden"}, {"type": "paragraph", "text": "bloß seltsam, daß bei den Christen nur einmal geschehen sey, was sich bei ihnen oftmals und in steter Wiederholung zutrage. Man kann nicht leugnen, daß sie von ihrer Religion mehr Verstand gehabt haben, wie die christlichen Missionarien von der ihrigen. Die historische Construktion des Christenthums kann wegen dieser Universalität seiner Idee nicht ohne die religiöse Construktion der ganzen Geschichte gedacht werden. Sie ist also ebensowenig mit dem, was man bisher allgemeine Religionsgeschichte genannt hat (obgleich von nichts weniger als Religion darin die Rede ist), als mit der partielleren Geschichte der christlichen Religion und Kirche zu vergleichen. Eine solche Construktion ist schon an sich selbst nur der höhern Erkenntnißart möglich, welche sich über die empirische Verkettung der Dinge erhebt; sie ist also nicht ohne Philosophie, welche das wahre Organ der Theologie als Wissenschaft ist, worin die höchsten Ideen von dem göttlichen Wesen, der Natur als dem Werkzeug und der Geschichte als der Offenbarung Gottes objektiv werden. Es wird von selbst niemand die Behauptung der speculativen Bedeutung der vornehmsten Lehren der Theologie mit der Kantischen verwechseln, deren Hauptabsicht am Ende allein darauf geht, das Positive und Historische aus dem Christenthum gänzlich zu entfernen und zur reinen Vernunftreligion zu läutern. Die wahre Vernunftreligion ist, einzusehen, daß nur zwei Erscheinungen der Religion überhaupt sind, die wirkliche Naturreligion, welche nothwendig Polytheismus im Sinn der Griechen ist, und die, welche, ganz sittlich, Gott in der Geschichte anschaut1. In der Kantischen Läuterung ist auch keineswegs ein speculativer, sondern ein moralischer Sinn jener Lehren beabsichtigt, wodurch der empirische Standpunkt im Grunde nicht verlassen, auch die Wahrheit derselben nicht an sich, sondern allein in der subjektiven Beziehung möglicher Motive der Sittlichkeit angenommen wird. Wie der Dogmatismus in der Philosophie ist der gleiche in der Theologie ein Versetzen dessen, was nur absolut erkannt werden kann,"}, {"type": "footnote", "text": "1 Man vergl. die Aeußerung in der Philosophie der Offenbarung, II. Abth., Bd. 3, S. 144. D. H."}, {"type": "paragraph", "text": "auf den empirischen Gesichtspunkt des Verstandes. Kant hat weder den einen noch den andern in der Wurzel angegriffen, da er nichts Positives an ihre Stelle zu setzen wußte. Insbesondere nach seinem Vorschlag beim Volksunterricht die Bibel moralisch auslegen, hieße nur die empirische Erscheinung des Christenthums zu Zwecken, die ohne Mißdeutung gar nicht erreicht werden können, gebrauchen, aber nicht sich über dieselbe zur Idee erheben. Die ersten Bücher der Geschichte und Lehre des Christenthums sind selbst nichts als auch eine besondere, noch dazu unvollkommene, Erscheinung desselben; seine Idee ist nicht in diesen Büchern zu suchen, deren Werth erst nach dem Maß bestimmt werden muß, in welchem sie jene ausdrücken und ihr angemessen sind. Schon in dem Geiste des Heidenbekehrers Paulus ist das Christenthum etwas anderes geworden, als es in dem des ersten Stifters war: nicht bei der einzelnen Zeit sollen wir stehen bleiben, die nur willkürlich angenommen werden kann, sondern seine ganze Geschichte und die Welt, die es geschaffen, vor Augen haben. Zu den Operationen der neuern Aufklärerei, welche in Bezug auf das Christenthum eher die"}]}, {"page_pdf": 1578, "page_book": 301, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Ausklärerei heißen könnte, gehört allerdings auch das Vorgeben, es, wie man sagt, auf seinen ursprünglichen Sinn, seine erste Einfachheit zurückzuführen, in welcher Gestalt sie es auch das Urchristenthum nennen. Man sollte denken, die christlichen Religionslehrer müßten es den späteren Zeiten Dank wissen, daß sie aus dem dürftigen Inhalt der ersten Religionsbücher so viel speculativen Stoff gezogen und diesen zu einem System ausgebildet haben. Bequemer mag es freilich seyn, von dem scholastischen Wust der alten Dogmatik zu reden, dagegen populäre Dogmatiken zu schreiben und sich mit der Sylbenstecherei und Worterklärung zu beschäftigen, als das Christenthum und seine Lehren in universeller Beziehung zu fassen. Man kann sich indessen nicht des Gedankens erwehren, welch ein Hinderniß der Vollendung die sogenannten biblischen Bücher für dasselbe gewesen sind, die an ächt religiösem Gehalt keine Vergleichung mit so vielen andern der früheren und späteren Zeit, vornämlich den Indischen, auch nur von ferne aushalten."}, {"type": "paragraph", "text": "Man hat dem Gedanken der Hierarchie, dem Volk diese Bücher zu entziehen, eine bloß politische Absicht untergelegt: er möchte wohl den tieferen Grund haben, daß das Christenthum als eine lebendige Religion, nicht als eine Vergangenheit, sondern als eine ewige Gegenwart fortdaure, wie auch die Wunder der Kirche nicht aufhörten, welche der Protestantismus, auch darin inconsequent, nur als vor Zeiten geschehen zuläßt. Eigentlich waren es diese Bücher, die als Urkunden, deren bloß die Geschichtforschung, nicht aber der Glaube bedarf, beständig von neuem das empirische Christenthum an die Stelle der Idee gesetzt haben, welche unabhängig von ihnen bestehen kann, und lauter durch die ganze Geschichte der neuen Welt in Vergleich mit der alten als durch jene verkündet wird, wo sie noch sehr unentwickelt liegt. Der Geist der neuen Zeit geht mit sichtbarer Consequenz auf Vernichtung aller bloß endlichen Formen, und es ist Religion, ihn auch hierin zu erkennen. Nach diesem Gesetz mußte der Zustand eines allgemeinen und öffentlichen Lebens, den die Religion im Christenthum mehr oder weniger erreicht hatte, vergänglich seyn, da er nur einen Theil der Absichten des Weltgeistes realisirt darstellte. Der Protestantismus entstand, und war auch zur Zeit seines Ursprungs eine neue Zurückführung des Geistes zum Unsinnlichen, obgleich dieses bloß negative Bestreben, außerdem daß es die Stetigkeit in der Entwickelung des Christenthums aufhob, nie eine positive Vereinigung und eine äußere symbolische Erscheinung derselben, als Kirche, schaffen konnte. An die Stelle der lebendigen Auktorität trat die andere todter in ausgestorbenen Sprachen geschriebener Bücher, und da diese ihrer Natur nach nicht bindend seyn konnte, eine viel unwürdigere Sklaverei, die Abhängigkeit von Symbolen, die ein bloß menschliches Ansehen für sich hatten. Es war nothwendig, daß der Protestantismus, da er seinem Begriff nach antiuniversell ist, wieder in Sekten zerfiel, und daß der Unglaube sich an die einzelnen Formen und die empirische Erscheinung heftete, da die ganze Religion an diese gewiesen war. Nicht geistreich aber ungläubig, nicht fromm und doch auch nicht witzig und frivol, ähnlich den Unseligen, wie sie Dante im Vorgrund"}, {"type": "paragraph", "text": "der Hölle existiren läßt, die weder rebellisch gegen Gott noch treu waren, die der Himmel ausstieß und die Hölle nicht aufnahm, weil auch die Verdammten keine Ehre von ihnen haben würden, haben vornehmlich deutsche Gelehrte, mit Hülfe einer sogenannten gesunden Exegese, einer aufklärenden Psychologie und schlaffen Moral, alles Speculative und selbst das subjektiv-Symbolische aus dem Christenthum entfernt. Der Glaube an seine Göttlichkeit wurde auf empirisch-historische Argumente"}]}, {"page_pdf": 1579, "page_book": 303, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "gebaut, das Wunder der Offenbarung in einem sehr handgreiflichen Cirkel durch andere Wunder bewiesen. Da das Göttliche seiner Natur nach empirisch weder erkennbar noch demonstrabel ist, so hatten hiemit die Naturalisten gewonnenes Spiel. Man hat schon mit ihnen unterhandelt, als man die Untersuchungen über die Aechtheit der christlichen Bücher, den Beweis ihrer Eingebung aus einzelnen Stellen zum Fundament der Theologie machte. Die Zurückweisung auf den Buchstaben einiger Bücher machte nothwendig, daß die ganze Wissenschaft sich in Philologie und Auslegekunst verwandelte, wodurch sie eine gänzlich profane Scienz geworden ist, und wo man das Palladium der Rechtgläubigkeit in der sogenannten Sprachkenntniß sucht, ist die Theologie am tiefsten gesunken und am weitesten von ihrer Idee entfernt. Hier besteht eine Hauptkunst darin, so viel Wunder als möglich aus der Bibel weg oder heraus zu erklären, welches ein ebenso klägliches Beginnen ist als das umgekehrte, aus diesen empirischen, noch dazu höchst dürftigen Factis die Göttlichkeit der Religion zu beweisen. Was hilft es, noch so viele hinwegzuschaffen, wenn es nicht mit allen möglich ist, denn auch nur Eines würde, wenn diese Beweisart überhaupt Sinn hätte, so viel wie tausend beweisen. Zu diesem philologischen Bestreben hat sich das psychologische gesellt, indem man sich große Mühe gegeben, viele Erzählungen, die offenbar jüdische Fabeln sind, erfunden nach der Anleitung messianischer Weissagungen des alten Testaments (über welche Quelle die Urheber sogar selbst keinen Zweifel zulassen, indem sie hinzusetzen: es habe geschehen müssen, damit erfüllet werde, was geschrieben stehe), aus psychologischen Täuschungen begreiflich zu machen."}, {"type": "paragraph", "text": "Verbunden hiemit ist die beliebte Verwässerungsmethode, kraft welcher, unter dem Vorwand, dieses oder jenes seyen nur Redensarten orientalischen Schwulstes, die flachen Begriffe des behaglichsten gemeinen Verstandes, der modernen Moral und Religion in die Urkunden hinein erklärt werden. Zuletzt hat sich diese Entfernung der Wissenschaft von der Speculation auch auf den Volksunterricht verbreitet, welcher rein moralisch, ohne alle Ideen seyn sollte. Die Moral ist ohne Zweifel nichts Auszeichnendes des Christenthums; um einiger Sittensprüche willen, wie die von der Liebe des Nächsten u.s.w., würde es nicht in der Welt und der Geschichte existirt haben. Es ist nicht die Schuldigkeit dieser gemeinen Menschenverständigkeit, wenn jenes moralische Predigen sich nicht noch tiefer herabgelassen und zu einem ökonomischen geworden ist. Die Prediger sollten wirklich zu verschiedenen Zeiten Landwirthe, Aerzte, und was nicht alles seyn, und nicht allein die Kuhpocken von der Kanzel empfehlen, sondern auch die beste Art Kartoffeln zu erziehen lehren. Ich mußte über den Zustand der Theologie reden, weil ich das, was mir über das Studium der Wissenschaft zu sagen nöthig schien, nicht anders als durch den Gegensatz gegen die herrschende Art desselben deutlich zu machen hoffen konnte. Die Göttlichkeit des Christenthums kann schlechterdings auf keine mittelbare Weise, sondern nur eine unmittelbare und im Zusammenhang mit der absoluten Ansicht der Geschichte erkannt werden. Deßhalb ist unter andern der Begriff einer mittelbaren Offenbarung, außerdem daß er nur zum Behuf einer Zweideutigkeit in der Rede ausgedacht ist, ein durchaus unzulässiger, da er ganz empirisch ist. Was an dem Studium der Theologie wirklich bloß Sache der Empirie ist, wie die kritische und philologische Behandlung der ersten christlichen Bücher, ist von dem Studium der Wissenschaft an und für sich ganz abzusondern. Auf die Auslegung derselben können die höheren Ideen keinen Einfluß haben, diese muß ganz unabhängig wie bei jedem andern Schriftsteller geschehen, wo nicht gefragt wird, ob das, was er sagt, vernunftgemäß, historisch wahr oder religiös ist, sondern ob er"}]}, {"page_pdf": 1580, "page_book": 305, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "es wirklich gesagt hat. Hinwiederum ob diese Bücher ächt oder unächt, die darin enthaltenen Erzählungen wirkliche unentstellte Facta sind, ob ihr Inhalt selbst der Idee des Christenthums angemessen ist oder nicht, kann an der Realität derselben nichts ändern, da sie nicht von dieser Einzelheit abhängig, sondern allgemein und absolut ist. Und schon längst, wenn man nicht das Christenthum selbst als bloß zeitliche Erscheinung begriffen hätte, wäre die Auslegung frei gegeben, so daß wir in der historischen Würdigung dieser für die erste Geschichte desselben so wichtigen Urkunden schon viel weiter gelangt seyn und in einer so einfachen Sache nicht bis jetzt noch so viele Umwege und Verwicklungen gesucht würden. Das Wesentliche im Studium der Theologie ist die Verbindung der speculativen und historischen Construktion des Christenthums und seiner vornehmsten Lehren. Zwar an die Stelle des Exoterischen und Buchstäblichen des Christenthums das Esoterische und Geistige treten zu lassen: diesem Beginnen widerspricht allerdings die offenbare Absicht der frühesten Lehrer und der Kirche selbst, da diese wie jene zu jeder Zeit darüber einverstanden waren, sich dem Eindringen alles dessen, was nicht Sache aller Menschen und völlig exoterisch seyn könnte, zu widersetzen. Es beweist ein richtiges Gefühl, ein sicheres Bewußtseyn dessen, was sie wollen mußten, in den ersten Gründern wie in den spätern Häuptern des Christenthums, daß sie mit Ueberlegung entfernten, was der Oeffentlichkeit desselben Eintrag thun konnte, und es ausdrücklich als Häresis, als der Universalität entgegenwirkend, ausschlossen. Selbst unter denjenigen, die zu der Kirche und den Orthodoxen gehörten, erlangten doch die, welche am meisten auf den Buchstaben drangen, das größte Ansehen, ja sie haben eigentlich das Christenthum als universelle Religionsform erschaffen. Nur der Buchstabe des Occidents konnte dem von Orient kommenden idealen Princip einen Leib und die äußere Gestalt geben, wie das Licht der Sonne nur in dem Stoff der Erde seine herrlichen Ideen ausgebiert. Aber eben dieses Verhältniß, welches den ersten Formen des"}, {"type": "paragraph", "text": "Christenthums den Ursprung gab, kehrt, nachdem jene dem Gesetz der Endlichkeit gemäß zerfallen sind, und die offenbare Unmöglichkeit ist, das Christenthum in der exoterischen Gestalt zu behaupten, aufs neue zurück. Das Esoterische muß also hervortreten und, von seiner Hülle befreit, für sich leuchten. Der ewig lebendige Geist aller Bildung und Erschaffung wird es in neue und dauerndere Formen kleiden, da es an dem dem Idealen entgegengesetzten Stoff nicht fehlt, der Occident und Orient sich in einer und derselben Bildung nahe gerückt sind, und überall, wo Entgegengesetzte sich berühren, neues Leben entzündet wird. Der Geist der neueren Welt hat in der Schonungslosigkeit, womit er auch die schönsten aber endlichen Formen, nach Zurückziehung ihres Lebensprincips, in sich zerfallen ließ, hinlänglich seine Absicht offenbart, das Unendliche in ewig neuen Formen zu gebären. Daß er das Christenthum nicht als einzelne empirische Erscheinung, sondern als jene ewige Idee selbst wolle, hat er ebenso klar bezeugt. Die nicht auf die Vergangenheit eingeschränkten, sondern auf eine ungemessene Zeit sich erstreckenden Bestimmungen des Christenthums lassen sich deutlich genug in der Poesie und Philosophie erkennen. Jene fordert die Religion als die oberste, ja einzige Möglichkeit auch der poetischen Versöhnung, diese hat mit dem wahrhaft speculativen Standpunkt auch den der Religion wieder errungen, den Empirismus und ihm gleichen Naturalismus nicht bloß partiell, sondern allgemein aufgehoben und die Wiedergeburt des esoterischen Christenthums wie die Verkündigung des absoluten Evangelium in sich vorbereitet1."}, {"type": "footnote", "text": "1 Vgl. Ueber das Verhältniß der Naturphilosophie zur Philosophie überhaupt, oben S. 120. Jene Abhandlung ist übrigens ihrem ganzen religionsphilosophischen Inhalt nach mit dieser und der vorhergehenden (achten) Vorlesung zu vergleichen. D. H."}]}, {"page_pdf": 1581, "page_book": 306, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "heading", "text": "Zehnte Vorlesung. *Ueber das Studium der Historie und der Jurisprudenz.*", "level": null}, {"type": "paragraph", "text": "Wie das Absolute selbst in der Doppelgestalt der Natur und Geschichte als ein und dasselbige erscheint, zerlegt die Theologie als Indifferenzpunkt der realen Wissenschaften sich von der einen Seite in die Historie, von der andern in die Naturwissenschaft, deren jede ihren Gegenstand getrennt von dem andern und eben damit auch von der obersten Einheit betrachtet. Dieß verhindert nicht, daß nicht jede derselben in sich den Centralpunkt herstellen und so in das Urwissen zurückgehen könne. Die gemeine Vorstellung der Natur und Geschichte ist, daß in jener alles durch empirische Nothwendigkeit, in dieser alles durch Freiheit geschehe. Aber eben dieß sind selbst nur die Formen oder Arten, außer dem Absoluten zu seyn. Die Geschichte ist insofern die höhere Potenz der Natur, als sie im Idealen ausdrückt, was diese im Realen; dem Wesen nach aber ist eben deßwegen dasselbe in beiden, nur verändert durch die Bestimmung oder Potenz, unter der es gesetzt ist. Könnte in beiden das reine An-sich erblickt werden, so würden wir dasselbe, was in der Geschichte ideal, in der Natur real vorgebildet erkennen. Die Freiheit, als Erscheinung, kann nichts erschaffen: es ist Ein Universum, welches die zwiefache Form der abgebildeten Welt jede für sich und in ihrer Art ausdrückt. Die vollendete Welt der Geschichte wäre"}, {"type": "paragraph", "text": "demnach selbst eine ideale Natur, der Staat, als der äußere Organismus einer in der Freiheit selbst erreichten Harmonie der Nothwendigkeit und der Freiheit. Die Geschichte, sofern sie die Bildung dieses Vereins zum vorzüglichsten Gegenstand hat, wäre Geschichte im engern Sinn des Wortes. Die Frage, welche uns hier zunächst entgegenkommt, nämlich ob Historie Wissenschaft seyn könne, scheint wegen ihrer Beantwortung keinen Zweifel zuzulassen. Wenn nämlich Historie als solche, und von dieser ist die Rede, der letzten entgegengesetzt ist, wie im Vorhergehenden allgemein angenommen wurde, so ist klar, daß sie nicht selbst Wissenschaft seyn könne, und wenn die realen Wissenschaften Synthesen des Philosophischen und Historischen sind, so kann eben deßwegen die Historie selbst nicht wieder eine solche seyn, so wenig als es Philosophie seyn kann. Sie träte also in der letzten Beziehung mit dieser auf gleichen Rang. Um dieses Verhältniß noch bestimmter einzusehen, unterscheiden wir die verschiedenen Standpunkte, auf welchen Historie gedacht werden könnte. Der höchste, der von uns im Vorhergehenden erkannt wurde, ist der religiöse oder derjenige, in welchem die ganze Geschichte als Werk der Vorsehung begriffen wird. Daß dieser nicht in der Historie als solcher geltend gemacht werden könne, folgt daraus, daß er von dem philosophischen nicht wesentlich verschieden ist. Es versteht sich, daß ich hiemit weder die religiöse noch die philosophische Construktion der Geschichte leugne; allein jene gehört der Theologie, diese der Philosophie an, und ist von der Historie als solcher nothwendig verschieden. Der entgegengesetzte Standpunkt des Absoluten ist der empirische, welcher wieder zwei Seiten hat. Die der reinen Aufnahme und Ausmittlung des Geschehenen, welche Sache des Geschichtforschers ist, der von dem Historiker als solchen nur eine Seite repräsentirt. Die der Verbindung des empirischen Stoffs"}]}, {"page_pdf": 1582, "page_book": 308, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "nach einer Verstandes-Identität, oder, weil die letztere nicht in den Begebenheiten an und für sich selbst liegen kann, indem diese empirisch viel mehr zufällig und nicht harmonisch"}, {"type": "paragraph", "text": "erscheinen, der Anordnung nach einem durch das Subjekt entworfenen Zweck, der insofern didaktisch oder politisch ist. Diese Behandlung der Geschichte, in ganz bestimmter, nicht allgemeiner Absicht, ist, was, der von den Alten festgesetzten Bedeutung zufolge, die pragmatische heißt. So ist Polybius, der sich über diesen Begriff ausdrücklich erklärt, pragmatisch wegen der ganz bestimmten auf die Technik des Kriegs gerichteten Absicht seiner Geschichtsbücher; so Tacitus, weil er Schritt vor Schritt an dem Verfall des römischen Staats die Wirkungen der Sittenlosigkeit und des Despotismus darstellt. Die Modernen sind geneigt, den pragmatischen Geist für das Höchste in der Historie zu halten und zieren sich selbst untereinander mit dem Prädicat desselben als mit dem größten Lob. Aber eben wegen ihrer subjektiven Abhängigkeit wird niemand, der Sinn hat, die Darstellungen der beiden angeführten Geschichtschreiber in den ersten Rang der Historie setzen. Bei den Deutschen hat es nun überdieß mit dem pragmatischen Geist in der Regel die Bewandtniß, wie bei dem Famulus in Goethes Faust: \"Was sie den Geist der Zeiten nennen, ist ihr eigner Geist, worin die Zeiten sich bespiegeln.\" In Griechenland ergriffen die erhabensten, gereiftesten, erfahrungsreichsten Geister den Griffel der Geschichte, um sie wie mit ewigen Charakteren zu schreiben. Herodotus ist ein wahrhaft Homerischer Kopf, im Thucydides concentrirt sich die ganze Bildung des Perikleischen Zeitalters zu einer göttlichen Anschauung. In Deutschland, wo die Wissenschaft immer mehr eine Sache der Industrie wird, wagen sich gerade die geistlosesten Köpfe an die Geschichte. Welch ein widerlicher Anblick, das Bild großer Begebenheiten und Charaktere im Organ eines kurzsichtigen und einfältigen Menschen entworfen, besonders wenn er sich noch Gewalt anthut Verstand zu haben, und diesen etwa darein setzt, die Größe der Zeiten und Völker nach beschränkten Ansichten, z.B. Wichtigkeit des Handels, diesen oder jenen nützlichen oder verderblichen Erfindungen, zu schätzen, und überhaupt einen so viel möglich gemeinen Maßstab an alles Erhabene zu legen; oder wenn er auf der andern Seite den historischen Pragmatismus darin sucht, sich selbst durch Räsonniren über die"}, {"type": "paragraph", "text": "Begebenheiten oder Ausschmücken des Stoffs mit leeren rhetorischen Floskeln geltend zu machen, z.B. von den beständigen Fortschritten der Menschheit und wie * wir's* denn zuletzt so herrlich weit gebracht. Dennoch ist selbst unter dem Heiligsten nichts, das heiliger wäre als die Geschichte, dieser große Spiegel des Weltgeistes, dieses ewige Gedicht des göttlichen Verstandes: nichts das weniger die Berührung unreiner Hände ertrüge. Der pragmatische Zweck der Geschichte schließt von selbst die Universalität aus und fordert nothwendig auch einen beschränkten Gegenstand. Der Zweck der Belehrung verlangt eine richtige und empirisch begründete Verknüpfung der Begebenheiten, durch welche der Verstand zwar aufgeklärt wird, die Vernunft aber ohne andere Zuthat unbefriedigt bleibt. Auch Kants Plan einer Geschichte im weltbürgerlichen Sinn beabsichtigt eine bloße Verstandesgesetzmäßigkeit im Ganzen derselben, die nur höher, nämlich in der allgemeinen Nothwendigkeit der Natur, gesucht wird, durch welche aus dem Krieg der Friede, zuletzt sogar der ewige und aus vielen andern Verirrungen endlich die ächte Rechtsverfassung entstehen soll. Allein dieser Plan der Natur ist selbst nur der empirische Widerschein der wahren Nothwendigkeit, so wie die Absicht einer darnach geordneten Geschichte nicht sowohl eine weltbürgerliche als eine bürgerliche heißen müßte, den Fortgang nämlich der Menschheit zum ruhigen"}]}, {"page_pdf": 1583, "page_book": 310, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Verkehr, Gewerbe und Handelsbetrieb unter sich, und dieses sonach überhaupt als die höchsten Früchte des Menschenlebens und seiner Anstrengungen darzustellen. Es ist klar, daß, da die bloße Verknüpfung der Begebenheiten nach empirischer Nothwendigkeit immer nur pragmatisch seyn kann, die Historie aber in ihrer höchsten Idee von aller subjektiven Beziehung unabhängig und befreit seyn muß, auch überhaupt der empirische Standpunkt nicht der höchste ihrer Darstellungen seyn könne. Auch die wahre Historie beruht auf einer Synthesis des Gegebenen und Wirklichen mit dem Idealen, aber nicht durch Philosophie, da diese die Wirklichkeit vielmehr aufhebt und ganz ideal ist, Historie aber ganz in jener und doch zugleich ideal seyn soll. Dieses ist nirgends als"}, {"type": "paragraph", "text": "in der Kunst möglich, welche das Wirkliche ganz bestehen läßt, wie die Bühne reale Begebenheiten oder Geschichten, aber in einer Vollendung und Einheit darstellt, wodurch sie Ausdruck der höchsten Ideen werden. Die Kunst also ist es, wodurch die Historie, indem sie Wissenschaft des Wirklichen als solchen ist, zugleich über dasselbe auf das höhere Gebiet des Idealen erhoben wird, auf dem die Wissenschaft steht; und der dritte und absolute Standpunkt der Historie ist demnach der der historischen Kunst. Wir haben das Verhältniß desselben zu den vorher angegebenen zu zeigen. Es versteht sich, daß der Historiker nicht, einer vermeinten Kunst zu lieb, den Stoff der Geschichte verändern kann, deren oberstes Gesetz Wahrheit seyn soll. Ebensowenig kann die Meinung seyn, daß die höhere Darstellung den wirklichen Zusammenhang der Begebenheiten vernachlässige, es hat vielmehr hiermit ganz dieselbe Bewandtniß wie mit der Begründung der Handlungen im Drama, wo zwar die einzelne aus der vorhergehenden und zuletzt alles aus der ersten Synthesis mit Nothwendigkeit entspringen muß, die Aufeinanderfolge selbst aber nicht empirisch, sondern nur aus einer höheren Ordnung der Dinge begreiflich seyn muß. Erst dann erhält die Geschichte ihre Vollendung für die Vernunft, wenn die empirischen Ursachen, indem sie den Verstand befriedigen, als Werkzeuge und Mittel der Erscheinung einer höheren Nothwendigkeit gebraucht werden. In solcher Darstellung kann die Geschichte die Wirkung des größten und erstaunenswürdigsten Drama nicht verfehlen, das nur in einem unendlichen Geiste gedichtet seyn kann. Wir haben die Historie auf die gleiche Stufe mit der Kunst gesetzt. Aber, was diese darstellt, ist immer eine Identität der Nothwendigkeit und Freiheit, und diese Erscheinung, vornehmlich in der Tragödie, ist der eigentliche Gegenstand unserer Bewunderung. Diese selbe Identität aber ist zugleich der Standpunkt der Philosophie und selbst der Religion für die Geschichte, da diese in der Vorsehung nichts anderes als die Weisheit erkennt, welche in dem Plane der Welt die Freiheit der Menschen mit der allgemeinen Nothwendigkeit und umgekehrt diese mit"}, {"type": "paragraph", "text": "jener vereinigt. Nun soll aber die Historie wahrhaft weder auf dem philosophischen noch auf dem religiösen Standpunkt stehen. Sie wird demnach auch jene Identität der Freiheit und Nothwendigkeit in dem Sinne darstellen müssen, wie sie vom Gesichtspunkt der Wirklichkeit aus erscheint, den sie auf keine Weise verlassen soll. Von diesem aus ist sie aber nur als unbegriffene und ganz objektive Identität erkennbar, als Schicksal. Die Meinung ist nicht, daß der Geschichtschreiber das Schicksal im Munde führe, sondern daß es durch die Objektivität seiner Darstellung von selbst und ohne sein Zuthun erscheine. Durch die Geschichtbücher des Herodotus gehen Verhängniß und Vergeltung als unsichtbare überall waltende Gottheiten; in dem höheren und völlig unabhängigen Styl des Thucydides, der sich"}]}, {"page_pdf": 1584, "page_book": 312, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "schon durch die Einführung der Reden dramatisch zeigt, ist jene höhere Einheit in der Form ausgedrückt und ganz bis zur äußern Erscheinung gebracht. Ueber die Art, wie Historie studirt werden soll, möge Folgendes hinreichen. Sie muß im Ganzen nach Art des Epos betrachtet werden, das keinen bestimmten Anfang und kein bestimmtes Ende hat: man nehme denjenigen Punkt heraus, den man für den bedeutendsten oder interessantesten hält, und von diesem aus bilde und erweitere sich das Ganze nach allen Richtungen. Man meide die sogenannten Universalhistorien, die nichts lehren; andere gibt es noch nicht. Die wahre Universalgeschichte müßte im epischen Styl, also in dem Geiste verfaßt seyn, deren Anlage im Herodotus ist. Was man jetzt so nennt, sind Compendien, darin alles Besondere und Bedeutende verwischt ist: auch derjenige aber, der Historie nicht zu seinem besondern Fach wählt, gehe so viel wie möglich zu den Quellen und den Particulargeschichten, die ihn bei weitem mehr unterrichten. Er lerne für die neuere Geschichte die naive Einfalt der Chroniken liebgewinnen, die keine prätensionvollen Charakterschilderungen machen, oder psychologisch motiviren. Wer sich zum historischen Künstler bilden will, halte sich einzig an die großen Muster der Alten, welche, nach dem Zerfall des allgemeinen und öffentlichen Lebens, nie wieder erreicht werden konnten."}, {"type": "paragraph", "text": "Wenn wir von Gibbon absehen, dessen Werk die umfassende Conception und die ganze Macht des großen Wendepunktes der neueren Zeit für sich hat, obgleich er nur Redner nicht Geschichtschreiber ist, existiren bloß wahrhaft nationelle Historiker, unter denen die spätere Zeit nur Macchiavelli und Joh. Müller nennen wird. Welche Stufen derjenige zu erklimmen hat, der würdiger Weise die Geschichte verzeichnen will, könnten die, so diesem Beruf sich weihen, vorerst nur aus den Briefen, welche dieser als Jüngling geschrieben, ohngefähr ermessen. Aber überhaupt alles, was Wissenschaft und Kunst, was ein erfahrungsreiches und öffentliches Leben vermögen, muß dazu beitragen den Historiker zu bilden. Die ersten Urbilder des historischen Styls sind das Epos in seiner ursprünglichen Gestalt und die Tragödie; denn wenn die universelle Geschichte, deren Anfänge, wie die Quellen des Nils, unerkennbar, die epische Form und Fülle liebt, will die besondere dagegen mehr concentrisch um einen gemeinschaftlichen Mittelpunkt gebildet seyn; davon zu schweigen, daß für den Historiker die Tragödie die wahre Quelle großer Ideen und der erhabenen Denkungsart ist, zu welcher er gebildet seyn muß. Als den Gegenstand der Historie im engern Sinne bestimmten wir die Bildung eines objektiven Organismus der Freiheit oder des Staats. Es gibt eine Wissenschaft desselben, so nothwendig es eine Wissenschaft der Natur gibt. Seine Idee kann um so weniger aus der Erfahrung genommen seyn, da diese hier vielmehr selbst erst nach Ideen geschaffen und der Staat als Kunstwerk erscheinen soll. Wenn die realen Wissenschaften überhaupt nur durch das historische Element von der Philosophie geschieden sind, so wird dasselbe auch von der Rechtswissenschaft gelten; aber nur so viel von dem Historischen derselben kann der Wissenschaft angehören, als Ausdruck von Ideen ist, nicht also, was seiner Natur nach bloß endlich ist, wie alle Formen der Gesetze, die sich allein auf den äußeren Mechanismus des Staats beziehen, wohin fast der ganze Inbegriff derjenigen gehört, welche in der gegenwärtigen Rechtswissenschaft gelehrt werden, und in denen man"}, {"type": "paragraph", "text": "den Geist eines öffentlichen Zustandes nur noch wie in Trümmern wohnen sieht. In Ansehung derselben gibt es keine andere Vorschrift, als sie empirisch, wie es zu dem Gebrauch in"}]}, {"page_pdf": 1585, "page_book": 314, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "einzelnen Fällen vor Gerichtshöfen oder in öffentlichen Verhältnissen nöthig ist, zu erlernen und zu lehren, und nicht die Philosophie zu entweihen, indem man sie in Dinge einmischt, welche an ihr keinen Theil haben. Die wissenschaftliche Construktion des Staats würde, was das innere Leben desselben betrifft, kein entsprechendes historisches Element in den späteren Zeiten finden, außer inwiefern selbst das Entgegengesetzte wieder zum Reflex desjenigen dient, von dem es dieß ist. Das Privatleben und mit ihm auch das Privatrecht hat sich von dem öffentlichen getrennt; jenes hat aber, abgesondert von diesem, so wenig Absolutheit, als es in der Natur das Seyn der einzelnen Körper und ihr besonderes Verhältniß untereinander hat. Da in der gänzlichen Zurückziehung des allgemeinen und öffentlichen Geistes von dem einzelnen Leben dieses als die rein endliche Seite des Staats und völlig todt zurückgeblieben ist, so ist auf die Gesetzmäßigkeit, die in ihm herrscht, durchaus keine Anwendung von Ideen und höchstens die eines mechanischen Scharfsinnes möglich, um die empirischen Gründe derselben in einzelnen Fällen darzuthun oder streitige Fälle nach jenen zu entscheiden. Was allein von dieser Wissenschaft einer universell-historischen Ansicht fähig seyn möchte, ist die Form des öffentlichen Lebens, inwiefern diese, auch ihren besondern Bestimmungen nach, aus dem Gegensatz der neuen mit der alten Welt begriffen werden kann und eine allgemeine Nothwendigkeit hat. Die Harmonie der Nothwendigkeit und Freiheit, die sich nothwendig äußerlich und in einer objektiven Einheit ausdrückt, differenziirt sich in dieser Erscheinung selbst wieder nach zwei Seiten, und hat eine verschiedene Gestalt, je nachdem sie im Realen oder Idealen ausgedrückt wird. Die vollkommene Erscheinung derselben im Ersten ist der vollkommene Staat, dessen Idee erreicht ist, sobald das Besondere und das Allgemeine absolut eins, alles was nothwendig zugleich frei und"}, {"type": "paragraph", "text": "alles frei Geschehende zugleich nothwendig ist. Indem das äußere und öffentliche Leben in einer objektiven Harmonie jener beiden verschwand, mußte es durch das subjektive in einer idealen Einheit ersetzt werden, welche die Kirche ist. Der Staat, in seiner Entgegensetzung gegen die Kirche, ist selbst wieder die Naturseite des Ganzen, worin beide eins sind. In seiner Absolutheit mußte er das Entgegengesetzte für die Erscheinung verdrängen, eben deßwegen weil er es begriff: wie der griechische Staat keine Kirche kannte, wenn man nicht die Mysterien dafür rechnen will, die aber selbst nur ein Zweig des öffentlichen Lebens waren; seit die Mysterien exoterisch sind, ist der Staat dagegen esoterisch, da in ihm nur das Einzelne im Ganzen, zu welchem es im Verhältniß der Differenz ist, nicht aber das Ganze auch im Einzelnen lebt. In der realen Erscheinung des Staats existirte die Einheit in der Vielheit, so daß sie völlig mit ihr eins war; mit der Entgegensetzung beider sind auch alle anderen in dieser begriffenen Gegensätze im Staat hervorgetreten. Die Einheit mußte das Herrschende werden, aber nicht in der absoluten sondern abstrakten Gestalt, in der Monarchie, deren Begriff mit dem der Kirche wesentlich verflochten ist. Im Gegentheil mußte die Vielheit oder Menge, durch ihre Entgegensetzung mit der Einheit selbst, ganz in Einzelnheit zerfallen, und hörte auf Werkzeug des Allgemeinen zu seyn. Wie die Vielheit in der Natur als Einbildung der Unendlichkeit in die Endlichkeit wieder absolut, in sich Einheit und Vielheit ist, so war in dem vollkommenen Staat die Vielheit eben dadurch, daß sie zu einer abgeschlossenen Welt (im Sklavenstand) organisirt war, innerhalb derselben absolut, die gesonderte, aber eben deßwegen in sich bestehende, reale Seite des Staats, während aus dem gleichen Grunde die Freien in dem reinen Aether eines idealen und dem der Ideen gleichen Lebens sich bewegten. Die neue Welt ist in allen Beziehungen die Welt der Mischung, wie die alte die der reinen Sonderung und Beschränkung. Die sogenannte bürgerliche Freiheit hat nur die trübste Vermengung der Sklaverei mit der Freiheit, aber kein absolutes und eben dadurch wieder freies Bestehen der einen oder andern hervorgebracht. Die Entgegensetzung der Einheit und der Vielheit machte"}]}, {"page_pdf": 1586, "page_book": 315, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "in dem Staat die Mittler nothwendig, die aber in dieser Mitte von Herrschen und Beherrschtseyn zu keiner absoluten Welt sich ausbildeten, und nur in der Entgegensetzung waren, niemals aber eine unabhängige, ihnen eigenthümlich inwohnende und wesentliche Realität erlangten. Das erste Streben eines jeden, der die positive Wissenschaft des Rechts und des Staats selbst als ein Freier begreifen will, müßte dieses seyn, sich durch Philosophie und Geschichte die lebendige Anschauung der späteren Welt und der in ihr nothwendigen Formen des öffentlichen Lebens zu verschaffen: es ist nicht zu berechnen, welche Quelle der Bildung in dieser Wissenschaft eröffnet werden könnte, wenn sie mit unabhängigem Geiste, frei von der Beziehung auf den Gebrauch und an sich behandelt würde. Die wesentliche Voraussetzung hiezu ist die ächte und aus Ideen geführte Construktion des Staats, eine Aufgabe, von welcher bis jetzt die Republik des Plato die einzige Auflösung ist. Obgleich wir auch hierin den Gegensatz des Modernen und Antiken anerkennen müssen, wird dieses göttliche Werk doch immer das Urbild und Muster bleiben. Was sich über die wahre Synthesis des Staats in dem gegenwärtigen Zusammenhang aussprechen ließ, ist im Vorhergehenden wenigstens angedeutet, und kann ohne die Ausführung oder die Hinweisung auf ein vorhandenes Dokument nicht weiter erklärt werden. Ich beschränke mich daher auf die Anzeige desjenigen, was in der bisherigen Behandlung des sogenannten Naturrechts allein beabsichtigt und geleistet worden ist. Fast am hartnäckigsten hat in diesem Theil der Philosophie sich das analytische Wesen und der Formalismus erhalten. Die ersten Begriffe wurden entweder aus dem römischen Recht oder von irgend einer eben gangbaren Form hergenommen, so daß das Naturrecht nicht nur alle möglichen Triebe der menschlichen Natur, die ganze Psychologie, sondern auch alle erdenklichen Formeln nach und nach durchgewandert ist. Durch Analyse derselben wurde eine Reihe formaler Sätze gefunden, mit deren Hülfe man nachher in der positiven Jurisprudenz aufzuräumen hoffte. Besonders haben Kantische Juristen diese Philosophie als Magd ihrer Scienz zu brauchen fleißig angefangen und zu diesem Behuf auch"}, {"type": "paragraph", "text": "richtig immer das Naturrecht reformirt. Diese Art des Philosophirens äußert sich als ein Schnappen nach Begriffen, gleich viel welcher Art sie sind, nur daß sie eine Einzelheit seyen, damit der, welcher sie aufgefangen, durch die Mühe, die er sich gibt, die übrige Masse nach ihr zu verziehen, sich das Ansehen eines eignen Systems geben könne, das aber dann in kurzer Zeit wieder durch ein anderes eignes verdrängt wird u.s.w. Das erste Unternehmen, den Staat wieder als reale Organisation zu construiren, war Fichtes Naturrecht. Wenn die bloß negative Seite der Verfassung, die nur auf Sicherstellung der Rechte geht, isolirt, und wenn von aller positiven Veranstaltung für die Energie die rhythmische Bewegung und die Schönheit des öffentlichen Lebens abstrahirt werden könnte: so würde sich schwerlich überhaupt ein anderes Resultat oder eine andere Form des Staats ausfindig machen lassen, als in jenem dargestellt ist. Aber das Herausheben der bloß endlichen Seite dehnt den Organismus der Verfassung in einen endlosen Mechanismus aus, in dem nichts Unbedingtes angetroffen wird. Ueberhaupt aber kann allen bisherigen Versuchen die Abhängigkeit ihres Bestrebens vorgeworfen werden, nämlich eine Einrichtung des Staats zu ersinnen, *damit *jenes oder dieses erreicht werde. Ob man diesen Zweck in die allgemeine Glückseligkeit, in die Befriedigung der socialen Triebe der menschlichen Natur, oder in etwas rein Formales, wie das Zusammenleben freier Wesen unter den Bedingungen der möglichsten Freiheit, setzt, ist in jener Beziehung völlig gleichgültig; denn in jedem Fall wird der Staat nur als Mittel, als bedingt"}]}, {"page_pdf": 1587, "page_book": 317, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "und abhängig begriffen. Alle wahre Construktion ist ihrer Natur nach absolut und immer nur auf Eines, auch in der besondern Form, gerichtet. Sie ist z.B. nicht Construktion des Staats als solchen, sondern des absoluten Organismus in der Form des Staats. Diesen construiren heißt also nicht, ihn als Bedingung der Möglichkeit von irgend etwas äußerem fassen, und übrigens, wenn er nur vorerst als das unmittelbare und sichtbare Bild des absoluten Lebens dargestellt ist, wird er auch von selbst alle Zwecke erfüllen: wie die Natur nicht ist, damit ein Gleichgewicht der Materie sey, sondern dieses Gleichgewicht ist, weil die Natur ist."}, {"type": "heading", "text": "Eilfte Vorlesung. *Ueber die Naturwissenschaft im Allgemeinen.*", "level": null}, {"type": "paragraph", "text": "Wenn wir von der Natur absolut reden wollen, so verstehen wir darunter das Universum ohne Gegensatz, und unterscheiden nur in diesem wieder die zwei Seiten: die, in welcher die Ideen auf reale, und die, in welcher sie auf ideale Weise geboren werden. Beides geschieht durch eine und dieselbe Wirkung des absoluten Producirens und nach den gleichen Gesetzen, so daß in dem Universum an und für sich selbst kein Zwiespalt, sondern die vollkommene Einheit ist. Um die Natur als die allgemeine Geburt der Ideen zu fassen, müssen wir auf den Ursprung und die Bedeutung von diesen selbst zurückgehen. Jener liegt in dem ewigen Gesetze der Absolutheit, sich selbst Objekt zu seyn; denn kraft desselben ist das Produciren Gottes eine Einbildung der ganzen Allgemeinheit und Wesenheit in besondere Formen, wodurch diese, als besondere, doch zugleich Universa und das sind, was die Philosophen Monaden oder Ideen genannt haben. Es wird in der Philosophie ausführlicher gezeigt, daß die Ideen die einzigen Mittler sind, wodurch die besonderen Dinge in Gott seyn können, und daß nach diesem Gesetz so viel Universa als besondere Dinge sind, und doch, wegen der Gleichheit des Wesens, in allen nur Ein Universum. Obgleich nun die Ideen in Gott rein und absolut ideal sind, sind sie doch nicht todt, sondern lebendig, die ersten"}, {"type": "paragraph", "text": "Organismen der göttlichen Selbstanschauung, die eben deßwegen an allen Eigenschaften seines Wesens und in der besondern Form dennoch an der ungetheilten und absoluten Realität theilnehmen. Kraft dieser Mittheilung sind sie, gleich Gott, produktiv, und wirken nach demselben Gesetze und auf die gleiche Weise, indem sie ihre Wesenheit in das Besondere bilden und durch einzelne und besondere Dinge erkennbar machen, in ihnen selbst und für sich ohne Zeit, vom Standpunkt der einzelnen Dinge aber und für diese in der Zeit. Die Ideen verhalten sich als die Seelen der Dinge, diese als ihre Leiber; jene sind in dieser Beziehung nothwendig unendlich, diese endlich. Das Unendliche kann aber mit dem Endlichen nie anders als durch innere und wesentliche Gleichheit eins werden. Wenn also dieses nicht in sich selbst, und als endlich, das ganze Unendliche schon begreift und ausdrückt, und es selbst ist, nur von der objektiven Seite angesehen, kann auch die *Idee *nicht als Seele eintreten, und das Wesen erscheint nicht an sich selbst, sondern durch ein anderes, nämlich das Seyn. Wenn dagegen das Endliche, als solches, das ganze Unendliche in sich gebildet trägt, wie der vollkommenste Organismus, der für sich schon die ganze Idee ist, tritt auch das Wesen des Dinges als Seele, als Idee hinzu, und die Realität löst"}]}, {"page_pdf": 1588, "page_book": 319, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "sich wieder in die Idealität auf. Dieß geschieht in der Vernunft, welche demnach das Centrum der Natur und des Objektivwerdens der Ideen ist. Wie also das Absolute in dem ewigen Erkenntnißakt sich selbst in den Ideen objektiv wird, so wirken diese auf eine ewige Weise in der Natur, welche sinnlich, d.i. vom Standpunkt der einzelnen Dinge angeschaut, diese auf zeitliche Weise gebiert, und, indem sie den göttlichen Samen der Ideen empfangen hat, endlos fruchtbar erscheint. Wir sind bei dem Punkte, wo wir die beiden Erkenntniß- und Betrachtungsarten der Natur in ihrer Entgegensetzung verständlich machen können. Die eine, welche die Natur als das Werkzeug der Ideen, oder allgemein als die reale Seite des Absoluten und demnach selbst absolut, die andere, welche sie für sich als getrennt vom Idealen und"}, {"type": "paragraph", "text": "in ihrer Relativität betrachtet. Wir können die erste allgemein die philosophische, die andere die empirische nennen, und stellen die Frage über den Werth derselben so, daß wir untersuchen: ob die empirische Betrachtungsart überhaupt und in irgend einem Sinn zu einer *Wissenschaft *der Natur führen könne. Es ist klar, daß die empirische Ansicht sich nicht über die Körperlichkeit erhebt und diese als etwas, das an sich selbst ist, betrachtet, da jene dagegen sie nur als das in ein Reales (durch den Akt der Subjekt-Objektivirung) verwandelte Ideale begreift. Die Ideen symbolisiren sich in den Dingen, und da sie an sich Formen des absoluten Erkennens sind, erscheinen sie in diesen als Formen des Seyns, wie auch die plastische Kunst ihre Ideen tödtet, um ihnen die Objektivität zu geben. Der Empirismus nimmt das Seyn ganz unabhängig von seiner Bedeutung, da es die Natur des Symbols ist, ein eignes Leben in sich selbst zu haben. In dieser Trennung kann es nur als rein Endliches mit gänzlicher Negation des Unendlichen erscheinen. Und wenn nur diese Ansicht in der späteren Physik sich zur Allgemeinheit ausgebildet hätte, und jenem Begriff der Materie aus dem rein Leiblichen nicht dennoch der des Geistes absolut entgegenstünde, wodurch sie verhindert wird, wenigstens in sich selbst ein Ganzes zu seyn, und diejenige Vollendung zu haben, die sie im System der alten Atomistik, vorzüglich des Epikurus, erlangt hat. Dieses befreit durch die Vernichtung der Natur selbst das Gemüth von der Sehnsucht und Furcht, anstatt daß jene vielmehr sich mit allen Vorstellungen des Dogmatismus befreundet und selbst dient, die Entzweiung zu erhalten, aus der sie hervorgegangen ist. Dieses Denksystem, welches seinen Ursprung von Cartesius herschreibt, hat das Verhältniß des Geistes und der Wissenschaft zur Natur selbst wesentlich verändert. Ohne höhere Vorstellungen der Materie und der Natur als die Atomenlehre, und doch ohne den Muth, diese zum umfassenden Ganzen zu erweitern, betrachtet es die Natur im Allgemeinen als ein verschlossenes Buch, als ein Geheimniß, das man immer nur im Einzelnen, und auch dieses nur durch Zufall oder Glück,"}, {"type": "paragraph", "text": "niemals aber im Ganzen erforschen könne. Wenn es wesentlich zum Begriff der Wissenschaft ist, daß sie selbst nicht atomistisch, sondern aus Einem Geiste gebildet sey, und die Idee des Ganzen den Theilen, nicht umgekehrt, diese jener vorangehen, so ist schon hieraus klar, daß eine wahre Wissenschaft der Natur auf diesem Wege unmöglich und unerreichbar sey. Die rein-endliche Auffassung hebt an und für sich schon alle organische Ansicht auf, und setzt an die Stelle derselben die einfache Reihe des Mechanismus, so wie an die Stelle der Construktion die Erklärung. In dieser wird von den beobachteten Wirkungen auf die Ursachen zurückgeschlossen; allein"}]}, {"page_pdf": 1589, "page_book": 321, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "daß es eben diese und keine andern sind, würde, wenn auch übrigens die Schlußart zulässig und keine Erscheinung wäre, die unmittelbar aus einem absoluten Princip käme, selbst daraus nicht gewiß seyn, daß jene durch sie begreiflich wären. Denn es folgt nicht, daß sie es nicht auch aus andern seyn können. Nur wenn die Ursachen an sich selbst gekannt wären und von diesen auf die Wirkungen geschlossen würde, könnte der Zusammenhang beider Nothwendigkeit und Evidenz haben; davon nichts zu sagen, daß die Wirkungen nothdürftig wohl aus den Ursachen folgen müssen, nachdem man diese erst so ausgedacht hat, als nöthig war jene daraus abzuleiten. Das Innere aller Dinge und das, woraus alle lebendigen Erscheinungen derselben quillen, ist die Einheit des Realen und Idealen, welche, an sich absolute Ruhe, nur durch Differenziirung von außen zum Handeln bestimmt wird. Da der Grund aller Thätigkeit in der Natur Einer ist, der allgegenwärtig, durch keinen andern bedingt und in Bezug auf jedes Ding absolut ist, so können sich die verschiedenen Thätigkeiten voneinander bloß der Form nach unterscheiden, keine dieser Formen aber kann wieder aus einer andern begriffen werden, da jede in ihrer Art dasselbe was die andere ist. Nicht daß eine Erscheinung von der andern abhängig, sondern daß alle aus einem gemeinschaftlichen Grunde fließen, macht die Einheit der Natur aus. Selbst die Ahndung des Empirismus, daß alles in der Natur durch die prästabilirte Harmonie aller Dinge vermittelt sey, und kein Ding"}, {"type": "paragraph", "text": "das andere anders als durch Vermittlung der allgemeinen Substanz verändere oder afficire, wurde von ihm wieder mechanisch begriffen und zu dem Unding einer Wirkung in die Ferne (in der Bedeutung, welche dieser Ausdruck bei Newton und seinen Nachfolgern hat) umgedeutet. Da die Materie kein Lebensprincip in sich selbst hatte, und man eine Einwirkung des Geistes auf sie als Erklärungsgrund für die höchsten Erscheinungen, der willkürlichen Bewegung und ähnlicher, aufsparen wollte, so wurde für die nächsten Wirkungen etwas außer ihr angenommen, das nur gleichsam Materie seyn und durch Negation der vornehmsten Eigenschaften derselben, der Schwere u.a. sich dem negativen Begriff des Geistes als (immaterieller Substanz) annähern sollte, als ob der Gegensatz zwischen beiden dadurch umgangen oder wenigstens vermindert werden könnte. Auch die Möglichkeit des Begriffs imponderabler und incoërcibler Materien zugegeben, würde doch jener Erklärungsart zufolge alles in der Materie durch äußere Einwirkung gesetzt, der Tod das Erste, das Leben das Abgeleitete seyn. Selbst aber wenn von Seiten des Mechanismus jede Erscheinung vollkommen durch die Erklärung begriffen würde, bliebe der Fall derselbe, wie wenn jemand den Homer oder irgend einen Autor so erklären wollte, daß er anfinge, die Form der Drucklettern begreiflich zu machen, dann zu zeigen, auf welche Weise sie zusammengestellt und endlich abgedruckt worden, und wie zuletzt jenes Werk daraus entstanden sey. Mehr oder weniger ist dieß der Fall vorzüglich mit dem, was man bisher in der Naturlehre für mathematische Construktionen ausgegeben hat. Schon früher wurde bemerkt, daß die mathematischen Formen dabei von einem ganz bloß mechanischen Gebrauch seyen. Sie sind nicht die wesentlichen Gründe der Erscheinungen selbst, welche vielmehr in etwas ganz Fremdartigem, Empirischem liegen, wie in Ansehung der Bewegungen der Weltkörper in einem Stoß, den diese nach der Seite bekommen haben. Es ist wahr, daß man durch Anwendung der Mathematik die Abstände der Planeten, die Zeit ihrer Umläufe und Wiedererscheinungen mit Genauigkeit vorherbestimmen gelernt hat, aber über das Wesen oder An-sich dieser Bewegungen ist dadurch nicht der mindeste"}]}, {"page_pdf": 1590, "page_book": 323, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Aufschluß gegeben worden. Die sogenannte mathematische Naturlehre ist also bis jetzt leerer Formalismus, in welchem von einer wahren Wissenschaft der Natur nichts anzutreffen ist. Der Gegensatz, der zwischen Theorie und Erfahrung gemacht zu werden pflegt, hat schon darum keinen rechten Sinn, da in dem Begriff der Theorie bereits die Beziehung auf eine Besonderheit und demnach auf Erfahrung liegt. Die absolute Wissenschaft ist nicht Theorie, und der Begriff der letzteren gehört selbst der trüben Mischung von Allgemeinem und Besonderem an, worin das gemeine Wissen befangen ist. Theorie kann sich von der Erfahrung nur dadurch unterscheiden, daß sie diese abstrakter, gesonderter von zufälligen Bedingungen und in ihrer ursprünglichsten Form ausspricht. Aber eben diese herauszuheben und in jeder Erscheinung das Handeln der Natur rein darzustellen, ist auch die Sache des Experiments: beide stehen also auf gleicher Stufe. Man sieht daher nicht ein, wie das experimentirende Naturforschen sich über die Theorie auf irgend eine Weise erheben könne, da es einzig diese ist, von der jenes geleitet wird, ohne deren Eingebung es auch nicht einmal die Fragen (wie man es nennt) an die Natur thun könnte, von deren Sinnigkeit die Klarheit der Antworten abhängt, welche sie ertheilt. Beide haben das gemein, daß ihr Ausgangspunkt immer der bestimmte Gegenstand, nicht ein allgemeines und absolutes Wissen ist. Beide, wenn sie ihrem Begriff treu bleiben, unterscheiden sich von dem falschen Theoretisiren, welches auf Erklärung der Naturerscheinungen geht und zu diesem Behuf die Ursachen erdichtet; denn beide beschränken sich auf das bloße Aussprechen oder Darstellen der Erscheinungen selbst, und sind hierin der Construktion gleich, welche ebensowenig sich mit Erklären abgibt. Wäre ihr Bestreben mit Bewußtseyn verbunden, so könnten sich beide kein anderes Ziel denken, als von der Peripherie gegen das Centrum zu dringen, wie die Construktion vom Centro gegen die Peripherie geht. Allein der Weg in der ersten Richtung ist, wie der in der andern, unendlich, so daß, weil der Besitz des Mittelpunkts erste Bedingung der Wissenschaft ist, diese in der ersten nothwendig unerreichbar ist."}, {"type": "paragraph", "text": "Jede Wissenschaft fordert zu ihrer objektiven Existenz eine exoterische Seite; eine solche muß es also auch für die Naturwissenschaft oder für die Seite der Philosophie geben, durch welche sie Construktion der Natur ist. Diese kann nur in dem Experiment und seinem nothwendigen Correlat, der Theorie (in der angegebenen Bedeutung), gefunden werden; aber diese muß nicht fordern, die Wissenschaft selbst, oder etwas anderes als die reale Seite derselben zu seyn, in welcher das außereinander und in der Zeit ausgedehnt ist, was in den Ideen der ersten zumal ist. Nur dann wird die Empirie der Wissenschaft sich als Leib anschließen, wenn sie in ihrer Art dasselbe zu seyn sich bestrebt, was jene in der ihrigen ist, nämlich empirische Construktion: dann wird sie im Geiste des Ganzen sowohl gelehrt als betrieben, wenn sie, mit Enthaltung von Erklärungen und Hypothesen, reine objektive Darstellung der Erscheinung selbst ist und keine Idee anders als durch diese auszusprechen sucht; nicht aber, wenn dürftige Empirie aus ihren verschobenen Ansichten heraus Blicke in das Universum werfen oder sie den Gegenständen aufdringen will, oder wenn dieses empirische Beginnen gar gegen allgemein bewiesene und allgemein einzusehende Wahrheiten oder ein System von solchen mit einzelnen abgerissenen Erfahrungen, aus der Mitte einer Folge von Fällen, die sie selbst nicht übersehen kann, oder einer Menge sich durchkreuzender und verwirrender Bedingungen, sich erhebt, ein Bestreben, das in seiner Absicht gegen die Wissenschaft ebenso viel ist, als, um mich dieses bekannten Gleichnisses zu bedienen, den Durchbruch des Oceans mit Stroh stopfen zu wollen. Die absolute, in Ideen gegründete Wissenschaft der Natur ist demnach das Erste und die Bedingung, unter welcher zuerst die empirische Naturlehre an die Stelle ihres blinden Umherschweifens ein methodisches, auf ein bestimmtes Ziel gerichtetes Verfahren setzen kann. Denn die Geschichte der Wissenschaft zeigt, daß ein solches Construiren der Erscheinungen durch das Experiment, als wir gefordert haben, jederzeit nur in einzelnen Fällen wie durch Instinkt geleistet worden ist, daß also, um diese Methode der Naturforschung allgemein geltend zu"}]}, {"page_pdf": 1591, "page_book": 324, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "machen, selbst das Vorbild der Construktion in einer absoluten Wissenschaft erfordert wird. Die Idee einer solchen habe ich zu oft und zu wiederholt vor *Ihnen *entwickelt, als daß ich nöthig achtete, sie hier weiter als in den allgemeinsten Beziehungen darzustellen. Wissenschaft der Natur ist an sich selbst schon Erhebung über die einzelnen Erscheinungen und Produkte zur Idee dessen, worin sie eins sind und aus dem sie als gemeinschaftlichem Quell hervorgehen. Auch die Empirie hat doch eine dunkle Vorstellung von der Natur als einem Ganzen, worin Eines durch Alles und Alles durch Eines bestimmt ist. Es hilft also nicht, das Einzelne zu kennen, wenn man das Ganze nicht weiß. Aber eben der Punkt, in welchem Einheit und Allheit selbst eines sind, wird nur durch Philosophie erkannt, oder vielmehr die Erkenntniß von ihm ist die Philosophie selbst. Von dieser ist die erste und nothwendige Absicht, die Geburt aller Dinge aus Gott oder dem Absoluten zu begreifen, und inwiefern die Natur die ganze reale Seite in dem ewigen Akt der Subjekt-Objektivirung ist, ist Philosophie der Natur die erste und nothwendige Seite der Philosophie überhaupt. Das Princip und das Element von ihr ist die absolute Idealität, aber diese wäre ewig unerkennbar, verhüllt in sich selbst, wenn sie nicht sich als Subjektivität in die Objektivität verwandelte, von welcher Verwandlung die erscheinende endliche Natur das Symbol ist. Die Philosophie im Ganzen ist demnach absoluter Idealismus, da auch jener Akt im göttlichen Erkennen begriffen ist, und die Naturphilosophie hat in dem ersten keinen Gegensatz, sondern nur in dem relativen Idealismus, welcher von dem absolut-Idealen bloß die eine Seite begreift. Denn die vollendete Einbildung seiner Wesenheit in die Besonderheit, bis zur Identität beider, producirt in Gott die Ideen, so daß die Einheit, wodurch diese in sich selbst und real sind, mit der, wodurch sie im Absoluten und ideal sind, unmittelbar eine und dieselbige ist. In den besondern Dingen aber, welche von den Ideen die bloßen Abbilder sind, erscheinen diese Einheiten nicht als Eines, sondern in der Natur"}, {"type": "paragraph", "text": "als der bloß relativ-realen Seite ist die erste im Uebergewicht, so daß sie im Gegensatz gegen die andere Seite, wo das Ideale hüllenlos, unverstellt in ein anderes hervortritt, als das Negative, die letztere dagegen als das Positive und das Princip von jener erscheint, da doch beide nur die relativen Erscheinungsweisen des absolut-Idealen und in ihm schlechthin eins sind. Nach dieser Ansicht ist die Natur, nicht nur in ihrem An-sich, wo sie der ganze absolute Akt der Subjekt-Objektivirung selbst ist, sondern auch der Erscheinung nach, wo sie sich als die relativ-reale oder objektive Seite desselben darstellt, dem Wesen nach eins, und keine innerliche Verschiedenheit in ihr, in allen Dingen Ein Leben, die gleiche Macht zu seyn, dieselbe Legirung durch die Ideen. Es ist keine reine Leiblichkeit in ihr, sondern überall Seele in Leib symbolisch umgewandelt, und für die Erscheinung nur ein Uebergewicht des einen oder andern. Aus dem gleichen Grunde kann auch die Wissenschaft der Natur nur Eine seyn, und die Theile, in welche sie der Verstand zersplittert, sind nur Zweige einer absoluten Erkenntniß. Construktion überhaupt ist Darstellung des Realen im Idealen, des Besonderen im schlechthin Allgemeinen, der Idee. Alles Besondere als solches ist Form, von allen Formen aber ist die nothwendige, ewige und absolute Form der Quell und Ursprung. Der Akt der Subjekt-Objektivirung geht durch alle Dinge hindurch, und pflanzt sich in den besonderen Formen fort, die, da sie alle nur verschiedene Erscheinungsweisen der allgemeinen und unbedingten, in dieser selbst unbedingt sind. Da ferner der innere Typus aller Dinge wegen der gemeinschaftlichen Abkunft Einer seyn muß, und dieser mit Nothwendigkeit eingesehen werden kann, so wohnt dieselbe Nothwendigkeit auch der in ihm"}]}, {"page_pdf": 1592, "page_book": 326, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "gegründeten Construktion bei, welche demnach der Bestätigung der Erfahrung nicht bedarf, sondern sich selbst genügt, und auch bis dahin fortgesetzt werden kann, wohin zu dringen die Erfahrung durch unübersteigliche Grenzen gehindert ist, wie in das innere Triebwerk des organischen Lebens und der allgemeinen Bewegung. Nicht nur für das Handeln gibt es ein Schicksal: auch dem Wissen steht das An-sich des Universum und der Natur als eine unbedingte"}, {"type": "paragraph", "text": "Nothwendigkeit vor, und wenn, nach dem Ausspruch eines Alten, der tapfere Mann im Kampf mit dem Verhängniß ein Schauspiel ist, auf das selbst die Gottheit mit Lust herabsieht, so ist das Ringen des Geistes nach der Anschauung der ursprünglichen Natur und des ewigen Innern ihrer Erscheinungen ein nicht minder erhebender Anblick. Wie in der Tragödie der Streit weder dadurch, daß die Nothwendigkeit, noch dadurch, daß die Freiheit unterliegt, sondern allein durch die Erhebung der einen zur vollkommenen Gleichheit mit der andern wahrhaft gelöst wird: so kann auch der Geist aus jenem Kampf mit der Natur allein dadurch versöhnt heraustreten, daß sie für ihn zur vollkommenen Indifferenz mit ihm selbst und zum Idealen sich verklärt. An jenen Widerstreit, der aus unbefriedigter Begier nach Erkenntniß der Dinge entspringt, hat der Dichter seine Erfindungen in dem eigenthümlichsten Gedicht der Deutschen geknüpft und einen ewig frischen Quell der Begeisterung geöffnet, der allein zureichend war, die Wissenschaft zu dieser Zeit zu verjüngen und den Hauch eines neuen Lebens über sie zu verbreiten. Wer in das Heiligthum der Natur eindringen will, nähre sich mit diesen Tönen einer höheren Welt und sauge in früher Jugend die Kraft in sich, die wie in dichten Lichtstrahlen von diesem Gedicht ausgeht und das Innerste der Welt bewegt."}, {"type": "heading", "text": "Zwölfte Vorlesung. *Ueber das Studium der Physik und Chemie.*", "level": null}, {"type": "paragraph", "text": "Den besondern Erscheinungen und Formen, welche durch Erfahrung allein erkannt werden, geht nothwendig das vorher, wovon sie es sind, die Materie oder Substanz. Die Empirie kennt diese nur als Körper, d.h. als Materie mit veränderlicher Form, und denkt selbst den Urstoff, wenn sie anders darauf zurückgeht, nur als eine unbestimmbare Menge von Körpern unveränderlicher Form, die deßwegen Atomen heißen. Es fehlt ihr also die Erkenntniß der ersten Einheit, aus der alles in der Natur hervorgeht, und in die alles zurückkehrt. Um zum Wesen der Materie zu gelangen, muß durchaus das Bild jeder besondern Art derselben, z.B. der sogenannten unorganischen oder der organischen entfernt werden, da sie an sich nur der gemeinschaftliche Keim dieser verschiedenen Formen ist. Absolut betrachtet ist sie der Akt der ewigen Selbstanschauung des Absoluten, sofern dieses in jenem sich objektiv und real macht; sowohl dieses An-sich der Materie, als wie die besondern Dinge mit den Bestimmungen der Erscheinung aus ihm hervorgehen, zu zeigen, kann allein Sache der Philosophie seyn. Von dem ersten habe ich hinlänglich schon im Vorhergehenden geredet und beschränke mich also auf das andere. Die Idee jedes besondern Dinges ist schlechthin Eine, und zu dem Werden unendlich vieler"}]}, {"page_pdf": 1593, "page_book": 328, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Dinge derselben Art ist die Eine Idee zureichend, deren unendliche Möglichkeit durch keine Wirklichkeit erschöpft wird. Da das erste Gesetz"}, {"type": "paragraph", "text": "der Absolutheit dieses ist, schlechthin untheilbar zu seyn, so kann die Besonderheit der Ideen nicht in einer Negation der andern Ideen, sondern allein darin bestehen, daß in jeder alle, aber angemessen der besonderen Form derselben, gebildet seyen. Von dieser Ordnung in der Ideenwelt muß das Vorbild für die Erkenntniß der sichtbaren hergenommen werden. Auch in dieser werden die ersten Formen Einheiten seyn, welche alle anderen Formen als besondere in sich tragen und aus sich produciren, die also eben deßwegen selbst als Universa erscheinen. Die Art, wie sie in die Ausdehnung übergehen und den Raum erfüllen, muß aus der ewigen Form der Einbildung der Einheit in die Vielheit selbst abgeleitet werden, die in den Ideen mit der entgegengesetzten (wie gezeigt) eins, in der Erscheinung aber als diese unterscheidbar und unterschieden ist. Der erste und allgemeine Typus der Raumerfüllung ist nothwendig, daß die sinnlichen Einheiten, wie sie als Ideen aus dem Absoluten, als dem Centro, hervorgehen, ebenso in der Erscheinung aus einem gemeinschaftlichen Mittelpunkt, oder, weil jede Idee selbst wieder produktiv ist und ein Centrum seyn kann, aus gemeinschaftlichen Centris geboren werden, und wie ihre Vorbilder zugleich abhängig und selbständig seyen. Nach der Construktion der Materie ist also die Erkenntniß des Weltbaues und seiner Gesetze die erste und vornehmste in der Physik. Was die mathematische Naturlehre, seit der Zeit, daß durch Keplers göttliches Genie jene Gesetze ausgesprochen sind, für Erkenntniß derselben geleistet, ist, wie bekannt, daß sie eine den Gründen nach ganz empirische Construktion davon versucht hat. Man kann als allgemeine Regel annehmen, daß, was in einer angeblichen Construktion nicht reine allgemeine Form ist, auch keinen wissenschafltichen Gehalt noch Wahrheit haben könne. Der Grund, aus welchem die Centrifugalbewegung der Weltkörper abgeleitet wird, ist keine nothwendige Form, ist empirisches Factum. Die Newtonische Attraktivkraft, wenn sie auch für die auf dem Standpunkt der Reflexion haftende Betrachtung eine nothwendige Annahme seyn mag, ist doch für die Vernunft, die nur absolute Verhältnisse kennt, und also für die Construktion von keiner Bedeutung."}, {"type": "paragraph", "text": "Die Gründe der Keplerschen Gesetze lassen sich, ohne allen empirischen Zusatz, rein aus der Lehre von den Ideen und den zwei Einheiten einsehen, die an sich selbst Eine Einheit sind, und kraft deren jedes Wesen, indem es in sich selbst absolut, zugleich im Absoluten ist, und umgekehrt. Die physische Astronomie oder die Wissenschaft der besonderen Qualitäten und Verhältnisse der Gestirne beruht ihren vorzüglichsten Gründen nach ganz auf allgemeinen Ansichten, und in Beziehung auf das Planetensystem insbesondere auf der Uebereinstimmung, welche zwischen diesen und den Produkten der Erde stattfindet. Der Weltkörper gleicht der Idee, deren Abdruck er ist, darin, daß er wie diese produktiv ist und alle Formen des Universum aus sich hervorbringt. Die Materie, obgleich der Erscheinung nach der Leib des Universum, differenziirt sich in sich selbst wieder zu Seele und Leib. Der Leib der Materie sind die einzelnen körperlichen Dinge, in welchem die Einheit ganz in die Vielheit und Ausdehnung verloren ist, und die deßwegen als unorganisch erscheinen. Die rein-historische Darstellung der unorganischen Formen ist zu einem abgesonderten Zweig der Kenntniß gebildet worden: nicht ohne richtigen Sinn mit Enthaltung von aller Berufung auf innere qualitative Bestimmungen. Nachdem die specifische Verschiedenheit der Materie selbst quantitativ"}]}, {"page_pdf": 1594, "page_book": 330, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "begriffen und die Möglichkeit gegeben ist, sie als Metamorphose einer und derselben Substanz durch bloße Formänderung darzustellen, ist auch der Weg zu einer historischen Construktion der Körperreihe geöffnet, zu welcher bereits durch Steffens Ideen ein entschiedener Anfang gemacht ist. Die Geologie, welche das Gleiche in Ansehung der ganzen Erde seyn müßte, dürfte keine ihrer Hervorbringungen ausschließen, und müßte die Genesis aller in historischer Stetigkeit und Wechselbestimmung zeigen. Da die reale Seite der Wissenschaft immer nur historisch seyn kann (weil außer der Wissenschaft nichts ist, was unmittelbar und ursprünglich auf Wahrheit geht, als die Historie), so würde die Geologie, in der Fülle der höchsten Ausbildung, als Historie der Natur selbst, für"}, {"type": "paragraph", "text": "welche die Erde nur Mittel- und Ausgangspunkt wäre, die wahre Integration und rein objektive Darstellung der Wissenschaft der Natur seyn, zu welcher auch die experimentirende Physik nur einen Uebergang bildet und das Mittel seyn kann. Wie die körperlichen Dinge der Leib der Materie sind, so ist die ihr eingebildete Seele das Licht. Durch die Beziehung auf die Differenz und als der unmittelbare Begriff derselben, wird das Ideale selbst endlich, und erscheint in der Unterordnung unter die Ausdehnung als ein Ideales, das den Raum zwar beschreibt, aber nicht erfüllt. Es ist also in der Erscheinung selbst zwar das Ideale, aber nicht das ganze Ideale des Akts der Subjekt-Objektivirung (indem es die eine Seite außer sich in dem Körperlichen zurückläßt), sondern das bloß relativ-Ideale. Die Erkenntniß des Lichts ist der der Materie gleich, ja mit ihr eins, da beide nur im Gegensatz gegeneinander, als die subjektive und objektive Seite, wahrhaft begriffen werden können. Seitdem dieser Geist der Natur von der Physik gewichen ist, ist für sie das Leben in allen Theilen derselben erloschen, wie es für sie keinen möglichen Uebergang von der allgemeinen zu der organischen Natur gibt. Die Newtonsche Optik ist der größte Beweis der Möglichkeit eines ganzen Gebäudes von Fehlschlüssen, die in allen seinen Theilen auf Erfahrung und Experiment gegründet ist. Als ob es nicht die, mehr oder minder bewußt, schon vorhandene Theorie wäre, welche den Sinn und die Folge der Versuche nach sich, eigenwillig bestimmt, - wenn nicht ein seltener, aber glücklicher Instinkt, oder ein durch Construktion gewonnener allgemeiner Schematismus die natürliche Ordnung vorschreibt, - wird das Experiment, welches wohl Einzelheiten lehren, aber nie eine ganze Ansicht geben kann, für das untrügliche Princip der Naturerkenntniß geachtet. Der Keim der Erde wird nur durch das Licht entfaltet. Denn die Materie muß Form werden und in die Besonderheit übergehen, damit das Licht als Wesen und Allgemeines eintreten kann. Die allgemeine Form der Besonderwerdung der Körper ist das, wodurch sie sich selbst gleich und in sich zusammenhängend sind. Aus"}, {"type": "paragraph", "text": "den Verhältnissen zu dieser allgemeinen Form, welche die der Einbildung der Einheit in die Differenz ist, muß sich also auch alle specifische Verschiedenheit der Materie einsehen lassen. Das Hervorgehen aus der Identität ist in Ansehung aller Dinge unmittelbar zugleich das Zurückstreben in die Einheit, welches ihre ideale Seite ist, das, wodurch sie beseelt erscheinen. Den Inbegriff der lebendigen Erscheinungen der Körper darzustellen, ist nach den bereits bezeichneten Gegenständen der vorzüglichste und einzige der Physik, auch inwiefern sie in der gewöhnlichen Begrenzung und Trennung von der Wissenschaft der organischen Natur gedacht wird. Jene Erscheinungen sind, als den Körpern wesentlich inhärirende Thätigkeitsäußerungen, überhaupt"}]}, {"page_pdf": 1595, "page_book": 332, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "dynamisch genannt worden, so wie der Inbegriff derselben nach ihren verschieden bestimmten Formen der dynamische Proceß heißt. Es ist nothwendig, daß diese Formen auf einen gewissen Kreis eingeschlossen sey'n und einen allgemeinen Typus befolgen. Nur durch den Besitz desselben kann man gewiß seyn, weder ein nothwendiges Glied zu übersehen, noch Erscheinungen, die wesentlich eines sind, als verschiedene zu betrachten. Die gewöhnliche Experimentalphysik findet sich in Rücksicht der Mannichfaltigkeit und Einheit dieser Formen in der größten Ungewißheit, so daß jede neue Art der Erscheinung für sie Grund der Annahme eines neuen von allen verschiedenen Princips wird, und daß bald diese Form aus jener, bald jene aus dieser abgeleitet wird. Stellen wir die gangbaren Theorien und die Erklärungsart jener Phänomene im Allgemeinen unter den schon bestimmten Maßstab, so ist in keiner derselben irgend eines als nothwendige und allgemeine Form, sondern durchaus bloß als Zufälligkeit begriffen. Denn daß es solche imponderable Flüssigkeiten gibt, als zu jenem Behuf angenommen werden, ist ohne alle Nothwendigkeit, und daß diese ebenso beschaffen sind, daß ihre homogenen Elemente sich abstoßen, die heterogenen sich anziehen, wie zur Erklärung der magnetischen und elektrischen Erscheinungen angenommen wird, ist eine vollkommene Zufälligkeit. Wenn man die Welt dieser hypothetischen Elemente sich zusammensetzt, so"}, {"type": "paragraph", "text": "erhält man folgendes Bild ihrer Verfassung. Zunächst in den Poren der gröberen Stoffe ist die Luft, in den Poren der Luft der Wärmestoff, in den Poren von diesem die elektrische Flüssigkeit, welche wieder in den ihrigen die magnetische, so wie diese in den Zwischenräumen, welche auch sie hat, den Aether begreift. Gleichwohl stören sich diese verschiedenen ineinander eingeschachtelten Flüssigkeiten nicht, und erscheinen nach dem Gefallen des Physikers jede in ihrer Art, ohne mit der andern vermischt zu seyn, und finden sich ebenso ohne alle Verwirrung jede wieder an ihre Stelle. Diese Erklärungsart ist also, außerdem daß sie ganz ohne wissenschaftlichen Gehalt ist, nicht einmal der empirischen Anschaulichkeit fähig. Aus der Kantischen Construktion der Materie entwickelte sich zunächst eine höhere, gegen die materielle Betrachtung der Phänomene gerichtete Ansicht, die aber in allem, was sie Positives dagegen aufstellt, selbst auf einem zu untergeordneten Standpunkt zurückblieb. Die beiden Kräfte der Anziehung und Zurückstoßung, wie sie Kant bestimmt, sind bloß formelle Faktoren, durch Analysis gefundene Verstandesbegriffe, die von dem Leben und dem Wesen der Materie keine Ideen geben. Es kommt dazu, daß nach demselben die Verschiedenheit der Materie aus dem Verhältniß dieser Kräfte, das er als ein bloß arithmetisches kannte, einzusehen unmöglich ist. Die Nachfolger von Kant und die Physiker, welche eine Anwendung seiner Lehren versuchten, beschränkten sich in Ansehung der dynamischen Vorstellung auf das bloß Negative, wie in Ansehung des Lichts, von dem sie eine höhere Meinung ausgesprochen zu haben glaubten, wenn sie es nur überhaupt als immateriell bezeichneten, womit sich dann übrigens jede andere mechanische Hypothese des Euler u.a. vertrug. Der Irrthum, der allen diesen Ansichten gemeinschaftlich zu Grunde lag, ist die Vorstellung der Materie als reiner Realität: es mußte erst die allgemeine Subjekt-Objektivität der Dinge und der Materie insbesondere wissenschaftlich hergestellt seyn, ehe man diese Formen, in denen ihr inneres Leben sich ausdrückt, begreifen konnte. Das Seyn jedes Dinges in der Identität als der allgemeinen"}]}, {"page_pdf": 1596, "page_book": 334, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Seele, und das Streben zur Wiedervereinigung mit ihr, wenn es aus der Einheit gesetzt ist, ist als allgemeiner Grund der lebendigen Erscheinungen schon im Vorhergehenden angegeben. Die besondern Formen der Thätigkeit sind keine der Materie zufällige, sondern ursprünglich eingeborene und nothwendige Formen. Denn wie die Einheit der Idee im Seyn zu drei Dimensionen sich ausbreitet, drückt auch das Leben und die Thätigkeit sich in demselben Typus und durch drei Formen aus, welche demnach dem Wesen der Materie so nothwendig als jene inhäriren. Durch diese Construktion ist nicht allein gewiß, daß es nur diese drei Formen der lebendigen Bewegung der Körper gibt, sondern es ist auch für alle besonderen Bestimmungen derselben das allgemeine Gesetz gefunden, aus dem sie als nothwendige eingesehen werden können. Ich beschränke mich hier zunächst auf den chemischen Proceß, da die Wissenschaft seiner Erscheinungen zu einem besondern Zweig der Naturkenntniß gebildet worden ist. Das Verhältniß der Physik zur Chemie hat sich in der neueren Zeit fast zu einer gänzlichen Unterordnung der ersten unter die letzte entschieden. Der Schlüssel zur Erklärung aller Naturerscheinungen, auch der höheren Formen, des Magnetismus, der Elektricität u.s.w. sollte in der Chemie gegeben seyn, und je mehr allmählich alle Naturerklärung auf diese zurückgebracht wurde, desto mehr verlor sie selbst die Mittel, ihre eignen Erscheinungen zu begreifen. Noch von der Jugendzeit der Wissenschaft her, wo die Ahndung der inneren Einheit aller Dinge dem menschlichen Geist näher lag, hatte die jetzige Chemie einige bildliche Ausdrücke, wie Verwandtschaft u.a. behalten, die aber, weit entfernt Andeutungen einer Idee zu seyn, in ihr vielmehr nur Freistätten der Unwissenheit wurden. Das oberste Princip und die äußerste Grenze aller Erkenntniß wurde immer mehr das, was sich durch das Gewicht erkennen läßt, und jene der Natur eingeborenen, in ihr waltenden Geister, welche die unvertilgbaren Qualitäten wirken, wurden selbst Materien, die in Gefäßen aufgefangen und eingesperrt werden konnten. Ich leugne nicht, daß die neuere Chemie uns mit vielen Thatsachen bereichert hat, obgleich es immer wünschenswerth bleibt, daß"}, {"type": "paragraph", "text": "diese neue Welt gleich anfangs durch ein höheres Organ entdeckt worden wäre, und die Einbildung lächerlich ist, in der Aneinanderreihung jener Thatsachen, die durch nichts als die unverständlichen Worte Stoff, Anziehung u.s.w. zusammengehalten wird, eine Theorie erlangt zu haben, da man nicht einmal einen Begriff von Qualität, von Zusammensetzung, Zerlegung u.s.w. hatte. Es mag vortheilhaft seyn, die Chemie von der Physik abgesondert zu behandeln; aber dann muß sie auch als bloße experimentirende Kunst, ohne allen Anspruch auf Wissenschaft, betrachtet werden. Die Construktion der chemischen Erscheinungen gehört nicht einer besonderen Scienz, sondern der allgemeinen und umfassenden Wissenschaft der Natur an, in der sie nicht außer dem Zusammenhang des Ganzen und als Phänomene von eigenthümlicher Gesetzmäßigkeit, sondern als einzelne Erscheinungsweisen des allgemeinen Lebens der Natur erkannt werden. Die Darstellung des allgemeinen dynamischen Processes, der im Weltsystem überhaupt und in Ansehung des Ganzen der Erde stattfindet, ist im weitesten Sinn Meteorologie und insofern ein Theil der physischen Astronomie, da auch die allgemeinen Veränderungen der Erde nur durch ihr Verhältniß zum allgemeinen Weltbau vollkommen gefaßt werden können. Die Mechanik betreffend, von der ein großer Theil in die Physik aufgenommen worden ist, so gehört diese der angewandten Mathematik an; der allgemeine Typus ihrer Formen aber, welche nur die, rein objektiv ausgedrückten, gleichsam getödteten Formen des dynamischen Processes sind, ist ihr durch die Physik vorgezeichnet. Das Gebiet der letztern in ihrer gewöhnlichen Absonderung beschränkt sich auf die Sphäre des allgemeinen Gegensatzes zwischen dem Licht und der Materie oder Schwere. Die absolute Wissenschaft"}]}, {"page_pdf": 1597, "page_book": 335, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der Natur begreift in einem und demselben Ganzen sowohl diese Erscheinungen der getrennten Einheit, als die der höheren, organischen Welt, durch deren Produkte die ganze Subjekt-Objektivirung, in ihren zwei Seiten zugleich, erscheint."}, {"type": "heading", "text": "Dreizehnte Vorlesung. *Ueber das Studium der Medicin und der organischen Naturlehre überhaupt.*", "level": null}, {"type": "paragraph", "text": "Wie der Organismus, nach der ältesten Ansicht, nichts anderes als die Natur im Kleinen und in der vollkommensten Selbstanschauung ist, so muß auch die Wissenschaft desselben alle Strahlen der allgemeinen Erkenntniß der Natur wie in einen Brennpunkt zusammenbrechen und eins machen. Fast zu jeder Zeit wurde die Kenntniß der allgemeinen Physik wenigstens als nothwendige Stufe und Zugang zu dem Heiligthum des organischen Lebens betrachtet. Aber welches wissenschaftliche Vorbild konnte die organische Naturlehre von der Physik entlehnen, die selbst ohne die allgemeine Idee der Natur, jene nur mit ihren eignen Hypothesen beschweren und verunstalten konnte, wie es allgemein genug geschehen ist, seitdem die Schranken, wodurch man die allgemeine und die lebendige Natur voneinander getrennt glaubte, mehr oder weniger durchbrochen wurden? Der Enthusiasmus des Zeitalters für Chemie hat diese auch zum Erkenntnißgrund aller organischen Erscheinungen und das Leben selbst zu einem chemischen Proceß gemacht. Die Erklärungen der ersten Bildung des Lebendigen durch Wahlanziehung oder Krystallisation, der organischen Bewegungen und selbst der sogenannten Sinneswirkungen durch Mischungsveränderungen und Zersetzungen gehen vortrefflich von statten, nur daß diejenigen, die sie machen, vorerst noch zu erklären"}, {"type": "paragraph", "text": "haben, was denn Wahlanziehung und Mischungsveränderung selbst sey, eine Frage, welche beantworten zu können, sie sich ohne Zweifel bescheiden. Mit dem bloßen Uebertragen, Anwenden von dem einen Theil der Naturwissenschaft auf den andern ist es nicht gethan: jeder ist in sich absolut, keiner von dem andern abzuleiten, und alle können nur dadurch wahrhaft eins werden, daß in jedem für sich das Besondere aus dem Allgemeinen und aus einer absoluten Gesetzmäßigkeit begriffen wird. Daß nun erstens die Medicin allgemeine Wissenschaft der organischen Natur werden müsse, von welcher die sonst getrennten Theile derselben sämmtlich nur Zweige wären, und daß um ihr sowohl diesen Umfang und innere Einheit, als den Rang einer Wissenschaft zu geben, die ersten Grundsätze, auf denen sie ruht, nicht empirisch oder hypothetisch, sondern durch sich selbst gewiß und philosophisch seyn müssen: dieß ist zwar seit einiger Zeit allgemeiner gefühlt und anerkannt worden, als es in Ansehung der übrigen Theile der Naturlehre der Fall ist. Aber auch hier sollte die Philosophie vorerst kein weiteres Geschäft haben, als in die vorhandene und gegebene Mannichfaltigkeit die äußere formale Einheit zu bringen, und den Aerzten, deren Wissenschaft durch Dichter und Philosophen seit geraumer Zeit zweideutig geworden war, wieder einen guten Namen zu machen. Wenn Browns Lehre durch nichts ausgezeichnet wäre als durch die Reinheit von empirischen Erklärungen und Hypothesen, die Anerkennung und Durchführung des großen Grundsatzes der bloß quantitativen Verschiedenheit aller Erscheinungen, und die Consequenz, mit der sie aus Einem ersten Princip folgert, ohne sich etwas"}]}, {"page_pdf": 1598, "page_book": 337, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "anderes zugeben zu lassen oder je von der Bahn der Wissenschaft abzuschweifen: so wäre ihr Urheber schon dadurch einzig in der bisherigen Geschichte der Medicin und der Schöpfer einer neuen Welt auf diesem Gebiet des Wissens. Es ist wahr, er bleibt bei dem Begriff der Erregbarkeit stehen und hat von diesem selbst keine wissenschaftliche Erkenntniß, aber er verweigert zugleich alle empirische Erklärung davon, und warnt, sich nicht auf die ungewisse Untersuchung der Ursachen, das Verderben der Philosophie, einzulasssen. Ohne Zweifel hat er damit nicht geleugnet, daß es eine höhere Sphäre des Wissens gebe, in welcher"}, {"type": "paragraph", "text": "jener Begriff selbst wieder als ein abzuleitender eintreten und aus höheren ebenso construirt werden könne, wie er selbst aus ihm die abgeleiteten Formen der Krankheit hervorgehen läßt. Der Begriff der Erregbarkeit ist ein bloßer Verstandesbegriff, wodurch zwar das einzelne organische Ding, aber nicht das Wesen des Organismus bestimmt ist. Denn das absolut-Ideale, welches in ihm ganz objektiv und subjektiv zugleich, als Leib und als Seele erscheint, ist an sich außer aller Bestimmbarkeit; das einzelne Ding aber, der organische Leib, den es sich als Tempel erbaut, ist durch äußere Dinge bestimmbar und nothwendig bestimmt. Da nun jenes über die Einheit der Form und des Wesens im Organismus wacht, als in welcher allein dieser das Symbol von ihm ist, so wird es durch jede Bestimmung von außen, wodurch die erste verändert wird, zur Wiederherstellung und demnach zum Handeln bestimmt. Es ist also immer nur indirekt, nämlich durch Veränderung der äußern Bedingungen des Lebens, niemals aber an sich selbst bestimmbar. Das, wodurch der Organismus Ausdruck der ganzen Subjekt-Objektivirung ist, ist, daß die Materie, welche auf der tieferen Stufe dem Licht entgegengesetzt und als Substanz erschien, in ihm dem Licht verbunden (und weil beide, vereinigt, sich nur als Attribute von einem und demselbigen verhalten können) bloßes Accidens des An-sich des Organismus und demnach ganz Form wird. In dem ewigen Akt der Umwandlung der Subjektivität in die Objektivität kann die Objektivität oder die Materie nur Accidens seyn, dem die Subjektivität als das Wesen oder die Substanz entgegensteht, welche aber in der Entgegensetzung selbst die Absolutheit ablegt und als bloß relativ-Ideales (im Licht) erscheint. Der Organismus ist es also, welcher Substanz und Accidens als vollkommen eins und, wie in dem absoluten Akt der Subjekt-Objektivirung, in eins gebildet darstellt. Dieses Princip der Formwerdung der Materie bestimmt nicht allein die Erkenntniß des Wesens, sondern auch der einzelnen Funktionen des Organismus, deren Typus mit dem allgemeinen der lebendigen Bewegungen derselbe seyn muß, nur daß die Formen, wie gesagt, mit der"}, {"type": "paragraph", "text": "Materie selbst eins sind und ganz in sie übergehen. Wenn man alle Versuche der Empirie, diese Funktionen sowohl überhaupt als ihren besondern Bestimmungen nach zu erklären, durchgeht, so findet sich auch nicht in Einer derselben eine Spur des Gedankens, sie als allgemeine und nothwendige Formen zu fassen. Die zufällige Existenz unwägbarer Flüssigkeiten in der Natur, für welche ebenso zufälligerweise in der Conformation des Organismus gewisse Bedingungen der Anziehung, der Zusammensetzung und Zerlegung gegeben sind, ist auch hier das letzte trostlose Asyl der Unwissenheit. Und dennoch ist selbst mit diesen Annahmen noch keine Erklärung dahin gelangt, irgend eine organische Bewegung z.B. der Contraktion auch nur von Seiten ihres Mechanismus begreiflich zu machen. Man fiel zwar sehr frühzeitig auf die Analogie zwischen diesen Erscheinungen und denen der Elektricität; aber da man diese selbst nicht als allgemeine, sondern nur als besondere Form kannte und auch keinen Begriff"}]}, {"page_pdf": 1599, "page_book": 339, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "von Potenzen in der Natur hatte, so wurden die ersten, anstatt mit den andern auf die gleiche Stufe, wenn nicht auf die höhere, gesetzt zu werden, vielmehr von ihnen abgeleitet und als bloße Wirkungen von ihnen begriffen: wobei, auch das elektrische Wesen als Thätigkeitsprincip zugegeben, den eigenthümlichen Typus der Zusammenziehung zu erklären, noch neue Hypothesen erfordert wurden. Die Formen der Bewegung, welche in der anorgischen Natur schon durch Magnetismus, Elektricität und chemischen Proceß ausgedrückt sind, sind allgemeine Formen, die in den letzteren selbst bloß auf eine besondere Weise erscheinen. In ihrer Gestalt als Magnetismus u.s.w. stellen sie sich als bloße von der Substanz der Materie verschiedene Accidenzen dar. In der höheren Gestalt, welche sie durch den Organismus erhalten, sind sie Formen, die zugleich das Wesen der Materie selbst sind. Für die körperlichen Dinge, deren Begriff bloß der unmittelbare Begriff von ihnen selbst ist, fällt die unendliche Möglichkeit aller als Licht außer ihnen: im Organismus, dessen Begriff unmittelbar zugleich der Begriff anderer Dinge ist, fällt das Licht in das Ding selbst, und in gleichem Verhältniß wird auch die zuvor als Substanz angeschaute Materie ganz als Accidens gesetzt."}, {"type": "paragraph", "text": "Entweder ist nun das ideelle Princip der Materie nur für die erste Dimension verbunden: in diesem Fall ist jene auch nur für die letztere als Dimension des in-sich-selbst-Seyns von der Form durchdrungen und mit ihr eins; das organische Wesen enthält bloß die unendliche Möglichkeit von sich selbst als Individuum oder als Gattung. Oder das Licht hat auch in der andern Dimension der Schwere sich vermählt: so ist die Materie zugleich für diese, welche die des Seyns in andern Dingen ist, als Accidens gesetzt, und das organische Wesen enthält die unendliche Möglichkeit anderer Dinge außer ihm. In dem ersten Verhältniß, welches das der Reproduction ist, waren Möglichkeit und Wirklichkeit beide auf das Individuum beschränkt und dadurch selbst eins; in dem andern, welches das der selbständigen Bewegung ist, geht das Individuum über seinen Kreis hinaus auf andere Dinge: Möglichkeit und Wirklichkeit können hier also nicht in ein und dasselbige fallen, weil die andern Dinge ausdrücklich als andere, als außer dem Individuum befindliche gesetzt seyn sollen. Wenn aber die beiden vorhergehenden Verhältnisse in dem höheren verknüpft werden und die unendliche Möglichkeit anderer Dinge doch zugleich als Wirklichkeit in dasselbige fällt, worein jene, so ist damit die höchste Funktion des ganzen Organismus gesetzt; die Materie ist in jeder Beziehung und ganz Accidens des Wesens, des Idealen, welches an sich produktiv, aber hier, in der Beziehung auf ein endloses Ding, als ideal zugleich sinnlich-producirend, also anschauend ist. Wie auch die allgemeine Natur nur in der göttlichen Selbstbeschauung besteht und die Wirkung von ihr ist, so ist in den lebenden Wesen dieses ewige Produciren selbst erkennbar gemacht und objektiv geworden. Es bedarf kaum des Beweises, daß in diesem höheren Gebiet der organischen Natur, wo der ihr eingeborne Geist seine Schranken durchbricht, jede Erklärung, die sich auf die gemeinen Vorstellungen von der Materie stützt, so wie alle Hypothesen, durch welche die untergeordneten Erscheinungen noch nothdürftig begreiflich gemacht werden, völlig unzureichend werden; weßhalb auch die Empirie dieses Gebiet allmählich ganz geräumt und sich theils hinter die Vorstellungen des Dualismus theils in die Teleologie zurückgezogen hat."}, {"type": "paragraph", "text": "Nach Erkenntniß der organischen Funktionen in der Allgemeinheit und Nothwendigkeit ihrer Formen ist die der Gesetze, nach welchen ihr Verhältniß untereinander, sowohl im Individuum als in der gesammten Welt der Organisationen, bestimmt ist, die erste und wichtigste."}]}, {"page_pdf": 1600, "page_book": 341, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Das Individuum ist in Ansehung desselben auf eine gewisse Grenze eingeschränkt, welche nicht überschritten werden kann, ohne sein Bestehen als Produkt unmöglich zu machen: es ist dadurch der Krankheit unterworfen. Die Construktion dieses Zustandes ist ein nothwendiger Theil der allgemeinen organischen Naturlehre, und von dem, was man Physiologie genannt hat, nicht zu trennen. In der größten Allgemeinheit kann sie vollkommen aus den höchsten Gegensätzen der Möglichkeit und Wirklichkeit im Organismus und der Störung des Gleichgewichtes beider geführt werden: die besondern Formen und Erscheinungen der Krankheit aber sind allein aus dem veränderten Verhältniß der drei Grundformen der organischen Thätigkeit erkennbar. Es gibt ein doppeltes Verhältniß des Organismus, wovon ich das erste das natürliche nennen möchte, weil es als ein rein quantitatives der innern Faktoren des Lebens zugleich ein Verhältniß zu der Natur und den äußern Dingen ist. Das andere, welches ein Verhältniß der beiden Faktoren in Bezug auf die Dimensionen ist, und die Vollkommenheit bezeichnet, in welcher der Organismus Bild des Universum, Ausdruck des Absoluten ist, nenne ich das göttliche Verhältniß. Brown hat allein auf das erste als das vornehmste für die medicinische Kunst reflektirt, aber deßhalb das andere nicht positiv ausgeschlossen, dessen Gesetze allein den Arzt die Gründe der Formen, den ersten und hauptsächlichsten Sitz des Mißverhältnisses lehren, ihn in der Wahl der Mittel leiten, und über das, was der Mangel an Abstraktion das Specifische in der Wirkung der letztern sowohl als in den Erscheinungen der Krankheit genannt hat, verständigen. Daß nach dieser Ansicht auch die Lehre von den Arzneimitteln keine eigne Scienz, sondern nur ein Element der allgemeinen Wissenschaft der organischen Natur sey, versteht sich von selbst. Ich müßte nur das von würdigen Männern vielfach Gesagte wiederholen, wenn ich beweisen wollte, daß die Wissenschaft der Medicin"}, {"type": "paragraph", "text": "in diesem Sinne nicht nur überhaupt philosophische Bildung des Geistes, sondern auch Grundsätze der Philosophie voraussetze; und wenn es zur Ueberzeugung von dieser Wahrheit für die Verständigen noch etwas außer den allgemeinen Gründen bedürfte, wären es folgende Betrachtungen: daß in Ansehung dieses Gegenstandes das Experiment, die einzig mögliche Art der Construktion für die Empirie, an sich unmöglich ist, daß alle angebliche medicinische Erfahrung ihrer Natur nach zweideutig ist, und mittelst derselben über Werth oder Unwerth einer Lehre niemals entschieden werden kann, weil in jedem Fall die Möglichkeit bleibt, daß sie falsch angewendet worden; daß in diesem Theile des Wissens, wenn in irgend einem andern, die Erfahrung erst durch die Theorie möglich gemacht werde, wie die durch die Erregungstheorie gänzlich veränderte Ansicht aller vergangenen Erfahrung hinlänglich beurkundet. Zum Ueberfluß könnte man sich auf die Werke und Hervorbringungen derjenigen berufen, die, ohne den geringsten Begriff oder einige Wissenschaft erster Grundsätze, durch die Macht der Zeit getrieben, die neue Lehre, obgleich sie ihnen unverständlich ist, dennoch in Schriften oder Lehrvorträgen behaupten wollen, und selbst den Schülern lächerlich werden, indem sie das Unvereinbare und Widersprechende damit zu vereinen suchen, auch das Wissenschaftliche wie einen historischen Gegenstand behandeln, und da sie von Beweisen reden, doch immer nur zu erzählen vermögen: auf die man anwenden möchte, was zu seiner Zeit Galenus von dem großen Haufen der Aerzte gesagt hat: so ungeübt und ungebildet und dabei so frech und schnell im Beweisen, wenn sie schon nicht wissen, was ein Beweis ist - wie soll man mit diesen vernunftlosen Wesen * noch * länger streiten und seine Zeit an ihren Erbärmlichkeiten verlieren! Dieselben Gesetze, welche die Metamorphosen der Krankheit bestimmen, bestimmen auch die allgemeinen und bleibenden Verwandlungen, welche die Natur in der Produktion der verschiedenen Gattungen übt. Denn auch diese beruhen einzig auf der steten Wiederholung eines und desselben Grundtypus mit beständig veränderten Verhältnissen, und es ist offenbar, daß die Medicin erst dann in die allgemeine organische Naturlehre vollkommen sich auflösen wird, wenn sie die Geschlechter"}]}, {"page_pdf": 1601, "page_book": 342, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der Krankheiten, dieser idealen Organismen, mit der gleichen Bestimmtheit wie die ächte Naturgeschichte die Geschlechter der realen Organismen construirt, wo denn beide nothwendig als sich entsprechend erscheinen müssen. Aber was kann die historische Construktion der Organismen, welche den schaffenden Geist durch seine Labyrinthe verfolgt, anders leiten als die Form der äußern Bildung, da kraft des ewigen Gesetzes der Subjekt-Objektivirung das Aeußere in der ganzen Natur Ausdruck und Symbol des Inneren ist, und sich ebenso regelmäßig und bestimmt wie dieses verändert? Die Denkmäler einer wahren Geschichte der organisch-zeugenden Natur sind also die sichtbaren Formen lebendiger Bildungen von der Pflanze bis zum Gipfel des Thiers, deren Kenntniß man bisher, in einseitigem Sinne, als vergleichende Anatomie bezeichnet hat. Zwar leidet es keinen Zweifel, daß in dieser Art des Wissens Vergleichung das erste leitende Princip ist: aber nicht Vergleichung mit irgend einem empirischen Vorbild, am wenigsten mit der menschlichen Bildung, welche als die vollendetste nach einer Richtung zugleich an der Grenze der Organisation steht. Die erste Beschränkung der Anatomie überhaupt auf die des menschlichen Körpers hatte zwar in dem Gebrauch, der von derselben in der Arzneikunst beabsichtigt wurde, einen sehr einleuchtenden Grund, war aber der Wissenschaft selbst in keinem Betracht vortheilhaft. Nicht nur weil die menschliche Organisation so verborgen ist, daß, um der Anatomie derselben auch nur diejenige Vollkommenheit zu geben, die sie jetzt hat, die Vergleichung mit andern Organisationen nothwendig war, sondern auch, weil sie, durch ihre Potenzirtheit selbst, den Gesichtspunkt für die übrigen verrückt und die Erhebung zu einfachen und allgemeinen Ansichten erschwert. Die Unmöglichkeit, über die Gründe einer so verwickelten Bildung im Einzelnen die geringste Rechenschaft abzulegen, nachdem man selbst den Weg dazu versperrt hatte, führte die Trennung der Anatomie und Physiologie, die sich beide wie Aeußeres und Inneres entsprechen müßten, und jene ganz mechanische Art des Vortrags herbei, der in den meisten Lehrbüchern und auf Akademien der herrschende ist. Der Anatom, welcher seine Wissenschaft zugleich als Naturforscher und im allgemeinen Geiste behandeln wollte, müßte zuvörderst erkennen,"}, {"type": "paragraph", "text": "daß es einer Abstraktion, einer Erhebung über die gemeine Ansicht bedarf, um die wirklichen Formen auch nur historisch wahr auszusprechen. Er begreife das Symbolische aller Gestalten, und daß auch in dem Besondern immer eine allgemeine Form, wie in dem Aeußern ein innerer Typus, ausgedrückt ist. Er frage nicht: wozu dient dieses oder jenes Organ? sondern: wie ist es entstanden? und zeige die reine Nothwendigkeit seiner Formation. Je allgemeiner, je weniger auf den besondern Fall eingerichtet die Ansichten sind, aus denen er die Genesis der Formen herleitet, desto eher wird er die unaussprechliche Naivetät der Natur in so vielen ihrer Bildungen erreichen und fassen. Am wenigsten wolle er, indem er die Weisheit und Vernunft Gottes zu bewundern meint, seine eigne Unweisheit und Unvernunft zu bewundern geben. Beständig sey in ihm die Idee von der Einheit und inneren Verwandtschaft aller Organisationen, der Abstammung von Einem Urbild, dessen Objektives allein veränderlich, das Subjektive aber unveränderlich ist: und jene darzustellen, halte er für sein einziges wahres Geschäft. Er bemühe sich vor allem um das Gesetz, nach welchem jene Veränderlichkeit stattfindet: er wird erkennen, daß, weil das Urbild an sich immer dasselbige bleibt, auch das, wodurch es ausgedrückt wird, nur der Form nach veränderlich seyn könne, daß also eine gleiche Summe von Realität in allen Organisationen verwendet"}]}, {"page_pdf": 1602, "page_book": 344, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "und nur verschiedentlich genutzt wird; daß eine Ersetzung des Zurückstehens der einen Form durch das Hervortreten der andern und des Uebergewichts von dieser durch das Zurückdrängen von jener statthabe. Er wird sich aus Vernunft und Erfahrung einen Schematismus aller innern und äußern Dimensionen entwerfen, in welche sich der produktive Trieb werfen kann, wodurch er für die Einbildungskraft ein Prototyp aller Organisationen gewinnt, das in seinen äußersten Grenzen unbeweglich, innerhalb derselben aber der größten Freiheit der Bewegung fähig ist. Die historische Construktion der organischen Natur würde, in sich vollendet, die reale und objektive Seite der allgemeinen Wissenschaft derselben zum vollkommenen Ausdruck der Ideen in dieser, und dadurch mit ihr selbst wahrhaft eins machen."}, {"type": "heading", "text": "Vierzehnte Vorlesung. *Ueber Wissenschaft der Kunst, in Bezug auf das akademische Studium.*", "level": null}, {"type": "paragraph", "text": "Wissenschaft der Kunst kann vorerst die historische Construktion derselben bedeuten. In diesem Sinne fordert sie als äußere Bedingung nothwendig unmittelbare Anschauung der vorhandenen Denkmäler. Da diese in Ansehung der Werke der Dichtkunst allgemein möglich ist, wird auch jene in der angegebenen Beziehung, als Philologie, ausdrücklich unter die Gegenstände des akademischen Vortrags gezählt. Demungeachtet wird auf Universitäten nichts seltener gelehrt als Philologie in dem zuvor bestimmten Sinne, welches nicht zu verwundern, da jene ebenso sehr Kunst ist wie die Poesie, und der Philologe nicht minder als der Dichter geboren wird. Noch viel weniger also ist die Idee einer historischen Construktion der Werke bildender Kunst auf Universitäten zu suchen, da sie der unmittelbaren Anschauung derselben beraubt sind, und wo etwa auch ehrenhalber, mit Unterstützung einer reichen Bibliothek, solche Vorträge versucht werden, schränkten sie sich von selbst auf die bloß gelehrte Kenntniß der Kunstgeschichte ein. Universitäten sind nicht Kunstschulen. Noch weniger also kann die Wissenschaft derselben in praktischer oder technischer Absicht auf ihnen gelehrt werden. Es bleibt also nur die ganz speculative übrig, welche nicht auf"}, {"type": "paragraph", "text": "Ausbildung der empirischen, sondern der intellektuellen Anschauung der Kunst gerichtet wäre. Aber eben hiemit wird die Voraussetzung einer philosophischen Construktion der letzteren gemacht, gegen welche sich von Seiten der Philosophie wie der Kunst bedeutende Zweifel erheben. Sollte zuvörderst der Philosoph, dessen intellektuelle Anschauung allein auf die, sinnlichen Augen verborgene und unerreichbare, nur dem Geiste zugängliche Wahrheit gerichtet seyn soll, sich mit der Wissenschaft der Kunst befassen, welche nur die Hervorbringung des schönen Scheins zur Absicht hat, und entweder bloß die täuschenden Nachbilder von jener zeigt, oder ganz sinnlich ist, wie sie der größte Theil der Menschen begreift, der sie als Sinnenreiz, als Erholung, Abspannung des durch ernstere Geschäfte ermüdeten Geistes ansieht, als angenehme Erregung, die vor jeder andern nur das voraus hat, daß sie durch ein zarteres Medium geschieht, wodurch sie aber für das Urtheil des Philosophen, außerdem daß er sie als eine Wirkung des sinnlichen Triebes betrachten muß, nur das noch verwerflichere Gepräge"}]}, {"page_pdf": 1603, "page_book": 346, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der Verderbniß und der Civilisation erhalten kann. Nach dieser Vorstellung derselben könnte Philosophie sich von der schlaffen Sinnlichkeit, welche die Kunst sich wegen dieser Beziehung gefallen läßt, nur durch absolute Verdammung derselben unterscheiden. Ich rede von einer heiligeren Kunst, derjenigen, welche, nach den Ausdrücken der Alten, ein Werkzeug der Götter, eine Verkündigerin göttlicher Geheimnisse, die Enthüllerin der Ideen ist, von der ungebornen Schönheit, deren unentweihter Strahl nur reine Seelen inwohnend erleuchtet, und deren Gestalt dem sinnlichen Auge ebenso verborgen und unzugänglich ist als die der gleichen Wahrheit. Nichts von dem, was der gemeinere Sinn Kunst nennt, kann den Philosophen beschäftigen: sie ist ihm eine nothwendige, aus dem Absoluten unmittelbar ausfließende Erscheinung, und nur sofern sie als solche dargethan und bewiesen werden kann, hat sie Realität für ihn. \"Aber hat nicht selbst der göttliche Plato in seiner Republik die nachahmende Kunst verdammt, die Poeten aus seinem Vernunftstaat verbannt, nicht nur als unnütze, sondern als verderbliche Glieder, und"}, {"type": "paragraph", "text": "kann irgend eine Autorität beweisender für die Unverträglichkeit der Poesie und Philosophie seyn, als dieses Urtheil des Königs der Philosophen?\" Es ist wesentlich, den bestimmten Standpunkt zu erkennen, aus welchem Plato jenes Urtheil über die Dichter spricht; denn wenn irgend ein Philosoph die Absonderung der Standpunkte beobachtet hat, ist es dieser, und ohne jene Unterscheidung würde es, wie überall, so hier insbesondere, unmöglich seyn, seinen beziehungsreichen Sinn zu fassen, oder die Widersprüche seiner Werke über denselbigen Gegenstand zu vereinigen. Wir müssen uns vorerst entschließen, die höhere Philosophie und die des Plato insbesondere als den entschiedenen Gegensatz in der griechischen Bildung, nicht nur in Beziehung auf die sinnlichen Vorstellungen der Religion, sondern auch auf die objektiven und durchaus realen Formen des Staates, zu denken. Ob nun in einem ganz idealen und gleichsam innerlichen Staat, wie der Platonische, von der Poesie auf andere Weise die Rede seyn könne, und jene Beschränkung, die er ihr auferlegt, nicht eine nothwendige sey, die Beantwortung dieser Frage würde uns hier zu weit führen. Jener Gegensatz aller öffentlichen Formen gegen die Philosophie mußte nothwendig eine gleiche Entgegensetzung der letzteren gegen die erstere hervorbringen, wovon Plato weder das früheste noch das einzige Beispiel ist. Von Pythagoras an und noch weiter zurück bis auf Plato herab erkennt sich die Philosophie selbst als eine exotische Pflanze im griechischen Boden, ein Gefühl, das schon in dem allgemeinen Trieb sich ausdrückte, welcher diejenigen, die entweder durch die Weisheit früherer Philosophen oder die Mysterien in höhere Lehren eingeweiht waren, nach dem Mutterland der Ideen, dem Orient, führte. Aber auch abgesehen von dieser bloß historischen, nicht philosophischen, Entgegensetzung, die letztere vielmehr zugegeben, was ist Platos Verwerfung der Dichtkunst, verglichen insbesondere mit dem, was er in andern Werken zum Lob der enthusiastischen Poesie sagt, anders als Polemik gegen den poetischen Realismus, eine Vorahndung der späteren Richtung des Geistes überhaupt und der Poesie insbesondere? Am"}, {"type": "paragraph", "text": "wenigsten könnte jenes Urtheil gegen die christliche Poesie geltend gemacht werden, welche im Ganzen ebenso bestimmt den Charakter des Unendlichen trägt, wie die antike im Ganzen den des Endlichen. Daß wir die Grenzen, welche die letztere hat, genauer bestimmen können als Plato, der ihren Gegensatz nicht kannte, daß wir eben deßwegen uns zu einer umfassenderen Idee und Construktion der Poesie als er erheben, und das, was er als das Verwerfliche der Poesie seiner Zeit betrachtete, nur als die schöne"}]}, {"page_pdf": 1604, "page_book": 348, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Schranke derselben bezeichnen, verdanken wir der Erfahrung der späteren Zeit, und sehen als Erfüllung, was Plato weissagend vermißte. Die christliche Religion und mit ihr der aufs Intellektuelle gerichtete Sinn, der in der alten Poesie weder seine vollkommene Befriedigung noch selbst die Mittel der Darstellung finden konnte, hat sich eine eigne Poesie und Kunst geschaffen, in der er sie findet: dadurch sind die Bedingungen der vollständigen und ganz objektiven Ansicht der Kunst, auch der antiken, gegeben. Es erhellt hieraus, daß die Construktion derselben ein würdiger Gegenstand nicht nur überhaupt des Philosophen, sondern auch insbesondere des christlichen Philosophen sey, der sich ein eignes Geschäft daraus zu machen hat, das Universum derselben zu ermessen und darzustellen. Aber ist, um die andere Seite dieses Gegenstandes herauszukehren, seinerseits nun der Philosoph geeignet, das Wesen der Kunst zu durchdringen und mit Wahrheit darzustellen? \"Wer kann, so höre ich fragen, von jenem göttlichen Princip, das den Künstler treibt, jenem geistigen Hauch, der seine Werke beseelt, würdig reden, als wer selbst von dieser heiligen Flamme ergriffen ist? Kann man versuchen, dasjenige der Construktion zu unterwerfen, was ebenso unbegreiflich in seinem Ursprung als wundervoll in seinen Wirkungen ist? Kann man das unter Gesetze bringen und bestimmen wollen, dessen Wesen es ist, kein Gesetz als sich selbst anzuerkennen? Oder ist nicht das Genie durch Begriffe so wenig zu fassen, als es durch Gesetze erschaffen werden kann? Wer wagt es, noch über das hinaus einen Gedanken haben zu wollen, was offenbar das Freieste, das Absoluteste"}, {"type": "paragraph", "text": "ist im ganzen Universum, wer über die letzten Grenzen hinaus seinen Gesichtskreis zu erweitern, um dort neue Grenzen zu stecken?\" So könnte ein gewisser Enthusiasmus reden, der die Kunst nur in ihren Wirkungen aufgefaßt hätte, und weder sie selbst wahrhaft noch die Stelle kennte, welche der Philosophie im Universum angewiesen ist. Denn auch angenommen, daß die Kunst aus nichts Höherem begreiflich sey, so ist doch so durchgreifend, so allwaltend das Gesetz des Universum, daß alles, was in ihm begriffen ist, in einem andern sein Vorbild oder Gegenbild habe, so absolut die Form der allgemeinen Entgegenstellung des Realen und Idealen, daß auch auf der letzten Grenze des Unendlichen und Endlichen, da wo die Gegensätze der Erscheinung in die reinste Absolutheit verschwinden, dasselbe Verhältniß seine Rechte behauptet und in der letzten Potenz wiederkehrt. Dieses Verhältniß ist das der Philosophie und der Kunst. Die letztere, obgleich ganz absolut, vollkommene Ineinsbildung des Realen und Idealen verhält sich doch selbst wieder zur Philosophie wie Reales zum Idealen. In dieser löst der letzte Gegensatz des Wissens sich in die reine Identität auf, und nichtsdestoweniger bleibt auch sie im Gegensatz gegen die Kunst immer nur ideal. Beide begegnen sich also auf dem letzten Gipfel und sind sich, eben kraft der gemeinschaftlichen Absolutheit, Vorbild und Gegenbild. Dieß ist der Grund, daß in das Innere der Kunst wissenschaftlich kein Sinn tiefer eindringen kann, als der der Philosophie, ja daß der Philosoph in dem Wesen der Kunst so gar klarer als der Künstler selbst zu sehen vermag. Insofern das Ideelle immer ein höherer Reflex des Reellen ist, insofern ist in dem Philosophen nothwendig auch noch ein höherer ideeller Reflex von dem, was in dem Künstler reell ist. Hieraus erhellt nicht nur überhaupt, daß in der Philosophie die Kunst Gegenstand eines Wissens werden könne, sondern auch, daß außer der Philosophie und anders als durch Philosophie von der Kunst nichts auf absolute Art gewußt werden könne. Der Künstler, da in ihm dasselbe Princip objektiv ist, was sich in dem Philosophen subjektiv reflektirt, verhält sich darum auch zu jenem"}]}, {"page_pdf": 1605, "page_book": 350, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "nicht subjektiv oder bewußt, nicht als ob er nicht gleichfalls durch einen höheren Reflex sich desselben bewußt werden könnte; aber dieß ist er nicht in der Qualität des Künstlers. Als solcher ist er von jenem Princip getrieben und besitzt es eben darum selbst nicht; wenn er es mit demselben zum idealen Reflex bringt, so erhebt er sich eben dadurch als Künstler zu einer höheren Potenz, verhält sich aber als solcher auch in dieser stets *objektiv:* das Subjektive in ihm tritt wieder zum Objektiven, wie im Philosophen stets das Objektive ins Subjektive aufgenommen wird. Darum bleibt die Philosophie, der inneren Identität mit der Kunst ungeachtet, doch immer und nothwendig Wissenschaft, d.h. ideal, die Kunst immer und nothwendig Kunst, d.h. real. Wie also der Philosoph die Kunst sogar bis zu der geheimen Urquelle und in die erste Werkstätte ihrer Hervorbringungen selbst verfolgen könne, ist nur vom rein objektiven Standpunkt, oder von dem einer Philosophie aus, die nicht im Idealen zu der gleichen Höhe mit der Kunst im Realen geht, unbegreiflich. Diejenigen Regeln, die das Genie abwerfen kann, sind solche, welche ein bloß mechanischer Verstand vorschreibt; das Genie ist autonomisch, nur der fremden Gesetzgebung entzieht es sich, nicht der eignen, denn es ist nur Genie, sofern es die höchste Gesetzmäßigkeit ist; aber eben diese absolute Gesetzgebung erkennt die Philosophie in ihm, welche nicht allein selbst autonomisch ist, sondern auch zum Princip aller Autonomie vordringt. Zu jeder Zeit hat man daher gesehen, daß die wahren Künstler still, einfach, groß und nothwendig sind in ihrer Art, wie die Natur. Jener Enthusiasmus, der in ihnen nichts erblickt als das von Regeln freie Genie, entsteht selbst erst durch die Reflexion, die von dem Genie nur die negative Seite erkennt: es ist ein Enthusiasmus der zweiten Hand, nicht der, welcher den Künstler beseelt, und der in einer gottähnlichen Freiheit zugleich die reinste und höchste Nothwendigkeit ist. Allein wenn nun der Philosoph auch am ehesten das Unbegreifliche der Kunst darzustellen, das Absolute in ihr zu erkennen fähig ist: wird er ebenso geschickt seyn, das Begreifliche in ihr zu begreifen und durch Gesetze zu bestimmen? Ich meine die technische Seite der Kunst: wird"}, {"type": "paragraph", "text": "sich die Philosophie zu dem Empirischen der Ausführung und der Mittel und Bedingungen derselben herablassen können? Die Philosophie, die ganz allein mit Ideen sich beschäftigt, hat in Ansehung des Empirischen der Kunst nur die allgemeinen Gesetze der Erscheinung, und auch diese nur in der Form der Ideen aufzuzeigen; denn die Formen der Kunst sind die Formen der Dinge an sich und wie sie in den Urbildern sind. Soweit also jene allgemein und aus dem Universum an und für sich eingesehen werden können, ist ihre Darstellung ein nothwendiger Theil der Philosophie der Kunst, nicht aber insofern sie Regeln der Ausführung und Kunstausübung enthält. Denn überhaupt ist Philosophie der Kunst Darstellung der absoluten Welt in der Form der Kunst. Nur die Theorie bezieht sich unmittelbar auf das Besondere oder einen Zweck, und ist das, wornach eine Sache empirisch zu Stande gebracht werden kann. Die Philosophie dagegen ist durchaus unbedingt, ohne Zweck außer sich. Wenn man auch darauf sich berufen wollte, daß das Technische der Kunst dasjenige ist, wodurch sie den Schein der Wahrheit erhält, was also dem Philosophen anheimfallen könnte, so ist diese Wahrheit doch bloß empirisch: diejenige, welche der Philosoph in ihr erkennen und darstellen soll, ist höherer Art, und mit der absoluten Schönheit eins und dasselbe, die Wahrheit der Ideen. Der Zustand des Widerspruchs und der Entzweiung, auch über die ersten Begriffe, worin sich das Kunsturtheil nothwendig in einem Zeitalter befindet, welches die versiegten Quellen derselben durch die Reflexion wieder öffnen will, macht es doppelt wünschenswürdig, daß die absolute Ansicht der Kunst auch in Bezug auf die Formen, in denen diese sich ausdrückt, auf wissenschaftliche Art, von den ersten Grundsätzen aus, durchgeführt würde, da, solange dieß nicht geschehen ist, im Urtheil wie in der Forderung, neben dem, was an sich gemein und platt ist, auch das Beschränkte, das Einseitige, das"}]}, {"page_pdf": 1606, "page_book": 351, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Grillenhafte bestehen kann. Die Construktion der Kunst in jeder ihrer bestimmten Formen bis ins Concrete herab führt von selbst zur Bestimmung derselben durch Bedingungen der Zeit, und geht also dadurch in die historische Construktion"}, {"type": "paragraph", "text": "über. An der vollständigen Möglichkeit einer solchen und Ausdehnung auf die ganze Geschichte der Kunst ist um so weniger zu zweifeln, nachdem der allgemeine Dualismus des Universum, in dem Gegensatz der antiken und modernen Kunst, auch in diesem Gebiet dargestellt und auf die bedeutendste Weise, theils durch das Organ der Poesie selbst, theils durch die Kritik, geltend gemacht worden ist. Da Construktion allgemein Aufhebung von Gegensätzen ist, und die, welche in Ansehung der Kunst durch ihre Zeitabhängigkeit gesetzt sind, wie die Zeit selbst, unwesentlich und bloß formell seyn müssen, so wird die wissenschaftliche Construktion in der Darstellung der gemeinschaftlichen Einheit bestehen, aus der jene ausgeflossen sind, und sich eben dadurch über sie zum umfassenderen Standpunkt erheben. Eine solche Construktion der Kunst ist allerdings mit nichts von dem zu vergleichen, was bis auf die gegenwärtige Zeit unter dem Namen von Aesthetik, Theorie der schönen Künste und Wissenschaften, oder irgend einem andern existirt hat. In den allgemeinsten Grundsätzen des ersten Urhebers jener Bezeichnung lag wenigstens noch die Spur der Idee des Schönen, als des in der concreten und abgebildeten Welt erscheinenden Urbildlichen. Seit der Zeit erhielt diese eine immer bestimmtere Abhängigkeit vom Sittlichen und Nützlichen: so wie in den psychologischen Theorien ihre Erscheinungen ungefähr gleich den Gespenstergeschichten oder anderem Aberglauben wegerklärt worden, bis der hierauf folgende Kantische Formalismus zwar eine neue und höhere Ansicht, mit dieser aber eine Menge kunstleerer Kunstlehren geboren hat. Die Samen einer ächten Wissenschaft der Kunst, welche treffliche Geister seitdem ausgestreut haben, sind noch nicht zum wissenschaftlichen Ganzen gebildet, das sie jedoch erwarten lassen. Philosophie der Kunst ist nothwendiges Ziel des Philosophen, der in dieser das innere Wesen seiner Wissenschaft wie in einem magischen und symbolischen Spiegel schaut; sie ist ihm als Wissenschaft an und für sich wichtig, wie es z.B. die Naturphilosophie ist, als Construktion der merkwürdigsten aller Produkte und Erscheinungen, oder Construktion einer ebenso in sich geschlossenen und vollendeten Welt, als es die Natur ist. Der"}, {"type": "paragraph", "text": "begeisterte Naturforscher lernt durch sie die wahren Urbilder der Formen, die er in der Natur nur verworren ausgedrückt findet, in den Werken der Kunst und die Art, wie die sinnlichen Dinge aus jenen hervorgehen, durch diese selbst sinnbildlich erkennen. Der innige Bund, welcher die Kunst und Religion vereint, die gänzliche Unmöglichkeit, einerseits der ersten eine andere poetische Welt als innerhalb der Religion und durch Religion zu geben, die Unmöglichkeit auf der andern Seite, die letztere zu einer wahrhaft objektiven Erscheinung anders als durch die Kunst zu bringen, machen die wissenschaftliche Erkenntniß derselben dem ächten Religiösen auch schon in dieser Beziehung zur Nothwendigkeit. Endlich gereicht es demjenigen, der unmittelbar oder mittelbar Antheil an der Staatsverwaltung hat, zu nicht geringer Schande, weder überhaupt für die Kunst empfänglich zu seyn, noch eine wahre Kenntniß von ihr zu haben. Denn wie Fürsten und Gewalthaber nichts mehr ehrt, als die Künste zu schätzen, ihre Werke zu achten und durch Aufmunterung hervorzurufen: so gewährt dagegen nichts einen traurigeren"}]}, {"page_pdf": 1607, "page_book": 353, "page_kind": "toc", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "und für sie schimpflicheren Anblick, als wenn diejenigen, welche die Mittel haben, diese zu ihrem höchsten Flor zu befördern, dieselben an Geschmacklosigkeit, Barbarei oder einschmeichelnde Niedrigkeit verschwenden. Wenn es auch nicht allgemein eingesehen werden könnte, daß die Kunst ein nothwendiger und integranter Theil einer nach Ideen entworfenen Staatsverfassung ist, so müßte wenigstens das Alterthum daran erinnern, dessen allgemeine Feste, verewigende Denkmäler, Schauspiele, so wie alle Handlungen des öffentlichen Lebens nur verschiedene Zweige Eines allgemeinen objektiven und lebendigen Kunstwerks waren."}, {"type": "paragraph", "text": "Philosophie der Kunst."}, {"type": "paragraph", "text": "* (Aus dem handschriftlichen Nachlaß.)*"}, {"type": "footnote", "text": "Erstmals vorgetragen zu Jena im Winter 1802 bis 1803, wiederholt 1804 und 1805 in Würzburg."}, {"type": "paragraph", "text": "*Inhalt.*"}, {"type": "paragraph", "text": "*Einleitung.* Seite Beweggründe zur Bearbeitung der Wissenschaft der Kunst ........................ 355 Möglichkeit einer Philosophie der Kunst .................................................... 364 Allgemeinste Deduktion der Philosophie der Kunst .................................... 369 I. Allgemeiner Theil der Philosophie der Kunst."}, {"type": "paragraph", "text": "A) Construktion der Kunst überhaupt und im Allgemeinen ........................ 373 B) Construktion des Stoffs der Kunst"}, {"type": "paragraph", "text": "1) Ableitung der Mythologie als Stoffs der Kunst.................................. 388 2) Gegensatz der antiken und modernen Poesie in Bezug auf"}, {"type": "paragraph", "text": "Mythologie........................................................................................ 417 Religionsphilosophische Entwicklung. C) Construktion des Besonderen oder der Form der Kunst (des besonderen Kunstwerks)"}, {"type": "paragraph", "text": "1) Theorie des Kunstwerks überhaupt .................................................... 458"}, {"type": "paragraph", "text": "Die Gegensätze von Erhabenheit und Schönheit, von Naiv und Sentimental, von Styl und Manier. 2) Uebergang der ästhetischen Idee in das concrete Kunstwerk"}, {"type": "paragraph", "text": "a) Deduktion der bildenen Kunst ...................................................... 480 b) Deduktion der redenden Kunst .................................................... 482 Resultat: Philosophie der Kunst = Construktion des Universums in"}]}, {"page_pdf": 1608, "page_book": 356, "page_kind": "toc", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der Form der Kunst. II. Besonderer Theil der Philosophie der Kunst."}, {"type": "paragraph", "text": "D) Construktion der Kunstformen in der Entgegensetzung der realen"}, {"type": "paragraph", "text": "und idealen Reihe. 1) Reale Seite der Kunstwelt oder die bildende Kunst."}, {"type": "paragraph", "text": "a) Construktion der Musik (Klang, Schall, Gehör) .......................... 488"}, {"type": "paragraph", "text": "á) die Formen der Musik an sich ................................................ 491 â) die Formen der Musik bezogen auf das Leben der Weltkörper .................................................................................. 501 b) Construktion der Malerei (Licht, Farben, Gesichtssinn).............. 506"}, {"type": "paragraph", "text": "á) die Formen der Malerei .......................................................... 517 â) die Gegenstände oder die Kunststufen der Malerei................ 542 c) Construktion der Plastik und ihrer Formen .................................. 569"}, {"type": "paragraph", "text": "á) Architektur.............................................................................. 572 â) Basrelief.................................................................................. 599 ã) Skulptur .................................................................................. 602"}, {"type": "paragraph", "text": "Symbolische Bedeutung der menschlichen Gestalt .............. 604 Allgemeine Anmerkungen über die bildende Kunst überhaupt........ 628"}, {"type": "paragraph", "text": "Seite 2) Ideale Seite der Kunstwelt oder die redende Kunst (Poesie"}, {"type": "paragraph", "text": "im engeren Sinn) a) Verhältniß der Poesie zur Kunst überhaupt.................................. 630 b) Wesen und Form der Poesie ........................................................ 633 c) Construktion der einzelnen Dichtarten"}, {"type": "paragraph", "text": "á) die lyrische Poesie .................................................................. 639 â) die epische Poesie"}, {"type": "paragraph", "text": "aa) Construktion des Epos nach seinen Hauptbestim-"}, {"type": "paragraph", "text": "mungen............................................................................ 646 bb) der epische Stoff ............................................................ 654"}, {"type": "paragraph", "text": "Vergleichung des Virgil mit Homer Neuere Nachahmungen des alten Epos cc) die Differenziirung des Epos in besonderen Gattungen"}, {"type": "paragraph", "text": "áá) Elegie und Idylle ...................................................... 658 ââ) Lehrgedicht und Satyre ............................................ 662"}, {"type": "paragraph", "text": "Lucretius. dd) das romantische (moderne) Epos"}, {"type": "paragraph", "text": "áá) Rittergedicht (Ariosto).............................................. 669 ââ) Roman (Cervantes, Goethe)...................................... 673 ãã) epische Versuche mit neueren Stoffen (Voß. Goethe)684 ee) die göttliche Komödie des Dante (eine epische Gattung"}, {"type": "paragraph", "text": "für sich) .......................................................................... 686 ã) die dramatische Poesie."}, {"type": "paragraph", "text": "aa) Begriff des dramatischen Gedichts überhaupt ................ 687 bb) die Differenziirung des Drama in Tragödie und Komödie"}, {"type": "paragraph", "text": "áá) die Tragödie"}]}, {"page_pdf": 1609, "page_book": 357, "page_kind": "toc", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "aaa) das Wesen und der wahre Gegenstand der"}, {"type": "paragraph", "text": "Tragödie .............................................................. 694 bbb) die innere Construktion der Tragödie .............. 699 ccc) die äußere Form der Tragödie .......................... 704"}, {"type": "paragraph", "text": "Aeschylos, Sophokles, Euripides........................ 708 ââ) von dem Wesen der Komödie .................................. 711"}, {"type": "paragraph", "text": "Aristophanes ...................................................... 714 cc) die moderne dramatische Poesie."}, {"type": "paragraph", "text": "Shakespeare .............................................................. 718 Calderon.................................................................... 726 Goethes Faust............................................................ 731 Die moderne Komödie.............................................. 734 Zurückstreben der redenden zur bildenden Kunst in Musik,"}, {"type": "paragraph", "text": "Gesang, Tanz .................................................................. 735"}, {"type": "heading", "text": "*Einleitung.*", "level": null}, {"type": "footnote", "text": "- - - - - - - - - - - - - - - - - - - - - - - - - - - 1"}, {"type": "footnote", "text": "1 Der Anfang dieser Einleitung, welcher ausführt, \"daß die Kunst ein großer und würdiger Gegenstand nicht nur überhaupt des Philosophen, sondern auch vorzüglich des neueren Philosophen sey\", ist hier weggefallen, da er mit der Vorlesung über die Kunst in der Methode des akademischen Studiums (oben S. 344 ff.) fast gleichlautend ist. Es ist also die genannte Vorlesung zugleich als der Anfang der Einleitung in die Philosophie der Kunst anzusehen. D. H."}, {"type": "paragraph", "text": "Ich bitte *Sie* bei den gegenwärtigen Vorträgen durchaus die rein wissenschaftliche Absicht derselben vor Augen zu haben. Wie die Wissenschaft überhaupt, so ist Wissenschaft der Kunst *an sich* interessant, auch ohne äußeren Zweck. So viele zum Theil unwichtige Gegenstände ziehen die allgemeine Wißbegierde und selbst den wissenschaftlichen Geist auf sich; sonderbar, wenn es eben die Kunst nicht vermöchte, dieser *eine *Gegenstand, der fast allein die höchsten Gegenstände unserer Bewunderung in sich schließt. Der ist noch sehr weit zurück, dem die Kunst nicht als ein geschlossenes, organisches und ebenso in allen seinen Theilen nothwendiges Ganzes erschienen ist, als es die Natur ist. Fühlen wir uns unaufhaltsam gedrungen, das innere Wesen der Natur zu schauen, und jenen fruchtbaren Quell zu ergründen, der so viele große Erscheinungen mit ewiger Gleichförmigkeit und Gesetzmäßigkeit aus sich herausschüttet, wie viel mehr muß es uns interessiren, den Organismus der Kunst zu durchdringen, in der aus der absoluten Freiheit sich die höchste Einheit und Gesetzmäßigkeit herstellt, die uns die Wunder unseres eignen"}, {"type": "paragraph", "text": "Geistes weit unmittelbarer als die Natur erkennen läßt. Interessirt es uns, den Bau, die innere Anlage, die"}]}, {"page_pdf": 1610, "page_book": 359, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Beziehungen und Verwickelungen eines Gewächses oder eines organischen Wesens überhaupt so weit wie möglich zu verfolgen, wie viel mehr müßte es uns reizen, dieselben Verwickelungen und Beziehungen in den noch viel höher organisirten und in sich selbst verschlungeneren Gewächsen zu erkennen, die man Kunstwerke nennt. Den meisten geht es mit der Kunst, wie es dem Meister Jourdain bei Molière1 mit der Prosa ging, der sich wunderte, sein ganzes Leben Prosa gesprochen zu haben, ohne es zu wissen. Die wenigsten überlegen, daß schon die Sprache, in der sie sich ausdrücken, das vollkommenste Kunstwerk ist. Wie viele haben vor einem Theater gestanden, ohne sich nur einmal die Frage aufzuwerfen, wie viele Bedingungen zu einer auch nur einigermaßen vollkommenen theatralischen Erscheinung erfordert werden; wie viele den edlen Eindruck einer schönen Architektur empfunden, ohne Versuchung den Gründen der Harmonie nachzuspüren, die sie daraus angesprochen hat! Wie viele haben ein einzelnes Gedicht oder ein hohes dramatisches Werk auf sich wirken lassen, und sind dadurch bewegt, entzückt, erschüttert worden, ohne je zu untersuchen, durch welche Mittel es dem Künstler gelingt, ihr Gemüth zu beherrschen, ihre Seele zu reinigen, ihr Innerstes aufzuregen - ohne den Gedanken, diesen ganz passiven und insofern unedlen Genuß in den weit höheren der thätigen Beschauung und der Reconstruktion des Kunstwerks durch den Verstand zu verwandeln! Derjenige wird für roh und ungebildet geachtet, der die Kunst *überall *nicht auf sich einfließen lassen und ihre Wirkungen erfahren will. Aber es ist, wenn nicht in demselben Grade, doch dem Geiste nach ebenso roh, die bloß sinnlichen Rührungen, sinnlichen Affekte, oder sinnliches Wohlgefallen, welche Kunstwerke erwecken, für Wirkungen der Kunst als solche zu halten. Für den, der es in der Kunst nicht zur freien, zugleich leidenden"}, {"type": "footnote", "text": "1 Bourgeois gentilhomme, Act. II, Scène 4."}, {"type": "paragraph", "text": "und thätigen, fortgerissenen und überlegten Beschauung bringt, sind alle Wirkungen der Kunst bloße Naturwirkungen; er selbst verhält sich dabei als Naturwesen, und hat die Kunst als Kunst wahrhaft nie erfahren und erkannt. Was ihn bewegt, sind vielleicht die einzelnen Schönheiten, aber in dem wahren Kunstwerk gibt es keine einzelne Schönheit, nur das Ganze ist schön. Wer sich also nicht zur Idee des *Ganzen* erhebt, ist gänzlich unfähig ein Werk zu beurtheilen. Und trotz dieser Gleichgültigkeit sehen wir doch die große Menge der Menschen, die sich gebildet nennen, zu nichts geneigter, als in Sachen der Kunst ein Urtheil zu haben, die Kenner zu spielen, und nicht leicht wird ein nachtheiliges Urtheil tiefer empfunden als das, daß jemand keinen Geschmack habe. Die, welche ihre Schwäche in der Beurtheilung fühlen, halten, bei der sehr entschiedenen Wirkung, die ein Kunstwerk auf sie hat, und der Originalität der Ansicht, die sie vielleicht davon haben, unerachtet, doch ihr Urtheil lieber zurück, als daß sie sich Blößen geben. Andere, die weniger bescheiden sind, machen sich durch ihr Urtheil lächerlich oder fallen den Verständigen damit beschwerlich. Es gehört also sogar zur allgemein gesellschaftlichen Bildung - da überhaupt kein gesellschaftlicheres Studium als das der Kunst - über die Kunst Wissenschaft zu haben, die Fähigkeit, die *Idee *oder das Ganze so wie die wechselseitigen Beziehungen der Theile aufeinander und auf das Ganze und hinwiederum die des Ganzen auf die Theile aufzufassen, in sich ausgebildet zu haben. Aber dieses eben ist nicht möglich anders als durch *Wissenschaft* und insbesondere durch Philosophie. Je strenger die Idee der Kunst und des Kunstwerks construirt wird, desto mehr wird nicht nur der Schlaffheit der Beurtheilung, sondern auch jenem leichtfertigen Versuchen in der Kunst oder Poesie gesteuert, welches gewöhnlich ohne alle Idee derselben angestellt wird. Wie nöthig gerade eine streng wissenschaftliche Ansicht der Kunst zur Ausbildung des intellektuellen Anschauens der Kunstwerke sowie vorzüglich zur Bildung des Urtheils über dieselbe sey, darüber will"}]}, {"page_pdf": 1611, "page_book": 360, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "ich nur noch Folgendes bemerken. Man kann sehr häufig, insbesondere jetzt, die Erfahrung machen,"}, {"type": "paragraph", "text": "wie sehr selbst Künstler untereinander in ihren Urtheilen nicht nur verschieden, sondern entgegengesetzt sind. Dieses Phänomen ist sehr leicht zu erklären. In den Zeitaltern der blühenden Kunst ist es die Nothwendigkeit des allgemein herrschenden Geistes, das Glück und gleichsam der Frühling der Zeit, der unter den großen Meistern mehr oder weniger die allgemeine Uebereinstimmung hervorbringt, so daß, wie dieß auch die Geschichte der Kunst zeigt, die großen Werke gedrängt aufeinander, fast zu gleicher Zeit, wie von einem gemeinschaftlichen Hauch und unter einer gemeinsamen Sonne, entstehen und reifen. Albrecht Dürer zugleich mit Raphael, Cervantes und Calderon zugleich mit Shakespeare. Wenn ein solches Zeitalter des Glücks und der reinen Produktion vorbei ist, so tritt die Reflexion und mit ihr die allgemeine Entzweiung ein; was dort lebendiger Geist war, wird hier Ueberlieferung. Die Richtung der alten Künstler war vom Centrum gegen die Peripherie. Die späteren nehmen die äußerlich abgehobene Form und suchen sie unmittelbar nachzuahmen; sie behalten den Schatten ohne den Körper. Jeder bildet sich nun seine eignen, besonderen Gesichtspunkte für die Kunst, und beurtheilt selbst das Vorhandene darnach. Die einen, welche das Leere der Form ohne den Inhalt bemerken, predigen die Rückkehr zur Materialität durch Nachahmung der Natur, die andern, die sich über jenen leeren und hohlen äußerlichen Abhub der Form nicht schwingen, predigen das Idealische, die Nachahmung des schon Gebildeten; keiner aber kehrt zu den wahren Urquellen der Kunst zurück, aus denen Form und Stoff ungetrennt strömt. Mehr oder weniger ist dieß der gegenwärtige Zustand der Kunst und des Kunsturtheils. So mannichfaltig die Kunst in sich selbst ist, so mannichfaltig und nuancirt sind die verschiedenen Gesichtspunkte der Beurtheilung. Keiner der Streitenden versteht den andern. Sie beurtheilen, der eine nach dem Maßstab der Wahrheit, der andere nach dem der Schönheit, ohne daß ein einziger wüßte, was Wahrheit oder was Schönheit ist. Unter den eigentlich praktischen Künstlern einer solchen Zeit ist also mit wenigen Ausnahmen nichts über das Wesen der Kunst zu erfahren,"}, {"type": "paragraph", "text": "weil es ihnen in der Regel an der Idee der Kunst und der Schönheit gebricht. Und eben diese, selbst unter denen, welche die Kunst ausüben, herrschende Uneinigkeit ist ein dringender Bestimmungsgrund, die wahre Idee und die Principien der Kunst in der Wissenschaft zu suchen. Noch mehr ist ein ernster, aus Ideen geschöpfter Unterricht über Kunst nöthig in diesem Zeitalter des literarischen Bauernkriegs, der gegen alles Hohe, Große, auf Ideen Gegründete, ja gegen die Schönheit in der Poesie und Kunst selbst geführt wird, wo das Frivole, Sinnenreizende oder auf niederträchtige Art Edele die Götzen sind, welchen die größte Verehrung gezollt wird. Nur die Philosophie kann die für die Produktion großentheils versiegten Urquellen der Kunst für die Reflexion wieder öffnen. Nur durch Philosophie können wir hoffen, eine wahre Wissenschaft der Kunst zu erlangen, nicht als ob die Philosophie den Sinn geben könnte, den nur ein Gott geben kann, nicht als ob sie das Urtheil demjenigen verleihen könnte, dem es die Natur versagt hat, sondern daß sie auf eine unveränderliche Weise in Ideen ausspricht, was der wahre Kunstsinn im Concreten anschaut, und wodurch das ächte Urtheil bestimmt wird. Ich halte nicht für unnöthig die Gründe noch anzugeben, welche mich *insbesondere *bestimmt haben, sowohl diese Wissenschaft zu bearbeiten, als diese Vorträge darüber zu halten. Vor allem bitte ich *Sie*, diese Wissenschaft der Kunst mit nichts von all dem zu verwechseln, was"}]}, {"page_pdf": 1612, "page_book": 362, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "man bisher unter diesem Namen oder irgend einem andern als Aesthetik oder Theorie der schönen Künste und Wissenschaften vorgetragen hat. Noch existirt überall keine wissenschaftliche und philosophische Kunstlehre; höchstens existiren Bruchstücke einer solchen, und auch diese sind noch wenig verstanden, und können nicht anders als im Zusammenhang eines Ganzen verstanden werden. Vor Kant war alle Kunstlehre in Deutschland ein bloßer Abkömmling der Baumgartenschen Aesthetik - denn dieser Ausdruck wurde zuerst von Baumgarten gebraucht. Zur Beurtheilung derselben reicht"}, {"type": "paragraph", "text": "es hin zu erwähnen, daß sie selbst wieder ein Sprößling der Wolffschen Philosophie war. In der Periode unmittelbar vor Kant, wo seichte Popularität und Empirismus in der Philosophie das Herrschende waren, wurden die bekannten Theorien der schönen Künste und Wissenschaften aufgestellt, deren Principien die psychologischen Grundsätze der Engländer und Franzosen waren. Man suchte das Schöne aus der empirischen Psychologie zu erklären, und behandelte überhaupt die Wunder der Kunst ohngefähr ebenso aufklärend und wegerklärend wie zu derselben Zeit die Gespenstergeschichten und andern Aberglauben. Bruchstücke dieses Empirismus trifft man selbst noch in späteren, zum Theil nach einer besseren Ansicht gedachten Schriften an. Andere Aesthetiken sind gewissermaßen Recepte oder Kochbücher, wo das Recept zur Tragödie so lautet: Viel Schrecken, doch nicht allzuviel; so viel Mitleid als möglich und Thränen ohne Zahl. Mit Kants Kritik der Urtheilskraft ging es wie mit seinen übrigen Werken. Von den Kantianern war natürlich die äußerste Geschmacklosigkeit, wie in der Philosophie Geistlosigkeit, zu erwarten. Eine Menge Menschen lernten die Kritik der ästhetischen Urtheilskraft auswendig und trugen sie vom Katheder und in Schriften als Aesthetik vor. Nach Kant haben einige vorzügliche Köpfe treffliche Anregungen zur Idee einer wahren philosophischen Wissenschaft der Kunst und einzelne Beiträge zu einer solchen geliefert; noch aber hat keiner ein wissenschaftliches Ganzes oder auch nur die *absoluten * Principien selbst - allgemein gültig und in strenger Form - aufgestellt; auch ist bei mehreren derselben noch nicht die strenge Sonderung des Empirismus und der Philosophie geschehen, die zur wahren Wissenschaftlichkeit erfordert würde. Das System der Philosophie der Kunst, welches ich vorzutragen denke, wird sich also von den bisher vorhandenen wesentlich und sowohl der Form als dem Gehalt nach unterscheiden, indem ich selbst in den Principien weiter zurückgehe, als bisher geschehen ist. Dieselbe Methode, durch die es mir, wenn ich mich nicht irre, in der Naturphilosophie bis zu einem gewissen Punkte möglich geworden ist,"}, {"type": "paragraph", "text": "das vielfach verschlungene Gewebe der Natur zu entwirren und das Chaos seiner Erscheinungen zu sondern, dieselbe Methode wird uns auch durch die noch labyrinthischeren Verwicklungen der Kunstwelt hindurchleiten und über die Gegenstände derselben ein neues Licht verbreiten lassen. Weniger kann ich mir selbst Genüge zu leisten gewiß seyn in Ansehung der *historischen *Seite der Kunst, welche, aus Gründen, die ich in der Folge angeben werde, ein wesentliches Element aller Construktion ist. Ich erkenne zu gut, wie schwierig es ist, in diesem unendlichsten aller Gebiete auch nur die allgemeinsten Kenntnisse über jeden Theil desselben sich zu erwerben, geschweige denn es über alle seine Theile bis zur bestimmtesten und genauesten Kenntniß zu bringen. Was ich allein für mich anführen kann, ist, daß ich das Studium der alten und neueren Werke der Poesie eine lange Zeit mit Ernst betrieben und es zu meinem angelegentlichen Geschäft gemacht habe, daß ich einige Anschauung von Werken der bildenden Kunst gehabt habe, daß ich im Umgang mit ausübenden Künstlern zum Theil zwar nur ihre"}]}, {"page_pdf": 1613, "page_book": 364, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "eigne Uneinigkeit und ihr Nichtverstehen der Sache kennen gelernt, zum Theil aber auch im Umgang mit solchen, die außer der glücklichen Ausübung der Kunst auch noch über sie philosophisch gedacht haben, mir einen Theil derjenigen historischen Ansichten der Kunst erworben habe, die ich zu meinem Zwecke nothwendig glaube. Für diejenigen, die mein System der Philosophie kennen, wird die Philosophie der Kunst nur die Wiederholung desselben in der höchsten Potenz seyn, denjenigen, die es noch nicht kennen, wird die Methode desselben in dieser Anwendung vielleicht nur noch in die Augen springender und deutlicher seyn. Die Construktion wird sich nicht bloß auf das Allgemeine, sondern auch bis auf diejenigen Individuen erstrecken, welche für eine ganze Gattung gelten; ich werde sie und die Welt ihrer Poesie construiren. Ich nenne vorläufig nur Homer, Dante, Shakespeare. In der Lehre von den bildenden Künsten werden die Individualitäten der größten Meister im Allgemeinen charakterisirt werden; in der Lehre von der"}, {"type": "paragraph", "text": "Poesie und den Dichtarten werde ich sogar bis zur Charakteristik einzelner Werke der vorzüglichsten Dichter, z.B. Shakspeares, Cervantes, Goethes herabsteigen, um so die gegenwärtige Anschauung, die uns bei jenen fehlt, hier zu ersetzen. In der allgemeinen Philosophie freuen wir uns, das strenge Antlitz der Wahrheit an und für sich selbst zu sehen, in dieser besondern Sphäre der Philosophie, welche die Philosophie der Kunst begrenzt, gelangen wir zur Anschauung der ewigen Schönheit und der Urbilder alles Schönen. Die Philosophie ist die Grundlage von allem und befaßt alles; sie erstreckt ihre Construktion auf alle Potenzen und Gegenstände des Wissens; nur durch sie gelangt man zum Höchsten. Durch die Kunstlehre bildet sich innerhalb der Philosophie selbst ein engerer Kreis, in dem wir unmittelbarer das Ewige gleichsam in sichtbarer Gestalt schauen, und so steht diese richtig verstanden mit der Philosophie selbst im vollkommensten Einklang. Schon in dem bisher Vorgetragenen lag zum Theil die Andeutung dessen, was Philosophie der Kunst sey; es ist aber nöthig, mich jetzt ausdrücklicher darüber zu erklären. Ich werde die Frage in der größten Allgemeinheit so stellen: *Wie ist Philosophie der Kunst möglich*? (denn Beweis der Möglichkeit in Ansehung der Wissenschaft auch Wirklichkeit). Jeder sieht ein, daß in dem Begriff einer Philosophie der Kunst Entgegengesetztes verbunden werde. Die Kunst ist das Reale, Objektive, die Philosophie das Ideale, Subjektive. Man könnte also die Aufgabe der Philosophie der Kunst zum voraus schon so bestimmen: *das Reale, welches in der Kunst ist, im Idealen darzustellen.* Allein die Frage ist nun eben, was es heiße: *ein Reales im Idealen *darzustellen, und ehe wir dieß wissen, sind wir über den Begriff der Philosophie der Kunst noch nicht im Reinen. Wie haben also die ganze Untersuchung noch tiefer anzufassen. - Da Darstellung im Idealen überhaupt = Construiren, auch die Philosophie der Kunst = Construktion der Kunst seyn soll, so wird diese Untersuchung"}, {"type": "paragraph", "text": "nothwendig zugleich in das Wesen der Construktion tiefer eindringen müssen. Der Zusatz Kunst in \"Philosophie der Kunst\" beschränkt bloß den allgemeinen Begriff der Philosophie, aber hebt ihn nicht auf. Unsere Wissenschaft soll Philosophie seyn. Dieß ist das Wesentliche; daß sie eben Philosophie seyn soll in Beziehung auf Kunst, ist das Zufällige unseres Begriffs. Nun kann aber weder überhaupt das Accidentelle eines Begriffs das Wesentliche desselben"}]}, {"page_pdf": 1614, "page_book": 366, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "verändern, noch kann Philosophie insbesondere als Philosophie der Kunst etwas anderes seyn, als sie an sich und absolut betrachtet ist. Philosophie ist schlechthin und wesentlich eins; sie kann nicht getheilt werden; was also überhaupt Philosophie ist, ist es ganz und ungetheilt. Diesen Begriff von der Ungetheiltheit der Philosophie wünsche ich, daß *Sie *sich insbesondere fest gegenwärtig erhalten, um die ganze Idee unserer Wissenschaft zu fassen. Es ist bekannt genug, welcher heillose Mißbrauch mit dem Begriff der Philosophie getrieben wird. Wir haben schon eine Philosophie, ja sogar eine Wissenschaftslehre der Landwirtschaft erhalten, es ist zu erwarten, daß man auch noch eine Philosophie des Fuhrwerks aufstelle, und daß es am Ende so viel Philosophien gibt, als es überhaupt Gegenstände gibt, und man vor lauter Philosophien die Philosophie selbst gänzlich verlieren wird. Außer diesen vielen Philosophien hat man aber auch noch einzelne philosophische Wissenschaften oder philosophische Theorien. Auch damit ist es nichts. Es ist nur Eine Philosophie und Eine Wissenschaft der Philosophie; was man verschiedene philosophische Wissenschaften nennt, ist entweder etwas ganz Schiefes, oder es sind nur Darstellungen des Einen und ungetheilten Ganzen der Philosophie in verschiedenen *Potenzen* oder unter verschiedenen ideellen Bestimmungen1. Ich erkläre diesen Ausdruck hier, da er das erstemal wenigstens in einem Zusammenhang vorkommt, in dem es wichtig ist daß er"}, {"type": "footnote", "text": "1 Man vergl. hier und zum gleich Folgenden den Anfang der Abhandlung über das Verhältniß der Naturphilosophie zur Philosophie überhaupt, oben S. 106 ff. D. H."}, {"type": "paragraph", "text": "verstanden werde. Er bezieht sich auf die allgemeine Lehre der Philosophie von der wesentlichen und innern Identität aller Dinge und alles dessen, was wir überhaupt unterscheiden. Es ist wahrhaft und an sich nur Ein Wesen, Ein absolut Reales, und dieses Wesen als absolutes ist untheilbar, so daß es nicht durch Theilung oder Trennung in verschiedene Wesen übergehen kann; da es untheilbar ist, so ist Verschiedenheit der Dinge überhaupt nur möglich, insofern es als das Ganze und Ungetheilte unter verschiedenen Bestimmungen gesetzt wird. Diese Bestimmungen nenne ich Potenzen. Sie verändern schlechthin nichts am Wesen, dieses bleibt immer und nothwendig dasselbe, deßwegen heißen sie *ideelle* Bestimmungen. Z.B. das, was wir in der Geschichte oder der Kunst erkennen, ist wesentlich dasselbe mit dem, was auch in der Natur ist: jedem nämlich ist die ganze Absolutheit eingeboren, aber diese Absolutheit steht in der Natur, der Geschichte und der Kunst in verschiedenen Potenzen. Könnte man diese hinwegnehmen, um das *reine Wesen *gleichsam entblößt zu sehen, so wäre in allem wahrhaft Eins. Die *Philosophie *nun tritt in ihrer vollkommenen Erscheinung nur in der Totalität aller Potenzen hervor. Denn sie soll ein getreues Bild des Universums seyn - dieses aber = *dem Absoluten, dargestellt in der Totalität aller ideellen Bestimmungen. -* Gott und Universum sind eins oder nur verschiedene Ansichten Eines und desselben. Gott ist das Universum von der Seite der Identität betrachtet, er ist *Alles*, weil er das allein Reale, außer ihm also nichts ist, das *Universum *ist Gott von Seiten der Totalität aufgefaßt. In der absoluten Idee, die Princip der Philosophie ist, ist aber auch wieder Identität und Totalität eins. Die vollkommene Erscheinung der Philosophie, sage ich, tritt nur in der Totalität aller Potenzen hervor. Im Absoluten als solchen, und demnach auch im Princip der Philosophie, ist eben deßwegen, weil es *alle *Potenzen begreift,* keine *Potenz, und hinwiederum nur, inwiefern in ihm keine Potenz ist, sind in ihm alle enthalten. Ich nenne dieses Princip eben deßwegen, weil es keiner besonderen Potenz gleich ist, und doch alle begreift, den *absoluten Identitätspunkt *der Philosophie."}]}, {"page_pdf": 1615, "page_book": 368, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Dieser Indifferenzpunkt nun, eben weil er dieß ist, und weil er schlechthin eins, untrennbar, untheilbar ist, ist nothwendig wieder in jeder * besonderen *Einheit (so auch Potenz zu nennen), und auch dieß ist nicht möglich, ohne daß in jeder dieser *besonderen* Einheiten wieder alle Einheiten, also *alle Potenzen* wiederkehren. Es ist also in der Philosophie überhaupt nichts als Absolutes, oder wir kennen in der Philosophie nichts als Absolutes - immer nur das schlechthin Eine, und nur dieß schlechthin Eine in besonderen Formen. Philosophie geht - ich bitte *Sie*, dieß streng aufzufassen - überhaupt nicht auf das Besondere als solches, sondern unmittelbar immer nur auf das Absolute, und auf das Besondere nur, sofern es das ganze Absolute in sich aufnimmt und in sich darstellt. Hieraus ist nun offenbar, daß es keine *besonderen *Philosophien und ebensowenig besondere und einzelne philosophische Wissenschaften geben könne. Die Philosophie hat in allen Gegenständen nur Einen Gegenstand, und sie ist eben deßwegen selbst nur Eine. Innerhalb der allgemeinen Philosophie ist jede einzelne Potenz für sich absolut, und in dieser Absolutheit oder dieser Absolutheit unbeschadet doch wieder ein Glied des Ganzen. Wahrhaftes Glied des Ganzen ist jede nur, sofern sie der vollkommene Reflex des Ganzen ist, es ganz in sich aufnimmt. Dieß ist eben jene Verbindung des Besonderen und Allgemeinen, die wir in jedem organischen Wesen, so wie in jedem poetischen Werk, wiederfinden, in welchem z.B. verschiedene Gestalten jede ein dienendes Glied des Ganzen und doch bei der vollkommenen Ausbildung des Werks wieder in sich absolut ist. Wir können nun allerdings die einzelne Potenz herausheben aus dem Ganzen und für sich behandeln, aber nur, sofern wir wirklich das *Absolute *in ihr darstellen, ist diese Darstellung selbst *Philosophie.* Wir können alsdann diese Darstellung z.B. Philosophie der Natur, Philosophie der Geschichte, Philosophie der Kunst nennen. Hiermit ist nun bewiesen: 1) daß sich kein Gegenstand zum Gegenstand der Philosophie qualificire, als insofern er selbst im Absoluten durch eine ewige und nothwendige Idee gegründet und fähig ist das"}, {"type": "paragraph", "text": "ganze ungetheilte Wesen des Absoluten in sich aufzunehmen. Alle verschiedenen Gegenstände als verschiedene sind nur *Formen *ohne Wesenheit - Wesenheit hat nur Eines, und durch dieses Eine, was fähig ist, es als das Allgemeine in sich, *seine *Form, als Besonderes aufzunehmen. Es gibt also z.B. eine Philosophie der Natur, weil in das Besondere der Natur das Absolute gebildet, weil es demnach eine absolute und ewige Idee der Natur gibt. Ebenso eine Philosophie der Geschichte, eine Philosophie der Kunst1. Es ist hiermit 2) die Realität einer Philosophie der Kunst bewiesen, eben dadurch, daß ihre *Möglichkeit *bewiesen ist; es sind eben damit auch ihre Grenzen zugleich und ihre Verschiedenheit namentlich von der bloßen *Theorie *der Kunst gezeigt. Nämlich nur sofern die Wissenschaft der Natur oder Kunst in ihr das Absolute darstellt, ist diese Wissenschaft wirkliche Philosophie,* Philosophie *der Natur,* Philosophie * der Kunst. In jedem andern Fall, wo die besondere Potenz als *besondere *behandelt und für sie als *besondere *Gesetze aufgestellt werden, wo es also keineswegs um die Philosophie als Philosophie, die schlechthin allgemein ist, sondern um *besondere *Kenntniß des Gegenstandes, also einen endlichen Zweck, zu thun ist - in jedem solchen Fall kann die Wissenschaft nicht Philosophie, sondern nur * Theorie *eines besonderen Gegenstandes, wie Theorie der Natur, Theorie der Kunst, heißen. Diese Theorie könnte allerdings ihre Principien wieder von der Philosophie *entlehnen*, wie z.B. die Theorie der Natur von der Naturphilosophie, aber eben deßwegen, weil sie nur * entlehnt*, ist sie nicht Philosophie. Ich construire demnach in der Philosophie der Kunst zunächst nicht die Kunst *als *Kunst, als dieses *Besondere*, sondern ich *construire das Universum in der Gestalt der Kunst*, und Philosophie der *Kunst*"}]}, {"page_pdf": 1616, "page_book": 369, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "*ist Wissenschaft des All in der Form oder Potenz der Kunst.* Erst mit diesem Schritt erheben wir uns in Ansehung dieser Wissenschaft auf das Gebiet einer absoluten Wissenschaft der Kunst."}, {"type": "footnote", "text": "1 Man vergl. auch hierzu und dem unmittelbar Folgenden die angeführte Abhandlung, oben S. 107. D. H."}, {"type": "paragraph", "text": "Allein daß Philosophie der Kunst Darstellung des Universums in der Form der Kunst ist, gibt uns doch noch keine vollständige Idee dieser Wissenschaft, ehe wir die *Art *der Construktion, die einer Philosophie der Kunst nothwendig ist, genauer bestimmt haben. Objekt der Construktion und dadurch der Philosophie ist überhaupt nur, was fähig ist, als Besonderes das Unendliche in sich aufzunehmen. Die Kunst, um Objekt der Philosophie zu seyn, muß also überhaupt das Unendliche in sich als Besonderem entweder wirklich darstellen oder es wenigstens darstellen können. Aber nicht nur findet dieses in Ansehung der Kunst *statt*, sondern sie steht auch als Darstellung des Unendlichen auf der gleichen Höhe mit der Philosophie: - wie diese das Absolute im *Urbild*, so jene das Absolute im *Gegenbild *darstellend. Da die Kunst der Philosophie so genau entspricht, und selbst nur ihr vollkommenster objektiver Reflex ist, so muß sie auch durchaus alle Potenzen durchlaufen, welche die Philosophie im Idealen durchläuft, und dieses Eine reicht hin, uns über die nothwendige Methode unserer Wissenschaft außer Zweifel zu setzen. Die Philosophie stellt nicht die wirklichen Dinge, sondern ihre Urbilder dar, aber ebenso die Kunst, und dieselben Urbilder, von welchen nach den Beweisen der Philosophie diese (die wirklichen Dinge) nur unvollkommene Abdrücke sind, sind es, die in der Kunst selbst - als Urbilder - demnach in ihrer Vollkommenheit - objektiv werden, und in der reflektirten Welt selbst die Intellektualwelt darstellen. Um einige Beispiele zu geben, so ist die *Musik *nichts anderes als der urbildliche Rhythmus der Natur und des Universums selbst, der mittelst dieser Kunst in der abgebildeten Welt durchbricht. Die vollkommenen Formen, welche die *Plastik *hervorbringt, sind die objektiv dargestellten Urbilder der organischen Natur selbst. Das Homerische Epos ist die Identität selbst, wie sie der Geschichte im Absoluten zu Grunde liegt. Jedes Gemälde öffnet die Intellektualwelt. Dieß vorausgesetzt, werden wir in der Philosophie der Kunst in Ansehung der letzteren alle diejenigen Probleme zu lösen haben, die wir"}, {"type": "paragraph", "text": "in der allgemeinen Philosophie in Ansehung des Universums überhaupt auflösen. Wir werden 1) auch in der Philosophie der Kunst von keinem andern Princip als dem des Unendlichen ausgehen können; wir werden das Unendliche als das unbedingte Princip der Kunst darthun müssen. Wie für die Philosophie das Absolute das Urbild der Wahrheit - so für die Kunst das Urbild der *Schönheit. *Wir werden daher zeigen müssen, daß Wahrheit und Schönheit nur zwei verschiedene Betrachtungsweisen des Einen Absoluten sind. 2) Die zweite Frage, wie in Ansehung der Philosophie überhaupt, so auch in Ansehung der Philosophie der Kunst, wird seyn: wie jenes an sich schlechthin Eine und Einfache in eine Vielheit und Unterscheidbarkeit übergehe, wie also aus dem allgemeinen und absoluten Schönen besondere schöne Dinge hervorgehen können. Die Philosophie beantwortet diese Frage durch die Lehre von den Ideen oder Urbildern. Das Absolute ist schlechthin Eines, aber dieses Eine absolut angeschaut in den besonderen"}]}, {"page_pdf": 1617, "page_book": 371, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Formen, so daß das Absolute dadurch nicht aufgehoben wird, ist = Idee. Ebenso die Kunst. Auch die Kunst schaut das Urschöne nur in Ideen als besonderen Formen an, deren jede aber für sich göttlich und absolut ist, und anstatt daß die Philosophie die Ideen wie sie *an sich *sind, anschaut, schaut sie die Kunst *real *an. Die *Ideen *also, sofern sie als real angeschaut werden, sind der Stoff und gleichsam die allgemeine und absolute Materie der Kunst, aus welcher alle besonderen Kunstwerke als vollendete Gewächse erst hervorgehen. Diese *realen*, lebendigen und existirenden Ideen sind die Götter; die allgemeine Symbolik oder die allgemeine *Darstellung der Ideen *als realer ist demnach in der Mythologie gegeben, und die Auflösung der zweiten obigen Aufgabe besteht in der Construktion der Mythologie. In der That sind die Götter jeder Mythologie nichts anderes als die Ideen der Philosophie nur objektiv oder real angeschaut. Hiermit aber ist noch immer unbeantwortet, wie ein *wirkliches* und einzelnes Kunstwerk entstehe. Wie nun das Absolute - Nichtwirkliche - überall in der Identität, so ist das Wirkliche in der Nichtidentität"}, {"type": "paragraph", "text": "des Allgemeinen und Besonderen, in der Disjunktion, so daß entweder im Besonderen oder Allgemeinen. So entsteht auch hier ein Gegensatz, der Gegensatz von bildender und redender Kunst. Die bildende und die redende Kunst = der realen und idealen Reihe der Philosophie. Jener steht diejenige Einheit vor, in welcher das Unendliche ins Endliche aufgenommen wird - die Construktion dieser Reihe entspricht der *Naturphilosophie -*, dieser steht die andere Einheit vor, in welcher das Endliche ins Unendliche gebildet wird, die Construktion dieser Reihe entspricht dem *Idealismus *in dem allgemeinen System der Philosophie. Die erste Einheit werde ich die reale, die andere die ideale nennen, die, welche beide begreift, die Indifferenz. Fixiren wir nun jede dieser Einheiten für sich, so müssen, weil jede derselben für sich absolut ist, in jeder wieder dieselben Einheiten wiederkehren, in der realen also wiederum die reale, ideale, und die, worin beide eins sind. Ebenso in der idealen. Jeder dieser Formen, insofern sie entweder in der realen oder idealen Einheit begriffen sind, entspricht eine besondere Form der Kunst, der realen, sofern in der realen, entspricht die *Musik*, der idealen die *Malerei*, der welche innerhalb der realen wieder beide Einheiten in-eins-gebildet darstellt, die *Plastik.* Dasselbe ist der Fall in Ansehung der idealen Einheit, welche wieder die drei Formen der lyrischen, epischen und dramatischen Dichtkunst in sich begreift. Lyrik = Einbildung des Unendlichen ins Endliche = Besonderem. Epos = Darstellung (Subsumtion) des Endlichen im Unendlichen = Allgemeinem. Drama = Synthese des Allgemeinen und Besonderen. Nach diesen Grundformen ist also die gesammte Kunst sowohl in ihrer realen als idealen Erscheinung zu construiren. Indem wir die Kunst in jeder ihrer besonderen Formen bis aufs Concrete herab verfolgen, gelangen wir noch zu der Bestimmung der Kunst durch Bedingungen der Zeit. Wie die Kunst an sich ewig und nothwendig ist, so ist auch in ihrer Zeiterscheinung keine Zufälligkeit, sondern absolute Nothwendigkeit. Sie ist auch in dieser Beziehung noch"}, {"type": "paragraph", "text": "der Gegenstand eines möglichen Wissens, und die Elemente dieser Construktion sind durch die Gegensätze gegeben, welche die Kunst in ihrer Zeiterscheinung zeigt. Die Gegensätze aber, die in Ansehung der Kunst durch ihre Zeitabhängigkeit gesetzt sind, sind, wie die Zeit selbst, nothwendig unwesentliche und bloß formelle Gegensätze, ganz verschieden also von den *realen *im Wesen oder der Idee der Kunst selbst gegründeten. Dieser allgemeine und durch alle Zweige der Kunst hindurchgehende"}]}, {"page_pdf": 1618, "page_book": 373, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "formelle Gegensatz ist der der *antiken *und *modernen * Kunst. Es wäre ein wesentlicher Mangel der Construktion, wenn wir die Rücksicht darauf bei jeder einzelnen Form der Kunst vernachlässigen wollten. Da aber dieser Gegensatz als ein bloß formeller angesehen wird, so die Construktion eben in der Negation oder Aufhebung bestehend. Wir werden, indem wir diesen Gegensatz berücksichtigen, unmittelbar zugleich die *historische *Seite der Kunst darstellen, und können hoffen nur dadurch unserer Construktion im Ganzen die letzte Vollendung zu geben. Nach meiner ganzen Ansicht der Kunst ist sie selbst ein Ausfluß des Absoluten. Die Geschichte der Kunst wird uns am offenbarsten ihre unmittelbaren Beziehungen auf die Bestimmungen des Universums und dadurch auf jene absolute Identität zeigen, worin sie vorherbestimmt sind. Nur in der Geschichte der Kunst offenbart sich die wesentliche und innere Einheit aller Kunstwerke, daß alle Dichtungen eines und desselben Genius sind, der auch in den Gegensätzen der alten und neuen Kunst sich nur in zwei verschiedenen Gestalten zeigt."}, {"type": "paragraph", "text": "I. Allgemeiner Theil der Philosophie der Kunst."}, {"type": "heading", "text": "Erster Abschnitt. *Construktion der Kunst überhaupt und im Allgemeinen.*", "level": null}, {"type": "paragraph", "text": "Die Kunst construiren heißt, ihre Stellung im Universum bestimmen. Die Bestimmung dieser Stelle ist die einzige Erklärung, die es von ihr gibt. Wir müssen demnach auf die ersten Principien der Philosophie zurückgehen. Jedoch versteht es sich, daß wir diese Principien hier nicht in jeder möglichen Richtung verfolgen, sondern nur in der, welche uns durch den bestimmten Gegenstand vorgezeichnet ist; ferner, daß die meisten Sätze im Anfang als bloße Lehnsätze aus der Philosophie aufgestellt werden, die nicht sowohl bewiesen, als vielmehr nur erläutert werden. Dieß vorausgesetzt stelle ich die folgenden Sätze auf."}, {"type": "paragraph", "text": "§. 1. *Das Absolute oder Gott ist dasjenige, in Ansehung dessen das Seyn oder die Realität unmittelbar, d.h. kraft des bloßen Gesetzes der Identität aus der Idee folgt*, oder*: Gott ist die unmittelbare Affirmation von sich selbst. Erläuterung.* Folgte das Seyn nicht unmittelbar aus der Idee Gottes, d.h. wäre seine Idee nicht selbst die der *absoluten*, der *unendlichen *Realität, so wäre er durch irgend etwas bestimmt, was nicht seine Idee ist, d.h. er wäre bedingt durch etwas von seinem"}, {"type": "paragraph", "text": "Begriff Verschiedenes, demnach überhaupt abhängig, nicht absolut. - In Ansehung keines abhängigen oder bedingten Dings folgt aus dem Begriff das Seyn, z.B. der einzelne Mensch ist bestimmt durch etwas, das nicht seine Idee ist, woraus hinwiederum folgt, daß keinem Einzelnen *wahre *Realität, Realität an"}]}, {"page_pdf": 1619, "page_book": 375, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "sich zukomme. - Die besondere Form betreffend, in der wir die Idee Gottes noch außerdem ausgesprochen haben \"Gott die unmittelbare Affirmation von sich selbst\" erläutert sich durch Folgendes. Realseyn = Affirmirtseyn. Nun * ist *Gott nur kraft seiner Idee, d.h. er selbst ist die Affirmation von sich, und da er sich nicht auf endliche Art affirmiren kann (da er absolut ist), so ist er unendliche Affirmation von sich selbst."}, {"type": "paragraph", "text": "§. 2. *Gott als die unendliche Affirmation von sich selbst begreift sich selbst als unendlich Affirmirendes, als unendlich Affirmirtes, und als Indifferenz davon, er selbst aber ist keines von diesen insbesondere.* Gott * begreift *durch seine Idee sich selbst als unendlich Affirmirendes (denn er ist die Affirmation von sich selbst) *und * als unendlich Affirmirtes aus demselben Grunde. Da es ferner ein und dasselbe ist, das affirmirt und das affirmirend ist, so begreift er sich auch als Indifferenz. Aber er *ist *selbst keines davon insbesondere, denn er selbst ist nur die *unendliche Affirmation*, und zwar als unendlich, so daß er jene nur begreift; das Begreifende aber ist nicht *identisch *mit dem, was es begreift, z.B. Länge = Raum, Breite = Raum, Tiefe = Raum, aber der Raum selbst eben deshalb nichts davon insbesondere, sondern nur die absolute Identität, die unendliche Affirmation, das Wesen davon. - Auch so: Gott ist nichts überhaupt nur, sondern, was er ist, nur kraft unendlicher Affirmation - also Gott als affirmirend sich selbst, als affirmirt von sich selbst, und als Indifferenz, nur wieder durch die unendliche Affirmation von sich selbst. *Zusatz.* Gott als das Affirmirende von sich selbst kann auch beschrieben werden, als die unendliche alle Realität in sich begreifende Idealität, als das Affirmirte von sich selbst als die unendliche alle Idealität in sich begreifende Realität."}, {"type": "paragraph", "text": "§. 3. *Gott ist unmittelbar kraft seiner Idee absolutes All . *Denn unmittelbar aus der Idee Gottes folgt Unendliches, und es folgt nothwendig auf unendliche Weise, da Gott als unendliche Affirmation von sich selbst auch sich selbst wieder unendlich als Affirmirendes, unendlich als Affirmirtes, und unendlich als Indifferenz beider begreift. Nun ist unendliche Realität, die aus der Idee Gottes folgt, 1) schon an sich = All (denn nichts außer ihr), aber auch 2) positiv, denn alles, was kraft der Idee Gottes möglich ist, und dieß Unendliches, ist dadurch, daß diese sich selbst affirmirt, auch wirklich - alle Möglichkeiten sind Wirklichkeiten in Gott. Aber dasjenige, in dem alles Mögliche wirklich, ist = All. Also folgt unmittelbar aus der Idee Gottes absolutes All. - Aber ferner, es folgt kraft des bloßen Gesetzes der Identität, d.h. Gott selbst in der unendlichen Affirmation seiner selbst betrachtet ist = absolutes All."}, {"type": "paragraph", "text": "§. 4. *Gott ist als absolute Identität unmittelbar auch absolute Totalität, und umgekehrt. Erläuterung:* Gott ist eine Totalität, die keine Vielheit, sondern schlechthin einfach ist. Gott ist eine Einheit, die gleichfalls nicht im Gegensatz gegen Vielheit bestimmbar ist, d.h. er ist nicht einzig im numerischen Sinn, er ist auch nicht bloß der *Eine*, sondern er ist die absolute Einheit selbst, nicht alles, sondern die absolute Allheit selbst, und dieß beides unmittelbar als eins."}, {"type": "paragraph", "text": "§. 5. *Das Absolute ist schlechthin ewig.* In der Anschauung jeder *Idee*, z.B. der Idee des Cirkels, wird auch die Ewigkeit angeschaut. Dieß die positive Anschauung der Ewigkeit. Der negative Begriff der Ewigkeit ist: nicht nur unabhängig von der Zeit seyn, sondern auch ohne alle Beziehung auf Zeit. Wäre also das Absolute nicht schlechthin ewig, so hätte es ein Verhältniß zur Zeit. *Anmerkung*: Wenn die Ewigkeit des Absoluten durch ein Daseyn von * unendlicher Zeit* her bestimmt würde, so müßten wir z.B. sagen können, daß Gott jetzt eine längere Zeit existire, als er bei dem Ursprung der Welt existirt habe, welches also in Gott eine Zunahme der Existenz voraussetzte, was"}]}, {"page_pdf": 1620, "page_book": 376, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "unmöglich, da seine Existenz"}, {"type": "paragraph", "text": "sein Wesen ist, dieses aber weder vermehrt noch vermindert werden kann. Daß dem *Wesen *der Dinge keine Dauer zugeschrieben werden könne, ist eine zugestandene Sache. Wir können wohl z.B. vom einzelnen oder concreten Cirkel sagen, daß er diese oder jene Zeit gedauert habe, von dem Wesen oder der Idee des Cirkels wird niemand sagen, daß sie daure, oder daß sie z.B. jetzt eine längere Zeit existirt habe als bei dem Anfang der Welt. Nun ist aber das Absolute eben dasjenige, in Ansehung dessen der Gegensatz der Idee und des Concreten gar nicht stattfindet, in Ansehung dessen das, was in den Dingen das Concrete oder Besondere ist, selbst wieder das Wesen oder Allgemeine (nicht Negation) ist, so daß Gott kein anderes Seyn als das seiner Idee zukommen kann. Dasselbe noch von einer andern Seite. - Wir sagen, daß ein Ding *dauert*, weil seine Existenz seinem Wesen, sein Besonderes seinem Allgemeinen *unangemessen *ist. Die Dauer ist nichts anderes als ein fortgehendes Setzen seines Allgemeinen in *sein *Concretes. Vermöge der Beschränktheit des letzteren *ist *es nicht alles und in der That auf einmal, was es seinem Wesen oder seinem Allgemeinen nach seyn könnte. Dieß ist nun im Absoluten wieder undenkbar: da das Besondere in ihm dem Allgemeinen absolut gleich, so ist es alles, was es seyn *kann*, auch *wirklich *und auf einmal ohne Dazwischentreten der Zeit, es ist also ohne alle Zeit, an sich ewig. Die Idee des schlechthin Ewigen ist eine äußerst wichtige Idee sowohl für die Philosophie überhaupt als für unsere besondere Construktion. Denn was das Erste betrifft, so folgt unmittelbar (was *Sie *auch als *Folgesatz *bemerken können), daß das *wahre *Universum *ewig*, weil das Absolute zu ihm kein Zeitverhältniß haben kann. Für unsere besondere Construktion ist diese Idee wichtig, weil sie zeigt, daß die Zeit das * an sich *Ewige überall nicht afficirt, daß also das *an sich *Ewige selbst mitten in der Zeit kein Verhältniß zu der Zeit hat. Andere Ausdrücke desselben Satzes: a) Das Absolute kann daher auch nichts anderem als der Zeit nach *vorangegangen* gedacht werden (bloße Folge aus dem Vorhergehenden)."}, {"type": "paragraph", "text": "- *Positiv *ausgedrückt: Das Absolute geht allem nur der *Idee * nach voran, und alles *andere*, alles, was nicht das Absolute ist, *ist * nur, inwiefern in ihm das Seyn nicht der Idee gleich ist, d.h. inwiefern es selbst nur Privation, nicht wahres Seyn ist. Der concrete Cirkel als solcher gehört nur zur erscheinenden Welt. Der Cirkel an sich aber geht ihm doch nie der Zeit, sondern nur der Idee nach voran. Ebenso geht das Absolute allem andern auf keine Weise voran als der Idee nach. b) Im Absoluten selbst kann kein Vor oder Nach stattfinden, also keine Bestimmung der anderen weder vorangehen noch nachfolgen. Denn wäre dieß, so müßten wir im Absoluten eine Affektion oder Leiden, ein Bestimmtwerden setzen. Es ist aber ganz affektionslos, ohne Entgegensetzung in sich selbst."}, {"type": "paragraph", "text": "§. 6. *Das Absolute ist an sich weder bewußt noch bewußtlos, weder frei noch unfrei oder nothwendig.* Nicht bewußt, denn alles Bewußtseyn beruht auf der relativen Einheit des Denkens und Seyns, im Absoluten ist aber absolute Einheit. Nicht bewußtlos; denn es ist nur darum nicht bewußt, weil es absolutes Bewußtseyn ist. Nicht *frei; *denn Freiheit beruht auf der relativen Entgegensetzung und relativen Einheit der Möglichkeit und der Wirklichkeit, im Absoluten aber sind beide absolut eins. Nicht unfrei oder nothwendig; denn es ist affektionslos; es ist nichts in ihm oder außer ihm, das ihn bestimmen könnte, oder"}]}, {"page_pdf": 1621, "page_book": 378, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "wozu es sich neigen könnte."}, {"type": "paragraph", "text": "§. 7. * Im All ist begriffen, was in Gott begriffen ist.* Demnach begreift das All, ebenso wie Gott, sich selbst als unendlich Affirmirendes, als unendlich Affirmirtes und als Einheit beider, ohne selbst eine dieser Formen insbesondere zu seyn (eben weil begreifend), und nicht so, daß die Formen geschieden, sondern so, daß sie in die absolute Identität aufgelöst sind."}, {"type": "paragraph", "text": "§. 8. *Das unendliche Affirmirtseyn Gottes im All, oder die Einbildung seiner unendlichen Idealität in die Realität als solche, ist die ewige Natur.* Dieß ist eigentlich Lehnsatz. Doch will ich ihn hier beweisen. Die"}, {"type": "paragraph", "text": "Natur verhält sich zum Universum, absolut betrachtet, wie jedermann zugeben wird, als reales. Nun ist aber auch diejenige Einheit, welche durch Einbildung der unendlichen Idealität in die Realität gesetzt ist, das unendliche Affirmirt*seyn * Gottes im All, = reale Einheit. Denn herrschend ist das, was das andere aufnimmt. Also etc. *Anmerkung.* Unterschied zwischen der Natur,* sofern sie erscheint *(diese ist bloße Natura naturata - Natur in ihrer Besonderung und Trennung vom All - als bloßer Widerschein vom absoluten All), und der *Natur an sich*, wiefern sie in das *absolute All *aufgelöst und Gott in seinem unendlichen Affirmirtseyn ist."}, {"type": "paragraph", "text": "§. 9. *Die ewige Natur begreift in sich wieder alle Einheiten, die des Affirmirtseyns, des Affirmirenden und der Indifferenz beider.* Denn das Universum an sich = Gott. Wäre nun nicht in jedem die Einheit, die das Universum an sich begreift, wäre also nicht auch in der Natur wieder die ganze unendliche Affirmation, d.h. das ganze Wesen Gottes, so hätte sich Gott im All getheilt, welches unmöglich ist. Jeder der im All begriffenen Einheiten ist also wieder der Abdruck des ganzen All. *Zur Erklärung:* Auch in der erscheinenden Natur sind jene Folgen der unendlichen Affirmation ins Unendliche nachzuweisen; nur sind sie hier nicht ineinander, wie im absoluten All, sondern gesondert und außereinander. Z.B. die Einbildung des Idealen ins Reale oder die Form des Affirmirtseyns im All drückt sich durch Materie aus, die Idealität, welche alle Realität auflöst, das Affirmirende, ist = Licht, die Indifferenz = Organismus."}, {"type": "paragraph", "text": "§. 10. *Die Natur als solche erscheinend ist keine vollkommene Offenbarung Gottes. *Denn selbst der Organismus ist nur besondere Potenz."}, {"type": "paragraph", "text": "§. 11. *Vollkommene Offenbarung Gottes ist nur da, wo in der abgebildeten Welt selbst die einzelnen Formen sich in absolute Identität auflösen, welches in der Vernunft geschieht. Die Vernunft also ist im All selbst das vollkommene Gegenbild Gottes.*"}, {"type": "paragraph", "text": "*Erläuterung.* Das unendliche Affirmirtseyn Gottes spricht sich aus in der Natur, als der realen Welt, die dann selbst wieder im All für sich alle Einheit begreift. Ich bemerke hierüber noch Folgendes. - Wir bezeichnen die Einheiten oder die besonderen Folgen der Affirmation Gottes, sofern sie im realen oder idealen All wiederkehren, durch Potenzen. Die erste Potenz der Natur ist die Materie, sofern sie mit dem"}]}, {"page_pdf": 1622, "page_book": 380, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Uebergewicht des Affirmirtseyns oder unter der Form der Einbildung der Idealität in die Realität gesetzt ist. Die andere Potenz ist das Licht als die alle Realität in sich auflösende Idealität. Das *Wesen *der Natur als Natur kann aber einzig durch die *dritte Potenz *dargestellt werden, welche das gleicherweise Affirmirende des Realen oder der Materie und des Idealen oder des Lichts ist, und eben dadurch beide gleichsetzt. Das Wesen der Materie = Seyn, des Lichts = Thätigkeit. In der dritten Potenz müssen also Thätigkeit und Seyn *verbunden *und indifferent seyn. Die Materie, nicht an sich, sondern der körperlichen Erscheinung nach betrachtet, ist nicht Substanz, sondern bloß Accidens (Form), dem das Wesen oder das Allgemeine im Licht gegenübersteht. In der dritten Potenz integriren sich beide, es entsteht ein Indifferentes, in dem Wesen und Form ein und dasselbe, das Wesen von der Form, die Form von dem Wesen unzertrennlich ist. Ein solches ist Organismus, weil sein Wesen als Organismus von dem Bestehen der Form unzertrennlich ist, weil in ihm ferner das Seyn unmittelbar auch Thätigkeit, das Affirmirte dem Affirmirenden absolut gleich ist. Keine dieser Formen insbesondere, noch eben deßhalb auch die Natur in den Geschiedenheiten dieser Formen ist eine vollkommene Offenbarung des Göttlichen. Denn nicht der besonderen Folge seiner Affirmation ist Gott gleich, sondern der Allheit dieser Folgen, sofern sie reine Position, als Allheit zugleich absolute Identität ist. Nur also inwiefern die Natur sich selbst wieder in Totalität und absolute Einheit der Formen verklärte - nur insofern wäre sie ein Spiegel der göttlichen. Jenes aber ist nur in der Vernunft der Fall. Denn die Vernunft ist ebenso das Auflösende aller besonderen Formen, wie es das All oder Gott ist. Die Vernunft gehört aber eben deßwegen weder der realen noch der idealen Welt"}, {"type": "paragraph", "text": "ausschließlich an, und (was gleichfalls eine Folge davon ist) weder diese noch jene für sich kann höher als zur *Indifferenz*, nicht aber zur absoluten Identität gelangen. Wir verfahren nun in Ansehung des idealen All ebenso wie in Ansehung des realen, und stellen zuvörderst den Satz auf:"}, {"type": "paragraph", "text": "§. 12. *Gott als die unendliche, alle Realität in sich begreifende Idealität, oder Gott als unendlich Affirmirendes, ist, als solches, das Wesen des idealen All. *Dieß ist von selbst deutlich schon durch den Gegensatz."}, {"type": "paragraph", "text": "§. 13. *Das ideale All begreift dieselben Einheiten in sich, die auch das reale in sich begreift: die reale, ideale und * - nicht die absolute Identität beider (denn diese gehört weder ihr noch der realen besonders an) - sondern * die Indifferenz beider.* Auch hier bezeichnen wir diese Einheiten durch Potenzen; nur ist zu bemerken, daß, wie in der realen Welt die Potenzen Potenzen des idealen Faktors sind, so hier des realen vermöge des entgegengesetzten Verhältnisses beider. Die erste Potenz bezeichnet hier das Uebergewicht des Idealen; die Realität ist hier nur in der ersten Potenz des Affirmirtseyns gesetzt. In diesen Punkt fällt das *Wissen*, welches demnach mit dem größten Uebergewicht des idealen Faktors oder des Subjektiven gesetzt ist. Die dritte Potenz beruht auf einem Uebergewicht des Realen; der Faktor des Realen ist nämlich hier zur zweiten Potenz erhoben. In diesen Punkt fällt das *Handeln* als die objektive oder reale Seite, zu der sich das Wissen als die subjektive verhält. Das *Wesen* der idealen Welt ist aber ebenso wie das * Wesen *der realen die Indifferenz. Wissen und Handeln indifferenziiren sich also nothwendig in einem Dritten, welches als das Affirmirende beider die dritte Potenz ist. In *diesen *Punkt fällt nun die *Kunst*, und ich stelle demnach bestimmt den Satz auf:"}, {"type": "paragraph", "text": "§. 14. *Die Indifferenz des Idealen und Realen als Indifferenz stellt sich in der idealen Welt durch die Kunst dar. * Denn die Kunst ist an sich weder ein bloßes Handeln noch ein bloßes Wissen, sondern sie ist ein ganz von Wissenschaft durchdrungenes"}]}, {"page_pdf": 1623, "page_book": 381, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Handeln, oder umgekehrt ein ganz zum Handeln gewordenes Wissen, d.h. sie ist Indifferenz beider. Dieser Beweis genügt uns für den gegenwärtigen Zweck. Es versteht sich, daß wir auf diesen Satz zurückkommen. Hier ist unsere Absicht bloß den allgemeinen Typus des Universums zu entwerfen, um nachher die einzelne Potenz herauszuheben aus dem Ganzen und dem Verhältniß zu diesem gemäß zu behandeln. Wir fahren daher in unserer Darstellung fort."}, {"type": "paragraph", "text": "§. 15. *Der vollkommene Ausdruck * nicht des *Realen *noch des Idealen noch selbst der Indifferenz beider (denn diese, wie wir jetzt sehen, hat einen gedoppelten Ausdruck), sondern der *absoluten Identität als solcher oder des Göttlichen, sofern es das Auflösende aller Potenzen ist, ist die absolute Vernunftwissenschaft oder die Philosophie.* Die Philosophie ist also in der erscheinenden idealen Welt ebenso das Auflösende aller Besonderungen, wie es Gott in der urbildlichen Welt ist. (Göttliche Wissenschaft.) Weder die Vernunft noch die Philosophie gehören der realen oder idealen Welt als solcher an, obgleich dann wieder - in dieser Identität - sich Vernunft und Philosophie wie Reales und Ideales verhalten können. Da aber jede für sich absolute Identität ist, so macht dieses Verhältniß keinen wirklichen Unterschied beider. Philosophie ist nur die ihrer selbst bewußte oder sich selbst bewußt werdende Vernunft, die Vernunft dagegen ist der Stoff oder der objektive Typus aller Philosophie. Bestimmen wir das Verhältniß der Philosophie zu der Kunst vorläufig, so ist es dieses: die Philosophie ist die unmittelbare Darstellung des Göttlichen, wie die Kunst unmittelbar nur Darstellung der Indifferenz als solcher (dieß, daß nur Indifferenz, macht das Gegenbildliche aus. Absolute Identität = Urbild). Da indeß der Grad der Perfektion oder Realität eines Dings wächst in dem Verhältniß, als es sich der absoluten Idee, der Fülle der unendlichen Affirmation, annähert, je mehr es also andere Potenzen in sich begreift, so ist von selbst klar, daß die Kunst auch wieder das unmittelbarste Verhältniß zur Philosophie"}, {"type": "paragraph", "text": "hat, und von ihr nur durch die Bestimmung der Besonderheit oder der Gegenbildlichkeit noch unterschieden, denn übrigens ist sie die höchste Potenz der idealen Welt. Nun weiter."}, {"type": "paragraph", "text": "§. 16. *Den drei Potenzen der realen und idealen Welt entsprechen die drei Ideen (die Idee* als Göttliches gehört gleichfalls weder der realen noch der idealen Welt insbesondere an) - *die Wahrheit, die Güte und die Schönheit*: der ersten Potenz der idealen und realen Welt entspricht die Wahrheit, der zweiten Potenz die Güte, der dritten die Schönheit - im Organismus und in der Kunst. Ueber das Verhältniß, das wir diesen drei Ideen zueinander geben, ferner über die Art, wie sich beide in der realen und idealen Welt differenziiren, uns zu erklären, ist hier nicht der Ort, dieß geschieht in der allgemeinen Philosophie. Nur über das Verhältniß, das wir der *Schönheit *geben, müssen wir uns erklären. Die Schönheit, kann man sagen, ist überall gesetzt, wo Licht und Materie, Ideales und Reales sich berühren. Die Schönheit ist weder bloß das Allgemeine oder Ideale (dieß = Wahrheit) noch das bloß Reale (dieß im Handeln), also sie ist nur die vollkommene Durchdringung oder Ineinsbildung beider. Schönheit ist da gesetzt, wo das Besondere (Reale) seinem Begriff so angemessen ist, daß dieser selbst, als Unendliches, eintritt in das Endliche und in concreto angeschaut wird. Hierdurch *wird *das *Reale*, in dem er (der Begriff) erscheint, dem Urbild, der Idee wahrhaft ähnlich und gleich, wo eben dieses"}]}, {"page_pdf": 1624, "page_book": 383, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Allgemeine und Besondere in absoluter Identität ist. Das Rationale wird als Rationales zugleich ein Erscheinendes, Sinnliches. *Anmerkung*: 1) Wie Gott *über *den Ideen der Wahrheit, der Güte und der Schönheit als ihr Gemeinsames schwebt, so die Philosophie. Die Philosophie behandelt weder allein die Wahrheit, noch bloß die Sittlichkeit, noch bloß die Schönheit, sondern das Gemeinsame aller, und leitet sie aus Einem Urquell her. Wollte man die Frage aufwerfen, woher es komme, daß Philosophie, obgleich auch über der Wahrheit ebenso wie über der Güte und über der Schönheit schwebend,"}, {"type": "paragraph", "text": "dennoch den Charakter der Wissenschaft trage, und ihr Höchstes die Wahrheit sey, so ist zu bemerken, daß die Bestimmung der Philosophie als Wissenschaft bloß ihre formelle Bestimmung ist. Sie ist Wissenschaft, aber von der Art, daß *in* ihr Wahrheit, Güte und Schönheit, also Wissenschaft, Tugend und Kunst selbst sich durchdringen; insofern ist sie also auch *nicht Wissenschaft*, sondern ein Gemeinsames der Wissenschaft, der Tugend und Kunst. Dieß ihr großer Unterschied von allen andern Wissenschaften. Mathematik z.B. macht eben keine besonderen sittlichen Forderungen. Philosophie fordert Charakter, und zwar von bestimmter sittlicher Höhe und Energie. Ebenso ist ohne alle Kunst und Erkenntniß der Schönheit Philosophie undenkbar. 2) Der Wahrheit entspricht die Nothwendigkeit, der Güte die Freiheit. Unsere Erklärung der Schönheit, sie sey die Ineinsbildung des Realen und Idealen, sofern sie im Gegenbild dargestellt ist, schließt also auch die in sich: Schönheit ist Indifferenz der Freiheit und der Nothwendigkeit, in einem Realen angeschaut. Wir nennen z.B. schön eine Gestalt, in deren Entwurf die Natur mit der größten Freiheit und der erhabensten Besonnenheit, jedoch immer in den Formen, den Grenzen der strengsten Nothwendigkeit und Gesetzmäßigkeit gespielt zu haben scheint. Schön ist ein Gedicht, in welchem die höchste Freiheit sich selbst wieder in der Nothwendigkeit faßt. Kunst demnach eine absolute Synthese oder Wechseldurchdringung der Freiheit und der Nothwendigkeit. Nun zu den übrigen Verhältnissen des Kunstwerks."}, {"type": "paragraph", "text": "§. 17. *In der idealen Welt verhält sich die Philosophie ebenso zur Kunst, wie in der realen die Vernunft zum Organismus. * - Denn wie die Vernunft unmittelbar nur durch den Organismus objektiv wird, und die ewigen Vernunftideen als Seelen organischer Leiber objektiv werden in der Natur, so wird die Philosophie unmittelbar durch die Kunst, und so werden auch die Ideen der Philosophie durch die Kunst als Seelen wirklicher Dinge objektiv. Eben daher verhält sich dann auch Kunst in der idealen Welt, wie sich Organismus in der realen verhält."}, {"type": "paragraph", "text": "Hierüber noch folgenden Satz."}, {"type": "paragraph", "text": "§. 18. *Das organische Werk der Natur stellt dieselbe Indifferenz noch ungetrennt dar, welche das Kunstwerk nach der Trennung, aber wieder als Indifferenz darstellt.* Das organische Produkt begreift in sich die beiden Einheiten, der Materie oder der Einbildung der Einheit in die Vielheit, und die entgegengesetzte des Lichts oder der Auflösung der Realität in die Idealität; und es begreift beide als eins. Aber das Allgemeine oder die unendliche Idealität, welche hier dem Besonderen verknüpft ist, ist selbst noch das dem Endlichen, dem Besondern Untergeordnete (Allgemeines = Licht). Daher, weil das Unendliche hier selbst noch der allgemeinen Bestimmung der"}]}, {"page_pdf": 1625, "page_book": 385, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Endlichkeit unterliegt, nicht *als *Unendliches erscheint, auch Nothwendigkeit und Freiheit (das als Unendliches erscheinende Unendliche) gleichsam noch unter einer gemeinschaftlichen Hülle, noch unentfaltet ruhen, wie in einer Knospe, die in ihrem Brechen eine neue Welt, die der Freiheit, aufschließen wird. Da nun erst in der idealen Welt der Gegensatz des Allgemeinen und Besonderen, Idealen und Realen, sich als Gegensatz der Nothwendigkeit und der Freiheit ausspricht, stellt das organische Produkt denselben Gegensatz noch unaufgehoben dar (weil noch unentfaltet), den das Kunstwerk aufgehoben darstellt, (in beiden dieselbe Identität)."}, {"type": "paragraph", "text": "§. 19. *Nothwendigkeit und Freiheit verhalten sich wie Bewußtloses und Bewußtes. Kunst beruht daher auf der Identität der bewußten und der bewußtlosen Thätigkeit.* Die Vollkommenheit des Kunstwerks als solchen steigt in dem Verhältniß, in welchem es diese Identität in sich ausgedrückt enthält, oder in welchem Absicht und Nothwendigkeit sich in ihm durchdrungen haben. Noch einige andere allgemeine Folgerungen:"}, {"type": "paragraph", "text": "§. 20. *Schönheit und Wahrheit sind an sich oder der Idee nach eins. -* Denn die Wahrheit der *Idee* nach ist ebenso wie die Schönheit Identität des Subjektiven und Objektiven, nur jene subjektiv oder vorbildlich angeschaut, wie die Schönheit gegenbildlich oder objektiv."}, {"type": "paragraph", "text": "*Anmerkung*. Die Wahrheit, die nicht Schönheit ist, ist auch nicht absolute Wahrheit, und umgekehrt. - (Der sehr gemeine Gegensatz von Wahrheit und Schönheit in der Kunst beruht darauf, daß unter Wahrheit die trügerische, nur das Endliche erreichende Wahrheit verstanden wird. Aus der Nachahmung dieser Wahrheit entstehen jene Kunstwerke, an welchen wir nur die Künstlichkeit bewundern, mit der das Natürliche an ihr erreicht ist, ohne es mit dem Göttlichen zu verbinden. * Diese *Art der Wahrheit aber ist noch nicht Schönheit in der Kunst, und nur absolute Schönheit in der Kunst ist auch die rechte und eigentliche Wahrheit. Aus dem gleichen Grund ist die Güte, die nicht Schönheit ist, auch nicht absolute Güte, und umgekehrt. Denn auch die Güte in ihrer Absolutheit wird zur *Schönheit *- in jedem Gemüth z.B., dessen Sittlichkeit nicht mehr auf dem Kampfe der Freiheit mit der Nothwendigkeit beruht, sondern die absolute Harmonie und Versöhnung ausdrückt. *Zusatz*. Wahrheit und Schönheit, so wie Güte und Schönheit, verhalten sich daher niemals als Zweck und Mittel; sie sind vielmehr eins, und nur ein harmonisches Gemüth - Harmonie aber = wahre Sittlichkeit - ist auch für Poesie und für Kunst wahrhaft empfänglich. Poesie und Kunst lassen sich nie eigentlich lehren."}, {"type": "paragraph", "text": "§. 21. *Das Universum ist in Gott als absolutes Kunstwerk und in ewiger Schönheit gebildet.* Unter Universum ist nicht das reale oder ideale All, sondern die absolute Identität beider verstanden. Ist nun die Indifferenz des Realen und Idealen im realen oder idealen All Schönheit, und zwar gegenbildliche Schönheit, so ist die absolute Identität des realen und idealen All nothwendig die urbildliche, d.h. absolute Schönheit selbst, und insofern verhält sich auch das Universum, wie es in Gott ist, als absolutes Kunstwerk, in welchem unendliche Absicht mit unendlicher Nothwendigkeit sich durchdringt. *Anmerkung*. Es folgt zugleich von selbst, daß ebenso vom Standpunkt der Totalität betrachtet, oder betrachtet, wie sie an sich"}]}, {"page_pdf": 1626, "page_book": 387, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "sind, alle Dinge in absoluter Schönheit gebildet, die Urbilder aller Dinge, wie sie absolut wahr, auch absolut schön sind, das Verkehrte, Häßliche daher, ebenso wie der Irrthum oder das Falsche, in einer bloßen Privation besteht und nur zur zeitlichen Betrachtung der Dinge gehört."}, {"type": "paragraph", "text": "§. 22. *Wie Gott als Urbild im Gegenbild zur Schönheit wird, so werden die Ideen der Vernunft im Gegenbild angeschaut, zur Schönheit;* und das Verhältniß der Vernunft zu der Kunst ist daher dasselbe wie das Verhältniß Gottes zu den Ideen. Durch die Kunst wird die göttliche Schöpfung objektiv dargestellt, denn diese beruht auf derselben Einbildung der unendlichen Idealität ins Reale, auf welcher auch jene beruht. Das treffliche deutsche Wort Einbildungskraft bedeutet eigentlich die Kraft der *Ineinsbildung*, auf welcher in der That alle Schöpfung beruht. Sie ist die Kraft, wodurch ein Ideales zugleich auch ein Reales, die Seele Leib ist, die Kraft der Individuation, welche die eigentlich schöpferische ist."}, {"type": "paragraph", "text": "§. 23. *Die unmittelbare Ursache aller Kunst ist Gott*. - Denn Gott ist durch seine absolute Identität der Quell aller Ineinsbildung des Realen und Idealen, worauf alle Kunst beruht. Oder: Gott ist der Quell der Ideen. Nur in Gott sind ursprünglich die Ideen. Nun ist aber die Kunst Darstellung der Urbilder, also Gott selbst die unmittelbare Ursache, die letzte Möglichkeit aller Kunst, er selbst der Quell aller Schönheit."}, {"type": "paragraph", "text": "§. 24. *Die wahre Construktion der Kunst ist Darstellung ihrer Formen als Formen der Dinge, wie sie an sich, oder wie sie im Absoluten sind*. - Denn nach Satz 21 ist das Universum in Gott als ewige Schönheit und als absolutes Kunstwerk gebildet; nicht minder sind alle Dinge, wie sie an sich oder in Gott sind, ebenso absolut schön, als sie absolut wahr sind. Demnach sind auch die Formen der Kunst, da sie die Formen schöner Dinge sind, Formen der Dinge, wie sie in Gott, oder wie sie an sich sind, und da alle Construktion Darstellung der Dinge im Absoluten ist, so"}, {"type": "paragraph", "text": "ist die Construktion der Kunst insbesondere * Darstellung ihrer Formen *als Formen der Dinge, wie sie im Absoluten sind, und demnach auch des Universums selbst als absoluten Kunstwerks, wie es in ewiger Schönheit in Gott gebildet ist. *Anmerkung.* Mit diesem Satz ist die Construktion der allgemeinen Idee der Kunst vollendet. Die Kunst ist nämlich dargethan als *reale *Darstellung der Formen der Dinge, wie sie an sich sind - der Formen der Urbilder also. - Es ist uns damit zugleich auch die Richtung der folgenden Construktion der Kunst sowohl ihrem Stoff als auch ihrer Form nach vorgezeichnet. Ist nämlich die Kunst Darstellung der Formen der Dinge, wie sie an sich sind, so ist der allgemeine *Stoff *der Kunst in den Urbildern selbst, und unser nächster Gegenstand ist daher Construktion des allgemeinen Stoffes der Kunst oder ihrer ewigen Urbilder, welche Construktion den zweiten Abschnitt der Philosophie der Kunst ausmacht."}, {"type": "heading", "text": "Zweiter Abschnitt. *Construktion des Stoffs der Kunst*.", "level": null}]}, {"page_pdf": 1627, "page_book": 389, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "In §. 24 ist bewiesen worden: die Formen der Kunst müssen die Formen der Dinge seyn, wie sie im Absoluten oder *an sich *sind. Demnach wird vorausgesetzt, diese *besonderen Formen*, wodurch eben das Schöne in einzelnen realen und wirklichen Dingen dargestellt wird, * seyen * besondere Formen, die im Absoluten selbst sind. Die Frage ist, wie dieß möglich sey. (Es ist dieß ganz dasselbe Problem, welches in der allgemeinen Philosophie durch Uebergehen des Unendlichen ins Endliche, der Einheit in die Vielheit ausgedrückt wird)."}, {"type": "paragraph", "text": "§. 25. * Die besonderen Formen sind als solche ohne Wesenheit, bloße Formen, die im Absoluten nicht anders seyn können, als inwiefern sie als besondere wieder das ganze Wesen des Absoluten in sich aufnehmen.* Dieß ist von selbst klar, da das Wesen des Absoluten untheilbar ist. - Hierdurch allein sind sie in Ansehung des Absoluten, d.h. absolut möglich, eben darum auch absolut wirklich, da im Absoluten keine Differenz der Wirklichkeit und der Möglichkeit. *Zusatz.* Dasselbe ist auch auf folgende Art einzusehen. Das Universum (worunter hier immer das Universum an sich, das ewige, unerzeugte verstanden wird) - das Universum ist, wie das Absolute, schlechthin Eines, untheilbar, denn es ist das Absolute selbst (§. 3), es können also im *wahren* Universum keine besonderen Dinge seyn,"}, {"type": "paragraph", "text": "als inwiefern sie das ganze ungetheilte Universum in sich aufnehmen, also selbst Universa sind. Wenn hieraus geschlossen würde, daß es demnach so viele Universa seyen, als Ideen besonderer Dinge sind, so ist dieß eben der Schluß, den wir beabsichtigen. Es gibt entweder überhaupt keine besonderen Dinge, oder jedes derselben ist für sich ein Universum. In Gott selbst, weil er die Einheit aller *Formen* ist, liegt eben deßwegen das Universum in keiner besonderen Form, weil es in allen, so wie es in allen liegt, weil in keiner besonderen. Wenn die *besondere *Form an sich reell seyn soll, so kann sie es nicht als besondere, sondern nur als Form des Universums seyn. Z.B. die besondere Form *Mensch *ist im Absoluten nicht als besondere, sondern das eine und ungetheilte Universum in der Form des Menschen. Eben deßwegen ist nichts von dem, was wir einzelne Dinge nennen, an sich reell. Sie sind eben *einzelne* dadurch, daß sie das *absolute Ganze *nicht in sich, ihrer besonderen Form, aufnehmen, sich von ihm getrennt haben, und umgekehrt, inwiefern sie es in sich haben, sind sie nicht mehr einzelne."}, {"type": "paragraph", "text": "§. 26. *Im Absoluten sind alle besonderen Dinge nur dadurch wahrhaft geschieden und wahrhaft eins, daß jedes für sich das Universum, jedes das absolute Ganze ist. * - Geschieden: denn kein einzelnes Ding als solches ist wahrhaft geschieden, absolut geschieden ist nur das Universum, weil keinem andern Dinge weder gleich noch ungleich, weil nichts außer ihm ist, dem es entgegengesetzt oder verglichen werden könnte. Wahrhaft *eins*, weil in jedem dasselbe ist. Eben deßwegen ist hier auch alle Zahl oder Bestimmung durch Zahl aufgehoben. Das *besondere* Ding in der Absolutheit wird nicht durch Zahl bestimmt; denn wird auf das Besondere an ihm reflektirt, so ist es selbst das absolute Ganze und hat nichts außer sich; auf das Allgemeine, so ist es in der absoluten Einheit mit allen andern Dingen. Es begreift also nur selbst Einheit und Vielheit unter sich, ist aber nicht durch diese Begriffe bestimmbar. *Anmerkung. *Diese Begriffe sind von Wichtigkeit a) wegen der gedoppelten Ansicht, die vom Universum überhaupt nothwendig ist,"}]}, {"page_pdf": 1628, "page_book": 390, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "á) der Ansicht des Universums als *Chaos*, welches, im Vorbeigehen gesagt, die Grundanschauung des Erhabenen ist, sofern nämlich in ihm in absoluter Identität alles als eins liegt, â) als der höchsten Schönheit und Form, weil es eben durch die Absolutheit der *Form*, oder dadurch, daß in jedes Besondere und jede *Form *wieder alle Formen, und demnach die absolute Form gebildet ist, Chaos ist. Wir werden von diesen Begriffen in der Folge sehr bestimmten Gebrauch machen. b) Vorzüglich ist der Begriff der absoluten Geschiedenheit des Besonderen für die Kunst wichtig, da gerade auf dieser Absonderung der Formen ihre größte Wirkung beruht. Aber diese Absonderung ist eben nur dadurch, daß jedes für sich absolut ist."}, {"type": "paragraph", "text": "§. 27. *Die besonderen Dinge, sofern sie in ihrer Besonderheit absolut, sofern sie also als Besondere zugleich Universa sind, heißen Ideen.* Dieser Satz ist bloße *Erklärung, *also keines Beweises bedürftig, obwohl es sich zeigen ließe, daß schon der erste Urheber der Lehre von den Ideen, wenn er auch diese nicht gerade so erklärt, doch dasselbe darunter verstanden. *Erläuterung.* Jede Idee ist = Universum in der Gestalt des Besonderen. Aber eben deßwegen ist sie nicht als dieses Besondere real. Das Reale ist immer nur das Universum. Jede Idee hat zwei Einheiten, die eine, wodurch sie * in sich selbst *und *absolut *ist, die also, wodurch das Absolute in ihr Besonderes gebildet ist, und die, wodurch sie als Besonderes in das Absolute als ihr Centrum aufgenommen wird. Diese gedoppelte Einheit jeder Idee ist eigentlich das Geheimniß, wodurch das Besondere im Absoluten, und gleichwohl wieder als Besonderes begriffen werden kann."}, {"type": "paragraph", "text": "§. 28. *Dieselben Ineinsbildungen des Allgemeinen und Besonderen, die an sich selbst betrachtet Ideen, d.h. Bilder des Göttlichen sind, sind real betrachtet Götter . *Denn das Wesen, das An-sich von ihnen = * Gott.* Ideen sind sie nur, inwiefern sie Gott in besonderer Form. Jede Idee ist also = Gott, aber ein besonderer Gott."}, {"type": "paragraph", "text": "*Anmerkung.* Dieser Satz bedarf keiner Erläuterung, um so mehr, da die folgenden Sätze dienen werden, ihn noch weiter ins Licht zu stellen. - Die Idee der Götter ist nothwendig für die Kunst. Die wissenschaftliche Construktion derselben führt uns eben dahin zurück, wohin der Instinkt die Poesie in ihrem ersten Beginn schon geführt hat. Was für die Philosophie Ideen sind, sind für die Kunst Götter, und umgekehrt."}, {"type": "paragraph", "text": "§. 29. *Die absolute Realität der Götter folgt unmittelbar aus ihrer absoluten Idealität. * - Denn sie sind absolut, im Absoluten aber ist Idealität und Realität eins, absolute Möglichkeit = absolute Wirklichkeit. Die höchste Identität ist unmittelbar die höchste Objektivität. Wer sich noch nicht zu dem Punkte erhoben hat, daß ihm das absolut Ideale unmittelbar und eben darum auch das absolute Reale ist, ist weder des philosophischen noch des poetischen Sinns fähig. Die Frage nach einer Wirklichkeit, wie sie im gemeinen Bewußtseyn gemacht wird, hat in Ansehung dessen, was absolut ist, gar keine Bedeutung, im Poetischen so wenig als im Philosophischen. * Diese* Wirklichkeit * ist* keine wahre Wirklichkeit, vielmehr im wahren Sinn Nichtwirklichkeit. Alle Gestalten der Kunst, also vornämlich die Götter sind *wirklich*, weil sie *möglich *sind. Wer noch fragen kann, wie so hoch gebildete Geister als die Griechen an die Wirklichkeit der Götter haben glauben können, wie Sokrates Opfer anbefohlen, der Sokratiker Xenophon als Heerführer bei dem berühmten"}]}, {"page_pdf": 1629, "page_book": 392, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Rückzug selbst habe opfern können u.s.w., - wer solche Fragen macht, beweist nur, daß er selbst nicht auf dem Punkt der Bildung angekommen ist, auf dem eben das * Ideale *das Wirkliche und viel wirklicher als das sogenannte Wirkliche selbst ist. In dem Sinn, wie etwa ein gemeiner Verstand an die Wirklichkeit der sinnlichen Dinge glaubt, haben *jene *Menschen die Götter überhaupt nicht genommen und weder für wirklich noch für nicht wirklich gehalten. In dem höheren Sinne waren sie den Griechen reeller als jedes andere Reelle."}, {"type": "paragraph", "text": "§. 30. *Reine Begrenzung von der einen und ungetheilte*"}, {"type": "paragraph", "text": "*Absolutheit von der andern Seite ist das bestimmende Gesetz aller Göttergestalten. * - Denn sie sind die real angeschauten Ideen. Die besondern Dinge aber sind in den Ideen nicht, ohne eben dadurch zugleich wahrhaft oder absolut geschieden und wahrhaft eins, nämlich gleich absolut zu seyn, nach §. 26. Also ist auch strenge Absonderung oder Begrenzung von der einen und gleiche Absolutheit von der andern Seite das bestimmende Gesetz der Götterwelt. *Anmerkung. * Wir haben vorzüglich auf dieses Verhältniß zu achten, wenn wir die große Bedeutung der Göttergestalten im Einzelnen und im Ganzen fassen wollen. Nur dadurch *erstens*, daß sie streng begrenzt, daß also sich wechselseitig einschränkende Eigenschaften in einer und derselben Gottheit sich ausschließen und absolut getrennt sind, und daß gleichwohl innerhalb dieser Begrenzung jede Form die ganze Göttlichkeit in sich empfängt, liegt eigentlich das Geheimniß ihres Reizes und ihrer Fähigkeit für Kunstdarstellungen. Dadurch erhält die Kunst gesonderte, beschlossene Gestalten, und in jeder doch die Totalität, die ganze Göttlichkeit. Ich sehe mich hier in der Nothwendigkeit, um durch Beispiele verständlich zu werden, diese aus der griechischen Götterwelt zu entlehnen, obgleich wir die vollständige Construktion derselben erst durch die ganze Folge erhalten können. Indeß wenn *Sie * sehen, daß alle Züge der griechischen Götter auf unsere Deduktion des Gesetzes aller Göttergestalten passen, so muß zum voraus auch zugegeben werden, daß die griechische Mythologie das höchste Urbild der poetischen Welt ist. Also um einige Beispiele für den Satz zu geben, daß reine Begrenzung einerseits und ungetheilte Absolutheit andererseits das Wesen der Göttergestalten; so ist die Minerva das Urbild der Weisheit und Stärke in Vereinung, * aber *die weibliche Zärtlichkeit ist ihr genommen; beide Eigenschaften vereinigt würden diese Gestalt zur Gleichgültigkeit, und demnach mehr oder weniger zur Nullität reduciren. Juno ist Macht ohne Weisheit und sanften Liebreiz, den sie von der Venus mit ihrem Gürtel borgt. Wäre dagegen dieser zugleich die kalte Weisheit der Minerva verliehen, so wären ohne Zweifel ihre Wirkungen nicht so verderblich, als es die des trojanischen Kriegs sind, den sie veranlaßt,"}, {"type": "paragraph", "text": "um die Lust ihres Lieblings zu befriedigen. Aber dann wäre sie auch nicht mehr die Göttin der Liebe, und darum kein Gegenstand der Phantasie mehr, für die das Allgemeine und Absolute im Besonderen - in der Begrenzung - das Höchste ist. Man kann also, von dieser Seite die Sache angesehen, mit *Moriz *sagen, daß es eben die gleichsam *fehlenden * Züge sind in den Erscheinungen der Göttergestalten, was ihnen den höchsten Reiz gibt und sie wieder untereinander verflicht. Das Geheimniß alles Lebens ist Synthese des Absoluten mit der Begrenzung. Es gibt ein gewisses Höchstes in der Weltanschauung, das wir zur vollkommenen Befriedigung fordern, es ist: *höchstes *Leben, freiestes, eigenstes Daseyn und Wirken ohne Beengung oder Begrenzung des Absoluten. Das Absolute an und für sich bietet keine Mannichfaltigkeit dar, es ist"}]}, {"page_pdf": 1630, "page_book": 394, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "insofern für den Verstand eine absolute, bodenlose Leere. Nur im Besonderen ist Leben. Aber Leben und Mannichfaltigkeit, oder überhaupt *Besonderes * ohne Beschränkung des schlechthin Einen, ist ursprünglich und an sich nur durch das Princip der göttlichen Imagination, oder, in der abgeleiteten Welt, nur durch die Phantasie möglich, die das Absolute mit der Begrenzung zusammenbringt und in das Besondere die ganze Göttlichkeit des Allgemeinen bildet. Dadurch wird das Universum bevölkert, nach diesem Gesetz strömt vom Absoluten, als dem schlechthin Einen, das Leben aus in die Welt; nach demselben Gesetz bildet sich wieder in dem Reflex der menschlichen Einbildungskraft das Universum zu einer Welt der Phantasie aus, deren durchgängiges Gesetz Absolutheit in der Begrenzung ist. Wir verlangen für die Vernunft sowohl als für die Einbildungskraft, daß nichts im Universum gedrückt, rein beschränkt und untergeordnet sey. Wir fordern für jedes Ding ein besonderes und freies Leben. Nur der Verstand ordnet unter, in der Vernunft und in der Einbildungskraft ist alles frei und bewegt sich in dem gleichen Aether, ohne sich zu drängen und zu reiben. Denn jedes für sich ist wieder das Ganze. Der Anblick der reinen Beschränktheit ist von dem untergeordneten Standpunkt aus bald lästig, bald schmerzlich, bald sogar"}, {"type": "paragraph", "text": "beleidigend, auf jeden Fall widerlich. Für die Vernunft und Phantasie wird auch die Begrenzung entweder nur Form des Absoluten oder, als *Begrenzung *aufgefaßt, ein unerschöpflicher Quell des Scherzes und des Spiels, denn mit der Begrenzung zu scherzen ist erlaubt, da sie dem * Wesen *nichts entzieht, an sich bloße Nichtigkeit ist. So spielt in der griechischen Götterwelt der kühnste Scherz wieder mit den Phantasiebildern ihrer Götter, wie wenn Venus von Diomedes verwundet ist, und Minerva spottet: \"Gewiß hat Venus eine geschmückte Griechin überreden wollen, zu den Trojanern mitzugehen, und mit der goldenen Spange der Griechin die Hand sich geritzt\", und Zeus lächelnd zu ihr mit sanften Worten spricht:"}, {"type": "footnote", "text": "Nicht dir wurden verlieh'n, mein Töchterchen, Werke des Krieges; Ordne du lieber hinfort anmuthige Werke der Hochzeit, Jene besorgt schon Ares, der stürmende, und Athenäa1."}, {"type": "footnote", "text": "1 Ilias V, 424 ff."}, {"type": "paragraph", "text": "Als eine Folge aus dem aufgestellten Princip kann ferner angesehen werden, daß die vollkommenen Götterbildungen erst erscheinen können, nachdem das rein Formlose, Dunkle, Ungeheure verdrungen ist. In diese Region des Dunkeln und Formlosen gehört noch alles, was unmittelbar an die Ewigkeit, den ersten Grund des Daseyns erinnert. Es ist schon öfters bemerkt worden, daß erst die Ideen das Absolute aufschließen; nur in ihnen ist eine positive, zugleich begrenzte und unbegrenzte Anschauung des Absoluten. Als der gemeinschaftliche Keim der Götter und der Menschen ist das absolute Chaos Nacht, Finsterniß. Auch die ersten Gestalten, welche die Phantasie aus ihm geboren werden läßt, sind noch formlos. Es muß eine Welt unförmlicher und ungeheurer Gestalten versinken, ehe das milde Reich der seligen und bleibenden Götter eintreten kann. Auch in dieser Beziehung bleiben die griechischen Dichtungen dem Gesetz aller Phantasie getreu. Die ersten Geburten aus den Umarmungen des Uranus und der Gäa sind noch Ungeheuer, hundertarmige Riesen, mächtige Cyclopen und die wilden Titanen, Geburten, vor denen sich"}]}, {"page_pdf": 1631, "page_book": 395, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der Erzeuger selbst entsetzt und sie wieder in den Tartaros verbirgt. Das Chaos muß seine eignen Geburten wieder verschlingen. Uranos, der seine Kinder birgt, muß verdrungen werden, es beginnt die Herrschaft des Kronos. Aber auch Kronos noch verschlingt seine eignen Kinder. Endlich beginnt das Reich des Zeus, aber auch dieses nicht ohne vorhergegangene Zerstörung. Jupiter muß die Cyclopen und die hundertarmigen Riesen befreien, damit sie ihm gegen Saturn und die Titanen beistehen, und erst nachdem er diese Ungeheuer und die letzten Geburten der über die Schmach ihrer Kinder zürnenden Gäa, die himmelstürmenden Giganten und das Ungeheuer, an dem sie ihre letzten Kräfte verschwendet, den Typhoëus besiegt hat, klärt sich der Himmel auf, Zeus nimmt ruhigen Besitz vom heitern Olymp, an die Stelle aller unbestimmten und formlosen Gottheiten treten bestimmte, bezeichnete Gestalten, an die Stelle des alten Okeanos Neptun, des Tartaros Pluto, an die Stelle des Titanen Helios der ewig jugendliche Apoll. Selbst der älteste aller Götter, Eros, den die älteste Dichtung zugleich mit dem Chaos seyn ließ, wird als Sohn der Venus und des Mars wieder geboren und eine begrenzte, bleibende Gestalt."}, {"type": "paragraph", "text": "§. 31. *Die Welt der Götter ist kein Objekt weder des bloßen Verstandes noch der Vernunft, sondern einzig mit der Phantasie aufzufassen. -* Nicht des Verstandes, denn dieser haftet nur an der Begrenzung, nicht der Vernunft, denn diese kann auch in der * Wissenschaft *die Synthese des Absoluten und der Begrenzung nur ideell (urbildlich) darstellen; also der Phantasie, welche dieselbe gegenbildlich darstellt. Also etc. *Erklärung.* Im Verhältniß zur Phantasie bestimme ich Einbildungskraft als das, worin die Produktionen der Kunst empfangen und ausgebildet werden, Phantasie, was sie äußerlich anschaut, sie aus sich hinauswirft gleichsam, insofern auch darstellt. Es ist dasselbe Verhältniß zwischen Vernunft und intellektueller Anschauung. In der Vernunft und gleichsam vom Stoff der Vernunft werden die Ideen gebildet, die intellektuelle Anschauung ist das innerlich Darstellende. Phantasie also ist die intellektuelle Anschauung in der Kunst."}, {"type": "paragraph", "text": "§. 32. *Die Götter sind an sich weder sittlich noch unsittlich, sondern losgesprochen von diesem Verhältniß, absolut selig.* (Dieß ist nothwendig festzuhalten, um den gehörigen Gesichtspunkt vorzüglich für Homers Dichtungen zu fassen. Es ist bekannt, wie viel über die Unsittlichkeit seiner Götter gesprochen worden ist; man hat daraus selbst die Vorzüge der modernen Poesie beweisen wollen. Allein daß dieser Maßstab auf diese höheren Wesen der Phantasie nicht angewendet werden könne, erhellt aus Folgendem). *Beweis*: Sittlichkeit wie Unsittlichkeit beruht auf Entzweiung, indem Sittlichkeit nichts anderes ist als Aufnahme des Endlichen ins Unendliche im Handeln. Allein da, wo beide bis zur absoluten Indifferenz eins sind, fällt nothwendig auch jenes, demnach Sittlichkeit, und mit dieser ihr Entgegengesetztes hinweg. Die Unsittlichkeit spricht sich an den homerischen Göttern eben deßwegen nicht als Unsittlichkeit, sondern nur als reine Begrenzung aus. Sie handeln durchaus innerhalb dieser Begrenzung, und sind nur insofern göttlich, als sie innerhalb derselben handeln; nur so ist das Unendliche mit dem Begrenzten in ihnen wahrhaft eins. Sie sind zu betrachten als Wesen einer höheren Natur. Sie handeln innerhalb ihrer Begrenzung so frei und nothwendig zugleich, als jedes Naturwesen innerhalb der seinigen; *frei*, weil es ihre Natur ist so zu handeln und sie kein anderes Gesetz kennen als ihre Natur, *nothwendig*, aus demselben Grunde, weil ihr Handeln ihnen durch ihre Natur vorgeschrieben ist. Die homerischen Götter sind daher in ihrer Unsittlichkeit nur naiv und wahrhaft weder sittlich noch unsittlich, sondern ganz freigesprochen von diesem Gegensatz."}]}, {"page_pdf": 1632, "page_book": 397, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Wir können denselben Satz nun auch so ausdrücken: * die Götter sind absolut selig.* Kein anderes Beiwort tragen sie häufiger; ihr Leben macht den beständigen Gegensatz gegen das menschliche, welches voll Mühe, Zwietracht, der Krankheit und dem Alter unterworfen ist. Auch bei Sophokles sagt der alte Oedipus zu Theseus:1"}, {"type": "footnote", "text": "1 Oed. Col. v. 607 seq."}, {"type": "footnote", "text": "O theurer Sohn des Aegeus, nur den Göttern ist Gegeben nie zu altern noch zu sterben je; Das andre alles aber mischt die Macht der Zeit. Die Kraft der Erde schwindet, auch die Kraft des Leibs, Es welkt dahin der Glaube, Untreu blühet auf."}, {"type": "paragraph", "text": "Die Tragödie wie das epische Gedicht ist voll dieses Gegensatzes. Wir können die Nothwendigkeit dieses Attributs der Götter unmittelbar aus dem Princip einsehen, aus dem sie überhaupt begriffen werden, nämlich: *als absolute Wesen besondere und als besondere absolute zu seyn. *- Daß überhaupt *Sittlichkeit* nichts Höchstes sey, nichts also, was Göttern zugeschrieben werden könnte, erhellt aus dem Gegensatz, den sie an der Glückseligkeit hat, und in dem eigentlich alles Endliche befangen ist. Wie Sittlichkeit Aufnahme des Endlichen oder Besonderen ins Unendliche, so Seligkeit Aufnahme des Unendlichen ins Endliche oder Besondere. In der ersten, wo das Besondere ins Allgemeine aufgenommen wird, unterliegt das Besondere dem Gesetz als dem Allgemeinen, es verhält sich wie der Körper, der der Schwere gehorcht1. Die Götter, in deren Natur beide Einheiten vereinigt sind, leben eben deßwegen kein abhängiges und bedingtes, sondern ein freies und unabhängiges Leben, sie genießen als *besondere* gleichwohl die Seligkeit des Absoluten, und umgekehrt (Streben nach Seligkeit = Streben, der Absolutheit als ein Besonderes zu genießen), ein Verhältniß, wovon nur etwa an den Weltkörpern, als den ersten sinnlichen Bildern der Götter, ein Beispiel, die zugleich als besondere absolut - in sich selbst -, und hinwiederum in ihrer Absolutheit *besondere*, und demnach zugleich außer dem Centro und im Centro sind. Insofern nun beide Einheiten in ihrer Absolutheit einander in sich schließen, weil das Besondere nicht absolut seyn kann, ohne eben dadurch auch wieder im Absoluten zu seyn, und inwiefern in diesem Betracht Seligkeit und Sittlichkeit wieder ein und dasselbe sind, kann man auch sagen, die Götter seyen eben deßwegen absolut sittlich, weil sie absolut selig sind."}, {"type": "footnote", "text": "1 Vgl. Philosophie und Religion, S. 61. D. H."}, {"type": "paragraph", "text": "§. 33. *Das Grundgesetz aller Götterbildungen ist*"}, {"type": "paragraph", "text": "*das Gesetz der Schönheit. * - Denn Schönheit ist das *real *angeschaute Absolute. Die Götterbildungen sind das * Absolute selbst *im Besonderen (oder synthesirt mit der Begrenzung) *real *angeschaut. Also etc. Man könnte dagegen einwerfen: eben deßwegen, weil mit Begrenzung, seyen die Götterbildungen nicht absolut schön. Allein ich kehre es vielmehr um, daß nämlich das Absolute nur in der Begrenzung,"}]}, {"page_pdf": 1633, "page_book": 399, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "nämlich im Besonderen, angeschaut überhaupt schön ist. Die gänzliche Hinwegnahme aller Begrenzung ist entweder gänzliche Negation aller Form (allein dieß nur, wo die Negation der Form zugleich die absolute Form - wie wir in der Folge hören werden - bei der erhabenen Schönheit) oder durchgängige wechselseitige Einschränkung, d.h. Reduktion zur Nullität. Jene Art der Schönheit findet sich z.B. in der würdigen und erhabenen Bildung des Jupiter, die gleicher Ausdruck der Weisheit und Macht ohne Schranken ist, wie in der Juno, welche reiner Ausdruck der Macht ohne Verlust der Schönheit. Diese Begrenzungen sind also nur das, was wir vorläufig die verschiedenen Arten der Schönheit nennen können, da wir diese Untersuchung erst, wenn von den Formen der plastischen Kunst die Rede seyn wird, mit Erfolg anstellen können. Man könnte aber von dem Beispiele der griechischen Mythologie selbst Einwürfe hernehmen, Vulcan, die Bildungen des Pan, des Silen, der Faunen, der Satyre u.s.w. Was die Bildung des Vulcan betrifft, so zeigt uns diese die große Identität zwischen den Bildungen der Phantasie und der organisch schaffenden Natur. Wie die Natur durch die vorzügliche Ausbildung eines Organs oder Triebs in einer Gattung von Geschöpfen sich genöthigt sieht, es dagegen in einem andern zu verkürzen, so hat hier die Phantasie das, was sie den mächtigen Armen des Hephästos gab, seinen Füßen entziehen müssen, welche hinkend sind. Aber allgemein gilt in Ansehung der häßlichen Bildungen der griechischen Götterwelt, daß diese sämmtlichen Bildungen in ihrer Art wieder Ideale, nur die *umgekehrten Ideale *sind, und daß sie dadurch wieder in den Kreis des Schönen aufgenommen werden. Doch auch dieß ist bloß eine anticipirte Erklärung. Was den Vulcan"}, {"type": "paragraph", "text": "betrifft, so wird die Begrenzung, die bei ihm bis zur Häßlichkeit geht, in der Dichtung wieder Quell des unversiegbaren Scherzes und im Kreis der Götter selbst eines unauslöschlichen Gelächters, wenn er den Nektarbecher herumreicht. Vorzüglich zeigt sich nun das Schöne als Canon aller Götterbildung in der Milderung alles Furchtbaren und Schrecklichen durch das Schöne. Die Parcen, nach der ältesten Dichtung Töchter der Nacht, nach einer späteren des Jupiter und der Themis, sind nicht nur in der bildenden Kunst mit hoher Schönheit gebildet, sondern auch die ganze Vorstellung der Phantasie von ihnen deutet auf diese Milderung hin. Dienerinnen der unerbittlichen Nothwendigkeit führen sie doch das höchste Geschäft, die Lenkung der menschlichen Dinge, wie die leichteste Arbeit - als einen zarten Faden, der durch ihre Hände läuft, der sanft und ohne Mühe zerschnitten wird."}, {"type": "paragraph", "text": "§. 34. *Die Götter bilden nothwendig unter sich wieder eine Totalität, eine Welt *(hiermit gehe ich in die innere Construktion ein). - Denn da in jeder Gestalt das Absolute mit Begrenzung gesetzt ist, so setzt sie eben dadurch andere voraus, und mittelbar oder unmittelbar jede einzelne alle anderen und alle jede einzelne. Demnach bilden sie nothwendig unter sich wieder eine Welt, worin alles durcheinander wechselseitig bestimmt ist, ein organisches Ganzes, eine Totalität, eine Welt."}, {"type": "paragraph", "text": "§. 35. *Einzig, indem die Götter unter sich eine Welt bilden, erlangen sie eine unabhängige Existenz für die Phantasie oder eine unabhängige poetische Existenz. * Dieser Satz folgt unmittelbar, denn nur dadurch werden sie Wesen einer eignen Welt, die ganz für sich besteht und von der insgemein sogenannten wirklichen völlig getrennt ist. Jede Berührung mit der gemeinen Wirklichkeit oder mit Begriffen dieser Wirklichkeit zerstört nothwendig den Zauber dieser Wesen selbst, denn dieser beruht eben darauf, daß es nach §. 29 zu ihrer Wirklichkeit nichts anderes als die Möglichkeit bedarf, daß sie also in einer absoluten Welt leben, welche real anzuschauen nur der Phantasie möglich ist."}]}, {"page_pdf": 1634, "page_book": 400, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "*Zur Erläuterung der beiden vorhergehenden Sätze * (34 und 35). Nachdem einmal diese eigentliche Welt der Phantasie erschaffen ist, ist der Einbildung keine weitere Grenze gesetzt, eben deßwegen, weil innerhalb derselben alles Mögliche unmittelbar wirklich ist. Diese Welt kann, ja muß sich also von Einem Punkt aus ins Unendliche bilden; kein mögliches Verhältniß der Götter unter sich und keine mögliche Begrenzung in Ansehung des Absoluten ist nun ausgeschlossen. - Dadurch, daß alle Gestalten als für sich bestehende Wesen in allen Verwicklungen und Verhältnissen betrachtet werden, daß sich unter ihnen selbst wieder ein Kreis von Beziehungen und eine eigne Geschichte bildet, erlangen sie die höchste Objektivität, wodurch dann diese Dichtungen sämmtlich in die Mythologie übergehen. Was insbesondere die Totalität der Bildungen in der griechischen Mythologie betrifft, so läßt sich zeigen, daß in der That alle Möglichkeiten, die in dem Ideenreich liegen, wie es von der Philosophie construirt wird, in der griechischen Mythologie vollkommen erschöpft sind. - Die Nacht und das Fatum, das selbst *über *den Göttern, wie *jene *die Mutter der Götter ist, sind der dunkle Hintergrund, die verborgene geheimnißvolle Identität, aus der sie alle hervorgegangen sind. Immer schweben beide noch über ihnen; aber im lichten Reich der begrenzten und erkennbaren Gestalten ist Jupiter der absolute Indifferenzpunkt, in ihm ist die absolute Macht mit der absoluten Weisheit gepaart; denn als ihm , da er zuerst mit der Metis sich vermählte, geweissagt wurde, daß diese von ihm einen Sohn gebären würde, der, beider Naturen vereinend, alle Götter beherrschen würde, zog er diese in sich selbst hinüber und vermählte sie ganz mit sich: offenbares Sinnbild der absoluten Indifferenz der Weisheit und Macht im ewigen Wesen. Nun gebar er unmittelbar aus sich selbst die Minerva, die gerüstet und gewappnet aus seinem ewigen Haupte entsprang, das Sinnbild der absoluten Form und des Universums, als Bildes der göttlichen Weisheit, das zumal, in seiner ganzen Form, ohne Zeit aus dem ewigen Princip entspringt. * Nur nicht*: daß etwa Jupiter oder Minerva dieß *bedeutet* oder auch bedeuten *sollen. *Dadurch"}, {"type": "paragraph", "text": "würde alle poetische Unabhängigkeit dieser Gestalten vernichtet. Sie *bedeuten *es nicht, sie *sind *es selbst. Die Ideen in der Philosophie und die Götter in der Kunst sind ein und dasselbe, aber jedes ist für sich das, was es ist, jedes eine eigne Ansicht desselbigen, keines um des andern willen, oder um das andere zu bedeuten. - In der Bildung des Jupiter sind alle Beschränkungen entfernt außer der nothwendigen; die Begrenzungen sind nur da, um das Wesentliche schauen zu lassen. Die absolute Macht ist eben darum, weil sie dieß ist, wieder die höchste Ruhe: Jupiter winkt mit den Augenbraunen, und der Olymp erbebt. Er säet gleichsam die Blitze nur, wie sich ein neuerer Dichter vortrefflich ausdrückt. Minerva trägt in sich selbst alles, was die Form Hohes und Mächtiges, Kunstreiches und Zerstörendes, Vereinendes und Entzweiendes in sich hat. Die Form an und für sich ist kalt, da ihr in dieser Absonderung der Stoff fremd ist, sie ist aber zugleich die höchste Macht, die keine Schwäche, wie keinen Irrthum kennt; sie ist daher zugleich das Urbild und die ewige Erfinderin aller * Kunst*, und die furchtbare *Zerstörerin *der Städte, die verwundende und die heilende. Sie ist vereinend als die absolute Form, aber auch die Göttin des Kriegs in Bezug auf die menschlichen Geschlechter. Im hohen Olymp, in der heiteren Region des Göttlichen ist kein Streit, denn das Widerstreitende ist hier, gesondert oder vereint, zur gleichen Absolutheit ausgebildet; nur in der niederen Welt, wo Form sich gegen Form, Besonderes gegen Besonderes empört, ist Krieg, die Werkstätte der nicht ruhenden Bildung und Zerstörung, des Wechsels und Wandels; aber alle diese Erscheinungen der Zerstörung des Kriegs ruhen doch als Möglichkeiten in dem Schooß der absoluten Form. Insofern kann man sagen, daß die jungfräuliche Minerva, die selbst aus keiner Mutter Schooß geboren, die in sich fruchtbarste aller Gottheiten sey. Fast alle Werke der"}]}, {"page_pdf": 1635, "page_book": 402, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Menschen sind ihre Bildungen; in ihrer Strenge (reinen Form) ist sie die gleiche Göttin des Philosophen, des Künstlers und des Kriegers, und ihre Hoheit ruht vorzüglich darin, daß, unerachtet sie von allen allein das Entgegengesetzte vereinet, doch in ihr keines das andere stört, und in ihrem Bild doch alles sich auf Eines"}, {"type": "paragraph", "text": "reducirt, daß sie nämlich die unbewegliche, immer gleiche, unveränderliche Weisheit ist. - Juno hat von dem Zeus die reine Macht ohne die erhabene Weisheit. Daher erstens ihr Haß gegen alles, was durch die Form göttlich ist, und demnach gegen alles Göttliche, was erst in dem von Jupiter neu bezwungenen Lauf der Zeiten gebildet wird, wie gegen den Apollon, die Diana u.s.w. Als Jupiter aus sich selbst die Minerva gebiert, gebiert sie (Juno) ohne Antheil Jupiters, ihm zum Trotz, den Vulcan, den bildenden Künstler sinnreicher Arbeiten ohne die hohe Weisheit der Minerva, den Handhaber des Feuers und Bildner der Waffen, während sein eigner Arm nur den Hammer führt. Sehr bedeutend zeigt sich diese Dichtung und Entgegenstellung mit der Minerva in dem Zusatz, daß der Vulkan nach der Vermählung mit der Minerva gestrebt, daß er in dem vergeblichen Ringen mit ihr die Erde befruchtet, worauf diese den Erichthonios mit den Drachenfüßen gebar. Bekannt ist, daß die Drachengestalt immer das Erdentsprossene bezeichnet: so ist Vulcan damit als die bloß irdische Form der Kunst, die vergeblich sich der himmlischen zu vermählen trachtet, bezeichnet, ebenso wie auf der andern Seite die ihm vermählte Venus die irdische Schönheit, obwohl ihr hohes Urbild zugleich im Himmel wohnt. Ohne in diese zarten Schöpfungen der Phantasie einen ihnen fremden Vernunftzusammenhang bringen zu wollen, können wir doch die ganze Kette, wie sie von Jupiter an in die Hauptgottheiten sich fortsetzt, auf folgende Art bestimmen. Jupiter also als der ewige Vater ist der absolute Indifferenzpunkt, der im Olymp ist, erhaben über allen Widerstreit; bei ihm wohnt die Gestalt der Minerva, die ewige Weisheit - sein Gegenbild, das aus seinem Haupte entsprungen. Unter ihm ist a) in der *realen *Welt das formende und das formlose Princip (Eisen und Wasser), Vulcan und Neptun, welche, damit die Kette sich nach beiden Seiten schließe, als der dem Jupiter entsprechende Indifferenzpunkt, ein unterirdischer Gott wieder zusammenknüpft, Pluto oder der stygische Jupiter, Herrscher im Reich der Nacht oder der Schwere. Wie dieser Indifferenzpunkt (entsprechend dem Jupiter) in der realen Welt, so ist b) Apollon der der idealen Welt,"}, {"type": "paragraph", "text": "das entgegengesetzteste Bild des Pluto, der alt vorgestellt wird, wie jener in ewig jugendlicher Schönheit; der eine im öden Reich der Schatten, der leeren Dinge und des Dunkels, der andere der Gott des Lichts, der Ideen, der lebendigen Gestalt, der, indem er in seinem Reiche nur das Lebendige duldet, selbst dem von Alter Verwelkten mit sanftem Pfeil den Tod schenkt, wie seine Geschoße, die dicht wie Strahlen schießen, schaarenweise vertilgen, was ihm verhaßt ist, z.B. die Griechen, nachdem sie seinen Priester beleidigt1. Alle übrigen Eigenschaften dieses Gottes, daß er der heilende, der Erzeuger des heilbringenden Aeskulap, der Führer der Musen, Erleuchter der Zukunft, wie das allsehende Auge der Welt am Himmel ist, - alle diese Züge stimmen zu der Bedeutung zusammen, die wir diesem Götterbild gegeben haben. Getrennt erblicken wir die hauptsächlichsten dieser Züge wieder in dem Mars, der dem Vulcan auf der ideellen Seite entspricht, und der Venus, welche dem formlosen Princip, dem Neptun, als die höchste irdische Form entspricht, die selbst nach der alten Mythologie sich als die Form zuerst dem Reich des Formlosen - dem Ocean - entwand, den unter den neuen Göttern Poseidon beherrscht. Die Totalität der griechischen Götterwelt wäre übrigens nicht vollkommen, wenn nur das"}]}, {"page_pdf": 1636, "page_book": 404, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Nothwendige, wenn nicht auch jede * besondere*, ja vielleicht zufällige Ansicht der Dinge in ihr wieder absolut wäre. Ganze Massen von Erscheinungen, die vielleicht nur von einem gewissen Gesichtspunkt als Eines erscheinen, überhaupt alle Arten von Verhältnissen werden als das Allgemeine durch ein Individuum zusammengefaßt, welches ohne Zweifel das auffallendste Beispiel der Darstellung des Allgemeinen im Besonderen ist. So ist z.B. die ganze Masse der Erscheinungen, welche das unterirdische Feuer erzeugt, wieder in das Bild des Vulcans zusammengefaßt, wie die, mit welchen"}, {"type": "footnote", "text": "1 Da die Ideenwelt in der griechischen Mythologie in die Sinnenwelt selbst fällt, so ist die eigentliche Welt der bloß scheinbaren Realität, die Schattenwelt, dafür im Reich der Todten, welches sich zu der Sinnenwelt wieder ebenso wie diese nach den Lehren der Philosophie zur Intellektualwelt verhält."}, {"type": "paragraph", "text": "das warme innere Leben der Natur unsere Sinne erfüllt, in das Bild der Vesta. Auch die ungeheuren Erzeugungen der noch nicht gemäßigten, aber durch Jupiters Macht gebändigten Natur ziehen sich in den Titanen zusammen, deren sich noch regende Glieder Erschütterungen der festen Erde bewirken. Die Ansicht der Natur als eines unter vielfach wechselnden Gestalten doch immer sich selbst gleichen Ganzen ist in der Gestalt des Proteus fixirt, der nur denen, die unter jeder Verwandlung ihn mit starken Armen festhielten, zuletzt in der Urgestalt erschien und ihnen das Wahre entdeckte. Die Göttlichkeit, welche auch die Natur in dieser Phantasiewelt erhält, erlaubt auch Verwandlungen der Götter in Thiergestalten, obgleich die griechische Phantasie niemals, wie die ägyptische, die Götter in lauter Thiergestalten verhüllen konnte. Die Totalität forderte, daß in keiner Umgebung etwas der Phantasiewelt Widersprechendes wäre, deßhalb mußte die Vergötterung der Naturdinge nothwendig bis ins Einzelnste fortgesetzt werden, Bäume, Felsen, Berge, Flüsse, auch einzelne Quellen von göttlichen Naturen bewohnt seyn (Genien als Mittelglieder). Die kühnen Spiele der Natur selbst, indem sie nicht selten ihr eignes Ideal auf den Kopf stellt, wo sie mit überfließender Kraft gleichsam verschwenden kann, erneuern sich in der üppigen Fülle der Phantasie, die das Ganze ihrer Welt zuletzt mit den schalkhaften, halb thierischen und halb menschlichen Bildungen der Satyrn und Faunen schloß. Indem hier die menschliche Gestalt zur thierischen herabgezogen wird, die nur den Ausdruck der sinnlichen Begier, der Sorglosigkeit in ihren Zügen erkennen läßt, entsteht die entgegengesetzte Wirkung von der, welche durch die Hinaufbildung derselben Gestalt zum Göttlichen erreicht wurde. Auch hier fordert die Totalität Befriedigung der Phantasie durch Gegensatz. Endlich erscheint auch noch das Umgekehrte, Vereinigung ganz thierischer Leiber mit sinnigem Antlitz, in den Sphinxen. Zuletzt mußten sich die Verwicklungen der Götter auch noch bis in die menschlichen Verhältnisse herein erstrecken. Nicht nur besonders geheiligte Plätze, damit auf diese Weise die ganze Natur geweiht und in eine höhere Welt gehoben würde, sondern auch Theilnahme der"}, {"type": "paragraph", "text": "Götter an den menschlichen Handlungen wie im trojanischen Krieg. Sogar Thiere werden in die Geschichte der Götter verflochten, wie in der Geschichte von den zwölf Arbeiten des Hercules."}, {"type": "paragraph", "text": "§. 36. *Das Verhältniß der Abhängigkeit unter Göttern kann nicht anders denn als Verhältniß der Zeugung vorgestellt werden * (Theogonie). - Denn Zeugung ist die einzige Art der Abhängigkeit, bei welcher das Abhängige gleichwohl in sich absolut bleibt. Nun wird aber zur Idee der Götter erfordert, daß sie als"}]}, {"page_pdf": 1637, "page_book": 406, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "besondere absolut seyen. Also etc. *Erläuterung.* Die Zeugungen der Götter auseinander sind wieder ein Sinnbild der Art, wie die Ideen ineinander sind und auseinander hervorgehen. Die absolute Idee oder Gott begreift z.B. alle Ideen in sich, und sofern diese als in ihm begriffene doch zugleich wieder als für sich absolut gedacht werden, sind sie aus ihm gezeugt, daher Jupiter Vater der Götter und Menschen, und selbst schon geborene Wesen werden durch ihn wieder gezeugt, da mit ihm der Lauf der Welt erst anhebt, und alles *in ihm *seyn muß, um in der Welt zu seyn."}, {"type": "paragraph", "text": "§. 37. *Erklärung. Das Ganze der Götterdichtungen*, indem sie zur vollkommenen Objektivität oder unabhängigen poetischen Existenz gelangen, *ist die Mythologie. *(Bloße Erklärung, also keines Beweises bedürftig)."}, {"type": "paragraph", "text": "§. 38. *Mythologie ist die nothwendige Bedingung und der erste Stoff aller Kunst.* Alles Bisherige der Beweis. Der nervus probandi liegt in der Idee der Kunst als Darstellung des absolut, des an sich Schönen durch besondere schöne Dinge; also Darstellung des Absoluten in Begrenzung ohne Aufhebung des Absoluten. Dieser Widerspruch ist nur in den Ideen der Götter gelöst, die selbst wieder keine unabhängige, wahrhaft objektive Existenz haben können als in der vollkommenen Ausbildung zu einer eignen Welt und zu einem Ganzen der Dichtung, welches Mythologie heißt. *Zur weiteren Erläuterung.* - Die Mythologie ist nichts"}, {"type": "paragraph", "text": "anderes als das Universum im höheren Gewand, in seiner absoluten Gestalt, das wahre Universum an sich, Bild des Lebens und des wundervollen Chaos in der göttllichen Imagination, selbst schon Poesie und doch für sich wieder Stoff und Element der Poesie. Sie (die Mythologie) ist die Welt und gleichsam der Boden, worin allein die Gewächse der Kunst aufblühen und bestehen können. Nur innerhalb einer solchen Welt sind bleibende und bestimmte Gestalten möglich, durch die allein ewige Begriffe ausgedrückt werden können. Die Schöpfungen der Kunst müssen dieselbe, ja noch eine höhere Realität haben als die der Natur, die Götterformen, die so nothwendig und ewig fortdauern, als das Geschlecht der Menschen oder das der Pflanzen, zugleich Individuen und Gattungen und unsterblich wie diese1. Inwiefern Poesie das Bildende des Stoffes, wie Kunst im engeren Sinn der Form ist, so ist die Mythologie die absolute Poesie, gleichsam die Poesie in Masse. Sie ist die ewige Materie, aus der alle Formen so wundervoll, mannichfaltig hervorgehen."}, {"type": "footnote", "text": "1 Vergl. hierzu die späteren Aeußerungen in der Einleitung der Philos. der Mythologie, S. 241 ff. und Philosophie der Offenbarung (2. Abth., Bd. 3) S. 429. D. H."}, {"type": "paragraph", "text": "§. 39. *Darstellung des Absoluten mit absoluter Indifferenz des Allgemeinen und Besonderen im Besonderen ist nur symbolisch möglich. Erläuterung.* Darstellung des Absoluten mit absoluter Indifferenz des Allgemeinen und Besonderen *im Allgemeinen = * Philosophie - Idee -. Darstellung des Absoluten mit absoluter Indifferenz des Allgemeinen und Besonderen *im Besonderen* = Kunst. Der allgemeine Stoff dieser Darstellung = Mythologie. In dieser also ist schon die zweite Synthese, die der Indifferenz des Allgemeinen und Besonderen mit dem *Besonderen *gemacht. Der aufgestellte Satz ist demnach Princip der Construktion der Mythologie überhaupt. Um den Beweis dieses Satzes führen zu können, ist es nöthig, daß wir eine Erklärung des *Symbolischen *geben; und da diese"}]}, {"page_pdf": 1638, "page_book": 407, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Darstellungsart wieder die Synthesis zweier entgegengesetzter ist, der schematischen und der allegorischen, so werde ich also bei dieser Gelegenheit erklären, was Schematismus und was Allegorie ist. *Erläuterungssätze.* Diejenige Darstellung, in welcher das Allgemeine das Besondere bedeutet, oder in welcher das Besondere durch das Allgemeine angeschaut wird, ist * Schematismus.* Diejenige Darstellung aber, in welcher das Besondere das Allgemeine bedeutet, oder in welcher das Allgemeine durch das Besondere angeschaut wird, ist *allegorisch.* Die Synthesis dieser beiden, wo weder das Allgemeine das Besondere, noch das Besondere das Allgemeine bedeutet, sondern wo beide absolut eins sind, ist das *Symbolische.* Diese drei verschiedenen Darstellungsarten haben das Gemeinschaftliche, daß sie nur durch Einbildungskraft möglich und Formen derselben sind, nur daß die dritte ausschließlich die absolute Form ist. Wir haben jedes dieser drei auch noch vom *Bild *zu unterscheiden. Das Bild ist immer concret, rein besonder, und von allen Seiten so bestimmt, daß zur völligen Identität mit dem Gegenstand nur der bestimmte Theil des Raumes fehlt, worin letzterer sich befindet. Das Herrschende im Schema dagegen ist das Allgemeine, obgleich allerdings das Allgemeine in ihm als ein Besonderes angeschaut wird. Daher konnte es Kant in der Kritik der reinen Vernunft definiren: als die sinnlich angeschaute Regel der Hervorbringung eines Gegenstandes. Es steht insofern allerdings zwischen dem Begriff und dem Gegenstand in der Mitte, und ist in dieser Beziehung Produkt der Einbildungskraft. Am deutlichsten sieht man, was Schema sey, aus dem Beispiel des mechanischen Künstlers, der einen Gegenstand bestimmter Form einem Begriffe gemäß hervorbringen soll. Dieser Begriff *schematisirt * sich ihm, d.h. er wird ihm unmittelbar in der Einbildungskraft in seiner Allgemeinheit zugleich das Besondere und Anschauung des Besonderen. Das Schema ist die Regel, welche sein Hervorbringen leitet, aber er schaut in diesem Allgemeinen zugleich das Besondere an. Er wird"}, {"type": "paragraph", "text": "dieser Anschauung gemäß zuerst nur den rohen Entwurf des Ganzen hervorbringen, dann die einzelnen Theile vollständig ausbilden, bis ihm das Schema allmählich zum völlig concreten Bild wird, und noch mit der vollständig eintretenden Bestimmung des Bildes in seiner Einbildungskraft auch das Werk selbst vollendet ist. Was Schema und Schematismus sey, kann also jeder nur durch eigne innere Anschauung erfahren; da aber unser Denken des Besonderen eigentlich immer ein Schematisiren desselben ist, so bedarf es eigentlich bloß der Reflexion auf den beständig, selbst in der Sprache geübten Schematismus, um sich der Anschauung davon zu versichern. In der Sprache bedienen wir uns auch zur Bezeichnung des Besonderen doch immer nur der allgemeinen Bezeichnungen; insofern ist selbst die Sprache nichts anderes als ein fortgesetztes Schematisiren. Es gibt nun allerdings auch einen Schematismus der Kunst, allein nach der Erklärung selbst, die wir davon gegeben haben, ist offenbar, daß bloßer Schematismus keine vollkommene Darstellung des Absoluten im Besonderen heißen könne, obgleich das Schema als Allgemeines auch wieder ein Besonderes ist, aber nur so, daß das Allgemeine das Besondere bedeutet. Es wäre also unmöglich, Mythologie überhaupt, oder die griechische insbesondere, da sie wahre Symbolik ist, bloß als einen"}]}, {"page_pdf": 1639, "page_book": 409, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Schematismus der Natur oder des Universums zu begreifen, obgleich es allerdings scheinen möchte, daß einzelne Elemente derselben so gedeutet werden können. Man könnte jenes schon bemerkte Zusammenfassen besonderer, zu einem gewissen beschränkten Kreis gehöriger Erscheinungen auf ein Individuum als Schematismus begreifen, indem man nun dieses Individuum selbst wieder als das Allgemeine jener Erscheinungen begriffe. Aber ebenso gut könnte man umgekehrt sagen, daß in ihnen vielmehr das Allgemeine (volle Massen von Erscheinungen) durch das Besondere bedeutet werde, welches ebenso viel Wahrheit hätte als das Erste, da in der symbolischen Darstellung eben beides vereinigt ist. Ebenso, wenn man Mythologie nur überhaupt als eine bloß *höhere *Sprache begreifen wollte, da die Sprache allerdings ganz schematisirend ist."}, {"type": "paragraph", "text": "Was nun die *Allegorie *betrifft, so ist sie das Umgekehrte des Schema, also wie dieses auch eine Indifferenz des Allgemeinen und Besonderen, aber so, daß Besonderes hier das Allgemeine bedeutet oder als Allgemeines angeschaut wird. Am ehesten konnte noch diese Erklärungsart auf die Mythologie mit einigem Schein angewendet werden, und ist auch vielfach angewendet worden. Allein es tritt hier dasselbe ein, was in Ansehung des Schematismus. In der Allegorie *bedeutet *das Besondere nur das Allgemeine, in der Mythologie * ist *es zugleich selbst das Allgemeine. Aber eben deßwegen ist auch alles Symbolische sehr leicht zu allegorisiren, weil die symbolische Bedeutung die allegorische ebenso in sich schließt, wie in der Ineinsbildung des Allgemeinen und Besonderen auch die Einheit des Besonderen mit dem Allgemeinen wie die des Allgemeinen mit dem Besonderen enthalten ist. Daß nun allerdings bei Homer, so wie in den Darstellungen der bildenden Kunst, die Mythen nicht allegorisch, sondern mit absoluter poetischer Unabhängigkeit, als Realität für sich gemeint seyen, konnte man sich nicht verbergen. Daher wurde in neueren Zeiten ein anderes Expediens ausgedacht. Man sagte nämlich, ursprünglich seyen die Mythen allegorisch gemeint, aber Homer habe sie gleichsam episch travestirt, rein poetisch genommen und daraus diese angenehmen Kindermährchen zusammengesetzt, die er in der Ilias und Odyssee erzählte. Dieß ist bekanntlich die Vorstellung, welche Heyne aufgebracht und seine Schule geltend zu machen gesucht hat. Die innere Geistlosigkeit einer solchen Vorstellung überhebt uns aller Widerlegung derselben. Es ist, möchte man sagen, die gröbste Art, das Poetische des Homeros zu zerstören. Das Gepräge einer solchen gemeinen Absichtlichkeit wird man an keiner Spur seiner Werke erkennen1. Der Zauber der homerischen Dichtung und der ganzen Mythologie ruht allerdings mit darauf, daß sie die allegorische Bedeutung auch als *Möglichkeit *enthält - man kann auch wirklich durchweg alles allegorisiren.- Darauf beruht die Unendlichkeit des Sinns in der griechischen"}, {"type": "footnote", "text": "1 Man vergl. die zweite Vorlesung der Einleitung in die Philosophie der Mythologie. D. H."}, {"type": "paragraph", "text": "Mythologie. Aber das Allgemeine ist nur als Möglichkeit darin. Das An-sich davon ist weder allegorisch noch schematisch, sondern die absolute Indifferenz beider - das Symbolische. Diese Indifferenz war hier das *Erste*. Homeros hat diese Mythen nicht erst unabhängig poetisch und symbolisch gemacht, sie waren dieß gleich im Anfang; daß man das Allegorische in ihnen sonderte, war ein Einfall späterer Zeiten, der erst nach Erlöschung alles poetischen Geistes möglich war. So läßt es sich auch, wie ich im Folgenden zeigen werde, hinlänglich evident machen, daß der homerische Mythos, und insofern Homer selbst, in der"}]}, {"page_pdf": 1640, "page_book": 411, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "griechischen Poesie absolut das Erste und der Anfang ist. Die allegorischen Poesien und Philosopheme, wie es Heyne nennt, sind durchaus das Werk späterer Zeiten. Die Synthesis ist das Erste. Dieß ist das allgemeine Gesetz der griechischen Bildung, welche eben dadurch ihre Absolutheit beweist. So sehen wir auch deutlich, daß die Mythologie sich schließt, sowie die Allegorie anfängt. Der Schluß der griechischen Mythe ist die bekannte Allegorie von Amor und Psyche. Die gänzliche Entfernung der griechischen Phantasie vom Allegorischen zeigt sich vorzüglich darin, daß selbst Personificata, die man am ehesten für allegorische Wesen halten könnte, wie z.B. die Eris (Zwietracht) doch durchaus nicht bloß als Wesen, die etwas bedeuten sollen, sondern als *reelle *Wesen, die zugleich das sind, was sie bedeuten, behandelt werden. (Gegensatz der Neueren hierin: Dante allegorisch im höchsten Styl, dann Ariosto, Tasso. Beispiel: Voltaires Henriade, wo das Allegorische ganz sichtbar und grob). Der *Begriff *des Symbolischen ist jetzt durch den Gegensatz hinlänglich erläutert. Man kann die Stufenfolge der drei Darstellungsarten wieder als eine Stufenfolge von Potenzen ansehen. Insofern sind sie wieder allgemeine Kategorien. Man kann sagen: die Natur in der Körperreihe allegorisirt bloß, da nur Besonderes Allgemeines bedeutet, ohne es selbst zu seyn; daher keine Gattungen. Im Licht im Gegensatz mit den Körpern ist sie schematisirend, im Organischen symbolisch, denn hier ist der unendliche Begriff dem Objekt selbst"}, {"type": "paragraph", "text": "verbunden, das Allgemeine ist ganz das Besondere und das Besondere das Allgemeine. Ebenso das Denken ist ein bloßes Schematisiren, alles Handeln dagegen allegorisch (denn als Besonderes bedeutend ein Allgemeines), die Kunst ist symbolisch. Auch auf die Wissenschaft ist dieser Unterschied überzutragen. Die Arithmetik ist allegorisirend, denn sie bedeutet durch das Besondere das Allgemeine. Die Geometrie kann man schematisirend nennen, insofern als sie durch das Allgemeine das Besondere bezeichnet. Endlich die Philosophie ist unter diesen Wissenschaften die symbolische. (Wir werden zu denselben Begriffen bei der Construktion der einzelnen Kunstformen zurückkehren. Die Musik ist eine allegorisirende Kunst, die Malerei schematisirend, die Plastik symbolisch. Ebenso in der Poesie die Lyrik allegorisch, die epische Poesie hat die nothwendige Hinneigung zum Schematisiren, die Dramatik ist symbolisch). Als ein nothwendiger * Folgesatz *geht nun aus dieser ganzen Untersuchung hervor: die Mythologie überhaupt und jede Dichtung derselben insbesondere ist weder schematisch noch allegorisch, sondern *symbolisch *zu begreifen. Denn die Forderung der absoluten Kunstdarstellung ist: Darstellung mit *völliger Indifferenz*, so nämlich, daß das Allgemeine ganz das Besondere, das Besondere zugleich das ganze Allgemeine *ist*, nicht es bedeutet. Diese Forderung ist poetisch gelöst in der Mythologie. Denn jede Gestalt in ihr ist zu nehmen als das, was sie ist, denn eben dadurch wird sie auch genommen als das, was sie bedeutet. Die Bedeutung ist hier zugleich das Seyn selbst, übergegangen in den Gegenstand, mit ihm eins. Sobald wir diese Wesen etwas * bedeuten *lassen, sind sie selbst *nichts mehr.* Allein die Realität ist bei ihnen mit der Idealität eins (§. 29), d.h. auch ihre *Idee*, ihr Begriff, wird zerstört, wofern sie nicht als wirklich gedacht werden. Ihr höchster Reiz beruht eben darauf, daß sie, indem sie bloß *sind* ohne alle Beziehung - in sich selbst absolut -, doch zugleich immer die Bedeutung durchschimmern lassen. Wir begnügen uns allerdings nicht mit dem bloßen *bedeutungslosen Seyn*, dergleichen z.B. das bloße Bild"}]}, {"page_pdf": 1641, "page_book": 413, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "gibt, aber ebensowenig mit der bloßen Bedeutung, sondern wir wollen, was Gegenstand der absoluten Kunstdarstellung seyn soll, so concret, nur sich selbst gleich wie das Bild, und doch so allgemein und sinnvoll wie der Begriff; daher die deutsche Sprache Symbol vortrefflich als Sinnbild wiedergibt. Selbst an den Naturwesen, z.B. der Pflanze ist die Allegorie nicht zu verkennen, sie ist gleichsam die anticipirte sittliche Schönheit, sie würde aber keinen Reiz für die Phantasie, keine Befriedigung für die Anschauung enthalten, wenn sie um dieser Bedeutung willen und nicht zuerst um ihrer selbst willen wäre. Eben in diesem unabsichtlichen, unbefangenen, nach außen unzweckmäßigen Seyn doch zugleich das Bedeutende, Sinnvolle zu erkennen, entzückt uns. Es als Absicht darin zu erblicken, hebt den Gegenstand selbst für uns auf, der, da er seiner Natur nach absolut seyn soll, um keines Zwecks willen, der außer ihm liegt, daseyn darf. Es ist ein großes Verdienst, das sich unter den Deutschen und überhaupt zuerst *Moritz *gemacht hat, die Mythologie in dieser ihrer poetischen Absolutheit darzustellen. Obgleich die letzte Vollendung der Ansicht bei ihm fehlt, und er nur zeigen kann, daß es mit diesen Dichtungen so sey, nicht aber die Nothwendigkeit und den Grund davon, so waltet doch in seiner Darstellung durchaus der poetische Sinn, und vielleicht sind die Spuren Goethes darin erkennbar, der diese Ansichten durchaus in seinen eignen Werken ausgedrückt und sie ohne Zweifel auch in Moritz geweckt hat. Ein untergeordneter *Folgesatz *ist noch: daß ebenso unmittelbar die Mythologie *historisch *zu begreifen. Ohne Zweifel ist es die am meisten prosaische Ansicht dieser Dichtungen, nach welcher ein großer Theil der Göttergeschichte Spuren großer Natur-Revolutionen in der Urwelt, die Götter selbst uralte Könige bedeuten u.s.w. Hiermit ginge nun selbst die Beziehung der Mythologie auf Anschauung des Universums und der Natur anders als in der historischen Beziehung, d.h. es ginge das schlechthin Allgemeingültige derselben verloren. Nur als Typus - gleichsam als die"}, {"type": "paragraph", "text": "urbildliche Welt selbst - hat die Mythologie allgemeine Realität für alle Zeiten. Die wunderbare Verflechtung, die in diesem göttlichen Ganzen stattfindet, läßt uns allerdings erwarten, daß auch Züge aus der Geschichte darein spielen. Aber wer kann in diesem lebendigen Ganzen das Einzelne sondern, ohne den Zusammenhang des Ganzen zu zerstören? Wie diese Dichtungen gleichsam als ein zarter Duft die Natur durch sich erblicken lassen, so wirken sie auch als ein Nebel, durch den wir die entfernte Zeit der Urwelt und einzelne große Gestalten erkennen, die sich auf ihrem dunklen Hintergrund bewegen. Alles andere überzeugt uns, daß das gegenwärtige Menschengeschlecht ein Menschengeschlecht aus der zweiten Hand ist, daß also ohne Zweifel, was in den Dichtungen der Mythologie lebt, einst wirklich existirt hat, und ein Göttergeschlecht dem gegenwärtigen der Menschen vorangegangen ist; aber die mythologischen Dichtungen selbst sind doch von einer solchen Wahrheit völlig unabhängig und ganz allein in sich selbst zu betrachten. (*Sie *werden sich nun ferner auch nicht wundern, wenn ich von jenen beliebten historisch-psychologischen Erklärungen der Mythologie keinen Gebrauch gemacht habe, nach welchen der Ursprung der Mythologie in den Bestrebungen roher Natursöhne gesucht wird, alles zu personificiren und zu beleben, ungefähr wie es der amerikanische Wilde auch thut, wenn er die Hand in einen Topf siedenden Wassers steckt und glaubt, daß ein Thier darin sey, das ihn gebissen habe. Von dieser rohen Natursprache wäre die Mythologie, nicht dem Princip, sondern nur dem Grad der Ausführung nach verschieden. Nach andern ist sie ein bloßer Nothbehelf wegen der Armuth der Bezeichnungen oder Unwissenheit der Ursachen, z.B. der Gott des Donners, des Feuers u.s.w.)."}, {"type": "paragraph", "text": "§. 40. *Der Charakter der wahren Mythologie ist der der Universalität, der Unendlichkeit. -* Denn sie ist nach §. 34 möglich in sich selbst nur, inwiefern sie bis zur Totalität ausgebildet und das urbildliche Universum selbst darstellt. In diesem aber sind nicht nur alle Dinge, sondern auch alle Verhältnisse der"}]}, {"page_pdf": 1642, "page_book": 414, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Dinge als absolute Möglichkeiten zumal; dasselbe muß also auch in der Mythologie der Fall seyn: insofern Universalität. Da aber in dem"}, {"type": "paragraph", "text": "Universum an sich, in der urbildlichen Welt, wovon die Mythologie die unmittelbare Darstellung, Vergangenheit und Zukunft als Eines sind, so muß dasselbe auch in der Mythologie der Fall seyn. Sie muß nicht nur das Gegenwärtige oder auch Vergangene darstellen, sondern auch die Zukunft begreifen; sie muß wie durch prophetische Anticipation auch künftigen Verhältnissen und den unendlichen Entwickelungen der Zeit zum voraus angemessen oder adäquat, d.h. sie muß unendlich seyn. Diese Unendlichkeit muß sich gegenüber von dem Verstand dadurch ausdrücken, daß kein Verstand fähig ist sie ganz zu entwickeln, daß in ihm selbst eine unendliche Möglichkeit liegt, immer neue Beziehungen zu bilden."}, {"type": "paragraph", "text": "§. 41. *Die Dichtungen der Mythologie können weder als absichtlich noch als unabsichtlich gedacht werden. - *Nicht als absichtlich, denn sonst wären sie um einer Bedeutung willen erfunden, welches nach §. 39 unmöglich ist. Nicht unabsichtlich, weil nicht bedeutungslos. Es ist damit im Grunde dasselbe behauptet, was schon in dem Vorhergehenden implicite behauptet wurde, nämlich die Dichtungen der Mythologie sind zugleich bedeutend und bedeutungslos - bedeutend, weil ein Allgemeines im Besonderen, bedeutungslos, weil beides wieder mit absoluter Indifferenz, so daß das, worin indifferenziirt, wieder absolut, um seiner selbst willen ist."}, {"type": "paragraph", "text": "§. 42. *Die Mythologie kann weder das Werk des einzelnen Menschen noch des Geschlechts oder der Gattung seyn *(sofern diese nur eine Zusammensetzung der Individuen),* sondern allein des Geschlechts, sofern es selbst Individuum und einem einzelnen Menschen gleich ist. *Nicht des Einzelnen, weil die Mythologie absolute Objektivität haben, eine zweite *Welt *seyn soll, die nicht die des Einzelnen seyn kann. Nicht eines Geschlechts oder der Gattung, sofern sie nur eine Zusammensetzung der Individuen, denn alsdann wäre sie ohne harmonische Zusammenstimmung. Sie fordert also zu ihrer Möglichkeit nothwendig ein Geschlecht, das Individuum wie Ein Mensch ist. Die Unbegreiflichkeit,"}, {"type": "paragraph", "text": "die diese Idee für unsere Zeit haben mag, kann ihrer Wahrheit nichts nehmen. Sie ist die höchste Idee für die *ganze* Geschichte überhaupt. Analogien, ferne Anspielungen auf ein solches Verhältniß enthält schon die Natur in der Art, wie sich die Kunsttriebe der Thiere äußern, indem bei mehreren Gattungen ein ganzes Geschlecht zusammen wirkt, jedes Individuum als das Ganze, und das Ganze selbst wieder als Individuum handelt. Ein solches Verhältniß kann uns in der Kunst um so weniger befremden, da wir eben hier - auf der höchsten Stufe der Produktion - den Gegensatz der *Natur *und *Freiheit *noch einmal eintreten sehen, und die griechische Mythologie z.B. uns in der Kunst *selbst* die * Natur *wieder bringt, wie ich noch bestimmt beweisen werde. Aber eben auch nur in der Kunst kann die Natur eine solche Eintracht des Individuums und der Gattung bewirken (im Handeln behauptet sie auch ihr Recht, aber weniger auffallend, mehr im Ganzen als im Einzelnen, und im Einzelnen nur für Momente). In der griechischen Mythologie hat die Natur ein solches Werk eines auf ein ganzes Geschlecht ausgedehnten gemeinschaftlichen Kunsttriebs aufgestellt, und die entgegengesetzte Bildung der griechischen, die moderne, hat nichts Aehnliches aufzuweisen, obgleich sie in der Bildung einer universellen Kirche gleichsam instinktmäßig etwas Aehnliches beabsichtigte."}]}, {"page_pdf": 1643, "page_book": 416, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Vollkommen deutlich kann dieses Verhältniß, durch welches wir uns die griechische Mythologie als entstanden denken müssen - diese in ihrer Art einzige Besitznahme eines ganzen Geschlechts durch einen gemeinschaftlichen Kunstgeist - nur in der Entgegenstellung gegen den Ursprung der modernen Poesie gemacht werden, zu der ich jetzt nicht fort gehen kann. Ich erinnere an die Wolfsche Hypothese vom Homer, daß er auch in seiner ursprünglichen Gestalt nicht das Werk eines Einzigen, sondern mehrerer von dem gleichen Geist getriebener Menschen gewesen. Wolf hat als Kritiker die Sache nur zu empirisch, zu beschränkt auf das schriftliche Werk, das wir Homer nennen, mit Einem Wort zu untergeordnet angefaßt, um die Idee der Sache selbst, das Allgemeine vielleicht seiner eignen Vorstellung deutlich und anschaulich machen zu können. Ich lasse die unbeschränkte Richtigkeit der Wolfschen"}, {"type": "paragraph", "text": "Ansicht des Homer hier gänzlich dahingestellt, aber ich will durch den aufgestellten Satz von der Mythologie dasselbe, was Wolf vom Homer, behaupten. Die Mythologie und Homer sind eins, und Homer lag in der ersten Dichtung der Mythologie schon fertig involvirt, gleichsam potentialiter vorhanden. Da Homer, wenn ich so sagen darf, geistig - im Urbild - schon prädeterminirt, und das Gewebe seiner Dichtungen mit dem der Mythologie schon gewoben war, so ist begreiflich, wie Dichter, aus deren Gesängen Homer zusammengesetzt wäre, unabhängig voneinander jeder in das Ganze eingreifen konnten, ohne seine Harmonie aufzuheben, oder aus der ersten Identität herauszugehen. Es war wirklich ein schon - wenn gleich nicht empirisch - vorhandenes Gedicht, was sie recitirten. Der Ursprung der Mythologie und der des Homer fallen also zusammen, daher es begreiflich ist, wie der Ursprung beider schon den frühesten hellenischen Historikern gleich verborgen ist, und schon Herodotos die Sache einseitig vorstellt, nämlich Homeros habe den Hellenen zuerst die Göttergeschichte gemacht. Die Alten selbst bezeichnen die Mythologie und, da diese ihnen mit dem Homer in eins zusammenfällt, die homerischen Dichtungen als die gemeinsame Wurzel der Poesie, der Geschichte und Philosophie. Für die Poesie ist sie der Urstoff, aus dem alles hervorging, der Ocean, um ein Bild der Alten zu gebrauchen, aus dem alle Ströme ausfließen, wie sie alle in ihn zurückkehren. Erst allmählich verliert sich der mythische Stoff in den historischen; man könnte sagen, erst wie die Idee des Unendlichen hervortritt und die Beziehung auf das *Schicksal *entstehen kann (Herodot). In der Zwischenperiode muß, weil das Unendliche, noch ganz dem Stoff verbunden, selbst stoffartig wirkt, jener in der Mythologie ausgestreute göttliche Same noch lange in wunderbaren großen Ereignissen wuchern, wie die des heroischen Zeitalters sind. Die Gesetze gemeiner Erfahrung sind noch nicht eingetreten, noch immer concentriren sich ganze volle Massen von Erscheinungen auf einzelne große Gestalten, wie auch in der Ilias geschieht. Da die Mythologie nichts anderes als die urbildliche Welt selbst ist, die erste allgemeine Anschauung des Universums, so war sie Grundlage"}, {"type": "paragraph", "text": "der Philosophie, und es ist leicht zu zeigen, daß sie die ganze Richtung auch der griechischen Philosophie bestimmt hat. Das Erste, was sich aus ihr loswand, war die älteste Naturphilosophie der Griechen, die noch rein realistisch war, bis zuerst Anaxagoras (íï™ò) und vollendeter nach ihm Sokrates das idealistische Element darein brachte. Aber auch von dem sittlichen Theil der Philosophie war sie die erste Quelle. Die ersten Ansichten sittlicher Verhältnisse, aber vorzüglich jenes allen Griechen bis zur höchsten Bildung im Sophokles gemeinschaftliche, allen ihren Werken tief eingeprägte Gefühl des untergeordneten Verhältnisses der Menschen zu den Göttern, der Sinn für Begrenzung und Maß auch im"}]}, {"page_pdf": 1644, "page_book": 418, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Sittlichen, die Verabscheuung des Uebermuths, der frevelnden Gewaltthätigkeit u.s.w., die schönsten sittlichen Seiten der Sophokleischen Werke stammen noch von der Mythologie her. So ist also die griechische Mythologie nicht nur für sich von unendlichem Sinn, sondern, weil sie auch ihrem *Ursprung *nach Werk einer Gattung ist, die zugleich Individuum ist, selbst das Werk eines Gottes, wie in der griechischen Anthologie selbst das Sinngedicht auf Homer enthalten ist:"}, {"type": "footnote", "text": "War Homeros ein Gott, so werden ihm Tempel errichtet, War er ein Sterblicher, sey dennoch er göttlich verehrt."}, {"type": "paragraph", "text": "Noch eine Reflexion. - Wir haben die Mythologie von den ersten Kunstforderungen aus ganz rational construirt, und von selbst stellte sich als die Auflösung aller jener Forderungen die griechische Mythologie dar. Hier drängt sich uns das erste Mal die durchgängige Rationalität der griechischen Kunst und Poesie auf, so daß man immer sicher seyn kann, jede ihrer Idee gemäß construirte Kunstgattung, ja fast das Kunstindividuum in der griechischen Bildung anzutreffen. Die moderne Poesie und Kunst dagegen ist die irrationale, insofern die negative Seite der alten Kunst, womit ich sie nicht herabsetzen will, da auch das Negative als solches wieder Form werden kann, die das Vollendete aufnimmt. Es führt uns dieß auf den Gegensatz *der antiken und modernen Poesie *in Bezug auf Mythologie."}, {"type": "paragraph", "text": "Wie uns schon in der Natur die Wiederkehr desselben Gegensatzes in verschiedenen Potenzen in Verwirrung setzt, wenn wir das allgemeine Gesetz derselben nicht kennen, so noch viel mehr in der Geschichte und dem, was uns der Freiheit anzugehören scheint. Wir würden auch ohne alle anderen Gründe schon bloß durch die Wirklichkeit uns genöthigt sehen, anzunehmen, daß auch in der Kunst selbst - der höchsten Vereinigung von Natur und Freiheit - wieder dieser Gegensatz der Natur und Freiheit und der des Unendlichen und Endlichen zurückkehre, und wir bedürfen einer festen Norm, eines aus der Vernunft selbst entworfenen Typus, um die Nothwendigkeit dieser Wiederkehr zu begreifen. Der bloße Weg der Erklärung führt überhaupt und in nichts zur wahren Erkenntniß. Die Wissenschaft erklärt nicht; unbekümmert, welche Gegenstände aus ihrem rein wissenschaftlichen Handeln hervorgehen mögen, construirt sie; allein eben bei diesem Verfahren wird sie am Ende mit der vollkommenen und geschlossenen Totalität überrascht; die Gegenstände treten unmittelbar, durch die Construktion selbst, an ihre wahre Stelle, und diese Stelle, die sie in der Construktion erhalten, ist zugleich ihre einzig wahre und richtige Erklärung. Es braucht nun nicht weiter von der gegebenen Erscheinung auf ihre Ursache zurückgeschlossen zu werden; sie ist diese bestimmte, weil sie in diese Stelle tritt, und umgekehrt, sie nimmt diese Stelle ein, weil sie diese bestimmte ist. Nur bei solchem Verfahren ist Nothwendigkeit. Die griechische Mythologie, um jetzt die nähere Anwendung auf unsern Gegenstand zu machen, könnte von allen Seiten betrachtet und als eine gegebene Erscheinung nach allen Rücksichten erklärt werden, ohne Zweifel würde auch die Erklärung zu derselben Ansicht zurückführen, welche uns die Construktion gegeben hat - (denn dieß ist eben auch ein Vorzug der Construktion, daß sie das mit der Vernunft anticipirt, worauf die richtig angestellte Erklärung am Ende zurück führt), aber immer würde bei diesem Verfahren noch etwas fehlen, die Einsicht der Nothwendigkeit und des allgemeinen Zusammenhangs, der für diese Erscheinung gerade diese Stelle und diesen Grund bestimmt. Der"}, {"type": "paragraph", "text": "Anblick und die genauere Betrachtung der griechischen Mythologie muß jeden, der dafür Sinn hat,"}]}, {"page_pdf": 1645, "page_book": 420, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "überzeugen, daß diese Mythologie in der Sphäre der Kunst selbst die Natur wiederbringe, aber die Construktion bezeichnet zum voraus und mit Nothwendigkeit diese Stelle im allgemeinen Zusammenhang, welche sie einnimmt. Das Princip der Construktion ist, in einem andern und höhern Sinn, das der alten Physik, * daß die Natur einen Abscheu vor der Leere hat.* Wo demnach im Universum eine leere Stelle ist, füllt sie die Natur aus. Weniger bildlich ausgedrückt: keine Möglichkeit ist im Universum unerfüllt, alles Mögliche ist wirklich. Da das Universum Eins ist, untheilbar, so kann es sich in nichts ergießen, ohne sich ganz darein zu ergießen. Es ist kein Universum der Poesie, ohne daß auch in ihm wieder *Natur *und *Freiheit* sich entgegenstehen. Wer unsere Behauptung von der griechischen Mythologie als einem Werk der Natur so verstehen wollte, als wäre sie es auf eine eben so blinde Weise, als es die Hervorbringungen des Kunsttriebs der Thiere sind, würde sie freilich ganz roh verstehen. Aber nicht weniger würde derjenige von der Wahrheit abirren, der sie als ein Werk absolut-poetischer Freiheit denken wollte. Ich habe die Hauptzüge schon angegeben, durch welche die griechische Mythologie sich innerhalb der Kunstwelt wieder als die organische Natur darstellt. Es ist schon vielmals bemerkt worden, welche Flucht vor dem Formlosen, dem Unbegrenzbaren in ihr herrschend ist. Wie das Organische ins Unendliche zurück nur aus dem Organischen entstehen kann, so auch hier nichts ohne Zeugung, nichts aus dem Formlosen, dem Unendlichen für sich, sondern immer aus dem schon Gebildeten. Der Unendlichkeit unerachtet, welche die griechische Mythologie noch immer hat, zeigt sie doch nach außen sich durchaus als endlich, vollendet, ihrem ganzen Wesen nach als realistisch. Das Unendliche zeigt sich hier auf der höheren Stufe wieder ebenso wie im Organismus unmittelbar dem Stoffe verbunden; deßwegen ist, innerhalb dieses Ganzen, alle Bildung eine nothwendige, und betrachtet man es als Ein organisches Wesen, so hat es nach innen wirklich die"}, {"type": "paragraph", "text": "materielle Unendlichkeit, die das organische Wesen auszeichnet. Bildung quillt aus Bildung hervor, ins Unendliche nicht nur theilbar, sondern wirklich getheilt. Nirgends tritt das Unendliche als unendlich hervor, es ist überall da, aber nur in dem Gegenstand - dem Stoff verbunden -, nirgends in der Reflexion des Dichters z.B. in den homerischen Gesängen. Unendliches und Endliches ruhen noch unter einer gemeinschaftlichen Hülle. Gegenüber von der Natur ist jede ihrer Gestalten ideal-unendlich, in der Beziehung auf die Kunst selbst aber durchaus real-begrenzt und endlich. Daher die gänzliche Abwesenheit aller sittlichen Begriffe in der Mythologie, sofern sie die Götter betrifft. Diese sind organische Wesen einer höheren, einer absoluten, durchaus idealistischen Natur. Sie handeln durchaus als solche, immer ihrer Begrenzung gemäß, und darum wieder absolut. Selbst die sittlichsten Götter, wie Themis, sind doch sittlich nicht aus Sittlichkeit, sondern bei ihnen gehört auch dieses wieder zur Begrenzung. Sittlichkeit ist wie Krankheit und Tod allein den Sterblichen anheim gefallen, und in diesen kann sie sich in Beziehung auf die Götter nur als Empörung gegen diese äußern. Prometheus ist das Urbild der Sittlichkeit, welches die alte Mythologie aufstellt. Er ist das allgemeine Symbol desjenigen Verhältnisses, welches die Sittlichkeit in ihr hat. Darum, weil in ihm die Freiheit sich als Unabhängigkeit von den Göttern äußert, wird er an den Felsen geschmiedet, ewig heimgesucht von dem von Jupiter gesandten Geier, der seine immer wieder wachsende Leber nagt. So repräsentirt er das ganze menschliche Geschlecht, und duldet in seiner Person die Qualen der ganzen Gattung. Hier tritt also das Unendliche allerdings hervor, aber in seinem Hervortreten unmittelbar wieder gefesselt, zurückgehalten und begrenzt. Ebenso wie in der alten Tragödie, wo die höchste Sittlichkeit in der Anerkennung der Schranken und der Begrenzung liegt, die dem menschlichen Geschlecht gesetzt ist1. Wenn alle Gegensätze überhaupt nur auf einem Ueberwiegen des Einen, niemals auf einem gänzlichen Ausschließen des Entgegengesetzten"}]}, {"page_pdf": 1646, "page_book": 421, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "footnote", "text": "1 Man vergl. die spätere Gestaltung dieser Gedanken über Prometheus in der Einleitung in die Philosophie der Mythologie, 23[.] Vorlesung. D. H."}, {"type": "paragraph", "text": "beruhen, so wird dasselbe nothwendig auch von der griechischen Poesie gelten. Wenn wir daher behaupten, daß Endlichkeit, Begrenzung das Grundgesetz aller griechischen Bildung sey, so ist damit nicht behauptet, daß in ihr überall kein Regen des Entgegengesetzten, des Unendlichen wahrnehmbar sey. Es läßt sich vielmehr der Punkt sehr bestimmt bezeichnen, bei welchem es entschieden hervortrat. Ohne Zweifel war es der Zeitpunkt des entstehenden Republikanismus, mit welchem auch der Ursprung vorzüglich der lyrischen Kunst und der Tragödie als gleichzeitig angenommen werden kann1. Aber eben dieß ist der auffallendste Beweis, daß diese entschiedenere und bis zu einer gewissen Aeußerung durchgedrungene Regung des Unendlichen in der griechischen Bildung durchaus nachhomerisch ist. Nicht als ob nicht früher schon in Griechenland unmittelbarer aufs Unendliche sich beziehende Gebräuche und religiöse Handlungen gewesen wären, sie schlossen sich gleich ursprünglich als Mysterien von dem Allgemeingültigen und der Mythologie ab. Es sollte nicht schwer fallen, zu beweisen, daß alle mystischen Elemente - so will ich bis zur näheren Erklärung vorläufig alle sich unmittelbar auf das Unendliche beziehenden Begriffe nennen - daß alle solche Elemente der hellenischen Bildung ursprünglich fremd waren, sowie sie sich selbige auch späterhin nur in der Philosophie aneignen konnte. Die ersten Regungen der Philosophie, deren Beginn überall der Begriff des Unendlichen ist, zeigten sich selbst zuerst in mystischen Gedichten, dergleichen die von Platon und Aristoteles erwähnten orphischen Lieder, die Gedichte des Musäos, die zahlreichen Poeme des Sehers und Philosophen Epimenides. Jemehr sich in der griechischen Bildung das Princip des Unendlichen entwickelte, desto mehr bestrebte man sich, dieser mystischen Poesie ein höheres Ansehen des Alters zu geben und ihren Ursprung selbst über das Zeitalter Homers hinaus zu rücken. Allein schon Herodotos widerspricht dem, wenn er sagt, daß alle Dichter, die für älter ausgegeben werden als Homeros und Hesiodos, jünger seyen. Homer kennt keine Orgien, keinen Enthusiasmus im Sinne der Priester und der Philosophen."}, {"type": "footnote", "text": "1 Fr. Schlegels Geschichte der Poesie der Griechen und Römer, S. 24."}, {"type": "paragraph", "text": "So wenig bedeutend aber diese mystischen Elemente für die Geschichte der hellenischen Poesie waren, so merkwürdig sind sie doch uns als die Regungen des entgegengesetzten Pols in der griechischen Bildung, und wenn wir den Gegensatz, an seinem höchsten Punkte angefaßt, als Christenthum und Heidenthum bezeichnen, so deuten sie uns im Heidenthum Elemente des Christenthums an, wie wir dagegen im Christenthum gleiche Elemente des Heidenthums nachweisen können. Sieht man auf das *Wesen *der griechischen Dichtungen, so hat sich in ihnen Endliches und Unendliches so durchdrungen, daß man in ihnen kein Symbolisiren des einen durch das andere, sondern nur das absolute Gleichsetzen beider wahrnehmen kann. Sieht man aber auf die * Form*, so ist jene ganze Ineinsbildung des Unendlichen und Endlichen wieder im Endlichen oder im Besonderen dargestellt. Da nun, wo die Einbildungskraft nicht bis zur völligen Wechseldurchdringung beider ging, konnten nur die zwei Fälle stattfinden, daß entweder das Unendliche durch das Endliche, oder das Endliche durch das Unendliche symbolisirt wurde. Das Letzte war der Fall des Orientalen. Der Grieche zog nicht das"}]}, {"page_pdf": 1647, "page_book": 423, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "einseitig-Unendliche, sondern das schon mit dem Endlichen durchdrungene Unendliche, d.h. das ganze Göttliche, das Göttliche, sofern es Allheit ist, herab in die Endlichkeit. Die griechische Poesie ist *insofern *die absolute, und hat als Indifferenzpunkt keinen Gegensatz außer sich. Der Orientale war überall nicht bis zur Durchdringung selbst gekommen; nicht nur also, daß in seiner Mythologie Gestalten von wahrhaft unabhängigem poetischem Leben unmöglich sind, seine ganze Symbolik ist auch noch einseitig, nämlich Symbolik des Endlichen durch das Unendliche; er ist daher mit seiner Einbildungskraft ganz in der übersinnlichen oder Intellektualwelt, wohin er auch die Natur versetzt, statt umgekehrt die Intellektualwelt - als die, worin Endliches und Unendliches eins sind - durch die Natur zu symbolisiren und so ins Reich des Endlichen zu versetzen, und insofern kann man wirklich sagen, daß seine Poesie das Umgekehrte der griechischen ist. Wenn wir unter dem Unendlichen das absolut Unendliche, demnach"}, {"type": "paragraph", "text": "die vollkommene Ineinsbildung des Unendlichen und Endlichen verstehen, so ging die Richtung der griechischen Phantasie vom Unendlichen oder Ewigen zum Endlichen, die der orientalischen dagegen vom Endlichen zum Unendlichen, aber so, daß in der Idee des Unendlichen die Entzweiung nicht nothwendig aufgehoben war. Vielleicht ist dieß am bestimmtesten darzustellen an der persischen Lehre, soweit sie aus den Zendbüchern und andern Quellen bekannt ist. Die persische und indische Mythologie aber sind unter den idealistischen Mythologien ohne Zweifel die berühmtesten. Es wäre ungeschickt, auf die indische Mythologie dasselbe anwenden zu wollen, was von der griechischen (realistischen) gilt, und die Forderung zu machen, ihre Gestalten unabhängig, an sich, rein als das, was sie sind, zu betrachten. Von der andern Seite ist aber nicht zu leugnen , daß die indische Mythologie der poetischen Bedeutung mehr als die persische sich genähert hat. Wenn diese in allen ihren Bildungen bloßer Schematismus bleibt, so erhebt sich jene wenigstens zur allegorischen, und das Allegorische ist das herrschende poetische Princip in ihr. Daher die Leichtigkeit oberflächlich poetischer Köpfe, sie sich anzueignen. Zum Symbolischen geht es nicht. Allein da sie doch wenigstens durch Allegorie poetisch ist, so konnte in der weiteren Ausbildung der allegorischen Seite allerdings wahre Poesie entstehen, so daß die indische Bildung Werke ächter Dichtkunst aufzuweisen hat. Der Grund oder Stamm ist unpoetisch; das aber, was gleichsam unabhängig von diesem sich für sich selbst gebildet hat, ist poetisch. Die herrschende Farbe auch der dramatischen Gedichte der Indier, z.B. der Sakontala und des Sehnsucht- und Wollust-athmenden Gedichts der Gita-Govin, ist die lyrisch-epische. Diese Gedichte sind für sich nicht allegorisch, und wenn etwa die Liebschaften und die Wandelbarkeit des Gottes Krischna (welche das Sujet des zuletzt angeführten Gedichtes ist) ursprünglich allegorische Bedeutung hatten, so haben sie solche wenigstens in diesem Gedicht verloren. Aber obgleich diese Werke wenigstens als *Ganzes *nicht allegorisch sind, so ist doch die innere Construktion derselben ganz im Geiste der Allegorie. Man kann allerdings nicht wissen, wie weit die Poesie der Indier sich zur Kunst gebildet hätte,"}, {"type": "paragraph", "text": "wäre ihnen nicht durch ihre Religion alle bildende Kunst als Plastik versagt gewesen. Man wird den Geist ihrer Religion, ihrer Gebräuche und Poesie am besten fassen, wenn man als den Grundtypus derselben den Pflanzenorganismus denkt. Die Pflanze ist für sich wieder in der organischen Welt das allegorische Wesen. Farbe und Duft, diese stille Sprache, ist ihr einziges Organ, wodurch sie sich zu erkennen gibt. Dieser Pflanzencharakter spricht sich in ihrer ganzen Bildung aus, namentlich z.B. der Architektur (Arabesken); sie ist von den plastischen Künsten die einzige, in der sie es zu einem bedeutenden Grad"}]}, {"page_pdf": 1648, "page_book": 425, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "von Ausbildung gebracht haben. Architektur an sich ist noch eine allegorische Kunst, der das Schema der Pflanze zu Grunde liegt, ganz besonders der indischen, von der man sich des Gedankens kaum erwehren kann, daß sie der *gothisch *genannten ihren Ursprung gegeben habe (worauf wir später wieder zurückkommen werden). Wir mögen soweit zurückgehen in der Geschichte menschlicher Bildung als wir können, so finden wir schon zwei getrennte Ströme von Poesie, Philosophie und Religion, und der allgemeine Weltgeist offenbart sich auch auf diese Weise unter den zwei entgegengesetzten Attributen, des Idealen und Realen. Die realistische Mythologie hat ihre Blüthe in der griechischen erreicht, die idealistische sich im Lauf der Zeit ganz in das Christenthum ergossen. Niemals konnte der Lauf der alten Geschichte so abbrechen, eine wirkliche neue Welt beginnen, die mit dem Christenthum wirklich begonnen *hat*, ohne einen gleichsam durch das ganze Menschengeschlecht greifenden Abfall. Die, welche die Dinge nur in der Einzelheit aufzufassen im Stande sind, mögen es auch in Ansehung des Christenthums so halten. Für einen höheren Gesichtspunkt war es in seinem ersten Entstehen selbst eine bloß einzelne Erscheinung des *allgemeinen *Geistes, der sich bald der ganzen Welt bemächtigen sollte. Nicht das Christenthum hat den Geist der damaligen Jahrhunderte einseitig erschaffen; es war * von* diesem allgemeinen Geist zuerst nur eine Aeußerung, war das Erste, was diesen Geist *aussprach*, und ihn dadurch fixirte."}, {"type": "paragraph", "text": "Es ist nothwendig, auf die historischen Anfänge des Christenthums zurückzugehen, selbst um nachher die Poesie, die sich aus ihm zu einem unabhängigen Ganzen gestaltet hat, zu begreifen. Um diese Art der Poesie, die von der antiken nicht bloß gradweise, sondern ganz verschieden ist, nur überhaupt zuerst in ihrem Gegensatz zu fassen, müssen wir die früheren Zustände, die der späteren Verklärung zur Poesie vorangehen, aufzufassen suchen. Wir erkennen in der ersten Epoche des Christenthums gleich zwei ganz verschiedene Momente. Der erste, wo es sich ganz innerhalb der Mutterreligion - der jüdischen - als Glaube einer einzelnen Sekte hielt; weiter hatte es Christus selbst nicht geführt, obgleich er, soviel man von seiner Geschichte weiß, von einer sehr hohen Ahndung der weiteren Verbreitung seiner Lehre erfüllt war und gewissermaßen seyn mußte. Die jüdische Mythologie, welche sich erst, nachdem diese Nation durch ihre politische Unterjochung mit fremden Völkern in nähere Berührung kam, einigermaßen geläutert hatte - indem sie alle höheren Vorstellungsarten, selbst den philosophischen Monotheismus bloß fremden Völkern verdankte - war in ihrem Ursprung und an sich eine ganz realistische Mythologie. In diesen rohen Stoff senkte Christus den Keim einer höheren Sittlichkeit, es sey nun, daß er diesen aus sich ganz unabhängig geschöpft habe oder nicht (Hypothese eines Verhältnisses Christi zu den Essäern). Wir können nicht beurtheilen, wieweit sich die besondere Wirkung Christi erstreckt hätte ohne die nachherigen Ereignisse. Was seiner Sache den höchsten Schwung gab, war die letzte Katastrophe seines Lebens und das vielleicht beispiellose Ereigniß, daß er den Kreuzestod überwand und lebendig wieder hervorging, eine Thatsache, welche etwa als Allegorie wegerklären und also als Faktum leugnen zu wollen, historisch wahnsinnig ist, da diese Eine Begebenheit die ganze Geschichte des Christenthums gemacht hat. Alle Wunder, die man nachher auf dieß Eine Haupt häufte, hätten dieß nicht vermocht. Von diesem Augenblick an war Christus der Heros einer neuen Welt, das Niedrigste ward zum Höchsten, das Kreuz, das Zeichen der tiefsten Schmach, ward zum Zeichen der Welteroberung."}]}, {"page_pdf": 1649, "page_book": 427, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "In den ersten schriftlichen Denkmälern der Geschichte des Christenthums rührt sich schon der Gegensatz des realistischen und idealistischen Princips im Christenthum. Der Verfasser des Evangeliums Johannis ist von den Ideen einer höheren Erkenntniß begeistert und nimmt diese zur Einleitung in seine einfache und stille Erzählung von dem Leben Christi; die andern erzählen im jüdischen Geist und umgeben seine Geschichte mit Fabeln, die nach Anleitung der Weissagungen im A.T. erfunden waren. Sie sind a priori überzeugt, daß diese Geschichten sich so ereignet haben müssen, da sie im A.T. vom Messias prophezeit sind, deßwegen setzen sie hinzu: \"auf daß erfüllet würde, was geschrieben steht\", und in Beziehung auf sie kann man sagen: Christus sey eine historische Person, deren Biographie schon vor ihrer Geburt verzeichnet gewesen. Es ist wichtig gleich mit diesen ersten Regungen der Gegensätze im Christenthum zu bemerken, wie das realistische Princip durchaus das Uebergewicht behauptet und auch in der Folge erhält, welches nothwendig war, wenn das Christenthum sich nicht ebenso wie alle andern ursprünglich, orientalischen Religionen in Philosophie auflösen sollte. Schon zu der Zeit als die ersten Berichte vom Leben Jesu abgefaßt wurden, bildete sich im Christenthum selbst ein engerer Kreis geistigerer Erkenntniß, Gnosis genannt. Es beweist ein richtiges Gefühl, ein sicheres Bewußtseyn dessen, was sie wollen mußten, in den ersten Verbreitern des Christenthums, daß sie sich wie einmüthig dem Eindringen philosophischer Systeme widersetzten. Sie entfernten mit offenbarer Ueberlegung alles, was nicht universalhistorisch, nicht Sache aller Menschen werden konnte. Wie sich das Christenthum ursprünglich aus dem Haufen der Elenden und Verachteten seine Anhänger geholt, und gleichsam in seinem Ursprung schon die demokratische Richtung hatte, so suchte es auch diese Popularität fortwährend zu erhalten. Der erste große Schritt zur künftigen Bildung des Christenthums war der Eifer des Apostels Paulus, der jene Lehre zuerst unter die Heiden trug. Nur in dem fremden Boden konnte es sich gestalten. Es war nothwendig, daß die orientalischen Ideen in den occidentalischen"}, {"type": "paragraph", "text": "Boden verpflanzt wurden. Allerdings war dieser Boden für sich unfruchtbar, das ideale Princip mußte vom Orient kommen, aber auch dieses war für sich wie in den orientalischen Religionen reines Licht, reiner Aether, gestalt- und sogar farblos. Nur in der Verbindung mit dem Entgegengesetzten konnte es Leben entzünden. Wo ganz verschiedenartige Elemente sich berühren, da erst bildet sich der chaotische Stoff, der der Anfang alles Lebens ist. Nimmermehr aber hätte sich der christliche Stoff zur Mythologie gebildet, wäre das Christenthum nicht universalhistorisch geworden. Denn ein universeller Stoff ist die erste Bedingung aller Mythologie. Der Stoff der griechischen Mythologie war die Natur, die allgemeine Anschauung des Universums als Natur, der Stoff der christlichen die allgemeine Anschauung des Universums als Geschichte, als einer Welt der Vorsehung. Dieß ist der eigentliche Wendepunkt der antiken und modernen Religion und Poesie. Die moderne Welt beginnt, indem sich der Mensch von der Natur losreißt, aber da er noch keine andere Heimath kennt, so fühlt er sich verlassen. Wo ein solches Gefühl sich über ein ganzes Geschlecht ausbreitet, wendet es sich freiwillig oder durch inneren Trieb gezwungen der ideellen Welt zu, um sich dort einheimisch zu machen. Ein solches Gefühl war über die Welt verbreitet, als das Christenthum entstand. Griechenlands Schönheit war dahin. Rom, welches alle Herrlichkeit der Welt auf sich gehäuft hatte, erlag unter seiner eignen Größe; die vollste Befriedigung durch alles Objektive führte von selbst den Ueberdruß und die Hinneigung zum Ideellen herbei. Ehe noch das Christenthum seine Macht nach Rom erstreckt hatte, schon unter den ersten Kaisern, war diese sittenlose Stadt mit orientalischem Aberglauben erfüllt, Sterndeuter und Magier selbst die Rathgeber des Staatsoberhaupts, die Orakel der Götter hatten ihr Ansehen verloren, noch eh' sie gänzlich verstummten. Das allgemeine Gefühl, daß eine neue Welt kommen müßte, da die alte nicht weiter fortschreiten konnte, lag gleich einer schwülen Luft,"}]}, {"page_pdf": 1650, "page_book": 428, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "die eine große Bewegung der Natur voraus verkündet, auf der ganzen damaligen Welt, und eine allgemeine Ahndung schien alle Gedanken nach dem"}, {"type": "paragraph", "text": "Orient hinzuziehen, als ob dorther der Retter kommen würde, wovon selbst in den Nachrichten des Tacitus und Sueton Spuren liegen. In der Weltherrschaft Roms, kann man sagen, hat der Weltgeist zuerst die Geschichte als Universum angeschaut; von ihr als dem Mittelpunkt aus bildeten und verketteten sich alle Bestimmungen der Völker, und, gleichsam nur seine Absicht einer neuen *Welt *aufs deutlichste auszusprechen, führte der Weltgeist - wie ein großer Sturmwind oft ganze Schaaren von geflügelten Thieren über ein Land führt, oder große Gewässer ungeheure Massen gegen * Eine *Stelle gewälzt haben, so führte der Weltgeist noch unbekannte, entlegene Völker her auf den Schauplatz der Weltherrschaft, um mit den Trümmern des dahinstürzenden Roms den Stoff aller Klimate und aller Völker zu vermischen. Wer nicht an den Zusammenhang der Natur und der Geschichte glaubt, der müßte es, wenn er diesen Punkt auffaßte. In demselben Augenblick, wo der Weltgeist ein großes, nie gesehenes Schauspiel vorbereitet, auf eine neue Welt sinnt und zürnend auf die stolze Größe Roms, welches die Herrlichkeit der ganzen Welt, indem es sie in sich versammelte, zugleich in sich begrub, die damalige Welt zum Gericht reif sieht, führt eine Bestimmung der Natur, eine Nothwendigkeit, die so bestimmt ist, als die, welche die großen Perioden der Erde und die Bewegung ihrer Pole lenkt, Massen fremder Horden von allen Seiten gegen diesen Mittelpunkt heran, und eine Naturnothwendigkeit führt das aus, was der Geist der Geschichte in seinen Planen entworfen hat. Ich will hier also nur meinen Unglauben an das Unzureichende aller historischen Erklärungen der Völkerwanderung bekennen und gestehen, daß ich ihren Grund weit bestimmter in einem allgemeinen, auch die Natur bestimmenden Gesetz, als einem bloß historischen Grund, suchen möchte, einem Naturgesetz, welches rohe, barbarische Nationen blinder leitet. Was in der Natur, dem Gesetz der Endlichkeit gemäß, stiller, beschränkter geschieht, spricht sich in der Geschichte in größeren Perioden und lauter aus, und was die periodische Declination der Magnetnadel physisch, war historisch betrachtet die Völkerwanderung. Von diesem Zeitpunkt, dem der höchsten Macht und der Zertrümmerung"}, {"type": "paragraph", "text": "des römischen Reichs, beginnt eigentlich zuerst, was wir Universalhistorie nennen können. Jenseits desselben ist, wie in * dem *Theil des Universums, der die *reale *Seite desselben darstellt, das *Besondere* herrschend; ein besonderes Volk, wie das der Griechen, wohnend in engen Grenzen und auf wenigen Eilanden, ist dort die Gattung, hier dagegen wird das Allgemeine herrschend und das Besondere zerfällt darin. Die ganze alte Geschichte kann als die tragische Periode der Geschichte betrachtet werden. Auch das Schicksal ist Vorsehung, aber im Realen angeschaut, so wie die Vorsehung das Schicksal ist, aber im Idealen angeschaut. Die ewige Nothwendigkeit offenbart sich in der Zeit der Identität mit ihr als Natur. So in den Griechen. Mit dem Abfall von ihr offenbart sie sich als Schicksal in herben und gewaltigen Schlägen. Um sich dem Schicksal zu entziehen , ist nur Ein Mittel, sich in die Arme der Vorsehung zu werfen. Dieß war das Gefühl der Welt in jener Periode der tiefsten Umwandlung, als das Schicksal an allem Schönen und Herrlichen des Alterthums seine letzte Tücke übte. Da verloren die alten Götter ihre Kraft, die Orakel schwiegen, die Feste verstummten und ein bodenloser Abgrund voll wilder Vermischung aller Elemente der gewesenen Welt schien sich vor dem menschlichen Geschlecht zu öffnen. Ueber diesem finstern Abgrund erschien als das einzige Zeichen des Friedens und des"}]}, {"page_pdf": 1651, "page_book": 430, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Gleichgewichts der Kräfte das Kreuz, gleichsam der Regenbogen einer zweiten Sündfluth, wie es ein spanischer Dichter nennt, - zu einer Zeit, wo keine Wahl übrig blieb, an dieses Zeichen zu glauben. Wie nun aus diesem trüben Stoff sich endlich die zweite Welt der Poesie losgewunden, wie er sich zu einem mythischen Stoff gebildet hat, davon werde ich die *Hauptzüge *wenigstens angeben. (Wenn ich die ganze Totalität des mythischen Stoffs, der im Christenthum liegt, dargestellt haben werde, werde ich das Resultat des Ganzen wieder zu wenigen Hauptsätzen vereinigt darlegen können). Um die Mythologie des Christenthums in ihrem Princip zu fassen, gehen wir auf den Punkt ihrer Entgegensetzung mit der griechischen"}, {"type": "paragraph", "text": "zurück. In dieser wird das Universum angeschaut als Natur, in jener aber als moralische Welt. Der Charakter der Natur ist ungetrennte Einheit des Unendlichen mit dem Endlichen: das Endliche ist herrschend, aber in ihm als der gemeinschaftlichen Hülle liegt der Keim des Absoluten, der ganzen Einheit des Unendlichen und Endlichen. Der Charakter der moralischen Welt - die Freiheit - ist *ursprünglich *Entgegensetzung des Endlichen und Unendlichen mit der absoluten Forderung der Aufhebung des Gegensatzes. Aber selbst diese, da sie auf einem Einbilden des Endlichen ins Unendliche beruht, steht wieder unter der Bestimmung der Unendlichkeit, so daß der Gegensatz zwar immer im Einzelnen, aber doch nie im Ganzen aufgehoben seyn kann. Wenn also die in der griechischen Mythologie erfüllte Forderung Darstellung des Unendlichen als solchen im Endlichen, demnach Symbolik des Unendlichen war, so liegt dem Christenthum die entgegengesetzte zu Grunde, das Endliche ins Unendliche aufzunehmen, d.h. es zur Allegorie des Unendlichen zu machen. Im ersten Fall gilt das Endliche etwas für sich, denn es nimmt das Unendliche in sich selbst auf, im andern Fall ist das Endliche für sich selbst nichts, sondern nur, sofern es das Unendliche bedeutet. Unterordnung des Endlichen unter das Unendliche ist also Charakter einer solchen Religion. Im Heidenthum ist das Endliche als in sich selbst unendlich so weit geltend gegen das Unendliche, daß in ihm sogar Aufstand gegen das Göttliche möglich, und dieser sogar Princip der Erhabenheit ist. Im Christenthum ist unbedingte Hingabe an das Unermeßliche, und dieß einziges Princip der Schönheit. - Aus dieser Entgegensetzung lassen sich alle anderen möglichen Gegensätze des Heidenthums und Christenthums vollkommen begreifen; z.B. in jenem die heroischen, in diesem die milden und sanften Tugenden herrschend, dort strenge Tapferkeit, hier Liebe oder wenigstens Tapferkeit durch Liebe gemäßigt und gemildert, wie in den Zeiten der Chevalerie. Man könnte glauben, daß in der Idee des Christenthums, die eine Mehrheit von Personen in der Gottheit behauptet, eine Spur von Polytheismus sey; daß aber die Dreieinigkeit *als solche *nicht *als*"}, {"type": "paragraph", "text": "*Symbol *einer Idee betrachtet werden kann, erhellt daraus, daß die drei Einheiten in der göttlichen Natur selbst ganz ideal gedacht werden, und selbst Ideen, aber nicht Symbole von Ideen sind, daß diese Idee von ganz philosophischem Gehalt ist. Das Ewige ist Vater aller Dinge, der nie aus seiner Ewigkeit herausgeht, aber sich von Ewigkeit in zwei mit ihm gleich ewige Formen gebiert, das Endliche, welches der an sich absolute, in der Erscheinung aber leidende und menschwerdende Sohn Gottes ist, dann der ewige Geist, das Unendliche, in dem alle Dinge eins sind. Ueber dem der alles auflösende Gott. Man kann sagen, daß, wenn diese Ideen an und für sich fähig wären, poetische Realität zu haben, sie solche durch ihre Behandlung im Christenthum erlangt hätten. Sie wurden gleich anfänglich völlig"}]}, {"page_pdf": 1652, "page_book": 432, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "unabhängig von ihrer speculativen Bedeutung, ganz historisch, buchstäblich genommen. Aber es war der ersten Anlage nach unmöglich, daß sie sich symbolisch gestalten konnten. * Dante*, der im letzten Gesang seines Paradieses zur Anschauung Gottes gelangt, sieht in der Tiefe der klaren Substanz der Gottheit drei Lichtkreise von drei Farben und Einem Umfang; einer schien nur von dem andern wie Regenbogen von Regenbogen reflektirt, und der dritte war der Brennpunkt, der nach allen Seiten gleich ausathmete. Aber er selbst verglich seinen Zustand mit dem des Geometers, der sich ganz auf die Messung des Kreises heftet, und das Princip nicht findet, dessen er bedarf. Nur die Idee des *Sohns *ist im Christenthum zur Gestalt geworden; aber auch dieß nur durch Verlust ihres höchsten Sinns. Wenn in dem Christenthum der Sohn Gottes eine wahrhaft symbolische Bedeutung haben sollte, so hatte er diese als Symbol der ewigen Menschwerdung Gottes im Endlichen. Also dieß sollte er bedeuten und * zugleich * eine einzelne Person seyn; aber im Christenthum ist er *bloß *dieses, seine Beziehung ist nur historisch, keine Beziehung auf Natur. Christus war gleichsam der Gipfel der Menschwerdung Gottes, und demnach der Mensch gewordene Gott selbst. Aber wie verschieden zeigt sich diese Menschwerdung Gottes im Christenthum von der Verendlichung des Göttlichen im Heidenthum. Es ist im Christenthum nicht"}, {"type": "paragraph", "text": "um das Endliche zu thun; Christus kommt in die Menschheit in ihrer Niedrigkeit und zieht Knechtsgestalt an, um zu leiden und das Endliche in seinem Beispiel zu vernichten. Hier ist keine Vergötterung der Menschheit, wie in der griechischen Mythologie; es ist eine Menschwerdung Gottes in der Absicht, das von Gott abgefallene Endliche durch die Vernichtung in seiner Person mit Gott zu versöhnen. Nicht das Endliche wird hier absolut und Symbol des Unendlichen; der Menschgewordene Gott ist keine bleibende, ewige Gestalt, sondern nur eine von Ewigkeit zwar beschlossene, in der Zeit aber vergängliche Erscheinung. In Christus wird viel mehr das Endliche durch das Unendliche als dieses durch jenes symbolisirt. Christus geht in die übersinnliche Welt zurück, und verheißt statt seiner den Geist - nicht das ins Endliche kommende, im Endlichen bleibende Princip, sondern das ideale Princip, welches vielmehr das Endliche ins Unendliche und zum Unendlichen führen soll. Es ist, als ob Christus als das in die Endlichkeit gekommene und sie *in* seiner menschlichen Gestalt Gott opfernde Unendliche den Schluß der *alten *Zeit machte; er ist bloß da, um die Grenze zu machen - der letzte Gott. Nach ihm kommt der Geist, das ideelle Princip, die herrschende Seele der neuen Welt. Inwiefern die alten Götter gleichfalls das Unendliche im Endlichen, aber mit vollkommener Realität, waren, mußte das wahre Unendliche - der wahre Gott - endlich werden, um an sich die Vernichtung des Endlichen zu zeigen. Insofern war Christus zugleich der Gipfel und das Ende der alten Götterwelt. Dieß beweist, daß die Erscheinung Christi, weit entfernt der Anfang eines neuen Polytheismus zu seyn, vielmehr die Götterwelt absolut schloß. Es ist nicht leicht zu sagen, inwiefern eigentlich Christus eine poetische Person ist. Nicht rein als Gott; denn er ist in seiner Menschheit nicht Gott, wie es die griechischen Götter unbeschadet ihrer Endlichkeit sind, sondern wahrer Mensch, selbst den Leiden der Menschheit untergeordnet. Nicht als Mensch, denn er ist doch auch nicht von allen Seiten zum Menschen begrenzt. Die Synthesis dieser Widersprüche liegt nur in der Idee eines *freiwillig leidenden *Gottes. Aber eben dadurch ist er die antipodische Entgegensetzung mit den alten"}, {"type": "paragraph", "text": "Göttern. Diese leiden nicht, sondern sind selig in ihrer Endlichkeit. Auch Prometheus, selbst ein Gott, leidet nicht, da sein Leiden zugleich Thätigkeit und Empörung ist. Das reine Leiden kann nie Gegenstand"}]}, {"page_pdf": 1653, "page_book": 434, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der Kunst seyn. Selbst als Mensch genommen kann Christus doch nie anders als duldend genommen werden, weil die Menschheit bei ihm übernommene * Last*, nicht Natur ist, wie den griechischen Göttern, und seine menschliche Natur durch ihre Theilnahme an der göttlichen selbst für die Leiden der Welt fühlbarer wird, und auffallend genug ist, daß die ächte Malerei Christum am liebsten und häufigsten als Kind abgebildet hat, gleichsam als ob, wie jemand sehr richtig bemerkt hat, das Problem dieser wunderbaren - nicht Indifferenz, sondern - Mischung der göttlichen und menschlichen Natur nur in der Unbestimmtheit des Kindes vollkommen lösbar wäre. Den gleichen Charakter des Leidens und der Demuth trägt auch das Bild der *Mutter Gottes. * Auch dieses hat, wenn vielleicht nicht in den Ideen der *Kirche*, doch durch eine innere Nothwendigkeit eine symbolische Bedeutung. Es ist Symbol der allgemeinen Natur oder des mütterlichen Princips aller Dinge, welches ewig jungfräulich blüht. Allein in der Mythologie des Christenthums hat auch dieses Bild keine Beziehung auf Materie (daher keine symbolische Bedeutung), und nur die moralische Beziehung ist geblieben. Maria bezeichnet als Urbild den Charakter der Weiblichkeit, den das ganze Christenthum hat. Das Vorherrschende des Antiken ist das Erhabene, Männliche, des Modernen das Schöne, demnach das Weibliche. Es ist ganz dem gemäß, was überhaupt als Princip des Christenthums anzusehen ist: daß es keine vollendeten Symbole, sondern nur symbolische *Handlungen *hat. Der ganze Geist des Christenthums ist der des Handelns. Das Unendliche * ist* nicht mehr im Endlichen, das Endliche kann nur ins Unendliche übergehen; nur in diesem können beide eins werden. Die Einheit des Endlichen und Unendlichen ist also im Christenthum Handlung. Die erste symbolische Handlung Christi ist die Taufe, wo der Himmel sich ihm verband, der Geist in sichtbarer Gestalt herabkam, die andere sein Tod, wo er den Geist"}, {"type": "paragraph", "text": "dem Vater wieder befahl, zurückgab, und an sich das Endliche vernichtend, Opfer für die Welt wird. Die symbolischen Handlungen werden im Christenthum fortgesetzt durch das *Nachtmahl *und die *Taufe.* Das Nachtmahl hat wieder zwei Seiten, von denen es betrachtet werden kann, die ideelle, inwiefern es das Subjekt ist, das sich den Gott schafft, und in das jene geheimnißvolle Einigung des Unendlichen und Endlichen fällt, und die symbolische. Inwiefern die Handlung, wodurch das Endliche hier zugleich das Unendliche wird, als Andacht in das empfangende Subjekt selbst fällt, insofern ist sie nicht symbolisch, sondern *mystisch; *inwiefern sie aber eine äußere Handlung ist, ist sie symbolisch. (Wir werden auf diesen sehr wichtigen Unterschied des Mystischen und Symbolischen in der Folge zurückkommen). Inwiefern nun die *Kirche *sich als den sichtbaren Leib Gottes betrachtete, wovon alle einzelnen die Glieder wären, constituirte sie sich selbst durch Handlung. Das öffentliche Leben der Kirche konnte also allein symbolisch, ihr Cultus ein lebendiges Kunstwerk, gleichsam ein geistliches Drama seyn, woran jedes Glied theilhatte. Die populäre Richtung des Christenthums, das Princip der Kirche, *alles *wie ein Ocean in sich aufzunehmen, auch die Elenden und Verachteten nicht von sich auszuschließen, das Streben mit Einem Wort, katholisch, universell zu seyn, mußte sie bald bestimmen, eine äußerliche Totalität, gleichsam einen Leib sich zu geben; und so war die Kirche selbst in der Ganzheit ihrer Erscheinung symbolisch und das Symbol der Verfassung des Himmelreichs selbst. Das Christenthum als die in Handlung ausgesprochene Ideenwelt war ein sichtbares Reich, und bildete sich nothwendig zur *Hierarchie*, deren Urbild in der Ideenwelt lag. In den Menschen fiel hier die Forderung, Symbol der Ideenwelt zu seyn, nicht mehr in die Natur, in das Handeln, nicht mehr in das Seyn. Die Hierarchie war das einzige Institut seiner Art von einer Größe des Gedankens, die insgemein viel zu einseitig gefaßt wird. Ewig merkwürdig wird es bleiben, daß eben mit dem Untergang des römischen Reichs, welches den größten Theil der bekannten Welt zur Totalität vereinigt hatte, das"}]}, {"page_pdf": 1654, "page_book": 435, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Christenthum mit schnellen Schritten zur Universalherrschaft fortging. Nicht nur daß es in einem Zeitalter des Unglücks und eines zerfallenden Reichs, dessen Macht bloß zeitlich war, und das nichts enthielt, wozu der Mensch in einem solchen Zustand hätte flüchten können, wo der Muth und gleichsam das Herz zum Objekt verloren war: nicht nur, sage ich, daß es in einem *solchen* Zeitalter in einer Religion, welche Verleugnung lehrte und sogar zum Glück machte, ein allgemeines Asyl öffnete, es that noch mehr, es verband, sobald es sich zur Hierarchie entwickelte, alle Theile der kultivirten Welt und ging von seinem Beginn wie eine Universalrepublik, aber auf geistliche Eroberungen aus. (Proselytenmacherei, Bekehrung der Heiden, Verjagen der Saracenen und Türken aus Europa, Missionen in späteren Zeiten). Bei dem großen, universellen Sinn der Kirche konnte ihr nichts fremd bleiben, nichts, was in der Welt gewesen, schloß sie von sich aus: sie konnte alles mit sich vereinigen. Vorzüglich von der Seite des Cultus, als der einzigen, von welcher sie symbolisch seyn konnte, verstattete sie auch dem Heidenthum wieder den Eingang. Der katholische Cultus vereinigte die religiösen Gebräuche der ältesten Völker mit denen der spätesten, nur daß für die meisten in der Folgezeit der Schlüssel verloren gegangen ist. Die ersten Erfinder jener symbolischen Gebräuche, die großen Köpfe, welche den ersten Gedanken und Entwurf zu diesem Ganzen machten und in ihm, als in einem lebendigen Kunstwerk, fortlebten, sind gewiß nicht so einfältig gewesen, um von unsern blödsinnigen Aufklärern übersehen zu werden, die, wenn man sie alle vereinte und hundert Jahre machen ließe - doch nichts als Sandhaufen zusammenbrächten. Der Hauptpunkt, auf den es hier ankommt, ist, einzusehen, wie dem allgemeinen Charakter der Subjektivität und Idealität des Christenthums gemäß das Symbolische hier durchaus in das Handeln (in Handlungen) fallen müsse. Wie die Grundanschauung des Christenthums die historische ist, so ist es nothwendig, daß das Christenthum eine mythologische Geschichte der Welt enthalten müsse. Die Menschwerdung Christi ist selbst nur im Zusammenhang mit einer allgemeinen Vorstellung"}, {"type": "paragraph", "text": "der *Menschengeschichte *denkbar. Es gibt im Christenthum keine wahre Kosmogonie. Was im A.T. davon vorkommt, sind sehr unvollkommene Versuche. Handlung, Geschichte ist überall nur, wo Vielheit ist. Insofern also Handlung in der göttlichen Welt ist, insofern muß auch in ihr Vielheit seyn. Sie kann aber dem Geist des Christenthums nach nicht als *polytheistisch *gedacht werden, also nur durch die Hülfe von Mittelwesen, welche in dem unmittelbaren Anschauen der Gottheit und die ersten Geschöpfe, die ersten Hervorbringungen der göttlichen Substanz sind. Solche Wesen sind im Christenthum die *Engel.* Man könnte vielleicht versucht werden, die Engel als den Ersatz des Polytheismus im Christenthum zu betrachten, um so mehr, da sie ihrem eigenthümlichen Ursprung im Orient nach ebenso bestimmt Personificationen der Ideen sind als die Götter der griechischen Mythologie. Auch ist bekannt, welchen starken Gebrauch die neuern christlichen Dichter, Milton, Klopstock u.a. von diesen Mittelwesen machen zu müssen glaubten, fast so arg als Wieland von den Grazien. Allein der Unterschied ist nur der, daß die griechischen Götter die wirklich * real-*angeschauten Ideen sind, da bei den Engeln sogar noch ihre Leiblichkeit zweifelhaft ist, und sie also selbst wieder unsinnliche Wesen sind. Wollte man die Engel als Personificationen von *Wirkungen *Gottes auf die Sinnenwelt denken, so wären sie als solche in ihrer Unbestimmtheit doch wiederum ein bloßer Schematismus, und also zur Poesie unbrauchbar1. Die Engel und ihre Verfassung haben gleichsam selbst erst einen Leib in der Kirche bekommen, deren Hierarchie ein unmittelbares Abbild des himmlischen Reichs seyn sollte. Deßwegen ist nur die Kirche im"}]}, {"page_pdf": 1655, "page_book": 437, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Christenthum symbolisch. Die Engel sind keine Naturwesen; es fehlt also durchgängig an der Begrenzung; selbst die obersten derselben fließen fast ineinander, und die ganze Masse ist, wie die Heiligenscheine mancher großer italienischer Maler, die in der Nähe genau betrachtet aus lauter kleinen Engelköpfen bestehen, fast breiartig. Es ist, als ob man dieses Zerfließen im Christenthum durch"}, {"type": "footnote", "text": "1 Vergl. I. Abth., Bd. 1, S. 473. D. H."}, {"type": "paragraph", "text": "die einförmigste Thätigkeitsäußerung, die man ihnen geben konnte, nämlich das ewige Singen und Musiciren derselben Art, habe ausdrücken wollen. Die Geschichte der Engel für sich hat also nichts Mythologisches, außer inwiefern sie die der Empörung und der Verstoßung des *Lucifer *in sich begreift, welcher schon eine entschiedenere Individualität und eine realistischere Natur ist. Diese bildet eine wirklich mythologische Ansicht der Geschichte der Welt, obgleich freilich etwas in ungeheurem und orientalischem Styl. Das Reich der Engel auf der einen und des Teufels auf der andern Seite zeigt die reine Geschiedenheit des guten und bösen Princips, welches in allen concreten Dingen gemischt ist. Der Abfall Lucifers, welcher zugleich die Welt mit verderbte und den Tod in sie brachte, ist also eine mythologische Erklärung der concreten Welt, der Mischung des unendlichen und endlichen Princips in den sinnlichen Dingen, da nämlich den Orientalen das Endliche überhaupt vom Argen und in keinem Verhältniß, auch dem der Idee nicht, vom Guten ist. Diese Mythologie erstreckt sich bis an das Weltende, wo nämlich die Scheidung des Guten und Bösen aufs neue vorgehen, und jedes der beiden in seine reine Qualität gestellt werden wird, womit nothwendig Untergang des Concreten, und das Feuer als Symbol des ausgeglichenen Streits im Concreten die Welt verzehren wird. Bis dahin theilt das böse Princip gar *sehr *mit Gott die Herrschaft über die Erde, obgleich die Menschwerdung Christi den ersten Ansatz zu einem ihm entgegengesetzten Reich auf der Erde machte. (Vollständiger wird von dieser orientalischen Maske erst bei der modernen Komödie die Rede seyn können, da nämlich Lucifer in der späteren Zeit allgemein die Rolle der lustigen Person im Universum hat, als einer, der beständig neue Plane entwirft, die ihm in der Regel immer wieder vereitelt werden, der aber so gierig auf Seelen ist, daß er sich sogar zu den niederträchtigsten Diensten hergibt, und doch nachher oft, wegen der beständigen Bereitschaft der Gnadenmittel und der Kirche, wenn er seiner Sache am gewissesten zu seyn glaubt, mit langer Nase abziehen muß. Wir"}, {"type": "paragraph", "text": "Deutsche sind ihm ganz besonders viel Obligation schuldig, da wir ihm unsere mythologische Hauptperson, den Doktor Faust, verdanken. Andere theilen wir mit anderen Nationen, diesen haben wir ganz für uns allein, da er recht aus der Mitte des deutschen Charakters und seiner Grundphysiognomie wie geschnitten ist). Unter einem Volk, in dessen Poesie die Begrenzung, das Endliche, herrschend ist, ist die Mythologie und die Religion Sache der Gattung. Das Individuum kann sich zur Gattung constituiren und wahrhaft mit ihr eins seyn, wo dagegen das Unendliche, das Allgemeine herrschend ist, kann das Individuum nie zugleich zur Gattung werden, es ist Negation der Gattung. Hier kann also die Religion nur durch den Einfluß einzelner von überlegener Weisheit sich verbreiten, die nur persönlich vom Allgemeinen und Unendlichen erfüllt, demnach Propheten, Seher, gottbegeisterte Menschen sind. Die Religion nimmt hier"}]}, {"page_pdf": 1656, "page_book": 439, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "nothwendig den Charakter einer * geoffenbarten Religion *an, und ist darum schon in ihrem Fundament historisch. Die griechische Religion, als poetische, durch die Gattung lebende Religion, bedurfte keiner historischen Grundlage, so wenig als es die immer offene Natur bedarf. Die Erscheinungen und Gestalten der Götter waren hier ewig; dort, im Christenthum, war das Göttliche nur flüchtige Erscheinung und mußte in dieser festgehalten werden. In Griechenland hatte die Religion keine eigne, von der des Staats unabhängige Geschichte; im Christenthum gibt es eine Geschichte der Religion und der Kirche. Von dem Begriff der Offenbarung ist der des *Wunders *unzertrennlich. Wie der griechische Sinn nach allen Seiten hin reine, schöne Begrenzung forderte, um die ganze Welt für sich zu einer Welt der Phantasie zu erheben, so der orientalische nach allen Seiten hin das Unbegrenzte, das Uebernatürliche, und er fordert auch dieses in einer gewissen Totalität, um von keiner Seite aus seinen übersinnlichen Träumen geweckt zu werden. Der Begriff des Wunders ist in der griechischen Mythologie unmöglich, denn die Götter sind da selbst nicht außer- und übernatürlich, es sind da nicht zwei Welten, eine sinnliche und übersinnliche, sondern *Eine *Welt. Das Christenthum, welches"}, {"type": "paragraph", "text": "nur in der absoluten Entzweiung möglich ist, ist in seinem Ursprung schon auf Wunder gegründet. Wunder ist eine vom empirischen Standpunkt aus angesehene Absolutheit, die in die Endlichkeit fällt, ohne deßwegen ein Verhältniß zu der Zeit zu haben. Das *Wunderbare *in der *historischen *Beziehung ist nun der einzige mythologische Stoff des Christenthums. Es verbreitet sich von der Geschichte Christi und der Apostel aus herab durch die Legende, die Märtyrer- und Heiligengeschichte bis zum romantischen Wunderbaren, welches sich durch die Berührung des Christenthums mit der Tapferkeit entzündete. Es ist uns unmöglich, diesen historisch-mythologischen Stoff zu verfolgen. Es ist nur im Allgemeinen zu bemerken, daß diese Mythologie des Christenthums ursprünglich durchaus auf der Anschauung des Universums als eines Reichs Gottes beruht. Die Geschichten der Heiligen sind zugleich eine Geschichte des Himmels selbst, und sogar die Geschichten der Könige sind verflochten in diese allgemeine Geschichte des Reiches Gottes. Einzig nach dieser Seite hat sich das Christenthum zur Mythologie ausgebildet. So sprach es sich zuerst in dem Gedicht des *Dante *aus, welches das Universum unter den drei Grundanschauungen des Infernums, des Purgatoriums und des Paradieses darstellt. Der Stoff aller seiner Dichtungen aber in diesen drei Potenzen ist doch immer historisch. In Frankreich und Spanien bildete sich der historisch-christliche Stoff vorzüglich zu der Mythologie des Ritterthums aus. Der poetische Gipfel davon ist *Ariosto*, dessen Gedicht das einzige epische wäre, wenn überhaupt in der modernen Poesie bis jetzt ein Epos seyn könnte. In späteren Zeiten, nachdem der Geschmack am Ritterthum verdrängt war, haben die Spanier vorzüglich die Heiligenlegenden zu dramatischen Vorstellungen genutzt. Den Gipfel dieser Poesie bezeichnet der Spanier *Calderon della Barca*, von dem vielleicht noch nicht einmal alles gesagt ist, wenn man ihn dem Shakespeare gleich setzt. Die poetische Ausbildung der christlichen Mythologie in den Werken der bildenden Kunst, vorzüglich der Malerei, in den lyrischen,"}, {"type": "paragraph", "text": "romantisch-epischen und dramatischen Werken der neueren Welt können wir erst in der Folge vollständiger darstellen. Aber eben auch *dieses *ist Gegenstand der modernen Welt, daß alles Endliche in ihr vergänglich ist,"}]}, {"page_pdf": 1657, "page_book": 441, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "und das Absolute in unendlicher Ferne liegt. Alles ist hier dem Gesetz des Unendlichen untergeordnet. Nach diesem Gesetz hat sich auch zwischen die Kunstwelt im Katholicismus und die gegenwärtige Zeit wieder eine neue Masse geworfen. Der Protestantismus entstand und war historisch nothwendig. Preis den Heroen, welche zu jener Zeit, für einige Theile der Welt wenigstens, die Freiheit des Denkens und der Erfindung auf ewig befestigten! Das Princip, das sie weckten, war in der That neu beseelend, und konnte, verbunden mit dem Geist des klassischen Alterthums, unendliche Wirkungen hervorbringen, da es in der That seiner *Natur *nach unendlich war, keine Schranke erkennend, wenn nicht durch das Unglück der Zeit aufs neue gehemmt. Aber die nur zu bald eintretende Folge der Reformation war, daß an die Stelle der alten Autorität eine neue, prosaische, buchstäbliche trat. Die ersten Reformatoren selbst wurden noch von den Wirkungen der Freiheit, die sie gepredigt hatten, überrascht. Diese Sklaverei des Buchstabens konnte noch weniger dauern; aber der Protestantismus konnte nie dazu gelangen, sich eine äußerliche und wahrhaft objektive und endliche Gestalt zu geben. Nicht nur, daß er selbst wieder in Sekten zerfiel, sondern, was in ihm nur Zurücknahme der ewigen Rechte des menschlichen Geistes war, wurde zu einem gänzlich zerstörenden Princip für die Religion und mittelbar für die Poesie. Es entstand jene Erhebung des gemeinen Menschenverstandes, des Werkzeugs bloß weltlicher Angelegenheiten, zum Urtheil über geistliche Angelegenheiten. Höchster Repräsentant dieses Menschenverstandes - Voltaire. Eine trübere und unlustigere Freidenkerei entwickelte sich in England. Die deutschen Theologen machten die Synthesis. Ohne es mit dem Christenthum oder der Aufklärung verderben zu wollen, stifteten sie zwischen beiden ein Wechselbündniß, wo die Aufklärung versprach die Religion zu erhalten, wenn sie sich auch nützlich machen wollte."}, {"type": "paragraph", "text": "Man braucht nur zu erinnern, daß die Freidenkereien und Aufklärungen nicht die geringsten poetischen Hervorbringungen aufweisen können, um zu sehen, daß sie sämmtlich in ihrem Grund nichts als die Prosa des neueren Zeitalters sind, angewendet auf die Religion. Mit dem gänzlichen Mangel an Symbolik und wahrer Mythologie - was jene betrifft, im Christenthum überhaupt, was diese, wenigstens im Protestantismus - traten gleichwohl spätere Dichter wieder auf den Kampfplatz, um in *ihrer *Meinung sogar mit den *epischen *Dichtungen des Alterthums zu wetteifern. Vorzüglich *Milton * und *Klopstock.* Das Gedicht des ersten kann schon darum kein rein christliches Gedicht heißen, da sein Stoff im A.T. liegt, und dem Ganzen die Einschränkung auf das Moderne, Christliche fehlt, während dieser die Tendenz hat im Christenthum erhaben zu seyn und mit einer widernatürlichen Spannung die innere Hohlheit zur Unbegrenztheit aufbläht. Miltons Gestalten sind zum Theil wenigstens wirkliche Gestalten mit Umriß und Bestimmtheit, so daß man z.B. seinen Satan, den er als einen Giganten oder Titanen behandelt, von einem Gemälde abgenommen glauben könnte, während bei Klopstock alles wesen- und gestaltlos, ohne Gediegenheit wie ohne Form, schwebt. Milton war lange in Italien gewesen, wo er die Kunstwerke gesehen, auch den Plan zu seinem Gedicht gefaßt und seine Gelehrsamkeit sich gebildet hat. Klopstock war ohne alle Natur- und ächte Kunstanschauung (es versteht sich, daß seine Sprachverdienste nicht geschmälert werden sollen). Wie wenig Klopstock bei dem Plan, ein christlich-episches Gedicht zu machen, selbst gewußt habe, was er wollte, erhellt daraus, daß er uns nachher auch die nordisch-barbarische Mythologie der alten Deutschen und Scandinavier empfehlen wollte. Sein hauptsächlichstes Bestreben ist ein Ringen mit dem Unendlichen, nicht daß es ihm endlich werden soll, sondern daß es ihm, gegen seinen Willen und mit beständigem Sträuben dagegen von seiner Seite, endlich wird, wo es dann auf solche Widersprüche hinausläuft, wie in dem bekannten Anfang einer seiner Oden:"}, {"type": "paragraph", "text": "Der Seraph stammelt's und die Unendlichkeit"}]}, {"page_pdf": 1658, "page_book": 442, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "footnote", "text": "Bebt's durch den Umkreis ihrer Gefilde nach."}, {"type": "paragraph", "text": "Daß die moderne Welt kein wahres *Epos *hat, und, weil mit einem solchen erst Mythologie sich fixirt, auch keine geschlossene Mythologie, brauche ich nicht weiter zu beweisen. Es muß indeß hier noch Erwähnung von dem neueren Versuche geschehen, die Mythologie auf den Kreis der katholischen zurückzuführen. Alles, was sich über die Nothwendigkeit eines bestimmten mythologischen Kreises für die Poesie sagen läßt, glaube ich im Vorhergehenden gesagt zu haben. Ebenso möchte sich aus dem Vorhergehenden von selbst beurtheilen lassen, welcher Fond von Poesie innerhalb der Beschränkung, die der bisherigen modernen Welt überhaupt gesetzt ist, im Katholicismus angetroffen werden könne. Es gehört aber wesentlich zum Christenthum, auf die Offenbarungen des Weltgeistes zu achten, und nicht zu vergessen, daß es zu seinem Plane gehörte, auch *diese *Welt, welche die moderne Mythologie sich gebildet hatte, zu einer Vergangenheit zu machen. Es gehört mit zum Christenthum, in der Geschichte nichts partial aufzufassen. Der Katholicismus ist ein nothwendiges Element aller modernen Poesie und Mythologie, aber er ist sie nicht ganz und in den Absichten des Weltgeistes ohne Zweifel nur ein Theil davon. Wenn man bedenkt, welcher ungeheure historische Stoff in dem Untergang des römischen Reichs und des griechischen Kaiserthums und überhaupt der ganzen modernen Geschichte ist, welche Mannichfaltigkeit der Sitten und Bildungen *zugleich *- unter einzelnen Nationen und der Menschheit im Ganzen - und *nacheinander *in verschiedenen Jahrhunderten gewesen ist, wenn man bedenkt, daß die moderne Poesie nicht mehr die Poesie für ein besonderes Volk ist, das sich zur Gattung ausgebildet hat, sondern Poesie für das ganze Geschlecht, und, so zu sagen, aus dem Stoff der ganzen Geschichte dieses Geschlechts mit allen ihren verschiedenen Farben und Tönen gebildet seyn muß, wenn man alle diese Umstände zusammennimmt, wird man nicht zweifeln, daß auch die Mythologie des Christenthums in den Gedanken des Weltgeistes immer nur ein Theil des größeren Ganzen sey, das er ohne Zweifel vorbereitet. Daß sie nicht universell, daß noch eine Seite davon die beschränkte war, um welcher willen der durchgängig auf Zerschlagung"}, {"type": "paragraph", "text": "aller rein endlichen Formen ausgehende Geist der neuen Welt das Ganze in sich zerfallen ließ, dieß erhellt schon daraus, daß dieß geschehen ist. Es erhellt daraus, daß das Christenthum erst in das größere Ganze, von dem es ein Theil seyn wird, wieder als allgemeingültiger poetischer Stoff wird eintreten können; und aller Gebrauch, der von ihm in der Poesie gemacht wird, sollte schon in dem Sinne dieses größeren Ganzen, welches man wohl ahnden, aber nicht aussprechen kann, gemacht werden. Am wenigsten aber könnte dieser Gebrauch poetisch seyn, wo sich diese Religion der Poesie selbst nur als Subjektivität oder Individualität ausspricht. Nur wo sie wahrhaft ins Objekt übergeht, kann sie poetisch heißen. Denn das Innerste des Christenthums ist die Mystik, welche selbst nur ein inneres Licht, eine innere Anschauung ist. Nur ins Subjekt fällt hier die Einheit des Unendlichen und Endlichen. Aber von diesem inneren Mysticismus kann selbst wieder eine sittliche Person das objektive Symbol seyn, und er kann so zur poetischen Anschauung gebracht werden, nicht aber wenn man ihn selbst nur wieder sich subjektiv aussprechen läßt. Der Mysticismus ist verwandt mit der reinsten und schönsten Sittlichkeit, sowie es umgekehrt selbst in der Sünde einen Mysticismus geben kann. Wo er sich wahrhaft in Handlung äußert und an einer objektiven Person abbildet, kann die moderne Tragödie z.B. ganz die hohe und symbolische Sittlichkeit der sophokleischen Stücke erreichen, wie denn Calderon in dieser Rücksicht mit keinem andern als mit Sophokles verglichen werden kann."}]}, {"page_pdf": 1659, "page_book": 444, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Nur der Katholicismus lebte in einer mythologischen Welt. Daher die Heiterkeit der poetischen Werke, die in dem Katholicismus selbst entsprungen sind, die Leichtigkeit und Freiheit der Behandlung dieses - ihnen natürlichen - Stoffes, faßt wie die Griechen ihre Mythologie behandelt haben. Außer dem Katholicismus * kann *faßt nur Unterordnung unter den Stoff, gezwungene Bewegung ohne Heiterkeit und bloße Subjektivität des Gebrauchs erwartet werden. Ueberhaupt wenn eine Mythologie zum *Gebrauch* herabgesunken, z.B. der Gebrauch der alten Mythologie in den Modernen, so ist dieser, eben weil bloß Gebrauch, bloße Formalität; sie muß nicht auf den Leib passen, wie"}, {"type": "paragraph", "text": "ein Kleid, sondern der Leib selbst seyn. Selbst die vollendete Dichtung im Sinn der rein-mystischen Poesie würde eine Absonderung im Dichter, sowie in denen, für welche er dichtet, voraussetzen, sie wäre nie rein, nie aus dem Ganzen der Welt und des Gemüths gegossen. Die Grundforderung an alle Poesie ist - nicht universelle Wirkung, aber doch Universalität nach innen und außen. Partialitäten können hier am wenigsten geltend seyn. Zu jeder Zeit sind nur einige gewesen, in welchen sich ihre ganze Zeit und das Universum, sofern es in dieser angeschaut wird, concentrirt hat, diese sind berufene Dichter. Nicht die Zeit, sofern sie selbst eine Partialität, sondern sofern Universum, Offenbarung Einer ganzen Seite des Weltgeistes. Wer den ganzen Stoff seiner Zeit, sofern sie als Gegenwart auch die Vergangenheit wieder begreift, poetisch unterjochen und verdauen könnte, wäre der epische Dichter seiner Zeit. Universalität, die nothwendige Forderung an alle Poesie, ist in der neueren Zeit nur dem möglich, der sich aus seiner Begrenzung selbst eine Mythologie, einen abgeschlossenen Kreis der Poesie schaffen kann. Man kann die moderne Welt allgemein die Welt der Individuen, die antike die Welt der Gattungen nennen. In dieser *ist *das Allgemeine das Besondere; die Gattung das Individuum; darum ist sie, obgleich in ihr das Besondere herrschend ist, doch die Welt der Gattungen. In jener bedeutet das Besondere nur das Allgemeine, und eben darum ist, weil in ihr das Allgemeine *herrscht*, die moderne Welt die der Individuen, des Zerfallens. Dort ist alles ewig, dauernd, unvergänglich, die Zahl hat gleichsam keine Gewalt, da der allgemeine Begriff der Gattung und des Individuums in eins fällt, hier - in der modernen Welt - ist Wechsel und Wandel das herrschende Gesetz. Alles Endliche vergeht hier, da es nicht an sich selbst ist, sondern nur, um das Unendliche zu bedeuten. Der allgemeine Weltgeist, der auch an der Natur und dem Weltsystem die Unendlichkeit der Geschichte nur gleichsam concret aufgestellt hat, hat denselben Gegensatz, den der alten und der neuen Zeit, im Planetensystem und der Kometenwelt aufgestellt. Die Alten"}, {"type": "paragraph", "text": "sind die Planeten der Kunstwelt, eingeschränkt auf wenige Individuen, die zugleich Gattungen sind und in der freiesten Bewegung doch am wenigsten sich von der Identität entfernen. Auch die Planetenbilder unter sich haben ihre bestimmten Gattungen. Die tiefsten sind die rhythmischen, die entfernteren, wo sich die Masse als Totalität bildet, alles concentrisch, wie die Blätter der Blüthe, in Ringen und Monden sich um den Mittelpunkt stellt, sind die dramatischen. Den Kometen gehört der grenzenlose Raum. Wenn sie erscheinen, so kommen sie unmittelbar aus dem unendlichen Raum, und so sehr sie der Sonne sich nähern, ebenso weit verlieren sie sich wieder von ihr. Sie sind gleichsam bloß allgemeine Wesen, weil sie keine Substanz in sich haben; sie sind nur Luft und Licht, jene aber, die plastischen, symbolischen Gestalten - durchaus herrschende Individuen, keine Beschränkung durch Zahl. Wir können, dieß vorausgesetzt, behaupten, daß bis zu dem in noch unbestimmbarer Ferne liegenden"}]}, {"page_pdf": 1660, "page_book": 446, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Punkt, wo der Weltgeist das große Gedicht, auf das er sinnt, selbst vollendet haben, und das Nacheinander der modernen Welt sich in ein *Zumal* verwandelt haben wird, jeder große Dichter berufen sey, von dieser noch im Werden begriffenen (mythologischen) Welt, von der ihm * seine *Zeit nur einen Theil offenbaren kann, - von dieser Welt, sage ich, diesen ihm offenbaren Theil zu einem Ganzen zu bilden und aus dem Stoff derselben sich * seine *Mythologie zu schaffen. So, um dieß an dem Beispiel des größten Individuums der modernen Welt deutlich zu machen, schuf sich *Dante *aus der Barbarei und der noch barbarischeren Gelehrsamkeit seiner Zeit, aus den Gräueln der Geschichte, die er selbst erlebt hatte, wie aus dem Stoff der bestehenden Hierarchie, eine eigne Mythologie und mit dieser sein göttliches Gedicht. Die historischen Personen, welche Dante aufgenommen hat, werden in aller Zeit für mythologische gelten, wie Ugolino. Könnte das Andenken der hierarchischen Verfassung je zu Grunde gehen, man würde es aus dem Bild, das sein Gedicht davon entwirft, wieder herstellen. - Auch *Shakespeare *hat sich seinen eignen mythologischen Kreis geschaffen, nicht allein aus dem"}, {"type": "paragraph", "text": "historischen Stoff seiner Nationalgeschichte, sondern auch aus den Sitten seiner Zeit und seines Volkes. Es ist in Shakespeare, der großen Mannichfaltigkeit seiner Werke unerachtet, dennoch Eine Welt; überall schaut man ihn als einen und denselben an, und ist man bis auf die Grundanschauung von ihm durchgedrungen, so findet man sich in jedem seiner Werke gleich wieder auf dem ihm eignen Boden (Falstaff: Lear. Macbeth). - *Cervantes *hat aus dem Stoff seiner Zeit die Geschichte des Donquixote gebildet, der bis auf diesen Augenblick, ebenso wie Sancho Pansa, das Ansehn einer mythologischen Person hat. Es sind hier ewige Mythen. - Soweit man *Goethes Faust *aus dem Fragment, das davon vorhanden ist, beurtheilen kann, so ist dieses Gedicht nichts anderes als die innerste, reinste Essenz unseres Zeitalters: Stoff und Form geschaffen aus dem, was die ganze Zeit in sich schloß, und selbst dem, womit sie schwanger war oder noch ist. Daher ist es ein wahrhaft mythologisches Gedicht zu nennen. Man hat mehrmals in neuerer Zeit den Gedanken gehört, daß es wohl möglich wäre, aus der *Physik *- natürlich, sofern sie speculative Physik ist - den Stoff einer neuen Mythologie zu nehmen. Hierüber ist Folgendes zu bemerken. Erstens, nach dem, was ich so eben bewiesen habe, ist das Grundgesetz der modernen Poesie *Originalität *(in der alten Kunst war dieß keineswegs in dem Sinn der Fall). Jedes wahrhaft schöpferische Individuum hat sich selbst seine Mythologie zu schaffen, und es kann dieß, aus welchem Stoff es nur immer will, geschehen, also vornehmlich auch aus dem einer höheren Physik. Allein diese Mythologie wird doch durchaus *erschaffen*, nicht etwa bloß nach Anleitung gewisser Ideen der Philosophie entworfen werden dürfen; denn in diesem Fall möchte es unmöglich seyn, ihr ein unabhängiges poetisches Leben zu geben. Käme es nur überhaupt darauf an, Ideen der Philosophie oder höheren Physik durch mythologische Gestalten zu symbolisiren, so finden sich diese sämmtlich schon in der griechischen Mythologie, so daß ich mich anheischig machen will, die ganze Naturphilosophie in Symbolen"}, {"type": "paragraph", "text": "der Mythologie darzustellen. Aber dieß wäre doch wieder nur *Gebrauch *(wie bei Darwin). Die Forderung einer Mythologie ist ja aber gerade, *nicht *daß ihre Symbole bloß Ideen bedeuten, sondern daß sie für sich selbst bedeutend, unabhängige Wesen seyen. Vorläufig also hätte man sich nur nach der Welt umzusehen, in der sich diese Wesen unabhängig bewegen könnten. Wäre uns diese durch die *Geschichte* gegeben, so würden sich jene ohne Zweifel von selbst finden. Man gebe uns nur erst das trojanische"}]}, {"page_pdf": 1661, "page_book": 448, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Schlachtfeld, worauf die Götter und die Göttinnen selbst mit an dem Kampf theilnehmen können. Also: ehe die *Geschichte * uns die Mythologie als allgemeingültige Form wiedergibt, wird es immer dabei bleiben, daß das Individuum selbst sich seinen poetischen Kreis schaffen muß; und da das allgemeine Element des Modernen die Originalität ist, wird das Gesetz gelten, daß gerade je origineller, desto universeller; wobei man von der Originalität nur die Particularität unterscheiden muß. Jeder originell behandelte Stoff ist eben dadurch auch universell poetisch. Wer den Stoff der höheren Physik auf diese *originelle *Weise zu brauchen weiß, dem wird er wahrhaft- und universell-poetisch werden können. Aber eine andere Beziehung, welche Naturphilosophie auf die moderne Bildung hat, kommt hier in Betracht. Die dem Christenthum eigenthümliche Richtung ist vom Endlichen zum Unendlichen. Es ist gezeigt worden, wie diese Richtung alle symbolische Anschauung aufhebt und das Endliche nur als das Allegorische des Unendlichen begreift. Die *in* dieser allgemeinen Richtung wieder durchbrechende Tendenz, das Unendliche im Endlichen zu schauen, war ein symbolisches Bestreben, das aber wegen des Mangels an Objektivität, weil die Einheit in das Subjekt zurückfiel, sich nur als Mysticismus äußern konnte. Die Mystiker im Christenthum sind von jeher innerhalb desselben als Verirrte, wenn nicht gar als Abtrünnige, betrachtet worden. Die Kirche verstattete den Mysticismus nur im Handeln (Handlungen), weil er hier zugleich objektiv, universell war, statt daß jener subjektive Mysticismus eine Besonderheit von dem Ganzen, eine wirkliche Häresis war. Naturphilosophie"}, {"type": "paragraph", "text": "ist gleichfalls Anschauung des Unendlichen im Endlichen, aber auf eine allgemeingültige und wissenschaftlich objektive Art. Alle speculative Philosophie hat nothwendig dieselbe der Richtung des Christenthums entgegengesetzte Richtung, sofern man nämlich das Christenthum in dieser seiner empirisch-historischen Gestalt nimmt, in welcher es sich als Gegensatz darstellt, und nicht in dieser Entgegensetzung es selbst als *Uebergang *betrachtet. Das Christenthum ist aber schon jetzt durch den Lauf der Zeit und durch die Wirkungen des Weltgeistes, der sein entferntes Vorhaben nur erst ahnden, aber doch auch nicht verkennen läßt, bloß als Uebergang und bloß als Element und gleichsam die eine Seite der neuen Welt dargestellt, in der sich die Successionen der modernen Zeit endlich als Totalität darstellen werden. Wer den allgemeinen Typus kennt, nach dem alles geordnet ist und geschieht, wird nicht zweifeln, daß dieser integrante Theil der modernen Bildung die andere Einheit ist, welche das Christenthum als Gegensatz von sich ausschloß, und daß diese Einheit, welche ein Schauen des Unendlichen im Endlichen ist, in das Ganze derselben aufgenommen werden müsse, obgleich freilich untergeordnet ihrer besonderen Einheit. Folgendes wird dienen, meine Meinung deutlich zu machen. Die realistische Mythologie der Griechen schloß die historische Beziehung nicht aus, vielmehr wurde sie erst in der historischen Beziehung - als Epos - wahrhaft zur Mythologie. Ihre Götter waren dem Ursprung nach *Naturwesen; *diese Naturgötter mußten von ihrem Ursprung sich losreißen und historische Wesen werden, um wahrhaft unabhängige, poetische zu werden. Hier erst werden sie Götter, vorher sind sie Götzen. Das Herrschende der griechischen Mythologie blieb deßwegen doch immer das realistische oder endliche Princip. Das Entgegengesetzte wird in der modernen Bildung der Fall seyn. Sie schaut das Universum nur an als *Geschichte*, als moralisches Reich; insofern stellt sie sich als Gegensatz dar. Der Polytheismus, der in ihr möglich ist, ist nur durch Begrenzungen in der *Zeit*, durch historische Begrenzungen möglich, ihre Götter sind Geschichtsgötter. *Diese *werden nicht wahrhaft Götter, lebendig, unabhängig, poetisch werden"}]}, {"page_pdf": 1662, "page_book": 450, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "können, ehe sie von der Natur Besitz ergriffen haben, ehe sie Naturgötter sind. Man muß der christlichen Bildung nicht die realistische Mythologie der Griechen aufdringen wollen, man muß vielmehr umgekehrt ihre idealistischen Gottheiten in die Natur pflanzen, wie die Griechen ihre realistischen in die Geschichten. Dieß scheint mir die letzte Bestimmung aller modernen Poesie zu seyn, so daß auch dieser Gegensatz, wie jeder andere, nur in der Nichtabsolutheit besteht, jedes der Entgegengesetzten aber in seiner Absolutheit auch mit dem andern in Harmonie tritt, und ich verhehle meine Ueberzeugung nicht, daß in der Naturphilosophie, wie sie sich aus dem idealistischen Princip gebildet hat, die erste ferne Anlage jener künftigen Symbolik und derjenigen Mythologie gemacht ist, welche nicht ein Einzelner, sondern die ganze Zeit geschaffen haben wird. Nicht *wir *wollen der idealistischen Bildung ihre Götter durch die *Physik *geben. Wir erwarten vielmehr ihre Götter, für die wir, vielleicht noch ehe sie in *jener *ganz unabhängig von dieser sich gebildet haben, die Symbole schon in Bereitschaft haben. Dieß war der Sinn meiner Meinung, inwiefern ich behauptete, daß in der höheren speculativen Physik die Möglichkeit einer künftigen Mythologie und Symbolik zu suchen sey. Uebrigens muß diese Bestimmung allein der Fügung der Zeit überlassen werden; denn noch scheint der Punkt der Geschichte, wo sich ihr Nacheinander in ein Zumal verwandeln wird, unbestimmbar weit entfernt, und was jetzt möglich ist, nur das schon früher Angegebene seyn zu können, nämlich daß jede überwiegende Kraft sich aus jedem Stoff, also auch aus dem der Natur, ihren mythologischen Kreis bilden kann, welches doch wiederum nicht ohne eine Synthese der Geschichte mit der Natur möglich seyn wird. Das Letzte der reine Homeros. Da die antike Mythologie sich überall auf die Natur bezieht und eine Symbolik der Natur ist, so muß es uns interessiren zu sehen, wie in der modernen Mythologie bei ihrem vollkommenen Gegensatz mit der antiken die Beziehung auf die *Natur *sich ausdrücken werde. Im Allgemeinen läßt sich dieß schon aus dem Bisherigen bestimmen."}, {"type": "paragraph", "text": "- Absolutes Uebergewicht des Idealen über das Reale, des Geistigen über das Leibliche war Princip des Christenthums. Daher das unmittelbare Eingreifen des Uebersinnlichen in das Sinnliche im *Wunder.* Dieselbe Oberherrschaft des Geistes über die Natur ist ausgedrückt in der *Magie*, soferne sie Beschwörung, Bezauberung in sich begriff. Die magische Ansicht der Dinge oder das Begreifen der Naturwirkungen als magischer war nur eine unvollständige Ahndung des höheren und absoluten Vereins aller Dinge, in welchem keins in dem andern etwas unmittelbar, sondern nur durch prästabilirte Harmonie, mittelst der absoluten Identität aller Dinge, setzt oder bewirkt. Magisch heißt eben deßwegen auch jede Wirkung, welche Dinge auf einander bloß durch ihren Begriff, also nicht auf natürliche Art ausüben, z.B. daß Bewegungen oder gewisse Zeichen rein als solche einem Menschen verderblich werden können. In dem Glauben an Magie drückte sich ferner die Ahndung vom Daseyn verschiedener Naturordnungen, des Mechanismus, Chemismus, Organismus aus. Es ist bekannt, wie die erste Bekanntschaft mit chemischen Erscheinungen auf die Geister der neueren Welt gewirkt hat. Ueberhaupt gab das Zurücktreten der Natur als Mysterium der neueren Welt eine allgemeine Richtung auf Geheimnisse der Natur. Die geheimnißvolle Sprache der Gestirne, die sich in ihren verschiedenen Bewegungen und Conjunktionen ausdrückt, bekam unmittelbar historische Beziehung; ihr Lauf, ihr Wechsel, ihre Verbindungen deuteten auf Schicksale der Welt im Ganzen und mittelbar des Einzelnen. Auch hier lag eine richtige Ahndung zu Grunde, daß in der Erde, da sie Universum für sich ist, die Elemente aller Gestirne seyn müssen, und daß die verschiedenen Stellungen und Entfernungen der Gestirne von der Erde besonders auf den zarteren Bildungen der Erde, wie die menschliche, schon bei der ersten Formation einen nothwendigen Einfluß haben. - Es wird in der Naturphilosophie bewiesen, daß den verschiedenen Ordnungen von Metallen, dem Gold oder Silber u.s.w. gleiche Ordnungen am Himmel"}]}, {"page_pdf": 1663, "page_book": 451, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "entsprechen, sowie wir an der Construktion des Erdkörpers für sich nach seinen vier Seiten wirklich ein vollkommenes Bild des ganzen Sonnensystems haben. Das Beseeltseyn"}, {"type": "paragraph", "text": "der Gestirne, und daß sie von inwohnenden Seelen in ihren Bahnen geführt werden, war eine Meinung, die sich noch von Plato und Aristoteles her erhalten hatte. Die Erde wurde bis zu Copernicus als Mittelpunkt des Universums angeschaut; darauf ruhte auch jene aristotelische Astronomie, die dem Gedicht des Dante durchweg zu Grunde liegt. Es läßt sich leicht denken, welche Folge für das Christenthum, d.h. für das katholische System, die Copernicanische Theorie haben mußte, und es war gewiß nicht allein wegen des Spruchs bei Josua, daß die römische Kirche dieser reinen Lehre sich so mächtig widersetzte. - Geheimnißvolle Kräfte der Steine und Pflanzen waren im Orient allgemein angenommen. Der Glaube daran kam ebenso wie die Arzneikunst mit den Arabern nach Europa. Ebenso der Gebrauch der Talismane und Amulete, womit man sich im Orient seit den ältesten Zeiten gegen giftige Schlangen und böse Geister verwahrt. Viele der mythologischen Ansichten der Thierwelt waren den Neueren nicht eigenthümlich. Ich werde nun, was ich von der modernen Mythologie bisher vorgetragen, in einige Sätze zusammenfassen, um dadurch die Uebersicht zu erleichtern. Zuerst haben wir des Zusammenhangs wegen auf einen früheren Satz §. 28 zurückzusehen, welcher das Princip für diese ganze Untersuchung enthält. Er setzte nämlich im Allgemeinen fest, daß die Ideen real und als Götter, die Ideenwelt demnach als eine Welt der Götter angeschaut werden könne. Diese Welt ist der Stoff aller Poesie. Wo er sich bildet, ist die höchste Indifferenz des Absoluten mit dem Besonderen in der realen Welt producirt. Hieran schließt sich nun der folgende Satz an:"}, {"type": "paragraph", "text": "§. 43. *Im Stoff der Kunst ist kein Gegensatz denkbar als ein formeller. *Dem Wesen nach ist nämlich jener immer und ewig eins, immer und nothwendig absolute Identität des Allgemeinen und des Besonderen. Wenn also überhaupt ein Gegensatz in Ansehung des Stoffes stattfindet, so ist er bloß formell, und als solcher muß er auch objektiv sich ausdrücken als bloßer Gegensatz in der Zeit."}, {"type": "paragraph", "text": "§. 44. *Der Gegensatz wird sich darin äußern, daß die Einheit des Absoluten und Endlichen (Besonderen) in dem*"}, {"type": "paragraph", "text": "*Stoff der Kunst von der einen Seite als Werk der Natur, von der andern als Werk der Freiheit erscheint.* Denn da in dem Stoff an und für sich immer und nothwendig Einheit des Unendlichen und Endlichen gesetzt ist, diese aber nur auf die gedoppelte Art möglich ist, daß das Universum im Endlichen oder das Endliche im Universum dargestellt werde, jenes aber die Einheit ist, die der Natur zu Grunde liegt, so wie dieses die, welche der ideellen Welt oder der Welt der Freiheit, so wird auch die Einheit, inwiefern sie als producirend erscheint und nach entgegengesetzten Seiten sich trennt, nach der einen nur als Werk der Natur, nach der andern als das der Freiheit erscheinen können. *Anmerkung.* Daß nun dieser Gegensatz eben in der griechischen oder antiken und der modernen Poesie dargestellt ist, davon ist nur der empirische Beweis aus dem Faktum möglich, der auch in dem Vorhergehenden geführt worden ist."}, {"type": "paragraph", "text": "§. 45. *Die Einheit wird in dem ersten Fall * (der Nothwendigkeit)* als Einheit des Universums mit dem*"}]}, {"page_pdf": 1664, "page_book": 453, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "*Endlichen, in dem andern *(der Freiheit)* als Einheit des Endlichen mit dem Unendlichen erscheinen.* Dieser Satz ist, wie aus dem Beweis des vorhergehenden erhellt, nur ein anderer Ausdruck des vorhergehenden. Doch ist noch folgender besonderer Beweis davon zu führen: die Entgegengesetzten verhalten sich (nach §. 44) wie Natur und Freiheit; nun ist der Charakter der Natur (nach §. 18) ungetrennte, *noch vor der Trennung bestehende *Einheit des Unendlichen und Endlichen. Das Endliche ist in ihr herrschend, aber in ihr liegt der Keim des Absoluten. Wo die Einheit getrennt ist, da ist das Endliche als Endliches gesetzt, also ist nur die Richtung vom Endlichen zum Unendlichen, also die Einheit des Endlichen mit dem Unendlichen möglich."}, {"type": "paragraph", "text": "§. 46. *Im ersten Fall ist das Endliche als Symbol, im andern als Allegorie des Unendlichen gesetzt. *- Folgt aus den Erklärungen, die beim §. 39 gegeben worden sind. *Anmerkung.* Auch so auszudrücken: Im ersten Fall ist das"}, {"type": "paragraph", "text": "Endliche zugleich das Unendliche selbst, nicht bloß es bedeutend, eben darum etwas für sich, auch unabhängig von seiner Bedeutung. Im andern Falle ist es für sich selbst nichts, nur in der Beziehung aufs Unendliche. *Folgesatz. *Der Charakter der Kunst im ersten Fall ist im Ganzen *symbolisch*, im andern im Ganzen *allegorisch.* (Daß dieß in der modernen Kunst der Fall sey, ist in der Folge im Einzelnen zu beweisen. Indessen fassen wir hier natürlich den reinen Gegensatz auf, also das Moderne, nicht wie es in seiner Absolutheit seyn kann, sondern wie es sich in seiner Nicht-Absolutheit darstellt, und demnach bisher dargestellt hat, da uns alles überzeugt, daß die bisherige Erscheinung der modernen Poesie noch nicht der *vollendete *Gegensatz ist, in welchem eben deßwegen die beiden Entgegengesetzten auch wieder eins würden)."}, {"type": "paragraph", "text": "§. 47. *In der Mythologie der ersten Art wird das Universum angeschaut als Natur, in der andern als Welt der Vorsehung oder als Geschichte. * - Nothwendige Folge, da die Einheit, welche der andern zu Grunde liegt, = Handeln, Vorsehung im Gegensatz gegen *Schicksal: *Schicksal = Differenz (Uebergang), Abfall von der Identität der Natur, Vorsehung = Reconstruktion. *Zusatz.* Die Entgegensetzung des Endlichen mit dem Universum muß sich in der ersten als Empörung, in der andern als unbedingte Hingabe an das Universum darstellen. Jenes kann als *Erhabenheit* (Grundcharakter des Antiken), dieses als *Schönheit *im engern Sinn charakterisirt werden."}, {"type": "paragraph", "text": "§. 48. *In der poetischen Welt der ersten Art wird die Gattung sich zum Individuum oder Besondern ausbilden, in der andern das Individuum für sich das Allgemeine auszudrücken streben.* - Nothwendige Folge. Denn dort ist das Allgemeine im Besonderen als solchen, hier das Besondere im Allgemeinen als bedeutend das Allgemeine."}, {"type": "paragraph", "text": "§. 49. *Die Mythologie der ersten Art wird sich zu einer geschlossenen Götterwelt bilden, für die andere wird das Ganze, worin ihre Ideen objektiv werden, selbst wieder ein unendliches Ganzes seyn. *Nothwendige Folge. Denn"}, {"type": "paragraph", "text": "dort ist Begrenzung, Endlichkeit herrschend, hier Unendlichkeit. - Auch: dort Seyn, hier *Werden. *Die"}]}, {"page_pdf": 1665, "page_book": 455, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Gestalten der ersten Welt bleibend, ewig, die Naturwesen einer höheren Ordnung, hier vorübergehende Erscheinungen."}, {"type": "paragraph", "text": "§. 50. *Dort wird Polytheismus durch Naturbegrenzung * (von dem hergenommen, was in den Raum fällt), *hier nur durch Begrenzung in der Zeit möglich seyn.* Folgt von selbst. Alle Anschauung Gottes nur in der Geschichte. *Anmerkung.* Inwiefern das Unendliche hier in das Endliche kommt, so wird es nur seyn, um dieses an sich (selbst) und durch sein Beispiel zu vernichten, und so die Grenze der zwei Welten zu machen. Daher nothwendig die Idee der späteren Welt: Menschwerdung und Tod Gottes."}, {"type": "paragraph", "text": "§. 51. *In der ersten Art der Mythologie ist die Natur das Offenbare, die ideelle Welt ist das Geheime, in der andern wird die ideelle Welt offenbar, und die Natur tritt ins Mysterium zurück. * - Folgt von selbst."}, {"type": "paragraph", "text": "§. 52. *Dort ist die Religion auf die Mythologie, hier vielmehr die Mythologie auf die Religion gegründet. -* Denn Religion: Poesie wieder = subjektiv: objektiv. Das Endliche wird im Unendlichen angeschaut durch *Religion*, wodurch mir erst auch das Endliche zum Reflex des Unendlichen wird, das Unendliche im Endlichen dagegen symbolisch, und insofern mythologisch. *Erläuterung.* Die griechische Mythologie war nicht als solche Religion; sie ist an sich nur als *Poesie* zu begreifen; Religion wurde sie erst in dem Verhältniß, welches sich der Mensch nun selbst zu den Göttern (dem Unendlichen) gab in religiösen Handlungen u.s.w. Im Christenthum ist dieses Verhältniß das erste, und jede mögliche Symbolik des Unendlichen, alle Mythologie also auch, davon abhängig gemacht. *Zusatz* 1. Die Religion selbst mußte dort mehr als Naturreligion, hier konnte sie nur als geoffenbarte erscheinen. - Folgt aus §. 47 und 48."}, {"type": "paragraph", "text": "*Zusatz* 2. Unmittelbar aus einer solchen Religion konnte Mythologie entspringen, weil jene auf Tradition gegründet war. *Zusatz* 3. Die Ideen dieser Religion an und für sich selbst konnten nicht mythologisch seyn. Denn sie sind durchaus unsinnlich. Beweis an der Dreieinigkeit, den Engeln u.s.w. *Zusatz* 4. Nur in der Historie konnte eine solche Religion mythologischer Stoff werden. Denn nur darin erlangen sie (die Ideen) eine Unabhängigkeit von ihrer Bedeutung."}, {"type": "paragraph", "text": "§. 53. *Wie dort die Ideen vorzugsweise nur in dem Seyn, so konnten sie hier nur in dem Handeln objektiv werden. * - Denn jede Idee ist = Einheit des Unendlichen und Endlichen, diese hier aber nur durch Handlung, wie dort durch das Entgegengesetzte, also durch Seyn."}, {"type": "paragraph", "text": "§. 54. *Die Grundanschauung aller Symbolik der letzten Art war nothwendig die Kirche . *Denn in der Mythologie der andern Art wird das Universum oder Gott angeschaut in der Geschichte (vergl. §. 47). Nun ist aber der Typus oder die Form der Geschichte Getrenntheit im Einzelnen und Einheit im Ganzen (etwas, das hier als in der Philosophie zu Beweisendes *vorausgesetzt *wird), also konnte in jener Art der Symbolik Gott überhaupt nur objektiv werden als das vereinende Princip der Einheit im Ganzen und der Getrenntheit im Einzelnen. Dieß aber konnte nur in der *Kirche *geschehen (wo auch unmittelbare Anschauung *Gottes*), denn in der objektiven Welt war keine andere Synthese dieser Art (z.B. in der Staatsverfassung, in der Geschichte selbst könnte diese Synthese wieder nur im *Ganzen *objektiv werden, d.h. in der unendlichen Zeit, aber nicht gegenwärtig). *Zusatz. *Die Kirche ist als ein Kunstwerk zu betrachten."}]}, {"page_pdf": 1666, "page_book": 456, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "§. 55. *Die äußere Handlung, in welcher die Einheit des Unendlichen und Endlichen ausgedrückt wird, ist symbolisch.* - Denn sie ist Darstellung der Einheit des Unendlichen und Endlichen im *Endlichen *oder Besonderen."}, {"type": "paragraph", "text": "§. 56. *Dieselbe Handlung, insofern sie bloß innerlich*"}, {"type": "paragraph", "text": "*ist, ist mystisch. * - Dieß der Begriff, den wir von mystisch festsetzen, und der also als Erklärung keines Beweises bedarf. *Zusatz* 1. Mysticismus also = subjektiver Symbolik. *Zusatz* 2. Mysticismus an und für sich selbst ist unpoetisch - denn er ist der entgegengesetzte Pol der Poesie, welche die Einheit des Unendlichen und Endlichen im *Endlichen. * - Es versteht sich, daß von Mysticismus an und für sich die Rede ist, nicht, inwiefern er selbst wieder objektiv werden kann, z.B. in sittlicher Gesinnung u.s.w."}, {"type": "paragraph", "text": "§. 57. *Das Gesetz der ersten Art der Kunst ist Unwandelbarkeit in sich selbst, das der andern Fortschritt im Wechsel. * - Folgt schon aus der Entgegensetzung beider als Natur und Freiheit."}, {"type": "paragraph", "text": "§. 58. *Dort ist das Exemplarische oder die Urbildlichkeit, hier die Originalität herrschend. *- Denn dort erscheint das Allgemeine als Besonderes, die Gattung als Individuum, hier dagegen soll das Individuum als Gattung, das Besondere als Allgemeines erscheinen. - Dort ist der Ausgangspunkt identisch (”μηρος), Einer, nämlich das Allgemeine selbst, hier aber ist der Ausgangspunkt immer und nothwendig ein verschiedener, weil er im Besonderen liegt. Der Unterschied der *Originalität *von der *Besonderheit *besteht darin, daß jene vom Besonderen sich zum Allgemeinen, Universellen bildet1."}, {"type": "footnote", "text": "1 Man vergl. den Aufsatz: Ueber das Wesen der philosophischen Kritik überhaupt u.s.w. Krit. Journal I, 1, S. XI. (oben S. 8). D. H."}, {"type": "paragraph", "text": "§. 59. *Die andere Art der Kunst ist nur als Uebergang oder als in der Nichtabsolutheit im Gegensatz mit der ersten.* - Denn die vollkommene Einbildung des Endlichen ins Unendliche wird auch die des Universums ins Endliche wieder mit sich führen. *Zusatz. *In diesem Uebergang, wo die Originalität das Herrschende ist, ist es nothwendig, daß das Individuum sich selbst aus der Besonderheit den universellen Stoff schaffe."}, {"type": "paragraph", "text": "§. 60. *Die Forderung der Absolutheit in Ansehung*"}, {"type": "paragraph", "text": "*der letzten Art der Mythologie wäre die der Verwandlung des Nacheinander ihrer göttlichen Erscheinung in ein Zumal *(erklärt sich aus §. 50). *Zusatz. *Dieß ist nur durch Integration mittelst der entgegengesetzten Einheit möglich. In der Natur ist"}]}, {"page_pdf": 1667, "page_book": 458, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "zumal, was in der Geschichte nacheinander. - Absolute Identität der Natur und der Geschichte."}, {"type": "paragraph", "text": "§. 61. *Wie in der Mythologie der ersten Art die Naturgötter sich zu Geschichtsgöttern bildeten, so müssen in der andern Art die Götter aus der Geschichte in die Natur, und also aus Geschichtsgöttern zu Naturgöttern sich bilden.* Denn nur dann Absolutheit nach §. 60. *Zusatz. *Insofern diese erste wechselseitige Durchdringung der beiden Einheiten - der Natur mit der Geschichte und der Geschichte mit der Natur - in dem Epos geschieht, insofern wird das Epos, der Homeros (nach dem wörtlichen Sinn der Einigende, die Identität), welcher dort das Erste ist, hier das Letzte seyn und die ganze Bestimmung der neuen Kunst erfüllen."}, {"type": "heading", "text": "Dritter Abschnitt. *Construktion des Besonderen oder der Form der Kunst.*", "level": null}, {"type": "paragraph", "text": "Mit der vollendeten Construktion des Stoffs der Kunst, welcher in der Mythologie liegt, tritt für uns ein neuer Gegensatz ein. Wir begannen von der Construktion der Kunst als *realer *Darstellung des Absoluten. Diese konnte nicht real seyn, ohne jenes durch einzelne endliche Dinge darzustellen. Wir machten die Synthesis des Absoluten mit der Begrenzung; es entstand uns daraus die Ideenwelt der Kunst, aber auch diese ist in Bezug auf die Darstellung selbst wieder nur Stoff oder Allgemeines, dem die Form oder das Besondere entgegensteht. Wie geht jener allgemeine Stoff über in die besondere Form und wird Materie des besonderen Kunstwerks? Es läßt sich aus dem zu Anfang aufgestellten Princip zum voraus einsehen, daß es auch hier darauf ankommen wird, die beiden Entgegengesetzten absolut zu synthesiren, Stoff und Form durch eine neue Synthese in Indifferenz darzustellen. Hierauf beziehen sich die folgenden Sätze, mit denen wir zur Construktion des Kunstwerks als solches fortgehen."}, {"type": "paragraph", "text": "§. 62. *Das unmittelbar Hervorbringende des Kunstwerks oder des einzelnen wirklichen Dings, durch welches in der idealen Welt das Absolute real-objektiv wird, ist*"}, {"type": "paragraph", "text": "*der ewige Begriff oder die Idee des Menschen in Gott, der mit der Seele selbst eins und mit ihr verbunden ist. Beweis.* Dieser ist aus §. 23 zu führen, nach welchem die formale oder absolute Ursache aller Kunst Gott ist. Nun producirt aber Gott unmittelbar und aus sich selbst nur die Ideen der Dinge, wirkliche und besondere Dinge aber nur mittelbar in der reflektirten Welt. Inwiefern also das Princip der göttlichen Ineinsbildung, d.h. Gott selbst, durch besondere Dinge objektiv wird, insofern ist nicht *Gott *unmittelbar und an sich selbst betrachtet, sondern nur Gott als das Wesen eines Besonderen und in der Beziehung auf ein Besonderes das, was die besonderen Dinge producirt. Nun bezieht sich aber Gott auf das Besondere nur durch das, worin es mit seinem Allgemeinen eins ist, d.h. durch seine Idee oder seinen ewigen Begriff. Diese Idee aber ist in dem vorliegenden Fall die des Absoluten selbst. Diese aber bekommt die unmittelbare Beziehung auf ein Besonderes oder wird objektiv producirt nur in dem Organismus und der Vernunft, beide als eins gedacht (denn nur jener ist das reale, diese das ideale Abbild des Absoluten in"}]}, {"page_pdf": 1668, "page_book": 460, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der realen oder geschaffenen Welt, nach den §§. 17 und 18). Die Indifferenz des Organismus und der Vernunft aber oder das Eine, in welchem auf gleiche Weise real und ideal das Absolute objektiv wird, ist der Mensch. Es ist also Gott, inwiefern er sich durch eine Idee oder einen ewigen Begriff auf den Menschen bezieht, d.h. es ist der ewige Begriff des Menschen selbst, der in Gott ist, wodurch das Kunstwerk hervorgebracht wird. Die Idee des Menschen ist aber nichts anderes als das *Wesen *oder *An-sich *des Menschen selbst, welches in der Seele und dem Leib objektiv wird, und demnach der Seele unmittelbar vereinigt ist. *Erläuterung.* Alle Dinge sind in Gott nur durch ihre Idee, und diese Idee wird objektiv da, wo auch im Reflex die Einheit des Unendlichen im Endlichen in der Form producirt wird. Da nun dieß im Menschen der Fall ist, indem hier das Endliche, der Leib, wie die Seele die ganze Einheit ist, so wird hier die Idee als Idee objektiv, und da es ihr Wesen ist zu produciren, überhaupt produktiv."}, {"type": "paragraph", "text": "§. 63. *Dieser ewige Begriff des Menschen in Gott als der unmittelbaren Ursache seiner Produktionen ist das, was man Genie*, gleichsam den Genius, das inwohnende Göttliche des Menschen, *nennt. *Es ist so zu sagen ein Stück aus der Absolutheit Gottes. Jeder Künstler kann daher auch nur so viel produciren, als mit dem ewigen Begriff seines eignen Wesens in Gott verbunden ist. Je mehr nun in diesem für sich schon das Universum angeschaut wird, je organischer er ist, je mehr er die Endlichkeit der Unendlichkeit verknüpft, desto produktiver. *Erläuterungen. *1) Gott producirt aus sich nichts, als worin wieder sein ganzes Wesen ausgedrückt ist, nichts also, das nicht wieder producirte, wieder Universum wäre. So verhält es sich in dem *An-sich. *Daß nun aber das Produciren Gottes, d.h. die Idee als Idee, auch in der erscheinenden Welt hervortrete, dieß hängt von Bedingungen ab, die in dieser liegen, und die uns insofern als zufällig erscheinen, obgleich, von einem höheren Gesichtspunkt aus betrachtet, auch die Erscheinung des Genies immer wieder eine nothwendige ist. 2) Das Produciren Gottes ist ein ewiger, d.h. überhaupt kein Verhältniß zur Zeit habender Akt der Selbstaffirmation, worin eine reale und ideale Seite. In jener gebiert er seine Unendlichkeit in die Endlichkeit und ist *Natur*, in dieser nimmt er die Endlichkeit wieder zurück in seine Unendlichkeit. Aber eben dieß wird auch in der Idee des Genies gedacht, daß es nämlich von der einen Seite ebenso als natürliches wie von der andern als ideelles Princip gedacht wird. Es ist demnach die ganze absolute Idee, angeschaut in der Erscheinung oder Beziehung auf Besonderes. Es ist ein und dasselbe Verhältniß, durch welches in dem ursprünglichen Erkenntnißakt die Welt an sich, und durch welches in dem Akt des Genies die Kunstwelt, als dieselbe Welt an sich nur in der Erscheinung producirt wird. (Das Genie unterscheidet sich von allem, was bloß Talent, dadurch, daß dieses eine bloß empirische Nothwendigkeit, die selbst wieder Zufälligkeit, hat, jenes absolute Nothwendigkeit. Jedes wahre Kunstwerk ist ein absolut nothwendiges;"}, {"type": "paragraph", "text": "ein solches, das gleicherweise seyn und nicht seyn konnte, verdient diesen Namen nicht1)."}, {"type": "footnote", "text": "1 Vergl. die Aeußerung in der Einleitung in die Philosophie der Mythologie, (2. Abth. 1. Bd.) S. 242. D. H."}]}, {"page_pdf": 1669, "page_book": 462, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "§. 64. *Erklärung. Die reale Seite des Genies oder diejenige Einheit, welche Einbildung des Unendlichen ins Endliche ist, kann im engern Sinn die Poesie , die ideale Seite oder diejenige Einheit, welche Einbildung des Endlichen ins Unendliche ist, kann die Kunst in der Kunst heißen. Erläuterung.* Unter Poesie im engern Sinne wird, wenn wir uns auch bloß an die Sprachbedeutung halten, das unmittelbare Hervorbringen oder Schaffen eines *Realen *verstanden, die *Invention *an und für sich selbst. Alles unmittelbare Hervorbringen oder Schaffen ist aber immer und nothwendig Darstellung eines Unendlichen, eines Begriffs in einem Endlichen oder Realen. Die Idee der Kunst beziehen wir alle mehr auf die entgegengesetzte Einheit, die der Einbildung des Besonderen ins Allgemeine. In der Invention expandirt oder ergießt sich das Genie in das Besondere; in der Form nimmt es das Besondere zurück in das Unendliche. - Nur in der vollendeten Einbildung des Unendlichen in das Endliche wird dieses etwas für sich Bestehendes, ein Wesen * an sich selbst*, das nicht bloß ein anderes bedeutet. So gibt das Absolute den Ideen der Dinge, die in ihm sind, ein unabhängiges Leben, indem es sie in die Endlichkeit auf ewige Weise einbildet; dadurch bekommen sie ein Leben in sich selbst, und nur sofern in sich absolut, sind sie im *Absoluten. *Poesie und Kunst also sind wie die zwei Einheiten: Poesie das, wodurch ein Ding Leben und Realität in sich selbst hat, Kunst das, wodurch es in dem Hervorbringenden ist."}, {"type": "paragraph", "text": "§. 65. *Erklärung. Die erste der beiden Einheiten, die, welche Einbildung des Unendlichen ins Endliche, drückt sich an dem Kunstwerk vorzugsweise als Erhabenheit , die andere, welche Einbildung des Endlichen ins Unendliche, als Schönheit aus.*"}, {"type": "paragraph", "text": "Wir können dieß nicht anders beweisen, als indem wir zeigen, daß das, was nach allgemeiner Uebereinstimmung zum Erhabenen und Schönen gefordert wird, nichts anderes sey, als was durch unsere Erklärung ausgedrückt ist. - Die Meinung ist eigentlich diese: wo die Aufnahme des Unendlichen ins Endliche als solche, Unendliche also im Endlichen unterschieden wird, urtheilen wir, daß der Gegenstand, worin dieß der Fall ist, erhaben sey. Alle Erhabenheit ist entweder Natur oder Gesinnung (wir werden durch die weitere Betrachtung finden, daß das Wesen, die Substanz des Erhabenen, immer eine und dieselbe ist, und daß nur die Form wechselt). Das Erhabene der Natur findet wieder auf doppelte Weise statt: \"da, wo uns ein sinnlicher Gegenstand dargeboten wird, der für unsere Fassungskraft zu hoch und in der Beziehung auf selbige unermeßlich ist, oder da, wo unserer Kraft, sofern wir lebendige Wesen sind, sich eine Macht der Natur entgegenstellt, gegen welche jene in nichts verschwindet\". - Beispiele des ersten Falls sind z.B. ungeheure Gebirgs- und Felsenmassen, deren Gipfel das Auge nicht erreicht, der weite, nur vom Himmel umwölbte Ocean, das Weltgebäude in seiner Unermeßlichkeit, für welche jeder mögliche Maßstab des Menschen unzureichend befunden wird. Die gemeine Betrachtung dieses Unermeßlichen der Natur ist, es als das Unendliche selbst anzusehen; mit dieser Ansicht ist durchaus kein Gefühl der Erhabenheit, vielmehr der Niederschlagung verbunden. In der Größe als solcher ist gar nichts Unendliches, bloß in ihr als Widerschein *wahrer *Unendlichkeit. Die Anschauung des Erhabenen tritt dann ein, wenn die sinnliche Anschauung für die Größe des sinnlichen Gegenstandes unangemessen gefunden wird, und nun das wahre Unendliche hervortritt, für welches jenes bloß sinnliche Unendliche zum Symbol wird. Das Erhabene ist insofern eine Unterjochung des Endlichen, welches Unendlichkeit *lügt*, durch das wahre Unendliche. Es kann keine vollkommenere Anschauung des Unendlichen geben, als wo das Symbol, in welchem es angeschaut wird, in seiner Endlichkeit die Unendlichkeit heuchelt. \"Den bloß sinnlichen Beschauer kann (um mich hier"}]}, {"page_pdf": 1670, "page_book": 463, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Schillers Worte1 zu bedienen) die Unermeßlichkeit der Natur nur an die Schranken seiner Fassungskraft, ebenso wie die furchtbare und mit unmeßbaren Kräften verderbende Natur einzig an seine Ohnmacht erinnern. In der bloß sinnlichen Anschauung würde er sich nun entweder mit Kleinmuth oder Entsetzen von diesem großen Bild der Natur abwenden. Aber nicht so bald erhebt er sich zur absoluten Contemplation, kaum steigt ihm das Unendliche einer höheren Anschauung herab in die Fluth dieser Erscheinungen und verbindet sich mit dem Ungeheuren der sinnlichen Anschauung als seiner bloßen Hülle, so fangen die wilden Naturmassen um ihn her an eine ganz andere Anschauung für ihn zu werden, indem ihm das relativ Große außer ihm nur der Spiegel ist, worin er das *absolut* Große, das Unendliche an und für sich selbst erblickt. Absichtlich bietet er nun das Vermögen, das an sich Unendliche anzuschauen, auf, um das sinnlich-Unendliche ihm als bloße Form zu unterwerfen, und in diesem Unterliegen des sinnlich-Großen die Ueberlegenheit seiner Ideen über das *Höchste*, was die Natur aufbieten oder darstellen kann, desto unmittelbarer zu empfinden. Diese Anschauung des Erhabenen ist ihrer Verwandtschaft mit dem Ideellen und Sittlichen unerachtet eine ästhetische Anschauung, um hier einmal dieses Wort zu gebrauchen. Das Unendliche ist das Herrschende, aber es herrscht doch nur, inwiefern es in dem sinnlich-Unendlichen, das insofern wieder ein Endliches ist, angeschaut wird. Dieses Anschauen des wahrhaft Unendlichen in dem Unendlichen der Natur ist die Poesie, welche der Mensch allgemein üben kann; denn es ist der Anschauende selbst, dem das relativ Große der Natur zum Erhabenen wird, indem er es zum Symbol des absolut Großen macht. Die moralische und intellektuelle Schlaffheit, die Weichlichkeit wie die Feigheit der Gesinnung wendet sich von diesen großen Anblicken ab, welche ihr ein furchtbares Bild ihrer eignen Nichtigkeit und"}, {"type": "footnote", "text": "1 Ueber das Erhabene (Taschenausgabe 1847, Bd. 12, S. 292). D. H."}, {"type": "paragraph", "text": "Verächtlichkeit vorhalten. Das Erhabene der Natur wie das der Tragödie und der Kunst überhaupt reiniget die Seele, indem es sie von dem bloßen Leiden befreit. Wie der tapfere Mann in dem Moment, wo alle Kräfte der Natur und des Verhängnisses auf ihn zugleich feindlich eindringen, in dem Moment selbst des höchsten Leidens zur höchsten Befreiung und zu einer überirdischen Lust übergeht, die alle Schranken des Leidens abgelegt hat, so geht dem, der das Antlitz der furchtbaren und zerstörenden Natur erträgt, das höchste Aufgebot ihrer verderbenden Kräfte selbst, die absolute Anschauung auf, welche der Sonne gleicht, die aus den Gewitterwolken bricht. Schwerlich möchte es in einem Zeitalter der Kleinlichkeit der Gesinnungen und Verkrüppelung des Sinns ein allgemeineres Mittel geben, sich selbst davor zu bewahren und immer davon zu reinigen, als diesen Verkehr mit der großen Natur, schwerlich auch eine reichere Quelle großer Gedanken und des heldenmüthigen Entschlusses als die immer erneuerte Lust in der Anschauung des sinnlich-Furchtbaren und -Großen. Wir haben in dem Bisherigen das Erhabene der beiden Arten betrachtet, jenes, in welchem die Natur durch ihre Größe für das Fassungsvermögen, und jenes, in welchem sie durch ihre Macht für unsere physische Kraft absolut groß und unendlich, in Beziehung auf das wahrhaft Unendliche aber selbst wieder nur relativ groß, relativ unendlich ist. Wir haben nun noch genauer als bisher die *Form *der Anschauung des Erhabenen zu bestimmen. Die Form ist, wie immer, so auch hier das Endliche, nur ist die Bestimmung hinzugefügt worden, daß"}]}, {"page_pdf": 1671, "page_book": 465, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "es hier als relativ unendlich, und in der Beziehung auf sinnliche Anschauung als absolut groß erscheinen müsse. Es ist aber eben dadurch von dem Endlichen die *Form *negirt, und wir begreifen hierdurch, wie es eben das Formlose ist, welches für uns am unmittelbarsten *erhaben*, d.h. Symbol des Unendlichen als solchen wird. Die Form, welche als Form unterschieden wird, setzt das Endliche eben dadurch als ein Besonderes, das Endliche, welches das Unendliche"}, {"type": "paragraph", "text": "aufnehmen soll, muß aber diesem als Symbol adäquat seyn, welches nun auf doppelte Weise geschehen kann, entweder wenn es absolut formlos oder absolut geformt ist, denn beides ist selbst wieder eins und dasselbe. Die absolute Formlosigkeit ist eben die höchste, die absolute Form, wo sich das Unendliche in ein Endliches faßt, ohne von seinen Schranken berührt zu werden. Eben darum aber hat auch die wirklich absolute Form, in der alles Beschränkende aufgehoben ist, wie in den Götterbildungen des Jupiter, der Juno u.s.w. für uns wieder dieselbe Wirkung wie die absolute Formlosigkeit. Die Natur ist allerdings nicht nur in ihrer unserer Fassungskraft unerreichbaren Größe oder in ihrer unserer physischen Gewalt unbesiegbaren Macht erhaben, sie ist es auch allgemein in dem Chaos oder, wie Schiller sich auch ausdrückt1, in der *Verwirrung *ihrer Erscheinungen überhaupt. Das *Chaos *ist die Grundanschauung des Erhabenen, denn wir fassen selbst die Masse, die für die sinnliche Anschauung zu groß, wie die Summe blinder Kräfte, die für unsere physische Macht zu gewaltig ist, in der Anschauung nur als Chaos auf, und nur insofern wird es uns zum Symbol des Unendlichen. Die Grundanschauung des Chaos selbst liegt in der Anschauung des Absoluten. Das innere Wesen des Absoluten, worin alles als eins und eins als alles liegt, ist das ursprüngliche Chaos selbst; aber eben auch hier begegnen wir jener Identität der absoluten Form mit der Formlosigkeit; denn jenes Chaos im Absoluten ist nicht *bloße *Negation der Form, sondern Formlosigkeit in der höchsten und absoluten Form, sowie umgekehrt höchste und absolute Form in der Formlosigkeit: absolute Form, weil in jede Form alle und in alle jede gebildet ist, Formlosigkeit, weil eben in dieser Einheit aller Formen keine als besondere unterschieden wird2."}, {"type": "footnote", "text": "1 a.a.O. S. 293. D. H. 2 Man vergl. zu dem Gedanken: Formlosigkeit = absolute (höchste) Form die Einleitung zum Kritischen Journal (Ueber das Wesen der philos. Kritik überhaupt u.s.w.) S. IX. (oben S. 7). D. H."}, {"type": "paragraph", "text": "Durch die Anschauung des Chaos, möchte ich sagen, geht der Verstand zu aller Erkenntniß des Absoluten, es sey in der Kunst oder in der Wissenschaft, über. Das gemeine Wissen, wenn es, nach vergeblichem Bestreben das Chaos von Erscheinungen in der Natur und der Geschichte mit dem Verstand auszuschöpfen, zu dem Entschluß übergeht, \"das *Unbegreifliche *selbst, wie Schiller sagt1, zum Standpunkt der Beurtheilung\", d.h. zum Princip zu machen, scheint hier mit dem ersten Schritt zur Philosophie oder wenigstens zur ästhetischen Anschauung der Welt. Erst in dieser Ungebundenheit, die dem gemeinen Verstand als Gesetzlosigkeit erscheint, erst in dieser Selbständigkeit und Freiheit von Bedingungen, in welcher sich selbst jede Naturerscheinung für ihn hält, da er niemals eine vollkommen aus der andern begreifen kann und nothgedrungen jeder ihre Absolutheit zugestehen muß - erst in dieser"}]}, {"page_pdf": 1672, "page_book": 467, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Unabhängigkeit jeder einzelnen Erscheinung, die dem nur auf Bedingungen gehenden Verstand ein Ende macht, kann er die Welt als das wahre Sinnbild der Vernunft, in der alles unbedingt, und des Absoluten, in dem alles frei und ungezwungen ist, erkennen. Von dieser Seite stellt sich nun auch die Erhabenheit der *Gesinnung *dar, vorzüglich inwiefern derjenige, in welchem sie sich zeigt, zugleich als Symbol der ganzen Geschichte dienen kann. Die selbige Welt, welche noch als Natur sich in Schranken von Gesetzen hält, die nur weit genug gezogen sind, um innerhalb derselben noch einen Schein der Gesetzlosigkeit zu behalten, scheint als Geschichte alle Gesetzmäßigkeit abgelegt zu haben. Das Reale rächt sich hier, und kehrt mit seiner ganzen strengen Nothwendigkeit zurück, um hier vielmehr alle Gesetze, welche das Freie sich selbst gibt, zu zerstören und sich ihm gegenüber frei zu zeigen. Die Gesetze und Absichten der Menschen sind hier kein Gesetz für die Natur, sie \"tritt, um mich wieder einer Stelle von Schiller2 zu bedienen, die Schöpfungen der Weisheit und des Zufalls mit gleicher Achtlosigkeit in den Staub, und reißt das Wichtige wie das Geringe, das Edle wie das Gemeine in Einem Untergang mit sich fort. Die"}, {"type": "footnote", "text": "1 a.a.O. S. 296. D. H. 2 ebendaselbst. D. H."}, {"type": "paragraph", "text": "vollkommensten Werke und ihre eignen mühsamsten Erwerbungen verdirbt und verschwendet sie in dem Augenblick, und bildet dagegen an einem Werke der Thorheit Jahrhunderte lang fort. Dieser Abfall der Natur im Großen von der Regel des Verstandes ist es, (setzt Schiller hinzu) was die absolute Unmöglichkeit unmittelbar sichtbar macht, die Natur selbst wieder durch Naturgesetze zu erklären, die bloß in ihr, aber nicht von ihr gelten. Die einfache Betrachtung hievon führt das Gemüth schon unwiderstehlich hinaus über die Welt der Erscheinungen in die Ideenwelt, aus dem Bedingten ins Unbedingte\". Der Held der Tragödie, der alle Härten und Tücken des Schicksals zusammengehäuft auf sich dennoch ruhig erträgt, repräsentirt eben deßwegen jenes *An-sich*, jenes Unbedingte und Absolute selbst wieder in seiner Person; sicher seines Plans, den keine Zeit ausführt, aber auch keine vernichtet, blickt er auf den Strom des Weltlaufs ruhig herab. Das Unglück, welches die tragische Person *sinnlich* niederwirft und vernichtet, ist ein ebenso nothwendiges Element der sittlich-erhabenen als der Streit der Naturkräfte und die Uebermacht der Natur über die bloß sinnliche Fassungskraft für das *physisch-*Erhabene. Nur im Unglück wird die Tugend, nur in der Gefahr die Tapferkeit erprobt; der Tapfere im Kampf mit dem ersten, worin er weder physisch siegt, noch moralisch unterliegt, ist nur Symbol des Unendlichen, dessen, was *über alles Leiden *ist. Nur in dem Maximum des Leidens kann das Princip offenbar werden, in dem *kein *Leiden ist, wie alles überall nur in seinem Entgegengesetzten objektiv wird. Das wahre tragisch Erhabene ruht eben deßwegen auf den zwei Bedingungen, daß die moralische Person den Naturkräften unterliegt und zugleich durch die *Gesinnung *siegt; es ist wesentlich, daß der Held nur durch das siege, was nicht Naturwirkung oder Glück seyn kann, also nur durch die Gesinnung, wie bei Sophokles immer, nicht daß etwas Anderes, Fremdartiges, wie oft schon bei Euripides, das Herbe seines Schicksals vermeintlich wieder lindere. Die *falsche *Schonung, welche dem schlaffen Geschmack huldigt, der den ernsten Anblick der Nothwendigkeit nicht erträgt, ist selbst nicht nur an sich verächtlich, sondern verfehlt auch die eigentliche Kunstwirkung, die sie beabsichtigt."}]}, {"page_pdf": 1673, "page_book": 469, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Es ist jetzt hinlänglich erläutert, inwiefern das Erhabene Einbildung des Unendlichen im Endlichen, nur daß das Endliche immer selbst als ein relativ Unendliches erscheine (denn nur in diesem Fall wird das *wahrhaft Unendliche *als solches unterschieden) als relativ Unendliches, es sey nun für die Auffassung, oder für die physische Macht, oder für das Gemüth, wie in der Tragödie, wo es durch das Unendliche der moralischen Gesinnung besiegt wird. Ich will hier nur noch in Bezug auf das Erhabene *Eine *Bemerkung machen, die aus unserer bisherigen Darstellung folgt, nämlich, daß nur in der *Kunst *das Objekt selbst erhaben ist, da es die Natur nicht an sich ist, weil hier die Gesinnung oder das Princip, durch welches das Endliche zum Symbol des Unendlichen herabgesetzt wird, doch nur in das Subjekt fällt. Im Erhabenen, sagten wir, werde das sinnlich Unendliche durch das wahre Unendliche bezwungen. Im *Schönen *darf das Endliche sich wieder zeigen, indem es im Schönen nicht anders als selbst schon eingebildet dem Unendlichen erscheint. Dort (im Erhabenen) zeigt sich das Endliche noch gleichsam in der Empörung gegen das Unendliche, obgleich es in diesem Verhältniß selbst zum Symbol von ihm wird. Hier (im Schönen) ist es ihm ursprünglich versöhnt. Daß dieß das Verhältniß des Schönen zum Erhabenen seyn müsse, *inwiefern *beide einander entgegengesetzt werden, geht übrigens durch den Gegensatz aus dem hervor, was von dem Erhabenen bewiesen worden ist. Allein eben daraus das Folgende."}, {"type": "paragraph", "text": "§. 66. *Das Erhabene in seiner Absolutheit begreift das Schöne, wie das Schöne in seiner Absolutheit das Erhabene begreift.* Dieß ist allgemein schon daraus einzusehen, daß das Verhältniß beider wie das der beiden Einheiten ist, von denen aber jede gleichfalls in ihrer Absolutheit selbst die andere begreift. Das Erhabene, inwiefern es nicht *schön*, wird aus diesem Grunde auch nicht *erhaben*, sondern nur ungeheuer oder abenteuerlich seyn. Ebenso muß die absolute Schönheit mehr oder weniger immer zugleich auch die furchtbare"}, {"type": "paragraph", "text": "Schönheit seyn. Da übrigens Schönheit immer und nothwendig *Begrenzung *fordert, so wird die Begrenzungslosigkeit selbst zur Form wie in der Bildung des Jupiter, wo keine als die nothwendige Begrenzung ist, nur damit überhaupt ein Bild sey, denn übrigens ist alle andere Begrenzung aufgehoben, z.B. weder jung noch alt. Ebenso ist Juno nur so viel begrenzt, als nöthig ist weibliche Gestalt zu seyn. Je geringer die Begrenzung, innerhalb welcher ein Bild als Schönheit ist, desto mehr neigt es gegen das Erhabene hin, ohne doch aufzuhören Schönheit zu seyn. Apollos Schönheit hat mehr Begrenzung als Jupiters - er ist *jugendlich-*schön. Bei ihm ist die Begrenzung nicht bloß wie bei Jupiter so weit, daß nur überhaupt das Unendliche im Endlichen erscheint, das Endliche gilt auch schon für sich wieder als eingebildet dem Unendlichen. Näher liegt das Beispiel der männlichen und weiblichen Schönheit; dort zeigt auch die Natur nur das Nothwendige von Begrenzung, hier ist sie freigebig mit derselben. Hieraus folgt, daß zwischen Erhabenheit und Schönheit kein qualitativer und wesentlicher, sondern nur ein quantitativer Gegensatz. Das Mehr oder Weniger von Schönheit oder von Erhabenheit gehört (dient) selbst wieder zur Begrenzung: Juno = erhabene Schönheit, Minerva = schöne Erhabenheit. Je mehr aber die Begrenzung das Unendliche versöhnt, desto reiner schön. Indeß weil eben wegen der Indifferenz des Erhabenen und Schönen die Bestimmung auch wieder relativ wird, so daß dasselbe, was in einer Beziehung als Erhabenheit begriffen wird, z.B. das Bild der Juno, in einer andern Beziehung wieder als Schönheit im Gegensatz gegen Erhabenheit erscheinen kann (wie Juno im Vergleich mit Jupiter), so erhellt, daß überhaupt und in keiner Sphäre etwas schön genannt werden kann, das in anderer Beziehung nicht auch erhaben wäre, daß aber eben deßwegen in jedem, das nur überhaupt für sich absolut ist, beides unauflöslich voneinander durchdrungen erscheine, wie z.B."}]}, {"page_pdf": 1674, "page_book": 470, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Juno, nicht verglichen, sondern für sich betrachtet, oder um aus einer andern Sphäre Beispiele zu nehmen, Sophokles im Vergleich mit Aeschylos als schön, für sich aber und absolut betrachtet, als"}, {"type": "paragraph", "text": "eine ganz unauflösliche Vereinigung des Schönen und Erhabenen erscheine. Wollte man sich in Ansehung des Erhabenen etwa auf die bloße Vorstellung der Unbegrenztheit und Formlosigkeit berufen, welche damit in der Regel verbunden wird, so ist diese, wie bereits gezeigt, allerdings eine nothwendige Bedingung des Erhabenen, aber nicht so, daß sie nicht selbst wieder innerhalb streng begrenzter Formen möglich wäre, sondern so vielmehr, daß eben die höchste Form (wo die Form in der Form nicht mehr erkannt wird) zur Formlosigkeit, wie in andern Fällen die Formlosigkeit selbst zur Form wird. Jenes, wie gesagt, in der Bildung des Jupiter und in dem Kopf der sogenannten Juno Ludovisi, wo das Erhabene so mit dem Schönen durchdrungen ist, daß es nicht geschieden werden kann. Winkelmann nimmt eine hohe Grazie an, und die Alten selbst haben die furchtbaren Grazien des Aeschylos gepriesen. Im Kunstwerk selbst als Objektivem verhalten sich Erhabenheit und Schönheit wie im Subjektiven Poesie und Kunst. Aber auch in der Poesie für sich, sowie der Kunst für sich, ist wieder derselbe Gegensatz möglich, dort als naiv und sentimental, hier als Styl und Manier. Daher:"}, {"type": "paragraph", "text": "§. 67. *Derselbe Gegensatz der beiden Einheiten drückt sich in der Poesie für sich betrachtet durch den Gegensatz des Naiven und Sentimentalen aus. Allgemeine Anmerkung.* In Ansehung aller dieser Gegensätze muß man beständig im Auge behalten, daß sie in der Absolutheit aufhören es zu seyn. Nun ist aber der Fall eben *der*, daß die erste Einheit, die, in welcher das Unendliche ins Endliche eingebildet ist, immer und nothwendig als die *vollendete* erscheint, daß hier der Ausgangspunkt und der der Vollendung in eins zusammenfallen, daß dagegen für das andere Glied des Gegensatzes sehr wohl der absolute Ausdruck fehlen kann, eben deßwegen, weil es nur in der Nicht-Absolutheit als Entgegengesetztes erscheint. Dieß ist der Fall z.B. mit dem Sentimentalen und Naiven. Das Poetische und Genialische ist immer und nothwendig naiv; das Sentimentale ist also das Entgegengesetzte nur in seiner Unvollkommenheit. Wir statuiren also nicht sowohl Naives und"}, {"type": "paragraph", "text": "Sentimentales in der Poesie, sondern wir statuiren allgemein * zwei Richtungen *in der Poesie, die, wo das Allgemeine als ins Besondere gebildet erscheint, und die, wo das Besondere ins Allgemeine gebildet. In der Absolutheit müßten beide eins, d.h., nachdem naiv der einzige Ausdruck ist, den wir für die Absolutheit haben, beide müßten naiv seyn. Sentimental ist also nur der Ausdruck der andern Richtung in ihrer Mangelhaftigkeit, insofern also das Verhältniß von Naiv zu Sentimental keineswegs wie das im vorigen Satze von Erhabenheit zu Schönheit, wo jede für sich ein Absolutes bezeichnet. Es ist bekannt, daß *Schiller *diesen Gegensatz zuerst in einem Aufsatz über naive und sentimentalische Dichtung geltend gemacht hat, der außer diesem sehr reich ist an fruchtbaren Ideen. Ich entlehne hier folgende Sätze aus demselben, welche am besten dazu dienen, jenen Gegensatz deutlich zu machen. \"Naiv ist zu erklären als Natur ober Erscheinung der Natur, sofern sie die Kunst beschämt\". (Diese Erklärung befaßt die Bedeutung des Worts in Verhältnissen des Umgangs *und *die höhere, welche ihm hier in Beziehung auf Kunst gegeben wird. Schon daß der Grundcharakter des Naiven der ist, daß es"}]}, {"page_pdf": 1675, "page_book": 472, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "*Natur *seyn muß, beweist, daß es dem ersten der beiden Gegensätze ursprünglich entspreche.)"}, {"type": "paragraph", "text": "\"Das Naive * ist *Natur, das Sentimentale *sucht *die Natur\". \"Das naive Gemüth empfindet natürlich, das sentimentale empfindet *das *Natürliche\". Am auffallendsten ist dieser Gegensatz wieder in der Vergleichung des Antiken und Modernen, wie dieß Schiller ebenfalls sehr schön nachweist. Die Anschauung des Erhabenen in der Natur z.B. ist bei dem Griechen durchaus nicht die empfindsame, welche die bloße Rührung davon empfindet, ohne bis zur freien, kalten Betrachtung zu gehen. Dagegen ist das rein bloß subjektive Interesse an der Natur ohne alle Objektivität der Anschauung oder des Denkens Grundzug im Charakter der Modernen, und sie selbst sind in dem Verhältniß entfernt von der Natur, in welchem sie die Natur empfinden, nicht anschauen oder darstellen. Man kann den ganzen Unterschied des naiven und sentimentalen"}, {"type": "paragraph", "text": "Dichters darin zusammenfassen, daß bei jenem nur das *Objekt *waltet, bei diesem das Subjekt als Subjekt hervortritt, daß jener über sein Objekt bewußtlos *scheint*, dieser es mit seinem Bewußtseyn beständig begleitet und dieses Bewußtseyn zu erkennen gibt. Jener ist kalt und fühllos bei seinem Objekt, wie die Natur, dieser gibt uns sein Gefühl mit zu genießen. Jener zeigt keine Vertraulichkeit gegen uns, nur das Objekt ist uns verwandt, er selbst entflieht uns; dieser macht, indem er das Objekt darstellt, zugleich auch sich selbst zum Reflex desselben. Ebenso wie in der Poesie selbst mischt sich dieser Gegensatz auch in die Beurtheilung ein; es gehört ebenso zum modernen Charakter, daß ihn in der Regel die Fühllosigkeit des Dichters kalt läßt (das Objekt muß schon durch die Reflexion hindurchgegangen seyn, um auf ihn zu wirken), ja daß ihn das, was eben die höchste Kraft aller Poesie ist, nur das Objekt walten zu lassen, an dem Dichter empört. Es erhellt schon aus Schillers Abhandlung, daß der Grundcharakter der Modernen im Gegensatz gegen die Alten als der sentimentale ausgedrückt werden kann. Daß diese Behauptung aber wenigstens Beschränkung leide, zeigt schon die einzige Ausnahme des Shakespeare, welche auch Schiller macht. Es möchte sich eben auch in dieser Beziehung mit Shakespeare verhalten wie in der Beziehung auf den früheren Gegensatz der bewußten und bewußtlosen Seite. Die vollkommene Indifferenz des Naiven und Sentimentalen selbst wieder (denn ich habe schon bemerkt, daß naiv ja eben auch wieder naiv nur für den sentimentalen Beschauer) hat vielleicht überhaupt kein Neuerer erreicht, also auch Shakespeare nicht. Der Grund, der Ausgangspunkt ist hier immer die Entgegensetzung des Subjekts und Objekts, d.h. das Sentimentale, nur im Objekt wieder zur Naivheit reducirt. Ganz unterscheidbar liegen in Ariosto die Elemente des Sentimentalen und Naiven beieinander; man könnte von ihm sagen: er ist auf naive Weise sentimental, anstatt daß Shakespeare innerhalb des Sentimentalen ganz und gar naiv ist. Für die äußere Erscheinung des Naiven ist noch zu bemerken, daß es sich immer durch Simplicität und Leichtigkeit der Behandlung ebenso sehr als durch strenge Nothwendigkeit auszeichnen wird. Wie das"}, {"type": "paragraph", "text": "Schöne in dem Maße erhaben ist, in welchem zu seiner Darstellung nur das *Nothwendige *erfordert wird, so gibt es kein größeres Zeichen des Genies, als daß es mit wenigen strengen und nothwendigen Zügen das Objekt zur vollkommenen Anschauung bringt (*Dante*). Für das Genie gibt es keine *Wahl*, weil es nur das Nothwendige kennt und nur dieses will. Ganz anders ist der sentimentale Dichter daran, welcher reflektirt, und nur rührt und selbst gerührt wird, inwiefern er reflektirt. Der Charakter des naiven Genies ist vollständige - *Nachahmung *nicht sowohl, wie Schiller sich ausdrückt1, als vielmehr *Erreichnung *der"}]}, {"page_pdf": 1676, "page_book": 474, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Wirklichkeit; sein Objekt ist unabhängig von ihm, an sich selbst. Der sentimentale Dichter strebt nach einem Unendlichen, das, weil es in dieser Richtung nicht zu erreichen ist, auch nie zur Anschauung kommt."}, {"type": "footnote", "text": "1 a.a.O. (Taschenausgabe 1847, Bd. 12, S. 188.) D. H."}, {"type": "paragraph", "text": "§. 68. *Die Poesie in ihrer Absolutheit ist an sich weder naiv noch sentimental.* Nicht naiv, denn dieß ist eine Bestimmung, die selbst nur durch den Gegensatz gemacht wird (das Absolute erscheint nur dem Sentimentalen naiv), das Sentimentale aber ist an und für sich selbst eine Nicht-Absolutheit. Demnach etc. *Anmerkung.* Der ganze Gegensatz ist also selbst ein subjektiver, ein bloßer Erscheinungsgegensatz. Dieß läßt sich selbst sogar als Thatsache nachweisen. Von Sophokles z.B. wird niemand versucht werden zu sagen, daß er sentimental sey, aber gerade eben auch nicht, daß er naiv sey. Er ist mit Einem Wort der schlechthin absolute ohne alle weitere Bestimmung. Schiller hat seine Beispiele in Ansehung des Antiken vorzüglich aus dem Epos entlehnt. Nur möchte man sagen, daß es mit zur Begrenzung, zur besondern *Art* des Epos gehöre, daß es naiv *erscheine*, wie z.B. das Homerische in den meisten Zügen seiner Helden. Wollte man das Sentimentale für etwas gelten lassen, so könnte man es, in wiefern es überhaupt etwas wäre, dem Lyrischen gleichsetzen. Das dramatische Werk aber kann eben deßwegen weder naiv noch sentimental erscheinen, und eben daß Shakespeare z.B. naiv erscheinen kann, würde ihn in dieser Rücksicht wieder als Modernen charakterisiren."}, {"type": "paragraph", "text": "§. 69. *Der Gegensatz der beiden Einheiten in der Kunst für sich betrachtet kann sich nur als Styl und Manier ausdrücken. Anmerkung.* Dieselbe Bemerkung, die ich schon bei dem vorhergehenden Gegensatz gemacht habe, findet hier noch weit mehr statt. Von den beiden Entgegengesetzten ist *Styl *das Absolute, Manier das Nicht-Absolute, insoweit Verwerfliche. Die Sprache hat nur Einen Ausdruck für die Absolutheit in beiden Richtungen. Die Absolutheit in der Kunst besteht immer darin, daß das *Allgemeine *der Kunst und das *Besondere*, welches sie im Künstler als Individuum annimmt, absolut eins, dieses Besondere das ganze Allgemeine sey und umgekehrt. Nun läßt sich wohl denken, daß diese Indifferenz sich auch vom Besonderen aus erlangen lasse, oder daß der Künstler die Besonderheit *seiner *Form, sofern sie die seinige ist, in die Allgemeinheit des Absoluten bilden könne, ebenso wie umgekehrt gedacht werden kann, daß die allgemeine Form in dem Künstler sich bis zur Indifferenz mit der besonderen, die er als Individuum haben *muß*, in-eins-bilde. Im ersten Betracht könnte man alsdann Styl die absolute Manier nennen, so wie im entgegengesetzten Fall (wo jenes nicht erreicht) Manier der nicht-absolute, der verfehlte, nicht-erlangte Styl heißen müßte. Allgemein ist anzumerken, daß dieser Gegensatz noch von dem *ersten *herfließt, den wir in dieser Untersuchung gemacht haben, nämlich da sich die Kunst nur im Individuum manifestiren kann, jene aber immer absolut ist, so kommt es vorzüglich wieder auf die Synthese des Absoluten mit dem Besonderen an. Die bloß empirischen Theoretiker befinden sich in nicht geringer Verlegenheit, wenn sie den Unterschied von Styl und Manier erklären sollen, und es zeigt sich hier vielleicht am deutlichsten das allgemeine Verhältniß oder die allgemeine Bewandtniß, die es mit den Gegensätzen in der Kunst überhaupt hat. Der eine ist immer der absolute, der andere *erscheint *als Gegensatz nur, sofern er nicht"}]}, {"page_pdf": 1677, "page_book": 475, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "ist, und nur, sofern er gleichsam auf halbem Wege zur Vollendung aufgenommen"}, {"type": "paragraph", "text": "wird. Nämlich die Besonderheit kann unbeschadet der Besonderheit absolut, sowie das Absolute unbeschadet der Absolutheit besonder seyn. Die besondere Form *soll *selbst wieder die absolute seyn, nur dann ist sie in der Indifferenz mit dem Wesen, und läßt dieses frei. *Styl *also schließt nicht die Besonderheit von sich aus, sondern ist vielmehr die *Indifferenz * der allgemeinen und absoluten Kunstform mit der besondern Form des Künstlers, und ist Styl so nothwendig, als daß die Kunst nur im Individuum sich äußern kann. Styl würde nur immer und nothwendig die wahre Form, insofern also wieder das Absolute, Manier nur das Relative seyn. Es ist aber durch die angenommene Indifferenz eben nicht bestimmt, daß sie durch Einbildung des Allgemeinen ins Besondere oder umgekehrt durch Hineinbildung der besonderen Form in die allgemeine gesetzt sey. Es stellt sich hier, wie gesagt, nur wieder das schon Bemerkte ein, daß die Einbildung des Absoluten in das Besondere immer als das Vollendete, und also in dem gegenwärtigen Fall allein als Styl erscheint. Die entgegengesetzte Einheit kann als *entgegengesetzte *eben nur in der Nicht-Absolutheit erscheinen: ist sie absolut, so heißt alsdann auch *sie *Styl, ist sie nicht absolut, so ist sie Manier. Man wird gewiß nicht leugnen können, daß auch in der andern Richtung, nämlich die von der Besonderheit ausgeht, *Styl *erreichbar sey, obgleich immer noch die Spur dieser formalen Differenz übrig bleiben, und der in dieser Richtung erreichte Styl die *absolute Manier *heißen kann. Styl wird in diesem Sinn eine *absolute *(zur Absolutheit erhobene) *Besonderheit*, wie in der ersten Bedeutung eine besondere (zur Besonderheit gebildete) Absolutheit bedeuten. Im Ganzen muß überhaupt der Styl der Modernen von der ersten Art seyn, da (nach §. 58) hier die Besonderheit immer der Ausgangspunkt ist, sowie dagegen nur die Alten den Styl der ersten Gattung haben. Dieß kann behauptet werden, ohne den Modernen zu nahe zu treten, da ihnen der Styl überhaupt zugestanden wird. Daß in der letzten Vollendung der modernen Kunst auch dieser Gegensatz verschwinden müsse, ist ohnehin offenbar."}, {"type": "paragraph", "text": "Auch die Natur, kann man sagen, hat eine Manier in diesem Sinn oder einen gedoppelten Styl. Sie hat Manier in allem, was auf die Hineinbildung des Besonderen ins Allgemeine geht, z.B. in der Färbung der Körper, vorzüglich in der organischen Welt, wo sie in der männlichen Gestalt offenbar Styl hat, dagegen sie in der weiblichen Schönheit, wo so viele Besonderheiten mit in die Bildung aufgenommen werden mußten, in gewissem Sinn manierirt ist. Aber eben dieß ist Beweis, daß auch in dieser Richtung Schönheit, demnach Styl möglich ist. Es hat daher jemand sehr geistreich gesagt, daß, wenn z.B. Shakespeare Manier hätte, unser Herrgott auch Manier haben müßte. Man kann es von den Modernen nicht hinwegnehmen, daß sie nur in der Richtung vom Besonderen zum Allgemeinen Styl haben. Aber ebensowenig kann man den Neueren absprechen, daß sie in *dieser Richtung *Styl erreicht haben und zu erreichen fähig sind, so sehr, daß selbst innerhalb der modernen Kunst wieder die zwei Richtungen erkennbar sind. So ist derjenige der Modernen, der in der bildenden Kunst Styl vor allen hat, ohne Zweifel Michel Angelo: sein Entgegengesetztester unter den großen Meistern ist ohne Zweifel Correggio; es wäre gewiß falsch, diesem Künstler unbedingt Manier zuzuschreiben, obgleich es ebenso unmöglich ist, ihm einen andern als den Styl der zweiten Gattung zuzuschreiben; er ist vielleicht das anschaulichste Beispiel davon, daß auch in der Richtung vom Besonderen zum Allgemeinen Styl möglich ist."}]}, {"page_pdf": 1678, "page_book": 477, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Allgemein können wir nun die Manier im verwerflichen Sinne, demnach die *Manierirtheit*, erklären als ein Geltendmachen der besonderen Form statt der allgemeinen. Da dem Künstler überhaupt nur die Form zu Gebot steht, so daß er allein durch diese das Wesen erreicht, dem Wesen, aber nur die absolute Form adäquat ist, so löst sich mit der Manier in diesem Sinne unmittelbar auch das Wesen der Kunst selbst auf. Am meisten zeigt sich Manierirtheit in einem Bestreben nach oberflächlicher, nur ungeübte Augen blendender Eleganz und schwächlicher Schönheit, in dem Geleckten, Verwaschenen mancher"}, {"type": "paragraph", "text": "Werke, deren einziges oder Hauptverdienst wenigstens das Saubere ist. Es gibt aber auch eine rohe und derbe Manier, wo mit Absicht das Uebertriebene, Forcirte gesucht wird. Immer ist Manier eine Beschränkung und zeigt sich in der Unfähigkeit, gewisse Besonderheiten der Form, es sey nun im Ganzen der Figuren (denn am besten werden die Beispiele doch von der bildenden Kunst hergenommen) oder in einzelnen Theilen zu überwinden. So gibt es Maler, die nur kurze und stämmige, andere, die nur lang und schmal auslaufende, hagere Figuren machen können; andere, die entweder nur dicke oder dünne Beine mache oder dieselbe Form der Köpfe halsstarrig immer wieder bringen. Das Manierirte zeigt sich dann noch weiter in dem Verhältniß, das den Figuren zu einander gegeben wird, vorzüglich in dem Eigensinn der Stellungen, aber selbst in der ersten Invention und der unbiegsamen Gewohnheit, alle Sujets von einer gewissen Seite, z.B. der empfindsamen, der geistreichen, oder gar witzigen aufzufassen. Das bloß Geistreiche, ebenso wie der Witz, gehört einzig zur sentimentalen Richtung, da die Kunst im großen Styl, selbst bei Aristophanes, eigentlich nie witzig, sondern immer nur groß ist. Es muß endlich noch bemerkt werden, daß die Besonderheit, welche in dem Styl zur Allgemeinheit hinzukommt, außer der des einzelnen Individuum, auch die der *Zeit *seyn kann. In diesem Sinn spricht man von dem verschiedenen Styl verschiedener Zeitalter. Der Styl, welchen sich der individuelle Künstler bildet, ist für ihn, was ein Denksystem für den Philosophen im Wissen, oder für den Menschen im Handeln ist. Winckelmann nennt ihn daher mit Recht ein System der Kunst und sagt, daß der ältere Styl auf ein System gebaut gewesen. Von den Schwierigkeiten in bedeutenden Fällen Styl und Manier und den Uebergang des Einen zu unterscheiden, wäre viel zu sagen. Allein dieß ist nicht unseres Amts und geht die allgemeine Wissenschaft der Kunst nichts an."}, {"type": "paragraph", "text": "*Allgemeine Anmerkung über die bis jetzt von §. 64-69*"}, {"type": "paragraph", "text": "*abgehandelten Gegensätze.*"}, {"type": "paragraph", "text": "Diese Gegensätze gehören alle zu einer und derselben Familie und gehen sämmtlich aus dem ersten Verhältniß der Kunst als absoluter Form zu der besondern Form hervor, die durch die Individuen gesetzt ist, durch welche sie sich äußert. Sie mußte daher gerade hier hervortreten. Gleich der erste - für die Reflexion zu machende - Gegensatz der Poesie und der Kunst zeigt uns jene als absolute, diese als besondere Form; das was in dem Genie an sich absolut-eins ist, zerlegt sich in diese beiden Erscheinungsweisen, die übrigens in ihrer Absolutheit wieder eins und dasselbe sind. Ebenso was in dem Schönen an und für sich schlechthin eins ist, zerlegt sich in dem besonderen Objekt, dem"}]}, {"page_pdf": 1679, "page_book": 479, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "einzelnen Kunstwerk, in die zwei Erscheinungsweisen des Erhabenen und Schönen, die übrigens auch wieder nur in ihrer Nicht-Absolutheit verschieden sind, so daß, wie in dem vollendeten Künstler Poesie und Kunst, ebenso in den höchsten Werken sich Erhabenheit und Schönheit unauflösbar durchdringen. Als Erhabenheit erscheint überall die absolute und allgemeine Form der Kunst, in welcher das Besondere nur ist, um die ganze Unendlichkeit in sich aufzunehmen. Als Schönheit insbesondere erscheint die besondere Form als versöhnt der absoluten und ganz in sie aufgenommen, ganz mit ihr eins. Diesen Gegensätzen sind die folgenden nicht gleich zu setzen, die nur entweder in der Poesie für sich oder in der Kunst für sich stattfinden, und die im ersten Fall, wo sie als *Naives* und *Sentimentales* erscheinen, selbst bloß subjektiv sind (indem es schon eine Subjektivität ist, das Absolute nur als naiv zu begreifen, das Sentimentale aber als solches absolut verwerflich ist) - sowie denn in dem anderen Fall wiederum nur das Eine von beiden das Absolute bezeichnet, obgleich allerdings die Verschiedenheit der Richtung besteht, in welcher das Absolute, der Styl, erreichbar ist. Innerhalb dieser bloß subjektiven und formellen Entgegensetzung"}, {"type": "paragraph", "text": "verhält sich aber das Naive und der Styl allerdings als absolute, wie das Sentimentale und die Manier immer als besondere Form. Man kann diese Gegensätze wieder auf einander beziehen und z.B. bemerken, daß Manier nie naiv seyn kann, sowie daß das Sentimentale immer und nothwendig manierirt ist. Man kann ferner sagen, daß Manier immer bloß Kunst ohne Poesie, d.h. nicht-absolute Kunst sey, daß mit der Manier sich keine Erhabenheit, eben deßwegen aber auch nicht Schönheit im absoluten Sinne vertrage. Ferner, daß das Sentimentale immer mehr als *Kunst *denn als Poesie erscheinen könne, und eben dadurch selbst der Absolutheit entbehre. Aber wir sind durch das Bisherige noch immer nicht bis zur Construktion des besonderen Kunstwerks vorgedrungen. Das Absolute bezieht sich (nach den Beweisen des §. 62) auf das hervorbringende Individuum durch den ewigen Begriff, der von ihm im Absoluten ist. Dieser ewige Begriff, das An-sich der Seele, zerlegt sich in der *Erscheinung *in Poesie und Kunst und die übrigen Gegensätze, oder vielmehr er ist der absolute Identitätspunkt dieser Gegensätze, die es nur für die Reflexion sind. Es war nicht um diese Gegensätze als solche zu thun, sondern um die Erkenntniß des Genies. Das, wovon alle diese Gegensätze nur entweder die einseitigen Erscheinungsweisen oder Bestimmungen sind, ist das absolute Princip der Kunst, das dem Künstler eingebildete Göttliche oder *An-sich.* In dem Kunstwerk an und für sich sollen diese Entgegensetzungen nie als solche hervortreten, in diesem soll immer nur das Absolute objektiv werden. Die bisherige Untersuchung war also bloß beschäftigt, das *Genie *als die absolute Indifferenz aller möglichen Gegensätze zwischen dem Allgemeinen und Besondern, *die sich in der Beziehung der Idee oder des ewigen Begriffs auf ein Individuum hervorthun können*, darzustellen. Das Genie ist eben selbst schon das, worin das Allgemeine der Idee und das Besondere des Individuums wieder gleichgesetzt wird. Aber dieses Princip der Kunst, damit es dem gleiche, dessen unmittelbarer Ausfluß es ist - dem Ewigen - muß wie dieses"}, {"type": "paragraph", "text": "den Ideen, die in ihm sind, dadurch eine von ihrem Princip unabhängige Existenz vergönnen, daß es sie als die Begriffe einzelner wirklicher Dinge existiren läßt, sie in Leiber gestaltet. Hievon ist der Beweis §§. 62 und 63 gegeben. Die Möglichkeit dieser objektiven Bildung ist es nun, was wir darzuthun haben. Erst damit wird sich uns das ganze Kunstsystem vollends entfalten."}]}, {"page_pdf": 1680, "page_book": 481, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Wir haben uns hier zu erinnern, daß die Philosophie der Kunst die allgemeine Philosophie selbst ist, nur dargestellt in der Potenz der Kunst. Wir werden also die Art, wie die Kunst ihren Ideen die Objektivität gibt, vollkommen nach der Weise begreifen, wie die Ideen einzelner wirklicher Dinge in der Erscheinung objektiv werden, oder: die gegenwärtige Aufgabe, den Uebergang der ästhetischen Idee in das conkrete Kunstwerk zu begreifen, ist dieselbe, wie die allgemeine der Philosophie überhaupt von der Erscheinung der Ideen durch besondere Dinge. Natürlich können wir hier nur gewisse Sätze als durch die allgemeine Philosophie gegeben annehmen, ohne sie zu beweisen, und wir schicken in dieser Hinsicht folgenden *Lehnsatz *voran."}, {"type": "paragraph", "text": "§. 70. *(Lehnsatz.) Das Absolute wird in der Erscheinung durch die drei Einheiten objektiv, sofern diese nicht in ihrer Absolutheit, sondern in ihrer relativen Differenz als Potenzen aufgenommen und dadurch zum Symbol der Idee werden. *Dieser Satz, da er nur Lehnsatz aus der allgemeinen Philosophie ist, bedarf hier nur der *Erläuterung.* Stoff und Form ist im Absoluten eins, es hat keinen Stoff des Producirens als sich selbst in der Allheit seiner Formen. * Erscheinen* aber kann es nicht, als wenn jede dieser Einheiten als * besondere *Einheit zum Symbol von ihm wird. In der Absolutheit sind diese Einheiten nicht von einander unterschieden; hier ist bloß Stoff, reine Unendlichkeit und Idee. Sie können als die Urideen objektiv werden nur, inwiefern jede sich selbst *als besondere Einheit *wieder zum Leib, zum Gegenbild nimmt. Unmittelbar dadurch ist für die Erscheinung die Differenziirung dessen gesetzt, was im Absoluten eins ist. So ist die erste der beiden Einheiten in ihrer Absolutheit Idee; inwiefern"}, {"type": "paragraph", "text": "sie sich selbst als Potenz - als besondere Einheit - zum Symbol nimmt, ist sie Materie. Alles Erscheinende überhaupt ist ein Gemischtes aus dem Wesen und aus der Potenz (oder der Besonderheit); das Wesen aller Besonderheit * ist *im Absoluten, dieses Wesen aber erscheint durch das Besondere. Dieß vorausgesetzt folgt nothwendig, daß das Absolute als Princip der Kunst in der Sphäre der Erscheinung oder Differenz nur dadurch objektiv wird, daß ihm *entweder *die reale *oder *die ideale Einheit zum Symbol wird, also überhaupt dadurch, daß es in getrennten Erscheinungen offenbar wird, und dort sich durch Erscheinen einer relativ-realen, hier durch Erscheinen einer relativ-idealen Welt symbolisirt."}, {"type": "paragraph", "text": "§. 71. *(Lehnsatz.) Die Idee, inwiefern sie die reale Einheit als besondere Einheit zum Symbol hat, ist Materie.* Der Beweis dieses Satzes wird in der allgemeinen Philosophie geführt. Die erscheinende Materie ist die Idee, aber von der Seite der bloßen Einbildung des Unendlichen in das Endliche, und so daß diese Einbildung selbst nur relativ, nicht absolut ist. Die erscheinende Materie ist nicht das An-sich, sie ist nur Form , Symbol, aber sie *ist - nur als Form, als* relative Differenz - wieder dasselbe mit dem, wovon sie das Symbol ist, und welches die Idee als absolute Einbildung des Unendlichen in das Endliche selbst ist."}, {"type": "paragraph", "text": "§. 72. *Der Kunst also, inwiefern sie die Form der Einbildung des Unendlichen ins Endliche als besondere Form wieder aufnimmt, wird die Materie zum Leib oder zum Symbol. *- Folgt unmittelbar. *Zusatz* 1*.* Die Kunst ist in dieser Beziehung = allgemein-bildender oder plastischer Kunst. - Gewöhnlich wird bildende Kunst in der engeren Bedeutung gebraucht, nämlich von der bildenden Kunst, wo sie sich selbst durch körperliche Gegenstände ausdrückt. Allein es ist mit der Bestimmung als bildender Kunst nicht ausgeschlossen, daß nicht innerhalb dieser allgemeinen Einheit alle Potenzen"}]}, {"page_pdf": 1681, "page_book": 482, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "wiederkehren, die in der Materie begriffen sind, und eben auf diesem Wiederkehren beruht der Unterschied der einzelnen bildenden Künste."}, {"type": "paragraph", "text": "*Zusatz* 2*. Die bildende *Kunst ist die *reale *Seite der Kunstwelt."}, {"type": "paragraph", "text": "§. 73. *Die ideale Einheit als Auflösung des Besondern ins Allgemeine, des Concreten in Begriff, wird objektiv in Rede oder Sprache . -* Auch der Beweis dieses Satzes gehört in die allgemeine Philosophie. Die Sprache ist, nur wieder real angeschaut, dieselbe Auflösung des Concreten in das Allgemeine, des Seyns in das Wissen, welche das Denken ideal ist. Die Sprache von der einen Seite betrachtet ist unmittelbarer Ausdruck eines *Idealen *- des Wissens, Denkens, Empfindens, Wollens u.s.w. - in einem *Realen*, insofern selbst ein Kunstwerk. Allein sie ist von der anderen Seite ebenso bestimmt ein Naturwerk, indem sie als die Eine nothwendige Form der Kunst nicht ursprünglich durch Kunst erfunden oder entstanden gedacht werden kann. Sie ist also ein natürliches Kunstwerk, wie es mehr oder weniger alles ist, was die Natur hervorbringt. Wir werden den überzeugendsten Beweis unseres Satzes nur in einem allgemeineren Zusammenhang, vorzüglich aber durch die Entgegensetzung der Sprache und der anderen Form der Kunst, der Materie, führen können. Folgende Verhältnisse sind es, aus denen die Bedeutung der Sprache am bestimmtesten eingesehen werden kann. Das Absolute ist seiner Natur nach ein ewiges Produciren, dieses Produciren ist sein Wesen. Sein Produciren ist ein absolutes Affirmiren oder Erkennen, dessen zwei Seiten die beiden angegebenen Einheiten sind. Wo der absolute Erkenntnißakt nur dadurch objektiv wird, daß die *eine *Seite desselben als besondere Einheit zur Form wird, da erscheint er nothwendig verwandelt in ein anderes, nämlich in ein Seyn. Die absolute Einbildung des Unendlichen ins Endliche, welche die *reale *Seite desselben ist, ist an sich kein Seyn, sie ist in ihrer Absolutheit wieder die ganze Idee, die ganze unendliche Selbstaffirmation; nur in ihrer Relativität, also *als besondere Einheit* aufgenommen,"}, {"type": "paragraph", "text": "erscheint sie nicht mehr als Idee, als Selbstaffirmation, sondern als Affirmirtes, als Materie; die reelle Seite als besondere wird hier zum Symbol der absoluten Idee, die erst durch diese Hülle hindurch als solche erkannt wird. Da wo der Idee die ideale Einheit selbst, als besondere, zur Form wird - in der idealen Welt - wird sie nicht in ein anderes verstellt, sie bleibt ideal, aber so, daß sie die andere Seite dagegen zurückläßt, und demnach nicht als absolut Ideales erscheint, sondern als bloß relativ Ideales, das das Reale außer sich - sich entgegenstehend - hat. Als rein-Ideales wird sie aber nicht objektiv, sie fällt in das Subjektive zurück, und ist selbst das Subjektive; sie strebt also nothwendig unmittelbar *wieder *nach einer Hülle, einem Leib, durch den sie ihrer Idealität unbeschadet objektiv werde; sie integrirt sich wieder durch ein Reales. In dieser Integration entsteht das entsprechendste Symbol der absoluten oder unendlichen Affirmation Gottes, weil diese *hier *sich durch ein Reales darstellt, ohne daß sie aufhörte ideal zu seyn (welches eben die höchste Forderung ist), und * dieses *Symbol ist die Sprache, wie sich leicht einsehen"}]}, {"page_pdf": 1682, "page_book": 484, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "läßt. Aus diesem Grunde hat nicht nur in den meisten Sprachen Sprache und Vernunft (welche eben das absolute Erkennen, das Erkennende der Idee ist) ein und denselben Ausdruck, sondern auch in den meisten philosophischen und religiösen Systemen, vorzüglich des Orients, ist der ewige und absolute Akt der Selbstaffirmation in Gott - der Akt seines ewigen Schaffens - als das *sprechende Wort *Gottes, der Logos, der zugleich Gott selbst ist, bezeichnet worden. Das Wort oder Sprechen Gottes betrachtete man als den Ausfluß der göttlichen Wissenschaft, als die gebärende, in sich unterschiedene und doch zusammenstimmende Harmonie des göttlichen Producirens. Wir werden nach dieser hohen Bedeutung der Sprache, da sie nämlich der nicht bloß relative, sondern der mit seinem Entgegengesetzten wieder integrirte,in*so*fern wieder absolute Erkenntnißakt ist, auch die bildende Kunst der redenden nicht absolut entgegensetzen, wie die meisten thun (weßhalb sie z.B. die Musik nicht recht unter die bildenden Künste"}, {"type": "paragraph", "text": "rechnen, sondern ihr noch eine besondere Stelle anweisen). Auf keine andere Weise, als wie sich in der Sprache das Wissen noch jetzt symbolisch fasset, hat sich das göttliche Wissen in der Welt symbolisch gefaßt, so daß auch das *Ganze* der realen Welt (nämlich inwiefern sie selbst wieder Einheit des Realen und Idealen ist) auch wieder ein ursprüngliches Sprechen ist. Aber die *reale *Welt ist nicht mehr das lebendige Wort, das Sprechen Gottes selbst, sondern nur das gesprochene - geronnene - Wort. So ist die bildende Kunst nur das gestorbene Wort, aber doch auch Wort, doch auch Sprechen, und je vollkommener es stirbt - bis herauf zu dem auf den Lippen der Niobe versteinerten Laut, desto höher ist die bildende Kunst in ihrer Art, während dagegen auf der tieferen Stufe, in der Musik, das in den Tod eingegangene Lebendige - das ins Endliche *gesprochene *Wort - noch als Klang vernehmbar wird. Auch in der bildenden Kunst also ist der absolute Erkenntnißakt, die Idee, nur gleich von der realen Seite aufgefaßt, anstatt daß sie in der Rede oder redenden Kunst *ursprünglich *als ideal aufgefaßt ist, und selbst in der durchsichtigen Hülle, die sie annimmt, nicht aufhört es zu seyn. Die Sprache als die sich *lebendig * aussprechende unendliche Affirmation ist das höchste Symbol des Chaos, das in dem absoluten Erkennen auf ewige Weise liegt. In der Sprache liegt alles als eins, von welcher Seite man sie auffasse. Von der Seite des Tons oder der Stimme liegen in ihr alle Töne, alle Klänge ihrer qualitativen Verschiedenheit nach. Jene Verschiedenheiten sind alle vermischt in der menschlichen Sprache; daher sie keinem Klang oder Ton insbesondere ähnlich ist, weil alle in ihr liegen. Noch mehr ausgedrückt ist die absolute Identität in der Sprache, inwiefern sie von der Seite ihrer Bezeichnungen betrachtet wird. Sinnliches und Unsinnliches ist hier eins, das Handgreiflichste wird zum Zeichen für das Geistigste. Alles wird Bild von allem und die Sprache selbst eben dadurch Symbol der Identität aller Dinge. In der innern Construktion der Sprache selbst ist alles Einzelne bestimmt durch das Ganze; es ist nicht Eine Form oder einzelne Rede möglich, die nicht das Ganze forderte."}, {"type": "paragraph", "text": "Die Sprache, absolut betrachtet oder an sich, ist nur Eine, wie die Vernunft nur Eine ist, aber aus dieser Einheit gehen ebenso, wie aus der absoluten Identität die verschiedenen Dinge, die verschiedenen Sprachen hervor, deren jede für sich ein Universum, von den andern absolut gesondert, und die doch alle *wesentlich *eins, nicht bloß dem inneren Ausdruck der Vernunft nach, sondern auch was die Elemente betrifft, die bei jeder Sprache, wenige Nüancen ausgenommen, gleich sind. Nämlich dieser äußere Leib selbst ist in sich wieder Seele und Leib. Die Vocale sind gleichsam der unmittelbare Aushauch des"}]}, {"page_pdf": 1683, "page_book": 486, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Geistes, die formirende Form (das Affirmative); die Consonanten sind der Leib der Sprache oder die geformte Form (das Affirmirte). Je mehr daher in einer Sprache Vocale sind, - jedoch so, daß die Begrenzung durch die Consonanten nicht bis zu einem gewissen Grad verschwinde -, desto beseelter, und umgekehrt, je überhäufter mit Consonanten, desto seelenloser. Ich will hier noch kurz die verschiedentlich gemachte Frage berühren, warum sich das Vernunftwesen eben für die Rede oder Stimme als unmittelbaren Leib der inneren Seele entschieden habe, da es auch andere äußere Zeichen, z.B. Geberden, dazu hätte brauchen können, wie nicht nur die Taubstummen sich verständlich machen, sondern auch gewissermaßen alle wilden und uncultivirten Nationen, die mit dem ganzen Leib sprechen. Schon die Frage selbst betrachtet die Sprache als Willkür und als Erfindung der Willkür. Einige haben als Grund angegeben, diese äußeren Zeichen hätten solche seyn müssen, die der, welcher sie brauchte, zugleich selbst beurtheilen konnte, also natürlich ein auf Laut und Stimme sich beziehendes Zeichensystem, damit der Sprecher sich zugleich selbst hörte, welches bekanntlich für manche Sprecher in der That ein großes Vergnügen ist. So zufällig ist die Sprache nicht; es liegt eine höhere Nothwendigkeit darin, daß Laut und Stimme das Organ seyn müssen, die inneren Gedanken und Bewegungen der Seele auszudrücken. Man könnte jene Erklärer fragen, warum denn auch der Vogel Gesang und das Thier eine Stimme hat. Die Frage nach dem ersten Ursprung der Sprache hat bekanntlich"}, {"type": "paragraph", "text": "Philosophen und Historiker, besonders neuerer Zeit, sehr stark beschäftigt. Sie hielten es für möglich, die Sprache aus der psychologisch-isolirten menschlichen Natur zu begreifen, da sie nur aus dem ganzen Universum begreiflich ist. Die absolute Idee der Sprache muß man also nicht bei ihnen suchen. Jene ganze Frage nach dem Ursprung der Sprache, so wie sie bis jetzt behandelt worden, ist eine bloß empirische, mit der also der Philosoph nichts zu thun hätte; nur den Ursprung der Sprache in der Idee interessirt ihn zu wissen, und in diesem Sinn entspringt die Sprache noch immer ebenso wie das Universum auf unbedingte Weise durch die ewige Wirkung des absoluten Erkenntnißakts, der aber in der vernünftigen Natur die Möglichkeit findet, sich selbst auszusprechen1. Den Typus der Vernunft und Reflexion im Bau und in den inneren Verhältnissen der Sprache darzulegen gehört in eine andere Sphäre der Wissenschaft als diejenige, mit der wir uns hier beschäftigen, und in welcher die Sprache selbst wieder nur als Medium eintritt."}, {"type": "footnote", "text": "1 Randbemerkung: Sprache überhaupt = Kunsttrieb des Menschen, und wie der Lehrer des Instinkts das Sittliche ist, so der Sprache. Beide Behauptungen, daß durch Erfindung der Menschen, durch Freiheit, und daß durch göttlichen Unterricht, sind falsch."}, {"type": "paragraph", "text": "§. 74. *Die Kunst, inwiefern sie die ideale Einheit als Potenz wieder auf- und zur Form nimmt, ist redende Kunst. -* Folgt unmittelbar. *Zusatz. *Die* redende *Kunst ist die *ideale *Seite der Kunstwelt. *Allgemeiner Zusatz * (zu dieser Construktion des Gegensatzes der redenden und bildenden Kunst). Da nach §. 24 die Formen der Kunst Formen der Dinge sind, wie sie in Gott sind, so ist die reale Seite des Universums selbst die plastische, die ideale die poetische oder redende, und alle besonderen Formen, welche in diesen Grundformen wiederkehren, werden wiederum nur die Art der besondern Dinge ausdrücken, im Absoluten zu seyn."}, {"type": "paragraph", "text": "§. 75. *In jeder der beiden Urformen der Kunst kehren nothwendig alle Einheiten, die reale (etc.), die ideale*"}]}, {"page_pdf": 1684, "page_book": 487, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "*(etc.),*"}, {"type": "paragraph", "text": "*und die, worin beide gleich sind, zurück*. - Denn jede der beiden Urformen ist *an sich *absolut, jede die ganze Idee. *Zusatz.* Wenn wir die erste Einheit oder Potenz die der Reflexion, die andere die der Subsumtion, die dritte die der Vernunft nennen, so ist also das System der Kunst bestimmt durch *Reflexion, Subsumtion* und *Vernunft.* Alle Potenzen der Natur und ideellen Welt kehren hier - nur in der höchsten - wieder, und es wird ganz klar, wie Philosophie der Kunst Construktion des Universums in der Form der Kunst sey."}, {"type": "paragraph", "text": "In der jetzt folgenden Construktion hatte ich zwei Möglichkeiten vor mir: entweder die parallelen Potenzen der reellen und ideellen Kunstwelt unmittelbar einander entgegenzustellen, z.B. die Lyrik zugleich mit der Musik abzuhandeln, oder jede der beiden Seiten und die Potenzen einer jeden gesondert zu betrachten. Ich habe die letztere vorgezogen, weil ich sie für den Vortrag deutlicher glaube und die Beziehung der idealen Kunstformen auf die realen doch beständig nachgewiesen werden müßten. Ich werde also vorerst in der bildenden Kunst die drei Grundformen derselben, Musik, Malerei und Plastik, nebst allen Uebergängen der einen in die andere construiren. Jede dieser Formen wird in ihrem Zusammenhang und an ihrer Stelle construirt. Ich schicke daher keine allgemeine Eintheilung der Künste voran, wie man sonst in Lehrbüchern zu thun pflegt. Nur historisch erwähne ich, daß bis jetzt allgemein Musik von bildender Kunst getrennt worden. -* Kant *hat dreierlei Arten: redende, bildende und die Kunst des Spiels der Empfindungen Sehr vag. Hierher Plastik, Malerei: dorthin Beredtsamkeit und Dichtkunst. Unter die dritte die Musik, was eine ganz subjektive Erklärung derselben ist, fast wie die Sulzers, der sagt, der Zweck der Musik sey, Empfindung zu erwecken, was noch auf viel andere Dinge paßt, wie auf Concerte von Gerüchen oder Geschmäcken."}, {"type": "paragraph", "text": "II. Besonderer Theil der Philosophie der Kunst."}, {"type": "heading", "text": "Vierter Abschnitt. *Construktion der Kunstformen in der Entgegensetzung*", "level": null}, {"type": "paragraph", "text": "*der realen und idealen Reihe.*"}, {"type": "paragraph", "text": "In dem zunächst vorhergehenden Satz ist bewiesen, daß sich jede der beiden Urformen *in sich *aufs neue und zwar in alle Formen differenziirt. Anders ausgedrückt: jede der beiden Urformen nimmt alle"}]}, {"page_pdf": 1685, "page_book": 489, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "andern Formen oder Einheiten als Potenz auf und macht sie zu ihrem Symbol oder Besondern. Dieß wird also nun hier vorausgesetzt."}, {"type": "paragraph", "text": "§. 76. *Die Indifferenz der Einbildung des Unendlichen ins Endliche rein als Indifferenz aufgenommen ist Klang. Oder: *In der Einbildung des Unendlichen ins Endliche kann die Indifferenz, als Indifferenz, nur als *Klang *hervortreten. Dieses aber erhellt auf folgende Art. - Die Einpflanzung des Unendlichen ins Endliche als solche drückt sich an der Materie (dieß die gemeinschaftliche Einheit) durch die erste Dimension oder das aus, wodurch sie (als Differenz) sich selbst gleich (Indifferenz) ist. Nun ist aber die erste Dimension in der Materie nicht rein als solche, sondern mit der zweiten zugleich, demnach synthesirt durch die dritte gesetzt. In dem Seyn der Materie kann sich also die Einbildung des Unendlichen ins Endliche nicht *rein als solche *darstellen. Dieß"}, {"type": "paragraph", "text": "ist die negative Seite des Beweises. - Daß es nun aber der *Klang *sey, wodurch sich die Indifferenz in der Einpflanzung des Unendlichen ins Endliche rein als solche ausspreche, erhellt auf folgende Art. 1) Der Akt der Einpflanzung selbst ist an dem Körper als Magnetismus ausgedrückt (Beweis in der Naturphilosophie), aber der Magnetismus ist ebenso wieder, wie die erste Dimension, mit dem Körper verbunden, also nicht jene Einbildung selbst, nicht rein als solche, sondern Differenz. Rein als solche und als *Indifferenz *ist er sie nur, inwiefern er von dem Körper abgesondert, als Form für sich ist, als absolute Form. Diese ist nur im Klang, denn dieser ist einerseits lebendig - für sich -, andererseits eine bloße Dimension in der Zeit, nicht aber im Raume. 2) Nur anführen will ich, daß die Sonorität der Körper im nächsten Verhältniß steht mit ihrer Cohärenz. Durch Erfahrung ist bewiesen, daß ihre Leitungsfähigkeit für Schall sich nach ihrer Cohärenz richtet. Allein aller Schall überhaupt ist Leitung, kein Körper schallt, als inwiefern er den Schall zugleich leitet. In der Cohärenz oder dem Magnetismus an und für sich war aber das ideelle Princip ganz übergegangen ins Körperliche. Die Forderung aber war, daß die Einbildung der Einheit in die Vielheit rein als solche, als Form für sich erscheine. Dieß aber geschieht nur im Klang, denn dieser = Magnetismus, aber von der Körperlichkeit abgesondert, gleichsam das An-sich des Magnetismus selbst, die Substanz. *Anmerkung* 1*.* Ich brauche den Unterschied des Klangs von *Schall *und *Laut *nicht weitläufig auseinanderzusetzen. Schall ist das Generische. Laut ist Schall, der nur unterbrochen; Klang ist Schall, der als Stetigkeit, als ein ununterbrochenes Fließen des Schalls aufgefaßt wird. Der höhere Unterschied beider ist aber, daß der bloße Schall oder Laut die Einheit in der Vielheit nicht deutlich erkennen läßt, was dagegen der Klang thut, welcher demnach Schall verbunden mit Totalität ist. Wir hören nämlich in dem Klang nicht bloß den einfachen Ton, sondern eingehüllt gleichsam oder eingeboren in diesen"}, {"type": "paragraph", "text": "eine Menge von Tönen, und zwar so, daß die consonirenden überwiegen, anstatt daß dort die dissonirenden. Das geübte Ohr *unterscheidet *sie sogar und hört außer dem Unisonus oder Grundton auch noch dessen Oktave, die Oktave der Quinte u.s.w. Die Vielheit, welche in der Cohärenz als solcher mit der Einheit verbunden ist, wird also in dem Klang eine lebendige Vielheit, eine sich selbst affirmirende Vielheit. 2. Da die Sonorität der Körper durch die Cohärenz gesetzt ist, so ist auch das Schallen selbst nichts"}]}, {"page_pdf": 1686, "page_book": 491, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "anderes als die Wiederherstellung oder die Affirmation, d.h. die Identität in der Cohärenz, wodurch sich der Körper - aus der Identität gesetzt - zur Ruhe und zum Seyn in sich selbst reconstruirt. Der Klang selbst ist nichts anderes als die Anschauung der Seele des Körpers selbst oder des ihm unmittelbar verbundenen Begriffs in der unmittelbaren Beziehung auf dieses Endliche. Die Bedingung des Klangs ist Differenziirung des Begriffs und des Seyns, der Seele und des Leibs in dem Körper, der Akt der Indifferenziirung selbst ist es, in welchem das Ideale in der Wiedereinbildung ins Reale als Klang vernehmbar wird. Bedingung des Schalls ist daher, daß der Körper aus der Indifferenz gesetzt werde, welches durch Berührung eines anderen geschieht. 3. Wir müssen unmittelbar mit dieser Ansicht des Klanges die des *Gehörs *verbinden. - Die Wurzel des Gehörsinns liegt schon in der anorgischen Natur, im Magnetismus. Das Gehörorgan selbst ist nur der zur organischen Vollkommenheit entwickelte Magnetismus. Die Natur integrirt allgemein in der organischen Natur die anorgische durch ihre entgegengesetzte Einheit. Diese (die anorgische) ist bloß Unendliches im Endlichen. Dieß ist z.B. der Klang oder Schall. Integrirt mit dem Entgegengesetzten wird er = Gehör. Auch das Gehörorgan besteht äußerlich aus starren und sonoren Körpern, nur daß mit dieser Einheit die entgegengesetzte der Wiederaufnahme der Differenz im Schall in die Indifferenz verbunden ist. Der todt genannte Körper hat von dem Hören die eine Einheit, es fehlt ihm nur die andere."}, {"type": "paragraph", "text": "§. 77. *Die Kunstform, in welcher die reale Einheit rein als solche zur Potenz, zum Symbol wird, ist Musik. * - Folgt unmittelbar aus den beiden vorhergehenden Sätzen. *Anmerkung.* Die Natur der Musik läßt sich noch von verschiedenen Seiten her bestimmen, die angegebene Construktion aber ist die aus den früheren Grundsätzen fließende; die verschiedenen anderen Bestimmungen der Musik ergeben sich daraus als unmittelbare Folgen. *Folgesatz* 1. Die Musik ist als Kunst ursprünglich der *ersten Dimension *untergeordnet (hat nur Eine Dimension.) *Folgesatz* 2. Die nothwendige Form der Musik ist die *Succession. * - Denn Zeit ist allgemeine Form der Einbildung des Unendlichen ins Endliche, sofern als Form, abstrahirt von dem Realen, angeschaut. Das Princip der Zeit im Subjekt ist das Selbstbewußtseyn, welches eben die Einbildung der Einheit des Bewußtseyns in die Vielheit im Idealen ist. Hieraus ist die nahe Verwandtschaft des Gehörsinns überhaupt und der Musik und der Rede insbesondere mit dem Selbstbewußtseyn begriffen. - Es läßt sich hieraus auch vorläufig, bis wir die noch höhere Bedeutung davon aufgezeigt haben, die arithmetische Seite der Musik begreifen. Die Musik ist ein reales Selbstzählen der Seele - schon Pythagoras hat die Seele einer Zahl verglichen - aber eben deßwegen wieder ein bewußtloses, sich selbst wieder vergessendes Zählen. Daher das Leibnizische: Musica est raptus numerare se nescientis animae. (Die übrigen Bestimmungen des Charakters der Musik können erst im Verhältniß zu den andern Künsten entwickelt werden.)"}, {"type": "paragraph", "text": "§. 78. *Die Musik als Form, in welcher die reale Einheit sich selbst zum Symbol wird, begreift nothwendig wieder alle Einheiten in sich. - *Denn die reale Einheit nimmt *sich selbst *(in der* Kunst*) als Potenz auf, nur um *sich, durch sich selbst*, als Form wieder *absolut *darzustellen. Nun begreift aber jede Einheit in ihrer Absolutheit wieder alle anderen, also begreift auch die Musik etc."}, {"type": "paragraph", "text": "§. 79. *Die in der Musik selbst wieder als besondere*"}]}, {"page_pdf": 1687, "page_book": 492, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "*Einheit begriffene Einbildung der Einheit in die Vielheit oder reale Einheit ist der Rhythmus.* Denn, um mich jetzt zum Behuf des Beweises nur des allgemeinsten Begriffs von Rhythmus zu bedienen, so ist er in diesem Sinn nichts anderes als eine periodische Eintheilung des Gleichartigen, wodurch das Einförmige desselben mit Mannichfaltigkeit, die Einheit also mit Vielheit verbunden wird. Z.B. die Empfindung, welche ein Tonstück im Ganzen erregt, ist eine durchaus homogene, einartige; sie ist z.B. fröhlich oder traurig, allein diese Empfindung, die für sich durchaus homogen gewesen wäre, bekommt durch die rhythmischen Eintheilungen Abwechslung und Mannichfaltigkeit. Der Rhythmus gehört zu den bewundernswürdigsten Geheimnissen der Natur und der Kunst, und keine Erfindung scheint den Menschen unmittelbarer durch die Natur selbst inspirirt zu seyn. Die Alten haben durchaus dem Rhythmus die größte ästhetische Kraft zugeschrieben; auch wird schwerlich jemand leugnen, daß alles, was man in Musik oder Tanz (etc.) wahrhaft schön nennen kann, eigentlich von dem Rhythmus herrühre. Wir müssen aber, um den Rhythmus rein zu fassen, vorerst alles absondern, was die Musik etwa außerdem Reizendes und Erregendes hat. Die Töne z.B. haben auch an sich eine Bedeutung, sie können für sich fröhlich, zärtlich, traurig oder schmerzhaft seyn. Hievon wird bei der Betrachtung des Rhythmus ganz abstrahirt, seine Schönheit ist nicht stoffartig und bedarf der bloß natürlichen Rührungen, die etwa in Tönen an und für sich liegen, nicht, um absolut wohlzugefallen und eine dafür empfängliche Seele zu entzücken. Um dieß recht deutlich zu sehen, denke man sich anfänglich die Elemente des Rhythmus als an sich ganz gleichgültige, wie z.B. die einzelnen Töne einer Saite für sich, oder wie der Schlag einer Trommel ist. Wodurch kann eine Folge solcher Schläge bedeutend, aufregend, wohlgefällig werden? - Schläge oder Töne, die sich ohne die geringste Ordnung succedirten, sind von keiner Wirkung auf uns. Sobald aber selbst in die ihrer Natur oder dem Stoff nach bedeutungslosesten, nicht einmal an sich angenehmen Töne eine Regelmäßigkeit"}, {"type": "paragraph", "text": "kommt, daß sie immer in gleicher Zeit wiederkehren und eine Periode zusammen bilden, so ist hier schon etwas von Rhythmus, obgleich nur ein sehr entfernter Anfang - wir werden unwiderstehlich zur Aufmerksamkeit fortgezogen. In alles, was an sich eine *reine Identität *der Beschäftigung ist, sucht der Mensch daher, von Natur getrieben, Vielheit oder Mannichfaltigkeit durch Rhythmus zu legen. Wir halten es in allem an sich Bedeutungslosen, z.B. im Zählen, nicht lange bei der Gleichförmigkeit aus, wir machen Perioden. Die meisten mechanischen Arbeiter erleichtern sich ihre Arbeiten damit; die innere Lust des doch nicht bewußten, sondern bewußtlosen Zählens läßt sie die Arbeit vergessen; der einzelne fällt mit einer Art von Lust an seiner Stelle ein, weil es ihn selbst schmerzen würde, den Rhythmus unterbrochen zu sehen. Wir haben bis jetzt nur die unvollkommenste Art Rhythmus bezeichnet, wo die ganze Einheit in der Mannichfaltigkeit nur auf der Gleichheit der Zwischenzeiten in der Succession beruht. Bild davon: gleich große, gleich entfernte Punkte. Unterster Grad des Rhythmus. Eine höhere Art der Einheit in der Mannichfaltigkeit ist zunächst dadurch erreichbar, daß die einzelnen Töne oder Schläge nicht gleich stark, sondern abwechselnd nach einer gewissen Regel, starke und schwache angegeben werden. Hiermit tritt als nothwendiges Element in den Rhythmus der *Takt *ein, der auch überall gesucht wird, wo ein Identisches verschieden, mannichfaltig werden soll, und der nun wieder einer Menge von Veränderungen fähig ist, wodurch in die Einförmigkeit der Aufeinanderfolge eine noch größere Abwechslung kommt. Allgemein nun angesehen ist Rhythmus überhaupt Verwandlung der an sich bedeutungslosen Succession in eine bedeutende. Die Succession rein als solche hat den Charakter der Zufälligkeit."}]}, {"page_pdf": 1688, "page_book": 494, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Verwandlung des Zufälligen der Succession in Nothwendigkeit = Rhythmus, wodurch das Ganze nicht mehr der Zeit unterworfen ist, sondern sie *in sich selbst *hat. Artikulation der Musik ist Bildung in eine Reihe von Gliedern, so daß mehrere Töne zusammen wieder ein Glied ausmachen, welches nicht zufällig oder willkürlich von andern unterschieden ist."}, {"type": "paragraph", "text": "Dieser noch immer bloß *einfache *Rhythmus, der darin besteht, daß die Folge der Töne in gleich lange Glieder eingetheilt wird, wovon jedes durch etwas Empfindbares unterschieden von dem andern, hat dennoch schon sehr vielerlei Arten, z.B. er kann gerad oder ungerad seyn u.s.w. Aber mehrere Takte zusammen können wieder zu Gliedern vereinigt werden, welches eine höhere Potenz des Rhythmus - zusammengesetzter Rhythmus ist (in der Poesie das Distichon). Endlich können auch aus diesen schon zusammengesetzten Gliedern wieder größere (Perioden) gemacht werden (in der Poesie die Strophe) u.s.f. bis zu dem Punkt, wo diese ganze Ordnung und Zusammensetzung für den inneren Sinn noch übersehbar bleibt. - Die ganze Vollkommenheit des Rhythmus können wird indeß erst durch die folgenden Sätze einsehen lernen. *Zusatz. Der Rhythmus ist die Musik in der Musik. -* Denn die Besonderheit der Musik ist eben darauf gegründet, daß sie Einbildung der Einheit in die Vielheit ist. Da nun nach §. 79 der Rhythmus nichts anderes ist als diese Einbildung selbst *in* der Musik, so ist er die Musik in der Musik, und also der Natur dieser Kunst gemäß das Herrschende in ihr. Nur das Festhalten dieses Satzes wird uns in den Stand setzen, besonders den Gegensatz der antiken und modernen Musik wissenschaftlich zu begreifen."}, {"type": "paragraph", "text": "§. 80. *Der Rhythmus in seiner Vollkommenheit begreift nothwendig die andere Einheit in sich , welche in dieser Unterordnung Modulation *(in der allgemeinsten Bedeutung) * ist. -* Der erste Theil des Satzes begreift sich von selbst und ist ganz allgemein einzusehen. In Ansehung des zweiten bedarf es bloß der Erklärung dessen, was Modulation heißt. Die erste Bedingung des Rhythmus ist eine Einheit in der Mannichfaltigkeit. Diese Mannichfaltigkeit ist nun aber nicht bloß in der Verschiedenheit der Glieder überhaupt, sofern sie willkürlich oder unwesentlich, d.h. bloß überhaupt in der Zeit stattfindet, sondern sofern sie zugleich auf etwas Reelles, Wesentliches, Qualitatives gegründet"}, {"type": "paragraph", "text": "ist. Dieses liegt einzig in der musikalischen Bestimmbarkeit der Töne. In dieser Beziehung ist nun Modulation die Kunst, die Identität des Tons, welcher in dem Ganzen eines musikalischen Werks der herrschende ist, in der *qualitativen *Differenz ebenso zu erhalten, wie durch den Rhythmus dieselbe Identität in der quantitativen Differenz beobachtet wird. Ich muß mich in dieser Allgemeinheit ausdrücken, weil Modulation in der Kunstsprache so verschiedene Bedeutungen hat, und damit nicht etwas von der Bedeutung sich einmische, die sie nur in der modernen Musik hat. Jene künstliche Art, durch die sogenannten Ausweichungen und Schlüsse Gesang und Harmonie durch mehrere Töne hindurchzuführen, zuletzt aber wieder auf den ersten Hauptton zu kommen, gehört schon ganz der modernen Kunst an. Da es unmöglich ist, daß ich in alle diese technischen Erörterungen eingehe, welche nur in einer Theorie der Musik und nicht in einer allgemeinen Construktion gegeben werden können, so bemerken *Sie *nur im *Allgemeinen*, daß sich die beiden Einheiten, die durch Rhythmus und Modulation bezeichnet"}]}, {"page_pdf": 1689, "page_book": 496, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "werden können, jene als die quantitative, diese als die qualitative zu denken ist, daß aber jene in ihrer Absolutheit die andere schon begreifen müsse, so daß die Unabhängigkeit der anderen Einheit von der ersten jene selbst in ihrer Absolutheit aufhebt, und die bloß auf Harmonie gegründete Musik zum Produkt gibt, was durch die Folge sogleich verständlicher werden soll: - Rhythmus in dieser Bedeutung, d.h. *sofern er die andere Einheit schon begreift*, ist also die ganze Musik. - Wir werden hierdurch schon auf die Idee einer Differenz geleitet, die dadurch entsteht, daß in dem einen Fall die ganze Musik der ersten Einheit, dem Rhythmus, in dem andern der zweiten oder der Modulation untergeordnet wird, wodurch zwei in ihrer Art zwar gleich absolute, aber verschiedene Gattungen der Musik entspringen."}, {"type": "paragraph", "text": "§. 81. *Die dritte Einheit, in welcher die beiden ersten gleich gesetzt sind, ist die Melodie. * - Da dieser Satz eigentlich nur Erklärung ist, und niemand in Zweifel ziehen wird, daß Vereinigung"}, {"type": "paragraph", "text": "von Rhythmus und Modulation *Melodie * sey, so bedarf er keines Beweises. - Wir wollen, um das Verhältniß der drei Einheiten innerhalb der Musik anschaulich zu machen, sie vielmehr nach verschiedenen Maßstäben noch weiter zu bestimmen suchen. Man kann also sagen: der Rhythmus = erster Dimension, Modulation = zweiter, Melodie = dritter. Durch den ersten ist die Musik für die Reflexion und das Selbstbewußtseyn, durch die zweite für die Empfindung und das Urtheil, durch die dritte für Anschauung und Einbildungskraft bestimmt. Wir können auch zum voraus ahnden, daß wenn die drei Grundformen oder Kategorien der Kunst Musik, Malerei und Plastik sind, der Rhythmus das Musikalische in der Musik, die Modulation das Malerische (welches ja nicht mit dem *Malenden *verwechselt werden darf, welches nur ein ganz verdorbener und gesunkener Geschmack, wie der heutige z.B., der sich an dem Blöcken der Schafe in Haydns Schöpfungsmusik ergötzt, in der Musik gut finden kann), die Melodie das Plastische. Es erhellt nun aber aus dem, was in dem vorhergehenden Satz bewiesen worden ist, von selbst, daß Rhythmus in der angegebenen Bedeutung (nämlich als die entgegengesetzte Einheit begreifend) und Melodie selbst wieder eins und dasselbige sind. *Zusatz. Rhythmus in der Absolutheit gedacht ist die ganze Musik*, oder umgekehrt: die ganze Musik ist etc. - Denn dieser begreift alsdann die andere Einheit unmittelbar in sich und ist durch sich selbst Melodie, d.h. das Ganze. Rhythmus ist überhaupt die herrschende Potenz in der Musik. Inwiefern nun das Ganze der Musik, demnach Rhythmus, Modulation und Melodie, gemeinschaftlich wieder dem Rhythmus untergeordnet, insofern ist rhythmische Musik. Eine solche war die Musik der Alten. Es muß jedem auffallen, wie genau in dieser Construktion alle Verhältnisse eintreffen, und daß auch hier wieder der Rhythmus als Einbildung des Unendlichen ins Endliche sich auf die Seite des Antiken stellt, indeß die entgegengesetzte Einheit, wie wir finden werden, auch hier das Herrschende des Modernen ist."}, {"type": "paragraph", "text": "Von der Musik der Alten haben wir allerdings nicht die * anschauliche * Vorstellung. Man sehe Rousseau in seinem Dictionnaire de Musique (noch immer das gedachteste Werk über diese Kunst), wo man findet, wie wenig wir daran denken können, eine antike Musik auch nur einigermaßen durch Aufführung anschaulich zu machen. Da die Griechen in allen Künsten groß waren, so waren sie es gewiß auch in der Musik. So wenig wir indeß davon wissen, so doch so viel, daß auch hier das realistische, plastische, heroische Princip das herrschende, und dieß einzig dadurch, daß dem Rhythmus alles"}]}, {"page_pdf": 1690, "page_book": 498, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "untergeordnet war. Das Herrschende der neueren Musik ist die Harmonie, welche eben das Entgegengesetzte der rhythmischen Melodie der Alten ist, wie ich dieß noch bestimmter zeigen werde. Die einzige, obgleich höchst verstellte Spur der alten Musik ist noch in dem *Choral *übrig. Zwar hatte, wie Rousseau sagt, zu der Zeit, als die Christen anfingen in eignen Kirchen Hymnen und Psalmen zu singen, die Musik schon fast allen ihren Nachdruck verloren. Die Christen nahmen sie, wie sie dieselbe fanden, und beraubten sie noch ihrer größten Kraft, des Zeitmaßes und des Rhythmus, aber doch blieb der Choral in den alten Zeiten immer einstimmig, und dieß ist es eigentlich, was Canto Firmo heißt. In späteren Zeiten wurde er immer vierstimmig gesetzt, und die verwickelten Künste der Harmonie haben sich auch in den Kirchengesang ausgebreitet. Die Christen nahmen die Musik erst von der gebundenen Rede ab, und setzten sie auf die Prosa der heiligen Bücher oder eine völlig barbarische Poesie. So entstand der Gesang, der jetzt ohne Takt und mit immer einerlei Schritten fortgeschleppt wird, und verlor mit dem rhythmischen Gang alle Energie. Nur in einigen Hymnen merkte man noch den Fall der Verse, weil das Zeitmaß der Sylben und die Füße beibehalten wurden. Aber aller dieser Mängel unerachtet findet auch Rousseau in dem Choral, den die Priester in der römischen Kirche in seinem ursprünglichen Charakter erhalten haben, höchst schätzbare Ueberbleibsel des alten Gesanges und seiner verschiedenen Tonarten, sowie es möglich war sie ohne Takt und Rhythmus zu erhalten."}, {"type": "paragraph", "text": "§. 82. *Der Melodie, welche die Unterordnung der drei Einheiten der Musik unter die erste ist, steht die Harmonie als die Unterordnung der drei Einheiten unter die andere entgegen. -* Die Harmonie als ein Gegensatz der Melodie ist allgemein auch bei den bloß empirischen Theoretikern anerkannt. Melodie ist in der Musik die absolute Einbildung des Unendlichen ins Endliche, also die ganze Einheit. Harmonie ist gleichfalls Musik, insofern nicht minder Einbildung der Identität in die Differenz, aber diese Einheit wird hier durch die entgegengesetzte - die ideale Einheit - symbolisirt. Im gemeinen Sprachgebrauch sagt man von einem Tonkünstler, daß er die Melodie verstehe, wenn er einen einstimmigen durch Rhythmus und Modulation ausgezeichneten Gesang setzen kann, daß er Harmonie, wenn er der Identität, welche im Rhythmus in die Differenz aufgenommen wird, auch noch Breitheit (Ausdehnung nach der zweiten Dimension) zu geben weiß, also wenn er mehrere Stimmen, deren jede ihre eigne Melodie hat, in ein wohlklingendes Ganzes zu vereinigen weiß. Dort ist offenbar Einheit in Vielheit, hier Vielheit in Einheit, dort Succession, hier Coexistenz. Harmonie ist auch in der Melodie, aber nur in der Unterordnung unter Rhythmus (das Plastische). Hier ist von Harmonie die Rede, inwiefern sie die Unterordnung unter Rhythmus ausschließt, inwiefern sie selbst das *Ganze *ist, untergeordnet der zweiten Dimension. Harmonie kommt zwar in verschiedenen Bedeutungen bei den Theoretikern vor, so daß es z.B. die Vereinigung vieler zugleich angeschlagenen Töne in einen einzigen Klang bedeutet; hier wird also Harmonie in der höchsten Einfachheit aufgefaßt, in welcher sie z.B. auch eine Eigenschaft des einzelnen Klangs ist, da in diesem zugleich mehrere und von ihm verschiedene Töne mitklingen, die aber so genau vereinigt sind, daß man nur Einen zu hören glaubt. Diese selbige Vielheit in der Einheit nun angewendet auf die größeren Momente eines ganzen Tonstücks, so besteht Harmonie darin, daß in jedem dieser Momente"}, {"type": "paragraph", "text": "differente Tonverhältnisse dennoch wieder zur Einheit im Ganzen gebracht seyen, sowie dieselbe in"}]}, {"page_pdf": 1691, "page_book": 500, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Ansehung des ganzen Tonstücks wiederum die Resumtion aller möglichen besonderen Einheiten und aller - nicht dem Rhythmus, sondern der Modulation nach verschiedenen - Verwicklungen der Töne in die absolute Einheit des Ganzen bedeutet. Aus diesem allgemeinen Begriff geht schon zur Genüge hervor, daß sich Harmonie zu Rhythmus und insofern auch zu Melodie, da Melodie nichts anderes als der integrirte Rhythmus ist, daß sich, sage ich, Harmonie zu Melodie wieder wie die ideale Einheit zur realen oder wie die Einbildung der Vielheit in die Einheit zu der entgegengesetzten der Einheit in die Vielheit verhalte, welches eben zu beweisen war. Nur ist dabei im Auge zu behalten, daß Harmonie, inwiefern sie der Melodie entgegengesetzt, wieder für sich das *Ganze *ist, also die * Eine *der beiden Einheiten bloß, inwiefern allein auf die *Form *reflektirt wird, nicht aber inwiefern auf das *Wesen*, denn insofern ist sie wieder die Identität *an sich*, also die Identität der drei Einheiten, aber ausgedrückt in der idealen. Nur insofern können Harmonie und Melodie einander wirklich entgegengesetzt werden. Wird nun etwa nach dem Vorzug der Harmonie oder Melodie in diesem Sinne gefragt, so sehen wir uns wieder in demselben Falle, wie wenn nach dem Vorzug der antiken oder modernen Kunst überhaupt gefragt wird. Sehen wir auf das Wesen, so ist freilich jedes von beiden die ganze ungetheilte Musik, sehen wir aber auf die Form, so wird unser Urtheil eben dahin ausfallen müssen, wohin das Urtheil über antike und moderne Kunst überhaupt. Der Gegensatz beider ist, daß überhaupt jene nur das Reelle, das Wesentliche, das Nothwendige, diese auch das Ideelle, Unwesentliche und Zufällige in der Identität mit dem Wesentlichen und Nothwendigen darstellt. Angewendet auf den vorliegenden Fall, so stellt sich die rhythmische Musik überhaupt als eine Expansion des Unendlichen im Endlichen dar, wo also dieses (das Endliche) etwas für sich selbst gilt, anstatt daß in der harmonischen die Endlichkeit oder Differenz nur als eine Allegorie des Unendlichen"}, {"type": "paragraph", "text": "oder der Einheit erscheint. Jene bleibt gleichsam der Naturbestimmung der Musik getreuer, welche die ist, eine Kunst in der Succession zu seyn, sie ist daher realistisch; diese möchte in der tieferen Sphäre gern die höhere ideale Einheit vorausnehmen, die Succession gleichsam ideal aufheben und die Vielheit in dem Moment als Einheit darstellen. Die rhythmische Musik, welche das Unendliche im Endlichen darstellt, wird mehr Ausdruck der Befriedigung und des rüstigen Affekts, die harmonische mehr des Strebens und der Sehnsucht seyn. Daher es nothwendig war, daß eben in der Kirche, deren Grundanschauung auf der Sehnsucht und dem Zurückstreben der Differenz in die Einheit beruht, das gemeinschaftliche, von jedem Subjekt insbesondere ausgehende Streben, im Absoluten sich als Eins mit allen anzusehen, durch die harmonische, rhythmuslose Musik sich ausdrücken mußte. Dagegen ein Verein, wie in den griechischen Staaten, wo ein rein Allgemeines, die Gattung, sich völlig zum Besonderen gebildet hatte und es selbst war, gleichwie er in seiner Erscheinung als Staat rhythmisch war, so auch in der Kunst rhythmisch seyn mußte. Wer, ohne anschauliche Kenntniß von der Musik insbesondere zu haben, sich dennoch eine Anschauung des Verhältnisses von Rhythmus und rhythmischer Melodie zur Harmonie geben will, der vergleiche in Gedanken etwa ein Stück des Sophokles mit einem des Shakespeare. Ein Sophokles'sches Werk hat reinen Rhythmus, nur die Nothwendigkeit ist dargestellt, es hat keine überflüssige Breite; Shakespeare dagegen ist der größte Harmonist, Meister im dramatischen Contrapunkt; es ist nicht der einfache Rhythmus einer einzigen Begebenheit, es ist zugleich ihre ganze Begleitung und ihr von verschiedenen Seiten kommender Reflex, was uns dadurch vorgestellt wird. Man vergleiche z.B. den Oedipus und Lear. Dort nichts als die reine Melodie der Begebenheit, anstatt daß hier dem Schicksal des von seinen Töchtern verstoßenen Lear die Geschichte eines Sohns, der von seinem Vater verstoßen, und so jedem einzelnen Moment des Ganzen wieder ein anderes Moment entgegengesetzt ist, von dem es begleitet und reflektirt wird."}]}, {"page_pdf": 1692, "page_book": 501, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Die Verschiedenheit der Urtheile über den Vorzug der Harmonie und Melodie sind so wenig zu vereinigen, als die über antike und moderne Kunst überhaupt. Rousseau nennt jene eine gothische, barbarische Erfindung; dagegen gibt es Enthusiasten der Harmonie, die erst von der Erfindung des Contrapunkts an wahre Musik datiren. Dieß wird freilich allein dadurch hinlänglich widerlegt, daß die Alten eine Musik von so großer Kraft ohne alle Kenntniß oder wenigstens Gebrauch der Harmonie hatten. Die meisten sind der Meinung, daß der vielstimmige Gesang gar erst im zwölften Jahrhundert erfunden."}, {"type": "paragraph", "text": "§. 83. *Die Formen der Musik sind Formen der ewigen Dinge, inwiefern sie von der realen Seite *betrachtet werden. - Denn die reale Seite der ewigen Dinge ist die, von welcher das Unendliche ihrem Endlichen eingeboren ist. Aber diese selbe Einbildung des Unendlichen in das Endliche ist auch die Form der Musik, und da die Formen der Kunst überhaupt die Formen der Dinge an sich sind, so sind die Formen der Musik nothwendig Formen der Dinge an sich oder der Ideen ganz von ihrer realen Seite betrachtet. Da dieß nun allgemein bewiesen ist, so gilt es auch von den besonderen Formen der Musik, von Rhythmus und Harmonie, nämlich daß sie Formen der ewigen Dinge ausdrücken, sofern diese ganz von der Seite ihrer Besonderheit betrachtet werden. Inwiefern dann ferner die ewigen Dinge oder die Ideen von der realen Seite in den Weltkörpern offenbar werden, so sind die Formen der Musik als Formen der real betrachteten Ideen auch Formen des Seyns und des Lebens der Weltkörper als solcher, demnach die Musik nichts anderes als der vernommene Rhythmus und die Harmonie des sichtbaren Universums selbst. *Verschiedene Anmerkungen.* 1) Allgemein geht die Philosophie, wie die Kunst, nicht auf die Dinge selbst, sondern nur auf ihre Formen oder ewigen Wesenheiten. Das Ding selbst ist aber eben nichts anderes als diese Art oder Form zu seyn, und durch die Formen besitzt man die Dinge. Die Kunst bestrebt sich z.B. in ihren plastischen Werken nicht, mit den ähnlichen Hervorbringungen der Natur, was das Reelle betrifft, zu wetteifern."}, {"type": "paragraph", "text": "Sie sucht die bloße Form, das Ideale, von welchem aber das Ding selbst doch wieder nur die andere Ansicht ist. Dieß angewendet auf den vorliegenden Fall, so bringt die Musik die Form der Bewegungen der Weltkörper, die reine, von dem Gegenstand oder Stoff befreite *Form *in dem Rhythmus und der Harmonie als solche zur Anschauung. Die Musik ist insofern diejenige Kunst, die am meisten das Körperliche abstreift, indem sie die *reine *Bewegung selbst als solche, von dem Gegenstand abgezogen, vorstellt und von unsichtbaren, fast geistigen Flügeln getragen wird. 2) Bekanntlich war der erste Urheber dieser Ansicht der himmlischen Bewegungen als Rhythmus und Musik Pythagoras, aber ebenso bekannt ist, wie wenig seine Ideen verstanden worden sind, und man kann sehr leicht schließen, wie verdorben sie auch zu uns gekommen sind. Man hat des Pythagoras Lehre von der Musik der Sphären gewöhnlich ganz grob verstanden, nämlich in dem Sinn, daß so große Körper in ihren schnellen Bewegungen einen *Schall verursachen *müssen, der, weil sie mit verschiedener, jedoch abgemessener Geschwindigkeit und in immer ausgedehnteren Kreisen rotiren, eine zusammenklingende, nach musikalischen Tonverhältnissen geordnete Harmonie erzeuge, so daß das Sonnensystem einer siebenfach besaiteten Leyer gleiche. In dieser Vorstellung war die ganze Sache empirisch genommen."}]}, {"page_pdf": 1693, "page_book": 503, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Pythagoras sagt nicht, daß diese Bewegungen eine Musik *verursachen*, sondern, daß sie es selbst seyen. Diese inwohnende Bewegung bedurfte keines äußeren Mediums, wodurch sie Musik wurde, sie war es in sich selbst. Als man nachher den Raum zwischen den Himmelskörpern leer machte, oder höchstens ein sehr zartes und feines Medium darin zugeben wollte, gegen welches keine Reibung stattfand, und das auch den erregten Schall nicht aufnehmen oder in sich fortpflanzen konnte, so glaubte man damit diese Vorstellung abgethan zu haben, die man noch gar nicht erreicht hatte. Wie man es gewöhnlich darstellt, hat Pythagoras gesagt, man könne jene Musik wegen ihrer zu großen Gewalt, und weil sie beständig sey, nicht vernehmen, ungefähr so, wie Menschen, die in einer Mühle wohnen. Wahrscheinlich ist dieß gerad' umgekehrt zu"}, {"type": "paragraph", "text": "verstehen, nämlich daß allerdings die Menschen in einer Mühle leben, daß sie aber vor diesem Sinnengeräusch die Accorde jener himmlischen Musik nicht vernehmen können, wie sich denn dieß auch wirklich an solchem Verstehen gezeigt hat. Sokrates bei Platon sagt: Derjenige ist der Musiker, der von den sinnlich vernommenen Harmonien fortschreitend zu den unsinnlichen, intelligibeln und *ihren* Proportionen. - Noch ein größeres Problem bleibt der Philosophie zu lösen übrig, das Gesetz der Anzahl und der Distanzen der Planeten. Erst mit diesem wird auch daran gedacht werden können, Einsicht in das innere System der Töne zu erhalten, welches bis jetzt noch ein gänzlich verschlossener Gegenstand ist. Wie wenig unser jetziges Tonsystem auf Einsicht und Wissenschaft gegründet sey, erhellt daraus, daß manche Intervalle und Fortschreitungsarten in der alten Musik üblich waren, die nach unserer Eintheilung unausführbar oder gar uns unverständlich sind. 3) Wir können jetzt erst die höchste Bedeutung von Rhythmus, Harmonie und Melodie festsetzen. Sie sind die ersten und reinsten Formen der Bewegung im Universum und, real angeschaut, die Art der materiellen Dinge den Ideen gleich zu seyn. Auf den Flügeln der Harmonie und des Rhythmus schweben die Weltkörper; was man Centripetal- und Centrifugalkraft genannt hat, ist nichts anderes als - dieses Rhythmus, jenes Harmonie. Von denselben Flügeln erhoben schwebt die Musik im Raum, um aus dem durchsichtigen Leib des Lauts und Tons ein hörbares Universum zu weben. Auch im Sonnensystem drückt sich das ganze System der Musik aus. Kepler schon schreibt die Durart den Apheliis, die Mollart den Periheliis zu. Die unterscheidenden Eigenschaften, welche in der Musik dem Baß, dem Tenor, dem Alt und Diskant zugeschrieben werden, theilt er verschiedenen Planeten zu. Aber noch mehr ist der *Gegensatz *der Melodie und Harmonie, wie er in der Kunst nacheinander erschien, in dem Sonnensystem ausgedrückt. In der Planetenwelt ist der Rhythmus das Herrschende, ihre Bewegungen sind *reine Melodie*; in der Kometenwelt ist die"}, {"type": "paragraph", "text": "Harmonie herrschend. Wie die ganze moderne Welt allgemein der Centripetalkraft gegen das Universum, der Sehnsucht nach dem Centrum unterliegt, so auch die Kometen, deren Bewegungen daher eine bloße harmonische Verwirrung ohne allen Rhythmus ausdrücken, und wie dagegen das Leben und Wirken der Alten gleich ihrer Kunst expansiv, centrifugal, d.h. in sich selbst absolut und rhythmisch war, so ist auch in den Bewegungen der Planeten vergleichungsweise die Centrifugalkraft - die Expansion des Unendlichen im Endlichen - herrschend. 4) Hiernach bestimmt sich nun auch die Stelle, welche die Musik in dem allgemeinen System der Künste einnimmt. - Wie sich der allgemeine Weltbau ganz unabhängig verhält von den andern Potenzen"}]}, {"page_pdf": 1694, "page_book": 505, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der Natur, und je nachdem er von einer Seite betrachtet wird, das Höchste und Allgemeinste ist, worin sich unmittelbar in die reinste Vernunft auflöst, was im Concreten sich noch verwirrt, von der andern Seite aber auch die tiefste Potenz ist: so auch die Musik, welche, von der einen Seite betrachtet, die allgemeinste unter den realen Künsten und der Auflösung in Rede und Vernunft am nächsten ist, obgleich von der andern nur die erste Potenz derselben. Die Weltkörper in der Natur sind die ersten Einheiten, die aus der ewigen Materie hervorgehen; auch schließen sie alles in sich, obgleich sie sich in sich selbst erst contrahiren und in mehr besondere und engere Sphären zurückziehen müssen, um die höchsten Organisationen in sich darzustellen, in welchen die Einheit der Natur zur vollkommenen Selbstanschauung gelangt. In ihren allgemeinen Bewegungen drückt sich also der in ihnen liegende Typus der Vernunft nur für die erste Potenz aus, und ebenso nimmt die Musik, welche von der einen Seite die verschlossenste aller Künste ist, die die Gestalten noch im Chaos und ununterscheidbar begreift, und die nur die reine Form dieser Bewegungen, abgesondert vom Körperlichen, ausdrückt, den absoluten Typus nur als Rhythmus, Harmonie und Melodie, d.h. für die erste Potenz, auf, obgleich sie nun innerhalb dieser Sphäre die grenzenloseste aller Künste ist. Hiermit ist die Construktion der Musik vollendet, da alle Construktion der Kunst nur darauf ausgehen kann, ihre Formen als Formen"}, {"type": "paragraph", "text": "der Dinge an sich darzustellen, welches in Ansehung der Musik geleistet worden ist. Ehe ich weiter gehe, erinnere ich folgendes Allgemeine. Unsere gegenwärtige Aufgabe ist Construktion der *besonderen Kunstformen. *Da Stoff und Form im Absoluten und also auch im Princip der Kunst eins ist, so kann nur dasselbe, was in dem Stoff oder Wesen ist, auch wieder zur Form werden; die Unterscheidung von Stoff und Form aber kann nur darauf beruhen, daß, was in dem Stoff als absolute Identität gesetzt ist, in der Form als relative gesetzt werde. Nun ist schon in dem Absoluten an und für sich das Allgemeine und Besondere eins, dadurch, daß in ihm die besonderen Einheiten oder Formen der Einheit als absolut gesetzt sind. Aber eben deßwegen, weil sie in ihm selbst absolut, in Ansehung einer jeden also die Form auch das Wesen, das Wesen die Form ist, - eben deßwegen, sage ich, sind sie in ihm ununterscheidbar und ununterschieden, und jene Einheiten oder ewigen Ideen können als solche nur dadurch wahrhaft objektiv werden, daß sie * in ihrer Besonderheit*, als besondere Formen, sich selbst zum Symbol werden. Das, was * durch sie * erscheint, ist nur die absolute Einheit, die Idee an und für sich; die Form ist nur der Leib, mit dem sie sich bekleidet, und in dem sie objektiv wird. Die erste Einheit in dem absoluten Wesen ist nun allgemein die, wodurch es seine Subjektivität und ewige Einheit in die Objektivität oder Vielheit gebiert, und diese Einheit in ihrer Absolutheit oder als die eine Seite des absoluten Producirens aufgefaßt, ist die ewige Materie oder ewige Natur selbst. Ohne diese würde das Absolute eine in sich verschlossene Subjektivität seyn und bleiben ohne Erkennbarkeit und Unterscheidbarkeit. Nur durch die Subjekt-Objektivirung gibt es sich selbst in der Objektivität zu erkennen, und führt sich selbst als Erkanntes aus der Objektivität in sein Selbsterkennen zurück. Diese Zurückbildung der Objektivität in sich selbst ist die andere Einheit, die in ihm von der ersten ungetrennt ist. Denn wie wir die vollendete Einbildung der Subjektivität in die Objektivität im Organismus unmittelbar in die"}, {"type": "paragraph", "text": "Vernunft als das absolut Ideale umschlagen sehen, so verklärt sich im Absoluten, wo die Einbildung"}]}, {"page_pdf": 1695, "page_book": 507, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "immer absolut ist, das Reale jener Subjekt-Objektivirung unmittelbar wieder in den Aether der absoluten Idealität, so daß das absolut Reale jederzeit auch das absolut Ideale und beides wesentlich ein und dasselbige ist. Das Absolute nun, inwiefern es in der Erscheinungswelt durch die erste der beiden Einheiten sich ausprägt, ist das Wesen der Materie; und alle Kunst, sofern sie dieselbe Einheit zur Form nimmt, ist plastische oder bildende Kunst. Innerhalb derselben sind ebenso wieder wie innerhalb der Materie alle Einheiten begriffen, und drücken sich durch die besonderen Kunstformen aus. Die erste, welche die Einbildung der Einheit in die Vielheit sich zur Form nimmt, um in ihr das Universum darzustellen, ist, wie zuletzt bewiesen wurde, die Musik. Wir gehen jetzt zur andern Einheit fort, und haben die ihr entsprechende Kunstform zu construiren. Wir bedürfen auch hiezu wieder mehrerer Lehnsätze aus der allgemeinen Philosophie, die ich daher vorausschicke."}, {"type": "paragraph", "text": "§. 84. *Lehnsatz. Der unendliche Begriff aller endlichen Dinge, sofern er in der realen Einheit begriffen ist, ist das Licht.* - Da der Beweis in die allgemeine Philosophie gehört, so gebe ich hier nur die Hauptmomente an. Vorläufig ist zu bemerken: a) Licht = Begriff, *ideale *Einheit, b) aber ideale Einheit innerhalb der realen. Der Beweis wird am kürzesten durch die Entgegensetzung mit der andern Einheit geführt. In dieser wird die Identität der ewigen Materie überhaupt in die Differenz, und demnach in unterschiedene und besondere Dinge gebildet. Hier ist die Differenz oder Besonderheit das Herrschende, die Identität kann nur als Einheit in der *Vielheit *aufgefaßt werden. In der entgegengesetzten Einheit ist die Identität, das Wesen, das Allgemeine das Herrschende. Die Realität löst sich hier wieder in die Idealität auf. Aber diese Idealität muß doch im Ganzen wieder der Realität und der Differenz untergeordnet seyn, weil es die ideale Einheit innerhalb der realen ist. Sie muß also, da die allgemeine Form des Realen in der Differenz der Raum ist, als ein Ideales des Raums oder im Raum"}, {"type": "paragraph", "text": "erscheinen, sie muß demnach den Raum beschreiben, ohne ihn zu erfüllen, und als die ideale Einheit der Materie überall alle Attribute, die die Materie real an sich trägt, auf ideale Weise an sich tragen. Aber alle diese Bestimmungen treffen nur in Ansehung des Lichts zusammen, und es ist demnach das Licht die *in* der realen Einheit begriffene unendliche Idee aller Differenz, welches eben zu beweisen war. Das Verhältniß des Lichts zur Materie läßt sich noch auf andere Weise so deutlich machen. Die Idee nach ihren zwei Seiten wiederholt sich im Einzelnen, wie im Ganzen. Auch in der realen Seite, wo sie ihre Subjektivität in eine Objektivität bildet, ist sie Idee, obgleich sie in der Erscheinung nicht als solche, sondern als *Seyn *erscheint. Die Idee läßt in dem Realen der Erscheinung nur die eine Seite zurück, in dem Idealen der Erscheinung zeigt sie sich als Ideales; aber eben deßwegen nur in der Entgegensetzung gegen das Reale, also als *relativ-*Ideales. Das *An-sich* ist eben das, worin die beiden Seiten eins sind. Dieß angewendet auf den vorliegenden Fall, so ist die Körperreihe eben die eine Seite der Idee in ihrer Objektivität, die reale. Die andere Seite, wo die Idee als ein *Ideales *erscheint, fällt in das Licht, aber es erscheint *als* Ideales eben nur, indem es die andere Seite oder die reale zurückläßt, und wir sehen also hier zum voraus, daß das Höhere auch in der Natur dasjenige seyn wird, worin Materie und Licht selbst wieder eins sind. Das Licht ist das in die Natur scheinende Ideale, der erste Durchbruch des Idealismus. Die *Idee selbst* ist das *Licht*, aber *absolutes *Licht. In dem erscheinenden Licht erscheint sie *als *Ideales, als Licht; aber nur als *relatives *Licht, relativ-Ideales. Sie legt die Hülle ab, mit der sie sich in der *Materie* bekleidet; aber, um eben *als *Ideales zu *erscheinen*, muß sie im Gegensatz gegen das Reale erscheinen. Ich kann unmöglich diese Ansicht des Lichts hier durch alle Punkte verfolgen, und muß deßhalb auf"}]}, {"page_pdf": 1696, "page_book": 508, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "die allgemeine Philosophie verweisen. Nur über das Verhältniß des Lichts zum Klang und über den Gesichtssinn"}, {"type": "paragraph", "text": "als die nothwendige Bedingung der Existenz des Lichts für die Kunst muß ich mich hier erklären. a) Das* Verhältniß des Licht zum Klang* betreffend, so ist bekannt, wie vielfache Vergleichungen darüber gemacht worden sind, obschon die wahre Identität und Verschiedenheit beider bisher meines Wissens noch nicht auseinandergesetzt ist. - In der Materie, sagten wir, bildet das Wesen, die Identität, sich in die Form; in dem Licht dagegen ist die Form oder Besonderheit wieder zum Wesen verklärt. Hieraus muß sich auch das Verhältniß des Lichts und des Klanges einsehen lassen. Der Klang ist, wie wir wissen, nicht absolut gesetzt, nur gesetzt unter Bedingung einer dem Körper mitgetheilten Bewegung, wodurch er aus der Indifferenz mit sich selbst gesetzt wird. Der Klang selbst ist nichts anderes als die Indifferenz von Seele und Leib, aber diese Indifferenz nur, soweit sie in der ersten Dimension liegt. Wo dem Ding der unendliche Begriff absolut verbunden ist, wie dem Weltkörper, der auch als endlich unendlich, da entsteht jene innere Musik der Bewegungen der Gestirne; wo bloß relativ, entsteht der Klang, welcher nichts anderes als der Akt der Wiedereinbildung des Idealen ins Reale, also die Erscheinung der Indifferenz ist, nachdem beides aus der Indifferenz gerissen. Das Ideale ist nicht an sich *Klang*, ebenso wie der Begriff eines Dings nicht an sich Seele ist. Der Begriff des Menschen wird *Seele *eben nur in der Beziehung auf den Leib, wie der Leib nur Leib ist in Beziehung auf die Seele. So ist das, was wir Klang des Körpers nennen, eben schon das in Beziehung auf den Körper gesetzte Ideale. Wenn also das, was im Klang sich offenbart, nur der Begriff des Dings ist, so werden wir dagegen das Licht der *Idee *der Dinge gleichsetzen, oder dem, worin das Endliche dem Unendlichen wahrhaft verknüpft ist. Der Klang ist also das inwohnende oder endliche Licht der körperlichen Dinge, das Licht ist die unendliche Seele aller körperlichen Dinge. Allein das absolute Licht, das Licht als wahrhaft absolute Auflösung der Differenz in die Identität, würde selbst gar nicht als"}, {"type": "paragraph", "text": "Erscheinung in die Sphäre der Objektivität fallen. Nur als relativ-Ideales und demnach in seiner Entgegensetzung zugleich und relativer Einheit mit dem Körper kann es *als *Licht *erscheinen.* Es fragt sich, wie eine Einheit zwischen dem Licht und dem Körper denkbar sey. Nach unsern Grundsätzen können wir keine unmittelbare Wirkung beider aufeinander zugeben. So wenig wir annehmen können, daß die Seele unmittelbare *Ursache *einer Wirkung in dem Leib oder umgekehrt der Leib in der Seele werden könne, ebensowenig können wir das Licht unmittelbar auf die Körper, oder hinwiederum diese unmittelbar auf das Licht wirken lassen. Licht und Körper können also überhaupt nur durch prästabilirte Harmonie eins seyn, und nur durch das, worin sie eins *sind*, nicht aber durch ein einseitiges Causalverhältniß aufeinander wirken. Es ist die Schwere, welche hier in der höheren Potenz wieder eintritt, die absolute Identität, welche, es sey nun in Reflexion oder Refraktion, Licht und Körper vereint. Der allgemeine Ausdruck nun des mit dem Körper synthesirten Lichts ist *getrübtes *Licht oder Farbe. Daher wäre als *Zusatz * zu §. 84 zu bemerken: *Das Licht kann als Licht nur in der Entgegensetzung mit dem Nicht-Licht, und demnach nur als Farbe* erscheinen. Der Körper ist überhaupt Nicht-Licht, sowie das Licht dagegen Nicht-Körper ist. So gewiß nun im empirischen Licht das absolute Licht nur als relativ-Ideales erscheint, so gewiß kann es überhaupt nur in"}]}, {"page_pdf": 1697, "page_book": 510, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der Entgegensetzung gegen das Reale erscheinen. Licht mit Nicht-Licht verbunden ist nun allgemein getrübtes Licht, d.h. Farbe. Die Lehre vom Ursprung der Farben ist keineswegs für die Theorie der Kunst unwichtig, obgleich es eine bekannte Sache ist, daß kein neuerer Künstler, der über seine Kunst nachgedacht, von der *Newton-*schen Farbentheorie je eine Anwendung machte. Aber schon dieß könnte hinreichen zu beweisen, wie gänzlich unbegründet in der Natur sie ist, denn Natur und Kunst sind eins. Der Instinkt der Künstler lehrte sie den allgemeinen Gegensatz der Farben, den sie als Gegensatz von Kälte und Wärme ausdrückten, ganz unabhängig von den Newtonschen"}, {"type": "paragraph", "text": "Vorstellungen erkennen. *Goethes *neue Ansichten dieser Lehre sind ebensosehr auf die Natur- als auf die Kunstwirkungen der Farben gegründet; man sieht in ihnen die innigste Harmonie zwischen Natur und Kunst, anstatt daß in den Newtonschen schlechthin kein Mittel lag, die Theorie mit der Praxis des Künstlers zu verbinden. Das Princip, welches der wahren Ansicht der Farbe zu Grunde gelegt werden muß, ist die *absolute Identität und Einfachheit des Lichts.* Newtons Theorie widerlegt sich für den, der überhaupt sich über den Gesichtspunkt des einseitigen Causalverhältnisses erhoben hat, schon allein dadurch, daß er bei dem Phänomen der Farbenproduktion in der Brechung durch transparente Körper *diese *als gänzlich müßig annahm und aus dem Spiel ließ. Dadurch war er nun genöthigt, alle Mannichfaltigkeit der Farbe in das Licht selbst, und zwar als eine vorhandene, mechanisch vereinigte und mechanisch trennbare zu legen. Bekanntlich ist nach Newton das Licht aus sieben Strahlen von verschiedener Brechbarkeit zusammengesetzt, so daß jeder einfache Strahl ein Büschel von sieben farbigen Strahlen ist. Diese Vorstellung ist durch die höhere Ansicht der Natur des Lichts selbst genug widerlegt, daß wir kein Wort zur Widerlegung hinzuzufügen haben. Um das Farben-Phänomen ganz zu begreifen, müssen wir zuvor von dem Verhältniß der *durchsichtigen *und *undurchsichtigen Körper *zum Licht einige Begriffe haben. Der Körper trübt sich in dem Verhältniß für das Licht, in welchem er sich von der Allheit der übrigen Körper absondert und als ein selbständiger heraustritt. Denn das Licht ist die Identität aller Körper; in dem Verhältniß also, in welchem er sich von der Totalität absondert, sondert er sich auch von dem Licht, denn er hat mehr oder weniger die Identität *in sich selbst *als Besonderes aufgenommen. Dieß gilt so weit, daß die undurchsichtigsten Körper, die Metalle, eben auch diejenigen sind, die am meisten jenes innere Licht, den *Klang*, sich eingeboren haben. Die *relative Gleichheit mit sich selbst *ist das, wodurch der Körper aus der Gleichheit mit allen andern tritt. Diese relative Gleichheit aber (= Cohäsion, Magnetismus) beruht auf einer relativen"}, {"type": "paragraph", "text": "Indifferenz seines Besonderen mit seinem Allgemeinen oder Begriff. Die Trübung für das Licht wird also nur da aufhören, wo diese relative Gleichheit so weit aufgehoben ist, daß entweder das rein-Allgemeine oder das rein-Besondere überwiegend ist - also an den Enden der Cohäsionsreihe -, oder da, wo beide zur absoluten Indifferenz reducirt sind, wie im Wasser, dessen Allgemeines das ganze Besondere, das Besondere das ganze Allgemeine ist, oder da, wo auch der Streit der absoluten Cohäsion (wodurch der Körper in sich selbst) und der relativen (wodurch er dem Licht angehört) vollkommen ausgeglichen ist, und der Körper ganz Erde und ganz Sonne ist. - Die weiteren Erläuterungen dieser Sätze gehören, wie von selbst offenbar ist, in eine andere Sphäre der Untersuchung."}]}, {"page_pdf": 1698, "page_book": 512, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Ein solcher Körper nun, der in der vollkommenen Identität mit dem Licht ist (und ein solcher wäre ein absolut-durchsichtiger Körper), wäre dem Licht überall nicht mehr entgegengesetzt. Nur insofern der Körper noch immer ein Besonderes bleibt oder dem Licht relativ - zum Theil - entgegengesetzt ist, synthesirt die absolute Identität, die hier als Schwerkraft der höheren Potenz eintritt, das Licht mit ihm (daß nämlich nicht der *Körper *das Licht breche, folgt aus der Newtonschen Erfahrung, daß die Brechung nicht unmittelbar, sondern in einiger Entfernung von der Oberfläche des Körpers geschieht, wozu Newton eine actio in distans annimmt, die ich - im Newtonschen Sinne - nicht nur hier, sondern überall verwerfe). Diese Synthese des Lichts und des Körpers ist beim durchsichtigen und undurchsichtigen Körper gleicherweise der Fall, nur daß dieser das Licht reflektirt, der durchsichtige Körper aber nimmt es in sich selbst auf und durchdringt sich mit ihm. Da es aber keine vollkommene Durchsichtigkeit gibt, sondern in denjenigen durchsichtigen Körpern, welche das Licht am meisten brechen, auch noch das größte Uebergewicht der Besonderheit ist, so wird das Licht oder die Identität im Licht selbst mit der Besonderheit oder Differenz synthesirt und demnach getrübt. (Alle unsere durchsichtigen Körper sind trübende Mittel). Es ist abermals weder das Licht für sich noch der Körper für sich, sondern es ist das, worin beide eins sind, was die Farbe"}, {"type": "paragraph", "text": "producirt. Das Licht wird daher in diesem Proceß auf keine Weise weder zerlegt noch gespalten, nicht chemisch oder mechanisch decomponirt, sondern es selbst bleibt als der eine Faktor des Processes in seiner absoluten Einfachheit; alle Differenz ist durch das Nicht-Licht oder den Körper gesetzt. Farbe ist = Licht + Nicht-Licht, Positives + Negatives. Das Wichtigste für die Ansicht der Kunstwirkungen der Farben ist nun das Begreifen der Totalität der Farben. Das, wodurch eine Totalität allein möglich ist, ist eine Vielheit in der Einheit, demnach ein Gegensatz, der sich in allen Farbenerscheinungen zeigen muß. Wir brauchen, um diesen Gegensatz darzustellen, nicht unmittelbar zum prismatischen Bild zu gehen, welches bereits ein verwickeltes und zusammengesetztes Phänomen ist. Kein Wunder, daß Newton zu keinem andern Resultat kam, da er gerade dieses Phänomen als das erste nahm, und daß es nicht weniger als der Anschauung eines *Goethe* bedurfte, um den wahren Faden dieser Erscheinung wieder zu finden, den Newton in dem Knäuel so künstlich versteckt hatte, den er seine Theorie nannte. Noch jetzt ist die prismatische Erscheinung den Physikern die Grunderscheinung; auch die Künstler werfen sich einzig auf sie, obgleich sie eine Menge Fälle unerklärt läßt, die in ihrer Kunst wiederkommen. Wir finden den Gegensatz der Farben schon in viel einfacheren Fällen. Es gehören hieher die Phänomene der gefärbten Gläser oder farbigen Flüssigkeiten, welche Newton aus einer Verschiedenheit des reflektirten und restringirten Lichts zu erklären suchte. Wenn z.B. ein blaugefärbtes Glas gegen eine dunkle Fläche gehalten wird, und das Auge sich zwischen dem Licht und dem Körper befindet, so geht jene Farbe bis zum tiefsten Blau hinab; derselbe Körper aber so gehalten, daß er zwischen dem Auge und dem Licht sich befindet, gibt das schönste Gelb- oder auch wohl Hochroth. Hier entsteht also die rothe Farbe unmittelbar durch ein Weniger des Getrübtwerdens, anstatt daß in dem ersten Fall die dunklere Farbe durch ein bloßes Mehr des Getrübtwerdens entsteht. Die beiden Farbenpole schließen sich hier noch aus, sie erscheinen nicht simultan, aber nacheinander. Durch eine Verbindung verschiedener"}, {"type": "paragraph", "text": "Linsen, durch die man das Licht gehen läßt, und wovon die erste das Licht noch vollkommen weiß durchscheinen läßt, kann man in einem dunklen Zimmer das erst weiße Licht endlich bis zum *rothen*"}]}, {"page_pdf": 1699, "page_book": 514, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Licht trüben; durch eine weitere Fortsetzung würde man es bis ins Blaue treiben. Nach diesem Gesetze färbt sich der Himmel für uns blau, die Sonne dagegen im Aufgehen roth. *Diese * Phänomene, in welchen durch das bloße Mehr oder Weniger der Trübung Farbe entsteht, sind die einfachen, von denen man auszugehen hat. Von viel accidentelleren Bedingungen sind alle Arten prismatischer Erscheinungen abhängig. Sie beruhen, kann man allgemein sagen, darauf, daß ein Doppelbild gesehen wird. Wir *sehen* Licht und Nicht-Licht zugleich (es findet eine subjektive Synthese von Licht und Nicht-Licht im Auge statt). Durch die Wirkung der Refraktion wird daher das betrachtete Bild verrückt, aber es erleidet keine Veränderung, wenn es über einen andern relativ dunklen oder erleuchteten Raum geführt wird, so daß das verrückte Bild zugleich mit einem andern gesehen wird. Je nachdem nun dieser Raum relativ gegen den andern hell oder dunkel ist, erscheint das Bild an den Rändern verschiedentlich gefärbt; ist es nämlich der hellere Raum auf dunklem Grund, der durch die Refraktion verrückt wird, so daß - bei abwärts gekehrtem Brechungswinkel - der dunkle Raum von oben ins Helle, von unten der helle ins Dunkle geführt wird, so erscheinen an jener Stelle die warmen, an dieser die kalten Farben. Die Sonne in den Newtonschen Versuchen mit dem in einem dunklen Zimmer auf das Prisma fallenden Licht stellt in der That dabei nichts anderes als einen hellen Fleck auf dunklem Grund dar; sie wirkt in der ganz allgemeinen Qualität eines Bilds von eminenter Helligkeit auf einem durchaus dunklen Grund, dem Weltraum. Die prismatische Erscheinung, sofern sie mit dem Sonnenlicht hervorgebracht wird, ist also von den möglichen prismatischen Erscheinungen nur der Eine Fall, der nämlich, wo auf einem dunklen Grunde ein heller Raum gesehen wird. Wichtiger ist es für uns, die ganze secundäre Stelle dieser Erscheinungen einzusehen."}, {"type": "paragraph", "text": "Die Farben bilden unter sich ein System ebenso wie die Töne. Sie sind daher an sich weit ursprünglicher als sie im prismatischen Bild erscheinen, dessen Bedingungen zufällig und abgeleitet sind. Daß unter diesen Bedingungen keine andern als eben diese Farben erscheinen, ist nothwendig, weil es die einzigen sind, die überhaupt möglich sind. Die Totalität oder das System der Farben hat also in sich betrachtet allerdings eine Art der Nothwendigkeit; es ist nicht zufällig, aber es muß nur nicht gerade von den prismatischen Erscheinungen abstrahirt werden, noch müssen diese für das ursprüngliche Phänomen gehalten werden, in denen sich die Farben erzeugen. Der Gegensatz, welcher sich im prismatischen Bild zwischen den kalten und warmen Farben zeigt, die sich polarisch einander entgegenstellen, ist allerdings ein nothwendiger Gegensatz und zur Totalität, welche die Farbe als geschlossenes System in sich bilden, nothwendig. Allein dieser Gegensatz ist eben deßwegen auch ursprünglicher als das abgeleitete und zusammengesetzte Phänomen des Farbenspectrums. Die Polarität der Farben ist nicht als eine fertig vorhandene, sondern als eine producirte zu denken, die sich überall entwirft, sowie nur Licht und Nicht-Licht in Conflikt gesetzt werden. Das Farben-Phänomen ist die aufbrechende Lichtknospe; die Identität, die in dem Lichte ist, wird mit der Differenz, die durch das Nicht-Licht in sie gesetzt ist, verbunden zur Totalität. In einer viel höheren Beziehung erscheint die Nothwendigkeit dieser Polarität und der inneren Totalität der Farben in den Forderungen, die der Gesichtssinn macht, und die für die Kunst ebenso wichtig als für die Naturforschung interessant sind. Jetzt also zu dem Verhältniß des *Gesichtssinns*. Die beiden Seiten, die wir in der Körperreihe und dem Licht abgesondert herausgeworfen sehen - reale und ideale -, sind im Organismus beisammen und eins. Das relativ-Ideale im Licht ist hier durch das Reale integrirt. Das Wesen des Organismus ist: *Licht mit Schwere verbunden. *Der Organismus ist ganz Form und ganz Stoff, ganz Thätigkeit und ganz Seyn. Dasselbige Licht, welches in der allgemeinen Natur die anschauende Thätigkeit des Universums"}]}, {"page_pdf": 1700, "page_book": 515, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "ist, ist im Organismus dem Stoffe vermählt; es ist nicht mehr bloß rein ideelle Thätigkeit, wie in der allgemeinen Natur, sondern ideelle Thätigkeit, die, mit dem Stoffe verbunden, das Attribut eines Existirenden ist. Ein und dasselbe ist zugleich die reelle und ideelle. Jedes von außen Einwirkende macht an den Organismus die Forderung einer bestimmten Dimension, so auch das Licht. Und wenn Sensibilität überhaupt = dritter, das Sehen aber wieder die Blüthe der Sensibilität ist, so ist die Forderung des Lichts an den Organismus Produkt der dritten organischen Dimension, vollkommene Indifferenz des Lichts und der Materie. Aber was ist denn Sehen auch anders? Das ideelle Princip für sich wäre reines Denken, das reelle reines Seyn. Allein das von außen sollicitirte Indifferenzvermögen des Organismus setzt Denken und Seyn immer wieder gleich. Denken synthesirt mit Seyn aber ist *anschauen. *Das Anschauende ist die Identität selbst, welche hier *in * der reflektirten Welt wieder die Indifferenz des Idealen und Realen darstellt. Es ist das Wesen, die Substanz des Organismus - aber eben deßwegen zugleich das *absolut*-, nicht das bloß relativ-Ideale (wie im Licht) - das Producirende, Anschauende. Es ist das fühlende, hörende, sehende Princip auch im Thier. Es ist das absolute Licht. Die allgemeine Bedingung der *Anschauung *dieses Lichts ist die Indifferenz des A2 und A = B. Nach der verschiedenen Art, wie, oder den Bedingungen, unter welchen beide gleichgesetzt werden, ist es z.B. hörendes, sehendes oder fühlendes Princip. Jedes Sinnesorgan drückt für sich eine solche Indifferenz des Ideellen und Reellen, des Lichts und der Schwere aus; in jeder solchen Indifferenz wird das Wesen, das An-sich des Organismus produktiv, anschauend. Auch physisch genommen schaut das organische Wesen nicht den Gegenstand außer sich an, es schaut nur die in ihm gesetzte Indifferenz des Ideellen und Reellen an. Diese tritt ihm an die Stelle des Gegenstandes. Kraft der prästabilirten Harmonie zwischen der allgemeinen und der organischen Natur ist in den Anschauungen der letzteren dasselbe System, welches in den entsprechenden Formen der Außenwelt ist. Die Harmonie des Dreiklangs ist etwas Objektives und doch"}, {"type": "paragraph", "text": "zugleich durch den Gehörsinn Gefordertes. Dasselbe ist der Fall mit dem Gesichtssinn, dessen Forderungen das tiefste Studium des Künstlers seyn müssen, der auf dieses zarteste aller Organe wirken will. Das Auge fordert in allem, was ihm als wohlgefällig dargeboten werden soll, die Harmonie der Farben nach derselben Nothwendigkeit und denselben Gesetzen, nach welchen sie in der äußeren Erscheinung producirt wird. Die höchste Lust des Auges ist, indem es aus der ermüdenden Identität gesetzt wird, in der höchsten Differenz doch wieder durch die Totalität in ein vollkommenes Gleichgewicht gesetzt zu werden. Deßwegen fordert das Auge im Allgemeinen in jedem Gemälde Totalität der Farben, und es bedarf nur geringes Studium und Aufmerksamkeit, um zu finden, welch ein vollkommenes Gefühl dieser Forderung die größten Meister geleitet hat. Sehr häufig findet man diese Forderung in großen Compositionen nicht bloß insofern befriedigt, als die Totalität der Farben zu denselben *nothwendig *war; nicht selten findet man die Forderung einer Farbe, für welche in dem Hauptgegenstand kein Grund lag, durch einen Nebengegenstand befriedigt, z.B. die Forderung des Gelb oder irgend einer andern Farbe durch Früchte, Blumen u.s.w., die in dem Gemälde angebracht sind. Aber auch da, wo das Auge von der Forderung der vollkommenen Totalität absteht, macht es doch immer die Forderung der entsprechenden Farben geltend. Dieß ist vorzüglich deutlich in der Erscheinung der sogenannten physiologischen Farben. Das Auge z.B., welches durch den Reiz des Rothen ermüdet ist, producirt, nachdem dieser Reiz entfernt ist, von freien Stücken die grüne Farbe, oder bestimmter von Blau und Gelb als Farben das, was denselben am unmittelbarsten entgegengesetzt ist, die Indifferenz. In"}]}, {"page_pdf": 1701, "page_book": 517, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "dem Farbenbild schließen sich Grün und Purpur aus. Eben weil beide sich ausschließen, fordert sie das Auge. Ermüdet durch das Grün fordert das Auge Purpur oder die entsprechende Totalität von Violett und Roth. Durch Purpur das vollkommenste Grün. So auch in der Kunst. Die Verbindung von Purpur und Grün z.B. in Gewändern bringt die höchste Pracht hervor. - Ich stelle nun einen weiteren Satz auf, dem ich nur noch folgendes Allgemeine voranschicke."}, {"type": "paragraph", "text": "Unmittelbar aus der Idee des Lichts folgt, daß es als die *besondere *Einheit nur unter der Bedingung eines Gegensatzes erscheinen könne. Es ist die im Realen durchbrechende ideale Einheit. Soll es *als diese *erscheinen, so muß es als Zurückbildung der Differenz in die Identität erscheinen, aber nicht *als absolute *(denn in der Absolutheit wird die Einheit nicht als die besondere unterschieden), demnach bloß in relativer Identität. - Nun ist aber das Besondere oder die Differenz *für sich *nichts als die Negation des Allgemeinen oder der Identität. Nur inwiefern sich das Allgemeine, die Identität selbst in das Besondere verwandelt, ist es *reell *(deßwegen die Einformung der Einheit in die Vielheit die *reale *Einheit ist). Wenn also in der idealen Einheit oder in der Zurückbildung des Besonderen ins Absolute das Besondere noch als solches unterschieden werden soll, kann es nur *als Negation *unterschieden werden. Demnach wird sich das Allgemeine und Besondere in der Erscheinung der idealen Einheit nur als Realität und Privation, also, weil das Allgemeine Licht ist, nur als Licht und Nicht-Licht verhalten können, oder die Besonderheit wird in dem Allgemeinen nur als Privation oder Begrenzung der Realität dargestellt werden können."}, {"type": "paragraph", "text": "§. 85. *Die Kunstform, welche die ideale Einheit in ihrer Unterscheidbarkeit zum Symbol nimmt, ist die Malerei. -* Folgt unmittelbar aus den vorhergehenden Sätzen. Denn die ideale Einheit in ihrer Relativität erscheint innerhalb der Natur durch den Gegensatz des Lichts und Nicht-Lichts. Aber eben desselben bedient sich die Malerei zum *Mittel *ihrer Darstellung. *Anmerkung. *Die ferneren Bestimmungen der Malerei folgen von selbst aus dem ersten Begriff."}, {"type": "paragraph", "text": "§. 86. *Die nothwendige Form der Malerei ist die aufgehobene Succession. *- Dieser Satz fließt unmittelbar aus dem schon in §. 77 bewiesenen Begriff der Zeit. Die Einbildung der Einheit in die Vielheit ist Zeit. Da nun Malerei vielmehr auf der entgegengesetzten Einheit, der Einbildung der Vielheit in die Einheit beruht, so ist die nothwendige Form derselben die aufgehobene Succession."}, {"type": "paragraph", "text": "Die Malerei, welche die Zeit aufhebt, bedarf doch des Raumes, und zwar so, daß sie genöthigt ist den Raum zu dem Gegenstand hinzuzufügen. Der Maler kann keine Blume, keine Gestalt, überhaupt nichts darstellen, ohne *im Gemälde *selbst zugleich den Raum darzustellen, in welchem sich der Gegenstand befindet. Die Produkte der Malerei können also noch nicht als Universa den Raum in sich selbst und keinen außer sich haben. Wir werden in der Folge hierauf zurückkommen und zeigen, wie die Malerei sich dadurch am meisten der höchsten Kunstform annähert, daß sie den Raum als ein Nothwendiges behandelt und ihn mit den Gegenständen ihrer Darstellung gleichsam verwachsen darstellt. In dem vollkommenen Gemälde muß auch der Raum für sich, ganz unabhängig von dem inneren oder qualitativen Verhältniß des Gemäldes, eine Bedeutung haben."}]}, {"page_pdf": 1702, "page_book": 519, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Es gibt noch eine andere Art sich dieses Verhältniß deutlich zu machen. Nach dem Bisherigen sind die beiden Künste der Musik und Malerei den beiden Wissenschaften der Arithmetik und Geometrie zu vergleichen. Die *geometrische Figur *bedarf des Raumes außer ihr, weil sie auf das Reale Verzicht thut, nur das *Ideale *im Raum darstellt. Der Körper, welcher eine reale Ausdehnung hat, hat seinen Raum in sich selbst, und ist unabhängig von einem Raum außer ihm zu begreifen. Die Malerei, die vom Realen nur das Ideale darstellt, keine wirklich körperlichen Gestalten, sondern nur die Schemata dieser Gestalten, bedarf nothwendig des Raumes außer ihr, wie die geometrische Figur nur durch Begrenzung eines gegebenen Raumes möglich ist. *Folgesatz* 1. Die Malerei ist als Kunst ursprünglich der *Fläche *untergeordnet. Sie stellt nur Flächen dar, und kann nur *innerhalb *dieser Begrenzung den Schein des Körperlichen hervorbringen. *Folgesatz* 2.* Die Malerei ist die erste Kunstform, welche Gestalten darstellt. -* Die Malerei stellt überhaupt das Besondere im Allgemeinen oder in der Identität dar. Nun kann sich aber das Besondere vom Allgemeinen überhaupt nur durch Begrenzung oder Negation unterscheiden. Aber eben Begrenzung der Identität ist, was wir Umriß, Gestalt nennen (Musik gestaltlos)."}, {"type": "paragraph", "text": "*Folgesatz* 3. Die Malerei hat außer den Gegenständen noch den Raum als solchen darzustellen. *Folgesatz* 4. Wie die Musik im Ganzen der Reflexion, ist die Malerei der Subsumtion untergeordnet. Es wird in der Philosophie bewiesen, daß das, was an dem Körper Umriß und Gestalt bestimmt, eben dasjenige ist, wodurch er der Subsumtion eignet. Bloß durch seine Begrenzung hebt er sich als Besonderes ab, und ist *als solches *der Aufnahme unter das Allgemeine fähig. Man hat schon längst bemerkt, daß die Malerei vorzugsweise eine Kunst des Geschmacks und des Urtheils sey. Nothwendig: weil sie am meisten von der Realität sich entfernt und ganz ideal ist. Das Reale ist nur Gegenstand der Reflexion oder der Anschauung. Das Reale aber im Idealen zu schauen, ist Gegenstand des Urtheils. *Folgesatz* 5. Die Malerei ist im Ganzen eine qualitative Kunst, wie die Musik im Ganzen eine quantitative. Denn jene beruht auf den rein qualitativen Gegensätzen der Realität und Negation."}, {"type": "paragraph", "text": "§. 87. *In der Malerei wiederholen sich alle Formen der Einheit, die reale, ideale und die Indifferenz beider.* - Folgt aus dem allgemeinen Princip, daß jede besondere Kunstform wieder die ganze Kunst. *Zusatz. *Die besonderen Formen der Einheit, sofern sie in der Malerei zurückkehren, sind: *Zeichnung, Helldunkel *und *Colorit. - *Diese drei Formen sind also gleichsam die allgemeinen Kategorien der Malerei. Ich werde die Bedeutung jeder dieser besonderen Formen für sich und ihre Vereinigung und Zusammenwirkung zum Ganzen angeben. - Ich erinnere auch hier, daß ich nicht in der technischen Beziehung davon handle, sondern die absolute Bedeutung einer jeden angeben werde. Die *Zeichnung *ist innerhalb der Malerei als der idealen Kunst die reale Form, die erste Einfassung der Identität in die Besonderheit. Diese Besonderheit als Differenz wieder in die Identität zu verschmelzen und als Differenz aufzuheben, ist die eigentliche Kunst des Helldunkels, welche demnach die Malerei in der Malerei ist. Allein da"}, {"type": "paragraph", "text": "alle Kunstformen als solche nur besondere sind, und ihr Bestreben seyn muß, in der besonderen Form absolute Kunst zu seyn, so ist leicht einzusehen, daß die Malerei, wenn sie auch als besondere Form alle Forderungen erfüllte, ohne denen der allgemeinen Kunst zu genügen, durchaus mangelhaft seyn würde. Die bildende Kunst überhaupt ist im Ganzen der realen Einheit untergeordnet; die reale Form ist also die"}]}, {"page_pdf": 1703, "page_book": 521, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "erste Forderung an bildende Kunst, wie z.B. der Rhythmus an die Musik. Die Zeichnung ist der Rhythmus der Malerei. Die Widersprüche der Kunstkenner oder Kunstrichter über die größere Wichtigkeit der Zeichnung oder des Kolorits beruhen auf einem nicht geringeren Mißverstand, als etwa in Ansehung der Musik, ob Rhythmus oder Melodie wichtiger. Man sagt: es gibt Gemälde, die, obgleich der Zeichnung nach nur mittelmäßig, dennoch wegen ihrer Vortrefflichkeit von Seiten des Colorits unter die Meisterwerke gesetzt werden. Es kann nicht zweifelhaft seyn, wenn es wirklich solche Gemälde gibt, worauf sich ein solches Kennerurtheil gründe. Ganz gewiß nicht auf die eigentliche Bewunderung der Kunst, sondern auf den angenehmen sinnlichen Effekt, den ein gut colorirtes Gemälde auch ohne allen Werth der Zeichnung machen kann. Die Richtung der Kunst geht aber überall nicht auf das Sinnliche, sondern auf *eine über alle Sinnlichkeit erhabene Schönheit.* Der Ausdruck des absoluten Erkennens an den Dingen ist die Form; bloß durch diese erheben sie sich in das Reich des Lichts. Die Form ist demnach das Erste an den Dingen, wodurch sie auch der Kunst eignen. Die Farbe ist nur das, wodurch auch das Stoffartige der Dinge zur Form wird; sie ist nur die höhere Potenz der Form. Alle Form aber hängt von der Zeichnung ab. Nur durch die Zeichnung also ist die Malerei überhaupt Kunst, so wie sie nur durch die Farbe Malerei ist. Die Malerei als solche nimmt die rein-ideale Seite der Dinge auf, aber ihr Hauptzweck ist keineswegs jene grobe Täuschung, die man gewöhnlich dafür angibt, uns den gemalten Gegenstand für einen wirklich vorhandenen ansehen zu machen. * Diese * Täuschung in ihrer Vollkommenheit wäre ohne die hinzukommende Wahrheit der Farben und das daraus entspringende Leben nicht zu"}, {"type": "paragraph", "text": "erreichen, und wenn wir sie forderten, würden wir eher beträchtliche Fehler der Zeichnung als des Colorits übersehen. Allein die Kunst überhaupt und auch die Malerei ist so weit entfernt auf Täuschung auszugehen, daß sie vielmehr gerade in ihren höchsten Wirkungen den Schein der Wirklichkeit, in dem dabei angenommenen Sinn des Worts, *vernichten *muß. Jeden, der die idealischen Bildungen der griechischen Künstler betrachtet, muß ihre Gegenwart unmittelbar mit dem Eindruck der Nicht-Wirklichkeit überfallen, er muß erkennen, daß hier etwas dargestellt sey, das über alle Wirklichkeit erhaben, obgleich in dieser Erhabenheit durch die Kunst * wirklich gemacht ist. *Wer zum Kunstgenuß der Täuschung bedarf und sich, um zu genießen, den Gedanken entfernen muß, daß er ein Kunstwerk vor sich habe, ist zuverlässig überhaupt nicht dessen fähig, und höchstens mag er sich an den derbsten Produktionen der niederländischen Malerei ergötzen, durch welche freilich weder eine höhere Befriedigung gewährt noch eine höhere Forderung aufgeregt wird, als die auch in den Sinnen gefunden werden kann. Es ist eine von französischen Kunstrichtern aufgebrachte Trivialität, zu sagen, daß Raphael z.B. in der Zeichnung überlegen, dagegen im Colorit nur mittelmäßig, Correggio dagegen in dem Verhältniß, in welchem er in dem Colorit überlegen, in der Zeichnung untergeordnet sey. Dieser Satz ist geradezu falsch. Raphael hat in vielen seiner Werke so vortrefflich als Correggio colorirt, Correggio in bei weitem den meisten so vortrefflich wie Raphael gezeichnet. Gerade bei Correggio, den einige Kunstrichter in Ansehung der Zeichnung unterordnen, zeigt sich, wie tief und verborgen diese Seite der Kunst ist, da jener Künstler durch die Magie des Helldunkels und Colorits sie dem gemeinen Auge wieder zu entziehen wußte. Ohne die tiefere Grundlage seiner vortrefflichen Zeichnung würde auch die größte Schönheit der Farben den Kenner nicht entzücken. Ich gebe die Hauptforderungen, die an die Zeichnung gemacht werden müssen, kurz an. Die erste Forderung ist die Beobachtung der *Perspektive*. - Erklärung des Begriffs der Perspektive. - Gegensatz der Linienperspektive und der Luftperspektive."}]}, {"page_pdf": 1704, "page_book": 523, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Es ist vorzüglich wichtig, daß ich mich über die Grenzen erkläre, * innerhalb *welchen die Beobachtung der Perspektive *nothwendig *ist, und *außerhalb *deren sie eine freie Kunst oder selbst Zweck wird. Wie überall finden wir auch hier wieder einen Gegensatz der antiken und modernen Kunst, daß nämlich jene durchaus auf das Nothwendige, Strenge, Wesentliche ging, diese das Zufällige ausbildete und ihm eine unabhängige Existenz gab. Es ist viel über die Frage gestritten worden, ob die Alten die Linienperspektive gekannt haben oder nicht. Wir würden uns ohne Zweifel ganz gleich irren, wenn wir den Alten die Kenntniß und Beobachtung der Perspektive soweit absprechen wollten, als sie zur *Richtigkeit *gehört, und wenn wir auf der andern Seite annehmen wollten, daß sie die Perspektive, wie die Neueren, zur Täuschung benutzt haben. Den Alten die Perspektive absprechen, auch insoweit sie zur allgemeinen Richtigkeit ohne Illusion gehört, hieße, ihnen in der Malerei die größten Unschicklichkeiten zutrauen, oder behaupten, daß sie Ungeheuer von Gestalten gemacht haben. Z.B. wenn wir einen Menschen mit ausgestreckten Armen von der Seite, aber in der Nähe sehen, so daß Eine Hand vom Auge entfernter ist als die andere, so ist es perspektivisch nothwendig, daß die entferntere kleiner ins Auge falle. Weil wir aber einmal wissen, daß in der Natur eine Hand so groß ist wie die andere, so finden wir auch in der Anschauung beide gleich groß. Wollte nun der Maler diesem zufolge, ohne auf die perspektivische Verkürzung Rücksicht zu nehmen, beide Hände wirklich gleich groß machen, so würde er eben dadurch eine Unrichtigkeit begehen, denn ein geübtes Auge wird *nun *erst die näher liegende Hand kleiner als die entferntere sehen. Solche Monstruositäten, die aus der Vernachlässigung der Perspektive im Nothwendigen entständen, den Alten Schuld zu geben, wäre eine vollkommene Absurdität. Dagegen aber vermochten die Alten niemals die Illusion zum Zweck zu machen, und deßwegen etwas, das bloß als Mittel der Richtigkeit Werth hat, als eine selbständige Kunst auszubilden, wie es die Neueren mit der Perspektive gemacht haben. Die Perspektive dient dazu, alles Harte, Einförmige zu vermeiden,"}, {"type": "paragraph", "text": "indem der, welcher sie innehat, mit leichter Mühe z.B. ein Quadrat als Trapezium, einen Cirkel als Ellipse erscheinen lassen kann. Ueberhaupt hilft sie, von den Gegenständen gerade die schönsten Theile und die größten Massen zu zeigen, das Mindergefällige oder das Kleinliche zu verbergen. Dieser freie Gebrauch muß übrigens nie soweit ausgedehnt werden, daß durch die Perspektive allein das Angenehme gesucht, und die Strenge der Nothwendigkeit, das, worin sich die tiefste Kunst der Zeichnung äußern müßte, umgangen wird. Da die Zeichnung und Malerei zunächst auf Darstellung der *Formen *geht, und die Bedingung des Schönen, obgleich allerdings nicht die Vollendung des Schönen selbst, die Wohlgefälligkeit ist, so muß diese in der Zeichnung so weit gesucht werden, als sie den höheren Forderungen der Wahrheit und Richtigkeit keinen Eintrag thut. Der vorzüglich, ja der fast einzig würdige Gegenstand der bildenden Kunst ist die menschliche Gestalt. Wie der Organismus innerlich und seinem Wesen nach die sich aus sich selbst erzeugende und in sich zurückkehrende Succession ist, so drückt er diese Form auch äußerlich aus durch die Herrschaft der elliptischen, parabolischen und anderer Formen, welche am meisten die Differenz in der Identität ausdrücken. In der Zeichnung wird gefordert, daß die einförmigen, sich immer wiederholenden Formen selbst bei geringeren Gegenständen vermieden werden, als ob der Künstler auch hier das Symbol der organischen Gestalt vor sich haben müßte. Sich selbst beständig wiederholende Formen sind die viereckigten, weil sie aus vier Linien bestehen, von welchen immer zwei und zwei einander parallel sind, aber nicht minder die vollkommen runden, weil sie von allen Seiten betrachtet immer die nämlichen sind. Das Oval und die Ellipsen drücken in der Identität noch Differenz und"}]}, {"page_pdf": 1705, "page_book": 524, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Mannichfaltigkeit aus. Unter den regelmäßigen Figuren ist aus gleichem Grunde das Dreieck noch die am wenigsten mißfällige, weil die Winkel der Anzahl nach ungleich sind, und die Linien keine Parallele bilden. Eine Forderung der Zeichnung ist also, soviel möglich jede Wiederholung von Formen, jede Parallele, Winkel von gleichen Graden, vorzüglich aber rechte Winkel zu vermeiden, weil in diesen"}, {"type": "paragraph", "text": "gar keine Mannichfaltigkeit möglich ist. Gerade Linien müssen so viel möglich in wellenförmige verwandelt werden, und zwar so, daß im Ganzen der Gestalt ein möglichst vollkommenes und verhältnißmäßiges Gleichgewicht des Concaven und Convexen, des Ein- und Ausbiegens beobachtet werde. Bloß mit diesem einfachen Mittel reicht man aus, den Gliedmaßen größere oder geringere Leichtigkeit zu geben, da das Uebergewicht des Ausgebogenen Schwere, des Eingebogenen Leichtigkeit andeutet. Diese Grundsätze, welche sich alle auf die symbolische Bedeutung der Formen selbst stützen, sind aber keineswegs so zu verstehen, wie es von den sogenannten eleganten Malern geschieht, die durch das Bestreben, so viel möglich das Eckige, Winklichte zu vermeiden, in den Fehler der Nullität und der gänzlichen Flachheit fallen. So ist es zwar gegründet, daß man bei Figuren, deren Bestimmung ist reizend zu erscheinen, die Verkürzungen meiden muß, weil hier die Muskeln vielfach unterbrochen werden, indem die erhabenen Formen die eingebogenen verbergen. In diesem Fall bildet sich durch eine Art Abschnitt nothwendig ein Winkel. Ueberall also, wo der Charakter hart, der Ausdruck stark seyn soll, müssen diese Formen nicht gescheut werden, indem sonst die Sklaverei gegen das Angenehme den wahrhaft großen Styl verdrängt, der auf eine viel höhere Wahrheit geht als diejenige, die durch Sinnen schmeichelt. Alle Regeln, welche die Theoretiker über die *Formen * geben, haben bloß Werth, sofern diese Formen in der absoluten Beziehung, nämlich in ihrer symbolischen Qualität, gedacht werden. Es ist nicht zu leugnen, daß die gerade Linie auch für das Auge das Symbol der Härte, der Starrheit der Ausdehnung ist, die krumme der Biegsamkeit, die elliptische, horizontal gestellt, der Zartheit und Flüchtigkeit, die Wellenlinie des Lebens u.s.w. Ich komme zu der Hauptforderung, welche an die Zeichnung gemacht werden muß, die *Wahrheit*, welche hier freilich nicht viel sagen wollte, wenn man darunter nur die Wahrheit verstünde, inwiefern sie durch getreue Nachahmung der Natur erreicht werden kann. Der Künstler, welcher sie im wahren Sinn erreichen will, muß sie"}, {"type": "paragraph", "text": "noch viel tiefer suchen, als sie die Natur selbst angedeutet hat, und als die bloße Oberfläche der Gestalten zeigt. Er soll das Innere der Natur enthüllen, und also vorzüglich in Ansehung des würdigsten Gegenstandes, der menschlichen Gestalt, nicht bloß mit der gewöhnlichen Erscheinung sich begnügen, sondern die tiefer verborgene Wahrheit an die Oberfläche bringen. Er muß daher in den tiefsten Zusammenhang, das Spiel und die Schwingungen der Sehnen und Muskeln eindringen, und die menschliche Gestalt überhaupt nicht zeigen, wie sie erscheint, sondern wie sie in dem Entwurf und der Idee der Natur ist, welche keine wirkliche Gestalt vollkommen ausdrückt. Zu der Wahrheit der Gestalt gehört auch die Beobachtung des Verhältnisses der einzelnen Theile oder die Proportion, welche der Künstler wiederum nicht nach den zufälligen Erscheinungen der Wahrheit in der Wirklichkeit, sondern frei und dem Urbild seiner Anschauung gemäß hervorzubringen hat. Wir bemerken in der Natur überall Consequenz in Bildung der Theile, z.B. mit solchem Gesicht auch solche Füße und Hände übereinstimmend. Da die menschliche Gestalt zusammengesetzt ist, und die symbolische Bedeutung, die"}]}, {"page_pdf": 1706, "page_book": 526, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "das Ganze derselben hat, auf die einzelnen Theile vertheilt ist, so besteht die Hauptsache der Proportion darin, das gehörige Gleichgewicht der Theile so zu beobachten, daß jeder im Besonderen die Bedeutung des Ganzen soweit ausdrückt, als ihm zukommt. Hierbei kann der berühmte Torso des Herkules zum Beispiel dienen. \"Ich sehe, \"sagt Winkelmann1, \"in den mächtigen Umrissen dieses Leibes die unüberwundene Kraft des Besiegers der gewaltigen Riesen, die sich gegen die Götter empörten, und von ihm in den phlegräischen Feldern erlegt wurden, und zu gleicher Zeit stellen mir die sanften Züge dieser Umrisse, die das Gebäude des Leibes leicht und gelenksam machen, die geschwinden Wendungen desselben in dem Kampfe mit dem Achelous vor, der mit allen vielförmigen Verwandlungen seinen Händen nicht entgehen konnte. *In jedem Theile des Körpers offenbaret sich,* wie in einem Gemälde, *der ganze Held*"}, {"type": "footnote", "text": "1 Winkelmanns Werke, Ausg. von Fernow 1808, 1 Bd., S. 270."}, {"type": "paragraph", "text": "*in einer besonderen That*, und man siehet, so wie die richtigen Absichten in dem vernünftigen Baue eines Pallastes, *hier *den Gebrauch, zu welchem, und zu welcher That ein jeder Theil gedient hat. \"Winkelmann spricht in dieser Stelle das höchste Geheimniß der zeichnenden Künste aus. Es ist das: erstens das Ganze der Darstellung *symbolisch*, also nicht als den Gegenstand eines Moments empirisch, sondern in der Ganzheit seines Daseyns zu fassen, und so die einzelnen Theile des Leibs wieder als Repräsentanten der einzelnen Momente dieses Daseyns zu gebrauchen. Wie das Leben eines Menschen in der Idee eines ist und alle seine Thaten und Handlungen zumal angeschaut werden, so soll das Gemälde, welches den Gegenstand, indem es ihn aus der Zeit heraus nimmt, in seiner Absolutheit darzustellen hat, das Unendliche seines Begriffs und seiner Bedeutung ganz durch die Endlichkeit erschöpfen, und im Theil das Ganze, wie alle Theile wieder in der Einheit des Ganzen darstellen. Die letzte und höchste Forderung an die Zeichnung ist endlich, daß sie nur das Schöne, das Nothwendige, das Wesentliche auffasse, das Zufällige und Ueberflüssige aber vermeide. Die größte Kraft also wird sie in der menschlichen Figur in die wesentlichen Theile legen; sie wird die Knochen sich mehr zeigen lassen als die kleinen Falten des Fleisches, die Sehnen der Muskeln mehr als das Fleisch, die wirkenden Muskeln mehr als diejenigen, welche in Ruhe sind. Außer denjenigen Dingen, welche die Schönheit unmittelbar vernichten, wie das an sich Widrige, gibt es Dinge, die, ohne an sich häßlich zu seyn, die Schönheit verderben, und das Vorzüglichste unter diesen ist Darstellung des Ueberflüssigen, namentlich in dem, was ganz accidentell, z.B. der Umgebung, die mit einer Handlung zugleich vorgestellt werden soll. Z.B. in einem historischen Gemälde darf die Architektur u.s.w. nicht so fleißig als die Hauptfiguren ausgeführt seyn, indem es nothwendig ist, daß die Betrachtung von dem Wesentlichen dadurch abgelenkt wird. In näherer Beziehung mit dem Gegenstand steht die Bekleidung, die durchaus nur in der Identität mit dem Wesentlichen ist, nämlich der Gestalt, die sie bald zu verhüllen, bald durchscheinen zu lassen, bald zu"}, {"type": "paragraph", "text": "heben, bestimmt ist; wenn aber die Kleidung etwa zum Zweck gemacht wird, so kann man in denselben Fall kommen, wie jener Maler, der von dem Apelles, den er um sein Urtheil wegen eines Gemäldes der Helena, das er verfertigt, gefragt hatte, zur Antwort bekam: Weil du sie nicht schön zu machen wußtest, hast du sie wenigstens reich machen wollen. Noch näher an das Wesentliche sich anschließend, aber"}]}, {"page_pdf": 1707, "page_book": 528, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "insofern nur noch störender für Darstellung desselben, ist die Beobachtung der Kleinigkeiten der Gestalt, der Haut, der Haare u.s.w. Von dieser Art sind vorzüglich die Arbeiten einiger niederländischer Meister. Sie sind wie für den Geruch gearbeitet, denn man muß, um dasjenige, wodurch sie gefallen wollen, zu erkennen, sie dem Gesichte so nahe bringen als Blumen. Ihre Sorgfalt ging auf strenge Nachahmung des Allerkleinsten, sie scheuten sich das geringste Häärchen anders zu legen, als man es fand, um dem schärfsten Auge, ja wenn es möglich gewesen wäre, selbst den Vergrößerungsgläsern das Unmerklichste in der Natur, alle Poren der Haut, alle Nuancen der Barthaare vorzulegen. Eine solche Kunstfertigkeit könnte etwa zu Insektenmalerei zuträglich und dem Physiker oder Naturbeschreiber erwünscht seyn. In dem Verhältniß, wie in der Zeichnung von dem Zufälligen abgesehen und nur das Wesentliche dargestellt wird, nähert sie sich dem Idealischen; denn die Idee ist die Nothwendigkeit und Absolutheit eines Dings. Man kann allgemein sagen, daß mit der Entfernung dessen, was nicht zum Wesen gehört, von selbst die Schönheit hervortrete, da die Schönheit das schlechthin Erste, die Substanz und das Wesen der Dinge ist, dessen Erscheinung nur durch die empirischen Bedingungen gestört ist. Die bildende Kunst hat aber überall den Gegenstand nicht in seiner empirischen, sondern in seiner absoluten Wahrheit, befreit von den Bedingungen der Zeit, in seinem *An-sich* darzustellen. Gewöhnlich wird zu der Zeichnung auch noch der Ausdruck und die Composition gerechnet. *Ausdruck *ist überhaupt Darstellung des Inneren durch das Aeußere. Allein man sieht deutlich, daß diese zwei Seiten hat, die der Invention und die der Ausführung; bloß die letzte gehört der Zeichnung an. Wenn die Frage ist, *welche *Art des"}, {"type": "paragraph", "text": "Ausdrucks in den Gegenstand gelegt werden soll, so kann dieß nur in der höheren Untersuchung über das Poetische der Malerei beantwortet werden - eine Untersuchung, die hier noch nicht angestellt werden kann, da bloß von den technischen Bedingungen der Kunst (soweit diese von absoluter Bedeutung) die Rede ist. Was die *Composition *betrifft, so versteht man darunter entweder die poetische Zusammensetzung des Gemäldes, von der hier auch nicht die Rede seyn kann, oder die technische. In diesem Fall wird das Hauptbestreben der Zeichnung seyn müssen, *dem Raum in dem Gemälde an und für sich eine Bedeutung zu geben*, und ihn zur Wohlgefälligkeit, Anmuth und Schönheit des Ganzen zu gebrauchen. In dieser Beziehung würden die zwei Hauptbestandtheile der Kunst eines Gemäldes die Symmetrie und die Gruppirung seyn. *Symmetrie *bezieht sich vorzüglich auf die zwei Hälften eines Gemäldes. Die Identität ist das Herrschende der Malerei. Es hebt die Identität auf, wenn z.B. die eine Seite des Gemäldes mit Figuren angefüllt, die andere dagegen verhältnißmäßig leer gelassen ist; es ist ein gestörtes Gleichgewicht der Symmetrie. Diese Art von Gleichgewicht ohne wirklichen Gegensatz ist eine bleibende Norm aller Hervorbringungen der Natur. Aller Gegensatz ist im Individuum vertilgt; es findet keine wahre Polarität mehr statt, aber Gleichgewicht, z.B. in der Doppelheit der vorzüglichsten Gliedmaßen. Wo aber zwei Seiten sind, ist auch eine Mitte, und die Mitte des Gemäldes ist der Punkt derselben, in welchen nothwendig das Wesentliche desselben fällt. Es ist aber schon bemerkt worden, daß die bildende Kunst, vorzüglich inwiefern sie das Lebendige darstellt, ebenso wie die Natur, in den organischen Hervorbringungen das geometrisch Regelmäßige meidet. Dieß tritt erst ein, wo sie über die Grenzen des Organischen hinaus ist. Aus diesem Grunde ist die Regel keineswegs, daß die Hauptfigur in die wahre Mitte des Gemäldes - den Durchschnittspunkt der beiden Diagonalen - falle, sondern vielmehr, daß sie etwas weniges nach der einen oder andern Seite falle. Die Symmetrie ist eben deßwegen auch nicht in der vollkommenen geometrischen Gleichheit der beiden"}]}, {"page_pdf": 1708, "page_book": 530, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Hälften, sondern mehr in einem relativen und inneren Gleichgewicht beider zu suchen. Die *Gruppirung *ist schon eine höhere Synthese. Die Vereinigung der Theile zu einem organischen Leib ist nur uneigentlich Gruppirung, eigentlich aber ist Gruppirung nur Zusammenseyn von Theilen, deren jeder für sich unabhängig, ein selbständiges Ganzes und doch zugleich Glied des höheren Ganzen. Dieß ist das höchste Verhältniß der Dinge, von seiner Beobachtung im Gemälde also ein großer Theil seiner Vortrefflichkeit abhängig. Das Anordnen der Figuren in einzelne Gruppen bringt die Klarheit, Einfalt in der Auffassung hervor. Es setzt das Auge vorläufig in Ruhe, indem es nicht gezwungen ist die Figuren erst zusammenzusetzen, und in der Synthesis derselben nicht erst eine Wahl zu üben hat. Da die beste Form der Gruppirung die Triplicität ist, so wird die größte Mannichfaltigkeit der Figuren durch sie auf drei Einheiten zurückgebracht, so daß in der ersten Betrachtung die Gruppe als einzelne Figur angesehen werden kann, und so das *Ganze *auch in der Betrachtung den Theilen vorhergeht, wie es ihnen in der Hervorbringung vorangehen muß. Noch wichtiger ist die Gruppirung in der Rücksicht, daß sie in Ansehung des Einzelnen seine Selbständigkeit und seine Abhängigkeit vom Ganzen und den Rang, den es darin hat, zugleich ausdrückt. Der Künstler spricht dadurch seine Absicht vollständig aus, indem er nicht zweifelhaft läßt, welche Wichtigkeit er dem einzelnen Theil gegeben habe. Endlich ist die letzte, aber auch am schwersten zu erreichende Absicht der Gruppirung die Synthese des Gegenstandes mit dem Raum. Da die Mannichfaltigkeit in der Gruppirung vorzüglich nur durch die verschiedene Größe der Gegenstände, die sie entweder durch ihre natürliche Gestalt oder ihre Stellung haben, möglich ist, so ist die pyramidalische Form diejenige, welche alle Vortheile am vorzüglichsten vereinigt. Obgleich sie in der Antike mehr oder weniger angedeutet ist, so ist doch ihr vorzüglichster Erfinder Correggio, der sie auch in der Art gebraucht, daß einzelne Gruppen, jede für sich betrachtet, und das Ganze wieder dieser Form gleicht."}, {"type": "paragraph", "text": "Die Bedeutung der Zahlen ist auch in der Zusammensetzung der Gruppen unverkennbar. Obgleich man die Freiheit hat, sie aus geraden und ungeraden Zahlen zusammenzusetzen, so sind doch die doppelt geraden, z.B. 4, 8, 12 etc., davon ausgeschlossen, und nur die aus ungeraden zusammengesetzten, z.B. 6, 10, 14 etc., erträglich, obgleich die ungeraden immer die vorzüglicheren sind. Sonst wird noch als Regel der Gruppirung aufgestellt, daß die Gruppe die verhältnißmäßige *Tiefe* habe, daß also die Figuren nicht nach einer Reihe gestellt seyen, oder wenigstens nicht die äußersten Theile, wie die Köpfe, einander in geraden, horizontalen, senkrechten oder schiefen Linien begegnen. Allein diese Regel hat ihre vornehmste Beziehung auf die Spiele und Zufälligkeiten des Helldunkels, um nämlich diese desto leichter hervorbringen zu können. In der Zeichnung an und für sich, welche die reale Form der Kunst ist und nicht auf Illusion geht, ist diese Regel sehr untergeordnet (Beispiele der Alten, Raphaels). Zur Anschauung jeder dieser besondern Formen will ich nun dasjenige Individuum herausnehmen, welches am ausgezeichnetsten darin. Wenn man von Zeichnung rein als solcher sprechen will, so muß man *Michel Angelo *nennen. Er bewies seine tiefe Kenntniß schon in einem der frühesten Werke, einem Carton, den man nur noch durch Benvenuto kennt (Beschreibung eines Ueberfalls nackter Krieger im Arno). Michel Angelos Styl ist groß, ja schrecklich durch seine Wahrheit. Der Tiefsinn eines reichen und durchaus unabhängigen Geistes, die stolze Zuversicht auf sich selbst, der verschlossene Ernst der Gemüthsart, Hang zur Einsamkeit sind in seinen Werken abgedrückt; ebenso bezeugen sie sein tiefes Studium der Anatomie, dem er zwölf Jahre lang oblag, und das er immer wieder bis ins hohe Alter vornahm, wodurch er in den verborgensten Mechanismus des menschlichen Körpers eindrang. Seine Gestalten sind nicht zarte, weichliche, sondern"}]}, {"page_pdf": 1709, "page_book": 531, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "kräftige, starke und trotzige Gestalten (wie bei Dante). Beispiel: sein jüngstes Gericht. So viel also von der Zeichnung als der realen Form innerhalb der Malerei als der idealen Kunst."}, {"type": "paragraph", "text": "Die *ganz ideale *Form der Malerei ist das *Helldunkel.* Damit ergreift die Kunst den ganzen Schein des Körperlichen, und stellt ihn, abgehoben von dem Stoffe, als Schein und für sich dar. Das Helldunkel macht den Körper als Körper erscheinen, weil Licht und Schatten uns von der Dichtigkeit belehrt. Das natürlichste Beispiel ist die Kugel; um aber Kunstwirkungen hervorzubringen, muß sie in *Flächen *verwandelt werden, damit die Theile der Schatten- und Lichtseite sich mehr in sich selbst absondern. Am vollkommensten wird es durch den Cubus vorgestellt, von dessen drei gesehenen Seiten die eine das Licht, die andere die Mitteltinte und die dritte den Schatten abgesondert und nebeneinander, also flächenhaft, vorstellt. Schon aus diesem einfachsten Beispiel erhellt, daß das Helldunkel nicht allein in schwarz und weiß besteht, sondern daß die Wirkung desselben auch durch hellere und dunklere Farben erreichbar ist. Allein auch dieß ist noch nicht zureichend einen vollständigen Begriff davon zu geben, da es eben der *Gebrauch *dieser Farben ist, der das Helldunkel macht. Ich will nur einiges vom *natürlichen *Helldunkel anführen, d.h. von dem, was schon die bloße Anschauung der natürlichen Körper vom Helldunkel lehrt. Vom Unterschied der *Fläche *und *Tiefe *urtheilt unser Auge schon einfach dadurch, daß von einer Oberfläche die erhabenen Theile das Licht auf ganz andere Art, nämlich unter einem anderen Winkel, zurückzuwerfen scheinen als die flachen und tiefen Theile. Wenn also das Auge schnell einem großen auf einen kleinen Winkel oder umgekehrt fortgeleitet wird, so wird der Gegenstand als unterbrochen oder abgeschnitten, und jene unmerkbare Gradation von Licht und Schatten, welche das Helldunkel macht, würde zerstört erscheinen. Es ist die Wirkung des natürlichen Helldunkels, daß es in der Natur fast keinen vollkommenen Winkel gibt, und die meisten Winkel kleine krumme Linien sind, die sich in zwei sich ausbreitende Linien verlieren. Es ist die Wirkung des natürlichen Helldunkels, daß der Contur der Körper selten mit einer wirklich lichten, sondern mit einer Mittelfarbe erscheint, denn wäre der Contur in hohem Grade erleuchtet, so würde damit die"}, {"type": "paragraph", "text": "Hellung des Gegenstandes selbst vernichtet. Ein allgemeines Gesetz auch des natürlichen Helldunkels ist, daß helle und dunkle Farben nicht unberührt und ohne Wirkung aufeinander nebeneinander stehen, daß eins das andere wirklich erhöht und mäßiget - vergrößert sogar (expandirt und contrahirt). Die am meisten magische Wirkung des Helldunkels entsteht durch die Reflexe, indem der Schatten, welcher im Reflex eines hellen Körpers liegt, weder ganz Schatten noch wahrhaft erleuchtet ist, und hinwiederum ein durch seine Localfarbe heller Körper durch den Schatten, den ein anderer auf ihn wirft, wiederum ganz verschieden afficirt wird; z.B. er sey weiß oder gelb, nun fällt ein Schatten auf ihn, aber jetzt ist er weder das eine noch das andere. Einer der vornehmsten Theile des Helldunkels ist die *Luftperspektive.* Sie unterscheidet sich von der Linienperspektive dadurch, daß diese bloß lehrt, wie ein Bild sich aus einem angenommenen Standpunkt darstellt, jene aber den Grad der Lichter in Proportion der Entfernung. Je entfernter ein Körper ist, desto mehr verliert seine Farbe an Lebhaftigkeit; die kleineren Abstufungen der Tinten und Schatten in ihm selbst verlieren sich, so daß er nicht nur einfärbig, sondern, weil alle sichtbare Erhabenheit auf dem Helldunkel beruht, flach wird (alles Relief verliert sich); in der letzten Entfernung aber verliert sich seine natürliche Farbe ganz, und alle noch so verschiedenfarbigen Gegenstände nehmen die allgemeine"}]}, {"page_pdf": 1710, "page_book": 533, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Luftfarbe an. Die Verminderung des Helldunkels mit der Entfernung geschieht nach bestimmten Gesetzen. Wenn z.B. unter mehreren perspektivisch gestellten Figuren von der ersten zur zweiten ein Grad des Unterschieds ist, so wird dieser schon von der zweiten zur dritten geringer seyn, wie die Verminderung der Größe auch in der Linienperspektive in immer geringerem Verhältniß geschieht mit der größeren Entfernung. Ein Gegenstand, der mir nahe ist, ist in der Stärke des Helldunkels allerdings sehr verschieden von einem, der etwa eine oder mehrere Stunden weit entfernt ist. Wenn ich aber einen dritten Gegenstand, der noch eine oder mehrere Stunden entfernter ist als der zweite, mit diesem vergleiche, so wird der Unterschied in Ansehung dieser beiden fast unmerklich seyn, so daß also"}, {"type": "paragraph", "text": "die Abnahme des Helldunkels mit der Entfernung nicht gleichen Schritt hält. Ich glaube, daß dieß hinreichend ist, sich einen Begriff des Helldunkels, dessen successive Verminderung durch die Entfernung die Luftperspektive lehrt, zu machen. Alle diese Gegenstände aber müssen das tiefste Studium des Künstlers seyn. Die Anschauung muß in diesen Dingen die Hauptsache thun, und ohne selbige reicht auch die deutlichste Beschreibung nicht hin, einen angemessenen Begriff dieser Sache zu geben. - Ich habe nun erst von der *Bedeutung *des Helldunkels in der Kunst zu reden. Das Helldunkel ist der eigentlich magische Theil der Malerei, indem es den Schein aufs höchste treibt. Durch das Helldunkel lassen sich nicht nur erhabene, frei voneinander abstehende Figuren, zwischen denen das Auge sich ohne Widerstand hin- und herbewegt, sondern auch alle möglichen Effekte des Lichts hervorbringen. Durch die Künste des Helldunkels ist es sogar möglich geworden, die Bilder *ganz* selbständig zu machen, nämlich die Quelle des Lichts in sie selbst zu versetzen, wie in jenem berühmten Gemälde des Correggio, wo ein unsterbliches Licht, von dem Kinde ausgehend, die dunkle Nacht mystisch und geheimnißvoll erleuchtet. Bis zu dieser Höhe der Kunst reicht keine Regel, sondern nur eine für die zarteste Empfindung des Lichts und der Farben geschaffene Seele, eine Seele, die gleichsam selbst Licht ist, in deren inneren Anschauungen alles Widerstrebende, Widrige, Harte der Formen sich verschmilzt. Die Dinge, als besondere, können im Gegensatz der absoluten Idealität nur als Negationen erscheinen. Der Zauber der Malerei besteht aber darin, die Negation als Realität, Dunkel als hell, und dagegen die Realität in der Negation, das Helle als dunkel erscheinen und durch die Unendlichkeit der Abstufungen das eine so in das andere übergehen zu lassen, daß sie in der Wirkung unterscheidbar bleiben, ohne in sich selbst unterschieden zu seyn. Der Stoff des Malers, gleichsam der Leib, an dem er die flüchtigste Seele des Lichtes fasset, ist das Dunkel, und selbst das Mechanische der Kunst treibt ihn dazu, da die Schwärzen, deren er sich"}, {"type": "paragraph", "text": "bedienen kann, den Wirkungen der Finsterniß weit näher kommen als das Weiß denen des Lichts. Schon Leonardo da Vinci, der Vorläufer des himmlischen Genies Correggio sagt: Maler, wenn du den Glanz des Ruhmes begehrst, fürchte die Dunkelheit der Schatten nicht. Jene Identität, zu welcher Licht und Dunkel verschmolzen werden sollen, daß sie Ein Leib und Eine Seele sind, fordert von selbst schon, daß sie zu großen Massen vereinigt, wie aus Einem Guß seyen. Diese identische und nur in sich selbst sich abstufende Masse verleiht dem Ganzen den Ausdruck tiefer Ruhe, und setzt das Auge, wie den inneren Sinn, welchen weder das Licht allein noch das Dunkel allein befriedigt, in jenen Zustand der aus der Differenz hergestellten Indifferenz, welcher die eigentlichste und wahrste Wirkung aller Kunst seyn muß. Soll für die Anschauung der höchste Gipfel in Erreichung der Kunst des Helldunkels bezeichnet"}]}, {"page_pdf": 1711, "page_book": 535, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "werden, so ist dieß nur durch *Correggio *möglich. Ich habe schon des faden Vorurtheiles erwähnt, welches diesen Künstler in der Zeichnung heruntersetzt. Wenn man dieß von den Gegenständen seiner Zeichnung versteht, so ist es richtig, daß er nicht die einfachen Formen der Alten gewählt hat: in ihm ist das eigentlich romantische Princip der Malerei ausgesprochen, in ihm herrscht für seine Kunst durchaus das Ideale, da in der Kunst der Alten, in der Plastik, und sicher ebenso in der Malerei, das Reale herrschend war. Ist die Rede davon, daß er nicht wie Michel Angelo in die Tiefen der Zeichnung gedrungen, das Innere des Organismus wie dieser entwickelt dargestellt, und im Nackten ebenso kühn gewesen als Michel Angelo, so ist auch dieß gegründet. Aber in keinem seiner Originalwerke ist etwas, das der wahren Zeichnung widerspräche. Dieß ist selbst das Urtheil von Mengs, obgleich er Correggio übrigens als Gegensatz betrachtete, und selbst den Eklektiker in der Kunst machte. An und für sich schon ist das Helldunkel von der Zeichnung unzertrennlich, denn Zeichnung ohne Licht und Schatten kann niemals die wahre Gestalt eines Dings ausdrücken. Dabei mag es nun immer unentschieden bleiben, ob das tiefe Studium des Helldunkels den"}, {"type": "paragraph", "text": "Correggio auch die Vollkommenheit der Formen gelehrt habe, die in seinen Werken bewundert wird, ob *dieses *ihn gelehrt habe, daß das Gebäude der menschlichen Gestalt weder in rein geraden Linien noch in *Abwechslungen *von krummen und geraden Linien, sondern in abwechselnden Krümmungen bestehe, oder ob er umgekehrt durch Zeichnung, tiefe Kenntniß und genaue Nachahmung der Wahrheit in die Geheimnisse des Helldunkels eingedrungen sey. Genug, er vereinigte diese beiden Formen der Kunst ebenso in seinen Werken, wie sie in der Natur selbst verbunden sind. Aber Correggio hat das Höchste im Helldunkel nicht nur von Seiten der Formen und der Körperlichkeiten überhaupt, sondern auch in dem allgemeineren Theile erreicht, der in der Vertheilung der Lichter und Schatten besteht. Kraft der ihm einzig eignen Verschmelzung und Abstufung ist, wie das Licht jeder einzelnen Figur, so das Licht des ganzen Bildes bei ihm Ein Licht. Ebenso die Schatten. Wie uns die Natur niemals verschiedene Gegenstände mit einem und demselben Nachdruck von Seiten des Lichts zeigt, und die verschiedenen Lagen und Wendungen der Körper verschiedenes Licht hervorbringen, so hat Correggio im Inneren seiner Bilder und in der größten Identität des Ganzen doch die größtmögliche Mannichfaltigkeit der Beleuchtung angebracht und niemals dieselbe Stärke, es sey im Licht oder Schatten, wiederholt. In dem schon oben bemerkten Fall, wo ein Körper durch seinen Schatten das Licht eines andern verändert, ist es nicht gleichgültig, welche besondere Farbe der schattende Körper hat: auch dieß findet sich mit der größten Ueberlegung in den Werken des Correggio beobachtet. Außer diesen Theilen des Helldunkels übte er vorzüglich die Kenntniß seiner Verminderung so wie der der Farben durch die Entfernung, d.h. die Luftperspektive, und er kann auch hiervon als der erste Schöpfer in der Kunst selbst betrachtet werden, obgleich der tiefsinnige Leonardo da Vinci die ersten Gründe der Theorie vor ihm enthüllt hatte, und die vollkommene Ausbildung der Luftperspektive erst dadurch möglich war, daß sie unabhängig von den übrigen Theilen, vorzüglich der Zeichnung, in der Landschaftsmalerei behandelt wurde,"}, {"type": "paragraph", "text": "in welcher Beziehung man sagen kann, daß Tizian den ersten Grund derselben gelegt habe. - Wir haben noch von der Nothwendigkeit des Helldunkels als der Einen Form der Malerei und den Grenzen dieser Nothwendigkeit zu reden. Daß das Helldunkel die einzig mögliche Art sey, selbst ohne Farbengebung, in der Zeichnung, den"}]}, {"page_pdf": 1712, "page_book": 537, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Schein des Körperlichen zu erreichen, lehrt jeden die unmittelbare Anschauung. Dieß verhindert aber nicht, daß diese Form mehr oder weniger unabhängig behandelt, und die Wahrheit mehr dem Schein oder der Schein der Wahrheit untergeordnet werden könne. Die Meinung ist diese: die Malerei ist die Kunst, in der Schein und Wahrheit eins, der Schein Wahrheit und die Wahrheit Schein seyn muß. Aber man kann den Schein entweder nur wollen, soweit er vermöge der Natur dieser Kunst zur Wahrheit erforderlich ist, oder man kann ihn um seiner selbst willen lieben. Niemals zwar wird es in der Malerei einen Schein geben können, der nicht zugleich Wahrheit wäre; was nicht Wahrheit ist, ist hier auch nicht Schein; aber es kann entweder die Wahrheit als Bedingung des Scheins oder der Schein als Bedingung der Wahrheit dargestellt und eins dem andern untergeordnet werden. Dieß wird zwei ganz verschiedene Arten des Styls geben. Correggio, den wir eben als Meister des Helldunkels aufgestellt haben, hat den der ersten Art. In seiner Kunst ist durchgängig die tiefste Wahrheit, aber der Schein ist als das Erste behandelt, oder der Schein gilt weiter, als zur Wahrheit an und für sich erforderlich ist. Wir können uns auch hier wieder nicht besser als durch das Verhältniß des Antiken und Modernen erläutern. Jenes geht auf das Nothwendige, und nimmt das Ideale nur soweit auf, als es zu diesem erforderlich ist, dieses macht das Ideale selbst zu einem Selbständigen und Nothwendigen; es geht damit nicht über die Grenze der Kunst, aber es geht in eine andere Sphäre derselben. Es existirt keine absolute Forderung in der Kunst, daß *Täuschung *sey, welche eintritt, sowie der Schein weiter aufgenommen wird als zu der Wahrheit *an und für sich selbst*, wenn er also bis zur *empirischen*,"}, {"type": "paragraph", "text": "sinnlichen Wahrheit aufgenommen wird. Es gibt keinen kategorischen Imperativ der Illusion. Aber es existirt auch keiner dagegen. Schon dieß, daß die Kunst in der Hervorbringung der Täuschung oder des Scheins bis zur empirischen Wahrheit frei ist, beweist, daß sie hierin über die Grenze der strengen Gesetzmäßigkeit schreitet - in das Reich der Freiheit, der Individualität, wo das Individuum sich selbst Gesetz wird. Dieß ist allgemein die Sphäre des Modernen, und deßwegen Correggio als der erste in dieser zu setzen. Der Styl in dieser Sphäre ist der Styl der Grazie, der Anmuth, für welche keine kategorische Forderung existirt, obgleich sie nie *überflüssig *ist. Ebenso ist er beschränkt auf gewisse Sujets, daher nur an Correggio schön. Der Styl der andern Art ist der hohe, strenge Styl, weil es für diesen eine absolute Forderung gibt, und der Schein ihm nur Bedingung der Wahrheit ist. Hieraus erhellt, daß eine sehr hohe, ja in ihrer Sphäre absolute Art der Kunst in der Malerei ohne den Gebrauch des Helldunkels ist (außer inwiefern es zur Wahrheit, nicht aber zur Täuschung erforderlich). Von dieser Art war ohne Zweifel der erste Styl der alten Malerei im Vergleich mit dem des Parrhasius und Apelles, welcher vorzugsweise der Maler der Grazie hieß. Von dieser Art ist in der neueren Zeit der Styl nicht nur des Michel Angelo, sondern auch des Raphael, dessen streng angegebene Formen vielen gegen die Weichheit der Umrisse und die rundlich sanften Formen des Correggio hart und steif geschienen haben, wie etwa, nach Winkelmanns Vergleichung, der Pindarische Rhythmus oder die Strenge des Lucretius gegen die Horazische Lieblichkeit und die Weichheit des Tibullus rauh oder vernächlässigt klingen mag. Dieses sage ich nicht zum Nachtheil des Correggio; er ist der erste und einzige in seiner Sphäre (ja dieser göttliche Mensch ist eigentlich der Maler aller Maler), wie Michel Angelo in der seinigen, der Zeichnung, obgleich das höchste und wahrhaft absolute Wesen der Kunst nur in dem Raphael erschienen. - Es ist nothwendig und gegründet in viel allgemeineren Ansichten, daß jede der besonderen Formen wieder in sich absolut, sich für sich zu einer Welt ausbilden könne, wie dieß auch historisch nach dem, was wir noch ferner finden werden,"}]}, {"page_pdf": 1713, "page_book": 539, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der Fall. Nur kann keine in der Besonderheit sich zur Absolutheit ausbilden, ohne die andern zu begreifen, obgleich in einer Unterordnung im Ganzen. Es ist, wie wir in der Musik gesehen haben, daß diese ganze Kunst sich in die Harmonie wirft, die an sich nur Eine *Form* der Musik ist, obgleich sie in der Ausartung von dem Rhythmus sich sogar unabhängig gemacht hat. Aber in der Malerei tritt noch der besondere Fall ein, daß in ihr, als an sich idealer Kunst, nothwendigerweise das Ideale zur Herrschaft streben muß. Sieht man daher auf die Malerei in der Malerei, so ist diese das Helldunkel, und insofern, wenn auf dieselbe als besondere Kunst gesehen wird, ist, wie gesagt, Correggio der eigentliche Maler κατE dξοχήν. Wir haben uns schon oben dahin erklärt, daß die *empirische* Wahrheit die *letzte* Forderung in der Kunst sey, da diese ihrem ersten Beruf nach eine über die Sinne erhabene Wahrheit darzustellen hat. Wenn also das Helldunkel an sich eine nothwendige Form ist, ohne welche Malerei als Kunst überhaupt nicht gedacht werden kann, so kann dagegen die Luftperspektive, inwiefern sie auf eine empirische Wahrheit geht, nicht zu dem Wesentlichen der Kunst gerechnet werden; und anders als in der vollkommensten Unterordnung, wie von Correggio, gebraucht ist sie Mißbrauch. Die Abdämmerung der Farben in der Ferne beruht auf dem empirischen und demnach zufälligen Umstand, daß ein durchsichtiges, trübendes Medium zwischen uns und den Gegenständen liegt (die Linienperspektive, welche nicht auf die Farben sich bezieht, ist in allgemeinen Gesetzen des Raumes gegründet, und bezieht sich auf Größe, Figur, demnach allgemeine Bestimmungen der Körper); es ist allerdings richtig, daß ein Bild, in welchem die Luftperspektive beobachtet ist, uns weniger als ein anderes, worin nicht, daran erinnern wird, daß es ein Werk der Kunst ist, was wir anschauen; aber wenn man dieses Princip allgemein machen wollte, so würde überhaupt keine Kunst seyn, und da es nicht allgemein seyn kann, so kann Illusion, d.h. Identifikation der Wahrheit mit dem Schein bis zur sinnlichen Wahrheit, überhaupt nicht Zweck der Kunst seyn. Auch haben die Alten nach allem, was wir von ihnen wissen, die Luftperspektive"}, {"type": "paragraph", "text": "nicht beobachtet. Ebensowenig die Maler aus dem vierzehnten und fünfzehnten Jahrhundert, z.B. Pietro Perugino, Raphaels Lehrer, (Gemälde in Dresden). Auch in Raphaels Gemälden ist die Luftperspektive nur mäßig beobachtet. Das Helldunkel bezieht sich auf die Flächenwirkungen des allgemeinen Lichts, die den Schein des Körperlichen hervorbringen. Das Licht ist in dem Helldunkel noch immer das bloß *Beleuchtende * des Körpers, und macht bloß die *Wirkung *des Körpers, ohne er selbst wahrhaft zu seyn. Die *dritte *Form ist also, wie immer, so auch hier diejenige, welche die dritte Dimension bestimmt, oder das Licht verkörpert, Licht und Körper also als wahrhaft eins darstellt. Diese Form ist das *Colorit. *Das Colorit bezieht sich nicht auf das allgemeine, hellere oder dunklere, Licht des Ganzen; seine Grundlage sind die Localfarben der Gegenstände, obgleich, wie schon bei dem Helldunkel bemerkt wurde, diese auch wieder auf das allgemeine Licht zurückwirken und auf die Erscheinungen des Helldunkels einen bestimmenden Einfluß haben. Wir werden die Stufen, in welchen das Licht sich dem Körper vermählt, in der Folge noch genauer bestimmen müssen. Hier will ich eben deßhalb bloß das Allgemeine davon angeben. An den unorganischen Körpern, den *Mineralien*, finden sich großentheils noch die ursprünglichsten, einfachsten und reinsten Farben. Das allgemeinste Färbungsmittel der Natur scheinen die Metalle zu seyn; da aber, wo der Charakter der Metallität am vollkommensten verschwindet, geht sie zur völligen Durchsichtigkeit über. Eigenthümliches Colorit und lebendige Farbengebung erscheint erst an den Blüthen und manchen Früchten der *Pflanzen*, dann an den Federn der *Vögel*, welche selbst ein pflanzenartiges Gewächs sind, in den farbigen Bedeckungen der *Thiere *u.s.w. So einfach die Kunst des Colorits bei einfärbigen Körpern scheint, so schwierig ist doch die Hervorbringung desselben mit allen"}]}, {"page_pdf": 1714, "page_book": 540, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "möglichen Bestimmungen der Individualität, indem außer der Farbe auch noch die Affektionen z.B. der Mattheit und des Glanzes ausgedrückt seyn wollen."}, {"type": "paragraph", "text": "Die höchste Vermählung des Lichtes mit dem Stoffe, so daß das Wesen ganz Stoff und ganz Licht wird, geschieht in der Produktion des *Fleisches. *Das Fleisch ist das wahre Chaos aller Farben und eben deßhalb keiner besonderen ähnlich, sondern unauflöslichste und schönste Mischung aller. Aber auch diese ganz einzige Art der Farbe ist noch überdies nicht unbeweglich, wie die andern Arten der Farbe, sondern lebendig und beweglich. Die inneren Regungen des Zorns, der Scham, der Sehnsucht u.s.w. bewegen gleichsam jenes Farbenmeer, und lassen es in bald sanfteren, bald stärkeren Wellen schlagen1 . Dieses also ist die höchste Aufgabe des Colorits. (Ich erinnere hier Folgendes. Jede Kunstform entspricht selbst einer Dimension, und in jeder Kunstform ist dasjenige das Wesen, die Substanz, was ihrer Dimension am meisten entspricht. So fanden wir, daß in der Musik Rhythmus die eigentliche Substanz dieser Kunst ist, weil sie selbst der ersten Dimension untergeordnet ist. So wird es in der Malerei das Helldunkel seyn, und Colorit ist zwar die dritte Dimension, inwiefern darin Licht und Körper nicht bloß scheinbar, sondern wahrhaft eins sind, Helldunkel aber ist gleichwohl die Substanz der Malerei als solcher, weil diese selbst nur auf der zweiten Dimension beruht). Wer die Gemälde des *Tizian *gesehen hat, dessen, der in dieser Beziehung als der Erste zu nennen ist, hat von selbst die Einsicht und das Gefühl, daß eine vollkommenere Identification des Lichts und des Stoffes nicht denkbar sey, als er erreicht hat. Eine größere Ausbreitung hat die Kunst des Colorits in größeren Compositionen, wo seine höchste Vollendung *im Ganzen *das ist, was man Harmonie der Farben nennen kann. Die Forderung ist hier: nicht nur daß dem Einzelnen in Ansehung der Farbe sein Recht widerfahre, sondern daß auch das Ganze wieder einen harmonischen Eindruck mache und die Seele in der höchsten Lust, zwischen gestörtem und wiederhergestelltem Gleichgewicht, in Bewegung zugleich und Ruhe, gleichsam schwebend erhalte."}, {"type": "footnote", "text": "1 Man vergl. \"Diderots Versuch über die Malerei\" bei Goethe."}, {"type": "paragraph", "text": "Schon hieraus ist einzusehen, daß weder die bloße Art der Beleuchtung, noch die gleichförmige Dämpfung der Farben durch die Luft im Gemälde die Harmonie hervorbringe. Die Harmonie und harmonische Wirkung beruht keineswegs auf dem *Grad*, wie manche sich einbilden, sondern auf der *Art* und *Qualität *der Farben. Durch diese sind sie fähig, eine weit höhere Art der Uebereinstimmung hervorzubringen, als durch das Gleichgewicht, welches bloß auf Graden beruhte. Nur in der Qualität sind die höchsten Gegensätze, aber eben deßwegen auch die höchste Art der Identität möglich. Die Gründe der Harmonie müssen also in dem ursprünglichen System der Farben selbst und den Forderungen des Auges gesucht werden, von denen schon früher die Rede war. Das Licht ist der positive Pol der Schönheit und ein Ausfluß der ewigen Schönheit in der Natur. Aber es wird offenbar und erscheint nur im Kampf gegen die Nacht, welche, als der ewige Grund alles Daseyns, selbst nicht *ist*, obgleich sie durch ihre beständige Gegenwirkung sich als Macht beweist. Die Dinge, sofern sie der Nacht oder Schwere eignen, haben ein dreifaches Verhältniß zum Licht. Das erste, daß sie sich rein als Negationen von dem Licht abschneiden und als solche sich in ihm darstellen. Dieses"}]}, {"page_pdf": 1715, "page_book": 542, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "ist der allgemeine *Umriß. * Das andere, daß aus der Wirkung und Gegenwirkung von Licht und Schatten selbst der höhere * Schein der Körperlichkeit *producirt werde. Das Auge sieht eigentlich nicht die Körper, sondern nur ihren ideellen Entwurf im Licht, und so beruht schon die natürliche Erscheinung des Körpers durch das Licht auf dem Helldunkel. Das dritte Verhältniß ist das der absoluten Indifferenziirung der Materie und des Lichts, wo aber deßwegen in dem Stoff sich die *höchste Schönheit *entzündet, und das Unsterbliche sich ganz in das Sterbliche faßt. Diesen drei Verhältnissen entsprechen die drei nothwendigen Formen der Kunst, welche die Dinge nur im Licht und durch das Licht darstellt, die Zeichnung, welche nur die Negation, den Umriß bezeichnet, wodurch das Ding sich als Besonderes abhebt, das Helldunkel, welches den Körper *als solchen *dennoch im Lichte und demnach in der Identität zeigt, und endlich das"}, {"type": "paragraph", "text": "Colorit, welches in seiner höchsten Vollendung die Materie nicht nur oberflächlich, sondern ganz bis ins Innerste, in Licht, und das Licht in Materie verwandelt. Schon diese Verhältnisse der Form deuten auch die höheren Verhältnisse der Gegenstände an, welche die malerische Darstellung wählen kann. Die Malerei ist die erste Kunst, welche Gestalten und demnach auch wahre Gegenstände hat. Die Musik in ihrer höchsten Bedeutung drückt nur das Werden der Dinge, die ewige Einbildung der Einheit in die Vielheit aus. Die Malerei stellt schon gewordene Dinge dar. Eben deßhalb muß bei ihr vorzüglich von den *Gegenständen *die Rede seyn, denn der Gegenstand bezeichnet hier auch zugleich die Stufe der Kunst selbst. Alle Stufen lassen sich nach dem verschiedenen Verhältniß des Lichts zu den körperlichen Dingen bestimmen. Es gibt drei entgegengesetzte Kategorien oder Bestimmungen des Lichts in Bezug auf die Dinge. Es ist äußerlich, unbeweglich, unorganisch, oder es ist innerlich, beweglich, organisch. Zwischen diesen beiden Extremen liegen alle möglichen Verhältnisse des Lichts. Die tiefste Stufe ist die, wo ganz unorganische Gegenstände ohne inneres Leben, ohne bewegliche Farbe dargestellt werden. Es kann hier das malerische Princip sich höchstens in der Anordnung offenbaren, kraft welcher die Dinge, ohne eben in der Unordnung zu seyn, doch in einer angenehmen zufälligen Nachlässigkeit sich befinden, welche Gelegenheit gibt, sie in Verkürzungen, wechselseitig durch einander bedeckt, durch Schatten und gegenseitige Reflexe nuancirt darzustellen. Man nennt solche Darstellungen *Still-Leben*, und so untergeordnet sie sind, weiß ich doch nicht, ob man sie nicht als eine Art symbolischer Gemälde betrachten soll, da sie auf etwas Höheres hindeuten, indem sie die Spuren eines Handelns und Daseyns ausdrücken, welches nicht mit dargestellt ist. Wenigstens kann der einzige Reiz und das Poetische dieser Art von Bildern bloß darin bestehen, daß sie uns den Geist desjenigen ahnden läßt, der diese Anordnung gemacht hat."}, {"type": "paragraph", "text": "Eine Art von poetischem Still-Leben ist in einer Scene von Goethes Faust ausgedrückt, wo dieser auf Margarethens Zimmer ist und den Geist der Ordnung, der Zufriedenheit und die Fülle in der Armuth darin schildert. Die zweite Stufe der Darstellung wäre die von solchen Gegenständen, wo die Farbe äußerlich und zwar organisch, aber doch unbeweglich ist. Dieß die *Blumen- *und *Fruchtmalerei. *Es ist nicht zu leugnen, daß Blumen und Früchte in ihrer Frischheit lebendig sind, und daß mit ihnen eine concrete Malerei möglich ist. Allein von der andern Seite kann diese Art der Darstellung doch wieder nur im"}]}, {"page_pdf": 1716, "page_book": 544, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "allegorischen oder symbolischen Gebrauch einen Kunstwerth haben. Die Farben sind an sich symbolisch, ein natürlicher Instinkt hat sie zu Symbolen der Hoffnung, der Sehnsucht, der Liebe u.s.w. erhoben. Inwiefern Blumen diese Farben in natürlicher Einfachheit darstellen, sind sie an sich schon eines Charakters fähig, und in der Anordnung derselben kann ein einfältiges Gemüth sein ruhiges Inneres ausdrücken. Inwiefern es möglich wäre, in die Anordnung von Blumen so viel Bedeutendes zu legen, daß wirklich ein innerer Zustand darin erkennbar wäre, wäre diese Art von Bildern zur Allegorie geeignet. Die dritte Stufe wäre Darstellung der Farbe, sofern sie beweglich, organisch, aber doch bloß äußerlich ist. Dieß ist der Fall mit der *Thiermalerei. *Beweglich, theils inwiefern überhaupt lebendige Geschöpfe ein Vermögen der Selbstbewegung und der Veränderung in sich haben, theils inwiefern die unbedeckten Theile der Thiere, z.B. das Auge, wirklich ein bewegliches lebendiges Feuer haben. Allein dabei bleibt die Farbe doch immer noch eine äußerliche, weil an den Thieren das Fleisch als solches nicht erscheint, und die Darstellung also sich auf die Abbildung ihrer farbigen Bedeckungen, ihrer Bewegungen, und bei den gewaltigeren Naturen unter den Thieren auf Abbildung des Funkelns ihrer Augen und des darin ausgedrückten Zustandes sich beschränken muß. Die thierische Natur überhaupt und einzelne thierische Leiber sind an sich von symbolischer Bedeutung, die Natur selbst wird in ihnen"}, {"type": "paragraph", "text": "symbolisch. Thierstücke können also nur entweder durch das Herausheben der symbolischen Bedeutung der Gestalten durch *kräftige *Darstellung oder nur durch eine höhere Beziehung einigen Kunstwerth haben. Einige holländische Maler sind bis zu Darstellung von Hühnerhöfen heruntergegangen. Wenn eine solche Schilderei noch eingigermaßen tolerirt wird, so ist es, weil auch ein Hühnerhof auf das Innere eines Hauses, die Armuth oder den Reichthum des Besitzers kann schließen lassen. Höhere Beziehung und Bedeutung erhalten Thierstücke, wo Thiere wirklich in Handlung und im Kampf entweder untereinander oder mit Menschen dargestellt werden. Die tiefste Note des historischen Gemäldes bezeichnen die *Jagdstücke.* Die folgende Kunststufe ist die, wo das Licht äußerlich unorganisch, aber beweglich, und insofern lebendig ist. Diese die *Landschaftsmalerei.* In dieser Gattung wird außer dem Gegenstand, dem Körper, das Licht selbst als solches zum Gegenstand. Diese Gattung bedarf nicht nur des Raums zu ihrem Gemälde, sondern sie geht ausdrücklich sogar auf Darstellung des Raums als solchen aus. Die Gegenstände der zuvor genannten Gattungen sind, so untergeordnet sie in anderer Rücksicht seyn mögen, doch an und für sich selbst bedeutend; von ihnen ist eine wahrhaft objektive Darstellung möglich. In der Landschaftsmalerei ist überall nur subjektive Darstellung möglich, denn die Landschaft hat nur im Auge des Betrachters Realität. Die Landschaftsmalerei geht nothwendig auf die empirische Wahrheit, und das Höchste, was sie vermag, ist, *diese *selbst wieder als eine Hülle zu gebrauchen, durch die sie eine höhere Art der Wahrheit durchscheinen läßt. Aber eben nur die Hülle wird dargestellt, der wahre Gegenstand, die Idee, bleibt gestaltlos, und es ist von dem Betrachter abhängig gemacht, sie aus dem duftigen und formlosen Wesen herauszufinden. Es ist nicht zu leugnen, daß Verhältnisse des allgemeinen Lichts zu einem ausgebreiteten Ganzen von Gegenständen, je nachdem es offenbarer oder verhüllter, stärker und unterschiedener, oder schwächer und gleichsam schwimmender über der Natur liegt, gewisse Zustände der Seele hervorrufen, auf eine indirekte Weise Ideen, oder vielmehr nur"}, {"type": "paragraph", "text": "Geister von Ideen wecken, und nicht selten vor unsern Augen den *Schleier *hinwegheben, der uns die"}]}, {"page_pdf": 1717, "page_book": 546, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "unsichtbare Welt bedeckt. Allein alle Anschauung dieser Art fällt ins Subjekt zurück. Wir sehen, daß je dürftiger die Poesie einer Nation, sie desto mehr sich zu diesem formlosen Wesen hinneigt. Welche Gelegenheit in Homer, Landschaften zu schildern und doch keine Spur davon! Dagegen sind die Gesänge des Ossian voll von Schildereien der Nebelwelt und der formlosen Natur, die ihn umgab. Die Schönheit einer Landschaft hängt von so vielen Zufälligkeiten ab, daß es schwer, ja unmöglich ist, ihr in der Kunst diejenige Nothwendigkeit zu geben, welche z.B. jede organische Gestalt in sich trägt. Es sind nicht innere, sondern äußere und gewaltsame Ursachen, welche die Form, den Abhang der Berge und die Schweifungen der Thäler bestimmen. Gesetzt ein Künstler besitze so tiefe Kenntniß der Erde, daß er in der Landschaft selbst, die er vor uns ausgebreitet darstellt, uns zugleich die Gründe und Gesetze ihrer Bildung, den Lauf des Flusses, der die Berge und Thäler formirt, oder die Gewalt des unterirdischen Feuers darzustellen weiß, welches zugleich die Zerstörung und die Ströme der Ueppigkeit über eine Gegend ausgießt, gesetzt, er wisse dieß alles darzustellen, so bleibt doch selbst der Moment des Lichts, den er wählt, der Grad der Erleuchtung oder Dämpfung, der auf dem Ganzen liegt, eine Zufälligkeit, und da es eigentlich *diese *ist, die er darstellt und zum Gegenstand macht (da sie in den andern Gattungen ausdrücklich nur als Accidens des Gegenstandes erscheint), da er also überhaupt das, was bloß zum Schein gehört, als unabhängig behandelt und selbständig darstellt, so ist er dadurch einer nicht zu überwindenden Zufälligkeit unterworfen, und er kehrt in der Malerei selbst gewissermaßen zu der tieferen Stufe, der formlosen Kunst, zurück. Die Zeichnung ist in der Landschaftsmalerei als solcher eigentlich gar nicht anzutreffen; alles beruht in ihr auf den Künsten der Luftperspektive, also auf der ganz empirischen Art des Helldunkels. Die Landschaftsmalerei ist daher als eine durchaus empirische Kunstart zu betrachten. Die Einheit, welche in einem Werk derselben"}, {"type": "paragraph", "text": "liegen kann, fällt selbst wieder in das Subjekt zurück; es ist die Einheit einer Stimmung, welche die Gewalt des Lichts und seines wundervollen Kampfes mit dem Schatten und der Nacht in der allgemeinen Natur in uns hervorbringt. - Das Gefühl der * objektiven *Bedeutungslosigkeit der Landschaft hat den Maler vermocht, ihr eine objektivere Bedeutung durch Belebung mit Menschen zu geben. Es versteht sich, daß dieß immer das Untergeordnete ist, so wie in den höheren Formen der Kunst der wahre Künstler es verschmähen wird, seinem Bilde noch durch die Zuthat einer Landschaft Reize geben zu wollen, da der vollkommen genügende Gegenstand für ihn die menschliche Gestalt in ihrer hohen Bedeutung und unendlichen Bedeutsamkeit ist. In dem angenommenen Fall, wo die Landschaftsmalerei ihre Schildereien mit Menschen belebt, muß doch eine Nothwendigkeit in ihr Verhältniß zu denselben gebracht werden. Schon der Anblick einer Landschaft, besonders aber die Farbe des Himmels, belehrt vom Clima, da die nördliche Welt gegen die Heiterkeit des südlichen Himmels wie in dumpfer Nacht brütet, und läßt das geübte Auge auf die Formen von Menschen schließen, die sie bewohnen. Die Menschen in der Landschaft müssen daher entweder als gleichsam auf der Stelle gewachsen, als Autochthonen geschildert werden, oder sie müssen auch durch die im Verhältniß zu der Landschaft fremde Art ihres Wesens, Aussehens, ja selbst der Bekleidung, als Fremde, als Wanderer dargestellt werden. Auf diese Weise lassen sich in der Landschaft noch in einem andern Sinn Nähe und Ferne verbinden und die eigenthümlichen Gefühle, die auf den Vorstellungen derselben beruhen, hervorrufen. Die letzte und höchste Stufe der Farbenerscheinung ist die , wo sie als innerlich, organisch, lebendig und beweglich erscheint. Da dieß nur in der *menschlichen Gestalt *vollkommen der Fall ist, so ist diese der letzte und vollkommenste Gegenstand der malerischen Darstellung; mit derselben betritt die Kunst ein Gebiet, in dem eigentlich erst ihre absoluten Erzeugnisse beginnen, und ihre wahre Welt sich entfaltet. Die unterste Stufe ist auch hier die bloße Nachahmung der Natur, und wo diese bezweckt wird und die"}]}, {"page_pdf": 1718, "page_book": 547, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "vollkommene Uebereinstimmung des"}, {"type": "paragraph", "text": "Bildes mit dem Gegenstand beabsichtigt ist, entsteht das *Portrait.* Ueber den Kunstwerth oder -unwerth des Portraits hat man sich von Zeit zu Zeit gestritten; es scheint aber, daß man sich nur über den Begriff desselben zu verstehen habe, um auch über jenen einig zu seyn. Portrait, sagt man, ist sklavische Nachahmung der Natur, und allerdings, wenn man nicht die Kunst überhaupt in bloße Nachahmung setzen und die mikroskopischen Maler, die keinen Porus der Haut übergehen, für die größten erklären will, kann es nach diesem Begriff von Portrait kein Zweifel seyn, daß dasselbe einen sehr untergeordneten Rang einnehme. Versteht man aber unter Portrait eine solche Schilderung, die, indem sie die Natur nachahmt, zugleich die Dolmetscherin ihrer Bedeutung wird, das Innere der Gestalt herauskehrt und sichtbar macht, so wird man den bedeutenden Kunstwerth eines Portraits allerdings anerkennen müssen. Das Portraitiren als Kunst würde dann freilich vorzugsweise auf solche Gegenstände eingeschränkt werden müssen, denen wirklich eine symbolische Bedeutung abzusehen ist, und bei denen man sehen kann, daß die Natur einen vernünftigen Entwurf und gleichsam den Zweck, eine Idee auszudrücken, befolgt habe. Die wahre Kunst des Portraits würde darin bestehen, die auf die einzelnen Bewegungen und Momente des Lebens zerstreute Idee des Menschen in Einen Moment zusammen zu fassen, und auf diese Weise zu machen, daß das Portrait, indem es von der einen Seite durch Kunst veredelt ist, von der andern dem Menschen, d.h. der Idee des Menschen, ähnlicher sey, als er sich selbst in den einzelnen Momenten. Plinius1 erzählt von dem Euphranor, daß er ein Bild des Paris gemalt (welches freilich kein Portrait war) von der Art, daß man in ihm zugleich den Richter der drei Göttinnen, den Entführer der Helena und denjenigen, der den Achill erlegte, erblicken konnte. Diese Darstellung des *ganzen *Menschen in den einzelnen Erscheinungen wäre die höchste, obgleich, wie man wohl sieht, schwierigste Aufgabe des Portraits. - In Ansehung der Frage, ob die Person in Ruhe oder in Handlung dargestellt werden solle, ist"}, {"type": "footnote", "text": "1 Hist. nat. IV, 2."}, {"type": "paragraph", "text": "es offenbar, daß, da jede mögliche Handlung die Allseitigkeit eines Bildes aufhebt und den Menschen im *Moment *fixirt, in der Regel die größtmögliche Ruhe vorzuziehen sey. Die einzige erlaubte Ausnahme findet da statt, wo die Handlung so mit dem Wesen des Menschen eins ist, daß sie wiederum zur Charakteristik von ihm gehört. Z.B. einen Tonkünstler in der Handlung seiner Kunst vorzustellen, würde darum vorzüglicher seyn, als einen Dichter etwa mit der Feder in der Hand, weil das musikalische Talent isolirender und mit dem Wesen dessen, der es besitzt, am meistens verwebt ist. Sonst ist die Forderung, welche das Portrait nothwendig zu erfüllen hat, die höchste Wahrheit; nur daß sie nicht im Kleinen und *bloß *Empirischen gesucht werde. Von dieser Art sind denn die Bilder der alten, vorzüglich unserer deutschen Maler, Holbeins z.B., dessen eines, in Dresden zu sehendes Bild, welches einen Bürgermeister zu Basel mit seiner Familie vorstellt, indem er die heil. Jungfrau anbetet, gewiß niemand ohne Bewegung sehen wird - nicht nur (um dieß im Vorbeigehen zu bemerken) weil er in diesem, wie in andern ähnlichen Bildern, den ächten alten deutschen Styl, der dem italienischen bei weitem näher ist als dem niederländischen und den Keim eines Höheren in sich trägt, der ohne die besonderen unglücklichen Verhängnisse Deutschlands auch sicher sich entfaltet haben würde, erkennen kann, sondern auch, weil"}]}, {"page_pdf": 1719, "page_book": 549, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "dieses Bild eine *sittliche *Bedeutung hat, und so wie alle von demselben Styl, die gute alte Zeit, die strenge Zucht, den Ernst und die Frömmigkeit derselben dem Betrachtenden zurückruft. Ich bemerke noch, daß die vorzüglichsten historischen Maler Leonardo da Vinci, Correggio, Raphael, sämmtlich Portraits gemalt haben, ja es ist bekannt, daß Raphael in manchen seiner unabhängigen Compositionen wirkliche Portraits angebracht hat. Wir gehen endlich zu der letzten Kunststufe der Malerei über. Das höchste Bestreben des Geistes ist, *Ideen *hervorzubringen, die über das Materielle und Endliche erhaben sind. \"Die Idee der Schönheit, sagt Winkelmann, ist wie ein aus der Materie durchs Feuer gezogener Geist, welcher sich suchet ein Geschöpf zu erzeugen nach"}, {"type": "paragraph", "text": "dem Ebenbilde der in dem Verstande der Gottheit entworfenen ersten vernünftigen Creatur.\" Wir haben zu bestimmen, welche Mittel in der Malerei liegen, diesem Streben Genüge zu thun und die Ideen darzustellen. Da die bildende Kunst überhaupt Darstellung des Allgemeinen durch das Besondere ist, so sind ihr auch nur zwei Möglichkeiten gegeben, durch welche sie die Ideen erreichen und in wirklicher und sichtbarer Gestalt darstellen kann. Entweder daß sie das Allgemeine durch das Besondere bedeuten läßt, oder daß dieses, indem es jenes bedeutet, zugleich *es selbst *ist. Die erste Art der Darstellung ist die *allegorische*, die andere die *symbolische *(nach den Erklärungen, die davon schon früher gegeben wurden). Ich werde hier noch einiges von der *Allegorie *überhaupt nachtragen und dann insbesondere von der Allegorie in der Malerei reden. Die Allegorie kann überhaupt einer *allgemeinen *Sprache verglichen werden, die nicht, wie die besonderen Sprachen, auf willkürlichen, sondern auf natürlichen und objektiv gültigen Zeichen beruht. Sie ist Bedeutung der Ideen durch wirkliche, concrete Bilder, und demnach die Sprache der Kunst und der bildenden insbesondere, welche, da sie nach dem Ausdruck eines Alten eine stumme Dichtkunst ist, ihre Gedanken persönlich gleichsam, durch Gestalten, vorstellen lassen muß. Der strenge Begriff der Allegorie aber, den wir auch hier voraussetzen, ist, daß das, was dargestellt wird, etwas anderes als sich selbst bedeute, etwas anzeige, das verschieden von ihm ist. Die Allegorie ist, wie von der Sprache, ebenso auch von der *Hieroglyphe *verschieden. Denn auch diese ist nicht nur überhaupt willkürlich und nicht nothwendig an den wesentlichen Zusammenhang dessen, was bedeutet werden soll, und dessen, wodurch, gebunden, sondern sie ist auch noch überdieß mehr eine Sache des Bedürfnisses als der höheren Absicht, die auf Schönheit an und für sich gerichtet ist; daher es für die Hieroglyphe genug ist, wenn sie die Sache nur überhaupt, gleichviel ob auf eine schöne oder widrige Weise, andeutet. Von der Allegorie dagegen wird gefordert, daß jedes Zeichen oder Bild nicht"}, {"type": "paragraph", "text": "bloß auf allegorische Weise mit dem Gegenstand verknüpft sey, sondern daß es mit Freiheit und Absicht auf das Schöne entworfen und ausgeführt sey. Die Natur ist selbst allegorisch in allen denjenigen Wesen, denen sie den unendlichen Begriff von ihnen selbst nicht als Lebensprincip und Princip der Selbständigkeit einverleibt hat. So ist die Blume, deren Farbe die innere Natur oder die Intention der Natur, oder, was dasselbe ist, die *Idee *nur andeutet, wahrhaft allegorisch. Sonst hat sich auch darin der Instinkt zur Allegorie gezeigt, daß der Grund aller Sprachen, vorzüglich aber der ältesten Völker, ein"}]}, {"page_pdf": 1720, "page_book": 551, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "allegorischer ist. Wie wären, um nur etwas ganz Allgemeines anzuführen, die Menschen je darauf gefallen, die Dinge in der Sprache nach dem Geschlechte zu sondern (eine Sonderung, die durch alle nicht vorzüglich unpoetischen Sprachen geht), ohne allegorische und gleichsam persönliche Vorbilder dieser Dinge zu haben? Daß nun aber Malerei insbesondere allegorisch ist, davon liegt der Grund in ihrer Natur selbst, da sie nämlich noch nicht die *wahrhaft *symbolische Kunst ist, und wenn sie nicht zu dieser, wie in der höchsten Kunstgattung, sich erhebt, das Allgemeine nur durch das Besondere *bedeuten *kann. In Ansehung der Allegorie in der Malerei sind aber zwei Fälle wohl zu unterscheiden. Sie wird entweder bloß als *Zugabe *eines im Uebrigen historischen Gemäldes gebraucht, oder die ganze Erfindung und Composition ist selbst allegorisch. Das Erste ist immer fehlerhaft, wenn nicht die allegorischen Wesen, welche eingemischt werden, selbst eine *historische *Bedeutung in dem Gemälde haben können. Wenn z.B. auf einer sogenannten Ruhe auf der Flucht nach Aegypten, wo die heilige Jungfrau mit dem Kind unter einem Baume, auf das Kind herabsehend und es zugleich fächelnd, ruht, auf den Zweigen Engel vorgestellt sind, so sind diese hier wirklich als historische Gegenstände anzusehen. Oder wenn auf einem Gemälde des Albani, das den Raub der Helena vorstellt, Venus die Helena aus dem Hause des Menelaus an der Hand führt, und im Hintergrund Liebesgötter dargestellt sind, die sich dieses Vorfalls freuen, so treten auch diese hier als historische Wesen ein. Wenn dagegen auf einem"}, {"type": "paragraph", "text": "Bilde, das den Tod eines modernen Königs vorstellt, auf dessen Sterbebette vielleicht sogar die Reichsinsignien liegen, an einer Seite desselben der Genius mit der gesenkten Fackel stünde, so wäre dieß ein ganz platter Gebrauch der Allegorie, weil der Genius auf keine Weise in das Gemälde historisch aufgenommen werden kann. Oder wenn Poussin in einem Gemälde, das die Aussetzung Mosis in Aegypten vorstellt, den Nil als Flußgott darstellt, der sein Haupt in den Schilf verbirgt, so ist das Letztere eine sehr schöne Allegorie, sofern dadurch angedeutet wird, daß die Quellen des Nils unbekannt seyen; wenn aber ferner der kleine Moses diesem Flußgott in die Arme gelegt wird, so hebt diese Allegorie den Sinn des Gemäldes selbst auf, indem niemand dabei sich eine Gefahr vorstellen wird, da das Kind vielmehr der Fürsorge eines sinnigen Gottes als der blinden Gewalt eines vernunftlosen Elements überantwortet wird. Es gibt also meines Erachtens keine partielle Allegorie im Gemälde, weil dieß eine Dissonanz in das Gemälde bringt; und wo ein Wesen, das in anderer Rücksicht als ein allegorisches gedacht werden muß, in einem historischen Gemälde vorkommt, so muß es darin selbst die historische Bedeutung annehmen, so daß das Ganze den Charakter einer mythologischen Darstellung hat. Desto weiter ist das Feld der Allegorie in dem Gemälde, sofern sie unbeschränkter Weise gebraucht wird. Die Allegorie hat hier keine Grenzen als die *allgemeinen *der Kunst selbst, daß nämlich der Ueberfluß vermieden, und die Idee so einfältig wie möglich dargestellt werde. \"Die Einfalt,\" sagt Winkelmann1, \"ist in Allegorien wie Gold ohne Zusatz und der Beweis der Güter derselben, weil sie alsdann mit wenigem viel erklären; wo das Gegentheil geschiehet, ist es mehrentheils ein Zeichen undeutlicher und unreifer Begriffe.\" Mit der Einfalt zugleich entsteht die Deutlichkeit, die freilich relativ ist, und in der man nicht die allzu große Popularität verlangen muß, wie man etwa ein paar weiße Rüben finden könnte, die Guido Reni einer übrigens"}, {"type": "footnote", "text": "1 a.a.O. 2 Bd., S. 484. D. H."}]}, {"page_pdf": 1721, "page_book": 553, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "sehr schönen büßenden Magdalena mitgegeben hat, um ihre strenge Lebensart anzudeuten. Denn wie hat der Künstler überhaupt nöthig, uns daran zu erinnern, daß die büßende Magdalena irdische Nahrung genieße? Die höchste Regel ist aber, weil in aller Kunst, so auch hier, die Schönheit, und daß das rein Gräßliche, Abscheuliche und Widrige vermieden werde. Die wüthende Nothwendigkeit, wie sie Horatius nennt, die Wuth des Krieges bei Virgilius oder die Teufeleien des Milton würden in der Malerei nur mit schlechtem Erfolg ausgeführt werden können. So ist in der St. Peterskirche zu Rom ein allegorisches Gemälde, das die Ketzerei zu den Füßen der Heiligen in der häßlichsten Gestalt vorstellt, als ob sie in einer schönen weiblichen Figur vorgestellt in dieser Unterwerfung und Beugung nicht eine viel bessere Wirkung machte. Die Allegorie in Gemälden kann nun übrigens entweder physisch seyn und sich auf Naturgegenstände beziehen, oder moralisch, oder historisch. - Als ein allegorisches Bild der *Natur *muß man das Bild der Diana mit den vielen Brüsten betrachten, dagegen in der bekannten Vergötterung des Homer die Natur ganz einfach unter dem Bild eines kleinen Kindes vorgestellt ist. - Die Nacht wird mit einem fliegenden Gewand voll Sterne gebildet, der Sommer im Laufen und mit zwei brennenden gerade in die Höhe gehaltenen Fackeln in den Händen. Der Nil und dessen Ueberschwemmung bis zu 16 Fuß, welches nach der alten Meinung die größte Fruchtbarkeit bedeutet, wurde in ebensoviel Kindern abgebildet, die auf der kolossalen Figur des Flusses saßen. Ich bemerke, daß die vornehmsten Allegorien der bildenden Kunst, nachdem das Schicksal der Zeit uns die Schätze der alten Malerei entrissen hat, durch die kleineren Denkmäler der Skulptur in geschnittenen Steinen auf uns gekommen sind. Die Plastik legt nicht mit einemmal die Schranken der Malerei ab, sie behält noch in mehreren Gattungen den Raum als nothwendige Zugabe, und kann daher, wie die Malerei, in den meisten Hervorbringungen auch nur bedeutend, aber noch nicht wahrhaft symbolisch seyn. Von den* moralischen *Allegorien ist zu bemerken, daß sie bei den Alten nicht unsern Begriffen angemessen seyn können, da von diesen"}, {"type": "paragraph", "text": "nur die heroischen Tugenden oder jene, welche die Würdigkeit des Menschen erheben, geschätzt, andere aber von ihnen nicht gelehrt noch gesucht wurden. An die Stelle der Geduld und Unterwerfung tritt bei den Alten die Tapferkeit und die männliche, großmüthige Tugend, welche kleine Absichten und das Leben selbst verachtet. Von der christlichen Demuth war bei den Alten ohnedieß kein Begriff anzutreffen. Alle diese passiven Tugenden, wohin auch die Reue, z.B. der Magdalena, gehört, sind nur in den christlichen Bildern zu suchen. Dagegen konnten auch bei den Alten die Werke der Kunst nicht dem Laster geweiht seyn, und nur mit großer Einschränkung waren allegorische Vorstellungen davon möglich. Das berühmteste Beispiel davon ist ein Gemälde der Verleumdung von Apelles, dessen Beschreibung Lucian1 hinterlassen hat. Apelles malte die Verleumdung, da er von einem seiner Kunstgenossen bei Ptolemäos Philostratos als Mitschuldiger einer Verrätherei fälschlich angegeben worden war. Auf seinem Gemälde saß zur Rechten eine männliche Figur mit langen Ohren und reichte der Verleumdung die Hand; um diese herum stand die Unwissenheit und der Verdacht. Von der andern Seite trat eine andere Gestalt der Verleumdung herbei, welche eine schöne Figur, aber erbost, aufgebracht war, in der rechten Hand eine brennende Fackel haltend, mit der linken einen Jüngling bei den Haaren herbeiziehend, welcher die Hände zum Himmel erhob und die Götter zu Zeugen anflehte. Vor der Verleumdung her trat ein großer und wie von langer Krankheit ausgezehrter Mann, welcher den Neid vorstellte. Die Begleiterinnen der Verleumdung selbst waren zwei Weiber, welche sie putzten und ihr zuredeten, nämlich die Falschheit und die Hinterlist. Hinterher ging eine andere Figur in schwarzer und zerrissener Kleidung, welche die"}]}, {"page_pdf": 1722, "page_book": 554, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Scham andeutete, indem sie beschämt und weinend nach der Wahrheit sich umsah. Andere moralische Eigenschaften wurden durch entferntere Beziehungen angedeutet, wie z.B. die Verschwiegenheit durch die Rose, weil diese die Blume der Liebe ist, welche Verschwiegenheit liebt, oder,"}, {"type": "footnote", "text": "1 Imag. c. 6."}, {"type": "paragraph", "text": "wie ein alter Epigrammatist sagt, weil die Liebe dem Harpokrates, dem Gott des Stillschweigens, die Rose gab, damit die Ausschweifungen der Venus möchten verschwiegen bleiben. Daher bei den Alten eine Rose bei Fröhlichkeiten über die Tische aufgehängt wurde zum Zeichen, daß, was gesprochen würde, als unter Freunden geheim bleiben sollte. Unter die *moralischen *Allegorien rechne ich alle, welche allgemein menschliche Verhältnisse andeuteten. So wurde das Schicksal vorgestellt durch die Lachesis, welche die Spindel drehend auf einer komischen Larve sitzt und vor sich die tragische stehen hat, um die vermischten Spiele auf der Schaubühne des Lebens anzudeuten. Ein frühzeitiger Tod wurde durch das Bild der Aurora vorgestellt, die ein Kind in den Armen fortträgt. Vermittelst der Allegorie, wie des Sinnbildlichen, kann sich die Malerei bis in die Region des Uebersinnlichen erheben. Die Belebung des Körpers durch Einflößung der Seele ist ohne Zweifel einer von den abgesondertsten Begriffen, der aber doch allegorisch-dichterisch versinnlicht ist. Prometheus bildet einen Menschen von Thon, und Minerva hält einen Schmetterling auf den Kopf desselben als Bild der Seele, welches zugleich alle die verschiedenartigen Vorstellungen zusammenfaßt, welche die Metamorphose dieses Geschöpfes erwecken kann. Die *historische *Allegorie ist vorzüglich von neueren Künstlern gebraucht, z.B. französischen (Rubens), zur Verherrlichung von Thaten ihrer Könige, z.B. das Wiederaufleben einer Stadt durch Begünstigung eines Fürsten auf alten Münzen vorgestellt durch eine weibliche Figur, die durch eine männliche von der Erde aufgehoben wird. Vom höchsten Styl war das Bild des Aristides, welcher das athenische Volk nach seinem ganzen Charakter zugleich als leichtsinnig und ernst, tapfer und feig, klug und unweise darstellte, obgleich man gestehen muß, daß wir uns von diesem keinen deutlichen Begriff machen können. Nun ist noch vom *symbolischen *Gemälde zu reden. Da aber hievon bei der Plastik gesprochen wird, so beschränke ich mich hier auf das Allgemeinste. Symbolisch ist ein Bild, dessen Gegenstand die Idee"}, {"type": "paragraph", "text": "nicht nur bedeutet, sondern *sie selbst *ist. Sie sehen von selbst, daß auf diese Weise das symbolische Gemälde ganz mit dem sogenannten historischen zusammenfällt und für dieses selbst die höhere Potenz bezeichnet. Hier sind nun wieder Verschiedenheiten nach den Gegenständen. Diese nämlich können entweder etwas *allgemein Menschliches *seyn, was sich im Leben stets wiederholt und erneuert, oder sie können sich auf ganz geistige und intellektuelle *Ideen *beziehen. Von letzterer Gattung ist der Parnaß und die Schule von Athen des Raphael, welche die ganze Philosophie sinnbildlich darstellt. - Die vollkommenste symbolische Darstellung aber ist durch bleibende und unabhängige poetische Gestalten einer bestimmten *Mythologie *gegeben. So *bedeutet *die heil. Magdalena nicht nur die Reue, sondern ist die lebendige Reue selbst. So ist das Bild der heil. Cäcilia, der Schutzheiligen der Musik, nicht ein"}]}, {"page_pdf": 1723, "page_book": 556, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "allegorisches, sondern ein symbolisches Bild, da es eine von der Bedeutung unabhängige Existenz hat, ohne die Bedeutung zu verlieren. So das Bild Christi, weil es die ganz einzige Identität der göttlichen und menschlichen Natur anschaulich darstellt. Ebenso ist das Bild der Madonna mit dem Kinde ein symbolisches Bild. Das symbolische Bild setzt eine Idee als vorausgehend voraus, die symbolisch wird dadurch, daß sie historisch-objektiv, auf unabhängige Weise anschaulich wird. Wie nun die *Idee* dadurch, daß sie *historische *Bedeutung erhält, symbolisch wird, so kann umgekehrt das Historische nur dadurch, daß es mit der Idee verbunden und Ausdruck der Idee wird, ein symbolisches Bild werden, und so kommen wir damit auf den eigentlichen und höchsten Begriff des *historischen Gemäldes*, unter dem man insgemein alles zu begreifen pflegt, was wir bisher als allegorisch und symbolisch bezeichnet haben. Nach unsrer Erklärung ist das Historische selbst nur eine Art des Symbolischen. Die Historie ist ohne Zweifel der vornehmste Gegenstand der Malerei, da hier das Unterscheidende von Göttern und Menschen, den würdigsten Gegenständen der malerischen Darstellung, zugleich im Handeln erkannt wird. Allein die bloße Darstellung einer Handlung an und für sich würde die Malerei nur zu dem Range erheben, den in der Poesie"}, {"type": "paragraph", "text": "die Tragödie oder das Heldengedicht hat. Jede mögliche Geschichte ist an und für sich ein einzelnes Factum, welches demnach zur Kunstdarstellung nur dadurch erhoben wird, daß es zugleich bedeutend und wo möglich Ausdruck von Ideen, allgemein bedeutend, wird. Aristoteles sagt, Homer habe lieber das Unmögliche, welches wahrscheinlich ist, als das bloß Mögliche darstellen wollen; man fordert mit Recht dasselbe von dem Gemälde, daß es sich nämlich über das gemeinhin Mögliche erhebe und eine höhere und absolute Möglichkeit zum Maßstab der Darstellung nehme. Das historische Gemälde, sagten wir, könne Darstellung von Ideen, also symbolisch seyn theils in dem Ausdruck, welcher den einzelnen Gestalten gegeben wird, theils in der Art des Geschehens der Begebenheit, welche vorgestellt wird. Was das Erste betrifft, so gewährt nichts Befriedigung, was bloß die Sinne rührt und nicht in das Innere des Geistes dringt. Die bloße Schönheit der Umrisse vollendet das Bedeutende nicht ohne tieferen Hintergrund, der nicht gleich beim ersten Blicke erforscht wird. Eine ernsthafte Schönheit läßt niemals völlig satt und zufrieden gehen, weil man immer noch Schöneres und Tieferes an ihr entdecken zu können glaubt. Von dieser Art sind die Schönheiten des Raphael und der alten Meister, \"nicht spielend und liebreizend, wie Winkelmann sagt, aber wohlgebildet und erfüllet mit einer wahrhaften und ursprünglichen Schönheit\". Durch Reizungen dieser Art ist Cleopatra durch alle Zeiten berühmt geworden, und selbst in die Köpfe des Antonius haben die Alten diesen würdigen Ernst gelegt. Es gibt also eine Würde und Höhe des Ausdrucks, die noch über die Schönheit des Umrisses hinzukommt, oder diesen erst wirklich bedeutend macht. Eine Veredlung der gemeinen Natur fordert man auch von dem Portraitmaler, und er kann diese erreichen, ohne der Aehnlichkeit zu schaden, d.h. ohne daß er aufhört Nachahmer zu seyn. Das, was immer und nothwendig erfunden ist, ist die Idee, und diese, wenn von ihr in dem Bilde ein Ausdruck ist, kann sogar dem Portrait durch höheren Reiz das Symbolische geben. Was die Art des Darstellens der *Begebenheiten *selbst betrifft,"}, {"type": "paragraph", "text": "so ist die *höchste *Norm, wie überall, so auch hier, daß die Kunst uns die Formen einer höheren Welt und die Dinge, wie sie in dieser geschehen, darzustellen hat. Das Reich der Ideen ist das Reich der adäquaten"}]}, {"page_pdf": 1724, "page_book": 558, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "und klaren Vorstellungen, wie das Reich der Erscheinung das der unangemessenen, dunklen und verworrenen. In dem Reich der Erscheinung trennt sich Form und Stoff, Thätigkeit und Seyn. Im Reich des Absoluten ist beides eins, die höchste Ruhe ist die höchste Thätigkeit, und umgekehrt. Alle diese Charaktere müssen übergehen in das, was Abdruck des Absoluten seyn will. Wir würden sie schwerlich anders bezeichnen, als wie sie längst Winkelmann bezeichnet hat, der Vater aller Wissenschaft von der Kunst, dessen Ansichten noch jetzt die höchsten sind und es immer bleiben werden. Das Adäquate und Vollkommene der Vorstellungen drückt sich in dem Gegenstand durch dasjenige aus, was Winkelmann die *edle Einfalt *nennt, sowie jene ruhige Macht, die, um als Macht zu erscheinen, nicht nöthig hat, aus dem Gleichgewicht ihres Daseyns zu weichen, das ist, was Winkelmann als die stille Größe bezeichnet hat. Auch hier wieder stehen uns nun die Griechen als Urbilder da. Wie die Tiefe des Meers jederzeit ruhig bleibt, das Oberste mag noch so rasch und bewegt seyn, so zeigt der Ausdruck der griechischen Figuren bei allen Leidenschaften eine ruhige und gesetzte Seele. In dem Ausdruck der Schmerzen und der körperlichen Erstarrung selbst sehen wir die Seele siegen und als ein göttliches Licht von unverderblicher Heiterkeit über der Gestalt aufgehen. Eine solche Seele ist in dem Gesichte des Laokoon und in dem ganzen Leibe ausgedrückt (denn nur von der Plastik sind die passenden Beispiele des höchsten symbolischen Styls herzunehmen). \"Der Schmerz\", sagt Winkelmann in seiner herrlichen Beschreibung dieses Werks1, \"der Schmerz, welcher sich in allen Muskeln und Sehnen des Körpers entdecket, und den man ganz allein, ohne das Gesicht und andere Theile zu betrachten, an dem schmerzlich eingezogenen Unterleibe beinahe selbst zu empfinden glaubet, dieser Schmerz äußert sich dennoch mit keiner Wuth in dem"}, {"type": "footnote", "text": "1 a.a.O. 1 Bd., S. 31 ff."}, {"type": "paragraph", "text": "Gesichte und in der ganzen Stellung. Er erhebet kein schreckliches Geschrei, wie Virgil seinen Laokoon beschreibt; die Oeffnung des Mundes läßt dieß nicht zu, es ist nur ein ängstliches und beklemmtes Seufzen. Der Schmerz des Körpers und die Größe der Seele sind durch den ganzen Bau der Figur mit gleicher Größe ausgetheilet und gleichsam abgewogen. Laokoon leidet, aber er leidet wie des Sophokles Philoktetes; sein Elend gehet uns bis an die Seele, aber wir wünschten, wie dieser große Mann das Elend ertragen zu können.\" Diese Beschreibung reicht hin einzusehen, daß *dieser *Ausdruck der Seele nichts mehr ist, das aus der Erfahrung genommen, daß es eine über die Natur sich erhebende Idee ist, die der Künstler in sich selbst haben mußte, um sie dem Marmor einzuprägen. Ein gleiches Bild ist das der Niobe mit ihren Töchtern. Diese, auf welche Diana die tödtlichen Pfeile richtet, sind in der unbeschreiblichen Angst mit übertäubter Empfindung geschildert, wo die Erstarrung selbst die Ruhe und jene hohe Gleichgültigkeit zurückbringt, die sich mit der Schönheit am meisten verträgt und keine Züge der Gestalt und der Bildung ändert. Wir können nach diesen Betrachtungen alle Erfordernisse des Gemäldes im symbolischen Styl wieder auf das einzige zurückbringen, daß alles der Schönheit untergeordnet sey, denn diese ist immer symbolisch. Der bildende Künstler ist in Ansehung seiner Gegenstände ganz an die Gestalt gewiesen, da er diese allein ausdrücken kann. Der Dichter, welcher nicht Gestalten für die Anschauung aufstellt, beleidigt die Schönheit nicht nothwendig, wenn er auch in der Leidenschaft zum Heftigeren geht, der bildende Künstler aber, nur an die Anschauung gewiesen, ist in dem Fall, die Schönheit nothwendig zu beleidigen, wenn er sich nicht auf einen gewissen Grad des Ausdrucks der Leidenschaften einschränkt: allerdings der plastische Künstler noch mehr als der malende, theils weil diesem viele Mittel der Milderung durch Licht und Schatten zu Gebot stehen, die jenem nicht, theils weil von der andern Seite alles Plastische eine größere Gewalt der Wirklichkeit war. Die Einschränkung jener strengen"}]}, {"page_pdf": 1725, "page_book": 559, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Forderungen, welche an die Plastik gemacht werden müssen, in Bezug auf Malerei ergeben sich übrigens auch schon"}, {"type": "paragraph", "text": "daraus, daß sie, auch bloß allegorisch, nicht aufhört Kunst zu seyn, und daß sie, einmal mit dem Schein sich vermengend, auch mit dem Empirischen kecker als die Skulptur sich verbinden kann, - freieres Spiel hat. In allen heftigeren Bewegungen der Seele entstellen sich die Züge wie die Haltung des Körpers und alle Formen der Schönheit. Die Stille ist der der Schönheit eigenthümliche Zustand, wie die Ruhe dem ungestörten Meere. Nur in der Ruhe kann die menschliche Gestalt überhaupt und das Gesicht der Spiegel der Idee seyn. Auch hierin deutet die Schönheit auf Einheit und Indifferenz als ihr wahres Wesen hin. Das Gegentheil dieses ruhigen und großen Styls nannten die Alten Parenthyrsos, welcher einen gemeinen Styl erzeugt, dem nichts als das Ungewöhnliche in Stellungen und Handlungen, ein freches Feuer, die heftigen, flüchtigen und schreienden Gegensätze, genügen. Dieses Verwirrende der Darstellung hervorzubringen, sind die meisten artistischen Regeln der neueren Theoretiker über die Composition und das, was sie den Contrastoff nennen, erfunden. Dafür ist in den Werken dieses Styls alles in Bewegung, man befindet sich, wie Winkelmann sagt, unter den Gegenständen derselben, wie in einer Gesellschaft, worin alle zugleich reden wollen. Die Ruhe in der Größe und jenes höhere Symbolische des historischen Gemäldes, das es als Ausdruck der Ideen erhält, hat vor allen andern neueren Meistern *Raphael *erreicht. Nur demjenigen, der den Sinn dafür in sich gebildet hat, wird in der Ruhe und Stille der Hauptfiguren seines Gemäldes, welche andern leblos scheinen mögen, die höchste Schönheit aufgehen. Von dieser Art ist sein Bild des Attila, auf welchem der Moment dargestellt ist, wie der römische Bischof diesen Eroberer zum Rückzug bewegt. Alles, was in diesem Bilde von erhabener Natur ist, der Pabst und seine Begleiter, wie die beiden vom Himmel her schwebenden Apostel, Petrus und Paulus, ist in jenem Sinn der Ruhe gedacht. Der Pabst erscheint in der stillen Sicherheit eines ehrwürdigen Mannes, der einen Aufruhr durch seine bloße"}, {"type": "paragraph", "text": "Gegenwart stillt. Die Apostel erscheinen ohne gewaltsame Bewegung drohend und erschreckend. Im Attila ist Schrecken wahrzunehmen, und jener Ruhe und Stille der würdigeren Stelle steht die Unruhe und Bewegung auf der andern Seite entgegen, wo zum Abmarsch geblasen wird, und alles voll Verwirrung und Bestürzung sich zum Rückzug wendet. Ueberhaupt ist Raphael von Seiten der *Höhe *der Erfindung der einzig größte, und wenn wir im Vorhergehenden in Ansehung jeder der besonderen Kunstformen einen als den überwiegenden auszeichneten, in der Zeichnung den Michel Angelo, im Helldunkel Correggio, im Colorit Tizian, so müssen wir von Raphael behaupten, daß er alle diese Formen im Gleichgewicht besessen, und demnach der wahrhaft göttliche Priester der neueren Kunst ist. Den Michel Angelo trieb die Macht seines Geistes in der Zeichnung unwiderstehlich und fast ausschließlich zum Gewaltsamen, Starken und Schrecklichen; nur in solchen Gegenständen konnte die wahre Tiefe seiner Kunst sichtbar werden. Den Correggio beschränkte seine große Kunst im Helldunkel im Zarten, Sanften und Gefälligen wieder in Ansehung der Gegenstände; er bedurfte derjenigen, welche vorzugsweise die Ausübung des ersten begünstigen, und welche die Weichheit der Umrisse, das Schmeichelnde der Formen verstatten. Endlich war Tizian, als der höchste Meister im Colorit, damit am meisten auf die Wahrheit und die Nachahmung eingeschränkt. In der Seele des Raphael ruhten alle diese Formen im gleichen Gewicht, Maß und Ziel, und da er keiner besonderen verbunden war, blieb sein Geist für die"}]}, {"page_pdf": 1726, "page_book": 561, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "höhere Invention frei, sowie für die wahre Erkenntniß des Charakters der Alten, die er, der einzige unter den Neueren, bis zu einem gewissen Punkte erreicht hat. Seine Fruchtbarkeit führt ihn doch nie über die Grenze des Nothwendigen, und in aller Milde seines Gemüths bleibt doch die Strenge seines Geistes bestehen. Er verschmäht das Ueberflüssige, wirkt mit dem Einfachsten das Größte, und haucht damit seinen Werken ein solches objektives Leben ein, daß sie ganz in sich selbst bestehend, sich aus sich selbst entwickelnd und mit Nothwendigkeit erzeugend erscheinen. Daher, obgleich er sich über das gemeinhin Mögliche erhebt, doch die Wahrscheinlichkeit"}, {"type": "paragraph", "text": "seiner Werke; daher * in *ihrer Uebernatürlichkeit doch wieder die höchste, in Unschuld übergehende Natürlichkeit, jenes letzte Kennzeichen der Kunst. Bisher war von der Kunst des historischen Gemäldes rein als solcher die Rede. Es ist nöthig, daß wird noch von den *Gegenständen *des historischen Gemäldes handeln. - Vorzüglich kommt dabei eine Frage in Betracht, welche nicht nur die Liebhaber, sondern selbst Kenner interessirt hat: durch welche in der Kunst selbst liegende Mittel es möglich sey, einen Gegenstand malerisch so darzustellen, daß er als dieser erkannt werde. Man setzt nämlich bei dieser Frage voraus, daß die Hauptsache im historischen Gemälde die wirkliche, *empirische *Erkennbarkeit des Gegenstandes sey: allein dieß kann wenigstens nicht auf irgend eine Weise zum Gesetz gemacht werden, weil, sobald es allgemein gedacht wird, die Forderung selbst ungereimt ist. Wer z.B. in dem oben angeführten Gemälde des Raphael den römischen Bischof nicht nur so weit als nöthig ist diesen allgemeinen Charakter zu wissen, sondern auch persönlich als den, der so oder so geheißen hat, bezeichnet wissen wollte, der müßte die Sitte der alten Maler, ihren Figuren Zettel aus dem Munde herausgehen zu lassen, worauf ihre Bedeutung geschrieben stand, für die zweckmäßigste erklären. Die Forderung, ein Gemälde bis zur empirischen Wirklichkeit zu begreifen, muß also immer eingeschränkt bleiben, und das Symbolische des historischen Gemäldes erhebt schon von selbst über diesen Gesichtspunkt. Wir würden von der hohen Schönheit der Gruppe des Laokoon nichts verlieren, wenn wir auch nicht durch Plinius und Virgilius von dem Namen des Leidenden unterrichtet wären. Die Grundforderung ist nur, daß der Gegenstand an und für sich selbst vollkommen und klar erkennbar sey. Ist das Gemälde seinem eigentlichen Gegenstande nach symbolisch, so gehört es schon von selbst zu einem gewissen mythologischen Kreis, dessen Kenntniß auf eine allgemeingültige Weise vorausgesetzt wird. Ist es der ersten Intention nach historisch, so stehen eben der malerischen Darstellung Mittel genug zu Gebot Zeitalter und Nation zu bezeichnen. Nicht eben allein durch das, was man Beobachtung des Kostüms in der Kleidung nennt, das bei antiken Gegenständen freilich darum nicht"}, {"type": "paragraph", "text": "verletzt werden darf, weil es mit zu der Schönheit gehört. Allein auch in einem Gemälde, das neuere Gegenstände vorstellt, müssen sich unabhängig von Kleidung, z.B. bei nackten Figuren oder bei einem nicht eben die Zeit charakterisirenden Kostüm Mittel genug finden lassen die Zeit zu bezeichnen. In der Schlacht des Constantin von Raphael würde ohne alle andern Merkmale das Zeichen des Kreuzes hinreichen zu belehren, daß eine Begebenheit aus der Geschichte des Christenthums vorgestellt werde. Von denjenigen Gegenständen, die nicht durch wahrhaft künstlerische Mittel bezeichnet werden können, kann man zum voraus mit Gewißheit sagen, daß sie der künstlerischen Darstellung überhaupt nicht werth seyen. Wenn z.B. Künstler eines neueren Staates angewiesen sind, vorzüglich edle Handlungen aus der vaterländischen Geschichte darzustellen, so ist die geforderte Nationalität (= Nicht-Universalität) ebenso sonderbar als die Forderung, die Sittlichkeit der Handlungen zu malen - und dann mögen die Soldaten"}]}, {"page_pdf": 1727, "page_book": 563, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "auch immerhin noch in preußischen Uniformen gemalt werden. Wir müssen uns hier dessen erinnern, was in der Untersuchung über Mythologie bemerkt wurde, daß, da uns eine universelle Mythologie fehlt, jeder Künstler sich aus dem vorliegenden Stoff der Zeit eine specielle Mythologie schaffen kann. Daß er von der Geschichte nichts aufnehme, was nicht in demjenigen Kreis der Historie liegt, den man als allgemeingültig annehmen kann, ist etwas, worauf er noch aus viel höheren Gründen als der bloßen Besorgniß unverstanden zu bleiben eingeschränkt ist. Außer den allgemeineren Bedingungen der Verständlichkeit des historischen Gemäldes kann aber noch die besondere hinzu kommen, daß eine Begebenheit durch eine vorhergehende bedingt ist, die zu ihrem Verständniß nothwendig erfordert wird. Fürs erste kann man auch in dieser Rücksicht zweifeln, ob eine Begebenheit, die der künstlerischen Darstellung werth ist, nicht von sich selbst so prägnant sey, daß man in der Gegenwart wenigstens die nächste Vergangenheit erblickt, wie z.B. in der Gruppe des Laokoon niemand darüber zweifelhaft seyn kann. Wer sich hiezu unfähig fühlt, dem wäre wieder ein Mittel älterer"}, {"type": "paragraph", "text": "Maler zu empfehlen, welche frühere Momente der Geschichte im Hintergrund darstellen und den Helden derselben auf einem und demselben Bilde mehrmals vorkommen lassen. Ein anderer Fall noch wäre, wenn eine darzustellende Begebenheit auf mehrere weiter entfernte Begebenheiten nothwendig zurückwiese, und sie zu ihrem Verständniß forderte. Ich glaube auch hieran zweifeln zu müssen, obgleich, wenn diese Forderung wirklich existiren könnte, man allerdings sich auf den Vorschlag zurückziehen müßte der in den Propyläen geschieht, nämlich den eines Cyklus historischer Darstellungen, einer Reihe von Bildern, die verschiedene Momente einer zusammenhängenden Geschichte fixiren. Man muß dieß freilich nicht, wie einige gethan haben, zu streng nehmen und die wirkliche absolute Stetigkeit fordern, wozu eine unendliche Reihe von Bildern nicht hinreichen würde. Das Princip, aus welchem diese ganze Untersuchung über Verständlichkeit historischer Gemälde zu entscheiden ist, ist *ohne allen Zweifel *dieses: die historische Kenntniß der Begebenheit, welche dargestellt wird, nach allen ihren gegenwärtigen und vergangenen Bedingungen trägt zum Genusse des Kunstwerks bei, allein diese Art des Genusses selbst liegt außer dem Kreis der Beabsichtigung des Künstlers. Sein Werk muß den Reiz nicht erst von diesem fremdartigen Interesse entlehnen. Viele Bildungen auf alten Kunstwerken sind unverständlich gewesen, man hat sie nachher durch gelehrten Fleiß entziffert; viele sind es noch und sie verlieren dadurch nichts an der wahrhaft künstlerischen Schönheit. Es ist gleich unrichtig, zu fordern, daß im Gemälde selbst alle Anleitung zum empirisch-historischen Verhältnisse desselben gegeben sey, und der Maler für uns gleichsam ein Lehrer der Geschichte werde, und hinwiederum das Gemälde zwar davon freizusprechen, dagegen von dem Beschauer die gelehrte Kenntniß zu fordern. Das letztere ist darum fehlerhaft, a) weil man nicht weiß, wo man mit dieser Gelehrsamkeit anfangen, und wo man enden soll, b) weil man die empirisch historische Verständlichkeit dabei als etwas Wesentliches gelten läßt, und ihre Bedingung doch in etwas Zufälliges, nämlich die Kenntniß des Betrachters legt."}, {"type": "paragraph", "text": "Das Gemälde hat nur die innern Forderungen zu erfüllen, wahr, schön, ausdrucksvoll und *allgemein* bedeutend zu seyn, so daß es des zufälligen Reizes, selbst von der Kenntniß der besonderen empirischen Begebenheit, die es vorstellt, allenfalls entbehren kann. Ebenso fehlerhaft von Seiten der Kunst ist es der"}]}, {"page_pdf": 1728, "page_book": 565, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Gelehrsamkeit als der Ungelehrsamkeit zu schmeicheln. Wer sich getrieben fühlt, der Kunst recht zu genießen und auch diesen höheren Antheil seines Gemüths an einer bekannten Begebenheit nicht aufzugeben, mag selbst sehen, wie er sich in den Stand setzt diese stumme Dichtkunst, die immer und nothwendig entweder allegorisch oder symbolisch bleibt, auch von ihrer historischen Seite zu verstehen. Sein Gemüth wird dadurch mehr bewegt werden, die künstlerische Anschauung aber nichts gewinnen, was sie nicht auch ohne jene Kenntniß hätte erlangen können. Wir haben die Malerei bis zu ihrer äußersten Höhe der historisch-symbolischen Darstellung begleitet. Wie aber alles Menschliche, sobald in Einer Richtung der Gipfel erreicht, sich sogleich auch von der anderen Seite wieder herunter neigt, so ist auch die Malerei diesem Schicksal nicht entgangen. Kurze Zeit nach Erreichung der höchsten Kunst und auf dem Schauplatz selbst der herrlichsten Denkmäler derselben bildete sich die fremdartigste Ausartung des Geschmacks in der Gattung, welche das historische Gemälde zum Niedrigen und Gemeinen herunterzieht, der Bambocciade. Den Ursprung gab ihr der Niederländer Peter Laar, genannt il Bamboccio, der im Anfang des siebenzehnten Jahrhunderts nach Rom kam und sich durch seine Possen, die ein glänzendes Colorit und ein frecher Pinselstrich auszeichnete, so großen Beifall erwarb, daß diese bald allgemeiner Geschmack und von den Großen eben so sehr begünstigt wurde, als zuvor die ächte Kunst begünstigt worden war. Man muß gestehen, daß die ersten Bamboccianten es an kunstvoller Behandlung nicht fehlen ließen, und ihr Gegensatz zu den ernsthaft-gemeinen niederländischen Gemälden war, daß jene sich selbst nur als Parodien der großen Kunst betrachteten. Die nothwendige Forderung an den, der mit seiner Kunst scherzen will, ist, daß er die Meisterschaft in hohem Grade besitze. Die Verirrung ist"}, {"type": "paragraph", "text": "freilich noch immer nicht so groß als in der jetzigen Zeit, wo Bambocciaden in der Poesie und andern Künsten ohne Kraft, Wahrheit und Meisterschaft die allgemeinste Wirkung machen. Die Geschichten dieser Geistesepidemien erläutern sich wechselseitig, obgleich freilich, was unsre Zeit in dem niedrigen Fach aufzuweisen hat, gegen die ähnlichen Produkte jener früheren Zeit soweit absticht als diese ganze Zeit gegen jene frühere in Ansehung der Kunst überhaupt. Jene waren im Niedrigen wenigstens meisterhaft, diese sind selbst im Allerniedrigsten nicht einmal zu einem Grad der Meisterhaft gelangt. - Verwerflichkeit *Hogarths.* Auf diese Weise hätten wir den ganzen Kreis der malerischen Darstellung, wie er sich von der ersten bloßen Nachahmung todter Gegenstände zum Gipfel erhebt und von da nach der andern Seite wieder zum Gemeinen herabsenkt, durchlaufen. Ich gebe nun kurz die Sätze die Malerei betreffend an. Der letzte (Zusatz zu §. 87) war: \"Die besonderen Formen der Einheit, sofern sie in der Malerei zurückkehren, sind Zeichnung, Helldunkel und Colorit.\" Es bedurfte zur Erläuterung dieses Satzes nichts als des allgemeinen Begriffs der drei Einheiten selbst. Die Zeichnung ist hinlänglich dadurch charakterisirt, daß sie als die reale, das Helldunkel dadurch, daß sie als die ganz ideale Form der Malerei bezeichnet wurde. Alle Bestimmungen einer jeden dieser Formen sowie ihr Verhältniß zueinander sind unmittelbar daraus einzusehen. Das Colorit insbesondere betreffend, so ist es dasjenige, was den Schein und die Wahrheit, das Ideale und Reale ganz indifferenziirt und eins macht. Ich füge daher nur noch die Sätze bei, welche die *Gegenstände *der Malerei betreffen."}, {"type": "paragraph", "text": "§. 88. *Die Malerei hat ihre Gegenstände als Formen der Dinge darzustellen, wie sie in der idealen Einheit vorgebildet sind. - *Die Musik hat die realen Formen darzustellen, die Malerei die Dinge, wie sie in der rein idealen Einheit als solcher. Denn sie ergreift nur das rein-Ideale der Dinge, und sondert es von dem Realen ganz ab. *Zusatz* 1. Die Malerei geht also vorzüglich auf Darstellung von"}]}, {"page_pdf": 1729, "page_book": 566, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Ideen von der idealen Seite. - Jede Idee hat, wie das Absolute, zwei Seiten, eine reale und eine ideale, oder: sie ist ganz gleich real und ideal, aber im Realen als ein Anderes, als ein Seyn, nicht als *Idee.* Die Malerei also, indem sie die Gegenstände vorzugsweise von der idealen Seite darstellt, geht nothwendig auf Darstellung der Ideen als solcher. *Zusatz* 2. Inwiefern die Malerei alle Gegenstände überhaupt nicht unmittelbar und an sich selbst, sondern nur durch ihr Allgemeines, Ideales bedeutet, ist sie allgemein schematisirend. Auf sich selbst bezogen oder in sich selbst ist sie aber nothwendig wieder allegorisch und symbolisch. *Anmerkung. *Das Schematisirende ist allgemeines Princip der modernen Religion. Daher die Malerei in der neueren Welt vorherrschend. (Warum nicht Plastik?) Die Mutter Gottes von Michelangelo = Juno."}, {"type": "paragraph", "text": "§. 89. *Die Malerei ist bloß allegorisch in denjenigen Gegenständen, die nicht um ihrer selbst willen dargestellt werden. - *Denn was nicht um seiner selbst willen, bloß um eines andern willen, ist es *bedeutend. Anmerkung. *Hierher gehören die untergeordneten Gattungen des Still-Lebens, der Blumen- und Frucht-, sowie im Ganzen auch der Thierstücke. Alle diese Gattungen sind entweder überhaupt keine Kunstgattungen oder von allegorischer Bedeutung. Was Thierstücke insbeondere betrifft, so ist die Natur in der Produktion der Thiere selbst gewissermaßen allegorisch, sie deutet ein Höheres, die menschliche Gestalt an, es sind unvollkommene Versuche, die höchste Totalität zu produciren. Selbst der Charakter, den sie in das Thier wirklich gelegt hat, spricht sich in ihm nicht vollkommen aus, sondern ist bloß angedeutet und wird errathen. Aber auch der bekannte Charakter des Thiers ist nur eine einseitige Erscheinung des Totalcharakters der Erde, und inwiefern dieser im Menschen am vollkommensten ausgedrückt ist, des Menschen."}, {"type": "paragraph", "text": "§. 90. *Die Malerei ist bloß schematisirend in der*"}, {"type": "paragraph", "text": "*Landschaft. - *Denn es wird in dieser nicht das wahrhaft Gestaltete, Begrenzte und durch dieses das Unbegrenzte dargestellt, vielmehr wird umgekehrt das Begrenzte hier durch das Unbegrenzte und Formlose angedeutet; das Geformte wird durch die Form symbolisirt, welche formlos. Demnach schematisirend."}, {"type": "paragraph", "text": "§. 91. *Die Malerei innerhalb ihrer Grenzen erhebt sich zum Symbolischen, sofern der dargestellte Gegenstand die Idee nicht bloß bedeutet, sondern es selbst ist.*"}, {"type": "paragraph", "text": "§. 92. * Die unterste Gattung des Symbolischen ist, wo sie sich mit dem Symbolischen begnügt, das der natürliche Gegenstand an und für sich selbst hat, d.h. wo sie bloß nachahmt. Zusatz.* Da kein natürlicher Gegenstand außer der menschlichen Gestalt wahrhaft symbolische Bedeutung hat, so ist dieses der Fall des *Portraits.*"}, {"type": "paragraph", "text": "§. 93. * Die höhere Stufe des Symbolischen ist, wo das Symbolische der Natur wieder zur Bedingung eines noch höheren Symbolischen gemacht wird. *Ist von selbst klar."}, {"type": "paragraph", "text": "§. 94. *Wird das Symbolische der Natur nur zur Allegorie der höheren Idee gemacht, so entsteht die Allegorie*"}]}, {"page_pdf": 1730, "page_book": 568, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "*der höheren Art.* Bemerken *Sie *hiebei, daß die erste Stufe des Symbolischen hierdurch insofern doch überschritten ist als jenes schon wieder zur Bedingung oder Form und nicht zum Gegenstand der Darstellung gemacht wird. Ein allegorisches Gemälde in diesem Sinn ist im niedereren Sinne symbolisch, inwiefern es nämlich die menschliche Gestalt in ihrer Schönheit zur Bedingung der Allegorie macht, der höheren Intention nach aber allegorisch."}, {"type": "paragraph", "text": "§. 95. *Schlechthin symbolisch ist die Malerei, wenn sie absolute Ideen im Besonderen so ausdrückt, daß jene und dieses absolut Eines sind.*"}, {"type": "paragraph", "text": "§. 96. * Erklärung. Die Malerei als schlechthin symbolisch kann allgemein historisch heißen insofern, als das*"}, {"type": "paragraph", "text": "*Symbolische, indem es ein anderes bedeutet, zugleich es selbst ist, und also eine von der Idee unabhängige, historische Existenz an sich hat.*"}, {"type": "paragraph", "text": "§. 97. * Das historische Gemälde ist symbolisch-historisch, wo die Idee das Erste ist, und das Symbol erfunden ist, um sie darzustellen. Beispiele:* Das jüngste Gericht von Michel Angelo, die Schule von Athen und der Parnaß von Raphael."}, {"type": "paragraph", "text": "§. 98. *Das Gemälde ist historisch-symbolisch, wo das Symbol oder die Geschichte das Erste ist, und diese zum Ausdruck der Idee gemacht wird. -* Dieß ist das historische Gemälde in der gewöhnlichen Bedeutung."}, {"type": "paragraph", "text": "§. 99. *Das Symbolische in dem Gemälde findet in dem Verhältniß statt, in welchem der Ausdruck des Absoluten erreicht ist.*"}, {"type": "paragraph", "text": "§. 100. * Die erste Forderung an das symbolische Gemälde ist daher Adäquatheit der Ideen, Aufhebung des Verworrenen im Concreten *- was Winkelmann die hohe Einfalt genannt hat. (Bemerken *Sie*, daß dieß nur vom symbolischen Gemälde im höchsten Styl, nicht aber von der Malerei überhaupt und schlechthin betrachtet gesagt ist)."}, {"type": "paragraph", "text": "§. 101. *Aus dieser Forderung folgt von selbst, daß Seyn und Thätigkeit in dem Gegenstand eins seyen. *- Denn wenn durch die Thätigkeit im Gegenstand das Seyn, durch die Form das Wesen verworren wird, wird die Adäquatheit der Vorstellung aufgehoben. Also gemäßigte Thätigkeit, die das Seyn und Gleichgewicht des Wesens nicht aufhebt. - Winkelmanns ruhige Größe."}, {"type": "paragraph", "text": "§. 102. *Da die Schönheit das an und für sich und absolut Symbolische ist, so ist Schönheit das höchste Gesetz der malerischen Darstellung.*"}, {"type": "paragraph", "text": "§. 103. * Die Malerei kann das Niedrige darstellen nur, inwiefern es als das Entgegengesetzte der Idee doch*"}]}, {"page_pdf": 1731, "page_book": 570, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "*wieder Reflex derselben und also das umgekehrt Symbolische ist. *- Dieser Satz hat eine allgemeine Gültigkeit für die Darstellung der schönen Kunst überhaupt. Sie kann sich in die Sphäre des Niedrigen nur begeben, inwiefern sie auch in dieser wieder das Ideal erreicht und es völlig umkehrt. Diese Umkehrung ist überhaupt das Wesen des *Komischen. *In diesem Sinn haben auch die Alten komische und niedrige Darstellungen. Es ist damit, wie mit der allgemeinen Ansicht der Welt, welcher gemäß man sagen kann, daß die Weisheit Gottes am meisten in der Thorheit der Menschen objektiv werde. So kann die höchste Weisheit und innere Schönheit des Künstlers sich in der Thorheit oder Häßlichkeit desjenigen spiegeln, was er darstellt, und nur in diesem Sinn kann das Häßliche Gegenstand der Kunst werden, indem es durch diesen Reflex gleichsam aufhört es zu seyn. Ich gehe nun zu der dritten Form der bildenden Kunst über und verfahre in Construktion derselben ebenso wie in Construktion der vorhergehenden."}, {"type": "paragraph", "text": "§. 104. *Lehnsatz. Die vollkommene Ineinsbildung oder Indifferenz der beiden Einheiten, im Realen ausgedrückt, ist die Materie selbst, dem Wesen nach betrachtet. *- Nach §. 71 ist die Materie, als *Potenz* betrachtet, die reale Einheit. Inwiefern sie aber alle Einheiten wieder in sich begreift, d.h. dem Wesen nach betrachtet, ist sie = Indifferenz = dritter Einheit. *Zusatz.* Um den Zusammenhang mit dem Vorhergehenden einzusehen, bemerke ich Folgendes: Die Construktion der Materie beruht auf drei Potenzen, aber diese sind allgemeine Kategorien, so daß, wie die Materie im Einzelnen, auch die Natur im Ganzen wieder auf denselbigen beruht. Durch die erste Potenz ist die Materie anorgisch, dem Schema der geraden Linie untergeordnet, durch die zweite organisch, durch die dritte Ausdruck der Vernunft. Dieselben Potenzen kehren aber in Ansehung * des Ganzen *der Materie selbst wieder zurück. Die Materie ist im Ganzen wieder anorgisch, und organisch, und nur in der dritten Potenz, im menschlichen Organismus, Ausdruck der Vernunft."}, {"type": "paragraph", "text": "Dieß angewendet auf den vorliegenden Fall, so ist die Musik die anorgische Kunst, die Malerei organisch, denn sie drückt in der höchsten Stufe die Identität der Materie und des Lichts aus. Erst in der dritten Kunstform wird sie absoluter Ausdruck der Vernunft. Wir behaupten nun: \"die vollkommne Indifferenz der beiden Einheiten, im Realen ausgedrückt, sey die Materie dem *Wesen *nach betrachtet.\" Das *Wesen * der Materie nämlich ist die Vernunft, deren unmittelbarer Ausdruck im Stoff der Organismus ist, sowie der Organismus als das Wesen der anorgischen Materie sich wieder in dieser symbolisirt. Die erste Potenz ist das bloße *Anorgische,* Geradlinige, die Cohäsion. Der Kunst der * ersten *Potenz also, die bloß die erste Potenz zum Mittel der Darstellung nimmt, wird die Cohäsion im *Klang* zum Leib. Die zweite Potenz beruht auf dem Gleichseyn des Lichts und des Körpers durch verschiedene Stufen: *organisch. *Endlich die dritte Potenz ist das * Wesen*, das *An-sich *der ersten und der zweiten Potenz; denn da die verschiedenen Potenzen sich bloß dadurch von einander unterscheiden, daß in der ersten das Ganze, aber untergeordnet der Endlichkeit, ebenso in der zweiten das Ganze, aber untergeordnet der Unendlichkeit oder Identität erscheint, so ist in allen Potenzen das *Wesen *oder An-sich dasselbe."}, {"type": "paragraph", "text": "§. 105. *Die Kunstform, welcher die Indifferenz der beiden Einheiten oder das Wesen der Materie zum Leib wird, ist Plastik in der allgemeinsten Bedeutung des Worts.* - Denn die Plastik stellt ihre Ideen durch reale körperliche Gegenstände dar, anstatt daß die Musik von der Materie bloß das Anorgische (die Form, das Accidens), die Malerei das rein Organische als solches, das Wesen, das rein Ideale des Gegenstandes darstellt. Die Plastik stellt in der realen Form zugleich das Wesen und das Ideale der Dinge, demnach"}]}, {"page_pdf": 1732, "page_book": 571, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "überhaupt die höchste Indifferenz des Wesens und der Form dar. *Folgesatz* 1. Die Plastik ist als Kunst ursprünglich der *dritten Dimension *untergeordnet. *Folgesatz* 2. Wie die Musik im Ganzen die Kunst der Reflexion"}, {"type": "paragraph", "text": "oder des Selbstbewußtseyns, die Malerei der Subsumtion oder der Empfindung ist, so ist die Plastik vorzugsweise Ausdruck der Vernunft oder Anschauung. *Folgesatz* 3. Ueber das Verhältniß der drei Grundformen der Kunst kann ich mich auch so ausdrücken. Die Musik stellt das Wesen in der Form dar, insofern also nimmt sie die reine Form, das Accidens der Dinge als Substanz auf und bildet durch dasselbe. Die Malerei dagegen stellt die Form in dem Wesen dar und bildet, inwiefern das Ideale auch das Wesen ist, die Dinge in dem Wesen vor. Jene daher ist quantitativ, diese qualitativ. Die Plastik dagegen stellt Substanz und Accidens, Ursache und Wirkung, Möglichkeit und Wirklichkeit als Eines dar. Sie drückt also die Formen der Relation aus (Quantität und Qualität als eins). *Folgesatz* 4. Die Plastik ist ihrem Wesen nach symbolisch. - Dieß folgt unmittelbar daraus, daß sie weder allein die Form darstellt (in welchem Fall schematisch), noch allein das Wesen oder Ideale (in welchem Fall allegorisch), sondern beides in der Indifferenz, so daß weder das Reale das Ideale noch das Ideale das Reale bedeutet, sondern beide absolut eins sind."}, {"type": "heading", "text": "§. 106.", "level": null}, {"type": "paragraph", "text": "*Die Plastik für sich allein faßt alle andern Kunstformen als besondere in sich, * oder:* sie ist in sich selbst wieder und in abgesonderten Formen Musik, Malerei und Plastik.* Dieß folgt daraus, daß die Plastik das *An-Sich *der übrigen darstellt, dasjenige, aus dem die andern als besondere Formen hervorgehen. Auch die Musik und die Malerei, jede derselben, faßt wieder alle Einheiten in sich. In der Musik z.B. ist der Rhythmus die Musik, die Harmonie die Malerei, die Melodie der plastische Antheil, aber die Musik faßt diese Formen nicht als abgesonderte Kunstformen, sondern als Einheiten von ihr selbst in sich. Ebenso die Malerei. Die Meinung ist aber, daß in der Plastik als der Totalität aller bildenden Kunstformen diese wieder *abgesondert *von einander enthalten seyen. *Erläuterung.* Die Musik, sagten wird, nimmt die Einbildung"}, {"type": "paragraph", "text": "der Einheit in die Vielheit rein als solche zur Form. Aber eben diese ist ja auch wieder eine Potenz der Materie, dem Wesen nach betrachtet; sie kann also auch selbst wieder körperlich ausgedrückt werden. Die Musik stellt diese Einheit nicht durch Körper dar, sondern nur als Akt und insofern ideal. Aber sowie diese selbige Einheit in der Materie auch real, nämlich in der Körperreihe dargestellt ist, so kann und muß sie auch in der Plastik wiederum, nur nicht *bloß *durch die Form, sondern zugleich wesentlich, also weil Wesen und Form zusammengenommen *Körper *ist, körperlich ausgedrückt werden. Dasselbe läßt sich von der Malerei zeigen. Aber diese nimmt die *ideale *Einheit nur als Potenz und insofern als Form auf. Aber dieselbige muß auch real, demnach körperlich und durch die Plastik ausgedrückt werden können. Ich bemerke zum voraus, daß die drei Kunstformen Musik, Malerei und Plastik, sofern sie in der Plastik als abgesonderte Formen wiederkehren, die *Architektur*, das *Basrelief *und die *Plastik *sind, die letzte im engeren Sinn, sofern sie nämlich runde Figuren und von allen Seiten darstellt. Ich werde nun auch die Construktion der drei Formen nach der angegebenen Ordnung vortragen."}]}, {"page_pdf": 1733, "page_book": 573, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "§. 107. *Die anorgische Kunstform oder die Musik in der Plastik ist die Architektur. *- Der Beweis beruht auf mehreren Mittelgliedern, welche folgende sind: Daß die Architektur überhaupt eine Art der Plastik sey, erhellt von selbst, da sie ihre Gegenstände durch körperliche Dinge darstellt. Daß sie aber die Musik in der Plastik sey, ist auf folgende Art einzusehen. Es muß überhaupt eine solche Kunstform in der Plastik vorkommen, durch welche sie zum Anorgischen zurückstrebt. Da sie aber ihrem innersten Wesen nach organisch ist, so wird dieses Zurückstreben nach keinem andern Grund oder Gesetz geschehen können, als nach welchem auch der Organismus in der Natur wieder zur Produktion des Anorgischen zurückgeht. Nun geht aber der Organismus (ein Satz, der in der Naturphilosophie bewiesen und hier nur als Lehnsatz aufgenommen wird) zu dem Anorgischen nur in den Produktionen des Kunsttriebs der Thiere zurück. Die anorgische Form wird also innerhalb"}, {"type": "paragraph", "text": "der Plastik nur nach dem Gesetz und Grund der Kunsttriebe stattfinden können. Wir haben jetzt also dieses zu bestimmen. In der Naturphilosophie ist bewiesen, daß der sogenannte Kunsttrieb der Thiere nichts anderes als eine bestimmte Richtung oder Modification des allgemeinen Bildungstriebs ist; und der vornehmste Beweis, den ich hier anführen kann, ist, daß der Kunsttrieb in den meisten Gattungen als Aequivalent des Zeugungstriebs auftritt. So sind es die geschlechtslosen Bienen, die nach außen die anorgischen Massen ihrer Zellen produciren. In andern Gattungen begleiten die Erscheinungen des Kunsttriebs die der Metamorphose oder der Geschlechtsentwicklung, so daß mit dem entwickelten Geschlecht auch der Kunsttrieb verschwindet. In andern Gattungen gehen die Aeußerungen des Kunsttriebs der Zeit der Begattung voran. - Schon die bisherige Betrachtung führt uns darauf, eine gewisse Identität zwischen den Produkten und dem Producirenden in allen Fällen des Kunsttriebs zu erkennen. Die Biene producirt aus sich selbst den Stoff ihres Gebäudes, die Spinne und der Seidenwurm ziehen die Fäden ihres Gespinnstes aus sich selbst. Ja wenn wir noch tiefer heruntergehen, so verliert sich der Kunsttrieb ganz in anorgische Absätze nach außen, die mit dem Producirenden oder dem Thiere in Cohäsion bleiben. Von dieser Art sind die Produkte der Polypen, die die Korallen bewohnen, die Schalen der Mollusken und Austern, ja selbst die steinartigen und harten Bedeckungen mancher Insekten, wie des Krebses, dem deßhalb der Kunsttrieb versagt ist, der sich bei ihm ganz in die Produktion jener Bedeckungen verliert. Die Identität zwischen Producirendem und Producirtem findet hier in dem Maße statt, daß wir, wie Steffens gezeigt hat, diese Produktionen als das nach außen gekehrte Knochengerüste der unteren Thiergattungen betrachten können. Erst auf den höheren Stufen der Organisation gelingt es der Natur diese anorgische Masse nach innen zurückzudrängen und den Gesetzen des Organismus zu unterwerfen. Sowie dieß einigermaßen erreicht ist, z.B. in den Vögeln, wo übrigens das Knochensystem noch sehr unvollkommen ausgeführt ist,"}, {"type": "paragraph", "text": "erscheint die anorgische Masse nicht mehr in unmittelbarer Identität mit dem Producirenden, aber sie tritt doch nicht gänzlich aus der Cohärenz mit ihm. Der Kunsttrieb äußert sich freier in dem Nesterbauen der Vögel, es findet hier eine scheinbare Wahl statt, und das Produkt empfängt den Abdruck eines höheren, inneren Lebens."}]}, {"page_pdf": 1734, "page_book": 575, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Noch weiter geht diese scheinbare Freiheit in Bildung eines von dem organischen Wesen unabhängigen, obgleich zu ihm gehörigen Produkts in dem Bau des Bibers. Fassen wir alle Verhältnisse zusammen, so ergibt sich von selbst das Gesetz, daß das Organische das Anorgische überall nur in der Identität oder in der Beziehung auf sich selbst producirt, und wenn wir die Anwendung auf den höheren Fall, die Produktion des Anorgischen durch menschliche Kunst, machen, daß *das Anorgische, weil es an und für sich keine symbolische Bedeutung haben kann, sie in der Produktion durch menschliche Kunst, durch die Beziehung auf den Menschen und die Identität mit ihm erhalten muß*, und daß also, da diese Beziehung und mögliche Identität, bei der Vollendung der menschlichen Natur in sich, nicht eine unmittelbare, körperliche, sondern nur eine mittelbare, durch den Begriff vermittelte Beziehung seyn kann, daß - aus diesen Gründen - die Plastik, inwiefern sie im Anorgischen producirt, etwas Aeußeres in der *Beziehung *auf den Menschen und sein Bedürfniß stehendes, und doch sowohl von ihm Unabhängiges als an sich Schönes produciren muß, und weil dieß nur in der Architektur der Fall seyn kann, so folgt, daß sie demnach Architektur seyn muß. *Verschiedene Anmerkungen.* 1) Daß Architektur = Musik, folgt vorerst nur aus dem gemeinsamen Begriff des Anorgischen. Denn die Musik ist allgemein die anorgische Kunstform. 2) Eine Frage, welche uns die angegebene Construktion der Architektur von selbst aufdringt, ist: inwiefern eine Kunst, die dem Bedürfniß untergeordnet einem Zweck außer ihr dient, unter die schönen Künste gezählt werden könne. Schöne Kunst ist in sich absolut, also"}, {"type": "paragraph", "text": "ohne äußeren Zweck, nicht Sache des Bedürfnisses. Aus diesem Grunde haben wirklich mehrere die Architektur ausgeschlossen. Folgendes ist die Auflösung dieses scheinbaren Widerspruchs. Daß die Kunst als schöne Kunst keinem Zwecke untergeordnet seyn könne, ist ein Axiom der richtigen Ansicht, und inwiefern sie wirklich untergeordnet, insofern ist sie auch wirklich nicht schöne Kunst. Die Architektur z.B., sofern sie *bloß *das Bedürfniß und die Nützlichkeit bezweckte, wäre nicht schöne Kunst. Allein für die Architektur als schöne Kunst ist die Nützlichkeit und die Beziehung auf das Bedürfniß selbst nur *Bedingung*, nicht Princip. Jede Art der Kunst ist an eine bestimmte Form der Erscheinung gebunden, die mehr oder weniger unabhängig von ihr existirt, und nur, *daß * sie in diese Form den Abdruck und das Bild der Schönheit legt, erhebt sie zur schönen Kunst. So ist in Ansehung der Architektur eben die *Zweckmäßigkeit *die Form der Erscheinung, nicht aber das Wesen, und in dem Verhältniß, in welchem sie Form und Wesen eins macht, in welchem sie diese Form, die an sich auf Nützlichkeit geht, zugleich zur Form der Schönheit macht, in dem Verhältniß erhebt sie sich zur schönen Kunst. Alle Schönheit ist überhaupt Indifferenz des Wesens und der Form - Darstellung des Absoluten in einem Besondern -. Das Besondere, die Form ist nun eben die Beziehung auf Bedürfniß. Allein wenn nun die Kunst in diese Form den Ausdruck des absoluten Wesens legt, so wird nur auf diese Indifferenz der Form und des Wesens selbst, keineswegs auf die Form *für sich* gesehen, und das besondere Verhältniß oder die besondere Beziehung dieser Form auf Nutzen und Bedürfniß fällt gänzlich hinweg, da sie überhaupt nur in der Identität mit dem Wesen angeschaut wird. Architektur als schöne Kunst ist also ganz wieder außer der Beziehung auf das Bedürfniß, welche bloß die Form ist (wie und in welcher Beziehung, dieß ist noch genauer in der Folge auseinander zu setzen); die Form aber wird hier gar nicht mehr an sich, sondern nur in der Indifferenz mit dem Wesen betrachtet. Noch andere zur Aufklärung dieses Punktes dienende *Bemerkungen.*"}]}, {"page_pdf": 1735, "page_book": 577, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "a) Schöne Kunst wird durch äußere Bedingungen und Beschränkungen nie aufgehoben oder unmöglich gemacht, z.B. bei Alfresco-Gemälden, wo ein bestimmter Raum nicht nur von bestimmter Größe sondern auch Form vorgeschrieben ist. b) Es gibt Gattungen der Architektur, wo das Bedürfniß, die Nützlichkeit ganz hinwegfällt, und ihre Werke selbst schon Ausdruck vom Bedürfniß unabhängiger und absoluter Ideen sind, ja, wo sie sogar symbolisch wird, in Tempelräumen (Tempel der Vesta nach dem Bild der himmlischen Umwölbung). c) Das, was an der Architektur sich eigentlich auf Bedürfniß bezieht, ist das Innere, an dieses aber wird die Forderung der Schönheit auch bei weitem zufälliger gemacht, als an das Aeußere. *Folgesatz.* Die Architektur bildet nothwendig nach arithmetischen oder, weil sie die Musik im *Raume* ist, nach geometrischen Verhältnissen. - Der Beweis ist in Folgendem enthalten. 1. Es ist früher bewiesen worden, daß Natur, Wissenschaft und Kunst in ihren verschiedenen Stufen die Folge vom Schematischen zum Allegorischen und von da zum Symbolischen beobachtet. Der ursprünglichste Schematismus ist die Zahl, wo das Geformte, Besondere durch die Form oder das Allgemeine selbst symbolisirt wird. Was also in dem Gebiet des Schematismus liegt, ist der arithmetischen Bestimmung unterworfen in der Natur und Kunst, die Architektur, als die Musik der Plastik, folgt also nothwendig arithmetischen Verhältnissen, da sie aber die Musik im Raume, gleichsam die erstarrte Musik ist, so sind diese Verhältnisse zugleich geometrische Verhältnisse. 2. In den tieferen Sphären der Kunst wie der Natur herrschen arithmetische und geometrische Verhältnisse. Auch die Malerei ist in der Linienperspektive noch ganz diesen unterworfen. Auf den höheren Stufen der Natur, sowie der Kunst, wo sie wahrhaft symbolisch wird, wirft sie jene Schranken einer bloß endlichen Gesetzmäßigkeit ab; es tritt die höhere ein, die für den Verstand irrational ist, und nur von der Vernunft gefaßt und begriffen wird: in der Wissenschaft z.B. der höheren Verhältnisse, welche nur die Philosophie, die symbolische unter"}, {"type": "paragraph", "text": "den drei Grundwissenschaften, begreift: in der Natur die Schönheit der Gestalt, welche nur die Einbildungskraft faßt. Es liegt hier der Natur nicht mehr an dem Ausdruck einer bloß endlichen Gesetzmäßigkeit, sie wird Bild der absoluten Identität, das Chaos im Absoluten; das geometrisch Regelmäßige verschwindet und das Gesetzmäßige einer höheren Ordnung tritt ein. Ebenso in der Kunst in der eigentlichen Plastik, welche von geometrischen Verhältnissen am meisten unabhängig, ganz frei nur die der Schönheit an und für sich darstellt, und in Betrachtung zieht. Da nun aber die Architektur nichts anderes ist als ein *Zurückgehen *der Plastik zum Anorgischen, so muß auch in ihr die geometrische Regelmäßigkeit noch ihr Recht behaupten, die erst auf den höheren Stufen abgeworfen wird. Das zuletzt Bewiesene führt uns übrigens noch nicht weiter als eben zur Einsicht der Unabhängigkeit der Architektur von der geometrischen Regelmäßigkeit. Wir begreifen sie dadurch nur von ihrer Naturseite und noch nicht als unabhängige und selbständige Kunst. Als freie und schöne Kunst kann Architektur nur erscheinen, inwiefern sie Ausdruck von *Ideen*, Bild des Universums und des Absoluten wird. Aber reales Bild des Absoluten und demnach unmittelbarer Ausdruck der Ideen ist nach §. 62 überall nur die organische Gestalt in ihrer Vollkommenheit. - Die Musik, welcher die Architektur unter den Formen der Plastik entspricht, ist zwar davon freigesprochen, Gestalten darzustellen, weil sie das Universum in den Formen der ersten und reinsten Bewegung, abgesondert von dem Stoffe darstellt. Die Architektur ist aber eine Form der Plastik, und wenn sie Musik ist, so ist sie *concrete *Musik. Sie kann das Universum nicht bloß durch die Form, sie muß es in Wesen und Form zugleich darstellen. Die organische Gestalt hat ein unmittelbares Verhältniß zur Vernunft, denn sie ist ihre nächste Erscheinung und selbst nur die real-angeschaute Vernunft. Zum Anorgischen hat die Vernunft nur ein"}]}, {"page_pdf": 1736, "page_book": 578, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "mittelbares Verhältniß, nämlich durch den Organismus, der ihr unmittelbarer Leib ist. Die erste Beziehung auch der Architektur auf die Vernunft, bleibt also immer nur eine mittelbare, und da sie nur"}, {"type": "paragraph", "text": "durch den Begriff des Organismus vermittelt seyn kann, eine überhaupt durch *Begriff *vermittelte Beziehung. Soll sie aber eine absolute Kunst seyn, so muß sie an sich selbst und ohne Vermittlung in der Identität mit der Vernunft seyn. Dieß kann nicht dadurch geschehen, daß in dem Stoff nur *überhaupt *ein Zweckbegriff ausgedrückt wird. Denn auch bei dem vollkommensten Ausdruck geht der Zweckbegriff doch, wie er nicht aus dem Objekt *kommt*, auch nicht in das Objekt über. Er ist nicht der unmittelbare Begriff des Objekts selbst, sondern eines Anderen, das außer ihm liegt. Im Organismus dagegen geht der Begriff ganz über in das Objekt, so daß Subjektives und Objektives, Unendliches und Endliches in ihm wahrhaft eins sind, und er dadurch in sich selbst und an sich selbst Bild der Vernunft wird. Wenn die Architektur *unmittelbar *durch Ausdruck eines Zweckbegriffs schöne Kunst werden könnte, so sieht man nicht ein, warum dieß nicht auch andern Künsten freistünde, warum es nicht wie es Baukünstler gibt auch z.B. Kleiderkünstler geben sollte. Es muß also eine innigere, scheinbar aus dem Objekt selbst kommende Identität, eine wahre Verschmelzung mit dem Begriff seyn, was die Architektur zur schönen Kunst macht. Bei dem bloß mechanischen Kunstwerk ist dieser Zusammenhang immer nur subjektiv. (Hiermit ist die letzte Antwort auf jene erste Frage gegeben). Ohne Zweifel war es das Gefühl dieses Verhältnisses, was der herrschenden Meinung über Architektur den Ursprung gab. Nämlich, solang Architektur dem bloßen Bedürfniß fröhnt und nur nützlich ist, ist sie auch *nur * dieses und kann nicht zugleich schön seyn. Dieß wird sie nur, wenn sie davon unabhängig wird, und weil sie dieß doch nicht absolut seyn kann, indem sie durch ihre letzte Beziehung immer wieder an das Bedürfniß grenzt, so wird sie schön nur, indem sie zugleich von *sich selbst *unabhängig, gleichsam die *Potenz *und die freie Nachahmung *von sich selbst *wird. Alsdann, indem sie mit dem Schein zugleich die Realität und den Nutzen erreicht, ohne sie doch *als *Nutzen und als Realität zu beabsichtigen, wird sie freie und unabhängige Kunst, und indem sie das schon mit dem Zweckbegriff verbundene Objekt, also den Zweckbegriff selbst mit dem Objekt zugleich zum Gegenstand macht,"}, {"type": "paragraph", "text": "ist dieses *für sie *als höhere Kunst eine objektive Identität des Subjektiven und Objektiven, des Begriffs und des Dings, und demnach etwas, das *an sich *Realität hat. Obgleich die gewöhnliche Vorstellung von der Architektur als Kunst als einer beständigen Nachahmung, der Baukunst als Kunst des Bedürfnisses nicht eben auf diese Weise abgeleitet zu werden pflegt, so muß doch dieß Raisonnement ihr zu Grunde gelegt werden, wenn sie überhaupt begründet seyn soll. Ich werde diese Ansicht in der Folge mehr im Detail angeben; vorjetzt genügt es, sie im Allgemeinen zu kennen. Um es kurz zu sagen, so sind alle scheinbar-freien Formen der Architektur, von denen niemand leugnet, daß ihnen eine Schönheit an sich zukomme, nach dieser Ansicht Nachahmungen der Formen der roheren Baukunst und insbesondere der Baukunst mit Holz als der einfachsten, und die am wenigsten Bearbeitung erfordert, z.B die Säulen der schönen Baukunst Baumstämmen nachgebildet, die auf die Erde gestellt wurden, um das Dach der ersten Wohnungen zu tragen. Beim ersten Entstehen war diese Form Sache des Bedürfnisses; nachher, da sie durch freie Kunst und Bearbeitung nachgeahmt wurde, erhob sie sich zu einer Kunstform. Die Triglyphen der dorischen Säulen-Ordnung, sagt man, waren ursprünglich die hervorsehenden Köpfe der Querbalken, nachher wurde der Schein davon ohne die"}]}, {"page_pdf": 1737, "page_book": 580, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Realität beibehalten, wodurch also diese Form gleichfalls zu einer freien Kunstform wurde. Dieß mag indessen hinreichend seyn, diese Ansicht im Allgemeinen zu kennen. Was an dieser Meinung wahr ist, fällt auf den ersten Blick ins Auge, nämlich daß die Architektur als schöne Kunst von sich selbst als Kunst des Bedürfnisses die Potenz seyn, oder sich selbst als solche zur Form, zum Leib nehmen muß, um eine unabhängige Kunst zu seyn. Dieß ist auch von uns bereits behauptet worden. Allein eben wie die Form, deren die Baukunst als Handwerk bedurfte, unmittelbar durch die freie Nachahmung oder Parodie - *durch * diesen Uebergang vom Realen zum Idealen selbst eine an sich schöne Form werden könne:"}, {"type": "paragraph", "text": "die Beantwortung dieser Frage liegt weit tiefer, und sicher wird man nicht behaupten wollen, daß jede nothdürftige Form einzig dadurch, daß sie, ohne Noth, nachgeahmt wird, zu einer schönen Form werden könne. Auch ist es ganz unmöglich, alle Formen der schönen Architektur aus dieser bloßen Nachahmung abzuleiten. Hiezu bedarf es also eines höheren Princips, welches wir jetzt abzuleiten haben. Ich schicke zu diesem Behuf folgende Sätze voraus:"}, {"type": "paragraph", "text": "§. 108. *Die Architektur, um schöne Kunst zu seyn, muß die Zweckmäßigkeit, die in ihr ist, als eine objektive Zweckmäßigkeit, d.h. als objektive Identität des Begriffs und des Dings, des Subjektiven und Objektiven, darstellen. Beweis. *Denn nach §. 19 ist Kunst überhaupt nur objektive oder reale Darstellung der Identität des Allgemeinen und Besondern, des Subjektiven und Objektiven, so also, daß diese im Gegenstand selbst als eins erscheinen."}, {"type": "paragraph", "text": "§. 109. *Lehnsatz. Objektive Zweckmäßigkeit *oder objektive Identität des Subjektiven und Objektiven *ist ursprünglich*, d.h. unabhängig von der Kunst, *nur im Organismus.* Folgt aus dem, was ebenfalls früher (§. 17) bewiesen worden."}, {"type": "paragraph", "text": "§. 110. *Die Architektur als schöne Kunst hat den Organismus als das Wesen des Anorgischen, und demnach die organischen Formen als präformirt im Anorgischen darzustellen. *- Dieß ist nun jenes höhere Princip, nach welchem die Formen der Architektur beurtheilt werden müssen. Der erste Theil des Satzes ist so zu beweisen: die Architektur ist die anorgische Form der Plastik nach §. 107. Nun ist aber die Plastik nach §. 105, Folgesatz 2 Ausdruck der Vernunft als des Wesens der Materie. Das unmittelbare reale Bild der Vernunft ist aber, wie schon §. 18 bewiesen wurde, in dem Organismus ausgedrückt. Das Anorgische kann also kein unmittelbares und absolutes Verhältniß zur Vernunft, d.h. ein *solches *Verhältniß haben, welches nicht auf Vermittlung durch Zweckbegriff, sondern auf der unmittelbaren Identität mit der Vernunft selbst beruht, außer inwiefern, ebenso wie die Vernunft als das Wesen, das"}, {"type": "paragraph", "text": "*An-sich *des Organismus unmittelbar in diesem, ebenso der Organismus wieder als das Wesen oder die Wurzel des Anorgischen in diesem dargestellt wird. Also kann auch die Architektur nicht Plastik, d.h. unmittelbarer Ausdruck der Vernunft als der absoluten Indifferenz des Subjektiven und Objektiven seyn, ohne den Organismus als das Wesen, das An-sich des Anorgischen darzustellen. Der zweite Theil des Satzes folgt nun aus dem Beweise des ersten von selbst. Denn da die Architektur die Grenzen des Anorgischen nicht übersteigen soll, da sie die anorgische Kunstform ist, so kann sie den"}]}, {"page_pdf": 1738, "page_book": 582, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Organismus als das Wesen des Anorgischen nur dadurch darstellen, daß sie jenen als begriffen in diesem, demnach die organischen Formen als präformirt im Anorgischen darstellt. Die weitere Erklärung, auf welche Weise sie diese Forderung erfülle, wird durch die Folge von selbst gegeben werden. *Zusatz. *Dasselbe kann auch so ausgedrückt werden: *die Architektur als schöne Kunst hat das Anorgische als Allegorie des Organischen darzustellen. - *Denn sie soll jenes als das Wesen von diesem, aber doch im Anorgischen, d.h. so darstellen, daß dieses nicht selbst organisch ist, sondern das Organische bloß bedeutet. Aber eben dieß ist die Natur der Allegorie."}, {"type": "paragraph", "text": "§. 111. *Die Architektur, um schöne Kunst zu seyn, muß von sich selbst als Kunst des Bedürfnisses die Potenz oder Nachahmung seyn. Beweis. *Denn ihrem letzten Grund nach bleibt sie der Beziehung auf Zweck untergeordnet, indem das Anorgische als solches zur Vernunft nur ein mittelbares Verhältniß, also nie symbolische Bedeutung haben kann. Um also einerseits der Nothwendigkeit zu gehorchen, andererseits sich über sie zu erheben, und die subjektive Zweckmäßigkeit zu einer objektiven zu machen, muß sie sich selbst Objekt werden, sich selbst nachahmen. *Anmerkung.* Es versteht sich von selbst, daß diese Nachahmung nur so weit geht, als dadurch wirklich eine Zweckmäßigkeit* im Objekte *selbst gesetzt wird."}, {"type": "paragraph", "text": "*Der Beweis *ist noch auf andere Art so zu führen. Die Architektur (nach §. 110) hat den Organismus als die *Idee * und das Wesen des Anorgischen auszudrücken. Dieß heißt dem *Zusatz *zufolge soviel: Sie hat das Organische durch das Anorgische anzudeuten, dieses zur Allegorie von ihm, nicht zum Organischen selbst zu machen. Sie fordert also von der einen Seite zwar eine *objektive *Identität des Begriffs und des Dings, von der anderen aber auch keine *absolute*, dergleichen im organischen Wesen selbst ist (denn sonst wäre sie Sculptur). Indem sie nur sich selbst als mechanische Kunst nachahmt, werden die Formen der letzteren Formen der Architektur als Kunst der Nothwendigkeit werden: denn jene sind gleichsam Naturobjekte, die unabhängig von der Kunst als solcher schon da sind, und da sie nach einem Zweck entworfen sind, drücken sie eine objektive Identität des Begriffs und des Dings aus, die insofern (durch die Objektivität) der Identität des organischen Naturprodukts gleicht, von der anderen Seite aber - da jene Identität doch ursprünglich keine *absolute *(sondern eine bloß durch mechanische Kunst hervorgebrachte) war - nur eine Andeutung, Allegorie des Organischen ist. Indem also die Architektur sich selbst als mechanische Kunst nachahmt, erfüllt sie, *indem *sie die Forderungen der Nothwendigkeit befriedigt, zugleich die der Kunst. Sie ist unabhängig vom Bedürfniß und doch zugleich Befriedigung des Bedürfnißes und erreicht also die vollkommene Synthese ihrer Form oder ihres Besonderen (welches darin besteht, daß sie eine ursprünglich zweckmäßige Kunst ist) und des Allgemeinen oder Absoluten der Kunst, welches in einer *objektiven Identität *des Subjektiven und Objektiven besteht; sie erfüllt also die Forderung, die wir gleich anfangs (§. 107, Anm. 2) an sie gemacht haben. *Folgesatz. *Alle diejenigen Formen der Architektur sind an sich schön, in welchen eine Allegorie des Organischen durch das Anorgische ausgedrückt ist, es sey nun, daß diese durch Nachahmung der Formen dieser Kunst als Kunst der Nothwendigkeit oder durch freie Produktion entstehen."}]}, {"page_pdf": 1739, "page_book": 584, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Dieser Satz kann nun als allgemeines Princip der Construktion und Beurtheilung aller architektonischen Formen gelten. Indem er von der einen Seite das Princip, daß die Architektur eine Parodie der mechanischen Baukunst sey, auf die Bedingung beschränkt, daß die Formen derselben durch diese Objektivirung allegorisch für das Organische werden, läßt er diese Kunst in anderer Rücksicht frei über diese Nachahmung hinausgehen, wofern sie nur die allgemeine Forderung, das Organische als präformirt im Anorgischen darzustellen, erfüllt. Es kann hiebei noch allgemein bemerkt werden, daß die Kunst das Anorgische auch in andern Beziehungen nur in jenem Verhältniß zum Organischen nachahmen kann. Nicht der geringste Theil der plastischen Kunst ist die Kunst der *Draperie *und Bekleidung, welche als die vollkommenste und schönste Architektonik betrachtet werden kann. Aber die Kleidung um ihrer selbst willen plastisch auszudrücken, würde keine Aufgabe der Kunst seyn. Nur als Allegorie des Organischen, als andeutend die höheren Formen des organischen Leibs, ist sie einer der schönsten Theile der Kunst."}, {"type": "paragraph", "text": "§. 112. *Die Architektur hat vorzugsweise den Pflanzenorganismus zum Vorbild. -* Denn sie ist nach dem Zusatz zu §. 110 eine Allegorie des Organischen, sofern dieses objektive Identität des Allgemeinen und Besondern ist. Der Organismus κατE dξοχήν aber ist nur der thierische, und in diesem wieder der menschliche Organismus, zu welchem sich der der Pflanze nur als Allegorie verhält. Demnach ist Architektur vorzugsweise nach dem Vorbild des Pflanzenorganismus gebildet. *Anmerkung. *Die Pflanze als Allegorie des Thierischen ist vorzüglich daraus zu begreifen, daß in ihr die Besonderheit herrschend, das Allgemeine also durch die Besonderheit vorgebildet wird. (Größte Aehnlichkeit des menschlichen und Pflanzenorganismus.) *Erläuterung. *Die nahe Verwandtschaft der Architektur mit der Pflanzenwelt können wir von der tiefsten Stufe selbst der rohesten Kunst an verfolgen, wo sie die gleichsam bloß instinktmäßige Hinneigung zu diesem Vorbild zeigt. Die sogenannte *gothische *Baukunst zeigt"}, {"type": "paragraph", "text": "uns diesen Instinkt noch ganz roh, indem in ihr sogar die Pflanzenwelt unverändert durch die Kunst zum Vorbild wird. Es bedarf bloß des Anblicks der ächten Werke gothischer Baukunst, um in allen Formen derselben die unveränderten Formen der Pflanze zu erkennen. Was das Hauptauszeichnende derselben betrifft, die zum Verhältniß des Umfangs und der Höhe schmale Basis, so haben wir uns ein gothisches Gebäude, z.B. einen Thurm, wie das Münster zu Straßburg u.a. als einen ungeheuren Baum vorzustellen, der von einem verhältnißmäßig schmalen Stamm aus sich in eine unermeßliche Krone verbreitet, die ihre Aeste und Zweige nach allen Seiten in die Lüfte streckt. Die Menge kleinerer, auf dem Hauptstamm angebrachter Gebäude, die Nebenthürmchen u.s.w., durch welche das Gebäude von allen Seiten nach der Breite sich ausdehnt, sind nur Darstellungen dieser Aeste und Zweige, eines gleichsam selbst zu einer Stadt gewordenen Baumes, sowie das überall angebrachte und gehäufte Laubwerk unmittelbarer auf dieses Urbild hindeutet. Die Nebengebäude, welche näher an der Erde den ächt-gothischen Werken zugegeben werden, wie die Nebenkapellen an den Kirchen, deuten die Wurzel an, welche dieser große Baum unten um sich verbreitet. Alle Eigenheiten der gothischen Baukunst drücken diese Beziehung aus, z.B. die sogenannten Kreuzgänge in Klöstern, welche eine Reihe von Bäumen vorstellen, deren Zweige oben gegen einander geneigt und in einander verwachsen sind, und auf diese Weise ein Gewölbe bilden. Ich bemerke nur zur Geschichte der gothischen Baukunst, daß es ein offenbarer Irrthum ist, die Gothen als die Urheber des nach ihnen genannten Geschmacks und als diejenigen zu bezeichnen, die diese Form der Architektur nach Italien gebracht. Die Gothen, als ein ganz kriegerisches Volk, brachten weder Architekten noch andere Künstler mit sich nach Italien, und als sie sich dort niederließen, bedienten sie sich der einheimischen Künstler. Nur war unter diesen selbst der Geschmack schon im Verfall, und die Gothen strebten sogar dieß zu verhindern, indem ihre Fürsten das Kunsttalent offenbar"}]}, {"page_pdf": 1740, "page_book": 585, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "aufmunterten und die Kunstausübung begünstigten. Die jetzt gewöhnliche Meinung ist, daß"}, {"type": "paragraph", "text": "die Saracenen diese Baukunst mit nach dem Abendland und zwar zuerst nach Spanien gebracht, von wo aus sie sich über Europa verbreitet. Man beruft sich unter anderem darauf, daß diese Baukunst die eines sehr heißen Himmelstrichs seyn mußte, in welchem man Schatten und Kühle zu suchen hatte. Allein man könnte diesen Grund auch umkehren und die gothische Baukunst für viel einheimischer halten. Wenn Tacitus von den alten Germanen sagt, daß sie keine Tempel gehabt, sondern im Freien unter Bäumen die Götter verehrt, und wenn Deutschland in den ältesten Zeiten ganz mit Wäldern bedeckt war, so läßt sich denken, daß auch beim ersten Anfang der Civilisation in der Bauart, vorzüglich der Tempel, die Deutschen das alte Vorbild ihrer Wälder nachgeahmt haben, daß auf diese Weise die gothische Baukunst in Deutschland ursprünglich heimisch war, und von da aus sich vorzüglich nach Holland und England verpflanzte, wo z.B. das Schloß in Windsor in diesem Styl gebaut ist, und wo sich die reinsten Werke desselben finden, indem anderwärts, z.B. in Italien, er nur gemischt mit dem neueren italienischen existirte. Dieß sind verschiedene Möglichkeiten, über welche nur aus historischen Gründen entschieden werden kann. Ein solcher scheint mir aber wirklich vorhanden zu seyn, da die Ursprünge der gothischen Baukunst noch weiter zurückreichen. Es ist nämlich eine verwundernswerthe und in die Augen springende Aehnlichkeit, welche die indische Bauart mit der gothischen zeigt. Sicher kann diese Bemerkung niemand entgehen, der etwa die Zeichnungen indischer Landschaften und Gebäude von Hodges gesehen hat. Die Architektur der Tempel und Pagoden ist ganz gothischer Art; selbst gemeinen Gebäuden fehlen die gothischen Pfeiler und die spitzigen Thürmchen nicht. Das Laubwerk als architektonische Verzierung ist ohnehin orientalischen Ursprungs. Der ausschweifende Geschmack der Orientalen, der überall das Begrenzte meidet und auf das Unbegrenzte geht, blickt unverkennbar durch die gothische Baukunst hindurch, und diese wird im Kolossalen noch von der indischen Architektur übertroffen, welche Gebäude, die einzeln dem Umfang einer großen Stadt gleichen, ebenso wie die riesenhafteste Vegetation der Erde aufzuweisen hat. Wie dieser ursprünglich indische"}, {"type": "paragraph", "text": "Geschmack sich nachher über Europa verbreitet habe, die Beantwortung dieser Frage muß ich dem Historiker überlassen. Auf eine andere Weise hat sich der kolossale Geschmack in der Baukunst in Aegypten ausgedrückt. Die ewig unveränderliche Gestalt des Himmels, die gleichförmigen Bewegungen der Natur trieben dieses Volk selbst gegen das Feste, das Unveränderliche hin, ein Sinn, der sich in ihren Pyramiden verewigt hat, sowie nach allem, was wir wissen, eben dieser aufs Unwandelbare gerichtete Sinn die Aegypter verhindert hat, jemals anders als mit Stein zu bauen. Daher die cubische Form aller ihrer Werke; die leichtere und rundere Form, deren Vorbild die Architektur von Bäumen und den zur ersten Bauart mit Holz gebrauchten Baumstämmen entlehnt hat, konnte bei ihnen nicht entstehen. Wir gehen zu der höheren Nachbildung der Pflanzenform in der edleren Architektur fort. Die gothische Baukunst ist ganz naturalistisch, roh, bloße unmittelbare Nachahmung der Natur, in der nichts an absichtliche und freie Kunst erinnert. Die erste noch rohe dorische Säule, welche einen behauenen Stamm vorstellt, erhebt mich schon auf das Gebiet der Kunst, indem sie mir die mechanische Bearbeitung durch freie Kunst nachgeahmt, diese also als über das Bedürfniß und die Nothwendigkeit erhaben, auf das Schöne und Bedeutende an sich gerichtet zeigt. Der angegebene Ursprung der dorischen Säule und die Umkehrung des Geschmacks, der die rohe Natur nachahmt, drückt sich in ihrer Form aus."}]}, {"page_pdf": 1741, "page_book": 587, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Der gothische Geschmack muß, weil er den Baum ungeformt darstellt, die Basis verengen und den obern Theil ausdehnen. Die dorische Säule ist, wie der behauene Stamm, nach unten breiter und verjüngt sich nach oben. Die Pflanze ist hier schon zur Allegorie des Thierreichs gemacht, eben weil der rohe Erguß der Natur in ihr aufgehoben und damit angedeutet ist, daß sie nicht um ihrer selbst willen, sondern um ein anderes zu bedeuten da sey. Die Kunst spricht hier die Natur vollkommener aus und verbessert sie gleichsam. Sie nimmt das Ueberfließende und das bloß zur Individualität Gehörige hinweg, und läßt"}, {"type": "paragraph", "text": "nur das Bedeutende bestehen. Der Baum wird theils für sich selbst und in sich selbst zur Allegorie des höheren Organischen, da er, wie dieses, nach oben und unten, durch Haupt und Fuß geschlossen wird, theils wird er es in der Beziehung auf das Ganze, wo er die Säule eines organischen Ganzen bedeutet, wodurch dieses sich über die Erde in die höhere Region des Aethers erhebt. Wie in der Natur die Pflanze nur das Vorspiel und insofern gleichsam der Boden der höheren Entwicklung im Thierreich ist, so zeigt sie sich auch hier; die Säule ist das Stützende, gleichsam die Stufe, die zu dem höheren Gebilde hinaufleitet, das vollkommener schon die Formen der thierischen Organisation verkündet; nur auf ihrem Gipfel, da wo sie die höhere Bildung berührt, und in diese gleichsam übergeht, darf sie ihre eigne Ueppigkeit zeigen und, wie in der korinthischen Säule, in Blättern ranken, die selbst wieder, das erhabenere Gebilde tragend, durch ihre Leichtigkeit und Zartheit die höhere Natur des letzteren andeuten, und uns gleichsam vergessen lassen, daß es den Gesetzen der Schwere unterworfen ist. Es kommt nun darauf an, die Allegorie des höheren Organischen in den einzelnen Formen der Architektur noch bestimmter nachzuweisen."}, {"type": "paragraph", "text": "§. 113. *Die Allegorie des höheren Organischen findet sich theils in der Symmetrie des Ganzen, theils in der Vollendung des Einzelnen und des Ganzen nach oben und unten, wodurch es eine in sich beschlossene Welt wird. -* Es ist schon bei der Malerei bemerkt worden, daß die Natur, wo sie die höchste Indifferenz und Totalität erreicht, im Organischen und vorzüglich im Thierleib, eine doppelte Polarität annimmt, Ost- und Westpolarität, (von oben nach unten findet Differenz statt, *reelle *Polarität, nach der Seite bloß ideelle). Sie producirt daher die edelsten Organe, d.h. diejenigen, in welchen sie am meisten jene letzte Indifferenz erreicht hat, doppelt, und macht das organische Gebilde in zwei symmetrische Hälften zerfallen, die dem Entwurf der Natur nach sich mehr oder weniger gleich sind. Diese *Symmetrie*, welche mehr oder weniger in dem architektonischen Theil der Malerei gefordert wird,"}, {"type": "paragraph", "text": "wird nur noch bestimmter in der Architektur selbst gefordert, und zwar wird sie zur vollkommensten Coincidenz mit dem Bau des *menschlichen *Leibs so gefordert, daß die Linie, welche die beiden symmetrischen Hälften scheidet, nicht horizontal, sondern perpendikular, von oben nach unten, gehe. Diese Symmetrie wird an allen Werken der Baukunst, die Anspruch machen, schön zu seyn, so entschieden gefordert, als sie nur an der menschlichen Gestalt gefordert wird, und der Verstoß dagegen so wenig vertragen als ein schiefes Gesicht oder ein solches, das aus zwei gar nicht zu einander gehörigen Hälften zusammengesetzt scheint. Die zweite das organische Verhältniß andeutende Form ist *die Vollendung *des Ganzen und Einzelnen *nach oben und unten.* Die Natur schließt keine ihrer Bildungen anders als durch eine ganz entschiedene Aufhebung der Succession oder reinen Länge, die sich durch eine concentrische Stellung andeutet. Die Pflanze würde ins"}]}, {"page_pdf": 1742, "page_book": 589, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Unendliche nach der Länge fortsprossen, Knoten auf Knoten treiben - und wirklich kann jede Pflanze durch übermäßigen Zufluß roher Säfte in diesem Sprossungszustand fortwährend erhalten werden - wenn die Natur nicht einen Punkt erreichte, wo sie das, was sie zuvor successiv producirt, zumal producirt. So macht sie es bei dem Produciren der Blüthe in der Pflanze, sie bildet damit einen Kopf, ein bedeutendes Ende. Und auch im Thierreich folgt sie diesem Gesetz, sie schließt das Thier nach oben durch den Kopf, das Gehirn, und auch dieses Ende entsteht ihr nur dadurch, daß sie das, was sie zuvor (in den Nervenknoten) successiv producirte, zumal producirt und ihm eine concentrische Stellung gibt. Dasselbe ist mehr oder weniger in den Formen der Architektur nachzuweisen. Bereits ist erinnert worden, daß die Säule, die vorzüglich nach dem Schema der Pflanze gebildet ist, in der Architektur ausdrücklich auf die Pflanze selbst als die bloße Vorbedeutung, die Stütze des höheren Organischen hindeutet. Aber wie die Natur, wie die höhere Wissenschaft und Kunst selbst überall auch das, was Theil ist, wieder zum Ganzen und als Glied in diesem wieder für sich absolut zu machen"}, {"type": "paragraph", "text": "strebt, so auch die Architektur. Auch die Säule also wird in sich auf eine bedeutende Weise geschlossen. Nach unten erhält sie einen Fuß, das architektonische Gebild wird dadurch ganz aus der Cohärenz mit der Erde gerissen, es steht frei auf ihr wie das Thier, denn wäre die Säule nach unten nicht auf bedeutende Weise geschlossen, so könnte sie, als in die Erde versenkt oder ihre Wurzeln darein senkend erscheinen, das Ganze würde zur Pflanzennatur zurücksinken. Nach oben wird die Säule durch den Kopf auf verschiedene Weise geschlossen, durch das einfache Capitäl der dorischen Ordnung, durch die Schneckenwindungen der jonischen, wo gleichsam als auf der Grenze das höhere Vorspiel des Thierischen beginnt, und in der concentrischen Blätterstellung der korinthischen. Dasselbe findet sich nun wieder im Ganzen, welches nach unten durch die Säulen als die Füße geschlossen wird. Der mittlere Theil des Gebäudes bedeutet den mittleren Theil des Leibes, wo äußerlich die größte Symmetrie herrschen muß, und wo, wie im thierischen Leib, erst das wahrhaft Innere, welches wieder selbständige Ganze für sich bildet, beginnt (und schon bemerkt, daß nach innen auch hier unbeschadet der Schönheit mehr auf das Bedürfniß als auf die Symmetrie gesehen werden kann). Je näher dem Gipfel, desto bedeutender werden alle Formen. Das Fronton bedeutet schon dem Namen nach die Stirne des Gebäudes. Dieß ist der Ort der vorzüglichsten Verzierungen durch Basreliefs, wo die Stirn gleichsam als Sitz der Gedanken äußerlich angedeutet wird. Nach innen schließt sich das Ganze durch das Gebälk, welches seiner inneren Construktion nach eine concentrische Stellung hat und ein sich selbst tragendes und haltendes Ganzes ist. Das Dach, wo es stattfindet, kann als die äußerliche, organisch indifferente Bedeckung betrachtet werden. Der vollkommenste und bedeutendste Beschluß des Ganzen aber ist ein vollkommen gewölbtes Dach, d.h. die Kuppel. Hier ist die concentrische Stellung am vollkommensten, und indem hier sich die einzelnen Theile wechselseitig tragen und unterstützen, entsteht die vollkommenste Totalität, ein Bild des allgemeinen, alles tragenden Organismus und der himmlischen Umwölbung."}, {"type": "paragraph", "text": "§. 114. *Die Architektur hat, als die Musik der Plastik, wie jene einen rhythmischen, harmonischen und melodischen Theil. *- Folgt von selbst aus §. 107."}, {"type": "paragraph", "text": "§. 115. *Der architektonische Rhythmus drückt sich in der periodischen Eintheilung des Gleichartigen*, also"}]}, {"page_pdf": 1743, "page_book": 591, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "vornämlich in folgenden Theilen *aus*: Abnahme und Verjüngung der Säulen nach oben und unten, Größe der Säulenweite, in der dorischen Ordnung insbesondere durch Verbindung der Glieder in Gesimse, Zahl der Triglyphen in einer Säulenweite u.s.w. *Erläuterung. *Die Verjüngung der Säule geschieht in der dorischen Ordnung nach oben in gerader Linie, an der jonischen, der korinthischen ist die Linie, nach der sie abnehmen, eine Curve. Was die Säulenweiten betrifft, so war nach Vitruvius1 bei den Alten fünferlei gebräuchlich, wovon weder die zu geringe, noch die zu große die schönste ist, sondern die mittlere, denn jene gibt dem Ganzen ein zu dickes, diese ein zu mageres Ansehen. Das Rhythmische hierin einzusehen, müssen wir die Erklärung zurückrufen, daß es in einer periodischen Eintheilung des Gleichartigen besteht. In der Musik sind die Weiten Zeitentfernungen, in der Architektur Raumweiten. Die Zahl der Triglyphen ist abhängig von der Säulenweite, indem die beiden äußersten in einem Intercolumnium immer genau über eine Säule zu stehen kommen müssen. Die Glieder des Gesimses sind die verschiedenen größeren und kleineren Theile, woraus diese zusammengesetzt werden. Die Hauptforderung ist, daß sie rhythmisch geordnet seyen, d.h. daß die Menge und Verschiedenheit der Glieder weder das Auge verwirren, noch daß auf der anderen Seite in Ansehung der Form und Größe derselben zu großen Einförmigkeit herrsche. Zwei Glieder derselben Art und Größe dürfen daher nicht unmittelbar unter oder über einander liegen, und das Ganze muß sich gewissermaßen wieder gruppiren, wie in der Musik auch aus schon zusammengesetzten rhythmischen Gliedern wieder größere gebildet werden."}, {"type": "footnote", "text": "1 Lib. III, Cap. 2."}, {"type": "paragraph", "text": "*Zusatz.* Allgemein kann in Ansehung des rhythmischen Theils behauptet werden, daß, was das Schöne, auch zugleich das Nützliche und Nothwendige ist. - Denn das Schöne in der Architektur beruht eben auf der Synthesis des Allgemeinen mit dem Besondern dieser Kunst, welches ihre Beziehung auf Zweck oder Nutzen ist. So ist z.B. die Regel der Verjüngung der Säule nach oben durchaus auch die Regel der Sicherheit und Festigkeit."}, {"type": "paragraph", "text": "*[§. 116.] Die drei Säulenordnungen haben unter sich wieder ein Verhältniß wie Rhythmus, Harmonie und Melodie*, oder sie sind theils vorzugsweise nach rhythmischen theils vorzugsweise nach harmonischen theils endlich nach melodischen Grundsätzen gebildet. - (Die nothwendige und wesentliche Besonderheit bewährt sich in Erklärung der einzelnen Formen.) *Zusatz.* Die *dorische *Säulenordnung ist vorzugsweise die rhythmische. Der Rhythmus ist in der Musik die reale Form, das Wesentliche, das Nothwendige der Musik. So die dorische Ordnung, welche am meisten Nothwendigkeit, am wenigsten Zufälliges hat. Sie ist unter den drei Ordnungen die strenge, realistische, männliche und ohne Ausbildung nach der Breite. Bei ihr läßt sich daher auch der realistische Ursprung aus der Nachahmung der Baukunst als Kunst der Nothwendigkeit noch am meisten nachweisen. Die gewöhnliche Erklärung oder Construktion der dorischen Ordnung in ihren einzelnen Formen ist folgende aus dem bekannten Princip geführte. In der ersten Zeit der noch einfachen Baukunst begnügten sich die Menschen mit einem bloßen Dach, das ihnen Schutz gegen Sonne, Regen und Kälte gab. Die einfachste Weise, dazu zu gelangen, war ohne Zweifel, daß sie in die Erde vier oder mehrere Pfähle steckten, auf welche dann von vorn und hinten erstens ein Querbalken gelegt wurde, um die in gleicher Linie stehenden Balken zu verbinden, und zugleich die Unterlagen für die Hauptbalken zu geben. Der Querbalken bildete den Architrav. Auf diesen Querbalken wurden nun erst die Hauptbalken, die das Gebäude von vorn nach hinten verbinden, gelegt, und zwar in einiger Entfernung, um sie nachher mit Brettern zu überlegen. Die Hervorragungen"}]}, {"page_pdf": 1744, "page_book": 592, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "oder Köpfe dieser Hauptbalken mußten nun natürlich oberhalb des Querbalkens sichtbar seyn, die man erst gerade absägte, nachher des Schmuckes halber Bretter von der nachherigen Form der Triglyphen davor nagelte. Die Triglyphen sind also noch jetzt eine ideale Vorstellung der Köpfe vor den Hauptbalken. Die Zwischenräume zwischen diesen Balken blieben anfänglich in der roheren Baukunst leer, nachher wurden sie, um diesen Uebelstand für das Auge aufzuheben, gleichfalls mit Brettern bedeckt, welche dann in der Nachahmung der schönen Architektur die Veranlassung der *Metopen* geworden, wodurch der gar zu große Raum zwischen den Querbalken und den obersten hervortretenden Brettern (deren Vorsprung, um den Regen abzuhalten, das Karnies bildete) zu einer identischen Fläche wurde, die dann den Zophorus oder Fries bildete. - Im *Allgemeinen *habe ich schon früher gesagt, was von dieser Erklärungsart zu halten sey. Es ist allerdings eine Nothwendigkeit darin, daß die Architektur, um schöne Kunst zu werden, sich ideal macht, und dadurch das Bedürfniß abstreift. Aber es liegt keine Nothwendigkeit darin, daß die Kunst, wenn sie sich über das Bedürfniß erhebt, die roheren Formen beibehalte, wenn diese nicht an sich schön sind. So ist freilich offenbar die dorische Säule der behauene Baumstamm; sie verjüngt sich deßhalb nach oben, aber sie würde keine Form der schönen Architektur und in ihr beibehalten seyn, wenn sie nicht an sich selbst auf die Weise bedeutend wäre, wie es bereits gezeigt wurde, daß sie nämlich einen Baum vorstellt, der seine besondere Natur abgelegt hat und Vorbedeutung von etwas Höherem wird. So ist es gewiß, daß man die ältesten Säulen dieser Ordnung ohne Kapitäl und Base findet; sie stellen also noch die Bauart dar, wo man die behauenen Baumstämme unmittelbar unter das Dach und auf den flachen Erdboden stützte. Der Säulenfuß und die Plinthe nach unten und das Kapitäl nach oben, kann man sagen, stellen nichts anderes vor als, jene das eine oder die mehreren Bretter, die man unterlegte, damit die Stämme durch die oben aufliegende Last nicht sich senkten oder von der Feuchtigkeit litten, dieses die oben über einander gelegten Bretter, damit der Stamm"}, {"type": "paragraph", "text": "der zu tragenden Last eine größere Fläche darbiete. Allein das Kapitäl wie der Säulenfuß sind doch in der schönen Architektur aus einem viel höheren Grund als dem der Nachahmung beibehalten, nämlich um die Säule nach Art eines organischen Wesens nach oben und unten zu vollenden. Vorzüglich nun tritt dieß in Ansehung der Triglyphen ein; denn wie diese bestimmte Form aus den Balkenköpfen entstehen konnte, ist nicht einmal einzusehen, und man muß dabei doch eine Art von Erfindung zulassen, indem man sie zunächst von den Brettern ableitet, welche - in der späterhin durch die Triglyphen nachgeahmten Form - vor diese hervorragenden Köpfe gesetzt worden1. Die Triglyphen haben also eine mehr oder weniger unabhängige und selbständige Bedeutung. Meine Vorstellung darüber ist diese. Wenn die Architektur überhaupt die erstarrte Musik ist, ein Gedanke, der selbst den Dichtungen der Griechen nicht fremd war, wie schon aus dem bekannten Mythus von der Leyer des Amphion, der durch die Töne derselben die *Steine *bewegt habe sich zusammenzufügen und die Mauern der Stadt Thebe zu bilden - wenn also überhaupt die Architektur eine concrete Musik ist, und auch die Alten sie so betrachteten, so ist es ganz insbesondere die am meisten rhythmische, die dorische oder altgriechische Architektur (denn dorisch hieß überhaupt alles Altgriechische), und auch die Alten mußten sie vorzüglich unter diesem Gesichtspunkt betrachten. Unmöglich konnte ihnen also auch das Allgemeine ferne liegen, diesen rhythmischen Charakter sinnbildlich durch eine Form auszudrücken, die sich der einer Leyer vorzüglich nähert, und eine solche Form sind die sogenannten Triglyphen. Ich will nicht behaupten, daß"}]}, {"page_pdf": 1745, "page_book": 594, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "sie eine Anspielung auf die Leyer des Amphion seyn sollen, auf jeden Fall sind sie eine solche auf die alte griechische Leyer, das Tetrachord, dessen Erfindung einige dem Apollon, andere dem Mercur zuschreiben. Das älteste Musiksystem der Griechen enthielt nicht mehr als vier Töne, in einer einzigen Oktave, den Grundton"}, {"type": "footnote", "text": "1 Cf. Vitruv Lib. IV, cap. 2."}, {"type": "paragraph", "text": "nämlich, den tonus major, die Quinte und die Oktave. Daß wirklich ein solches Tonsystem in den Triglyphen ausgedrückt sey, läßt sich nicht deutlich machen, ohne die Anschauung zu Hülfe zu nehmen, daher ich es der eignen Ansicht überlassen muß, sich davon zu überzeugen. Ich kann zur Bestätigung dieser Vermuthung noch die sogenannten Tropfen der Triglyphen zu Hülfe nehmen. Die gewöhnliche Vorstellung ist, in die hervorragenden Balkenköpfe seyen anfänglich *darum *senkrecht heruntergehende Schlitze gemacht worden, damit das Wasser desto leichter abliefe, und man beruft sich deßhalb auf die unten hängenden Tropfen. Allein die Anzahl derselben steht mit der Anzahl der Rinnen, als welche nämlich die Schlitze betrachtet werden müßten, in keinem Verhältniß. Da in dem System von vier Tönen nur sechs verschiedene Verbindungen von Tönen oder Consonanzen möglich sind, so würde die Sechszahl hier eben für das Zusammenfließen der vier Töne in sechs Consonanzen bedeutend seyn. Die genaue Zusammenstimmung der Verhältnisse der dorischen Ordnung mit musikalischen Verhältnissen ist auch noch auf andere Weise offenbar. Vitruvius gibt das Verhältniß der Breite zu der Höhe der Triglyphen wie 1:1½ oder 2:3 an, welches das Verhältniß einer der schönsten Consonanzen, der Quinte, ist, anstatt daß das andere von ihm für bei weitem weniger schön angegebene Verhältniß von 3:4 der Quarte in der Musik entspricht, die jener an Annehmlichkeit bei weitem nachsteht. Ob man mit solchen Vorstellungen zu viel Absichtlichkeit und Sinn in die architektonischen Formen der Griechen legt, mögen diejenigen beurtheilen, die die Klarheit und das in allen ihren Werken herrschende Bewußtseyn sonst zu erkennen fähig sind."}, {"type": "paragraph", "text": "§. 117. *Der harmonische Theil der Architektur bezieht sich vornehmlich auf die Proportionen oder Verhältnisse und ist die ideale Form dieser Kunst. -* Proportionen finden in der Architektur vorzüglich wegen der Anspielung auf den menschlichen Körper statt, dessen Schönheit eben darauf beruht. Die Architektur, welche in der Beobachtung des Rhythmus noch die hohe, strenge Form behält und auf Wahrheit geht, nähert"}, {"type": "paragraph", "text": "sich also durch Beobachtung des harmonischen Theils der organischen Schönheit, und da sie in Ansehung dieser nur allegorisch seyn kann, so ist die Harmonie eigentlich der ideale Theil dieser Kunst. (Ueber die Harmonie in der Architektur ist vorzüglich Vitruvius zu lesen.) Die Architektur schließt sich auch dadurch ganz an die Musik an, so daß ein schönes Gebäude in der That nichts anderes als eine mit dem Aug empfundene Musik, ein nicht in der Zeit-, sondern in der Raumfolge aufgefaßtes (simultanes) Concert von Harmonien und harmonischen Verbindungen ist. * Zusatz* 1. Die *Harmonie *ist der herrschende Theil der Architektur. - Denn sie ist ihrer Natur nach ideal und allegorisch, und nähert sich als Musik im Raum wieder der Malerei als der idealen Kunstform, und in dieser derjenigen Gattung, welche vorzugsweise auf Harmonie (nicht auf Zeichnung) geht, - der"}]}, {"page_pdf": 1746, "page_book": 596, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Landschaft. Die Harmonie als die ideale Form ist also in ihr, die selbst ihrer Natur nach ideal ist, nothwendig die herrschende. *Zusatz* 2. Die *jonische *Säulenordnung ist die vorzugsweise harmonische. - Der Beweis liegt in der Schönheit aller Proportionen. Sie bildet den wahren Indifferenzpunkt zwischen der noch strengen Art der dorischen Ordnung und der überfließenden Ueppigkeit der korinthischen. Vitruvius1 berichtet, daß die jonischen Griechen, als sie den Tempel der Diana zu Ephesus bauen wollten, die Verhältnisse der altgriechischen oder dorischen Ordnung, deren sie sich bisher bedient hatten, nicht zierlich und schön genug fanden, da diese mehr nach den Verhältnissen der männlichen Gestalt eingerichtet gewesen, indem die Säule mit Kapitäl (ohne Fuß) um sechsmal höher als die Dicke an dem untersten Ende des Stammes war. Sie gaben also ihrer Säulenordnung ein schöneres Verhältniß, indem sie dieselbe (*mit *dem Fuß) achtmal höher machten, als der Stamm dick war, welches dann die Proportionen der weiblichen Gestalt gab. Aus diesem Grunde haben sie auch die *Voluten *nach Aehnlichkeit des weiblichen Haarputzes an den Schläfen"}, {"type": "footnote", "text": "1 Lib. IV, cap. 1."}, {"type": "paragraph", "text": "erfunden, sowie ferner die Kannelirungen die Falten weiblicher Kleider vorstellen. Daß die Proportionen der dorischen und jonischen Ordnung, jene wirklich mehr denen des gedrungenen männlichen Körpers, diese mehr denen des weiblichen Körpers nahe kommen, ist offenbar (da auch wirklich männliche Schönheit rhythmisch, weibliche harmonisch), obgleich diese Analogie von Vitruvius zu weit ausgedehnt worden ist. So haben die Schneckenwindungen des jonischen Knaufs nach meinem Bedünken eine allgemeinere Nothwendigkeit in sich als die der Nachahmung eines zufälligen Kopfschmucks, welches ohne Zweifel eine bloße Vermuthung des Vitruvius ist. Offenbar drücken diese Windungen die Präformation des Organischen im Anorgischen aus; sie sind wie die Versteinerungen der Erde Anspielungen auf das Organische, und wie diese in dem Verhältniß als sie der thierischen Form analoger werden, mehr auf den jüngeren Gebirgen und näher der Oberfläche erst gefunden werden, so bildet auch die anorgische Masse der Säule erst auf der Grenze, die sie mit dem höheren Gebilde macht, sich in Formen, die Vorbedeutungen des Lebendigen sind. Die dorische Säule verjüngt sich, wie schon bemerkt, nach oben in einer geraden Linie - hier die Länge, die Starrheit, der Rhythmus herrschend -, die jonische nach einer Curve, welche die harmonische Form auch in der Malerei ist. Sie ist also selbst im rhythmischen Theil mehr harmonisch. Von den unendlich schönen Proportionen dieser Ordnung, die in ihrer Art wieder so vollkommen sind, als die der andern in der ihrigen - daß man es einem deutschen Baumeister nicht übel nehmen kann, der es sogar für unmöglich hielt, daß sie menschliche Erfindungen seyen, und sie daher unmittelbar von Gott eingegeben glaubte - von diesen Proportionen der jonischen Ordnung will ich nur die ihres Säulenfußes oder der sogenannten Attica anführen, welche durch die Höhe ihrer Glieder, wie sie Vitruvius angibt, die vollkommenste Harmonie, nämlich den harmonischen Dreiklang ausdrückt."}, {"type": "paragraph", "text": "§. 118. *Der melodische Theil der Architektur entsteht*"}, {"type": "paragraph", "text": "*aus der Verbindung des Rhythmischen mit dem Harmonischen. *- Folgt schon aus dem Begriff der"}]}, {"page_pdf": 1747, "page_book": 598, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Melodie im §. 81. Anschaulich aber kann es an der dritten Säulenordnung, der korinthischen, nachgewiesen werden. *Zusatz. * Die* korinthische* Säulenordnung ist vorzugsweise die melodische. - Vitruvius, dessen Bericht vom Ursprung der jonischen Ordnung schon angeführt worden (es sey der Uebergang von den Proportionen der männlichen Gestalt zu denen der weiblichen gewesen), sagt, daß man in der korinthischen von den Proportionen des weiblichen Körpers zu dem des jungfräulichen fortgegangen sey, und wenn dieser Gedanke auch nicht eben der letzte Begriff ist, den man von dem Ursprung dieser Säulenordnung geben kann, so dient er doch vollkommen unsere Gedanken zu erläutern. Die korinthische Ordnung vereinigt mit der harmonischen Weichheit der jonischen wieder die rhythmischen Formen der dorischen, wie der jungfräuliche Leib mit der allgemeinen Weichheit weiblicher Formen die größere Herbheit und Strenge der jugendlichen Formen vereint. Schon die größere Schlankheit der korinthischen Säulen macht in ihnen den Rhythmus bemerklicher. Die Erzählung des Vitruvius von dem Ursprung ihrer Erfindung ist bekannt. Ein junges Mädchen, das eben verheirathet werden sollte, starb, und ihre Amme setzte auf ihren Grabhügel in einem Korb einige kleine Gefässe, die dieses Mädchen im Leben geliebt hatte, und damit diese durch die Witterung nicht so bald verdorben würden, wenn jener offen stände, legte sie einen Ziegel auf den Korb. Da nun dieser zufälliger Weise auf die Wurzel einer Acanthuspflanze gesetzt war, so geschah es, daß im Frühling, da die Blätter und Ranken hervorsproßten, diese an dem auf der Mitte der Wurzel stehenden Korb rings emporwuchsen, und die Ranken, welche dem Ziegel begegneten, genöthigt wurden, sich an ihrer Extremität umzubeugen und Voluten zu bilden. Der Architekt Kallimachos ging vorbei und sah den Korb, wie er von den Blättern umgeben, und da ihm diese Form ausnehmend gefiel, ahmte er sie in den Säulen nach, die er nachher den Korinthern machte. Das Auszeichnende der korinthischen Säule ist nämlich bekanntlich ein hohes"}, {"type": "paragraph", "text": "Kapitäl mit drei übereinanderstehenden Reihen von Akanthusblättern und verschiedenen zwischen denselben sich hervordringenden Stengeln, die sich oben an dem Deckel in Schneckenformen falten. Obgleich es nicht unmöglich ist, daß ein Anblick wie der von Vitruvius erzählte einem aufmerksamen Künstler die erste Veranlassung einer solchen Erfindung gegeben, und auf jeden Fall die erzählte Geschichte, wenn nicht wahr, doch angenehm erfunden ist, so müssen wir doch diesem Blätterschmuck in der Idee eine allgemeinere Nothwendigkeit geben. Es ist die der Anspielung auf die Formen organischer Natur. Die größere Strenge, welche die korinthische Ordnung in dem rhythmischen Theil hat, erlaubt es ihr von der andern Seite mehr die natürliche Schönheit zu suchen, wie der natürliche Putz (Blumen etc.) am meisten der schönen jungfräulichen Gestalt, dagegen dem reiferen weiblichen Alter mehr der conventionelle Schmuck ziemt. Die größte Vereinigung des Entgegengesetzten in der korinthischen Ordnung, des Geraden mit dem Runden, des Glatten mit dem Gebogenen, des Einfältigen mit dem Gezierten gibt ihr eben jene melodische Fülle, durch welche sie sich vor den andern auszeichnet. Es sollte nun noch von den besonderen *Zierathen *der Architektur die Rede seyn, von den Werken der höheren Plastik, die als Basreliefs z.B. den Fronton, oder als Statuen die Eingänge oder einzelne Gipfel des Gebäudes zieren. Allein da bereits im Vorhergehenden angedeutet ist, inwieweit in der Architektur höhere organische Formen anticipirt werden können, so ist die Hauptsache darüber gesagt. Die Architektur braucht auch die geringeren Formen von ihr selbst zur Zierath, z.B. Schilde, womit, sowie mit Stierköpfen, die Metopen ausgefüllt wurden. Wahrscheinlich geschah dieß aus Nachahmung von wirklich aufgehangenen Schilden, wie die am Tempel des Apollon zu Delphos aus der marathonischen Beute. Von den geringeren Formen der Architektur, sofern sie sich in Vasen, Bechern, Candelabern u.s.w. ausdrückt, noch etwas zu erwähnen, wäre gleichfalls überflüssig. Ich gehe daher zu der zweiten Form der"}]}, {"page_pdf": 1748, "page_book": 599, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Plastik fort."}, {"type": "paragraph", "text": "§. 119. *Die Malerei in der Plastik ist das Basrelief. *- Denn das Basrelief stellt seine Gegenstände einerseits zwar auf körperliche Weise, andererseits doch nach dem Schein vor, und bedarf wie die Malerei des Grundes oder der Zugabe des Raums. Die Beschränkung, welche der Malerei eben dadurch gesetzt ist, daß sie außer den Gegenständen auch den Raum darzustellen hat, in welchem diese erscheinen, ist hier noch nicht überwunden, oder, wenn man will, die Plastik kehrt in diese Schranke freiwillig zurück. Sowohl dadurch als durch die Darstellung des Scheins ist das Basrelief als die Malerei in der Plastik anzusehen. *Anmerkung.* Etwas von der Unterscheidung des *Haut- * und *Basrelief *ist zu erwähnen. Beide sind dadurch unterschieden, daß bei jenem, dem erhabeneren Relief, die Figuren stark und über die Hälfte ihrer Dicke aus dem Grund hervorstehen, in diesem aber nicht einmal mit der Hälfte ihrer Dicke sich von dem Grund abheben. Da diese beiden Arten sich nicht wesentlich von einander unterscheiden, so kann das eigentliche Basrelief oder die flach erhabene Arbeit als das, was die besondere Eigenschaft der Gattung am ausgezeichnetsten darstellt, als Repräsentant derselben, genommen werden."}, {"type": "paragraph", "text": "§. 120. §. 120.* Das Basrelief ist selbst innerhalb der Plastik als eine ganz ideale Kunstform zu betrachten. *- Folgt schon daraus, daß = Malerei. Wir werden seine Natur vollkommen erschöpft haben, wenn wir diesen idealen Charakter nach seinen einzelnen Bestimmungen darlegen. Man kann schon zum voraus vermuthen, daß das Basrelief in seiner Art noch idealer seyn müsse als selbst die Malerei, da es von der höheren Kunstform, der Plastik, zur tieferen zurückstrebt. Es hat zwar allerdings darin, daß es uns nur die Hälfte der Figuren, nicht, wie die Plastik, die ganzen, rund gearbeiteten darstellt, sowie in der flachen Erhöhung einen Grund für sich in der Natur. Wenn wir nicht um eine Figur rund herumgehen, sehen wir nur die uns zugekehrte Hälfte, selbst wenn die Figur freisteht, wenigstens vor dem gleichförmigen Hintergrund der Luft. Daß die Figuren nicht erhabener, sondern"}, {"type": "paragraph", "text": "nur mit *flacher *Erhöhung gearbeitet werden, hat, kann man sagen, seinen Grund darin, daß wirklich gesehene Körper in der Entfernung sich nicht mir ihrer ganzen Rundirung abheben, indem dieß von dem Helldunkel abhängig ist, das durch die Luft sich abschwächt. In gleichem Verhältniß aber auch den *Umriß* unbestimmt zu machen, würde theils ganz gegen den Charakter der Plastik seyn, die sich auf Luftperspektive einließe, theils bei der Homogeneität des Hintergrunds die Figur ganz zerfließen machen. Bis hierher also hat das Basrelief den Grund in der Natur. In allem Uebrigen aber ist es eine in den meisten Regeln conventionelle Kunst, die sich von dem Betrachter ausdrücklich etwas vorgeben läßt (wie man sich im Spiel etwas vorgeben läßt), um durch falsche Mittel dem geforderten Effekt gleichzukommen. Es ist ein wechselseitiges Verstehen des Künstlers und Kenners. Von denjenigen, die an die Malerei die Forderung der Illusion machen, und sie in dem Grad vollkommen glauben, in welchem sie uns den empirischen Schein für Wahrheit geltend macht - uns täuscht -, sollte man nach diesem Princip einmal eine künstlerische Entwicklung des Basreliefs fordern. - Einiges von dem *Conventionellen.* a) Es ist so viel möglich im Profil darzustellen; die Verkürzungen sind so viel als möglich zu"}]}, {"page_pdf": 1749, "page_book": 601, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "umgehen, weil diese mit unauflöslichen Schwierigkeiten begleitet sind, welche hier auszuführen zu weitläuftig wäre; daher die Basreliefs der Alten meistens solche Gegenstände darstellen, die ihrer Natur nach die Stellung im Profil erlauben, wie Züge von Kriegern, Priestern, Opferthieren, die in Einer Richtung geschehen. b) Da bei complicirteren Gegenständen es unmöglich ist, Stellungen zu vermeiden, wobei Glieder heraus oder hineinwärts gehen und Gruppirungen nothwendig werden, so nimmt sich das Basrelief die Freiheit solche Gegenstände getheilt vorzustellen, das Ganze also durch das Einzelne bloß anzudeuten. An der Pallas in Dresden, einem der herrlichsten Monumente der uralten, herben, strengen Kunstform, ist in einem längs des Gewandes gehenden Streifen in zwölf"}, {"type": "paragraph", "text": "verschiedenen Feldern ganz im Kleinen die Bezwingung der Centauren durch die Minerva vorgestellt. Das Basrelief macht also auch in dieser Eigenschaft einen beständigen Anspruch an die Besonnenheit des Beschauers und den höheren Kunstsinn, der keine grobe Täuschung verlangt. c) Es ist schon in dem früher Gesagten angedeutet worden, daß das Basrelief keine Rücksicht auf Linienperspektive nimmt. Es geht nie auf Täuschung aus auch nur wie die Malerei. Es zeigt sich auch darin als ganz freie, ideale Kunst, daß es von dem Beschauer fordert die einzelne Figur sich gegenüber zu denken und von ihrer Mitte aus zu beurtheilen. Sollen Figuren wirklich in verschiedener Entfernung vorgestellt werden, so wird nur der Plan etwas erhöht und die Figuren um sehr weniges verkleinert und flacher gehalten, welches die durch die Entfernung verminderte Schattirung ausdrückt. d) Der Grund, welchen das Basrelief mit der Malerei gemein hat, erfordert in ihm weit weniger Sorgfalt der Ausführung als in dieser. Gewöhnlich ist er nur angedeutet, nie perspektivisch ausgeführt."}, {"type": "paragraph", "text": "§. 121. *Das Basrelief hat eine nothwendige Tendenz sich mit andern Kunstformen und vorzüglich der Architektur zu verbinden. *- Denn da es die ganz ideale Form ist, strebt es sich nothwendig mit der realen Form zu integriren, welche die Architektur ist, sowie diese selbst hinwiederum das Bestreben hat sich so viel möglich ideal zu machen. *Anmerkung.* Nicht nur die größeren und kolossalen Werke der Baukunst verschönert das Basrelief, sondern auch die geringeren, die Sarkophagen, Urnen, Becher u.s.w. Das älteste Beispiel ist der Schild des Achilles bei Homer. Die Architektur integrirt sich viel unmittelbarer mit dem Basrelief als mit der Malerei, welches eine viel stärkere μετάβασις åkò Tλλο γένος ist. Das Basrelief ist der Architektur darum mehr verwandt, weil es zu seiner Natur gehört einen gleichförmigen Hintergrund zu haben, welchen die Malerei nur freiwillig annimmt, um sich mit der Architektur zu verbinden. *Zusatz.* Eine Art des Basrelief sind auch die *Münzen * und die *geschnittenen Steine*, theils die tiefgeschnittenen theils die"}, {"type": "paragraph", "text": "Kameen. In Ansehung dieser genügt es, die allgemeine Kategorie anzugeben, unter die sie gehören. Jetzt zur Plastik κατE dξοχήν oder zur Sculptur."}, {"type": "paragraph", "text": "§. 122. *Die Plastik *κατE dξοχήν* ist die Sculptur, sofern sie ihre Ideen durch organische und von allen Seiten unabhängige, also absolute Gegenstände darstellt. *- Denn durch das erste unterscheidet sie sich von der Architektur, durch das andere von dem Basrelief, welches seine Gegenstände im Zusammenhang mit"}]}, {"page_pdf": 1750, "page_book": 603, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "irgend einem Grunde darstellt. *Zusatz* 1. Das plastische Werk als solches ist ein Bild des Universums, welches seinen Raum in sich selbst und keinen außer sich hat. *Zusatz* 2. In der Plastik fällt alle Beschränkung auf einen gewissen Gesichtspunkt hinweg, und das plastische Werk erhebt sich dadurch zu einer Selbständigkeit, die dem malerischen Werke fehlt."}, {"type": "paragraph", "text": "§. 123. *Die Plastik, als der unmittelbare Ausdruck der Vernunft, drückt ihre Ideen vorzugsweise durch die menschliche Gestalt aus.* Beweis. Nach §. 105 ist die Plastik diejenige Kunstform, welcher das Wesen der Materie zum Leib wird. Nun ist aber das Wesen der Materie Vernunft, und als ihr unmittelbarstes reales Abbild der vollkommenste Organismus, und weil dieser nur in der menschlichen Gestalt existirt, menschliche Gestalt. *Anmerkung. *Wollte erstens die Plastik sich durch anorgische Formen ausdrücken, so würde sie diese entweder genau nachahmen, oder sie würde sie selbst als bloße Allegorie des Organischen behandeln. Im ersten Fall wäre kein Grund der Nachahmung, denn in der anorgischen Natur sind keine wahre Individuen, die Nachahmung würde also nichts von dem Nachgeahmten Unterschiedenes hervorbringen und sich nur die unnütze Mühe geben, das, was sie ohne Kunst durch die Natur ebenso vollkommen besitzt, durch Kunst in einem zweiten Abdruck zu besitzen. Im andern Fall fiele sie mit der Architektur zusammen. Wollte die Plastik zweitens zwar organische Wesen, aber z.B. *Pflanzen *darstellen, so sänke sie dadurch wieder unter die Architektur zurück."}, {"type": "paragraph", "text": "Denn da auch die Pflanze keinen ausgezeichneten individuellen, sondern nur einen Gattungscharakter hat, so wäre hier so wenig als in Ansehung des Anorgischen ein Grund der reellen Nachahmung (ein anderes ist die ideelle in der Malerei, die mit Licht und Schatten die Farben wiedergibt); wollte sie aber die Pflanze als Allegorie des höheren Thierischen darstellen, so fiele sie wieder mit der Architektur zusammen. Wenn endlich die Plastik die höheren Thiergattungen nachahmt, so ist auch hier ihr Vermögen sehr durch den Gegenstand beschränkt. Denn auch im Thierreich hat jedes Thier nur den Charakter seiner Gattung, aber keinen *individuellen. *Wenn daher die Plastik Thiergestalten bildet, so ist es nur in folgenden Rücksichten: a) als die allgemeinste kann die angesehen werden, daß obgleich das Thier keinen individuellen Charakter hat, doch die Gattung selbst hier das Individuum ist. Alle verschiedenen Charaktere der Thiere, welche immer ganzen Gattungen gemein sind, sind Negationen oder Beschränkungen des absoluten Charakters der Erde; sie erscheinen als besondere eben deßwegen, weil sie nicht die Totalität ausdrücken, welche nur im Menschen erscheint. Jede Gattung ist also hier Individuum, sowie dagegen im Menschengeschlecht jedes Individuum mehr oder weniger Gattung ist, oder wenigstens seyn muß, wenn es Gegenstand einer Kunstdarstellung seyn soll. Der Löwe z.B. ist nur großmüthig, d.h. die ganze Gattung hat den Charakter eines Individuums, der Fuchs ist nur listig und feig, der Tiger grausam. Wie also das Individuum der Menschengattung dargestellt wird, weil es als Individuum zugleich Gattung ist, so kann die Sculptur von dem Thier zwar immer nur die Gattung, aber diese doch deßwegen darstellen, weil sie an sich eigentlich ein Individuum ist. Dieses Verhältniß der Thiercharaktere ist z.B. der Grund ihres Gebrauchs in der Fabel, in welcher auch das Thier nie als Individuum, sondern nur als Gattung auftritt. Die Fabel erzählt nicht: ein Fuchs, sondern *der *Fuchs, nicht ein Löwe, sondern *der *Löwe. b) Eine andere Rücksicht, in der die Sculptur Thiergestalten bilden kann, ist die Beziehung der Thiere auf den Menschen; in dieser"}]}, {"page_pdf": 1751, "page_book": 604, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Rücksicht erscheinen die Thiere in der Sculptur in der Verbindung mit andern Werken derselben, z.B. der Architektur, wie die ehemaligen Löwen auf dem St. Markusplatz zu Venedig oder andere Thiergestalten, die vor die Eingänge der Paläste oder Kirchen gleichsam als Hüter gesetzt werden, wohin auch die noch symbolischeren oder bedeutenderen Gestalten der Sphinxe gehören. Ebenso die Pferde einer Quadrige als architektonischer Zierath auf dem Gipfel eines Gebäudes, eines Tempels, eines Portals u.s.w. Es versteht sich von selbst, daß die Plastik Thiergestalten bilden kann, sobald diese mit zur Darstellung des eigentlichen Gegenstandes gehören, wie z.B. in Basreliefs, die Opferfeste vorstellen oder die Schlangen in der Gruppe des Laokoon. c) Bisweilen bildet die Plastik Thiere als Attribute oder Nebenbezeichnungen, so den Adler zu den Füßen des Jupiter, der oft auch auf den Gipfel seiner Tempel gesetzt wurde, den Tiger in dem Zuge des Bakchos, die Pferde am Sonnenwagen u.s.w."}, {"type": "paragraph", "text": "*Symbolische Bedeutung der menschlichen Gestalt. Erstens:* Die aufrechte Stellung bei gänzlicher Losgerissenheit von der Erde. - Im organischen Naturreich kommt die aufgerichtete Stellung nur der Pflanze zu, aber sie ist in der Cohäsion mit der Erde. In dem Thierreich, welches den Uebergang von der Pflanze zum Menschen macht, tritt sehr bedeutend die horizontale Stellung ein (es ist eine allmähliche Umkehrung der Pflanze). Mit der horizontalen Stellung ist die Abhängigkeit von der Erde angedeutet. Der Theil des Leibs, welcher die Werkzeuge der Nahrung in sich schließt, bildet ein förmliches Gewicht, wodurch der ganze Leib niedergezogen wird. Die Bedeutung der aufrechten Gestalt ist also wirklich die, welche schon in Ovids Metamorphosen1 bezeichnet ist:"}, {"type": "footnote", "text": "Os homini sublime dedit caelumque tueri Jussit, et erectos ad sidera tollere voltus."}, {"type": "paragraph", "text": "*Zweitens: *Symmetrischer Bau - und zwar so, daß die Linie, welche die zwei Hälften scheidet, auch perpendikular gegen die Erde"}, {"type": "footnote", "text": "1 I, 85. 86."}, {"type": "paragraph", "text": "gerichtet ist. Sie ist Ausdruck der vernichteten Ost- und Westpolarität; und je selbständiger ein Organ producirt wird, desto gewisser ist jener Gegensatz ohne wirkliche Entgegensetzung erreicht. Es gibt eine Sphäre der Metamorphose, wo das Auge z.B. (als Lichtorgan der höchste Ausdruck der Ost-West-Indifferenz) nur einfach oder noch zerstreut und zahlreich ohne bestimmte Symmetrie producirt ist, sowie es ebenfalls merkwürdig ist, daß in denjenigen Organen, welche die unmittelbare Beziehung auf den allgemeinen Ost-Westpolarismus haben, z.B. Respirationsorgane und Herz, Leber und Milz, jener Gegensatz in eine wirkliche Entgegensetzung ausschlägt. *Drittens:* Entschiedne Unterordnung der beiden Systeme, des der Nahrung und Reproduktion und des der freien Bewegung, unter das oberste, dessen Sitz der Kopf ist. Diese verschiedenen Systeme haben an sich eine symbolische Bedeutung, erlangen sie aber erst vollkommen in einer Unterordnung, wie die der menschlichen Gestalt. Diese verhält sich zu den Thiergestalten wieder wie das Urbild, von der jene bloß die auf verschiedene Weise verschobenen Abbilder zeigen. - Die Bedeutung der *einzelnen *Systeme ist diese: Der Mensch ist, wie alle organischen Wesen insofern ein Mittelwesen, als er ursprünglich zwischen Flüssigem und Festem gestellt ist. Die andern Gattungen leben nur auf dem *Grund *des"}]}, {"page_pdf": 1752, "page_book": 606, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Luftmeers, der Mensch erhebt sich am freiesten in ihm. Wie nun die Natur des Menschen an und für sich selbst eine Verbindung des Himmels mit der Erde ausdrückt, so ist diese, zugleich mit dem Uebergang von dem einen zum andern, auch durch seine Gestalt ausgedrückt. Das *Haupt *bedeutet den Himmel und fürnehmlich die Sonne. Wie jener die Erde durch seine Einflüsse regiert, so das Haupt den ganzen Leib durch die seinigen, und was die Sonne im Planetensystem ist, ist das Haupt unter den übrigen Gliedern. Die *Brust *und die dazu gehörigen Organe bezeichnen den Uebergang vom Himmel zur Erde, und bedeuten insofern die Luft. Das Athmen, in welchem die Brust wechselweise steigt und sinkt, zeigt das erste Wechselverhältniß zwischen Himmel und Erde an. In dem *Herz *löst sich zuerst die Starrheit des bloß auf Selbstheit gerichteten Triebs in relative"}, {"type": "paragraph", "text": "Cohäsion auf, daher das Herz der erste Sitz der Leidenschaft, der Zuneigung und Begierde, der Heerd der Lebensflamme. Damit aber dieses Feuer, welches durch die Berührung der Entgegengesetzten sich entzündet, gekühlt werde, wie der Platonische Timäos1 sagt, sind die Lungen oder die Werkzeuge des Athmens zugegeben. Die *Höhlung *des Leibes bedeutet die Umwölbung, welche der Himmel über der Erde bildet, sowie der eigentliche *Unterleib *die im Inneren der Erde wirksame Reproduktionskraft, wodurch sie beständig ihren eignen Stoff verzehrt und zu höheren Entwicklungen vorbereitet, die erst näher der Oberfläche und dem Anblick der Sonne sich hervorthun. Die drei Systeme sind die Grundlage und das Wesentliche des menschlichen Leibs. Außer diesem aber waren ihm noch Hülfsorgane nothwendig, worunter ich die *Füße *und *Hände *verstehe. Die Füße drücken die gänzliche Losgerissenheit von der Erde aus, und da sie die Nähe und Ferne verbinden, bezeichnen sie den Menschen als das sichtbare Bild der Gottheit, der nichts nahe und nichts ferne ist. Homer beschreibt das Schreiten der Juno so schnell als den Gedanken eines Menschen, der viele entlegene Länder, die er bereist hat, in einem Augenblick durchfährt und sagt: hier bin ich gewesen und dort war ich. Die Schnelligkeit der Atalante wird so beschrieben, daß sie im Lauf keine Spur im Sand zurücklasse, über den ihr Fuß geschritten. (Vatikanischer Apoll.) Die Arme und Hände bedeuten den Kunsttrieb des Universums und die Allmacht der Natur, die alles umwandelt und gestaltet. - Wir werden späterhin finden, daß es eben diese Bedeutung der einzelnen Theile des menschlichen Leibs ist, nach welcher sie auch in der Plastik gebildet werden. *Viertens:* Die menschliche Gestalt auch in ihrer Ruhe deutet auf ein geschlossenes und vollkommen abgewogenes System von Bewegungen. Man sieht auch in ihrer Ruhe, daß wenn sie sich bewegen wird, dieß mit dem vollkommensten Gleichgewicht des Ganzen geschehen wird. Auch darin wird die symbolische Bedeutung der menschlichen"}, {"type": "footnote", "text": "1 p. 88. d."}, {"type": "paragraph", "text": "Gestalt als eines Bilds des Universums offenbar. Wie das Universum nach außen nur die vollkommene Harmonie, das Gleichgewicht seiner Gestalt und den Rhythmus seiner Bewegungen erkennen läßt, und dagegen die geheimen Triebfedern des Lebens verborgen, die Werkstätte der Zubereitung und Hervorbringung nach innen gebracht sind, so auch in dem menschlichen Leib. - Das* Muskelsystem *läßt den Leib äußerlich nur als ein geschlossenes System von Bewegungen erkennen, es ist dadurch Symbol des allgemeinen Weltbaus. Die Werkzeuge der Assimilation aber wie die Triebfedern der Bewegung in"}]}, {"page_pdf": 1753, "page_book": 608, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "diesem System sind verborgen; ja in den Göttergestalten ist sogar alle Spur von Adern und Nerven aufgehoben. Diese Beziehung ist der Grund von der Wichtigkeit des Muskelsystems in der Malerei, und vorzüglich in der Plastik. Man mag nun das Muskelsystem mit dem System der allgemeinen Bewegung der Weltkörper, oder, wie Winkelmann einmal thut, mit einer Landschaft, oder etwa mit der Ruhe und Bewegung zugleich, die die stille Fläche des Meeres beständig zeigt, vergleichen, so bleibt immer dieselbe Beziehung. In den Betrachtungen einer schönen Landschaft erkennen wird auch nur die Wirkungen, ohne die inneren Ursachen und die fortwährend thätigen Triebfedern der Bildung zu erkennen; wir ergötzen uns an dem äußerlich dargelegten Gleichgewicht der inneren Kräfte. Ebenso im Muskularsystem. Winkelmann in der Beschreibung des schönen Torso vom Herkules1 sagt: \"Ich sehe hier den vornehmsten Bau der Gebeine dieses Leibes, den Ursprung der Muskeln und den Grund ihrer Lage und Bewegung, und dieses alles zeiget sich wie eine von der Höhe der Berge entdeckete Landschaft, über welche die Natur den mannichfaltigen Reichthum ihrer Schönheiten ausgegossen. So wie die luftigen Höhen derselben sich mit einem sanften Abhang in gesenkte Thäler verlieren, die hier sich schmälern und dort erweitern: so mannichfaltig, prächtig und schön erheben sich hier schwellende Hügel von Muskeln, um welche sich oft unmerkliche Tiefen gleich dem Strome des Mäander krümmen, die weniger dem Gesichte als dem Gefühl"}, {"type": "footnote", "text": "1 a.a.O. Bd. 1, S. 273."}, {"type": "paragraph", "text": "offenbar werden.\" Anderswo vergleicht er das Muskelspiel derselben Gestalt mit einer eben anfangenden Bewegung des Meers, von der man den Grund noch nicht erkennt. \"Sowie in einer anhebenden Bewegung des Meers, sagt er, die zuvor stille Fläche einer nebeligen Unruhe mit spielenden Wellen anwächst, wo eine von der andern verschlungen und aus derselben wieder hervorgewälzt wird, ebenso sanft aufgeschwellet und schwebend gezogen fließt hier ein Muskel in den andern, und ein dritter, der sich zwischen jenen erhebt, und ihre Bewegung zu verstärken scheint, verliert sich in jenen, und unser Blick wird gleichsam mit verschlungen.\" Um es mit Einem Wort zu sagen: die menschliche Gestalt ist dadurch vorzüglich ein verkleinertes Bild der Erde und des Universums, daß das Leben als Produkt der inneren Triebfedern sich auf der Oberfläche concentrirt und als reine Schönheit sich über sie verbreitet. Hier ist nichts mehr, was an das Bedürfniß und die Nothwendigkeit erinnerte, es ist die freieste Frucht der inneren und verborgenen Nothwendigkeit, ein unabhängiges Spiel, das nicht mehr an seinen Grund erinnert, sondern an und für sich selbst gefällt. Hierzu gehört nun nothwendig auch, daß die menschliche Gestalt der fremdartigen Bedeckungen entbehre, die den Thieren zugegeben sind, daß sie auch auf der Oberfläche nur *Organ *sey, unmittelbare Empfänglichkeit mit unmittelbarem Rückwirkungsvermögen. Von manchen Philosophen ist die ursprüngliche Nacktheit des Menschen als ein Mangel, eine Zurücksetzung der Natur beklagt worden. Mit welchem Rechte, sieht man aus dem Bisherigen. Zu der äußeren Erscheinung des Lebens gehören auch die Sinnesorgane und unter diesen vorzüglich das *Auge*, durch welches gleichsam das innerste Licht der Natur hindurchsieht, und das am Haupt wieder als dem Sitz der edelsten Organe nebst der Stirne der ausgezeichnetste Punkt ist. Die menschliche Gestalt ist schon an sich selbst ein Bild des Universums, und ohne noch den Ausdruck in Anschlag zu bringen, der in sie gelegt werden kann, dadurch, daß sie in Handlung gesetzt wird, daß die inneren Bewegungen des Gemüths in ihr gleichsam äußerlich"}]}, {"page_pdf": 1754, "page_book": 610, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "widerhallen. Durch ihre erste Anlage ist sie zu einem vollkommen leitenden Medium der Aeußerungen der Seele gemacht, und da die Kunst überhaupt, die Plastik aber insbesondere Ideen, die über die Materie erhaben sind, dennoch durch äußere Erscheinung darzustellen hat, so ist überhaupt kein Gegenstand der bildenden Kunst angemessener, als die menschliche Gestalt, der unmittelbare Abdruck der Seele und der Vernunft."}, {"type": "paragraph", "text": "§. 124. *Die plastische Kunst ist vorzüglich nach drei Kategorien erkennbar. Die erste ist die Wahrheit oder das rein Nothwendige, welches im Einzelnen auf Darstellung der Formen geht. Die zweite ist die Anmuth, welche auf Maß und Verhältniß beruht. Die dritte, als die Synthesis der beiden ersten, ist die vollendete Schönheit selbst. Anmerkung.* Das Nothwendige oder die Schönheit der *Formen *kann überhaupt als die reale Form, demnach als das rein Rhythmische oder die Zeichnung in der Plastik gedacht werden. - Die Anmuth oder Schönheit der Verhältnisse ist das Ideale; es entspricht dem Helldunkel der Malerei (obschon es ganz von ihm verschieden ist) und der Harmonie in der Musik. Die *vollendete *Schönheit oder die Schönheit der Formen und der Verhältnisse zugleich ist in der Plastik wieder das rein Plastische. Die *Erläuterung*, die ich von diesen Sätzen gebe, wird fast ganz historisch seyn müssen. Es sind nämlich die angegebenen Kategorien dieselben, welche die Bildung der Kunst wirklich durchlaufen hat (bei den Griechen). Der allerälteste Styl war, wie Winkelmann sagt, in der Zeichnung nachdrücklich aber hart, mächtig aber ohne Grazie, und so, daß der starke Ausdruck die Schönheit verminderte. Schon nach dieser Beschreibung, noch mehr aber durch den Anblick solcher Werke, z.B. geschnittener Steine dieser Zeit, ist offenbar, daß in ihnen das rein Nothwendige, die Strenge und Wahrheit das *Herrschende *war. Die Strenge, Bestimmtheit muß in allem Kunstbestreben der Anmuth vorangehen. Wir sehen, daß dieß der Fall in der Malerei gewesen ist, und daß die Meister, die das Zeitalter des Raphael gegründet haben,"}, {"type": "paragraph", "text": "ihre Werke mit der größten Strenge und bis ins Kleine gehender Geduld ausgeführt haben. So mußte auch jener noch herbe Styl der Plastik vorangehen, ehe die süßen Früchte der Kunst reifen konnten. Es war der Weg, den auch Michel Angelo in der Plastik betreten hatte, der aber nicht verfolgt wurde. Der Anfang einer Kunst mit leichten, schwebenden, kaum angedeuteten Zügen deutet auf einen oberflächlichen Kunsttrieb. Nur durch männliche, obgleich harte und stark begrenzte Züge kann die Zeichnung zur Wahrheit und Schönheit der Form gelangen - (Aeschylos). - Wohl eingerichtete Staaten fangen mit strengen Gesetzen an und werden dadurch groß. Jener älteste Styl der griechischen Kunst gründete sich auf ein wirkliches System von Regeln, und war eben deßwegen, wie alles, was nach Regeln geschieht, noch hart und unbeweglich. Der erste Schritt, sich zur Kunst und über die Natur zu erheben, ist, daß man nicht mehr nöthig hat unmittelbar an diese, durch Nachahmung, zu recurriren, und daß man statt des einzelnen und empirischen Vorbilds gleichsam den Typus der Gesetzmäßigkeit vor sich hat, der der Natur selbst bei der Hervorbringung zu Grunde liegt. Ein solches System von Regeln ist gleichsam das geistige Urbild, das nur mit dem *reinen *Verstande gefaßt wird. Weil es aber doch nur ein *gemachtes *System ist, so entfernt sich die Kunst dadurch von der Art der Wahrheit, welche die Natur ihren Produktionen gibt. Aus diesem allerältesten und herben Styl entsprang nun zuerst der *große *Styl, der nach der Darstellung Winkelmanns zwar die Unbiegsamkeit des ersten ablegte, die Härte und jähen Absprünge der Formen in flüssige Umrisse verwandelte, die gewaltsamen Stellungen und Handlungen reifer und ruhiger machte, der aber doch dadurch der große genannt zu werden verdient, daß das Nothwendige und Wahre in ihm das Herrschende blieb. Nur jenes angenommene und insofern ideale System der früheren Hervorbringungen war abgeworfen, indeß blieb ihm im Vergleich der Weichheit und Anmuth der späteren Werke noch das Gerade, das Rhythmische eigen, so daß selbst von den Alten dieser Styl noch"}]}, {"page_pdf": 1755, "page_book": 611, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der eckigte genannt wird. In diesem Styl sind die Werke des Phidias und Polyklet. Noch wurde der"}, {"type": "paragraph", "text": "Richtigkeit und der Wahrheit der Formen ein gewisser Grad der Schönheit aufgeopfert; die Majestät und Großheit der Formen muß eben deßwegen gegen die wellenförmigen Umrisse des anmuthigen Styls als Härte erscheinen, wie auch in der Malerei selbst Raphael gegen Correggio oder Guido Reni hart erscheinen kann. Von diesem hohen Styl ist nach Winkelmann vorzüglich die Gruppe der Niobe ein Denkmal, und zwar nicht sowohl wegen eines Scheins von Härte als wegen des gleichsam unerschaffenen Begriffs der Schönheit und der hohen Einfalt, die darin herrschend ist. Ich führe Winkelmanns Worte an zum Beweis, in welchem Grade dieser gelehrteste aller Kenner das Höhere in der Kunst erkannt hat. \"Diese Schönheit, sagt er1, ist wie eine nicht durch Hülfe der Sinne empfangene Idea, welche in einem hohen Verstande und in einer glücklichen Einbildung, wenn sie sich, anschauend, nahe bis zur göttlichen Schönheit erheben könnte, erzeuget würde, in einer so großen Einheit der Form und des Umrisses, daß sie nicht mit Mühe gebildet, sondern wie ein Gedanke erwecket und mit einem *Hauche * geblasen zu seyn scheinet.\" Das rein Nothwendige oder Rhythmische der Plastik bezieht sich auf die Schönheit der Formen und der Gestalt; der harmonische Theil bezieht sich auf Maß und Verhältniß. Mit der Berücksichtigung derselben in der Kunst tritt der anmuthige oder sinnlich-schöne Styl ein, der, wo er zugleich die rhythmische Schönheit begreift, sich unmittelbar zur vollendeten Schönheit erhebt. Ich folge auch hier ganz den Angaben von Winkelmann, da ich es für ganz unmöglich halte, in den Theilen der Kunst, von welchen er gehandelt hat, höhere Principien erreichen zu wollen. Das Ausgezeichnetste dieses Styls in Vergleich mit dem hohen Styl ist die Anmuth oder *Grazie, *das sinnlich-Schöne. Hierzu wurde erfordert, daß in der Zeichnung alles Eckige vermieden wurde, was zuvor noch in den Werken des Polyklet und der größten Meister herrschend war. \"Die Meister des hohen Styls, sagt Winkelmann2, hatten die Schönheit allein in einer vollkommenen Uebereinstimmung"}, {"type": "footnote", "text": "1 a.a.O. Bd. 5, S. 240. 2 a.a.O. Bd. 5, S. 243."}, {"type": "paragraph", "text": "der Theile und in einem erhabenen Ausdrucke und mehr das wahrhaftig Schöne - worunter er das geistig-Schöne versteht - als das Liebliche - oder das sinnlich-Schöne - gesucht.\" Die höchste Schönheit ist aber, wie das Absolute, immer sich selbst gleich und schlechthin eins. Alle in der Anschauung derselben entworfenen Vorstellungen mußten sich also mehr oder weniger diesem Einen nähern und dadurch auch unter sich gleich und einförmig werden, wie man auch an den Köpfen der Niobe und ihrer Töchter bemerkt, die gleichsam bloß quantitativ, nämlich nach dem Alter und Grad, nicht aber nach der Art der Schönheit verschieden erscheinen. Ueberhaupt konnte, wo nur das Große, Mächtige, nicht das Reizende, sondern das *an sich *Hohe, das innere Gleichgewicht der Seele, die Entfernung von Empörungen des Gefühls und Leidenschaftlichkeit gesucht wurde, jene sinnliche Art der Schönheit, die wir Anmuth nennen, weder gesucht noch angebracht werden. Dieß ist aber nicht so zu verstehen, als ob die Werke der älteren Künstler der Grazie beraubt wären. Nur von dem ältesten, herbsten Styl ließe sich dieß einigermaßen sagen, aber wir müssen auch in Ansehung der Grazie wieder einen Unterschied der geistigeren und der sinnlicheren zulassen. Die ersten Nachfolger der großen"}]}, {"page_pdf": 1756, "page_book": 613, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Künstler des hohen Styls kannten nur die erste und erreichten sie bloß dadurch, daß sie die hohen Schönheiten an den Statuen ihrer *Meister*, die, wie Winkelmann sagt, wie von der Natur abstrahirte Ideen und nach einem Lehrgebäude gebildete Formen waren, mäßigten, und dadurch wieder eine größere Mannichfaltigkeit erhielten. Denn der Begriff jedes Dings ist nur einer, und was nicht nach der Natur, deren Charakter Differenz, sondern nach dem Begriff gemacht ist, ist nothwendig ebenso eins als der Begriff. Von den zwei Arten der Grazie sagt Winkelmann1, es sey mit diesen wie mit der Venus, welche auch eine gedoppelte Natur habe. Die eine sey, wie die himmlische Venus, von höherer Geburt und von der Harmonie gebildet und beständig und unveränderlich wie die ewigen"}, {"type": "footnote", "text": "1 a.a.O. Bd. 7, S. 106. 107."}, {"type": "paragraph", "text": "Gesetze von dieser. Die zweite sey, wie die von der Diana geborene Venus, mehr der Materie unterworfen, eine Tochter der Zeit und nur eine Begleiterin der ersten. Diese lasse sich herunter von ihrer Hoheit, ohne sich zu erniedrigen, und mache mit Mildigkeit denjenigen sich bekannt, die auf sie aufmerksam sind. Jene andere aber sey sich selbst genugsam und biete sich nicht an, sondern wolle gesucht seyn, und sey zu erhaben, um sich sehr sinnlich zu machen. Diese höhere und geistigere Grazie nun ist es, die in den Werken der höheren und älteren Künstler, im olympischen Jupiter des Phidias, in der Gruppe der Niobe u.a. Der zweite Styl der Kunst gesellte nun zu dem ersten oder zur geistigen Anmuth die sinnliche, welche in der Mythologie durch den Gürtel der Venus bedeutet wird. Zuerst in der Malerei (durch Parrhasius), wie begreiflich, da diese Kunst sich unmittelbarer zu ihr hinneigt. Der Erste, der sie in Marmor und Erz ausdrückte, war Praxiteles, der ebenso wie Apelles, der Maler der Grazie, in Ionien, dem Vaterland des Homer in der Poesie und der harmonischen Säulenordnung in der Architektur, geboren war. Es erhellt schon aus der bisherigen Darstellung, daß die eigentlichen Meister des schönen Styls unmittelbar von der hohen, rhythmischen Schönheit zu der vollendeten, welche die Wahrheit der Formen mit der Anmuth der Verhältnisse verbindet, fortgingen, und daß die der hohen Schönheit beraubte, bloß sinnliche Anmuth sich erst einfand, nachdem die Kunst, welche durch jene zwei Stufen zu ihrem Culminationspunkt gelangt war, wieder nach der entgegengesetzten Richtung zu sinken begann. Wenigstens, wenn es Werke der ächten Kunst gibt, welche der sinnlichen Grazie vornehmlich geweiht scheinen, so ist der Grund davon mehr in dem Gegenstand als in der Kunst zu suchen. So war, wenn der Jupiter des Phidias ein Werk des hohen Styls ist, die Venus des Praxiteles allerdings ein durch die sinnliche Anmuth ausgezeichnetes Werk. Ein vollkommenes Beispiel der Verbindung der hohen und geistigen Schönheit, in welcher keine Leidenschaft, sondern nur Größe der Seele erscheint, mit der sinnlichen Anmuth ist die *Gruppe des Laokoon. *Winkelmann hat in Ansehung derselben"}, {"type": "paragraph", "text": "vorzüglich auf die in ihr herrschende Mäßigung des Ausdrucks aufmerksam gemacht. Goethe in einem Aufsatz der Propyläen hat gezeigt, daß sie ebenso ausgezeichnet ist von Seiten einer gewissen sinnlichen Anmuth, die sie im Einzelnen und im Ganzen hat. Wir haben die zwei Kategorien der Plastik, das Reale oder Nothwendige und das Ideale oder die Anmuth bisher bloß in ihrer Allgemeinheit betrachtet. Wir haben nun zu zeigen, wodurch sich jede"}]}, {"page_pdf": 1757, "page_book": 615, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "derselben im Einzelnen ausdrücke. Das Reale oder Nothwendige beruht, wie schon in dem Satz selbst angezeigt ist, auf der Wahrheit und Richtigkeit der *Formen.* Unter dieser Wahrheit wird hier keineswegs jene empirische, sondern jene höhere verstanden, die auf abstrakten, von der Natur und der Besonderheit abgesonderten, mit dem reinen Verstand aufgefaßten Begriffen beruht (dieß als *Anmerkung *zu erinnern) wie die Wahrheit in den Werken des ältesten Styls. Die Wahrheit in dem höchsten Sinne ist das Wesen der Dinge selbst, das aber in der Natur in die Form gebildet und durch die Besonderheit mehr oder weniger verworren und unerkennbar gemacht ist. Deßwegen kann diese höhere Art der Wahrheit nicht unmittelbar aus Nachahmung der Natur entspringen, sondern nur aus einem System von Begriffen, das anfangs einen härteren und eckigen Styl bildet, bis auch dieses System von Regeln selbst wieder zur Natur wird und die Anmuth eintritt, denn das Zeichen der Anmuth ist die Leichtigkeit; alles aber, was durch Natur geschieht, sagt ein Alter, geschieht mit Leichtigkeit. Jene höchste Art der Wahrheit ist, wie schon §. 20 bewiesen, an sich mit der Schönheit eins, und so konnten die Meister des hohen Styls, indem sie bloß nach dieser Art der Wahrheit trachteten, dennoch eben deßwegen und unmittelbar die geistige Schönheit erreichen. Sie ahmten nicht das Individuelle nach, in welchem jederzeit mehr oder weniger Formen sich finden, die sich vollkommener finden lassen, sondern einen allgemeinen Begriff, welchem angemessen kein einzelner oder besonderer Gegenstand existiren konnte. Wie die Wissenschaft das Persönliche - Neigung und Interesse - abstreifen muß, um die Wahrheit an und für sich selbst zu"}, {"type": "paragraph", "text": "erreichen, so haben auch diese sie erreicht, indem sie alles die persönliche Neigung Ansprechende aus ihren Bildern entfernten. Um nun ins Einzelne zu gehen, so beruhte jene abstrakte Wahrheit in Bildung der einzelnen Formen des menschlichen Leibs vorzüglich darauf, das Uebergewicht des Geistes auch körperlich auszudrücken, also denjenigen Organen, welche auf geistigere Verhältnisse deuten, das Uebergewicht über die andern zu geben, die mehr eine sinnliche Bestimmung haben. Hierauf gründet sich das sogenannte griechische Profil, welches nichts anderes als ein Uebergewicht der edleren Theile des Kopfes über die minder edlen andeutet. Hierauf gründet sich die dem *hohen *Styl eigenthümliche Auszeichnung der Augen, die dadurch erreicht wurde, daß sie allezeit tiefer gebildet wurden, als sie insgemein in der Natur erscheinen. Dieß geschah wirklich nach einem ganz abstrakten Begriff, um an diesem Theile mehr Licht und Schatten hervorzubringen, und dadurch das Auge, welches insbesondere an sehr großen Figuren unerkennbarer wurde, als lebhafter und wirksamer auszuzeichnen. Auch in Ansehung des Auges ging man in den früheren Zeiten nicht auf eine Nachahmung, sondern nur auf eine symbolische Bezeichnung der Natur (wie das eben Angeführte beweist), und daraus folgte auch, daß der Augenstern z.B. erst in späteren Zeiten der Kunst besonders angedeutet wurde. Sonst, wie gesagt, bestand die Schönheit der Formen im Einzelnen vorzüglich auf der Mäßigung aller der Theile, welche näheren Bezug auf die Nahrung und überhaupt auf das Thierische oder die Wollust hatten, z.B. des Ueberflusses der weiblichen Brüste, welche die Griechinnen selbst in der Natur zu mäßigen durch künstliche Mittel sich bestrebten. Dagegen wurde die männliche Brust vorzüglich prächtig gewölbt, und zwar in einem gewissen umgekehrten Verhältniß zu der Erhabenheit des Haupts und der Stirne. Die Köpfe des Neptunus, dem die Brust geweiht war, finden sich auf allen geschnittenen Steinen bis unter die Brust ausgeführt, viel seltener die der andern Gottheiten. Der Unterleib erschien ohne eigentlichen Bauch an den edleren Gottheiten, der nur dem Silen und den Faunen zugetheilt wurde. Außer der allgemeinen Mäßigung besonderer Theile strebten die griechischen Künstler"}]}, {"page_pdf": 1758, "page_book": 617, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "auch jene aus männlichem und weiblichen Wesen gemischte Naturen, welche die asiatische Weichlichkeit durch Verschneidung zarter Knaben hervorbrachte, in der Kunst nachzuahmen, und so gewissermaßen einen Zustand der Nichttrennung und der Identität der Geschlechter zu repräsentiren, welcher Zustand, in einer Art des Gleichgewichts erreicht, welches nicht bloße Nullität, sondern wirkliche Verschmelzung der beiden widerstreitenden Charaktere ist, mit zu dem Höchsten gehört, was die Kunst vermag. Was den zweiten Theil der plastischen Kunst, nämlich *Maß *und *Verhältnisse der Theile *betrifft, so ist dieser einer der schwersten, und worüber noch am wenigsten durch Theorie ausgemacht ist. Offenbar zwar ist, daß die griechischen Künstler für das Verhältniß im Ganzen und Einzelnen ihre bestimmten Regeln gehabt; nur aus einem solchen Lehrgebäude über die Proportionen läßt sich die Uebereinstimmung in den Werken der Alten begreifen, die fast alle wie aus Einer Schule zu seyn scheinen. (Die alten Theoristen sind uns verloren gegangen.) Neuere haben zwar empirische Abstraktionen von den Werken der Alten hierüber gemacht, aber allgemeine Gründe oder eine Herleitung dieser Verhältnisse aus solchen Gründen wird noch gänzlich vermißt, und Winkelmann selbst hat über diesen Gegenstand in seine Geschichte der Kunst eine Anleitung von Mengs eingerückt, welche nach dem Zeugniß selbst von Künstlern höchst unverständlich ist. Was also die Ausübung der Kunst betrifft, so kann man bis jetzt, da in der neueren Welt nie wieder eine wahre Kunstschule und ein System der Kunst, wie unter den Alten, sich gebildet hat, den * Lehrling *der Kunst bloß an die empirische Beobachtung der in den schönsten Werken des Alterthums angenommenen Verhältnisse verweisen. Die Theorie aber hat hier eine Lücke, welche auszufüllen noch viel höhere Untersuchungen erfordert werden, die sich nicht bloß auf diesen besonderen Gegenstand, die Proportionen der menschlichen Gestalt, sondern auf ein allgemeines Gesetz aller Proportionen der Natur erstrecken müßten. Die letzte, vollendete Schönheit entspringt aus der Verbindung der beiden ersten Arten, aus der Schönheit der Formen und der Schönheit"}, {"type": "paragraph", "text": "der Verhältnisse. Der höchste Repräsentant dieser Schönheit unter den uns übrig gebliebenen Werken des Alterthums ist die *Statue des Apollon*, von der Winkelmann sagt, sie sey das höchste Ideal der Kunst unter allen. \"Der Künstler, sagt er1, hat dieses Werk ganz auf das Ideal gebaut, und er hat nur ebensoviel von der Materie dazu genommen als nöthig war, um seine Absicht auszuführen und sichtbar zu machen. Ueber die Menschheit erhaben ist sein Gewächs, und sein Stand zeuget von der ihn erfüllenden Größe. Ein ewiger Frühling, wie in dem glücklichen Elysien, bekleidet die reizende Männlichkeit vollkommener Jahre mit gefälliger Jugend und spielt auf dem stolzen Gebäude seiner Glieder.\" In allen Werken dieser Art überhaupt zeigt sich die Hoheit und Größe durch *Anmuth gemäßigt *aber *nicht *erniedrigt, und umgekehrt: die Anmuth ist, beseelt von jener höheren und geistigen Schönheit, zugleich erhaben und streng."}, {"type": "footnote", "text": "1 a.a.O. Bd. 6, S. 260."}, {"type": "paragraph", "text": "§. 125. *Die plastische Kunst ist die vollendete Einbildung des Unendlichen ins Endliche. *Denn *jede *Einheit, z.B. die der Einbildung des Unendlichen ins Endliche, in ihrer Vollendung schließt die andere in sich. Nun ist aber die Plastik unter den realen Kunstformen diejenige, welche die reale Einheit, die der Form, und die ideale, die des Wesens, allein vollkommen gleichsetzt (nach §. 105). Demnach ist sie auch die"}]}, {"page_pdf": 1759, "page_book": 618, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "vollendete Einbildung des Unendlichen ins Endliche. *Anmerkung.* (Musik ist die Einbildung der Einheit in die Vielheit *als solche *als *Form*, daher real; Malerei die Einbildung der Form in das Wesen als solches, daher rein *ideal*.) *Zusatz* 1. Der plastischen Kunst eignet vorzugsweise Erhabenheit. - Nach dem Begriff der Erhabenheit §. 65. Denn diese ist wirklich das im relativen Universum angeschaute wahre Universum. Nun aber kann die Einbildung des Unendlichen ins Endliche in der Plastik wirklich nicht vollendet seyn, ohne daß das Endliche selbst als solches"}, {"type": "paragraph", "text": "zugleich relativ unendlich sey. In der Plastik wird also vorzugsweise das relativ oder sinnlich Unendliche Symbol des an sich und absolut Unendlichen. Die menschliche Gestalt, welche der vornehmste Gegenstand der Plastik ist, muß, um wirklicher, sichtbarer Ausdruck der Vernunft zu seyn, schon durch das rein Endliche an ihr unendlich und ein Universum seyn, wie dieß auch im Vorhergehenden bewiesen worden. *Anmerkung.* Die vorzüglichste Wirkung der Kunst und vorzugsweise der plastischen ist: daß das absolut Große, das *an sich *Unendliche in die Endlichkeit gefaßt, und wie mit *Einem *Blicke gemessen wird. Dieß ist es, wodurch sich die Einbildung des Unendlichen ins Endliche für den Sinn ausdrückt. Das an sich und absolut Große in die Endlichkeit gefaßt, wird dadurch nicht *eingeschränkt *und verliert nichts von seiner Größe, daß es dem Geist in der ganzen Begreiflichkeit eines Endlichen erscheint, vielmehr wird eben durch diese Faßlichkeit uns seine ganze Größe offenbar. Großentheils kommt hierauf zurück, was Winkelmann die *hohe Einfalt *in der Kunst nennt. Man könnte sagen, diese Einfalt in der Größe, mit der sich uns ein hohes Kunstwerk darstellt, sey der äußere Ausdruck jener inneren Einbildung des Unendlichen ins Endliche, die das *Wesen *des Kunstwerks ausmacht. Alles Große erscheint mit Einfalt ausgeführt, sowie dagegen alles Unterbrochene, und was getheilt betrachtet werden muß, uns auch den Eindruck der Kleinheit und bei gänzlicher Ueberladung der Kleinlichkeit gibt. *Zusatz* 2. Der erste Satz ist auch so auszudrücken: die plastische Kunst stellt die höchste Berührung des Lebens mit dem Tode dar. - Denn das Unendliche ist das Princip alles Lebens und von sich selbst lebendig; das Endliche aber oder die Form ist todt. Da nun beide in den plastischen Werken zur größten Einheit übergehen, so begegnen sich hier Leben und Tod gleichsam auf dem Gipfel ihrer Vereinung. Das Universum, wie der Mensch, ist aus Unsterblichem und Sterblichem, Leben und Tod gemischt. Aber in der ewigen Idee ist das dort sterblich Erscheinende zur absoluten Identität mit dem Unsterblichen gebracht"}, {"type": "paragraph", "text": "und nur Form des an sich Unendlichen. Als solche stellt es sich in den plastischen Werken dar, wie Winkelmann in der vorhin angeführten Stelle sagt, der Bildner des Apollon habe nur so viel Materie zu diesem Werke genommen, als nöthig gewesen, seine geistige Absicht auszudrücken. Die Materie und der Begriff sind hier wahrhaft eins; jene ist nur der in Objektivität verwandelte Begriff, also er selbst, nur von einer andern Seite angesehen."}, {"type": "paragraph", "text": "§. 126. *In der Plastik hört die geometrische Regelmäßigkeit auf herrschend zu seyn. * - Denn hier ist nicht eine endliche, mit dem bloßen Verstande, sondern eine unendliche, nur mit der Vernunft zu fassende Gesetzmäßigkeit, die zugleich die Freiheit ist. In Bezug auf endliche Gesetzmäßigkeit ist alle Plastik transscendent."}]}, {"page_pdf": 1760, "page_book": 620, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Die Malerei ist ihr (der geometrischen Regelmäßigkeit) noch unterworfen dadurch, daß sie eine endliche, beschränkte Wahrheit darstellt. Die Malerei hat einzig darum die Linienperspektive zu beobachten, weil sie auf einen endlichen Gesichtspunkt beschränkt ist. Die Plastik geht auf eine allseitige, demnach unendliche Wahrheit. So wenig die Formen des menschlichen Leibs an und für sich selbst durch jene endliche Gesetzmäßigkeit bestimmbar sind, so wenig die des plastischen Kunstwerks. Wenn man die Formen eines schönen Körpers auf Linien ausdrücken will, so sind es solche, die ihren Mittelpunkt beständig verändern, und fortgeführt niemals eine regelmäßige Figur wie den Cirkel beschreiben. Es ist dadurch eine größere Mannichfaltigkeit zugleich und Einheit gesetzt. Größere Mannichfaltigkeit, denn der Cirkel z.B. ist immer sich selbst gleich. Größere Einheit, denn man setze, daß das Gebäude des Leibes aus Formen bestehe, die dem Cirkel gleichen, so würde eine die andere ausschließen, keine aus der andern mit Stetigkeit herfließen, dagegen in einem schönen organischen Leib jede Form als der unmittelbare Ausfluß der andern erscheint, eben deßwegen, weil *keine *insbesondere eine beschränkte ist."}, {"type": "paragraph", "text": "§. 127. *Die Plastik kann vorzugsweise kolossal bilden.* - Dieß ist nämlich der Fall in Vergleichung mit der Malerei und dem Basrelief. *Grund: *weil ganz unabhängig von einem Raume"}, {"type": "paragraph", "text": "bildend, den die Malerei und das Basrelief noch mit dem Gegenstande zugleich darzustellen hat. Wollte die Malerei kolossal bilden, so würde sie den Raum, den sie dem Gegenstande gibt, entweder gleichfalls mit vergrößern, oder nicht. Im ersten Fall bliebe das Verhältniß unverändert, im andern würde, weil die Relation doch nicht aufgehoben ist, nur das Unförmliche entstehen, keineswegs aber das Große. Da alle Schätzung von Größe auf Relationen zu einem gegebenen empirischen Raum beruht, so kann die Kunst das Kolossale, ohne in das Unförmliche zu gerathen, nur insofern bilden, als sie von den Beschränkungen des vom Gegenstand verschiedenen Raums innerhalb ihrer Darstellungen selbst befreit ist. *Anmerkung.* Denn der außer dem Gegenstand zufälligerweise befindliche große oder kleine Raum hat auf die Schätzung seiner Größe keinen Einfluß. - Neuere haben gegen den kolossalen Jupiter des Phidias eingewendet, daß wenn er sich (da er sitzend vorgestellt war) von seinem Thron erhoben, er das Tempeldach hätte einstoßen müssen, und haben dieß als eine Unschicklichkeit angesehen. Ganz unkünstlerisch geurtheilt. Jedes plastische Werk ist eine Welt für sich, das seinen Raum wie das Universum in sich selbst hat, und auch nur aus sich selbst geschätzt und beurtheilt werden muß; der äußere Raum ist ihm zufällig und kann zu seiner Schätzung nichts beitragen."}, {"type": "paragraph", "text": "§. 128. *Die Plastik stellt ihre Gegenstände als die Formen der Dinge dar, wie sie in der absoluten Ineinsbildung des Realen und Idealen begriffen sind.* Von der Musik wurde (§. 83) bewiesen, daß ihre Formen Formen der Dinge sind, wie sie in der realen Einheit existiren, von der Malerei, wie sie in der idealen Einheit vorgebildet sind (§. 88). Da nun (nach §. 105) die Plastik die Kunstform ist, in welcher die absolute Ineinsbildung der beiden Einheiten objektiv wird, so stellt sie auch ihre Gegenstände als Formen der Dinge dar, wie sie in der absoluten Ineinsbildung des Realen und Idealen begriffen sind. *Erläuterung. *Von der Malerei wurde im Zusatz 1. zu §. 88 bewiesen, sie gehe vorzugsweise auf Darstellungen der Ideen als solcher."}]}, {"page_pdf": 1761, "page_book": 622, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Jede Idee nämlich, als das vollkommene Ebenbild des Absoluten, hat wie dieses selbst zwei Seiten, eine reale und ideale. Von jener Seite angeschaut erscheinen die Ideen als Dinge, nur von der idealen erscheinen sie als *Ideen*, obgleich das, worin die beiden Seiten eins sind, selbst wieder * die *Idee ist. Die Malerei stellt also die Ideen vorzugsweise *als Ideen*, d.h. von der idealen Seite dar, die Plastik aber so, daß sie zugleich ganz Idee und ganz Ding sind. Die Malerei gibt ihre Gegenstände keineswegs für real, sondern will sie ausdrücklich als ideal angesehen wissen. Die Plastik, indem sie ihre Gegenstände als *Ideen *darstellt, gibt sie doch zugleich als Dinge, und umgekehrt; sie stellt also wirklich das *absolut Ideale * auch *zugleich als das absolut Reale dar*, und dieß ist ohne Zweifel der höchste Gipfel der bildenden Kunst, wodurch sie in die *Quelle *aller Kunst und aller Ideen, aller Wahrheit und Schönheit, nämlich in die Gottheit zurückkehrt."}, {"type": "paragraph", "text": "§. 129. *Die Plastik kann sich selbst in ihren höchsten Forderungen einzig durch Darstellung der Götter genügen. *- Denn sie stellt vorzugsweise die absoluten Ideen dar, die als ideal zugleich real. Aber die Ideen, real angeschaut, sind Götter (§. 28), die Plastik bedarf also vorzüglich der göttlichen Naturen etc. *Erläuterung. * Diese Behauptung ist nicht empirisch gemeint nämlich so, daß die plastische Kunst niemals ihre wahre Höhe erreicht hätte, ohne Götter darzustellen. Es ist allerdings gewiß, daß die Nothwendigkeit, in der sich die griechischen Künstler befanden, Bilder von Göttern zu entwerfen, sie nöthigte unmittelbarer sich über die Materie zu erheben, in das Reich des Abstrakten und Körperlosen zu dringen, und das Ueberirdische und von der bedürftigen und abhängigen Natur Abgesonderte zu suchen. Allein die Meinung ist eigentlich diese, daß die Plastik an und für sich selbst, und wenn sie nur *sich selbst *und ihren besonderen Forderungen genügen will, Götter darstellen muß. Denn ihre besondere Aufgabe ist eben, das absolut Ideale zugleich als das Reale, und demnach eine Indifferenz darzustellen, die an und für sich selbst nur in göttlichen Naturen seyn kann. Man kann also sagen, daß jedes höhere Werk der Plastik an und"}, {"type": "paragraph", "text": "für sich selbst eine Gottheit sey, gesetzt, daß auch noch kein Name für sie existire, und daß die Plastik, wenn sie nur sich selbst überlassen alle Möglichkeiten, die in jener höchsten und absoluten Indifferenz beschlossen liegen, als Wirklichkeiten darstellte, dadurch von sich selbst den ganzen Kreis göttlicher Bildungen erfüllen und die Götter erfinden müßte, wenn sie nicht wären. Von der anderen Seite betrachtet, muß man sagen, daß, da das Wesen des griechischen Polytheismus (nach dem, was §. 30 ff. bewiesen wurde) in der reinen Begrenzung von der einen und der ungetheilten Absolutheit von der andern Seite bestand, da ferner diese Götterwelt in sich wieder eine Totalität, ein beschlossenes System bildete, eben dadurch auch die Möglichkeit für die plastische Kunst begründet war sich frühzeitig zu begrenzen, ihre Gegenstände in streng abgesonderte Formen zu fassen, und ein ebenso in sich beschlossenes System der Götterbildungen zu entwerfen, als es schon zuvor in der Mythologie vorhanden war. Die plastische Kunst der Griechen bildet eben deßwegen für sich wieder eine Welt, der, wie sie nach innen vollendet ist, ebenso auch nach außen nichts gebricht, worin alle Möglichkeiten erfüllt, alle Formen gesondert und strenge bestimmt sind. Das Ansehen des Jupiter, des Neptunus und aller männlichen Gottheiten war ein für immer bestimmtes, ebenso das der weiblichen Gottheiten. (Vollkommene Aehnlichkeit der Köpfe auf allen Münzen.) Dadurch wurde die Kunst gleichsam canonisch und exemplarisch; es gab keine Wahl mehr in ihr, das Nothwendige herrschte."}, {"type": "paragraph", "text": "§. 130. *Die Werke der plastischen Kunst werden vorzugsweise die Charaktere der Ideen in ihrer Absolutheit an sich tragen. *- Unmittelbare Folge aus dem Vorhergehenden. *Erläuterung.* Das Wesen der Ideen ist, daß in ihnen Möglichkeit und Wirklichkeit jederzeit oder vielmehr ohne Zeit eins sind, daß sie alles, was sie seyn können, in der That und zumal sind. Dadurch"}]}, {"page_pdf": 1762, "page_book": 623, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "entsteht die höchste Befriedigung, und - weil in diesem Zustand kein Mangel, kein Gebrechen denkbar, also nichts vorhanden ist, wodurch sie aus ihrer Ruhe weichen könnten - das höchste Gleichgewicht und die tiefste Ruhe in der höchsten Thätigkeit."}, {"type": "paragraph", "text": "Dieser Charakter, wie er hier angegeben ist, ist der Charakter der plastischen Götterbildungen, jeder nämlich in ihrer Art. Jede ist vollendet, jede ruht in der höchsten Befriedigung, ohne deßwegen unthätig zu scheinen. Nur *die *Thätigkeit, welche das Gleichgewicht der Seele aufhebt, der Ernst und die Arbeit, welche die Stirne der Sterblichen furcht, ebenso wie die Lust und die Begier, welche sie aus sich selbst herauszieht, sind so ihrem Angesicht verschwunden. In dieser erhabenen Gleichgültigkeit kann keine Möglichkeit der Wirklichkeit vorangehen; deßwegen ist \"mit der Neigung zugleich auch alle Spur des Willens, der nicht zugleich That und Befriedigung wäre, aus ihnen ausgelöscht\"1. Sie erscheinen als Wesen, die schlechthin um ihrer selbst willen und ganz in sich selbst sind. Sie erscheinen unbeschränkt von außen, denn sie sind gleichsam nicht im Raum, sondern tragen ihn selbst in sich als eine geschlossene Schöpfung. Jeder fremden Berührung entrückt, erscheint auch, was in ihnen wirklich Begrenzung ist, als ihre Vollkommenheit und Absolutheit. Eben durch diese sind sie in sich selbst."}, {"type": "footnote", "text": "1 Schiller über die ästhetische Erziehung des Menschen (Taschenausgabe von 1847, Bd. 12, S. 62)."}, {"type": "paragraph", "text": "§. 131. *Das höchste Gesetz aller plastischen Bildungen ist Indifferenz, asolutes Gleichgewicht der Möglichkeit und Wirklichkeit. *- Unmittelbare Folge aus dem Vorhergehenden. Dieses Gesetz ist allgemein, denn das höhere plastische Werk ist schon für sich ein Gott, auch wenn es einen Sterblichen darstellen sollte. Auch der Mensch, wenn er leidet, soll leiden, wie ein Gott leiden würde, wenn er dessen fähig wäre. Schon aus dem Begriff der Götter folgt, daß sie alles Leidens entbunden erscheinen, und nur Prometheus, das Urbild aller tragischen Kunst, leidet als Gott. In den Göttergestalten kann also an und für sich selbst kein Ausdruck angetroffen werden, der das innere Gleichgewicht der Seele aufgehoben zeigte. In der Construktion der Malerei wurde (§. 87) behauptet, daß auch in ihren Darstellungen der Ausdruck gemäßigt werden müsse. Allein in der Malerei ist dieß nicht so unmittelbar der Fall als in der Plastik. Die Malerei muß ihn mäßigen, damit er der Schönheit nicht"}, {"type": "paragraph", "text": "nachtheilig werde, worunter hier die *ideale *Schönheit, die Grazie verstanden wird, deren die Malerei, als die ideale Form, vorzüglich sich bestrebt. Allein in der Plastik ist der gemäßigte Ausdruck und das Ansehen, welches einen innerlich abgewogenen Zustand der Seele erkennen läßt, an sich nothwendig, wegen des Berufs, ein Bild der göttlichen Natur und der in ihr wohnenden Indifferenz zu seyn. Dieses ist das Erste, die Schönheit ist die nothwendige und unmittelbare Wirkung oder Erscheinung davon. - So haben Schönheit und Wahrheit in ihrer Absolutheit einen gemeinschaftlichen Grund - die Indifferenz. Ich führe nur einige Beispiele dieses ruhigen, über Leidenschaft und Gewaltsamkeit erhabenen Ausdrucks in griechischen Werken, sowohl die Götter als, die sterbliche Naturen vorstellen, an. Das höchste Urbild der Ruhe und der Indifferenz ist der Vater der Götter; daher wird dieser in ewiger Heiterkeit, gleichsam ungerührt von Empfindungen vorgestellt. Eine größere Thätigkeit darf dem Apollon zugeschrieben werden; da er der *ideale *unter den Göttern ist. Diese größere Thätigkeit wird ausgedrückt"}]}, {"page_pdf": 1763, "page_book": 625, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "durch die Erhabenheit seines Ganges, den kühnen Schwung seines Leibes, auf dem die ewige Schönheit spielt. Uebrigens ist auch in ihm die höchste Schönheit in der tiefsten Ruhe gebildet. \"Keine Adern, noch Sehnen, sagt Winkelmann1, erhitzen und erregen diesen Körper, sondern ein himmlischer Geist, der sich wie ein sanfter Strom ergossen, hat gleichsam die ganze Umschreibung dieser Figur erfüllt.\" - Er ist vorgestellt, wie er den Python, gegen den er erst seinen Bogen gebraucht, verfolgt, wie sein mächtiger Schritt ihn erreicht und erlegt hat. Aber er ist nicht auf seinen Gegenstand geheftet. \"Von der Höhe seiner Genügsamkeit gehet sein erhabner Blick, wie ins Unendliche, weit über seinen Sieg hinaus. Verachtung sitzt auf seinen Lippen, und der Unmuth, welchen er in sich zieht, bläht sich in den Nüstern seiner Nase und steigt bis in die stolze Stirne hinauf. Aber der Friede, welcher in einer göttlichen Stille auf ihr schwebet, bleibt ungestört u.s.w.\""}, {"type": "footnote", "text": "1 Ebendaselbst."}, {"type": "paragraph", "text": "Von den vornehmsten Beispielen des gemäßigten Ausdrucks in Darstellung menschlichen Handelns und Leidens, dem Laokoon und der Niobe, ist schon bei der Malerei die Rede gewesen. Aber über die *Niobe *will ich noch bemerken, daß sie schon dem Gegenstand nach zu den höchsten Werken gehört. Die Plastik stellt sich in ihr gleichsam selbst dar, und sie ist das Urbild der Plastik, vielleicht eben so, wie Prometheus das der Tragödie. Alles Leben beruht auf der Verbindung eines an sich Unendlichen mit einem Endlichen, und das Leben als solches erscheint nur in der Entgegensetzung dieser beiden. Wo ihre höchste oder absolute Einheit ist, ist, relativ betrachtet, der Tod, aber eben deßwegen wieder das höchste Leben. Da es nun überhaupt Werk der plastischen Kunst ist, jene höchste Einheit darzustellen, so erscheint das absolute Leben, von dem sie die Abbilder zeigt, an und für sich schon, und verglichen mit der Erscheinung, als Tod. Aber in der Niobe hat die Kunst dieses Geheimniß selbst ausgesprochen, dadurch, daß sie die höchste Schönheit in dem Tode darstellt, und die nur der göttlichen Natur eigne, der *sterblichen *aber unerreichbare Ruhe -* diese *im Tod gewinnen läßt, gleichsam um anzudeuten, daß der Uebergang zum höchsten Leben der Schönheit in der Beziehung auf das Sterbliche als Tod erscheinen müsse. Die Kunst ist also hier auf gedoppelte Weise symbolisch; sie wird nämlich wieder zur Auslegerin von ihr selbst, so daß, was alle Kunst wolle, hier in der Niobe ausgesprochen vor Augen liegt. *Anmerkung, das Verhältniß zur Malerei betreffend. *- Die Malerei ist rein ideale Kunstform. Das Wesen des Idealen = Thätigkeit. Daher ist in der Malerei mehr Thätigkeit und mehr Ausdruck der Leidenschaft erlaubt. Nur findet die Eine Beschränkung statt, daß die sinnliche Schönheit, Anmuth und Grazie nicht aufgehoben werde. Jene letzte Schönheit, die Erhabenheit ist, und die ursprünglich als totale Indifferenz von Unendlichem und Endlichen nur in Gott wohnt, ist nur der Plastik möglich darzustellen. Noch einige Bestimmungen der plastischen Kunst. Zu erwarten ist, wegen der unendlichen Wiederholung von allem in allem, daß auch in der Plastik κατE dξοχήν wieder die anderen"}, {"type": "paragraph", "text": "plastischen Formen, obgleich in sehr eingeschränkter Gültigkeit, zurückkehren. - Hierauf beziehen sich die folgenden Sätze."}, {"type": "paragraph", "text": "§. 132. *Der architektonische Theil der Plastik, soweit er in ihr auf eine untergeordnete Art stattfindet, ist die*"}]}, {"page_pdf": 1764, "page_book": 627, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "*Draperie oder Bekleidung.* Architektonisch ist die Draperie, weil sie mehr oder weniger nur eine Allegorie oder Andeutung (Echo) der Formen der organischen Gestalt ist. Diese Andeutung beruht fürnehmlich auf dem Gegensatz der Falten und des Flachen, Faltenlosen. Ein erhobenes Glied, von dem ein freies Gewand auf beiden Seiten herabfällt, ist in der Natur nie ohne Falten, und diese fallen dahin, wo eine Hohlung ist. - An Werken des alten Styls gehen die Falten *meist * gerade. In dem schönsten und vollendetsten Style der Kunst gingen sie mehr in gezogenen Bogen, und der Mannichfaltigkeit halber wurden sie gebrochen, aber so, daß sie wie Zweige von einem gemeinschaftlichen Stamm und mit einem sehr sanften Schwung ausgingen. In der That kann es keine herrlichere und schönere Architektonik geben als die der vollendetsten Draperie in den griechischen Werken. Die Kunst, das Nackte darzustellen, potenzirt sich hier gleichsam selbst, indem sie die organische Form auch durch ein fremdartiges Medium hindurch erkennen läßt; und je weniger unmittelbar, je mehr mittelbar sie hier darstellt, desto schöner wird dieser Theil der Kunst. Indeß bleibt die Draperie doch immer dem Nackten untergeordnet, welches die wahre und erste Liebe der Kunst ist. Die Kunst verschmäht die Verhüllung, insofern sie bloß Mittel und nicht etwa selbst wieder zur Allegorie der Schönheit gemacht wird, da sie durchaus für den höchsten Sinn gebildet ist, und den niedrigen, auch wo sie unverhüllt ist, verschmäht. Wie kein Volk einen höheren Sinn für Schönheit hatte, als die Griechen, so war auch keines, welches von jener falschen und unkeuschen Scham, die sich Decenz nennt, entfernter. Die Draperie in Kunstwerken konnte darum keinen außer der Kunst liegenden Zweck haben, und selbst nur um der Schönheit willen, nicht in sogenannter sittlicher Absicht, ausgebildet werden; daher auch die griechische Kleidung einzig schön genannt werden kann."}, {"type": "paragraph", "text": "§. 133. *Der malerische Theil der Plastik, inwiefern er in ihr stattfinden könnte, müßte sich auf die Gruppirung* oder Zusammensetzung mehrerer Gestalten zu einer gemeinschaftlichen Handlung *beziehen. -* Denn da es bei einer beträchtlichen Composition nicht zu vermeiden wäre, daß einzelne Figuren durch andere verdeckt und für Betrachtung des Ganzen ein gewisser, bestimmter Gesichtspunkt nothwendig würde, so würde die Plastik sich dadurch eine der Malerei ähnliche Beschränkung geben. Allein man sieht schon aus der Sache selbst, wie nothwendig die Plastik sich in Rücksicht der Composition auf wenig Gestalten zu beschränken hat, und sie kann dieß um so eher, da sie die einzige bildende Kunst ist, welcher die Gestalt an und für sich genügt, und die nichts außer ihr bedarf. Die Malerei hat wenigstens den Grund darzustellen, und begnügt sich schon darum weniger mit Einer Gestalt, weil sie dem Raum Bedeutung geben muß. Eben deßwegen aber, weil die Malerei ihren Gegenständen den Grund zugibt, hat sie zugleich das Verbindungsmittel für sie, anstatt daß die Plastik, wo jede Gestalt für sich und von allen Seiten beschlossen ist, wenn sie zu viele Gestalten durch eine äußeres Medium, z.B. den Boden, auf den sie gestellt werden, verbinden wollte, dadurch dem Außerwesentlichen eine zu große Bedeutung geben würde. Man kann also behaupten, daß eben in der Absolutheit der Plastik der Grund liegt, warum sie sich nicht auf zusammengesetztere Compositionen ausdehnt, indem in Einem oder in Wenigem ihre ganze Größe beschlossen liegt, die nicht auf der Ausdehnung im Raum, sondern allein auf der inneren Vollendung und Beschlossenheit des Gegenstandes beruht, demnach eine Größe ist, die nicht empirisch, sondern der Idee nach geschätzt wird. Wie die Natur zur Vollendung jedes einzelnen ihrer organischen Werke dadurch gelangt, daß sie Länge und Breite aufhebt, und alles concentrisch aufstellt, so schließt auch die bildende Kunst in der Plastik als ihrer Blüthe sich dadurch, daß sie alles gegen den Mittelpunkt zusammenzieht und *scheinbar *sich beschränkend sich zur Totalität erweitert."}]}, {"page_pdf": 1765, "page_book": 628, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Ich schließe die Construktion der Plastik mit einigen"}, {"type": "paragraph", "text": "Allgemeinen Anmerkungen über die bildende Kunst"}, {"type": "paragraph", "text": "überhaupt."}, {"type": "paragraph", "text": "Wir haben gleich anfänglich die bildende Kunst überhaupt construirt als die reale Seite der Kunstwelt, deren zu Grunde liegende Einheit also die Einbildung der Identität in die Differenz ist. Diese ist vollendet ohne Zweifel da, wo das Allgemeine das ganze Besondere, das Besondere das ganze Allgemeine ist. Dieß ist vorzugsweise nur in der Plastik der Fall. Wir sind also sicher, die Construktion der bildenden Kunst vollendet, d.h. in ihren Anfangspunkt zurückgeführt zu haben. Der allgemeine Umkreis, in welchen ihre Formen fallen, ist der der realen Einheit, die, in ihrem An-sich dargestellt, selbst wieder eine Indifferenz ist. Durch Differenziirung gehen aus ihr die reale und die ideale Form hervor, jene als Musik, diese als Malerei. Sie selbst drückt sich als Indifferenz erst vollkommen in der Plastik aus. Man könnte der von uns statuirten Aufeinanderfolge der drei Grundkünste folgende andere entgegensetzen. Zugegeben, könnte man sagen, und vorausgesetzt, daß die bildende Kunst der realen Einheit entspricht und in ihren Formen gemäß den Formen der letzteren construirt werden muß, so wird die Plastik in dem System der Kunst nothwendig der Materie in der Natur entsprechen und die erste Potenz der bildenden Künste bezeichnen. Das An-sich der Kunst kleidet sich hier, wie das An-sich der Natur ganz in Materie und Körper. Durch die zweite Potenz wird die Materie ideal, in der Natur durch das Licht, in der Kunst durch die Malerei. Endlich in der dritten wird die reale und ideale eins; das dem Realen oder der Materie Verbundene oder Eingebildete wird zum Klang oder Laut, in der Kunst zur Musik und zum Gesang. Hier wird also der absolute Erkenntnißakt mehr oder weniger von den Fesseln der Materie befreit, und sie selbst bloß als Accidens setzend, objektiv und als Akt der Einbildung der ewigen Subjektivität in die Objektivität erkennbar. - Hier ist also die umgekehrte Ordnung der von uns angenommenen. Diese andere Ordnung schiene sich noch dadurch zu"}, {"type": "paragraph", "text": "empfehlen, daß sie den Uebergang von der bildenden Kunst zur redenden unmittelbarer und stetiger machen läßt. Die Materie löst sich allmählich ins Ideale auf: - in der Malerei schon ins relativ-Ideale, in dem Licht; in der Musik, und dann noch mehr in Rede und Poesie in das wahrhaft Ideale, in die vollkommenste Erscheinung des absoluten Erkenntnißaktes. Der Mißverstand, auf welchem diese Ordnung beruhen würde, wäre der der Potenzen in der Philosophie. Die Meinung ist nicht, daß die Potenzen wahre *reale *Gegensätze bilden, sondern daß sie allgemeine Formen sind, die in allen Gegenständen auf gleiche Weise zurückkehren. Z.B. die Potenz des Organischen ist keineswegs bloß das organische Wesen selbst, sondern sie ist ebenso nothwendig und bestimmt auch in der Materie selbst, nur hier untergeordnet dem Anorgischen. Die Materie ist anorgisch, organisch und vernünftig zugleich, und dadurch ein Bild des allgemeinen Universums. Die Plastik, als die dritte Potenz der bildenden Kunst, stellt nun eben das, was in der Materie Ausdruck der Vernunft ist, als *entwickelt *dar, und sie geht hierin sogar durch verschiedene Stufen, indem sie, als Architektur z.B. die Materie oder das Anorgische nur bis zur Allegorie des Organischen und mittelbar der Vernunft entwickelt. Die Plastik also, wenn sie auch dadurch, daß sie die Materie zum Leib nimmt, unter die erste Potenz fällt, wäre doch in dieser, nämlich unter dem gemeinschaftlichen Exponenten des ersten, wieder"}]}, {"page_pdf": 1766, "page_book": 630, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "die dritte Potenz, indem sie die Vernunft als das Wesen der Materie darstellt. Auf diese Weise würde sich also, wie die *Natur *in Bezug auf das Universum im Ganzen wieder die erste Potenz darstellt, so die bildende Kunst in Bezug auf das Universum der Kunst im Ganzen als die erste Potenz verhalten. Was aber über die Ordnung der drei Grundformen der bildenden Kunst entscheidet, ist Folgendes. Alle bildende Kunst ist Einbildung des Unendlichen ins Endliche, des Idealen ins Reale. Da sie also überhaupt auf die Umwandlung des Idealen in das Reale geht, so muß die vollkommenste Erscheinung des Idealen als eines Realen, die absolute Verwandlung des ersten in das andere, den Gipfel aller bildenden Kunst bezeichnen."}, {"type": "paragraph", "text": "Es erhellt von selbst, daß die Kunst in dem Verhältniß, als sie *real *ist, also in dem Verhältniß, in welchem sie das Unendliche dem Endlichen einbildet, auch als *real *erscheine, dagegen daß sie im umgekehrten Verhältniß jener Umwandlung noch mehr oder weniger als *ideal *erscheine. So erscheint in der Musik die Einbildung des Idealen ins Reale noch *als Akt*, als ein Geschehen, nicht als ein Seyn, und als bloß relative Identität. In der Malerei hat sich das Ideale bereits zu Umriß und Gestalt zusammengezogen, aber noch ohne als Reales zu erscheinen; sie stellt bloß Vorbilder des Realen dar. Endlich in der Plastik ist das Unendliche ganz in das Endliche, das Leben in den Tod, der Geist in Materie verwandelt, aber eben deßwegen, und *nur* weil es ganz und absolut *real *ist, ist das plastische Werk auch wieder absolut ideal. - Die von uns aufgestellte Ordnung ist also die in der Sache selbst gegründete, und wir werden ein gleiches Verhältniß auch wieder auf der idealen Seite in der Poesie antreffen, in welcher gleichfalls die höchste Potenz auf jener Umwandlung eines Idealen in ein gänzliches Seyn, in eine als *wirklich *dargestellte Realität beruht, im Gegensatz gegen welche die Lyrik z.B. weit mehr ideal erscheint. Hiermit wäre also der Kreis der bildenden Künste durchlaufen. Wir werden uns daher jetzt zu der *idealen Seite *der Kunstwelt wenden, welche die Poesie im engeren Sinn ist, Poesie nämlich, sofern sie durch Rede und Sprache sich ausdrückt. Ich erinnere hier an folgende Hauptsätze. 1. Das Universum ist nach den Beweisen, welche gleich anfangs (§. 8) geführt wurden, nach zwei Seiten gegliedert, welche den beiden Einheiten im Absoluten entsprechen. In der einen, *für sich* betrachtet, erscheint das Absolute bloß als *Grund *von Existenz, denn es ist die, worin es seine ewige Einheit in die Differenz gestaltet. In der andern erscheint das Absolute als *Wesen, als *Absolutes, denn wie dort (in der ersten Einheit) das Wesen in die Form gebildet wird, so hier dagegen die Form in das Wesen. Dort ist also die Form das Herrschende, hier das Wesen."}, {"type": "paragraph", "text": "2. Die beiden Seiten des absolut-Idealen sind wesentlich eins; denn, was in der einen real, ist in der andern nur ideal ausgedrückt und umgekehrt; beide sind also, getrennt betrachtet, nur die verschiedenen Erscheinungsweisen von Einem und demselbigen. Die Natur in der Getrenntheit von der anderen Einheit (in der die Form in das Wesen gebildet wird) erscheint mehr als geschaffene, die ideale als schaffende; in dem einen ist aber eben deßwegen und nothwendig das, was in dem anderen. Die Natur ist nach §. 74 (Allg. Zus.) die plastische Seite, ihr Bild ist die Niobe der plastischen Kunst, die mit ihren Kindern erstarrt, die ideale Welt die Poesie des Universums. Dort verhüllt sich das göttliche Princip in ein anderes, ein Seyn, hier erscheint es als das,"}]}, {"page_pdf": 1767, "page_book": 632, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "was es ist, als Leben und Handeln. Allein dieser Unterschied ist wieder ein bloßer Formunterschied, wie anfänglich in Ansehung der bildenden und redenden Kunst bewiesen worden. Die Natur ist an sich betrachtet wieder das Ursprünglichste, das erste Gedicht der göttlichen Imagination. Die Alten und nach ihnen die Neuern nannten die reale Welt *natura rerum*, die Geburt der Dinge. In ihr werden die ewigen Dinge, nämlich die Ideen zuerst wirklich, und inwiefern sie die aufgeschlossene Ideenwelt ist, enthält sie die wahren Urbilder der Poesie. Aller Unterschied zwischen bildender und redender Kunst kann daher nur in Folgendem beruhen. Alle Kunst ist unmittelbares Nachbild der absoluten Produktion oder der absoluten Selbstaffirmation; die bildende nur läßt sie nicht als ein Ideales *erscheinen*, sondern durch ein anderes, und demnach als ein Reales. Die Poesie dagegen, indem sie dem Wesen nach dasselbe ist, was die bildende Kunst ist, läßt jenen absoluten Erkenntnißakt unmittelbar als Erkenntnißakt erscheinen, und ist insofern die höhere Potenz der bildenden Kunst, als sie in dem Gegenbild selbst noch die Natur und den Charakter des Idealen, des Wesens, des Allgemeinen beibehält. Das, wodurch die bildende Kunst ihre Ideen ausdrückt, ist ein an sich Concretes; das, wodurch die redende, ein an sich *Allgemeines*, nämlich die Sprache. Deßwegen hat die Poesie vorzugsweise den Namen der Poesie, d.h. der *Erschaffung *behalten, weil ihre Werke"}, {"type": "paragraph", "text": "nicht als ein Seyn, sondern als Produciren erscheinen. Daher kommt es, daß die Poesie wieder als das *Wesen *aller Kunst kann angesehen werden, ungefähr so wie die Seele als das Wesen des Leibes. Allein in der Beziehung, inwiefern nämlich Poesie das Erschaffende der *Ideen*, und dadurch das Princip aller Kunst ist, war von ihr schon in der Construktion der Mythologie die Rede. Nach der von uns genommenen Methode kann also hier - im Gegensatz mit der bildenden Kunst - von Poesie nur die Rede seyn, inwiefern sie selbst *besondere *Kunstform, und also von der Poesie, die von dem *An-sich *aller Kunst die Erscheinung ist. Allein selbst innerhalb dieser Beschränkung ist die Poesie ein gänzlich unbegrenzter Gegenstand und unterscheidet auch dadurch sich von der bildenden Kunst. Z.B. um nur eines anzuführen: ein Gegensatz von Antikem und Modernem hat in der *Plastik *gar nicht statt, dagegen in allen Gattungen der Poesie. Die Poesie der Alten ist ebenso rational begrenzt, sich selbst gleich, als ihre Kunst. Dagegen die der Neueren nach allen Seiten hin und in allen Theilen so mannichfaltig unbegrenzt und zum Theil irrational als es ihre Kunst überhaupt ist. Auch *dieser *Charakter der Unbegrenztheit beruht darauf, daß die Poesie die ideale Seite der Kunst, wie die Plastik die reale ist. Denn das Ideale = das Unendliche. Man könnte den Gegensatz des Antiken und Modernen in der eben erwähnten Beziehung so ausdrücken: die Alten sind redend in der Plastik, und dagegen plastisch in der Poesie. Die Rede ist der stillste und unmittelbarste Ausdruck der Vernunft. Jede andere Handlung hat mehr körperlichen Antheil. Die Neueren legen in ihren Bildern den Ausdruck in ein gewaltsames, körperliches Handeln. Die Bilder der Alten sind, indem sie den Ausdruck der Ruhe tragen, eben dadurch redend, wahrhaft poetisch. Dagegen sind aber die Alten selbst in der Poesie plastisch, und drücken auf diese Weise die Verwandtschaft und innere Identität der redenden und bildenden Kunst weit vollkommner als die Neueren aus. Die innere Unbegrenztheit der Poesie bringt nun auch einen Unterschied für die wissenschaftliche Behandlung derselben mit sich. Wie nämlich die Natur rational ist, und nach einem allgemeinen Typus"}]}, {"page_pdf": 1768, "page_book": 634, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "dargestellt werden kann, die Geschichte aber irrational, unerschöpflich, ihr verborgenes Gesetz nur in Manifestationen aussprechend, ebenso verhält es sich mit der bildenden und der redenden Kunst. Wie in der Natur Nothwendigkeit als das Allgemeine das Besondere beherrscht, in der idealen Welt dagegen das Besondere entfesselt, frei zu dem Unendlichen strebt, so in bildender und redender Kunst. Daher uns in Betrachtung der Poesie erstens unmöglich ist, das Allgemeine so durch Construktion fort ins Besondere zu führen, wie in der bildenden Kunst. Denn die Besonderheit hat hier mehr Gewalt und Freiheit. Das Allgemeine, was hier ausgesprochen werden kann, kann daher nur mehr im Großen und in ganzen Massen ausgesprochen werden. Dagegen je weniger das Allgemeine das Besondere hier gebietend bestimmt, desto mehr verlangt zweitens das Einzelne in seiner Absolutheit dargestellt zu werden. Daher wird die Darstellung hier mehr zur Charakteristik auch von Individuen herabsteigen. Uebrigens werde ich mich nicht so sehr bei dem Einzelnen, als nur bei den Hauptsachen verweilen, und kann aus diesem Grunde auch nicht mehr einzelne Sätze, sondern nur Ansichten im Ganzen darstellen. Ich werde nun zuerst die Frage beantworten: *wodurch wird die Rede zur Poesie*? Es wird in dieser Frage a) von dem *An-sich * der Poesie, soweit es nicht schon im Vorhergehenden bestimmt ist, b) von den Formen die Rede seyn müssen, wodurch sich die Poesie als solche von der Rede absondert, also vornehmlich vom Rhythmus, Sylbenmaß u.s.w. Hierauf werden wir die besonderen in der Grundeinheit der Poesie begriffenen Einheiten oder die Gattungen und Arten der Dichtkunst, deren vornehmste die lyrische, epische und dramatische sind, im Allgemeinen zu construiren haben, und dann jede dieser Gattungen insbesondere behandeln müssen. Wenn man die gewöhnlichen Theoretiker der schönen Künste nachsieht, findet man sie in nicht geringer Verlegenheit, einen Begriff oder eine sogenannte Definition von der Dichtkunst zu geben, und in denjenigen, welche sie geben, ist nicht einmal die Form der Poesie, geschweige das Wesen derselben ausgedrückt. Das Erste aber zur Erkenntniß der Poesie"}, {"type": "paragraph", "text": "ist ohne Zweifel, ihr *Wesen *zu erkennen, denn die Form folgt erst aus diesem, weil nämlich nur eine *solche *Form *diesem*, dem Wesen, angemessen seyn kann. Das *An-sich *der Poesie ist nun das aller Kunst: es ist Darstellung des Absoluten oder des Universum in einem Besonderen. Wenn von manchen besondern Dichtarten eine Einwendung dagegen hergenommen werden könnte, so würde diese nur beweisen, daß diese sogenannten Dichtarten selbst keine poetische Realität haben. Sowie nichts Kunstwerk überhaupt ist, das nicht mittelbar oder unmittelbar Reflex des Unendlichen ist, so kann insbesondere nichts *Gedicht *oder poetisch seyn, was nicht irgend etwas Absolutes, d.h. eben das Absolute in der Beziehung auf irgend eine Besonderheit darstellt. Welcher Art übrigens diese Besonderheit sey, ist dadurch nicht bestimmt. Der poetische Sinn besteht eben darin, zu der Wirklichkeit, der Realität, außer der Möglichkeit nichts zu bedürfen. Was poetisch möglich ist, ist eben deßwegen schlechthin wirklich, wie in der Philosophie, was ideal - real. Das Princip der Unpoesie wie das der Unphilosophie ist der Empirismus oder die Unmöglichkeit, etwas anderes als wahr und real zu erkennen, als was in der Erfahrung liegt. Ueber die großen Gegenstände der Poesie, die Ideenwelt, die für die Kunst die Welt der Götter ist, das Universum, die Natur, war schon in der Lehre von der Mythologie die Rede. Mit der Nothwendigkeit der Mythologie für alle Kunst, die dort bewiesen ist, ist diese Nothwendigkeit vorzüglich für die Poesie dargethan. Inwiefern auch die neueren Zeiten eine Mythologie haben, und wie aus dem vorliegenden Stoff diese sich immer vermehren oder neu erschaffen lasse, wurde dort gleichfalls gezeigt. Die Anwendung dieser allgemeinen Grundsätze kann aber nur bei Gelegenheit der einzelnen Dichtarten gemacht werden. Die allgemeine *Form *der Poesie ist nun überhaupt die, daß sie die Ideen in Rede und Sprache"}]}, {"page_pdf": 1769, "page_book": 635, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "darstellt. Den Grund und die Bedeutung der Sprache betreffend, erinnere ich an §. 73, woselbst bewiesen, daß sie das entsprechendste Symbol des absoluten Erkenntißakts. Denn er erscheint in der Sprache von der einen Seite als *ideal*, nicht real, wie"}, {"type": "paragraph", "text": "im Seyn, und integrirt sich doch von der andern durch ein Reales, ohne daß er aufhörte ideal zu seyn. Insbesondere das Verhältniß der Sprache zum Klang überhaupt betreffend, erinnere ich Folgendes. Klang = reine Einbildung des Unendlichen ins Endliche, als solche aufgefaßt. In der Sprache ist diese Einbildung vollendet, und es beginnt schon das Reich der entgegengesetzten Einheit. Die Sprache ist daher gleichsam der potenzirteste, aus der Einbildung des Unendlichen ins Endliche entsprungene Stoff. Die Materie ist das ins Endliche eingegangene Wort Gottes. Dieses Wort, welches sich im Klang noch durch lauter Differenzen (in der Verschiedenheit der Töne) zu erkennen gibt und anorgisch ist, also den entsprechenden Leib noch nicht gefunden hat, findet ihn in der Sprache. Wie in dem Fleisch des menschlichen Leibs sich alle Differenzen der Farben aufheben, und die höchste Indifferenz aller entsteht, so ist die Rede der zur Indifferenz reducirte Stoff aller Töne und Klänge. - Es ist nothwendig, wie auch in dem Verlauf der allgemeinen Philosophie klar wird, daß die höchste Verkörperung und Bindung der Intelligenz zugleich der Moment ihrer Befreiung ist. In dem menschlichen Organismus ist der höchste Contraktionspunkt des Universum und der in ihm wohnenden Intelligenz. Aber eben im Menschen auch bricht sie zur Freiheit durch. Deßwegen erscheint auch hier wieder Klang, Ton als Ausdruck des Unendlichen im Endlichen, aber als Ausdruck der vollendeten Einbildung - in der *Sprache*, die sich zum bloßen Klang ebenso verhält, wie sich der dem Licht vermählte Stoff eines organischen Leibs zur allgemeinen Materie verhält. Die Sprache für sich selbst nun ist das Chaos, aus dem die Poesie die Leiber ihrer Ideen bilden soll. Das poetische Kunstwerk soll aber, wie jedes andere, ein Absolutes im Besondern, ein Universum, ein Weltkörper seyn. Dieß ist nicht anders möglich als durch Absonderung der *Rede*, worin das Kunstwerk sich ausdrückt, von der Totalität der Sprache. Aber diese Absonderung einerseits und die Absolutheit andererseits ist nicht möglich, ohne daß die Rede ihre eigne unabhängige Bewegung und eben deßwegen ihre Zeit in sich selbst habe, wie der Weltkörper; dadurch schließt sie sich allem andern ab, indem sie einer *inneren *Gesetzmäßigkeit"}, {"type": "paragraph", "text": "folgt. Die Rede bewegt sich frei und selbständig nach außen betrachtet, und ist nur in sich wieder geordnet und der Gesetzmäßigkeit unterworfen. Demjenigen nun, wodurch der Weltkörper in sich selbst ist, und die Zeit in sich selbst hat, entspricht in der Kunst, sowohl sofern sie Musik als redende Kunst ist, der Rhythmus. Da Musik sowohl als Rede eine Bewegung in der Zeit haben, so würden ihre Werke nicht in sich beschlossene Ganze seyn, wenn sie der Zeit unterworfen wären, und sie nicht vielmehr sich unterwürfen und in sich selbst hätten. Diese Beherrschung und Unterwerfung der Zeit = * Rhythmus.* Rhythmus überhaupt ist Einbildung der Identität in die Differenz; er schließt also Wechsel in sich, aber einen selbstthätig geordneten, der Identität dessen, worin er stattfindet, untergeordneten. (Wegen des allgemeinen Begriffs von Rhythmus ist sich zu beziehen auf das bei der Musik davon Gesagte.) Ich nehme hier vorläufig Rhythmus in der allgemeinsten Bedeutung, inwiefern er nämlich überhaupt eine innere Gesetzmäßigkeit der Folge der Tonbewegungen ist. Aber in dieser weitesten Bedeutung schließt er nun selbst wieder zwei Formen in sich, die eine, welche Rhythmus im engeren Sinn heißen kann, und die als Einbildung der Einheit in die Vielheit der Kategorie der Quantität entspricht, die andere,"}]}, {"page_pdf": 1770, "page_book": 637, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "welche als die entgegengesetzte der ersten der Kategorie der Qualität entsprechen muß. Wie sehen leicht, daß Rhythmus im engeren Sinn Bestimmung der *Folge der Tonbewegungen nach Gesetzen der Quantität* ist, sowie nun dagegen die der Qualität entsprechende Form auf folgende Art näher zu bestimmen ist. Da es in den Tönen außer der Dauer oder Quantität keinen Unterschied als den der Höhe und Tiefe geben kann, die Differenzen der Töne aber nach dem, was zuvor von der Rede bewiesen wurde, in ihr aufgehoben und vertilgt sind - (denn in dem *Gesang*, der wieder *Musik *ist, wird die in der Sprache erreichte Identität wieder zerlegt, die Rede kehrt zu den Elementartönen zurück), da also in der Rede als solcher keine Höhe und Tiefe des Tons an sich stattfindet, und die Einheiten der Sprache nicht Töne, so wenig wie die Einheiten eines organischen Leibs Farben seyn können,"}, {"type": "paragraph", "text": "- da also die Einheiten der Sprache schon organische Glieder, Sylben sind, und sich die qualitative Bestimmung nicht auf Höhe und Tiefe der Töne beziehen kann, so bleibt nichts übrig, worin sie bestehen könnte, als die Auszeichnung einer Sylbe durch eine Hebung der Stimme, wodurch eine Anzahl anderer Sylben mit ihr verbunden und diese Einheit dem Gehör fühlbar gemacht wird, und dagegen - Fallenlassen der anderen Sylben durch ein Sinken der Stimme. Dieß ist aber, was *Accent * heißt1."}, {"type": "footnote", "text": "1 Die nun folgenden weiteren Ausführungen über das Sylbenmaß, den Versbau, die Anwendung des rhythmischen Sylbenmaßes auf die neueren Sprachen, ferner über die neuen Sylbenmaße (den Reim etc.) wurden als nichts Eigenthümliches enthaltend (und theilweise nur in Andeutungen bestehend) hier übergangen, um so mehr, als der Verfasser im Verlauf derselben selbst erklärt sich in seinen Angaben meist nach bekannten Schriftstellern (A. W. Schlegel, Moriz) gerichtet zu haben. D. H."}, {"type": "paragraph", "text": "Ich gehe nun zu den *einzelnen Dichtarten *fort, indem ich folgendes Allgemeine vorausschicke. *Gedicht *überhaupt ist ein *Ganzes*, das seine Zeit und Schwungkraft in sich selbst hat, und dadurch von dem Ganzen der Sprache abgesondert, vollkommen in sich selbst beschlossen ist. Eine unmittelbare Folge dieses in-sich-selbst-Seyns der Rede durch Rhythmus und Sylbenmaß ist, daß die Sprache auch in anderer Rücksicht eigenthümlich und von der gemeinen verschieden seyn muß. Durch den Rhythmus erklärt die Rede, daß sie ihren Zweck absolut in sich selbst hat; es wäre widersinnig, wenn sie in dieser Erhebung sich nach den gewöhnlichen Verstandeszwecken der Sprache bequemen, und alle dazu dienenden Formen derselben nachahmen sollte. Sie strebt vielmehr so viel möglich auch in ihren Theilen absolut zu seyn. (Keine logische Unterordnung, Wegfallen der Verbindungspartikeln.) Ohnehin ist alle Poesie in ihrem Ursprung für das Hören gedichtet, sie sey nun lyrisch oder episch oder dramatisch. Die Begeisterung erscheint hier am unmittelbarsten als Inspiration, die den davon Ergriffenen nicht an äußere Zwecke denken läßt. Nur hörend auf die Stimme des Gottes"}, {"type": "paragraph", "text": "bewegt er sich gleichsam außerhalb der gemeinen Gesetzmäßigkeit, verwegen und doch sicher und leicht. Es ist nur ein Vorurtheil, daß die Poesie in keiner andern Sprache zu reden habe, als welche auch in der Prosa gebräuchlich ist (Gottsched, Wieland). Die Prosa überhaupt, um diese Erklärung hier einzuschalten, ist die von dem Verstand in Besitz genommene und nach seinen Zwecken geformte Sprache. In der Poesie ist alles Begrenzung, strenge Absonderung der Formen. Die Prosa ist insofern wieder die Indifferenz und ihr vorzüglichster Fehler der, daraus heraustreten zu wollen, woher die Aftergeburt der poetischen Prosa entsteht. Die Poesie"}]}, {"page_pdf": 1771, "page_book": 639, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "unterscheidet sich von ihr nicht allein durch Rhythmus, sondern auch durch theils einfältigere theils schönere Sprache. Es ist damit nicht ein wildes, in der leeren Ueberspanntheit der Sprache sich ausdrückendes Feuer gemeint, welches die Alten Parenthyrsos genannt haben. Zwar es gibt Kunstrichter, die sogar von dem wilden Feuer des Homer reden. Die *Einfalt *ist auch in der Poesie wie in der bildenden Kunst das Höchste, und Dionys von Halikarnaß, der trefflichste Kunstrichter unter den Alten, zeigt ausdrücklich an einer Stelle der Odyssee, die, wie er sagt, in den gemeinsten Ausdrücken abgefaßt ist, der sich etwa ein Bauer oder Handwerker bedienen würde, das Verdienst der poetischen *Synthesis.* Verschieden in diesem Betracht von der epischen Diktion ist allerdings die lyrische und die dramatische, sofern sie einem großen Theile nach lyrisch ist. Aber auch hier drückt sich die Begeisterung mehr durch die kühnen Absprünge von der logischen oder mechanischen Gedankenfolge, als durch Schwulst der Worte aus. Die Sprache wird zu einem höheren Organ, es sind ihr kürzere Wendungen, ungewöhnlichere Worte, eigenthümliche Biegungen der Worte erlaubt, aber alles in den Grenzen der wahren Begeisterung. Man pflegt in den poetischen Kunstlehren sonst auch von *Metaphern, Tropen *und den übrigen Zierathen der Rede zu sprechen dergleichen die Epitheta sind, die Vergleichungen und die Gleichnisse. Was die Metaphern betrifft, so gehören sie mehr der Rhetorik an."}, {"type": "paragraph", "text": "Die Rhetorik kann den Zweck haben, durch Bilder zu reden, um sich anschaulich zu machen, oder um zu täuschen und Leidenschaft zu erwecken. Die Poesie hat nie einen Zweck außer sich, obgleich sie diejenige Empfindung, die in ihr selbst ist, auch außer sich hervorbringt. Plato vergleicht die Wirkungen der Dichtkunst mit denen eines Magnets etc. In der Poesie also ist alles, was zum Schmuck der Rede gehört, dem höchsten und obersten Princip der Schönheit untergeordnet, es läßt sich eben deßwegen über Gebrauch der Bilder, Tropen etc. kein allgemeines Gesetz als eben das dieser Unterordnung aufstellen"}, {"type": "paragraph", "text": "Construktion der einzelnen Dichtarten."}, {"type": "paragraph", "text": "Das Wesen aller Kunst als Darstellung des Absoluten im Besonderen ist reine Begrenzung von der einen und ungetheilte Absolutheit von der andern Seite. Schon in der Naturpoesie müssen die Elemente sich scheiden, und die vollendet eintretende *Kunst *ist erst mit der strengen Scheidung gesetzt. Am strengsten begrenzt in allen Formen ist auch hier wieder die antike Poesie, ineinanderfließender, mischender die moderne: daher durch diese eine Menge Mittelgattungen entstanden sind. Wenn wir in der Abhandlung der verschiedenen Dichtungen der natürlichen oder historischen Ordnung folgen wollten, so würden wir von dem Epos als der Identität ausgehen und von da zur lyrischen und dramatischen Poesie fortgehen müssen. Allein da wir uns hier ganz nach der wissenschaftlichen Ordnung zu richten haben, und da nach der bereits vorgezeichneten Stufenfolge der Potenzen die der Besonderheit oder Differenz die erste, die der Identität die zweite, und das, worin Einheit und Differenz, Allgemeines und Besonderes selbst eins sind, die dritte ist, so werden wir auch hier dieser Stufenfolge getreu bleiben und machen demnach den Anfang mit der lyrischen Kunst. Daß die *lyrische *Poesie unter den drei Dichtarten der *realen *Form entspricht, erhellt schon daraus, daß ihre Bezeichnung auf die Analogie mit der Musik hinweist. Allein noch bestimmter ist dieß auf folgende Weise darzuthun. In derjenigen Form, welche der Einbildung des Unendlichen in"}]}, {"page_pdf": 1772, "page_book": 640, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "das Endliche entspricht, muß eben deßwegen das Endliche, die Differenz, die Besonderheit das Herrschende seyn. Aber eben dieß ist der Fall in der lyrischen Poesie. Sie geht unmittelbarer als irgend eine andere Dichtart von dem Subjekt und demnach von der Besonderheit aus, es sey nun, daß sie den Zustand eines Subjekts z.B. des Dichters ausdrücke, oder von einer Subjektivität die Veranlassung einer objektiven Darstellung nehme. Sie kann eben deßwegen und *in *dieser Beziehung wieder die subjektive Dichtart heißen, Subjektivität nämlich im Sinn der Besonderheit genommen. In jeder andern Art des Gedichts ist seiner inneren Identität unerachtet doch ein Wechsel der Zustände möglich, in der lyrischen herrscht, wie in jedem Musikstück, nur Ein Ton, Eine Grundempfindung, und wie in der Musik eben wegen der Herrschaft der Besonderheit alle Töne, welche sich mit dem herrschenden verbinden, auch wieder nur *Differenzen *seyn können, so spricht sich auch in der Lyrik jede Regung wieder als Differenz aus. Die lyrische Poesie ist am meisten dem Rhythmus untergeordnet, ganz abhängig, ja fortgerissen von ihm. Sie meidet die gleichförmigen Rhythmen, während das Epos sich auch in dieser Rücksicht in der höchsten Identität bewegt. Das lyrische Gedicht ist überhaupt Darstellung des Unendlichen oder Allgemeinen im Besondern. So geht jede pindarische Ode von einem besonderen Gegenstand und einer besonderen Begebenheit aus, schweift aber von dieser ins Allgemeine ab, z.B. in den späteren mythologischen Kreis, und indem sie aus diesem wieder zum Besondern zurückkehrt, bringt sie eine Art der Identität beider, eine wirkliche Darstellung des Allgemeinen im Besondern hervor. Da die lyrische Poesie die subjektivste Dichtart, so ist nothwendig auch die Freiheit in ihr das Herrschende. Keine Dichtart ist weniger einem Zwang unterworfen. Die kühnsten Absprünge von der gewohnten Gedankenfolge sind ihr erlaubt, indem alles nur darauf ankommt, daß ein Zusammenhang im Gemüth des Dichters oder Hörers sey, nicht objektiv oder außer ihm. In dem Epos waltet vollkommenste Stetigkeit, im lyrischen Gedicht ist diese aufgehoben, wie in der Musik, wo lauter"}, {"type": "paragraph", "text": "Differenzen, und zwischen dem einen Ton und dem folgenden eine wahre Stetigkeit unmöglich ist, dagegen in Farben alle Differenzen wieder in Eine Masse, wie aus Einem Guß, zusammenfließen. Das * An-sich *aller lyrischen Poesie ist Darstellung des Unendlichen im Endlichen, aber da sie nur in der Succession sich bewegt, so entsteht dadurch gleichsam als inneres Lebens- und Bewegungsprincip der *Gegensatz *des Unendlichen und Endlichen. In dem Epos ist Unendliches und Endliches absolut eins, deßwegen in diesem keine Anregung des Unendlichen, nicht als ob es nicht da wäre, sondern weil es in einer gemeinschaftlichen Einheit mit dem Endlichen ruht. Im lyrischen Gedicht ist der Gegensatz erklärt. Daher die vorzüglichsten Gegenstände des lyrischen Gedichts *moralisch*, kriegerisch, leidenschaftlich überhaupt. Leidenschaft überhaupt ist der Charakter des Endlichen oder der Besonderheit im Gegensatz mit der Allgemeinheit. Am reinsten und ursprünglichsten stellt uns diesen Charakter der lyrischen Kunst, sowohl ihrem Ursprung, als ihrer Beschaffenheit nach, wieder die *antike Poesie *dar. Die Entstehung und erste Entfaltung der lyrischen Poesie in Griechenland ist gleichzeitig mit dem Auflbühen der Freiheit und Entstehen des Republikanismus. Zuerst verband sich die Poesie mit den Gesetzen und diente zur Ueberlieferung derselben. Bald wurde sie als lyrische Kunst für Ruhm, Freiheit und schöne Geselligkeit begeistert. Sie wurde die Seele des öffentlichen Lebens, die Verherrlicherin der Feste. Die zuvor ganz nach außen gerichtete, in einer objektiven Identität, dem Epos, verlorene Kraft wandte sich nach innen, fing an sich zu beschränken; mit diesem erwachenden Bewußtseyn und der eintretenden Differenziirung"}]}, {"page_pdf": 1773, "page_book": 642, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "entstanden die ersten lyrischen Töne, die sich bald zu der höchsten Mannichfaltigkeit entwickelten. Das Rhythmische der griechischen Staaten, die ganz auf sich selbst und ihr Daseyn und Wirken gerichtete Besonnenheit der Griechen entzündete die edleren Leidenschaften, die der lyrischen Muse würdig waren. Zu gleicher Zeit mit der Lyrik belebte die Musik die Feste und das öffentliche Leben. Im Homer sind sogar noch Opfer und Gottesdienste ohne Musik. Zu"}, {"type": "paragraph", "text": "der Identität des homerischen Epos gehört auch das heroische Princip, das Princip des Königthums und der Herrschaft. Die lyrische Poesie begann mit Kallinos und Archelaos nach schon gänzlich vollendeter Ausbildung des Epos; und in Vergleichung mit dem Epos ist daher die lyrische Kunst bis zu ihrer letzten Vollendung im Pindaros ganz republikanische Poesie1. Fast alle lyrischen Gesänge der Alten, von deren Existenz wir entweder nur durch historische Ueberlieferung wissen, oder die uns in Bruchstücken, oder selbst ganz übrig geblieben sind, beziehen sich auf das öffentliche und allgemeine Leben, und die selbst mehr aufs Einzelne sich beziehenden lyrischen Gedichte der Alten drücken Geselligkeit aus, weil sie nur in einem freien und großen Staate seyn und werden konnte. Alles deutet darauf, daß die im Epos noch geschlossene Knospe gebrochen ist und die freiere Bildung des Lebens sich entfaltet. Auch in der Besonderheit der lyrischen Dichtkunst also sind die Griechen objektiv, real, expansiv. Die ersten lyrischen Rhythmen waren, wie bemerkt, diejenigen, in welchen die Gesetze freier Staaten gesungen wurden; noch bei Solon. Die Kriegslieder des Tyrtaios \"spornte\" eine ganz objektive Leidenschaft. Alkaios war das Haupt der Verschworenen gegen die Tyrannen, nicht nur mit dem Schwert, sondern auch mit Gesängen sie bekämpfend. Von mehreren lyrischen Dichtern dieser Zeit wird erzählt, daß sie auf Rath der Götter herbeigerufen worden, bürgerliche Uneinigkeiten beizulegen. Andere waren geehrt an Höfen der Herrscher und Tyrannen der damaligen Zeit. Arion z.B. von Periander. Die Zeit der Unschuld war auch dadurch vorbei, daß die Sänger nicht mehr genügsam waren wie die homerischen; daß sie Lohn, Gewinn, Ansehen für das Talent forderten. Pindaros, dessen Leyer bei den öffentlichen Wettspielen ertönte, war auch in dieser - objektiven - Beziehung der griechischen Lyrik die Blüthe. Er anticipirte in sich die Bildung des Perikleischen Zeitalters; der rohere Republikanismus ist schon zur"}, {"type": "footnote", "text": "1 S. Friedr. Schlegel, Geschichte der Poesie der Griechen und Römer, S. 218."}, {"type": "paragraph", "text": "Herrschaft der Gebildeten zurückgeführt; er vereinigt mit dem Feuer des lyrischen Dichters die Würde eines pythagoreischen Philosophen, wie auch die Sage bekannt ist, daß er die Lehre des Pythagoras geliebt habe. (Das Plastische, gleichsam Dramatische der pindarischen Oden.) Diese Objektivität der griechischen Lyrik ist es aber doch wieder nur innerhalb des allgemeinen Charakters der Gattung, welcher der der Innerlichkeit, der besonderen und gegenwärtigen Wirklichkeit ist. Das Epos erzählt die Vergangenheit. Das lyrische Gedicht besingt die Gegenwart, und geht bis zur Verewigung der einzelnsten und vergänglichsten Blüthe derselben herunter, des Genusses, der Schönheit, der Liebe zu einzelnen Jünglingen, wie in dem Gedicht des Alkman und der Sappho, und auch hier wieder bis zur Einzelheit schöner Augen, Haare, einzelner Glieder, wie in den Gedichten des Anakreon. Dionys von Halikarnaß bestimmt als das Ausgezeichnetste des Epos, daß der Dichter *nicht *erscheine."}]}, {"page_pdf": 1774, "page_book": 644, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Die lyrische Kunst dagegen ist die eigentliche Sphäre der Selbstbeschauung und des Selbstbewußtseyns, wie die Musik, wo keine Gestalt, sondern nur ein Gemüth, kein Gegenstand, sondern nur eine Stimmung sich ausdrückt. Der Charakter der *Differenz*, der Scheidung und Sonderung, welcher in der Lyrik an und für sich selbst liegt, drückt sich in der lyrischen Kunst der Griechen nicht minder bestimmt als alle andern aus. Vollkommene Ausbildung aller rhythmischen Gattungen, so daß dem Drama nichts übrig blieb. Scharfe Absonderung aller Arten, sowohl was die äußeren Verschiedenheiten des Rhythmus, als die innere Diversität des Stoffs, der Sprache u.s.w. betrifft, scharfe Absonderung endlich in den verschiedenen Stylen der lyrischen Kunst, dem jonischen, dorischen u. d. a. Wir finden auch in Ansehung der lyrischen Kunst wieder den allgemeinen Gegensatz des Antiken und Modernen auf gleiche Weise zurückkehren. Wie die höchste Blüthe der lyrischen Kunst der Griechen in das Entstehen der Republik, der höchsten Blüthe des öffentlichen Lebens fällt, so der erste Beginn der modernen Lyrik im 14. Jahrhundert in die Zeit der öffentlichen Unruhen und der allgemein geschehenden"}, {"type": "paragraph", "text": "Auflösung des republikanischen Verbands und der Staaten in Italien. Indem das öffentliche Leben mehr oder weniger verschwand, mußte es sich nach innen richten. Die glücklichen Zeiten, welche Italien einigen großgesinnten Fürsten, vorzüglich den Mediceern verdankte, traten erst später ein, und kamen dem romantischen Epos zu gut, welches sich in Ariosto ausbildete. Dante und Petrarca, die ersten Urheber der lyrischen Poesie, fielen in die Zeiten der Unruhe, der gesellschaftlichen Auflösung, und ihre Gesänge, wenn sie sich auf diese äußern Gegenstände beziehen, sprechen laut das Unglück dieser Zeit aus. Die Dichtkunst der Alten feierte vorzüglich die männlichen Tugenden, die der Krieg und das gemeinsame öffentliche Leben erzeugt und nährt. Von allen Verhältnissen der Empfindung war daher die Freundschaft der Männer das Herrschende und die Weiberliebe ein durchaus Untergeordnetes. Die moderne Lyrik war in ihrem Ursprung der Liebe mit all den Empfindungen geweiht, welche im Begriff der Neueren damit verbunden sind. Die erste Begeisterung des *Dante *war die Liebe eines jungen Mädchens, der Beatrice. Er hat die Geschichte dieser Liebe in Sonetten, Canzonen und prosaischen, mit Gedichten untermischten Werken, vorzüglich der Vita nuova verewigt. Die größeren Schicksale seines späteren Lebens, die Verbannung aus Florenz, das Unglück und das Verbrechen der Zeit, spornten seinen göttlichen Geist erst zur Hervorbringung seines höheren Werks, der Divina Comedia, obgleich der Grund und Anfang dieses Gedichts wieder Beatrice ist. Das ganze Leben des *Petrarca *war jener geistigen Liebe geweiht, die sich in der Anbetung genügt. Dieser harmonischen, von der Blüthe der Bildung und der edelsten Tugenden seiner Zeit erfüllten Seele bedurfte es, um in ihr die italienische Poesie zu dem höchsten Grad lyrischer Schönheit, Reinheit und Vortrefflichkeit auszubilden. Man würde sich sehr irren, in Petrarca einen in Liebe zerfließenden und zerschmelzenden Dichter zu suchen, da seine Formen eben so streng, präcis, bestimmt sind als die des Dante in ihrer Art. Auch *Boccaccio *gesellt sich zu diesem Verein; denn auch die Muse seiner Poesie ist die Liebe."}, {"type": "paragraph", "text": "Der Geist der modernen Zeit, der im Allgemeinen schon früher dargestellt worden ist, bringt die Beschränkung der modernen Lyrik in Ansehung der Gegenstände mit sich. Bild und Begleitung eines"}]}, {"page_pdf": 1775, "page_book": 646, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "öffentlichen und allgemeinen Lebens - eines Lebens in einem organischen Ganzen - konnte die Lyrik in den modernen Staaten nicht mehr werden. Es blieben für keine andern Gegenstände als entweder die ganz subjektiven, einzelne momentane Empfindungen, worein sich die lyrische Poesie auch in den schönsten Ergüssen der spätern Welt verloren hat, und aus denen nur sehr mittelbar ein *ganzes *Leben hervorleuchtet, oder dauernde auf Gegenstände sich beziehende Gefühle, wie in den Gedichten des Petrarca, wo das Ganze wieder eine Art von romantischer oder dramatischer Einheit wird. Die Sonetten des Petrarca sind nicht nur im Einzelnen, sondern im Ganzen wieder Kunstwerke. (Das Sonett einer bloß architektonischen Schönheit fähig.) Unverkennbar ist aber, daß Wissenschaft, Kunst, Poesie von dem geistlichen Stande ausgegangen, woraus das Unheroische, sowie daß die Liebesgeschichten mehr auf Weiber als auf unverheirathete Mädchen sich beziehen. Sonst theilt sich die lyrische Poesie in Gedichte moralischen, didaktischen, politischen Inhalts, immer mit Uebergewicht der Reflexion, der Subjectivität, da ihr die Objektivität im Leben fehlt. Die einzige Art lyrischer Gedichte, welche auf ein öffentliches Leben sich beziehen, sind die religiösen, da nur in der Kirche noch öffentliches Leben war. - Wir kommen nun zum Epos. Das lyrische Gedicht bezeichnet überhaupt die erste Potenz der idealen Reihe, also die der Reflexion, des Wissens, des Bewußtseyns. Es steht eben deßwegen ganz unter Herrschaft der Reflexion. Die zweite Potenz der idealen Welt überhaupt ist die des *Handelns*, des * an sich* Objektiven, wie das Wissen des Subjektiven. Gleichwie aber die Formen der Kunst überhaupt die Formen der Dinge an sich sind, so muß diejenige Dichtart, welche der idealen Einheit entspricht, nicht überhaupt nur das erscheinende Handeln, sondern"}, {"type": "paragraph", "text": "das Handeln absolut betrachtet, und wie es in seinem *An-sich *ist, darstellen. Handeln, absolut oder objektiv betrachtet, ist Geschichte. Die Aufgabe der zweiten Art ist also: *ein Bild der Geschichte zu seyn, wie sie an sich oder im Absoluten *ist. Daß diese Dichtart das *Epos *ist, wird sich am bestimmtesten daraus ergeben, daß alle aus dem angegebenen Charakter abzuleitenden Bestimmungen sich in dem Epos vereinigen und zusammentreffen. 1) Nicht daß überhaupt nur Handlung, Geschichte dargestellt wird, sondern daß sie *in der Identität der Absolutheit *erscheint, ist das Auszeichnende des Epos. Das Handeln objektiv angesehen oder als Geschichte ist in dem An-sich als *reine *Identität, ohne Gegensatz des Unendlichen und Endlichen. Denn in dem *An-sich*, von dem alles Handeln die bloße Erscheinung ist, ist das Endliche im Unendlichen, und also außer Differenz mit ihm. Das Letztere ist nur möglich, wo das Endliche etwas für sich, real ist, also inwiefern das Unendliche im Endlichen repräsentirt ist. Der Gegensatz der Besonderheit und Allgemeinheit drückt sich in Bezug auf das Handeln als der der Freiheit und der Nothwendigkeit aus. Auch diese also sind in dem An-sich des Handelns eins. Ist also im Epos kein Gegensatz des Unendlichen und Endlichen, so kann auch kein Streit zwischen Freiheit und Nothwendigkeit in ihm dargestellt seyn. Beide erscheinen eingewickelt in einer gemeinschaftlichen Einheit. Der Streit der Freiheit und Nothwendigkeit wird nur durch das Schicksal entschieden, und ruft es gleichsam hervor. Alle Entgegensetzung von Nothwendigkeit und Freiheit liegt nur in der Besonderheit, in der Differenz. Durch das Differenzverhältniß der Besonderheit erhält die Identität zu ihr das Verhältniß des Grundes, und erscheint demnach als Schicksal. In dem An-sich des Handelns, als der absoluten Identität, ist kein Schicksal. Die erste Bestimmung des Epos also ist so zu fassen: *es stellt die Handlung in der Identität der Freiheit und Nothwendigkeit dar, ohne Gegensatz des Unendlichen und Endlichen, ohne Streit und eben deßwegen ohne Schicksal.*"}]}, {"page_pdf": 1776, "page_book": 647, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Es ist höchst auffallend, wenn man das homerische Epos selbst mit den frühesten Werken der lyrischen Poesie vergleicht, in ihm durchaus keine Anregung des Unendlichen zu finden. Das Leben und Handeln der Menschen bewegt sich von der einen Seite betrachtet in der reinen Endlichkeit, aber eben deßwegen auch in der absoluten Identität der Freiheit und Nothwendigkeit. Die Hülle, welche beide wie in der Knospe verschließt, ist noch nicht gebrochen, nirgends ist Empörung gegen das Schicksal, obgleich Trotz gegen die Götter, weil diese selbst nicht über- und außernatürlich sind, sondern mit in den Kreis menschlicher Begebenheiten fallen. Man könnte einwenden, daß doch auch Homer schon die schwarzen Keren und das Verhängniß kenne, dem selbst Zeus und die andern Götter unterworfen sind. Dieß ist wahr, aber das Verhängniß *erscheint *eben deßwegen noch nicht als Schicksal, weil kein Widerstreit dagegen erscheint. Götter und Menschen, die ganze Welt, die das Epos umfaßt, sind in der höchsten Identität mit ihm dargestellt. Aeußerst bedeutend ist in dieser Rücksicht die Stelle im 16. Gesang der Ilias,1 wo Zeus seinen geliebten Sarpedon aus den Händen des Patroklos und vom Tode erretten will und Here ihn mit den Worten erinnert:"}, {"type": "footnote", "text": "Einen sterblichen Mann längst auserseh'n dem Verhängniß Denkst du anjetzt von des Tods grau'nvoller Gewalt zu erlösen."}, {"type": "paragraph", "text": "Sie führt hierauf an, daß auch andere Götter, wenn er den Sarpedon lebend entrückte, das Gleiche für ihre Söhne begehrten, und fährt fort:"}, {"type": "footnote", "text": "Auf, wofern du ihn liebst und deine Seel' ihn betrauert, Siehe, so laß ihn zwar im Ungestümme der Feldschlacht Sterben - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - Aber sobald ihn verlassen der Geist und der Odem des Lebens, Gib ihn hinwegzutragen dem Tod und dem ruhigen Schlafe, Bis sie gekommen zum Volk des weiten Lykierlandes, Wo ihn rühmlich bestatten die Brüder zugleich und Verwandten, Mit Grabhügel und Säule; denn das ist Ehre der Todten."}, {"type": "paragraph", "text": "In dieser Stelle erscheint das Verhängniß in der Milde einer stillen Nothwendigkeit, gegen die es noch keine Empörung, keinen Widerstreit gibt, denn auch Zeus gehorcht der Here und"}, {"type": "footnote", "text": "1 442 ff."}, {"type": "footnote", "text": "- beträufelt mit blutigen Tropfen die Erde Ehrend den theuren Sohn - - - - - - - - - - - 1"}, {"type": "paragraph", "text": "Noch viel weniger ist den Helden der Ilias irgend ein Gefühl oder Widerstreit gegen das Schicksal"}]}, {"page_pdf": 1777, "page_book": 649, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "verliehen, und das Epos stellt sich auf diese Weise höchst bedeutend zwischen die zwei andern Gattungen, das lyrische Gedicht, wo der bloße Streit des Unendlichen und Endlichen, die Dissonanz der Freiheit und Nothwendigkeit ohne vollständige und andere als subjektive Auflösung herrscht, und die Tragödie, wo der Streit und das Schicksal zugleich dargestellt ist. Die Identität, die in dem Epos noch verhüllt und als milde Gewalt herrschte, entladet sich da, wo ihr der Streit gegenüber steht, in herben und gewaltigen Schlägen. Die Tragödie kann insofern allerdings als Synthese des Lyrischen und Epischen betrachtet werden, da die Identität des Letzteren in ihr durch den Gegensatz selbst sich in das Schicksal verwandelt. Das Epos, verglichen mit der Tragödie, ist also ohne Streit gegen das Unendliche, aber auch schicksallos. 2) Das Handeln ist in seinem *An-sich *zeitlos, denn alle Zeit ist nur Differenz der Möglichkeit und Wirklichkeit, und alles erscheinende Handeln ist nur Zerlegung jener Identität, in der alles zumal ist. Das Epos muß ein Bild dieser Zeitlosigkeit seyn. Wie ist dies möglich? - Die Poesie ist als Rede selbst an die Zeit gebunden, alle poetische Darstellung nothwendig successiv. Hier scheint also ein unauflöslicher Widerspruch zu seyn. Er hebt sich auf folgende Art. Die Poesie selbst als solche muß wie außer der Zeit, von der Zeit unberührt seyn, sie muß daher alle Zeit, alles Successive rein in den Gegenstand legen und dadurch sich selbst ruhig erhalten und unbewegt von dem Strom der Aufeinanderfolge über ihm schweben. So ist in dem * An-sich *alles Handelns, an dessen Stelle die Poesie tritt, keine Zeit, nur in den Gegenständen *als solchen *ist sie, und jede Idee, indem sie aus dem An-sich als Gegenstand hervortritt, tritt in die Zeit ein. Das Epos selbst also muß das Ruhige und dagegen der Gegenstand das Bewegte seyn. - Man denke sich einmal die Umkehrung, nämlich daß"}, {"type": "footnote", "text": "1 Vgl. über diese Stelle Phil. der Mythologie S. 360. D. H."}, {"type": "paragraph", "text": "das Epos Darstellung des Ruhenden durch Bewegung sey, so daß die Bewegung in die Poesie und die Ruhe in den Gegenstand fiele, so würde dieß sogleich den epischen Charakter aufheben, es entstünde dadurch die beschreibende Dichtart, das sogenannte poetische Gemälde, und fremder kann dem Epos nichts seyn als dieses. Es ist ein widerstrebender Anblick, den beschreibenden Dichter sich anstrengen und bewegen zu sehen, während der Gegenstand immer unbeweglich bleibt. Weßhalb selbst da, wo das Epos das Ruhende beschreibt, das Ruhende selbst in Bewegung und Fortschreitung verwandelt werden muß. Beispiel: Schild des Achilles, obwohl auch nach andern Gründen dieses Stück der Ilias zu den spätesten gehört. Wenn wir nun jedoch auf den allgemeinen Typus reflektiren, der den Formen der Kunst zu Grunde liegt, so finden wir, daß das Epos in der Poesie dem Gemälde in der bildenden Kunst entspreche. Wie dieses, so ist auch jenes Darstellung des Besondern im Allgemeinen, des Endlichen im Unendlichen. Wie in diesem Licht und Nichtlicht in Eine identische Masse zusammen fließt, so in jenem auch Besonderheit und Allgemeinheit. Wie in diesem die Fläche herrschend ist, so breitet sich auch das Epos nach allen Seiten wie ein Ocean aus, der Länder und Völker verbindet. Wie ist nun dieses Verhältniß zu begreifen? Der Gegenstand des Gemäldes, könnte man einwenden, ist ruhig, in dem des Epos dagegen ein stetiger Fortschritt. Allein in diesem Einwurf wird das, was die bloße Grenze der Malerei ist, zu ihrem Wesen gemacht. Objektiv angesehen ist das, was wir den Gegenstand im Gemälde nennen können, nicht ohne Fortschreitung; es ist nur ein - subjektiv - fixirter Moment, aber wir sehen besonders bei affektvollen Gegenständen, aber überhaupt im historischen Gemälde, daß der nächste Moment alle Verhältnisse ändert, aber dieser nächste Moment ist nicht dargestellt, alle Figuren des Gemäldes bleiben in ihrer Stellung; es ist ein empirisch zur Ewigkeit gemachter Moment. Man kann aber wegen dieser in gegenwärtigem Betracht bloß zufälligen Begrenzung nicht sagen, der Gegenstand ruhe; vielmehr schreitet"}]}, {"page_pdf": 1778, "page_book": 650, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "er fort, nur ist uns der nächste Moment entzogen. Es ist dasselbe Verhältniß wie"}, {"type": "paragraph", "text": "im Epos. Im Epos fällt die Fortschreitung ganz in den Gegenstand, der ewig bewegt ist, die Ruhe aber in die Form der Darstellung, wie im Gemälde, wo das stets Fortschreitende nur durch die Darstellung fixirt ist. Das Verweilen, welches bei dem Gemälde in den Gegenstand zu fallen scheint, fällt hier ins Subjekt zurück, und dieß der Grund einer sogleich noch weiter zu erklärenden Eigenthümlichkeit des Epos, daß ihm auch der Augenblick werth ist, daß es nicht forteilt, eben deßwegen, weil das Subjekt ruht, gleichsam unangerührt von der Zeit, außer ihr. Wir werden uns also über die Art wie das Epos ein Bild der Zeitlosigkeit des Handelns in seinem An-sich ist, so ausdrücken können: das, was selbst in keiner Zeit ist, faßt alle Zeit in sich, und umgekehrt, ist aber deßwegen indifferent gegen die Zeit. *Diese Indifferenz gegen die Zeit ist der Grundcharakter des Epos.* Es ist gleich der absoluten Einheit, innerhalb der alles ist, wird und wechselt, die aber selbst keinem Wechsel unterworfen ist. Die Kette der Ursachen und Wirkungen reicht ins Unendliche zurück, aber das, was diese Reihe der Succession selbst wieder in sich schließt, liegt nicht mit in der Reihe, sondern ist außer aller Zeit. Die weiteren Bestimmungen ergeben sich nun von selbst und sind gewissermaßen die bloße Folge der eben angegebenen. Nämlich 3) da die Absolutheit nicht auf der Extension, sondern auf der Idee beruht, und daher in dem An-sich alles gleich absolut und das Ganze nicht absoluter ist als der Theil, so muß auch diese Bestimmung auf das Epos übergehen. Es ist also der Anfang wie das Ende in dem Epos gleich absolut, und inwiefern überhaupt das Nichtbedingte sich in der Erscheinung als *Zufälligkeit *darstellt, erscheint beides als *zufällig. *Die Zufälligkeit des Anfangs und des Endes ist also in dem Epos der Ausdruck seiner Unendlichkeit und Absolutheit. Mit Recht ist derjenige Sänger, der den trojanischen Krieg von dem Ei der Leda anfangen wollte, dadurch zum Sprichwort geworden. Es ist gegen die Natur und Idee des Epos, daß es rückwärts oder vorwärts bedingt erscheine. In der Succession der Dinge, wie sie im Absoluten"}, {"type": "paragraph", "text": "vorgebildet ist, ist alles absoluter Anfang, aber eben deßwegen ist hier auch kein Anfang. Das Epos, indem es absolut beginnt, constituirt sich eben dadurch selbst zu einem gleichsam aus dem Absoluten selbst herausgehörten Stück, das, in sich absolut, doch wieder nur Bruchstück eines absoluten und unübersehbaren Ganzen ist, wie der Ocean, weil er nur durch den Himmel begrenzt wird, unmittelbar an die Unendlichkeit hinausweist. Die Ilias beginnt absolut, mit dem Vorsatz den Groll des Achilleus zu singen, und sie ist ebenso absolut geschlossen, da kein Grund ist, mit dem Tod des Hektor zu enden (denn bekanntlich sind die beiden letzten Gesänge spätere Zuthaten, und auch wenn man diese mit zu dem unter dem Namen der Ilias nun vorliegenden Ganzen rechnet, so ist auch ihnen kein eigentlicher Grund des Schließens). Ebenso absolut beginnt nun die Odyssee wieder. - Wenn man diese als Zufälligkeit erscheinende Absolutheit, die tief im Wesen des Epos gegründet ist, auffaßt, so reicht diese allein hin, die neuere Wolfsche Ansicht des Homer nicht so fremd und unfaßlich zu finden, als sie von den meisten gefunden wird. Sie haben sich aus den gewöhnlichen Theorien gewisse Grundsätze über die Künstlichkeit des Epos genommen, und können damit die Zufälligkeit nicht reimen, womit, nach ihrer Art sich die Wolfsche Hypothese zu deuten, der Homer zusammengekommen. Freilich ist diese grobe Zufälligkeit aufgehoben, sobald man sich der Idee bemächtigt, wie ein ganzes Geschlecht einem Individuum gleich seyn kann (wovon schon früher in der Lehre von der Mythologie geredet war); aber auch diejenige"}]}, {"page_pdf": 1779, "page_book": 652, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Zufälligkeit, die in dem Entstehen der Homerischen Gesänge wirklich gewaltet hat, trifft eben hier mit dem Nothwendigen und der Kunst zusammen, da das Epos seiner Natur nach sich mit einem Schein der Zufälligkeit darstellen muß. Dieß wird weiter bestätigt durch folgende Bestimmungen. 4) Die Indifferenz gegen die Zeit muß nothwendig auch eine Gleichgültigkeit in Behandlung der Zeit zur Folge haben, so daß in der Zeit, welche das Epos begreift, alles Raum hat, das Größte wie das Kleinste, das Unbedeutendste wie das Bedeutendste. Es entsteht dadurch auf eine viel vollkommenere Weise als in der gemeinen"}, {"type": "paragraph", "text": "Erscheinung das Bild der Identität aller Dinge im Absoluten, die *Stetigkeit*. Alles was zu derselben gehört, die unbedeutend scheinenden Handlungen des Essens, Trinkens, des Aufstehens, zu Bettgehens, des Anlegens der Kleider und des Schmucks - alles wird mit der verhältnißmäßigen Ausführlichkeit, wie alles andere beschrieben. Alles ist gleich wichtig oder unwichtig, gleich groß und klein. Dadurch vorzüglich erhebt sich die Poesie im Epos und der Dichter selbst gleichsam zu der Theilnahme an der göttlichen Natur, vor der das Große und das Kleine gleich ist, und die mit ruhigem Auge, wie ein Dichter sagt, ein Königreich und einen Ameisenhaufen zerstören sieht. Denn 5) in dem *An-sich * des Handelns sind alle Dinge und alle Begebenheiten in gleichem Gewicht; keine wird von der andern verdrungen, weil keine größer ist als die andere. Alles ist hier absolut, als ob ihm nichts vorangegangen wäre, und ihm auch nichts folgen sollte. Dasselbe also auch im Epos. Der Dichter muß mit ungetheilter Seele, ohne Andenken des Vergangenen und ohne Voraussicht der Zukunft bei der Gegenwart weilen, und er selbst nicht forteilen, da er auch in der Bewegung ruht, sondern nur dem Gegenstand seine Bewegung lassen. Endlich faßt sich alles darin zusammen, daß die Poesie oder der Dichter über allem wie ein höheres, von nichts angerührtes Wesen schwebe. Nur innerhalb des Umkreises, den sein Gedicht beschreibt, stößt und drängt eins das andere, Begebenheit Begebenheit, Leidenschaft Leidenschaft; er selbst tritt nie in diesen Umkreis herein, und wird dadurch zum Gott und zum vollkommensten Bild der göttlichen Natur. Ihn drängt nichts, er läßt alles ruhig geschehen, er greift dem Lauf der Begebenheiten nicht vor, denn er ist selbst nicht davon ergriffen; er schaut ruhig auf alles herab, denn ihn ergreift nichts von dem, was geschieht. Er selbst empfindet nie etwas von dem Gegenstand, und dieser kann daher das Höchste und das Niedrigste, das Außerordentlichste und das Gemeinste, tragisch und komisch seyn, ohne daß *er selbst*, der Dichter, je hoch oder niedrig, tragisch oder komisch würde. Alle Leidenschaft fällt in den Gegenstand selbst; Achilles weint und wehklagt schmerzlich um den verlorenen Freund, Patroklos; der Dichter"}, {"type": "paragraph", "text": "selbst erscheint weder gerührt noch ungerührt, denn er erscheint überhaupt nicht. In der weiten Umwölbung des Ganzen hat neben den herrlichen Gestalten der Helden auch Thersites, sowie neben den großen Gestalten der Unterwelt in der Odyssee auf der Oberwelt auch der göttliche Sauhirt und der Hund des Odysseus seinen Platz. Diesem geistigen, in dem ewigen Gleichgewicht der Seele schwebenden Rhythmus muß nun auch ein gleicher hörbarer Rhythmus entsprechen. Aristoteles nennt den *Hexameter *das beständigste und gewichtigste aller Sylbenmaße. Der Hexameter hat ebensowenig einen fortreißenden, leidenschaftlichen, als einen verweilenden und zurückhaltenden Rhythmus; er drückt auch in diesem Gleichgewicht des Verweilens und des Fortschreitens die Indifferenz aus, die dem ganzen Epos zu Grunde liegt. Da nun"}]}, {"page_pdf": 1780, "page_book": 654, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "noch überdieß der Hexameter in seiner Identität wieder große Mannichfaltigkeit zuläßt, so ist er dadurch am meisten geeignet sich dem Gegenstand anzuschließen, ohne ihm Gewalt anzuthun, und insofern das objektivste aller Versmaaße. Dieß sind die vorzüglichsten und auszeichnendsten Bestimmungen des epischen Gedichts, von denen *Sie *eine mehr kritische und historische Ausführung in der Recension von Göthes Hermann und Dorothea von A. W. Schlegel finden können. Nun noch von einigen besonderen Formen des Epos, dergleichen die Reden, die Gleichnisse und die Episoden sind. Der *Dialog* neigt sich seiner Natur nach und sich selbst überlassen zum Lyrischen hin, weil er mehr vom Selbstbewußtseyn aus und an das Selbstbewußtseyn geht. Die Rede würde also den Charakter des Epos selbst verändern, wenn nicht vielmehr umgekehrt ihr Charakter nach dem des Epos modificirt wäre. Diese Modification muß sich nun durch den Gegensatz gegen den *eigenthümlichen *Charakter der Rede bestimmen. Dieser ist Beschränkung auf die Absicht der Rede und darum Forteilen zum Ziel, wo etwas erreicht; Heftigkeit und Kürze, wo Leidenschaft ausgedrückt werden soll. Dieß alles ist im Epos gemäßigt und dem Hauptcharakter untergeordnet. Selbst in der leidenschaftlichsten Rede ist noch die epische Fülle und Umständlichkeit, der"}, {"type": "paragraph", "text": "Gebrauch der Beiwörter, wodurch die Sprache eine gewisse Sattheit erhält, wie in dem einfach erzählenden Gang. - Ebenso verhält es sich mit dem *Gleichniß. *Im lyrischen Gedicht, auch in der Tragödie wirkt es oft nur dem Blitz ähnlich, der plötzlich einen dunklen Zustand erleuchtet und von der Nacht wieder verschlungen wird. Im Epos hat es Leben in sich selbst, und ist selbst wieder ein kleines Epos. - Was endlich die *Episode *betrifft, so ist auch diese zunächst ein Abdruck der Gleichgültigkeit des Sängers gegen seine Gegenstände, auch die hauptsächlichsten, der Abwesenheit der Furcht, auch die größte Verwicklung nicht mehr zu übersehen, oder über dem Nebengegenstand den Hauptgegenstand aus dem Gesicht zu verlieren. Die Episode ist also ein nothwendiger Theil des Epos, um es zu einem vollkommenen Bild des Lebens zu machen. In den gewöhnlichen Theorien wird auch noch das *Wunderbare *als ein nothwendiger Hebel der Epopee angeführt. Allein dieß kann nur von der modernen Gattung gelten und hat von dem Epos überhaupt ausgesagt eine ganz verkehrte Ansicht des alten Epos zum Grunde. Der nordischen Barbarei haben die Götter Homers und ihre Wirkungen nur als Wunder erscheinen können, wie ja auch die Kunstrichter dieser Art es für absichtliches rhetorisches und poetisches Pathos halten, wenn Homer, anstatt zu erzählen: es blitzte, sagt: Zeus habe Blitze gesendet. Den Griechen und dem alten Epos insbesondere ist das Wunderbare gänzlich fremd, denn ihre Götter sind innerhalb der Natur. Was den eigentlichen epischen *Stoff* betrifft, so liegt schon in dem, was über die Bestimmung des Epos, ein Bild des Absoluten selbst zu seyn, gesagt worden ist, daß es einen *wahrhaft universellen *Stoff fordert, und inwiefern dieser nur durch Mythologie existiren kann, daß *ohne Mythologie *das Epos undenkbar ist. Ja die Identität beider ist so groß, daß die Mythologie nicht eher die wahre Objektivität als in dem Epos selbst erlangt. Da das Epos die objektivste und allgemeinste Dichtart ist, so fällt sie mit dem Stoff aller Poesie am meisten in eins. Wie nun die Mythologie nur Eine ist, so"}, {"type": "paragraph", "text": "kann bei dieser Untrennbarkeit des Stoffs und der Form in einer gesetzmäßigen Bildung wie die der"}]}, {"page_pdf": 1781, "page_book": 656, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "griechischen Poesie auch das Epos nur Eines seyn und kann höchstens darin dem allgemeinen Gesetz der Erscheinung folgen, daß es sich in seiner Identität durch zwei verschiedene Einheiten ausdrückt. Die Ilias und Odyssee sind nur die zwei Seiten eines und desselbigen Gedichts. Die Verschiedenheit der Urheber kommt hier nicht in Betracht; sie sind durch ihre Natur eins und darum auch durch den gemeinschaftlichen Namen Homeros vereinigt, der selbst allegorisch und bedeutend ist. Einige haben den Gegensatz der Ilias und Odyssee als den der aufgehenden und untergehenden Sonne dargestellt. Ich möchte die Ilias das centrifugale, die Odyssee das centripetale Gedicht nennen. Was die *neueren *im Sinn des alten Epos unternommenen Gedichte betrifft, so will ich den Uebergang zu diesen durch eine kurze *Vergleichung des Virgil mit Homer *machen. Man kann Virgil fast nach allen angegebenen Bestimmungen dem Homer entgegensetzen. Die erste gleich, die Schicksallosigkeit des Epos betreffend, so hat sich Virgil vielmehr bestrebt in die Handlung Schicksal durch eine Art tragischer Verwicklung zu bringen. Die Bestimmung des Epos, die Bewegung ganz allein in den Gegenstand zu legen, ist ebensowenig erfüllt, da er nicht selten zur Theilnahme an seinem Gegenstand herabsinkt. Die erhabene Zufälligkeit des Epos, dessen Anfang und Ende ebenso, wie die dunkle Zeit der Urwelt und die Zukunft unbestimmt ist, ist durch die Aeneis gänzlich aufgehoben. Sie hat einen bestimmten Zweck, die Gründung des römischen Reichs von Troja abzuleiten, und dadurch dem Augustus zu schmeicheln. Dieser Zweck ist gleich anfangs bestimmt verkündet, und wie die Absicht erreicht ist, schließt auch das Gedicht. Der Dichter überläßt hier nicht den Gegenstand seiner eignen Bewegung, sondern er macht etwas aus ihm. Die Gleichgültigkeit in Behandlung der Zeit fehlt gänzlich, der Dichter meidet sogar die Stetigkeit und hat gleichsam beständig den Zustand seines gebildeten Cirkels vor Augen, den er durch die Einfalt der Erzählung nicht beleidigen will. Sein Ausdruck ist daher auch künstlich,"}, {"type": "paragraph", "text": "rhetorisch verflochten, prächtig. In seinen Reden ist er durchaus lyrisch oder rednerisch und in der Episode der Liebesgeschichte der Dido fast modern. - Das Ansehen des Virgil in den Schulen und bei modernen Kunstrichtern hat lange Zeit nicht nur die Theorie des Epos verfälscht (die gewöhnlichen Theorien sind ganz nach dem Virgil gemodelt, einer von den vielen Beweisen, daß die Menschen lieber aus der zweiten Hand das Verschlechterte, als aus der ersten das Treffliche wollen), dieses Ansehen Virgils hat auch auf die späteren Versuche epischer Poesie nachtheiligen Einfluß gehabt. In der That verräth *Milton *eine Bildsamkeit des Geistes, die kaum zweifeln läßt, daß wenn er das unverstellte Vorbild des Epos vor Augen hatte, er sich ihm beträchtlich mehr genähert hätte, als es geschehen ist; wenn nicht etwa die tiefere Kenntniß ihn noch weiter bis zu der Einsicht geführt hätte, daß eine Sprache, in der die alten Sylbenmaße nicht Platz greifen können, überhaupt nicht mit den Alten im Epos wetteifern kann. Milton theilt übrigens die meisten Fehler des Virgil, z.B. den Mangel derjenigen Absichtlosigkeit, die zum Epos gehört, obwohl er in Ansehung der Sprache z.B. sich verhältnißmäßig der Einfalt des Epos mehr als Virgil nähert. Zu den Fehlern, die er mit Virgil gemein hat, kommen die eigenthümlichen hinzu, deren Grund in den Begriffen und dem Charakter der Zeit, sowie in der Natur des Gegenstandes liegen. Nach allem, was zuvor gezeigt wurde, bedarf es keines Beweises, daß der Stoff, welchen *Klopstock* gewählt hat, besonders in der Art, wie er von ihm genommen ist, kein epischer Stoff sey. Klopstock wollte ihn erhaben nehmen, und die Vorstellungen nicht der mystischen, sondern der unmystischen und unpoetischen, noch mit einiger Aufklärung versetzten Dogmatik durch seine Anstrengungen zur Erhabenheit hinauftreiben. Aber wenn erstens überhaupt das Leben und der Tod Christi episch behandelt werden könnte, so müßte es rein menschlich genommen und mit der größten Einfalt - fast idyllisch - behandelt werden. Oder müßte das Gedicht ganz im modernen Geiste und von den Ideen des christlichen Mysticismus und Mythologie erfüllt seyn. Dann wäre es wenigstens als absolute Entgegensetzung gegen das antike Epos in seiner Art"}]}, {"page_pdf": 1782, "page_book": 657, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "wieder absolut. Klopstock gehört aber zu denjenigen Dichtern, in welchen Religion als lebendige Anschauung des Universums und Intuition der Ideen am wenigsten wohnt. Das Herrschende in ihm ist der Verstandesbegriff. In diesem Verstandessinn nimmt er die Unendlichkeit Gottes, die Hoheit Christi, und anstatt die Unendlichkeit und Hoheit in den Gegenstand zu legen, fällt sie vielmehr stets in den Dichter zurück, so daß beständig nur * er selbst * und * seine *Bewegung erscheint, der Gegenstand selbst aber unbeweglich bleibt und weder Gestalt noch Fortschritt gewinnt. Das Widersinnigste ist, daß der Schluß Gottes, seinen Sohn zur Erlösung der Menschen dahin zu geben, von Ewigkeit genommen ist, daß Christus, der selbst Gott ist, ihn weiß, und daß also über das Ende bei dem Helden des Gedichts gar kein Zweifel seyn kann, wodurch die ganze Handlung des Gedichts schleppend und die etwaige Maschinerie, durch welche das Ende herbeigeführt wird, als völlig nutzlos erscheint. Man kann sich übrigens von dem Anblick dieses Gedichts nicht ohne Bedauern abwenden, daß eine so große Kraft so fruchtlos verschwendet worden ist. Es war nur der Zweck, von *denjenigen *epischen Gedichten der Neueren zu sprechen, welche Ansprüche machen mehr oder weniger im Sinn des alten Epos gedichtet zu seyn. Ueber Goethes Hermann und Dorothea, das einzige epische Gedicht im wahren Sinn der Alten, werde ich noch besonders reden, und auch von der eigentlichen modernen Epopee kann hier noch nicht die Rede seyn. Wir haben noch einige der besondern epischen Formen zu betrachten. Man könnte zwar vorläufig fragen, wie das epische Gedicht als die höchste Identität einiger Differenz fähig seyn könne. Es versteht sich nun wohl von selbst, daß der Raum, in welchen das epische Gedicht ausweichen kann, sehr beschränkt seyn muß; es versteht sich aber noch unmittelbarer, daß es durch jene Ausweichung von dem Punkt, in den es einzig fallen kann, auch nothwendig den Charakter abgelegt, der nur an jenen Punkt gebunden ist. Es liegen nun zunächst nur zwei Möglichkeiten im epischen Gedicht, welche in ihrer Differenziirung zwei besondere Gattungen bilden. Das"}, {"type": "paragraph", "text": "Epos ist die objektive Gattung, wenn wir unter Objektivem das absolut-Objektive verstehen. Es ist schlechthin objektiv, weil es die höchste Identität der Subjektivität und Objektivität ist. Aus dieser Identität also kann die Poesie heraustreten bloß dadurch, daß sie entweder *relativ-*objektiver oder relativ-subjektiver wird. Im Epos verhält sich sowohl das Subjekt (der Dichter) als der Gegenstand objektiv. Diese Identität kann nun nach zwei Seiten aufgehoben werden, a) so, daß die Subjektivität oder die Besonderheit ins Objekt, die Objektivität oder Allgemeingültigkeit in den Darstellenden, b) daß die Objektivität, die Allgemeinheit in den Gegenstand, die Subjektivität in den Darstellenden gelegt ist. Diese zwei Pole sind in der Poesie wirklich dargestellt, aber sie selbst differenziiren sich in sich wieder nach der subjektiven und objektiven Seite. Die Sphäre der relativ-objektiven epischen Poesie (wo es nämlich die Darstellung ist) ist durch die *Elegie *und die *Idylle*, die sich unter sich wieder, jene als das Subjektive, diese als das Objektive verhalten; die Sphäre der relativ-subjektiveren Poesie (wo es nämlich die Darstellung ist) ist durch das *Lehrgedicht *und die *Satyre*, wovon jenes das Subjektive, diese das Objektive ist, beschrieben. Man könnte versucht seyn, gegen diese Eintheilung anzuführen, daß es nicht einzusehen, wie die Elegie, die insgemein für eine subjektiv-lyrische Ergießung angesehen wird, objektiver seyn könne als das Lehrgedicht, welches man dagegen für das relativ-objektivste zu halten tentirt seyn könnte. Es ist also"}]}, {"page_pdf": 1783, "page_book": 659, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "zu erinnern, daß hierbei keineswegs der gewöhnliche Begriff der Elegie zugegeben wird, der ihr allerdings die Objektivität, aber auch das Epische rauben und sie zu einem bloß lyrischen Gedicht machen würde. Was aber das Lehrgedicht betrifft, so geht die Poesie in ihm zu dem *Wissen *als der ersten Potenz zurück, welches *als Wissen *immer subjektiv bleibt. Die bestimmteren Gründe dieser Eintheilung sind folgende. Vergleichen wir Elegie und Idylle einerseits und Lehrgedicht und Satyre von der andern Seite, so finden wir die ersten beiden darin übereinstimmend unter sich und darin verschieden von den andern beiden, daß jene ohne Zweck und Absicht sind"}, {"type": "paragraph", "text": "und nur um ihrer selbst willen zu seyn scheinen, diese aber immer einen bestimmten Zweck haben, und schon dadurch sind die beiden letzten Gattungen in die Sphäre der Subjektivität gewiesen. Vergleichen wir ferner Elegie und Idylle unter sich, so sind sich beide dadurch gleich, daß sie auf einen universellen und objektiven Stoff Verzicht thun, daß jene den Zustand oder die Begebenheit eines Individuums, aber objektiv behandelt, diese den Zustand und das Leben einer Gattung darstellt, die überhaupt isolirt ist und eine besondere Welt bildet, nicht nur in sogenannten Hirtengedichten, sondern auch in anderen Arten, z.B. in häuslichen Idyllen, ja in denen nur z.B. eine Liebe, welche die Liebenden ganz auf sich beschränkt und die Welt außer sich vergessen macht, dargestellt wird, wie in Voßens Luise. Verschieden sind aber beide eben dadurch wieder, daß die Elegie mehr zu dem Lyrischen, die Idylle dagegen nothwendigerweise mehr zu dem Dramatischen sich hinneigt. Man kann nun Elegie und Idylle *gemeinschaftlich *wieder dem Lehrgedicht und der Satyre so entgegensetzen, daß in jenen der Stoff oder Gegenstand beschränkt, und insofern, wenn man will, subjektiv, dagegen der Ort der Darstellung allgemein und objektiv ist, während in diesen der Stoff oder Gegenstand allgemein, dafür aber die Darstellung oder das Princip, von dem sie ausgehen, subjektiv ist. Lehrgedicht und Satyre können sich daher auch, weil sie sich von der einen Seite in Ansehung des Stoffs gleich sind, eben deßwegen von der andern Seite als subjektiv und objektiv auch nur durch den Stoff entgegengesetzt seyn. Der des Lehrgedichts ist der subjektive, weil er im Wissen liegt, der der Satyre ist der objektive, weil sie sich auf das Handeln bezieht, welches objektiver ist als das Wissen. Das Princip der Darstellung ist aber in beiden subjektiv. Dort liegt es im Geist, hier mehr im Gemüth und der sittlichen Stimmung."}, {"type": "paragraph", "text": "*Kurze Betrachtung dieser Gattungen im Einzelnen.*"}, {"type": "paragraph", "text": "Ich will keine Definitionen geben. Jede Art der Kunst ist nur durch ihre Stelle bestimmt, diese ist ihre Erklärung. Uebrigens aber mag sie dieser Stelle entsprechen, auf welche Weise sie will. Jeder"}, {"type": "paragraph", "text": "Dichtart liegt eine Idee zu Grunde. Wird nun ihr Begriff nach der einzelnen Erscheinung bestimmt, so ist er, weil diese der Idee niemals ganz angemessen seyn kann, nothwendig in der Gefahr über kurz oder lang zu eng befunden und also verworfen zu werden oder gar gebraucht zu werden, um ein in ihre Schranken nicht sich fügendes, auch vortreffliches Kunstwerk zu verwerfen. Die Idee jeder Dichtart aber ist durch die Möglichkeit bestimmt, die durch sie erfüllt ist. Der Begriff, den die Neueren von der *Elegie *fast allgemein gehabt haben, ist, daß sie Klaggedichte seyen, ihr herrschender Geist empfindsame Trauer. Es ist nicht zu leugnen, daß auch die Klage und die Trauer sich in dieser Dichtart ausgesprochen hat, und daß die Elegie vorzüglich zu Klaggesängen über"}]}, {"page_pdf": 1784, "page_book": 661, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Verstorbene bestimmt war. Dieß aber ist nur Eine Erscheinungsweise, übrigens aber von unendlicher Mannichfaltigkeit und Bildsamkeit und so, daß diese Eine Gattung, obwohl allerdings nur bruchstücklich, das ganze Leben zu umfassen fähig ist. Die Elegie ist, als Art des epischen Gedichts, ihrer Natur nach *geschichtlich;* auch als Klaggesang verleugnet sie ihren Charakter nicht, ja sie ist, könnte man sagen, der Trauer fähig eben nur, weil sie des Blicks in die Vergangenheit fähig ist, wie das Epos. Uebrigens weilt sie ebenso bestimmt in der Gegenwart, und besingt die befriedigte Sehnsucht nicht minder als den Stachel der unbefriedigten. Ihre Grenze in der Darstellung ist ihr nicht durch den individuellen und einzelnen Zustand gesteckt, sondern sie schweift von da wirklich in den epischen Kreis aus. Die Elegie ist durch ihre Natur schon eine der unbegrenzbarsten Gattungen, daher sich außer dem allgemeinen Charakter, der durch ihr Verhältniß zum Epos und zur Idylle bestimmt ist, nur eben diese unendliche Bildsamkeit als ihr eigenthümlichstes und natürlichstes Wesen bezeichnen läßt. Die unmittelbarste Bekanntschaft mit dem Geist der Elegie gewinnt man durch die Muster der Alten. Einige der schönsten Bruchstücke des Phanokles, des Hermesianax sind im Athenäum übersetzt. Die Elegie hat aber auch in der römischen Sprache in Tibull, Catull und Properz wieder aufleben können, und zu unseren Zeiten hat Goethe durch seine römischen Elegien die ächte Gattung wiederhergestellt."}, {"type": "paragraph", "text": "An Goethes Elegien ließe sich am unmittelbarsten zeigen, daß in Ansehung der Elegie die Subjektivität in das Objekt, dagegen die Objektivität in die Darstellung und das darstellende Princip fällt. Diese Elegien besingen den höchsten Reiz des Lebens und der Lust, aber auf eine wahrhaft epische Weise mit Verbreitung über den großen Gegenstand seiner Umgebung. Die *Idylle *ist gegenüber von der Elegie die objektivere Gattung, und also überhaupt die objektivste unter den vier dem epischen Gedicht untergeordneten Gattungen. Da in ihr der Gegenstand (subjektiv) beschränkter als im Epos, und die allgemein gültige Ruhe also bloß in die Darstellung gelegt wird, so nähert sie sich dadurch schon mehr dem *Gemälde*, und dieß ist auch ihre ursprüngliche Bedeutung, da Idylle ein kleinstes Bild, ein Gemälde bezeichnet. Da sie ferner das Uebergewicht in das Objektive der Darstellung legen muß, so wird sie dadurch am meisten Idylle seyn, daß der Gegenstand sich mit roherer Besonderheit abhebt, weniger also gebildet ist als der des Epos. Die Idylle nimmt daher ihre Gegenstände nicht nur überhaupt aus einer beschränkten Welt, sondern macht sie auch in dieser noch scharf individuell, ja sogar local nach Sitten, Sprache, Charakter, etwa wie die menschlichen Gestalten in einer Landschaft seyn müssen, derb, von nichts entfernter als von Idealität. Nichts ist daher der Natur der Idylle widersprechender, als den Personen Empfindsamkeit, eine Art unschuldiger Sittlichkeit mitzutheilen. Wenn die Derbheit der theokritischen Idylle verlassen werden kann, so ist es nur, wenn dafür der ganze Charakter romantisch wird, wie in den vorzüglichsten Schäferpoesien der Italiener und Spanier. Wenn aber, wie in *Geßner*, neben dem Aechten und Antiken zugleich das romantische Princip fehlt, so kann man die Bewunderung, die seine Idyllen besonders im Ausland gefunden haben, nur als eine der unzähligen Aeußerungen der Unpoesie begreifen. In Geßners Idyllen, wie in sehr vielen der Franzosen, ist, ganz gegen den Geist der Idylle, eine Art von flacher, sittlich-empfindsamer Allgemeingültigkeit in den Gegenstand gelegt und die Gattung völlig verkehrt worden. Der ächte Geist der Idylle ist in einer späteren"}, {"type": "paragraph", "text": "Zeit auch in Deutschland wieder aufgelebt durch *Voßens *Luise, obgleich er die Ungünstigkeit des Locals nicht überwinden konnte, und was den Reiz, die Frischheit der Farben, die Lebendigkeit"}]}, {"page_pdf": 1785, "page_book": 663, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "natürlicher Aeußerungen betrifft, zu dem theokritischen Geist fast ganz das Verhältniß des nördlichen Deutschlands zu der Schönheit der sicilischen Fluren beobachtet. Die Italiener und Spanier haben auch in der Idylle das romantische Princip geltend gemacht, aber innerhalb der Begrenzung der Gattung, aber da ich nur den Pastor fido des Guarini kenne, so kann ich auch nur diesen als Beispiel anführen. Das Wesen der Romantik ist, daß es durch Gegensätze zum Ziel kommt und nicht sowohl die Identität als Totalität darstellt. So auch in der Gattung der Idylle. Das Derbe, rein und streng Gesonderte ist im Pastor fido in einige Charaktere gelegt und der Gegensatz dazu in anderen gegeben. Auf diese Weise hat das Ganze das Antike überschritten und doch die Gattung behauptet. Uebrigens hat die Idylle im Pastor fido eine wirkliche dramatische Höhe erreicht, und doch ließe sich zeigen, daß die Schicksallosigkeit der Idylle, die von der einen Seite darin aufgehoben, doch von der anderen wieder hergestellt ist. - Befreundung der Idylle mit allen Formen. Vorzügliche Hinneigung zum Dramatischen, weil die Darstellung noch objektiver. Schäferromane (Galatea des Cervantes). Unter denjenigen epischen Formen, welche durch ein Uebergewicht der *Subjektivität *in der Darstellung aus der Indifferenz der Gattung heraustreten, ist das *Lehrgedicht *selbst wieder die subjektivere Form. Wir haben vor allem ohne Zweifel die *Möglichkeit *eines Lehrgedichts zu untersuchen, worunter hier, wie sich versteht, die poetische Möglichkeit gemeint ist. Man kann erstens gegen die Gattung im Allgemeinen, also auch gegen die Satyre anführen, daß sie nothwendig einen Zweck hat, das Lehrgedicht zu lehren, die Satyre zu strafen, und daß sie, weil alle schöne Kunst nach außen ohne Zweck ist, beide nicht als Formen derselben gedacht werden können. Allein es ist mit diesem an sich wichtigen Grundsatz nicht gesagt, daß die Kunst nicht einen von ihr unabhängig vorhandenen Zweck oder ein wirkliches"}, {"type": "paragraph", "text": "Bedürfniß sich zur Form nehmen kann, wie ja auch die Architektur thut; es wird nur gefordert, daß sie sich *in sich selbst * wieder davon unabhängig zu machen wisse und die äußeren Zwecke *bloß *Form für sie seyen. Daß nun die Absicht, wissenschaftliche Lehren vorzutragen, für die Poesie nicht zur Form werden könne, dagegen existirt wenigstens von Seiten der Poesie kein denkbarer Grund, und die Forderung an das Lehrgedicht wäre nur die, in dem Werk selbst die Absicht wieder aufzuheben, so daß es um seiner selbst willen zu seyn scheinen könne. Dieß wird nun aber nie der Fall seyn können, als wenn die Form des *Wissens *im Lehrgedicht für sich fähig ist ein Reflex des All zu seyn. Da es eine Forderung ist, die an das Wissen, unabhängig von der Poesie, schon für sich selbst betrachtet gemacht wird, ein Bild des All zu seyn, so liegt schon im *Wissen * für sich die Möglichkeit, als *Form *der Poesie einzutreten. Wir haben demnach bloß die Art des Wissens zu bestimmen, von welchem dieß allein und vorzüglich gilt. Die Lehre, welche im didaktischen Gedicht vorgetragen wird, kann entweder sittlicher oder theoretischer und speculativer Natur seyn. Von der ersten Art ist die gnomische Poesie der Alten, z.B. die des Theognis. Hier wird das menschliche Leben als das Objektive zum Reflex des Subjektiven, nämlich der Weisheit und des praktischen Wissens gemacht. Wo sich die moralische Lehre auf Naturgegenstände bezieht, wie in dem hesiodischen *Werk*, in Gedichten über den Landbau u.s.w. geht das Bild der Natur als das eigentlich Objektive durch das Ganze hindurch und ist das Reflektirende des Subjektiven. Das Entgegengesetzte geschieht in dem eigentlich theoretischen Lehrgedicht. Hier wird das Wissen zum Reflex von einem Objektiven gemacht. Da nun in der höchsten Forderung dieses Objektive nur das Universum selbst seyn kann, so muß die *Art *des Wissens, welches zum Reflex dient, gleichfalls von universeller Natur seyn. Es ist bekannt, wie viele Lehrgedichte über ganz einzelne und besondere Gegenstände des Wissens verfaßt worden sind, über die Medicin z.B. oder einzelne Krankheiten, über Botanik, über die Kometen u.s.w. Die Beschränktheit des Gegenstandes an und für sich selbst ist hier nicht zu tadeln, wenn nur"}]}, {"page_pdf": 1786, "page_book": 664, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "dieser selbst allgemein und in der Beziehung aufs Universum gefaßt wird. In der Ermanglung der wahrhaft poetischen Ansicht des Gegenstandes selbst hat man alsdann auf verschiedene Weise ihn poetisch zu schmücken gesucht. Man hat die Vorstellungsarten und Bilder der Mythologie zu Hülfe gerufen. Man hat der Trockenheit des Gegenstandes durch geschichtliche Episoden aufzuhelfen gesucht, und was dergleichen mehr ist. Mit dem allem kann nie ein wahrhaftes *Lehrgedicht*, nämlich ein *poetisches *Werk dieser Art entstehen. Das Erste ist, daß das *Darzustellende *an und *für sich selbst* schon poetisch sey. Da nun das Darzustellende immer ein Wissen ist, so muß dieses Wissen an und für sich selbst und als Wissen schon zugleich poetisch seyn. Dieß ist aber nur einem absoluten Wissen, d.h. einem Wissen aus Ideen, möglich. Es gibt daher kein wahres Lehrgedicht, als in welchem unmittelbar oder mittelbar das All selbst, wie es im Wissen reflektirt wird, der Gegenstand ist. Da das Universum der Form und dem Wesen nach nur Eines ist, so kann auch in der Idee nur Ein absolutes Lehrgedicht seyn, von dem alle einzelnen bloße Bruchstücke sind, nämlich das Gedicht *von der Natur der Dinge.* Versuche dieses speculativen Epos - eines absoluten Lehrgedichts - sind in Griechenland gemacht worden; ob sie ihr Ziel erreicht haben, können wir nur im Allgemeinen wissen, da uns die Zeit von ihnen nichts als Bruchstücke gelassen hat. Parmenides und Xenohanes, beide trugen ihre Philosophie in einem Gedicht von der Natur der Dinge vor, wie schon früher die Pythagoreer und Thales ihre Lehren poetisch überlieferten. Von dem Gedicht des Parmenides ist uns fast keine Nachricht geblieben, als daß es in sehr unvollkommenen und holperigen Versen verfaßt gewesen. Mehr wissen wir von dem Gedicht des Empedokles, welcher die Physik des Anaxagoras mit dem Ernst der pythagoreischen Weisheit verband. Wir können die Grenzen, inwieweit dieses Gedicht die Idee des Universums erreichte, ungefähr eben daraus bestimmen, daß es die Physik des Anaxagoras war, die ihm zu Grunde lag. Ich muß die Bekanntschaft derselben hier voraussetzen. Aber wenn es von der wissenschaftlichen Seite das speculative Urbild nicht erreichte, so"}, {"type": "paragraph", "text": "müssen wir ihm dagegen nach dem einstimmigen Zeugniß der Alten, namentlich des Aristoteles, die größte rhythmische Energie und eine wahrhaft homerische Kraft zuschreiben. Das Glück hat auch gewollt, daß uns das Gedicht des Lucretius eine Spur des darin herrschenden Geistes erhalten hat. *Lucretius*, der in der schlechten Schreibart des Epikurus und seiner Anhänger kein Vorbild haben konnte, hat ohne Zweifel die rhythmische Form sowohl als die poetische Kraft und Weise der Darstellung von dem Empedokles entlehnt, und ist ihm in der Form ebenso wie dem Epikurus in der Materie des Gedichts gefolgt. Das Gedicht des Lucretius nähert sich in seiner Art mehr als irgend ein römisches, z.B. das Virgilische, den wahrhaft alten Vorbildern, und selbst die Kraft des ächt epischen Rhythmus stellt uns allein Lucretius dar, da von Ennius nur Bruchstücke geblieben sind. Lucretius' Hexameter machen den größten Contrast gegen die gefeilten und geleckten Verse des Virgil. Das Wesen seines Werks trägt durchaus das Gepräge eines großen Gemüths, und nur dem wahrhaft poetischen Geiste war es möglich in die Darstellung der Epikurischen Lehre solche Andacht und die Begeisterung eines wahren Priesters der Natur zu legen. Es ist nothwendig, daß, da der darzustellende Gegenstand an und für sich selbst unpoetisch ist, alle Poesie in das Subjekt zurückfallen muß, und aus demselben Grunde können wir auch das Gedicht des Lucretius nur als einen Versuch des absoluten Lehrgedichts ansehen, welches auch schon durch den Gegenstand selbst poetisch seyn muß. Aber diejenigen Stellen, in welchen sich wirklich seine persönliche Begeisterung ausspricht, der Eingang zum ersten Buch, welcher eine Anrufung der Venus ist,"}]}, {"page_pdf": 1787, "page_book": 666, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "sowie alle diejenigen Stellen, in welchen er den Epikurus preist als den, welcher die Natur der Dinge eröffnet und zuerst den Wahn und Aberglauben der Religion gestürzt habe, tragen durchaus die höchste Majestät und das Gepräge einer männlichen Kunst an sich. Wie die Alten von Empedokles sagen, daß er in seinem Gedicht mit wahrer Wuth über die Schranken der menschlichen Erkenntniß geredet, so geht das Feuer des Lucretius gegen Religion und falsche Sittlichkeit nicht selten in wahre begeisterte Wuth über. Die gänzliche Vernichtung alles Geistigen"}, {"type": "paragraph", "text": "nach außen, die Auflösung der Natur in ein Spiel der Atomen und des Leeren, die er mit wahrhaft epischer Gleichgültigkeit übt, ersetzt sich durch die sittliche Größe der Seele, die ihn selbst wieder über die Natur erhebt. Die Nichtigkeit der Natur selbst läßt zugleich seinen Geist sich über alle Sehnsucht in das Reich des Verstandes erschwingen. Wahrer und vortrefflicher kann über das Fruchtlose der Sehnsucht, die Unersättlichkeit der Begier, die Leerheit aller Furcht sowie aller Hoffnung im Leben nicht geredet werden, als von ihm geschieht, und wie die Lehre des Epikurus selbst nicht von der speculativen, sondern von der moralischen Seite groß ist, so erscheint auch Lucretius, wenn seine Begeisterung als Priester der Natur nur subjektiv seyn kann, dagegen als Lehrer der praktischen Weisheit objektiv und als ein Wesen höherer Ordnung, das den gemeinen Lauf der Dinge, die Leidenschaft und die Verwirrung des Lebens nur wie von einem höheren Standort aus betrachtet, an dem es selbst nicht davon erreicht wird. Man kann sich der Bemerkung des Gegensatzes nicht enthalten, den in dieser Beziehung andere Arten der Philosophie gegen die Epikurische machen, indem sie kleinliche Gesinnungen mit Vertilgung der großmüthigen und männlichen Tugenden im Sittlichen zum Größten machen, und dagegen im Speculativen einen höheren Flug vorgeben. Man braucht diese Vergleichung nicht weit herzuholen und nur gleich die Kantsche Philosophie zu nehmen. Von den *Lehrgedichten *der Neueren zu reden, glaube ich mich freisprechen zu dürfen. Denn da wir billig zweifeln, ob irgend ein Gedicht der Alten in dieser Gattung das wahre Urbild erreicht habe, so können wir es von den Neueren ohne Zweifel kategorisch behaupten, daß sie überhaupt kein ächt poetisches Werk dieser Art aufzuweisen haben. Dasjenige Lehrgedicht also, wo nicht bloß die Formen und die Hülfsmittel der Darstellung, sondern das Darzustellende selbst poetisch ist, ist noch zu erwarten. Folgendes läßt sich über die Idee eines solchen bestimmen. Das Lehrgedicht κατE dξοχήν kann nur ein Gedicht vom Universum oder der Natur der Dinge seyn. Es soll den Reflex des"}, {"type": "paragraph", "text": "Universums im Wissen darstellen. Das vollkommene Bild des Universum muß also in der Wissenschaft erreicht seyn. Die Wissenschaft ist berufen, es zu seyn. Es ist gewiß, daß die Wissenschaft, welche diese Identität mit dem Universum erreicht hätte, nicht nur von Seiten des Stoffs, sondern auch durch die Form mit der des Universum übereinstimmte, und inwiefern das Universum selbst das Urbild aller Poesie, ja die Poesie des Absoluten selbst ist, so würde die Wissenschaft in jener Identität mit dem Universum sowohl dem Stoff, als der Form nach schon an und für sich Poesie seyn und in Poesie sich auflösen. Der Ursprung des absoluten Lehrgedichts oder des speculativen Epos fällt also mit der Vollendung der Wissenschaft in eins zusammen, und wie die Wissenschaft erst von der Poesie ausging, so ist es auch ihre schönste und letzte Bestimmung, in diesen Ocean zurückzufließen. Ja nach dem, was schon früher von der einzigen Möglichkeit des wahren Epos und der Mythologie für die neuere Zeit gezeigt wurde, daß nämlich die Götter der neueren Welt, welche Geschichtsgötter sind, von der Natur Besitz ergreifen"}]}, {"page_pdf": 1788, "page_book": 668, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "müssen, um als *Götter *zu erscheinen - in dieser Hinsicht, sage ich, möchte das erste wahre Gedicht von der Natur der Dinge mit dem wahren Epos gleichzeitig seyn. In der subjektiven Sphäre der dem epischen Gedicht untergeordneten Gattungen ist die *Satyre *die objektivere Form, da ihr Gegenstand das Reale, Objektive und vorzugsweise wenigstens das *Handeln* ist. Ich begnüge mich mit Bemerkung der epischen Natur der Satyre. Da sie nicht erzählend ist, wie das Epos, also nicht wie dieses Personen auf epische Weise redend einführen kann, und doch vorzüglich Charaktere und Handlungen darzustellen hat, so nähert sie sich eben dadurch nothwendig dem Dramatischen, und sie muß der inneren Darstellung nach, um ihrer Aufgabe Genüge zu thun, nothwendig ein dramatisches Leben haben. Es versteht sich, daß unter den Begriff der Satyre im strengen Sinn nichts gehören kann, was absolut und an sich selbst dramatisch ist. Es wäre ebenso thöricht oder noch thörichter, die Komödien des Aristophanes zur Gattung der Satyre herunterzusetzen, als wie man sonst pflegte den Don Quixote des Cervantes zu einer Satyre zu machen."}, {"type": "paragraph", "text": "Die Satyre übrigens hat eine doppelte Gattung, die ernste und die komische. Beide Gattungen fordern die Würde eines sittlichen Charakters, wie er sich in dem edlen Zorn des Juvenal und des Persius ausspricht, und die Ueberlegenheit eines durchdringenden Geistes, der Verhältnisse und Begebenheiten in der Beziehung aufs Allgemeine zu sehen weiß, da eben auf der Contrastirung des Allgemeinen und Besonderen die vorzüglichste Wirkung der Satyre beruht. Daß in Deutschland diejenigen, die selbst die Karrikaturen oder die Geschöpfe des Zeitalters sind, je und je in sich den Kitzel empfinden, mit einer groben Feder satyrische Gemälde des Zeitalters aufs Papier zu kritzeln, ist nicht mehr zu verwundern, als daß überhaupt z.B. Menschen, die weder die Welt, noch irgend einen Gegenstand derselben erkannt haben, sich zur Poesie und den edelsten Gattungen derselben fähig glauben. Für die komische Satyre hatten die Griechen eigne Repräsentanten in den besonderen Gattungen halb thierischer, halb menschlicher Wesen, von welchen, wie das Wahrscheinlichste ist, die Satyre den Namen hat. Es ist bekannt, daß Aeschylos auch Satyrspiele geschrieben hat, wie späterhin Euripides. Das Gesetz der komischen Satyre ist in diesem Ursprung gleichsam ausgesprochen. Wenn die ernste Satyre das Laster, besonders das freche, mit Macht gepaarte züchtigt, so muß die komische dagegen ihren Gegenständen soviel möglich Schuld und Verdienst nehmen, sie ganz willenlos, soviel möglich thierisch und ganz und gar sinnlich zu machen suchen, wie die Satyrn und Faunen. Die Rohheit, die mit Bosheit und Niederträchtigkeit verbunden ist, erweckt nur Ekel und widrige Empfindungen, sie kann daher nie Gegenstand poetischer Laune seyn. Dieß wird sie nur durch gänzliche Beraubung des Menschlichen und völlige Umkehrung, in der sie rein komisch erscheint, ohne ein Gefühl zu beleidigen, und auf der andern Seite den Gegenstand am tiefsten herabsetzt. Hiemit haben wir den Kreis der rationalen epischen Formen durchlaufen. Wir haben nun noch von dem *modernen *oder *romantischen *Epos zu reden, und auch dieses in seine besondern Ausbildungen zu verfolgen."}, {"type": "paragraph", "text": "Da der Gegensatz des Antiken und Romantischen, so viel es möglich war, schon früher im *Allgemeinen *dargestellt wurde, und da die modernen Formen immer mehr oder weniger Irrationales behalten, so glaube ich in Ansehung des romantischen Epos am besten zu verfahren, wenn ich es meist historisch betrachte, und dabei die Gegensätze sowohl als die Uebereinstimmungen, die es mit dem alten Epos hat, heraushebe."}]}, {"page_pdf": 1789, "page_book": 670, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Ich knüpfe meine Betrachtung meinem Vorsatz gemäß, die Poesie auch in den merkwürdigsten Individuen zu charakterisiren, gleich an den *Ariosto *an, da zuvörderst kein Zweifel ist, daß er das ächteste moderne Epos gedichtet hat. Seine Vorgänger, Bojardo vorzüglich u.a. sind nicht zu rechnen, weil sie, wenn sie auch auf dem rechten Wege waren, doch nicht das Vortreffliche darin erreichen, langweilig und überladen geblieben sind. Tassos befreites Jerusalem nach Ariost ist durchaus mehr die Erscheinung einer schönen nach Reinheit strebenden Seele als eine objektive Dichtung, und nur das ganz Beschränkte darin, das Keusche, das Katholische, ist das Gute. Die Henriade zu nennen, würde kaum etwa ein Franzos begehren. Die Portugiesen haben ein Gedicht, die Lusiade von Camoens, das ich nicht kenne. Ariosto hat eine sehr bekannte mythologische Welt, in der er sich bewegt. Der Hof Karls des Großen ist der Olymp des Jupiter der Ritterzeit. Die Sagen von den zwölf Paladinen sind und waren nach allen Seiten verbreitet und gehörten allen gebildeteren Nationen, den Spaniern, Italienern, Franzosen, Deutschen, Engländern gemeinschaftlich an. Das Wunderbare hatte sich vom Christenthum aus verbreitet und in der Berührung mit der Tapferkeit der späteren Zeit sich zu einer romantischen Welt entzündet. Auf diesem glücklicheren Boden nun konnte der Dichter nach Willkür schalten, neu erfinden, schmücken. Alle Mittel standen ihm zu Gebot, er hatte Tapferkeit, Liebe, Zauberei, er hatte zu dem allem noch den Gegensatz des Morgen- und Abendlandes und der verschiedenen Religionen. Wie das Individuum oder Subjekt durchgehends mehr in der modernen Welt hervortritt, mußte es auch im Epos geschehen, so daß"}, {"type": "paragraph", "text": "es die absolute Objektivität des alten Epos verlor, und mit dieser Gattung nur als ihre vollkommene Negation vergleichbar ist, und auch Ariosto hat seinen Stoff nach sich modificirt, indem er ihm ein gutes Theil Reflexion und Muthwillen beigemischt hat. Da ein Hauptcharakter des Romantischen überhaupt in der Vermischung des Ernstes und des Scherzes liegt, so müssen wir ihm jenes zugeben, da von der anderen Seite seine Schalkhaftigkeit, so zu sagen, wieder nur an die Stelle der Gleichgültigkeit, der Untheilnahme des Dichters im Epos tritt. Er hat sich dadurch zum Herrn seines Gegenstandes gemacht. *Darin *schließt sich sein Gedicht dem Begriff des alten Epos am bestimmtesten an, daß es keinen bestimmten Anfang wie kein bestimmtes Ende hat, daß es ein herausgeschnittenes Stück aus seiner Welt ist, das man sich ebenso gut früher aufgenommen, wie weiter fortgeführt denken kann. (Tadel unverständiger Kunstrichter hierüber im Vergleich der künstlichen Composition des Tasso. Hier ist freilich alles regelmäßiger zugeschnitten, daß man nie zu verirren in Gefahr ist. Ariostos Gedicht gleicht einem Irrgarten, worin man mit Lust, ohne Furcht, sich verliert.) Ein anderer Beziehungspunkt ist: daß der Held nicht allein darin herausgehoben ist und oft ganz vom Schauplatz entfernt steht, oder vielmehr, daß es überhaupt eine Mehrzahl von Helden gibt. Die Geschichte Eines Helden durch alle Katastrophen hindurchgeführt, wie Wielands Oberon z.B., ist, wenn wir dieser Gattung nur einige Reinheit bewahren wollen, bloß eine romantische, oft sentimentale Biographie in Versen, also weder ein wahres Epos, noch ein wahrhafter Roman (der in Prosa geschrieben seyn müßte). Der Begriff des Wunderbaren ist, wie ich schon bemerkt habe, eine *neue *Zuthat des Epos, denn wenn auch Aristoteles schon vom θαυμα üí des homerischen Epos spricht, hat es doch bei ihm eine ganz andere Bedeutung als das moderne Wunderbare, nämlich überhaupt nur das Außerordentliche (mehr davon beim Drama). Homer hat kein Wunderbares, sondern lauter Natürliches, weil auch seine Götter natürlich sind. Im Wunderbaren zeigt sich Poesie und Prosa im Kampf; das Wunderbare * ist *es nur gegenüber von der Prosa und"}]}, {"page_pdf": 1790, "page_book": 672, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "in einer *getheilten *Welt. Im Homer ist, wenn man will, *alles*, aber eben deßwegen nichts wunderbar. Allein Ariosto hat wirklich vortrefflich verstanden, sein Wunderbares vermittelst seiner Leichtigkeit, seiner Ironie und des oft ganz ungeschmückten Vortrags in ein Natürliches zu verwandeln. Er wird auch am schwersten da zu erreichen seyn, wo er ganz trocken erzählt. Im Uebergang aber von solchen Partieen zu andern, über die er alle Anmuth und allen Schmuck seiner reichen Phantasie ergossen, malen sich die Contraste und Mischungen des Stoffs, welche im romantischen Gedicht nothwendig sind - man kann im eigentlichsten Sinn sagen, sie *malen *sich, weil alles lebendige Farbe bei ihm ist, bewegliches, rasches Gemälde, an dem die Umrisse zuweilen verschwinden, zuweilen nachdrücklich hervortreten, und das immer mehr als ein buntes Aggregat von Theilen eines Ganzen erscheint, als daß sich, auch innerhalb seiner partiellen Sphäre genommen, eine gediegene Stetigkeit darin ausdrückte. Auch hat Ariosto streng genommen nur einen nationalen und leicht gemeinten Versuch gemacht, wenn man ihn mit der höheren Idee eines, wenn gleich modernen, Epos zusammenhält, das, nicht mehr wie das Homerische durch ein Zeitalter, ein Volk gedichtet, sondern nothwendig durch einen Einzelnen, stets einen andern Charakter haben wird und das Antike und die Objektivität auf andere Art zu Stande bringen muß. Allein der Reiz eines hellen Verstandes und der unerschöpflichen Fülle von Lust und Laune löscht das Partikulare des Gedichtes wieder aus. Es ist nichts Gehäuftes in Ariosto, die edlen Züge sind schön vertheilt und halten wie Säulen das luftige Gebäude. Angelika ist die schöne Helena, der Zwist der Paladine um sie der trojanische Krieg; Orlando tritt ebenso selten auf den Schauplatz wie Achilles; es fehlt auch an einem Paris nicht, der ohne groß Verdienst und Würdigkeit die Schöne davon trägt, die bekannte Meda nämlich. - Natürlich ist diese Parallele nicht allzu ernstlich gemeint. Die schönste Gestalt des Dichters, durchaus romantisch und zart gedacht, ist Bradamante, die Waffen anlegt und auf Abenteuer ausgeht für den Geliebten; die Tapferkeit ist in ihr das Wunderbare und die Liebe das Natürliche und also auch das Liebenswerthe das"}, {"type": "paragraph", "text": "Ueberwiegende; auch ist sie Christin, dahingegen in einer anderen weiblichen Gestalt aus dem Morgenlande die Tapferkeit mehr männlich als siegend gezeichnet ist. Auch Orlando und Rinaldo machen einen starken Gegensatz des Gebildeten und Ungebildeten. In dem Meer von Episoden (um auch davon zu reden) und Zufällen tauchen die mannichfachen Gestalten unter und kommen wieder, stets kenntlich und von einander gesondert. Die Episoden sind hier die Novellen, die der Dichter eingeflochten wie Cervantes in seinen Roman; sie sind sowohl sehr rührenden und pathetischen, als muthwilligen Inhalts, wobei der Dichter immer davon geht, als ob nichts geschehen wäre: mischt er Betrachtung ein, so geschieht es nie verweilend, sondern daß es gleich wieder vorwärts geht, und ein neuer Horizont sich ihm wölbt. Die Gleichmäßigkeit und Identität des Geistes dieser Dichtart ist auch äußerlich ausgedrückt durch das am meisten identische Sylbenmaß der Neueren, die Stanze. Es verlassen, wie Wieland, heißt die Form des romantischen Epos selbst verlassen. Die durch die Charakteristik von Ariosto schon angegebenen Charaktere des romantischen Epos oder des *Rittergedichts *sind hinreichend, seine Verschiedenheit und Entgegensetzung mit dem antiken Epos zu zeigen. Wir können das Wesen desselben so aussprechen: es ist durch den Stoff episch, d.h. der Stoff ist mehr oder weniger universell, durch die Form aber ist es subjektiv, indem die Individualität des Dichters dabei weit mehr in Anschlag kommt, nicht nur darin, daß er die Begebenheit, welche er erzählt, beständig mit der Reflexion begleitet, sondern auch in der Anordnung des Ganzen, die nicht aus dem Gegenstand selbst sich entwickelt, und weil sie die Sache des Dichters ist, überhaupt keine andere Schönheit als die Schönheit der Willkür bewundern läßt. An und für sich schon gleicht der"}]}, {"page_pdf": 1791, "page_book": 673, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "romantisch-epische Stoff einem wild verwachsenen Wald voll eigenthümlicher Gestalten, einem Labyrinth, in dem es keinen andern Leitfaden gibt als den Muthwillen und die Laune des Dichters. Wir können schon hieraus begreifen, daß das romantische Epos weder die höchste, noch die einzige Art ist, in welcher *diese *Gattung (das Epos nämlich) in der modernen Welt überhaupt existiren kann."}, {"type": "paragraph", "text": "Das romantische Epos hat in der Gattung, zu der es gehört, selbst wieder einen Gegensatz. Wenn es nämlich überhaupt zwar dem Stoff nach universell, der Form nach aber individuell ist, so läßt sich zum voraus eine andere entsprechende Gattung erwarten, in welcher an einem partiellen oder beschränkteren Stoff sich die allgemein gültigere und gleichsam indifferentere Darstellung versucht. Diese Gattung ist der *Roman*, und wir haben mit dieser Stelle, die wir ihm geben, zugleich auch seine Natur bestimmt. Man kann allerdings auch den Stoff des romantischen Epos nur relativ-universell nennen, weil er nämlich immer den Anspruch an das Subjekt macht, sich überhaupt auf einen phantastischen Boden zu versetzen, welches das alte Epos nicht thut. Aber eben deßwegen auch, weil der Stoff vom Subjekt etwas fordert - Glauben, Lust, phantastische Stimmung - so muß der Dichter von der seinigen etwas hinzuthun, und so dem Stoff, was er in der einen Rücksicht an Universalität voraus haben kann, von der andern Seite wieder durch die Darstellung nehmen. Um sich dieser Nothwendigkeit zu überheben, und der objektiven Darstellung sich mehr zu nähern, bleibt demnach nichts übrig als auf die Universalität des Stoffs Verzicht zu thun und sie in der *Form *zu suchen. Die ganze Mythologie des Rittergedichts gründet sich auf das Wunderbare, d.h. auf eine getheilte Welt. Diese Getheiltheit geht nothwendig in die Darstellung über, da der Dichter, um das Wunderbare als solches erscheinen zu lassen, selbst für sich in derjenigen Welt seyn muß, wo das Wunderbare *als Wunderbares *erscheint. Will also der Dichter mit seinem Stoff wahrhaft identisch werden und sich ihm selbst ungetheilt hingeben, so ist kein Mittel dazu, als daß das Individuum, wie überhaupt in der modernen Welt, so auch hier ins Mittel trete und den Ertrag Eines Lebens und Geistes in Erfindungen niederlege, die, je höher sie stehen, desto mehr die Gewalt einer Mythologie gewinnen. So entsteht der *Roman*, und ich trage kein Bedenken, ihn in dieser Rücksicht über das Rittergedicht zu setzen, obgleich freilich von dem, was unter diesen Namen geht, das Wenigste nur"}, {"type": "paragraph", "text": "jene Objektivität der Form erreicht hat, bei welcher es näher noch als das Rittergedicht dem eigentlichen Epos steht. Schon durch die ausdrückliche Beschränkung, daß der Roman bloß durch die *Form *der Darstellung objektiv, allgemein gültig sey, ist angedeutet, innerhalb welcher Grenzen allein er dem Epos sich nähern könne. Das Epos ist eine ihrer Natur nach unbeschränkte Handlung: sie fängt eigentlich nicht an und könnte ins Endlose gehen. Der Roman ist, wie gesagt, durch den Gegenstand beschränkt, er nähert sich dadurch mehr dem Drama, welches eine beschränkte und in sich abgeschlossene Handlung ist. In dieser Beziehung könnte man den Roman auch als eine Mischung des Epos und des Drama beschreiben, so nämlich, daß er die Eigenschaften beider Gattungen theilte. Das Ganze der neueren Kunst zeigt sich auch darin mehr der Malerei und dem Reich der Farben gleich, da hingegen das plastische Zeitalter oder das Reich der Gestalten alles streng von einander sonderte. Die moderne Kunst hat für die objektive Form der Darstellung kein so gleichmäßiges, zwischen Entgegengesetztem schwebendes Sylbenmaß, als der Hexameter der antiken Kunst ist; alle ihre Sylbenmaße individualisiren gleich stärker und beschränken auf einen gewissen Ton, Farbe, Stimmung"}]}, {"page_pdf": 1792, "page_book": 675, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "u.s.w. Die gleichmäßigste neuere Versart ist die Stanze, aber sie hat nicht so das Ansehen unmittelbarer Inspiration und Abhängigkeit von dem Fortschreiten des Gegenstandes als der Hexameter, schon darum, weil sie ein ungleichförmiges Versmaß ist, und sich in Strophen absondert, und demnach auch überhaupt künstlicher und mehr als Werk des Dichters wie als Form des Gegenstandes erscheint. Dem Roman also, der in beschränkterem Stoff die Objektivität des Epos in der Form erreichen will, bleibt nichts als die Prosa, welche die höchste Indifferenz ist, aber die Prosa in ihrer größten Vollkommenheit, wo sie von einem leisen Rhythmus und einem geordneten Periodenbau begleitet ist, der dem Ohr zwar nicht so gebietet wie das rhythmische Sylbenmaß, aber doch von der andern Seite auch keine Spur der Gezwungenheit hat, und deßwegen die sorgfältigste Ausbildung erfordert. Wer diesen Rhythmus der Prosa im Don Quixote und"}, {"type": "paragraph", "text": "Wilhelm Meister nicht empfindet, der kann ihn freilich auch nicht gelehrt werden. Wie die epische Diktion, darf diese Prosa oder vielmehr dieser Styl des Romans verweilen, sich verbreiten und das Geringste nicht unberührt lassen an seiner Stelle, aber auch nicht sich in Schmuck verlieren, besonders nicht in bloßen Wortschmuck, weil sonst der unerträglichste Mißstand, die sogenannte poetische Prosa, unmittelbar angrenzt. Da der Roman nicht dramatisch seyn kann und doch von der andern Seite in der Form der Darstellung die Objektivität des Epos zu suchen hat, so ist die schönste und angemessenste Form des Romans nothwendig die *erzählende.* Ein Roman in Briefen besteht aus lauter lyrischen Theilen, die sich - im *Ganzen *- in dramatische verwandeln, und somit fällt der epische Charakter hinweg. Da in der Form der Darstellung der Roman dem Epos so viel möglich gleich seyn soll und doch ein beschränkter Gegenstand eigentlich den Stoff ausmacht, so muß der Dichter die epische Allgemeingültigkeit durch eine relativ noch größere Gleichgültigkeit gegen den Hauptgegenstand oder den Helden ersetzen, als diejenige ist, welche der epische Dichter übt. Er darf sich daher nicht zu streng an den Helden binden, und noch viel weniger alles im Buch ihm gleichsam unterwerfen. Da das Beschränkte nur gewählt ist, um in der Form der Darstellung das Absolute zu zeigen, so ist der Held gleichsam schon von Natur mehr symbolisch als persönlich und muß auch so im Roman genommen werden, so daß sich alles leicht ihm anknüpft, daß er der collective Name sey, das Band um die volle Garbe. Die Gleichgültigkeit darf so weit gehen, daß sie sogar in Ironie gegen den Helden übergehen kann, da Ironie die einzige Form ist, in der das, was vom Subjekt ausgeht oder ausgehen muß, sich am Bestimmtesten wieder von ihm ablöst und objektiv wird. Die Unvollkommenheit kann also dem Helden in dieser Hinsicht gar nichts schaden; die prätendirte Vollkommenheit hingegen wird den Roman vernichten. Hierher gehört auch, was Goethe im Wilhelm Meister über die retardirende Kraft des Helden mit besonderer Ironie diesem selbst in Mund"}, {"type": "paragraph", "text": "legt. Da nämlich der Roman von der einen Seite die nothwendige Hinneigung zum Dramatischen hat, und doch von der andern Seite verweilend wie das Epos seyn soll, so muß es diese den raschen Lauf der Handlung mäßigende Kraft in das Objekt, nämlich in den Helden selbst legen. Wenn Goethe in derselbigen Stelle des Wilhelm Meister sagt: Im Roman sollen vorzüglich *Gesinnungen *und *Begebenheiten*, im Drama *Charaktere * und *Thaten *vorgestellt werden, so hat dieß dieselbe Beziehung. Gesinnungen können auch wohl nur für eine gewisse Zeit und Lage stattfinden, sie sind wandelbarer als"}]}, {"page_pdf": 1793, "page_book": 677, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "der Charakter; der Charakter drängt unmittelbarer zur Handlung und zum Ende, als Gesinnungen thun, und die That ist entscheidender als Begebenheiten sind, wie sie aus dem entschiedenen und starken Charakter kommt und im Guten und Bösen eine gewisse Vollkommenheit desselben fordert. Allein dieß ist freilich nicht von einer gänzlichen Negation der Thatkraft im Helden zu verstehen, und die vollkommenste Vereinigung wird immer die bleiben, welche im Don Quixote getroffen ist, daß die aus dem Charakter kommende That durch die Begegnung und die Umstände für den Helden zur *Begebenheit* wird. Der Roman soll ein Spiegel der Welt, des Zeitalters wenigstens, seyn, und so zur partiellen Mythologie werden. Er soll zur heiteren, ruhigen Betrachtung einladen und die Theilnahme allenthalben gleich fest halten; jeder seiner Theile, alle Worte sollten gleich golden seyn, wie in ein innerliches höheres Sylbenmaß gefaßt, da ihm das äußerliche mangelt. Deßwegen kann er auch nur die Frucht eines ganz reifen Geistes seyn, wie die alte Tradition den Homeros immer als Greis schildert. Er ist gleichsam die letzte Läuterung des Geistes, wodurch er in sich selbst zurückkehrt und sein Leben und seine Bildung wieder in Blüthe verwandelt; er ist die Frucht, jedoch mit Blüthen gekrönt. Alles im Menschen anregend soll der Roman auch die Leidenschaft in Bewegung setzen; das höchste Tragische ist ihm erlaubt wie das Komische, nur daß der Dichter selbst von beidem unberührt bleibe."}, {"type": "paragraph", "text": "Es ist schon früher in Ansehung des Epos bemerkt worden, daß in ihm der Zufall verstattet ist; noch mehr darf der Roman mit allen Mitteln schalten, die Ueberraschung, Verflechtung und Zufall an die Hand geben: nur darf freilich der Zufall nicht allein schalten, sonst tritt wieder ein grillenhaftes, einseitiges Princip an die Stelle des ächten Bildes vom Leben. Auf der anderen Seite ist, wenn der Roman vom Epos das Zufällige der Begebenheiten entlehnen darf, das Princip des Schicksals, welches in ihn durch seine Hinneigung zum Drama kommt, ebenfalls zu einseitig und dabei zu herbe für die umfassendere und gefälligere Natur des Romans. Inwiefern Charakter auch eine Nothwendigkeit ist, die dem Menschen zum Schicksal werden kann, müssen im Roman Charakter und Zufall einander in die Hände arbeiten, und in dieser Stellung beider gegeneinander offenbart sich vorzüglich die Weisheit und Erfindung des Dichters. Der Roman, da er seiner näheren Verwandtschaft mit dem Drama gemäß mehr auf Gegensätzen beruht als das Epos, muß diese vorzüglich zur Ironie und zur pittoresken Darstellung gebrauchen, wie das Tableau im Don Quixote, wo dieser und Cardenio im Walde gegeneinander über sitzend beide vernünftig aneinander theilnehmen, bis der Wahnsinn des einen den des anderen in Aufruhr setzt. Uerberhaupt also darf der Roman nach dem Pittoresken streben, denn so kann man allgemein nennen, was eine Art von dramatischer, nur flüchtigerer, Erscheinung ist. Es versteht sich, daß es stets einen Gehalt, einen Bezug auf das Gemüth, auf Sitten, Völker, Begebenheiten habe. Was kann in dem angegebenen Sinn pittoresker seyn, als im Don Quixote Marcellas Erscheinung auf der Spitze des Felsens, an dessen Fuß der Schäfer begraben wird, den die Liebe für sie getödtet hat? Wo der Boden der Dichtung es nicht begünstigt, muß der Dichter es erschaffen, wie Goethe im Wilhelm Meister; Mignon, der Harfner, das Haus des Onkels sind einzig sein Werk. Alles, was die Sitten Romantisches darbieten, muß herausgewendet und das Abenteuerliche nicht verschmäht werden, sobald es auch wieder zur Symbolik dienen"}, {"type": "paragraph", "text": "kann. Die* gemeine *Wirklichkeit soll sich nur darstellen, um der Ironie und irgend einem Gegensatze dienstbar zu seyn."}]}, {"page_pdf": 1794, "page_book": 679, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Die Stellung der Begebenheiten ist ein anderes Geheimniß der Kunst. Sie müssen weise vertheilt seyn, und wenn auch gegen das Ende der Strom breiter wird, und die ganze Herrlichkeit der Conception sich entfaltet, so sollen sich doch die Begebenheiten nirgend drücken, drängen und jagen. Die sogenannten Episoden müssen entweder dem Ganzen wesentlich angehören, organisch mit ihm gebildet seyn (Sperata), nicht bloß angeflickt, um dieses und jenes herbeizuführen, oder sie müssen ganz unabhängig als Novellen eingeschaltet seyn, wogegen sich nichts einwenden läßt. Die *Novelle*, um dieß im Vorbeigehen zu bemerken, da wir uns auf alle diese Untergattungen nicht insbesondere einlassen können, ist der Roman nach der lyrischen Seite gebildet, gleichsam, was die Elegie in Bezug auf das Epos ist, eine Geschichte zur symbolischen Darstellung eines subjektiven Zustandes oder einer besonderen Wahrheit, eines eigenthümlichen Gefühls.) Um einen leichten Kern - einen *Mittelpunkt*, der nichts verschlinge und alles gewaltsam in seine Strudel ziehe - muß überhaupt im Roman alles fortschreitend geordnet seyn. Es leuchtet aus diesen wenigen Zügen ein, was der Roman nicht seyn darf, im höchsten Sinn genommen: keine Musterkarte von Tugenden und Lastern, kein psychologisches Präparat eines einzelnen menschlichen Gemüths, das wie in einem Kabinet aufbewahrt würde. Es soll uns an der Schwelle keine zerstörende Leidenschaft empfangen und durch alle ihre Stationen mit sich fortreißen, die den Leser zuletzt betäubt am Ende eines Wegs zurückläßt, den er um alles nicht noch einmal machen möchte. Auch soll der Roman ein Spiegel des allgemeinen Laufs menschlicher Dinge und des Lebens, also nicht bloß ein partielles Sittengemälde seyn, wo wir nie über den engen Horizont socialer Verhältnisse auch etwa der größesten Stadt oder eines Volks von beschränkten Sitten hinausgeführt werden, der endlosen schlechteren Stufen noch tiefer herabgehender Verhältnisse nicht zu gedenken."}, {"type": "paragraph", "text": "Daraus folgt natürlich, daß fast die gesammte Unzahl dessen, was man Roman nennt, - wie Fallstaff seine Miliz * Futter *für Pulver nennt, - Futter für den Hunger der Menschen ist, für den Hunger nach materieller Täuschung und für den unersättlichen Schlund der Geistesleere und derjenigen Zeit, die vertrieben seyn will. Es wird nicht zu viel seyn zu behaupten, daß es bis jetzt nur zwei Romane gibt, nämlich den Don Quixote des Cervantes und den Wilhelm Meister von Goethe, jener der herrlichsten, dieser der gediegensten Nation angehörig. *Don Quixote * ist nicht nach den frühesten deutschen Uebersetzungen zu beurtheilen, wo die Poesie vernichtet, der organische Bau aufgehoben ist. Man braucht sich des Don Quixote nur zu erinnern, um einzusehen, was der Begriff von einer durch das Genie eines Einzelnen erschaffenen Mythologie sagen will. Don Quixote und Sancho Pansa sind mythologische Personen über den ganzen gebildeten Erdkreis, sowie die Geschichte von den Windmühlen u.s.w. wahre Mythen sind, mythologische Sagen. Was in der beschränkten Conception eines untergeordneten Geistes nur als Satyre einer bestimmten Thorheit gemeint geschienen hätte, das hat der Dichter durch die allerglücklichste der Erfindungen in das universellste, sinnvollste und pittoreskeste Bild des Lebens verwandelt. Daß diese Eine Erfindung durch das Ganze hinläuft, und dann nur aufs reichste variirt erscheint, nirgend also eine Zusammenstückelung sichtbar wird, gibt ihm einen besonders großen Charakter. Indeß ist doch in dem Ganzen ein offenbarer und sehr entschiedener Gegensatz, und die beiden Hälften könnte man weder ganz unschicklich noch ganz unwahr die Ilias und die Odyssee des Romans nennen. Das Thema im Ganzen ist das Reale im Kampf mit dem Idealen. In der ersten Hälfte des Werks wird das Ideale nur *natürlich*-realistisch behandelt, d.h. das Ideale des Helden stößt sich nur an der gewöhnlichen Welt und den gewöhnlichen Bewegungen derselben, im andern Theil wird es mystificirt, d.h. die Welt, mit der es in Conflikt kommt, ist selbst eine ideale, nicht die gewöhnliche, wie in der Odyssee die Insel der Kalypso gleichsam eine fingirtere Welt ist als die, in welcher die Ilias sich bewegt, und wie hier die Kirke"}]}, {"page_pdf": 1795, "page_book": 680, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "erscheint, so im Don Quixote die Herzogin, die, ausgenommen die Schönheit, alles mit ihr gemein hat. Die Mystifikation geht allerdings bis zum Schmerzenden, ja bis zum Plumpen, und so daß das Ideale in der Person des Helden, weil es da verrückt geworden war, ermattend unterliegt; dagegen zeigt es sich im Ganzen der Composition durchaus triumphirend, und auch in *diesem *Theil schon die ausgesuchte Gemeinheit des Entgegengesetzten. Der Roman des Cervantes ruht also auf einem sehr unvollkommenen, ja verrückten Helden, der aber zugleich so edler Natur ist, und so oft als der Eine Punkt nicht berührt wird, so viel überlegenen Verstand zeigt, daß ihn keine Schmach, die ihm widerfährt, eigentlich herabwürdiget. An diese Mischung (in Don Quixote) ließ sich eben das wunderbarste und reichste Gewebe knüpfen, das im ersten Moment so anziehend wie im letzten stets den gleichen Genuß gewährt und die Seele zur heitersten Besonnenheit stimmt. Für den Geist ist die nothwendige Begleitung des Helden, Sancho Pansa, gleichsam ein unaufhörlicher Festtag; eine unversiegbare Quelle der Ironie ist geöffnet und ergießt sich in kühnen Spielen. Der Boden, auf dem das Ganze geschieht, versammelte in jener Zeit alle romantischen Principien, die es noch in Europa gab, verbunden mit der Pracht des geselligen Lebens. Hierin war der Spanier tausendfältig vor dem deutschen Dichter begünstigt. Er hatte die Hirten, die auf freiem Felde lebten, einen ritterlichen Adel, das Volk der Mauren, die nahe Küste von Afrika, den Hintergrund der Begebenheiten der Zeit und der Feldzüge gegen die Seeräuber, endlich eine Nation, unter welcher die Poesie popular ist - selbst malerische Trachten, für den gewöhnlichen Gebrauch die Maulthiertreiber und den Baccalaureus von Salar. Dennoch läßt der Dichter meißt aus Ereignissen, die nicht national sondern ganz allgemein sind, wie die Begegnung der Galeerensclaven, eines Marionettenspielers, eines Löwen im Käfig seine ergötzlichen Ereignisse entstehen. Der Wirth, den Don Quixote für einen Castellan ansieht, und die schöne Maritorne sind allenthalben zu Haus. Die Liebe dagegen erscheint immer in der eigenthümlichen romantischen Umgebung, die er in seiner Zeit"}, {"type": "paragraph", "text": "vorfand, und der ganze Roman spielt unter freiem Himmel in der warmen Luft seines Klima und in erhöhter südlicher Farbe. Die Alten haben den Homer als den glücklichsten Erfinder gepriesen, die Neueren billig Cervantes. Was hier Eine göttliche Erfindung ausrichten und aus Einem Guß schaffen konnte, das hat der Deutsche unter völlig ungünstigen, zerstückten Umständen durch eine große Denkkraft und Tiefe des Verstandes hervorbringen und erfinden müssen. Die Anlage erscheint unkräftiger, die Mittel dürftiger, allein die Gewalt der Conception, die das Ganze hält, ist wahrhaft unermeßlich. Auch im *Wilhelm Meister *zeigt sich der faßt bei keiner umfassenden Darstellung zu umgehende Kampf des Idealen mit dem Realen, der unsere aus der Identität herausgetretene Welt bezeichnet. Nur ist es nicht so wie im Don Quixote ein und derselbe sich beständig in verschiedenen Formen erneuernde, sondern ein vielfach gebrochener und mehr zerstreuter Streit; daher auch der Widerstreit im Ganzen gelinder, die Ironie leiser, sowie unter dem Einfluß des Zeitalters alles praktisch endigen muß. Der Held verspricht viel und vieles, er scheint auf einen Künstler angelegt, aber die falsche Einbildung wird ihm genommen, da er die vier Bände hindurch beständig nicht als Meister, wie er heißt, als *Schüler *erscheint oder behandelt wird; er bleibt als eine liebenswürdige gesellige Natur zurück, die sich leicht anschließt und immer anzieht; insofern ist er ein glückliches Band des Ganzen und macht einen anlockenden Vorgrund. Der Hintergrund öffnet sich gegen das Ende und zeigt eine unendliche Perspektive aller Weisheit des Lebens hinter einer Art von Gaukelspiel; denn nichts anderes ist die geheime Gesellschaft,"}]}, {"page_pdf": 1796, "page_book": 682, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "die sich in dem Augenblick auflöst, wo sie sichtbar wird, und nur das Geheimniß der Lehrjahre ausspricht: - * der *nämlich ist Meister, der seine Bestimmung erkannt hat. Diese Idee ist mit solcher Fülle, mit einem Reichthum unabhängigen Lebens bekleidet, daß sie sich nie als herrschender Begriff oder als Verstandeszweck der Dichtung entschleiert. Was sich in den Sitten nur irgend romantisch behandeln ließ, ist benutzt worden, herumziehende Schauspieler, das Theater überhaupt,"}, {"type": "paragraph", "text": "welches allenfalls die aus der socialen Welt verbannte Unregelmäßigkeit noch aufnimmt, ein Kriegsheer von einem Fürsten angeführt, ja Seiltänzer und eine Räuberbande. Wo Sitte und Zufall, der nach jener modificirt werden mußte, nicht mehr ausreichten, da ist das Romantische in den Charakter gelegt worden, von der freien anmuthigen Philine an bis zu dem edelsten Styl hinauf zu Mignon, durch welche der Dichter sich in einer Schöpfung offenbart, an der die tiefste Innigkeit des Gemüths und die Stärke der Imagination gleichen Antheil haben. Auf diesem wundervollen Wesen und der Geschichte ihrer Familie - in der tragischen Novelle der Sperata - ruht die Herrlichkeit des Erfinders; die Lebensweisheit wird gleichsam arm dagegen, und dennoch hat er in seiner künstlerischen Weisheit nicht mehr Gewicht darauf gelegt wie auf jeden andern Theil des Buchs. Auch sie nur haben, könnte man sagen, ihre Bestimmung erfüllt und ihrem Genius gedient. Was in dem Roman durch Schuld der Zeit und des Bodens der Farbengebung des Ganzen abgeht, muß in die einzelnen Gestalten gelegt werden; dieß ist das vorzüglichste Geheimniß in der Composition des Wilhelm Meister; diese Macht hat der Dichter so weit geübt, daß er auch den gemeinsten Personen, z.B. der alten Barbara in dem einzelnen Moment eine wunderbare Erhöhung geliehen hat, in der sie wahrhaft tragische Worte aussprechen, bei denen der Held der Geschichte gleichsam selbst zu vergehen scheint. Was Cervantes nur einmal zu erfinden hatte, mußte der deutsche Dichter vielfach erfinden und bei jedem Schritte auf so ungünstigem Boden sich neue Bahn brechen, und da die Ungünstigkeit der Umgebung seinen Erfindungen nicht die Gefälligkeit zuläßt, die denen des Cervantes eigen ist, geht er desto tiefer mit der Intention und ersetzt den äußern Mangel durch die innere Kraft der Erfindung. Dabei ist die Organisation aufs Kunstreichste gebildet, und im ersten Keim das Blatt wie die Blüthe mit entworfen, und der kleinste Umstand im voraus nicht vernachlässigt, um dann überraschend wiederzukehren. Außer dem Roman in der vollkommensten Gestalt, inwiefern er"}, {"type": "paragraph", "text": "bei einer gewissen Beschränktheit des Stoffes durch die Form die Allgemeingültigkeit des Epos annimmt, muß man nun allerdings noch überhaupt *romantische *Bücher gelten lassen. Ich verweise dahin - nicht die Novellen und Mährchen, die für sich bestehen als wahre Mythen (in den unsterblichen Novellen des Boccaccio) aus wirklichem oder phantastischem Gebiet, und die ebenfalls sich im äußern Element rhythmischer Prosa bewegen, sondern anderes gemischtes Vortreffliches, wie den Persiles des Cervantes, die Fiammetta des Boccaccio, allenfalls auch den Werther, der übrigens ganz in die Jugend und den sich mißverstehenden Versuch der in Goethe wiedergeborenen Poesie zurückgeschoben werden muß, ein lyrisch-leidenschaftliches Poem von großer materieller Kraft, obwohl die Scene ganz innerlich und nur im Gemüth liegt. Was die gepriesenen *englischen Romane *betrifft, so halte ich den Tom Jones für ein mit derben Farben aufgetragenes nicht Welt- sondern Sittengemälde, wo auch der moralische Gegensatz zwischen einem ganz niedrigen Heuchler und einem gesunden, aufrichtigen jungen Menschen etwas grob"}]}, {"page_pdf": 1797, "page_book": 684, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "durchgeführt ist mit mimischem Talent, aber ohne alle romantischen und zarten Bestandtheile. Richardson ist in der Pamela und dem Grandison wenig mehr als ein moralischer Schriftsteller; in der Clarissa zeigt er eine wahrhaft objektive Darstellungsgabe, nur in Pedanterie und Weitläufigkeit eingewickelt. Nicht romantisch, aber objektiv und ungefähr in der Art der Idylle allgemein gültig ist der Landprediger von Wakefield. (Erwähnung der Romanze und Ballade, deren Charakter nicht scharf gesondert ist, doch daß man jene als die subjektivere, diese als die objektivere Form ansehen kann.) Wir haben den Kreis der epischen Formen, wiefern sie im Geist der modernen und romantischen Poesie möglich sind, durchlaufen. Es ist noch die Frage übrig nach der Möglichkeit der antik-epischen Form für die Dichter der neueren Zeit. Früher schon war von den mißlungenen Versuchen dieser Art die Rede. Das erste, wornach sich der Dichter umzusehen hätte, wäre allerdings der Stoff, welcher seiner Natur nach"}, {"type": "paragraph", "text": "der antik-epischen Behandlung fähig wäre. Entweder könnte er nun selbst einen antiken Stoff wählen, der sich dem epischen Ganzen der Griechen anschlöße, oder wenigstens in den Kreis der epischen Mythologie gehörte. Oder er müßte einen Stoff der neueren Zeit auswählen. Aus der Geschichte ihn zu wählen würde darum unmöglich seyn, weil 1) was auch von der Geschichte episch abgesondert wird, immer nur zufällig abgesondert scheinen wird, 2) weil die Motive, die Sitten, Gebräuche, die mit zu der Geschichte gehören, nothwendig modern seyn müßten, wie wenn ein Dichter die Geschichte der Kreuzzüge antik-episch behandeln wollte. Am ehesten vielleicht wäre der epische Stoff von der Grenze der antiken und modernen Zeit zu nehmen, weil durch den Gegensatz des Heidenthums selbst das Christenthum eine höhere Farbe gewänne und sogar das Ansehen annehmen könnte, welches in der Odyssee das Fabelhafte der Sitten der Völker z.B. und das Wunderbare mancher Länder oder Inseln hat. Mit Einem Wort das Christenthum wäre in dieser Entgegensetzung einer wahrhaft objektiven Behandlung am fähigsten. Man würde ein solches Epos nicht als ein bloßes Studium nach der Antike betrachten können, es wäre einer einheimischen und eigenthümlichen Kraft und Farbe fähig. Aber abgesehen von diesem Einen Moment der Zeit, welcher selbst der Wendepunkt der alten und neuen ist, möchte sich in der ganzen späteren Geschichte kein allgemein gültiges Ereigniß und eine der epischen Darstellung fähige Begebenheit finden. Sie müßte nämlich, wie der trojanische Krieg, außerdem daß sie allgemein, zugleich national und volksmäßig seyn, da der epische Dichter vor allen andern der populärste zu seyn streben muß, und die Popularität nur in lebendiger Wahrheit und in der Beglaubigung durch Sitte und Ueberlieferung gefunden werden kann. Die Handlung müßte zugleich jener Ausführlichkeit in der Behandlung des Details der Erzählung, welche zum epischen Styl gehört, fähig seyn. Aber schwerlich möchte irgend ein diese Bedingungen erfüllender Stoff in der neueren Welt aufzufinden seyn, am wenigsten der der letzten Forderung entspräche, da in den Kriegen z.B. die Persönlichkeit gleichsam aufgehoben"}, {"type": "paragraph", "text": "ist und nur die Masse wirkt. Die epischen Versuche mit neueren Stoffen wären also an und für sich schon auf den Boden mehr der Odyssee als der Ilias gewiesen, aber auch auf jenem würden sich alterthümliche Sitten, eine Welt, wie sie zur epischen Entwicklung, Klarheit und Einfalt erforderlich ist, nur in beschränkteren Sphären finden lassen (wie in Voßens Luise). Aber hiedurch würde das epische Gedicht mehr die Natur der Idylle annehmen, wenn nicht etwa der Dichter die Möglichkeit fände, in diese"}]}, {"page_pdf": 1798, "page_book": 686, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Beschränktheit wieder die Allgemeinheit einer großen Begebenheit zu ziehen. Dieß ist in Goethes *Hermann und Dorothea *auf solche Weise geschehen, daß man diesem Gedicht seiner Beschränktheit durch den Stoff unerachtet den epischen Charakter im gewissen Grade zugestehen muß; dagegen die Luise von Voß durch den den Dichter selbst als Idylle, als *Gemälde*, nämlich mehr als Darstellung des Ruhigen denn als Darstellung des Fortschreitenden charakterisirt worden ist. Durch das Goethesche Gedicht ist also ein Problem der neueren Poesie gelöst und der Weg zu ferneren Versuchen dieser Art und Weise geöffnet. Es wäre nicht undenkbar, daß aus der Einzelnheit solcher Versuche, wenn sie sich gleich ursprünglich an einen bestimmt gebildeten Kern anschlößen, in der Folge sogar durch eine Synthese oder Ausdehnung, wie die mit den homerischen Gesängen geübte, ein gemeinschaftliches Ganzes entstehen könnte. Aber noch immer würde auch eine Totalität solcher kleineren epischen Ganzen nie die wahre Idee des Epos erreichen, das der modernen Welt so nothwendig fehlt, als die innere Identität der Bildung und die Identität des Zustandes, von dem sie ausgegangen ist. - Wir müssen daher diese Betrachtungen über das Epos mit demselben Resultat schließen, mit dem wir die über Mythologie geschlossen haben, nämlich daß der Homeros, der in der antiken Kunst der Erste war, in der modernen Kunst der Letzte seyn und die äußerste Bestimmung derselben vollenden wird. Dieses Resultat kann partielle Versuche den Homeros für eine bestimmte Zeit zu antipiciren, nicht niederschlagen, nur ist die Bedingung, unter welcher ächte Versuche dieser Art allein möglich werden, daß man die Grundeigenschaft des Epos, Universalität, d.h. Verwandlung alles"}, {"type": "paragraph", "text": "dessen, was in der Zeit zerstreut, aber doch entschieden vorhanden ist, in eine gemeinschaftliche Identität nicht aus den Augen setze. Für die Bildung der neueren Welt ist aber die Wissenschaft, die Religion, ja selbst die Kunst von nicht minder allgemeiner Beziehung und Bedeutung als die Geschichte, und in der unauflöslichen Mischung dieser Elemente würde eben das wahre Epos für die moderne Zeit bestehen müssen. Eines dieser Elemente kommt dem andern zur Hülfe; was für sich der epischen Behandlung nicht fähig wäre, wird es durch das andere, und etwas ganz und durchaus *Eigenthümliches *wenigstens müßte die Frucht dieser wechselseitigen Durchdringung seyn, ehe das ganz und durchaus Allgemeingültige entstehen kann. *Ein *Versuch dieser Art hat die Geschichte der neueren Poesie begonnen, es ist die göttliche Komödie des Dante, die so unbegriffen und unverstanden dasteht, weil sie in der Folge der Zeit einzeln geblieben ist, und von der Identität aus, welche dieses Gedicht bezeichnete, die Poesie sowohl als allgemeine Bildung sich nach so vielen Seiten zerstreut hat, daß es nur noch durch das Symbolische der Form allgemein gültig, durch die Ausschließung aber so vieler Seiten neuerer Bildung selbst wieder einseitig geworden ist. Die göttliche Komödie des Dante ist so ganz abgeschlossen in sich, daß die von den andern Gattungen abstrahirte Theorie für sie durchaus unzureichend ist. Sie fordert ihre eigne Theorie, sie ist ein Wesen einer eignen Gattung, eine Welt für sich. Sie bezeichnet eine Stufe, wohin sich nach Maßgabe der übrigen Verhältnisse die spätere Poesie nicht wieder erschwungen hat. Ich verhehle meine Ueberzeugung nicht, daß dieses Gedicht, so viel partiell Wahres darüber gesagt worden ist, doch *allgemein *und in seiner wahrhaft symbolischen Bedeutung noch nicht erkannt ist, daß es noch keine Theorie, keine Construktion dieses Gedichtes gibt. Schon darum ist es einer ganz besondern Betrachtung würdig. Es kann mit nichts anderem zusammengestellt, unter keine der andern Gattungen subsumirt werden; es ist nicht Epos, es ist nicht Lehrgedicht, es ist nicht Roman im eigentlichen Sinn, es ist selbst nicht Komödie oder Drama, wie es Dante selbst benennt hat; es ist die"}]}, {"page_pdf": 1799, "page_book": 688, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "unauflöslichste Mischung, die vollkommenste Durchdringung von allem; es ist nicht als dieses *einzelne* (denn insofern eignet auch dieses Gedicht der Zeit), aber es ist als Gattung allgemeinster Repräsentant der modernen Poesie, nicht ein einzelnes Gedicht, sondern das Gedicht aller Gedichte, die Poesie der modernen Poesie selbst. Dieß ist der Grund, warum ich die göttliche Komödie des Dante zum Gegenstand einer besondern Betrachtung mache, sie unter keine Gattung subsumire, sondern hiemit als Gattung für sich selbst constituire.1"}, {"type": "footnote", "text": "1 Der nun im Manuscript folgende Abschnitt \"Dantes göttliche Komödie\" ist unter den Abhandlungen des Kritischen Journals abgedruckt (oben S. 152 ff.). D. H."}, {"type": "paragraph", "text": "Von dem epischen Gedicht, welches wir bisher sowohl an sich selbst als in den Gattungen, die es durch Mischung mit andern Formen bildet, betrachtet haben - von dem epischen Gedicht als der Identität ging die Poesie aus, gleichsam als von einem Stande der Unschuld, wo alles noch beisammen und eins ist, was später nur zerstreut existirt, oder nur aus der Zerstreuung wieder zur Einheit kommt. Diese Identität entzündete sich im Fortgang der Bildung im lyrischen Gedicht zum Widerstreit, und erst die reifste Frucht der späteren Bildung war es, wodurch, auf einer höheren Stufe, die Einheit selbst mit dem Widerstreit sich versöhnte, und beide wieder in einer vollkommneren Bildung eins wurden. Diese höhere Identität ist das *Drama*, welches, die Naturen beider entgegengesetzten Gattungen in sich begreifend, die höchste Erscheinung des An-sich und des Wesens aller Kunst ist. So gesetzmäßig ist der Gang aller natürlichen Bildung, daß, was die letzte Synthese der *Idee *nach, die Vereinigung aller Gegensätze zur Totalität ist, auch die letzte Erscheinung der Zeit nach ist. Daß der allgemeine Gegensatz des Unendlichen und Endlichen für die Kunst in der höchsten Potenz sich als Gegensatz der Nothwendigkeit"}, {"type": "paragraph", "text": "und der Freiheit ausdrücke, ist im Allgemeinen schon beim lyrischen und epischen Gedicht bewiesen worden. Aber die Poesie hat überhaupt und in ihren höchsten Formen insbesondere diesen Gegensatz ohne Zweifel in der höchsten Potenz, also *als *Gegensatz von Nothwendigkeit und Freiheit darzustellen. Im lyrischen Gedicht ist, wie gesagt, dieser Widerstreit, aber so daß er als Streit und als Aufhebung des Streits nur im Subjekt ist und ins Subjekt zurückfällt; daher im Ganzen das lyrische Gedicht wieder vorzugsweise den Charakter der Freiheit an sich hat. Im epischen Gedicht ist überhaupt kein Widerstreit; hier herrscht die Nothwendigkeit als die Identität, nur daß sie, wie schon bemerkt, eben weil kein Streit ist, auch nicht als Nothwendigkeit, inwiefern diese *Schicksal *ist, sondern in der Identität mit der Freiheit, sogar zum Theil als Zufall, erscheinen kann. Das epische Gedicht geht durchaus mehr auf den *Erfolg *als auf die That. Im Erfolg kommt die Nothwendigkeit oder das Glück der Freiheit zu Hülfe, und führt aus was die Freiheit nicht ausführen kann. Hier also ist die Nothwendigkeit mit der Freiheit einstimmig ohne alle Differenz. Deßwegen kann der Held im Epos nicht unglücklich enden, ohne die Natur dieser Dichtart aufzuheben. Achill, wenn die Hauptperson der Ilias, kann nicht überwunden werden, sowie Hektor, weil er überwunden werden kann, nicht der Held der Ilias seyn kann. Aeneas ist nur als Eroberer von Latium und Gründer von Rom Held einer Epopee."}]}, {"page_pdf": 1800, "page_book": 689, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Wenn wir behaupten, daß im Epos die Identität oder die Nothwendigkeit das Herrschende sey, so könnte man einwenden, daß sie ihre Kraft weit mehr beweisen würde, wenn sie das, was die Freiheit nicht wollte, ausführte, als wenn sie umgekehrt mit der Freiheit eins ist und ausführt, was diese beginnt. Allein 1) kann die Nothwendigkeit im Epos nicht mit der Freiheit im Bunde erscheinen, ohne von der andern Seite gegen sie zu wirken. Achill ist nicht Sieger, ohne daß Hektor unterliegt. 2) Wenn die Nothwendigkeit auf die angegebene Weise im Streit gegen die Freiheit erschiene, daß sie dasjenige wollte, dem diese widerstrebt, so würde der Held der *Nothwendigkeit *entweder unterliegen,"}, {"type": "paragraph", "text": "oder sich über sie erheben. Im ersten Fall aber würde der Hauptheld unterliegen, im andern würde vielmehr die Freiheit ihre Uebermacht über die Nothwendigkeit beweisen, welches aber nicht der Fall seyn soll. Wir können also als ausgemacht Folgendes annehmen. Im lyrischen Gedicht ist ein Widerstreit, aber selbst bloß ein subjektiver; es kommt überhaupt nicht zum objektiven Conflikt mit der Nothwendigkeit. Im epischen Gedicht herrscht nur die Nothwendigkeit, die *insofern * mit dem Subjekt eins seyn muß als, ohne dieß, einer von den beiden Fällen eintreten müßte; und so also auch muß Unglück, inwiefern es auf der einen Seite stattfindet, durch ein verhältnißmäßiges Glück auf der andern ersetzt werden. Wenn wir nun diesen Grundsätzen zufolge ganz allgemein, und ohne noch irgend eine besondere Form vor Augen zu haben, fragen, von welcher Art dasjenige Gedicht seyn müßte, welches als die Totalität die Synthese der beiden entgegengesetzten Formen wäre, so ergibt sich gleich unmittelbar als erste Bestimmung folgende: es muß in dem Gedicht dieser Art ein wirklicher und demnach objektiver Widerstreit beider, der Freiheit und der Nothwendigkeit, da seyn, und zwar so daß beide *als solche erscheinen.* Es kann also in einem Gedicht, wie das angenommne, weder ein bloß subjektiver Streit noch auch eine *reine *Nothwendigkeit - die insofern mit dem Subjekt befreundet ist, und bloß darum aufhört Nothwendigkeit zu seyn - sondern nur eine mit Freiheit wirklich im Kampf begriffene Nothwendigkeit, und dennoch so, daß ein Gleichgewicht beider, dargestellt werden. Es fragt sich nur, wie dieß möglich sey. Kein wahrhafter Streit ist, wo nicht die Möglichkeit obzusiegen auf beiden Seiten ist. Aber diese scheint in dem angenommenen Fall von beiden Seiten undenkbar: denn keines von beiden ist wahrhaft überwindlich; die Nothwendigkeit nicht, denn, würde sie überwunden, so wäre sie nicht Nothwendigkeit; die Freiheit nicht, denn sie ist eben deßwegen Freiheit, weil sie nicht überwunden werden kann. Aber selbst"}, {"type": "paragraph", "text": "wenn es dem Begriff nach möglich wäre, daß diese oder jene unterläge, so wäre es nicht poetisch möglich; denn es wäre nicht ohne absolute Disharmonie möglich. Daß die Freiheit von der Nothwendigkeit überwunden würde, ist ein durchaus widriger Gedanke, aber ebensowenig können wir wollen, daß die Nothwendigkeit von der Freiheit überwunden werde, weil uns dieß den Anblick der höchsten Gesetzlosigkeit gibt. Es bleibt also in diesem Widerspruch schon von selbst nichts übrig als daß *beide*, Nothwendigkeit und Freiheit, aus diesem Streit zugleich als siegend und als besiegt, und demnach in jeder Rücksicht *gleich* hervorgehen. Aber eben dieß ist ohne Zweifel die höchste Erscheinung der Kunst, daß die Freiheit sich zur Gleichheit mit der Nothwendigkeit erhebe, und der Freiheit dagegen, ohne daß diese etwas dadurch verliere, die Nothwendigkeit gleich erscheine;"}]}, {"page_pdf": 1801, "page_book": 691, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "denn nur in diesem Verhältniß wird jene wahre und absolute Indifferenz, die im Absoluten ist, und die nicht auf einem Zugleich- sondern auf einem Gleichseyn beruht, objektiv. Denn Freiheit und Nothwendigkeit können, sowenig als Endliches und Unendliches, anders als in der gleichen Absolutheit eins werden. Die höchste Erscheinung der Kunst ist also, da * Freiheit *und *Nothwendigkeit * die * höchsten* Ausdrücke des Gegensatzes sind, der der Kunst überhaupt zu Grunde liegt, - diejenige, worin die Nothwendigkeit siegt, ohne daß die Freiheit unterliegt, und hinwiederum die Freiheit obsiegt, ohne daß die Nothwendigkeit besiegt wird. Es fragt sich nun, wie auch dieses möglich sey. Nothwendigkeit und Freiheit müssen, als allgemeine Begriffe, in der Kunst nothwendig symbolisch erscheinen, und da nur die menschliche Natur, indem sie von der einen Seite der Nothwendigkeit unterworfen ist, von der anderen der Freiheit fähig ist, so müssen beide an und durch die menschliche Natur symbolisirt werden, die selbst wieder durch Individuen dargestellt werden muß, die als Naturen, in welchen Freiheit und Nothwendigkeit in Verbindung sind, * Personen *heißen. Aber eben auch nur in der menschlichen Natur finden sich die Bedingungen der Möglichkeit, daß die Nothwendigkeit siege, ohne daß die Freiheit"}, {"type": "paragraph", "text": "unterliege, und umgekehrt die Freiheit überwinde, ohne daß der Gang der Nothwendigkeit unterbrochen werde. Denn dieselbe Person, welche durch die Nothwendigkeit unterliegt, kann sich durch die Gesinnung wieder über sie erheben, so daß beide, besiegt und siegend zugleich, in ihrer höchsten Indifferenz erscheinen. Im Allgemeinen also ist die menschliche Natur das einzige Mittel der Darstellung jenes Verhältnisses. Es fragt sich aber, in *welchen Verhältnissen *die menschliche Natur selbst fähig sey jene Macht der Freiheit zu zeigen, die, unabhängig von der Nothwendigkeit, zugleich, indem diese triumphirt, siegreich ihr Haupt erhebt. Ueber alles Günstige, dem Subjekt Angemessene wird die Freiheit mit der Nothwendigkeit einig seyn. Im Glück kann also die Freiheit weder im wahren Widerstreit noch in der wahren Gleichheit mit der Nothwendigkeit erscheinen. Nur dann wird sie auf diese Weise offenbar, wenn die Nothwendigkeit das Ueble verhängt, und die Freiheit, sich über diesen Sieg erhebend, *freiwillig *das Uebel übernimmt, sofern es nothwendig ist, sich also *als *Freiheit dennoch der Nothwendigkeit gleichstellt. Jene höchste Erscheinung der menschlichen Natur durch die Kunst wird also nie möglich seyn, als wo die Tapferkeit und Größe der Gesinnung über das Unglück siegt, und aus dem Kampf, welcher das Subjekt zu vernichten droht, die Freiheit als absolute Freiheit, für die es keinen Widerstreit gibt, hervorgeht. Aber ferner: welcher Art und Form wird die *Darstellung *dieser Erhebung der Freiheit zur vollkommenen Gleichheit mit der Nothwendigkeit seyn müssen? - Im epischen Gedicht wird die reine Nothwendigkeit, die deßwegen *selbst *nicht als Nothwendigkeit erscheint, weil Nothwendigkeit nur ein durch Gegensatz bestimmbarer Begriff ist - es wird die reine Identität *als solche *dargestellt. Die Nothwendigkeit aber ist sich selbst gleich und beständig, so daß auch der Gedanke der Nothwendigkeit in *dem *Sinn, in welchem sie im *epischen *Gedicht herrschend ist, als einer ewig *gleichmäßig *fließenden Identität, keine Bewegung der Seele verursacht, sondern sie ganz ruhig"}]}, {"page_pdf": 1802, "page_book": 693, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "läßt. Nur da bewegt sie die Seele, wo wirklich Widerstreit gegen sie ist. Aber in der Art von Darstellung, die wir voraussetzen, *soll *ja der Widerstreit erscheinen, nur nicht subjektiv - denn sonst wäre das Gedicht lyrisch - sondern *objektiv; *aber auch nicht objektiv wie im epischen Gedicht, so daß das Gemüth dabei ruhig und unbewegt bleibt. Es ist also nur Eine mögliche Darstellung, bei welcher das Darzustellende ebenso objektiv als im epischen Gedicht, und doch das Subjekt ebenso bewegt ist als im lyrischen Gedicht: es ist nämlich die, wo die Handlung nicht in der Erzählung, sondern selbst und wirklich vorgestellt wird (das Subjektive objektiv dargestellt wird). Die vorausgesetzte Gattung, welche die letzte Synthese aller Poesie seyn sollte, ist also das Drama. Um noch bei diesem Gegensatz des Drama als einer wirklich vorgestellten Handlung mit dem Epos zu verweilen, so ist wenn im Epos die reine Identität oder Nothwendigkeit herrschen soll, ein Erzähler nothwendig, der durch den Gleichmuth seiner Erzählung selbst von der allzugroßen Theilnahme an den handelnden Personen beständig zurückrufe, und ihre Aufmerksamkeit auf dem *reinen Erfolg *spanne. Dieselbe Begebenheit, welche, episch dargestellt, nur das objektive Interesse am Erfolg läßt, würde, dramatisch repräsentirt, unmittelbar das an den Personen damit vermischen, und dadurch die reine Objektivität der Anschauung aufheben. Der Erzähler, da er den handelnden Personen fremd ist, geht den Zuhörern in der gemäßigten Betrachtung nicht nur voran und stimmt sie durch die Erzählung selbst dazu, sondern er tritt auch gleichsam an die Stelle der Nothwendigkeit, und da diese ihr Ziel nicht selbst aussprechen kann, leitet er die Zuhörer darauf hin. Im dramatischen Gedicht dagegen, weil es die Natur der beiden entgegengesetzten Gattungen vereinigen soll, muß außer dem Antheil an der Begebenheit auch noch die Theilnahme an den Personen hinzukommen; nur durch diese Verbindung der Begebenheiten mit der Theilnahme an Personen wird sie Handlung und That. Thaten aber, um das Gemüth zu bewegen, müssen angeschaut werden, ebenso, wie Begebenheiten, um das Gemüth ruhiger zu lassen, erzählt seyn müssen. Thaten"}, {"type": "paragraph", "text": "gehen zum Theil aus inneren Zuständen der Ueberlegung, der Leidenschaften u.s.w. hervor, die, weil sie an sich subjektiv sind, nicht anders objektiv dargestellt werden können, als inwiefern das Subjekt, in dem sie vorgehen, selbst vor Augen gestellt wird. Begebenheiten lassen die inneren Zustände weniger erscheinen und berühren sie weniger, indem sie den Gegenstand sowohl als den Zuschauer mehr nach außen reißen. Wir haben, wie von selbst klar ist, das Drama gleich unmittelbar als Tragödie abgeleitet; insofern also die andere Form der Komödie, wie es scheint, ausgeschlossen. Das erste war nothwendig. Denn das Drama überhaupt kann nur aus einem wahren und wirklichen Streit der Freiheit und Nothwendigkeit, der Differenz und Indifferenz hervorgehen: es ist damit freilich nicht gesagt, * auf welcher Seite *die Freiheit, und auf welcher die Nothwendigkeit liegt; aber die ursprüngliche und absolute Erscheinung dieses Streits ist doch die, wo die Nothwendigkeit das Objektive, die Freiheit das Subjektive ist; und dieß das Verhältniß der Tragödie. Diese ist also das Erste und die Komödie das andere, denn sie entspringt durch eine bloße Umkehrung der Tragödie. Ich werde daher jetzt ferner auf gleiche Weise fortfahren, die Tragödie dem Wesen und der Form nach zu construiren. Das Meiste, was von der Form der Tragödie gilt, gilt auch von der der Komödie, und was sich daran durch die Umkehrung des Wesentlichen mit verändert, wird sich nachher sehr bestimmt angeben lassen."}, {"type": "paragraph", "text": "*Von der Tragödie.*"}, {"type": "paragraph", "text": "Das Wesentliche der *Tragödie *ist also ein wirklicher Streit der Freiheit im Subjekt und der Nothwendigkeit als objektiver, welcher Streit sich nicht damit endet, daß der eine oder der andere"}]}, {"page_pdf": 1803, "page_book": 694, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "unterliegt, sondern daß beide siegend und besiegt zugleich in der vollkommenen Indifferenz erscheinen. Wir haben noch genauer als bisher zu bestimmen, auf welche Weise dieß der Fall seyn könne."}, {"type": "paragraph", "text": "Nur da, wo die Nothwendigkeit das *Uebele *verhängt, bemerkten wir, könne sie mit der Freiheit wahrhaft im Streit erscheinen. Aber eben von welcher Art dieses Uebel seyn müsse, um der Tragödie angemessen zu seyn, ist die Frage. Bloß *äußeres *Unglück kann nicht dasjenige seyn, welches den wahrhaft tragischen Widerstreit hervorbringt. Denn daß die Person über äußeres Unglück sich erhebe, fordern wir schon von selbst, und sie wird uns nur verächtlich, wenn sie es nicht vermag. Der Held, der wie Ulyß auf der Heimkehr eine Kette von Unglücksfällen und vielfältiges Ungemach bekämpft, erweckt unsre Bewunderung, und wir folgen ihm mit Lust, aber er hat für uns kein tragisches Interesse, weil das Widerstrebende durch eine gleiche Kraft, nämlich durch physische Stärke oder durch Verstand und Klugheit bezwungen werden kann. Aber selbst Unglück, wogegen keine menschliche Hülfe möglich ist, z.B. unheilbare Krankheit, Verlust der Güter und dergl., hat, sofern es bloß physisch ist, kein tragisches Interesse; denn es ist eine nur noch untergeordnete und nicht die Schranken des Nothwendigen selbst überschreitende Wirkung der Freiheit, solche Uebel, die nicht zu ändern sind, mit Geduld zu ertragen. Aristoteles in der Poetik1 stellt folgende Fälle des Glückwechsels auf: 1) daß ein gerechter Mann aus dem Zustand des Glücks in Unglück verfalle; er sagt sehr richtig, daß dieß weder schrecklich noch bemitleidenswürdig, sondern nur abscheulich und darum zum tragischen Stoff untauglich sey; 2) daß ein Ungerechter aus widrigem Glück in günstiges übergehe. Dieß sey am wenigsten tragisch; 3) daß ein in hohem Grade Ungerechter oder Lasterhafter aus glücklichem Zustand in unglücklichen versetzt werde. Diese Zusammensetzung könne zwar die Menschenliebe berühren, aber weder Mitleid noch Schrecken hervorbringen. Es bliebe also nur ein mittlerer Fall übrig, nämlich daß ein *Solcher *Gegenstand der Tragödie sey, welcher weder durch Tugend und Gerechtigkeit vorzüglich ausgezeichnet, noch auch durch Laster und Verbrechen ins Unglück falle, sondern durch einen *Irrthum*, und daß"}, {"type": "footnote", "text": "1 Cap. XIII."}, {"type": "paragraph", "text": "derjenige, dem dieß begegnet, von solchen sey, die zuvor im großen Glück und Ansehen gestanden, wie Oedipus, Thyestes u.a. Aristoteles setzt hinzu, daß aus diesem Grunde, da vor Zeiten die Dichter alle möglichen Fabeln auf die Bühne gebracht haben, jetzt - zu * seiner *Zeit - die besten Tragödien sich auf wenige Familien beschränken, wie auf den Oedipus, Orestes, Thyestes, Telephos und diejenigen, denen überhaupt begegnet wäre Großes zu leiden oder zu verüben. Aristoteles hat, wie die Poesie überhaupt, so insbesondere auch die Tragödie mehr von der Verstandes- als von der Vernunft-Seite angesehen. Von der ersten betrachtet hat er den einzig höchsten Fall der Tragödie vollkommen bezeichnet. Derselbe Fall aber hat in allen den Beispielen, welche er selbst anführt, noch eine höhere Ansicht. Es ist die, daß die tragische Person *nothwendig * eines Verbrechens schuldig sey (und je höher die Schuld ist, wie die des Oedipus, desto tragischer oder verwickelter). Dieß ist das höchste denkbare Unglück, ohne wahre Schuld durch Verhängniß schuldig zu werden. Es ist also nothwendig, daß die Schuld selbst wieder Nothwendigkeit, und nicht sowohl, wie Aristoteles sagt, durch einen Irrthum, als durch den Willen des Schicksals und ein unvermeidliches"}]}, {"page_pdf": 1804, "page_book": 696, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Verhängniß oder eine Rache der Götter zugezogen sey. Von dieser Art ist die Schuld des Oedipus. Ein Orakel weissagt dem Lajos, es sey im Schicksal ihm vorherbestimmt, von der Hand seines und der Jokaste Sohns erschlagen zu werden. Der kaum geborene Sohn wird nach drei Tagen an den Füßen gebunden in einem unwegsamen Gebirg ausgesetzt. Ein Schäfer auf dem Gebirge findet das Kind oder erhält es aus den Händen eines Sclaven von Lajos Hause. Jener bringt das Kind in das Haus des Polybos, des angesehensten Bürgers von Korinth, wo es wegen der angeschwollenen Füße den Namen Oedipus erhält. Oedipus als er ins Jünglingsalter tritt, wird durch die Frechheit eines anderen, der ihn beim Trunk einen Bastard nennt, aus dem vermeinten elterlichen Hause fortgetrieben, und in Delphoi das Orakel wegen seiner Abkunft fragend erhält er *darauf *keine Antwort, wohl aber die Verkündung, er werde seiner Mutter beiwohnen, ein verhaßtes"}, {"type": "paragraph", "text": "und den Menschen unerträgliches Geschlecht zeugen, und den eignen Vater erschlagen. Dieß gehört sagt er, um sein Schicksal zu meiden, Korinth auf ewig Lebewohl, und beschließt bis dahin zu fliehen, wo er jene geweissagten Verbrechen niemals begehen könnte. Auf der Flucht begegnet er selbst Lajos ohne zu wissen, daß es Lajos und der König von Thebe ist, und erschlägt ihn im Streit. Auf dem Weg nach Thebe befreit er die Gegend von dem Ungeheuer der Sphinx und kommt in die Stadt, wo beschlossen war, daß wer sie erlegen würde, König seyn und Jokaste zur Gemahlin haben sollte. So vollendet sich das Schicksal des Oedipus, ihm selbst unbewußt; er heirathet seine Mutter und zeugt das unglückliche Geschlecht seiner Söhne und Töchter mit ihr. Ein ähnliches, obwohl nicht ganz gleiches Schicksal ist das der *Phädra*, welche durch den, von der Pasiphaë her, entbrannten Haß der Venus gegen ihr Geschlecht zur Liebe des Hippolytus entflammt wird. Wir sehen also, daß der Streit von Freiheit und Nothwendigkeit wahrhaft nur da ist, wo diese den Willen selbst untergräbt, und die Freiheit auf ihrem eignen Boden bekämpft wird. Man hat, anstatt einzusehen, daß *dieses *Verhältniß das einzig wahrhaft tragische ist, mit dem kein anderes verglichen werden kann, wo das Unglück nicht * im* Willen und in der Freiheit selbst liegt, vielmehr gefragt, wie die Griechen diese schrecklichen Widersprüche ihrer Tragödien haben ertragen können. Ein Sterblicher, vom Verhängniß zur Schuld und zum Verbrechen bestimmt, selbst wie Oedipus *gegen *das Verhängniß kämpfend, die Schuld fliehend, und doch fürchterlich bestraft für das Verbrechen, das ein Werk des Schicksals war. Sind, frug man, diese Widersprüche nicht rein zerreißend, und wo liegt der Grund der Schönheit, welche die Griechen in ihren Tragödien nichts desto weniger erreicht haben? - Die Antwort auf diese Frage ist folgende. Daß ein wahrhafter Streit von Freiheit und Nothwendigkeit nur in dem angegebenen Fall stattfinden kann, wo der Schuldige durch das Schicksal zum Verbrecher gemacht ist, ist bewiesen. Daß aber der"}, {"type": "paragraph", "text": "Schuldige, der doch nur der Uebermacht des Schicksals unterlag, dennoch bestraft wurde, war nöthig, *um* den Triumph der Freiheit zu zeigen, war Anerkennung der Freiheit, *Ehre*, die ihr gebührte. Der Held mußte gegen das Verhängniß kämpfen, sonst war überhaupt kein Streit, keine Aeußerung der Freiheit; er mußte in dem, was der Nothwendigkeit unterworfen ist, unterliegen, aber um die Nothwendigkeit nicht überwinden zu lassen, ohne sie zugleich wieder zu überwinden, mußte der Held auch für diese - durch das Schicksal verhängte - Schuld freiwillig büßen. Es ist der größte Gedanke und der höchste Sieg der Freiheit, willig auch die Strafe für ein unvermeidliches Verbrechen zu tragen, um so im Verlust seiner Freiheit selbst eben diese Freiheit zu beweisen, und noch mit einer Erklärung des freien Willens"}]}, {"page_pdf": 1805, "page_book": 698, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "unterzugehen. Dieß, wie es hier ausgesprochen ist, und wie ich es schon in den Briefen über Dogmatismus und Kriticismus gezeigt habe,1 ist der innerste Geist der griechischen Tragödie. Dieß ist der Grund der Versöhnung und der Harmonie, die in ihnen liegt, daß sie uns nicht zerrissen, sondern geheilt, und wie Aristoteles sagt, gereinigt zurücklassen. Die Freiheit als bloße Besonderheit kann nicht bestehen: dieß ist möglich nur, inwiefern sie sich selbst zur Allgemeinheit erhebt, und also über die Folge der Schuld mit der Nothwendigkeit in Bund tritt, und da sie das Unvermeidliche nicht vermeiden kann, die Wirkung davon selbst über sich verhängt. Ich sage: dieß ist auch das einzig wahrhaft *Tragische *in der Tragödie. Nicht der unglückliche Ausgang allein. Denn wie kann man überhaupt den Ausgang unglücklich nennen, z.B. wenn der Held freiwillig das Leben hingibt, das er nicht mehr mit Würde führen kann, oder wenn er andere Folgen seiner unverschuldeten Schuld auf sich selbst herbeizieht, wie Oedipus bei Sophokles thut, der nicht ruht, bis er das ganze schreckliche Gewebe selbst entwickelt und das ganze furchtbare Verhängniß selbst an den Tag gebracht hat?"}, {"type": "footnote", "text": "1 Zehnter Brief, 1. Abth., Bd. I., S. 336."}, {"type": "paragraph", "text": "Wie kann man den unglücklich nennen, der *so weit *vollendet ist, der Glück und Unglück gleicherweise ablegt und in demjenigen Zustand der Seele ist, wo es für ihn keines von beiden mehr ist? * Unglück *ist nur, so lange der Wille der Nothwendigkeit noch nicht entschieden und offenbar ist. Sobald der Held selbst im Klaren ist, und sein Geschick offen vor ihm daliegt, gibt es für ihn keinen Zweifel mehr, oder wenigstens darf es für ihn keinen mehr geben, und eben im Moment des *höchsten* Leidens geht er zur höchsten Befreiung und die höchste Leidenslosigkeit über. Von dem Augenblick an erscheint die nicht zu überwältigende Macht des Schicksals, die absolut-groß schien, nur noch relativ-groß; denn sie wird von dem Willen überwunden, und zum Symbol des absolut Großen, nämlich der erhabenen Gesinnung. Die tragische Wirkung beruht daher keineswegs allein oder zunächst auf dem, was man den unglücklichen Ausgang zu nennen pflegt. Die Tragödie kann auch mit vollkommener Versöhnung nicht nur mit dem Schicksal, sondern selbst mit dem Leben enden, wie Orest in den Eumeniden des Aeschylos versöhnt wird. Auch Orest war durch das Schicksal und den Willen eines Gottes, nämlich Apollos, zum Verbrecher bestimmt. Aber diese Schuldlosigkeit nimmt die *Strafe * nicht hinweg; er entflieht aus dem väterlichen Hause und erblickt gleich unmittelbar die Eumeniden, die ihn selbst bis in den geheiligten Tempel des Apollon verfolgen, wo sie, die schlafen, der Schatten der Klytämnestra erweckt. Die Schuld kann nur durch wirkliche Sühnung von ihm genommen werden, und auch der Areopag, an welchen Apoll ihn verweist, und vor dem er selbst ihm beisteht, muß gleiche Stimmen in die beiden Urnen legen, damit die Gleichheit der Nothwendigkeit und der Freiheit vor der sittlichen Stimmung bewahrt werde. Nur der weiße Stein, den Pallas der Lossprechungsurne zuwirft, befreit ihn, aber auch dieses nicht, ohne daß zugleich die Göttinnen des Schicksals und der Nothwendigkeit, die rächenden Erinnyen, versöhnt und von nun an unter dem Volk der Athene als göttliche Mächte verehrt werden und in ihrer Stadt selbst und gegenüber von der Burg, auf der sie thront, einen Tempel haben."}]}, {"page_pdf": 1806, "page_book": 700, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Ein *solches *Gleichgewicht des Rechts und der Menschlichkeit, der Nothwendigkeit und der Freiheit suchten die Griechen in ihren Tragödien, ohne welches sie ihren sittlichen Sinn nicht befriedigen konnten, sowie sich in diesem Gleichgewicht selbst die höchste Sittlichkeit ausgedrückt hat. Eben dieses Gleichgewicht ist die Hauptsache der Tragödie. Daß das überlegte und freie Verbrechen gestraft wird, ist nicht tragisch. Daß ein Schuldloser durch Schickung unvermeidlich fortan schuldig werde, ist, wie gesagt, an sich das höchste denkbare Unglück. Aber daß dieser schuldlose Schuldige freiwillig die Strafe übernimmt, dieß ist das *Erhabene *in der Tragödie, dadurch erst verklärt sich die Freiheit zur höchsten Identität mit der Nothwendigkeit. Nachdem wir das Wesen und den wahren Gegenstand der Tragödie durch das Bisherige bestimmt haben, so ist es nöthig, zunächst von der *inneren Construktion *der Tragödie, und alsdann von der äußeren Form derselben zu handeln. Da dasjenige, was in der Tragödie der Freiheit entgegengesetzt wird, die Nothwendigkeit ist, so erhellt von selbst, daß in der Tragödie durchaus dem Zufall nichts zugegeben werden darf. Denn selbst die Freiheit, sofern sie die Verwicklung durch ihre Handlungen hervorbringt, erscheint doch in dieser Beziehung als durch Schicksal getrieben. Es könnte zufällig scheinen, daß Oedipus dem Lajos an einer bestimmten Stelle begegnet, allein wir sehen aus dem Verlauf, daß diese Begebenheit zur Erfüllung des Schicksals nothwendig war. Inwiefern aber ihre Nothwendigkeit nur durch die Entwicklung kann eingesehen werden, insofern ist sie eigentlich auch nicht Theil der Tragödie und wird in die Vergangenheit verlegt. Uebrigens aber erscheint, im Oedipus z.B., alles, was zur Vollführung des in dem ersten Orakel Verkündeten gehört, eben durch diese Vorherverkündigung nothwendig und im Licht einer höheren Nothwendigkeit. Was aber die Handlungen der Freiheit betrifft, sofern diese erst auf die geschehenen Schläge des Schicksals folgen, so sind auch diese nicht zufällig, eben deßwegen weil sie aus absoluter Freiheit geschehen, und die absolute Freiheit selbst absolute Nothwendigkeit ist."}, {"type": "paragraph", "text": "Da selbst alle empirische Nothwendigkeit nur empirisch Nothwendigkeit, an sich betrachtet aber Zufälligkeit ist, so kann die ächte Tragödie auch nicht auf empirische Nothwendigkeit gegründet seyn. Alles, was empirisch nothwendig ist, ist, weil ein anderes ist, wodurch es möglich ist, aber dieses andere selbst ist ja nicht an sich nothwendig, sondern wieder durch ein anderes. Die empirische Nothwendigkeit würde aber die Zufälligkeit nicht aufheben. Diejenige Nothwendigkeit, die in der Tragödie erscheint, kann demnach einzig absoluter Art und eine solche seyn, die empirisch vielmehr unbegreiflich als begreiflich ist. Inwiefern selbst, um die Verstandesseite nicht zu vernachlässigen, eine empirische Nothwendigkeit in der Aufeinanderfolge der Begebenheiten eingeführt wird, muß diese doch selbst nicht wieder empirisch, sondern nur absolut begriffen werden können. Die empirische Nothwendigkeit muß als Werkzeug der höheren und absoluten erscheinen; sie muß nur dienen für die Erscheinung herbeizuführen, was in dieser schon *geschehen *ist. Hierher gehört nun auch das sogenannte *Motiviren*, welches ein Necessitiren oder Begründung der Handlung im Subjekt ist, und welches vornehmlich durch äußere Mittel geschieht. Die Grenze dieses Motivirens ist schon durch das Vorhergehende bestimmt. Soll es etwa auf das Herstellen einer recht empirisch-begreiflichen Nothwendigkeit gehen, so ist es ganz verwerflich, besonders wenn sich der Dichter dadurch zu der groben Fassungskraft der Zuschauer herablassen will. Die Kunst des Motivirens würde dann darin bestehen, dem Helden nur einen Charakter von recht großer Weite zu geben, aus dem nichts auf absolute Weise hervorgehen kann, in dem also alle möglichen Motive ihr Spiel treiben können. Dieß ist der gerade Weg, den Helden schwach und als das Spiel äußerer Bestimmungsgründe erscheinen zu lassen. Ein solcher ist nicht tragisch. Der tragische Held muß, in welcher Beziehung es sey, eine Absolutheit des Charakters haben, so daß ihm das Aeußere nur *Stoff *ist, und es in keinem Fall zweifelhaft seyn kann, wie er handelt. Ja in Ermanglung des anderen Schicksals"}]}, {"page_pdf": 1807, "page_book": 701, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "müßte ihm der Charakter dazu werden. Von welcher Art auch der äußere Stoff sey, die Handlung muß immer aus ihm selbst kommen."}, {"type": "paragraph", "text": "Aber überhaupt muß gleich die erste Construktion der Tragödie, der erste Wurf so seyn , daß die Handlung auch in dieser Rücksicht als *Eine* und als stetig erscheine, daß sie nicht durch ganz verschiedenartige Motive mühsam fortgetrieben wird. Stoff und Feuer müssen gleich so combinirt seyn, daß das Ganze von selbst fort brennt. Gleich das Erste der Tragödie sey ein Synthesis, eine Verwicklung, die nur so gelöst werden kann, wie sie gelöst wird, und für die ganze Folge keine Wahl läßt. Welche Mittelglieder auch der Dichter ins Spiel setzen möge, um die Handlung zu ihrem Ende zu leiten, so müssen diese zuletzt selbst wieder aus dem über dem Ganzen ruhenden Verhängniß hervorgehen und Werkzeuge von ihm scheinen. Widrigenfalls wird der Geist beständig aus der höheren Ordnung der Dinge in die tiefere versetzt, und umgekehrt. Die Begrenzung eines dramatischen Werks in Beziehung auf das, was in ihm sittlich-möglich ist, wird durch das ausgedrückt, was man die Sitten der Tragödie nennt. Was man ursprünglich darunter verstand, ist ohne Zweifel die Stufe der sittlichen Bildung, auf welche die Personen eines Drama gesetzt, und wodurch gewisse Arten von Handlungen von ihnen ausgeschlossen, dagegen die, welche geschehen, nothwendig gemacht sind. Die erste Forderung ist nun ohne Zweifel die, welche auch Aristoteles macht, daß sie edler Art seyen, worunter er nach dem, was früherhin als seine Behauptung über den einzig höchsten tragischen Fall angeführt worden, nicht eben absolut schuldlose, sondern überhaupt edle und große Sitten fordert. Daß ein wirklicher, aber durch Charakter großer Verbrecher vorgestellt wird, wäre bloß in dem anderen tragischen Fall möglich, wo ein äußerst ungerechter Mensch aus dem Glück in Unglück gestürzt würde. Unter denjenigen Tragödien der Alten, die uns geblieben sind, kenne ich keinen Fall dieser Art, und das Verbrechen, wenn es in der wahrhaft sittlichen Tragödie vorgestellt ist, erscheint immer selbst durch Schicksal verhängt. Es ist aber aus dem Einen Grund, daß den Neueren das Schicksal fehlt, oder von ihnen wenigstens nicht auf die Weise der Alten in Bewegung gesetzt werden kann, es ist, sage ich, schon daraus einzusehen, warum die"}, {"type": "paragraph", "text": "Neueren öfter zu diesem Fall recurrirt haben, große Verbrechen vorzustellen, ohne das Edle der Sitten dadurch aufzuheben, und deßwegen die Nothwendigkeit des Verbrechens in die Gewalt eines unbezwinglichen Charakters zu legen, wie Shakespeare sehr oft gethan hat. Da die griechische Tragödie so ganz sittlich und auf die höchste Sittlichkeit eigentlich gegründet ist, so kann in ihr auch über die eigentlich sittliche Stimmung, wenigstens in der letzten Instanz, keine Frage mehr seyn. Die Totalität der Darstellung fordert, daß auch in den Sitten der Tragödie Abstufungen stattfinden, und besonders Sophokles verstand mit den wenigsten Personen nicht nur überhaupt die größte Wirkung, sondern in dieser Begrenzung auch eine geschlossene Totalität der Sitten hervorzubringen. In dem Gebrauch dessen, was Aristoteles das θαυμαστόν, das Außerordentliche nennt, unterscheidet das Drama sich sehr wesentlich von dem epischen Gedicht. Das epische Gedicht stellt einen glücklichen Zustand dar, eine ungetheilte Welt, wo Götter und Menschen eins sind. Hier ist, wie wir schon sagten, die Dazwischenkunft der Götter nicht wunderbar, weil sie zu dieser Welt selbst gehören. Das Drama ruht schon mehr oder weniger auf einer getheilten Welt, indem es Nothwendigkeit und Freiheit sich entgegensetzt. Hier würde die Erscheinung der Götter, wofern sie auf dieselbe Weise wie im Epos stattfände, den Charakter des Wunderbaren annehmen. Da nämlich im Drama kein Zufall, und alles"}]}, {"page_pdf": 1808, "page_book": 703, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "entweder äußerlich oder innerlich *nothwendig *seyn soll, so könnten die Götter nur wegen einer Nothwendigkeit, die in ihnen selbst läge, also nur insofern sie selbst mithandelnde oder wenigstens in die Handlung ursprünglich verwickelte Personen sind, in ihr erscheinen, keineswegs aber um den handelnden Personen, vornehmlich aber der Hauptperson entweder zu Hülfe zu kommen, oder feindlich zu begegnen (wie in der Ilias). Denn der Held der Tragödie soll und muß den Kampf für sich allein ausfechten; nur durch die sittliche Größe seiner Seele soll er ihn bestehen, und die äußere Heilung und Hülfe, welche Götter ihm gewähren können, * genügt* nicht einmal seinem"}, {"type": "paragraph", "text": "Zustande. Sein Verhältniß kann sich nur innerlich lösen, und wenn die Götter, wie in den Eumeniden des Aeschylos das versöhnende Princip sind, so müssen sie selbst zu den Bedingungen herabsteigen, unter welchen der Mensch ist; auch sie können nicht versöhnen oder erretten, als inwiefern sie das Gleichgewicht der Freiheit und Nothwendigkeit herstellen und sich mit den Gottheiten des Rechts und des Schicksals in Unterhandlungen setzen. In diesem Fall aber ist in ihrer Erscheinung nichts Wunderbares, und die Errettung und Hülfe, die sie schaffen, leisten sie nicht als Götter, sondern dadurch, daß sie zu dem Loos der Menschen herabsteigen und sich selbst dem Recht und der Nothwendigkeit fügen. Wenn aber Götter in der Tragödie feindlich wirken, so sind sie selbst das Schicksal; auch thun sie es nicht in Person, sondern auch ihre feindliche Wirkung äußert sich durch eine innere Nothwendigkeit im Handelnden, wie bei der Phädra. Die Götter also in der Tragödie zu Hülfe zu rufen, um die Handlung nur äußerlich zu enden, wahrhaft aber und innerlich zu unterbrechen oder ungeschlossen zu lassen, wäre für das ganze Wesen der Tragödie zerstörend. Dasjenige Uebel, was Götter als solche durch ihre bloße Dazwischenkunft heilen können, ist an sich selbst kein wahrhaft tragisches Uebel. Umgekehrt; wo ein solches vorhanden ist, vermögen sie nichts, und wenn sie dennoch herbeigerufen werden, so ist dieß, was man den Deus ex machina nennt, und was allgemein als eversiv für das Wesen der Tragödie erkannt ist. Denn - um mit dieser Bestimmung die Untersuchung über die innere Construktion der Tragödie zu vollenden - so muß die Handlung nicht bloß äußerlich, sondern innerlich, im Gemüth selbst, geschlossen werden, wie es eine innerliche Empörung ist, welche das Tragische eigentlich hervorbringt. Nur von dieser * inneren *Versöhnung aus geht jene Harmonie, die wir zur Vollendung fordern. Schlechten Poeten genügt es die mühsam fortgeführte Handlung nur äußerlich zu schließen. Ebensowenig als dieß geschehen darf, darf die Versöhnung durch etwas Fremdartiges, Außerordentliches, außer dem Gemüth und der Handlung Liegendes geschehen, als ob die Herbheit des wahren Schicksals durch"}, {"type": "paragraph", "text": "irgend etwas anderes als die Größe und freiwillige Uebernahme und Erhebung des Gemüths gemildert werden könnte. (Hauptmotiv der Versöhnung die Religion, wie im Oedipus auf Kolonos. Höchste Verklärung wie ihn der Gott ruft: Horch, horch, Oedipus, warum zauderst du, und er dann den Augen der Sterblichen verschwindet.) Ich gehe nun zur *äußeren Form *der Tragödie fort. Daß also die Tragödie nicht eine Erzählung, sondern die wirklich-objektive Handlung selbst seyn müsse, ergibt sich aus dem ersten Begriff. Aber aus diesem folgt auch mit strenger Nothwendigkeit die übrige Gesetzmäßigkeit der äußeren Form. Die Handlung, wenn sie erzählt wird, geht durch das Denken hindurch, welches seiner Natur nach das freiste ist, und worin auch Entferntes sich unmittelbar berührt. Die Handlung, die objektiv-wirklich vorgestellt wird, wird angeschaut, und muß sich also auch den"}]}, {"page_pdf": 1809, "page_book": 705, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Gesetzen der Anschauung fügen. Diese aber verlangt nothwendig die Stetigkeit. Stetigkeit der Handlung ist demnach die nothwendige Eigenschaft jedes rationalen Dramas. Mit Veränderung derselben muß zugleich eine Veränderung in der ganzen übrigen Conformation desselben eintreten: daher es freilich thöricht ist, sich an dieses Gesetz der alten Tragödie zu binden, wenn man ihr in keinem anderen Zug auch nur von ferne nahe kommen kann, wie die Franzosen in ihren Stücken, die sie abusive Tragödien nennen, die Stetigkeit der Zeit zu beobachten. Aber die französische Bühne beobachtet sie nicht einmal, außer inwiefern sie ganz *bloß *beschränkend ist, dadurch, daß der Dichter zwischen den Aufzügen Zeit verfließen läßt. Die Stetigkeit der Handlung in diesem Fall aufheben, während man sie in anderer Rücksicht beobachten will, heißt nur Dürftigkeit und das Unvermögen verrathen, eine große Handlung concentrisch, gleichsam um einen und denselben Punkt geschehen zu lassen. Die Stetigkeit der Zeit ist eigentlich von den drei Einheiten, die Aristoteles gibt, die herrschende. Denn, was die sogenannte Einheit des Orts betrifft, so braucht diese bloß insofern stattzufinden, als sie für die Stetigkeit der Zeit nothwendig ist, und unter den wenigen uns übrig gebliebenen Tragödien der Alten existirt doch - und zwar in"}, {"type": "paragraph", "text": "Sophokles selbst (im Ajax nämlich) - das Beispiel einer nothwendigen Veränderung des Orts. Die äußere Stetigkeit der Handlung, welche zur vollkommensten Erscheinung der Tragödie gehört, was auch moderne Kunstrichter aus übelverstandenem Eifer gegen die übelverstandene Einheit der Zeit in den französischen Stücken und gegen ihre übrige Bornirtheit dawider vorgebracht haben möge, ist nur die äußere Erscheinung der inneren Stetigkeit und *Einheit *der Handlung selbst. Diese kann nun schon ihrer Natur nach nicht stattfinden, als inwiefern die Zufälligkeiten einer wirklich, empirisch geschehenen Handlung und ihre Begleitung aufgehoben werden. Nur durch Darstellung des Wesentlichen, gleichsam des reinen Rhythmus der Handlung, ohne alle Breitheit der Umstände und des zugleich mit der Haupthandlung Vorgehenden, wird die wahrhaft plastische Vollendung im Drama erreicht. Die herrlichste und durchaus von der erhabensten Kunst eingegebene Erfindung ist in dieser Beziehung der *Chor *der griechischen Tragödie. Ich nenne ihn eine hohe Erfindung, weil er den groben Sinnen nicht schmeichelt, von dem gemeinen Verlangen nach Täuschung gänzlich hinweg- und den Zuschauer unmittelbar auf das höhere Gebiet der wahren Kunst und der symbolischen Darstellung erhebt. Der Chor der griechischen Tragödie schließt zwar mehrfache Wirkungen ein, die vornehmste aber ist, daß er die Zufälligkeiten der Begleitung aufhebt, da natürlicher Weise keine Handlung vorgehen kann, die nicht außer den mithandelnden Personen auch noch andere hätte, die sich in Bezug auf die Haupthandlung unthätig verhalten. Diese *bloß *zuschauen oder *bloße * Nebendienste verrichten zu lassen, würde die Handlung, die gleichsam in jedem Punkt wie eine volle Blüthe, fruchtbar und schwanger seyn soll, leer lassen. Sollte nun dieser Uebelstand realistisch aufgehoben werden, so mußte auch in diese Nebenpersonen ein Gewicht gelegt und dem Ganzen dadurch die Breitheit gegeben werden, welche die Tragödie der Neueren hat. Die Alten nehmen dieses Verhältniß idealistischer, symbolisch. Sie verwandelten die Begleitung in den Chor, und gaben diesem in ihren Tragödien eine wahre, d.h. poetische"}, {"type": "paragraph", "text": "Nothwendigkeit. Er erhielt die Bestimmung, auch noch das, was in dem Zuschauer vorging, die Bewegung des Gemüths, die Theilnahme, die Reflexion, ihm vorweg zu nehmen, ihn auch in dieser Rücksicht nicht frei zu lassen, und dadurch ganz durch die Kunst zu fesseln. Der Chor ist einem großen"}]}, {"page_pdf": 1810, "page_book": 707, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Theile nach die objektivirte und repräsentirte Reflexion, die die Handlung begleitet. Wie nun die freie Contemplation auch des Furchtbaren und Schmerzvollen an und für sich schon über die erste Heftigkeit der Furcht und des Schmerzens erhebt, so war der Chor gleichsam ein stetiges Besänftigungs- und Versöhnungsmittel der Tragödie, wodurch der Zuschauer zur ruhigeren Betrachtung geleitet und von der Empfindung des Schmerzens gleichsam dadurch erleichtert wurde, daß sie in ein Objekt gelegt und in diesem schon gemäßigt vorgestellt wurde. - Daß diese Vollendung der Tragödie, in welcher sie nichts außer sich zurückläßt und gleichsam auch die Reflexion, die sie erweckt, wie die Bewegung und Theilnahme selbst in ihren Kreis zieht, die vornehmste Absicht des Chors gewesen, ergibt sich aus seiner Verfassung. 1) Der Chor bestand nicht aus Einer, sondern aus mehreren Personen. Bestand er aus Einer, so mußte er entweder mit den Zuschauern reden - aber eben diese sollten hier ja aus dem Spiel gelassen werden, um ihre eigne Theilnahme gleichsam objektivirt zu sehen, *oder *mit sich selbst, aber dieß konnte er wieder nicht, ohne zu bewegt zu erscheinen, welches gegen seine Bedeutung war. Er mußte also aus mehreren Personen bestehen, die aber nur Eine vorstellten, wodurch die ganz symbolische Bildung des Chors vollends offenbar wird. Der Chor war 2) nicht * in* der Handlung als solcher begriffen. Denn wenn er selbst der Haupthandelnde war, so konnte er nicht seine Bestimmung erfüllen, zu bewirken, daß die Gemüther der Zuhörer sich sammeln. Die Ausnahme, welche in den Eumeniden des Aeschylos stattzufinden scheint, wo diese selbst den Chor bilden, ist nur scheinbar, und gewissermaßen gehört dieser Zug mit zu der hohen und unerreichten sittlichen Stimmung, in der diese ganze Tragödie gedichtet ist, da der Chor in gewissem Sinn die objektivirte Reflexion der Zuschauer selbst und mit"}, {"type": "paragraph", "text": "*ihnen *einverstanden ist, Aeschylos also hier die Zuschauer als auf der Seite des Rechts und der Gerechtigkeit stehend annahm. Sonst ist der Chor mehr oder weniger indifferent. Die handelnden Personen sprechen, als ob sie ganz allein wären und keine Zeugen hätten. Auch darin zeigt sich die ganz symbolische Bedeutung des Chors. Er ist, wie der Zuschauer, der Vertraute beider Parteien und verräth keine an die andere. Wenn er aber Theil nimmt, so ist es, weil er unparteiisch ist, immer die Seite des Rechts und der Billigkeit, auf die er tritt. Er räth zum Frieden, sucht zu besänftigen, beklagt das Unrecht und unterstützt den Unterdrückten, oder gibt seine Theilnahme an dem Unglück durch sanfte Rührung zu erkennen. (Aus dieser Indifferenz und Unparteilichkeit des Chors sieht man das Mißlungene der Nachahmung desselben in Schillers Braut von Messina.) Da der Chor eine symbolische Person ist, so kann auf ihn auch alles andere zur Handlung Nothwendige, aber nicht in ihr selbst Begriffene übergetragen werden. Er überhebt also den Dichter einer Menge anderer zufälliger Beschwerlichkeiten. Die neueren Dichter ersticken die Handlung gleichsam unter der Last der Mittel, die sie brauchen, sie in Bewegung zu setzen. Zum wenigsten bedürfen sie doch für die Hauptperson eines Vertrauten, eines Rathgebers. Auch dieß ist durch den Chor aufgehoben, der, da er das Nothwendige und Unvermeidliche ebenso wie das Vermeidliche sieht, im erforderlichen Fall durch Rath, Vermahnung, Antrieb wirksam ist. Endlich auch die große Last neuerer Dichter, das Theater nie leer zu lassen, ist durch den Chor hinweggenommen. Gehen wir nun, nachdem wir die Tragödie ganz von innen heraus construirt haben, bis zur letzten Erscheinung fort, so ist sie unter den drei Formen der Poesie die einzige, die den Gegenstand von allen Seiten, demnach ganz absolut zeigt, da das Epos den Zuhörer ebenso wie die Malerei doch für jeden einzelnen Fall auf einen gewissen Gesichtspunkt beschränkt, und ihn von dem Gegenstand jedesmal nur so viel sehen läßt, als dem Erzähler gefällig ist. Das Drama ist endlich unter diesen drei Formen die einzig wahrhaft symbolische, eben dadurch, daß sie ihre"}]}, {"page_pdf": 1811, "page_book": 708, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Gegenstände nicht bloß bedeutet, sondern selbst vor Augen stellt. Es entspricht also der plastischen Kunst unter den redenden Künsten, und schließt als die letzte Totalität ebenso *diese *Seite der Kunstwelt, wie die Plastik die andere geschlossen hat."}, {"type": "paragraph", "text": "*Ueber Aeschylos, Sophokles, Euripides.*"}, {"type": "paragraph", "text": "Wenn man auf diese Weise das Wesen und die innere und äußere Form der Tragödie aus ganz allgemeinen Gründen construirt hat, und sich nun zu der Betrachtung der ächten Werke der griechischen Tragödie wendet, und sie durchaus dem, was sich darüber ganz allgemein einsehen läßt, angemessen findet, so begreift man erst vollständig die Reinheit und Rationalität der griechischen Kunst. Auch das *Epos * der Griechen trägt dieses Gepräge, aber es läßt sich in ihm, weil sein rationaler Charakter selbst mehr Zufälligkeit zuläßt, nicht so streng und bis ins Detail nachweisen, wie an der griechischen Tragödie, die man fast wie eine geometrische oder arithmetische Aufgabe ansehen kann, die völlig rein und ohne Bruch aufgeht. Zum Wesen des Epos gehört es, daß kein bestimmter Anfang noch Ende. Das Gegentheil bei der Tragödie. In ihr wird eben ein solches reines Aufgehen, ein absolutes Geschlossenseyn gefordert, ohne daß irgend etwas noch unbefriedigt zurückbliebe. Wenn die drei griechischen Tragiker unter einander verglichen werden, so findet sich zwar, daß Euripides von den beiden ersten in mehr als einer Beziehung abgesondert werden muß. Das Wesen der ächten Aeschyleischen und Sophokleischen Tragödie ist durchaus auf jene höhere Sittlichkeit gegründet, welche der Geist und das Leben ihrer Zeit und ihrer Stadt war. Das Tragische ruht in ihren Werken nie auf dem bloß äußeren Unglück; die Nothwendigkeit erscheint vielmehr mit dem Willen selbst in unmittelbarem Streit und bekämpft ihn auf seinem eignen Boden. Der Prometheus des Aeschylos leidet nicht bloß durch den *äußeren* Schmerz, sondern viel tiefer durch das innere Gefühl des Unrechts und der Unterdrückung, und sein Leiden äußert sich nicht als Unterwerfung, da es nicht das Schicksal ist, sondern die Tyrannei des neuen Herrschers der Götter, die ihm dieß Leiden bereitet, es"}, {"type": "paragraph", "text": "äußert sich als Trotz, als Empörung, und eben dadurch * siegt *hier die Freiheit über die Nothwendigkeit, daß ihn im Gefühl seines *persön*lichen Leidens doch nur die *allgemeine *Empörung gegen die unerträgliche Herrschaft des Jupiter bewegt. Prometheus ist das Urbild des größten Menschencharakters, und dadurch auch das wahre Urbild der Tragödie. Die sittliche Reinheit und Erhabenheit in den Eumeniden des Aeschylos wurde schon vorhin hervorgehoben. Aber in allen seinen Stücken ließe sich jenes Grundgesetz der Tragödie, daß das Verbrechen und die Schuld mittel- oder unmittelbares Werk der Nothwendigkeit sey, nachweisen. Die hohe Sittlichkeit, die absolute Reinheit der Sophokleischen Werke ist die Bewunderung aller Zeitalter gewesen; sie spricht sich ganz in den Worten des Chors bei Oedipus1 aus: \"O möge mir das Loos gelingen, fromme Heiligkeit zu bewahren in Worten und allen Werken, wofür vorgesetzt sind die erhaben gestellten Gesetze, aus dem himmlischen Aether geboren, deren einziger Vater Olympos, und die nicht die sterbliche Natur der Menschen geboren hat, noch die Vergessenheit je begraben wird. Ein großer Gott vielmehr ist in ihnen, der vor Alter nicht welkt.\" Was beiden, dem Sophokles und Aeschylos gemein ist, ist ferner, daß die Handlung nie bloß äußerlich, sondern innerlich und äußerlich zugleich geschlossen ist. Ihre Wirkung auf die Seele ist, sie von Leidenschaften zu reinigen, anstatt sie zu erregen, und vielmehr sie in sich zu vollenden und ganz zu"}]}, {"page_pdf": 1812, "page_book": 710, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "machen, als nach außen zu reißen und zu theilen. Viel anders ist es hiemit in den Euripideischen Tragödien. Die hohe sittliche Stimmung ist vorbei; andre Motive treten an die Stelle. Es ist ihm nicht mehr so sehr um die erhabene Rührung, welche Sophokles bewirkt, als um materielle und mehr mit Leiden vergesellschaftete Rührung zu thun. Er hat daher, wo er diesen Zweck verfolgt, nicht selten die rührendsten Bilder und Vorstellungen, die aber, weil es im Kern der Sache an der sittlichen und poetischen Reinheit fehlt, doch über das Ganze nicht bestechen können. Zu seinen Zwecken, die sehr oft oder fast immer außer den Grenzen der hohen und ächten Kunst liegen, reichten"}, {"type": "footnote", "text": "1 Tyrannos, V. 864-871."}, {"type": "paragraph", "text": "die alten Stoffe nicht mehr zu; er mußte also die Mythen auf eine oft frevelhafte Weise verändern, und aus diesem Grunde auch die Prologen in den Schauspielen einführen, welche ein anderer Beweis der in ihnen gesunkenen tragischen Kunst sind, was auch Lessing zur Empfehlung derselben sagen mag. Endlich ist er *nie *so sehr darum bekümmert, die Handlung im Gemüth als sie vielmehr nur äußerlich zu schließen, und man begreift eben daraus, sowie aus den stärkeren Mitteln materiellen Reizes, die er anwandte, was Aristoteles sagt, daß er auf die Zuschauer die größte Wirkung gemacht habe. In dem Bestreben, dem groben Sinne zu schmeicheln, und diesen gleichsam zu beruhigen, sinkt er nicht selten zu den gemeinsten Motiven herab, die etwa ein moderner Dichter und zwar von den schlechtesten brauchen könnte, z.B. daß er die Electra zuletzt den - Pylades heirathen läßt. Im Allgemeinen kann man also behaupten, daß Euripides vorzüglich nur groß ist in der Darstellung der Leidenschaft, nicht aber weder in der harten aber ruhigen Schönheit, welche Aeschylos, noch in der mit Güte gepaarten und zur Göttlichkeit geläuterten Schönheit, welche Sophokles eigenthümlich ist. Vergleichen wir nämlich die beiden größten tragischen Dichter untereinander, so gehn die Werke des Aeschylos den plastischen Werken des hohen und strengen Styls der Kunst, wie die des Sophokles den plastischen Werken des schönen Styls, der vor Polykleitos und Phidias anfing, parallel. Nicht als ob nicht im Aeschylos durchaus die sittliche Erhabenheit durchschiene, wenn sie auch nicht in allen Personen seiner Werke so einheimisch wohnt, als in denen des Sophokles; nicht als ob nicht diese Stimmung in der Darstellung auch da erkennbar wäre, wo er nur große Verbrechen und schreckliche Charaktere darstellt, wie den heimtückischen Mord des Agamemnon und den Charakter der Klytämnestra, sondern weil dieser Keim der Sittlichkeit hier noch in eine härtere Hülle verschlossen und herb und unzugänglicher ist, statt daß bei Sophokles die sittliche Güte mit der Schönheit zusammenfließt, und dadurch das höchste Bild der Göttlichkeit entsteht. Wenn ferner Aeschylos in strenger Begrenzung und Abgeschlossenheit jedes seiner Werke und in diesem wieder seine Gestalten hinstellt, so hat"}, {"type": "paragraph", "text": "dagegen Sophokles die Kunst und Schönheit über die Theile seiner Werke gleichmäßig verbreitet, und jedem außer der Absolutheit in sich auch noch die Harmonie mit den andern gegeben. Wie aber in der plastischen Kunst die nach dem hohen und strengen Styl hervorgehende *harmonische *Schönheit eine Blüthe war, die gleichsam nur auf Einem Punkte erreicht werden konnte, und dann wieder welken, oder nach dem entgegengesetzten Ende der bloß sinnlichen Schönheit sich fortbilden mußte, so ist dasselbe"}]}, {"page_pdf": 1813, "page_book": 712, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "auch in der dramatischen Kunst geschehen, in der Sophokles der wahre Gipfel ist, auf den gleich Euripides folgt, welcher weniger Priester der ungeborenen und ewigen, als Diener der zeitlichen und vergänglichen Schönheit ist."}, {"type": "paragraph", "text": "*Von dem Wesen der Komödie.*"}, {"type": "paragraph", "text": "Es wurde gleich anfangs bemerkt, daß durch den allgemeinen Begriff nicht bestimmt ist, auf welcher Seite die Freiheit, und auf welcher die Nothwendigkeit sey, daß aber das ursprüngliche Verhältniß von Freiheit und Nothwendigkeit dasjenige ist, in welchem die Nothwendigkeit als das Objekt, die Freiheit als das Subjekt erscheint. Dieses Verhältniß aber ist das der Tragödie, und darum auch sie die erste und gleichsam positive Erscheinung des Drama. Durch die Umkehrung des Verhältnisses muß also diejenige Form entspringen, worin die Nothwendigkeit oder Identität vielmehr das *Subjekt, *die Freiheit oder Differenz das Objekt ist, und dieß ist das Verhältniß der *Komödie*, wie aus folgenden Betrachtungen sich ergeben wird. Jede Umkehrung eines nothwendigen und entschiedenen Verhältnisses setzt einen in die Augen fallenden Widerspruch, eine Ungereimtheit in dem Subjekt dieser Umkehrung. Gewisse Arten der Ungereimtheit sind nun *unerträglicher *Art, theils inwiefern sie theoretisch pervers und verderblich sind, theils inwiefern sie praktisch nachtheilig sind und ernstliche Folgen haben. Allein in dem angenommenen Fall der Umkehrung wird 1) eine *objektive*, demnach nicht eigentlich theoretische Ungereimtheit gesetzt, 2) ist das Verhältniß in derselben so, daß das Objektive nicht die Nothwendigkeit, sondern die Differenz ist oder die Freiheit."}, {"type": "paragraph", "text": "Die Nothwendigkeit erscheint aber bloß, inwiefern sie das Objektive ist, als *Schicksal*, und nur insofern ist sie fruchtbar. Da also mit der angenommenen Umkehrung des Verhältnisses zugleich alle *Furcht * vor der Nothwendigkeit als Schicksal aufgehoben, und angenommen ist, daß in *diesem *Verhältniß der Handlung überhaupt kein wahres Schicksal möglich sey, so ist ein reines Wohlgefallen an der Ungereimtheit an und für sich selbst möglich, und dieses Wohlgefallen ist es, was man überhaupt das Komische nennen kann, und was sich äußerlich durch einen freien Wechsel des Anspannens und Nachlassens ausdrückt. Wir spannen uns an, die Ungereimtheit, die unserer Fassungskraft widerspricht, recht ins Auge zu fassen, bemerken aber in dieser Anspannung unmittelbar die vollkommene Widersinnigkeit und Unmöglichkeit der Sache, so daß diese Spannung augenblicklich in eine Erschlaffung übergeht, welcher Uebergang sich äußerlich durch das Lachen ausdrückt. Wenn wir nun die Umkehrung jedes möglichen Verhältnisses, das auf Gegensatz beruht, überhaupt ein komisches Verhältniß nennen können, so ist ohne Zweifel das höchste Komische und gleichsam die Blüthe desselben da, wo die Gegensätze in der höchsten Potenz, demnach als Nothwendigkeit und Freiheit umgekehrt werden, und da ein Streit dieser beiden an und für sich objektive Handlung ist, so ist auch das Verhältniß einer solchen Umkehrung durch sich selbst dramatisch. Es wird nicht geleugnet, daß jede mögliche Umkehrung des Ursprünglichen die komische Wirkung hat. Wenn der Feige in die Lage gesetzt wird tapfer seyn zu müssen, der Geizige verschwenderisch, oder wenn in einem unserer Familienstücke etwa die Frau im Hause die Rolle des Mannes, der Mann die Rolle der Frau spielt, so ist dieß eine Art des Komischen. Wir können diese allgemeine Möglichkeit nicht in alle ihre Verzweigungen verfolgen, aus denen die Unzahl von Situationen entspringt, auf denen unser neueres Lustspiel gegründet ist. Wir haben nur den Gipfel dieser Erscheinung zu bestimmen. Dieser also ist da, wo ein allgemeiner Gegensatz der Freiheit und der Nothwendigkeit ist, aber so, daß diese in das Subjekt, jene ins Objekt fällt."}]}, {"page_pdf": 1814, "page_book": 713, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Es versteht sich, daß, weil die Nothwendigkeit ihrer Natur nach objektiv ist, die Nothwendigkeit im Subjekt nur eine prätendirte, angenommene seyn kann und eine affektirte Absolutheit ist, die nun durch die Nothwendigkeit in der Gestalt der äußeren Differenz zu Schanden gemacht wird. So wie die Freiheit und Besonderheit auf der einen Seite die Nothwendigkeit und Allgemeinheit lügt, so nimmt auf der anderen Seite die Nothwendigkeit den Schein der Freiheit an und vernichtet unter dem angenommenen Aeußeren der Gesetzlosigkeit, im Grunde aber nach einer nothwendigen Ordnung die prätendirte Gesetzmäßigkeit. Es ist *nothwendig*, daß wo sich die Besonderheit zur Nothwendigkeit das Verhältniß der Objektivität gibt, sie zu nichte werde; es ist also *insofern *in der Komödie das höchste Schicksal und sie selbst wieder die höchste Tragödie; aber das Schicksal erscheint eben deßwegen, weil es selbst eine der seinigen entgegengesetzte Natur annimmt, in einer erheiternden Gestalt, nur als die Ironie, nicht aber als das Verhängniß der Nothwendigkeit. Da jede mögliche Affektation und Prätention auf Absolutheit ein unnatürlicher Zustand ist, so ist es für die Komödie, da sie als Drama ganz nur an die Anschauung geht, die vorzüglichste Aufgabe, nicht nur diese Prätention zur Anschauung zu bringen, sondern auch, weil die Anschauung vorzüglich nur das Nothwendige faßt, ihr eine Art von Nothwendigkeit zu geben. Die subjektive Absolutheit, sie sey nun wahr und in der Harmonie mit der Nothwendigkeit, oder bloß angenommen und also im Widerspruch mit ihr, drückt sich als Charakter aus. Der Charakter ist aber wie in der Tragödie ebenso auch in der Komödie ein Postulat, eben weil er das Absolute ist; er selbst ist nicht weiter zu motiviren. Nun ist es aber nothwendig, daß gerade in den höchsten Potenzen der Ungereimtheit und der Widersinnigkeit die Anschaulichkeit sich gleichsam verliert, wenn sie nicht auf andere Weise darein gebracht wird. (Anders im Roman - weil episch.) Dieß ist nun bloß möglich, wenn die Person durch einen von ihr unabhängigen Grund, eine äußere Nothwendigkeit schon bestimmt ist, einen gewissen Charakter anzunehmen und ihn öffentlich vor sich zu tragen. Zur"}, {"type": "paragraph", "text": "höchsten Erscheinung der Komödie bedarf es also nothwendig *öffentlicher *Charaktere, und damit das Maximum der Anschaulichkeit erreicht werde, so müssen es *wirkliche *Personen von öffentlichem Charakter seyn, die in der Komödie vorgestellt werden. In diesem Fall allein ist dem Dichter so viel vorausgegeben, daß er nun ferner alles wagen und den gegebenen Personen alle möglichen Erhöhungen der Züge ins Komische leihen kann, weil er die beständige Beglaubigung an dem unabhängig von seiner Dichtung existirenden Charakter der Person zur Begleitung hat. Das öffentliche Leben im Staat wird dem Dichter hier zur Mythologie. Innerhalb dieser Grenze braucht er sich nichts zu versagen, und je kecker er sein dichterisches Recht gebraucht, desto mehr erhebt er sich wieder über die Begrenzung, da die Person in seiner Behandlung gleichsam den persönlichen Charakter wieder ablegt und allgemein-bedeutend oder symbolisch wird. Die einzige höchste Art der Komödie ist also die *alte *griechische oder die Aristophanische, sofern sie sich auf öffentliche Charaktere wirklicher Personen gründet und diese gleichsam zur Form nimmt, worein sie ihre Erfindung ergießt. Wie die griechische Tragödie in ihrer Vollkommenheit die höchste Sittlichkeit verkündet und ausspricht, so die alte griechische Komödie die höchste denkbare Freiheit im Staat, welche *selbst *die höchste Sittlichkeit und mit dieser innig eins ist. Wenn uns auch von den dramatischen Werken der Griechen nichts geblieben wäre außer den Komödien des *Aristophanes*, so würden wir doch aus diesen allein auf einen Grad der Bildung und einen Zustand der sittlichen Begriffe schließen müssen, der der"}]}, {"page_pdf": 1815, "page_book": 715, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "modernen Welt nicht nur fremd, sondern sogar unfaßlich ist. Aristophanes ist mit Sophokles dem Geiste nach wahrhaft eins und *er selbst; * nur in der andern Gestalt, worin er allein noch existiren konnte, als das vollkommene Zeitalter Athens vorbei und die Blüthe der Sittlichkeit in Zügellosigkeit und üppige Schwelgerei übergangen war. Beide sind wie zwei gleiche Seelen in verschiedenen Leibern, und die sittliche und poetische Rohheit, die den Aristophanes nicht begreift, vermag ja auch den Sophokles nicht zu fassen."}, {"type": "paragraph", "text": "Die gemeine Vorstellung von den Aristophanischen Komödien ist, sie entweder für Farcen und Possenspiele oder für unmoralische Stücke zu halten, theils weil er wirkliche Personen aufs Theater gebracht, theils wegen der übrigen Freiheiten, die er sich genommen. Was das Erste betrifft, so ist bekannt genug, daß Aristophanes demagogische Oberhäupter des Volks, den Sokrates selbst auf die Bühne gebracht, und die Frage ist nur, auf welche Art dieß geschehen sey. - Wenn Aristophanes den *Kleon *als einen unwürdigen Anführer des Volks, einen Dieb und Verschwender der öffentlichen Gelder auf das Theater bringt, so übt er hier das Recht des vollkommensten Freistaates aus, in welchem jedem Bürger das Recht freistand über öffentliche und allgemeine Angelegenheiten seine Meinung zu sagen. Daher Kleon auch keine andere Maßregel gegen ihn brauchen konnte, als daß er ihm das Bürgerrecht streitig machte. Allein dieses Recht, das Aristophanes als Bürger hatte, ist für ihn doch nur das Mittel zu der künstlerischen Wirkung, und wenn seine Komödie als eine bloße Anklageakte gegen Kleon begriffen wird, so wäre ja eben darin *nichts *Unsittliches, sie wäre nur unpoetisch. - Nicht anders verhält es sich mit den *Wolken*, worin Sokrates vorgestellt ist, Sokrates hatte als Philosoph einen öffentlichen Charakter; aber daß derjenige Sokrates, welchen Aristophanes darstellt, der wirkliche Sokrates sey, konnte keinem Athener einfallen, und Sokrates selbst konnte, ohne alle Rücksicht auf seinen persönlichen Charakter, der ihn etwa über die Satyre erheben konnte, selbst sehr wohl Zuschauer bei der Aufführung der Wolken seyn. Wenn etwa einmal unsere lieben deutschen Nachahmer auf den Einfall kämen, den Aristophanes nachzuahmen, so würden daraus freilich nichts wie Pasquillen entstehen. Aristophanes stellt nicht die einzelne Person dar, sondern die ins Allgemeine erhöhte, also von sich selbst ganz verschiedene Person. Sokrates ist für Aristophanes ein *Name*, und er *rächt *sich an diesem *Namen,* ohne Zweifel weil Sokrates als Freund des Euripides bekannt war, den Aristophanes billiger Weise verfolgte. An der Person des Sokrates hat er sich auf keine Weise gerächt. Es ist ein symbolischer Sokrates, den er darstellt. Eben durch das, was man"}, {"type": "paragraph", "text": "dem Aristophanes vorwirft, den Sokrates so entstellt und ihm Züge und Handlungen geliehen zu haben, die zu seinem Charakter gar nicht passen, ist sein Gedicht poetisch, anstatt daß es im entgegengesetzten Fall nur gemein, grob oder Pasquill gewesen wäre. Um seinen Erfindungen Glauben, Anschaulichkeit, Eingang zu verschaffen, bedurfte Aristophanes eines berühmten Namens, auf den er alle die Lächerlichkeiten häufen konnte. Daß er eben den Namen des Sokrates wählte, davon war außer der Popularität, die dieser Name hatte, ohne Zweifel der vorhin angegebene Grund der vorzüglichste. Die Komödien des Aristophanes würden, ohne allgemeine Gründe, hinreichend seyn zu beweisen, daß die Komödie in ihrer wahren Erscheinung durchaus nur die Frucht der höchsten Bildung sey, sowie daß sie nur in einem freien Staat existiren kann. Unmittelbar nach der Erscheinung der ersten Aristophanischen Dramen, die noch zu der alten Komödie gehören, entstand in Athen die Herrschaft der"}]}, {"page_pdf": 1816, "page_book": 717, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "dreißig Tyrannen, welche durch ein Gesetz den komischen Dichtern untersagte, die Namen wirklicher Personen auf die Bühne zu bringen. Von diesem Verbot an hörte daher, wenigstens für eine Zeitlang, der Gebrauch der Komödiendichter auf ihre Personen nach wirklichen Menschen von öffentlichem Charakter zu benennen. (Kecke Allegorien.) Sobald Athen wieder frei war, stellte sich zwar der Gebrauch wieder her, so daß selbst in den neuen Komödien Namen wirklicher Personen vorkommen, aber auch die Dichter der sogenannten mittleren Komödie, wenn sie nicht wirkliche Namen gebrauchten, stellten doch unter erdichteten Namen wahre Personen und wahre Begebenheiten dar. Die Komödie ist ihrer Natur nach an das öffentliche Leben gewiesen. Es gibt für sie keine Mythologie und keinen fixirten Kreis ihrer Darstellungen, wie es für die Tragödie eine tragische Periode gibt. Die Komödie muß sich also ihre Mythologie selbst aus dem Zeitalter und dem öffentlichen Zustand schaffen, wozu denn freilich ein solcher politischer Zustand erfordert wird, der den Stoff nicht nur darbietet, sondern auch den Gebrauch verstattet. Sobald daher die alte Komödie die vorerwähnte Einschränkung erhielt, waren die Komödiendichter"}, {"type": "paragraph", "text": "genöthigt, wirklich zu den alten Mythen zurückzugehen; weil sie aber diese weder episch noch tragisch behandeln konnten, mußten sie mit ihnen die Umkehrung vornehmen und sie durch Parodien behandeln, in welchen das, was in jenen als ehrwürdig oder rührend war dargestellt worden, in das Niedrige und Lächerliche gezogen wurde. Die Komödie *lebt* also eigentlich von der Freiheit und der Beweglichkeit des öffentlichen Lebens. In Griechenland hat sie sich so lang wie möglich gesträubt aus dem öffentlichen und politischen Leben in das häusliche herabzusteigen, womit sie auch ihre mythologische Kraft verlor. Dieß geschah in den sogenannten neueren Komödien, da nach den gewöhnlichen Berichten zur Zeit Alexanders, wo die demokratische Verfassung ganz dahin war, durch ein neues Gesetz auch noch untersagt wurde, selbst bloß den Inhalt aus öffentlichen Begebenheiten zu nehmen, und diese, unter welcher Hülle es sey, auf das Theater zu bringen. Daß noch einige Ausnahmen existirten, ist schon oben bemerkt worden, und die Hinneigung zur Parodie des öffentlichen Lebens und die Gewohnheit, alles, was in der Komödie vorgestellt wurde, darauf zu beziehen, scheint so unüberwindlich gewesen zu seyn, daß Menander, das Haupt der neueren Komödie, obwohl er sich selbst vor Beziehungen auf das öffentliche Leben in Acht nahm, doch, um auch dem Argwohn zu entgehen, anfing, die Masken in wahre Carricatur zu verwandeln. Wir kennen zwar die Produkte der neueren Komödie nur bruchstücklich, und aus dem, was uns durch die Uebersetzungen und Nachahmungen des Plautus und Terenz geblieben ist. Allein es ist an sich nothwendig und auch historisch zu beweisen, daß mit der späteren Komödie zuerst die Intriguenstücke mit gänzlich erdichteten Charakteren und Verwicklungen entstanden, und die Komödie, die zuerst im Aether der öffentlichen Freiheit gelebt hatte, sich in die Sphäre der häuslichen Sitten und Begegnisse herabsenkte. Von der Komödie der Römer erwähne ich nichts, da sie niemals die Oeffentlichkeit der griechischen gehabt und in ihrer gebildeten Zeit vorzüglich nur von den Bruchstücken der neueren und mittleren Komödie der Griechen gelebt hat. Ich bemerke noch: die Form der alten"}, {"type": "paragraph", "text": "Komödie war der der Tragödie analog, nur daß mit der letzten Stufe der neueren auch der Chor verschwand."}, {"type": "paragraph", "text": "*Von der modernen dramatischen Poesie.*"}]}, {"page_pdf": 1817, "page_book": 719, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Ich gehe nun zur Darstellung der Tragödie und Komödie der Modernen fort. Um in diesem weiten Meer nicht ganz unterzugehen, werde ich suchen, die Aufmerksamkeit auf die wenigen großen Hauptpunkte der *Differenz *des modernen Drama vom antiken, seiner *Coincidenz *mit ihm und seiner Eigenthümlichkeiten zu bemerken, und werde auch allen diesen Beziehungen wieder gleich die bestimmte Anschauung dessen zu Grunde legen, was wir in der modernen Tragödie und Komödie als die höchsten Erscheinungen anerkennen müssen. Ich werde mich daher in Ansehung der hauptsächlichsten Punkte vorzüglich auf *Shakespeare *berufen. Das Erste, womit wir diese Betrachtung anfangen müssen, ist, daß die *Mischung des Entgegengesetzten*, also vorzüglich des Tragischen und Komischen selbst, als Princip dem modernen Drama zu Grunde liegt. Die Bedeutung dieser Mischung zu fassen, wird folgende Reflexion dienen. - Das Tragische und Komische könnte entweder im Zustand der Vollkommenheit, nicht aufgehobenen Indifferenz dargestellt seyn, dann aber müßte die Poesie weder als tragisch *noch *als komisch erscheinen; es wäre eine ganz andere Gattung, es wäre die epische Poesie. In der epischen Poesie sind die beiden Elemente, die sich in dem Drama streitend entzweien, - nicht vereinigt, sondern überhaupt noch nicht getrennt. Die Mischung beider Elemente auf solche Art, daß sie überhaupt nicht getrennt erschienen, kann also nicht die Eigenthümlichkeit der modernen Tragödie seyn. Es ist vielmehr eine Mischung, worin beide bestimmt unterschieden werden, und so daß der Dichter in beiden sich gleich als Meister zeigt, wie Shakespeare, der die dramatische Stärke nach beiden Polen hin concentrirt, und der *erschütternde* Shakespeare ist im Fallstaff und im Macbeth. Indeß können wir doch diese Mischung entgegengesetzter Elemente als ein Zurückstreben des modernen Drama zum Epos, ohne deßwegen"}, {"type": "paragraph", "text": "Epos zu werden, betrachten; sowie dieselbe Poesie dagegen im Epos durch den Roman zum Dramatischen strebt, und also von beiden Seiten die reine Begrenzung der höheren Kunst aufhebt. Es ist zu dieser *Mischung *nothwendig, daß dem Dichter das Tragische und Komische nicht nur massenweise, sondern auch in seinen Nüancen zu Gebot stehe, wie dem Shakespeare, der im Komischen zart, abenteuerlich und witzig zugleich, wie im Hamlet, und derbe (wie in den Fallstaffschen Stücken) ist, ohne jemals niedrig zu werden; sowie er dagegen im Tragischen zerreißend (wie im Lear), strafend (wie im Macbeth), schmelzend, rührend und beruhigend, wie in Romeo und Julie und mehreren gemischten Stücken ist. Sehen wir nun auf den Stoff der modernen Tragödie, so mußte auch dieser, in der vollkommenen Erscheinung wenigstens, eine mythologische Würde haben; es waren also nur drei Quellen möglich, aus denen er geschöpft werden konnte. Die einzelnen Mythen, welche, wie die der griechischen Tragödie, sich nicht zu epischen Ganzen vereinigt hatten, außer dem großen Kreis des universellen Epos zurückblieben: diese drücken sich in der modernen Welt durch die *Novellen *aus. Die Historie, die fabelhaft oder poetisch, konnte die andere Quelle seyn. Die Dritte der religiöse Mythus, die Legenden, die Heiligengeschichte. Shakespeare hat aus den beiden ersten geschöpft, da die dritte Quelle keinen seiner Zeit und seiner Nation angemessenen Stoff darbot. Aus der dritten schöpften vorzüglich die Spanier und unter diesen wieder Calderon. Shakespeare fand also seine Stoffe vor. In diesem Sinne war er nicht *Erfinder; * allein indem er sie gebrauchte, anordnete und beseelte, zeigte er sich in *seiner *Sphäre den Alten ähnlich und als der weiseste Künstler. Man hat bemerkt, und es ist ausgemacht, daß Shakespeare sich auf das Genaueste an den gegebenen Stoff, vorzüglich der Novellen band, daß er jeden, auch den kleinsten Umstand aufnahm und nicht unbenutzt ließ (ein Verfahren, das vielleicht oft über das unergründlich Scheinende einer manchen seiner Anlagen Aufschluß geben könnte), und daß er den vorhandenen Stoff so wenig wie möglich veränderte."}]}, {"page_pdf": 1818, "page_book": 720, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Auch hierin ist er den Alten ähnlich, unähnlich nur dem Euripides, der als der schon frivolere Dichter die Mythen willkürlich entstellt. Die nächste Untersuchung ist, inwiefern das *Wesen *der alten Tragödie in der modernen stattfinde, oder nicht. Ist in der modernen Tragödie ein wahres Schicksal, und zwar jenes höhere, welches die Freiheit in ihr selbst ergreift? Aristoteles drückt, wie bemerkt, den höchsten tragischen Fall so aus, daß ein gerechter Mensch durch *Irrthum *Verbrechen begehe; es muß dazu gesetzt werden, daß dieser Irrthum von der Nothwendigkeit oder von Göttern, womöglich selbst *gegen *die Freiheit, verhängt sey. Dieser letztere Fall scheint nun auch den Begriffen der christlichen Religion überhaupt ein unmöglicher. Diejenigen Mächte, die den Willen untergraben, und nicht nur das Ueble, sondern das * Böse *verhängen, sind selbst böse, sind höllische Mächte. Wenigstens wenn ein durch göttliche Schickung veranlaßter Irrthum Ursache von Unheil und Verbrechen seyn könnte, so müßte in derselbigen Religion, nach welcher dieß möglich ist, auch die Möglichkeit einer entsprechenden Versöhnung liegen. Diese ist nun allerdings im Katholicismus gegeben, der, seiner Natur nach eine Mischung des Heiligen und Profanen, die Sünden statuirt, um an ihrer Versöhnung die Kraft der Gnadenmittel zu beweisen. Hiermit war im Katholicismus die Möglichkeit des zwar von dem der Alten verschiedenen, aber doch *wahrhaft *tragischen Schicksals gegeben. Shakespeare war Protestant und für ihn stand diese Möglichkeit nicht offen. Wenn es also in ihm ein Faktum gibt, so kann es nur von gedoppelter Art seyn. Entweder daß das Unheil durch die Lockung böser und höllischer Mächtehe*[r]*beigeführt wird, aber nach den christlichen Begriffen können diese nicht unüberwindlich seyn, und es soll * und *kann ihnen Widerstand geleistet werden. Die Nothwendigkeit ihrer Wirkung, sofern sie statt hat, fällt also doch zuletzt in den Charakter oder das Subjekt zurück. So ist es auch bei Shakespeare. An die Stelle des alten Schicksals tritt bei ihm der Charakter, aber er legt in diesen ein so mächtiges Faktum, daß er nicht mehr für Freiheit gerechnet werden kann, sondern als unüberwindliche Nothwendigkeit dasteht."}, {"type": "paragraph", "text": "Den Macbeth lockt ein höllisches Gaukelspiel zum Mord, aber es liegt keine objektive Nothwendigkeit der That darin. Banquo läßt sich durch die Stimme der Hexen nicht bethören, wohl aber Macbeth. Es ist also der Charakter, der entscheidet. Die kindische Thorheit eines alten Mannes zeigt sich in Lear wie ein delphisches, verwirrendes Orakel, und die sanfte Desdemona mußte der düsteren Farbe, die mit Eifersucht gepaart ist, unterliegen. Shakespeare hat aus dem gleichen Grunde, weil er die Nothwendigkeit des Verbrechens in den *Charakter *legen mußte, den von Aristoteles *nicht * angenommenen Fall des Verbrechers, der aus Glück in Unglück stürzt, mit einer furchtbaren Gültigkeit behandeln müssen. Statt des eigentlichen Schicksals hat er die *Nemesis*, diese aber in allen Gestalten, wo Gräuel von Gräueln überwältigt werden, eine blutige Welle die andere treibt, und der Fluch der Verfluchten stets in Erfüllung geht, wie vorzüglich in der englischen Geschichte im Kampf der rothen und weißen Rose. Er *muß *sich dann als Barbar zeigen, weil er die höchste Barbarei darzustellen unternimmt, gleichsam das rohe Schlachten der Familien untereinander, wo alle Kunst ein Ende zu haben scheint und eine rohe Naturkraft eintritt, wie es im Lear heißt: \"Wenn die Tiger des Waldes oder die Ungeheuer der See aus der Dumpfheit herausträten, so"}]}, {"page_pdf": 1819, "page_book": 722, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "würden sie auf solche Weise wirken.\" Doch sind hier Züge zu finden, wo er unter die *Furien*, die nur nicht persönlich auftreten, die Anmuth der Kunst gesendet hat. *So *ist Margarethens Liebesklage über dem Haupt des unrechtmäßigen und strafbaren Geliebten und ihr Abschied von ihm. Shakespeare endet die Reihe mit Richard III., den er mit ungeheurer Energie sein Ziel verfolgen und erreichen läßt, bis er vom Gipfel desselben in die Enge der Verzweiflung getrieben wird und im Getümmel der Schlacht, die ihm verloren geht, rettungslos ausruft:"}, {"type": "footnote", "text": "Ein Pferd, ein Pferd, ganz England für ein Pferd."}, {"type": "paragraph", "text": "Im Macbeth dringt die Rache Schritt vor Schritt und so, daß er durch höllische Täuschungen verführt sie immer noch entfernt glaubt, auf den edleren Verbrecher ein, den die Ehrsucht mißleitete."}, {"type": "paragraph", "text": "Eine sanftere, ja die mildeste Nemesis ist im Julius Cäsar. Brutus geht nicht sowohl zu Grunde durch strafende Mächte als durch die eigne Milde des schönsten und zartesten Gemüths, das ihn nach der That falsche Maßregeln ergreifen ließ. Er hatte der Tugend das Opfer seiner That gebracht, das er ihr bringen zu müssen glaubte, und bringt ebenso ihr sich selbst dar. Der Unterschied dieser Nemesis von dem wahren *Schicksal *ist indeß sehr bedeutend. Sie kommt aus der wirklichen Welt und liegt in der *Wirklichkeit; *es ist die Nemesis, die auch in der Geschichte waltet, und Shakespeare hat sie, wie seinen ganzen Stoff, auch in *dieser *aufgefunden. Es ist *Freiheit mit Freiheit* streitend, was sie herbeiführt; es ist *Succession*, und die Rache ist nicht mit dem Verbrechen unmittelbar eins. Im Cyclus der griechischen Darstellungen herrschte ebenfalls eine Nemesis, aber hier begrenzte und bestrafte sich Nothwendigkeit unmittelbar durch Nothwendigkeit, und jede Lage für sich herausgenommen war eine beschlossene Handlung. Alle tragischen Mythen der Griechen gehörten schon von Anbeginn an mehr der Kunst an, und ein beständiger Verkehr der Götter und Menschen wie des Schicksals war in ihnen einheimisch, also auch der Begriff eines unwiderstehlichen Einflusses. Vielleicht spielt selbst der *Zufall *in dem unergründlichsten der Shakespeareschen Stücke (Hamlet) eine Rolle, aber Shakespeare hat ihn selbst *mit* seinen Folgen erkannt, und er ist daher wieder Absicht bei ihm und wird zum höchsten Verstande. Wenn wir nach diesem mit Einem Wort ausdrücken wollen, was Shakespeare in Bezug auf die Hoheit der alten Tragödie ist, so werden wir ihn den größten Erfinder im *Charakteristischen *nennen müssen. Er kann nicht jene hohe, im Schicksal sich bewährende, gleichsam geläuterte und verklärte Schönheit, die mit der sittlichen Güte in Eins fließt, - und auch diejenige Schönheit, die er darstellt, nicht so darstellen, daß sie im *Ganzen *erschiene, und das Ganze jedes Werks ihr Bild trüge. Er *kennt *die höchste Schönheit nur als einzelnen Charakter. Er hat ihr nicht alles unterordnen können, weil er als Moderner, *als*"}, {"type": "paragraph", "text": "der das Ewige nicht in der Begrenzung, sondern im Unbegrenzten auffaßt, zu ausgedehnt ist in der Universalität. Die Alten hatten eine concentrirte Universalität, die Allheit nicht in der Vielheit, sondern in der Einheit. Es ist *nichts * im Menschen, das Shakespeare nicht berührte, aber er berührt dieß einzeln, da die Griechen es in der Totalität berühren. Die Elemente der menschlichen Natur von den höchsten bis zu den niedrigeren liegen zerstreut in ihm: er kennt *alles*, jede Leidenschaft, jedes Gemüth, die Jugend und das"}]}, {"page_pdf": 1820, "page_book": 724, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Alter, den König und den Hirten. Aus der Reihe seiner Werke würde man die verloren gegangene Erde wieder schaffen können. Allein jene alte Lyra lockte aus *vier *Tönen die ganze Welt: das neue Instrument ist tausendsaitig, es zerspaltet die Harmonie des Universums, um sie zu erschaffen, und darum ist es stets weniger besänftigend für die Seele. Die strenge, alles lindernde Schönheit kann nur mit Einfachheit bestehen. Der Natur des romantischen Princips gemäß stellt die moderne Komödie die Handlung als Handlung nicht rein, isolirt und in der plastischen Beschränkung des alten Drama dar, sondern sie gibt zugleich ihre ganze Begleitung. Allein Shakespeare hat dafür seiner Tragödie die gedrungenste Fülle und Prägnanz in allen Theilen, auch nach der Richtung der Breite, gegeben, doch ohne willkührlichen Ueberfluß, sondern so, daß er als der Reichthum der Natur selbst erscheint, mit künstlerischer Nothwendigkeit aufgefaßt. Die Intention des *Ganzen *bleibt klar und geht dann wieder in eine unerschöpfliche Tiefe, in die alle Ansichten sich versenken können. Es folgt von selbst, daß Shakespeare bei dieser Art der Universalität keine beschränkte Welt hat, auch - inwiefern die idealische Welt selbst eine begrenzte, geschlossene Welt ist - keine idealische Welt, dagegen aber auch nicht die direkt entgegengesetzte Welt der idealischen, wodurch der elende Geschmack der Franzosen die idealische Welt ersetzt, - die conventionelle. Shakespeare stellt also nie weder eine idealische noch eine conventionelle, sondern stets die *wirkliche *Welt dar. Das Idealische beruht"}, {"type": "paragraph", "text": "bei ihm auf dem Bau seiner Stücke. Mit Leichtigkeit übrigens versetzt er sich in jede Nationalität und Zeit, wie wenn es die seinige wäre, d.h. er zeichnet sie im *Ganzen*, unbekümmert um die weniger bedeutenden Züge. Was Menschen beginnen, wie und wo sie es thun können, dieß alles hat Shakespeare gewußt: er ist daher allenthalben zu Haus; nichts ist ihm fremd oder wunderbar. Er beobachtet ein weit höheres Kostum als das der Sitten und Zeiten. Der Styl seiner Stücke ist nach dem Gegenstand gebildet und verschieden von einander (nur nicht etwas nach Chronologie) bis auf Härte, Weichheit, Regelmäßigkeit, Ungebundenheit der Verse, die Kürze und Abgebrochenheit oder die Länge der Perioden. Denn, um nun das Uebrige, die äußere Conformation der modernen Tragödie betreffend, zu erwähnen, und um uns nicht bei den nothwendigen Veränderungen desselben, die aus den vorher schon bemerkten Unterschieden nothwendig hervorgehen, wie die Verlassung der drei Einheiten, die Abtheilung des Ganzen in Aufzüge u.s.w. - um uns dabei nicht aufzuhalten, so ist die *Mischung *der Prosa und der gebundenen Rede im modernen Drama nur wieder äußerer Ausdruck ihrer innerlich episch- und dramatisch-gemischten Natur, und um von den sogenannten bürgerlichen oder anderen inferieuren Trauerspielen nicht zu reden, wo die Personen billigerweise sich in Prosa ausdrücken, war der *abwechselnde *Gebrauch der letzteren selbst, eben wegen des Austretens der dramatischen Fülle in secundäre Personen nothwendig. Uebrigens hat auch in dieser Mischung und in Beobachtung des Rechten in Ansehung der Sprache nicht nur im Einzelnen, sondern auch in Ansehung des Ganzen eines Werks Shakespeare sich als überlegenden Künstler gezeigt. So ist im Hamlet der Periodenbau verwirrt, abgebrochen, trüb wie der Held. In den historischen Stücken aus der älteren und neueren englischen und aus der römischen Geschichte herrscht ein in Bildung und Reinheit sehr abweichender Ton. In den römischen Stücken findet sich fast kein Reim, in den englischen dagegen zumal aus der älteren Geschichte finden sich sehr viele und äußerst pittoreske. Was man übrigens dem Shakespeare für Fehler, Verkehrtheiten"}]}, {"page_pdf": 1821, "page_book": 726, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "und sogar Rohheit anrechnet, sind meistentheils keine, und werden nur von einem beengten und unkräftigen Geschmack dafür gehalten. Von niemand ist er indeß mehr verkannt in seiner wahren Größe als von seinen eigenen Landsleuten und den *englischen *Commentatoren und Bewunderern. Sie halten sich immer an einzelne Darstellungen der Leidenschaft, eines Charakters, an die Psychologie, an Scenen, an Worte, ohne Sinn für das Ganze und die Kunst. Wenn man, sagt Tieck sehr treffend, in die englischen Commentatoren einen Blick wirft, so ist es, als wenn man in einer schönen Gegend reisend vor einer Schenke vorbeifährt, wovor sich besoffene Bauern zanken. Daß Shakespeare bloß durch eine glückliche Begeisterung und in unbewußter Herrlichkeit gedichtet habe, ist ein sehr gemeiner Irrthum und die Sage einer gänzlich verbildeten Zeit gewesen, die in England mit Pope begann. Die Deutschen mißkannten ihn natürlich oft, nicht nur wenn sie ihn etwa nur aus einer formlosen Uebersetzung kannten, sondern weil der Glaube an Kunst überhaupt untergegangen war. Shakespeares Jugendgedichte, die Sonette, Adonis, Lucretia zeugen von einer höchst liebenswerthen Natur und einem sehr *innigen, subjektiven *Gefühl, keinem bewußtlosen Genie-Sturm oder Drang. Spätherhin lebte Shakespeare ganz mit der Welt, so viel ihm seine Sphäre zuließ, bis er anfing sein Daseyn in einer unbeschränkten Welt zu offenbaren und in einer Reihe von Kunstwerken niederzulegen, die wahrhaft die ganze Unendlichkeit der Kunst und der Natur darstellen. Shakespeare ist so umfassend in seinem Genius, daß man ihn leicht wie den Homer für einen collektiven Namen halten könnte, und, wie sogar schon geschehen, seine Werke verschiedenen Verfassern zuschreiben. (Hier das Individuum collektiv, wie bei den Alten das Werk.) Wir würden Shakespeares Kunst doch immer nur mit einer Art von Trostlosigkeit anschauen können, wenn wir ihn unbedingt als den Gipfel der romantischen Kunst im Drama betrachten müßten, da man ihm doch immer vorerst die Barbarei zugeben muß, um ihn innerhalb derselben groß, ja göttlich zu finden. Shakespeare läßt sich in seiner Unbeschränkung mit keinem der alten Tragiker vergleichen, wir müssen"}, {"type": "paragraph", "text": "aber auf einen Sophokles der differenziirten Welt hoffen dürfen; in der gleichsam *sündlichen *Kunst auf eine Versöhnung. Von einer bisher weniger bekannten Seite her scheint wenigstens die Möglichkeit der vollständigen Erfüllung dieser Erwartung angedeutet. Spanien hat den Geist hervorgebracht, der, wenn er auch dem Stoff und Gegenstand nach selbst schon wieder eine Vergangenheit für uns geworden ist, doch der Form und der Kunst nach ewig ist und als schon erreicht und vorhanden zeigt, was die Theorie etwa nur als eine Aufgabe für die zukünftige Kunst weissagen zu können schien. Ich rede von *Calderon*, und ich rede so von ihm im Grunde nach der Einen Tragödie, die ich kenne, wie sich aus Einem Werk des Sophokles sein ganzer Geist ahnden ließe. Sie steht in dem spanischen Theater, übersetzt von A. W. Schlegel, der zu seinem großen Verdienst, zuerst eine ächte Uebersetzung des Shakespeare gegeben zu haben, auch noch dieses hinzugefügt hat, den Calderon in deutscher Sprache erscheinen zu lassen. Was ich also über Calderon sagen kann, bezieht sich auch bloß auf dieses Werk. Es wäre zu dreist, daraus ein Urtheil über die ganze Kunst dieses großen Geistes zu formiren. Was aber in diesem Einen klar vorliegt, ist Folgendes. Man könnte auf den ersten Blick geneigt seyn, den Calderon den südlichen, vielleicht katholischen Shakespeare zu nennen, allein es ist mehr als das, was beide Dichter unterscheidet. Das Erste und gleichsam der Grund des ganzen Gebäudes seiner Kunst ist freilich, was ihm die katholische Religion gegeben hat, zu deren Anschauungen des Universums und der göttlichen Ordnung der Dinge es wesentlich gehört, daß die *Sünde *sey und der Sünder, damit an ihnen Gott durch Vermittlung der Kirche seine Gnade beweise. Damit ist eine allgemeine Nothwendigkeit der Sünde eingeführt, und in dem vorliegenden Stück des Calderon entwickelt sich das ganze Schicksal aus einer Art göttlicher Schickung."}]}, {"page_pdf": 1822, "page_book": 727, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Eusebio, der Held der Tragödie, ist der unbewußte und unerkannte Sohn eines Curtio, dessen Tochter Julia von derselben Mutter zugleich mit ihm unter einem wunderthätigen Kreuz im Walde geboren ist, nachdem der Vater aus ungerechtem Verdacht die Mutter"}, {"type": "paragraph", "text": "an der selben Stelle zu ermorden gesucht hatte. Die Mutter wird durch ein Wunder des Kreuzes aus dem Wald in ihr Haus entrückt, wo sie Curtio, in der Meinung zurückkommend, daß sie ermordet sey, lebendig nebst der holden Tochter, Julia, findet. Der Knabe Eusebio war bei dem Kreuz zurückgeblieben und fiel einem wackern Mann in die Hände, der ihn erzog; die Mutter erinnert sich nur dunkel, zwei Kinder geboren zu haben. Dieß ist der Grund der Geschichte, der aber in der Tragödie selbst nur historisch vorkommt, die erste Synthese, mit der alles gegeben ist. Eusebio, der Vater und Schwester nicht erkennt (denn die Mutter ist seitdem gestorben) liebt Julia; hieraus entwickelt sich das ganze Schicksal beider. Dieses Schicksal und die folgenden Unthaten beider sind an die *göttliche *Fügung zurückgewiesen, die gewollt hat, daß Eusebio nach der Geburt bei dem Kreuze zurückbliebe. Zugleich ist das der christlichen Religion zwar nicht ausschließlich eigenthümliche, aber bestimmt auch in ihr geltende Schicksal eingeführt, daß sich die Schuld der Väter an den Kindern rächt bis ins dritte und vierte Glied (denn auch das Geschlecht des Oedipus verfolgt der Fluch des Vaters, wie das der Pelopiden die Gräuel der Ahnherrn), auch hierdurch ist die Schuld, als subjektive, von dem Helden hinweggenommen, und an die Nothwendigkeit gewiesen. Die erste Folge der Liebe zu Julia ist, daß Lisardo, ein älterer Bruder, von Eusebio deßhalb Genugthuung fordert, daß er, der ohne Namen und Eltern, gewagt ein Liebesverhältniß mit Julia anzuknüpfen. Lisardo fällt; dieß ist der Beginn der Tragödie, deren erste Entwicklung durch mehrere Zwischenfälle die ist, daß Julia sich in das Kloster begibt, Eusebio aber, der durch Verbrechen ohn' Ende sein unendliches Leiden rächen will, Anführer einer Räuberbande wird. Mitten in diesem Verderben sendet ihm der Himmel den künftigen Retter seiner Seele, den Bischof Alberto von Trident, dem er das Leben rettet, und der ihm dafür verheißt in Todesnoth ihm nahe zu seyn und seine Beichte zu hören. Eusebio und Julia stehen beide unter der besonderen Obhut des wunderthätigen Kreuzes, mit dessen Bild beide von Natur auf der Brust"}, {"type": "paragraph", "text": "gezeichnet sind. Eusebio kennt die Wirkung dieses Mals und der Andacht zu dem Kreuz, das ihn aus den wildesten Gefahren schon errettet hat. Auch jetzt wird jenes Zeichen schicksalbestimmend für beide. Eusebio dringt bei Nacht in Julias Kloster durch die Kreuzgänge bis in ihre Zelle: aber wir sehen ihn, wieder von ihr geschreckt, durch eine Furcht, die Julia nicht begreift, über die Klostermauer zurückeilen, wo ihn seine Kameraden erwarten. Es ist das Mal des Kreuzes, welches er auf ihrer Brust, wie es auf der seinigen ist, entdeckt, welches beide trennt, und Julia von der letzten Schuld der Blutschande und des Brechens der Gelübde errettet. Aber dasselbe Zeichen treibt Julia in ein weiteres Schicksal. Da in dem Schrecken, mit dem Eusebio forteilt, die Leiter stehen bleibt, folgt ihm Julia in der Verwirrung empörter Leidenschaft und steigt herab. In einiger Entfernung erwacht ihre Besinnung, sie will zurück, aber indeß haben Eusebios Gefährten die Leiter hinweggenommen; sie ist nun in der Nonnenkleidung in die weite Welt gestoßen, und auch die zarte Julia geht nun Eusebios Weg, indem sie ihr Leiden und ihre Verzweiflung durch gehäuften Mord und Unthaten rächt, bis sie nach einer Reihe solcher Thaten endlich zu Eusebio durchdringt. Curtio zieht indeß gegen die Räuber aus; in einem allgemeinen, hin und her schwankenden Kampf, bei welchem Julia in Männertracht ihren Geliebten vertheidigt, wird dieser"}]}, {"page_pdf": 1823, "page_book": 729, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "endlich tödtlich verwundet. Schon wie todt ruft er nach dem Bischof Alberto, der wie durch göttliche Schickung des Weges kommt und ihn Beichte hört, worauf er ruhig stirbt. Auch dieß geht auf dem einsamen Fleck im Walde vor bei dem Krucifix, welches seine Geburt beschirmte, sein Schicksal entschied und jetzt auch sein Ende selig macht. Curtio, Zeuge des Vorgehenden, erkennt die Stelle, erkennt Eusebio als seinen Sohn und Julia in der Verkleidung; welche ihm bekennt, daß ihre kurze Laufbahn seit der Entweichung aus dem Kloster mit Mord und Gräuelthaten bezeichnet war. Den Sohn preist der Vater selig, sie aber verdammt er und will sie vertilgen, als sie das Kreuz umschlingt, und ihre Schuld im Kloster zu büßen versprechend, es um Hülfe fleht, worauf das Kreuz sich erhebt und sie mit sich in die Höhe nimmt."}, {"type": "paragraph", "text": "Dieß ist der kurze Inhalt dieser Tragödie, in welcher, wie offenbar ist, das meiste durch höhere Schickung geschieht und durch ein christliches Schicksal verhängt ist, nach welchem Sünder seyn müssen, damit an ihnen die Macht der göttlichen Gnade offenbar werde. Dieß entscheidet über das *Wesentliche *dieser Tragödie, die weder höllischer Mächte zur Verführung, noch der bloß äußeren Nemesis zur Strafe bedarf. Wenn wir daher in Shakespeare eigentlich nur den unendlichen *Verstand*, der dadurch, daß er unendlich ist, als Vernunft erscheint, bewundern, so müssen wir in Calderon die *Vernunft *erkennen. Es sind nicht rein wirkliche Verhältnisse, in die ein unergründlicher Verstand den Widerschein einer absoluten Welt legt, es sind absolute Verhältnisse, es ist die absolute Welt selbst. Calderon, obgleich die Züge seiner Charaktere groß und mit ungemeiner Schärfe und Sicherheit angegeben sind, bedarf doch des Charakteristischen weniger, weil er ein wahreres Schicksal hat. Aber ebenso sehr müssen wir Calderon in Rücksicht auf die innere Form der Komposition erheben. Stellen wir das angeführte Werk unter den höchsten Maßstab, den, daß die Absicht des Künstlers in das Werk selbst übergegangen, mit ihm völlig eins und eben durch diese absolute Erkennbarkeit wieder unerkennbar sey, so ist er in dieser Beziehung nur mit Sophokles zu vergleichen. Im Shakespeare beruht die Objektivirung und Unerkennbarkeit der Absicht als solcher nur auf der Unergründlichkeit, Calderon ist ganz durchsichtig, man sieht bis auf den Grund seiner Absicht, ja er spricht sie nicht selten selbst aus, wie Sophokles oft thut, und doch ist sie mit dem Objekt so verschmolzen, daß sie nicht mehr *als *Absicht erscheint, wie in einem Krystall das vollkommenste Gewebe, aber unerkennbar, dargestellt ist. Diese höchste und absolute Besonnenheit, diese letzte Indifferenz von Absicht und Nothwendigkeit ist unter den Neueren nur in Calderon auf solche Weise erreicht. Es gehört zu dieser Durchsichtigkeit schon, daß das Ueberflüssige der Begleitung in ihm nicht so mit verarbeitet seyn kann wie in Shakespeare. Die ganze Form ist concentrirter, und obwohl auch hier die komischen Partien neben den"}, {"type": "paragraph", "text": "tragischen bestehen, so haben sie von der einen Seite doch nicht das große Gewicht wie bei Shakespeare, und sind von der anderen mit den tragischen mehr wie aus Einem Guß unauflöslich verschmolzen. Man würde sich sehr irren, wenn man in dem Werk des Calderon eine fromme und heilige Darstellung erwartete, wie die meisten aus Unkunde solche Werke sich denken: es ist keine Genoveva, wo der Katholicismus absichtlich fromm und im höchsten Grad trübe genommen ist, es ist vielmehr eine durchaus poetische und unauslöschliche Heiterkeit darin; es ist alles, im höchsten Styl, profan darin, ausgenommen die Kunst selbst, welche wahrhaft heilig erscheint."}]}, {"page_pdf": 1824, "page_book": 731, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Die Construktion des Ganzen ist rationeller, in einem Maß wie man es der modernen Poesie wahrscheinlich nicht zugetraut hätte, wenn man ihren Charakter allein von Shakespeare abstrahirte. Die zerstreuten Principien der romantischen Gattung hat Calderon in eine strengere Einheit gefaßt, die sich der wahren Schönheit nähert. Er hat, ohne die alten Regeln zu beobachten, die Handlung zusammengedrängt; sein Drama ist dramatischer und daher schon reiner. Innerhalb dieser Form ist er immer reine Gestaltung neben der höchsten Farbe, so daß im Großen und im Kleinen bis auf die Wahl des Sylbenmaßes Form und Stoff aufs innigste sich durchdringen. Die Motivirung ist nicht vernachlässigt, aber sie drängt sich nicht vor, sie ist ganz integrirender Theil der Organisation des Ganzen, von dem sich nichts hinwegnehmen, und dem sich nichts zusetzen läßt. Sie ist im Ganzen immer auf Schickung gegründet, obgleich sie im Einzelnen a) als *Zufall * sich zeigen kann, wie wenn Julia die Leiter nicht mehr findet, b) als *sittlich*, da der angeregte Aufruhr ihrer Brust sie zu Verbrechen treibt, aber auch ganz *absolut *in der Erscheinung und Wiedererscheinung des Priesters. Endlich, was Calderon durch die höhere Welt voraus hat, auf die seine Poesie sich gründet, ist, daß die Versöhnung zugleich mit der Sünde, und mit der Differenz unmittelbar auch die Nothwendigkeit bereitet ist. Er behandelt die Wunder seiner Religion wie eine unumstößliche Mythologie, den Glauben daran als die unbesiegbare"}, {"type": "paragraph", "text": "Göttlichkeit der Gesinnung. Durch diese werden Eusebio und Julia gerettet, und die Versöhnung, welche er den Vater über den ersten mit wahrhaft antiker Simplicität in den Worten aussprechen läßt:"}, {"type": "footnote", "text": "Nein, du bist kein Raub des Unglücks, Du mein herzgeliebter Sohn, Dem in seinem tragischen Ende Solche Glorie ward zum Lohn -"}, {"type": "paragraph", "text": "diese Versöhnung besänftigt, wie das Ende des Oedipus oder das letzte Loos der Antigone."}, {"type": "paragraph", "text": "Im Uebergang von der Tragödie der Neueren zur Komödie ist es ohne Zweifel am schicklichsten, des größten Gedichts der Deutschen, des *Faust *von Goethe, zu erwähnen. Es ist aber schwer, das Urtheil über den Geist des Ganzen aus dem, was wir davon besitzen, überzeugend genug zu begründen. So möchte der gewöhnlichen Ansicht davon die Behauptung sehr auffallend seyn, daß dieses Gedicht seiner Intention nach bei weitem mehr aristophanisch als tragisch ist. Ich begnüge mich daher, den allgemeinsten Gesichtspunkt für dieses Gedicht, soweit ich ihn einzusehen glaube, anzugeben. Es gibt nicht nur ein Schicksal für das Handeln; auch dem *Wissen *des Individuums als Individuum steht das An-sich des Universums und der Natur als eine unüberwindliche Nothwendigkeit vor. Des Unendlichen als Unendlichen kann nicht das Subjekt als Subjekt genießen, welches doch ein nothwendiger Hang desselben ist. Hier ein ewiger Widerspruch. Dieß ist gleichsam eine idealere Potenz des Schicksals, welches hier mit dem Subjekt nicht minder, wie im Handeln, im Gegensatz ist und im Kampfe liegt. Die aufgehobene Harmonie kann sich hier nach zwei Seiten ausdrücken, und der Streit einen gedoppelten Ausweg suchen. Der Ausgangspunkt ist der unbefriedigte Durst, das Innere der Dinge zu schauen und als Subjekt zu genießen, und die erste Richtung die, die unersättliche Begier außer"}]}, {"page_pdf": 1825, "page_book": 732, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "dem Ziel und Maß der Vernunft durch Schwärmerei zu stillen, wie es in der Stelle des Faust ausgesprochen ist:"}, {"type": "footnote", "text": "Verachte nur Vernunft und Wissenschaft, Des Menschen allerhöchste Kraft, Laß nur in Blend- und Zauberwerken Dich von dem Lügengeist bestärken, So hab' ich dich schon unbedingt."}, {"type": "paragraph", "text": "Der andere Ausweg des unbefriedigten Strebens des Geistes ist der, sich in die Welt zu stürzen, der Erde Weh, der Erde Glück zu tragen. Auch in dieser Richtung ist der Ausgang entschieden; auch hier nämlich ist es ewig unmöglich, als Endliches des Unendlichen theilhaftig zu werden; welches in den Worten ausgesprochen ist:"}, {"type": "footnote", "text": "Ihm hat das Schicksal einen Geist gegeben, Der ungebändigt immer vorwärts dringt, Und dessen übereiltes Streben Der Erde Freuden überspringt. Den schlepp' ich durch das wilde Leben, Durch flache Unbedeutenheit, Und seiner Unersättlichkeit Soll Speis' und Trank vor gier'gen Lippen schweben, Er wird Erquickung sich umsonst erflehn."}, {"type": "paragraph", "text": "In Goethes Faust sind diese beiden Richtungen dargestellt oder vielmehr unmittelbar vereinigt, so daß aus der einen zugleich die andere entspringt. Des Dramatischen wegen mußte das Uebergewicht auf die andere Richtung, die Begegnung eines solchen Geistes mit der Welt, gelegt werden. Soweit wir das Gedicht übersehen, erkennen wir deutlich, daß Faust in dieser Richtung durch das höchste Tragische gehen soll. Aber die heitere Anlage des Ganzen schon im ersten Wurf, die Wahrheit des mißleiteten Bestrebens, die Aechtheit des Verlangens nach dem höchsten Leben läßt schon erwarten, daß der Widerstreit sich in einer höheren Instanz *lösen * werde, und Faust in höhere Sphären erhoben vollendet werde. In diesem Betracht hat dieses Gedicht, so fremd dieß scheinen möge, eine wahrhaft Dantesche Bedeutung, obgleich es weit mehr"}, {"type": "paragraph", "text": "Komödie und mehr in poetischem Sinn göttlich ist, als das Werk des Dante. Das wilde Leben, in welches sich Faust stürzt, wird für ihn nach einer nothwendigen Folge zur Hölle. Die erste Reinigung von Qualen des Wissens und der falschen Imagination wird nach der heiteren Absicht des Ganzen in einer Einweihung in die Principien der Teufelei, als der eigentlichen Grundlage der besonnenen Ansicht der Welt, bestehen müssen, wie die Vollendung darin, daß er durch Erhebung"}]}, {"page_pdf": 1826, "page_book": 734, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "über sich selbst und das Unwesentliche das Wesentliche schaut und genießen lernt. Schon dieses Wenige, was sich über die Natur des Gedichts zum Theil mehr ahnden als wissen läßt, zeigt, daß es ein ganz und in jeder Beziehung originelles, nur sich selbst vergleichbares, in sich selbst ruhendes Werk sey. Die Art des Schicksals ist *einzig *und wäre eine neue Erfindung zu nennen, wenn sie nicht gewissermaßen in deutscher Art gegeben, und daher auch durch die mythologische Person des Faust ursprünglich repräsentirt wäre. Durch diesen eigenthümlichen Widerstreit, der im Wissen beginnt, hat das Gedicht seine wissenschaftliche Seite bekommen, so daß, wenn irgend ein Poem philosophisch heißen kann, dieses Prädikat Goethes Faust allein zugelegt werden muß. Der herrliche Geist, der mit der Kraft des außerordentlichen Dichters den Tiefsinn des Philosophen vereint, hat in diesem Gedicht einen ewig frischen Quell der Wissenschaft geöffnet, der allein hinreichend war, die Wissenschaft in dieser Zeit zu verjüngen, die Frischheit eines neuen Lebens über sie zu verbreiten. Wer in das wahre Heiligthum der Natur dringen will, nähere sich diesen Tönen aus einer höheren Welt und sauge in früher Jugend die Kraft in sich, die wie in dichten Lichtstrahlen von diesem Gedicht ausgeht und das Innerste der Welt bewegt."}, {"type": "paragraph", "text": "Goethes Faust könnte man eine moderne Komödie im höchsten Styl nennen, aus dem ganzen Stoff der Zeit gebildet. Wie die Tragödie in dem Aether der öffentlichen Sittlichkeit, so lebt die Komödie in der"}, {"type": "paragraph", "text": "Luft öffentlicher Freiheit. Mit der neuen Welt verschwand das öffentliche Leben; der Staat wurde durch die Kirche, wie überhaupt das Reale durch das Ideale verdrungen. Nur in dieser war noch ein allgemeines Leben; nur aus ihr, ihren Gebräuchen, Feierlichkeiten, öffentlichen Handlungen, wie aus ihrer Mythologie konnte die Komödie sich entwickeln. Die ersten Komödien waren daher Vorstellungen der biblischen Geschichte, worin der Teufel gewöhnlich die lustige Person spielte, die in Spanien, wahrscheinlich ihrem ersten Vaterlande, und wo sie sich bis in das vergangene Jahrhundert erhielten, Autos sacreamentales genannt wurden. Auf diese Art der Komödie gründete sich die Muse des Calderon, der in der Komödie so groß als in der Tragödie ist, und faßt einzig in diesem Stoff gelebt hat. Eine zweite Gattung bildete sich aus dem ersten, die Komödien der Heiligen, es sind wenige, die nicht auf die Bühne gebracht worden wären. Auch in dieser Gattung ist Calderon Meister. - Den ersten Uebergang von dieser idealen Welt in die gemeine und wirkliche machten in Spanien die Schäferspiele, und Shakespeare, kann man sagen, dem Geburt und Zeitalter jenen höheren Boden versagte, erschuf sich für das Lustspiel eine ganz eigne, romantische Welt, gewissermaßen auch eine Schäferwelt, aber von viel höherer Farbe, Kraft und Fülle. Auch hier mußte das Individuum ins Mittel treten, und die Welt, die ihm nicht gegeben war, sich erschaffen. Was kann eigener und vom Conventionellen entfernter seyn, als die Welt in *Wie es euch gefällt*, in *Was ihr wollt *u.s.w. In Einem Werk, der Komödie der Irrungen, hat Shakespeare einen alten Stoff, aber noch potenzirt und mit Vervielfachung der Verwirrung behandelt. Auch Calderon hat, wo er den Stoff seiner Komödie ganz auf Erfindung gründet, wie Shakespeare zugleich eine romantische Welt als Boden angenommen, nur daß er vor Shakespeare die Nation und die Wirklichkeit voraus hatte, da in Spanien im Zeitalter des Calderon noch eine Art von öffentlichem Leben - wenigstens im Romantischen - war, und seine Helden, so romantisch ihr Aussehen scheinen mag, doch zugleich die Sitten der Zeit und das Leben der damaligen Welt zum Hintergrund hatten."}]}, {"page_pdf": 1827, "page_book": 736, "page_kind": "body", "sigel": "SW I.5", "units": [{"type": "paragraph", "text": "Wie die Franzosen in der Tragödie zuerst an die Stelle der idealischen Welt, zu der sie sich nicht erheben können, die umgekehrte idealische Welt - die conventionelle - gesetzt haben, so auch in der Komödie, und ihre Einwirkung hat eigentlich die wahre absolute Komödie, diejenige, welche sich auf etwas Oeffentliches gründet, völlig verdrungen. Nicht als ob die Spanier nicht auch neben den Charakter- auch die Intriguenstücke gekannt hätten, von denen sie vielmehr die eigentlichen Erfinder sind, aber diese gründen sich auf ein romantisches Leben. Die der Franzosen auf das gemein-sociale oder häusliche, wie sie auch die Erfinder der weinerlichen Komödie sind. Deutschland hat außer den ersten noch wahren und derben Regungen einer gleichfalls aus der Religion hervorgehenden Komödie, wovon mehrere Stücke des Hans Sachs die Belege sind, in welchen die Religion ohne Spott, doch paradoxirt und biblische Mythen komisch behandelt sind, - nach diesen ersten Regungen, und nachdem hier der Protestantismus der Oeffentlichkeit des religiösen Lebens Eintrag gethan hat, fast nur von fremdem Raube gelebt, und die einzige eigenthümliche Erfindung der Deutschen in Masse bleibt es, in Familiengedichten den tiefsten Ton der Philisterei und Häuslichkeit angegeben, sowie in den gewöhnlichen Komödien die Infamie der herrschenden sittlichen Begriffe und niederträchtiger Edelmüthigkeit mit großer Natürlichkeit niedergelegt zu haben, und es bleibt für diese Schmach des deutschen Theaters kein Trost, als etwa daß andere Nationen nach diesem deutschen Wegwurf mit Begier gehascht haben."}, {"type": "paragraph", "text": "Nachdem im Drama nach seinen zwei Formen die höchste Totalität erreicht ist, so kann die redende Kunst nur wieder zur bildenden zurückstreben, aber selbst nicht weiter sich bilden. Im Gesang geht die Poesie zur Musik zurück, zur Malerei im Tanz, theils sofern er Ballet, theils sofern er Pantomime ist, zur eigentlichen Plastik in der Schauspielkunst, die eine lebendige Plastik ist. Da diese Künste, wie gesagt, durch ein Zurückstreben aus der redenden zur bildenden Kunst entstehen, so bilden sie eine eigne Sphäre"}, {"type": "paragraph", "text": "secundärer Künste, die ich in dem Kreis *unserer *Construktion darum nur * erwähnen *zu müssen glaube, da ihre Gesetze als zusammengesetzter Künste aus den Gesetzen derer, aus welchen sie zusammengesetzt sind, herfließen, und was an ihnen nicht auf diese Weise eingesehen werden kann, nur auf empirisch-technischen Regeln beruht, die von selbst aus unserer Construktion ausgeschlossen sind. Ich bemerke nur noch, daß die vollkommenste Zusammensetzung aller Künste, die Vereinigung von Poesie und Musik durch Gesang, von Poesie und Malerei durch Tanz, selbst wieder synthesirt die componirteste Theatererscheinung ist, dergleichen das Drama des Alterthums war, wovon uns nur eine Karrikatur, die *Oper*, geblieben ist, die in höherem und edlerem Styl von Seiten der Poesie sowohl als der übrigen concurrirenden Künste uns am ehesten zur Aufführung des alten mit Musik und Gesang verbundenen Dramas zurückführen könnte. Musik, Gesang, Tanz, wie alle Arten des Drama leben selbst nur im öffentlichen Leben und verbünden sich in diesem. Wo dieses verschwindet, kann statt des realen und äußerlichen Dramas, an dem, in allen seinen Formen, das ganze Volk, als politische oder sittliche Totalität, Theil nimmt, ein *innerliches*, ideales Drama allein noch das Volk vereinigen. Dieses ideale Drama ist der Gottesdienst, die einzige Art *wahrhaft *öffentlicher Handlung, die der neueren Zeit, und auch dieser späterhin nur sehr geschmälert und beengt geblieben ist."}]}], "stats": {"pages_total": 427, "pages_body": 412, "headings": 26, "paragraphs": 1329, "footnotes": 129}};